var sozlukData = [{"kelime":"A‘CEM","anlam":"1.Dilsiz, dili anlaşılmayan. 2.Yabancı.","kategori":"dil","osmanli":"اعجم"},{"kelime":"A‘MÂL","anlam":"Amel’in çokluk hâli, amel-ler, işler.","kategori":"dil","osmanli":"اعمال"},{"kelime":"A‘mâl-i Şer‘iyye","anlam":"Şer‘î ameller. İslâm dininde yapılması emredilen ibâdetler ve işler. (Bkz. Amel)","kategori":"akaid","osmanli":"شرعيه اعمال"},{"kelime":"A‘RABÎ","anlam":"Arab bedevîsi, göçebe Arab; Arab kavminin şehirlerde yaşayıp, ticaret ve ziraatla geçinenleri dışında, hayvancılıkla ve aralarındaki muharebelerden edindikleri ganimet ile geçinen kısmı.","kategori":"muamelat","misal":"A‘râbîler küfr ve münafıklıkta çok ileridir. Allah’ın kanunlarını tanımamaya daha yatkındın. Onlardan öylesi vardır ki, Allah yolunda harcayacağınızı angarya sayarlar. Başınıza belâ gelmesini isterler. Belâlar onlara olsun. Allah bilir, işitir ve hikmet sahibidir. Onlardan öylesi de vardır ki, Allah’a ve âhiret gününe inanır. Sarf ettiğini Allah’a yakınlık ve Resûlünün duâsına vesile sayarlar. Bilin ki harcadıkları…","osmanli":"اعرابى"},{"kelime":"A‘RÂF","anlam":"Cennet ile Cehennem’i birbirinden ayıran yerdeki surun yüksek kısmı-","kategori":"akaid","misal":"nın adıdır.","osmanli":"اعراف"},{"kelime":"A‘RÂF SûRESİ","anlam":"Kur’ân-ı kerîmin yedinci sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. 206 âyet-i kerîmedir. 46’dan 50’ye kadar olan âyet-i kerîmelerde A‘râf ’da bulunanlardan bahsedildiği için, sûre A‘râf adını almıştır. Sûrede, i‘tikâda ve diğer dinî hükümlere âit birçok esas bildirilmekte, bazı peygamberlerin kıssaları, ümmetlerinin hâlleri geniş olarak anlatılmaktadır. (Mefâtihü’l-Gayb)","osmanli":"سى سوره اعراف"},{"kelime":"A‘RÂZ","anlam":"1.Varlıkta kalabilmesi için başka bir şeye muhtaç olan hâssalar (hususiyetler), sıfatlar. 2.Sonradan ve tesadüfen ortaya çıkan hâller, hastalıklar, felâketler.","kategori":"akaid","misal":"Her mahlûk, ya cevherdir yâhud a‘râzdır. Cevher, varlıkta kalabilmesi için başka bir şeye muhtaç olmayan şeydir. Madde, cisim, meselâ elma, altın birer cevherdir. Bunların rengi, kokusu, şekli ise a‘râzdır. Renk cisim ile vardır, onun üzerinde görünür, cisim olmazsa, renk olmaz. (Mevâkıf)","osmanli":"اعراض"},{"kelime":"A‘yân-ı Sâbite","anlam":"Eşyanın vücuda gel-meden önce ilm-i ilâhîde sâbit olan suretleri. Âlem, yani her mevcud, yok iken ilm-i ilâhîde var idi. İlm-i ilâhîde var olanlara a‘yân-ı sâbite ve bu varlığa sübût-i eşya, hariçte var olmaya vücûd-i eşya demişlerdir. (Mektûbât-ı Ma‘sûmiyye)","kategori":"dil","osmanli":"ثابته اعيان"},{"kelime":"A‘ZAMÎ","anlam":"En çok, en fazla.","kategori":"dil","osmanli":"اعظمى"},{"kelime":"ÂB-I HAYÂT","anlam":"1.Hayat suyu, içenin ölümsüzlük kazanacağına inanılan su. 2.Saf ve berrak su. 3.İnce ve derin mânâlı söz. 4.Bir şeyin kıymetini kuvvetli bir şekilde ifâde etmek için kullanılan tabir. 5.Tasavvufta Allahü teâlânın Hayy isminin tecellisi.","kategori":"akaid","misal":"Allahü teâlânın Hayy isminin sırrına erenler, âb-ı hayât içmiş olurlar. Evliyânın bâtınları, kalbleri âb-ı hayâttır. Bir katre (bir damla) tadan, ölümsüz hayâtı bulmuş ve sonsuz saadete, mutluluğa kavuşmuş olur. (Mektûbât-ı İmâm-ı Rabbânî) Zemin her ne kadar zulmet ve karanlık içinde oldu. Lâkin âb-ı hayât zulûmâttadır. (Mektûbât-ı Ma‘sûmiyye)","osmanli":"حيات آب"},{"kelime":"ÂBÂ","anlam":"Baba ve dedeler. Eb (baba) kelimesinin çokluk hâli.","kategori":"miras","osmanli":"آباء"},{"kelime":"ÂBÂD","anlam":"Mâmur, şen.","kategori":"dil","misal":"Halkı tahrîb eyleyib de kendin âbâd eyleme, Bu cihânda ev yapıp ukbâyı berbâd eyleme! (Diyarbakırlı Said Paşa)","osmanli":"آباد"},{"kelime":"ÂBÂD","anlam":"Sonsuz gelecek. Ebed’in çok-luk hâli.","kategori":"dil","osmanli":"آباد"},{"kelime":"ABANOZ","anlam":"Hindistan, Madagaskar, Japonya ve Habeşistan’da yetişen, gayet kuvvetli, sert ve güzel cilâ kabul eden, tesbih, kutu, kalemdan, nalın, baston, minber, câmi ve türbe kapısı yapımında kullanılan siyah bir ağaç.","kategori":"ibadet","misal":"Aslı âbnûs olup, Yunanca ebenos kelimesinden gelir.","osmanli":"آبانوز"},{"kelime":"ABD","anlam":"1.Köle, memlûk, kul. 2.İnsan.","kategori":"hadis","misal":"Üzerinize, sizi Allahü teâlânın kitabı ile idare eden bir abd bile vâli tâyin edilse, onu dinleyin ve itâat edin. (Hadîs-i şerîf-Müslim) Her türlü noksanlıktan münezzeh olan Al-lahü teâlâ, abdini (Muhammed aleyhisselâmı) bir gece Mescid-i Harâm’dan, Mescid-i Ak-sâ’ya götürdü. (İsrâ sûresi: 1) Göklerde ve yerde olan herkes, hiçbiri müstesnâ olmamak üzere, çok esirgeyici Allahü teâlâya mutlaka abd olarak gelecektir. (Meryem sûresi: 93)","osmanli":"عبد"},{"kelime":"ABDÂL","anlam":"(Bkz. Ebdâl)","kategori":"dil","osmanli":"آبدال"},{"kelime":"ABDEST","anlam":"“El suyu” mânâsına namaz ve diğer bazı ibâdetlerin yerine getirilebilmesi için su ile yapılması lâzım gelen temizlik; el yıkamak.","kategori":"ibadet","misal":"Ey îmân edenler! Namaza kalkacağınız zaman yüzlerinizi ve dirseklerle beraber ellerinizi yıkayın ve başlarınızı meshedin ve her iki topukla beraber ayaklarınızı yıkayın. (Mâide sûresi: 6) Allahü teâlânın bir Müslüman kulu, abdest alıp da yüzünü yıkadığı zaman, gözleri ile yaptığı bütün günahlar su ile yahud suyun son katresi ile akıp gider. Ellerini yıkadığı zaman ise, elleri ile yaptığı günahlar akıp gider. Ve böyl…","osmanli":"آبدست","alternatif":["abdest","aptes"]},{"kelime":"ABES","anlam":"Boş, faydasız, lüzumsuz şey. “Sizi abes olarak, oyuncak olarak mı yarat-tım sanıyorsunuz? Bize dönmeyeceğinizi mi söylüyorsunuz?” (Mü’minûn sûresi: 115 )","kategori":"dil","misal":"Namazda abes hareketler mekrûhtur. Elbise ile oynamak gibi. Namazda faydalı hareketin me-selâ eli ile alnındaki teri silmenin zararı olmaz. Entâri (pantolon) vücuda yapışınca, avret ma-hallinin şekli belli olmasın diye, bunları etten ayırmak abes değildir, mekrûh olmaz. Namazda abes hareket hadîs-i şerîf ile men‘ edilmiştir. El-bisenin tozunu silkmek, mekrûhtur. Kaşınmak abes değilse de, bir rüknde, eli üç kere kaldır-mak, namazı bozar. (İbni Âbidîn) Âlimlerin çoğuna göre, herkesin ahlâkı değişe-bilir. Hiçbir kimsenin huyu, yaratılıştaki gibi kalmaz. Sonradan değişebilir. Ahlâk değişme-seydi, Peygamberlerin aleyhimüsselâm getirdik-leri dinler faydasız, lüzumsuz olurdu. Âlimlerin sözbirliği ile koymuş oldukları terbiye ve cezâ usûlleri abes olurdu. (Ahlâk-ı Alâî)","osmanli":"عبث"},{"kelime":"ABESE SûRESİ","anlam":"Kur’ân-ı kerîmin sekseninci sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Kırk iki âyet-i kerîmedir. Birinci âyet-i kerîmede “yüz çevirdi, iltifat etmedi” mânâsına gelen Abese lafzı sûreye isim olmuştur. İniş sebebi, Resû-lullah aleyhisselâm, Mekke’nin eşrâfına İslâ-miyet’i anlatırken, yanına gelip konuşmakta ısrarcı olan âmâ sahâbî İbnü Ümm-i Mek-tûm’a iltifat etmemesidir. Sâhha (kıyamet) ve Sefere (yazıcı melekler) sûresi de denir. Sûrede, Kur’ân-ı kerîmin Allahü teâlâ tarafından bir mev‘ize (nasihat) olduğu bildirilmekte, Cenâb-ı Hakk’ın kudret ve azametine deliller getiril-mekte, kıyâmet gününün dehşetli vaziyeti, o gün iyilerin ve kötülerin hâlleri ve daha başka hususlar anlatılmaktadır. (Kurtubî)","osmanli":"سى سوره عبس"},{"kelime":"ÂBİD","anlam":"1.İbâdet, kulluk eden; ibâdete çok düşkün. 2.Dünyaya düşkün olmayıp, kendini ibâ-dete veren.","kategori":"akaid","misal":"Çokluk şekli, âbidûn ve ubbâd’dır. (Bkz. Ubbâd) Tövbe edenler, âbidler, hamd edenler, (cihâd veya ilim için) seyahat edenler, rükû‘ edenler, secde edenler, emr-i mârûf nehyi anil mün-ker yapanlar ve Allahü teâlânın sınırlarını koruyanlara Cennet’i müjdele. (Tevbe sû-resi: 112) Allahü teâlânın haram kıldığı şey-lerden sakınırsan, insanların en âbidi olur-sun. (Hadîs-i şerîf-Tirmizî) Şeytâna karşı bir fakîh, bin âbidden daha kuvvetlidir. Şeytâ-nın bir âlimden korkması, câhil olan bin âbidden korkmasından daha çoktur! (Ha-dîs-i şerîf-Buhârî) Eshâb-ı kirâm, zâhid ve âbid bir hayat yaşar, dünyaya düşkünlük göstermezdi. Tâbi‘în dev-rinde zenginlik yayılıp insanlar gösterişe yöne-lince, samimi Müslümanlar dünyadan yüz çevi-rip kendisini ibâdete verdi. Bunlara âbid denildi. Âbidin en büyük maksadı, âhiret sevâbına ka-vuşmaktır. Âbid, ibâdetinden öyle zevk alır ki, ibâdetten bir an men‘ edilse, onun için en bü-yük eziyet olur. Hattâ âbidlerden biri; “Ölüm-den korkmuyorum, ancak gece ibâdetime mâni olacak diye korkuyorum” demiştir. Diğeri de; “Allah’ım mezarımda da bana ibâdet imkân-larını ihsân et” diye duâ etmiştir. (İhyâ)","osmanli":"عابد"},{"kelime":"ABRÂŞ","anlam":"1.Alacalı, benekli (at). 2.Be-yaz ve kırmızı alaca renk. 3.Vücudunda baras hastalığı (klorofil azlığı) sebebiyle açık renk lekesi bulunan (adam).","kategori":"dil","osmanli":"آبراش"},{"kelime":"ÂBRÎZ","anlam":"1-Su döken; 2-Mevlevî tekke-lerinde helâ ve hamamları temizlemekle va-zifeli derviş.","kategori":"dil","misal":"ACÂİB-İ SEB‘A-İ ÂLEM: عالم سبعهء عجائب (A) Dünyanın yedi harîkası.","osmanli":"آبريز"},{"kelime":"ACELE","anlam":"Bir şeyi vaktinden önce elde etmeye çalışma.","kategori":"dil","misal":"Teenni Allahü teâlâdan, acele şeytândandır. (Hadîs-i şerîf-Tirmizî, Beyhekî, İbn-i Ebi’d-dünyâ)","osmanli":"عجله"},{"kelime":"ACEM","anlam":"1.Yabancı. 2.Arab olmayan. 3.İranlı.","kategori":"hadis","misal":"Ey insanlar! Rabbiniz birdir. Babanız da bir-dir, hepiniz Âdem’in çocuklarısınız. Âdem ise, topraktandır. Allah katında en kıymet-liniz takvâsı (Allahü teâlâdan korkarak ha-ramlardan, günahlardan sakınması) çok olanı-nızdır. Arab’ın Acem’e bir üstünlüğü yoktur. Üstünlük ancak takvâ iledir. (Hadîs-i şerîf-İbn-i Hişâm) İlk zamanlar Arabların karşılaştıkları Fars kavmi olduğu için Acem sözü bunlar için kullanılmış; bilahare Arab olmayanlardan İslâm dinine giren herkese şâmil olmuştur. Türkler, bu sebeble İranlılara Acem der.","osmanli":"عجم"},{"kelime":"ACEMÎ","anlam":"1.Tecrübesiz, toy. 2.Osmanlılarda saraya ve hâssa ordusuna yeni gelen vazifeli ve hizmetkâr.","kategori":"dil","misal":"Piyasayı bilmeyenlere yüksek fiyatla mal sat-mak da haramdır. Hatta acemî olup, ucuz sa-tan veya pahalı alanlar ile alışveriş etmeme-lidir. Bunlarla alışveriş sahih ve câiz ise de, piyasadaki fiyatı bunlardan gizlemek günah-tır. (Kimyâ-i Seâdet) Boğulmak üzere olan bir acemî yüzücü, her ota sarıldığı gibi; acemî tasavvuf yolcusu da aşk sarhoşluğundan kurtulmak için raks ve musi-kiye sarılmaktadır. Bir şeyin aşkı, insanı sağır ve kör eder. Bunlara eğer namazın kemâlâtın-dan bir şey tattırılmış olsaydı, böyle yapmaz-lardı. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عجمى"},{"kelime":"ACÎB","anlam":"Tuhaf, enteresan.","kategori":"dil","osmanli":"عجيب"},{"kelime":"ÂCİR","anlam":"Malını kirâya veren.","kategori":"muamelat","misal":"Mal sahibi, mûcir. (Bkz. İcâre, Kirâ, Mûcir)","osmanli":"آجر"},{"kelime":"ÂCİZ","anlam":"Acz içinde, gücü yetmeyen, güçsüz, zayıf.","kategori":"dil","misal":"Allahü teâlâ her şeye kâdirdir (gücü yeter). Eğer gücü yetmezse âciz ve noksan olurdu. Âciz-lik ve noksanlık Allahü teâlâ için düşünüle-mez. (Mevâkıf)","osmanli":"عاجز"},{"kelime":"ACZ","anlam":"1.Güçsüzlük, kudretsizlik, düş-künlük. 2.Mükellefin dinî ve hukûkî mükel-lefiyetini yerine getirecek imkân ve iktidarı-nın bulunmaması.","kategori":"dil","osmanli":"عجز"},{"kelime":"ÂD","anlam":"Yemen’de yaşayan ve kendilerine Hûd aleyhisselâm gönderildiği hâlde iman etmedikleri için helâk edilen kavim.","kategori":"akaid","misal":"Âd kavmine, kardeşleri Hûd’u peygamber olarak gönderdik. Hûd (aleyhisselâm) onlara; “Ey kavmim! Allahü teâlâya ibâdet edin. İbâdet edilecek O’ndan başkası yoktur. Hâlâ O’nun azâbından korkmayacak mısınız?” dedi” (A‘râf sûresi: 65)","osmanli":"عاد"},{"kelime":"ÂD KAVMİ","anlam":"Hûd aleyhisselâmın kavmi.","kategori":"dil","misal":"Âd kavmine, kardeşleri Hûd’u peygamber olarak gönderdik. Hûd (aleyhisselâm) onlara; “Ey kavmim! Allahü teâlâya ibâdet edin. İbâdet edilecek O’ndan başkası yoktur. Hâlâ O’nun azâbından korkmayacak mısınız?” dedi. (A‘râf sûresi: 65) Kur’ân-ı kerîmde Hûd aleyhisselâm için; “Âd kavminin kardeşi” buyrulması din kardeşliği sebebiyle değildir. O kavmin içinden yetiştiği, onlarla aynı soydan geldiği içindir. Çünki dinî inan…","osmanli":"قومى عاد"},{"kelime":"ÂDÂB","anlam":"1.Edebler, güzel huylar, iyi hâller ve davranışlar; ahlâk, terbiye ve nezâket kâideleri.","kategori":"tasavvuf","misal":"İlmî münazaralarda tarafların riayet etmesi gereken hususlar (ilm-i edeb). İslâmiyet’in bir amel yapılırken şart koşmadığı, fakat güzel saydığı hareketler. Abdestin, namazın, yemeiçmenin, giyinmenin âdâbı, mahalle, câmi, cenâze âdâbı gibi. Âdâb, Hazret-i Peygamber’in sünnetine uygun davranmak demektir. Bu bakımdan edeb fıkıhta bazen sünnet-i gayrı müekkede, bazen müstehab ve mendub, bazen fazilet hükmündedir. Bu seb…","osmanli":"آداب"},{"kelime":"ADAK","anlam":"Nezir. Allahü teâlânın rızâsının elde edilmesi veya bir isteğin yerine gelmesi veya bir belâ ve musîbetin giderilmesi maksadıyla farz veya vâcib olmayan bir ibâdeti kendisine vâcib kabul etme.","kategori":"fikih","misal":"(Bkz. Nezr)","osmanli":"اداق"},{"kelime":"ADEDÎ","anlam":"Sayılabilen. Çokluk hâli adediyyât gelir.","kategori":"ibadet","misal":"Ceviz, yumurta, karpuz adedîdir. (İbni Âbidîn)","osmanli":"عددى"},{"kelime":"ADEM","anlam":"1.Yokluk, varlığın aksi, zıddı. 2.Tasavvufta sâlikin (tasavvuf yolcusunun) kendisini kaplayan mânevî hâl sebebiyle ken-dinden geçmesi hâli.","kategori":"tasavvuf","misal":"Kâinâtın aslı ademdir. Âlemler yani her şey var olmadan önce ademde idiler. (İ‘ikadnâme)","osmanli":"عدم"},{"kelime":"ÂDEM (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen peygamberlerden.","kategori":"dil","misal":"Muhakkak ki, Îsâ’nın hâli de (yani babasız dünyaya gelişi de) Allah indinde, Âdem’in hâli gibidir. Allahü teâlâ onu topraktan yarattı, sonra ona “Ol” dedi, o da (can gelip) oluverdi. (Âl-i İmrân sûresi: 59) Allahü teâlâ Âdem’i (aleyhisselâm) yeryüzünün her tarafından aldırdığı topraktan yarattı. Bu sebeble zürriyetinden siyah, beyaz, esmer, kırmızı renkte olanlar olduğu gibi, bazıları da bu renklerin arasındadır. Ba…","osmanli":"آدم"},{"kelime":"ÂDET","anlam":"1.Bir memleket veya topluluktaki insanların, öteden beri yapageldiği işler ve uyduğu usûl, alışılmış şey.","kategori":"fikih","misal":"Her memleketin âdeti başka başkadır. Hattâ bir memleketin âdeti zamanla değişir. Bulunduğu şehrin dine uygun olan âdetine uymamak şöhret ve tahrîmen mekrûh olur. (Mektûbât-ı İmâm-ı Rabbânî) Resûlullah’ın sallallahü aleyhi ve sellem yaptığı ve kaçındığı şeyler iki kısımdır: Birisi, ibâdet olarak yaptığı ve kaçındığı şeylerdir ki, her Müslümanın bunlara tâbi olması, uyması lâzımdır. İkincisi bulundukları memleketin âd…","osmanli":"عادت"},{"kelime":"Âdet-i İlâhiyye","anlam":"“İlahî âdet” mânâsına Allah’ın kanunu, Allah’ın bir şeyi yaratmak için arada bulundurduğu ve tecrübe ile anlaşılan sebebler.","kategori":"akaid","misal":"Allahü teâlânın âdet-i ilâhiyyesi şöyledir ki, her şeyi bir sebeble yaratmaktadır. Fakat sebeblerin, vâsıtaların, O’nun yaratmasına hiç tesirleri yoktur. O’ndan başka yaratıcı yoktur. (Mevâkıf) Rızık, maaşa, mala, çalışmaya bağlı değildir. Böyle olmakla beraber, çalışmak farzdır. Çünki Ef ‘âl-i ilâhiyye (Allahü teâlânın işleri) sebebler altında meydana gelir. Âdet-i ilâhiyye böyledir. Sebebleri aramak ve öğrenmek is…","osmanli":"الهيه عادت"},{"kelime":"Âdet-i İslâm","anlam":"“İslâm âdeti” mânâ-sına Müslümanlar tarafından yapılan ve kul-lanılan şeyler.","kategori":"dil","misal":"Gayrımüslimlerin âdetlerinden faydasız veya çirkin, mezmum (kötülenmiş, yerilmiş) olan-ları yapmak ve kullanmak caiz olmaz. Fakat küfr alâmeti olmadıkça, en az iki Müslüman tarafından kullanılırsa, âdet-i İslâm olur. Sa-dece ilk kullanan iki kişi günaha girer. Boyun-bağı gibi. Haramlar âdet hâline gelirse yine helâl olmazlar. Zünnar, haç, papaz külâhı gibi küfr alâmetleri âdet olup Müslümanlar arasında yayılsa da, yine âdet-i İslâm sayılmaz; küfr alâ-meti olmaktan çıkmazlar. (Seâdet-i Ebediyye)","osmanli":"اسلام عادت"},{"kelime":"ÂDÎ","anlam":"1.Âdet olan, âdete uygun, âdet icabı, normal, mutad. 2.Mâliki bilinmeyen eski şey. 3.Bayağı, aşağı, değersiz.","kategori":"dil","misal":"Beş dirhem bakırlı gümüş yerine, aynı kıymette, dört dirhem saf gümüş zekât verilemez. Beş dir-hem hâlis yerine, beş dirhem âdî (ayarı düşük) verilir. Fakat bu surette bile bile vermek mekrûh olur. Beş kile âdî buğday yerine, aynı kıymette dört kile hâlis buğday verilemez. (İbni Âbidîn) Böylece, o aşağı derecedeki insan, yükselerek kâmil olur. Âdî sıfatlardan kurtulup iyi sıfat-lara kavuşur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عادى"},{"kelime":"ÂDİL","anlam":"1.Adâletli; hakkı göze-terek iş yapan, zulüm ve haksızlık etmeyen. 2.Büyük günah işlemeyen ve küçük günaha devam etmeyen Müslüman.","kategori":"dil","misal":"(Bkz. Adâlet) Cennet’te bir derece vardır ki, oraya ancak üç zümre nâil olacaktır (kavuşacaktır). Âdil hükümdâr, akrabâyı ziyaret eden (kimse), sabırlı ve çocuklarına yaptığı harcamaları başlarına kakmayan hâne reisi. (Hadîs-i şerîf-Deylemî) Cennet’te öyle bir köşk var-dır ki, etrâfı kalelerle ve yeşilliklerle çevril-miştir, ayrıca beş bin de kapısı vardır. Orada ancak nebî, sıddîk, şehîd ve âdil hükümdâr barınır. (Hadîs-i şerîf-Deylemî) Mahkemede şâhidin âdil olması şarttır. Âdil, hasenâtı, seyyiâtına gâlib (iyilikleri kötülük-lerinden çok) olan kimsedir. Allah ile kul ara-sında olan işlere diyânât denir. Diyânâtta âdil ve bâlig bir Müslümanın sözüne inanılır. Su-yun pis olduğunu söylerse, bu su ile abdest alın-maz. Teyemmüm edilir. Diyânâtta da, mülkü giderecek haberi, iki Müslümanın bildirmesi lâzımdır. Meselâ zevc ile zevcenin süt kardeşi olduklarını âdil bir Müslüman söylerse, kabul edilmez. Nikâhları bozulmaz. (İbni Âbidîn)","osmanli":"عادل"},{"kelime":"ÂDİLE","anlam":"1.Eşitleme, denkleş-tirme. 2.İslâm miras hukukunda, muayyen hisse sahibi olan eshâbü’l-ferâizin mirastan ala-cakları hisselerin toplamının, mahrece (ortak paydaya) eşit olması hâli. Bu takdirde miras tam olarak bunlara dağıtılır; reddiye veya av-liye meselesi doğmaz.","kategori":"miras","osmanli":"عادله"},{"kelime":"ADL","anlam":"1.Her hak sahibine hakkını verme, zulmün zıddı, adâlet. 2.Doğruluk, denklik, uyumluluk, itidal, eşitlik. 3.Her işi maslahat ve fayda ile yapıcı; mül-künde tasarruf edici, her şeyi yerinde ve za-manında yaratıcı, mülk ve mâl ve mahlûkun cümle O’nun mâlı ve mülkü ve mahlûku ol-duğu, iyi işler yapanı mükâfatlandıran, kötü işler yapana mücâzat eden mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Adl).","kategori":"dil","misal":"Adl sahibi kimseler, kıyâmette Allah’ın huzu-runda, sağında nurdan minberler üzerinde bulunurlar. Bunlar hükümlerinde, aile efra-dına ve velisi olduğu kimselere adl ile mua-mele edenlerdir. (Hadîs-i şerîf-Müslim) Adl ile bu âlemi âbâd kıl! Resm-i cihâd ile beni şâd kıl! Râh-ı cihâd içre edip ictihâd, Memlekette kıl adl-ü dâd! (Osman Gazi’nin Vasîyeti, Tâcüttevârih) Etmiş, ol beden serâyın üstâd, Adl-ü dâd ile esâsın bünyâd. İ‘tidâl üzere idi, pâk teni, Nûra gark olmuşdu, bütün bedeni. (Hilye-i Seâdet)","osmanli":"عدل"},{"kelime":"ADLİYYE","anlam":"1.Adlî işler, mahkemelerle alâkalı işler. 2.Muhakeme işleriyle uğraşan resmî daire.","kategori":"osmanli","osmanli":"عدليه"},{"kelime":"ADûD","anlam":"1.Isırıcı. 2.Şeriat ve kanun hükümlerini icabında zorla yaptıran.","kategori":"dil","misal":"Benden sonra hilâfet otuz senedir. Sonra me-lik-i adûd gelir. (Hadîs-i şerîf-Müsnedü Ahmed) Resûlullah aleyhisselâmın vazifesi üç kısım idi. Birincisi, Allahü teâlânın emir ve yasaklarını öğretmek (tebliğ); ikinci vazifesi, bunları ge-rekirse zor kullanarak yaptırmak (saltanat); üçüncüsü ise kalbleri temizlemek (ihsan) idi. Hulefâ-i Râşidîn, bu üç vazifeyi birlikte yaptı. Sonra gelenler, yalnız saltanat vazifesini yaptı-lar. O zamanki insanlar artık ancak zor kullan-maktan anladığı için bu halîfelere melikü’l-a-dûd denildi. Tebliğ vazifesi, mezheb İmâmlarına, ihsan vazifesi de tasavvuf büyüklerine verildi. (İzâletü’l-Hafâ)","osmanli":"عضوض"},{"kelime":"ADÜVV","anlam":"Düşman, adû.","kategori":"dil","osmanli":"عدو"},{"kelime":"ÂFÂK","anlam":"1.Ufuklar. 2.İnsanın dışında olan mahlûklar.","kategori":"dil","misal":"Biz onlara âyetlerimizi hem âfâk hem de en-füsde göstereceğiz ki, onun (Kur’ân-ı kerî-min) hakkın ta kendisi olduğu açıkça belli olsun. (Fussilet sûresi: 53) Âfâk ve enfüste zâhir olan (görünen) şeyler, Hak teâlânın varlığını ve her şeye kâdir olduğunu gösteren âyetler (işâretler, deliller)dir. (Mektû-bât-ı Ma‘sûmiyye)","osmanli":"آفاق"},{"kelime":"ÂFÂKÎ","anlam":"1.İnsanın dışındaki şeyler. 2.Uzak memleketlerden hac ibâdetini yap-mak için gelenler.","kategori":"dil","misal":"Objektif. Akla, hayâle gelen her şey, hattâ keşif ile an-laşılan bilgiler, ister âfâkî olsunlar, ister enfüsî olsunlar, yani insanın içinde bulunsunlar hepsi mâsivâdır, Allah’tan başkadır, mahlûktur. (Mek-tûbât-ı İmâm-ı Rabbânî) Mekke’de yaşayanlar ile Mekke dışından ge-lenler arasında haccın yapılışında bazı farklar vardır. Meselâ âfâkî olanların Mekke’ye varınca hemen Mescid-i Harâm’a girip, tavâf-ı kudum yapmaları sünnet; Mekke’den ayrılacakları son gün de tavâf-ı sadr yani vedâ tavâfı yapması vâcibdir. (İbni Âbidîn)","osmanli":"آفاقى"},{"kelime":"ÂFET","anlam":"1.Büyük felâket, belâ. 2.Çok güzel insan.","kategori":"dil","misal":"Âfet-i gamdan aceb dünyada kim âzâdedir? Herkesin bir derdi var, mâdem ki âdemzâdedir.","osmanli":"آفت"},{"kelime":"AFÎF","anlam":"İffetli, namuslu, temiz, günah-tan sakınan. (Bkz. İffet)","kategori":"dil","osmanli":"عفيف"},{"kelime":"ÂFİTÂB","anlam":"1.Güneş. 2.Gü-zel yüz, güzel. 3.Şarap.","kategori":"dil","misal":"Güneşin ışığı. Mu‘cize, her kim nebîdir, sıdkına olur delîl, Şöyle ki, gün olduğunu haber verir âfitâb. (Na‘t-ı Şerif)","osmanli":"آفتاب"},{"kelime":"ÂFİYET","anlam":"1.Sıhhat; bedende hastalık bulunmaması. 2.Günah işlememe.","kategori":"dil","misal":"Allahü teâlâdan âfiyet isteyiniz. Îmândan sonra âfiyetten daha büyük nimet yok-tur. (Hadîs-i şerîf-Müsnedü Ahmed) Resû-lullah aleyhisselâm şu duâyı çok okurdu: Allahümme innî es’elüke’s-sıhhate ve’l-âfi-yete ve’l-emânete ve hüsne’l-hulkı ve’r-rı-dâe bi’l-kaderi bi-rahmetike yâ erhamer-râhimîn. (Ya Rabbî! Senden, sıhhat ve âfiyet ve emânete hıyânet etmemek ve güzel ahlâk ve kaderden râzı olmak istiyorum. Ey mer-hamet sahiplerinin en merhametlisi! Merha-metin hakkı için, bunları bana ver!). (Hadîs-i şerîf-Taberânî, Hâkim) Büyüklerden biri, hep duâ eder, Allahü teâlâ-dan bir günlük âfiyet isterdi. Adamın biri bu zâta; “Sen her gün âfiyette değil misin?” dedi. “Allahü teâlâdan öyle bir gün istiyorum ki, sa-bahtan akşama kadar Allahü teâlâya hiçbir günah işlemeyeyim. Âfiyetle geçen gün böyle olur.” buyurdu. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عافيت"},{"kelime":"AFOROZ","anlam":"“Sınır harici (etme)” mânâsına Hristiyanlık ve Yahudilikte, dinden ve cemaatten uzaklaştırma cezâsı.","kategori":"dil","misal":"sebebidir. Kürtaja bilerek sebebiyet vermek; kilise âyinlerine hakaret, papaya fiilî tecâvüz, inancını kaybetme, sapık bir inancı benimseme, papa dışında birisinin piskopos tayini, günah çıkarma mahremiyetinin ihlâli gibi sebebler vardır. Aforoz edilen, pişmanlık bildirir ve keffâret verirse affedilir. Papalığın da af salâhiyeti vardır. Aforoz edilen şahıs doğum ve ölüm kayıtlarını, ismini ve evliliğini kaybeder. Ki…","osmanli":"آفوروز"},{"kelime":"AFÜVV","anlam":"Afvı çok olan, günahlardan, hatâ ve kusurlardan dolayı cezâlandırma-yan, günahları affedip amel defterinden silen mânâsına Allahü teâlânın Esmâ-i hüsnâsın-dan. (el-Afüvv.)","kategori":"akaid","misal":"Siz bir hayrı, iyiliği açıklar veya gizlerseniz yahud (size yapılan) bir kötülüğü affederse-niz biliniz ki, Allahü teâlâ Afüvv’dür ve her şeye kâdirdir. (Âyet-i kerîmede mazlûmun zâ-limi affetmesi teşvik edilmektedir.) (Nisâ sû-resi: 149) Hazret-i Peygamber şu duâyı çok okurdu: Allahümme inneke afüvvün kerî-mün tuhibbü’l-afve fa‘fü annî (Allah’ım! Beni affet. Çünki sen affedicisin, kerem sahi-bisin, affetmeyi seversin, beni de affet!). (Ha-dîs-i şerîf-Taberânî)","osmanli":"عفو"},{"kelime":"AFV","anlam":"Suç, kusur, kabahat ve günahı ba-ğışlamak, ceza vermemek, kınamamak.","kategori":"dil","misal":"Afv yolunu tut. Ma‘rûfu emret ve câhillerden yüz çevir. (A‘râf sûresi: 199) Allahü teâlâ, afv edenleri azîz eder. Allah rızâsı için afv edeni, Allahü teâlâ yükseltir. (Hadîs-i şerîf-Beyhekî) Zinâ, şarap içme gibi Allah hakkına taalluk eden günahlarda afvedilmek için samimi tövbe kâ-fidir. Tövbe etmeyeni de Allah afvedebilir. Kul hakkına taalluk eden hususlarda, hak sahibi ile helâlleşmek, afvın şartıdır. Kul hakkını ihlâl eden katl, yaralama, hakaret gibi suçlarda yal-nızca mağdur veya mağdurun yakınları afva salahiyetlidir. Devletin afva hakkı yoktur. Ce-miyete karşı işlenen had suçlarında devlet de afvedemez. Bunun dışında kalan suçlarda dev-letin afva hakkı vardır. (İbni Âbidîn)","osmanli":"عفو"},{"kelime":"AFYON","anlam":"Haşhaş (papaver somniferum) bitkisinin kelle kısmından çizilip çıkarılan","kategori":"dil","misal":"kokulu ve acı sütten mayalanarak elde edi-len, baz morfin, eroin ve kokainin hammad-desi olan ve kullanan kişinin aklını perdele-yen uyuşturucu ve katı madde. Afyûn. Beng, benc (ban otu), kunneb (esrar) ve afyon gibi katı maddelerin akla zarar veren çok mik-darı haramdır. İlaç ve morfin olarak kullanılması ve bu maksatla satılması caizdir. (İbni Âbidîn)","osmanli":"آفيون"},{"kelime":"AĞA","anlam":"Köylük yerde geniş toprakları olan, sözü geçen, nüfuz sâhibi, varlıklı kimse.","kategori":"dil","osmanli":"آغا"},{"kelime":"ÂGÂH","anlam":"1.Haberdar, uyanık. 2.Gaflette olmayan, kalbi Allahü teâlâ ile beraber olan.","kategori":"akaid","misal":"Ubeydullah-ı Ahrâr buyurdu ki, İnsanlar ibâdet yapmak için yaratıldı. İbâdetin hülâsası, özü de kalbin her zaman Allahü teâlâdan âgâh olmasıdır. (Reşahât)","osmanli":"آﮔاه"},{"kelime":"AĞIRLIK","anlam":"Evlenirken mehr-i muaccele mahsuben veya mehrden ayrı olarak çeyiz karşılığı kadına ve bazı yerlerde yakınlarına verilen mal, para.","kategori":"dil","misal":"Ağırlık, nikâh akdi sırasında konuşulursa, mehr-i muaccel sayılır. Konuşulmazsa, örfe tâbi olarak çeyiz karşılığı olarak talep edilebilir. (İbni Âbidîn)","osmanli":"آغرلق"},{"kelime":"AĞYÂR","anlam":"Başkalar, yabancılar. Gayr’ın çokluk hâli.","kategori":"dil","misal":"Hadîs-i şerîfte; “Kaderiyye (kaderi inkâr eden-ler) fırkasında olanlarla birlikte bulunma-yınız!” buyuruldu. Çünki, ağyâr ile görüşmek, insanı helâke, felâkete sürükler. (Mirkat) Yâri bana bes görmüşüm, ağyârı dilden sür-müşüm, Üns ile tenhâ durmuşum, ben ins-ü cânı neylerim. (Niyazî Mısrî)","osmanli":"اغيار"},{"kelime":"ÂH","anlam":"1.Acı ve üzüntü sebebiyle ağızdan çıkan söz. 2.Yazık. 3.Bedduâ.","kategori":"fikih","misal":"Namazda âh etmek, namazı bozar. (İbni Âbidîn) Alma mazlumun âhını, Çıkar âheste âheste.","osmanli":"آه"},{"kelime":"AHBÂB","anlam":"(A. Hubb’dan) Sevilenler, dost-lar. Habîb’in çokluk hâli.","kategori":"dil","osmanli":"احباب"},{"kelime":"AHBÂR","anlam":"1.Bir kavim, kabile, şahıs, ülke, belde, şehir veya bir hâdise hakkında nakledilen bilgiler. 2.Yahudi âlimleri.","kategori":"hadis","misal":"Hibr’in çokluk şekli. Onlar (Ehl-i kitâb), ahbârı ve ruhbânı ve Meryem oğlu Îsâ Mesîh’i Allah’tan başka Rab’ler edindiler. Hâlbuki onlar, ancak bir olan ve kendisinden başka ilâh olmayan Allah’a ibadet etmekle emrolunmuşlardı. Allah onların ortak koştuklarından münezzehtir... Ey iman edenler! Hahamlar ve papazlardan pek çoğu haksız yere insanların mallarını yerler, onları Allah’ın yolundan alıkoya…","osmanli":"اخبار"},{"kelime":"AHD","anlam":"Söz vermek; sözleşmek.","kategori":"dil","misal":"Onlar (kurtuluşa eren mü’minler) emanetle-rini ve ahidlerini yerine getirirler. (Mü’minûn sûresi: 23, 8) Rabbinizle ve diğer insanlarla olan ahdinize vefâ ediniz, zîrâ kıyâmette ahd sahibinden, ahdini bozmasının sebebi sorulur. (İsrâ sûresi: 34) Birine verilen ahd ile yemin arasında fark var-dır. Yemîn bozulursa keffaret gerekir. Ahd böyle değildir. Ama Allah’a ahd ediyorum, ahdim ol-sun demek yemîn olur. (İbni Âbidîn)","osmanli":"عهد"},{"kelime":"AHD-İ ATÎK","anlam":"Yahudilerin mukaddes kitabı Tevrat ile buna ilave kitapların hepsine Hristiyanlarca verilen isim.","kategori":"dil","misal":"Eski Ahid. Ahd-i Atîk ismini kullanan Hristiyanlardır. Çünki Yahudilere göre Ahid bir tanedir. Onlar Ahd-i Atîk yerine Tanah der. Tanah, Tevrat, Neviim (peygamberler) ve Ketuviim (Kitaplar) olmak üzere üç kısımdır. Tevrat dışındakiler, Hazret-i Mûsâ’dan sonraki Benî İsrail peygamberlerine ait kıssa ve haberleri anlatır.","osmanli":"عتيق عهد"},{"kelime":"AHDNÂME (Ahidnâme)","anlam":"Devlet reisinin emriyle, bazı devlet, cemaat ve şahıslara hususî hak ve imtiyazlar tanımak maksadıyla hazırlanan vesika.","kategori":"osmanli","osmanli":"عهدنامه"},{"kelime":"ÂHENK","anlam":"Bir bütünün unsurlarının bir-biriyle uygunluk içinde olması. Armoni.","kategori":"dil","misal":"Çelik, taşa sürtülünce ateş çıktığı, gibi, güzel ve âhenkli ses işitmek de, gönül denilen gizli kuv-veti harekete getirir. Güzel ses, insanın elinde olmayarak, kalbine tesir eder. Çünki, kalbin ve ruhun, Arşın üstündeki Âlem-i ervâh ile bağlılığı vardır. Maddesiz, ölçüsüz olan o âlem, hüsn-i cemâl, güzellik âlemidir. Güzelliğin temeli ise tenâsüb, âhenk, uygun, düzgün olmaktır. Bu dünyadaki bütün güzellikler, o âlemin güzelli-ğinden gelmektedir. Güzel, düzgün, âhenkli ses-ler de, o âleme benzemektedir. (İhyâ)","osmanli":"آهنك"},{"kelime":"AHFÂ","anlam":"Tasavvufta velîlik mertebelerinden.","kategori":"tasavvuf","misal":"Çok gizli, âlem-i emrin (madde ve ölçü olmayan ve arşın üstündeki âlemin) beşinci ve son latîfesi (makamı, mertebesi). İnsana Âlem-i sagîr, yani küçük âlem denir. Âlem-i sagîr, on kısımdan meydana gelir. Bunların beşi Âlem-i emrdendir. Bu beş mertebe; kalb, ruh, sır, hafî ve ahfâdır. Bunların asılları, kökleri Âlem-i kebîrdedir (insanın dışındaki âlemdedir). Ahfâ latîfesi, mertebelerin en sonu ve en yukarıdaki merte…","osmanli":"اخفى"},{"kelime":"ÂHİR","anlam":"1.Son, sonuncu. 2.Mahlûkâtın (varlıkların) yok olmasından sonra, bâkî olan (varlığı devam eden) yalnız kendisi kalan, hiç yok olmayan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elÂhiru). O (Allahü teâlâ) Evvel ve Âhir’dir. (Hadîd sûresi: 3) elÂhiru ism-i şerîfini söyleyenin gönlü temizlenir. Safâya kavuşur. Günde yüz defa söylenirse, Allahü teâlâdan başka her şeyin sevgisi kalbden çıkar. (Elİstigâsetü’l-Kübrâ)","kategori":"akaid","osmanli":"آخر"},{"kelime":"ÂHİRET","anlam":"İnsanın ölümü ile başlayan ve inanması imanın altı şartından biri olan ebedî (sonsuz) hayat.","kategori":"akaid","misal":"Kim de mü’min olduğu hâlde âhireti ister ve onun için gereken şekilde çalışırsa, işte onların çalışmaları makbûl olur. (İsrâ sûresi: 19) Ne güzel evdir dünya, Allah razı oluncaya kadar âhiret azığını temin etmek için. Ne fena evdir dünya, âhiret azığını terk eden ve Allah’ın rızâsını da kazanmayanlara. (Hadîs-i şerîfHâkim)","osmanli":"آخرت","alternatif":["ahiret"]},{"kelime":"Âhiret Günü","anlam":"Âhiret zamanı için kullanılan bir tabirdir. Yevmü’l-Âhire (Son Gün).","kategori":"akaid","osmanli":"ﮔونى آخرت"},{"kelime":"Âhiret Hayatı","anlam":"Âhirette olacak hâdiseler için kullanılan bir tabirdir.","kategori":"akaid","osmanli":"حياتى آخرت","alternatif":["ahiret"]},{"kelime":"Âhiret Kardeşi","anlam":"Âhiretlik, Âhiret için, Allah yolunda edinilen kardeşlik.","kategori":"akaid","misal":"Kim Allah yolunda bir kardeş edinirse Cennet’te bin derece alır. (Hadîs-i şerîf- İbni Ebiddünyâ)","osmanli":"شى قارده آخرت","alternatif":["ahiret"]},{"kelime":"Âhiret Senesi","anlam":"Âhiret işlerinde esas alınan zaman müddeti.","kategori":"akaid","misal":"Rabbinin nezdinde bir gün, sizin saydıklarınızdan bin yıl gibidir. (Hac sûresi: 47) Allah, gökten yere kadar her işi düzenleyip yönetir. Sonra (bütün bu işler) sizin sayageldiklerinize göre bin yıl tutan bir günde O’nun nezdine çıkar. (Secde sûresi: 5) Allahü teâlânın bildirdiği bir âhiret gününün niçin bu kadar zaman olduğunu ancak Allahü teâlâ bilir. Çünki âhirette, dünyada bulunan gece, gündüz, ay ve sene yoktur.…","osmanli":"سى سنه آخرت","alternatif":["ahiret"]},{"kelime":"ÂHİRETLİK","anlam":"1.Âhiret kardeşi, ahretlik. 2.Âhiret sevabı ümidiyle alınıp beslenen kimsesiz çocuk. 3.Dünyaya düşkün olmayan saf kimse.","kategori":"akaid","osmanli":"آخرتلك"},{"kelime":"AHKÂF SûRESİ","anlam":"Kur’ân-ı kerî-min kırk altıncı sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Otuz beş âyettir. Yirmi birinci âyet-i kerîmede geçen Ahkâf kelimesi sûreye isim olmuştur. Ahkâf uzun ve yüksek kum yığınları demek olup, Arabistan’ın güneyinde Umman ile Mehre arasında Hûd aleyhisselâmın kavminin yaşa-dığı kumluk mıntıkadır. Hûd aleyhisselâm, Âd kavmini burada îmâna da’vet etti, ça-ğırdı. Sûrede, Allahü teâlânın birliğinin de-lilleri, şirkin yanlışlığı bildirilmekte; inanan-ların, Allahü teâlâdan korkarak günahlardan sakınanların büyük mükâfâtlara kavuşacakları müjdelenmektedir. Ayrıca mü’minlerin, ana-larına, babalarına iyi davranmakla mükellef oldukları, dünyanın fânî, geçici varlığına ve lezzetlerine kapılmanın uygun olmadığı an-latılmakta; Âd kavminin kıssası ve Hûd aley-hisselâma inanmamaları, ona karşı gelmeleri netîcesinde acı bir azapla helak oluşları haber verilmekte ve daha başka konular yer almak-tadır. (Tefsir-i Mazharî) Kim Ahkâf sûresini okursa, onun için, dün-yadaki kumların her birine karşılık on se-vab yazılır. (Hadîs-i şerîf-Beydâvî )","osmanli":"سى سوره احقاف"},{"kelime":"AHKÂM","anlam":"Hükümler; emir ve yasaklar.","kategori":"fikih","misal":"Hükm’ün çokluk şeklidir.","osmanli":"احكام"},{"kelime":"Ahkâm-ı İctihâdiyye","anlam":"“İctihadî hükümler” mânâsına Kur’ân-ı kerîm ve hadîs-i şerîflerde açıkça bildirilmeyip, müctehid de-nilen âlimlerin açıkça bildirilenlere benzete-rek elde ettikleri hükümler.","kategori":"hadis","osmanli":"اجتهاديه احكام"},{"kelime":"Ahkâm-ı İslâmiyye","anlam":"“İslâmî hükümler” mânâsına Allahü teâlânın emir ve","kategori":"akaid","misal":"yasakları, beden ve kalb ile yapılacak ve sakınılacak şeylerin tamâmı, İslâm dîni, şeri’ât-ı İslâmiyye; fıkıh ilmi.","osmanli":"اسلاميه احكام"},{"kelime":"Ahkâm-ı Şer‘iyye","anlam":"“Şer‘î hüküm-ler” mânâsına İslâm dininde bir işin yapılması veya yapılmaması gerektiğini bildiren hüküm-ler, emirler ve yasaklar, Şeriat-ı İslâmiyye’nin hükümleri. Ahkâm-ı ilâhiyye, Ahkâm-ı İslâ-miyye, Ahkâm-ı Kur’âniyye.","kategori":"ibadet","misal":"Bütün insanlara her şeyden önce lâzım olan, i‘tikâdı (inancı) düzeltmektir. Yani doğru bir îmân sahibi olmaktır. İkinci olarak, ahkâm-ı şer‘iyyeyi öğrenmektir. Beden, ahkâm-ı şer‘iy-yeyi yapmakla süslenince, nefs dünya kötülük-lerinden ve zararlarından kurtulur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"شرعيه احكام"},{"kelime":"AHLÂK","anlam":"İnsanda yerleşmiş huylar.","kategori":"tasavvuf","misal":"İslâm âlimlerinin çoğuna göre insanlar iyiliğe, yükselmeye elverişli olarak doğar. Sonra nefsin kötü arzuları, güzel ahlâkı öğrenmemek ve kötü arkadaşlarla düşüp kalkmak kötü huyları meydana getirir. (Ahlâk-ı A’lâî)","osmanli":"اخلاق"},{"kelime":"AHMAK","anlam":"(A. Humk’dan) Aklı az, görüşü kısa. Ahmakla arkadaşlık etmekten kaçın. (Ha-dîs-i şerîf-Beyhekî)","kategori":"dil","osmanli":"احمق"},{"kelime":"AHMEDİYYE","anlam":"1.İmâm-ı Rabbânî Ahmed Fârûkî Serhendî hazretlerinin tasavvuftaki yolu, Nakşibendîliğin İmâm-ı Rabbânî’den sonra aldığı isimlerden. Müceddidiyye-i Ahmediyye. 2.Hindistan’da İngiliz hâkimiyeti devrinde Gulam Ahmed Kâdiyânî tarafından kurulan bir bid‘at fırkası.","kategori":"ibadet","misal":"(Bkz. Kâdiyânîlik)","osmanli":"احمديه"},{"kelime":"AHMER","anlam":"Kırmızı, kızıl.","kategori":"dil","osmanli":"احمر"},{"kelime":"AHRÂRİYYE","anlam":"Ubeydullah Ahrâr’ın tasavvuftaki yolu; Nakşibendîliğin Ubeydullah Ahrâr’dan sonra aldığı isimlerden.","kategori":"tasavvuf","osmanli":"احراريه"},{"kelime":"AHŞÂ","anlam":"Bağırsak, ciğer gibi iç organ-lar. Haşâ’nın çokluk hâli.","kategori":"dil","osmanli":"احشاء"},{"kelime":"AHSEN","anlam":"Daha, en veya pek güzel.","kategori":"dil","osmanli":"احسن"},{"kelime":"AHSENÜ’L-HÂLİKÎN","anlam":"Yaratıcıların en güzeli mânâsına Allahü teâlânın sıfatlarından.","kategori":"akaid","misal":"Yaratanların en güzeli olan Allah ne uludur! (Mü’minûn sûresi: 14) Allah yaratanların en güzelidir. (Sâffât sûresi: 124) Allahü teâlâ, ahsenü’l-hâlikîndir, yaratıcı sanılanlara benzemez. Hâlık (yaratıcı) sıfatı, Allah’tan başkası için kullanılamaz. (Mefâtihü’l-Gayb)","osmanli":"الخالقين احسن"},{"kelime":"ÂHû","anlam":"Ceylan, karaca. (Mecaz) Güze-lin gözü.","kategori":"dil","misal":"Şîrler pençe-i kahrımda olurken lerzân, Beni bir gözleri âhûya zebûn etti felek. (Yavuz Sultan Selim)","osmanli":"آهو"},{"kelime":"AHuND","anlam":"Türkistan ve İran taraflarında gerek Şiî, gerekse Sünnîler arasında din adamı ve hocalara verilen isim. Âhend.","kategori":"dil","osmanli":"آخوند"},{"kelime":"AHVÂL","anlam":"1.Hâller, durumlar. 2.Tasavvuf yolunda bulunan kimselerin, kalblerinde meydana gelen değişmeler.","kategori":"tasavvuf","misal":"Ubeydullah-ı Ahrâr buyurdu ki: Kalbe gelen bütün mânevî ahvâli, keşifleri verseler; fakat kalbimizi Ehl-i sünnet i‘tikâdı ile süslemeseler kendimi mahv olmuş ve hâlimi harap bilirim. Bütün haraplıkları, felâketleri üzerime yığsalar, lâkin kalbimi Ehl-i sünnet i‘tikâdı ile şereflendirseler hiç üzülmem. (Mektûbât-ı Ma‘sûmiyye)","osmanli":"احوال"},{"kelime":"AHYÂ","anlam":"Diriler. Hayy kelimesinin çokluk hâli.","kategori":"dil","osmanli":"احياء"},{"kelime":"AHYÂF","anlam":"Ana bir kardeşler.","kategori":"dil","osmanli":"آخياف"},{"kelime":"AHYÂR","anlam":"1.Hayrı çok, iyiliği ziyâde kimseler. 2.Tasavvufta kemal mertebeye gel-miş kimseler.","kategori":"akaid","misal":"Ricâlü’l-Gayb denilen Allahü teâlânın insanlardan gizlediği evliyâ zâtlar-dan. Hayr’ın çokluk hâli. (Bkz. Rûhâniyyûn) (Nükabâ) üç yüz kişidir. (Nücebâ) yetmiş ki-şidir. (Büdelâ) kırk kişidir. Ahyâr, yedi kişidir. İnsanlara bir şey lâzım olunca önce Nükâba, sonra Nücebâ, sonra Ebdâl düa eder. Yine ka-bul olmazsa, Ahyâr duâ eder. (Tarih-i Bağdad)","osmanli":"اخيار"},{"kelime":"AHZÂB","anlam":"Topluluklar, fırkalar.","kategori":"dil","misal":"Hizb’in çokluk hâli.","osmanli":"احزاب"},{"kelime":"AHZÂB SûRESİ","anlam":"Kur’ân-ı kerîmin otuz üçüncü sûresi.","kategori":"dil","misal":"Medîne-i Münevvere’de inmiştir. Yetmiş üç âyet-i kerîmedir. Sûre, ismini, birleşik düşman ordusu anlamına gelen ahzâb kelimesinden almıştır. Sûrede İslâm düşmanlarının, İslâmiyet aleyhindeki çalışmaları ve sonunda hüsrana uğradıkları, Peygamber efendimize ve mü’minlere eziyet ve sıkıntı verenlerin şiddetli azaba uğrayacakları, Resûlullah efendimizin mübârek zevcelerinin ve diğer Müslüman âilelerin tesettüre (örtünme…","osmanli":"سى سوره احزاب"},{"kelime":"ÂİLE","anlam":"1.Zevce. 2.Akraba. 3.Ev halkı. 4.Aynı gaye için çalışanlar (Meselâ matbuat ailesi).","kategori":"dil","osmanli":"عائله"},{"kelime":"AKABE","anlam":"1.Sarp yokuş, tehlikeli geçit, aşılması zor dağ yolu, tepe. 2.Hicaz mıntıkasında Bi‘setten evvel mukaddes bilinen ve Medînelilerin Hazret-i Muhammed’e bî‘at ederek şehirlerine davet ettikleri belde.","kategori":"dil","misal":"Maksada ulaşmak, nefsi temizlemek için aşılması gereken engel. Akabenin ne olduğunu sen bilir misin? (Be-led sûresi: 12)","osmanli":"عقبه"},{"kelime":"AKÂİD","anlam":"İnanılacak şeyler, iman bilgileri.","kategori":"akaid","misal":"Akâidde, Ehl-i sünnet oldu mezhebim, hamdolsun Amelde, Ebû Hanîfe mezhebi, mezhebim vallah. (İbrâhim Hakkı Erzurumî)","osmanli":"عقائد"},{"kelime":"AKÂR","anlam":"Kendisinden istifade edilen arsa, tarla, ev gibi gayrımenkul.","kategori":"dil","osmanli":"عقار"},{"kelime":"AKÇE (Akça)","anlam":"Osmanlı Devletinin ilk zamanlarından itibaren Sultan Abdülmecid zamanına kadar kullanılan ve gümüşten basıldığı için ak (beyaz, parlak) para mânâsına bu ismi alan para.","kategori":"osmanli","misal":"Buyurdu akçeye sikke kazalar, Ki Osman bin Ertuğrul yazalar. (Hadîdî)","osmanli":"عقﭽه"},{"kelime":"AKD","anlam":"1.Bağlama. 2.Nikâh, alışveriş, kefâlet, havâle gibi taraflardan birinin teklifi, diğerinin kabulü ile gerçekleşen sözleşme, akid anlaşma.","kategori":"muamelat","osmanli":"عقد"},{"kelime":"ÂKİBET","anlam":"(Bkz. Âkıbet)","kategori":"dil","osmanli":"عاقبت"},{"kelime":"ÂKIBET (Âkibet)","anlam":"Son, netice. (Habîbim!) De ki: Yeryüzünde gezip dolaşın, sonra da bakın ki (peygamberleri) yalanlayanların âkıbeti nasıl olmuştur.","kategori":"akaid","misal":"sûresi: 11) O hâlde (Habîbim) sen de (Nûh gibi, kavminden gelen eziyetlere ve peygamberlik vazifesinin ağırlığına) sabret. Âkibet; hiç şüphesiz, takvâya erenlerindir (günahlardan sakınanlarındır). (Hûd sûresi: 49) Her ne kadar, yüz karası, yapdıysa ısyân sende, Âkıbet hayr olur elbet, cezbe-i tevhîd ile (Niyazî Mısrî)","osmanli":"عاقبت"},{"kelime":"AKÎD","anlam":"Akdi yapan taraflardan her biri.","kategori":"dil","osmanli":"عقيد"},{"kelime":"AKÎDE","anlam":"İnanılacak şey. Îmân ve i‘tikâd edilecek şey. (Bkz. Akâid, İ‘tikâd)","kategori":"akaid","osmanli":"عقيده"},{"kelime":"ÂKİF","anlam":"1.Bir şeyde sebat eden. 2.İbâ-det eden.","kategori":"dil","osmanli":"عاكف"},{"kelime":"AKÎK","anlam":"Kırmızı renkli, yarı saydam de-ğerli bir taş.","kategori":"dil","osmanli":"عقيق"},{"kelime":"AKÎKA","anlam":"1.Yeni doğan çocuğun başın-daki saç. 2.Çocuk nimetine karşılık, Allahü teâlâya şükr niyeti ile kesilen hayvan.","kategori":"akaid","misal":"(Çocuk doğduğunda) yedinci günü akîka hay-vanı kesilir, ismi konur, saçı traş edilir. (Ha-dîs-i şerîf-Tirmizî, Müsnedü Ahmed) Akîka, çocukları belâlardan, hastalıklardan ko-rur. Akîkası yapılanlar, kıyâmette anaya babaya ayrı bir şefâat ederler. (Şir‘atü’l-İslâm)","osmanli":"عقيقه"},{"kelime":"ÂKIL","anlam":"Akıllı, iyi ve kötüyü, faydalı ve zararlıyı birbirinden ayırabilen kimse.","kategori":"dil","misal":"Çocuk, yedi yaşında âkıl olur. Yedi ile onbeş yaş arasında iken akıllı çocuk denir. Âkıl olan bir çocuk, şeker, meyve gibi kendine yarar şey isterse ona satmak câiz değildir. Çünki velîsi izin vermemiş demektir. Eğer, tuz, pirinç gibi evle alâkalı bir şey isterse, satmak sahîh olur. Çünki velîsinin izin verdiği anlaşılır. Bunun izin ile alış-veriş etmesi câizdir. Çocuk akıllı olma-mış ise, velîsinin izni olsa da, alış-veriş etmesi sahîh olmaz. (Bey‘ ve Şirâ Risâlesi) Âkıl olmayan çocukların bütün sözleşmeleri bâtıldır, hükümsüzdür. Âkıl çocuk, bâliğ olana kadar, bağışlama, borç verme gibi aleyhine mu-ameleleri hiç yapamaz. Bağış kabulü gibi lehine akidleri izinsiz; alış-veriş, kirâ gibi hem lehine hem aleyhine olan akidleri ise velî veyâ vasîsi-nin izniyle yapabilir. (İbni Âbidîn)","osmanli":"عاقل"},{"kelime":"ÂKİL","anlam":"(Bkz. Âkıl)","kategori":"dil","osmanli":"عاقل"},{"kelime":"Âkıl Bâliğ","anlam":"Faydalı ve zararlı olanı birbirinden ayırabilen ve evlenme çağına gelip gusül abdesti almaya başlayan aklı başında erkek veya kadın.","kategori":"ibadet","misal":"Âkıl bâliğ her Müslümanın, namaz, oruç gibi ibadetleri yapması farzdır. İşlediği günahlardan mes’ûldür. Suç işlerse ceza verilir. Akidleri muteberdir. (İbni Âbidîn)","osmanli":"بالغ عاقل"},{"kelime":"ÂKILE","anlam":"Kasıt harici cinayetlerde diyet ödemeyi yüklenen kimseler.","kategori":"dil","misal":"Kâtilin beraber cihâd ile mükellef olduğu arkadaşları, yardımcılarıdır. Böyle yardımcıları olmayan kâtilin âkılesi, kabilesi, sonra akrabasıdır. Hanefî dışındaki mezheblere göre âkıle yalnızca kişinin baba yoluyla bağlı bulunduğu erkek akrabasıdır (asabesidir). Kadın, çocuk ve deli, âkıleye katılmaz. Müslüman kâtilin âkılesi ve vârisi yoksa diyetini beytülmâl; bu da yoksa kendi üç senede öder. Dârülharbde âkıle olma…","osmanli":"عاقله"},{"kelime":"AKÎM","anlam":"Neticesiz, muvaffak olunmayan.","kategori":"dil","osmanli":"عقيم"},{"kelime":"AKIN","anlam":"1.Keşf, yağma ve tahrip maksadıyla düşman topraklarına yapılan askerî hareket. 2.Kalabalık hâlde bir yere yönelme.","kategori":"dil","misal":"Bin atlı akınlarda çocuklar gibi şendik, Bin atlı o gün dev gibi bir orduyu yendik. (Yahya Kemal) Endülüs’te III. Abdurrahman zamanında ilim ve fen çok ilerledi. Her memleketten ilim öğ-renmek için Kurtuba’ya akın akın toplandılar. Kurtuba’da büyük ve mükemmel bir tıb fakül-tesi kurdu. Avrupa’da ilk yapılan tıb fakültesi budur. (Kâmûsü’l-A’lâm)","osmanli":"آقين"},{"kelime":"AKKÂD","anlam":"Akid yapan.","kategori":"dil","osmanli":"عقاد"},{"kelime":"Akl-ı Sakîm","anlam":"Kısa görüşlü akıl. Düşündükleri şeylerde ve yaptıkları işlerde yanılan ve çok kere pişmanlığa sebeb olan akıl.","kategori":"fikih","misal":"Akl-ı sakîm bazen doğruyu bulur, bazen yanılır. Yanılması daha çok olur. En akıllı denilen kimse, mütehassıs olduğu dünya işlerinde bile çok hatâ eder. Bu sebeble din ve sonsuz olan âhiret işlerinde akl-ı sakîme güvenilmez. Düşündükleri şeylerde ve yaptıları işlerde yanılır. Hepsi üzüntüye ve pişmanlığa, zarâra, sıkıntıya sebeb olur. (Abdülhakîm Arvâsî)","osmanli":"سقيم عقل"},{"kelime":"Akl-ı Selîm","anlam":"Selîm akıl, hiç yanıl-mayan, hatâ etmeyen akıl. İslâmiyet’i bilen ve ona uyan akıl, akl-ı me‘âd.","kategori":"dil","misal":"Akl-ı selîm, peygamberlerde aleyhimüsselâm bulunur. Onlar her başladıkları işte muvaffak olmuşlardır. Pişman olacak, zarar görecek bir şey yapmamışlardır. Eshâb-ı kirâmın, Tâbiînin, Tebe-i tâbiînin ve din İmâmlarının rıdvânul-lahi aleyhim ecmaîn akılları, derece bakımın-dan peygamberlerin akıllarından sonra gelir. Bunların akılları, din bilgilerinin hepsinin pek yerinde ve doğru olduklarını açıkça görür. Bu bilgileri bunlara ispat etmeye, açıklamaya lü-zum olmadığı gibi, tembih etmeye, haber ver-meye de lüzum yoktur. (Sevânihü’l-Enzâr-Ab-dülhakîm Arvâsî)","osmanli":"سليم عقل"},{"kelime":"AKR","anlam":"Kısırlık.","kategori":"dil","osmanli":"عقر"},{"kelime":"AKREB","anlam":"Daha yakın, en yakın.","kategori":"dil","osmanli":"اقرب"},{"kelime":"AKS","anlam":"Bir şeyi tersine çevirme.","kategori":"dil","osmanli":"عكس"},{"kelime":"Aks-i Sadâ","anlam":"Havada, suda yayıl-makta olan ses dalgalarının, duvar, kayalık gibi sert yüzeylere çarpınca, doğrultularını değiş-tirerek geriye dönüp, eşit vasıfta, kendini hâ-sıl eden birinci sesin hususiyetinde, meydana getirdiği ikinci ses, yankı.","kategori":"dil","osmanli":"صداء عكس"},{"kelime":"AKTÂB","anlam":"Tasavvufta yüksek derecelere ulaşmış mübârek, kıymetli zâtlar.","kategori":"tasavvuf","misal":"Kutb’un çokluk şeklidir. (Bkz. Kutb)","osmanli":"اقطاب"},{"kelime":"AKTÂR","anlam":"1.Yanlar, çaplar. 2.Attar, ıtır, baharat satan.","kategori":"dil","misal":"Kutr’un çok-luk hâli.","osmanli":"اقطار"},{"kelime":"ÂL","anlam":"Âile, akrabâ, sülâle; tâbî.","kategori":"dil","misal":"Duâ olsun âline dahi eshâbına, Tâbiîn, ensâr u hem ahbâbına. (Mevlid-i Süleymân Çelebi)","osmanli":"آل"},{"kelime":"Âl-i İmrân (Âlü İmrân)","anlam":"1.Süleymân aleyhisselâmın evlâdından İmrân bin Mâsân’ın kendisi veya onun kızı Hazret-i Meryem ile oğlu Hazret-i Îsâ. 2.Yâkûb aleyhisselâmın evlâdından İmrân bin Yeshâr ile oğulları Mûsâ ile Hârûn aleyhimesselâm.","kategori":"dil","misal":"İmrân âilesi. Gerçekten Allahü teâlâ, Âdem’i, Nûh’u, Âl-i İbrâhim’i, Âl-i İmrân’ı (peygamberlik, rûhî ve bedenî üstünlükler vermek sûretiyle kendi zamanlarındaki) âlemlerin üzerine mümtâz kıldı (seçti). (Âl-i İmrân sûresi: 33)","osmanli":"عمران آل"},{"kelime":"ÂL-İ İMRÂN SûRESİ (Âlü İmrân Sûresi)","anlam":"Kur’ân-ı kerîmin üçüncü sûresi.","kategori":"dil","misal":"Kıyâmet gününde Kur’ân-ı kerîm ve onunla amel edenler getirilirler. Kur’ân-ı kerîmin önünde (en uzun ve en çok hüküm bulunan sûrelerden oldukları için) Bakara ve Âl-i İmrân sûreleri bulunacaktır. Bu iki sûre sanki iki bulut yâhud aralarında bir nûr bulunan iki siyah gölgelik veya sahiplerini müdâfaa eden (savunan) saf bağlamış uçan iki kuş topluluğu gibi olacaklardır. (Hadîs-i şerîfMüslim)","osmanli":"سى سوره عمران آل"},{"kelime":"ALÂ KÜLLİ HÂL","anlam":"Her ha-lükârda, olabildiğince, mümkün mertebe, bü-tün hâllerdir.","kategori":"dil","osmanli":"حال كل على"},{"kelime":"ALÂKA","anlam":"Bir şeye, muhabbet veya husû-met suretiyle olan bağlılık, irtibat.","kategori":"dil","osmanli":"علاقه"},{"kelime":"ALÂMET","anlam":"1.İz, işaret, nişan. 2.Bir işin yapılmasını icap ettirmeyen, yapılmaması ile de işi yok etmeyen, ortadan kaldırmayan şey.","kategori":"fikih","misal":"Her şeyin vücûdü, yani var olması, bir işin yapılmasına bağlıdır. Bu bağlılık, beş türlü olur: İş, bu şeyin mahiyetinin içinde ise, onun bir parçası ise, bu işe, rükn denir. Dışında ise, bu şeye tesir ediyorsa, illet denir. Nikâh, evlenmenin illetidir. Tesir etmiyorsa, işin yapılması, bu şeyin vücûdünü icap ediyorsa, sebeb denir. Vakit, namazın sebebidir. İcap etmiyorsa, işin yapılmaması ile, o şey de yok olursa, şa…","osmanli":"علامت"},{"kelime":"ALDANMAK","anlam":"Kandırılmak; hîle su-retiyle akdin unsurlarında yanıltılmak. (Bkz. Gaben)","kategori":"dil","misal":"Aldatan ve aldanan bizden değildir. (Hadîs-i şerîf-Taberânî, Râfiî) Alışverişte aldatmak çeşitli şekillerde olur. Bi-rincisi malı olduğundan aşırı övmektir. İkincisi malın ayıbını, müşterîden gizlemektir. Üçün-cüsü ölçüde hîle etmek, doğru ölçmemektir. Dördüncüsü satış fiyatında hîle yapmaktır. Bunların hepsi haramdır. Bu aldatma belli bir nisbetin üzerinde ise, aldanan kimse, akdi bo-zabilir. Alışveriş yapan kimsenin, uyanık ol-ması; aldanmaması gerekir. (Kimyâ-i Seâdet)","osmanli":"آلدانمق"},{"kelime":"ÂLEM","anlam":"Allahü teâlâdan başka her şey, Allahü teâlânın yarattığı şeylerin hepsi, kâinât, varlıklar.","kategori":"akaid","misal":"Elbette Allahü teâlânın bu âlemlere hiç ihtiyâcı yoktur. (Ankebût sûresi: 6) Bütün varlıklar, Allahü teâlânın varlığına alâmet olduğu, O’nun varlığını gösterdiği için, mahlûkların hepsine “Âlem” denmiştir. Varlıkların aynı cinsten olanlarının her birine de, âlem, meselâ, insanlar âlemi, melekler âlemi, hayvanlar âlemi, cansız maddeler âlemi denir. (Mevâkıf)","osmanli":"عالم"},{"kelime":"ALEM","anlam":"1.Nişan, alâmet. 2.Has isim. 3.Bayrak, sancak. 4.Minare ve minber üs- tündeki hilâl.","kategori":"fikih","osmanli":"علم"},{"kelime":"Âlem-i Ecsâd","anlam":"“Cesedler âlemi” mânâsına yerler, dağlar, gökler gibi, ölçülebi-len ve tartılabilen madde âlemi. Buna âlem-i halk, âlem-i şehâdet ve âlem-i mülk de denir.","kategori":"muamelat","osmanli":"اجساد عالم"},{"kelime":"Âlem-i Emr","anlam":"Arşın üstünde olup, madde olmayan, ölçülemeyen ve herkesin anlayamayacağı âlem. Buna, âlem-i melekût","kategori":"akaid","misal":"ve âlem-i ervâh (ruhlar âlemi) ve mekânsız-lık âlemi de denir. Âlem-i halkın ötesi, âlem-i emrdir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"امر عالم"},{"kelime":"Âlem-i Ervâh","anlam":"Ruhlar âlemi. (Bkz.","kategori":"akaid","misal":"Âlem-i Emr)","osmanli":"ارواح عالم"},{"kelime":"Âlem-i Kebîr","anlam":"“Büyük âlem” mânâ-sına insandan başka bütün mahlûkât, kâinât ve içindekiler.","kategori":"dil","misal":"Âlem-i kebîrdeki mahlûkların en şereflisi ve en büyüğü Arş’dır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"كبير عالم"},{"kelime":"Âlem-i Melekût","anlam":"Melekût (hükümdarlık, azamet) âlemi; madde, his, akıl, ölçü âleminin üstündeki âlem; Allahü teâlânın mutlak hükümran olduğu âlem.","kategori":"akaid","misal":"Ruhlar ve melekler âlemi.","osmanli":"ملكوت عالم"},{"kelime":"Âlem-i Sagîr","anlam":"Küçük âlem; yara-tılmışların hepsinden kendisinde bir nümûne bulunduğu için insana verilen ad.","kategori":"dil","misal":"İnsan, âlem-i kebîrdeki (insan dışında bulu-nan âlemdeki) her şeyi kendinde topladığından, mahlûkların (yaratılan varlıkların) en kıymet-lisi olduğu gibi, kalb de âlem-i sagîrde bulunan her şeyi kendinde topladığı için çok kıymetli-dir. Kalbe Âlem-i asgar (en küçük âlem) ismi verilmektedir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"صغير عالم"},{"kelime":"ÂLET","anlam":"Bir işi yapmaya yarayan şey, vâsıta.","kategori":"dil","osmanli":"آلت"},{"kelime":"ALEVÎ","anlam":"1.İlk devirlerde Hazret-i Ali’nin halîfeliğini müdafaa eden ve bu hususta kendisinin yanında yer alan. 2.Hazret-i Ali’nin soyundan gelen. 3.Hazret-i Ali’nin diğer sahâbîlere üstünlüğü etrafında teşekkül eden ve giderek Ehl-i sünnet itikadından uzaklaşan dinî fırkaya mensub.","kategori":"dil","misal":"“Ali’ye mensub” mânâsına","osmanli":"علوى"},{"kelime":"ALEYHİMÜRRIDVÂN","anlam":"“Allahü teâlânın rızâsı onların üzerine olsun” veya “Allahü teâlâ onlardan râzı olsun” mânâsına ikiden fazla Eshâb-ı kirâmın ismi anıldığında, işitildiğinde ve yazıldığında söylenen ve yazılan duâ ve hürmet ifâdesi.","kategori":"akaid","misal":"Bir kişi için aleyhirrıdvân, iki kişi için aleyhimerrıdvân denir.","osmanli":"الرضوان عليهم"},{"kelime":"ALEYHİSSELÂM","anlam":"“Allahü teâlânın selâmı onun üzerine olsun” mânâsına peygamberler ve dört büyük melek için kullanılan","kategori":"dil","misal":"duâ ve ta‘zim ifâdesi. İki kişi için aleyhimesselâm, daha çok kişi için aleyhimüsselâm denir.","osmanli":"السلام عليه"},{"kelime":"ÂLÎ","anlam":". Pek yüksek.","kategori":"dil","osmanli":"عالى"},{"kelime":"ALÎM","anlam":"1.Her şeyi devamlı ve eksiksiz bilen. 2.Her şeyin zâhir ve bâtınını, başını ve sonunu tam ve külli ihâta ile ve dakîk bir şe-kilde bilen mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Alîm). Âlim’den farkı sıfat-ı müşebbihe oluşudur. Böylece devamlılığa, ezelî ve ebedîliğe delâlet eder. Âlim ise mu-ayyen bir zaman ve muayyen bir hususu bil-meyi ifade eder. O, her şeyi alîmdir. (Hadîd sûresi: 5) El-Alîm ism-i şerîfini söylemeye devam edene mânevî sırlar açılır, hikmet ve mârifete kavu-şur. (El-İstigâsetü’l-Kübrâ)","kategori":"akaid","osmanli":"عليم"},{"kelime":"ÂLİM","anlam":"1.Bilen, ilim sahibi, mütehassıs. 2.Allahü teâlânın sıfatlarından.","kategori":"dil","misal":"Allahü teâlâ gizliyi de âşikar olanı da âlim-dir. (Haşr sûresi: 22) Ümmetimin âlimlerine hürmet ediniz. Onlar peygamberlerin vâris-leridir. (Hadîs-i şerîf-Buhârî) Âlimin yüzüne bakmak ibâdettir. (Hadîs-i şerîf-Deylemî) Ya âlim, ya talebe, yâhud bunları dinleyici ol. Bu üçten olmazsan helâk olursun. (Hadîs-i şerîf-Müsnedü Ahmed)","osmanli":"عالم"},{"kelime":"ALIN YAZISI","anlam":"Talih, kader. İnsa-","kategori":"akaid","misal":"nın başına gelecek şeylerin doğmadan alnına yazıldığı için bu ismi almıştır. Allahü teâlâ, nutfeden bir insan yaratmak murad ettiğinde, emrettiği melek o insanın alnına, karşılaşacağı iyilik ve kötülük, hatta göreceği meşakkate kadar hepsini yazar. (Hadîs-i şerîfDâre Kutnî)","osmanli":"يازيسي آلين"},{"kelime":"ALİYY","anlam":"1.Yüce. 2.Mahlûkâtın akıl, ilim ve anlayışlarının erişemediği yücelikte; hem zâtı, hem sıfatı büyük olan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elAliyy). “O (Allah) Aliyy’dir, Hakîm (her işinde hikmet sahibi) dir. (Şûrâ sûresi: 51) ElAliyy ism-i şerîfini söyleyen, işlerinde muvaffak olup ilerler. (Elİstigâsetü’l-Kübrâ)","kategori":"akaid","osmanli":"على"},{"kelime":"ALKIŞ","anlam":"1.Teşvik, yüreklendirme; övme. 2.El çırpma.","kategori":"dil","osmanli":"آلقيش"},{"kelime":"ALKOL","anlam":"Mayalanmış şekerli sıvıların damıtılmasıyla elde edilen, İslâmiyet’te içilmesi yasaklanan ve üzerine dirhem mikdarından fazlası bulaştığında namaza mâni olan sıvı.","kategori":"ibadet","misal":"(Arabca elkuhl’den.)","osmanli":"آلقول"},{"kelime":"ALLAH (Celle Celâlühû)","anlam":"Her şeyi yoktan var eden yüce yaratıcı; varlığı muhakkak lâzım olan, iman ve ibâdet edilecek hakîkî mâbûd.","kategori":"akaid","misal":"Allahü teâlânın isimlerinden çoğu, mecaz olarak insanlar için de kullanılabilir ise de, bu isim, ifade ettiği ilâhî mânâ itibarıyla yalnız Allah’a aittir. Başka hiçbir kelime bu ismin mânâ ve muhtevasını ifade edemez. Bu isim başkası için de kullanılamaz. O, göklerin, yerin ve ikisi arasında bulunanların Rabbidir. Öyleyse O’na ibadette, kulluk etmekte sabırlı ol. Hiç O’nun ismine benzeyen bir şey var mı? (Meryem sûr…","osmanli":"جلاله الله"},{"kelime":"ALLAHSIZ","anlam":"Ateist, Tanrı tanımaz.","kategori":"dil","osmanli":"اللهسز"},{"kelime":"ALLAHÜ EKBER","anlam":"“Allahü teâlâ en büyüktür!” mânâsına bir zikr.","kategori":"akaid","misal":"İki kelime vardır ki, onlardan birinin arşa varmasına mâni yoktur. Diğeri ise yerle gök arasını doldurur. “Lâ ilâhe illallah ve Allahü ekber.” (Hadîs-i şerîfTaberânî) Hayvan keserken, av hayvanına ok atarken, ava ta‘lîm edilmiş köpeği gönderirken, Bismillâh veya Allahü ekber demek vâcibdir. Besmeleyi tamam söylemek de olur. (İbni Âbidîn)","osmanli":"اكبر الله"},{"kelime":"ALLÂHÜMME","anlam":"Duâların başında geçen ve “Allâh’ım!”, “Yâ Allâh!” mânâsına gelen bir nida, yakarış ve yardım dileme, istimdâd cümlesi.","kategori":"akaid","misal":"Cümlenin sonundaki mim, “Yâ” nidâ harfinden bedeldir.","osmanli":"اللهم"},{"kelime":"ALLÂM","anlam":"1.Çok çok bilen. 2.Allahü teâlânın sıfatlarından.","kategori":"dil","misal":"Mübâlağalı ism-i fâilidir.","osmanli":"علام"},{"kelime":"ALLÂME","anlam":"Çok bilen. Âlim kelimesinin mübâlağalı ismi fâilidir.","kategori":"dil","misal":"(Bkz. Âlim)","osmanli":"علامه"},{"kelime":"ALLÂT","anlam":"Ana ayrı, baba bir kardeşler.","kategori":"dil","osmanli":"آلات"},{"kelime":"ALTIN","anlam":"Tabiatta serbest olarak bulu-nan yumuşak, parlak sarı renkte üstün işleme","kategori":"dil","misal":"kabiliyeti olan ziynet ve para basmakta kulla-nılan kıymetli bir maden. Altun. İslâmiyet’te para altın ve gümüş olarak hesabla-nır. Para ile yapılan alışverişlerde, paranın de-ğeri düşse veya geçmez olsa, altın kıymeti ve-rilir. (İbni Âbidîn)","osmanli":"آلتون"},{"kelime":"ALTIN OLuK","anlam":"Kâbe’nin damına konulan su oluğu.","kategori":"dil","osmanli":"اولوق آلتون"},{"kelime":"AMD","anlam":"Kasıt, bir işi düşünerek, planla-yarak, bilerek yapma, taammüd.","kategori":"dil","osmanli":"عمد"},{"kelime":"AMDEN","anlam":"Kasten, bilerek, bile bile, ta-ammüden yapmak.","kategori":"dil","misal":"Erkek veya kadın, bir müslüman, âlimlerin söz-birliği ile küfre sebeb olacağını bildirdikleri bir sözün veya işin küfre sebeb olduğunu bilerek, amden (tehdîd edilmeden, istekle) ciddî ola-rak veya hezl, güldürmek için söyler, yaparsa, mânâsını düşünmese dahî îmânı gider. Mür-ted olur. Buna küfr-i inâdî denir. (Berîka, Ha-dîka, Mecmâ’ül-enhür) Bir kimseyi amden öldüren kısas edilir. Ölenin vârisleri diyete razı olursa, kısas düşer. Amden katl haricindeki öldürmelerde kısas olmaz; di-yet ödenir. (İbni Âbidîn)","osmanli":"عمدا"},{"kelime":"AMED","anlam":"Ricâl-i gayb denilen ve Allahü teâlânın insanlardan gizlediği evliyâ zâtlardan. (Aslı başlıca nokta, direk, aşk hastası, önder mânâsına ‘amîd’ kelimesidir.)","kategori":"akaid","misal":"İnsanlara bir şey lâzım olunca önce Nükâba, sonra Nücebâ, sonra Ebdâl duâ eder. Yine ka-bul olmazsa, Ahyâr duâ eder. Yine kabul ol-mazsa Amed duâ eder. Amed dört kişidir. Ka-bul olmazsa Gavs duâ eder. Bunun duâsı elbet kabul olur. (Tarih-i Bağdad)","osmanli":"عمد"},{"kelime":"ÂMED","anlam":"Geliş.","kategori":"dil","osmanli":"آمد"},{"kelime":"AMEL","anlam":"1.İş. 2.İbâdet.","kategori":"akaid","misal":"Herkes yaradılışına göre amel eder. Rabbi-niz kimin doğru yolda olduğunu bilir. (İsrâ sûresi: 84) Allahü teâlâ sûretlerinize ve amel-lerinize bakmaz; kalblerinize ve niyetleri-nize bakar. (Hadîs-i şerîf-Müslim, İbn-i Mâce) Ameller, niyete göre iyi veya kötü olur. (Ha-dîs-i şerîf-Buhârî, Müslim)","osmanli":"عمل"},{"kelime":"Amel Defteri","anlam":"İnsanların dünya hayatında yaptığı bütün işlerinin yazıldığı ve Arasat meydanında herkesin eline verilecek olan defter.","kategori":"tasavvuf","misal":"Kur’ân-ı kerîmde “kitap” tabiriyle zikredilir: İşte o vakit kitabı (amel defteri) sağ eline verilmiş olan kimse der ki: ‘Gelin kitabımı okuyun. Çünki ben hesabıma ulaşacağımı (hesaba çekileceğimi) zannetmiştim! Artık o hoşnud bir hayatta yüksek bir cennettedir. Kitabı sol eline verilmiş olan ise, der ki: Eyvah, keşke kitabım bana verilmeseydi... Hesabımın da ne olduğunu bilmeseydim! Tutun onu, hemen bağlayın, sonra…","osmanli":"دفترى عمل"},{"kelime":"Amel-i Kalîl","anlam":"“Az iş” mânâsına namaz kılarken namazdan sayılmayan, namazı bozmayan, fakat mekrûh olan hareket.","kategori":"ibadet","misal":"Namazda elbisesini yukarı çekmek, takkesini düzeltmek gibi gibi amel-i kalîl mekrûhtur. (İbni Âbidîn)","osmanli":"قليل عمل"},{"kelime":"Amel-i Kesîr","anlam":"“Çok iş” mânâsına namaz kılarken, namazdan olmayan ve namazı bozan hareket.","kategori":"ibadet","misal":"Amel-i kesîr namazı bozar. Ceketini çıkarmak, çorap giymek, taranmak, konuşmak, yürümek, bir şey yemek gibi, uzaktan bakanın, namaz kılanın namazda olmadığı kanaatine vardığı iş amel-i kesir, namazda olduğundan şüphe ettiği iş amel-i kalildir. (İbni Âbidîn)","osmanli":"كثير عمل"},{"kelime":"Amel-i Sâlih","anlam":"“İyi amel”, “faydalı iş” mânâsına Allahü teâlânın râzı olduğu, beğendiği iş, ibâdet.","kategori":"akaid","misal":"Erkek ve kadından her kim mü’min olarak amel-i sâlih işlerse, işte onlar Cennet’e girerler, orada hesâbsız olarak, rızıklandırılırlar. (Mü’min sûresi: 40) Bir kimse, zulm yani günah işleyip, sonra tövbe eder amel-i sâlih işlerse, Allahü teâlâ tövbesini elbette kabul eder. (Mâide sûresi: 39) Rabbine kavuşmak isteyen bir kimse, amel-i sâlih, işlesin ve Rabbine kullukta hiç ortak koşmasın. (Kehf sûresi: 110) İnsan kabr…","osmanli":"صالح عمل"},{"kelime":"Amelde Mezheb","anlam":"Mutlak müc-tehid denilen âlimin, amelî esaslara dair iş ve hususlarda, Kur’ân-ı kerîm, hadîs-i şerîf, icmâ ve kıyasa dayanarak çıkardığı hükümler. (Bkz. Mezheb, Müctehid)","kategori":"hadis","misal":"Amelde mezheblerin hak olanı dörttür. Bun-lar: Hanefî, Şâfiî, Mâlikî ve Hanbelî mezheb-leridir. Bu dört mezheb, itikad (inanç) bakı-mından birbirlerinden ayrı değildir. Yalnız amel bakımından bazı ufak şeylerde ayrıl-mışlardır. Böyle ayrılmaları Allahü teâlânın rahmeti olup, Müslümanlar için kolaylıktır.","osmanli":"مذهب عملده"},{"kelime":"ÂMÎ","anlam":"1.Avâma mahsus, halkla alâkalı. 2.Müctehid olmayan. 3.İlim sahibi olmayıp mezhebden anlamayan.","kategori":"dil","misal":"(Bkz. Avâm) Oruçlu iken hacâmat yapmak, Hanefî mezhe-binde orucu bozmaz. Bozuldu zan ederek bir şey yerse, kazâ ve keffâret lâzım olur. Orucun bozulmadığını bilmeyecek kadar câhil olana âmî denir. Hanbelî müftîsi bozuldu dedi ise, sonra, bir şey yiyince, keffâret lâzım olmaz. Çünki, avâmın mezhebi, sorduğu müftînin mezhebi-dir. (İbni Âbidîn)","osmanli":"عامى"},{"kelime":"ÂMİL","anlam":"1.İş yapan, amel eden; işçi. 2.Zekât, harâc ve öşür toplamakla vazifeli memur.","kategori":"hadis","misal":"Allahü teâlâ sizden ilmi almak için, ilmiyle âmil olan âlimleri kaldırır, câhiller kalır. (Bunlar) dinden suâl edenlere, kendi akıl-ları ile cevap verip insanları doğru yoldan ayırırlar. (Hadîs-i şerîf-Buhârî) Sadakalar (zekâtlar), Allahü teâlâdan bir farz olarak, ancak fakirlere, miskinlere, âmillere kalbleri Müslümanlığa ısındırılmak isteni-lenlere, (efendisinden kendisini satın alıp, bor-cunu ödeyince âzâd olacak) kölelere, borç-lulara, cihâd ve hac yolunda olup, muhtaç kalanlara, (kendi memleketinde zengin ise de, bulunduğu yerde yanında mal kalmamış ve çok alacağı varsa da alamayıp muhtaç dü-şen) yolda kalmışlara mahsûstur. (Tevbe sû-resi: 60) Halka zulmeden âmiller Cennet’e gi-remez. (Hadîs-i şerîf-Kitâbü’l-Emvâl)","osmanli":"عامل"},{"kelime":"ÂMÎN","anlam":"“Kabul et” mânâsına, duâ sonunda söylenen söz.","kategori":"ibadet","misal":"Her kim namazdan sonra imâm ile duâ edip, âmîn derse, âmîn kelimesinin harfleri dörttür, her harfine bin melek nâzil olur. Bunlar kıyâmet gününe kadar bu kimse için duâ ederler. (Hadîs-i şerîfHâkim) Cemaatle namaz kılarken imâm “Veleddâllîn” deyince, imâm ve cemaatin ve yalnız kılanın, kendisi Fâtiha-i şerîfeyi bitirdikte, yavaşça âmîn demeleri sünnettir. (Halebî-yi Sagîr)","osmanli":"آمين"},{"kelime":"ÂMİR","anlam":"1.Emreden. 2.Yerine birini vekil tayin eden kimse, müvekkil. 3.Kendisi hacca gidemeyip, yerine başkasını gönderen kimse. 4.Külfetsizce ziraat yapılan arâzî; işlenmemiş arâzî.","kategori":"ibadet","osmanli":"آمر"},{"kelime":"ÂMM","anlam":"1.Umumî. 2.Tek bir mânâ ifade etmek üzere konmuş ve muayyen bir mikdarla tahdit edilmeksizin bu mânâ kendisinde gerçekleşen bütün fertleri içine alan, herkese şâmil lafız, tefsir kâidesi. Hırsızlık cezasını tanzim eden âyet-i kerîmede hırsız lafzı âmmdır. Kendisinde hırsızlık fiilinin gerçekleştiği bütün ferdlere şâmildir. Âmmın ifade ettiği mânâya delâleti kat‘îdir, zannî değildir. Ama tahsîse, sınırlandırmaya gelebilir. Nitekim âyet-i kerîmede geçen hırsızın, gizlice alan hırsız olduğu hadîs-i şerîf ile bildirilerek âmm, tahsis edilmiş, sınırlandırılmıştır. Ancak bazı âmm lafızlar tahsîse, sınırlan…","kategori":"dil","osmanli":"عام"},{"kelime":"ÂMME","anlam":"Umum, kamu.","kategori":"dil","osmanli":"عامه"},{"kelime":"ÂMMÎ","anlam":"İnsanların avâmından; tahsil görmemiş, câhil.","kategori":"dil","osmanli":"عامى"},{"kelime":"AMûD","anlam":"Direk, sütün.","kategori":"dil","osmanli":"عمود"},{"kelime":"ANARŞİ","anlam":"Siyasî ve idarî müesseselerdeki çözülme sebebiyle devlet kontrolünün kalmaması, kargaşa, başıboşluk.","kategori":"fikih","osmanli":"آنارشى"},{"kelime":"ANÂSIR","anlam":"Unsur’un çokluk hâli.","kategori":"dil","osmanli":"عناصر"},{"kelime":"ANÎD","anlam":"Hakkı, doğruyu inatla redde-den, azgın, zorba.","kategori":"dil","misal":"Her anîd, hüsrana uğradı. (İbrâhim sûresi: 15)","osmanli":"عنيد"},{"kelime":"ANKÂ","anlam":"1.Şark mitolojisinde ismi var, cismi yok bir kuş, Zümrüd-i Ankâ Simürg. 2.(Mecaz) Çok nâdir bulunan.","kategori":"dil","misal":"Husûlde uzaklık vardır. Vüsûl ise çok güçtür. Ankâ kuşunu, kendimize göre bir şekil vererek düşünürsek, hâfızamızda Ankâ hâsıl oldu de-nebilir. Fakat Ankâya vâsıl olunmamıştır. Ankâ avlanamaz, tuzağını topla! Bu avdan tuzakta kalır ancak hava. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عنقاء"},{"kelime":"ANKEBûT SûRESİ","anlam":"Kur’ân-ı kerîmin yirmi dokuzuncu sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Altmış do-kuz âyet-i kerîmedir. Sûrede; putlara ve diğer güçsüz varlıklara tapanların hâlleri, onların dünyalık elde etmek için kurdukları tuzak ve gayretleri, pek zayıf olan ankebût (örümcek) ağına benzetildiğinden, bu kelime sûreye isim olmuştur. Sûrede, mü’minlerin Allah yolunda bazı sıkıntılara uğrayacaklarına, bunun, ken-dileri için dünya ve âhirete âit fâidelere vesîle olacağına işâret olunmakta, bazı peygamber-lerin kıssaları kısaca anlatılarak, onların Al-lah yolundaki fedâkarlıkları ve netîcede mu-vaffak oldukları gözler önüne konulmakta, Kur’ân-ı kerîmin büyük bir mûcize olduğu ve insanlık için fazîlet vesîlesi olduğu beyân edil-mekte, İslâmiyet’e cephe alanların acı sonları bildirilmekte, Müslümanların, âhirette ebedî nimetlere kavuşacakları müjdelenmekte, Al-lah yolunda çalışanların emeklerinin boşa gitmeyeceği, büyük mükâfatlara kavuşacak-ları ve daha başka hususlar bildirilmektedir. (Mefâtihü’l-Gayb) ANT (And): آند (T) Söz verme. Yemîn. Allah’a ant içiyorum demek yemîn olur. (Bkz. Yemîn)","osmanli":"سى سوره عنكبوت"},{"kelime":"ANTÂRÎ (Entâri)","anlam":"Erkek ve kadınların giydiği topuklara kadar inen elbise.","kategori":"osmanli","misal":"Resûlullah aleyhisselâm baş örtüsü ile başını örter, antârî, tasmalı ayakkabı ve benzerlerini giyerdi. Halîfe Ömer radıyallahü anh da, Azerbaycan’daki askerlerine mektup yazarak, böyle giyinmelerini emreyledi. Fakat şimdi, böyle giyinmek âdet değildir. Memlekette âdet olan şeyler giyilmezse, şöhret olur. Parmakla gösterilmeye, fitneye sebeb olur. Hadîs-i şerîfte; “İnsanın parmakla gösterilmesi, kendisine kötülük ola…","osmanli":"انتارى"},{"kelime":"ARAB","anlam":"Nûh aleyhisselâmın Sâm adlı oğlunun soyundan gelen tarihin en eski kavimlerinden biri.","kategori":"dil","misal":"Arabı üç şeyden dolayı sevin: Ben Arabım; Kur’ân-ı kerîm Arabcadır; Cennet ehlinin dili Arabcadır. (Hadîs-i şerîfHâkim). Allah katında en kıymetliniz, takvâsı çok olanınızdır. Arabın Arab olmayana bir üstünlüğü yoktur. Üstünlük ancak takvâ iledir. (Hadîs-i şerîfBuhârî, Müslim)","osmanli":"عرب"},{"kelime":"Arab-ı Âribe","anlam":"Arab kavminin ikinci safhasını teşkil edenler, Arab-ı Bâ‘i-de’den sonra Yemen’e yerleşip Himyer Devle-ti’ni kuran Kahtân evlâdları.","kategori":"dil","osmanli":"عاربه عرب"},{"kelime":"Arab-ı Bâ‘ide","anlam":"Arab kavminin ilk ataları olup, Âd, Semûd ve Amâlika gibi, Nûh aleyhisselâmdan sonra Arabistan yarımadasında yerleşenlere verilen isim.","kategori":"dil","osmanli":"باعده عرب"},{"kelime":"Arab-ı Müsta‘cime","anlam":"Arab kavminin dördüncü safhasıhı teşkil edenler olup, İslâm dininin doğmasından sonra, bu dini yaymak, Allahü teâlânın ismini yüceltmek için dünyanın diğer memleketlerine giderek başka milletlerle karışmasından meydana gelenler.","kategori":"akaid","osmanli":"مستعجمه عرب"},{"kelime":"Arab-ı Müsta‘ribe","anlam":"Arab kavminin üçüncü safhasını teşkil edenler olup, İsmâil aleyhisselâmın oniki evlâdının Arab-ı Âribe ile karışmasından meydana gelenler; Benî Adnan, bundan Mudar, Hevâzin, Sakîf, Temîm, Müzeyne ve Kureyş kabileleri.","kategori":"dil","osmanli":"مستعربه عرب"},{"kelime":"ARABÎ AYLAR","anlam":"1.Muharrem, 2.Safer, 3.Rebî’ul-evvel, 4.Rebî’ul-âhir, 5.Cemâzi’l-ev- vel, 6.Cemâzi’l-âhir, 7.Receb, 8.Şa‘bân, 9.Ra- mazan, 10.Şevvâl, 11.Zilka‘de, 12.Zilhicce.","kategori":"dil","misal":"Hicrî senenin on iki ayı (Bkz. Kamerî Aylar) Hicrî takvimde kullanılan Arabî ayların adları sırasıyla şunlardır: ARABÎ SENE: سنه عربى (T) Hicrî kamerî sene. Muharrem ayı ile başlayan ve Zilhicce ile sona eren, ayın dünya etrafındaki 12 devri ile tamam- lanan sene. 354 gün. (Bkz. Hicrî Kamerî Sene) A‘RÂF: اعراف (A) Cennet ile Cehennem’i bir-birinden ayıran yerdeki surun yüksek kısmı- nın adıdır.","osmanli":"آيلر عربى"},{"kelime":"ARAFÂT","anlam":"Mekke-i Mükerreme şehrinin yirmi beş kilometre güneydoğusunda haccın farzlarından vakfenin yapıldığı yer.","kategori":"dil","misal":"Arefe günü Arafât’ın (Vâdî-yi Urene) denilen yerinden başka her hangi bir yerinde, öğle ve ikindi namazlarından sonra bir mikdar vakfeye durmak farzdır. Bu gün bir an için bile olsa Arafât’ta bulunmayan hacı sayılmaz. (İbni Âbidîn, Mevkûfât) Resûlullah aleyhisselâm vefâtına yakın meşhur vedâ hutbesini Arafât’ta okudu. Âdem aleyhisselâm ile Havva vâlidemiz Cennet’ten ayrılıp yeryüzüne indirilince Arafât’ta buluştular…","osmanli":"عرفات"},{"kelime":"ARAK","anlam":"1.Ter. 2.Üzüm ve sâireden da-mıtılarak elde edilen ispirto, rakı.","kategori":"dil","misal":"Arak-ı hamr (ispirto), şarap gibi kaba necâset-tir. Sarhoş edecek kadar içene had vurulması sözbirliği ile bildirildi. Damlasını içene de had vurulur diyenler çoktur (İbni Âbidîn)","osmanli":"عرق"},{"kelime":"ARASÂT","anlam":"Öldükten sonra insan-ların ve diğer canlıların diriltilip toplanacak-ları meydan. Mevkıf, mahşer. (Bkz. Mahşer) Kıyâmet günü eshâbımdan herbiri, kabir-lerinden kalkarken, vefât ettiği memleke-tin bütün mü’minlerinin önlerine düşerek ve onları nûr ve ışık saçarak Arasât meyda-nına götürür. (Hadîs-i şerîf-Tirmizî) Kıyâmette herkes Arasât meydanında elli mev-kıfte (konakta) durdurulur. Her konak yerinde bin sene kalırlar. (Kadızâde-Âmentü Şerhi) Arasât meydanında meşakkat (zorluk) ve sıkın-tıda olanlar, kâfirler ile fâsıklardır (günahkâr-lardır). Onların hâlleri çok korkunç olup, gü-neş başlarına bir mil kadar yakın gelir. Herkes günahı kadar terler. Kimi dizine, kimi boğa-zına, kimi tepesine kadar ter içine gömülürler. (Birgivî Vasîyetnâmesi)","kategori":"hadis","osmanli":"عرصات"},{"kelime":"ARÂYÂ","anlam":"1.Bir kimsenin, hurma ağa-cını, fakir birine hurmasından istifade etmesi için bir yıllığına âriyet vermesi. 2.Taze hurma-nın dalında iken kuru hurma ile tahminî ola-rak alınmasına dair kıyasa muvafık olmamakla beraber elinde taze hurması olmayanların isti-fadesi için istihsanen câiz görülmüş bir akid. Âriyye’nin çokluk hâli.","kategori":"fikih","osmanli":"عرايا"},{"kelime":"ARÂZÎ","anlam":"Toprak. Arz’ın çokluk hâli.","kategori":"muamelat","osmanli":"اراضى"},{"kelime":"AREFE","anlam":"Zilhicce ayının dokuzuncu günü, kurban bayramından bir önceki gün.","kategori":"ibadet","misal":"Rivâyete göre Âdem aleyhisselâm ile Hazret-i Havvâ Cennet’ten çıkarıldıktan sonra bu gün Arafat’da buluşup birbirini tanıdıkları için ‘bildi’, ‘tanıdı’ mânâsına bu ismi almıştır. Duânın efdali Arefe günü yapılanıdır. (Hadîs-i şerîfMuvattâ) Arefe ne güzel gündür. O günde Allah semâya nüzûl eder (Rahmetle tecellî eder). (Hadîs-i şerîfDeylemî))","osmanli":"عرفه"},{"kelime":"Arefe Gecesi","anlam":"Arefe günü ile Kurban bayramının birinci günü arasındaki, yani Zilhicce ayının dokuzuncu ve onuncu geceleri arasındaki gece.","kategori":"ibadet","misal":"Mübarek gecelerden. Allah Arefe gecesine hayır yağdırır. (Hadîs-i ŞerîfDeylemî)","osmanli":"سى كيجه عرفه"},{"kelime":"ARGO","anlam":"1.Bir meslek veya topluluk arasında konuşulan hususî dil. 2.Umumiyetle ayak takımı ve kabadayıların, ana dillerinden bozduğu kelimeler ile yabancı dillerden alıp değiştirdiği sözlerden meydana gelen konuşma dili.","kategori":"dil","osmanli":"آرغو"},{"kelime":"ÂRÎ","anlam":"1.Çıplak, uzak. 2.Arınmış; temiz. 3.Hür. 4.Hind-Avrupa dil ailesinden olan.","kategori":"dil","misal":"Hac için, ihrâma niyet farzdır. İhrâm bezi tu-tunmak sünnettir. Dikilmiş esvâbdan ârî bu-lunmak vâcibdir. (Ni‘met-i İslâm) Doğrudan doğruya Allahü teâlâya teveccüh ederek, her ân nâzil olan feyz-i ilâhîden nasip alabilmek için, kalbin gafletten uyanık, dünya düşüncelerinden ârî olması lâzımdır. Böyle ol-mayan ve küfr, bid‘at ve günah zulmetleri ile kararmış olan kalbler, Allahü teâlâya teveccüh edemez. (Mektûbât-ı İmâm-ı Rabbânî) Şeriat sırâtı ile, nefs âteşinden geçip, Kalbi habâisden ârî, Ravda-i Rıdvân gerek! (Niyazî Mısrî)","osmanli":"عارى"},{"kelime":"ÂRİF","anlam":"1.Gönülle bilen, tanıyan, irfan sahibi. 2.Allahü teâlâyı tanımış; tasavvufta ye-tişip, kemâle ermiş velî zât, Ârif-i billah.","kategori":"akaid","misal":"Her şeyin kaynağı vardır. Takvânın (Allahü teâlâdan korkarak haramlardan, günahlardan sakınmanın) kaynağı âriflerin kalbleridir. (Hadîs-i şerîf-Taberânî) Âriflerin kalbleri Hak teâlânın azamet ve kib-riyâsına (büyüklük ve ululuğuna) hayrandır. Ârif kendini herkesten aşağı bilir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عارف"},{"kelime":"ÂRIZ","anlam":"Sonradan ortaya çıkan şey.","kategori":"dil","osmanli":"عارض"},{"kelime":"ARÎZA","anlam":"Küçük makamdan büyüğe arzedilen şey, yazılan yazı, istidâ, dilekçe.","kategori":"dil","osmanli":"عريضه"},{"kelime":"ARPA","anlam":"Buğdaygiller familyasından, pro-teini ve yağı az, hazmı kolay bir bitki. (Buğday ziraati yaygın olmadığından) Resûlul-lah aleyhisselâm arpadan öğütülmüş ekmek yerdi. (Hadîs-i şerîf-Tirmizî, Müsnedü Ahmed)","kategori":"hadis","misal":"Fıtra mikdarı arpada da buğdaydaki gibi yarım sa‘dır [takriben 1750 gramdır.] Arpa, keylîdir. Kile ile ölçülür. Misliyle veresiye veya fazlasıyla peşin satışında fâiz cereyan eder. (İbni Âbidîn)","osmanli":"آرﭘا"},{"kelime":"ARRÂF","anlam":"1.Çok bilen. 2.Bedevîlerde örfü en iyi bilen kimse. 3.Kâhinden farklı ola-rak gelecekten değil, çalınan şeylerin yerle-rini, çalanları ve sihir yapanları haber veren; zan ile veya cinden öğrendikleriyle konuşan kimse, falcı, müneccim. 4.Tabib.","kategori":"dil","osmanli":"عراف"},{"kelime":"ARŞ","anlam":"1.Taht. 2.Allahü teâlânın yarattığı en büyük varlık; yedi kat göklerin ve kürsînin üstünde, halk (madde) âleminin sonu, emr (maddesizlik) âleminin başlangıcı. Allahü teâlâ, gökleri ve yeri altı günde yarattı. (Bundan evvel ise) Arş’ı su üzerinde idi. (Hûd sûresi: 7) Bu âyet-i kerîme, suyun, yerden ve göklerden önce yaratıldığını gösteriyor. Demek ki, Arş, yerin yapısında olmadığı gibi, göklerin yapısına da benzemez. Yere ve göğe benzer tarafı yoktur. Ancak Arş, yerden ziyade göklere benzer. Bunun için göklerden sayılmaktadır. (Mektûbât-ı İmâm-ı Rabbânî) Yedi sınıf kimseyi…","kategori":"akaid","osmanli":"عرش"},{"kelime":"ARŞIN","anlam":"1.Dirsek. 2.Kumaş ölçmeye ya-rayan ve 68.58 cm gelen bir uzunluk ölçüsü. 75.774 cm gelir.","kategori":"dil","misal":"Mimarî arşın Zrâ.","osmanli":"آرشين"},{"kelime":"ARTIK","anlam":"Bir kabdan veya küçük ha-vuzdan bir canlı içtikten sonra geri kalan su. Küçük havuz, alanı yirmi üç metre kareden az olan havuzdur; derinlik mühim değildir. Mü’minin artığı şifâdır. (Hadîs-i şerîf-Keş-fü’l-Hafâ)","kategori":"hadis","misal":"Eti yenen hayvanların ağzına necâset (pislik) bulaşmış olmadıkça artıkları temizdir. Denizde ve karada yaşayan, akıcı kanı olmayan hay-vanlar ile eşek ve katır da böyledir. Domuz, köpek ve yırtıcı hayvanların, henüz fare yiyen kedinin artıkları kaba necâsettir. Yenmez, içil-mez, ilâç olarak da kullanılmaz. Henüz şarap içmiş insanın da artığı böyledir. (İbni Âbidîn)","osmanli":"آرتق"},{"kelime":"ARYuS (Aryüs)","anlam":"270.yılında doğdu.","kategori":"dil","misal":"Hristiyanlıkta bir mezheb kurucusu. Milâdın 336’da öldürüldü. Doğru yoldan ayrılan kiliseye karşı gelmesi ile meşhûrdur. Allah’ın bir olup, Îsâ aleyhisselâmın O’nun oğlu değil, kulu olduğunu söylerdi. İznik’de 325’de toplanan papaslar Aryus’u aforoz ettiler.","osmanli":"عاريوس"},{"kelime":"ARZ","anlam":"1.Dünya, yer küresi. 2.Yeryüzü, toprak, zemin. 3.Memleket.","kategori":"dil","osmanli":"ارض"},{"kelime":"ARZ","anlam":"1.Önüne koyma, huzura çıkarma, bir büyüğe takdim etme. 2.Hadîs rivâyet eden zâtın, öğrendiği hadîsleri şeyhine (üstadına) okuması ve başkalarına da rivâyet edebilmek için onun tasvibini alması. 3.Kıymetli bir şeyi, başka bir şeyle değiştirmek. 4.Altın ve gümüş dışındaki menkul mal. 5.Yeryüzündeki bir noktanın hatt-ı istivâdan (ekvatordan uzak-lığı, enlem, paralel.","kategori":"hadis","osmanli":"عرض"},{"kelime":"ARZ ve TALEB","anlam":"Üreticinin piyasaya belli fiyatla mal sürmesi ve tüketicinin de piyasadan mal çekmesi hâdisesi.","kategori":"hadis","misal":"İslâmiyet’te ticaret, arztaleb esasına göre yürür. Bir malın arz ve talebi, belli bir piyasa fiyâtında dengeye gelir. Bu fiyatın altındaki fiyatlarda taleb fazlası, üstündeki fiyatlarda arz fazlası meydana gelir. Taleb fazlası hâlinde arz yeterli olmayacak, tüketiciler istediği malı temin etmek için daha yüksek fiyatlarla aynı mikdarda malı satın almaya hazır olacaklardır. Arz fazlası olunca bu hâlde üreticiler elle…","osmanli":"طلب و عرض"},{"kelime":"ASÂ","anlam":"Baston.","kategori":"dil","misal":"Biz Mûsâ’ya dedik ki: Korkma! Sen onlara elbette gâlip geleceksin. Elindeki asânı yere bırakıver. (Onların asâlarının iplerinin çoklu-ğuna, bunların yılan şeklinde görünmelerine aldırma.) Senin asân, onların yaptıklarının hepsini yutar. Zira onların yaptıkları şeyler (ip ve asâların yılan şeklinde görünmesi), si-hirbazlık hîlesidir. Sâhir (sihir yapan) nerede olsa felâh bulamaz. (Tâhâ sûresi: 68, 69) Ben minber edindi isem, asâ edindi isem, babam İbrâhim de edinmiştir. (Hadîs-i şerîf-Taberânî) Asâ ile yürümek tevâzudandır. O kimsenin her bir adımına bir sevab yazılır ve bin de-rece yükseltilir. (Hadîs-i şerîf-Deylemî)","osmanli":"عصاء"},{"kelime":"ASABE","anlam":"1.Baba tarafından akraba. 3.Kur’ân-ı kerîmde hisse takdir edip bildirdiği vârislerden (Eshâb-ı ferâizden) sonra gelen ve belli bir payı olmayıp artan malı almaya hak kazanan, ölene erkek vâsıtasıyla bağlanan erkek akraba ve bu hükümde olan diğer şahıslar. Bağ, sarmaşık mânâsına asb’ın çokluk hâli. Asabe-i nesebiyye ve asabe-i sebebiyye olmak üzere iki çeşittir. Hak sahiplerine paylarını veriniz. Arta kalan asabeye âittir. (Hadîs-i şerîfBuhâr…","kategori":"miras","osmanli":"عصبه"},{"kelime":"ASABİYYET","anlam":"1.Akrabalık, soy ya-kınlığı. 2.Bir cemiyetin ileri gelenleri. 3.Ak-raba, soy, kavim, vatan, millet, din gayreti güt-mek. 4.Sinirlilik.","kategori":"dil","misal":"Ümmetimin helâki üç şeydedir: Asabiyyet, kaderiyye (kadere inanmamak), senedsiz ri-vâyet (aslını öğrenmeden söylemek). (Hadîs-i şerîf-Taberânî) Tarihî hâdiselerin meydana gelişinde asabiyyet mühim bir sebebdir. Asabiyyeti güçlü cemiyet-ler savaşçıdır. Tebliğ ve irşad faaliyetleri asabiy-yete dayanırsa daha muvaffak olur. “Halîfeler Kureyş’tendir” hadîs-i şerîfi de, ilk zamanlar Kureyş’in asabiyyeti güçlü olduğu için söylen-miştir. (Mukaddime-i İbni Haldun)","osmanli":"عصبيت"},{"kelime":"ASÂKİR","anlam":"Asker’in çokluk hâli, askerler.","kategori":"osmanli","osmanli":"عساكر"},{"kelime":"ASÂLET","anlam":"1.Soy temizliği, köklülük. 2.Kendi nâmına hareket etme, vekâletin zıddı. 1.Eserler. 2.Resûlullah aleyhis-selâm veya Sahâbe-i kirâm ile Tâbiînden bil- dirilen haberler.","kategori":"hadis","misal":"Tedbîr gibi akıl, güzel huy gibi asâlet ola-maz. (Hadîs-i şerîf-İbn-i Mâce) Kibrin, yani kendini büyük, üstün görmenin bir alâmeti de asâletle övünmektir. Babaları, dede-leri ile övünmek, câhilliktir. (Berîka) ÂSÂR: آثار (A) Eser’in çokluk hâli. (Bkz. Eser)","osmanli":"اصالت"},{"kelime":"ÂSÂR","anlam":"1.Eserler. 2.Resûlullah aleyhisselâm veya Sahâbe-i kirâm ile Tâbiînden bil- dirilen haberler.","kategori":"dil","misal":"Eser’in çokluk hâli. (Bkz. Eser)","osmanli":"آثار"},{"kelime":"ÂŞÂR","anlam":"“Onda bir” mânâsına Osmanlı Devleti’nde mîrî arâzî de denilen devlete ait arâzînin kirâcılarından her sene mahsul üzerinden harac olarak alınan kirâ.","kategori":"muamelat","osmanli":"اعشار"},{"kelime":"AŞERE-İ MÜBEŞŞERE","anlam":"“On müjdelenen” mânâsına Resûlullah aleyhisselâm tarafından Cennet’e girecekleri dünyada iken müjdelenen on sahâbî.","kategori":"dil","misal":"Ebû Bekr Cennet’tedir. Ömer Cennet’tedir. Osman Cennet’tedir. Ali Cennet’tedir. Talhâ Cennet’tedir. Zübeyr Cennet’tedir. Abdurrahmân ibni Avf Cennet’tedir. Sa’d ibni Ebî Vakkâs Cennet’tedir. Sa’îd ibni Zeyd Cennet’tedir. Ebû ubeyde bin Cerrâh Cennet’tedir. (Hadîs-i şerîfMüsnedü Ahmed)","osmanli":"مبشرة عشرۀ"},{"kelime":"ASFİYÂ","anlam":"“Saflar”, “gönlü açık ve temiz olanlar” mânâsına Allahü teâlânın evliyâ kulları.","kategori":"akaid","misal":"Safiyy’in çokluk hâlidir.","osmanli":"اصفياء"},{"kelime":"AŞHÂNE","anlam":"1.Aşevi, mutfak. 2.Câmi, medrese, hamam gibi yapıların da bulun-duğu külliyede çalışan İmâm, müezzin, ta-lebe ile o mahallin fakirlerine bedava yemek çıkaran yer. İmâret.","kategori":"ibadet","osmanli":"آشخانه"},{"kelime":"ÂSÎ","anlam":"1.İsyan eden, emre karşı gelen, itâatsizlik eden. 2.Günahkâr.","kategori":"dil","misal":"Allahü teâlânın ve Resûlünün (Muhammed aleyhisselâmın) emirlerine âsî olanlar, beğen-meyenler, kıyâmette Cehennem ateşinden kurtulamayacaklardır. Bunlara Cehennem’de, çok acı azap vardır. (Nisâ sûresi: 14) Melek-ler emrolundukları şeyde Allahü teâlâya âsî olmazlar ve emrolundukları şeyi yaparlar. (Tahrîm sûresi: 6) Ana-babasına vefâlı olan, ne yaparsa yapsın Cehennem’e asla girmez. Ana-babasına âsi olan da, ne yaparsa yap-sın Cennet’e giremez. (Hadîs-i şerîf-Hâkim) Müslümanlar devlete âsî olmaz. Fitneye, isyâna karışmaz. Kânunlara karşı gelmez. (Hadîka)","osmanli":"عاصى"},{"kelime":"AŞI","anlam":"1.Canlılarda muayyen hastalıklara karşı muafiyet (bağışıklık) sağlamak için kana verilen ve o hastalığın mikroplarından hazır-lanmış eriyik. Sâri hastalıklardan korunmak için aşı yapmak lâzımdır. Bunlar, tesiri, faydası kat‘i ilaçlar tü-ründendir. Suyun susuzluğu, ekmeğin açlığı gi-dermesi gibidir. Kininin sıtmaya tesiri böyledir (Kimyâ-i Seâdet) Aşı yaptırmak orucu bozar (İbni Âbidîn) 2.Ağaç veya dal üzerine, aynı familyadan ve daha iyi türden bir parçayı ekleme.","kategori":"dil","misal":"Ağacı aşılamak câizdir. Başka tür hayvanları birbiriyle çiftleştirmek caiz değildir. (İbni Âbidîn) ÂŞİNÂ: آشنا (F) Bildik, tanıdık; bilen, tanıyan. Âşnâ.","osmanli":"آشى"},{"kelime":"ASÎL","anlam":"1.Soylu, nesebi yüksek; aslı temiz. 2.Asıl borçlu; kendisine kefâlet olunan kimse; leh ve aleyhine hüküm doğuracak tasarrufu bizzat yapan kimse.","kategori":"muamelat","osmanli":"اصيل"},{"kelime":"ÂSIM","anlam":"1.Yasaktan, günah-tan çekinen. 2.İffetli.","kategori":"dil","misal":"(A. İsmet’ten)","osmanli":"عاصم"},{"kelime":"ÂSİM","anlam":"Günahkâr, kabahatli.","kategori":"dil","osmanli":"آثم"},{"kelime":"ÂŞİR","anlam":"1.Onuncu. 2.“Onda birci” mânâsına İslâm devletlerinde, şehir dışında durarak yol ve ticaret emniyetini temin eden; bunun mukabilinde Müslüman tüccardan o anda yanında bulunan ticâret malının zekâtını, Müslüman olmayanlardan ise, gümrük vergisini toplayan me’m… Amr bin Şuayb şöyle rivâyet etti: Müslüman olmayan Menbic halkı, Hazret-i Ömer’e mektup yazarak; “Bize memleketine girmemize izin ver, ticâret yapalım. Biz kazanır size de vergi veririz” dediler. Hazret-i Ömer, Eshâb-ı kirâmı toplayıp, meseleyi istişare etti, görüştü. Uygun görülünce, âşirler vâsıtasıyla uşr denilen bir vergi almaya karar verdiler. Harbîlerden ilk gümrük vergisi, Hazret-i Ömer zamanında alındı. (Kit…","kategori":"muamelat","osmanli":"عاشر"},{"kelime":"AŞK","anlam":"Aşırı sevgi.","kategori":"dil","misal":"Allahü teâlâyı ve O’nun sevdiklerini çok sevmek. Buna hakîkî aşk denir. Hakîkî aşk, nefsi terbiye eder, ahlâkı güzelleştirir; insanın kalbinde bir ateş olup, Allah sevgisinden başka her şeyi ya-kar, yok eder. Hak âşığı olanın sözü, işi ve dü-şüncesi doğru ve saftır. (Marifetnâme)","osmanli":"عشق"},{"kelime":"Aşk-ı İlâhî","anlam":"Allahü teâlâyı çok sevme hâli.","kategori":"akaid","misal":"Aşk-ı ilâhînin alâmeti, Allahü teâlânın emirle-rine çok uymaktır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"الهى عشق"},{"kelime":"ASL (Asıl)","anlam":"1.Kök, temel, esas. 2.Soy, nesep. 3.Kıyasın bir rüknü.","kategori":"fikih","misal":"Kıyasta hakkında hüküm bulunmayan meselenin (fer’in) benzetildiği ve hakkında hüküm bulunan meseleye asl denir. Hadîs-i şerîfte; “Buğdayı buğday ile misliyle satınız, fazlasına satarsanız ribâ, yani fâiz olur” buyurulmuştur. Darı da böyle midir? Burada asl, buğdaydır. Fer‘ darıdır. Buğdayın bu şekilde satılmasının câiz olmamasının illeti aynı cinsten ve kileyle ölçülebilir bulunmasıdır. Darıda da aynı hususlar cârî…","osmanli":"اصل"},{"kelime":"AŞMAK","anlam":"Hayvanın çiftleşmesi.","kategori":"dil","misal":"Erkek hayvânın dişiye aşması ücreti alınmaz, harâmdır. Dişi, erkeğin köyüne götürülürse, aygırın sahibine gıda ve hizmet masrafı öde-nir. (İbni Âbidîn)","osmanli":"آشمق"},{"kelime":"ASR","anlam":"1.Yüz yıllık zaman. 2.Zaman, devir. 3.İkindi vakti.","kategori":"hadis","misal":"(Asır.) Benden sonra her asırda bir âlim çıkar, dini kuvvetlendirir. (Hadîs-i şerîf-Ebû Dâvûd) Zamanların en hayırlısı benim asrımdır. On-dan sonra kıymetli olan, benim asrımdan sonra gelen asırdır. Daha sonra kıymetlisi, onlardan sonra gelen asrın Müslümanları-dır. Bunlardan sonra, yalancılık yayılır. Şâ-hid olmaları istenmediği hâlde, yalancı şâ-hidlik yapılır. (Hadîs-i şerîf-Buhârî)","osmanli":"عصر"},{"kelime":"AŞR (Aşir)","anlam":"1.On. 2.Cemaatle kılınan namazlardan sonra veya herhangi bir cemiyette Kur’ân-ı kerîmden sesli olarak okunan on âyet veya bu mikdara yakın bir kısım. Aşr-i şerîf.","kategori":"dil","osmanli":"عشر"},{"kelime":"Asr-ı Evvel","anlam":"İlk ikindi. Bir şeyin gölgesi, öğleden sonra boyu kadar olunca başlayan ve üç mezheb ile Hanefîlerden İmâm-ı Ebû Yûsuf ve İmâm-ı Muhammed’e göre ikindi vaktinin girdiği zaman.","kategori":"ibadet","osmanli":"اول عصر"},{"kelime":"Asr-ı Sânî","anlam":"İkinci ikindi. Bir şeyin gölgesi, öğleden sonra, boyunun iki misli olunca başlayan ve İmâm-ı A‘zâm Ebû Hanî-fe’ye göre ikindi namazının başladığı zaman.","kategori":"ibadet","misal":"İslâm memleketlerinde ikindi ezânları umumiyetle asr-ı evvele göre okunmaktadır. İkindi namazı, asr-ı sânîde, yani bu ezândan İstanbul için kışın 36, yazın ise 72 dakika sonra asr-ı sâni başlar. Her ay 6 dakika azalır veya artar.","osmanli":"ثانى عصر"},{"kelime":"Asr-ı Se‘âdet","anlam":"Peygamber efendimizin yaşadığı mübârek, bereketli ve hayırlı devir.","kategori":"akaid","misal":"Asr-ı saadet, zamanların en iyisidir. Sevgili Peygamberimiz; “Asırların en iyisi benim asrımdır.” buyurmuştur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سعادت عصر"},{"kelime":"ASTRONOMİ","anlam":"Gök cisimleri ve onların hareketleri ile meşgul olan ilim, felekiyyât.","kategori":"dil","osmanli":"آصطرونومى"},{"kelime":"Aşure Gecesi","anlam":"Mübârek ge-celerden. Muharrem ayının onuncu gecesi.","kategori":"dil","osmanli":"سى كيجه عاشوره"},{"kelime":"ÂSûRÎ","anlam":"Arabistan’dan kopup Mîlâddan evvel 3000 senelerinde Irak’ın yüksek mıntıkalarına yerleşerek Bâbil medeniyetine vâris olan, İranlı Medler tarafından devletleri yıkılan, vahşi, sert ve savaşçı bir Sâmi kavmi.","kategori":"miras","osmanli":"آصورى"},{"kelime":"ATEİST","anlam":"Tanrısız; tanrının varlığına inanmayan, Allah’ı inkâr eden.","kategori":"akaid","misal":"Dehrî.","osmanli":"ئست آته"},{"kelime":"ATEŞPEREST","anlam":"“Ateşe tapınan” mânâ-sına, Zerdüşt dini mensublarına verilen isim. ATEŞPERESTLİK: آتشﭘرستلك (T) Ateşi mukad-","kategori":"dil","misal":"des tuttuğu için Zerdüşt dinine takılan isim. Zerdüştlük. Mazdeizm.","osmanli":"آتشﭘرست"},{"kelime":"ATF (Atıf)","anlam":"Havâle etme, yollama.","kategori":"muamelat","osmanli":"عطف"},{"kelime":"ATF-I BEYÂN","anlam":"Bir şeyin mânâsını beyân etmek ve kuvvetlendirmek için bir kelime veyâ cümlenin başka bir kelime veya cümleye bağlanması.","kategori":"muamelat","misal":"ikincisinin meşhur olduğu anlaşılır. Meşhur olmayan birincisindeki kapalılığı açıklamak için, ikincisi zikr edilir. Bu ikincisi atf-ı beyândır. İbrahim aleyhisselâm iki kimseye baba demektedir. Birisi kendi babası; diğeri baba dediği başkasıdır. Îcâz, belâgat ve fesâhat kâidelerine göre, âyet-i kerîmenin mânâsı ‘İbrâhîm aleyhisselâm, Âzer olan babasına dediği zaman’ demektir. Böyle olmasaydı, Kur’ân-ı kerîmde, ‘Baba…","osmanli":"بيان عطف"},{"kelime":"ÂTÎ","anlam":"1.Gelecek, istikbal. 2.Aşağı.","kategori":"dil","osmanli":"آتى"},{"kelime":"ATÎK","anlam":"1.Âzâd olunmuş adam, azatlan-mış. 2.Cehennem’den azat olduğu, çeşitli ha-dîs-i şerîflerle bildirildiği üzere Hazret-i Ebû Bekr’in lâkabı. 3.Eski.","kategori":"akaid","misal":"ATİYYE: عطيه (A) İhsan, bahşiş. (Bkz. Atâ) Her peygambere bir dilek, atiyye verildi. On-lar da bunu dünyada harcadı, ben ise âhi-rette ümmetime şefaat için bıraktım. Üm-metimden öyle adam olacak ki, çok büyük bir topluluğa şefaat edecek de onlar da o yüzden Cennet’e girecekler. Öyle bir adam olacak ki, bir kabileye şefaat edecek. Yine bir adam olacak ki, ailesine şefaat edecek, Hatta kişiye, iki kişiye, bir kişiye şefaat ede-cek kimseler olacaktır. (Hadîs-i şerîf-Müsnedü Ahmed) Kim dilencilik kapısını açarsa, Al-lahü teâlâ dünyada ve âhirette ona fakirlik kapısını açar. Kim Allahü teâlânın rızâsını kasdederek atiyye kapısını açarsa, Cenâb-ı Hak ona hem dünya, hem âhiret saadeti ih-sân eder. (Hadîs-i şerîf-Ebû Dâvûd)","osmanli":"عتيق"},{"kelime":"ÂTIL","anlam":"(A. Atâlet’ten) Tembel; faydasız.","kategori":"dil","osmanli":"عاطل"},{"kelime":"ATKI","anlam":"Kumaş ve halı dokumada kul-lanılan ipliklerin bir tür ve şekli. Yanlamasına dokuma. Luhme. Pûd.","kategori":"dil","misal":"Kumaş ve halı dokunurken, önce uzunlama-sına çözgü iplikleri gerilerek hazırlanır. Bun-ların bir altından bir üstünden geçecek şekilde mekikle yanlamasına atkılar geçirilir. Atkıları, tarakla sıklaştırmak sûretiyle dokumanın sık ve düzgün olması sağlanmış olur. Renkli kumaşa rengini veren atkıdır. Çözgüsü ipek olan, luh-mesi yani atkısı ipek olmayan elbise erkeklere de harâm değildir. Çünki, kumaşın atkısı mü-himdir. Çözgüsünün değeri yoktur. Atkısı ipek olup, çözgüsü ipek olmayan elbise, saf ipek gibi harâmdır. (İbni Âbidîn)","osmanli":"آطقى"},{"kelime":"ATLAS","anlam":"1.Üst tarafı ipek, alt tarafı pa-muk kumaş. 2.Haritalar kitabı.","kategori":"dil","misal":"(Fr) Altından ırmaklar akan Adn Cennetleri on-larındır. Orada altın bileziklerle süslenirler; hafif ipekten ve ağır işlenmiş atlastan yeşil elbiseler giyerler ve tahtlar üzerinde kuru-lurlar. (Kehf sûresi: 31) Hafif ipekten ve ağır işlenmiş atlastan (elbiseler) giyinirler, kar-şılıklı (otururlar). (Duhan sûresi: 53) Astar-ları, ağır işlenmiş atlastan yataklar üzerinde yaslanırlar. (Rahman sûresi: 54) Onların üze-rinde hafif ipek ve ağır işlenmiş atlastan ye-şil elbiseler vardır. (İnsan sûresi: 21) Atlas kumaş giyinmek bu dünyada erkeklere câiz değildir. (İbni Âbidîn) Hırka-ı hazret-i fahr-i rusule Atlas-ı çarh olamaz pâyendaz. (Arif Hikmet Bey)","osmanli":"اطلس"},{"kelime":"ATTÂR","anlam":"Güzel kokular, iğne iplik, ilaç vs. satan, aktar.","kategori":"dil","misal":"Hakîkî din adamlarının va‘zları, kitapları, bun-ların nazarında, hayvan pazarında güzel ko-kular satan attâr ve körlere ayna satan kimse gibidir. (Riyâdü’n-Nâsıhîn)","osmanli":"عطار"},{"kelime":"AVÂM","anlam":"Halk, topluluk; müctehid olmayan.","kategori":"fikih","misal":"Âmî‘nin çokluk şekli.","osmanli":"عوام"},{"kelime":"AVÂMÎL","anlam":"1.Bir şeye tesir eden sebebler, âmiller. 2.Arabca gramerin nahv (sentaks) kısmına ait ve medreselerde okutulması âdet olan meşhur kitaplardan biri.","kategori":"fikih","misal":"Âmil’in çokluk hâli.","osmanli":"عوامل"},{"kelime":"AVÂNÎ (A‘vânî)","anlam":"1.Yardakçı, 2.Suçsuz kimseleri, iftirâ ederek mahkemeye sürükleyen.","kategori":"osmanli","misal":"Avânî, ta‘zir cezasına çarptırılır. (İbni Âbidîn)","osmanli":"عوانى"},{"kelime":"ÂVÂZ","anlam":"Ses, sedâ, yüksek ses.","kategori":"dil","misal":"Her bir çiçek bir nâz ile, öğer Hakkı, niyâz eder, Kurtlar, kuşlar, durmaz söyler, ol Hâlıka âvâz eder. AVDET: عودت (A) Geri gelme, dönme, dönüş. Resûlullah aleyhisselâm, Mi’racdan avdet bu- yurduğunda, henüz yatağı soğumayıp, taha-ret ibriğindeki suyun hareketi kaybolmamıştı. (Mevâhib-i Ledünniyye) Beş vaktin farzı ile vitrin edâ ve kazâlarında sı-rayı gözetmek lâzımdır. Fakat vaktin sonunda ise bu lâzım olmaz. Kazâsı olduğunu unutursa veya kazâ adedi altı olursa tertip düşer. Kazâ-ların adedi altıdan aşağı düşerse, tertip avdet etmez. (İbni Âbidîn)","osmanli":"آواز"},{"kelime":"AVESTA","anlam":"Zerdüşt dininin mukaddes kitabı.","kategori":"dil","osmanli":"آوسطه"},{"kelime":"AVL (Avliyye)","anlam":"İslâm miras hukukunda muayyen hisse sahiplerinin (eshâb-ı ferâizin)","kategori":"miras","misal":"alacakları hisselerin toplamının müşterek pay- dadan fazla olma hâli. Avlde, hisse sahibi mirasçıların hisseleri nisbetinde eksiltilir. Zevce, ana, iki kız kardeş ve anadan iki kız kardeş bulunduğu zaman, miras on ikiye taksim edilip, zevceye 3 hisse, anaya iki hisse, iki kız kardeşe sekiz hisse (her birine dörder hisse), ana bir iki kız kardeşe dört hisse (her birine ikişer hisse) verilir ki, hisseler toplamı on ye…","osmanli":"عول"},{"kelime":"AVLu","anlam":"Yapıların ortasında, tercihe göre üstü açık ya da kapalı geniş kısım.","kategori":"miras","misal":"Aslı Arabca etrafı çevrelenmiş mânâsına havlî’den gelir. Câmi avlusundan İmâma uymak arada saflar varsa sahihtir. Câmi avlusuna hayızlı kadın ve cünüb girebilir. (İbni Âbidîn)","osmanli":"آولو"},{"kelime":"AVN","anlam":"Yardım.","kategori":"dil","osmanli":"عون"},{"kelime":"AVRET","anlam":"1.İnsanın, gösterilmesi ayıp olan yerleri.","kategori":"fikih","misal":"İslâmiyet’te akıllı ve bâliğ olan kimsenin namaz kılarken açması veya her zaman başkasına göstermesi ve başkasının bakması haram olan yerlerine avret denir. Ey Resûlüm! Mü’min erkeklere söyle, harama bakmasınlar ve avret yerlerini haramdan korusunlar. Îmânı olan kadınlara da söyle, harama bakmasınlar ve avret yerlerini haram işlemekten korusunlar. (Nûr sûresi: 30) Avret yerinizi açmayınız (yani yalnız iken de açmayı…","osmanli":"عورت"},{"kelime":"AVuÇ","anlam":"1.Elin iç tarafı. 2.Elin iç tarafıyla ölçülebilen mikdar.","kategori":"dil","misal":"Duâ ederken avuçlar açılır, avuç içi semâya çevrilir. Çünki nasıl namazın kıblesi Kâ‘be ise, duânın kıblesi de semâdır. (İhyâ) Mâlikî ve Şâfiî mezhebinde avuç ve parmak içleri ile zekere dokunmak abdesti bozar. (el-Fıkhu ale’l-Mezâhibi’l-Erbaa) Namaza niyetlenirken avuç içleri kıbleye gelecek şekilde eller kaldırılır. Elleri erkek kulak yumu-şağına, kadın göğsü üzerine koyar. (İbni Âbidîn) İki avuç içi, yarım sa‘dan azdır. Yarım sa‘ takriben 1750 gramdır. Avuç içinden az kan, irin gibi necaset bulaşınca namaz sahîh olur. (İbni Âbidîn)","osmanli":"آووﭺ"},{"kelime":"AYA","anlam":"Parmaklar dâhil olmaksızın elin ve ayağın avuç içi.","kategori":"dil","osmanli":"آيا"},{"kelime":"ÂYÂ","anlam":"“Acaba”, “Nasıl olur?” “Ey!” mânâ-sına hayret nidâsı.","kategori":"dil","osmanli":"آيا"},{"kelime":"AYAK","anlam":"1.Canlılarda bacağın alt kısmında bulunup yürümeyi temin eden uzuv. 2.Bir ölçü birimi. 3.Şiirde kâfiye.","kategori":"dil","misal":"Abdestte, bilek kemiklerinden aşağıya doğru ayakları yıkamak farzdır. Namazda ayakları örtmek erkeklere sünnettir. Kadınların açması haram, bir kavle göre mekrûhtur. (İbni Âbidîn) Bir ayak 30,48 santimetredir.","osmanli":"آياق"},{"kelime":"AYAKKABI","anlam":"Sokakta ayağı muha-faza için giyilen giysi. Pabuç. Kundura.","kategori":"dil","misal":"Ayakkabı aldığın zaman, yenisini al! Elbise aldığın zaman, yenisini al! (Hadîs-i şerîf-Ta-berânî) Namazı ayakkabı ile kılmak sünnettir. Nitekim hadîs-i şerîfte; “Çıplak ayakla tapınan Yahu-dilere muhafet edin; namazı ayakkabı ile kı-lın!” buyuruluyor. Namazda ayakkabıyı arkada bırakmak zihni dağıtabileceği için mekrûhtur. (İbni Âbidîn)","osmanli":"قابى آياق"},{"kelime":"AYAKLANMA","anlam":"Hükümete karşı si-lahlı faaliyete girişme. İsyan, bağy.","kategori":"dil","osmanli":"آياقلانمه"},{"kelime":"AYAR","anlam":"1.Altının, gümüşün ve başka kıymetli madenlerin saflık derecesi. 2.Saatin hassas ölçümü.","kategori":"dil","osmanli":"عيار"},{"kelime":"ÂYÂT-I HIRZ","anlam":"164.âyetleri…","kategori":"dil","misal":"Sığınma âyetleri. Okunduğunda veya üzerinde taşındığında Allahü teâlânın muhafazasına vesile olan âyet-i kerîmeler. Bir köylü, Resûlullah’ın (sallallahü aleyhi ve sellem) yanına geldi. Kardeşinin ağır hasta olduğunu söyledi. “Hastalığı nedir?” buyurdukta, cin çarpması dedi. “Kardeşini buraya getir” buyurdu. Resûl-i ekrem bazı âyetleri okuyup, hastaya üfledi. Hemen iyi olup kalktı. Bu âyet-i kerîmeler şunlardır: Fâtiha, Bakara sûresi başından dört âyet. (Ve ilâhiküm)’den başlayarak Ya’kılûne’ye kadar, iki defâ 163 ve","osmanli":"حرز آيات"},{"kelime":"AYAZMA","anlam":"1.Kusur. 2.Utanılacak şey, ayıp.","kategori":"dil","misal":"“Mukaddes su” mânâsına Umumiyetle bir azizin kabri yanından çıkan ve Rumlar tarafından mukaddes bilinerek suyu hastalara içirilen kaynak, göze. AYB: عيب (A) Her kim bir Müslüman kardeşinin aybını, kusurunu, kimsenin görmesini ve işitme-sini istemediği şeylerini örterse, Allahü teâlâ da kıyâmet gününde onun ayblarını örter. Her kim Müslüman kardeşinin mey-dana çıkmasını istemediği bir şeyini ortaya çıkarır ve dile verirse, Allahü teâlâ da onun aybını, kimsenin bilmesini istemediği hâl-lerini meydana çıkarır ve bu sûretle kendi evi içinde de olsa onu rezil eder. Müslüman kardeşinin aybını örten, bir ölüyü diriltmiş gibidir. (Hadîs-i şerîf-Müslim)","osmanli":"آيازمه"},{"kelime":"ÂYET","anlam":"1.Alâmet, nişan. 2.Kur’ân-ı kerîmdeki her bir cümle.","kategori":"dil","misal":"Biz sana apaçık âyetler indirdik. Onları fâsıklardan (kâfirlerden) başkası inkâr etmez.” (Bakara sûresi: 99) Kur’ân-ı kerîmde 114 sûrede 6236 âyet vardır. Âyetlerin sayısının farklı verilmesi, büyük bir âyetin, bir kaç küçük âyet sayılmasından veya bir kaç kısa âyetin bir büyük âyet yahud sûrelerin başındaki besmelelerin bir veya ayrı ayrı âyet sayılmasından ileri gelir. (Tefsir-i Ebülleys)","osmanli":"آية"},{"kelime":"AYIN","anlam":"21.harfi.","kategori":"ibadet","misal":"Arap alfabesinin Mus-haflarda, Hazret-i Ömer radıyallahü anhın na-maz kıldırırken, ayakta okumayı bitirip, rükû’a eğildiği yeri gösteren işâret.","osmanli":"عين"},{"kelime":"ÂYİN","anlam":"1.Merasim. 2.Âdet, tarz. 3.Dinî merasim.","kategori":"dil","misal":"Âyin, umumiyetle İslâmiyet’ten başka dinler için kullanılan bir tabirdir.","osmanli":"آيين"},{"kelime":"ÂYİSE","anlam":"Âdet görmekten kesilmiş kadın.","kategori":"osmanli","misal":"Kadın elli beş yaşlarında âyise olur. Âyise kadından gelen kanlar, hayz olmaz; özür sayılır. Meğer ki, koyu kırmızı veya siyah olsun. (Zuh-rü’l-Müteehhilîn)","osmanli":"آيسه"},{"kelime":"AYN","anlam":"1.Göz. 2.Göze, pınar. 3.Dış âlemde var olan maddî şey. 4.Aslı, kendisi, bir şeyin eşi. 5.Alış-verişte, belli, meydanda, mevcut ve hâzır olan veya hâzır olmayıp da bulunduğu yeri, cinsi, mikdarı belli edilen mal. Nakdin (paranın) zıddı. Nakit paradan başka mülk edinilebilinen şey. Bir ev, bir at, bir sandalye, bir çuval buğday, bir mikdar para ayn’dır. (Mecelle)","kategori":"muamelat","osmanli":"عين"},{"kelime":"Ayn-ı Sâbite","anlam":"Her mahlûkun yaratılmasına ve varlıkta kalmasına vâsıta olan, Allahü teâlânın isimlerinin zılli, aksi ve nûru.","kategori":"akaid","misal":"Mebde-i te‘ayyün.","osmanli":"ثابته عين"},{"kelime":"AYNÎ","anlam":"Ayna ait. Para olarak değil, madde (eşya) olarak verilen, nakdî olmayan, malın aslına ait.","kategori":"dil","osmanli":"عينى"},{"kelime":"AYYÂŞ","anlam":"Çok içki içen. (Yaşamak mânâ-sına ayş’dan.)","kategori":"dil","osmanli":"عياش"},{"kelime":"AZÂB","anlam":"Eziyet, keder, işkence; işlenen günahlar sebebiyle âhirette çekilecek cezâ, azap.","kategori":"akaid","misal":"Nimetlerimin kıymetlerini bilir, emrettiğim gibi kullanırsanız, onları artırırım. Kıymetlerini bilmez, bunları beğenmezseniz, elinizden alır, şiddetli azap ederim. (İbrâhim sûresi: 7)","osmanli":"عذاب"},{"kelime":"AZAMET","anlam":"1.Büyüklük; Cenâb-ı Hakk’ın büyüklüğü. 2.Çalım, kurum, büyüklenme.","kategori":"dil","misal":"Kibriyâ, üstünlük ve azamet bana mahsustur. Bu ikisinde bana ortak olanı Cehennem’e ata-rım, hiç acımam. (Hadîs-i Kudsî-Ebû Dâvûd) Ümmetimin şerlileri, çok konuşan, düşün-cesizce konuşan ve azametle konuşanlardır. Ümmetimin hayırlıları ise ahlâkça en güzel olanlarıdır. (Hadîs-i şerîf-Deylemî)","osmanli":"عظمت"},{"kelime":"AZÎM","anlam":"1.Büyük. 2.Büyüklüğüne, beşer aklının erişemediği, hakîkatini kimsenin bilemediği; sıfatları büyük mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elAzîm). O (Allah) Aliyy’dir. (Mahlûkların, yaratılmışların akıl, ilim ve anlayışlarının erişemediği yüceliktedir.) Azîm’dir. (Bakara sûresi: 255) elAzîm ism-i şerîfini söyleyen, elem ve kederden kurtulur. (Elİstigâsetü’l-Kübrâ) Azîmü’ş-Şân: (A) “Şanı büyük” mânâsına Allahü teâlâ için kullanılan ta’zim kelimelerinden.","kategori":"akaid","osmanli":"عظيم"},{"kelime":"AZÎZ","anlam":"1.İzzetli; muhterem, yüce. 2.Sevgili kimse. 3.Mislinin vücudu bulunma-yan; büyük ve küçük her şeyin kendisine şid-detli ihtiyacı olup, O’na kavuşmak zor olan zât mânâsına Allahü teâlânın Esmâ-i hüsnâ-sından (el-Azîz). Bilin ki, Allahü teâlâ Azîz’dir. Hakîm’dir (hik-met sahibidir). (Bakara sûresi: 209) Bir kimse kırk gün ve her gün de kırk kere el-Azîz ism-i şerîfini söylerse Allahü teâlâ ona yar-dım eder ve onu üstün kılar. Mahlûkattan hiç birine muhtaç olmaz. (El-İstigâsetü’l-Kübrâ)","kategori":"dil","misal":"Ey Resûlüm! De ki: Ey mülkün sahibi olan Allah’ım! Mülkü dilediğine verirsin, dile-diğinden alırsın. Dilediğini azîz kılar, dile-diğini alçaltırsın. Hayır (iyilik) yalnız senin elindedir. Doğrusu Sen her şeye kâdirsin. (Âl-i İmrân sûresi: 26) Biz zelîl bir kavim idik. Allahü teâlâ bizi İslâm ile azîz eyledi. (Hazret-i Ömer)","osmanli":"عزيز"},{"kelime":"AZÎZAN","anlam":"1.İki aziz. 3.“İki azîz” mânâsına İslâm âlimlerinin ve ev-liyânın büyüklerinden Ali Râmitenî hazretle-rine verilen lakab.","kategori":"dil","misal":".(F) 2Azizler. (Kelimenin sonundaki ân takısı Arabca’da iki-lik, Farsça’da çokluk ifâde eder.) Ey azîzân işte başlarız söze, Bir vasîyet kılayım illâ size. (Mevlid-i Süleymân Çelebi) Ali Râmitenî hazretleri, kendisinde sıkıntılı za-manda hizmet eden bir gence hacet kapısının açık olmasından istifadeyle duâ etmek arzu bu-yurdu ve ne istediğini sordu. Genç; “Sizin gibi olmak istiyorum” dedi. Ali Râmitenî; “Ağır bir iş arzu ettin. Bunun yükünü kaldıramazsın” de-diyse de genç ısrar etti. Bunun üzerine gence te-veccüh buyurdu. Genç, Allah’ın izniyle Ali Râ-mitenî’nin derecesine kavuştu. Ancak bu hâle kırk gün dayandı, sonra vefat etti. Ona bir anda kendi mânevî makamlarını verip, kendisi gibi yaptığı için, Azîzân ismi verildi. (Molla Câmi)","osmanli":"عزيزان"},{"kelime":"AZL","anlam":"1.Ayırmak, uzaklaştırmak. 2.Bir memuru, vekili, vasî, mütevelliyi, emiri vazifesinden uzaklaştırmak. 3.Hâmile kalmayı önlemek için cinsî temas esnasında erkeğin dışarı boşalması.","kategori":"dil","misal":"Vekil, müvekkil dilediği zaman; vvasîyi, müte-velli ve emîr ise ancak meşru sebeblerin varlığı hâlinde azledilebilir. (İbni Âbidîn) Bir adam Resûlullah aleyhisselâma gelerek: “Yâ Resûlallah! Benim hizmetçi bir cariyem var bazen onunla beraber oluyorum, fakat hâ-mile kalmasını istemiyorum.” Bunun üzerine Resûlullah şöyle buyurdu: “İstersen ondan az-ledebilirsin.” (Hadîs-i şerîf-Müslim)","osmanli":"عزل"},{"kelime":"AZM","anlam":"Kasıt, niyet, karar.","kategori":"dil","misal":"İşlerinde Eshâbın ile meşveret et. Onlara danış. Bundan sonra bir işe azmettiğin za-man, Allahü teâlâya tevekkül et, O’na gü-ven. (Âl-i İmrân sûresi: 159) Âdem aleyhis-selâma önce söyledik. Fakat unuttu. Azm ile yapmadı. (Tâhâ sûresi: 115) Kalbe gelen düşünce beş derecedir: Birincisi, kalbde durmaz, def ‘ edilir. Buna hâcis denir. İkincisi kalbde bir zaman kalır. Buna hâtır de-nir. Üçüncüsü yapmak ile yapmamak arasında tereddüd olunur. Buna hadîsü’n-nefs denir. Dördüncü derece, yapması tercih edilir. Buna hemm denir. Beşinci derecede bu tercih kuvvet-lenip, karar verir. Buna azm ve cezm denir. İlk üç dereceyi melekler yazmaz. Hemm, hasene ise yazılır. Seyyie ise, terk edilirse, sevab yazı-lır. Azm olursa, bir günah yazılır. İşlemezse, bu da afv olur. Hadîs-i şerîfte; “Kalbe gelen kötü şey söylenmedikçe ve buna uygun hareket edilmedikçe afv olur” buyuruldu. (Hadîka)","osmanli":"عزم"},{"kelime":"AZM","anlam":"1.Büyüklük, azamet. 2.Kemik.","kategori":"dil","osmanli":"عظم"},{"kelime":"AZRÂİL (aleyhisselâm)","anlam":"Dört büyük melekten, ruhları almakla vazifeli olan, melekü’l-mevt, ölüm meleği.","kategori":"dil","misal":"Âyet-i kerîme ve hadîs-i şerîflerde melekü’l-mevt (ölüm meleği) diye geçer. Ölüm meleğine Azrâil ismi verilmesi insanlar arasında meşhur olmuştur. Sa‘lebî Tefsirinde şöyle bir rivâyet vardır: Tâbiînden Câbir elHasen elAnbesî’nin oğlu Eş‘as dedi ki: İbrâhim aleyhisselâm Azrâil adında bir gözü arkasında bir gözü önde olan ölüm meleğine sordu: “Ey ölüm meleği! Aynı anda hem doğuda hem batıda iki kişi ölecek olsa veya b…","osmanli":"عزرائيل"},{"kelime":"BÂB","anlam":"1.Kapı. 2.Bir kitabın kısımlarından her biri. 3.Bâbîliğin kurucusu Ali Muhammed’in kendisine verdiği ad.","kategori":"dil","misal":"(Bkz. Bâbîlik)","osmanli":"باب"},{"kelime":"Bâb-ı Cibrîl","anlam":"“Cebrâil Kapısı” mânâ-sına, Medîne-i Münevvere’deki Mescid-i Ne-bevî’nin doğu tarafında kıbleye yakın kapısı. Bâb-ı Cibrîl’e, Hazret-i Osman’ın evinin karşı-sında bulunması sebebiyle Bâb-ı Osmân; Resû-lullah efendimiz Hazret-i Osman’ın evini ziya-ret etmek üzere bu kapıdan girip çıkmayı âdet edindikleri için Bâb-ı Nebî de denilmiştir. Beni Kureyzâ Yahudileri üzerine sefer yapıldığı za-man, Cebrâil aleyhisselâm Peygamber efendi-mize yardım için geldiğinde Bâb-ı Cibrîl önünde beklemişti. (Mir’at-ı Haremeyn)","kategori":"akaid","osmanli":"جبريل باب"},{"kelime":"BABA","anlam":"1.Çocuğun dünyaya gelmesine sebeb olan erkek, ata. 2.Hürmete layık yaşlı erkek. 3.Her zümrenin başında bulunan zât. 4.Tasavvufta mürşidlik mertebesine yükselen zât.","kategori":"tasavvuf","misal":"Çocuk bâliğ olup ehliyetini kazanıncaya kadar velîsi ve vasîsi baba; baba yoksa babanın tayin ettiği vasîdir. (İbni Âbidîn)","osmanli":"بابا"},{"kelime":"BÂC","anlam":"1.Daha ziyade temettüden (gelir-den) alınan vergi. 2.Büyük bir hükümdarın, kendisinden daha aşağı mertebede bulunan hükümdarlardan aldığı vergi.","kategori":"dil","osmanli":"باج"},{"kelime":"BÂD","anlam":"Rüzgâr.","kategori":"dil","misal":"Ey bâd-ı sâbâ uğrarsa yolun Semt-i Haremeyn’e, Selâmımı arzeyle Resûlüssekaleyne.","osmanli":"باد"},{"kelime":"BÂDÎ","anlam":"1.Sebeb; başlangıç. 2.Açık, zâhir. 3.Bâdiyeli, bedevî, çöle mensub.","kategori":"fikih","osmanli":"بادى"},{"kelime":"BÂGÎ","anlam":"1.Azgın, taşkınlık ya-pan. 2.Bagy suçu işleyen, kendince meşru bir sebebe dayanarak meşru halîfeye silahla isyân eden, âsî.","kategori":"dil","misal":"Çokluk hâli bugât gelir. Bâgîler ile harb edip, bunları itâate getirin! (Hucurât sûresi: 9) Halîfe, bâgîlerden isyân sebeblerini sorar ve onları itâate dâvet eder. Bunu kabul etmeyip, harbe başlarsa, halîfe, onların topluluklarını dağıtıncaya kadar harb eder. Bâgîler döğüşür-ken öldürülünce, yıkanmaz, namazları kılın-maz. (İbni Âbidîn)","osmanli":"باغى"},{"kelime":"BAHÂ","anlam":"Kıymet, değer; semen, fiyat. Paha. Her gece kadr olsa, kadrin kadri olmazdı şâhâ Her hacer gevher olsa, gevher etmezdi behâ. (Bâkî)","kategori":"ibadet","misal":"[Ey padişahım her gece Kadir olsaydı kadrin kıymeti olmazdı. Her taş, cevher olsaydı, cev-her bu kadar kıymetli olmazdı].","osmanli":"بها"},{"kelime":"BAHÂDIR","anlam":"Cesur, yiğit, kahraman.","kategori":"dil","osmanli":"بهادر"},{"kelime":"BAHÎL","anlam":"Cimri.","kategori":"dil","misal":"Bahîl, Allahü teâlâdan, Cennet’ten ve insan-lardan uzaktır. (Hadîs-i şerîf-Tirmizî)","osmanli":"بخيل"},{"kelime":"BAHR","anlam":"1.Deniz. 2.Aruzda aslî bir vezinle ondan doğan vezinler mecmuası.","kategori":"dil","osmanli":"بحر"},{"kelime":"BAHREYN","anlam":"1.İki deniz. 2.Basra kör-fezinde bir ada.","kategori":"dil","osmanli":"بحرين"},{"kelime":"BAHRÎ","anlam":"1.Denize mensub. 2.Deniz-lerde yaşayan bir kuş.","kategori":"dil","osmanli":"بحرى"},{"kelime":"BAHŞ","anlam":"Bağış, ihsan.","kategori":"dil","misal":"Hak teâlâ yüce kerem ve ihsanından, kendi feyzlerini ve nimetlerini varlıklara vermek ve bahş eylemek murâd eyledi. Mahlûkları yara-tıp, kendi sıfatlarının kemallerinden onlara bahş eyledi. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"بخش"},{"kelime":"BAHT","anlam":"Tâlih, nasip, kısmet.","kategori":"dil","osmanli":"بخت"},{"kelime":"BAHTİYÂR","anlam":"Tâlihli, mes‘ûd, mutlu.","kategori":"dil","osmanli":"بختيار"},{"kelime":"BÂİN","anlam":"1.Ayırıcı. 2.İnsanlar-dan uzak olan.","kategori":"dil","misal":"(Bkz. Kâin ve Bâin)","osmanli":"بائن"},{"kelime":"Bâin Talâk","anlam":"Ayırıcı boşanma. Boşamada kullanılan sözleri söyler söylemez, evliliği sona erdiren boşama.","kategori":"dil","misal":"Bâin talâk üç çeşittir: 1-Daha evvel zifafa girmediği zevcesini boşama; 2-”Çık git!, “Örtün”, “Baba evine git” gibi boşanma için de, başka şey için de kullanılan kinâye kelimelerle boşama; “Elbette boşsun”, “Şiddetli talâk ile boşsun” gibi şiddetlendirici bir sözle boşama. (İbni Âbidîn)","osmanli":"طلاق بائن"},{"kelime":"BÂKÎ","anlam":"1.Devamlı, kalıcı. 2.Geri kalan, arta kalan. 3.Varlığının sonu olmayan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elBâkî).","kategori":"akaid","misal":"elBâkî ism-i şerîfini bin kere söyleyen kimse, zarar ve kederden korunmuş olur. (Elİstigâsetü’l-Kübrâ)","osmanli":"باقى"},{"kelime":"BAKÎ‘ KABRİSTANI","anlam":"Medîne-i Münevvere’de Mescid-i Nebevî’nin garbında Resûlullah zamanından kalma büyük kabris-tan. Cennetü’l-Bakî‘.","kategori":"akaid","misal":"Bana Hazret-i Cibril gelip şöyle dedi: “Mu-hakkak Rabbin Bakî‘ kabristanı ehline gidip onlar için istiğfâr etmeni emrediyor”. (Ha-dîs-i şerîf-Müslim) Ey Ümm-i Kays, Bakî‘ kab-ristanını görüyor musun? Buradan Allahü teâlâ kıyamette, yüzleri ayın on dördü gibi yetmiş bin kişiyi diriltecek ve onlar hesabsız Cennet’e gireceklerdir. (Hadîs-i şerîf-Taberânî)","osmanli":"قبرستانى بقيع"},{"kelime":"BÂKİRE","anlam":"Evlenmemiş kız; kız oğlan kız.","kategori":"dil","misal":"Resûl-i Ekrem perde arkasındaki bâkire kızdan daha hayâlıydı. (Hadîs-i şerîfBuhârî, Müslim) Bâkire kadınlarla evlenmeyi tercih ediniz. (Hadîs-i şerîfİbn-i Mâce) Nikâhı kıymak üzere velî, kızdan izin istediğinde, bâkirenin susması veya gülmesi yâhud sessizce ağlaması izin yerine geçer. Bâkire değilse, dul ise, geçmez. (İbni Âbidîn)","osmanli":"باكره"},{"kelime":"BAKIYYE","anlam":"(A. Beka’dan) Artan, kalan. (Şuayb aleyhisselâm dedi ki:) “Ey kavmim! Ölçüyü ve tartıyı adaletle yapın. İnsanlara eşyalarını eksik vermeyin. Yeryüzünde fe-sat çıkarmayın. Eğer mü’min iseniz Allah’ın bakıyyesi (helâlinden bıraktığı kâr) sizin için daha hayırlıdır. Ben üzerinize bir bekçi de-ğilim.” (Hûd sûresi: 85-86) Sizden öncekilerin ileri gelenleri, yeryüzünde bozgunculuğa en-gel olmalı değil miydiler? Onlardan bakıyye (kurtardıklarımız) pek azdır. (Hûd sûresi: 116)","kategori":"dil","osmanli":"بقيه"},{"kelime":"BALÇIK","anlam":"Su ile toprak karışımı. Âdem aleyhisselâm balçıktan yaratıldı. Allahü teâlâ, balçık çamurundan insan şeklinde bir heykel yapıp, bunu ete ve kemiğe çevirmişti. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","misal":"Balçık, kil yemek haramdır. Rengi ve kuvveti giderir. Hazret-i Ali radıyallahü anh buyurdu ki: “Üç şey ahmaklıktır: Diş ile tırnak uçlarını yemek, sakal yolmak ve balçık yemek.” (Şir‘a-tü’l-İslâm)","osmanli":"بالﭽيق"},{"kelime":"BALDIZ","anlam":"Zevcenin kızkardeşi.","kategori":"dil","misal":"Baldız ile evlenmek câiz değildir. Zevcesi ölür veya boşanırsa; iddetten sonra evlenebilir. Bu-nunla beraber baldız bir erkeğe nâmahremdir, yani yabancı kadın gibidir. Beraber oturmak, konuşmak, saçına koluna bakmak, beraber yal-nız sefere gitmek câiz değildir. (Ni’met-i İslâm)","osmanli":"بالديز"},{"kelime":"BÂLİĞ","anlam":"Bülûğa eren, ergenlik çağına gelen erkek.","kategori":"dil","misal":"Erkekte ihtilâm, kızda hayz bülûğun başlan-gıcıdır. 12 yaşındaki oğlan ve 9 yaşındaki kız, bâliğ olduğunu söyleyince kabul edilir. 15 ya-şını doldurunca hayz ve menî olmasa da, bâ-liğ sayılırlar. (Bkz. Âkıl-Bâliğ)","osmanli":"بالغ"},{"kelime":"BÂLİĞA","anlam":"Bülûğa eren, ergenlik çağına gelen, hayız görüp çocuk doğurma kabiliyeti kazanan kız.","kategori":"akaid","osmanli":"بالغه"},{"kelime":"BALIK","anlam":"Suda yaşayan, yumurta ile üreyen, solungaçlarıyla soluyan hayvan. Se-mek. Mâhî.","kategori":"dil","misal":"Avlanılan, yakalanan her balığı yemenin helâl olduğu, Mâide sûresinde bildirilmektedir. Su içinde kendiliğinden ölüp, karnı üst tarafta du-ran balık yenmez. Ağ, saçma, ilâç veya sarsıntı ile ölen her balık yenir. Denizde yaşayan hay-vanlardan balığa benzeyen hepsi Hanefî mez-hebinde yenir. (İbni Âbidîn)","osmanli":"باليق"},{"kelime":"BANDO","anlam":"Askerî mızıka.","kategori":"dil","misal":"Harbde, hac yolunda ve askerlikte davul ve benzeri âletleri çalmak câizdir. Muhârebede, askerin moralini kuvvetlendirmek için, bando, mızıka çalmak ve bunlara sulh zamanında da hazırlanmak ve düğünlerde davul, def çalmak, her Müslümana câizdir. Mekteplerde, millî ve siyâsî toplantılarda ve bayramlarda bando, mü-zika çalmak câiz olduğu buradan anlaşılmak-tadır. (İbni Âbidîn)","osmanli":"باندو"},{"kelime":"BÂNÎ","anlam":"Kurucu, binâ eden, kuran.","kategori":"dil","misal":"Cüneyd-i Bağdâdî, vahdet-i vücûd bânîsi iken, serâpa (tepeden tırnağa kadar) şeriate uymak ile bezenmişti (Mektûbât-ı Ma‘sûmiyye)","osmanli":"بانى"},{"kelime":"BANKA","anlam":"Kendi sermayesini veya tasarruf ve ticaret sahiplerinin yatırdıkları paraları","kategori":"muamelat","misal":"başkasına yâhud başka işlere borç veren veya yatıran müessese. (Banko=Tezgâh, gişe.)","osmanli":"بانقه"},{"kelime":"BANKNOT","anlam":"“Banka kâğıdı” mânâsına devlet bankası tarafından çıkarılan ve altın para yerine geçen kâğıt para.","kategori":"osmanli","misal":"Banknot, hükmen paradır. Bununla alışveriş yapmak caizdir. Zekâtını vermek de lâzımdır. (Kitâbü elFıkhı ale’l-Mezâhibi’l-erbaa)","osmanli":"بانقنوط"},{"kelime":"BÂNû","anlam":"1.Hanımefendi. 2.Hindistan’da soylu hanımlara verilen unvan.","kategori":"dil","osmanli":"بانو"},{"kelime":"BARAS","anlam":"Derinin rengini kaybettiren ve büyük beyaz lekeler hâsıl eden bir hastalık, abraş, vitiligo, alaca.","kategori":"muamelat","misal":"O (İsâ aleyhisselâm), İsrailoğullarına bir elçi olacak (ve onlara şöyle diyecek:) Size Rabbinizden bir mûcize getirdim. Size çamurdan bir kuş sureti yapar, ona üflerim ve Allah’ın izni ile o kuş oluverir. Yine Allah’ın izni ile körü ve baraslıyı iyileştirir, ölüleri diriltirim. Ayrıca evlerinizde ne yiyip ne biriktirdiğinizi size haber veririm. Eğer inanan kimseler iseniz, bunda sizin için bir ibret vardır. (Âl-i İm…","osmanli":"برص"},{"kelime":"BARBAR","anlam":"1.Eski Yunanlıların ve sonra da Romalıların kendilerinden olmayanlar için kullandıkları tabir. 2.Gayrımedenî, vahşi; mer-hametsiz.","kategori":"dil","osmanli":"باربار"},{"kelime":"BÂRGÂH","anlam":"1.İzinsiz girilemeyecek yer. 2.Yüksek divan, huzur.","kategori":"dil","misal":"Nerdesin şevketli Sultan Hamid han, Feryadım varır mı bârgâhına? (Rızâ Tevfik)","osmanli":"بارﮔاه"},{"kelime":"Bârgâh-ı Kibriyâ","anlam":"Allahü teâlâ-nın huzuru.","kategori":"akaid","osmanli":"كبرياء بارﮔاه"},{"kelime":"BÂRÎ","anlam":"Bir kalıptan döker gibi muntazam yaratan; yoktan var eden; yarattıklarını farklı şekiller ve hususiyetlerle birbirinden ayıran mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elBârî).","kategori":"akaid","misal":"Allahü teâlâ Bârî’dir. (Haşr sûresi: 24) Yedi gün arka arkaya yüz defâ elBârî ism-i şerîfine devam eden belâlardan selâmet bulur, kurtulur. (Elİstigâsetü’l-Kübrâ)","osmanli":"بارئ"},{"kelime":"BÂRIK","anlam":"Cennet’te bir nehir.","kategori":"akaid","osmanli":"بارق"},{"kelime":"BARNABAS İNCÎLİ","anlam":"Hazret-i Îsâ’nın havârîlerinden Barnabas’ın görüp işittiklerini yazdığı ve 325 tarihli İznik Konsili’nde emsali onlarcası gibi apokrif (uydurma) sayılıp okunması reddedilen İncil.","kategori":"dil","osmanli":"انجيلى بارناباس"},{"kelime":"BASAR","anlam":"1.Göz, görme. 2.Âletsiz ve şartsız olarak, gizli ve âşikâr her şeyi görmesi mânâsına Allahü teâlânın sübûtî sıfatlarından.","kategori":"akaid","osmanli":"بصر"},{"kelime":"BASÎR","anlam":"1.Gören. 2.Gizli ve açık her şeyi hakkıyla her zaman görücü mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elBasîr).","kategori":"akaid","misal":"Şüphesiz O, semî‘dir (her şeyi hakkıyla işitendir), Basîr’dir. (İsrâ sûresi: 1) Bir kimse Cum‘a namazından sonra yüz kere elBasîr ism-i şerîfini söylerse, Allahü teâlâ onun kalb gözünü açar. (Elİstigâsetü’l-Kübrâ)","osmanli":"بصير"},{"kelime":"BASÎRET","anlam":"İşlerin iç yüzünü görebilme; seziş; kalb gözü.","kategori":"tasavvuf","misal":"Ey basîret sahipleri! İbret alınız! (Haşr sûresi: 2) Allahü teâlâ mü’minlere basîretler ve nûrlar lütûf eylemiştir. Onlar bu sâyede işlerin iç yüzünü anlarlar. Resûlullah efendimizin sallallahü aleyhi ve sellem “Mü’min Allah’ın nûru ile nazar eder” hadîs-i şerîfi bu mânâda anlaşılmalıdır. (İmâm-ı Kuşeyrî)","osmanli":"بصيرت"},{"kelime":"BÂSIT","anlam":"1.Yayan, yayıcı. 2.Zamanı gelince ruhu bedene yayan; ilahî nimetleri kâinâta yayan; kullarına bol bol nimet veren mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elBâsıt). Bir kimse ellerini açıp, elBâsıt ism-i şerîfini söylese maişeti genişler. Bol rızka kavuşur. (Elİstigâsetü’l-Kübrâ)","kategori":"akaid","osmanli":"باسط"},{"kelime":"BAŞLIK","anlam":"Anadolu’da evlenirken kızın ailesinin erkekten talep ettiği mal veya para.","kategori":"dil","misal":"İslâmiyet’te kızın akrabasının kızı teslim etmek için, başlık olarak damattan aldıkları şeyler rüşvet olur. Damada geri vermeleri lâzım olur. Damat va‘d etse bile, vermesi lâzım olmaz. Vermiş ise geri alabilir. (Hamza Efendi Risâlesi, Fetâva’l-Hayriyye)","osmanli":"باشلق"},{"kelime":"BAŞÖRTÜSÜ","anlam":"Erkek ve kadı-nın sıcaktan veya soğuktan korunmak yâhud dinî veya örfî sebeblerle başına örttüğü ku-maş, himâr, eşarp.","kategori":"osmanli","misal":"Baş, kadınların örtmesi dinen farz olan yerle-rindendir. Geniş manto ve kalın başörtüsü âdet olan yerlerde bu şekilde örtünmeleri; çarşaf, ih-ram gibi başka örtülerin âdet olduğu yerlerde bunlarla örtünmeleri farzdır. (Şerhu Tefhîmat)","osmanli":"اورتوسى باش"},{"kelime":"BAŞSAĞLIĞI","anlam":"Ölünün ardın-dan yakınlarına verilen teselli, ta‘ziye.","kategori":"dil","misal":"Ölünün yakınlarına üç gün başsağlığında bu-lunmak sünnettir. Uzakta ise mektup yazılır. Hazret-i Peygamber aleyhisselâm, çocuğunu kaybeden Muaz bin Cebel radıyallahü anha başsağlığı mektubu yazmıştır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"صاغليغى باش"},{"kelime":"BAST","anlam":"1.Genişlemek, açılmak, kap-lamak. 2.Gönül ferahlığı; ruhen rahatlama.","kategori":"dil","misal":"Hesapta mahreci (paydayı) kıymetine ha-lel gelmeyecek şekilde büyültme ameliyesi. Allahü teâlânın cemâl sıfatının tecellîsiyle kalbde hâsıl olan sükûn, huzur ve ferahlama. Kabzın zıddı. Bast ve kabz, bu tarîkte uçulan kanattır. Kabz ile üzgün ve bast ile sevinçli olmayalar. (Mek-tûbât-ı İmâm-ı Rabbânî)","osmanli":"بسط"},{"kelime":"BÂSûR","anlam":"Kalın bağırsak ve makat et-rafındaki siyah kan damarlarının şişmesin-den ve bazen iltihaplanmasından dolayı ma-kat içinde ve dışında peyda olan memeler yüzünden makattan kan veya cerahat gelme. Mayasıl. Hemoroid.","kategori":"dil","misal":"Bâsûr, idrar, gâita damlaları bedene, çamaşıra bulaşırsa afv olur. İnsanın ve hayvanın kanı-nın, yara, çıban suyunun avuç içi kadarı afv olur. Bâsûr memesi çıkarsa, eliyle yerine iade ettiği takdirde abdesti bozulur. Kendi kendine girerse bozulmaz (İbni Âbidîn)","osmanli":"باسور"},{"kelime":"BÂT SATIŞI","anlam":"1.Boş, beyhûde.","kategori":"dil","misal":"Muhayyerlik gibi şartların bulunmadığı mutlak satış. Bey‘ü’l-Bât. BÂTIL: باطل (A. Butlan’dan) Bozuk; geçersiz. Göğü, yeri ve bunların arasında bulunan şeyleri bâtıl olarak yaratmadık. (Sâd sûresi: 27) Aranızda birbirinizin mallarını (kumar, fâiz, gasp gibi) bâtıl (yollar) ile yemeyin. (Ba-kara sûresi: 188) Hak gelince bâtıl gider. Bâtıl her zaman gidicidir. (İsrâ sûresi: 81) En güzel söz, (şâir) Lebîd’in 'Allahü teâlâdan başka her şey bâtıldır’ sözüdür. (Hadîs-i şerîf-Müslim)","osmanli":"صاتيشى باط"},{"kelime":"BÂTIL","anlam":"1.Boş, beyhûde.","kategori":"fikih","misal":"Bozuk; geçersiz. Göğü, yeri ve bunların arasında bulunan şeyleri bâtıl olarak yaratmadık. (Sâd sûresi: 27) Aranızda birbirinizin mallarını (kumar, fâiz, gasp gibi) bâtıl (yollar) ile yemeyin. (Bakara sûresi: 188) Hak gelince bâtıl gider. Bâtıl her zaman gidicidir. (İsrâ sûresi: 81) En güzel söz, (şâir) Lebîd’in 'Allahü teâlâdan başka her şey bâtıldır’ sözüdür. (Hadîs-i şerîfMüslim)","osmanli":"باطل"},{"kelime":"BÂTIN","anlam":"1.İç; içyüz. 2.Gizli, görünmeyen. 3.His uzuvları ile hissedilemeyen, hayâl gücü ile hayâl edilemeyen, akıl ile anlaşılamayan mânâsına Allahü teâlânın Es-mâ-i hüsnâsından (elBâtın). Allahü teâlâ Bâtındır. (Hadîd sûresi: 3) Bu dünyada, amel, ibâdet lâzımdır. Bu amellerin, bâtına çok yardımı vardır. Bâtının ilerlemesi, zâhirin (görünüşün, bedenin) İslâmiyet’e uymasına bağlıdır. O hâlde bu dünyada her zaman, zâhir de bâtın da İslâmiyet’e muhtaçtır. Bedenin işi İslâmiyet’e uymak, bâtının işi de, İslâmiyet’in (ona uymanın) meyvelerini toplamaktır. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"باطن"},{"kelime":"BÂTINİYYE (Bâtınîlik)","anlam":"Kur’ân-ı kerîm ve hadîs-i şerîflerin bir zâhirî, bir de bâtınî mânâsı olduğunu; kendilerinin bu bâtınî mânâyı sezdikleri için, şeriat ile mükellef olmadıklarını iddia eden Gulat-ı Şia’dan (aşırı Şia’nın) bir mezheb.","kategori":"dil","misal":"Tarihte Karmâtî, Sâibî, İsmailî, Mübârekî, Bâbekî, Hurufî, Haşhaşî diye bilinen fırkalar buradan çıkmıştır. Yemenli Yahudi dönmesi Abdullah bin Sebe tarafından tohumu atılan bu gizli mezheb, Meymun bin Keddah adlı yine Yahudi asıllı göz doktoru tarafından filizlendirilmiştir. Hicrî 255 senesinden sonra aleniyete dökülmüştür. Bunlar âyet ve hadîslerin bâtınî (gizli) mânâlarını ancak kendi İmâmlarının bildiğine inanır…","osmanli":"باطنيه"},{"kelime":"BATMAN","anlam":"Ölçek. 850 gram civarında bir ağırlık ölçüsü. Menn. Müd.","kategori":"dil","osmanli":"باطمان"},{"kelime":"BATN","anlam":"2.Nesil.","kategori":"dil","misal":"Karın. Çocuğun yaşayacağı ümit edildiği zaman, ço-cuğu çıkarmak için, ölmüş anasının batnını yar-mak câiz olur. İmâm-ı A‘zâm Ebû Hanîfe, bu sebeb ile, bir kadının karnının yarılmasını em-retmiş, kurtarılan çocuk, çok yaşamıştır. (Eşbâh)","osmanli":"بطن"},{"kelime":"BAYGINLIK (Bayılmak)","anlam":"Şiddetli heyecan, korku, güneş çarpması, tiksindirici koku, kan görmek, çok şiddetli acı ve ağrı gibi sebeblerle kalb vuruşlarının ve nefes alma hareketlerinin gerçekten veya görünüşte durmasıyla meydana gelen ve kişinin dinî ve hukukî ehliyetini ortadan kald…","kategori":"fikih","misal":"Bayılınca abdest veya namaz bozulur. Bayılan kimse, 24 saatte ayılamazsa, yani üzerinden altı namaz vakti geçerse, iyi olduğunda, bu namazlarını kazâ etmez. (İbni Âbidîn)","osmanli":"بايغينلق"},{"kelime":"BÂYİ‘","anlam":"Bey‘ eden, satan, satıcı.","kategori":"muamelat","misal":"Bâyi‘, bey‘ (satım) akdinin rüknüdür. Akdin sıhhati için bâyi‘in akıllı olması şarttır. Bülûğa ermemişse, vasîsinin izniyle satabilir. (İbni Âbidîn)","osmanli":"بايع"},{"kelime":"BAYRAM","anlam":"1.Her din veya millete ait hususî günler. 2.Çok sevinmek; eğlence.","kategori":"dil","misal":"Resûlullah aleyhisselâm, Medînelilerin câhi-liyye âdetlerinden kalma bayramları kutladık-larını görünce; “Allahü teâlâ size onlardan daha hayırlı iki bayram (Ramazan ve Kur-ban bayramı) ihsân buyurdu” dedi. (Hadîs-i şerîf-Ebû Dâvûd) Bayram bineklere binenler için değildir Ancak hatâ ve isyânı bırakanlar içindir. (Behlül Dânâ)","osmanli":"بايرام"},{"kelime":"Bayram Hutbesi","anlam":"Bayram namazından sonra Cum‘a hutbesi gibi okunup hükmü sünnet olan hutbe.","kategori":"ibadet","osmanli":"سى خطبه بايرام"},{"kelime":"BAYRAMİYYE","anlam":"Hacı Bayram-ı Velî hazretlerinin bir koldan Bâyezîd-i Bistâmî’ye, diğer koldan Hasen-i Basrî’ye ulaşan tasavvuftaki yolu.","kategori":"tasavvuf","misal":"Bayramîlik.","osmanli":"بايراميه"},{"kelime":"BAYTAR","anlam":"Hayvan hekimi, veteriner. BÂZÂ: بازا (F) “Geliniz!” mânâsına “Bâzâ, Bâzâ, Her an çe hestî bâzâ…” diye başlayan ve Mev-","kategori":"dil","misal":"lânâ Celâleddin Rûmî’ye mâl edilen, ama as- lında meşhur mutasavvıf Ebû Saîd Ebû’l-Hayr’a ait olduğu tahmin edilen meşhur söz. (Tercü-mesi: Gel, gel, her kim olursan ol gel! Allah’a ikilik koşanlardan, mecûsilerden, puta tapan-lardan da olsan gel! Bizim dergâhımız ümit-sizlik dergâhı değildir. Tövbeni yüz defa boz-muş olsan bile, yine gel!)","osmanli":"بيطار"},{"kelime":"BED","anlam":"Fena, yaramaz, çirkin; fenalık.","kategori":"tasavvuf","osmanli":"بد"},{"kelime":"BEDÂ","anlam":"1.Bir şeye sonradan muttali olma; sonradan ortaya çıkma. 2.Allahü teâlâ için muhal sıfatlardan.","kategori":"akaid","osmanli":"بداء"},{"kelime":"BEDBAHT","anlam":"Kötü talihli, şanssız, bahtı kara.","kategori":"dil","misal":"Bedbaht o kimsedir ki, Mevlâsının istemediği şeyleri ister. (Mektûbât-ı İmâm Rabbânî)","osmanli":"بدبخت"},{"kelime":"BEDDuÂ","anlam":"Kötü duâ. Bir kimsenin aleyhine yapılan duâ.","kategori":"ibadet","misal":"İnkisâr, ilenme, ilenç. Kendinize, evlâdınıza, bedduâ etmeyiniz. Ola ki kabul olur. Hayır duâ ediniz. (Hadîs-i şerîfMüslim, Ebû Dâvûd) Resûlullah aleyhisselâm Bi‘r-i Maûne’de yetmiş hâfızı şehîd edenlere bedduâ buyurmuştur. (Hadîs-i şerîfMüslim, Ebû Dâvûd, Nesâî)","osmanli":"بددعاء"},{"kelime":"BEDEL","anlam":"1.Karşılık, ivaz. 2.Bir şeyin ye-rini tutan şey.","kategori":"dil","misal":"Abdest almak için az vakti olup, Cum‘a nama-zını kaçırmamak için teyemmüm câiz değildir. Çünki Cum‘a namazının bedeli öğle namazı-dır. (İbni Âbidîn) Başkasının parasıyla onun yerine hacca gi-den kimse. Kendisine hac farz olduktan sonra, bir engel sebebiyle gidemeyecek hâle gelen kimse, ye-rine bir bedel gönderir veya bunu vasîyet eder. (İbni Âbidîn)","osmanli":"بدل"},{"kelime":"BEDENE","anlam":"Hacda kesilecek kurbanlardan deve ve sığırlara verilen isim.","kategori":"ibadet","misal":"Kıran ve temettü haccı yapanların, Harem’de şükür kurbanı kesmesi vâcibdir. Buna hedy kurbanı denir. Bu da ya bir yaşını geçmiş koyun veya keçi, yâhud beş yaşını geçmiş deve ile iki yaşını tamamlamış sığırdan olur. Bu hayvan sağılmaz, üstüne binilmez. Hacda işlenen bazı suçlar için keffâret olarak da bedene kesilmesi gerekir. (İbni Âbidîn) BEDESTÂN بدستان (Bedesten): (F) Değerli eşya ve mücevherlerin alınıp satıldığ…","osmanli":"بدنه"},{"kelime":"BEDEVÎ","anlam":"Bâdiye (sahra, çöl) halkın-dan olan kimse; göçebe.","kategori":"dil","osmanli":"بدوى"},{"kelime":"BEDEVİYYE","anlam":"Aslı Rifâiyye’ye ulaşan ve 675 (m.1276) senesinde Mısır’da vefat eden Seyyid Ahmed Bedevî hazretlerinin tasavvuftaki yolu.","kategori":"tasavvuf","osmanli":"بدويه"},{"kelime":"BEDÎ‘","anlam":"1.Eşi ve benzeri olma-yan bir şeyi yapan.","kategori":"dil","misal":"Sözün garip (alışılmadık) hitap ve kelime-lerle söylenerek güzelleştirilmesi. Âlet ilimlerinden belâgatın üç kısmından biridir. Diğer ikisi meâni ve beyândır. “Rahman, arş üzerine istivâ etti, yani gâlib oldu” âyetinde bedî‘ sanatı vardır. Bir insanın çok misafirper-ver olduğunu anlatmak için, “Ocağında çok kül vardır” demek de böyledir. (Mevdûâtu’l-Ulûm) Benzeri görülmemiş, işitilmemiş, bilinmemiş şeyleri yaratıp, zâtına, sıfatına ve zâtî kemal-lerine bunlar ile yol bulduran mânâsına Al-lahü teâlânın Esmâ-i hüsnâsından (el-Bedî‘). (Allah) göklerin ve yerin Bedî‘idir. O, bir şeyin olmasını irâde edince (dileyince), ona “Ol!” der, o da olur. (Bakara sûresi: 117) El-Bedî‘ ism-i şerîfini yetmiş bin kere söyleyen kimse, kendisine gelecek olan musîbetten kur-tulur. (El-İstigâsetü’l-Kübrâ)","osmanli":"بديع"},{"kelime":"BEDÎHÎ","anlam":"1.Akla kendili-ğinden gelen. 2.Delilsiz, açık, besbelli.","kategori":"dil","misal":"(A. Bedâhat’ten)","osmanli":"بديهى"},{"kelime":"BEDÎHİYYÂT","anlam":"Delili ve ispatı ge-rekmeyen açık şeyler. Bedîhî’nin çokluk hâli.","kategori":"dil","osmanli":"بديهيات"},{"kelime":"BEHÂÎLİK (Bahâîlik)","anlam":"XIX. asrın ikinci yarısında Şia’nın aşırılarından İranlı Behâullah tarafından Bâbîliğin devamı olarak ortaya çıkarılan, mabed ve hac yeri kurucusunun 1892’de öldüğü Akkâ’da bulunan, 19 sayısına kudsiyet atfeden İslâmiyet harici bir mezheb.","kategori":"dil","osmanli":"بهائيلك"},{"kelime":"BEHûR","anlam":"Tütsü, buhur.","kategori":"dil","misal":"Behûr otuna, öd ağacı talaşları ve günnük de-nilen ağacın zamkı da karıştırılıp, bir kaptaki ateşe konur. Teneşir etrafında üç def ‘a dolaştırı-larak, cenaze çıkan dumanlara tutulur. Cum‘a ve bayram namazından evvel câmide behûr yakmak müstehabdır. (İbni Âbidîn)","osmanli":"بخور"},{"kelime":"BEKÂ","anlam":"1.Bâkilik; devamlılık; sebat; önceki hâl üzere kalma. 2.Allahü teâlânın sıfatlarından. 3.Tasavvufta, fenâdan sonraki mertebe.","kategori":"tasavvuf","osmanli":"بقا"},{"kelime":"Bekâ-Billah","anlam":"Allah ile bâki olma; dâimâ Allahü teâlâyı hatırlama; Tasavvufta fenâ fil-lah’tan sonraki makam.","kategori":"akaid","misal":"Tasavvuf yolcusu (sâlik), ilerlemesinin ilk ba-samağında, Allahü teâlânın ilim sıfatı tecelli eder ve mahlûklara ait bilgilerin hepsi unu-tulur. Buna fenâ denir. Sonraki safhada anla-tılamayan, işaretle bildirilemeyen ve isim ve-rilemeyen, bir şeye benzetilemeyen, kimsenin bilemediği, anlayamadığı mertebeye varılır. Bu seyre (bekâ) denir. Sonunda bekâ billah hâsıl olur. Sâlik, her şeyi yok, yalnız Allah’ı var bilir. Böylece evliyâ olur. (Mektûbât-ı İmâm Rabbânî)","osmanli":"بالله بقا"},{"kelime":"BEKÂRET","anlam":"1.Kızlık, bâkirelik, bikr. 2.Henüz cinsî bir tecrübe yaşamama.","kategori":"dil","osmanli":"بكارت"},{"kelime":"BELÂ","anlam":"Musibet, âfet; sıkıntı; düşkünlük. Kulumu bir belâ ile ibtilâ (imtihân) ettiğim vakit sabreder ve ziyaretçilerine beni şikâyette bulunmazsa, ona etinden iyi et, kanından iyi kan veririm. İyileştiği vakit günahsız olarak iyileşir. Onu öldürürsem rahmetime, yani Cennet’ime gider. (Hadîs-i Kudsî-Muvattâ) Kazâ gelmez Hak yazmasa","kategori":"hadis","misal":"Belâ gelmez kul azmasa. (Atasözü)","osmanli":"بلاء"},{"kelime":"BELÂ","anlam":"(A.Menfi bir suale verilen “Evet” cevabı. Kıyamet gününde, biz bundan habersizdik demeyesiniz diye Rabbin Âdem oğulların-dan, onların bellerinden zürriyetlerini çı-kardı, onları kendilerine şâhid tuttu ve dedi ki: “Ben sizin Rabbiniz değil miyim?” (On-lar da) “Belâ, (buna) şâhid olduk” dediler. (A‘râf sûresi: 172-3)","kategori":"dil","osmanli":"بلي"},{"kelime":"BELÂGAT","anlam":"1.Sözün düzgün, kusur-suz ve yerinde söylenmesi. 2.Bunu öğreten ve Kur’ân-ı kerîmde geçen sanatları bildiren ilim.","kategori":"dil","misal":"Bedî‘, beyân ve me‘âni olmak üzere üçe ayrılır. Kur’ân-ı kerîmin aslındaki îcâz ve belâgatini muhâfaza ederek tercüme etmek mümkün de-ğildir. Fakat meâl (geniş açıklamalı) olarak ter-cümesi mümkündür. (Seâdet-i Ebediyye)","osmanli":"بلاغت"},{"kelime":"BELED","anlam":"Mahkemesi yahud karakolu ya da pazarı olan küçük iskân merkezi.","kategori":"osmanli","misal":"Belde.","osmanli":"بلد"},{"kelime":"BELKIS","anlam":"Süleymân aleyhisselâm zamanında Yemen’de Sebe’ şehrinde hüküm süren Himyerîlerden bir kadın sultan.","kategori":"dil","osmanli":"بلقيس"},{"kelime":"BENC","anlam":"(Bkz. Banotu)","kategori":"dil","osmanli":"بنج"},{"kelime":"BENDE","anlam":"Köle; bağlı.","kategori":"dil","osmanli":"بنده"},{"kelime":"BENÎ HÂŞİM","anlam":"Hâşimoğulları, Resûlullah aleyhisselâmın büyük dedesi Hâşim bin Abdi Menâf ’ın oğlu Abdülmuttalib’in soyundan gelenler.","kategori":"dil","misal":"Allahü teâlâ, İsmâil (aleyhisselâm) evlâdından Kinâne ismindeki kimseyi ve onun sülâlesinden, Kureyş adlı zâtı beğenip, seçti. Kureyş evlâdından da, Benî Hâşim’i seçti. Onlardan da, beni beğenip seçti. (Hadîs-i şerîfMüslim) Ey Benî Hâşim! Nefslerinizi ateşten (Cehennem’den) koruyunuz. Ey kızım Fâtıma, nefsini ateşten kurtar. Çünki sizleri kurtarmak için Allahü teâlânın sizinle alâkalı irâdesine mâni olacak hiçbir şe…","osmanli":"حاشم بنى"},{"kelime":"BENÎ İSRÂÎL","anlam":"İsrâîloğulları. Bir adı da İsrâîl olan Ya’kub aleyhisselâmın 12 oğlunun soyundan gelenler.","kategori":"dil","misal":"Ey Benî İsrâîl! Size verdiğim nimeti ve sizi bir zamanlar diğer insanlara üstün kıldığımı hatırlayın. Bana verdiğiniz sözü yerine getirin ki, ben de getireyim. Yoksa benden korkun. (Bakara sûresi: 40, 47)","osmanli":"اسرائيل بنى"},{"kelime":"BERÂ‘ÂT","anlam":"Zekât toplayan memurların, köylüden alacakları zekât ve uşrun cins ve mikdarını gösteren senedler.","kategori":"hadis","misal":"Berâ‘et’in çokluk hâli. Köylü, berâ‘ât ile zekâtını ödemiş olduğunu ispat eder. Senedlerde yazılı mal mevcut olmadığı için berâ‘ât satışı câiz değildir. (İbni Âbidîn). (Bkz. Bey‘)","osmanli":"براعت"},{"kelime":"BERÂ’ET","anlam":"Berî’ olma. Bir suçtan, bir dâvâdan temize çıkma, aklanma; bir borçtan kurtulma.","kategori":"muamelat","osmanli":"برائت"},{"kelime":"BERÂT","anlam":"1.Rütbe, nişan, memuriyet ve imtiyaz verildiğine dair vesika. 2.(mecazen) Kurtuluş vesikası.","kategori":"osmanli","osmanli":"برات"},{"kelime":"BERÂT GECESİ","anlam":"Şâban ayının on beşinci gecesi.","kategori":"osmanli","misal":"Bu gecenin, gemilerden harac alan memurun, haracı aldığına dair bir berat (vesîkamakbuz) yazıp vermesinde olduğu gibi, Allahü teâlânın bu gecede mü’minler için, böyle bir vesika yazdığından dolayı bu ismi aldığı söylenir. (Mefâtihü’l-Gayb) Biz onu (Kur’ân’ı) mübarek bir gecede indirdik. Her hikmetli işe, yani katımızdan verilen her emre o gecede hükmedilir. (Duhan 3-5) Bu gecenin Berât Gecesi olduğu hakkındaki rivây…","osmanli":"سى كيجه برات"},{"kelime":"BEREKÂT","anlam":"Bereketler. Bereket’in çokluk hâli.","kategori":"ibadet","osmanli":"بركات"},{"kelime":"BEREKET","anlam":"1.Bolluk. 2.Saadet, mutluluk.","kategori":"dil","misal":"Az malın, çok faydası olması. Ya Rabbi! Ümmetimden sabah erken kal-kanlara bereket ver. (Hadîs-i şerîf-Tirmizî) Böylece İbrâhim’i ve Lût’u (Irak’daki Nem-rûd’dan) kurtarıp, içinde âlemlere bereket-ler verdiğimiz arza (Şam diyârına) çıkardık. (Enbiyâ sûresi: 71)","osmanli":"بركت"},{"kelime":"BERÎ’","anlam":"1.Berâ’et eden; suçsuz. 2.Uzak, temiz.","kategori":"dil","osmanli":"برئ"},{"kelime":"BERÎD","anlam":"1.Posta; posta teşkilatı. 2.Orta yürüyüşle dört saatlik yol; dört fersah (12 mil=4800 zirâ‘=22179 metrelik) bir mesafe ölçüsü.","kategori":"dil","misal":"Hoş geldin eyâ berîd-i cânân. (Şeyh Gâlib)","osmanli":"بريد"},{"kelime":"BERK","anlam":"Şimşek.","kategori":"dil","misal":"Berk urup çıktı evimden nâgehân, Göklere dek nûri el doldu cihân. (Mevlid-i Süleyman Çelebi)","osmanli":"برق"},{"kelime":"BERR","anlam":"1.Doğru sözlü, hayırlı. 2.İhsân eden, iyilik eden, yani her iyilik kendisinden olan, îmân edip, iyi amel-ler yapmayı nasip edip, bunlara karşılık âhi-rette sevab ve dünyada sıhhat, kuvvet, mal, makam, evlâd ve yardımcılar veren mânâ-sına Allahü teâlânın Esmâ-i hüsnâsından (el-Berr). 3.Toprak, kara.","kategori":"akaid","misal":"Çokluk hâli ebrâr.","osmanli":"بر"},{"kelime":"BESÂİR","anlam":"İbretli görünüşler, ibretler. Basîret’in çokluk hâli.","kategori":"dil","osmanli":"بصائر"},{"kelime":"BEŞER","anlam":"İnsan, âdemoğlu. (Bkz. Benî Âdem)","kategori":"dil","osmanli":"بشر"},{"kelime":"BEŞÎR","anlam":"2.Kabirde mü’minlere suâl soran melekler.","kategori":"akaid","misal":"1 “Müjdeleyici” mânâsına Peygamber efendimizin isimlerinden. (Ey Resûlüm!) Biz seni; mü’minleri, inananları beşîr, kâfirleri de azap ile korkutucu, uyarıcı olarak gönderdik. (Bakara sûresi: 119) Kabirlerde kâfirlere ve âsî Müslümanlara azap edecek melekler ve kabirde suâl soracak melekler vardır. Suâl meleklerine münker ve nekir denir. Mü’minlere soranlara ise mübeşşir ve beşir denir. (İtikadnâme)","osmanli":"بشير"},{"kelime":"BESMELE","anlam":"“Rahman ve rahîm olan Allah’ın adıyla” mânâsına gelen “Bismillâhirrahmânirrahîm” sözü.","kategori":"akaid","misal":"Yemeğe besmele ile başlayın. Şeytân, besmele çekilmemiş taamı kendine helâl görür. (Hadîs-i şerîfMüslim, Taberânî) Abdest almaya, yemeğe, içmeye ve her mübârek işe başlarken Besmele çekmek Peygamber efendimizin âdet-i şerîflerinden olup sünnettir. (İbni Âbidîn)","osmanli":"بسمله"},{"kelime":"Besmele Duâsı","anlam":"Bismillahillezî.. diye başlayan ve okunduğu zaman belâlardan korunmasına vesile olan duâ.","kategori":"ibadet","misal":"Resûlullah aleyhisselâm Enes radıyallahü anha şu duâyı öğretti ve buyurdu ki, Bu duâyı, sabah üç kere okuyan kimse akşama kadar, akşam okuyan da, sabaha kadar belâdan kurtulur. Hiç derd, belâ gelmez. Duâ şudur: “Bismillâhillezî lâyedurru ma‘asmihî şey‘ün filerdı velâ fissemâî ve hüvessemî‘ul’alîm” [O Allah’ın adıyla ki, onun ismiyle yerde ve gökte hiçbir şey zarar veremez.] (Bostan, Tergibü’s-Salât) İmâm-ı Rabbânî h…","osmanli":"دعاسى بسمله"},{"kelime":"BETûL","anlam":"1.Kesilen; ayrı duran. 2.Er-keklerden çok sakınan. 3.Hazret-i Meryem ve Hazret-i Fâtımâ’nın lakabı.","kategori":"dil","misal":"Betîl. (İbra-nice Bethulah.)","osmanli":"بتول"},{"kelime":"BEVL","anlam":"İdrar; işeme.","kategori":"dil","misal":"Cünüb olup, bevl yapmadan gusl eden kimse-den, sonra menînin geri kalan kısmı, şehvetsiz aksa, tekrar gusl lâzım olur. Bevl kaba necâset-tir. İğne ucu kadar elbiseye sıçrayan bevl dam-laları sakınmak güç olacağı için afv edilmiştir. Ayakta bevletmek, gusledilen yere su akıp git-miyorsa bevletmek, topraktaki deliklere bevlet-mek hadîs-i şerîfle men edilmiştir. (İbni Âbidîn)","osmanli":"بول"},{"kelime":"BEY‘","anlam":"Satmak.","kategori":"muamelat","misal":"Allahü teâlâ bey‘i, helâl ve fâizi haram kıldı. (Bakara sûresi: 275)","osmanli":"بيع"},{"kelime":"Bey‘-i Fâsid","anlam":"Aslı dine uygun, fakat sıfatı uygun olmayan satış.","kategori":"muamelat","misal":"Bey‘ yani satış akdinin bazı sıhhat şartlarına riayet edilmemesi, akdi fâsid, geçersiz kılar. Semenin, mütekavvim mal olmadığı; yahud mebî veya semenin mikdarı ve evsâfının bilinmediği; satış veresiye ise taksit sayısının ve ödeme tarihlerinin tayin edilmediği yahud fâsid şarta bağlanan satıştır. Caiz değildir, günahtır. Böyle satışı derhal bozmak, alınanları iade etmek vâcibdir. (Bey‘ ve Şirâ Risâlesi)","osmanli":"فاسد بيع"},{"kelime":"Bey‘ ve Şirâ","anlam":"Alışveriş, malların ve paraların kendileriyle veya birbirleriyle karşılıklı rızâ dairesinde mülk edinmek üzere mübâdelesi.","kategori":"muamelat","misal":"(Bey’, satma; şirâ, satın almak.) Bir kimse İmâm-ı A‘zam Ebû Hanîfe hazretlerine “Vakitlerimi ibâdet ile geçirmek istiyorum. Bana bir şey yaz da, hep onu yapayım?” diye ricada bulundu. İmâm-ı A‘zam rahmetullahi aleyh de, bey‘ ve şirâ bilgilerini yazıp verince; “Bu tüccarlara lâzım olur. Ben evimde oturup ibâdet ile meşgul olacağım” dedi. Cevabında; “Yiyecek ve giyecek lâzım olmayan kimse var mı? İslâmiyet’in alışver…","osmanli":"شراع و بيع"},{"kelime":"BEYÂN","anlam":"1.Açık olma. 2.Açıklama, bildirme. 3.Konuşma, yazma, anlama, anlatma, ifâde etme.","kategori":"muamelat","misal":"Çokluk hâli beyânât’tır. (Allahü teâlâ) insanı yarattı. Ona beyânı öğretti. (Rahmân sûresi: 3-4) Beyânın öylesi vardır ki büyüleyici bir tesire sahiptir. (Hadîs-i şerîfBuhârî)","osmanli":"بيان"},{"kelime":"BEYHûDE","anlam":"Boş yere. Bîhûde, boşuboşuna.","kategori":"muamelat","misal":"Malını beyhûde yere sarf ve telef edene sefîh denir. Sefîh, akıllı çocuk gibidir. Malını hediye edemez. Alışveriş ve kirâ gibi muameleleri vasîsinin izniyle muteber olur. (İbni Âbidîn)","osmanli":"بيهوده"},{"kelime":"BEYNûNET","anlam":"1.Ayrılık. 2.Ara-lık, mesafe. 3.Asronomide gezegen-yer-güneş üçlüsünün teşkil ettiği açı.","kategori":"dil","misal":"Talâktan sonra beynûnet hâsıl olur. Tekrar ev-lenmenin câiz olduğu hâllerde beynûnet-i sugrâ; eşlerin hülle olmadan tekrar evlenemeyeceği üç talâkla boşama gibi hâllerde beynûnet-i kübrâ vardır. (İbni Âbidîn)","osmanli":"بينونت"},{"kelime":"BEYT","anlam":"Ev.","kategori":"muamelat","osmanli":"بيت"},{"kelime":"BEYTuLLAH","anlam":"1.“Allahü teâlânın evi” mânâsına Mekke-i Mükerreme’de Mescid-i harâmın ortasında bulunan ve Müslümanların kıblesi olan binâ. 2.Câmi, mescid.","kategori":"muamelat","misal":"Beytullah olan câmi ve mescidlerde ibâdet etmeyip, dünya kelâmı ile meşgul olmak tahrîmen mekrûhtur. Yani harama yakın günahtır. Ateş odunu yiyip bitirdiği gibi câmide dünya kelâmı konuşmak da, insanın sevablarını giderir. (Tahtâvî)","osmanli":"الله بيت"},{"kelime":"BEYYİNE","anlam":"1.Açık delil. 2.Mucize. 3.Kur’ân-ı kerîm.","kategori":"muamelat","misal":"(Ey Mekkeliler! Bu kitabı, Kur’ân-ı kerîmi) “Bizden evvel kitap yalnız iki taifeye (Yahudi ve Hristiyanlara) indirildi. Biz ise (konuştuğumuz dilde olmadığından) onu okumaktan gâfilleriz” dememeniz için yahud; “Bize de kitab indirilseydi, muhakkak onlardan daha fazla hidâyete ererdik” dememeniz içindir. İşte size Rabbinizden (konuştuğunuz dilde) apaçık bir beyyine, bir hidâyet ve bir rahmet gelmiştir. Artık Allahü t…","osmanli":"بينه"},{"kelime":"BEZZÂZ","anlam":"Manifaturacı, kumaş tâciri.","kategori":"dil","osmanli":"بزاز"},{"kelime":"BÎ‘A","anlam":"Hristiyan mâbedi, kilise.","kategori":"dil","misal":"Bî’adaki küfür alâmetleri boşaltılırsa, namaz kılmak mekrûh olmaz. (İbni Âbidîn)","osmanli":"بيعه"},{"kelime":"Bî‘at-i Rıdvân","anlam":"Allahü teâlânın ağaç altında söz verenlerden râzı olduğunu beyan buyurması üzerine “Rızâ sözleşmesi” mânâsına Hicretin altıncı senesi Hudeybiye’de Semûre denilen ağacın altında 1400 sahâbînin Resûlullah aleyhisselâma, emirlerini kayıtsız şartsız yerine getire…","kategori":"dil","misal":"Andolsun ki, Allahü teâlâ, seninle o ağacın altında bî‘at ettikleri vakit mü’minlerden râzı olmuştur. (Feth sûresi: 18) Resûlullah, Bedr’de ve Rıdvan bî‘atında bulunan bir kimsenin cenâzesi getirildiğinde, onun üzerine dokuz tekbir alırdı. Fakat Bedr’de bulunup da Rıdvân bî‘atında bulunmamış, yahud da Bî‘at-i Rıdvan’da bulunup da Bedr’de bulunmamış bir kimse getirildiğinde, onun üzerine yedi tekbir alırdı. Ne Bedr,…","osmanli":"تعيب ناوضر"},{"kelime":"BÎ-ÇûN ve BÎ-ÇÎGûNE","anlam":"11.âyet-i kerîmesinde; “O’nun misli, benzeri gibi hiçbir şey yoktur” meâ-lindeki sözdür.","kategori":"akaid","misal":"“Nasıl olduğu anlaşılamayan” ve “Hiçbir şeye benzemeyen” mânâsına Allahü teâlânın keyfi-yetinin bilinemeyeceği ve akıl ile anlaşılama-yacağının tasavvufî ifadesi. Allahü teâlâ bî-çûn ve bî-çîgûnedir. Akıl neyi düşünür neyi tasavvur (hayâl) ederse etsin, O değildir. Allahü teâlâ ötelerin ötesidir. (Mektû-bât-ı İmâm-ı Rabbânî) Allahü teâlâyı anlatan en iyi kelime, en geniş ibâre, Şûrâ sûresi, Buna Fârisî dilinde “bî-çûn ve bî-çîgûne” denir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"بيﭽيگونه بيﭽون،"},{"kelime":"Bİ‘SET","anlam":"(A. Ba’s’dan) Gönderme, gönde-rilme. Bir peygambere peygamber olduğu-nun bildirilmesi.","kategori":"akaid","misal":"Peygamber efendimiz kırk yaşında iken mîlâdî 610 senesi Ramazan ayının on yedinci Pazar-tesi günü Cebrâil ismindeki melek tarafından Peygamber olduğu kendisine bildirildi. Bu se-neye Bi‘set senesi denir. (İtikadnâme)","osmanli":"بعثت"},{"kelime":"BİD‘","anlam":"Üç ile on arası bir sayı; birkaç.","kategori":"dil","osmanli":"بضع"},{"kelime":"Bid‘at Ehli","anlam":"İtikad veyâ amelde bid‘at çıkaran veya yayan kimse.","kategori":"akaid","misal":"(Hadîs-i şerîfİbn-i Mâce) Bid‘at ehli, bid‘a-tinden vazgeçinceye kadar, Allahü teâlâ tövbesini kabul etmez. (Hadîs-i şerîfTaberânî)","osmanli":"اهلى بدعة"},{"kelime":"Bid‘at Fırkası","anlam":"Hadîs-i şerîfte, itikad ve amelde Resûlullah aleyhisselâm ve Eshâb-ı kirâmının yolunda olmadığı için Ce-hennem’e gidecekleri bildirilen yetmiş iki fır-kadan her biri.","kategori":"hadis","misal":"Bunlar umumiyetle Şiîlik, Hâricîlik, Mûtezile, Mürcie, Cebriye, Mücessime, Müşebbihe fır-kaları olup, son zamanlarda buna Vehhabîlik de eklenmiştir.","osmanli":"سى فرقه بدعة"},{"kelime":"Bid‘at-ı Hasene","anlam":"“Güzel bid‘at” mânâsına bir sünneti ortadan kaldırmayan veya daha iyi yapılmasını temin eden bid‘at.","kategori":"hadis","misal":"Eskiden gelen İslâm âlimleri, bid‘atte bir güzellik görmüş olacaklar ki, bunlardan bazılarına, hasene ismini vermişlerdir. Fakat bu fakir, bu noktada onlara uymuyorum ve bid‘atlerden hiçbirini güzel görmüyorum. Hepsini karanlık ve bulanık görüyorum. Mevlid okumak, minâre, türbe yapmak gibi sünnete muhalif olmayan yeniliklere, yani birinci asırda aslı bulunanlara bid‘at ismini bulaştırmamalı. Bunlara sünnet-i hasene…","osmanli":"حسنه بدعة"},{"kelime":"Bid‘at-ı Seyyie","anlam":"“Kötü bid‘at” mânâsına dinde yapılan ve sünnette değişikliğe sebeb olan yenilik.","kategori":"hadis","misal":"Âlimler, ameldeki, ibâdetteki bid‘atleri ikiye ayırmışlar, hasene ve seyyie demişlerdir. Buna göre yasak olan bid‘at budur.","osmanli":"سيئه بدعة"},{"kelime":"Bid‘at Sâhibi","anlam":"İtikad veya amelde bir bid‘at çıkaran veya yayan yâhud icma‘ya aykırı itikadda olan kimse.","kategori":"akaid","misal":"Bir kimse bid‘at sahibinden buğz ederek yüz çevirirse, Allah onun kalbini korkudan emin kılar ve imanla doldurur. Kim bid‘at sahibine sert muamele ederse, Allahü teâlâ onu en büyük korku gününde emin kılar. Kim bid‘at sahibini aşağı görürse, Allah onu Cennet’te yüz derece yükseltir. Kim de bid‘at sahibine selam verir veya onunla dostluk ederse, Muhammed aleyhisselâma indirileni hafife almış olur. (Hadîs-i şerîfHatîb…","osmanli":"صاحبى بدعة"},{"kelime":"BİHAKKILLAH","anlam":"Allah hakkı için. Üzerime hak olsun demek yemîn olmaz. Bi-hakkıllah (Allah hakkı için) demek yemîn olur. (İbni Âbidîn)","kategori":"dil","osmanli":"الله بحق"},{"kelime":"BİKR (Bekr)","anlam":"1.Evlenmemiş erkek veya kız. 2.Bekârlık; bâkirlik. 3.Dokunulmamış olma. 4.Erken davranma.","kategori":"dil","osmanli":"بكر"},{"kelime":"BİLLÂHİ","anlam":"“Allahü teâlâya yemîn ederim”","kategori":"akaid","misal":"mânâsına, yemîn sözlerinden biri. (Bkz. Yemîn)","osmanli":"بالله"},{"kelime":"BİNT","anlam":"Kız çocuğu, (ferâizde) sulbiyye.","kategori":"miras","misal":"Çokluk hâli benât gelir.","osmanli":"بنت"},{"kelime":"BİRA","anlam":"Arpa ile şerbetçiotundan yapı-lan, gaz çıkardığı, köpük yaptığı için ve tadı acı, keskin olduğu için azı da çoğu da, her ne","kategori":"dil","misal":"maksatla içilirse içilsin, âlimlerin çoğuna göre haram olan hafif alkollü bir içki.","osmanli":"بيرا"},{"kelime":"BİRÂDER","anlam":"Erkek kardeş.","kategori":"dil","osmanli":"برادر"},{"kelime":"BİRR","anlam":"Hayır, iyilik.","kategori":"dil","misal":"Birr ve takvâda birbirinize yardım edin. (Mâide sûresi: 2)","osmanli":"برر"},{"kelime":"BİSMİLLAH","anlam":"Allah’ın adıyla mânâsına her hayırlı işe girişirken söylenmesi gereken mübarek söz.","kategori":"akaid","osmanli":"الله بسم"},{"kelime":"BOLŞEVİK","anlam":"Bolşevizm dokt-rini taraftarı olup, 1917’den sonra Komünist Parti’yi kurdukları için Avrupa’da komünist karşılığı kullanılan bir tabir. Zıddı Menşevik.","kategori":"dil","osmanli":"بولشوك"},{"kelime":"BONO","anlam":"Borç için verilen sened.","kategori":"hadis","osmanli":"بونو"},{"kelime":"BORÇ","anlam":"1.Bir hukukî muamele neticesinde kişilerin zimmetinde sâbit olan ve bir işin yapılması veya yapılmaması yahud bir şeyin teslim edilmesi şeklinde tezâhür eden mükellefiyet, deyn. 2.Vecibe, vazife.","kategori":"muamelat","misal":"Ey îmân edenler! Muayyen bir vâde ile birbirinize borçlandığınız zaman, onu yazın (sened yapın)... (Bakara sûresi: 282) En iyiniz, borcunu iyi ödeyeninizdir. (Hadîs-i şerîfKeşfü’l-Hafâ) Acele etmek şeytândandır. Beş şey bundan müstesnâdır: Kızını evlendirmek, borcunu ödemek, cenâze hizmetlerini çabuk yapmak, misâfiri doyurmak, günah işleyince hemen tövbe etmek. (Hadîs-i ŞerîfTirmizî)","osmanli":"بورﭺ"},{"kelime":"BOŞAMAK","anlam":"Nikâh bağını çözmek, evliliğe son vermek.","kategori":"dil","misal":"(Bkz. Talâk)","osmanli":"بوشامق"},{"kelime":"BOZA","anlam":"Arpa, darı, mısır, buğday gibi hububatın ekşitilmesiyle yapılan koyuca, tatlı veya mayhoş içecek.","kategori":"dil","osmanli":"بوزا"},{"kelime":"BOZGuNCuLuK","anlam":"Yeryüzünde fitne ve karışıklık çıkarmak; zulüm ve taşkın-lık yaparak haddi aşmak, fesat.","kategori":"dil","osmanli":"بوزغونجيلق"},{"kelime":"BRAHMA","anlam":"1.Brahmanizm adlı dinde kâinâtın mutlak ruhu, yüce yaratıcı, tanrı. 2.Brahma dininin esaslarını bildirdiğine inanılan melek, Birmîhâ.","kategori":"dil","osmanli":"بيراهما"},{"kelime":"BRAHMAN (Brehmen)","anlam":"1.Brahmanizm adlı dinin râhiblerine verilen isim. 2.Brahma dininde cemiyeti meydana getiren dört kast (sınıf) arasında birinci sırada gelen sınıf ve bu sınıfa mensub.","kategori":"dil","osmanli":"برهمن"},{"kelime":"BRONZ","anlam":"Bakırla kalayın alaşımı. Prinç. Tunç.","kategori":"dil","misal":"Nu‘mân bin Beşîr, Resûlullah’ın yanına geldi. Parmağında altın yüzük vardı. “Cennet’e gir-meden önce, niçin Cennet zînetini kullan-mışsın?” buyurdu. Demir yüzük kullanmaya başladı. Bunu görünce; “Niçin Cehennem eş-yası taşıyorsun?” buyurdu. Bunu da çıkardı. Bronz, yani tunçtan yüzük taktı. Bunu görünce; “Niçin sende put kokusu duyuyorum?” buyurdu. “Nasıl yüzük kullanayım, yâ Resûlallah” dedi. “Gümüş yüzük takabilirsin. Ağırlığı da bir miskâli geçmesin ve sağ eline tak!” buyurdu. (Bostan, Mevâhib-i Ledünniyye)","osmanli":"برونز"},{"kelime":"BÜDELÂ","anlam":"“Bedeller” mânâsına Ricâ-lü’l-Gayb denilen Allahü teâlânın insanlardan gizlediği evliyâ zâtlardan.","kategori":"akaid","misal":"Bu velîler, başkasının suret ve siretine girerek iş gördüğü için, yerine geçen mânâsına bedel veya bedîl denir. Üç yüz velînin 7 tanesine bu isim verilir. Muhyiddin Arabî yedi iklimin işleriyle vazifeli yedi ebdâl ile büdelâyı aynı saymıştır.","osmanli":"بدلاء"},{"kelime":"BuDİST","anlam":"Budizm adlı din veya mezhebe mensub olan.","kategori":"dil","misal":"(Bkz. Budizm)","osmanli":"بوديست"},{"kelime":"BuĞD-I FİLLÂH","anlam":"“Allah için nefret” mânâsına Allah düşmanlarını Allah için sevmemek ve onlardan uzaklaşmak.","kategori":"akaid","misal":"(Bkz. Hubb-i Fillâh ve Buğd-i Fillâh)","osmanli":"الله فى بغض"},{"kelime":"BuHRÂN","anlam":"Kriz, bunalım, sıkıntılı devre. BuHTEC: بحتج (A) Pişirilmekle kabarıp ekşi-yen ve sarhoşluk veren yaş üzüm suyu. Keli-","kategori":"dil","misal":"menin aslı Farsça ‘buhte’dir.","osmanli":"بحران"},{"kelime":"BÜHTÂN","anlam":"Bir kimseye, onda olma-yan bir kusuru veya günahı yüzüne karşı is-nat etme, açıkça iftirâ atma.","kategori":"dil","misal":"Mü’min erkek ve mü’min kadınlara, işleme-dikleri (bir günahı, bir suçu isnâd etmek sû-retiyle) ezâ edenler, muhakkak bir bühtân ve apaçık bir günah yüklenmişlerdir. (Ah-zâb sûresi: 58) Bir kimse için söylenen ku-sur, onda varsa, bu söz gıybet, yoksa büh-tân olur. (Hadîs-i şerîf-Müslim) Her yere burnunu sokma! Ya bir kazâya, yâ-hud bir bühtâna uğrarsın. (Berîka)","osmanli":"بهتان"},{"kelime":"BuHuR","anlam":"(Bkz. Behûr) BuLûĞ: بلوغ (Bkz. Bülûğ) BuLuNTu: بولونطو (Bkz. Lukata)","kategori":"dil","osmanli":"بخور"},{"kelime":"BÜLûĞ","anlam":"Ergenlik yaşına girme, yetişme. Gusl abdesti almanın farz olma yaşıdır. Erkekte ihtilâm, kızda âdet görmeyle başlar. Alt sınırı kızda 9, erkekte 12, üst sınırı her ikisinde 15 yaştır. Bülûğa eren, ibâdetle mükellef; günâh ve suçundan mes’ûldür.","kategori":"ibadet","osmanli":"بلوغ"},{"kelime":"BuNAK","anlam":"1.Zekânın, zihnin ve aklın zayıflayarak vazifesini hakkıyla yapamaması. 2.Kişinin cezaî mes’ûliyetini kaldıran; hukukî mes’ûliyetini daraltarak mümeyyiz ço-cuk seviyesine indiren ehliyet ârızası.","kategori":"dil","misal":"Şuuru ve aklı zayıf, ma‘tuh. BuNAMA: بونامه (T) Atehi.","osmanli":"بوناق"},{"kelime":"BÜNYÂD","anlam":"1.Asıl, esas, temel. 2.Bina, yapı.","kategori":"dil","misal":"Etmiş, ol beden serâyın üstâd, Adl-ü dâd ile, esâsın bünyâd.","osmanli":"بنياد"},{"kelime":"BuRAK","anlam":"Mi‘rac’da Resûlullah aleyhisselâmın üzerine bindiği, erkekliği veya dişiliği olmayan, çok süratli gittiği için şimşek mânâsına bu ismi taşıyan Cennet bineği.","kategori":"akaid","misal":"Bana Burak getirildi. O, katırdan küçük, merkepten büyük, uzun ve beyaz bir hayvandır. Ayağını gözün görebildiği yerin ötesine kadar (rahatça) atabiliyordu. Ona bindim. (Hadîs-i şerîfŞifâ-i Şerîf)","osmanli":"براق"},{"kelime":"BuRC","anlam":"1.Kale, hisar çıkıntısı, kule. 2.Yu-varlak bina. 3.Güneşin ayrıldığı on iki kısımdan her biri, burç. 4.Herhangi bir şekilde gösteri-len ve hususî ismi bulunan hareketsiz yıldız-lar topluluğu.","kategori":"dil","misal":"Çokluk hâli burûc gelir. Burclar yarısı kuzeyde, yarısı güneyde olmak üzere 12 tanedir: 1) Koç (Hamel), 21 Mart- 19 Nisan. 2) Boğa (Sevr), 20 Nisan-20 Ma-yıs. 3) İkizler (Cevzâ), 21 Mayıs-21 Haziran. Yengeç (Seretân), 22 Haziran-22 Temmuz. Aslan (Esed), 23 Temmuz-22 Ağustos. 6) Başak (Sünbüle), 23 Ağustos-22 Eylül. 7) Te-razi (Mîzân) 23 Eylül-23 Ekim. 8) Akrep, 24 Ekim-21 Kasım. 9) Yay (Kavs), 22 Kasım-21 Aralık. 10) Oğlak (Cediy), 22 Aralık-19 Ocak 11) Kova (Delv) 20 Ocak-18 Şubat. 12) Balık (Hût), 19 Şubat-20 Mart. Yılın her ayında gü-neş bu burçlardan birine girer. Güneşin Koç burcuna girmesiyle ilkbahar; Yengeç burcuna girmesiyle yaz; Terâzi burcuna girmesiyle son-bahar; Oğlak burcuna girmesiyle kış başlar. Bazıları burçların hareketlerinden bir takım ne-ticeler çıkarmakta; insanların hayatının buna göre cereyan edeceğini söyleyerek bazı kehâ-net ve şahsiyet tasvirleri yapmaktadır. Bunun İslâmiyet’te yeri yoktur. Gaybı Allah’dan başka kimse bilmez. (İbni Âbidîn)","osmanli":"برج"},{"kelime":"BÜRD","anlam":"Ekseriya pamuk veya ketenden ince dokunmuş, umumiyetle renkli ve çizgili kumaş. Hırka. Hülle. Bürde’nin çokluk şeklidir. Kim çocuğunu kaybeden bir anneye ta‘zi-yede bulunursa Cennet’te ona bir bürde giy-dirilir. (Hadîs-i şerîf-Tirmizî)","kategori":"hadis","misal":"Asr-ı Saadette Arabistan’da erkek ve kadınla-rın yaygın olarak giydiği iç ve dış elbisedir. Ay-rıca bir kimseyi taltif etmek gerektiğinde, bürde giydirmek âdettir. Hazret-i Peygamber aleyhis-selâmın kendisini şiirle öven Kâb bin Züheyr’e bürde giydirdiği için, şiirin adı Kaside-i Bürde kalmıştır. Sehl bin Sa‘d es-Sâidî, Resûlullah aley-hisselâmın Zarib adlı atıyla yarıştı. Resûlullah aleyhisselâm ona bir bürd-i yemânî giydirdi. Necran taraflarında dokunanına Bürd-i Nec-rânî, Yemen tarafında dokunanına ise Bürd-i Yemânî denir. (Terâtib)","osmanli":"برد"},{"kelime":"BuRHÂN","anlam":"1.Bir dâvâyı ispat eden ke-sin delil. 2.Mantık ilminde mukaddime deni-len ve kesin netîceye ulaştıran iki cümle (söz). 3.Rufâîlere mahsus şiş vurmak, ateşe girmek gibi harikalar için kullanılan söz.","kategori":"dil","misal":"(Yahudiler ve Hristiyanlar) dediler ki: “Ya-hudi ve Nasrânî olanlardan başkası aslâ Cennet’e girmeyecek!” Bu onların kurun-tularıdır. (Habîbim onlara) söyle: Eğer (bu iddiânızda) doğru kimseler iseniz, burhâ-nınızı getiriniz. (Bakara sûresi: 111)","osmanli":"برهان"},{"kelime":"Burhân-ı Tatbîk","anlam":"Kelâm ilminde Allahü teâlânın varlığını ve kadîm (ezelî) olduğunu (başlangıcının olmadığını) ispatta kullanılan delillerden biri.","kategori":"akaid","misal":"Allahü teâlâ, kadîm (ezelî) olmasaydı, hâdis (sonradan yaratılmış) olsaydı, O’nu yaratan bir yaratıcı bulunurdu. Bu yaratıcı kadîm (bir başlangıcı yok) ise, Allah O’dur. Hâdis (bir başlangıcı var) ise, O’nu yaratan biri lâzım olur. Böylece, kadîm olmayan yaratıcılar zinciri mevcut olur. Bu zincire teselsül denir. Teselsül ise, muhâldir (imkânsızdır), olacak şey değildir. Teselsülün muhâl olduğu Burhân-ı tatbîk ile i…","osmanli":"تطبيق برهان"},{"kelime":"BuRKA","anlam":"Bilhassa Afganistan’da kadınların giydiği, vücudu tepeden tırnağa örten ve yüzü de peçe ile kapatan tek parça dış elbisesi.","kategori":"osmanli","misal":"Berku‘","osmanli":"برقع"},{"kelime":"BÜRûZ","anlam":"1.Zâhir olmak; görünmek, or-taya çıkmak. 2.Bir velînin sevenlerinde bazı sı-fatlarının zâhir olması, görünmesi.","kategori":"akaid","misal":"Bir velî, sevenini terbiye etmek, yetiştirmek için, onda bürûz etmeksizin, Allahü teâlânın ver-diği bir kuvvetle, kendi yüksek sıfatlarını (hâl-lerini), o kimseye aks ettirir, aktarır. (Abdül-hakîm Arvâsî)","osmanli":"بروز"},{"kelime":"BûY","anlam":"Koku.","kategori":"dil","osmanli":"بوى"},{"kelime":"BÜYÜ","anlam":"İlme, fenne uymayan gizli sebebler kullanarak garip işler yapmayı sağlayan ilim, sihir, gözbağcılık.","kategori":"fikih","misal":"(Bkz. Sihr)","osmanli":"بويو"},{"kelime":"BÜYÜK GÜNAHLAR","anlam":"(Bkz. Kebâir)","kategori":"dil","osmanli":"ﮔناهلر بيوك"},{"kelime":"CA‘FERİYYE","anlam":"Halîfeliğin Hazret-i Ali ve onun soyundan gelen 12 İmâma geçmesi-nin vahy ile emredildiğine inanan, bu sebeble ilk üç halîfe ve onlara bağlananları reddeden, amel bakımından 12 İmâmdan Ca’fer-i Sâdık’a bağlı olduğu iddiâsında bulunan bir Şiî fırkası. İmâmiyye. İsnâaşeriyye. Revâfıd.","kategori":"dil","misal":"Ca’ferîlerin Ehl-i beyti seviyoruz demeleri, Hris-tiyanların Hazret-i Îsâ’yı seviyoruz demelerine benzer. Çünki Hristiyanlar Hazret-i Îsâ’nın di-nini bozup değiştirdikleri gibi, Ca’feriyyenin ina-nışları da İmâm-ı Ca’fer-i Sâdık’ın yoluna hiç uymamaktadır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"جعفريه"},{"kelime":"CÂH","anlam":"İtibar; makam.","kategori":"dil","misal":"Bir kimse, Allahümme innî es’elüke bi-câh-i Ne-biyyikel-Mustafâ (Ey Allah’ım senden Muham-med aleyhisselâmın itibarı hatırına istiyorum) diyerek bir duâ etse, duâsı red olunmaz. Bu-nunla beraber, ufak tefek dünya işleri için, Resû-lullah’ı “sallallahü teâlâ aleyhi ve sellem” vesîle etmek, edebe uygun olmaz. (Mir’at-ı Haremeyn) Ey sahib-i ikbâl ü câh! İtmeyesin zulme nigâh! (Tâcüttevârih)","osmanli":"جاه"},{"kelime":"CAHÎM","anlam":"Cehennem’in dördüncü tabakasına verilen ad.","kategori":"akaid","misal":"Cahîm ise azgınlara apaçık gösterilmiştir. Ve onlara Allahü teâlâyı bırakıp ibâdet ettikleriniz hani nerede? Size yardım edebiliyorlar mı? Yâhud kendilerini (azaptan) kurtarabiliyorlar mı? denir. (Şu’arâ sûresi: 91-93)","osmanli":"جحيم"},{"kelime":"CÂİZ","anlam":"Cevaz, ruhsat, izin verilen; harâm olmayan.","kategori":"fikih","misal":"Kur’ân-ı kerîmi abdestsiz ezberden okumak câizdir. Fakat abdestli okumak daha iyidir. (İbni Âbidîn) Bâyi’ (satıcı) bu malı bin liraya sana sattım, dese, müşteri (alıcı) da bir şey söylemeyerek alsa câiz olur. Bâyi’ malı verse, müşteri parasını verse, hiçbir şey söylemeden câiz olur. (Fethü’l-Kadîr) Amca, dayı kızı ile evlenmek câizdir. Fakat tenzîhen mekrûhtur. (Fethü’l-Kadîr)","osmanli":"جائز","alternatif":["caiz"]},{"kelime":"CÂİZE","anlam":"1.Mükâfat. 2.Misafire, misafirlik hakkı cümlesinden olarak yapılan hususî ikram.","kategori":"fikih","osmanli":"جائزه"},{"kelime":"ÇÂK","anlam":"Yarık, yırtık; yırtmaç.","kategori":"dil","osmanli":"ﭼاك"},{"kelime":"CÂM","anlam":"1.Sırça, cam. 2.Bardak, kadeh, şişe ve toprak cinsinden şarap kadehi.","kategori":"dil","misal":"Sûsadım gâyet harâretden kat’î Sundular bir câm dolusu şerbeti (Mevlid-i Süleyman Çelebi)","osmanli":"جام"},{"kelime":"CÂME","anlam":"Elbise, çamaşır.","kategori":"dil","osmanli":"جامه"},{"kelime":"CÂMEKÂN","anlam":"Câmelik, elbise soyunu-lacak yer, câmeken.","kategori":"dil","osmanli":"جامكان"},{"kelime":"CÂMEKIYYE","anlam":"Vakfın gelirlerinden, vazife karşılığında hizmetlilere verilen ücret.","kategori":"osmanli","misal":"Câmekıyyenin satışı câiz değildir. Çünki ücret hak edilmiş ise de, kabz edilmemiş (alınmamış), mülk olmamıştır. (İbni Âbidîn)","osmanli":"جامكيه"},{"kelime":"CÂMİ‘","anlam":"1.Cem’ eden, toplayan. 2.Müslümanların ibâdet etmek için toplandıkları yer, mâbed. 3.Allahü teâlânın Esmâ-i hüsnâsından.","kategori":"ibadet","misal":"Hayızlı ve cünüp olanın Câmi’e girmesi harâmdır. Abdestsiz olanın girmesi mekrûhtur. (Dürer) (elCâmi’). Çeşitli hakîkatleri ve enfüs (iç) ve âfâktaki (dıştaki) zıt işleri birleştirici, kıyâmet gününde yeryüzünde olan cinleri, insanları ve mahlûkâtı bir araya getirici, insanların dağılmış bulunan et, kemik, kafa ve diğer organlarını tekrar birleştirici.","osmanli":"جامع"},{"kelime":"CÂMİ‘A","anlam":"Topluluk.","kategori":"ibadet","osmanli":"جامعه"},{"kelime":"CAMPHRE","anlam":"Uzak Doğu’da yetişen bir çeşit taflandan elde edilip hekimlikte kullanılan, ayrıca cenâzeyi yıkama suyuna katılan beyaz ve yarı saydam, kolaylıkla parçalanan bir madde, kâfur.","kategori":"ibadet","osmanli":"قمفر"},{"kelime":"CÂN","anlam":"Rûh.","kategori":"akaid","osmanli":"جان"},{"kelime":"CÂNÂN","anlam":"Sevgili, gönül verilmiş. Sabreyle gönül, derdine dermân ere umma, Can atma oda beyhude cânân ere umma. (Hoca Dehhânî)","kategori":"dil","osmanli":"جانان"},{"kelime":"CANAVAR","anlam":"1.Canlı, ya-şayan, can taşıyan, can götüren. 2.Zararlı, vahşi hayvan. 3.Şer’an artığı necis olan hayvan. 4.Domuz. 5.(Mecaz) Çok zararlı insan.","kategori":"dil","misal":"(Cânâver) Hayvan ruhunun ikinci kuvveti olan hareket kuvveti de iki türlüdür: Birincisi, şehevî kuv-vettir. İnsanlar ve hayvanlar, şehvet kuvvetleri ile kendilerine tatlı gelen ve muhtaç oldukları şeyleri isterler. Bunlara behîmî kuvvet de denir. İkincisi gadabî kuvvettir. Bu kuvvet ile, kendi-lerine çirkin, zararlı olan şeyleri def ’ ederler, kovarlar. Bunlara canavar kuvvetler de denir. (Ahlâk-ı A’lâî) İhramdaki bir kimse, yılan, akreb, kerten-kele veya fareyi öldürebilir. Kargaya taş atar öldürmez. Kuduz köpek, çaylak, saldıran ca-navar da öldürülür. (Hadîs-i şerîf-Ebû Dâvûd) Hazret-i Ömer’in huzûru ile, bir havuza tesadüf edildikte, orada hazır bulunan, Amr-İbnül-Âs hazretleri, havuzun sahibine, senin havuzuna canavarlar gelir mi, diye sorduğunda, Öme-rü’l-Faruk hazretleri, havuz sahibinin cevap vermesine meydan vermeyerek “Sen bize haber verme!” buyurmuştur. Bu habere göre, misafire takdim edilen taâmın, nereden hasıl olduğunu, ev sahibine sorması câiz olmaz. (Ni’met-i İslâm) Kedi gerçi, canavardır. Canavarın artığı ise, ne-cistir. Lâkin onun ehlî kısmı ile ibtilâ umumî olduğundan onun artığını, şer’î münir, mekrûh mertebesinde tutup, ona necis dememiştir. Vah-şisinde yani dağ kedisinde o sebeb câri olma-dığından onun artığı, sâir eti yenmeyen vah-şilerin artıkları gibi necistir. (Ni’met-i İslâm) CÂNÎ: جانى (A) Cinâyet işleyen. CÂNÎ: جانى (F) Azîz, candan sevilen.","osmanli":"آور جان"},{"kelime":"CÂNİB","anlam":"Taraf, cihet, yan, yön.","kategori":"dil","osmanli":"جانب"},{"kelime":"CÂR","anlam":"(A. Civâr’dan) Komşu.","kategori":"dil","osmanli":"جار"},{"kelime":"CÂR","anlam":"Uzun ve geniş örtü, ferâce.","kategori":"dil","osmanli":"جار"},{"kelime":"ÇÂR","anlam":"Dört. (Cihâr).","kategori":"dil","osmanli":"ﭼار"},{"kelime":"ÇARH","anlam":"1.Çark, tekerlek. 2.Felek, gök. 3.Yaka. 4.Ok yayı. 5.Çakır, doğan. 6.Tef. 7.Dev-reden, dönen.","kategori":"dil","misal":"Eğer insan, eğer melek, Yalvarırım, geçer dilek. Vefâsızdır çarh-ı felek, Dedikleri gerçek imiş. (Kuloğlu)","osmanli":"ﭼرخ"},{"kelime":"CÂRİYE","anlam":"Kadın köle.","kategori":"osmanli","misal":"Sizden hiç biriniz, sakın kölesine; “Kölem”, “Câriyem” diye seslenmesin. “Yiğidim, oğlum”, “Kızım” desin. Onlar da size “Efendim” desin. (Hadîs-i şerîfMüslim) Kölenin, câriyenin nafakasını vermek efendisine farzdır. (İbni Âbidîn)","osmanli":"جاريه"},{"kelime":"ÇARŞAF","anlam":"Müslüman kadınların tesettür maksadıyla giydikleri kolsuz, bol ve geniş üst örtüsü, çar.","kategori":"osmanli","misal":"Aslı çâderşeb.","osmanli":"ﭼارشاف"},{"kelime":"CÂSİLÎK (Câselîk)","anlam":"Hristiyanlıkta ibadetleri yaptıran din adamı, başpapaz.","kategori":"dil","misal":"Katolikos.","osmanli":"جاثليق"},{"kelime":"CÂSûS","anlam":"Gizli haberler öğrenerek haber veren.","kategori":"dil","osmanli":"جاسوس"},{"kelime":"CÂYI‘","anlam":"(A. Cu’dan) Aç, acıkmış.","kategori":"dil","misal":"Sadaka-i tetavvu’â (nâfile sadakayı) istemek, kazanmaya kudreti olmayan muhtaç içindir. Muhtaç, nefsine mevt veya maraz isâbetinden havf eden câyı’ veya bedeni örtecek şeye kudreti olmayan açık kimsedir. (Mektâbat-ı Ma’sûmiyye)","osmanli":"جايع"},{"kelime":"CÂZİB","anlam":"Cezbeden, çeken; çekici, sevimli.","kategori":"tasavvuf","osmanli":"جاذب"},{"kelime":"CÂZİBE","anlam":"Çekim, çekicilik.","kategori":"dil","osmanli":"جاذبه"},{"kelime":"CEBBÂR","anlam":"1.Çok cebreden, çok zorlayan. 2.Allahü teâlânın Esmâ-i hüsnâsından (elCebbâr).","kategori":"dil","misal":"Kullarının hâllerini ıslâh edip, onları tövbeye götüren, dilediğini yaptırmaya gücü yeten. Allahü teâlâ Cebbârdır. (Haşr sûresi: 23) Cebbâr (olan Allahü teâlâ) kıyâmet günü mülkü olan gökleri ve yerleri eline (kudretine) alır ve buyurur ki: “Cebbâr benim, Melik benim. Hani cebbârlar, mütekebbirler (kendilerini büyük görenler) nerede?” (Hadîs-i şerîfİbn-i Mâce) Sabah v…","osmanli":"جبار"},{"kelime":"CEBEL","anlam":"Dağ. Çokluk hâli cibâl gelir.","kategori":"dil","osmanli":"جبل"},{"kelime":"CEBEL-İ NûR","anlam":"“Nûr dağı” mânâsına Mekke-i Mükerreme yakınında Resûlullah","kategori":"dil","misal":"aleyhisselâma ilk vahyin geldiği mübârek dağ. Cebelü’n-Nûr.","osmanli":"نور جبل"},{"kelime":"CEBHE","anlam":"1.Kaşlarla saç bitim yerine kadar olan kısım, alın. 2.Taarruz eden ordu-nun sağ ve sol kanatlarının ortası. 3.Muha-rebe mıntıkası. 4.Cihet.","kategori":"dil","misal":"Cephe.","osmanli":"جبهه"},{"kelime":"CEBÎN","anlam":"1.Korkak; alçak. 2.Alın.","kategori":"dil","osmanli":"جبين"},{"kelime":"CEBİR","anlam":"Aritmetik.","kategori":"dil","osmanli":"جبير"},{"kelime":"CEBÎRE","anlam":"Kırık ve çıkığın iki yanına bağlanan esnek tahtalar.","kategori":"dil","misal":"Gusülde ve abdestte cebîre üzerine mesh câiz-dir. (Halebî)","osmanli":"جبيره"},{"kelime":"CEBR","anlam":"1.Zorlama, zor kullanma. 2.İrâde ve ihtiyârın zıddı. 3.Telâfi, ıslah, kırığı sarma.","kategori":"dil","misal":"İnsanın hiç bir irâde ve ihtiyâra sahip olmadığını, her şeyin cebr elinde esir olduğunu ve varlığının otomatik, fakat zembereği kırık bir makina gibi olduğunu iddiâ etmek yanlıştır. (Seâdet-i Ebediyye)","osmanli":"جبر"},{"kelime":"CEBRÂÎL (aleyhisselâm)","anlam":"Dört büyük melekten biri.","kategori":"dil","misal":"Gerçekten Cibrîl, Kur’ân-ı kerîmi, Allahü teâlânın izniyle senin kalbine indirdi. (Bakara sûresi: 97) Cebrâîl aleyhisselâm çok defâ Resûlullah’ın huzuruna, Eshâb-ı kirâmdan Dıh-ye-i Kelbî sûretinde gelirdi. Resûlullah efendimiz sallallahü aleyhi ve sellem şöyle buyurdu: “Dıhye-i Kelbî, Cebrâil’e benzer,” (Hadîs-i şerîfİbni Sa’d, İhyâ)","osmanli":"جبرائيل"},{"kelime":"CEBRÎ","anlam":"1.Zorla, zor altında. 2.Aritmetikle alâkalı.","kategori":"dil","osmanli":"جبرى"},{"kelime":"CEBRİYYE","anlam":"Hicrî I. asrın sonlarında ve II.","kategori":"dil","misal":"asrın başlarında Cehm bin Safvân tarafından ortaya çıkarılan, “İnsan hiçbir şey yapamaz. İnsan istese de, istemese de her şeyi Allah yaratır. Günah işleyenler ve kâfirler ma’zûrdurlar, mes’ûl olmazlar” şeklinde inanan bid‘at fırkası.","osmanli":"جبريه"},{"kelime":"CED (Cedd)","anlam":"Dede, büyük baba, ana ve babanın babalarıyla onların yukarıya doğru uzanan babaları.","kategori":"miras","misal":"Çocuğun velâsi baba, yoksa ceddir. (Mültekâ)","osmanli":"جد"},{"kelime":"CEDDE","anlam":"Nine, büyük anne. Çokluk hâli ceddât gelir.","kategori":"miras","osmanli":"جده"},{"kelime":"CEDÎD","anlam":"Yeni, kullanılmamış; pek az za-mandan beri bilinen veya mevcut olan.","kategori":"dil","osmanli":"جديد"},{"kelime":"CEFÂ","anlam":"Eziyet, incitme.","kategori":"dil","misal":"Hayâ îmândandır. Fuhuş (çirkin şeyler) söy-lemek cefâdandır. Îmân Cennet’e, cefâ Ce-hennem’e götürür. (Hadîs-i şerîf-Buhârî)","osmanli":"جفا"},{"kelime":"CEFFELKALEM","anlam":"Düşünmeksizin, birden, hemen.","kategori":"dil","osmanli":"القلم جف"},{"kelime":"CEHÂLET","anlam":"Câhillik, bilmeme, bilgisizlik. Âyetlerimize îmân edenler sana geldiği za-man şöyle de: “Allah’ın selâmı üzerinize ol-sun. Rabbiniz, size rahmet ve merhamet vaad buyurdu. Öyle ki, içinizden kim cehâ-letle bir fenâlık yapmış da arkasından tövbe edip (hâlini) düzeltmişse (Allah’ın ona mağ-fireti vardır.) Muhakkak ki Allah, Gafûr’dur, Rahîm’dir. (En’âm sûresi: 54) Bilmedikleri-nizi sorunuz. Cehâletin ilâcı sualdir (yani sorup öğrenmektir). (Hadîs-i şerîf-Sünen-i Ebû Dâvûd)","kategori":"hadis","misal":"Dârülislâm’da (İslâm memleketinde) bulunan bir kimsenin, meselâ namazın ve orucun farz, içki, kumar ve zinânın haram olduğuna dair cehâleti mâzeret kabul edilmez. (İbni Âbidîn)","osmanli":"جهالت"},{"kelime":"CEHD","anlam":"Gayret, olanca gücü ve kuvveti sarf etmek.","kategori":"muamelat","misal":"Onlar; “Allah ölen bir kimseyi diriltmez” diye cehd ile yemin ettiler. (Nahl sûresi: 38)","osmanli":"جهد"},{"kelime":"CEHENNEM","anlam":"“Derin kuyu” mânâsına kâfirlerin devamlı, günahkâr Müslümanların ise, günahları kadar âhirette azap görecekleri yer.","kategori":"akaid","misal":"kurtulamayacaklardır.) Bunlara Cehennem’de, çok acı azap vardır. (Nisâ sûresi: 14) Ey Müslümanlar topluluğu! Allahü teâlânın sizi teşvik ettiği şeye rağbet ediniz ve O’nun yasak ettiklerinden kaçınınız. Allahü teâlânın korkuttuğu şeylerden korkunuz. O’nun cezâsından, azâbından Cehennem’inden korkunuz. Şu bulunduğunuz dünyada O’nun ateşinden bir damla kıvılcım bulunmuş olsa, bu dünyayı sizler için yaşanmaz hâle getir…","osmanli":"جهنم","alternatif":["cehennem"]},{"kelime":"ÇEHİZ","anlam":"Ailesinin evlenen kıza verdiği eşya, cihâz, çeyiz.","kategori":"dil","misal":"Baba, kızına çehiz hazırlayıp sıhhatte iken kendisine teslim ettikten sonra ölse, vârisler bundan hak isteyemez. (Ukûdü’d-Dürriyye)","osmanli":"ﭼهيز"},{"kelime":"CEHL","anlam":"Câhillik, cehâlet, ilimsizlik, bil-gisizlik. (Bkz. Cehâlet)","kategori":"dil","misal":"Dârülislâmda, ibâdetlerde cehl özr olmaz (İbni Âbidîn)","osmanli":"جهل"},{"kelime":"Cehl-i Mürekkeb","anlam":"Câhil olduğu hâlde, câhilliğini bilmemek.","kategori":"dil","misal":"Îsâ aleyhisselâm buyurdu ki: “Sağırı, dilsizi, te-dâvi ettim. Ölüyü dirilttim. Fakat cehl-i mü-rekkebin ilâcını bulamadım.” (Berîka)","osmanli":"مركب جهل"},{"kelime":"CEHMİYYE","anlam":"Cebriyye’nin bir kolu olup, Hicrî II.","kategori":"dil","misal":"asırda Cehm bin Saffân tarafından kurulan, kulların amellerinde cebr ve mecburiyet altında olduğuna inanan, kulun yapabilme gücünü bütünüyle inkâr eden, imanın yalnızca Allah’ı bilmek, küfrün de yalnızca O’nu bilmemek olduğunu ileri süren; Âhirette Allahü teâlânın görülmesini, kabir azâbını, sırat ve mîzânı inkâr eden bid‘at fırkası.","osmanli":"جهميه"},{"kelime":"ÇEHRE","anlam":"1.Yüz, surat. 2.Görünüş.","kategori":"dil","misal":"Aslı çihre. Çehre-i mâşûk (sevgilinin yüzü) karşı karşıya gelen iki aynalarda, aynanın temizliği ve nûrâ-niyyeti kadar görünür. Ayna renge bulanmış ve sureti kabul etmiyorsa, noksanlık aynadadır. Yoksa aynanın gösterdiği sûrette değil. (Mek-tûbât-ı Ma’sûmiyye)","osmanli":"ﭼهره"},{"kelime":"CEHRÎ","anlam":"Açıktan, alenî olarak, yük-sek sesle.","kategori":"dil","misal":"İmâmın, sabah, Cum‘a, bayram, teravih, vitir namazlarında ve akşam ile yatsının ilk iki rek’a-tinde cehrî okuması vâcibdir. (Halebî)","osmanli":"جهرى"},{"kelime":"ÇEK","anlam":"Bankacılıkta bir havalenin ödenmesi için çıkarılan teyit emri, süftece.","kategori":"muamelat","misal":"Aslı Arabca sakk.","osmanli":"ﭼك"},{"kelime":"ÇEKİ","anlam":"Odun, taş gibi şeyleri tartmak için kullanılan ve 195 okka (250 kg.) gelen eski bir ağırlık ölçüsü.","kategori":"dil","osmanli":"ﭼكى"},{"kelime":"ÇEKİRDEK","anlam":"Sarraflıkta kullanılan ve denkin altıda biri gelen (0,15 gr.) ağırlık ölçüsü. ÇEKİRGE: ﭼكيرﮔه (T) Sıcak memleketlerde kır-","kategori":"muamelat","misal":"larda yaşayıp bitkilere zarar veren ve çok iyi sıç- ramasıyla tanınan düzkanatlılardan bir böcek. İki leş ve iki kan bize helâl kılındı. İki leş, balık ve çekirge; iki kan ise, ciğer ve dalak-tır. (Hadîs-i şerîf-Hakîm)","osmanli":"ﭼكيردك"},{"kelime":"CELÂBİB","anlam":"Cilbâblar, uzun ve ge-niş örtüler, mantolar. Cilbâb’ın çokluk hâli. (Bkz. Cilbâb)","kategori":"dil","osmanli":"جلابيب"},{"kelime":"CELÂL","anlam":"Allahü teâlânın kahr ve gazab sıfatlarından.","kategori":"akaid","misal":"Yeryüzünde bulunan her canlı fânîdir (yok olucudur). Ancak celâl ve ikrâm sahibi olan Rabbinin zâtı bâkîdir. Böyle iken Rabbinizin hangi nîmetlerini yalan sayabilirsiniz? (Rahmân sûresi: 26, 27, 28) Hiç şüphe yok ki, kıyâmet gününde Allahü teâlâ; “Nerede benim celâlim için birbirini sevenler! Bugün ben onları arşımın gölgesinde gölgelendireceğim” buyuracaktır. (Hadîs-i şerîfMüslim) Yâ zelcelâli ve’l-ikrâm’ı çok söyl…","osmanli":"جلال"},{"kelime":"CELÂLÎ","anlam":"Yavuz Sultan Selim devrinde isyan eden Kızılbaşlardan Bozoklu Celâl’in avanesine ve daha sonra bu yolda ayaklanan bütün eşkıyaya verilen isim.","kategori":"dil","osmanli":"جلالى"},{"kelime":"CELB","anlam":"1.Çekme, çekiş; kendine çekme. 2.Yazı ile resmî makama, mahkemeye çağırma.","kategori":"dil","misal":"CELD: جلد (A) Deriye vurmak veya deriyle vur-mak. Suçlunun ceza olarak değnek ile dövül- mesi. Celde.","osmanli":"جلب"},{"kelime":"ÇELEBİ","anlam":"1.Osmanlılarda Divan-ı Hümâyun kâtibi. 2.Mevlânâ Celâleddin Rûmî soyundan. 3.Mütevâzı, merhametli.","kategori":"osmanli","osmanli":"ﭼلبى"},{"kelime":"ÇELENK","anlam":"1.Mücevher veya herhangi bir mâdenden yapılıp başa takılan sorguç. 2.Halka şeklinde yapılmış çiçek, dal ve yaprak demeti.","kategori":"dil","osmanli":"ﭼلنك"},{"kelime":"CELÎ","anlam":"1.Âşikâr, meydanda, belli. 2.Cilâlı, parlak. 3.Kalın ve okunaklı bir çeşit sülüs yazısı.","kategori":"dil","misal":"(A. Cilâ’dan)","osmanli":"جلى"},{"kelime":"CELÎL","anlam":"Celâl sahibi. Allahü teâlânın Esmâ-i hüsnâsından (elCelîl).","kategori":"akaid","osmanli":"جليل"},{"kelime":"CELÎS","anlam":"Cülûs eden; oturan.","kategori":"dil","osmanli":"جليس"},{"kelime":"CELÎS-İ İLÂHÎ","anlam":"Allahü teâlâya yakın kimse, velî.","kategori":"akaid","misal":"Celîs-i ilâhî olanlarla birlikte bulunanlar, şakî (Cehennemlik) olmaz. (Hadîs-i şerîf-Buhârî, Müslim)","osmanli":"الهى جليس"},{"kelime":"CELLE CELÂLuH","anlam":"“O’nun celâli yücedir” mânâsına Allahü teâlânın ismi-i şerîfi","kategori":"akaid","misal":"söylenince, yazılınca ve işitilince, söylenilen ta’zim (hürmet, saygı) ifâdesi. Allahü teâlânın ismini işitince ve söyleyince, “celle celâlüh”, “teâlâ”, “tebâreke”, “sübhânallah” diyerek saygı göstermek vâcibdir. Tekrarında müstehabdır. (Hindiyye)","osmanli":"جلاله جل"},{"kelime":"CELSE","anlam":"1.Oturuş. 2.Namazda iki secde arasında hareketsiz bir mikdar oturma.","kategori":"ibadet","misal":"Rükû’da ve secdelerde ve kavmede ve celsede beden tumânînet, sakinlik bulduktan sonra biraz durmalıdır; Hanefî âlimlerinin çoğu buna vâcib demiştir. İmâm-ı Ebû Yûsuf ve İmâm-ı Şâfiî ve Mâlik ise farz demiştir. Bazı Hanefî âlimleri de sünnet demişlerdir. Müslümanların çoğu bunu yapmıyor. Bu bir ameli yapana ve meydana çıkarana, Allah yolunda harb edip canını veren yüz şehid sevâbından çok sevab verilir. (Mektûbât-ı İ…","osmanli":"جلسه"},{"kelime":"CELVETİYYE","anlam":"Bayrâmiyye tarikatının bir kolu olan ve Azîz Mahmûd Hüdâyî hazretlerinin tasavvuftaki yolu.","kategori":"tasavvuf","osmanli":"جلوتيه"},{"kelime":"CEM‘","anlam":"1.Toplama, birleştirme, bir araya getirme. 2.İki namazı birlikte kılma.","kategori":"ibadet","misal":"Hanefî mezhebinde hacıların Arafat meyda-nında öğle ve ikindiyi, Müzdelife’de akşam ve yatsıyı cem’ etmeleri lâzımdır. Mâlikî ve Şâfi’î mezheblerinde, günah olmayan seferde, yağ-murda, hastalıkta, ikindiyi öğle namazı vak-tinde ve yatsıyı akşam namazı vaktinde takdîm ederek veya öğleyi ikindi vaktinde ve akşamı yatsı vaktine te’hîr ederek iki namazı bir arada kılmak câizdir. Hanbelî mezhebinde; seferde, hastalıkta, kadının emzikli ve müstehâza ol-masında, abdesti bozan şeylerde, abdest ve te-yemmüm için meşakkat çekenlerde ve a’mâ ve yer altında çalışan gibi namaz vaktini anla-makta âciz olanın ve canından, malından ve nâmûsundan korkanın ve ma’îşetine zarar ge-lecek olanın, ayrıca; soğuk, kış, yağmur, çamur ve fırtınada iki namazın cem’ edilmesi câizdir. (el-Fıkhu ale’l-Mezâhibi’l-Erbaa)","osmanli":"جمع"},{"kelime":"Cem‘-i Takdim","anlam":"Vakti girmemiş namazı, vakti giren namazla cem’ etme, be-raber kılma.","kategori":"ibadet","osmanli":"تقديم جمع"},{"kelime":"CEM‘İYYET","anlam":"1.Topluluk. 2.Kalbde hâsıl olan mânevî toparlanma, huzur, Allahü teâlâ ile beraber olma hâli.","kategori":"akaid","misal":"Namazda, ayakta iken secde yerine, rükû’da iken ayaklara, secdede burun ucuna ve otururken iki ellere ve kucağına bakılır. Bu söylenenler yapılır ve gözler etrâfa kaymaz ise, namaz cem’iyyetle kılınmış olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"جمعيت"},{"kelime":"CEMÂL","anlam":"1.Güzellik, hüsn, yüz güzelliği. 2.Lutf ve rızâ. 3.Zât, yüz.","kategori":"hadis","misal":"Kadın ya malı, ya cemâli veya dini için alınır. Siz dini için alınız. Malı için alan, malına ka-vuşamaz. Yalnız cemâl için alan cemâlinden mahrum kalır. (Hadîs-i şerîf-Müsnedü Ahmed) Cemâl için temiz, güzel giyinmek mübahdır. Bu-nun için bulunduğu yerde âdet olan şeylerden haram olmayan en iyilerini kullanmak lâzım-dır. Gösteriş ve öğünmek için nîmeti göstermek, cemâl olmaz, kibir (büyüklenmek) olur. Nefsin zaîf, azgın olduğunu gösterir. (Bahrü’r-Râik) Allahü teâlâ kıyâmet günü mahşer yerinde, kâ-firlere ve günahı olan mü’minlere, kahr ve celâl, sâlih olan mü’minlere ise lütuf ve cemâl sıfatiyle muâmele edecektir. (İtikadnâme) Resûlullah aleyhisselâm mi’râcda Cennetdeki ni’metleri, Cehennemdeki azâbları gördü. Cenâb-ı Hakkın cemâlini görmek arzûsundan ve zevkınden, Cennetdeki ni’metlerin hiçbirine bakmadı. (İtikadnâme)","osmanli":"جمال"},{"kelime":"CEMÎ‘","anlam":"Tamamını, hepsini.","kategori":"dil","osmanli":"جميع"},{"kelime":"CEMÎL","anlam":"Cemâl sahibi, güzel. Allahü teâlânın isimlerinden (el-Cemîl). (Bkz. Cemâl) Allahü teâlâ Cemîldir, cemâl sahiplerini se-ver. (Hadîs-i şerîf-Müslim)","kategori":"hadis","osmanli":"جميل"},{"kelime":"CEMÎLE","anlam":"1.Topluluk. 2.Kalbde hâsıl olan mânevî toparlanma, huzur, Allahü teâlâ ile beraber olma hâli.","kategori":"tasavvuf","misal":"Hoşa gitmek için uğraşma. CEM‘İYYET: جمعيت (A) Namazda, ayakta iken secde yerine, rükû’da iken ayaklara, secdede burun ucuna ve otu-rurken iki ellere ve kucağına bakılır. Bu söy-lenenler yapılır ve gözler etrâfa kaymaz ise, namaz cem’iyyetle kılınmış olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"جميله"},{"kelime":"CEMRE","anlam":"1.Ateş yumağı. 2.Hacıların şeytân taşlarken attıkları taşlar veya bu taşların atıldığı yer.","kategori":"ibadet","misal":"Çokluk hâli cimâr ve cemerât’tır. Minâ’da birbirlerine birer ok atımı mesâfede bulunan üç taş yığını vardır. Bunlardan birincisine Cemre-i ûlâ (birinci cemre), ikincisine Cemre-i vustâ (orta cemre) ve üçüncüsüne Cemre-i Akabe adı verilir. Kurban bayramının birinci günü güneş doğmadan önce Müzdelife’den Minâ’ya hareket edilir. Burada Mescid-i Hîf ’e en uzak olan Cemre-i Akabe’ye yedi taş atılır. Sonra gidip kurban ke…","osmanli":"جمره"},{"kelime":"CENÂB","anlam":"Bir kimse için şeref ve büyük-lük bildirmek için kullanılan tabir.","kategori":"dil","osmanli":"جناب"},{"kelime":"CENÂBET","anlam":"Cünüplük, gusül (boy abdesti) almayı gerektiren hâl.","kategori":"ibadet","misal":"Cünüb)","osmanli":"جنابت","alternatif":["cunub","cenabet"]},{"kelime":"CENÂN","anlam":"Kalp, yürek, gönül.","kategori":"dil","osmanli":"جنان"},{"kelime":"CENÂZE","anlam":"İnsan ölüsü.","kategori":"ibadet","misal":"Üç şey geciktirilmez: Vakti girince namaz; hazır olunca cenâze ve dengi çıkınca bekâr. (Hadîs-i şerîfTirmizî)","osmanli":"جنازه"},{"kelime":"CENG","anlam":"Harb, savaş, vuruşma. CENGÂVER: جنگاور (F) Cenkçi, dövüşken, savaşçı. CENÎN: جنين (A) Ana karnındaki çocuk.","kategori":"dil","misal":"Sizi topraktan var ederken ve siz anneleri-nizin karınlarında cenîn hâlinde iken siz-leri çok iyi bilen O’dur. Kendinizi temize çı-karmayın. O, sakınanı çok iyi bilir. (Necm sûresi: 32) Ölüm zamanında ana rahminde bulunan cenîn, takdîren diri sayılır. Bunun hissesi ayrılıp sak-lanır. Diri olarak doğarsa, hemen ölse bile vâ-ris olur. (Dürrü’l-Müntekâ)","osmanli":"جنﮔ"},{"kelime":"ÇENGİ","anlam":"1.Çeng denilen sazı çalan. 2.Oyuncu kız.","kategori":"dil","osmanli":"ﭼنگى"},{"kelime":"CENNET","anlam":"1.Bahçe. 2.Âhirette Müslümanların nîmet ve mutluluk içerisinde sonsuz olarak yaşayacakları yer.","kategori":"akaid","misal":"Rabbinizden mağfiret istemeye ve Cennet’e girmeye koşunuz. Bunun için çalışınız! Cennet’in büyüklüğü, gökler ve yer küresi kadardır. Cennet, Allahü teâlâdan korkanlar için hazırlandı. Bunlar, az bulunsa da mallarını Allah yolunda verirler, öfkelerini belli etmezler, herkesi affederler. Allahü teâlâ, ihsân edenleri sever. (Âl-i İmrân sûresi: 133) Dikkat edin, Cennet için hazırlanan yok mudur? Kâbe’nin Rabbine (Allahü…","osmanli":"جنت","alternatif":["cennet"]},{"kelime":"CENûB","anlam":"Güney.","kategori":"dil","osmanli":"جنوب"},{"kelime":"CERÂHAT","anlam":"1.İrin; yara. 2.Cerrah-lık, cirâhat.","kategori":"dil","osmanli":"جراحت"},{"kelime":"CERÎDE","anlam":"1.Hâdise ve işlerin kaydedildiği defter. 2.Gazete.","kategori":"hadis","osmanli":"جريده"},{"kelime":"CESÂRET","anlam":"Cesurluk, yiğitlik, yü-reklilik.","kategori":"dil","osmanli":"جسارت"},{"kelime":"CESED","anlam":"Ölü vücut.","kategori":"dil","osmanli":"جسد"},{"kelime":"ÇEŞM","anlam":"Göz. (Çeşmân: iki göz.) Kerâmetidir beni kaldırdı hâk-ı mezelletden, Mu’azzez eyledi fakîri, rağmen çeşm-i hüssâda. (Işkî)","kategori":"dil","osmanli":"ﭼشم"},{"kelime":"ÇEŞTİYYE","anlam":"Evliyânın büyüklerinden Muînüddîn-i Çeştî hazretlerinin tasavvuftaki yolu.","kategori":"tasavvuf","osmanli":"ﭼشتيه"},{"kelime":"CESuR","anlam":"(A. Cesâret’ten) Cesaretli, yü-rekli, yiğit.","kategori":"dil","osmanli":"جسور"},{"kelime":"CEVÂB","anlam":"Sorulan bir şeye verilen karşılık. CEVÂD: جواد (A) “Çok cömert, pek cûd sa-hibi” mânâsına Allahü teâlânın isimlerinden","kategori":"akaid","misal":"(el-Cevâd).","osmanli":"جواب"},{"kelime":"CEVÂD","anlam":"“Çok cömert, pek cûd sahibi” mânâsına Allahü teâlânın isimlerinden","kategori":"akaid","misal":"(elCevâd).","osmanli":"جواد"},{"kelime":"CEVÂHİR","anlam":"1.Cevherler, elmaslar, kıy-metli taşlar. 2.Mayalar, özler.","kategori":"akaid","osmanli":"جواهر"},{"kelime":"CEVÂRÎ","anlam":"Câriyeler, kadın köleler.","kategori":"osmanli","misal":"Câriye’nin çokluk hâli.","osmanli":"جوارى"},{"kelime":"CEVÂZ","anlam":"Câiz olma. (Bkz.","kategori":"fikih","misal":"Câiz)","osmanli":"جواز"},{"kelime":"CEVHER","anlam":"1.Mâhiyet, asıl, öz. 2.Vezni (ağırlığı) ve hacmi olan, yani boşlukta yer kap-layan varlık. 2.Kıymetli taş, mâden. 3.Hüner, marifet.","kategori":"ibadet","misal":"Madde. Her mahlûk, ya cevherdir, yâhud arazdır. Var-lıkta kalabilmesi için, başka bir mahlûka muh-taç değilse, kendi kendine var ise, buna cevher denir. Varlıkta başka bir şeye muhtaç ise, araz veya sıfat denir. Madde ve cisim, birer cevher-dir. Bir cismin rengi, kokusu, şekli ise arazdır. Renk, cisim ile vardır. Cisim olmazsa, renk ola-maz. Cevher, iki türlüdür. Biri mücerred (maddî olmayan) varlıktır. Ağırlığı, şekli, rengi ve his organlarına tesiri yoktur. Mücerred olan cev-her, his organları ile duyulmaz, parçalanamaz. Akıl ve ruh böyledir. İkincisi maddedir. Madde ise, his olunur ve parçalanabilir. Cisim, mad-denin şekil almış hâlidir. Ruh cevherdir. Araz, yani hâssa, bir cevher üzerinde bulunur. Cev-her, arazı taşımaktadır. His olunan, düşünü-len her şeyi ruh almakta, taşımaktadır. Bu-nun için kalb ve ruh, cevherdir, araz değildir. (Ahlâk-ı A’lâî) Çokluk hâli cevâhir gelir. Kadr-i zer zerger şinâsed, Kadr-i gevher gevherî. (Altının kıymetini sarraf, gevherin kıymetini mücevherci anlar.) Allahü azîmüşşân, Âdemoğluna dört cevher vermiştir: Akıl, iman, hayâ ve fiil, yani amel-i sâlih. (Miftahü’l-Cenne) Allahü teâlâyı seven ve unutmayanlardan uzak kalmak, o saadet tohumunun açılıp büyüme-sine mâni olur. Fakat, o tohumun çürümemiş olması, bu yavrunun yetişmeye elverişli nefis bir cevher olduğunu göstermektedir. (Mektû-bât-ı İmâm-ı Rabbânî)","osmanli":"جوهر"},{"kelime":"CEVR","anlam":"Zulüm, haksızlık, eziyet. Adâ-letin zıddı.","kategori":"dil","misal":"Yeryüzü cevrle dolduktan sonra, benim Ehl-i beytimden (evlâdımdan) mutlaka bi-risi çıkar. Dünya daha önce nasıl zulüm ve cevr ile dolu ise o, dünyayı adâletle doldu-rur. (Hadîs-i şerîf-Ebû Dâvûd)","osmanli":"جور"},{"kelime":"CEVŞEN","anlam":"Zırh.","kategori":"dil","osmanli":"جوشن"},{"kelime":"Cevşen-i Kebîr","anlam":"23.ihyâ gecelerinde topluca okurlar.","kategori":"ibadet","misal":"“Büyük Zırh” mânâsına Oniki İmâm yoluyla ulaşan, Cebrâil aleyhisselâmın bir muharebenin en şiddetli zamanında gelerek Hazret-i Peygamber’e sırtındaki zırhı çıkarmasını ve okumasını telkin buyurduğu rivâyet olunan duâ. Şiî kaynaklarında Cevşen-i Kebîr ve Cevşen-i Sagîr adıyla farklı iki duâ vardır. Cevşen denince, Cevşen-i Kebîr anlaşılır. Caferîler kefenlerine yazdıkları gibi, Ramazan’ın 19, 21 ve Bu duânın münâcât ve niyaz ihtiva eden ifadesi akıcı olup, mûteber kitaplarda geçmediği halde Ehl-i sünnet akidesine de muhalif bulunmadığı için, bazı Sünnî Müslümanlar tarafından da itibar görmekte…","osmanli":"قبير جوشن"},{"kelime":"CEYYİD","anlam":"En iyi, hoş, saf. Başka mâdenle karışım hâlinde basılmış al-tın ve gümüş paralardan, karışımında altın ve gümüş mikdarı fazla olanlar.","kategori":"dil","misal":"Zekâtı, kendi cinsinden olmayan başka zekât malı ile verirse, kendi kıymeti kadar vermesi lâzım olur. Kendi cinsinden başka mal verirse, Şeyhayne göre, kıymeti kadar değil, mikdarı kadar verilir. İkiyüz dirhem ceyyid gümüşün zekâtı olan beş dirhem ceyyid gümüş yerine, beş dirhem züyûf verilebilir. Ama mekrûhtur. (Bedâyı’us-Sanâyı’)","osmanli":"جيد"},{"kelime":"CEZÂ","anlam":"İyi veya kötü karşılık.","kategori":"dil","misal":"İyiliğin cezâsı ancak iyiliktir. (Tâatleri ya-pıp, günah olan şeyleri terk etmenin karşılığı pekçok sevabtır.) (Rahman sûresi: 60) Kim bir hayırlı ve güzel amelle (işle) gelirse, ona, on misli sevab verilir. Kim de bir günah ile ge-lirse (eğer af olunmazsa), ona ancak misli ile (günahı kadarla) cezâ edilir. Onlar (sevabları noksanlaştırılmak veya cezâları artırılmak sû-retiyle) haksızlığa uğratılmaz. (En’âm sûresi: 160) Allahü teâlâ onlara zulmetmez. Onlar kendilerine zulmedip, ağır cezâları hak et-tiler. (Nahl sûresi: 33) Hâşâ zulmetmez kuluna Hüdâsı, Herkesin çektiği kendi cezâsı.","osmanli":"جزاء"},{"kelime":"CEZBE","anlam":"Çekmek, sürüklemek. Ruhun hayret ve sevinç içinde adeta bedenden ayrı imiş gibi olması.","kategori":"akaid","misal":"Rahmân’ın cezbelerinden bir cezbe bütün insanların ve cinnîlerin sevabları gibidir. (Hadîs-i şerîfSülûk Risâlesi) Tasavvuf yolu iki kısımdır: Cezbe ve sülûk. Sülûk uğraşarak ilerlemektir. Sülûk tamamlandıktan sonra cezbe lâzımdır. Sülûk olmadan maksada kavuşulamaz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"جذبه"},{"kelime":"CEZM","anlam":"1.Kati karar, niyet, azm. 2.Arab-ca’da bir kelimenin sonundaki harf veya ha-rekeyi düşürme.","kategori":"dil","misal":"Ezan’da Allahü ekber derken birinci ve üçüncü (R) ler cezm veya vasl ederek üstün okunur. (İbni Âbidîn)","osmanli":"جزم"},{"kelime":"CİBİNLİK","anlam":"Sineklerden korunmak üzere yatağın üzerine gerilen tül perde. (Ci-bin=sinek.)","kategori":"dil","osmanli":"جيبينلك"},{"kelime":"CİBRÎL","anlam":"Peygamberlere vahy getirmekle vazifeli melek.","kategori":"dil","misal":"(Bkz. Cebrâîl)","osmanli":"جبريل"},{"kelime":"CİDÂL","anlam":"Kavga, çekişme, münâkaşa. Cedel’in çokluk hâli.","kategori":"dil","misal":"Hacda kadına yaklaşmak, günah işlemek ve (hizmetçileri, arkadaşları ve başkaları ile) ci-dâl yoktur. (Bakara sûresi: 197) Hadîs-i şerîfte, ‘Resûlün yanında nizâ’, cidâl yapmayınız!’ buyurdu. Onun dininin âlimleri ile nizâ, cidâl yapmak, onların doğru olan ic-tihâdlarının çürük olduklarını göstermeğe kal-kışmak, O’nunla -sallallahü aleyhi ve sellem- ci-dâl etmek demektir. Çünki âlimler Resûlullah’ın vârisleridir. (el-Mîzânü’l-Kübrâ) Bir dikkatli nazar etsen, bu dünyâ ehline cânım, Kazanırlar para dâim, bunlar cenk ve cidâl üzre. (Zâtî)","osmanli":"جدال"},{"kelime":"CİHÂD","anlam":"1.Çalışma, çabalama, uğraşma, gayret sarf etme. 2.İnsanların İslâmiyet’i işitmelerine, Müslüman olmalarına engel olan veya Müslümanların dinine, vatanına ve nâmusuna saldıran düşmanı defetmek için yapılan muhârebe. 3.Mal, can, söz, neşriyat ve diğer vâsıtalar… Mallarını, canlarını fedâ ederek din düşmanları ile Allah rızâsı için cihâd eden Müslümanlar, oturup, ibâdet edenlerden daha üstündür. Hepsine de, Cennet’i söz veriyorum. (Nisâ sûresi: 95) İnsanların en faziletlisi, Allah yolunda canıyla, malıyla cihâd eden mü’mindir. (Hadîs-i şerîfBuhârî, Müslim, Ebû Dâvûd, Tirmizi, Nesâî, İbn-i Mâce) Cihâddan maksat, İslâm dinini yüceltmek ve din düşmanlarını zelîl etmektir. Cihâd…","kategori":"muamelat","osmanli":"جهاد"},{"kelime":"Cihâd-ı Ekber","anlam":"Büyük cihâd. Nefsin, insan tabiatının, bedeninin kötü isteklerini yerine getirmemek için yapılan mücâdele.","kategori":"tasavvuf","misal":"Küçük cihâddan büyük cihâda döndük ki, nefsin hevâsı ile mücâdelesidir. (Hadîs-i şerîfDeylemî, Hatîb)","osmanli":"اكبر جهاد"},{"kelime":"CİHÂN","anlam":"Dünya.","kategori":"dil","osmanli":"جهان"},{"kelime":"CİHÂNGÎR","anlam":"Cihanı, dünyayı zapte-den, hükümdar.","kategori":"dil","osmanli":"جهانگير"},{"kelime":"ÇİHÂR YÂR-I GÜZÎN","anlam":"“Seçilmiş, sevgili dört arkadaş” mânâsına Muhammed aleyhisselâmın dört mümtaz ve büyük halîfesi, Hazret-i Ebû Bekr, Hazret-i Ömer,","kategori":"dil","misal":"100 ÇÖMEZ Hazret-i Osman ve Hazret-i Ali radıyallahü anhümün ünvanı.","osmanli":"ﮔزين يار ﭼهار"},{"kelime":"CİHÂZ","anlam":"Donanmak, çeyiz.","kategori":"dil","osmanli":"جهاز"},{"kelime":"CİHET","anlam":"1.Yan, yön, taraf. 2.Yüz, yer. 3.Sebeb, vesile, bahane. 4.Vazife, hizmet. 5.Vakıflarda çalışanların, vakfın gelirinden aldığı maaş.","kategori":"fikih","misal":"Çokluk hâli cihât gelir.","osmanli":"جهت"},{"kelime":"CİLBÂB","anlam":"1.Gömlek; uzun ve geniş örtü. 2.Milhafe, câr, ferâce, kamîs, çarşaf, manto.","kategori":"dil","misal":"Çokluk hâli celâbîb gelir. Ey sevgili Peygamberim! Zevcelerine, kız-larına ve mü’minlerin kadınlarına cilbâb-larını üstlerine giymelerini söyle! (Ahzâb sûresi: 59) Haramdan olan cilbâb giyenin namazı kabul olmaz. (Hadîs-i şerîf-Zevâcir)","osmanli":"جلباب"},{"kelime":"CİLD","anlam":"Deri.","kategori":"dil","osmanli":"جلد"},{"kelime":"ÇİLE","anlam":"1.Kırk. 2.Dervişlerin, nefislerini terbiye ederek tasavvuf yolunda ilerliyebilmek için kırk gün tenhâ bir yerde riyâzet ve ibâdetle meşgul olmaları. Hak teâlâ, hepimizi her an kendinin esiri olmak şerefine kavuştursun. Hakîkî kurtuluş O’na esîr olmak, tutulmaktır. Ondan başka bir şey düşünmemek, hâtıra bir şey getirmemek, büyüklerimizin yolunda, pek kolay hâsıl olmaktadır. Hatta bu yolun büyüklerinden bir kaçı kırk gün çile çekmiş, kırk gün sonra, hâtırlarına dünya düşünceleri gelmez olmuştur. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"tasavvuf","osmanli":"ﭼله"},{"kelime":"CİLVE","anlam":"1.Kırıtma. 2.Tecelli, görünme.","kategori":"dil","misal":"Her çirkin şeytân, cilve ile, nâz ile kendini ma’şûk yapıp, sedd-i İskender gibi perde olur. (Mektû-bât-ı Ma’sûmiyye) Yatsı namazı köprüdür, Kılanı, Hakka erdirir, Matlûb, nikâbın kaldırıp, Anda cilve, etse gerek. (Yûnus Emre)","osmanli":"جلوه"},{"kelime":"CİM","anlam":"1.Arab alfabesinin beşinci harfi. 2.Kıraaat ederken durmanın efdal olduğu durak.","kategori":"muamelat","osmanli":"ج"},{"kelime":"CİMÂD","anlam":"Cansızlar. câmid’in çokluk hâli.","kategori":"ibadet","osmanli":"جماد"},{"kelime":"CİMRİLİK","anlam":"Dinin, vicdânın, mürüvvetin (insanlığın) vermeyi emrettiği yerde vermemek, vermek kendisine zor gelmek.","kategori":"tasavvuf","misal":"Allahü teâlânın ihsân ettiği malda cimrilik edenler, onun zekâtını vermeyenler, iyilik ettiklerini zengin kalacaklarını mı sanıyor. Hâlbuki kendilerine kötülük yapmış oluyorlar. O malları Cehennem’de azâb âleti olacak; yılan şeklinde boyunlarına sarılıp, baştan ayağa kadar onları sokacaktır. (Âl-i İmrân sûresi: 180) Cimrilikten sakınınız. Çünki cimrilik, sizden öncekilerin helâkına sebeb oldu. (Hadîs-i şerîfMüslim,…","osmanli":"جيمريلك"},{"kelime":"CİN (Cinn)","anlam":"Ateşin alev kısmından yaratılan, her şekle girebilen; evlenen, yiyip-i-çen, çoğalan ve gözle görülmeyen varlıklar.","kategori":"dil","misal":"Cinleri ve insanları ancak beni bilip ibâdet etmeleri için yarattım. (Zâriyât sûresi: 56) Ey Habîbim! Onlara de ki: “Cinlerden bir grubun Kur’ân-ı kerîm dinlediği bana bildirildi. Onlar şöyle demişlerdi.” Muhakkak ki biz doğru yola götüren, akıllara durgunluk ve hayranlık veren bir Kur’ân dinledik. O’na inandık. Rabbimize hiç bir şeyi ortak koşmayacağız. (Cin sûresi: 1, 2) Cinler çeşitli şekillere girip şaşılacak iş…","osmanli":"جن"},{"kelime":"CİN SûRESİ","anlam":"Kur’ân-ı kerîmin yetmiş ikinci sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Yirmi sekiz âyet-i kerîmedir. Resûlullah aleyhisselâma gelip iman eden cinlerden bahsettiği için bu ismi almıştır. “Kul ûhiye” suresi de denir. Sûrede, cinlerin hakikati ortaya konmaktadır.","osmanli":"سى سوره جن"},{"kelime":"CİNÂN","anlam":"Cennetler; bahçeler.","kategori":"akaid","misal":"Mülk-i bekâdan gelmişem, fâni cihânı n’eylerim? Ben dost cemâlin görmüşem, hûr-i cinânı neylerem? (Erzurumlu İbrâhim Hakkı)","osmanli":"جنان"},{"kelime":"CİNÂYET","anlam":"1.Büyük suç. 2.Yaralama veya öldürme şeklinde işlenen suç.","kategori":"dil","misal":"(Bkz. Katl) Cinâyet fi’n-Nefs: النفس فى جنايت (A) Cana taal- luk eden cinâyet, haksız yere adam öldürme.","osmanli":"جنايت"},{"kelime":"ÇİNİ","anlam":"Toprak sırlı kap, sırça kap.","kategori":"dil","osmanli":"ﭼنى"},{"kelime":"CİNNET","anlam":"Aklın örtülmesi, delilik.","kategori":"dil","misal":"(Bkz. Cünûn)","osmanli":"جنت"},{"kelime":"CİNS","anlam":"Çeşit, tür; kullanıldıkları yer-ler arasında fark bulunmayan eşyanın müş-terek adı.","kategori":"dil","misal":"Deve hayvan sınıfının bir cinsidir. Tüylü deve, bu cinsten bir nevidir. Aslı, kaynağı başka olan veya kullanıldığı yer çok farklı olan yâhud başka isim alacak kadar değiştirilmiş bir mal başka cinsten olur. Sığır eti, koyun eti ile, keçi kılı ko-yun yünü ile ve ekmek, un ile başka cinsten-dir. Keçi eti veya sütü ise, koyun eti veya sütü ile bir cinstendir. (İbni Âbidîn) Kile (ölçek) veya vezn (ağırlık) ile satılan bir şey, kendi cinsine peşin satılırken, birinin hacmi veya ağırlığı fazla olursa fâiz olur. (Erbâîn-i Nesefî)","osmanli":"جنس"},{"kelime":"CİNSÎ","anlam":"1.Cinsle alâkalı. 2.Seksüel, cin-siyete dair.","kategori":"dil","osmanli":"جنسى"},{"kelime":"CİRCÎS (aleyhisselâm)","anlam":"Îsâ aleyhisselâmdan sonra Filistin’e gönderildiği rivâyet edilen peygamber veya velî.","kategori":"dil","misal":"Cercis de denir.","osmanli":"جرجيس"},{"kelime":"CİSM","anlam":"1.Boşlukta yer kaplayan şekil al-mış ve başka bir şekle girmiş madde. 2.Beden, vücûd.","kategori":"dil","misal":"Cisimlerin, maddelerin durmadan değişmeleri, birbirlerinden hâsıl olmaları, sonsuz olarak gel-miş değildir. Yani böyle gelmiş, böyle gider de-nilemez. Bu değişmelerin bir başlangıcı vardır. Değişmelerin başlangıcı vardır demek, madde-lerin var oluşlarının başlangıcı vardır demek-tir. Yani hiçbir şey yok iken, hepsi yoktan ya-ratılmıştır demektir. (Şerh-i Emâlî) Dünya lezzetleri ve elemleri iki türlüdür. Bi-rincisi cismin, ikincisi ruhun lezzetleri ve acı-larıdır. Cisme lezzet veren her şey ruha elem verir. Cismi inciten her şey, ruha tatlı gelir. Gö-rülüyor ki, ruh ile cesed birbirinin zıddı, aksi-dir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"جسم"},{"kelime":"CİSMÂNÎ","anlam":"1.Bedenle alâkalı. 2.Rûhânî olmayan, dinî işlerden ayrı.","kategori":"dil","misal":"Rûh, his organları ile duyulmaz. Cism ve cis-mânî olan şeyler his olunur. Rûh, cism ve cis-mânî olmadığı için his olunamaz. (Ahlâk-ı Alâî) (Cis-mânî Meclis gibi.) Kur’ân-ı kerîmde, her ibâdet, güzel ahlâk, hukûk, ticâret, ziraat ve fen bilgilerine teşvîk, uzun bil-dirilmiştir. Cismânî ve rûhânî her müşkilât hal edilmiştir. (Îzâhu’l-Merâm)","osmanli":"جسمانى"},{"kelime":"CİVÂN","anlam":"Genç.(Aslı cevân ve cüvân’dır. Çokluk hâli civânân gelir.","kategori":"dil","misal":"Civânân-ı müste’idana hayf ve efsus ki, fıtrat-i âlîlerini bu fânî-i denîye masrûf edip, [Kıymetli ömrünü bu fânî ve denî (alçak) olan dünya için sarf eden kâbiliyyetli gençlere çok yazık] onlar gençliklerini dünya için harcamakla aldatıcı bir kahbeye tutulmuşlar, kıymetli cevherleri, saksı parçaları ile değişmişlerdir. (Mektûbât-ı Ma’sûmiyye)","osmanli":"جوان"},{"kelime":"CİVÂR","anlam":"1.Çevre, yöre. 2.Yakın yer, ya-kın komşu.","kategori":"dil","osmanli":"جوار"},{"kelime":"CÎYû","anlam":"Hind alt kıtasında “efendi” gibi umumî mânâda hürmet için kullanılan bir kelime.","kategori":"dil","misal":"İmâm-ı Rabbânî hazretlerinin mektuplarında çokça geçer. İmâm-ı Rabbânî hazretleri Hazret-i Hâce Cîyû derken üstadı BâkîBillah’ı; Şeyh Cîyû derken, nakîbüleşraf Şeyh Ferîd Buhârî’yi; Mirza Cîyû derken, pirdaşı Hâce Hüsâmeddin Ahmed’i kasdeder.","osmanli":"جييو"},{"kelime":"CİZVİT (Cezvit)","anlam":"Hristiyanlığa dinamizm katmak ve dini yaymak iddiasıyla 1512’de Îsâ Cemiyeti adıyla kurulan, dışa dönük faaliyetleri ve kaliteli mektepler açarak gençleri kendi maksatları için yetiştirmek yoluyla faaliyet gösteren yaygın bir Katolik tarikatı.","kategori":"dil","misal":"Compaigne de Jesus. Aslı Fransızca Jesuit.","osmanli":"جزويت"},{"kelime":"CİZYE","anlam":"İslâm devletinde zımmî denilen gayr-i müslim vatandaştan, can ve mal güvenliklerinin korunması ve askerlik karşılığı olarak alınan senelik vergi, haracü’r-re’s (baş vergisi).","kategori":"muamelat","misal":"Kendilerine kitab verilenlerden Allahü teâlâya ve âhiret gününe inanmayan, Allahü teâlânın ve Resûlünün haram (yasak) ettiği şeyleri haram tanımayan, hak olan İslâm dinini kabul etmeyen kimselerle; zelîl, hakîr ve kendi elleriyle cizyelerini verinceye kadar muhârebe edin. (Tevbe sûresi: 29) Harb iki türlüdür: Müşriklerle, iman edinceye veya cizye verinceye kadar; veya isyan etmiş tâifeye karşı, Allah’ın emrini onlar…","osmanli":"جزيه"},{"kelime":"ÇOCuK","anlam":"Doğum ile bulûğ arasındaki insan.","kategori":"dil","osmanli":"ﭼوجق"},{"kelime":"CÖMERDLİK","anlam":"Dinin, vicdânın ve mürüvvetin (insanlığın) vermeyi emret-tiği yerde vermek kendisine zor gelmemek; el açıklığı, aklık.","kategori":"dil","misal":"Cömertlik, Cennet ağaçlarından bir ağaçtır. Dalları dünyaya uzanmıştır. Kim ondan bir dal tutarsa, o dal onu Cennet’e çeker. (Ha-dîs-i şerîf-Dârekutnî, Beyhekî, İbn-i Adiyy) Cö-merdin yemeği şifâ, cimrininki hastalıktır. (Hadîs-i şerîf-Dâre Kutnî)","osmanli":"جومردلك"},{"kelime":"ÇÖMEZ","anlam":"1.Bir işi yeni yeni öğrenen; yamak. 2.Medresede müderrise veya kıdemli talebeye hizmet ederek ilmini ilerleten talebe.","kategori":"osmanli","osmanli":"ﭼومز"},{"kelime":"CÜBBE","anlam":"Bilhassa din adamlarının giy-diği uzun üstlük.","kategori":"dil","misal":"Cum‘a günü hatîbin siyâh cübbe giymesi sün-nettir. (İbni Âbidîn)","osmanli":"جبه"},{"kelime":"CûD","anlam":"Cömertlik, el açıklığı.","kategori":"tasavvuf","misal":"(Bkz. Cömerdlik)","osmanli":"جود"},{"kelime":"CÜDÂ","anlam":"Ayrı, ayrı düşmüş, ayrılmış.","kategori":"dil","misal":"Hasret kaldım, hep karardım, oldum nûrum-dan cüdâ, Feyz kaynağım, elvedâ, âh elvedâ, âh elvedâ. (Nevhatü’l-Uşşak)","osmanli":"جدا"},{"kelime":"CûDÎ DAĞI","anlam":"Kur’ân-ı kerîmde Tufan’dan sonra Nuh aleyhisselâmın gemisinin konduğu Şarkî Anadolu’da bulunan bir dağ.","kategori":"dil","osmanli":"طاغى جودى"},{"kelime":"CÜLûS","anlam":"1.Oturma. 2.Tahta çıkma.","kategori":"dil","osmanli":"جلوس"},{"kelime":"CuM‘A (Cuma)","anlam":"1.Toplanmak. 2.Perşembe’den sonra gelen ve Müslümanlara mahsûs kıymetli gün.","kategori":"ibadet","misal":"Cumartesi günleri Yahudilere, Pazar günleri Hristiyanlara verildiği gibi, Cum‘a günü, Müslümanlara verildi. Bugün, Müslümanlara hayır, bereket, iyilik vardır. (Hadîs-i şerîfRıyâdünNâsihîn) Güneş, Cum‘a gününden daha iyi bir gün üzerine doğmaz. Âdem (aleyhisselâm) Cum‘a günü yaratıldı. Cum‘a günü Cennet’e girdi. Cum‘a günü Cennet’ten çıktı. Kıyâmet Cum‘a günü kopar. (Hadîs-i şerîfMüslim)","osmanli":"جمعه"},{"kelime":"Cum‘a Gecesi","anlam":"Perşembeyi Cum‘aya bağlayan gece.","kategori":"ibadet","misal":"Allahü teâlâ Cum‘a gecesinde bütün Müslümanları mağfiret eder, günahlarını bağışlar. (Hadîs-i şerîfEbû Ya’lâ)","osmanli":"سى كيجه جمعه"},{"kelime":"Cum‘a Hutbesi","anlam":"Cum‘a namazının ilk dört rek’atlik sünnetinden sonra ve iki rek’atlik farzdan önce, İmâm tarafından","kategori":"ibadet","misal":"cemâat huzurunda minberden Arabca olarak okunan hutbe. Cum‘a hutbesinde bir tesbih, tahmid, tehlil yâhud tekbir gibi Cenab-ı Hakk’a mahsus bir zikr okumak İmâm Ebû Hanife’ye göre hutbenin sıhhati için kâfi ise de, mekrûhtur. İmâmeyn’e göre hutbe denilecek bir mikdar uzunlukta olması şarttır. Bunun da en azı tehiyyat mikdarı hamd, salavat ve mü’minlere duadır. (Ni’met-i İslâm) Cum‘a hutbesi okumak ve dinlemek farzdır…","osmanli":"سى خطبه جمعه"},{"kelime":"CuM‘A SûRESİ","anlam":"Kur’ân-ı kerîmin altmış ikinci sûresi.","kategori":"dil","misal":"Medîne-i Münevvere’de nâzil olmuştur. On bir âyettir. Cum‘a namazının farz oluşunu bildirdiği için, dokuzuncu âyet-i kerîmede geçen Cum‘a kelimesi sûreye isim olmuştur.","osmanli":"سى سوره جمعه"},{"kelime":"CuMHûR","anlam":"Halk, ahâli; kalabalık, ekseriyet.","kategori":"dil","misal":"Un eleği, çatal-kaşık gibi âdette bid‘atlere harâm denilemeyeceğini, cumhûr-i ulemâ bildirmiş-tir. (Hadîka)","osmanli":"جمهور"},{"kelime":"CuMHûRİYYET","anlam":"Cumhurluk, iktidarın belli bir aile veya seçkinlerin değil de, halktan kişi veya kişilerin elinde olduğu devlet rejimi.","kategori":"dil","misal":"Saltanatın zıddı.","osmanli":"جمهوريت"},{"kelime":"CÜMLE","anlam":"2.Fiil, fail (özne) ve mef ’ulden (nesne) müteşekkil mânâlı söz dizisi.","kategori":"dil","misal":"l.Bütün, hep. Muntazamdır cümle ef’âlin senin, Aklı ermez, hikmetine kimsenin!","osmanli":"جمله"},{"kelime":"CÜND","anlam":"Asker; yardımcı.","kategori":"dil","osmanli":"جند"},{"kelime":"CÜNÜB","anlam":"Gusletmesi (boy abdesti alması) gereken kimse.","kategori":"ibadet","misal":"Eğer, cünüb iseniz (yıkanmak, gusül abdesti almak sûretiyle) temizleniniz... (Mâide sûresi: 6) Kirlenince çabuk gusül abdesti alın! Çünki Kirâmen kâtibîn melekleri cünüb gezen kimseden incinir. (Hadîs-i şerîfTaberânî) Resim, köpek ve cünüb kimse bulunan eve rahmet melekleri girmez. (Hadîs-i şerîfMüslim) Cünüb ve hayızlı iken câmiye girmek, hattâ câmi içinden geçmek, Kur’ân-ı kerîm okumak, dokunmak ve tutmak, Kâbe-i…","osmanli":"جنب"},{"kelime":"CÜNûN","anlam":"Delilik, akıl hastalığı. Âhireti verip dünyayı almak. Hak’tan halka yüz çevirmek cünûn ve sefâhettir. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","misal":"Cünûn hâlindeki kimsenin namaz kılmaması için altı namaz vakti, oruç tutmaması için bir gece ve gündüz, zekât vermemesi için bir yıl aralıksız o hâlde olması lâzımdır. (İbni Âbidîn)","osmanli":"جنون"},{"kelime":"CÜRM","anlam":"Suç, günah, kabahat. (Bkz. Mücrim)","kategori":"dil","osmanli":"جرم"},{"kelime":"CÜZ’","anlam":"1.Bir bütünü meydana getiren parçalardan her biri. 2.Kur’ân-ı kerîmin yirmi sayfalık kısımlarından her biri.","kategori":"dil","misal":"Hâfız pazarlık etmeden, Allah rızâsı için hatm, cüz’ veya mevlid okursa, okutanın hediye ettiğini alması câiz olur. İtiraz ederse, aldığı harâm olur (Hadîka, Berîka)","osmanli":"جزء"},{"kelime":"CÜZ’Î","anlam":"Cüz ile alâkalı; bir parça.","kategori":"dil","osmanli":"جزئى"},{"kelime":"Cüz’î İrâde","anlam":"İnsanın dilemek, Allah’a itaat ve isyan hususundaki sınırlı irâdesi, irâ-de-i cüz’iyye.","kategori":"dil","misal":"CÜZÂF (Cizâf, Cezâf): جزاف (A) Götürü pazarlık, bir şeyi ölçmeden, tartmadan tahmin ile satıp almak; icab ve kabulde bulunmaksızın malı alıp gösterilen parayı verme suretiyle yapılan alışveriş.","osmanli":"اراده جزئى"},{"kelime":"Cüz’-i lâ-Yetecezzâ","anlam":"Maddenin yapı taşı hususiyetini taşıyan en küçük parçası.","kategori":"dil","osmanli":"يتجزا لا جزء"},{"kelime":"CÜZZÂM","anlam":"İnsan vücûdunda onulmayan çıbanlar ve yaralar meydana getiren hastalık, miskin hastalığı.","kategori":"dil","misal":"Cüzzamlıdan aslandan kaçar gibi kaç! (Hadîs-i şerîfBuhârî) Kadın nikâhdan sonra, zevcin cüzzam hastası olduğunu anlasa, nikâhını hâkime feshettirebilir. (Bahrü’l-Fetâvâ) Ç","osmanli":"جزام"},{"kelime":"DA‘VÂ","anlam":"Hak aramak üzere mahkemeye müracaatta bulunup hasmını hazır etmek.","kategori":"osmanli","osmanli":"دعوى"},{"kelime":"DA‘VET","anlam":"Çağırma.","kategori":"dil","misal":"Ey habibim! Rabbininin yoluna hikmetle, güzel nasihatlerle da‘vet et! (Nahl sûresi: 125) Müslümanın Müslüman üzerinde beş hakkı vardır: Selâmına cevap vermek, hastasını zi-yaret etmek, cenâzesinde bulunmak, da‘ve-tine gitmek ve aksırıp elhamdülillah deyince, yerhamükellah diyerek cevap vermek. (Ha-dîs-i şerîf-Buhârî, Müslim) Resûlullah sallallahü aleyhi ve sellem, Allahü teâlâdan kendisine gelen emirleri insanlara açıklamak ve onları îmâna da‘vetle emredildi. Da‘vetini üç yıl gizli yaptı. Üç yıl sonra ilâhî emir üzerine, Allahü teâlânın emirlerini açık açık bildirmeye, kavmine İslâmiyet’i anlatmaya başladı. (İbnü’l-Esîr) Riyâ, gösteriş ve övünmek için yapılan da‘vet-lere gitmek câiz değildir. (Berîka)","osmanli":"دعوت"},{"kelime":"Da‘vet Makâmı","anlam":"Vilâyet (evliyâ-lık) makamının üstünde, peygamberlere mah-sus bir makam.","kategori":"dil","misal":"Peygamberlerin izinde bulunanların en üstün-lerine de da‘vet makamından bir pay ayırırlar. Yûsuf sûresinin; “Ey sevgili Peygamberim! On-lara de ki, benim yolum budur. Sizi gaflet-ten uyandırarak, Allahü teâlâya da‘vet edi-yorum. Ben ve benim izimde bulunanlar çağırıcıyız” meâlindeki yüz sekizinci âyeti bunu göstermektedir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مقامى دعوت"},{"kelime":"DÂBBE","anlam":"Yük ve binek hayvanı.","kategori":"dil","osmanli":"دابه"},{"kelime":"DÂD","anlam":"1.Adalet, doğruluk. 2.İhsan, vergi.","kategori":"dil","misal":"Etmiş, ol beden serâyın üstâd Adl ü dâd ile, esâsın bünyâd. (Hilye-i Seâdet)","osmanli":"داد"},{"kelime":"DADBE","anlam":"Kapı sürgü demiri.","kategori":"dil","misal":"Tadbîb, şerit ile, dadbe gibi, enli, yassı bir şey ile şed etmek, sarmak demektir (Tahtâvî, İbni Âbidîn, Dürrü’l-Müntekâ)","osmanli":"دادبه"},{"kelime":"DAĞLAMA","anlam":"Kızdırılmış mâdenle vücûdun bir yerini yakma.","kategori":"dil","misal":"Şifa üç şeydedir: Bal şerbeti, hacamat (kan aldırma), dağlama. Fakat ben dağlamayı sev-mem. (Hadîs-i şerîf-Buhârî) Dağlamanın faydası kesin değildir. Çünki teh-likeli yaralara sebeb olabilir. Üstelik dağlama ile elde edilecek fayda, başka ilâçlarla da te’min edilebilir. Bu bakımdan dağlamak uygun de-ğildir. (İhyâ)","osmanli":"داغلامه"},{"kelime":"DAHVE-İ KÜBRÂ","anlam":"Kaba kuşluk. Oruç müddetinin yarısı, öğleden bir saat evvelki vakit.","kategori":"ibadet","misal":"Hanefî mezhebinde Ramazan orucu, nâfile oruç ve belli olan adak orucuna niyet etme zamanı, bir gün evvel güneşin batmasından başlayarak, ertesi gün dahve vaktine kadardır. (Miftahü’l-Cenne)","osmanli":"كبرى ضحوه"},{"kelime":"DÂİM","anlam":"1.Devamlı; sâbit. 2.Devamlı var olan, hiç ölmeyen, bâkî mânâ-sına Allahü teâlânın sıfatlarından (ed-Dâim).","kategori":"dil","misal":"(A. Devam’dan)","osmanli":"دائم"},{"kelime":"DÂİN","anlam":"1.Düz yuvarlak şe- kil, çember. 2.Bir şeyin manevî tesirinin geç- tiği yer. 3.Resmî hizmetin görüldüğü yer.","kategori":"dil","misal":"Alacaklı, garîm. DA‘ÎF: ضعيف (A) Güçsüz, takatsiz, zayıf. DÂİRE: دائره (A. Devr’den)","osmanli":"دائن"},{"kelime":"DÂİRE-İ HİNDİYYE","anlam":"Namaz vakitlerinin tesbitinde kullanılan ve güneş gören düz bir yere çizilen dâire veya bu şekle uygun olarak yapılan âlet.","kategori":"ibadet","osmanli":"هنديه دائره"},{"kelime":"DALÂLET","anlam":"Sapıklık, yoldan çıkma, dalâl.","kategori":"dil","misal":"Dinde yeni ortaya çıkan şeylerden kaçınınız. Çünki bunların hepsi bid‘attir. Bid‘atlerin hepsi dalâlettir, doğru yoldan ayrılmaktır. (Hadîs-i şerîf-Müslim, Ebû Dâvûd, İbn-i Mâce) Ümmetim dalâlet üzerinde icmâ etmez (bir-leşmez). (Hadîs-i şerîf-Beyhekî)","osmanli":"ضلالت"},{"kelime":"DÂLL","anlam":"Delâlet eden, delil olan, yol gös-teren.","kategori":"dil","osmanli":"دال"},{"kelime":"DÂLL","anlam":"Yolunu şaşıran, sapıtan. Resûlullah’ın Mekke’den Beytü’l-Mukaddes’e götürüldüğüne inanmayan kâfir olur. Göklere ve bilinmeyen yerlere götürüldüğüne inanma-yan ise, dâll ve mübtedi’ olur. (Bahrü’r-Râik, Rûhü’l-Beyân)","kategori":"dil","osmanli":"ضال"},{"kelime":"DÂLLE","anlam":"1.Dalâlete düşmüş, şaşırmış. 2.Âdet hâlinin kaç gün olduğunu unutan veya kaç gün olduğunu bilip ayın başında mı, or-tasında mı, sonunda mı olduğunu kestireme-yen kadın, muhayyire.","kategori":"dil","osmanli":"ضاله"},{"kelime":"DAMÂN","anlam":"1.Bir malın mislini veya kıymetini tazmin etme. 2.Kefil olma, kefâlet.","kategori":"muamelat","misal":"Damân-ı Akd: عقد ضمان (A) Akdin bir şekilde bozulması hâlinde, malın gerçek kıymetinin değil, konuşulan bedelini tazmin mükellefiyeti. Damân-ı Derek: درك ضمان (A) Satıcının, sattığı malda başkasının bir istihkak iddiası olursa, yani malın başkasına ait olduğu ortaya çıkarsa veya mal kusurlu ise müşterinin zararını öde-meyi üzerine alması. Damânu’l-Uhde, Damâ-nu’l-İstihkâk.","osmanli":"ضمان"},{"kelime":"DÂMİN","anlam":"1.Tazmin ile mükellef kimse. 2.Kefil, güvenilen.","kategori":"fikih","misal":"İmâm, dâmin; müezzin ise mü’temen, yani emniyet edilendir. Ey Allah’ım, İmâmları irşad et, müezzinleri de mağfiret et! (Hadîs-i şerîfMüsnedü Ahmed)","osmanli":"ضامن"},{"kelime":"DÂNİŞ","anlam":"Bilmek, ilim.","kategori":"dil","misal":"Her feyz ve nûr ki, gayb âleminden insana erişir, evvelâ sadra nâzil olur, göğüse iner, işte burası mahall-i ilm ve dâniştir. (Mektûbât-ı Ma’sûmiyye)","osmanli":"دانش"},{"kelime":"DÂNİŞMEND","anlam":"1.Bilgili. 2.Osmanlılarda Tanzimat’tan önce, müderris ve kadıların stajiyeri.","kategori":"osmanli","osmanli":"دانشمند"},{"kelime":"DANK","anlam":"Bir dirhem gümüşün altıda biri, takriben yarım gram gümüş.","kategori":"dil","misal":"Kıyâmet günü, hak sahibi, hakkını afv etmezse, bir dank için, cemaat ile kılınmış ve kabul ol-muş yediyüz namazın sevabı alınıp, hak sahi-bine verilecektir. (İbni Âbidîn)","osmanli":"ضنك"},{"kelime":"DANYÂL (aleyhisselâm)","anlam":"Bâbil sürgünü sırasında gönderilen ve Benî İsrâil’i tekrar Filistin’e getiren peygamber.","kategori":"dil","osmanli":"دانيال"},{"kelime":"DÂR","anlam":"1.Ev. 2.Yurt, vatan, memleket.","kategori":"dil","osmanli":"دار"},{"kelime":"DARB","anlam":"Dövmek, vurmak.","kategori":"dil","osmanli":"ضرب"},{"kelime":"DARI","anlam":"Tohumları buğday gibi gıda ola-rak kullanılan bir hububat nevi.","kategori":"dil","osmanli":"دارى"},{"kelime":"DÂRÜLFÜNûN","anlam":"“Fenler evi” mânâ-sına İstanbul Üniversitesi’nin 1863’teki kuru-luşundan 1933 tarihine kadar taşıdığı isim.","kategori":"osmanli","osmanli":"الفنون دار"},{"kelime":"DÂVûD (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi bildirilen Benî İsrail peygamberlerinden.","kategori":"dil","misal":"Dâvûd’a Zebûr’u verdik. (İsrâ sûresi: 55) İnsanın yediklerinin en hayırlısı, iyisi, bileği ile kazanıp yediğidir. Allahü teâlânın peygamberi Dâvûd (aleyhisselâm), elinin emeği ile kazanıp yerdi. (Hadîs-i şerîfBuhârî) Allahü teâlâ Mûsâ aleyhisselâmdan sonra, İsrâiloğullarına birçok peygamber gönderdi. Bu peygamberler insanları Tevrat’ın hükümleriyle amel etmeye da’vet etti. Fakat zaman geçtikçe azgınlaşan İsrâiloğull…","osmanli":"داود"},{"kelime":"DÂYİN","anlam":"Borç veren, alacaklı.","kategori":"muamelat","misal":"(Bkz. Borç)","osmanli":"داين"},{"kelime":"DECCÂL","anlam":"Kıyâmetin büyük alâmetlerinden olup, Kıyâmete yakın peygamberlik iddiasıyla ortaya çıkarak, Îsâ aleyhisselâm ile Mehdî aleyhirrahme tarafından öldürülecek olan kâfir.","kategori":"akaid","misal":"Hiç şüphe yok, deccâl çıkacaktır. Onun sol gözü kördür. Ve üzerinde beyaz bir ben vardır. Alnında “kâfir” diye yazılıdır. Gözlerinin üzerinde de kalın bir perde bulunur. Körleri ve baras hastalarını iyi eder, ölüleri diriltir. Ve; “Ben Rabbinizim” der. Kim onu tasdik ederse deccâlin fitnesine düşmüştür. Kim de “Rabbim Allah” der ve böyle ölürse o zaman deccalin fitnesinden kurtulmuş olur. Ve ona bir daha fitne ve az…","osmanli":"دجال"},{"kelime":"DEDİKODu","anlam":"Bir Müslümanın veya zimmînin ayıbını, onu kötülemek için arkasından söylemek. Kıyl-ü kâl. (Bkz. Gıybet) Sözün kısası şudur ki, dedikodu sözlere inanı-lacak, dostluk bunlara göre olacaksa, söz taşı-yanların ellerinden kurtuluş olamaz. Bunun","kategori":"dil","misal":"için de sağlam dostluk kurulamaz. Dediko-dulara kulak vermeyiniz ve geçmişleri unutu-nuz! Böylece dostluk yıkılmasın, eski sıkıntılar aradan kalksın. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قودو ديدى"},{"kelime":"DEF‘","anlam":"Bir şeyi savma, bertaraf etme.","kategori":"dil","osmanli":"دفع"},{"kelime":"Def ‘-i Hâcet","anlam":"Büyük veya küçük abdest bozmak.","kategori":"ibadet","osmanli":"حاجة دفع"},{"kelime":"DEFN","anlam":"1.Gömme. 2.Cenâzenin yıkanıp kefenlendikten ve namazı kılındıktan sonra kabre konularak üzerinin toprakla örtülmesi.","kategori":"ibadet","misal":"Meyyiti, sâlihlere ve evliyâya (Allahü teâlânın sevdiği kullarının kabirlerine) yakın defnetmelidir. Rutûbetli yerlere defnetmek iyi değildir. (Tahtâvî)","osmanli":"دفن"},{"kelime":"DEFTERDÂR","anlam":"Osmanlılarda merkez ve taşrada malî işlere bakan en yüksek rütbeli memur.","kategori":"osmanli","osmanli":"دفتردار"},{"kelime":"DEHR","anlam":"1.Zaman, devir. 2.Âlemin var-lığının başlangıcından son bulmasına kadar olan bütün zaman.","kategori":"dil","misal":"İnsanoğlu, var edilip bahse değer bir şey olana kadar, şüphesiz, uzun bir zaman geç-memiş midir? (Dehr sûresi: 1) Câhiliye devri insanları; “Bizi gece ve gündüzden başkası helâk etmiyor. Bizi helak eden, öldüren ve bize hayat veren odur” der ve dehre söverdi. Allahü teâlâ da şöyle buyurmaktadır: “Âde-moğlu dehre söverek bana eziyet veriyor. Hâlbuki dehr, benim. İş, benim elimdedir. Geceyi ve gündüzü ben evirip çeviririm. O hâlde sizden biriniz sakın dehre sövmesin.” (Hadîs-i şerîf-Muvattâ’)","osmanli":"دهر"},{"kelime":"DEHRİYYE","anlam":"Allah’a ve âhirete inan-","kategori":"akaid","misal":"mayıp, dehr (zaman) sonsuzdur ve dünyanın başlangıcı ve sonu yoktur, böyle gelmiş böyle gider diyen inkârcı bir felsefe ekolü.","osmanli":"دهريه"},{"kelime":"DELÂLET","anlam":"1.Delil olma, yol gösterme. 2.İşâret etme. 3.Bir sözün bir mânâyı göstermesi.","kategori":"dil","misal":"Ey îmân edenler! Sizi acı bir azaptan kur-taracak bir ticâreti göstereyim mi? Allahü teâlâ ve Resûlüne îmân edin, inanın, malla-rınızla ve canlarınızla Allah yolunda sava-şın. Eğer bilirseniz bu sizin için çok hayır-lıdır. (Saf sûresi: 10-11) Hayra delâlet eden, hayrı yapan gibidir. (Hadîs-i şerîf-Ebû Ya’lâ) Dinî bilgilerin delilleri (kaynakları) dörttür: Bi-rincisi sübûtu (varlığı) ve delâleti kat’î (kesin) olanlar. Açık anlaşılan âyetler ve tevâtür, söz birliği ile bildirilmiş açıkça anlaşılan hadîs-ler böyledir. İkincisi, sübûtu kat’î olup, delâ-leti zannî olanlar (kesin olmayanlar). Mânâsı açıkça anlaşılmayan âyetler böyledir. Üçüncüsü, sübûtu zannî, delâleti kat’î olanlar. Tek Sahâbî-nin (Peygamber efendimizin arkadaşının) bil-dirdiği açık ve anlaşılır hadîsler böyledir. Dör-düncüsü, sübûtu da delâleti de zannîdir. Tek Sahâbînin bildirdiği açıkça anlaşılmayan ha-dîsler böyledir. Birincisi farz ile haramları, ikin-cisi ve üçüncüsü vâcib ile tahrîmen mekrûhu (harama yakın mekrûhu), dördüncüsü sünnet ile müstehâbı bildirir. (Mir’at, Usûl-i Serahsî)","osmanli":"دلالت"},{"kelime":"Delâlet-i Nass","anlam":"Nassın delâleti. Nass’da (Kur’ân-ı kerîm ve hadîs-i şerîfte) zikredilen şeyin hükmünün, müşterek (ortak) illet sebebiyle zikredilmeyen şey hakkında da sâbit olduğuna delâlet etmesi.","kategori":"fikih","misal":"“Anababana öf (bile) deme” meâlindeki İsrâ sûresi yirmi üçüncü âyet-i kerîmesi, açıkça anababaya öf demenin haramlığını delâlet-i nass ile bildirmektedir. Öf demenin haram oluşunun illeti (sebebi), eziyet vermektir. Bu illet, anababayı dövmede ve sövmede fazlasıyle bulunduğundan, âyette açıkça bildirilmeyen anababayı dövmenin, onlara sövmenin de haramlığı ile hükmolunmuştur. (Şerhu Menâr, Usûl-i Serahsî)","osmanli":"نص دلالت"},{"kelime":"DELÎL","anlam":"1.Delâlet eden; kendisi bilinince başkası bilinen şey. 2.Dinî hükümlerin çıka-rıldığı kaynak, vesîka.","kategori":"dil","misal":"(Bkz. Edille-i Şer’iyye) Rabbinin sun’una (işine) bir bakmadın mı? Gölgeyi nasıl uzatıp yaymıştır. O, eğer dile-seydi, onu elbet sâkin kılardı. Sonra biz gü-neşi ona bir delil yapmışızdır. (Çünki güneş olmasaydı, gölge bulunmazdı. Nur olmasaydı, zulmet bilinmezdi. Zîrâ her şey zıddıyla bili-nir.) (Furkân sûresi: 45) Din bilgilerinin elde edildiği deliller dörttür: Bunlar; Kitap (Kur’ân-ı kerîm), sünnet, icmâ ve kıyâstır. (Hadîka)","osmanli":"دليل"},{"kelime":"DELK","anlam":"Oğma, (abdest ve gusülde) yıkanan yerleri oğuşturma.","kategori":"ibadet","misal":"Delk, Hanefî mezhebinde abdestin sünnetlerindendir. (Mültekâ) Mâlikî mezhebinde abdest ve guslde her uzvu delk farzdır. (elFıkhu ale’l-Mezâhibi’l-Erbaa)","osmanli":"دلك"},{"kelime":"DEM","anlam":"1.Kan. 2.Hacda koyun ve keçi cinsinden olan kurban.","kategori":"ibadet","osmanli":"دم"},{"kelime":"DEMOKRASİ","anlam":"“Çoğunluğun hâkimiyeti” mânâsına devletin, halkın ekseriyetinin iradesine göre idare olunması.","kategori":"osmanli","misal":"Otokrasi’nin zıddı.","osmanli":"دموقراسى"},{"kelime":"DENÎ","anlam":"Alçak, rezil, soysuz.","kategori":"dil","misal":"Alçak, rezil, soysuz. Bîvefâdır ey denî dünya senin her nimetin, Sârsâr-ı bâd-ı ecel mahveyliyor her rif ’atin. DENK: دنك (A) Miskalin dörtte birine ve altı çe- kirdeğe müsavi (0.8775 gr.) bir ağırlık ölçüsü.","osmanli":"دنى"},{"kelime":"DERECE","anlam":"1.Basamak. 2.Dairenin 360 cüzünden biri. 3.Akrabalıkta yakınlık sırası.","kategori":"dil","osmanli":"درجه"},{"kelime":"DEREZÎ","anlam":"(Bkz. Dürzî)","kategori":"dil","osmanli":"درزى"},{"kelime":"DERGÂH","anlam":"Makam, kapı girişi, eşik; tasavvufta kemale gelmiş zâtlar tarafından, taliblere, başta tasavvuf olmak üzere İslâm ilimlerinin öğretildiği yer.","kategori":"tasavvuf","misal":"Yâ Rab! Bu abd-i rû’siyâh, ettimse de yüzbin günah, Dergâhını kıldım penâh, afvındır ancak mültemes. (Sâmi Paşa)","osmanli":"درﮔاه"},{"kelime":"DERMÂN","anlam":"1.İlâç, çare. 2.Takat, kuv-vet, güç.","kategori":"dil","osmanli":"درمان"},{"kelime":"DERûN","anlam":"İç, içeri, dâhil; gönül, kalb, yürek.","kategori":"tasavvuf","osmanli":"درون"},{"kelime":"DERVÎŞ","anlam":"“Kapı eşiği” mânâsına Allahü teâlâdan başka şeyleri kalbinden çıkarıp bütün âzâsıyla İslâm dininin emir ve yasaklarına uyan, dünya malına gönül bağlamayan kimse.","kategori":"akaid","misal":"Gönlün derviş eyleyen hırkaya muhtaç değil. (Yûnus Emre)","osmanli":"درويش"},{"kelime":"DEST","anlam":"El, yed.","kategori":"dil","osmanli":"دست"},{"kelime":"DEVERÂN","anlam":"(Bkz. Devrân)","kategori":"dil","osmanli":"دوران"},{"kelime":"DEVLET","anlam":"1.Gâlib gelme, zafer. 2.Nöbetleşe ardı ardına gelme, tedâvül etme. 3.Talih, baht açıklığı, nimet bolluğu.","kategori":"osmanli","misal":"Eğer siz (Uhûd’da) bir acıya uğradınızsa, (Bedir’de de düşmanınız olan) o kavim benzer bir acıya uğramıştır. Bu günler, insanlar arasında dönüp duran bir devlettir. (Âl-i İmrân sûresi: 140) Allah’ın fethedilen memleketler halkının mallarından peygamberine verdikleri; Allah, Peygamber, yakınlar, yetimler, yoksullar ve yolda kalmışlar içindir; ta ki içinizdeki zenginler arasında elden ele dolaşan bir devlet olmasın. (…","osmanli":"دولت"},{"kelime":"DEVR","anlam":"Dönüp, dolaşma; zaman; na-kil, aktarma, bir şeyi başkasına teslim etme.","kategori":"dil","osmanli":"دور"},{"kelime":"Devr Hatmi","anlam":"Meyyit için çeşitli kimselerin sessiz olarak çeşitli cüzler okuyup Kur’ân-ı kerîmi hatm etmeleri ve herbirinin okuduğunun sevâbını ölünün ruhuna göndermeleri veya birinin hepsi için hediye etmesi.","kategori":"dil","osmanli":"ختمى دور"},{"kelime":"DEVRÂN","anlam":"1.Dünya, felek; zaman; talih, kader. 2.Devir, devretme. 3.Dervişlerin cezbe hâline gelip kendilerinden geçerek dönmeleri.","kategori":"akaid","osmanli":"دوران"},{"kelime":"DEYN","anlam":"Borç; hazır ve mevcut olmayan mal.","kategori":"muamelat","misal":"Her satışta söz kesilirken iki maldan her biri ya ayn (hazır, mevcût, varlığı belli) veya deyn olur. Bir satışta mebî’in (satılan malın) ve semenin (bedelin) söz kesilme sırasında ikisi de deyn olurlarsa, ayrılmadan önce kabz edilseler (teslim olunsalar) de bey’ (satış) sahîh (geçerli) olmaz. Akd (sözleşme) bâtıl (hükümsüz, geçersiz) olur. Sarf satışı bundan müstesnâdır. (Dürerü’l-Hükkâm)","osmanli":"دين"},{"kelime":"Deyn-i Kavî","anlam":"Kuvvetli borç. Ödünç verilen zekât malı ve zekât malının satışı karşılığı alınacak olan semen (bedel).","kategori":"muamelat","misal":"Deyn-i kavî, zekâtta nisâb hesâbına katılır. Alınacak paranın veya bunun ile yanında bulunanın toplamının nisâbı üzerinden bir sene geçince, eline geçen her mikdarın kırkta birini hemen vermek farz olur. İki sene sonra eline geçenin iki yıllık, üç sene sonra eline geçenin üç yıllık zekâtını verir. Meselâ, üç yüz dirhem alacağı olan, üç sene sonra, iki yüz dirhem alırsa, üç yıl için beşer dirhemden, on beş dirhem zek…","osmanli":"قوى دين"},{"kelime":"Deyn-i Mütevassıt","anlam":"Orta borç. Ti-câret malı olmayan zekât hayvanları ile köle, ev, yiyecek, içecek gibi ihtiyâç maddelerinin satışları karşılığı ve binâların kirâ alacakları. Deyn-i mütevassıt, nisâb hesâbına katılır. Bir sene sonra, eline nisâb mikdarı veya daha çok geçince, her sene ele geçenin kırkta biri hemen verilir. (İbni Âbidîn)","kategori":"ibadet","osmanli":"متوسط دين"},{"kelime":"Deyn-i Sahîh","anlam":"Sahih borç. Ödemekten ve ibrâdan yani aftan başka yol ile kurtuluşu olmayan borçlar.","kategori":"muamelat","misal":"Zekât borcu, deyn-i sahîh değildir. Çünki, borçlu ölürse veya mal elden çıkınca zekât vermesi afv olur. Böyle sahîh olmayan rehn, âriyet, emânet, mudârebe, şirket ve kirâya verilmiş olan mallar, havâle edilemez. Satılan malın semeni, kirâ bedeli ve ödünç verilen mislî eşya, deyn-i sahîh olduklarından, havâle olunur. (İbni Âbidîn)","osmanli":"صحيح دين"},{"kelime":"Deyn-i Za’îf","anlam":"Zayıf borç. Mehr, diyet, kitâbet, hul bedeli gibi bir mal veya hizmet karşılığı olmayan alacaklar.","kategori":"muamelat","misal":"Deyn-i za‘îf, nisâb hesâbına katılır. Nisâb mikdarı malı teslim aldıktan bir yıl sonra yalnız o yılın zekâtı verilir. Elinde nisâb mikdarı mal da varsa, deynden aldığını, buna katıp, elindekinin bir yılı tamam olunca, aldığının zekâtını da birlikte verir. Bunun için ayrıca bir yıl beklemez. Deyn-i kavî ve mutavassıttadan sene geçmeden önce ele geçirdiğini aynı şekilde kendisinde bulunan nisâba katarak zekâtlarını bi…","osmanli":"ضعيف دين"},{"kelime":"DEYR","anlam":"Hristiyan keşişlerinin kaldığı yer, manastır.","kategori":"dil","osmanli":"دير"},{"kelime":"DEYYÂN","anlam":"1.Din sahibi, hakkıyla karşılık veren, kıyâmet günü, herkesin dünyada iken yaptıklarının hesâbını ve hakkını en iyi bilen ve veren mânâsına Allahü teâlânın Es-mâ-i hüsnâsından (edDeyyân). Ben azîmüşşân herkese mücâzât eden deyyânım. (Hadîs-i KudsîBuhârî)","kategori":"akaid","osmanli":"ديان"},{"kelime":"DEYYûS","anlam":"Hanımının nâmussuzluğuna, ahlâksızlığına aldırış etmeyen, göz yuman kimse, pezevenk, kaltaban.","kategori":"tasavvuf","misal":"Cennet, deyyûsa haramdır. (Hadîs-i şerîfDeylemî) Üç kişi Cennet’e hiç girmeyecektir: Birincisi deyyûs, ikincisi, kendisini erkeklere benzeten kadınlar. Üçüncüsü, içki içmeye devam edenler. (Hadîs-i şerîfMüsnedü Ahmed)","osmanli":"ديوث"},{"kelime":"DİL","anlam":"Gönül, yürek, kalb.","kategori":"tasavvuf","osmanli":"دل"},{"kelime":"DİLBER","anlam":"Gönlü alıp götüren, güzel.","kategori":"dil","osmanli":"دلبر"},{"kelime":"DİMÂĞ","anlam":"Beyin.","kategori":"muamelat","osmanli":"دماغ"},{"kelime":"DİN ÂLİMİ","anlam":"Akl, ilim ve din sahibi olan din adamı.","kategori":"dil","osmanli":"عالمى دين"},{"kelime":"DİN (Dîn)","anlam":"1.Karşılık, ceza. 2.Allahü teâlânın peygamberleri vasıtasıyla insanlara gönderdiği, dünyada huzur ve âhirette kurtuluş va’deden inanılacak ve yapılacak şeylerin tamamı. Doğrusu Allahü teâlâ indinde makbûl olan din İslâm’dır. Kendilerine kitap verilenler kendilerine ilim geldikten (İslâm dinini bildikten) sonra aralarındaki çekememezlik, kin ve düşmanlıktan dolayı ihtilâfa düştüler. Kim Allah’ın âyetlerini inkâr ederse, şüphesiz ki Allah, hesâbı pek çabuk görendir. (Âl-i İmrân sûresi: 19) Bugün sizin dininizi kemâle erdirdim; üzerinize olan nîmetimi tamamladım ve din olarak da İslâm…","kategori":"akaid","osmanli":"دين"},{"kelime":"DÎNÂR","anlam":"25.âyetinde meâlen; “Onlara ki-tap ve mizân gönderdik ki, bunlarla adâleti yerine getirsinler” buyuruldu.","kategori":"dil","misal":"Bir miskal (4.8 gram) ağırlı-ğındaki altın para. Bir kimsenin infak edeceği (harcayacağı) en fazîletli dînâr, çoluğuna-çocuğuna infâk et-tiği (harcadığı) dînâr ile Allah yolunda hay-vanına infâk ettiği dînâr, bir de yine Allah yolunda arkadaşlarına sarf ettiği dînârdır. (Hadîs-i şerîf-Müslim) Allah yolunda infâk ettiğin bir dînâr, köle azâdı için infâk etti-ğin bir dînâr, bir fakire sadaka olarak ver-diğin bir dînâr, âilene sarf ettiğin bir dînâr vardır. Bunlardan sevâbı çok olanı âilene sarf ettiğindir. (Hadîs-i şerîf-Müslim) İnsanlar arasında adâleti te’mîn etmek için üç şey lâzımdır: Nâmûs-i rabbânî, hâkim-i insânî ve dinâr-ı mîzânî. Bunlardan en kuvvetlisi, en büyüğü, nâmûs-i rabbânî olan İslâmiyyet’tir. Dinler, Allahü teâlânın adâleti sağlamak için gönderdiği kanûnlardır. Hâkimlerin adâleti sağlamaları için, bu ilâhî kanûnları gönderdi. Hadîd sûresi Burada, kitap, din demektir. Çünki din, Kur’ân-ı kerîmdeki emr ve yasakların ismidir. Mizân da altına işâret-tir. Çünki altın, ağırlıkla ölçülür. Kur’ân-ı kerî-min emr ve yasaklarını beğenmeyen kâfirdir ve münâfıktır. Hâkimi, hükûmeti dinlemeyen âsî-dir. Altının değerini kabul etmeyen de, hâin ve hırsız olur. (Ahlâk-ı Alâî)","osmanli":"دينار"},{"kelime":"DİNDÂR","anlam":"Dinine bağlı.","kategori":"dil","osmanli":"ديندار"},{"kelime":"DIRÂRİYYE","anlam":"Dırâr bin Amr tarafından kurulan ve Mücessime ile Cebriye’nin fikirlerinin karışımını teşkil eden bid‘at fırkası.","kategori":"dil","osmanli":"ضراريه"},{"kelime":"DİRHEM","anlam":"Bir ağırlık birimi; umumi-yetle bu ağırlıkta basılan gümüş para.","kategori":"dil","misal":"(Kafile Mısır’a vardığında) onu (Yûsuf ’u) ucuz pahaya, birkaç dirheme sattılar. (Yûsuf sû-resi: 20) Bilerek yenen bir dirhem riba, Al-lah katında otuzaltı zinâdan beterdir. (Ha-dîs-i şerîf-Beyhekî, Müsnedü Ahmed) İki yüz dirhem gümüşten aşağısına zekât yoktur. (Hadîs-i şerîf-Müslim) Âhir zaman geldi-ğinde, insanlar için dirhem ve dinara (pa-raya) ihtiyaç daha fazla olur. Zira insan o zaman din ve dünyasını onlarla ayakta tu-tabilir. (Hadîs-i şerîf-Taberânî) Dirhem kelimesi necâset bakımından bir mis-kal (4,8 gr.); zekâtta 3,365 gr. ağırlığı ifâde eder. (İbni Âbidîn)","osmanli":"درهم"},{"kelime":"Dirhem-i Şer‘î","anlam":"Resûlullah aleyhisselâm zamanında kullanılan (3,36) üç gram ve otuz altı santigram ağırlığındaki gümüş para.","kategori":"dil","osmanli":"شرعى درهم"},{"kelime":"DÎV","anlam":"Dev; cin, şeytân.","kategori":"dil","misal":"Azığım yok, yazığım çok, yolda türlü korku var, Âh u figân eyliyorum, dîv-ü şeytân duymuyor, (Niyazî Mısrî)","osmanli":"ديو"},{"kelime":"DÎVÂN (Divân)","anlam":"1.İslâm devletlerinde Hazret-i Ömer’den itibaren kurulmaya başlanan, siyasî, idarî, malî ve adlî her çeşit işin yürütüldüğü ofisler. 2.İçinde isimlerin yazılı bulunduğu hesâb defteri, yazılı defter.","kategori":"dil","misal":"Kıyâmette, belâya müptelâ olan kimseler getirilir. Lâkin onlar için dîvân açılmaz, mizan kurulmaz ve sırata konulmaz. Onların üzerine ecir dökülür de dökülür. (Hadîs-i şerîfİbni Neccâr) Hükümdarın oturduğu sedir.","osmanli":"ديوان"},{"kelime":"DİYÂNET","anlam":"Allahü teâlâ ile kul arasında olan iş, ibâdet.","kategori":"akaid","misal":"Diyânette, âdil ve bâliğ bir Müslümanın sözüne inanılır. Bu hususta bir kadın da, bir erkek gibidir. Suyun pis olduğunu söylerse, bu su ile abdest alınmaz; teyemmüm edilir. Fâsık veya hâli belli olmayan bir Müslüman söylerse, araştırılır ve kuvvetli zanna göre hareket edilir. Kâfir veya çocuk, suya pis derse ve abdest alacak olan kimse kendi de buna inanırsa, o suyu dökmeli ve sonra teyemmüm etmelidir. (İbni Âbidîn)…","osmanli":"ديانت"},{"kelime":"DİYET","anlam":"Cinâyet (adam öldürme ve uzuv kesme) karşılığı suçun mağduruna ödenen para, kan parası, kan pahası.","kategori":"dil","misal":"Ey îman edenler! Öldürülenler hakkında size kısas yazıldı. Hüre hür, köleye köle, ka-dına kadın öldürülür. Ancak kim kardeşi tarafından affedilirse kısas düşer. Bundan sonra iyiye uymak, öldürülenin velisine (ge-reken diyeti) güzel bir şekilde ve tam olarak ödemek gelir. (Bakara sûresi: 178) Bir mü’mini hataen öldüren kimsenin, mü’min bir köle azat etmesi ve ölenin ailesine teslim edile-cek bir diyet vermesi gereklidir. Meğer ki ölünün ailesi o diyeti bağışlamış ola. (Nisa sûresi: 92) İnsan öldürmenin diyeti yüz de-vedir. (Hadîs-i şerîf-Beyhekî)","osmanli":"ديت"},{"kelime":"DOGMA","anlam":"Katı katıya benimsenen ve doğruluğu münakaşa edilmeyen prensip, nass.","kategori":"fikih","osmanli":"دوغمه"},{"kelime":"DOKTRİN","anlam":"Nazariye.","kategori":"dil","osmanli":"دوقترين"},{"kelime":"DÖNME","anlam":"Müslüman olduğunu söy-lediği hâlde, gerçek inancından ayrılmamış kimse. Avdetî. Ekseri Sabataycı denilen ve müslüman görünen Yahudi mezhebi men-subları için kullanılır.","kategori":"dil","osmanli":"دونمه"},{"kelime":"Du‘Â (Dü’â)","anlam":"1.Seslenmek, çağırma. 2.Allah’a yalvarmak.","kategori":"ibadet","misal":"Bana (hâlis kalb ile) du‘â ediniz. Du‘ânızı kabul ederim. (Mü’min sûresi: 60) Bütün iyilikleri işleme ibadetin yarısı, du‘â da öbür yarısıdır. Allah bir kulu için hayır murat ederse kalbini du‘âya meylettirir. (Hadîs-i şerîfİbn-i Mâce) Şu beş du‘â kabul edilir:","osmanli":"دعاء"},{"kelime":"Du‘â Ordusu","anlam":"Sıkıntıda olan ve darda kalan Müslümanlara duâları ile yardımda bulunan Allahü teâlânın sevgili kulları, velîler.","kategori":"akaid","misal":"İmrân sûresinin yüz yirmi altıncı âyetinde ve Enfâl sûresinde meâlen; “Yardım, ancak ve yalnız Allah’tandır” buyruldu. Bu yardıma, du‘â ordusu vâsıtası ile kavuşulur. Ayrıca du‘â, kazâyı def ’eder, uzaklaştırır. Resûlullah sallallahü aleyhi ve sellem; “Kazâ, ancak ve yalnız du‘â ile durdurulur” buyurdu. Du‘â ordusunun askerleri, gazâ ordusu askerlerinin ruhu gibidir. Gazâ ordusunun askerleri, onların kalbleri, beden…","osmanli":"اوردوسى دعاء"},{"kelime":"DÜBÜR","anlam":"1.Makat (mak’ad). 2.Bir işin sonu. 3.Bir şeyin gerisi, arkası.","kategori":"dil","osmanli":"دبر"},{"kelime":"DûÇÂR","anlam":"Tutulmuş, uğramış, yaka-lanmış.","kategori":"dil","osmanli":"دوﭼار"},{"kelime":"DuDu","anlam":"Papağan, tûtî.","kategori":"dil","osmanli":"دودو"},{"kelime":"DuHÂ VAKTİ","anlam":"Kuşluk (işrak) vakti. Oruç zamanının, yani imsak ile iftar vakti arasındaki müddetin dörtte birinin ta-mam olmasından itibaren başlayan vakit. Gü-neşin doğuşundan takrîben 40 dakika sonra başlar, öğleye bir saat kalasıya devam eder. Kuşluk vaktine andolsun! (Duhâ sûresi: 1)","kategori":"dil","osmanli":"وقتى ضحى"},{"kelime":"DÜLGER","anlam":"Bir binânın tahta kısımla-rını yapan usta. (Dürûger.)","kategori":"dil","osmanli":"دولگر"},{"kelime":"DûN","anlam":"Aşağı, aşağılık; altta, aşağıda. Her şey geçer âlemde, bir hâlde yoktur sükûn! Bil ki değmez teessüf etmeye dünya-yı dûn! (Said Paşa)","kategori":"dil","osmanli":"دون"},{"kelime":"DÜNYÂ","anlam":"1.Yer küresi. 2.Ölümden önce olan her şey. 3.Allah’ın rızası için olmayan her şey.","kategori":"dil","misal":"Allahü teâlâ arzdan bir şey yaratmadan bin yıl evvel Mekke’yi yarattı ve etrafını melek-lerle bürüdü. Ondan sonra ona Medîne’yi, sonra ona Kudüs’ü ekledi. Ondan bin yıl sonra da dünyayı bir kerede yarattı. (Ha-dîs-i şerîf-Deylemî) Şu insanlar, çarçabuk geçen dünyayı sevi-yorlar da, önlerindeki çetin bir günü (âhi-reti) ihmal ediyorlar. (İnsân sûresi: 27) Ne gü-zel yerdir dünya, Allah razı oluncaya kadar âhiret azığını temin etmek için; ne fenadır dünya, âhiret azığını terk edip Allah’ın rızâ-sını kazanmayanlara! (Hadîs-i şerîf-Hâkim) Dünyayı, isteyene, istediğimiz kimseye, di-lediğimiz kadar hemen veririz. Sonra onu Cehennem’e sokarız. (İsrâ sûresi: 18) Dünya-nın misali, köpeklerin üzerine toplanıp da sürükledikleri bir leşe benzer. Sen onlar gibi olup, onlarla beraber onu sürüklemeyi arzu eder misin? (Hadîs-i şerîf-Deylemî) Dünya, ednâ kelimesinin müennesidir. Yani, ism-i tafdîldir. Masdarı, dünüv veya denâettir. Birinci masdardan gelince, çok yakın demektir. “Biz en yakın olan göğü, çırağlarla süsledik” âyet-i kerîmesindeki dünya kelimesi böyledir. Bazı yerde de, ikinci mânâ ile kullanılmıştır. Meselâ; “Denî, alçak şeyler mel’ûndur” ha-dîs-i şerîfinde böyledir. Yani “Dünya mel’ûndur” demektir. Alçak şeyler, Cenâb-ı Hakk’ın nehy-i iktizâî ve nehy-i gayr-i iktizâîsidir. Yani, haram ile mekrûhlardır. Şu hâlde, Kur’ân-ı kerîmde, zem edilen, kötü denilen dünya, haramlar ve mekrûhlardır. Mal kötülenmemiştir. Çünki, Cenâb-ı Hak mala, hayr adını vermektedir. Bu sözümüzü isbât eden vesîka, bütün mah-lûkların ve insanlığın üstünlükte ikincisi olan İbrâhim Halîlürrahmân’ın malıdır. Yalnız ya-rım milyonu sığır olmak üzere, davarları, ova ve vâdileri dolduruyordu. (Seâdet-i Ebediyye)","osmanli":"دنيا"},{"kelime":"DÜNYÂLIK","anlam":"İnsanın hayatta muhtaç olduğu şeyler.","kategori":"tasavvuf","misal":"Kim nüfuz sahibi bir kimseye dünyalık umarak tevazu gösterirse, Allah ondan dünyada ve âhirette yüzünü çevirir. (Hadîs-i şerîfDeylemî) Resûlullah aleyhisselâm bir sabah, Eshâbı ile konuşurken, kuvvetli bir genç, erkenden dükkânına doğru geçti. Bazıları; “Erkenden dünyalık kazanmaya gideceğine, buraya gelip birkaç şey öğrenseydi iyi olurdu.” deyince, Resûlullah aleyhisselâm; “Öyle söylemeyiniz! Eğer kimseye muhtaç ol…","osmanli":"دنيالق"},{"kelime":"DÜNYÂYI TERK ETMEK","anlam":"Dünyada Allah için olmayan her şeyi terk etmek; haramlardan başka, mübâhların çoğunu da bırakıp, yaşamak için zaruri olan mikdarını kullanmak.","kategori":"fikih","misal":"Bir kimseye dünya ve âhiret arz olunsa, âhireti alıp dünyayı terk etse, ona Cennet vardır. Eğer dünyayı alıp âhireti terk ederse, ona Cehennem vardır. (Hadîs-i şerîfİbni Asâkir) Dünyanın her türlü zevk ve lezzetinden vazgeçip, bütün zamanını, ibâdet ile ve Müslümanların rahatlarını ve İslâm dinini bilmeyenlerin, doğru yola kavuşmaları için; lâzım olan ilmî ve teknik usûlleri ve vâsıtaları, en ileri ve en üstün şekil…","osmanli":"ايتمك ترك دنيايى"},{"kelime":"DÜNYEVÎ","anlam":"1.Uzağı, ileriyi gören. 2.Dürbün.","kategori":"dil","misal":"Dünyaya mensub, dün-yaya ait, dünya ile alâkalı, uhrevî olmayan. DÜRBİN: دربين (F)","osmanli":"دنيوى"},{"kelime":"DûR","anlam":"Uzak.","kategori":"dil","osmanli":"دور"},{"kelime":"DÜRûZ","anlam":"Dürzîler.","kategori":"dil","osmanli":"دروز"},{"kelime":"DÜRZÎ","anlam":"Şia’nın aşırı kanadından olup bugün ekseri Lübnan’da yaşayan bir mezheb mensubu.","kategori":"fikih","misal":"(Bkz. Derezîler)","osmanli":"درزى"},{"kelime":"DÜSTûR","anlam":"1.Kanun, kâide. 2.Büyük defter. 3.Devlet kanunlarını içine alan kitap; anayasa.","kategori":"osmanli","osmanli":"دستور"},{"kelime":"DÜYûN","anlam":"Borçlar. Deyn’in çokluk hâli. Düyûn-i umûmiyye: عموميه ديون (A) “Umumî borçlar” mânâsına Osmanlı Devleti’nin XIX.","kategori":"muamelat","misal":"asrın ikinci yarısından sonra yabancı devletler- den aldığı borçlara karşı gösterdiği gelirleri top-lamaya mahsus, İstanbul’da yabancı memurların idaresi altında çalışan müesseseye verilen isim.","osmanli":"ديون"},{"kelime":"E‘ûZÜ","anlam":"“Sığınırım!” mânâsına gelen ve “E‘ûzübillâhimineşşeytânirracîm” (Kovulmuş şeytândan Allah’a sığınırım) sözüne delâlet eden ifade.","kategori":"akaid","misal":"(Ey Habîbim!) Kur’ân-ı kerîm okuyacağın zaman E’ûzü... söyle (Nahl sûresi: 98) Allahü teâlâya yaklaşmak isteyenler, E’ûzü’ye yapışmakta, O’ndan korkanlar da, E’ûzü’ye sarılmaktadır. Günahı çok olanlar E’ûzü’ye sığınmıştır. E’ûzü’nün mânâsı; “Allah’ın rahmetinden uzak olan ve gazâbına uğrayarak dünyada ve âhirette helâk olan şeytândan, Allahü teâlâya sığınırım, korunurum, O’ndan yardım beklerim. O’na yalvarır, imdâd…","osmanli":"اعوذ"},{"kelime":"EBCED HESÂBI","anlam":"Hâdiselerin zamanının tesbiti ve hatırda daha kolay kalması için tarih düşürmeye yarayan ve her harfi bir rakama tekabül eden Arabî harflerle yazılı sekiz kelimeden meydana gelen bir hesab sistemi.","kategori":"dil","misal":"Hâdiselerin zamanının tesbiti ve hatırda daha kolay kalması için tarih düşürmeye yarayan ve her harfi bir rakama tekabül eden Arabî harflerle yazılı sekiz kelimeden meydana gelen bir hesab sistemi. Ebced hesâbında, harflerin sayı olarak değerleri şöyle hesaplanır: Ebced (elif):1, be:2, cim:3, dal:4, hevvez (he):5, vav:6, ze:7, huttî (ha):8, tı:9, ye:10, kelemen (kef):20, lam:30, mim:40, nun:50, safes (sin):60, ayın:70, fe:80, sad:90, karaşet (kaf):100, re:200, şin:300, te:400, şehaz (se):500, hı:600, zel:700, dazığ (dad):800, zı:900, gayın:1000.","osmanli":"حسابى ابجد"},{"kelime":"EBDÂL","anlam":"“Bedeller” mânâsına dünyanın nizâmı ile vazifeli olup, Allahü teâlânın insanlardan gizlediği ricâlü’l-gayb denilen büyük zâtlardan.","kategori":"akaid","misal":"Nücebâ duâ eder. Yine kabul olmazsa, Ebdâl, daha sonra Ahyâr, sonra Amed duâ ederler. Kabul olmazsa Gavs duâ eder. Bunun duâsı elbet kabul olur. (Târîh-i Bağdâd)","osmanli":"ابدال"},{"kelime":"EBDÂN","anlam":"Bedenler.","kategori":"dil","misal":"İlm ikidir: İlmü ebdân ve ilmü edyân (Ha-dis-i şerif-Rıyâdü’n-Nâsihîn)","osmanli":"ابدان"},{"kelime":"EBED","anlam":"Sonsuzluk, sonu olmayan. (Bkz. Ebedî)","kategori":"dil","osmanli":"دبأ"},{"kelime":"EBEDÎ","anlam":"Sonsuz, sonu olmayan.","kategori":"dil","misal":"Önce Müslüman olanlardan, muhâcirlerin ve ensârın önce gelenlerinden ve bunların yolunda gidenlerden Allahü teâlâ râzıdır. Ve bunlar da, Allahü teâlâdan râzıdırlar. Al-lahü teâlâ, bunlar için, cennetler hazırladı. Bu cennetlerin altından nehirler akmakta-dır. Bunlar Cennet’te ebedî olarak kalacak-lardır. (Tevbe sûresi: 100) Allahü teâlâ kadîm olan (öncesi, başlangıcı ol-mayan) zâtı ile vardır. O sonsuz olarak var idi. Varlığından evvel yokluk olamaz. O ebedîdir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ابدى"},{"kelime":"Ebedî Mahrem","anlam":"Dinde kendileriyle evlenilmesi ölünceye kadar haram, yasak olan kimseler.","kategori":"fikih","misal":"Erkek için; yedisi kan ile olan, nesepten (soydan) akrabâ, yedisi süt sebebiyle, dördü de nikâh sebebi ile sonradan akrabâ olan toplam on sekiz kadın ebedî mahremdir. Bunlar: 1) Anne, 2) Annesinin ve babasının annesi, 3) Kızı, kızının kızı, 4) Kız kardeşi, 5) Kız kardeşinin kızı, 6) Erkek kardeşinin kızı, 7) Hala ve teyze, 8) Süt anne, 9) Süt annesinin ve süt babalarının anneleri, 10) Süt kızı, 11) Süt kızkardeşi, 1…","osmanli":"محرم ابدى"},{"kelime":"EBHER","anlam":"1.Daha parlak, en parlak. 2.Atardamar, aort.","kategori":"dil","misal":"Hayber’de yediğim zehirli etin acısını duy-maktayım. O zehrin tesiri ile, ebherim şimdi çalışmayacak hâle geldi. (Hadîs-i şerîf-Buhârî)","osmanli":"ابهر"},{"kelime":"EBNÂ","anlam":"Oğullar. İbn’in çokluk hâli.","kategori":"dil","osmanli":"ابناء"},{"kelime":"EBR","anlam":"Bulut.","kategori":"dil","osmanli":"ابر"},{"kelime":"EBRÂR","anlam":"1.İyiler. 2.İmanı temiz ve sağlam, ameli sâlih, ahlâkı düzgün, Rabbin rızasına kavuşmak için uğraşan kimseler.","kategori":"akaid","misal":"Muhakkak ki ebrâr, nîmetleri devamlı olan Naîm Cennet’indedirler. (Mutaffifîn sûresi: 22) Allahü teâlâ ebrâra, anne ve babalarına ve çocuklarına iyilik yapmaları sebebiyle bu ismi verdi. (Hadîs-i şerîfİbni Asâkir) Ebrâr bana kavuşmayı çok istiyor. Ben de onları çok istiyorum. (Hadîs-i KudsîDeylemî) Mukarrebler, Rabbine ancak O’nun için ibâdet eder; nimetlere kavuşmak için değil. Ebrâr ise, Allahü teâlâya nimetlerine…","osmanli":"ابرار"},{"kelime":"EBTAH","anlam":"Hacıların Mina’dan Mekke’ye son dönüşte uğrayıp bir mikdar konaklamaları müstehab olan vadi.","kategori":"ibadet","misal":"Muhassab.","osmanli":"ابطح"},{"kelime":"EBTER","anlam":"1.Kuyruğu kesik. 2.Nesilden ve hayırdan kesilmiş.","kategori":"dil","misal":"(Habîbim) gerçekten biz sana Kevser’i ver-dik. O hâlde (buna şükür olarak) namaz kıl ve kurban kes. Sana buğzeden, düşmanlık eden yok mu? İşte asıl ebter odur. Sana ge-lince Habîbim; senin temiz neslin, şân ve şe-refin kıyâmete kadar devam edecektir. (Kev-ser sûresi: 1-3) Resûlullah aleyhisselâmın Hazret-i Hadîce’den olan son erkek çocuğu vefât edince, Âs bin Vâil’in; “Muhammed ebter oldu” demesi üzerine; Kev-ser sûresi gelerek, Allahü teâlâ Âs bin Vâil kâ-firine, cevap verdi. (Taberî, Kurtubî)","osmanli":"ابتر"},{"kelime":"ECDÂD","anlam":"Dedeler, atalar. Cedd’in çokluk hâli.","kategori":"miras","osmanli":"اجداد"},{"kelime":"ECEL","anlam":"1.Belli vakit, vâde. 2.Hayat sahi-binin (canlının) ölümü için Allah’ın takdir ve tayin ettiği vakit.","kategori":"akaid","misal":"Eceli geldiği zaman bir kimsenin ölümünü Allah geciktirmez (Münâfıkûn sûresi: 11) Muhakkak Allah’ın aldığı O’nun, verdiği de O’nundur. O’nun nezdinde her şeyin belli bir eceli vardır. (Hadîs-i şerîf-Buhârî, Müslim, Nesâî) Öldürülen kişi de eceliyle ölmüştür. Ancak katil bu fiilinden dolayı ceza görür. (el-Fıkhu’l-Ekber) Herkesin belli bir eceli vardır. Bu ecel hiç değiş-mez. Onun için hastalıkta sıkılmamalı, telâşa düşmemelidir. Böyle derd ve belâlar gelince, Al-lahü teâlâya sığınmalı, âfiyet vermesi, kurtar-ması için duâ etmelidir. (Mektûbât-ı İmâm-ı Rabbânî) Ecel geldi cihâne, Baş ağrısı bahâne. (Atasözü)","osmanli":"اجل"},{"kelime":"Ecel-i Kazâ","anlam":"Kazâ-i muallak, kat’i olmayıp uzaması bir sebebe, şarta bağlı kılınan ecel.","kategori":"fikih","misal":"Bir kimseye takdir edilen belâ, kazâ-i muallak ise, yani o kimsenin duâ etmesi de takdîr edilmiş ise, duâ eder, kabul olunca belâyı önler. Ecel-i kazâyı da iyilik etmek geciktirir. Ecel-i kazâ meselâ; eğer iyi iş yapar, yâhud sadaka verir, haccederse, ömrü altmış sene, bunları yapmazsa kırk sene diye takdir edilmesi gibidir. Birinin üç gün ömrü kalmış iken akrabâsını, Allah rızâsı için ziyaret etmesi ile ömrü otuz s…","osmanli":"قضاء اجل"},{"kelime":"Ecel-i Müsemmâ","anlam":"Allahü teâlânın bir kimse için ezelde takdir ve tayin buyurduğu, hiç bir şekilde değişmeyen ecel.","kategori":"akaid","misal":"Vebâ olan yerden kaçmayan ve ölmeyen kimse de, gâzîler, mücâhidler ve belâlara sebredenler gibidir. Herkesin azalmayan ve çoğalmayan bir ecel-i müsemmâsı vardır. Kaçıp da kurtulanlar ecel-i müsemmâları gelmediği için ölmemiştir. Yoksa kaçmak onları ölümden kurtarmış değildir. Kaçmayıp, sabredip ölenler de ecelleri geldiği için ölmüşlerdir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مسمى اجل"},{"kelime":"ECÎR","anlam":"Ücretli, ücretle tutulan kişi, işçi.","kategori":"dil","osmanli":"اجير"},{"kelime":"Ecîr-i Hâs","anlam":"Belli zamanda, belli işi yapmak için husûsî tutulan işçi.","kategori":"dil","osmanli":"خاص اجير"},{"kelime":"Ecîr-i Müşterek","anlam":"Terzi, hammal, saatçi gibi herkese çalışan serbest işçi.","kategori":"dil","osmanli":"مشترك اجير"},{"kelime":"ECNEBÎ","anlam":"1.Yabancı. 2.Emân, izin ile İslâm memleketine gelmiş harbî, müstemen. 1.İyilik, mükâfât, ücret, kar- şılık. 2.Allahü teâlânın râzı olduğu, beğendiği işleri yapanlara verdiği sevab.","kategori":"dil","misal":"ECR (Ecir): اجر (A) Biliniz ki, mallarınız ve çocuklarınız sizi imtihân etmek için verildi. Allahü teâlâ iyi-liklerinize karşılık, size çok büyük ecir ve-recektir. (Tegâbün sûresi: 15)","osmanli":"اجنبى"},{"kelime":"Ecr-i Misl","anlam":"Ücret konuşulmadan yapılan veya fâsid olan icâre akdinde âdil iki ehl-i vukûfun (bilirkişinin) takdir ettikleri ücret.","kategori":"fikih","misal":"Alacaklısına, evini verip ücretsiz otur demek, fâsiddir. Ecr-i misl lâzım olur. Alacaklısına evini rehn verip, ücretsiz oturmasına izin verse, ücret lâzım olmaz. Alacaklıya rehni kirâya verirse, rehn fâsid olur. Alacaklının rehnden istifâde etmesi tahrîmen mekrûhtur. Bir kadın, oğlunu evinde, tamir etmek şartı ile oturtsa, senelerce oturup, tamir etmeden çıksa, anasına ecr-i misl ödemesi lâzım olur. (elUkû-dü’d-Dürr…","osmanli":"مثل اجر"},{"kelime":"ECSÂD","anlam":"Bedenler, vücudlar. Cesed’in çokluk hâli, cesedler.","kategori":"dil","misal":"Cin tâifesi ecsâd ile mütecessid olup (cesedler ile cesedlenip), acâib işler vuku’a getirirler ki, tenâsüh değildir. (Mektûbât-ı İmâm-ı Rabbânî) Kabristâna girince, “Allahümme Rabbel-ecsâ-di’l-bâliyeh ve’l-ızâmin-nahiret-illetî harecet mined-dünya ve hiye bike mü’minetün. Edhil aleyhâ ravhan min ındike ve selâmen minnî” okursa, meyyitlerin sayısı kadar sevab verilir. (Risâle-i Etfâli’l-Müslimîn)","osmanli":"اجساد"},{"kelime":"ECZÂ","anlam":"Cüzler, parçalar, kısımlar. Cüz’ün çokluk hâli.","kategori":"dil","osmanli":"اجزا"},{"kelime":"EDÂ","anlam":"Yerine getirme; ödeme; bir borcu veya ibâdeti zamanında yapma.","kategori":"muamelat","misal":"Allahü teâlânın sana farz kıldıklarını edâ et ki, insanların en âbidi olasın. Allahü teâlânın haram kıldığı şeylerden sakın ki, insanların en zâhidi olasın. Allahü teâlânın verdiği rızka râzı ol ki, insanların en zengini olasın. (Hadîs-i şerîfİbni Adiyy) Edâ niyeti ile kılınan bir namaz, vakti girmeden kılınmış ise, nâfile olur. Vakti çıktıktan sonra kılınmış ise, kazâ olur. “Bugünün öğle namazını edâ etmeye” diye n…","osmanli":"اداء","alternatif":["eda"]},{"kelime":"Edâ Şartları","anlam":"Bir işin, ibadetin sahih ve muteber olması için lâzım olan şartlar.","kategori":"fikih","misal":"Cum‘a namazının edâ şartları yedidir: 1) Namazı şehirde kılmak. 2) Hükûmet reisi veya vâlinin izni ile kılmak. 3) Öğle namazının vaktinde kılmak. 4) Vakit içinde hutbe okumak. 5) Hutbeyi namazdan önce okumak. 6) Cum‘a namazını cemâatle kılmak. 7) Câminin herkese açık olmasıdır. (İbni Âbidîn)","osmanli":"شرطلرى ادا","alternatif":["eda"]},{"kelime":"EDEB","anlam":"1.Güzel huy, iyi hâl ve davranış.","kategori":"tasavvuf","misal":"Bana Rabbim edeb ve terbiye öğretti. (Hadîs-i şerîfMüslim, Tirmizî) İlmî münazaralarda tarafların riayet etmesi gereken husus (ilm-i edeb). İslâmiyet’in bir amel yapılırken şart koşmadığı, fakat güzel saydığı hareket. Meselâ abdestin, namazın, yemeiçmenin, giyinmenin edebi. Edeb fıkıhta bazen sünnet-i gayrı müekkede, bazen müstehab ve mendub, bazen fazilet hükmündedir. Bu sebeble meselâ abdestin, namazın farzları ve…","osmanli":"ادب"},{"kelime":"EDÎB","anlam":"Edebli, güzel hasletleri kendinde toplayan, haddini bilen; düzgün, güzel söz söyleyen ve yazan, edebiyatçı.","kategori":"tasavvuf","osmanli":"اديب"},{"kelime":"EDİLLE","anlam":"Deliller, burhanlar, vesika-lar, belgeler.","kategori":"dil","osmanli":"ادله"},{"kelime":"Edille-i Şer‘iyye","anlam":"“Şer’î deliller” mânâsına din bilgilerinin elde edilmesine esas olan ve bunlara bağlı bulunan kaynaklar. Edille-i şer’iyye dörttür: Kitap (Kur’ân-ı kerîm), sünnet (Peygamber efendimizin söz, fiil ve tak-rirleri, yani bir iş yapılırken görüp de mâni ol-madıkları şeyler), icmâ‘ (müctehid âlimlerin dinî bir işin hükmünde söz birliği etmeleri), kıyas (hükmü bilinmeyen bir şeyi hükmü bili-nene benzeterek anlamak). (Mir’at)","kategori":"akaid","misal":"Edille-i şer’iyyenin dört olması müctehidler için-dir. Mukallidler yani dört mezhebten birinde olanlar için delil, sened, bulunduğu mezheb re-isinin ictihadı ve sözüdür. (Mecâmî’)","osmanli":"شرعيه ادلۀ"},{"kelime":"EDNÂ","anlam":"1.Pek aşağı, en bayağı, çok alçak. 2.Az, pek az.","kategori":"dil","misal":"(A. Denî’den) Fâsık olsa bile bir Müslümanın kâfire verdiği emânın bütün Müslümanların üzerine mute-ber olmasının delili, Peygamberimizin; “Müs-lümanların kanları, kısas ve diyette müsâvî-dir. Bütün Müslümanlar düşmana karşı bir el gibidir. Birbirine yardımcı olmaları vâcib-dir. Zimmet akdinde ednâsı da muteberdir” hadîs-i şerîfidir. Bu hadîs-i şerîfteki “ednâ” lafzı ile eğer; “Ve lâ ednâ zâlike ve lâ ekser” (Mü-cadele sûresi: 7) nazm-ı kerîminde vâki olduğu gibi çoğun mukabili olan en az mânâsına alı-nırsa, bir kişinin emânının sahih olduğuna de-lildir. Ve eğer; “Fekâne kâbe kavseyni ev ednâ” (Necm sûresi: 9) kavl-i şerîfinde olduğu gibi yakınlık mânâsına olan dünüvv’den alınmışsa denâet (âdilik) vasfı, Müslümanlardan ancak fâsıka nisbet olunmak lâyık olduğu için, fâsıkın emânının sahih olduğuna delildir. (İbni Âbidîn)","osmanli":"ادنى"},{"kelime":"Ef‘âl-i İlâhiyye","anlam":"Allahü teâlânın işleri.","kategori":"akaid","misal":"ef ‘âl-i ilâhiyye, sebebler ile meydana gelir. Âdet-i ilâhiyye (Allahü teâlânın kânunu) böyledir. Fakat bazen bir işin meydana gelmesinde lâzım olan sebebler bulunduğu hâlde, o iş meydana gelmeyebilir. Yahud sebebsiz de hâsıl olabilir. (Riyâdü’n-Nâsihîn)","osmanli":"الهيه افعال"},{"kelime":"Ef‘âl-i Mükellefîn","anlam":"“Mükelleflerin işleri”mânâsına kulun, dinen yerine getirmekle mükellef olduğu ameller.","kategori":"fikih","misal":"Ef ‘âl-i mükellefîn sekizdir: Farz, vâcib, sünnet, müstehab, mubâh, harâm, mekrûh, müfsid. Bunları fıkıh ilmi öğretir. (İbni Âbidîn) İki cihân (dünya ve âhiret) saadetine kavuşmak, ancak ve yalnız, dünya ve âhiretin efendisi olan Muhammed aleyhisselâma tâbi olmaya (uymaya) bağlıdır. O’na tâbi olmak için îmân etmek ve ef ‘âl-i mükellefîni öğrenmek ve yapmak lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مكلفين افعال"},{"kelime":"EFDAL","anlam":"Daha faziletli, en faziletli, daha iyi.","kategori":"dil","misal":"Veren el, alan elden efdaldir. (Hadîs-i şerîf-Müs-nedü Ahmed) Her Müslümanın Cum‘a günleri, Cum‘a na-mazından önce veya sonra başını tıraş etmesi ve tırnaklarını kesmesi sünnettir. Namazdan sonra kesilmesi efdaldir. (İbni Âbidîn)","osmanli":"افضل"},{"kelime":"EFGÂN","anlam":"1.Figân, ıztırap ile haykırma, bağırıp çağırma; inleme, bağrışma. 2.Afganistan.","kategori":"dil","misal":"EFHÂM: افهام (A) İdrakler, anlamalar, zihinler. Fehm’in çokluk hâli. Vücûd-i hâricî, bizim efhâmımızın ötesidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"افغان"},{"kelime":"EFKÂR","anlam":"Fikirler, düşünceler.","kategori":"dil","misal":"Tekmîl-i sınâat telâhuk-ı efkâr iledir. [Sanatla-rın temâmlanması, fikrlerin birbirine eklenmesi iledir.] (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"افكار"},{"kelime":"EFLÂK","anlam":"Felekler, gökler; zamanlar; bahtlar, talihler, kaderler.","kategori":"akaid","osmanli":"افلاك"},{"kelime":"EFRENCÎ","anlam":"Frenklere, Avrupalılara mahsus, Frenkçe.","kategori":"dil","osmanli":"افرنجى"},{"kelime":"Efsânevî","anlam":"1.Büyük, meşhur. 2.Tarihî vesikalarda geçmemekle beraber, tanınan ve anlatılan hâdise ve şahıs.","kategori":"hadis","osmanli":"افسانوى"},{"kelime":"EFSûN","anlam":"1.Füsunlar, büyüler. 2.Bir şey elde etmek için kullanılan, fen yolu ile tec-rübe edilmemiş maddeler ve Kur’ân-ı kerîm-den olmayan, mânâsız yazılar.","kategori":"dil","osmanli":"افسون"},{"kelime":"EGOİST","anlam":"Kendi menfaatini dü-şünen bencil, hodbîn, enâniyet sahibi. (Bkz. Enâniyyet)","kategori":"dil","osmanli":"اغوئيست"},{"kelime":"EHÂDÎS","anlam":"1.Hadîsler, sözler. 2.Hazret-i Peygamber aleyhisselâmın hadîs-i şerîfleri.","kategori":"hadis","misal":"(Bkz. Hadîs)","osmanli":"احاديث"},{"kelime":"EHL (Ehil)","anlam":"1.Aile, topluluk, cemâ’at. 2.Bir şeyi yapanlar, elinde bulunduranlar. 3.Mahâretli, becerikli, usta, yetkili, ehil. 4.Karı kocadan her biri. 5.Bir yerin ahâlisi, halkı.","kategori":"dil","osmanli":"اهل"},{"kelime":"EHL-İ BEDR","anlam":"Bedir muharebe-","kategori":"dil","misal":"sinde bulunan ve sahih rivâyette sayıları 313 olan sahâbîler. Allahü teâlâ, Bedr Gazâsı’nda bulunanlara “İstediğinizi yapın! Sizin her işinizi afv eyledim” buyurdu. (Hadîs-i şerîfHâkim)","osmanli":"بدر اهل"},{"kelime":"EHL-İ BEYT","anlam":"1.Ev halkı. 2.Hazret-i Peygamber aleyhisselâmın bütün âile fertleri; zevceleri, çocukları, damat ve torunları ile kıyâmete kadar gelecek nesilleri. Ey Resûlullah’ın ehl-i beyti! Allahü teâlâ, sizden ricsi (her türlü kusur ve kirleri) gidermek ve sizi tam bir temizlikle temizlemek istiyor. (Ahzâb sûresi: 33) Ehl-i beytim, Nûh (aleyhisselâmın) gemisi gibidir. Binen kurtulur, binmeyen boğulur. (Hadîs-i şerîfHâkim) Zâhir ve bâtın ilimlerinde yani kalb ilimlerinde büyük âlim olan babam, h…","kategori":"muamelat","osmanli":"بيت اهل"},{"kelime":"EHL-İ BİD‘AT","anlam":"Bid‘at sahipleri. Resûlullah aleyhisselâm ile eshâbının bildirdiği ve üzerinde icmâ bulunan i’tikâddan ayrılanlar.","kategori":"dil","misal":"(Bkz. Bid‘at)","osmanli":"بدعت اهل"},{"kelime":"EHL-İ İSLÂM","anlam":"Müslümanlar. Peygamber efendimizin bildirdiklerinin hepsini beğenen, kalbiyle inanıp, diliyle söyleyen.","kategori":"akaid","misal":"(Bkz. Müslüman)","osmanli":"اسلام اهل"},{"kelime":"EHL-İ KIBLE","anlam":"Kâbe’yi kıble edinenler, itikat ve amelinde küfre düşmemiş dalâlet (bid‘at) fırkalarında olanlar.","kategori":"ibadet","misal":"Cehennem’e girecekleri bildirilmiş olan yetmişiki bid‘at fırkası, ehl-i kıble oldukları için bunların hiçbirine kâfir dememelidir. Fakat bunların, dinde inanılması zarûrî, lâzım olan şeylere inanmayanları ve şeriattan her Müslümanın işittiği, bildiği şeyleri te’vîlini bilmeden red edenleri kâfir olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قبله اهل"},{"kelime":"EHL-İ KİTÂB","anlam":"“Kitap sahipleri” mânâsına Yahudiler ve Hristiyanlar gibi semavî bir kitaba inananlar.","kategori":"dil","misal":"Ey Habîbim! Ehl-i kitâb olan Yahudi ve Hristiyanlara söyle: Semâvî kitaplar ve Resûllerde ihtilâf olmayıp, bizimle sizin aranızda beraber olan kelimeye gelin. Şöyle ki: “Allahü teâlâdan başkasına ibâdet etmeyelim ve hiçbir şeyi O’na şerik, ortak koşmayalım, Allah’ı bırakıp da içimizden hiç kimseyi Rab’lar edinmeyelim” deyiniz. Eğer ehl-i kitâb bu kelimeden yüz çevirirlerse (o hâlde) şöyle deyin: “Şâhid olun, biz ger…","osmanli":"كتاب اهل"},{"kelime":"EHL-İ KuBûR","anlam":"Kabir ehli. Kabirdekiler, ölüler.","kategori":"akaid","misal":"Dünyada garip veya yolcu gibi ol! Kendini ehl-i kuburdan say! (Hadîs-i şerîfBuhârî, Tirmizî, İbn-i Mâce, Müsnedü İmâm-ı Ahmed) Ne kendi etdi rahat ne âleme verdi huzur, Yıkıldı gitti cihândan dayansın ehl-i kubûr. (Lâ edrî)","osmanli":"قبور اهل"},{"kelime":"EHL-İ SÜNNET","anlam":"“Sünnet bağlıları” mânâsına itikat ve amelde Peygamber aleyhisselâm ve Eshâbının yolunda bulunan Müslümanlar, sünnîler.","kategori":"hadis","misal":"Resûlullah efendimiz, ümmetinin başına gelecekleri bildirirken; “Benî İsrâil yetmiş iki kısma ayrıldı. Ümmetim de yetmiş üç fırkaya ayrılacaktır. Bunlardan yalnız biri kurtulacak, diğerlerinin hepsi Cehennem’e gidecektir.” Eshâb-ı kirâm bunu işitince; “O hangisidir yâ Resûlallah!” dediler. “Benim ve Eshâbımın yolunda olanlardır” buyurdu. İslâm âlimleri, bu hadîs-i şerîfte bildirilen tek kurtuluş fırkasının Ehl-i sün…","osmanli":"سنت اهل"},{"kelime":"EHL-İ SÜNNET VE CEMAAT","anlam":"","kategori":"hadis","misal":"(A) “Sünnet ve cemaat bağlıları” mânâsına itikat ve amelde Resûlullah aleyhisselâmın ve onun cemaatinin, yani Sahâbe-i kirâmın yolunda bulunan Müslümanlar, sünnîler. Eh-lü’s-Sünneti ve’l-Cemâ‘a.","osmanli":"وجماعة سنت اهل"},{"kelime":"EHL-İ TARÎK","anlam":"Tarikat ehli. Tasavvuf yollarından (tarikatlardan) birine girmiş olan.","kategori":"tasavvuf","osmanli":"طريق اهل"},{"kelime":"EHL-İ VuKûF","anlam":"“Bilgi sahibi” mânâsına bir mesele hakkında ihtisas ve ma-lumat sahibi olan. Ehlihibre. Bilirkişi. Eksper. (Malın ayıplı çıkması hâlinde) Noksan-ı semen (değerinin düşüklüğü) bî-garaz ehl-i vukûfun ihbarıyla mâlum olur. (Mecelle, m. 346)","kategori":"dil","misal":"Bir sanat sahibine bir şey târif ederek iş yaptır-mak olan istisnâ (ısmarlama) sözleşmesi yapı-lırken, fiyatın tâyin (belli) edilmesi şart değil-dir. Tâyin edilmiş ise, sanat sahibinin sonradan fazla para istemesi câiz ise de, müşteri bunu ka-bul etmediği takdirde, ehl-i vukûfun tesbit ede-ceği piyasa değerinde anlaşmaları lâzım olur. (Bahrü’r-Râık) Vâsi, velî, yetimin malını başka birine kirâya verdikten sonra bir kimse çıkıp, bu kirâ sözleş-mesinin gaben-i fâhiş (çok aldanma) ile vukû bulduğunu iddiâ etse, bu gibi sırf iddiâ ile kirâ-lamanın sahîh olmadığına (geçersizliğine) hük-medilemez. Ancak ehl-i vukûfa başvurulur. Ehl-i vukûf, gaben-i fâhiş olduğunu söylerse, hâkim sözleşmeyi fesheder. (Dürerü’l-Hükkâm)","osmanli":"وقوف اهل"},{"kelime":"EHL-İ ZİMMET","anlam":"İslâm ülkesinde yaşayan ve zimmet antlaşması ile can, mal, ırz ve din emniyeti Müslümanların zimmetinde olan gayrımüslim vatandaşlar.","kategori":"muamelat","misal":"Ehl-i zimmete zulmetmek, Müslümana zulmetmekten daha fenâdır. Hayvana zulüm, işkence etmek ise, ehl-i zimmete zulmetmekten daha fenâdır. (İbni Âbidîn)","osmanli":"ذمت اهل"},{"kelime":"EHLİYET","anlam":"Salâhiyet. Yetki sahibi. Ki-şinin dinî emir ve yasaklarla muhatab, leh ve aleyhinde hak ve muamelelere yetkili olması.","kategori":"dil","osmanli":"اهليت"},{"kelime":"EHLuLLAH","anlam":"Allah adamları. Allahü teâlânın emirlerine uyup, O’nun sevgisini ve ism-i şerîfini gönlünden hiç çıkarmayan velî zâtlar.","kategori":"akaid","misal":"Ehlullah ile sohbete devam, âhireti düşünüp ona hazırlanma arzusunu artırır, günahlardan sakınmaya sebeb olur. (Şâh-ı Nakşibend)","osmanli":"الله اهل"},{"kelime":"EHRÂM","anlam":"1.Huni, piramit. 2.Mısır’da eski zamanlardan kalma huni şeklindeki bü-yük mezarlar.","kategori":"dil","misal":"Herem’in çokluk hâli.","osmanli":"اهرام"},{"kelime":"EİMME","anlam":"İmâmlar, devlet reisleri, liderler, önderler, rehberler.","kategori":"ibadet","misal":"Eğer antlaşmalarından sonra, yeminlerini bozarlar, dininize dil uzatırlarsa, inkârda önde gidenler (eimmetü’l-küfr) ile savaşın. (Tevbe sûresi: 12) O gün, her fırkayı (reis yaptıkları, kendilerini hayra veya şerre sürükleyen) imâmları ile çağırırız! (İsrâ sûresi: 71)","osmanli":"ائمه"},{"kelime":"EJDER","anlam":"Büyük yılan, korkunç ve hayalî bir hayvan.","kategori":"tasavvuf","osmanli":"اﮊدر"},{"kelime":"EKBER","anlam":"(A. Kebîr’den) Daha (en, pek) büyük.","kategori":"dil","osmanli":"اكبر"},{"kelime":"EKBER-İ KEBÂİR","anlam":"Kebîrelerin en büyüğü. En büyük günahlar.","kategori":"dil","misal":"Ekber-i kebâir; bir şeyi Allahü teâlâya or-tak etmek, adam öldürmek, anaya, babaya karşı gelmek, yalancı şâhidlik yapmaktır. (Hadîs-i şerîf-Buhârî)","osmanli":"كبائر اكبر"},{"kelime":"EKL","anlam":"Bir şey yeme, yenilme.","kategori":"dil","misal":"Duânın kabul olması için, ekl-i helâl ve sıdk-ı makâl ve ihlâs ile yapmak şarttır. (Makâmât-ı Mazhariyye)","osmanli":"اكل"},{"kelime":"EKMEL","anlam":"Daha kâmil, en kâmil, mükem-mel, kusursuz, en uygun, en eksiksiz.","kategori":"dil","osmanli":"اكمل"},{"kelime":"EKREM","anlam":"1.Daha şerefli, en şerefli, pek cömert. 2.Hazret-i Peygamber’in isimlerinden (elEkrem).","kategori":"akaid","osmanli":"اكرم"},{"kelime":"EKSER","anlam":"(A. Kesîr’den) Daha (en, pek) çok, çoklukla, çok olarak.","kategori":"dil","osmanli":"اكثر"},{"kelime":"EKSERÎ","anlam":"Eksere mensub, çok defa, çoğu.","kategori":"dil","osmanli":"اكثرى"},{"kelime":"ELEM","anlam":"Keder, dert, üzüntü, sıkıntı, acı. Dünya, elem ve meşakkat, âhiret ise, zevk ve lezzet yeridir. Dolayısıyla dünya ile âhiret bir-birinin zıddıdır, tersidir. Birini sevindirmek ötekinin gücenmesine sebeb olur. Yani birinde zevk aramak diğerinde elem çekmeye yol açar. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"الم"},{"kelime":"ELF","anlam":"Bin.","kategori":"dil","osmanli":"الف"},{"kelime":"ELF-İ SÂNÎ","anlam":"Hicret’i takip eden ikinci bin yıl.","kategori":"dil","osmanli":"ثانى الف"},{"kelime":"ELFÂZ","anlam":"Sözler, kelimeler. Lafz’ın çokluk hâli.","kategori":"dil","misal":"Ukûdda itibar makâsıd ve meânîyedir, elfâz ve mebânîye değildir. (Mecelle, m. 3)","osmanli":"الفاظ"},{"kelime":"ELFÂZ-I KÜFR","anlam":"Söylendiği zaman, imânı gideren, Müslümanlıktan çıkmaya sebeb olan sözler.","kategori":"akaid","misal":"(Bkz. Küfr)","osmanli":"كفر الفاظ"},{"kelime":"ELHAMDÜLİLLAH","anlam":"“Hamd Allahü teâlâya mahsustur” mânâsına gelen mübarek bir söz, hamdele.","kategori":"akaid","misal":"Elhamdülillah demek, şükürlerin başıdır. Allahü teâlâya şükretmeyen O’na hamd etmemiş (senâ etmemiş, O’nu övmemiş) olur. (Hadîs-i şerîfKünûzü’l-Hakâyık) Zikrin (Allahü teâlâyı anmanın) en üstünü, Elhamdülillah demektir. (Hadîs-i şerîfKünûzü’l-Hakâyık) Yemeğe ve içmeye başlarken Besmele (Bismillâhirrahmânirrahîm) okumalıdır. Yimekiçmek sonunda Elhamdülillah demelidir. (Şir’atü’l-İslâm)","osmanli":"الحمدلله"},{"kelime":"ELHÂN","anlam":"Nağmeler, melodiler, musiki perdeleri. Lahn’in çokluk şekli.","kategori":"dil","misal":"Kur’ân-ı kerîmi elhân ile okumak, mânâyı bo-zarsa, namazı da bozar. Kelimenin mânâ-sını değiştirmez ve harfler, iki harf kadar uza-mazsa, yalnız sesi güzelleştirip kırâeti süslerse, câiz olur. Hatta namaz içinde de, namaz dı-şında da, müstehab olur. (İbni Âbidîn)","osmanli":"الحان"},{"kelime":"ELİFBÂ","anlam":"1.Otuz üç harften ibaret olan Osmanlı alfabesi. 2.Bir şeyin başlangıcı.","kategori":"osmanli","osmanli":"الفباء"},{"kelime":"ELÎM","anlam":"Çok elemli, çok dert ve keder veren, acıklı; ağrı ve sancıyı hissettiren, sızlatan, pek ağrıtan, acıtan.","kategori":"miras","osmanli":"اليم"},{"kelime":"ELSAĞ","anlam":"Sin harfini se okuyan kimse, peltek.","kategori":"dil","misal":"Elsağ, elsağ olmayana imâm olamaz. Başka harfleri doğru okuyamayan da, doğru okuyanlara imâm olamaz. Harfleri doğru okuyan bir imâma uyarak cemâat ile kılması mümkün iken, yalnız kılarsa, harfi doğru okumadığı için namazı kabul olmaz. Doğru olarak okuduğu bir âyet varsa, bunu veya böyle bir kaç âyet-i kerîmeyi ezberlemesi ve namazlarda, bunları okuması lâzımdır. (İbni Âbidîn)","osmanli":"الصغ"},{"kelime":"ELTÂF","anlam":"İyi muameleler, iyilikler, iyi-likseverlikler; okşamalar; nezâketler. Lütf’un çokluk hâli.","kategori":"dil","osmanli":"الطاف"},{"kelime":"ELVEDÂ","anlam":"“Ayrılık geldi.” “Ah ayrılık!” “Allah’a ısmarladık” “Allah’a emânet olun!”","kategori":"akaid","misal":"mânâsına ayrılırken söylenen söz. (elVidâ‘.)","osmanli":"الوداع"},{"kelime":"ELYESA‘ (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen Benî İsrâil peygamberlerinden.","kategori":"dil","osmanli":"اليسع"},{"kelime":"EMÂN","anlam":"1.Korkusuzluk, emniyet. 2.Bir kimseye veya düşmana, söz, işaret veya yazı ile, mal ve canının emniyet altında oldu-ğunu bildirme.","kategori":"hadis","misal":"Hangi kavim ki, içlerinde sabah ezanı oku-nursa, o ezan onlar için akşama kadar, Al-lah’ın azâbından emân olur. İçlerinde ak-şam ezanı okunan kavme de, o ezan, ertesi günü sabahına kadar Allah’ın azâbından emân olur. (Hadîs-i şerîf-Taberânî) İyi biliniz ki, her kim emân verilen bir kim-seye, zulmeder veya ahdini bozar veya onun gücünün yetmeyeceği şeyi kendisine yük-ler veya gönül hoşluğu ile vermeyeceği bir şeyi ondan alırsa, kıyâmette ben o kimsenin hasmı olurum. (Hadîs-i şerîf-Ebû Dâvûd) İl-ticâ edenlere emân vermekte bütün Müslü-manlar eşittir. Halktan herhangi biri de bu hakka sahiptir. O hâlde kim bir Müslüma-nın ahdini (verdiği sözü) bozarsa, ona ihâ-net ederse, Allah’ın, meleklerin ve bütün in-sanların lâneti onun üzerine olsun. Kıyâmet gününde Allah onun ne farz, ne nâfile ibâ-detlerini, ne de tövbesini kabul eder. (Ha-dîs-i şerîf-et-Tergîb ve’t-Terhîb) Müslümanlardan aldığı emân ile, dârülislâma gelen gayrı müslim ecnebi, burada yaşamakta olan zımmî (gayrımüslim vatandaş) gibi kor-kusuz yaşar. Onun haklarına sahip olur. Buna müstemen denir. (Usûl-i Serahsî)","osmanli":"امان"},{"kelime":"EMÂNET","anlam":"1.Emîn, güvenilir olmak. 2.Bir kimseye, saklanmak ve istendiğinde geri vermek üzere verilen mal, vedîa.","kategori":"muamelat","misal":"Emânetlerine ve verdikleri söze riâyet edenler, namazlarına devam edenler, işte onlar Firdevs Cennet’ine vâris olacaklar ve orada ebedî kalacaklardır. (Mü’minûn sûresi: 8) Münâfıkın üç alâmeti vardır: Yalan söyler, emânete hıyânet eder ve sözünde durmaz. (Hadîs-i şerîfİbni Neccâr) Peygamberlerin sahip olduğu sıfatlardan birisi de emânetti…","osmanli":"امانت"},{"kelime":"EME","anlam":"Câriye, kadın köle.","kategori":"osmanli","osmanli":"امه"},{"kelime":"EMEL","anlam":"1.Arzu. 2.Ümid. 3.Hırs, tamah.","kategori":"dil","osmanli":"امل"},{"kelime":"EMÎN","anlam":"1.Kendisine güvenilen. 2.Resûlullah aleyhisselâmın lakabı (el-Emîn). 3.Osmanlılarda bilhassa mâlî yönü ağır ba-san bazı devlet hizmetlerini yürütmek üzere tayin edilen memur, şehremîni (belediye re-isi), rüsûmat emîni (vergi dairesi reisi), sandık emîni, alay emîni, tuzla emîni, binâ emîni gibi.","kategori":"hadis","misal":"(Şuayb’ın) iki kızından biri: “Babacığım! Onu (Mûsâ aleyhisselâmı) ücretle tut. Çünki bu güçlü ve emin bir kimsedir” dedi. (Ka-sas sûresi: 26) Size hayırlınızın kim, şerlini-zin kim olduğunu haber vereyim mi? Ha-yırlınız hayrı umulan, şerrinden de emin olunandır. Şerliniz ise hayrı umulmayan, kötülüğünden de emin olunmayan kimse-dir. (Hadîs-i şerîf-Tirmizî) Kirâcı, işçi, vekil gibi kimseler emindir. Elle-rindeki mal, kendi kusurları olmaksızın telef olursa ödemez. (İbni Âbidîn) Kendisine Peygamberliği bildirilmeden önce de, Kureyş kabilesi içinde çok güvenilir, inanı-lır bir zât olduğundan “Muhammedü’l-Emîn” diye anılırdı. Allahü teâlâya yemîn ederim ki, muhak-kak ben gökte de emînim, yerde de. (Ha-dîs-i şerîf-İhyâ)","osmanli":"امين"},{"kelime":"EMÎR","anlam":"1.Emreden; bir kavmin, bir topluluğun başı; devlet reisi, vâli, kumandan. 2.Hazret-i Ali’nin lakabı.","kategori":"osmanli","misal":"Bana itaat eden Allah’a itaat etmiş, bana isyan eden de Allah’a isyan etmiş olur. Emîre itaat eden bana itaat etmiş, emîre isyan eden de bana isyan etmiş demektir. (Hadîs-i şerîfBuhârî) Üç kişi sefere çıktığı zaman, aralarından birini emîr seçsinler. (Hadîs-i şerîfİbn-i Mâce) Hazret-i Emîr’in ismi, Cennet kapısının üstünde yazılıdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"امير"},{"kelime":"EMLÂK","anlam":"Mülkler.","kategori":"muamelat","osmanli":"املاك"},{"kelime":"EMMÂRE","anlam":"Emredici.","kategori":"dil","osmanli":"اماره"},{"kelime":"EMR","anlam":"1.Buyruk; emredenin, emrolunan-dan bir işin yapılmasını istemesi veya bu su-retle yapılması istenen şey. 2.İş.","kategori":"dil","misal":"O hâlde bana uyunuz. Emrime itâat ediniz. (Tâhâ sûresi: 90) Emre uymak, edebi gözetmekten önce gelir. (Mekâtib-i Şerife) Size söylediklerimi yakında hatırlayacaksı-nız. Ben emrimi Allahü teâlâya ısmarlıyo-rum. Çünki Allah kullarını çok iyi gören-dir. (Mü’min sûresi: 44) Bütün emrler Allah’a döndürülür. (Bakara sûresi: 210)","osmanli":"امر"},{"kelime":"Emr-i Şerîf","anlam":"“Şerefli emir” mânâsına umumiyetle padişah emri için kullanılan tabir. Emr-i Teklîfî: تكليفى امر (A) Allahü teâlânın in-","kategori":"akaid","misal":"sanlara yapmaları veya sakınmaları için ver- diği emirler, emr-i teşrîî. Allahü teâlânın emr-i teklîfîleri, ehemmiyetle-rine göre, derecelere ayrılmıştır: 1) Bütün in-sanlara, îmân etmelerini, Müslüman olmala-rını emretmiştir. 2) Îmân etmiş olanlara, harâm işlememelerini, kötülük yapmamalarını emret-miştir. 3) Îmân etmiş olanlara farzları yapma-larını emretmiştir. 4) Haramlardan sakınan ve farzları yapan Müslümanlara, mekrûhlardan sakınmağı, sünnetleri, nâfile ibâdetleri yapmağı emretmiştir. (Rûhü’l-Beyân)","osmanli":"شريف امر"},{"kelime":"EMRED","anlam":"Bâliğ olmamış, sakalı çıkma-mış, parlak genç.","kategori":"dil","misal":"Emred’in imâm olması, âlim olsa bile mekrûh-tur. Çünki fitneye sebeb olur. (İbni Âbidîn)","osmanli":"امرد"},{"kelime":"EMVÂL","anlam":"Mallar.","kategori":"dil","osmanli":"اموال"},{"kelime":"Emvâl-i Bâtına","anlam":"Görülmeyen, açıkta olmayan mallar; altın, gümüş ve ticâret eşyası cinsinden olan zekât malları.","kategori":"ibadet","misal":"(Bkz. Zekât) Hazret-i Osman’ın hilâfeti zamanına kadar, emvâl-i bâtınanın zekâtını da devlet topluyordu. Hazret-i Osman halîfe olunca, emvâl-i bâtınanın zekâtını vermek herkesin kendisine bırakıldı. Emvâl-i bâtınanın mikdarını sahibine sormak câiz değildir. Bunların zekâtını mal sahibi, yedi sınıftan dilediğine, kendi verir. Böyle verilmiş olan zekâtları, hükûmet ayrıca isteyemez. Bir şehirdeki zenginlerin hiç zekât…","osmanli":"باطنه اموال"},{"kelime":"Emvâl-i Zâhire","anlam":"Açık mallar; zekât hayvanları ve topraktan elde edilen mahsûl gibi saklanması mümkün olmayan mallar.","kategori":"ibadet","misal":"Emvâl-i zâhirenin zekâtını fakîrlere dağıtmak, bunların sahiplerine bırakılmamıştır. Bu işleri Müslümanların devlet reisi tarafından vazifelendirilen ve âmil denilen zekât me’mûru yapar. Böyle bir memur yoksa, herkes kendisi verir. (İbni Âbidîn)","osmanli":"ظاهره اموال"},{"kelime":"EMVÂT","anlam":"Ölüler. Meyyitin çokluk hâli.","kategori":"dil","osmanli":"اموات"},{"kelime":"EN‘ÂM SûRESİ","anlam":"Kur’ân-ı kerîmin altıncı sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Yüz altmış beş âyet-i kerîmedir. En’âm, deve, koyun ve sığır gibi hayvanlara denir. Allahü teâlâ bunları ve daha nice hayvanı insanların faydalanması için yarattığı hâlde, inanmayanların âciz varlıklar olan bir kısım hayvanlara tapınmalarından bahsedildiği için sûre bu ismi almıştır. En’âm sûresinde; İslâm dininin îmân esasları, dünya hayâtının fânî, oyun ve eğlenceden ibâret olduğu, âhiretin da…","osmanli":"سى سوره انعام"},{"kelime":"ENÂM","anlam":"Bütün mahlûklar, yaratılmış olan canlılar; halk, insanlar.","kategori":"dil","osmanli":"انام"},{"kelime":"ENBİYÂ","anlam":"Peygamberler. Nebî’nin çokluk hâli.","kategori":"akaid","osmanli":"انبياء"},{"kelime":"ENBİYÂ SûRESİ","anlam":"Kur’ân-ı kerîmin yirmi birinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Yüz on iki âyet-i kerîmedir. Sûre, Hazret-i İbrâhim, İshâk, Lût, Süleymân, Dâvûd, Eyyûb, Yûnus ve Zekeriyyâ aleyhimüsselâm’ın kavimlerini îmâna da’vet etmeleriyle alâkalı husûslardan bahsettiği için bu adı almıştır. Enbiyâ sûresinde ayrıca, Allahü teâlânın birliği, öldükten sonra dirilme ve âhiret hayâtına dâir hükümler anlatılır. (Beydâvî, Kurtubî)","osmanli":"سى سوره انبيا"},{"kelime":"ENCÜMEN","anlam":"Cemiyet, meclis, heyet, şûra, komisyon, takım.","kategori":"dil","osmanli":"انجمن"},{"kelime":"ENDAHT","anlam":"Atma, atış; atılma; silah atma.","kategori":"dil","osmanli":"انداخت"},{"kelime":"ENDÂM","anlam":"Vücut, beden; boy bos; cisim. ENDÂZE: اندازه (F) İpekli gibi kıymetli kumaşların ölçüldüğü 65 cm. uzunluğunda eski bir ölçü.","kategori":"dil","osmanli":"اندام"},{"kelime":"ENDERûN","anlam":"1.İç, dâhil. 2.Topkapı Sa-rayı’nın üçüncü avlusunda yer alan, padişahın çalışma ofislerinin, hazine dairesinin, mukad-des emânetlerin ve devlet adamı yetiştiren en-derûn mektebinin [bugün ayrıca saray ida-rehânesinin] bulunduğu iç kısım.","kategori":"dil","osmanli":"اندرون"},{"kelime":"ENE","anlam":"1.Ben, birinci müfred zamir. 2.İd-dia, kibir, egoizm, benlik.","kategori":"dil","osmanli":"انا"},{"kelime":"ENE’L-HAK","anlam":"“Ben Hakkım!” mânâsına vahdet-i vücûdu formüle eden ve mutasavvıf Hallâc-ı Mansûr’un idamına sebeb olan meşhur söz.","kategori":"fikih","misal":"Hallâc-ı Mansûr’un “Ene’l-Hak” sözü ve buna benzerleri bu zâtların içerisinde bulundukları makamda, kendi âlemlerinde, Allahü teâlâdan başka hiçbir şey göremeyince söyledikleri sözlerdir. Allahü teâlâ mahlûkları ile birleşik değildir. Onların aynı ve benzeri değildir. O, hiç bir bakımdan yarattıklarına benzemez. Hallâc-ı Mansûr, “Ene’l-Hak” demekle; “Ben Hakk’ım, Hak teâlâ ile birleştim” demek istemedi. Böyle diyen…","osmanli":"الحق انا"},{"kelime":"ENFÂL","anlam":"1.Ganimetler. 2.Emîrin, kumandanın, harbe teşvik için “herkesin elde ettiği kendisinindir” diyerek gâzilere ganimet hisselerinden fazla olarak verdiği mallar. Nefl’in çokluk hâlidir.","kategori":"miras","osmanli":"انفال"},{"kelime":"ENFÂL SûRESİ","anlam":"Kur’ân-ı kerîmin sekizinci sûresi.","kategori":"dil","misal":"Medîne-i Münevvere’de Bedr Muhârebesi’n-den sonra nâzil oldu. Yetmiş beş âyet-i kerîmedir. Sûre, ismini, birinci âyette geçen ve ganimetler mânâsına gelen Enfâl kelimesinden almıştır. Bu sûrede belli başlı konular; Bedr Harbi’nde elde edilen ganimetlerin dağıtılmasına dâir emirler, Peygamber efendimiz ve diğer peygamberlerle alâkalı bazı hususlardır. (Tefsir-i Mazharî) Kim Enfâl ve Berâe sûrelerini okursa, kıyâmet g…","osmanli":"سى سوره انفال"},{"kelime":"ENFİYE","anlam":"“Burun tozu” mânâsına keyf için buruna çekilen çürütülmüş ve içine bazı kokulu maddeler katılmış tütün tozu.","kategori":"dil","osmanli":"انفيه"},{"kelime":"ENFÜS","anlam":"1.Nefsler. 2.İnsanın iç âlemi.","kategori":"tasavvuf","misal":"Akla, hayâle gelen her şey, hatta keşf ve şühûd ile anlaşılan bilgiler ister âfâkta olsunlar, ister enfüste olsunlar, hepsi mâsivâdır. Allahü teâlânın mahlûklarıdır. Bunlara gönül bağlamak, oyun ve oyuncak gibi şeylerle boş yere vakit geçirmektir. Fâidesiz şeylerle oynamaktır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"انفس"},{"kelime":"ENFÜSÎ","anlam":"Bir şahsa mahsus fikir, gö-rüş, anlayış; iç âleme mahsus. Subjektif. Âfâkî (objektif) zıddı.","kategori":"dil","osmanli":"انفسى"},{"kelime":"ENÎS","anlam":"Ünsiyet edilen, dost, arkadaş; yar, sevgili.","kategori":"dil","osmanli":"انيس"},{"kelime":"ENKAZ","anlam":"Yıkılmış, bozulmuş bir şe-yin kalıntıları; harabe.","kategori":"dil","osmanli":"انقاض"},{"kelime":"ENSÂR","anlam":"1.Yardımcılar. 2.Mekke’den Medîne’ye hicretten sonra, Resûlullah efendimize ve Mekke’den gelen muhacir Müslümanlara yakın alâka gösterip, malları, mülkleri, bedenleri ve her şeyleri ile yardım eden Medîneli Müslümanlar. îmândandır. Onlara buğz etmek münâfıklık alâmetidir. (Hadîs-i şerîfBuhârî İbni Şeybe, İbnü’n-Neccar)","kategori":"dil","osmanli":"انصار"},{"kelime":"ENTAK","anlam":"Daha (pek, en) iyi nutk (söz) söyleyen, daha iyi anlatan, en iyi söyleyen. Lisân-ı hâl, lisân-ı kalden entaktır. (Atasözü)","kategori":"dil","osmanli":"انطق"},{"kelime":"ERAK","anlam":"Arabistan’da yetişen, dalların-dan, diş temizliğinde faydalanılan, bir karış uzunluğunda, misvâk denilen fırçanın yapıl-dığı ağaç. (Bkz. Misvâk)","kategori":"dil","osmanli":"اراق"},{"kelime":"ERÂZÎ (Arâzî)","anlam":"Arzlar, topraklar.","kategori":"muamelat","osmanli":"اراضى"},{"kelime":"ERBA‘ÎN","anlam":"1.Kırk; kırkıncı. 2.Karakış (22 Aralık-31 Ocak arası). 3.Tasavvufta maddî bağları azaltıp, mânevî tarafı kuvvetlendirmek ve kalb aynasını parlatmak için, az yemek, az içmek, az konuşmak ve çok ibâdet etmekle geçirilen kırk günlük riyâzet, çile. Ehl-i sünnet yolunun büyükleri, halvet yani yalnız başına kalmak ve erba‘în yerine, insanlar arasında kalbini Allah ile bulundurmak saadetine kavuşmuşlardır. Sünnetleri yaparak çok kıymetli şeyler elde etmişler ve bid‘atlerden sakınarak yüksek derecelere kavuşmuşlardır. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"tasavvuf","osmanli":"اربعين"},{"kelime":"ERBÂB","anlam":"1.Sahipler, mâlikler. 2.Ehil, muktedir, becerikli, lâyık.","kategori":"dil","misal":"Rabb’in (efendi) çokluk hâli.","osmanli":"ارباب"},{"kelime":"Erbâb-ı Dil","anlam":"Gönül sahipleri, velîler.","kategori":"tasavvuf","misal":"Hâlden anlayan, sözüsohbeti yerinde, esrarı keşfeden. Ehl-i dil. Erbâb-ı kulûb. İbnü’l-vakt. (Bkz. Erbâb-ı Kulûb)","osmanli":"دل ارباب"},{"kelime":"ERD","anlam":"1.Kahır, öfke. 2.Un.","kategori":"akaid","osmanli":"ارد"},{"kelime":"ERD","anlam":"Arz, yeryüzü.","kategori":"dil","osmanli":"ارض"},{"kelime":"ERDEN (Ürdün)","anlam":"Îsâ aleyhisselâmın Yahyâ aleyhisselâm tarafından yıkandığı ve Hristiyanların vaftiz olmak üzere suyunu mukaddes bildikleri Filistin’de bir nehir.","kategori":"dil","osmanli":"اردن"},{"kelime":"ERHÂM","anlam":"Rahmler.","kategori":"dil","misal":"Resûlullah’ın “sallallahü aleyhi ve sellem” nûru, sıfât-i ilmden olup, eslâbdan erhâma intikâl ile insan sûreti ile zuhûr eyledi. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ارحام"},{"kelime":"ERHAM","anlam":"Daha (en, çok) merhametli. ERHAMÜRRÂHİMÎN: الراحمين ارحم (A) Mer-hametlilerin en merhametlisi. Allahü teâlâ-","kategori":"akaid","misal":"nın isimlerinden. Seâdet sahibi o kimsedir ki, Azrâil aleyhisselâm gelip; “Korkma, Erhamürrâhimîne gidiyorsun. Asıl vatanına kavuşuyorsun.Büyük devlete eri-şiyorsun.” der. Böyle kimseye bundan daha şe-refli bir gün yoktur. (Abdülhakîm-i Arvâsî)","osmanli":"ارحم"},{"kelime":"ERÎS","anlam":"Medîne-i Münevvere’de suyunun tatlılığı ile meşhur ve Hazret-i Osman zamanında mühr-i nebevînin düşüp çok uğraşılmasına rağmen çıkarılamadığı kuyu.","kategori":"dil","osmanli":"اريس"},{"kelime":"ERKÂN","anlam":"Bir şeyin, işin, amelin bir par-çasını veya bütününü meydana getiren şey-ler, esaslar. Rükn’ün çokluk hâli. (Bkz. Rükn)","kategori":"dil","osmanli":"اركان"},{"kelime":"ERMENÎ","anlam":"Aziz Gregor vesilesiyle en eski devirlerde Hristiyanlığı kabul etmiş Anadolu halklarından birine mensub olup, ilk üç ekümenik konsili kabul eden monofiziyye itikadında kadîm bir Şark Kilisesi.","kategori":"dil","osmanli":"ارمنى"},{"kelime":"ERŞ","anlam":"Ölümden başka, uzuvlara karşı işlenen cinâyetlerin diyeti.","kategori":"dil","osmanli":"ارش"},{"kelime":"ERVÂH","anlam":"Ruhlar. (Bkz.","kategori":"akaid","misal":"Rûh)","osmanli":"ارواح"},{"kelime":"ERZÂK","anlam":"Yenilecek, içilecek şeyler, rı-zıklar. Rızk’ın çokluk hâli.","kategori":"dil","osmanli":"ارزاق"},{"kelime":"EŞ‘ÂRİYYE","anlam":"Ehl-i sünnetin iki büyük imâmından Ebü’l-Hasen Ali bin İsmâil Eş‘ârî’nin kelâmdaki yolu.","kategori":"hadis","osmanli":"اشعاريه"},{"kelime":"ESÂS","anlam":"Asıl, temel, dip, kök; doğruluk, gerçek. Üss’ün çokluk hâli.","kategori":"dil","osmanli":"اساس"},{"kelime":"ESBÂB","anlam":"İlahî iradenin tecellisi için kulların müracaat ettiği ve taraf-ı ilahîden yaratılan vesileler, sebebler.","kategori":"fikih","misal":"Sebeb’in çokluk hâli. Esbâba yapışmak tevekkülü bozmaz. Esbâb üçtür: Vehmî, terk edilmesi vâcib olan sebebler. Kat’î olarak bilinenler, yapılması vâcibdir. Şübheli ve zannî olanlar, yapılması zanlı ve şübhelidir. (Kimya-i Seâdet)","osmanli":"اسباب"},{"kelime":"EŞBÂH","anlam":"1.Benzeyen. 2.Fıkıhta bir me-selenin benzediği iki aslın her biri.","kategori":"dil","osmanli":"اشباه"},{"kelime":"ESED","anlam":"Arslan.","kategori":"dil","osmanli":"اسد"},{"kelime":"ESEF","anlam":"Acıma, keder, hüzün, gam, tasa.","kategori":"dil","osmanli":"اسف"},{"kelime":"ESER","anlam":"1.Nişan, alâmet, iz. 2.Sahâbe ve Tâbiîne ait söz.","kategori":"fikih","misal":"Allahü teâlâ bir kuluna nimet verince, bunun eserini onun üzerinde görmeyi sever. (Hadîs-i şerîf- Nesâî, Müsnedü İmâm-ı Ahmed) Eser, mevkûf ve maktû’ hadîs veya duâ bildiren merfû’ hadîs demektir (Mahzenü’l-Esrâr)","osmanli":"اثر"},{"kelime":"ESHÂB (Ashâb)","anlam":"1.Arkadaşlar. 2.Hazret-i Peygamber’i görüp, îmân eden ve mü’min olarak vefat eden mübârek, kutlu kimseler. 3.Bir âlimin talebeleri.","kategori":"akaid","misal":"Sâhib’in çokluk hâli. (Bkz. Sahâbe)","osmanli":"اصحاب"},{"kelime":"Eshâb-ı Ferâiz","anlam":"“Farz sahipleri” mânâsına ölen bir kimsenin mirasına","kategori":"miras","misal":"vâris olan ve hisseleri Kur’ân-ı kerîmde bildirilmiş kişiler. Eshab-i ferâiz 12 kişidir: 1) Baba, 2) Dedeler, 3) Erkek kardeşler, 4) Zevc (koca), 5) Ana bir","osmanli":"فرائض اصحاب"},{"kelime":"Eshâb-ı Fîl","anlam":"“Fil sahipleri” mânâsına Hazret-i Peygamber’in doğuşundan iki ay evvel, Kâbe’yi yıkmak üzere Mekke yakınlarına kadar gelen, fakat Allahü teâlânın gönderdiği Ebâbîl kuşlarının üzerlerine bıraktıkları mercimek büyüklüğündeki taşlarla perişan olan Yemen hükümdar…","kategori":"dil","misal":"(Ey Resûlüm!) Eshâb-ı fîl’e Rabbinin nasıl muâmele ettiğini görmedin mi? Onların hîlelerini boşa çıkarmadı mı? Üzerlerine sürüler hâlinde kuşlar gönderdi. O kuşların her biri onların üzerine çamurdan yapılmış ve ateşte pişirilmiş taş atarlardı. Nihâyet Allahü teâlâ onları güve yemiş ekin yaprağı gibi, yok ediverdi. (Fîl sûresi) Yemen vâlisi Ebrehe, Kâbe’ye gelen ziyaretçileri kendi memleketine çekmek üzere San’a şeh…","osmanli":"فيل اصحاب"},{"kelime":"Eshâb-ı Kehf","anlam":"“Mağara arkadaşları” mânâsına Îsâ aleyhisselâmın ümmetinden olup, dinlerini korumak için din düşmanlarından kaçarak her şeylerini terk eden ve bir mağaraya sığınarak burada 300 sene uyuyan Efsuslu yedi genç ile Kıtmîr adındaki köpekleri.","kategori":"dil","misal":"eden genç yiğitlerdi. Biz onların hidâyet ve sebatlarını artırmıştık. (Kehf sûresi: 13) Eshâb-ı Kehf, Mehdî’nin yardımcıları olacaktır ve Îsâ (aleyhisselâm) bunun zamanında gökten inecektir. (Hadîs-i şerîfAlâmetü’l-Mehdî) Eshâb-ı Kehf, Allahü teâlânın düşmanları her tarafı kapladığı zaman, îmân nûru ile hicret eylemeleri sebebiyle yüksek derecelere kavuşmuşlardır. (Mektûbât-ı İmâm-ı Rabbânî) Eshâb-ı Kehf’in isimleri…","osmanli":"كهف اصحاب"},{"kelime":"Eshâb-ı Kirâm","anlam":"“Şerefli arkadaşlar” mânâsına.","kategori":"muamelat","misal":"Mü’min olarak Resûlullah sallallahü aleyhi ve sellemi gören, kör ise huzurunda bulunup duyan ve mü’min olarak öldüğü bilinen mübârek insanlar ve cinler. (Bkz. Eshâb, Sahâbe)","osmanli":"كرام اصحاب"},{"kelime":"Eshâb-ı Şimâl","anlam":"Cehennem ehli. Âhirette amel defterleri şimâl (sol ve arka) tarafından verilecek olanlar.","kategori":"akaid","misal":"Eshâb-ı şimâl; (Vücûdun derinliklerine işleyen pek şiddetli bir) sıcak, kaynar su ve kapkara dumandan bir gölge içindedirler. (Vâkıa sûresi: 41-42) Eshâb-ı şimâl, amel defterlerini alınca, hâllerini anlayıp, büyük felâket, korkunç azap, sonsuz tehlike, bitmeyen elem, acı ve üzüntüye tutulacaklarını, elleri ve boğazları zincir ve bukağılar ile bağlanıp, pek çirkin arkadaş olan şeytânlarla beraber Cehennem’in dibine a…","osmanli":"شمال اصحاب"},{"kelime":"Eshâb-ı Tahrîc","anlam":"“Tahric sahipleri” mânâsına Hanefî mezhebinde, kısa bildirilmiş olup, iki türlü anlaşılabilen hükümleri açıklayarak bir mânâsını seçen dördüncü tabaka âlimleri.","kategori":"fikih","misal":"Ebû Bekr Ahmed Râzî ve Ebû Abdullah Cürcânî gibi âlimler, eshâb-ı tahrîcdendirler. (Vakfunniyyât)","osmanli":"تخريج اصحاب"},{"kelime":"Eshâb-ı Temyîz","anlam":"“Temyîz sahipleri” mânâsına Hanefî mezhebinde, kuvvetli hükümleri zayıf olanlardan, zâhir haberleri (İmâm-ı Muhammed’in Hanefî mezhebinin temeli olan meşhûr altı kitabında bildirdiği haberleri), nevâdir haberlerinden (İmâm-ı Muhammed’in diğer kitaplarında, İm…","kategori":"ibadet","misal":"Nesefî, Mavsılî, Tâcü’ş-Şerîa gibi âlimler, eshâb-ı temyîzdendirler. (Vakfunniyyât)","osmanli":"تمييز اصحاب"},{"kelime":"Eshâb-ı Tercîh","anlam":"“Tercih sahipleri” mânâsına Hanefî mezhebinde, müctehidlerin ictihadları arasından delili kuvvetli olanları seçebilen beşinci tabaka âlimleri.","kategori":"fikih","misal":"(hükümler) için; “Bu evlâdır (en iyidir)”, “Bu daha sahîhdir (doğrudur)”, “Bu daha açıktır” gibi tabirleri kullanır. (Vakfunniyyât)","osmanli":"ترجيح اصحاب"},{"kelime":"Eshâb-ı Yemîn","anlam":"Cennet ehli. Âhirette amel defterleri sağ taraflarından verilecek olan mü’minler.","kategori":"akaid","misal":"Eshâb-ı Yemîne ne mutlu! Onlar dikensiz kiraz, meyveleri tıklım tıklım muz ağaçları, yayılmış dâimî gölgeler, dâima akan sular, kesilmeyen, yasak da edilmeyen bir çok meyveler arasında ve kadri yükseltilmiş döşeklerdedirler. (Vâkıa sûresi: 27-34)","osmanli":"يمين اصحاب"},{"kelime":"ESHÂM","anlam":"1.Paylar, hisseler. 2.Hisse se-nedleri.","kategori":"dil","misal":"Sehm’in çokluk hâli.","osmanli":"اسهام"},{"kelime":"ESÎM","anlam":"1.Harbde düşmandan ele geçiri-len kimse. 2.Köle. 3.Düşkün, bir şeye vurgun.","kategori":"dil","misal":"Çok günah işleyen kimse. ESÎR: اسير (A) İslâm hukûkunda harbde esir alınmayan bir in- sanı satmak ve satın almak câiz değildir. Esir-den başkası köle olmaz. Köle âzâd etmek, ser-best bırakmak ise çok sevâbdır. (İbni Âbidîn) Maddeden yapılmış olan, his organlarının esiri bulunan bir kimse, maddesiz olandan ve his or-ganları ile anlaşılamayandan ne söyleyebilir? Yok iken sonradan yaratılmış olan bir kimse, hiç yok olmayandan ne anlayabilir? Maddeli, zamanlı ve mekânlı olan, maddesiz, zamansız ve mekânsız olana nasıl yol bulabilir? Zavallı mahlûk, kendi âleminden dışarıya nasıl çıka-bilir? (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اثيم"},{"kelime":"ESKÂM","anlam":"Hastalıklar, dertler. Sekam’ın çokluk hâli.","kategori":"dil","osmanli":"اسقام"},{"kelime":"EŞKIYÂ","anlam":"Haydutlar, yol kesiciler. Şâkî’nin çokluk hâli.","kategori":"dil","osmanli":"اشقياء"},{"kelime":"ESLÂF","anlam":"Öncekiler, geçmişler; bir me-muriyette daha evvel bulunanlar. Selef ’in çok-luk hâli.","kategori":"dil","osmanli":"اسلاف"},{"kelime":"ESLEM","anlam":"Daha sâlim, pek selâmetli, daha doğru.","kategori":"dil","osmanli":"اسلم"},{"kelime":"ESMÂ-İ HÜSNÂ","anlam":"1.Allah, 2.ErRahmân, 3.ErRahîm, 4.El-Me- lik, 5.ElKuddûs, 6.EsSelâm, 7.El-Mü’min,","kategori":"akaid","misal":"“Güzel isimler” mânâsına Allahü teâlânın Kur’ân-ı kerîmde bildirilen doksan dokuz ism-i şerîfi, elEsmâü’l-hüsnâ. Allahü teâlânın Esmâ-i hüsnâsı vardır. O hâlde O’na bunlarla duâ edin. (A’râf sûresi: 180) Esmâ-i hüsnâ şunlardır.","osmanli":"حسنى اسماء"},{"kelime":"ESMÂ-İ İLÂHİYYE","anlam":"Allahü teâlâ-","kategori":"akaid","misal":"nın isimleri. Esmâ-i ilâhiyye sonsuzdur. Binbir ismi var diye meşhurdur. Yani isimlerinden binbir tanesini insanlara bildirmiştir. Muhammed aleyhisselâmın dininde, bunlardan doksandokuzu bildirilmiştir. Bunlara Esmâ-i hüsnâ denir. (İtikadnâme) Esmâ-i ilâhiyye tevkîfîdir. Yani Allahü teâlânın bildirmesine bağlıdır. Şeriatte bildirilmeyen söylenmez. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"الهيه اسماء"},{"kelime":"ESNÂF","anlam":"1.Sınıflar, sıralar. 2.Her türlü sanat ve ticaret işleri ile uğraşan zümreler.","kategori":"ibadet","misal":"Sı-nıf ’ın çokluk hâli.","osmanli":"اصناف"},{"kelime":"ESRÂR","anlam":"1.Gizli ve akıl ermeyen şey-ler. 2.Hind kenevirinin yapraklarından elde edi-len ve sigara gibi içilen uyuşturucu madde.","kategori":"dil","misal":"Sırr’ın çokluk hâli. (Bkz. Sır) Bâtın ilmi, Allahü teâlânın esrârından bir sır-dır. Onu kularından dilediğinin kalbine bı-rakır. (Hadîs-i şerîf-Deylemî, Künûzü’d-Dekâik) Hadîs-i şerîfte; “Âlimler peygamberlerin vâ-risleridir” buyruldu. Peygamberlerin (aleyhi-müsselâm) bıraktıkları ilim iki türlüdür. Biri ahkâm, yapılacak ve sakınılacak şeyler, diğeri esrâr bilgileridir. (Mektûbât-ı İmâm-ı Rabbânî) Esrar, afyon, eroin gibi şeyleri keyf için yimek, harâm olup, tedavi için câizdir. (Enîsü’l-Vâizîn) ESRÂRENGİZ: انگيز اسرار (F) Esrar dolu, sırlı, gizli.","osmanli":"اسرار"},{"kelime":"EŞRÂR","anlam":"Şerliler, kötüler, pek kötü kim-seler. Şerîr’in çokluk hâli.","kategori":"dil","osmanli":"اشرار"},{"kelime":"EŞREF","anlam":"(A. Şerîf ’den) Daha (en, pek) şerefli. EŞREF-İ SAAT (Eşref Saat): ساعت اشرف (A) En şerefli sâat. Bir işe başlamak veya bir şeyi yap-","kategori":"dil","misal":"mak için tercih edilen zaman; du‘â ve ibâdet- lerin kabul edilmesi umulan kıymetli vakit. Eşref sâat, cevf-i şebdir (gece yarısıdır). (Mek-tûbât-ı Ma’sûmiyye)","osmanli":"اشرف"},{"kelime":"EŞRİBE","anlam":"1.Her çeşit içecek, meşrubat. 2.Din kitaplarında içilmesi helâl olup olmayan şeylerin anlatıldığı kısım.","kategori":"dil","misal":"Şerâb’ın çokluk hâli. EŞYÂ: اشياء (A) Şeyler, nesneler. Şey’in çokluk hâli.","osmanli":"اشربه"},{"kelime":"ESTAĞFİRuLLAH","anlam":"“Allahü teâlâdan istiğfâr ederim, hatâ ve kusurlarımı bağışlamasını dilerim” mânâsına bir dua sözü.","kategori":"akaid","misal":"Her pasın bir cilâsı vardır. Kalbin cilâsı da “Estağfirullah” demektir. (Hadîs-i şerîfDeylemî) Kul; “Estağfirullah ve etûbü ileyh” dedi. Sonra o günaha döndü ise, sonra tekrar deyip yine döndü ise, dördüncüde Allah o kimse için; “Çok yalancılardan” diye yazar. (Hadîs-i şerîfDeylemî) İşlediği günaha pişmanlık duymadan ve bu günahı bir daha yapmamaya karar vermeden estağfirullah demeyiniz. Çünki bu, günah ve yalan olu…","osmanli":"استغفرالله"},{"kelime":"ESVED","anlam":"(A, Sevâd’dan) Siyah, kara.","kategori":"dil","osmanli":"اسود"},{"kelime":"ETER","anlam":"Daha ziyade cerrahîde narkoz ola-rak kullanılan, yağları eriten, “azı bayıltan, çoğu ayıltan” sıvı veya gaz hâldeki kimyevî madde.","kategori":"dil","osmanli":"اتر"},{"kelime":"ETFÂL","anlam":"Çocuklar. Tıfl’ın çokluk hâli. Etfâl-i müşrikin (müşriklerin çocukları) ve ehl-i zimmetin çocukları imandan mes’ûl değildir. Bunlar âhirette dirildikten ve hakların alın-masından sonra, hayvanlar gibi yok edilirler. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"اطفال"},{"kelime":"ETTEHIYYÂTÜ","anlam":"Tehiyyatta (namazların birinci ve ikinci oturuşlarında) okunması hadîs-i şerifte bildirilen duâ.","kategori":"hadis","misal":"Dört rek’atli namazlarda iki ka’de (oturuş) vardır. Evvelki ka’de-i ûlâdır ki, burada Ettehiyyatü okumak sünnet, onu okuyacak kadar oturmak vâcibdir. İkincisi ise ka’de-i âhire olup, bunda Ettehiyyâtü okumak vâcib, okuyacak kadar oturmak farzdır. (Halebî)","osmanli":"التحيات"},{"kelime":"EVÂMİR","anlam":"Emirler, buyruklar. Emr’in çokluk hâli.","kategori":"dil","osmanli":"اوامر"},{"kelime":"Evâmir-i Teklîfiyye","anlam":"Teklîfî emirler. Allahü teâlânın insanlara yapmaları veya sakınmaları için verdiği emirler, emr-i teşri’iyye.","kategori":"akaid","osmanli":"تكليفيه اوامر"},{"kelime":"Evâmir-i Tekvîniyye","anlam":"Tekvînî emirler. İnsanların istemesine, iradesine bakılmaksızın, Allahü teâlânın yaratması.","kategori":"akaid","osmanli":"تكوينيه اوامر"},{"kelime":"EVDÂC","anlam":"Hayvanın boğazında iki yanda bulunan birer kan damarı.","kategori":"dil","misal":"Hayvanın boğazında merî denilen yemek borusu, hulkûm denilen hava borusu ve evdâc denilen iki yanda birer kan damarı vardır. Bu dört bo-rudan üçü bir anda kesilmelidir. (İbni Âbidîn)","osmanli":"اوداج"},{"kelime":"EVHÂM","anlam":"Şüpheler, esassız şeyler, ve-himler, kuruntular. Vehm’in çokluk hâli. (Bkz. Vehm)","kategori":"dil","misal":"Kazâ ve kader bilgisi karışık olduğundan, oku-yanlarda, bir takım yanlış fikrler, evhâm ve hayâller hâsıl olabilir. (Abdülhakîm Arvasî) Sâliklere yolda hâsıl olan hâller, mevâcid ve bil-giler ve marifetler asl maksattan değildir. Belki evhâm ve hayâldirler ki, tarîkat yolcuları onunla terbiye olunurlar. Cümlesinden geçip, sülûk ve cezbe makamının nihâyeti olan, rızâ makamına varmak gerektir. Tarîkatin maksadı ve gâyesi, rızâ makamında hâsıl olan ihlâsı ele geçirmek-tir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اوهام"},{"kelime":"EVKÂF","anlam":"Vakıflar; vakıflarla alâkalı merci.","kategori":"muamelat","misal":"Vakf ’ın çokluk hâli. (Bkz. Vakf)","osmanli":"اوقاف"},{"kelime":"EVKÂT","anlam":"Zamanlar; saatler. Vakt’in çokluk hâli.","kategori":"dil","misal":"Evkâtı, zikr ve fikr ile ma’mûr edeler. Ve en mü-him işlere sarf edeler. Ve gizli ve açıkta takvâ ve havf üzere olalar. Ve ölümü ve kıyâmet gü-nünü düşüneler ve bu tefekkürden uzak olma-yalar. (Mektûbât-ı Ma’sûmiyye)","osmanli":"اوقات"},{"kelime":"EVLÂ","anlam":"Daha âlâ, pek iyi, en üstün.","kategori":"dil","misal":"Peygamber, mü’minlere kendi canlarından evlâdır. (Ahzâb sûresi: 6) Def ’i mefâsid, celb-i menâfi’den evlâdır. (Fe-sadların defi, faydalıların alınmasından daha iyidir.). (Mecelle) Bir beldede birçok kimseler ölmüş olsa, hepsi-nin birden namazını kılmak câizdir. Lâkin evlâ olan, teker teker kılmaktır. (Miftahü’l-Cenne) Harâm şübhesi olan şeyleri terk etmek evlâdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اولى"},{"kelime":"EVLÂD","anlam":"Çocuklar, oğlullar. Veled’in çokluk hâli.","kategori":"dil","osmanli":"اولاد"},{"kelime":"EVLÂDLIK","anlam":"Başkasına ait olup, bir kimsenin kendi çocuğu yerine koyduğu kimse. Evlâdlık yapılan çocuk, o kimsenin öz evlâdı gibi olamaz. Mahremi, akrabâsı olmaz. Vâris olamaz. (Ni’met-i İslâm)","kategori":"dil","osmanli":"اولادلق"},{"kelime":"EVLİYÂ","anlam":"1.Dostlar. 2.Emir sahipleri, idareciler. 3.Himâye edenler. 4.Erenler, velîler Allah dostları.","kategori":"tasavvuf","misal":"Velî’nin çokluk hâli. (Bkz. Velî) Mü’minler, mü’minleri bırakıp da kâfirleri evliyâ edinmesin. (Âl-i İmrân sûresi: 28) Biliniz ki, Allahü teâlânın evliyâsı için azap korkusu ve nîmetlere kavuşmamak üzüntüsü yoktur. (Yûnus sûresi: 62) Evliyâmdan birine düşmanlık eden, benimle harb etmiş olur. (Hadîs-i KudsîBuhârî) Evliyâ görülünce, Allahü teâlâ hatırlanır. (Hadîs-i şerîfHâkim)","osmanli":"اولياء"},{"kelime":"EVRÂD","anlam":"Îtiyâd ve vazife olarak devamlı yapılan ibâdet, tesbih ve duâlar.","kategori":"ibadet","misal":"Vird’in çokluk hâlidir. (Bkz. Vird)","osmanli":"اوراد"},{"kelime":"EVRÂK","anlam":"Yapraklar, kâğıtlar. Varak’ın çokluk hâli.","kategori":"dil","osmanli":"اوراق"},{"kelime":"EVSÂF","anlam":"Sıfatlar, hususiyetler.","kategori":"akaid","misal":"Vasf ’ın çokluk hâli.","osmanli":"اوصاف"},{"kelime":"EVTÂD","anlam":"Allahü teâlânın insanlardan gizleyerek dünyanın nizâmiyle vazifelendirdiği ve ricâlü’l-gayb denilen evliyâdan dört büyüğü.","kategori":"akaid","misal":"Evtâd denilen evliyâ, dünyanın dört tarafında bulunurlar. Her biri bulunduğu yerde dünyevî bakımdan huzur ve rahatlığı sağlamakla vazifelidir. Evtâddan dünyanın doğu tarafında bulunan zâtın ismine Abdülhayy, batıdakinin ismine Abdülalîm, kuzeydeki zâtın ismine Abdülmürîd, güneydeki zâtın ismine ise Abdülkâdir denir. (Molla Câmi)","osmanli":"اوتاد"},{"kelime":"EVVÂB","anlam":"Allah’a sımsıkı bağlı, sofu, zâhid.","kategori":"akaid","misal":"Gölgeler batı tarafından doğu tarafına döndüğü ve rüzgarlar estiği zaman, Allah’a duâ ederek ihtiyaçlarınızı söyleyin. Zira o saat, evvâbîn (çok tövbe edenler) saatidir. (Hadîs-i şerîfAbdürrazzak)","osmanli":"اواب"},{"kelime":"EVVEL","anlam":"1.Önceki. 2.Her şeyin başlangıcı olan, varlığından önce yokluk geçmeyen, hiç bir şey yok iken, vâr olan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elEvvelü).. O, Evvel’dir, Âhir’dir... (Hadîd sûresi: 3)","kategori":"akaid","osmanli":"اول"},{"kelime":"EVVELÂ","anlam":"Her şeyden önce, birinci ola-rak, ilk defa.","kategori":"dil","osmanli":"اولا"},{"kelime":"EYÂ (Ayâ)","anlam":"“Ey, hey!” mânâsına gelip Arabca kelime ve terkiplere giren nida edatı.","kategori":"dil","osmanli":"ايا"},{"kelime":"EYLE","anlam":"Kızıldeniz’in kıyısında olup vergi ödemek suretiyle Resûlullah’a tâbiliğini bildi-ren mıntıka.","kategori":"dil","osmanli":"ايله"},{"kelime":"EYMÂN","anlam":"1.Sağ taraflar. 2.Kasemler, söz vermeler, yeminler.","kategori":"dil","misal":"Yemîn’in çokluk hâli. EYTÂM: ايتام (A) Babası ölmüş çocuklar, yetim- ler. Yetîm’in çokluk hâli.","osmanli":"ايمان"},{"kelime":"EYYÂM","anlam":"Günler. Yevm’in çokluk hâli.","kategori":"dil","osmanli":"ايام"},{"kelime":"Eyyâm-ı Nahr","anlam":"“Kurban kesme günleri” mânâsına Kurban bayramında, kurbanın kesildiği birinci, ikinci ve üçüncü günler.","kategori":"ibadet","osmanli":"نحر ايام"},{"kelime":"Eyyâm-ı Teşrîk","anlam":"4.Eyyâm-ı teşrîk, yiyip içmek ve Allah’ı zikretmek günleridir.","kategori":"ibadet","misal":"“Et kurutma günleri” mânâsına Kurban bayramının 2, 3 ve (Hadîs-i şerîfMüslim, Müsnedü Ahmed) Arefe günü, kurban kesme günü ve eyyâm-ı teşrîk, biz Müslümanların bayramıdır. Onlar, yiyip, içilen günlerdir. (Hadîs-i şerîfEbû Dâvûd, Tirmizî, Nesâî)","osmanli":"تشريق ايام"},{"kelime":"EYYûB (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde adı geçen Benî İsrâîl peygamberlerinden.","kategori":"dil","misal":"Eyyûb aleyhisselâmı da an! Hani Rabbine; “Başıma bu dert geldi. Sen, merhametlilerin en merhametlisisin” diye niyaz etmişti. (Enbiya sûresi: 83) Allahü teâlâya yemîn ederim ki, Eyyûb (aleyhisselâm) belâdan inlemedi, sızlanmadı. Ayakta namaz kılmak istedi. Duramadı düştü. Hizmette kusur görünce; “Bana gerçekten hastalık isâbet etti” dedi. (Hadîs-i şerîfHamîd-i Tavîl)","osmanli":"ايوب"},{"kelime":"EZÂ","anlam":"İncinme, incitme, can yakma, ezi-yet, cefâ, cevr.","kategori":"dil","osmanli":"اذا"},{"kelime":"EZÂN","anlam":"1.Bildirmek. 2.Namaz vakitlerini bildirmek, Müslümanları namaza dâvet etmek için yüksek bir yerde sözleri belli olan Arabca kelimeleri sırası ile okumak. Hangi kavim ki, içlerinde sabah ezanı okunursa, o ezan onlar için akşama kadar, Allah’ın azâbından emân olur. İçlerinde akşam ezanı okunan kavime de, o ezan, ertesi günü sabahına kadar Allah’ın azâbından emân olur. (Hadîs-i şerîfTaberânî) Ezân sesini duyduğunuzda müezzinin dediği gibi siz de söyleyin. (Hadîs-i şerîfBuhârî) Ezân okumak, hicretin birinci senesinde Medîne’de başladı. Eshâb-ı kirâmdan (Peygamber efendim…","kategori":"ibadet","osmanli":"اذان"},{"kelime":"Ezân Duâsı","anlam":"Ezânı işiten kimsenin, ezân bitince okuması sünnet olan duâ.","kategori":"ibadet","misal":"Her kim ki ezânı işittikten sonra; “Ey şu eksiği olamayan da’vetin ve işte kılınmakta olan namazın Rabbi olan Allah’ım Muhammed’e vesîle ve fazîleti ve O’nu va’dettiğin övülmüş makama gönder” meâlindeki, “Allahümme rabbe hâzihîd-da‘veti’t-tâmmeti ve’s-salâti’l-kâimeti, âti Muhammeden el vesîlete ve’l-fadîlete ve’d-derecete’l-vâsı’ate veb’ashü makâmen mahmûden ellezî veadtehü inneke lâ tühlifü’l-mîâd” duâsını okursa…","osmanli":"دعاسى اذان"},{"kelime":"Ezân-ı Cavk","anlam":"Bir câmide birkaç müezzinin aynı ezânı birlikte okumaları.","kategori":"ibadet","osmanli":"جوق اذان"},{"kelime":"EZÂNÎ SÂAT","anlam":"Her gün güneşin batışında 12’ye ayarlanan sâat.","kategori":"ibadet","misal":"Gurûbî sâat. Alaturka sâat.","osmanli":"ساعت اذانى"},{"kelime":"EZEL","anlam":"Başlangıcı olmayan, her zaman var olan.","kategori":"dil","misal":"Ezelde Allahü teâlâ tarafından takdir edilen şeyler bu takdire uygun olarak meydana ge-lir. (İhyâ)","osmanli":"ازل"},{"kelime":"EZELÎ","anlam":"Ezele mensub, devamlı var olup başlangıcı, evveli olmayan.","kategori":"dil","misal":"Allahü teâlâ kadîmdir, ezelîdir. Varlığının baş-langıcı yoktur, varlığından önce yok değildi. Hep var idi. Hiç bir zaman da yok olmaz. O’ndan başka hiç bir varlık, kadîm, ezelî değildir. (Mek-tûbât-ı İmâm-ı Rabbânî)","osmanli":"ازلى"},{"kelime":"EZKÂR","anlam":"Zikirler, virdler. (Bkz.","kategori":"tasavvuf","misal":"Zikr)","osmanli":"اذكار"},{"kelime":"EZLÂM","anlam":"Câhiliye devrinde Arabistan’da kullandıkları fal okları.","kategori":"dil","misal":"Ezlâm ile kısmet istemeniz haram kılınmış-tır. (Mâide sûresi: 3) Ey îmân edenler! Mu-hakkak ki içki, kumar, (ibâdet etmek için hazırlanmış) putlar ve ezlâm şeytânın işin-den olan birer pis şeydir. Artık ondan ka-çınınız ki, felâh (kurtuluş) bulabilesiniz. (Mâide sûresi: 90) Câhiliye devrinde, mühim bir işi yapıp yapma-mak hususunda ezlâm denilen oklar ile kur’â çekerlerdi. Bu oklardan birinin üzerine “Rab-bim bana emretti”, diğerinin üzerine “Rab-bim beni nehyetti (yasakladı)”, üçüncünün üzerine de “gaflet etti” diye yazılırdı. Bu ok-ları bir torba içine korlar, putlarından en bü-yüğünün önüne gelerek ey tanrımız biz şöyle şöyle istiyoruz diyerek bu oklardan rast gele bi-rini seçip çıkarırlardı. Eğer “Rabbim bana em-retti” yazılı ok çıkarsa, o işe başlanır, “Rabbim beni nehyetti” yazılı ok çıkarsa, o işten vazge-çilirdi. “Gaflet etti” diye yazılı ok çıkarsa, tek-rar çekiliş yapılırdı. İşte böyle bir muâmele ile yapılacak işi tâyin etmeye kalkışmak haram-dır. (Tefsir-i Mazharî)","osmanli":"ازلام"},{"kelime":"EZVÂC","anlam":"Eşler. Zevc ve zevce’nin çokluk hâli.","kategori":"dil","osmanli":"ازواج"},{"kelime":"FÂCİR","anlam":"1.Fücûr ehli, aleni günah iş-leyen, günaha dalmış, fâsık, günahkâr. 2.Ya-lancı. 3.Kadına düşkün erkek, erkeğe düşkün kadın. 4.Azgın, kâfir.","kategori":"osmanli","misal":"Kıyâmet gününde nice yüzler vardır ki (dün-yada iken geceleri ibâdetle geçirmek veya alı-nan abdestler sebebiyle) parıl parıl parlar, (ka-vuştukları nîmetlerden dolayı) güler ve sevinir (bunlar mü’minlerdir). Nice yüzleri de o gün, toz-toprak, karanlık ve siyahlık kaplayacak-tır. İşte bunlar, kâfirler ve fâcirlerdir. (Abese sûresi: 38-42) Fâcirlerin amel defterleri, Sic-cîn denilen yerdedir. (Mutaffifîn sûresi: 7) Al-lahü teâlâ bu dini fâcir kimselerle de elbette kuvvetlendirir. (Hadîs-i şerîf-Buhârî)","osmanli":"فاجر"},{"kelime":"FÂHİŞ","anlam":"1.Çirkin, ahlâksız, edebe uygun olmayan. 2.Ölçü dışı, aşırı; insafsızca.","kategori":"tasavvuf","osmanli":"فاحش"},{"kelime":"FÂHİŞE","anlam":"1.Haddi aşmak. 2.Ahlâksızlık, zinâ. 3.Zinâyı meslek hâline getirmiş kadın.","kategori":"tasavvuf","misal":"evlendikleri kadınlarla evlenmeyin. Geçmişte olanlar geçmiştir. Çünki o, fâhişe (çok çirkin) ve iğrenç bir şeydi” (Nisâ sûresi: 22)","osmanli":"فاحشه"},{"kelime":"FAHR-İ ÂLEM","anlam":"“Âlemin övüncü” mânâsına Muhammed aleyhisselâm için kullanılan hürmet ifâdesi.","kategori":"dil","misal":"Fahr-i âlem, insanların en cömerdi idi. Bir şey istenip de yok dediği görülmemiştir. İstenilen şey varsa verir, yoksa cevap vermezdi. (Mevâhib-i Ledünniyye)","osmanli":"عالم فخر"},{"kelime":"FAHR-İ KÂİNÂT","anlam":"“Kâinâtın övüncü” mânâsına Muhammed aleyhisselâm için kullanılan hürmet ifâdesi.","kategori":"dil","misal":"Fahrü’l-Kâinât. Fahr-i kâinâtın sallallahü aleyhi ve sellem mübârek yüzü ve bütün âzâları ve mübârek sesi, bütün insanların yüzlerinden ve âzâsından ve seslerinden güzel idi. Mübârek yüzü, bir mikdar yuvarlak idi. Neşeli olduğu zamanda, mübârek yüzü ay gibi nurlanırdı. Sevindiği mübârek alnından belli olurdu. (Mevâhib-i Ledünniyye)","osmanli":"كائنات فخر"},{"kelime":"FÂİDE (Fayda)","anlam":"Menfaat, kâr, kazanç; ümit; hayır; işe yarama.","kategori":"akaid","osmanli":"فائده"},{"kelime":"FÂİZ","anlam":"1.Fazlalık, bolluk, taşkınlık. 2.Hisse senedinin, tahvilin, muamele satışının kârı. 3.Karz, rehin, emânet ve satış gibi akidlerde, iki taraftan birinin ötekine karşılıksız vermesi şart edilen fazla mal, para veya menfaat, ribâ. (Bkz. Ribâ) Fâiz yiyenler, kıyâmet günü mezarlarından, sar’a hastası gibi perişân kalkacaklardır. Allah, fâiz alan ve verenlerin mallarının hepsini yok eder. İzini, eserini de bırakmaz. Zekât verenlerin malını elbette artı…","kategori":"muamelat","osmanli":"فائض"},{"kelime":"FAKÎH","anlam":"Fıkıh âlimi, dinde derin anla-yış sahibi âlim. (Bkz. Fıkıh)","kategori":"dil","misal":"Allahü teâlâ bir kuluna iyilik etmek isterse, onu dinde fakîh yapar. (Hadîs-i şerîf-Buhârî, İbn-i Mâce, Beyhekî, Dârekutnî, Deylemî, Ta-berânî) Şeytâna karşı bir fakîh bin âbidden (çok ibâdet edenden) daha kuvvetlidir. (Ha-dîs-i şerîf-Buhârî)","osmanli":"فقيه"},{"kelime":"FAKÎR","anlam":"1.Aslî ihtiyaçlarından başka dinen zengin sayılacak kadar (nisâb mikdarı) malı bulunmayan, muhtaç. 2.Tasavvufta Allah’dan başka kimseye muhtaç olmayıp hâlini yalnız Allah’a arzeden.","kategori":"ibadet","misal":"Artık ondan (kesilen kurbandan) hem kendiniz yiyin, hem de fakîre yedirin. (Hac sûresi: 28) Bir kimse alacaklı olduğu bir fakire mühlet verse veya borcunu bağışlasa, kendisinden başka gölge bulunmayan günde Allah onu kendi gölgesinde gölgelendirir. (Hadîs-i şerîfMüslim)","osmanli":"فقير"},{"kelime":"FAKR","anlam":"1.Fakirlik, malı olmama, yoksul-luk. 2.Tasavvufta her zaman ve her şeyde Al-lahü teâlâdan başkasına hâlini arzetmemek.","kategori":"tasavvuf","osmanli":"فقر"},{"kelime":"FAL","anlam":"1.Uğur saymak. 2.Talihini anlamak için kahve fincanı, iskambil kâğıdı, atılan taşlara, baklaya, kumdaki izlere bakarak olacaklar hakkında tahmin yürütme. Ümmetimden bir kısmını bana gösterdiler. Dağları, sahrâları doldurmuşlardı. Böyle çok olduklarına şaştım ve sevindim. “Sevindin mi?” dediler; “Evet” dedim. “Bunlardan ancak yetmiş bin adedi hesâbsız Cennet’e girer” dediler. “Bunlar hangileridir?” diye sordum; “İşlerine sihr, büyü, dağlamak, fal karıştırmayıp, Allahü teâlâdan başkasına güvenmeyenlerdir” denildi. (Hadîs-i şerîfMüslim)","kategori":"ibadet","osmanli":"فال"},{"kelime":"FALAKA","anlam":"1.İki ucu bir yere bağlı ip; çift atlı yük arabalarında, çeki kayışlarının bağ-landığı ağaç. 2.Kabahat işleyenleri cezalan-dırmak için arkası üstü yatırıp dayak atmak üzere ayak bileklerine takıp sıkıştırılan iki ucu ip bağlı bir sopa.","kategori":"dil","osmanli":"فلقه"},{"kelime":"FALANCA","anlam":"Metin veya söz arasında ismi bilinmeyen yâhud zikredilmek istenmeyen veya herhangi bir şahsı ifade etmek için kullanılan tabir.","kategori":"tasavvuf","misal":"Felân, felâne, fülân, fülâne.","osmanli":"فلانجه"},{"kelime":"FALCI","anlam":"Fala bakıp, istikbâle dair ha-berler verdiğini iddia eden.","kategori":"dil","misal":"Cebrâil (aleyhisselâm) bana geldi. Kalk na-maz kıl ve duâ et! Bu gece, Şâban’ın on be-şinci gecesidir dedi. Bu geceyi ihyâ edenleri Allahü teâlâ affeder. Yalnız kâfirleri, büyü-cüleri, falcıları, kendini beğenenleri, içki içenleri, fâiz yiyenleri ve zinâ yapanları af-fetmez. (Hadîs-i şerîf-Kimyâ-i Seâdet) Falcı-lar, İblis’in yeryüzündeki elçileridir. (Ha-dîs-i şerîf-Taberânî) Kâhinlere, falcılara inanmamalıdır. Bilinmeyen şeyleri bunlara sormamalıdır. Bunları gaybleri (gizli şeyleri) bilir sanmamalıdır. (Rûhü’l-Beyân)","osmanli":"فالجى"},{"kelime":"FÂNÎ","anlam":"1.Fenâ sahibi, yok olucu, geçici, devamlı olmayan. 2.Tasavvufta fenâ mertebesine kavuşup Allahü teâlâdan başka her şeyi unutan, bunların sevgi ve bağlılığından kurtulan.","kategori":"tasavvuf","misal":"Âlemlerin hâdis olduğuna yani sonradan yaratıldığına inanan, fânî olduklarına da inanır. Müslüman olmak için; maddelerin ve cisimlerin yani her varlığın, yoktan var edilmiş olduklarına ve tekrar fânî olacaklarına inanmak lâzımdır. (Mevâkıf) Dinin emirlerini en iyi şekilde yaparak süslenmek, ibâdetleri yapmakta ve yasaklardan kaçmakta kolaylık hâsıl olması; nefsin fânî olmasına bağlıdır. Bu da ancak, Ehl-i sünnet âli…","osmanli":"فانى"},{"kelime":"FANİLÂ","anlam":"Üste giyilen pamuklu veya yünlü, kollu veya kısa kollu iç çamaşırı.","kategori":"dil","osmanli":"فانله"},{"kelime":"FÂRİS","anlam":"1.İran’ın Fars ülkesi halkı. 2.Binici, süvari. 3.Ferâset sahibi, anlayışlı.","kategori":"hadis","misal":"Persler. İman Süreyyâ yıldızına çıksa, Fâris oğul-larından biri, elbette alıp getirir. (Hadîs-i şerîf-Müslim)","osmanli":"فارس"},{"kelime":"FARK","anlam":"1.Ayrılık, başkalık. 2.Tasav-vufta cem’ mertebesinden sonra gelen ma-kam.","kategori":"dil","misal":"Cem’ül-cem’. (Bkz. Cem’)","osmanli":"فرق"},{"kelime":"FÂRûK","anlam":"Ayırdeden, doğru ile yanlışı birbirinden ayırmakta mâhir, keskin; Hazret-i Ömer’in lakabı.","kategori":"dil","osmanli":"فاروق"},{"kelime":"FARZ","anlam":"Dinin, Allahü teâlâ ve Hazret-i Peygamber’in sarih ve kat’î beyanıyla sâbit olan emirleri.","kategori":"akaid","misal":"Kulum farzları yapmakla bana yaklaştığı gibi, başka şeyle yaklaşamaz. Kulum nâfile ibâdetleri yapınca, onu çok severim. Öyle olur ki, benimle işitir. Benimle görür. Benimle her şeyi tutar. Benimle yürür. Benden her ne isterse veririm. Bana sığınırsa, onu korurum. (Hadîs-i KudsîBuhârî)","osmanli":"فرض","alternatif":["fariza"],"baglamlar":[{"baglam":"kesin hüküm","anlam":"Kur'ân veya mütevâtir hadis ile sâbit olan, yapılması kesin olarak emredilen hüküm."},{"baglam":"farz-ı ayn","anlam":"Her Müslümanın bizzat yapması gereken farz (beş vakit namaz, oruç gibi)."},{"baglam":"farz-ı kifâye","anlam":"Bir kısım Müslümanların yapmasıyla diğerlerinden düşen farz (cenâze namazı gibi)."}]},{"kelime":"Farz-ı Ayn","anlam":"Her Müslümanın yerine getirmesi lâzım olan farz.","kategori":"fikih","misal":"Îmânı, iyi ve kötü huyları, abdesti, guslü, namazı ve orucu ve haramları da, her Müslümanın öğrenmesi farz-ı ayndır. (Mektûbât-ı İmâm-ı Rabbânî) İbâdetlerin en kıymetlisi, farz-ı ayn olanlardır. Farzlardan sonra en kıymetlisi, Şâfi’î’de sünnet namazlar, Hanbelî’de cihâddır. Hanefî ve Mâlikî’de ise, ilim öğrenmek ve öğretmek ve sonra cihâddır. (İfsâh)","osmanli":"عين فرض"},{"kelime":"Farz-ı Kifâye","anlam":"Müslümanların bir kısmının yerine getirmesi ile diğerlerinden düşen farz.","kategori":"fikih","misal":"Kur’ân-ı kerîmi dinlemek farz-ı kifâyedir. Okunmasından ve nâfile ibâdetlerden daha sevâbdır. (Halebî-yi Kebîr) Müslümanların cihâd etmeleri farz-ı kifâyedir. Düşman hücûm ettiği zaman, kadın, çocuk herkese, yani yakın olanlara, eğer bunların da gücü yetişmezse, uzakta ve daha uzaklarda olanlara da farz-ı ayn olur. (İbni Âbidîn)","osmanli":"كفايه فرض"},{"kelime":"Farz ve Sünnet","anlam":"Farz Allahü teâlâ-nın emirleri, sünnet ise Peygamberimizin sal-lallahü aleyhi ve sellem emirleri.","kategori":"akaid","osmanli":"سنت و فرض"},{"kelime":"FÂŞ","anlam":"Meydana çıkma, duyulma, açığa vurma, dile verme (fâş etmek).","kategori":"dil","osmanli":"فاش"},{"kelime":"FASD","anlam":"Damardan kan aldırma. (Bkz. Hacâmat)","kategori":"ibadet","osmanli":"فصد"},{"kelime":"FÂSİD","anlam":"1.Fesâda giden, bozulan, bozuk. 2.Sonradan ortaya çıkan bozucu bir sebebten dolayı bir ibâdetin, amelin, akdin, işin bozulması, geçersiz olması.","kategori":"fikih","misal":"Namaz kılarken göğüs özürsüz olarak kıbleden çevrilirse, namaz hemen fâsid olur. (Halebî) Veresiye yapılan satışta ödeme târihi belirtilmezse, fâsid olur. (Bedâyî) Mehr vermemek üzere seni nikâh ettim derse, nikâh sahîh olur. Şart fâsid olup, mehr-i misl lâzım olur. (İbni Âbidîn)","osmanli":"فاسد"},{"kelime":"Fâsid Akd","anlam":"Aslı İslâmiyet’e uygun olduğu hâlde, sıfatı uygun olmayan her çeşit sözleşme, akd-i fâsid.","kategori":"akaid","misal":"Dârülharbde bulunan bir müste’min Müslüman, meselâ, Türkiye’den Fransa’ya ticaret için gitmiş olan bir Müslüman, kâfirlerin malını, fâsid akd ile alabilir. Çünki, dârülharbde bulunan müste’minin, kâfirlerin mallarını, onların rızâsı ile alması câizdir. Meselâ, onlara para verip fâiz alması câiz olur. Çünki, onların malı, bizlere helâldir. Fakat gadr, yani sözümüzde durmamak, hıyânet etmek, her yerde harâmdır. (İbni…","osmanli":"عقد فاسد"},{"kelime":"Fâsid Bey‘","anlam":"Aslı İslâmiyet’e uygun olup sıfatı uygun olmayan satış.","kategori":"muamelat","misal":"Fâsid bey‘ aslında sahihtir. Çünki mütekavvim (kullanılması mübah ve kullanılabilir) olan malın satışıdır. Fakat sıfatı dine uygun olmadığı için sahih değildir. Semen (bedel) mütekavvim olmayınca veya mebîin (satılan malın) veya semenin mikdarı veya evsafı yâhud veresiye satışta semenin verileceği zaman belli olmayınca bu satış fâsid olur. (İbni Âbidîn)","osmanli":"بيع فاسد"},{"kelime":"Fâsid İcâre","anlam":"İn’ikad (anlaşma) şartları tamam olduğu hâlde, sıhhat şartları yerine gelmeyen; bir başka deyişle aslı şeriate uygun, ama sıfatı uygun olmayan icâre (kirâ) akdi.","kategori":"muamelat","misal":"Ücretin konuşulmaması icâreyi fâsid yapar. Fâsid İcâre, iki taraftan her hangi biri tarafından feshedilir. Eğer anlaşılan iş yapılmışsa, ecr-i misl ödenir. (İbni Âbidîn) İpliğin bir kısmını, dokumacıya kirâ olarak bırakmak üzere dokutmak, eşyadan bir kısmını, kirâ olarak vermek üzere taşıtmak için hayvân kirâlamak, unun bir kısmını kirâ vermek üzere buğday öğütmek fâsid icâredir. Ücreti ve zamanı söylenerek âriyet v…","osmanli":"اجاره فاسد"},{"kelime":"Fâsid Kan","anlam":"Sahîh olmayan, hükümsüz kan.","kategori":"fikih","misal":"-beş dakika bile az olsa- gelen kan, ilk defa hayz gören için on günden çok sürüp, onuncu günden sonra gelen kan, kadınlarda ise âdetinden çok olup on günü de aştığında âdetten sonraki günlerde gelen kan, hâmile ve âyise (ihtiyar) kadınlardan ve dokuz yaşından küçük kızlardan gelen kan. İstihâza kanı. Dem-i fâsid. (Bkz. İstihâza)","osmanli":"قان فاسد"},{"kelime":"Fâsid Temizlik","anlam":"Sahîh olmayan, hükümsüz temizlik.","kategori":"fikih","misal":"Hayz kanının durmadan hep akması lâzım değildir. İlk görülen kan kesilip, birkaç gün sonra tekrar görülürse, aradaki üç günden az olan temizlik, sözbirliği ile hep aktı kabul edilir. Üç gün ve daha çok süren temizlik, İmâm Muhammed’e göre, hayzın onuncu gününden önce biterse, yine kan aktı kabul edilir. Kan aktı kabul edilen bu temizlik günlerine fâsid temizlik denir. (İbni Âbidîn)","osmanli":"تميزلك فاسد"},{"kelime":"FASÎH","anlam":"Fesâhatli, güzel, düzgün ve açık konuşan, iyi söz söyleme kabiliyetinde olan.","kategori":"dil","osmanli":"فصيح"},{"kelime":"FÂSIK","anlam":"1.Fısk sahibi, zararlı, âsî, gü-nahkâr, günahı âdet hâline getiren mü’min. 2.Kâfir; münâfık.","kategori":"hadis","misal":"Ey îmân edenler! Eğer bir fâsık size bir ha-ber getirirse, onun iç yüzünü araştırın. Yoksa bilmeden bir millete (veya kimseye) fenâlık edersiniz ve sonra yaptığınıza pişman olur-sunuz. (Hucurât sûresi: 6) Fâsık medh olun-duğu zaman, Arş-ı âlâ titrer, Rabbimiz ga-dâba gelir. (Hadîs-i şerîf-Beyhekî, İbni Adiy, Ebû Ya’lâ) Hayvanlardan fasık olan şu beşi Harem-i Şerif ’de öldürülebilir: Karga, çay-lak, fare, akreb ve saldıran köpek. (Hadîs-i şerîf-Buhârî) Onlar için yetmiş defa af dilesen de, Allah onları affetmeyecektir. Bu, onların Allah ve Resûlünü inkâr etmelerinden ötürüdür. Al-lah fâsıklar topluluğunu hidâyete erdirmez. (Tevbe sûresi: 80) İşte fâsıkların inanmaya-caklarına dair Rabbinin sözü gerçekleşmiş oldu. (Yûnus sûresi: 33)","osmanli":"فاسق"},{"kelime":"FÂSILA","anlam":"1.Ara. 2.Âyet-i kerîmelerin son harfi birbirine benzeyen ve okurken du-rulan son kelimesi.","kategori":"dil","osmanli":"فاصله"},{"kelime":"FAŞİST","anlam":"Faşizm idelojisine mensub. FAŞİZM: فاشيزم (Fr) 1920’lerde İtalyan lider Mussolini tarafından ortaya atılan, devlet, li-","kategori":"dil","misal":"der, millet ve ırkın aşırı yüceltildiği, anti-de- mokratik, anti-komünist, baskıcı, otoriter re-jim anlayışını tasvir eden ideoloji.","osmanli":"فاشيست"},{"kelime":"FÂTİH","anlam":"Fetheden; açan.","kategori":"dil","osmanli":"فاتح"},{"kelime":"FÂTİHÂ","anlam":"1.Başlangıç, giriş. 2.Kur’ân-ı kerîm’in birinci sûresi.","kategori":"dil","osmanli":"فاتحه"},{"kelime":"FÂTİHA SûRESİ","anlam":"Kur’ân-ı kerîmin birinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Yedi âyet-i kerîmedir. Kur’ân-ı kerîmin başında olup, okumaya onunla başlandığı için Fâtiha, Kur’ân-ı kerîmdeki mânâların aslı olduğundan, Ümmü’l-Kur’ân, hadîs-i şerîfte şifâ olduğu bildirildiğinden Sûretü’ş-Şâfiye veya Sûretü’ş-Şifâ denilmiştir. Diğer isimleri; elEsâs, elVâfiye, elKâfiye, es-Se-bü’l-mesânî ve elKenz’dir. Sûre, Allahü teâlâya hamd ü senâyı (övgü ve şükrü), O’nun sıfatlarını ve m…","osmanli":"سى سوره فاتحه"},{"kelime":"FÂTIMÎLER","anlam":"Mısır, Kuzey Afrika, Filistin ve Sûriye’de 910-1171 seneleri arasında hüküm süren ve Şia’nın aşırı kollarından Bâtınîliğe mensub hânedân.","kategori":"dil","osmanli":"فاطميلر"},{"kelime":"FÂTIR","anlam":"“Benzeri bulunmayan bir şeyi yaratan” mânâsına Allahü teâlânın sıfatı.","kategori":"akaid","osmanli":"فاطر"},{"kelime":"FÂTIR SûRESİ","anlam":"Kur’ân-ı kerîmin otuz beşinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Kırk beş âyet-i kerîme-dir. İlk âyet-i kerîmede geçen ve yaratıcı mânâ-sında Allahü teâlânın sıfatı olan “Fâtır” keli-mesi sûreye isim olmuştur. Melâike sûresi de denilmektedir. Sûrede başlıca; Allahü teâlâ-nın üstün ve eşsiz yaratma kudreti, mü’min ile kâfir arasındaki fark, insan kalbinin kötü-lüklerden temizlenmesi ve güzel ahlâk ile be-zenmenin lüzumu anlatılmaktadır. (Taberî) Kim Fâtır sûresini okursa, dilediğinden gir-mesi için Cennet’in sekiz kapısına da’vet edi-lir. (Hadîs-i şerîf-Kâdı Beydâvî)","osmanli":"سى سوره فاطر"},{"kelime":"FAZÎLET (Fadîle)","anlam":"Üstünlük, iyi ahlâk; farz ve vâciblerin haricindeki nâfile ibâdetler, yani sünnet ve müstehâblar.","kategori":"fikih","misal":"Namazı cemâat ile kılmak, yalnız kılmaktan yirmi yedi derece daha fazîletlidir. (Hadîs-i şerîfBuhârî, Müslim, Neseî, Taberânî, Müsnedü Ahmed) Dört halîfenin fazîlet ve üstünlükleri hilâfetteki sıralarına göredir. (İhyâ) Din üç kısımdır: Emirler, yasaklar ve fazîletler. (Riyâdü’n-Nâsıhîn)","osmanli":"فضيلت"},{"kelime":"FECÎ’","anlam":"Elem, keder ve ıztırap veren, acıklı; dehşetli, korkunç, acınacak hâl. Fecaatli. FECR: فجر (A) Sabaha karşı, güneş doğmadan","kategori":"dil","misal":"önce, ufkun gün doğusu tarafında görünen aydınlık, tan yerinin ağarması, şafak sökmesi. Fecr-i Kâzib: كاذب فجر (A) “Yalancı, aldatıcı fecr” mânâsına fecr-i sâdıktan, gerçek fecrden iki derece kadar önce doğuda görülen ve sonra kaybolan geçici beyazlık. Zodyak Işığı.","osmanli":"فجيع"},{"kelime":"Fecr-i Sâdık","anlam":"“Gerçek, doğru fecr” mânâsına fecr-i kâzibi takip eden tam karanlıktan sonraki beyazlık, sabah namazı vaktinin girişi ve orucun başlama vakti.","kategori":"ibadet","misal":"Sabah namazı, dört mezhebte de fecr-i sâdıkın şarktaki ufk-i mer’îden (görünen ufuktan) aydınlanmaya yüz tutması ile başlar. (Kedûsî) Orucun farzı üçtür: 1) Niyet etmek, 2) Niyeti ilk ve son vakitleri arasında yapmak, 3) Fecr-i sâdıktan, güneşin batmasına kadar olan zaman içinde orucu bozan şeylerden sakınmak. (Miftahü’l-Cenne)","osmanli":"صادق فجر"},{"kelime":"FEDÂ","anlam":"Gözden çıkarma, vazgeçme, uğruna verme; kurban.","kategori":"ibadet","osmanli":"فداء"},{"kelime":"FEDÂÎ","anlam":"Canını esirgemeyen, mühim bir maksat uğruna canını vermeye hazır. Fidâî.","kategori":"dil","osmanli":"فدائى"},{"kelime":"FEDÂİL","anlam":"Üstünlükler, iyi huylar; farz ve vâcib olmayan nâfile ibâdetler.","kategori":"fikih","misal":"Yâ Ali! İnsanlar fedâil ile meşgul oldukları zaman, sen farzları tamamlamaya çalış. (Hadîs-i şerîfMiftahü’n-Necât) Za’îf hadîsler ancak fedâil için delil olur. Yani fedâil, za’îf hadîslere uyarak da yapılır. Farz, vâcib ve müekked sünnet olan ibâdetlerde ancak meşhûr ve sahîh hadîsler delil olurlar. (İbni Âbidîn)","osmanli":"فضائل"},{"kelime":"FEDÂKÂR","anlam":"Kendini veya şahsî menfaatlerini esirgemeyen, feda eden, cömert, eli açık.","kategori":"tasavvuf","misal":"Fidâkâr.","osmanli":"فداكار"},{"kelime":"FEHÎM","anlam":"Fehm (anlayış) sahibi, zeki, anlayışlı, akıllı.","kategori":"dil","osmanli":"فهيم"},{"kelime":"FEHM","anlam":"Anlayış, anlama, iyiyi kötüden ayıran anlama kuvveti.","kategori":"dil","misal":"Ahmak insan kendisini aldanmaktan koruya-maz. Akıl ve fehm, insanın yaratılışında ola-cak. Yaratılışında akıl ve fehimden mahrum olanlar, bunları sonradan te’min edemezler. (Kimyâ-i Seâdet)","osmanli":"فهم"},{"kelime":"FELÂH","anlam":"Kurtuluş, selâmet, mutluluk, hayır ve nîmetlerde, rahatta dâim olmak.","kategori":"dil","misal":"Sizden öyle bir cemâat (topluluk) bulunmalı-dır ki, (onlar herkesi) hayra çağırsınlar, iyiliği emretsinler, kötülükten vazgeçirmeye çalış-sınlar. İşte onlar felâha erenlerin tâ kendile-ridir. (Âl-i İmrân sûresi: 104) Mü’minler (Al-lahü teâlânın birliğine inananlar) muhakkak felâh bulmuştur. (Mü’minûn sûresi: 1)","osmanli":"فلاح"},{"kelime":"FELÂKET","anlam":"Musîbet, belâ; talihsizlik.","kategori":"dil","osmanli":"فلاكت"},{"kelime":"FELÂSİFE","anlam":"1.Filozoflar, bilginler. 2.Kaygısız yaşayanlar. 3.Dinsizler.","kategori":"dil","misal":"Feylesof’un çokluk hâli.","osmanli":"فلاسفه"},{"kelime":"FELEK","anlam":"1.Yörünge; yıldızların döndük-leri gök. 2.Talih, baht.","kategori":"dil","misal":"Ne güneş aya yetişebilir, ne de gece gün-düzü geçebilir. Bunlardan her biri belli bir felekte yüzmeye (akıp gitmeye) devam eder-ler. (Yâsîn sûresi: 40)","osmanli":"فلك"},{"kelime":"FELEKİYYE","anlam":"Felek’e (gök bilgisine) mensub, astronomik.","kategori":"dil","osmanli":"فلكيه"},{"kelime":"FELESOF","anlam":"Feylesof, filozof.","kategori":"dil","osmanli":"فيلسوف"},{"kelime":"FELLÂH","anlam":"1.Çiftçi. 2.Suriye’de yaşayan Arap Alevîsi. 3.Zenci.","kategori":"dil","osmanli":"فلاح"},{"kelime":"FELS","anlam":"1.Altın ve gümüşten başka mâ-denlerden basılmış para, mangır, pul. 2.Piya-sada tedâvül eden paranın en düşük birimi.","kategori":"dil","misal":"Çoğulu fülûs. Satılan veya satın alınan malın, bir felsin i’ti-bârî kıymetinden aşağı olmaması lâzımdır. Bir felsten aşağı alış-veriş, -bu parayı bulup satı-cıya teslim etmek mümkün olmadığı için- câiz değildir. (Eşbâh) Yüz fels, ortalama, bir dirhem gümüş kıymetin-dedir. Bir miskal ağırlığındaki altın kıymeti, on dirhem ağırlığındaki gümüş kıymetine müsâvî-dir. (İbni Âbidîn, Bezzâziyye) Bir felsin i’tibârî kıymeti, şimdi bir altın lira-nın kıymeti olan kâğıd lira adedinin onbeşde biri kadar olmakdadır. Bu kadar ucuz malın, bir fels değerinde olacak fazla mikdârı için veyâ başka cins mallar ile birlikde tek bir söz-leşme yaparak topdan satmak câiz olur. (Seâ-det-i Ebediyye)","osmanli":"فلس"},{"kelime":"FELSEFE","anlam":"1.Eşyanın ve hâdiselerin hakikatini ve niçin var olduğunu akıl ve mantığın yardımıyla sistemli bir şekilde çözmeye çalışma. Hikmet. 2.Bir ilmin esası.","kategori":"hadis","misal":"Aslı “Hikmete duyulan aşk” mânâsına Yunanca filozofia’dır. Akıl ile anlaşılan şeyler, his uzuvları ile anlaşılanların üstünde olduğu ve bunların yanlışını çıkardığı gibi, yani his uzuvlarımız, akıl ile anlaşılan şeyleri anlayamayacağı gibi, akıl da, Peygamberlik makamında anlaşılan şeyleri kavramaktan âcizdir. İnanmaktan başka çaresi yoktur. Akıl, anlayamadığı şeyleri nasıl ölçebilir. Bunl…","osmanli":"فلسفه"},{"kelime":"Felsefeciler","anlam":"Her şeyi akıl ile anlayıp izah etmeye çalışan kimseler.","kategori":"dil","osmanli":"جيلر فلسفه"},{"kelime":"FENÂ","anlam":"1.Kötü, iyi olmayan, uygunsuz. 2.Yok olma, yokluk, tasavvufta kendini yok görüp, başka her şeyi unutmak, mahlûkların bağlılığının kalbden çıkması, bekâ’nın zıddı. Fenâya kavuşmak için lâzım olan on şey: Tövbe, zühd (dünyaya düşkün olmamak), tevekkül (Allahü teâlâya güvenmek), kanâat, uzlet (insanlardan uzak durmak), zikr (her işte Allahü teâlâyı hâtırlamak), teveccüh (bütün arzu ve isteklerden sıyrılarak Allahü teâlâya yönelmek), sabır, murâkabe…","kategori":"tasavvuf","osmanli":"فناء"},{"kelime":"Fenâ fi’r-Resûl","anlam":"Resûlullah’da fenâ bulmak mânâsına tasavvufta fenâdan sonra hâsıl olan ve Resûlullah’ı hakîki muhabbet ile severek, feyzleri doğruca O’nun kalbinden alma makamı.","kategori":"tasavvuf","osmanli":"الرسول فى فنا"},{"kelime":"Fenâ fillah","anlam":"Allah’da fenâ bulmak; kalbin yalnız Allahü teâlâyı sevmesi, O’nun beğendiği şeylerde fâni olmak yani O’nun sevdiklerini sevmek O’nun sevdiklerini kendi için sevgili bilmek.","kategori":"tasavvuf","osmanli":"الله فى فنا"},{"kelime":"FENN","anlam":"1.Sanat. 2.Tekniği doğuran fizik, kimya, tabiat bilgisi gibi ilimler.","kategori":"dil","osmanli":"فن"},{"kelime":"FER","anlam":"Parlaklık, aydınlık; süs; güç.","kategori":"dil","osmanli":"فر"},{"kelime":"FER‘","anlam":"1.Dal, budak, asla bağlı kollar. 2.Asl ile beraber kıyasın bir rüknü. 3.Çocuk ve torun.","kategori":"dil","misal":"Allah’ın, hoş bir sözü, kökü sağlam, fer’i göğe doğru hoş bir ağaca benzeterek nasıl misal verdiğini görmez misin? (İbrâhim sûresi: 24) Kıyasta hakkında hüküm bulunan meseleye asl, bulunmayan meseleye fer’ (makîs) denir. Hadîs-i şerîfte; “Buğdayı buğday ile misliyle satınız, fazlasına satarsanız ribâ, yani fâiz olur” bu-yurulmuştur. Darı da böyle midir? Burada asl, buğdaydır. Fer’ darıdır. Buğdayın bu şekilde satılmasının câiz olmamasının illeti aynı cins-ten ve kileyle ölçülebilir bulunmasıdır. Darıda da aynı hususlar cârî olduğundan bu yasağın şümulüne girer. (Şerhu Menâr li-İbn-i Melek)","osmanli":"فرع"},{"kelime":"FERÂCE","anlam":"Eskiden Osmanlı memleketlerinde kadınların dışarı çıkarken üzerine giydiği geniş, uzun ve ekseriya koyu renkte yünlü veya ipekli dış elbise, milhafe, saya, manto.","kategori":"osmanli","osmanli":"فراجه"},{"kelime":"FERÂGAT","anlam":"Ferâğ etme, vazgeçme; din-lenme; vazgeçecek kadar zengin olma, istiğnâ. Îyş-ü nûşundan fânî dehrin ferâgât edelim, Çünki takdîr-i Hudâdır buna itâ’at edelim. (Nevhatü’l-uşşak)","kategori":"dil","osmanli":"فراغت"},{"kelime":"FERÂH","anlam":"Gönül açıklığı, sevinç, sevinme.","kategori":"dil","osmanli":"فراح"},{"kelime":"FERÂİZ","anlam":"1.İbâdetler, ferâiz ve fedâil (nâfile ibâdetler) olmak üzere iki kısımdır. 2.Bir kimse vefât edince, bıraktığı malın kimlere verileceğini ve nasıl dağıtılacağını öğreten ilim, mîrâs hukûku.","kategori":"miras","misal":"(Kudûrî) Ferâiz ilmini öğrenmeye çalışınız. Bu ilmi gençlere öğretiniz. Ferâiz ilmi din bilgisinin yarısı demektir. Ümmetimin en önce unutacağı, bırakacağı şey, bu ilim olacaktır. (Hadîs-i şerîfİbn-i Mâce, Dâre Kutnî)","osmanli":"فرائض"},{"kelime":"FERD","anlam":"Tek, yalnız, çift olmayan, eşi bu-lunmayan.","kategori":"dil","osmanli":"فرد"},{"kelime":"FERDÎ","anlam":"Ferde mensub, ferd ile alâ-kalı; tek şey.","kategori":"dil","osmanli":"فردى"},{"kelime":"FEREC","anlam":"Ferahlama, gam ve kederden kurtulma, teselli; zafer.","kategori":"dil","misal":"İstigfâra devam edeni, Allahü teâlâ her sı-kıntıdan çıkarır, her derdine ferec verir ve onu hiç ummadığı yerden rızklandırır. (Ha-dîs-i şerîf-Hâkim)","osmanli":"فرج"},{"kelime":"FERÎD","anlam":"Tek, eşsiz, eşi olmayan; kıyas kabul etmez, ölçüsüz; üstün.","kategori":"fikih","misal":"Ben de Ferîd-i asr idim, fass-ı nigîn-i sadr idim, Nakş-ı hümâyûnsatr idim, gösterdi çarh rûy-ı abes. (Sâmi Paşa)","osmanli":"فريد"},{"kelime":"FERMÂN","anlam":"Emr, hükümdar buyruğu.","kategori":"osmanli","osmanli":"فرمان"},{"kelime":"FERMANTASYON","anlam":"Bir maddenin bakteri, mantar ve diğer mikroorganizmalar vasıtasıyla ısı verip köpürerek kimyevî olarak çürümesi, mayalanma, tahammür.","kategori":"osmanli","osmanli":"فرمانتاصيون"},{"kelime":"FERSAH","anlam":"Bir saatte yaya gidilebilen üç millik (takriben 5 km) yol. Aslı Farsça fer-senk kelimesinden gelir.","kategori":"dil","misal":"Âlimlerin hepsi, dinde seferî (yolcu) sayılmak için gidilmesi lâzım olan üç günlük yolu, fersah dedikleri ölçü ile bildirdiler. Bir kısmı üç gün-lük yol, yirmi bir fersah, bir kısmı on sekiz, bir kısmı ise on beş fersahtır dedi. Fetvâ (hüküm) ikinci söze göre verilmiştir. Yani seferîlik mesâ-fesinin on sekiz fersah olduğunu esas almışlar-dır. (İbni Âbidîn)","osmanli":"فرسخ"},{"kelime":"FERYÂD","anlam":"1.Yardım istemek için çıkarı-lan yüksek ses. 2.Acı acı bağırıp çağırma, bağ-rışma, çağrışma. 3.Sızlanma, şikâyet. 4.Yay-gara, gürültü.","kategori":"dil","osmanli":"فرياد"},{"kelime":"FES","anlam":"Eskiden Osmanlı ve Arab memleketlerinde erkeklerin giydiği, ismini Fes şehrinden alan bordo renkli çuhadan serpuş.","kategori":"osmanli","osmanli":"فس"},{"kelime":"FESÂD","anlam":"Bozukluk; mâsiyet; helâk; ka-rışıklık, fitne, anarşi.","kategori":"dil","misal":"Yeryüzünde fesâd çıkarmayın. (Bakara sû-resi: 11) Ümmetim arasına fesâd yayıldığı zaman, sünnetime yapışan için yüz şehîd sevâbı vardır. (Hadîs-i şerîf-Hâkim) Fesâd-ı ümmet oldu âşikâre, Müdârâdan başka kalmadı çâre. (Terzi Baba)","osmanli":"فساد"},{"kelime":"FESÂHAT","anlam":"1.Köpüksüz hâlis süt. 2.Düzgün ve doğru (fasîh) konuşma.","kategori":"dil","osmanli":"فصاحت"},{"kelime":"FESH","anlam":"Bir akdi veya anlaşmayı bozma. Bir kimse, karşısındaki pişman olunca, satışı fesheder geri alırsa, Allahü teâlâ onun gü-nahlarını affeder. (Hadîs-i şerîf-İbni Hibbân)","kategori":"hadis","osmanli":"فسخ"},{"kelime":"FETÂVÂ","anlam":"Müftü tarafından verilen şer’î hüküm veya kararlar. Fetvâ’nın çokluk hâli.","kategori":"fikih","osmanli":"فتاوا"},{"kelime":"FETEVÂ","anlam":"(Bkz. Fetâvâ).","kategori":"dil","osmanli":"فتوا"},{"kelime":"FETH (Fetih)","anlam":"Açma, açılma; başlama; bir yeri zaptetme; bir harfin üstün (e) olarak okunması","kategori":"dil","osmanli":"فتح"},{"kelime":"FETH SûRESİ","anlam":"Kur’ân-ı kerîmin kırk sekizinci sûresi.","kategori":"dil","misal":"Hicretin altıncı yılında Hudeybiye Muahedesi dönüşünde Mekke ile Medîne arasında nâzil oldu. Yirmi dokuz âyet-i kerîmedir. İslâmiyet’in yakında elde edeceği fethi ve zaferi müjdelediğinden Sûretü’l-Fetih denilmiştir. Sûrede; Resûlullah aleyhisselâm ve mü’minler için verilen ve verilecek olan nîmetler, münâfıkların ve müşriklerin uğrayacağı azap hatırlatılmakta ve cihâddan geri kalanlar ve daha başka konular anlatılm…","osmanli":"سى سوره فتح"},{"kelime":"FETTÂH","anlam":"Çok açan, kapalı olan her şeyi açan, peygamberlerini düşmanlarının elinden kurtarıp memleketleri açan, yol göstererek meseleleri açan, hayır ve rahmet kapılarını açan, marifetiyle sevdiği mü’minlerin kalblerini açan mânâsına Allahü teâlânın Es-mâ-i hüsnâsında…","kategori":"akaid","misal":"O (Allahü teâlâ) Fettâh’tır. (Sebe’ sûresi: 26)","osmanli":"فتاح"},{"kelime":"FETVÂ","anlam":"Bir meselenin İslâmiyet’e uygun olup olmadığı hakkında müftü veya herhangi","kategori":"fikih","misal":"bir âlim tarafından verilen hüküm. Kadınlar hakkında senden fetvâ isterler. De ki: “Onlar hakkında fetvâyı size Allah veriyor. Bu fetva, kendilerine yazılan şeyi vermediğiniz ve kendileriyle evlenmeyi arzuladığınız yetim kadınlara ve bir de zavallı çocuklara ve yetimlere doğrulukla bakmanız hususunda Kitab’da size okunandır.” Ne iyilik yaparsanız Allah onu şüphesiz bilir. (Nisâ sûresi: 127) Kalbinden fetvâ iste! Eli…","osmanli":"فتوى"},{"kelime":"FETVÂ EMÎNÎ","anlam":"Osmanlılar zamanında şeyhülislamlıkta fetvâ işlerine bakan ve kadıların verdiği hükümleri tedkik eden yüksek ilim adamı.","kategori":"osmanli","osmanli":"امينى فتوى"},{"kelime":"FETVÂHÂNE","anlam":"Fetvâ verilen yer, müftülük mercii; Osmanlılarda şeyhülislâmlığın münhasıran fetvâ ile uğraşan dairesi, bâb-ı fetvâ.","kategori":"osmanli","osmanli":"خانه فتوى"},{"kelime":"FEVÂÎD","anlam":"Faydalar, kârlar. Fâide’nin çokluk hâli.","kategori":"dil","osmanli":"فوائد"},{"kelime":"FEVK","anlam":"Üst, üst taraf, yukarı.","kategori":"dil","osmanli":"فوق"},{"kelime":"FEVKÂNÎ","anlam":"Üstte olan, yukarıda bulunan.","kategori":"dil","osmanli":"فوقانى"},{"kelime":"FEVT","anlam":"Bir daha ele geçmemek üzere kaybetme, elden çıkarma, kaçırma.","kategori":"dil","misal":"Namazı özür ile kaçırmaya fevt etmek denir. (İbni Âbidîn)","osmanli":"فوت"},{"kelime":"FEVZ","anlam":"Gâlibiyet, zafer, üstünlük; selâ-met, kurtuluş.","kategori":"dil","misal":"İnsanda bulunan a’zâların harâmla alâkala-rının kesilmesi lâzımdır ki, fevz ü felâh bula-sın. Aksi takdîrde kendini helâk etmiş olursun. (Hüccetü’l İslâm)","osmanli":"فوز"},{"kelime":"FEY’","anlam":"1.Dönme. 2.Muhârebe bittikten sonra, kâfirlerden zorla veya harb yapılma-dan sulh yoluyla alınan mal. 3.Gölge.","kategori":"dil","misal":"Allah’ın, (fethedilen diğer kâfir) memleketle-rin ahâlisinden Peygamberine verdiği fey’; Allah’a, Peygamberine, Resûlullah’ın akra-bâsına, yetimlere, yoksullara, yolda kalan-lara âittir. (Haşr sûresi: 7) Fedek arâzîsi, sulh (barış) ile alındığı için o da fey’ idi. Düşman tarafından hediye olarak gön-derilen mallar da Resûlullah efendimiz için fey’ olup, O’nun tasarrufunda (idâresinde) idi. Dile-diği gibi harcardı. (Kitabü’l-Emvâl li-Ebi Ubeyd) Harâc (gayr-i müslim vatandaşlardan alınan vergi) ve cizye de (gayr-i müslim vatandaşla-rın hür ve mükellef olan erkeklerinden, seneden seneye alınan vergi) fey’dir. (Kitabü’l-Harâc)","osmanli":"فيئ"},{"kelime":"Fey’-i Zevâl","anlam":"Güneş, gün ortasında (nısfünnehârda), tam tepeye gelince (zevâl vakti) görülen en kısa gölge uzunluğu.","kategori":"dil","misal":"Asr-ı evvelin vakti; bir şeyin gölgesinin boyu, fey-i zevâl artı kendi boyu olunca başlar. Asr-ı sâninin vakti, bir şeyin gölgesi, fey-i zevâl artı kendi boyunun iki misli olunca başlar. Asr-ı evvel, İmâm-ı Ebû Yûsuf ile İmâm-ı Muhammed’e göre, Asr-ı sânî İmâm-ı A’zâm’a göre ikindinin başladığı vakittir. (Fethü’l-Kadîr)","osmanli":"زوال فيئ"},{"kelime":"FEYZ","anlam":"1.Taşıp akma. 2.Resûlullah aleyhisselâmın kalbinden, evliyânın kalbleri vâsıtasıyle akıp gelen mânevî bilgiler, mânevî lütuf ve nimet.","kategori":"tasavvuf","misal":"Din büyüklerinin yanına boş olarak gelmelidir ki, dolmuş (faydalanmış) olarak dönülebilsin. Onların acıması, ihsânda bulunması için, boş olduğunu bildirmek lâzımdır. Böylece feyz yolu açılır. (Mektûbât-ı İmâm-ı Rabbânî) Gelince feyz ü ihsânın, günahkâr kimseye bir an, Onun râhı düâlemde selâmet yâ Resûlallah! (Yaman Dede)","osmanli":"فيض"},{"kelime":"FEZÂ","anlam":"Ucu bucağı bulunmayan boşluk, dünyanın sonsuz olan genişliği, uzay.","kategori":"dil","osmanli":"فضاء"},{"kelime":"FEZLEKE","anlam":"1.Netice, hülâsa. 2.Bir tah-kikat veya teftiş neticesi hazırlanan rapor.","kategori":"dil","osmanli":"فذلكه"},{"kelime":"FÎ SEBÎLİLLÂH","anlam":"Allah yolunda, bir işin karşılıksız, sâdece Allahü teâlânın rızâsı için yapılması.","kategori":"akaid","misal":"Fî sebîlillâh, Müslümanları düşmandan korumak için nöbet tutarken ölenin, öldükten sonra da sevabları yazılır. (Hadîs-i şerîfMüsnedü Ahmed)","osmanli":"الله سبيل فى"},{"kelime":"FIDDA","anlam":"Gümüş.","kategori":"dil","osmanli":"فضه"},{"kelime":"FİGÂN","anlam":"Iztırap ile bağırıp çağırma, sesli sesli inleme, feryad.","kategori":"dil","osmanli":"فغان"},{"kelime":"FİHRİST","anlam":"1.Bir kitabın içindekiler lis-tesi, indeks. 2.Eşyanın adlarını gösteren defter.","kategori":"dil","osmanli":"فهرست"},{"kelime":"FIKH (Fıkıh)","anlam":"1.Bilmek, anlamak. 2.İslâmiyet’te inanılması, yapılması ve sakınılması lâzım gelenleri bildiren ilim.","kategori":"fikih","misal":"Mü’minlerin hepsinin toptan sefere çıkmaları doğru değildir. Her topluluktan bir taife fıkıh öğrenmek ve kavimleri döndüğünde onları ikaz etmek için geride kalmalıdır. (Tevbe sûresi: 122) Fıkh öğrenmek her Müslümana farzdır. (Hadîs-i şerîfHâkim) Fıkh kelimesi, Arabca’da, fekıha yefkahü şeklinde kullanılınca, yani dördüncü bâbdan olunca, bilmek, anlamak demektir. Beşinci bâbdan olunca, şeriati bilmek, anlamak demekti…","osmanli":"فقه"},{"kelime":"Fıkh-ı Ekber","anlam":"1.İslâmiyet’te inanılması gerekenleri bildiren ilim, fıkhın itikada dair olan kısmı. 2.İmâm Ebû Hanîfe’nin bu ilme dair meşhur eseri, elFıkhu’l-Ekber.","kategori":"akaid","osmanli":"اكبر فقه"},{"kelime":"FİKR","anlam":"1.Akıl. 2.Rey, görüş, düşünce.","kategori":"dil","osmanli":"فكر"},{"kelime":"FIKRA","anlam":"1.Omurga kemiğinin boğumu, omur. 2.Bend, madde, paragraf. 3.Kısa hikâye, kıssa. 4.Yazılmış kısa bir haber; gazetelerde, gündelik hâdiselerin kısa ve temiz bir üslûpla yazılmış şekli, kronik.","kategori":"hadis","osmanli":"فقره"},{"kelime":"FİKRET","anlam":"Fikretme, düşünme; düşü-nülen şey.","kategori":"dil","osmanli":"فكرت"},{"kelime":"FÎL SûRESİ","anlam":"Kur’ân-ı kerîmin yüz beşinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Beş âyet-i kerîmedir. Sûreye, Kâbe’yi yıkmak isteyen Yemen vâlisi Ebrehe’nin, arasında fillerin de bulunduğu bir orduyla hücûmunu anlattığı için, Sûret’ü-l-Fîl denilmiştir. Sûrede, İslâmiyet’ten önce de kutsal sayılan Kâbe-i Muazzama’ya karşı gi-rişilen bir saldırının fecî âkıbeti anlatılmak-tadır. (Kurtubî) (Ey Resûlüm!) Rabbinin, fil sahiplerine ne-ler ettiğini görmedin mi? O, bunların hîle-lerini boşa çıkarmadı mı? Onların üzerine bölük bölük kuşlar gönderdi. Ki bunlar, on-lara (fil sahiplerine) pişkin tuğladan (yapılmış) taşlar atıyordu. Derken (Allahü teâlâ) onları yenik ekin yaprağı gibi yapıverdi. (Âyet: 1-5)","osmanli":"سى سوره فيل"},{"kelime":"FİLÂNCA","anlam":"Metin veya söz arasında ismi bilinmeyen yâhud zikredilmek istenmeyen veya herhangi bir şahsı ifade etmek için kullanılan tabir.","kategori":"tasavvuf","misal":"Felân, felâne, fülân, fülâne.","osmanli":"فلانجه"},{"kelime":"FİLASTER","anlam":"Yaranın üzerine konan yapışkan bez şerit.","kategori":"dil","osmanli":"فلاستر"},{"kelime":"FİNÂ","anlam":"1.Avlu. 2.Evin veya şehrin, köyün önü, kenarı.","kategori":"miras","misal":"Finâ ve kasabadakilerin kullandıkları deniz ve göl kısımları şehirden sayılır. Seferî sayılmak için şehrin finâsını, yani büyük mezarlıklar (fabrika, mektep, kışlalar) ve kasabadakilerin harman yapmak, hayvan koşturmak, eğlenmek için devamlı kullandıkları yerleri de aşmak lâzımdır. Finâ iki yüz metreden daha uzakta ise veya arada tarla varsa şehirden sayılmaz. Böyle köyleri aşmak lâzım değildir. Yalnız finâyı aşmakl…","osmanli":"فناء"},{"kelime":"FİRÂK","anlam":"Ayrılık.","kategori":"dil","osmanli":"فراق"},{"kelime":"FİRÂR","anlam":"Kaçma, savuşma, izinsiz ola-rak ortadan kaybolma.","kategori":"dil","osmanli":"فرار"},{"kelime":"FİRÂRÎ","anlam":"Kaçak, kaçkın.","kategori":"dil","osmanli":"فرارى"},{"kelime":"FİRÂSET","anlam":"1.Anlayışlılık, olacakları çabuk sezme, ferâset, dıştan içi anlama. 2.At terbiyeciliği, binicilik. 3.Yiğitlik.","kategori":"dil","misal":"Mü’minin firâsetinden korkunuz. Zîrâ o, Allahü teâlânın nûru ile bakar. (Hadîs-i şerîf-Tirmizî, Taberânî) Firâset iki türlüdür: Birincisi, ma’rifet sâhible-rinin firâseti olup, talebenin isti’dâdını keşf et-mek, Allahü teâlânın Evliyâsını tanımakdır. İkincisi, riyâzet çeken, açlıkla nefslerini parla-tanların firâseti olup, mahlûklara âid gizli şey-leri bilmektir (Menâzilüssâyirîn).) Firâset, sâlih kimseleri ayırabilmek ve tanıya-bilmektir. (Mektûbât-ı Ma’sumiyye)","osmanli":"فراست"},{"kelime":"FİRDEVS","anlam":"1.Bostan, bahçe. 2.Sekiz Cennet’in altıncısı.","kategori":"akaid","misal":"Hakîkaten îmân edip de iyi amel ve harekette bulunanlar (var ya), onların konakları da Firdevs Cenneti’dir. (Kehf sûresi: 107) Cennet’te yukarıya doğru birbirlerinin üstünde bulunmak sûretiyle yüz derece ve mertebe vardır. Genişlikleri de çok fazladır. Firdevs, makam bakımından en âlâsıdır. Cennet’in dört nehri olan bal, süt, su, şarap (Cennet şarabı) Firdevs’ten akar ve o Firdevs’in üstünde arş-ı âlâ vardır. Öyle i…","osmanli":"فردوس"},{"kelime":"FIRKA","anlam":"1.Bölük, cemâat, topluluk. 2.Ferik kumandasındaki askerî birlik, tümen ve kolordu.","kategori":"dil","misal":"Ey Peygamberim! Dinde fırka fırka ayrılanlarla senin hiç bir alâkan yoktur. Onların cezâlarını Allah verecektir. Kıyâmet günü Allahü teâlâ, dünyada işlediklerini onlara hatırlatacaktır. (En’âm sûresi: 159) Benî İsrâil, yetmiş bir fırkaya ayrılmıştı. Bunlardan yetmişi Cehennem’e gidip, ancak bir fırkası kurtulmuştur. Nasârâ (Hristiyanlar) da yetmiş iki fırkaya a…","osmanli":"فرقه"},{"kelime":"Fırka-i Dâlle","anlam":"“Yolunu şaşırmış topluluk” mânâsına âyet-i kerîme ve hadîs-i şerîflere kendi görüşlerine göre mânâ vererek, icma’yı terk eden ve böylece Ehl-i sünnet ve cemaat yolundan ayrılıp dalâlete (yanlış ve bozuk yollara) sapmış fırkalardan her biri.","kategori":"dil","osmanli":"ضاله فرقه"},{"kelime":"FİRKAT","anlam":"Ayrılık.","kategori":"dil","osmanli":"فرقت"},{"kelime":"FİŞENK","anlam":"Saçma, av tüfeklerinin kul-landığı mühimmat, fişek.","kategori":"dil","osmanli":"فشنﮓ"},{"kelime":"FISK","anlam":"İsyan, haddini aşma; günahkâr-lık, günah işleme.","kategori":"dil","misal":"Allah size îmânı sevdirdi, onu kalbinize yer-leştirdi ve size; küfrü, fısk olan işleri ve is-yânı çirkin gösterdi. (Hücurât sûresi: 7) Bir Müslümana sövmek fısktır. (Hadîs-i şerîf-Müs-lim, Müsnedü Ahmed) Her işte nefsin arzularına uymak, nefse ta-pınmak olur. Nefsine uyan, küfre veya bid‘ate, dinden olmayan bir işin içine yâhud fıska dü-şer. (Berîka)","osmanli":"فسق"},{"kelime":"Fısk Meclisi","anlam":"Günah işlenen yer. Müslümanların, zarûret olmadıkça, fısk meclislerinde, yani fâsıkların toplandığı yerde","kategori":"osmanli","misal":"oturmaları ve zevcelerini buraya göndermeleri câiz değildir (Bezzâziyye) İçki, kumar, çalgı bulunan, kadın erkek beraber oturulan yerlere gitme ve zevceni, çocuklarını gönderme! Böyle yerlere fısk meclisi denir. (Miftahü’l-Cenne)","osmanli":"مجلسى فسق"},{"kelime":"FİTİL","anlam":"(Bkz. Fetîl)","kategori":"dil","osmanli":"فتيل"},{"kelime":"FİTNE","anlam":"1.Belâ, sıkıntı. 2.Ayartma, azdırma. 3.Fesad, karışıklık, kargaşa, ihtilâl. 4.Dinsizlik, sapkınlık, 5.Aklını kaçırma. 6.Çok güzel kadın.","kategori":"osmanli","misal":"Fitne, adam öldürmekten daha kötüdür. (Bakara sûresi: 191) Fitne uykudadır; uyandırana Allah lânet etsin! (Hadîs-i şerîfRâfiî) Fitne, müslümanlar arasında bölücülük yapmak, onları sıkıntıya, zarara, günaha sokmak, insanları hükûmete karşı isyâna kışkırtmak demektir. Zâlim olan hükûmete de itâ’at etmek vâcibdir. Şeriate uymayan emrlerine de, fitneye, fesâda sebeb olmamak için karşı gelmemeli, isyân etmemelidir. (Berî…","osmanli":"فتنه"},{"kelime":"FITR","anlam":"Oruç açma; yemek yeme; kahvaltı.","kategori":"ibadet","osmanli":"فطر"},{"kelime":"FITRA","anlam":"İhtiyâcı olan eşyadan ve borçlarından fazla olarak nisâb mikdarı malı, parası olan her hür Müslümanın Ramazan bayramının birinci günü sabahı fakirlere vermekle mükellef olduğu muayyen mikdardaki buğday veya arpa yâhud hurma veya kuru üzüm veya kıymetleri kada…","kategori":"fikih","misal":"Fıtra olarak 1750 gr. buğday veya buğday unu veya 3500 gr. arpa veya bu mikdar hurma veya kuru üzüm verilir. Bunların kendisi verilebildiği gibi, kıymeti kadar altın veya gümüş de verilebilir. Buğday, un vermek gücü olursa bunların kıymeti kadar ekmek verilebilir. Ekmek verirken, ağırlığına değil, parasına, kıymetine bakılır. Hanefî’de kıymeti çok olanı, Şâfiîde buğday vermek efdaldir, daha iyidir. (Tahtâvî) Fıtra,…","osmanli":"فطره"},{"kelime":"FITRAT","anlam":"1.Hilkat, yaratılış, tabiat, mizac. 2.İslâmiyet’e elverişli yaratılma. 3.Sünnet.","kategori":"akaid","misal":"Resûlullah sallallahü teâlâ aleyhi ve sellem bir-gün Ebû Bekr’e radıyallahü anh esrârdan anla-tıyordu. Ömer radıyallahü anh yanlarına ge-lince, sözü değiştirdi. Osmân radıyallahü anh gelince, daha da değiştirdi. Alî radıyallahü anh gelince, başka şeyler anlatmağa başladı. İsti’dâd-ları, fıtratları başka olduğu için, böyle yapdı. (Mektûbât-ı İmâm-ı Rabbânî) Bütün çocuklar, fıtrat üzere dünyaya gelir. Bunları sonra anaları, babaları Hristiyan, Yahudi ve Mecûsi yapar. (Hadîs-i şerîf-Buhârî) On şey fıtrattandır: Bıyığı kısaltmak, sakalı uzatmak, misvâk kullanmak, mazmaza (ağzı yıkamak), istinşak (burnu yıkamak), tırnak kesmek, ayak parmaklarını yıkamak, kol-tuk altını temizlemek, kasıkları temizlemek, su ile istincâ (önden ve arkadan çıkan necâ-seti temizlemek). (Hadîs-i şerîf-Müslim, Ebû Dâvûd, Tirmizî)","osmanli":"فطرت"},{"kelime":"FITRÎ","anlam":"Fıtratla alâkalı, tabîî, yaradı-lıştaki, yaratılışı gereği.","kategori":"dil","osmanli":"فطرى"},{"kelime":"FİYAT","anlam":"Pahalar, değerler, kıymetler, bir malın piyasa değeri, satan ile alan arasında uyuşulan, anlaşılan kıymet.","kategori":"fikih","osmanli":"فيئات"},{"kelime":"FRANSİSKEN","anlam":"On üçüncü asırda Assis’li Aziz Françesko tarafından kurulan bir Hristiyan tarikatı.","kategori":"dil","osmanli":"فرانسسكن"},{"kelime":"FuÂD","anlam":"1.Kalb, gönül. 2.Tasavvufta ilâhî tecellileri seyretme mahalli.","kategori":"tasavvuf","osmanli":"فؤاد"},{"kelime":"FÜCûR","anlam":"Azmak, günaha dalmak. Andolsun nefse fücûr ve takvâyı ilhâm edene! (Şems sûresi: 8) Yalandan sakının. Zira ya-lan fücûra; fücûr ise ateşe götürür. (Hadîs-i şerîf-Müslim, Ebû Dâvûd)","kategori":"hadis","misal":"Fücûr sahipleri dünya lezzetlerine düşkün olur. İslâmiyet’in ve aklın beğenmediği taşkınlıkları yapar. Yimekte, içmekte ve evlenmekte dinde mekrûhlara ve haramlara sapar. Çirkin, kötü işlerden zevk alır. (Ahlâk-ı A’lâî)","osmanli":"فجور"},{"kelime":"FuDûL","anlam":"İhtiyaçtan fazla şeyler. Fadl’ın çokluk hâli.","kategori":"dil","misal":"İnsanın kullandığı şeyler beşe ayrılır. Bunlar zaruret, ihtiyaç, menfaat, zînet ve fudûldür. Kullanılmadığı zaman helâke sebeb olan yasak şeyi kullanmak zaruret olur. Aç kalanın ölme-yecek kadar leş yemesi, abdest alırken elbiseye su sıçraması, hayvan idrar yaparken, üstün-dekinin elbisesine sıçraması zarurettir. Kulla-nılmaması sıkıntıya, meşakkate sebeb olursa, ihtiyaç denir. Fâidesi, menfeati olmayıp, yal-nız gösteriş için kullanılan şeye, zînet denir. İhtiyaç olunca, orucu bozmak câiz olur. Buğ-day ekmeği, koyun eti, yağlı yemek, menfeattir. Tatlı yemek, zînettir. Mübahları kullanmakta taşkınlık, fudûldur. (Uyûnü’l-Besâir) Mübahların fazlası, haramlara yakındır. Şeytâ-nın aldatması ile biraz daha aşırı gidilirse, ha-rama düşülür. Bunun için mübahları, zaruret olduğu kadar yapmak lâzımdır. Böyle yapınca, ayak kayarsa, fudûle düşülür. Eğer, fudûl işler-ken ayak kayıp, dışarı taşılırsa, harama düşü-lür. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"فضول"},{"kelime":"FuKAHÂ","anlam":"Fıkıh âlimleri. Fakîh’in çok-luk şekli. (Bkz. Fakîh)","kategori":"dil","osmanli":"فقهاء"},{"kelime":"Fukahâ-i Seb‘a","anlam":"Tâbiîn devrinde Medîne-i Münevvere’de yetişen en büyük yedi fıkıh âlimi.","kategori":"dil","misal":"Fukahâ-i seb’a şunlardır: Sa’îd bin Müseyyib, Kâsım bin Muhammed bin Ebî Bekr, Urve bin Zübeyr, Hârice bin Zeyd, Ebû Seleme bin Abdurrahmân bin Avf, Ubeydullah bin Utbe ve Ebû Eyyûb Süleymân. (Vefeyâtü’l-A’yân)","osmanli":"سبعة فقهاء"},{"kelime":"FuKARÂ","anlam":"Malı olmayanlar, yoksullar, fakirler. Fakîr’in çokluk hâli.","kategori":"dil","osmanli":"فقراء"},{"kelime":"FÜLK","anlam":"Gemi, filika; sandal, kayık.","kategori":"dil","osmanli":"فلك"},{"kelime":"FÜLûS","anlam":"Altın ve gümüşten olmayan mâdenî paralar, pullar, mangırlar. Fels’in ço-ğulu. (Bkz. Fels)","kategori":"dil","osmanli":"فلوس"},{"kelime":"FuRKÂN","anlam":"1.İyi ile kötü, doğru ile yan-lış arasındaki farkı gösteren. 2.Doğru ile yan-lışın arasına ayırdığı için Kur’ân-ı Kerîme ve-rilen isim.","kategori":"dil","osmanli":"فرقان"},{"kelime":"FuRKÂN SûRESİ","anlam":"Kur’ân-ı kerîmin yirmi beşinci sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Yetmiş yedi âyet-i kerîmedir. Hakkı bâtıldan ayıran mânâsına Kur’ân-ı kerîmin isimlerinden olan ve birinci âyet-i kerîmede geçen Furkân kelimesi, sûreye isim olmuştur. Sûrede; Kur’ân-ı kerîmin gönderilmesinin hikmetleri, müşriklerin Kur’ân-ı kerîm ve Resûl-i ekremin karşısındaki inâdcı tavırları, Allahü teâlânın kudret ve azameti, peygamberlik, kıyâmet hâlleri, hâlis mü’minlerin husu…","osmanli":"سى سوره فرقان"},{"kelime":"FÜRû‘","anlam":"1.Dallar, asıldan türeyenler. 2.Çocuklar, torunlar ve onların çocukları. 3.Ahkâm-ı şer’iyyenin ibâdet, münâkehât (aile), muâmelât (alış-veriş) ve ukûbâtla (cezâ) alâ-kalı hükümleri.","kategori":"dil","misal":"Fer‘in çokluk şeklidir. Miras hukukunda zevül-erham denilen akraba on sınıftır. Birinci sınıfı ölenin fürû‘u olup, kı-zının çocukları ve oğlunun kızının çocukları ve bunların çocuklarıdır. (Mevkûfât)","osmanli":"فروع"},{"kelime":"FuSSİLET SûRESİ","anlam":"Kur’ân-ı kerîmin kırk birinci sûresi. Secde sûresi ve Hâ mîm de denir.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Elli dört âyet-i kerîmedir. Üçüncü âyet-i kerîmede, “izah olundu” mânâsına Fussilet kelimesi sû-reye isim olmuştur. Sûrede; Kur’ân-ı kerîme inanmayan müşriklerin lâyık oldukları cezâ-lar, geçmişteki inkârcı kavimlerin başlarına gelen musîbetler, Allahü teâlânın varlığı ve birliği, Kur’ân-ı kerîmin indirilişindeki hik-metler, müslümanların ahlâkı, dünya ve âhiret mertebeleri anlatılmaktadır. (Mefâtihü’l-Gayb) Kim Fussilet sûresini okursa, Allahü teâlâ her harfine on sevab verir. (Hadîs-i şerîf- Beydâvî)","osmanli":"سى سوره فصلت"},{"kelime":"FÜTÜHÂT","anlam":"Zaferler, zaptedilen memleketler. Fethler mânâsına fütûh’un da çokluk hâli.","kategori":"dil","osmanli":"فتوحات"},{"kelime":"FÜTÜVVET","anlam":"Merdlik, insanlık, cö-mertlik, âhilik.","kategori":"dil","misal":"Dostların aybını örtmesi, bilhassa, düşmanla-rının başına gelen belâlara sevinmekten sakın-ması fütüvvetin îcâblarından, gereklerindendir. (er-Riyâdü’t-Tasavvufiyye)","osmanli":"فتوت"},{"kelime":"Gaben-i Fâhiş","anlam":"Çok aldanma. Piyasadaki en yüksek satılandan altın ve gümüşte % 2,5, urûzda (ölçülen veya tartılarak satılan menkul mallarda) % 5, hayvanda % 10, akarda (gayrımenkulde) % 20’den, abdest suyu gibi ibâdet konularında lâzım olan şeylerde de piyasadaki fiyatından…","kategori":"ibadet","misal":"Bâyi’ (satıcı), bu mala, şu kadar lira veren oldu deyip, satsa, sonra gaben-i fâhiş olduğu ve başkası, o kadar lira vermediği anlaşılsa, müşteri (alıcı) bey’i (satışı, alışverişi) feshedebilir, bozabilir. (Mecelle) Yolculukta, su, gaben-i fahişle satılırsa veya piyasa fiyatı ile alacak fazla parası yok ise, namazını teyemmüm ile kılması câiz olur. (İbni Âbidîn)","osmanli":"فاحش غبن"},{"kelime":"Gaben-i Yesîr","anlam":"Az aldanma. Ga-ben-i fâhişteki mikdarlardan daha az olan al-danma. Piyasadaki en yüksek satılandan altın ve gümüşte % 2,5, urûzda (ölçülen veya tartı-larak satılan menkul mallarda) % 5, hayvanda","kategori":"dil","misal":"% 10, akarda (gayrımenkulde) % 20’den, ab-dest suyu gibi ibâdet konularında lâzım olan şeylerde de piyasadaki fiyatından iki mislin-den az olan aldanma. Vekil, değeri bildirilmeyen malı, gaben-i yesîr ile alabilir. Fakat, et, ekmek, şeker gibi kıy-meti meşhur şeylerde gaben-i yesîr afv olmaz. Gaben-i fâhiş ile alınan malı, sahibi kabul et-meyebilir. (İbni Âbidîn)","osmanli":"يسير غبن"},{"kelime":"GABÎ","anlam":"Gabâvet sahibi, anlayışsız, kaba.","kategori":"dil","osmanli":"غبى"},{"kelime":"GADÂ’","anlam":"Sabah veya öğle yemeği.","kategori":"dil","osmanli":"غداء"},{"kelime":"GADR","anlam":"Hâinlik; vefasızlık, verdiği sözde durmamak; zulüm, haksızlık.","kategori":"dil","misal":"Dört şey münâfıklık alâmetidir: Emânete hıyâ-net etmek, yalan söylemek, va’dini bozmak ve ahdine gadr etmek, mahkemede doğruyu söylememek. (Hadîs-i şerîf-Buhârî, Tirmizî)","osmanli":"غدر"},{"kelime":"GAFFÂR","anlam":"Günah, kusur ve kabahatları çok bağışlayan, çok çok mağfiret eden mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elGaffâr).","kategori":"akaid","misal":"Şüphe yok ki ben, tövbe eden, îmân edip sâlih amel işleyen, sonra da hak yolda sebât gösteren ve buna devam eden kimseye Gaffârım. (Tâhâ sûresi: 82) Cum‘a namazından sonra yüz defâ elGaffâr ism-i şerîfini söyleyen, Allahü teâlânın af ve mağfiretine kavuşur. (Elİstigâsetü’l-Kübrâ)","osmanli":"غفار"},{"kelime":"GÂFİL","anlam":"Gaflette olan, unutan; endişe-siz; ihmâl eden; boş bulunan, dalgın, dikkatsiz. Kabul edileceğine yakînen inanarak duâ edin. Ve biliniz ki Allah gafil ve boş şey-lerle dolu bir kalb (sahibinin) ettiği duâyı kabul etmez. (Hadîs-i şerîf-Tirmizî) Gâfiller arasında Allahü teâlâyı zikreden, cepheden kaçanlar olduğu hâlde muhârebede sebat eden kimse gibidir. (Hadîs-i şerîf-Taberânî)","kategori":"hadis","osmanli":"غافل"},{"kelime":"GAFLET","anlam":"Unutmak, endişesizlik, ih-malkârlık, boş bulunma, dalgınlık, dikkatsizlik. (Ey Resûlüm!) Onları iş bitirildiği (hesâb gö-rüldüğü) zamanın dehşeti ile korkut. Onlar hâlâ gaflet içindedirler. Onlar îmân etmi-yorlar. (Meryem sûresi: 39) Ey insanlar! Öl-meden önce gafleti bırakın, Allahü teâlâya dönün. Tövbe istiğfâr ederek Allah’a kul-luk edin. Sizi oyalayıcı işleriniz çoğalma-dan yararlı işler yapmaya gayret edin. Al-lahü teâlâyı çok çok anın. Rabbinizin rızâsını kazanmaya çalışın. Böyle yaparsanız, rızkı-nız bol olur. Kazancınız çoğalır. Yardım gö-rürsünüz ve eksikleriniz tamamlanır. (Ha-dîs-i şerîf-İbn-i Mâce)","kategori":"dil","osmanli":"غفلت"},{"kelime":"GALÂ","anlam":"Pahalılık.","kategori":"dil","osmanli":"غلاء"},{"kelime":"GALAT","anlam":": Yanlışlık, yanılma.","kategori":"dil","misal":"İncîlin ibâresi, Yunancada güzel ve düzgün bir şekildedir. İçinde galat, yanlış lafzlar yok-tur. Fakat, Müşâhedât kitâbının ibâresi böyle olmayıp, Yunan lehçesine muhalif, bilinme-yen, alışılmamış bir üslûb üzerine yazılmıştır. (Dıyâü’l-Kulûb)","osmanli":"غلط"},{"kelime":"GAMÂRÂ (Gemara)","anlam":"Yahudilerin Hazret-i Mûsâ’ya verilen sözlü emirlerden teşek-","kategori":"dil","misal":"kül ettiğine inandıkları ve Tevrat’tan sonra mukaddes saydıkları Talmûd’un metni olan Mişna’nın şerh kısmı. Gemara, Arami dilinde tamamlayıcı demektir.","osmanli":"غماره"},{"kelime":"GAMM","anlam":"Keder, tasa, kaygı, dert, üzüntü. Belâ Allahü teâlâdan gelir. Belâdan kurtaran da, O’dur. Ona ilticâ edilirse, hiç gam kalmaz. Duâ etmemek, gamların en büyüğüdür. (Mek-tûbât-ı Ma’sûmiyye)","kategori":"akaid","osmanli":"غم"},{"kelime":"GANÎ","anlam":"1.Gınâ sahibi, zengin, muhtaç olmayan. 2.Hiçbir zamanda, hiçbir mekânda, hiçbir hâlde, hiçbir şeye muhtaç olmayan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Ganî). O’na bir yol bulabilenlerin (gücü yetenlerin) Beyti (Kâbe-i Muazzama’yı) hac (ve ziyaret) etmesi, Allahü teâlânın insanlar üzerinde bir hakkıdır. Kim küfrederse, şüphesiz ki Allahü teâlâ âlemlerden ganîdir. (Âl-i İm-rân sûresi: 97) Rabbin her şeyden ganîdir ve rahmet sahibidir. Eğer dilerse (ey müşrikler) sizi giderir (ortadan kaldırır), arkanızdan da yerinize dileyeceğini getirir. Nitekim sizi de başka başka bir kavmin neslinden peydâ et-miştir. (En’âm sûresi: 133) Allahü teâlâ ganîdir. İnsanlara acıdığı için, on-lara ihsânı olarak emir ve yasaklarını bildir-miştir. Emirlerin ve yasakların faydaları insan-laradır. Allahü teâlâya faydası yoktur. Allahü teâlânın bunlara ihtiyâcı yoktur. Allahü teâlâ Ganiy-yi mutlaktır. Ne kendine, ne sıfatlarına, ne de fiillerine hiçbir sûretle, hiçbir şey lâzım değildir. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"dil","misal":"Kim istiğnâ ederse (elindeki ile yetinip kim-seden bir şey istemezse) Allah onu ganî kılar. (Hadîs-i şerîf-Tirmizî, Hakîm)","osmanli":"غنى"},{"kelime":"GANÎM","anlam":"Ganimet alan, bir harbe muharib olarak katılan ve ganimete hak kazanan mücâhid.","kategori":"akaid","osmanli":"غنيم"},{"kelime":"GANÎMET","anlam":"Harpte düşmandan elde edilen mal.","kategori":"dil","misal":"Şimdi elde ettiğiniz ganimetten helâl ve hoş olarak yiyin. (Enfâl sûresi: 69) Ganimetler bana helâl kılındı. Benden önce hiç kimseye helâl kılınmadı. (Hadîs-i şerîf-Buhârî-Müslim) Düşmandan alınan ganimet, dârülislâma geti-rilince, askerin hakkı olur. Fakat, taksim edil-meden önce mülk olmaz. Ganimetin beşte biri beytülmâle (hazîneye) verilir. Geri kalanı as-kere dağıtılır. (İbni Âbidîn)","osmanli":"غنيمت"},{"kelime":"GARANTİ","anlam":"Teminat.","kategori":"ibadet","osmanli":"غرانتى"},{"kelime":"GARB","anlam":"Güneşin gurub ettiği taraf, batı.","kategori":"dil","osmanli":"غرب"},{"kelime":"GARGARA","anlam":"1.Suyu ağızda çalka-lama. 2.Ölüm anında canın boğaza dayanması.","kategori":"dil","misal":"GARÎB: غريب (A) Gurbette, yabancı, memleke- tinden uzakta, kimsesiz. Garîb hastalanır, dört yanına bakınır da, ta-nıdık bir kimse göremezse, Allah onun geç-miş günahlarını affeder. (Hadîs-i şerîf-Deylemî) Dünyada garîb veya yolcu gibi ol ve ken-dini ölmüş say. (Hadîs-i şerîf-Buhârî, Müslim)","osmanli":"غرغره"},{"kelime":"GARÎM","anlam":"1.Garâmet ehli, alacaklı. 2.Hasım, rakib.","kategori":"miras","misal":"Meyyitin borcu terekeden çok ise dâyin yani garîm (alacaklı) bir ise, terekenin hepsi ona verilir. Çok iseler, tereke, alacakları ile orantılı olarak hepsine dağıtılır. (Dürerü’l-Hükkâm)","osmanli":"غريم"},{"kelime":"GARûR","anlam":"Mal, mevki, şehvet gibi in-sanı aldatan her şey.","kategori":"dil","osmanli":"غرور"},{"kelime":"GASB","anlam":"Başkasının malını izinsiz al-mak veya alıkoymak.","kategori":"dil","misal":"Müslümana zulmedip de hakkını gasbedene yazıklar olsun. (Hadîs-i şerîf-Ebû Nuaym) Gasb, bir kimsenin malını zor ile almak veya kendindeki emânet malı inkâr etmektir. Büyük günahtır. Malda değişiklik oldu ise, sahibi, malı ile kıymetindeki değişikliği veya yalnız kıymetini ister. Gasb ettiği yerde ödemesi lâzım olur. Tazmînden sonra kullanması câiz ise de, satarak ettiği kâr yine helâl olmaz. Kârı sadaka vermesi lâzımdır. Muhtelif kimselerden gasb ettiklerini birbirleri ile veya kendi mülkü ile karıştırır ve ayrılamazlarsa, hepsi kendi habîs mülkü olur. Fakat, tazmîn etmedikçe, bu karışımı kullan-ması helâl olmaz. Tazmîn etmekle, gasb güna-hından kurtulmaz. (İbni Âbidîn)","osmanli":"غصب"},{"kelime":"GÂSIB","anlam":"Başkasının malını elinden veya tasarrufu dairesinden zorla veya haksız yere alan, gasbeden.","kategori":"dil","osmanli":"غاصب"},{"kelime":"GÂSİL","anlam":"Gasleden, cenâze yıkayıcısı.","kategori":"ibadet","osmanli":"غاسل"},{"kelime":"GASL","anlam":"Yıkamak; cenâzeyi yıkamak.","kategori":"ibadet","misal":"Âdem aleyhisselâm vefât edince, melekler Cennet’ten hanût ve kefen getirdiler. Su ve sedir yaprağı ile gasl ettiler. Üçüncüsünde kâfûr koydular. Üç kefen ile kefenlediler. Namazını kıldılar. Lahd yaparak, mezârın içinde kıble tarafını biraz açtılar. Defnettiler. Sonra çocuklarına dönerek, ey Âdemoğulları! Ölülerinize böyle yapınız!” dediler. (Sa’lebî, Mirhond, Mir’at-ı Kâinât) Meyyiti gasletmek, kefenlemek, cenâze n…","osmanli":"غسل"},{"kelime":"GAVS","anlam":"1.Yardım eden. 2.Evliyâ arasında gıyâset makamına erişen ve darda kalmış kullara yardımla vazifelendirilen zât.","kategori":"tasavvuf","misal":"Duayı kabul eden, yalnız Allahü teâlâdır. Buna sebeb, vesile olan, Peygamberdir. Allahü teâlâ, hakikî gavsdır. Resûlullah, mecâzî gavs olmaktadır. (Cevherü’l-Munzam) Muhyiddin-i Arabi hazretlerine göre, gavs, kutb-i medar demektir. Ayrıca bir gavslık makamı yoktur, demiştir. Bu fakirin inandığına göre gavs, kutb-i medardan başkadır. Kutb, işlerinin birçoğunda, gavsdan yardım ister. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"غوث"},{"kelime":"Gavs-ı A‘zâm","anlam":"“Büyük gavs” mânâsına Abdülkâdir Geylânî hazretlerinin lakabı.","kategori":"dil","misal":"Gavsü’l-A’zâm.","osmanli":"اعظم غوث"},{"kelime":"GÂVuR","anlam":"1.Müslüman olmayan, îmânsız. 2.Kötü kimse.","kategori":"akaid","misal":"Aslı Farsca gebr veya Arabca kâfir. (Bkz. Kâfir)","osmanli":"ﮔاوور"},{"kelime":"GAYB","anlam":"1.Hazır olmayan, gizli, göze gö-rünmeyen, kayıp. 2.Belirsiz, bilinmeyen şey-ler; his uzuvları ile anlaşılamayanlar.","kategori":"dil","misal":"Gaybları ancak Allahü teâlâ bilir. O’ndan başka kimse bilemez. (En’âm sûresi: 59) Onlar gayba îmân ederler. (Bakara sûresi: 3) Gayb-ları bilen yalnız O’dur (Allahü teâlâdır). Bil-diği gizli şeylerden dilediği kadarını yalnız peygamberlerinden istediğine açıklar. (Cin sûresi: 26) Gayb olan şeyler beştir. Onları yal-nız Allahü teâlâ bilir. Ana rahminde olanı, yarın ne olacağını, ne zaman yağmur yağa-cağını, nerede ve ne zaman öleceğini, kıyâ-metin ne zaman kopacağını. (Hadîs-i şerîf-Buhârî-Müslim) Cinlerin hâlleri, yaşayışları, insanlar için gayb-dır. Uzak yerlerdeki şeylerin hâlleri cinler için gayb olmadığı hâlde, insanlar için gaybdır. Bun-dan dolayı bazı kimseler, cinlerin gaybı bildi-ğini iddiâ etmişlerdir. Hâlbuki onlar, görmedik-lerini değil, gördükleri şeyi bilirler. Eğer cinler gaybı bilselerdi, Süleymân aleyhisselâm onları çalıştırırken, vefât ettiğinde, onun vefâtını da bilirlerdi. Hâlbuki bilememişlerdir. Yine semâ-lardaki şeyler, semâ ehline (meleklere) göre gayb olmadığı hâlde, insanlara gaybdır. Aynı şekilde doğudaki şeyler de batıdakilere göre gaybdır. Bu kısım gayb bazen vahy ve ilhâm ile, bazen aradan perdelerin kaldırılması veya bunların şeffaflaştırılması sûretiyle bilinir. Perdelerin kaldırılması şeklindeki bilme, mûcize ve kerâ-met kâbilinden olsa bile, gaybı bilme değil, gör-düğünü bilmektir. (Tefsir-i Mazharî)","osmanli":"غيب"},{"kelime":"GÂYE","anlam":"Maksat; netice, son; hedef.","kategori":"dil","osmanli":"غايه"},{"kelime":"GÂYET","anlam":"1.Nihayet, uç, son. 2.Çok, fazla, son derece.","kategori":"dil","osmanli":"غايت"},{"kelime":"GAYR","anlam":"1.Ayrı, başka, diğer, değil. 2.Yabancı, bildik olmayan. 3.Arabca sıfatla-rın başında gelen ve “-sız”, “değil” mânâsını taşıyan nefî edatı.","kategori":"akaid","misal":"Allahü teâlânın sekiz sıfat-ı sübûtiyyesi, zâtı-nın aynı da değildir, gayrı da değildir. Yani sı-fatları, kendisi değildir. Kendisinden başka da değildir. (İtikadnâme)","osmanli":"غير"},{"kelime":"Gayr-ı Ahlâkî","anlam":"Ahlâksızca, ahlâk ve edep dışı.","kategori":"tasavvuf","osmanli":"اخلاقى غير"},{"kelime":"Gayr-ı İhtiyârî","anlam":"Düşünmeden, istemeksizin, elinde olmayarak, ister istemez. Gayr-ı Lâzım: لازم غير (A) Bağlayıcı olmayan,","kategori":"dil","misal":"muhayyer, kendisinden dönülebilen (akid).","osmanli":"اختيارى غير"},{"kelime":"Gayr-ı Menkûl","anlam":"Arâzî, tarla, arsa veya buna bağlı olarak bina, ağaç gibi taşınmaz mallar, akar.","kategori":"muamelat","misal":"Menkullerden farklı olarak gayrımenkuller, kabz edilmeden başkasına satılabilir, kirâya verilebir. Şüf ’a hakkı yalnız bunlarda cereyan eder. borçlunun malının satışına menkullerden başlanır. Gayrımenkullerde gaben mikdarı da farklıdır. (İbni Âbidîn)","osmanli":"منقول غير"},{"kelime":"Gayr-ı Mu‘ayyen","anlam":"Mu‘ayyen olma-yan, tesbit edilmemiş.","kategori":"dil","osmanli":"معين غير"},{"kelime":"Gayr-ı Müekkede","anlam":"1.Te’kid edil-mişin dışında, kuvvetli olmayan. 2.Hazret-i Peygamber’in sünnetinden ikindi ve yatsı na-mazının ilk sünneti gibi devamlı değil de ara sıra yaptıkları.","kategori":"akaid","osmanli":"مؤكده غير"},{"kelime":"Gayr-ı Mümkin","anlam":"Olamaz, im-kân harici.","kategori":"dil","osmanli":"ممكن غير"},{"kelime":"Gayr-ı Müslim","anlam":"Müslüman olmayan. Müslüman olsun, gayr-i müslim olsun hiçbir insanın malına, canına ve ırzına, nâmusuna dokunmak câiz (uygun) değildir.","kategori":"fikih","misal":"(Berîka)","osmanli":"مسلم غير"},{"kelime":"GAYRET","anlam":"1.Kıskançlık, çekememe; bir kimseden zararlı şeylerin ayrılmasını istemek, bunları kabul etmemek, mukaddes ve muh-terem bir şeye yapılan hürmetsizliğe razı ol-mama; titizlik, hassasiyet. Gayret imandan, deyyusluk ise münafıklık-tandır. (Hadîs-i şerîf-Beyhekî) İlmini; mal, mevkî ele geçirmek, günah işlemek için kullanan din adamından ilmin gitmesini is-temek gayret olur. Malını; haramda, zulümde, İslâmiyet’i yıkmada, bid‘atleri ve günahları yay-makta kullananın malının yok olmasını istemek hased olmaz, din gayreti olur. (Berîka) 2.Fevkalâde çalışma, çabalama.","kategori":"dil","osmanli":"غيرت"},{"kelime":"GAYZ","anlam":"Hiddet, öfke, kızma, kızgın-lık; hınç.","kategori":"dil","misal":"Münkirlerden birine, Allah’a isnat ettiği kız evlat müjdelenince, o kimsenin içi gayzla do-larak yüzü simsiyah kesilir. (Zuhruf sûresi: 17)","osmanli":"غيظ"},{"kelime":"GAZÂ","anlam":"Allah yolunda muharebe.","kategori":"akaid","misal":"Gazve. Allah yolunda gazâda bir saat bulunmak, evinde bütün ömrünce nâfile ibâdet etmekten hayırlıdır. (Hadîs-i şerîfİbni Asâkir) Leşker-i gazâ, leşker-i duânın duâsına muhtaçtır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"غزاء"},{"kelime":"GAZEL","anlam":"1.Ceylan; geyik. 2.Güzel göz. 3.Edebiyatta çok kullanılan bir nazım (şiir) şekli.","kategori":"dil","osmanli":"غزل"},{"kelime":"Gecesi","anlam":"Kur’ân-ı kerîmin indirilmeye başladığı ve ulemânın ekserîsine göre Ramazân-ı şerîf ayı içerisinde bulunan mübarek gece.","kategori":"dil","misal":"Doğrusu, Biz, Kur’ân’ı Kadir Gecesinde indirdik. Kadir Gecesinin ne olduğunu sen bilir misin? Kadir Gecesi bin aydan hayırlıdır. (Kadr sûresi: 1-3) Dört gece, gündüz, dört gündüz de gece gibidir. Allah, o günlerde and verenin isteğini geri çevirmez, insanları mağfiret eder ve onlar bu günlerde bol bol ihsana nail olurlar. Bunlar: Kadir Gecesi, Kurban arefesi, Berât Gecesi, Cum‘a gecesi ve günleridir. (Hadîs-i şerîfD…","osmanli":"سى كيجه قدر"},{"kelime":"GEDİK","anlam":"1.Osmanlılarda bir şehir veya kasabada bir sanatı yapma imtiyazı. 2.Bir vakıf veya mülk dükkânda vitrin yapma mukabilinde elde edilen ve masrafları ödenmedikçe çıkarılamayan kirâcılık hakkı.","kategori":"muamelat","osmanli":"ﮔديك"},{"kelime":"GEH","anlam":"Bazı, ara sıra.","kategori":"dil","misal":"Her ten biter bir derd ile, geh germ ile geh serd ile, Uğraşmaya bir ferd ile, değmez bu dünya-yı ahes. (Sâmi Paşa)","osmanli":"ﮔه"},{"kelime":"GER","anlam":"Eğer. (Şiirde kullanılır.) Ger dilersiz kılasız oddan necât, Aşk ile şevk ile eydün essalât.","kategori":"dil","misal":"(Mevlid-i Süleymân Çelebi)","osmanli":"ﮔر"},{"kelime":"GEVHER","anlam":"Elmas, cevher; inci; değerli taş; bir şeyin aslı, esâsı.","kategori":"dil","misal":"Her gece Kadr olsa, Kadr’in kadri olmazdı şâhâ, Her hacer gevher olsa, gevher etmezdi bahâ. (Bâkî)","osmanli":"ﮔوهر"},{"kelime":"GILMÂN","anlam":"1.Genç oğlan hizmetkâr. 2.Allahü teâlânın Cennet ehline hizmet için yarattığı gençler.","kategori":"dil","misal":"(Cennet’te) Sedefteki inciler gibi gılmânlar etraflarında dönüp dolaşırlar. (Tûr sûresi: 24) Kabrimiz îmân ile pürnûr kıl, Mûnis-i Gılmân ile hem hûr kıl. (Mevlid-i Süleymân Çelebi)","osmanli":"غلمان"},{"kelime":"GINÂ","anlam":"1.Zenginlik. 2.Usanç, bezginlik. 3.Umumiyetle çalgı âleti ile beraber olan şarkı, musiki.","kategori":"dil","misal":"Gınâ sahibine tevâzû edenin, yani zengine zenginliği için alçalanın dininin üçte ikisi gider. (Hadîs-i şerîf-Deylemî) Tevâzu‘, gınâ sahiplerine yakışır; istiğnâ ise fakîrlere yaraşır. Çünki her şeyin ilâcı, zıddı iledir. (Mektûbât-ı İmâm-ı Rabbânî) Gınâ, kalbde nifâk hâsıl eder. (Hadîs-i şerîf-Dey-lemî) Gınâ, bala ve şekere karıştırılmış zehir gibidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"غناء"},{"kelime":"GİRDÂB","anlam":"Suların (veya rüzgârın) döndüğü ve çukurlaştığı yer, anafor; tehlikeli yer, dönegen.","kategori":"dil","misal":"Müslümanlar bir sebebe yapışırken, bunun, Al-lahü teâlânın yaratmasına sebeb olduğunu dü-şünür. O işi sebeblerin yapacağını düşünmez-ler. Müşrikler ise, o işi putların yapacaklarına veya Allahü teâlâya yaptıracaklarına inanır. Bu iki inanış arasını ayıramayanlar, inkâr gir-dâbına sürüklenerek helâk olmaktadırlar. (Risâ-le-i Hâlidiyye)","osmanli":"ﮔرداب"},{"kelime":"GIYBET (Gîbet)","anlam":"Bir kimsenin, yüzüne karşı söylendiği zaman hoşlanmayacağı, kalbinin kırılacağı bir sözünü, hâlini veya hareketini, arkasından, bulunmadığı yerde söylemek, hareketiyle göstermek veya îmâ etmek.","kategori":"tasavvuf","misal":"hoşlanır mı? Tiksinirsiniz. Allahü teâlâdan korkup, gıybet etmeyin, Allahü teâlâ gıybetten tövbe edenlerin tövbelerini kabul eder. O çok merhamet edicidir. (Hucurât sûresi: 12) Resûlullah efendimiz, Eshâb-ı kirâma; “Gıybetin ne olduğunu bilir misiniz?” buyurdu. Eshâb-ı kirâm; “Allah ve Resûlü daha iyi bilir” dediler. Resûl-i ekrem; “Gıybet, kardeşini, arkasından hoşlanmayacağı bir şeyle anmandır” buyurdu. Eshâb-ı ki…","osmanli":"غيبت"},{"kelime":"GÖÇEBE","anlam":"Yerleşik olmayan, belli veya belirsiz aralıklarla sürekli yer değiştiren. Bedevî.","kategori":"dil","osmanli":"ﮔوﭼبه"},{"kelime":"GÖNÜL","anlam":"Kalb, yürek.","kategori":"tasavvuf","misal":"Dünyanın görünüşü tatlıdır, lezzetlidir. Hâlbuki, hakîkatte zehirdir. Kıymetsizdir. Onun tuzağına düşen, hiç kurtulamaz. Bu zehir ile ölen, leş olur. Buna gönül vermek deliliktir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ﮔوکل"},{"kelime":"GuDDE","anlam":"Canlıların vücudundaki bezler. Kurbanın ve her hayvan etinin yedi yerini yi-mek harâmdır. Bunlar, akan kan, bevl âleti, ha-yaları (koç yumurtası), guddeleri, safra kesesi, dişi hayvanın önü ve bevl kesesi, yani mesâne-dir. (İbni Âbidîn)","kategori":"ibadet","osmanli":"غده"},{"kelime":"GuFRÂN","anlam":"Affetme, günahlarını silme, merhamet etme.","kategori":"dil","osmanli":"غفران"},{"kelime":"GuLÂM","anlam":"1.Tüyü, bıyığı çıkmamış de-likanlı, genç. 2.Genç erkek köle, esir; erkek hizmetkâr.","kategori":"dil","osmanli":"غلام"},{"kelime":"GuLÂT","anlam":"Aşırılar, taşkınlık gösterenler, azgınlar; bid‘at fırkalarından itikadı küfre varanlar.","kategori":"akaid","misal":"Gâlî’nin çokluk hâli.","osmanli":"غلات"},{"kelime":"GÜLBÂNK","anlam":"Tekkelerde, âyin sırasında ve saraylarda muayyen merasim esnâsında hep bir ağızdan çalgısız yüksek sesle okunan ilâhi veya duâ.","kategori":"ibadet","misal":"Vur pençe-i âlideki şimşir aşkına, Gülbângi âsumânı tutan pîr aşkına. (Yahya Kemal)","osmanli":"ﮔلبانك"},{"kelime":"GÜMÂN","anlam":"Zan; şüphe.","kategori":"dil","misal":"Yunus n’eyler iki cihanı sensiz, Sen hak peygambersin şeksiz gümânsız, Sana uymayanlar gider imansız, Adı güzel kendi güzel Muhammed. (Yûnus)","osmanli":"ﮔمان"},{"kelime":"GÜNÂH","anlam":"Dinin emirlerine aykırı iş.","kategori":"dil","misal":"(Bkz. Harâm)","osmanli":"ﮔناه"},{"kelime":"GuREBÂ","anlam":"Kimsesizler; yabancılar, ga-ripler. Garîb’in çokluk hâli.","kategori":"dil","osmanli":"غرباء"},{"kelime":"GÜRGÂNÎYYE","anlam":"Hindistan’da Emir Timur’un torunu Bâbür Şah tarafından kurulan büyük Türkİslâm devleti (1526-1858).","kategori":"osmanli","osmanli":"ﮔرﮔانيه"},{"kelime":"GuRûB","anlam":"Batma, görünmez olma; bir gök cisminin batması.","kategori":"dil","osmanli":"غروب"},{"kelime":"Gurûbî Sâat","anlam":"Güneşin batma-sının (gurûb etmesinin) 12 olarak kabul edil-diği ve diğer vakitlerin buna göre ayar edil-diği saat. (Bkz. Ezânî Sâat)","kategori":"ibadet","osmanli":"ساعت غروب"},{"kelime":"GÜRûH","anlam":"Cemâat, bölük, takım, in-san topluluğu.","kategori":"dil","misal":"Allahü teâlâ bütün mü’minleri Sırât üzerinden geçirir. Mü’minler derecelerine göre Cennet’e götürülür. İnsanlar gürûh gürûh geçerler. (Dür-retü’l-Fâhire)","osmanli":"ﮔروه"},{"kelime":"GuRûR","anlam":"Büyüklenme, kibir, ucub; boş şeylere güvenerek aldanma; övünme, onur. Askerine ve malına gurûr getirip, şeriat ehlin-den uzaklaşma! (Mir’at-i Kâinât)","kategori":"dil","osmanli":"غرور"},{"kelime":"GûŞ","anlam":"Kulak; işitme, dinleme.","kategori":"dil","misal":"Bir yerde ki yok nağmeni takdir edecek gûş, Tezyi-i nefes eyleme, tebdil-i makam et! (Ziyâ Paşa)","osmanli":"ﮔوش"},{"kelime":"GuSL","anlam":"Yıkanma; muayyen sebeb ve vesilelerle tepeden tırnağa kadar bütün vücudu kuru yer kalmayacak şekilde yıkama.","kategori":"ibadet","misal":"Ey iman edenler! Cünüp iken de gusül edinceye kadar namaza yaklaşmayın. (Nisâ sûresi: 43) Kim cenâbetten gusl ederken bedeninde bir kıl yeri kuru bırakırsa, ateşle muameleye maruz kalır. (Hadîs-i şerîfEbû Dâvûd) Bir kimse Cum‘a günü gusl ederse, bir haftalık günahlarına keffâret olur (Hadîs-i şerîfDeylemî, Taberânî) Gusl abdesti, onbeş nev’dir: Beşi farz, beşi vâcib, dördü sünnet, biri müstehab. Hâtunun hayz ve nifâ…","osmanli":"غسل"},{"kelime":"GuSSA","anlam":"Keder, kaygı, tasa.","kategori":"dil","osmanli":"غصه"},{"kelime":"GÜVEY","anlam":"Damat.","kategori":"dil","osmanli":"ﮔوى"},{"kelime":"GûY","anlam":"Söyleyen; yuvarlak şey, top.","kategori":"dil","osmanli":"ﮔوى"},{"kelime":"GÜZÎN","anlam":"Seçen, seçilmiş, beğenilmiş, mümtaz, müstesna, güzide.","kategori":"dil","osmanli":"ﮔزين"},{"kelime":"HÂB","anlam":"Uyku.","kategori":"dil","osmanli":"خواب"},{"kelime":"HABÂİS","anlam":"Kötü, alçak, pis şeyler, ha-ramlar. Habîsin çokluk hâli. (Bkz. Habîs)","kategori":"dil","osmanli":"خبائث"},{"kelime":"HABBE","anlam":"1.Tanecik. 2.Bir arpa ağırlığı, beş santigram ağırlığında bir ölçü.","kategori":"dil","osmanli":"حبه"},{"kelime":"HABER","anlam":"1.Herhangi bir mevzuda gelen yazılı veya sözlü bilgi. 2.Sünnet, hadîs-i şerîf. 3.Eshâb-ı kirâm, Tâbiîn ve Tebe‘-i tâbiînden bildirilen söz.","kategori":"hadis","misal":"Her hadîs-i şerîf haberdir; ancak her haber ha-dîs-i şerîf değildir. (Süyûtî)","osmanli":"خبر"},{"kelime":"Haber-i Âhâd","anlam":"Her nesilde hep bir kimse tarafından rivâyet edilen, müsned-i muttasıl (senedinde kopukluk olmayan) hadîs-i şerîf.","kategori":"hadis","misal":"Ahad hadîs.","osmanli":"آحاد خبر"},{"kelime":"Haber-i Vâhid","anlam":"(Bkz. Haber-i Âhad)","kategori":"dil","osmanli":"واحد خبر"},{"kelime":"HABÎB","anlam":"Sevgili, sevilen.","kategori":"dil","misal":"Allahü teâlâ İbrâhîm aleyhisselâmı halîl edinmiş; Mûsâ aleyhisselâmı kelîm olarak seçmiş; beni de habîb ittihaz etmiştir. Sonra şöyle buyurmuştur: İzzetim ve celâlim hakkı için ben habîbimi, halîlim ve kelîmim için seçtiğime tercih edip üstün tutarım. (Hadîs-i şerîf-Beyhekî) Öğünmek için söylemiyorum. Allahü teâlânın habîbiyim, peygamberlerin reisiyim. (Hadîs-i şerîf- Tirmizî) Afv edip isyânımız kıl rahmeti, Ol Habîbin yüzü suyu hürmeti. (Mevlid-i Süleymân Çelebi)","osmanli":"حبيب"},{"kelime":"HABÎBuLLAH","anlam":"“Allah’ın sevgilisi” mânâsına Muhammed aleyhisselâm.","kategori":"akaid","misal":"(Bkz. Habîb)","osmanli":"الله حبيب"},{"kelime":"HAÇ","anlam":"Birbirini dik olarak kesen iki doğrunun meydana getirdiği, Hristiyanlığın sembolü kabul edilen şekil.","kategori":"ibadet","misal":"Salîb. İstavroz. Çelîpâ. İnsanların doğuştan günahkâr olduğuna inanan Hristiyanlar, Îsâ aleyhisselâmın bu günahlara keffâret olarak kendini fedâ ettiğini, haça gerilmek suretiyle öldürüldüğünü kabul ederler. Haç, Îsâ aleyhisselâma yapılan işkencenin, dolayısıyla onu kurtarmanın sembolü sayılır. (Dıyâü’l-Kulûb)","osmanli":"خاﭺ"},{"kelime":"HACÂMAT","anlam":"Kan deverânını düzenleyerek vücudu rahatlatmak ve bazı hastalıkları tedavi etmek icin vücudun herhangi bir yerini hafifçe kesip, boynuz, bardak veya şişe oturtarak kan alma.","kategori":"ibadet","misal":"Hacâmatta şifâ vardır. (Hadîs-i şerîfBuhârî)","osmanli":"حجامت"},{"kelime":"HÂCÂT","anlam":"İstekler; ihtiyaçlar.","kategori":"ibadet","misal":"Hâcet’in çokluk hâli.","osmanli":"حاجات"},{"kelime":"HACC (Hac)","anlam":"1.Kasdetmek, muhterem bir yeri ziyaret istemek. 2.İcab eden şartları hâiz (bâliğ, hür, zengin, akıllı) her Müslümanın ömründe bir defâ ihramlı olarak Mekke’ye gidip Kâbe’yi ziyaret etmesi ve Arafât denilen yerde bir mikdar durması ve bazı vazifeleri yerine getirmesi. Azık ve binek bakımından yoluna gücü yeten her kimsenin o Beyt’i (Kâbe’yi) hac etmesi, insanlar üzerine Allahü teâlânın hakkıdır, farzdır. (Âl-i İmrân sûresi: 97) Hacc, güna…","kategori":"ibadet","osmanli":"حج"},{"kelime":"Hacc-ı Asgar","anlam":"Küçük hac. Hac günleri dışında, ihramlı olarak Kâbe’yi tavaf ve Safa ile Merve arasında sa’y yapıp traş olarak ihramdan çıkılmak suretiyle ifa edilen ibâdet.","kategori":"ibadet","misal":"Umre.","osmanli":"اصغر حج"},{"kelime":"Hacc-ı Ekber","anlam":"Büyük hac, farz olan hac.","kategori":"ibadet","misal":"Hacca giden Müslümanların hacı olabilmeleri için şartlarını yerine getirmeleri lâzımdır. Arefe günü Cum‘a’ya rastlarsa yetmiş hac sevâbı meydana gelir. Halk arasında buna hacc-ı ekber deniliyor. Bu söz doğru değildir. Hacc-ı ekber, farz olan hacdır. (İbni Âbidîn)","osmanli":"اكبر حج"},{"kelime":"HACCETÜ’L-İSLÂM","anlam":"Farz olan hacc.","kategori":"ibadet","osmanli":"الاسلام حجة"},{"kelime":"HÂCE","anlam":"1.Hoca, müderris, efendi. 2.Osmanlılarda Bâbıâli kâtipleri arasındaki bir rütbe.","kategori":"ibadet","osmanli":"خواجه"},{"kelime":"HÂCEGÂN","anlam":"1.Hocalar; Bâbıâli kâtibleri.","kategori":"ibadet","misal":"Hâtıralardan kurtulmak ve vesveseleri kovmak, tarîka-i hâcegânda (hâcegân yolunda) çok kolay olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خواجهﮔان"},{"kelime":"HÂCET","anlam":"İhtiyaç.","kategori":"ibadet","osmanli":"حاجت"},{"kelime":"HACI","anlam":"Hac farîzasını yerine getiren kimse.","kategori":"ibadet","misal":"Hâccî. elHâcc. (Bkz. Hacc)","osmanli":"حاجى"},{"kelime":"HÂCİB","anlam":"1.Sultan, vezir gibi yüksek makamların kapıcısı. 2.Hacbeden, yani varlığı ile bir kimseyi mirastan mahrum eden vâris.","kategori":"ibadet","misal":"Perdedâr.","osmanli":"حاجب"},{"kelime":"HACM","anlam":"","kategori":"ibadet","misal":"Bir cismin kapladığı yer. Keyl.","osmanli":"حجم"},{"kelime":"HACZ (Haciz)","anlam":"1.Ayırmak, bölmek. 2.Alacaklının hakkını korumak için borçlunun malına el koymak.","kategori":"ibadet","osmanli":"حجز"},{"kelime":"HADARÂT (Hadrât)","anlam":"1.Yeşillik. 2.Alçak gönüllülük; tasavvuf ehlinin Allahü teâlânın huzurunda bulunması telâkkisi.","kategori":"akaid","osmanli":"خضرات"},{"kelime":"HADD","anlam":"1.Sınır,uç. 2.Sınırlama, men etme. 3.Cezâsı Kur’ân-ı kerîm ve sünnette kat’i su-rette tayin edilmiş olan suç.","kategori":"dil","misal":"Beş günah için had cezâsı vardır:Zinâ, şarab içmek, şarab dışındaki alkollü içkiler ile sar-hoş olmak, kazf (iffetli erkek veya kadına zinâ etti diye iftirâda bulunmak), hırsızlık, yol ke-sicilik. Had, günahın temizlenmesine sebeb ol-maz. Günahtan kurtulmak için ayrıca tövbe etmek de lâzımdır. (İbni Âbidîn)","osmanli":"حد"},{"kelime":"Hadd-i Sirkat","anlam":"Başkasının malını gizlice, mülk edinmek maksadıyla almak sebebiyle verilen cezâ, hırsızlık cezası.","kategori":"fikih","misal":"Akıllı ve erginlik çağına gelmiş erkek, kadın, köle, efendi, Müslüman veya zımmî (Müslüman olmayan vatandaş), on dirhem (33 gr. ve 65 santigram) gümüş parayı veya değerinde olan mütekavvim (kıymetli, kullanılması câiz ve mümkün) ve durmakla bozulmayan bir malı, Müslüman veya zımmî olan sahibinin mülkünden dârülislâmda, bir defâda gizlice alırsa ve mal sahibi de dâvâ ederse, hadd-i sirkat tatbik olunur ve suçlunun sa…","osmanli":"سرقت حد"},{"kelime":"HADDÂD","anlam":"1.Demirci. 2.Kapıcı; muhafız.","kategori":"dil","osmanli":"حداد"},{"kelime":"HADEME","anlam":"Hâdimler, hizmetçiler.","kategori":"dil","osmanli":"خدمه"},{"kelime":"Hademe-ı Hayrât","anlam":"Hayır işlerinde çalışan İmâm, müezzin, muallim gibi kimseler.","kategori":"dil","osmanli":"خيرات خدمۀ"},{"kelime":"HADES","anlam":"1.Hâdis olan, yeni ortaya çı-kan. 2.Abdest veya gusl almayı gerektiren hâl.","kategori":"hadis","misal":"Yağmur, kar ve dolu suyu, deniz, nehr, kuyu, göl, menba sularına, mutlak su denir. Bunlarla hem hades, hem de necâset temizlenir. Çiçek suyu, asma suyu, üzüm suyu, et suyu gibi hu-susî isimlerle söylenen sulara mukayyed su de-nir. Bunların akıcı olanları ile yalnız necâset temizlenir. Süt, zeytinyağı gibi akıcı olmayan mâyiler ile ve bevl gibi necs olan sıvı ile hiçbir şey temizlenmez. (Ni’met-i İslâm)","osmanli":"حدث"},{"kelime":"HÂDÎ","anlam":"1.Hidâyet eden, yol gösteren. 2.Kullarından dilediğine doğru yolu gösteren, kullarının havâssına (seçilmişlerine) doğrudan; insanların avâmına (havâsstan aşağı derecede olanlara) yarattıkları varlıkları vâsıtasıyla ken-dini tanıtan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Hâdî). Rabbin, Hâdîdir, yardımcı olarak yeter. (Furkân sûresi: 31)","kategori":"dil","osmanli":"هادى"},{"kelime":"HADÎD","anlam":"Demir; sert şey.","kategori":"dil","osmanli":"حديد"},{"kelime":"HADÎD SûRESİ","anlam":"Kur’ân-ı kerîmin elli yedinci sûresi.","kategori":"dil","misal":"Medîne-i Münevvere’de nâzil oldu. Yirmi beşinci âyet-i kerîmede demir mânâsına olan hadîdin ehemmiyetinden ve fâidelerinden bahsedildiği için, Sûretü’l-Hadîd ismi verilmiştir. tesbih ile başlayan ve müsebbihât denilen yedi sureden biridir. Bütün varlıkların Allahü teâlâyı tesbih ettiklerini bildirmekle başlayan sûrenin başlıca mevzuları şunlardır: Allahü teâlânın mübârek isimleri, sıfatları, mallarını Allah için har…","osmanli":"سى سوره حديد"},{"kelime":"HADIM","anlam":"Erkekliği olmayan, iğdiş edil-miş, cinsiyet uzvu veya husyeleri ya da ikisi birden alınmış erkek. Puluç. Aslı hizmetçi mânâsına ‘hâdim’ kelimesinden gelir.","kategori":"dil","misal":"Livâta cezası olarak bile erkeğin hadım edil-mesi veya tenâsül uzvunun kesilmesi câiz de-ğildir. (İbni Âbidîn)","osmanli":"خادم"},{"kelime":"HÂDİM","anlam":"Hizmet eden, hizmetçi.","kategori":"dil","osmanli":"خادم"},{"kelime":"HÂDİS","anlam":"Hudûs eden, ortaya çıkan; eskiden yokken ortaya çıkan, yaratılmış.","kategori":"hadis","misal":"Âlemin hâdis olduğunu gösteren ikinci bir delil de âlemin her zaman bozularak değişmesidir. (İtikadnâme)","osmanli":"حادث"},{"kelime":"HADÎS","anlam":"1.Söz. 2.Hazret-i Peygamber aleyhisselâmın sözleri.","kategori":"hadis","misal":"Benden bildiğinizin haricinde hadîs naklinden sakının. Zira her kim kasten yalan bir hadîs söylerse ateşten oturacağı yeri hazırlasın. (Hadîs-i şerîfTirmizî) Hadîs-i şerîfleri, sahîh veya mevzu olduğunu bilmeden söylemek, sahîh olsa bile, günah olur. Böyle kimsenin hadîs-i şerîf okuması câiz olmaz. Hadîs kitablarından hadîs nakletmek için hadîs âlimlerinden icâzet (izin) almış olmak lâzımdır. (Berîka)","osmanli":"حديث","baglamlar":[{"baglam":"rivâyet","anlam":"Hz. Peygamber'in sözleri, fiilleri ve takrirleri; sened ve metin kısımlarından oluşur."},{"baglam":"ilim","anlam":"Hadis ilmi; rivâyetlerin sıhhatini, râvîlerin güvenilirliğini inceleyen ilim dalı."}]},{"kelime":"Hadîs Âlimi","anlam":"Hadîs-i şerîf sahasında mütehassıs kimse.","kategori":"hadis","osmanli":"عالمى حديث"},{"kelime":"Hadîs-i Cibrîl","anlam":"İslâm dini ve ima-nın esaslarını ortaya koyan ve Hazret-i Pey-gamber’e insan suretinde gelerek sorduğu su-allerden teşekkül ettiği için bu isimle tanınan meşhur hadîs.","kategori":"hadis","misal":"O zât-ı şerîf (Cebrâil aleyhisselâm) ellerini Resûl-i ekremin mübârek dizleri üzerine koydu ve Resûlullah’a; “Yâ Resûlallah! Bana İslâmiyet’i, Müslümanlığı anlat” dedi. Resûl-i ekrem bu-yurdu ki: “İslâm’ın şartları; kelime-i şehâdet getirmek, vakti gelince namaz kılmak, malı-nın zekâtını vermek, Ramazân-ı şerîf ayında her gün oruç tutmak ve gücü yetenin, öm-ründe bir kere hac etmesidir.” Îmânın şart-larını sorduğunda; “Allahü teâlâya inanmak, O’nun meleklerine inanmak, indirdiği kitap-larına inanmak, peygamberlerine inanmak, âhiret gününe inanmak, kadere, hayr ve şer-rin Allahü teâlâdan olduğuna inanmaktır” buyurdu. “İhsân nedir? diye sorduğunda da; “Allahü teâlâyı görür gibi ibâdet etmendir. Sen O’nu görmüyorsan da, O seni görür” buyurdu. (Hadîs-i şerîf-Müslim)","osmanli":"جبريل حديث"},{"kelime":"Hadîs-i Garîb","anlam":"Senedinin bir veya birkaç tabakasında râvî adedi bire düşen veya herkes aynı şekilde rivâyet ederken bir râvinin biraz farklı rivâyet etmesinden dolayı hususîlik gösteren hadîs.","kategori":"hadis","misal":"Garîb hadîs.","osmanli":"غريب حديث"},{"kelime":"Hadîs-i Hâs","anlam":"Muayyen bir kimse için söylenmiş hadîs-i şerîf.","kategori":"hadis","misal":"Her ümmetin bir emîni vardır. Ey ümmetim! Bizim emînimiz de Ebû ubeyde bin Cerrâh’tır. Bu hadîs, hadîs-i hâstır. (Müslim)","osmanli":"خاص حديث"},{"kelime":"Hadîs-i Hasen","anlam":"Râvîleri sâdık ve emîn olmakla beraber, hâfızası, anlayışı sahîh","kategori":"hadis","misal":"hadîsleri bildirenler kadar kuvvetli olmayan hadîs-i şerîf.","osmanli":"حسن حديث"},{"kelime":"Hadîs-i Kavî","anlam":"Resûlullah aleyhisselâmın, söyledikten sonra, peşinden bir âyet-i kerîme okuduğu hadîs-i şerîfler.","kategori":"hadis","osmanli":"قوى حديث"},{"kelime":"Hadîs-i Kudsî","anlam":"Mânâsı Allahü teâlâ tarafından, kelimeleri ise Resûl-i ekrem sallallâhü aleyhi ve sellem tarafından olan hadîs-i şerîfler.","kategori":"hadis","osmanli":"قدسى حديث"},{"kelime":"Hadîs-i Maktû‘","anlam":"Râvîleri, Tâbiîne kadar bilinip, Tâbiîn’den rivâyet olunan hadîs-i şerîfler.","kategori":"hadis","misal":"Tâbiîn’den rivâyet edilen hadîs-i maktû‘un sonraki râvîleri Ehl-i sünnet ise, bunlar hakîkaten hadîs-i maktû‘dur. Mevdû‘ sanmamalıdır. (edDürrü’n-Nakîİbni Kudâme)","osmanli":"مقطوع حديث"},{"kelime":"Hadîs-i Mensûh","anlam":"Peygamber aleyhisselâm tarafından söylenip, sonra hükmünün değiştirildiği bildirilen hadîsler.","kategori":"hadis","osmanli":"منسوخ حديث"},{"kelime":"Hadîs-i Merdûd","anlam":"Hadîs olarak söylenmekle bebaber, mânâsı olmayan ve rivâyet şartlarını taşımayan sözler.","kategori":"hadis","osmanli":"مردود حديث"},{"kelime":"Hadîs-i Merfû‘","anlam":"Sahâbînin, “Resûlullah’tan işittim, böyle buyurdu” diyerek haber verdiği hadîs, hadîs-i mevsûl.","kategori":"hadis","osmanli":"مرفوع حديث"},{"kelime":"Hadîs-i Meşhûr","anlam":"İlk zamanda bir kişi bildirmişken, ikinci asırda şöhret bu-lan hadîs-i şerîf.","kategori":"hadis","osmanli":"مشهور حديث"},{"kelime":"Hadîs-i Mevdû‘","anlam":"“Vaz’ olunmuş, konulmuş, uydurulmuş hadîs” mânâsına bir hadîs imâmının sıhhat için aradığı şartlara uymayan hadîs-i şerîf.","kategori":"hadis","misal":"Bir müctehid, bir hadîsin sahîh olması için, lüzum gördüğü şartları taşımayan bir hadîs için; “Benim mezhebimin usûlünün kâidelerine göre hadîs-i mevdû‘dur” der. Yoksa; “Resûlullah aleyhisselâmın sözü değildir” demez. (Şerhu Usû-li'l-HadîsDâvûdü’l-Karsî) Hadîs-i Mevdû‘, şeriat kâidelerine aykırı ise, hiçbir suretle, hatta amellerinin fazileti bâbında dahi rivâyet câiz değildir. Umumî bir kâideye dâhil olursa rivâyet…","osmanli":"موضوع حديث"},{"kelime":"Hadîs-i Mevkûf","anlam":"Eshâb-ı kirâma kadar râvîleri hep bildirilip, sahâbî olan râvînin, “Resûl-i ekremden işittim” demeyip, “Böyle buyurmuş” dediği hadîs-i şerîfler.","kategori":"hadis","misal":"Hadîs âlimlerinin aslı yoktur demesi, bu hadîsin merfû’ olmasının aslı yoktur demek olup, hadîs-i mevkûf olduğunu bildirmektedir. (İbni Âbidîn)","osmanli":"موقوف حديث"},{"kelime":"Hadîs-i Mevsûl","anlam":"Sahâbînin, “Resûlullah’tan işittim, böyle buyurdu” diyerek haber verdiği hadîs-i müsned-i müttasıl.","kategori":"hadis","osmanli":"موصول حديث"},{"kelime":"Hadîs-i Mu‘allak","anlam":"Baştan bir veya birkaç râvîsi veya hiçbir râvîsi belli olmayan hadîs-i şerîf.","kategori":"hadis","osmanli":"معلق حديث"},{"kelime":"Hadîs-i Muddarib (Hadîs-i Muzdarib)","anlam":"Bir çok rivâyetleri olup, bu rivâyetler birbirine müsavi olduğu için aralarında tercih yapılamayan hadîs-i şerîf.","kategori":"hadis","misal":"Muzdarib hadîs.","osmanli":"حديث مضطرب"},{"kelime":"Hadîs-i Müfterî","anlam":"Yalancı peygamber Müseylemetü’l-Kezzâb ve ondan sonra gelen münâfıkların, zındıkların hadîs kisvesiyle söylediği söz.","kategori":"hadis","osmanli":"مفترى حديث"},{"kelime":"Hadîs-i Muhkem","anlam":"Te’vîle muhtaç olmayan hadîs-i şerîf.","kategori":"hadis","osmanli":"محكم حديث"},{"kelime":"Hadîs-i Münfasıl","anlam":"Aradaki râvî-lerden (nakledenlerden), birden ziyâdesi (faz-lası) unutulmuş olan hadîs-i şerîfler.","kategori":"hadis","osmanli":"منفصل حديث"},{"kelime":"Hadîs-i Mürsel","anlam":"Tâbiîn’den birinin, Sahâbînin ismini söylemeyip, doğruca “Resûl-i ekrem buyurdu ki” dediği hadîs-i şerîf.","kategori":"hadis","osmanli":"مرسل حديث"},{"kelime":"Hadîs-i Müsned","anlam":"Peygamber aleyhisselâmdan işiten sahâbînin adının bildirildiği hadîs-i şerîf.","kategori":"hadis","osmanli":"مسند حديث"},{"kelime":"Hadîs-i Müsned-i Munkatı‘","anlam":"Sahâbîden başka bir veya birkaç râvîsi bildi-rilmeyen hadîs-i şerîf.","kategori":"hadis","osmanli":"منقطع مسند حديث"},{"kelime":"Hadîs-i Müsned-i Muttasıl","anlam":"Peygamber aleyhisselâma kadar râvîlerden hiç-biri noksan olmayan hadîs-i şerîf.","kategori":"hadis","osmanli":"متصل مسند حديث"},{"kelime":"Hadîs-i Müstefîz","anlam":"","kategori":"hadis","misal":"Söyleyenleri üçten çok olan hadîs-i şerîf. Hadîs-i müstefîd.","osmanli":"مستفيز حديث"},{"kelime":"Hadîs-i Müteşâbîh","anlam":"Te’vîle muh-","kategori":"hadis","misal":"taç hadîs-i şerîf.","osmanli":"متشابه حديث"},{"kelime":"Hadîs-i Mütevâtir","anlam":"Her nesilde yalan üzere ittifakı mümkün olmayan bir topluluk tarafından rivâyet edilen ve te’vîlsiz inkârı küfr sayılan hadîs-i şerîf.","kategori":"hadis","osmanli":"متواتر حديث"},{"kelime":"Hadîs-i Nâsih","anlam":"Resûlullah aleyhisselâmın daha evvel söylediği bir hadîs-i şerîfin hükmünün sona erdiğini bildiren hadîs-i şerîf.","kategori":"hadis","osmanli":"ناسخ حديث"},{"kelime":"Hadîs-i Sahîh","anlam":"Râvîleri tam, âdil ve mazbut olup, şâz ve muallel (icmaya aykırı, sened ve metninde ıllet, sıhhate aykırı bir husus) bulunmayan hadîs-i şerîf.","kategori":"hadis","osmanli":"صحيح حديث"},{"kelime":"Hadîs-i Şâz","anlam":"Sikâ (güvenilir) bir râvînin, diğer râvîlere veya kendisinden daha","kategori":"hadis","misal":"makbul diğer bir sikâ râvîye muhalif olarak rivâyet ettiği, kabul olunan, fakat sened sayılmayan hadîs-i şerîf.","osmanli":"شاذ حديث"},{"kelime":"Hadîs-i Za‘îf","anlam":"Sahîh ve hasen hadîslerin sıfatı kendisinde bulunmayan, nâfile ibâdetler için delil olan, fakat şer’î hükme vesika (delil) sayılmayan hadîs-i şerîf.","kategori":"hadis","osmanli":"ضعيف حديث"},{"kelime":"Hadîs İlmi","anlam":"Hazret-i Peygamber aleyhisselâmdan nakledilen hadîslerin rivâyeti, sened ve metninin tetkiki ile meşgul olan ilim.","kategori":"hadis","osmanli":"علمى حديث"},{"kelime":"Hadîs İmâmı","anlam":"Üç yüz binden çok hadîs-i şerîfi, râvîleri ile beraber bilen hadîs âlimi.","kategori":"hadis","misal":"Hadîs müctehidi.","osmanli":"امامى حديث"},{"kelime":"HÂDİSE","anlam":"Hudûs eden şey, vak’a.","kategori":"hadis","osmanli":"حادثه"},{"kelime":"HADR","anlam":"1.Dolmak, şişmek, hızlı söy-lemek. 2.Kıraat ilminde Kur’ân-ı kerîmin te-cvîd üzere okunduğu üç tarzdan sür’atli olanı.","kategori":"dil","osmanli":"حدر"},{"kelime":"HADSÎ","anlam":"Zan ve tahmin ile alâkalı; zihnin sür’atli fakat doğru bir şekilde netî-ceye ulaşması ile bilinen şey.","kategori":"dil","misal":"Tasavvuf büyüklerinin eserden müessiri anla-maları hadsîdir. Diğer insanların, eseri görüp, müessiri anlayabilmeleri ise, düşünmekle, in-celemekle olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"حدسى"},{"kelime":"HAFÂ","anlam":"Gizli olma, gizlilik, kapalılık.","kategori":"dil","osmanli":"خفاء"},{"kelime":"HAFAZA MELEKLERİ","anlam":"Koruyucu melekler. İnsanın devamlı yanında bulunup kendisini cinlerin zararlarına karşı koruyan ve amellerini yazan melekler.","kategori":"akaid","misal":"Muhakkak sizin üzerinizde hafaza melekleri var. Kirâmen kâtibîn (şerefli kâtipler) var. Her ne yaparsanız bilirler. (İnfitâr sûresi: 10, 11, 12) Avret yerlerinizi açmayınız! (Yani yalnız iken de açmayınız) Çünki yanınızdan hiç ayrılmayan hafaza melekleri vardır. Onlardan utanınız ve onlara saygılı olunuz. (Hadîs-i şerîfTirmizî) Hafaza meleklerinin insanın amellerini yazan kirâmen kâtibînden ayrı olduğu da söylenmişt…","osmanli":"ملكلرى حفظه"},{"kelime":"HAFÎ","anlam":"1.Gizli, kapalı. 2.Usûl-i fıkıhta mânâsı açık olduğu hâlde söyleyenin maksadını ifâde etme hususunda kapalı, gizli söz. 3.Tasavvufta âlem-i kebîrdeki beş latîfeden, beş konaktan biri.","kategori":"fikih","misal":"Kalb, ruh, sır, hafî ve ahfâ latîfelerinin asılları, kökleri âlem-i kebîrdedir. İnsanın dışındaki varlıklara “âlem-i kebîr” denir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خفى"},{"kelime":"Hafî Zikr","anlam":"Allahü teâlâyı hufyeten (yüksek olmayan sesle veya içten) zikretme.","kategori":"tasavvuf","misal":"denir. Bu da, yalnız Zat-ı ilahîyi zikirdir. Yahud, sıfatlarını düşünerek yapılır. Nimetleri de düşünülürse, buna tefekkür denir. 3-Kalb ile ve dil ile birlikte zikrdir. Dil ile kendi işitecek kadar söylenirse, İslamiyet’te hafî zikr denir. Âyet-i kerimede emrolunan, bu hafî zikrdir. Başkası da işitirse çehrî zikr denir. Âyet-i kerimeler ve hadîs-i şerifler, hafî zikrin, cehrî zikrden efdal olduğunu gösteriyor. Resû…","osmanli":"ذكر خفى"},{"kelime":"HÂFID","anlam":"1.Aşağı düşüren, alçaltan. 2.Kıyâmet günü, yani öldükten sonra mah-lûkât diriltilip, herkes dünyada iken yaptığının hesâbını verirken, kâfirleri ve kötü kimseleri en aşağı seviyeye indiren, huzurunda düşman-larının başlarını aşağı eğdiren mânâsına Al-lahü teâlânın Esmâ-i hüsnâsından (el-Hâfıd). El-Hâfıd ism-i şerîfini söyleyen zararlardan ko-runmuş olur. (El-İstigâsetü’l-Kübrâ)","kategori":"dil","osmanli":"حافض"},{"kelime":"HAFÎD","anlam":"Torun.","kategori":"dil","osmanli":"حفيد"},{"kelime":"HAFİF NECÂSET","anlam":"Eti yenen dört ayaklı hayvanların bevli (idrarı) ve eti yenmeyen kuşların pisliği.","kategori":"fikih","misal":"Necâset-i hafîfe. Hafif necâsetlerden bir uzva veya elbisenin bir kısmına bulaşınca, bu kısım veya uzvun dörtte biri kadar olursa namaza zarar vermez. (İbni Âbidîn)","osmanli":"نجاست خفيف"},{"kelime":"HAFÎZ","anlam":"Çok hıfz edici, koruyucu.","kategori":"dil","misal":"lûkları bozulmaktan, nizamı değişmekten, gökleri düşmekten koruyucu, hakiki bir muhafaza ile hıfzedici mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elHafîz). Bir gün i’tikâf eden kimse ile Cehennem arasında üç hendek olur ki, herbiri hâfikayndan daha çoktur. (Mektûbât-ı Ma’sûmiyye)","osmanli":"حافظ"},{"kelime":"HÂFIZ","anlam":"1.Hıfz eden, koruyan, esirgeyen; ezberleyen. 2.Hakikî ve tam hıfz edici mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elHâfız). 3.Râvileriyle birlikte yüz bin hadîs-i şerîfi ezbere bilen hadîs âlimi.","kategori":"dil","misal":"“Allah, hâfızların en hayırlısıdır” (Yûsuf sûresi: 64) O zikri (Kur’ân-ı kerîmi) biz indirdik ve onun hâfızı (koruyucusu) da elbette biziz! (Hicr sûresi: 9)","osmanli":"حافظ"},{"kelime":"Hâfız-ı Kur’ân","anlam":"Kur’ân-ı kerîmi ezbere bilen.","kategori":"dil","misal":"Doğrusu kârî’dir. (Bkz. Kârî)","osmanli":"قرآن حافظ"},{"kelime":"HÂFIZA","anlam":"Hıfz etme, ezberleme ve hatırda tutma kuvveti.","kategori":"dil","misal":"Az yemek yiyenin bedeni kuvvetli, kalbi nûrlu, hâfızası kuvvetli olur. (Miftahü’l-Cenne)","osmanli":"حافظه"},{"kelime":"HAHAM","anlam":"Yahudi din adamı. Aslı hikmet sahibi, hakîm mânâsına hohma kelimesidir.","kategori":"dil","osmanli":"خاخام"},{"kelime":"HÂİD","anlam":"Hayız (âdet) gören kadın.","kategori":"osmanli","misal":"(Bkz. Hayz)","osmanli":"حائض"},{"kelime":"HÂİL","anlam":"Perde, bir şeyin önündeki engel. Önünde hâil (perde) yok iken, kabre karşı na-maz kılmak mekrûhtur. (Miftahü’l-Cenne)","kategori":"fikih","osmanli":"حائل"},{"kelime":"HÂİN","anlam":"Hıyânet eden, birine kendini emin tanıttıktan sonra o emniyeti bozacak iş yapan. Cimriler, hîlekârlar, hâinler ve kötü huylu in-sanlar Cennet’e giremezler. (Hadîs-i şerîf-Tir-mizî). Ümmetim belki her günahı işleyebilir ama, yalan söyleyemez ve hâinlik yapamaz. (Hadîs-i şerîf-Kimyâ-ii Seâdet)","kategori":"hadis","osmanli":"خائن"},{"kelime":"HÂİZ","anlam":"Elinde bulunduran, taşıyan; mâ-lik, sahip.","kategori":"dil","misal":"Kıyâsın şartları, rüknü, hükmü ve def ’i var-dır. Müctehidin bunları hâiz olması lâzımdır. (Şerhu Menâr)","osmanli":"حائز"},{"kelime":"HÂK","anlam":"Toprak.","kategori":"dil","misal":"Ölüm vakti gelince, kimseden gelmez meded, Nefsine uyma sakın, hâk olur birgün cesed.","osmanli":"خاك"},{"kelime":"Hâk ile Yeksân","anlam":"Yerle bir. HAKÂIK (Hakâyık): حقائق (A) Hakîkatler. HÂKÂN: خاقان (A) Türk hükümdarı.","kategori":"dil","osmanli":"يكسان ايله خاك"},{"kelime":"Hak Teâlâ","anlam":"“Yüce Hak” mânâsına Allahü teâlâ için kullanılan tazimkâr ifade.","kategori":"akaid","misal":"Hak teâlâ, intikamın kul eli ile alır, Bilmeyen ilm-i ledünni anı kul yaptı sanır.","osmanli":"تعالى حق"},{"kelime":"HÂKÂNÎ","anlam":"Hâkâna ait, hâkâna mahsus.","kategori":"dil","osmanli":"خاقانى"},{"kelime":"HAKÂRET","anlam":"Aşağılama, tahkîr etme, hor görme; incitme, sövme.","kategori":"dil","misal":"Üzerinde sûret, yani canlı resmi bulunan elbise ile namaz kılmak tahrîmen mekrûhtur. Cansız resmleri bulunursa, mekrûh olmaz. İster hur-met edilmek için, ister hakâret edilmek için ol-sun, ister büyük olsun, ister küçük olsun, canlı resmi yapmak harâmdır. (İbni Âbidîn)","osmanli":"حقارت"},{"kelime":"HAKEM","anlam":"1.Hüküm sahibi, bir nizanın çeşitli taraflarının, hükmüne rızâ göstermek üzere seçtikleri kimse. 2.Hükmedici, hak ile bâtılı ayırıcı, en sağlam ve doğru hüküm veren, hükmünü reddeden ve takip edeni bulunmayan, saîdlerin Cennete ve şakîlerin cehenneme erdirilmesini hükmeden mânâsına Allahü teâlânın Esmâ-i hüsnâsından (e…","kategori":"fikih","misal":"Eğer karıkocanın aralarının açılmasından korkarsanız, erkeğin ailesinden bir hakem ve kadının ailesinden bir hakem gönderin. Bunlar barıştırmak isterlerse Allah aralarını bulur. (Nisâ sûresi: 35)","osmanli":"حكم"},{"kelime":"HAKÎKAT","anlam":"1.Bir şeyin doğrusu, gerçek; mahiyet, asıl. 2.Tasavvufta her şeyi Allah’tan olduğunu idrak etmek, her şeyde O’nun isim ve sıfatını hatırlamak.","kategori":"tasavvuf","misal":"Aslan denilince, bilinen yırtıcı hayvan kaste-dilir, bu mânâda kullanılırsa, hakikat olur, ce-sur insan mânâsında kullanılırsa, mecâz yani hakîkî mânâsının dışında kullanılmış olur. (Mir’atü’l-Usûl) Alan sensin veren sensin kılan sen, Ne verdinse odur dahi nemiz var. Hakîkat üzre anlayıp bilen sen, Ne verdinse odur dahi nemiz var. (Hüdâyî) Kur’ân-ı kerîmde bulunan bilgiler üç kısımdır: Bir kısmını, hiçbir kuluna bildirmemiştir. Zâtı-nın ve sıfatlarının hakîkati ve gaybden haber vermek böyledir. İkinci kısım, yalnız peygam-berlerine bildirdiği esrârdır. Üçüncü kısım bil-gileri, peygamberine bildirmiş ve bütün ümme-tine bildirmesini emretmiştir. (Berîka) Tarîkat ve hakîkatten maksat, ihlâsı elde et-mektir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"حقيقت"},{"kelime":"Hakîkat Âlemi","anlam":"Allahü teâlânın isim ve sıfatları; öteki âlem; bu isim ve sıfatların zılli (gölgesi) olan âlem-i mecâzın zıddı.","kategori":"akaid","misal":"Âlem-i hakîkat.","osmanli":"عالمى حقيقت"},{"kelime":"Hakîkat-i Câmî‘a","anlam":"Toplayıcı hakîkat. Tasavvufta, kalb latîfesi için kullanılan tabir.","kategori":"tasavvuf","misal":"Sünnet-i seniyyeye tâbi olmak, uymak, nefsin âdetlerini, kalbi karartan isteklerini yok eder. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"جامعه حقيقت"},{"kelime":"HAKÎKÎ KIYMET","anlam":"Malın râ-yiç değil, maliyet değeri. Kıymet-i hakîkiyye. Semenin cinsi söylenmedi ise, söz kesilirken orada kullanılan semen anlaşılır. Burada, pi-yasadaki paraların maliyeti, yani hakîkî kıy-meti ve revâcı, yani geçer kıymeti müsâvî ise, bey’ sahîh olur. Müşterî hangi parayı isterse verebilir. Geçer kıymetleri farklı ise, en yükse-ğini verir. Geçer kıymetleri aynı olup, maliyet-leri farklı ise, cinsi, sıfatı söylenemezse, bey’ fâ-sid olur. (İbni Âbidîn)","kategori":"dil","misal":"Fülûsun (metal ve kâğıt paranın) kıymetleri, al-tın ile gümüşün kıymetleri gibi, hakîkî kıymet değildir. İ’tibârî kıymettir. Hükûmetlerin ver-dikleri kıymettir. Verdikleri gibi, geri de alır-lar. İ’tibârî kıymetleri gidince, semen olamaz-lar. Zekât malı olmaktan çıkarlar. (İbni Âbidîn)","osmanli":"قيمت حقيقى"},{"kelime":"HÂKİM","anlam":"Hüküm sahibi, hükmeden; haklı ve haksızı ayırıp, hak ve adâlet üzere hükmeden, mazlumun hakkını zâlimden alan.","kategori":"fikih","misal":"Hâkim-i Mutlak: (A) Tam ve gerçek hükmedici, Allahü teâlâ. Akıllı, nefsine hâkim olan ve ölüm sonrası için hazırlanan kimsedir. Âciz ve ahmak olan da, nefsinin yularını salıverir ve Hâkim-i mutlak (olan) Allahü teâlâya karşı boş ümitlere kapılır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"حاكم"},{"kelime":"HÂKİMİYYET","anlam":"Hâkim olma, hü-küm sürme.","kategori":"dil","osmanli":"حاكميت"},{"kelime":"HÂL","anlam":"1.Vaziyet, tavır. 2.Tasavvuf ehlinin kalbine kendiliğinden gelen sevinç, hüzün, darlık, genişlik, arzu ve korku gibi mânâlar, manevî dereceler. Ey hareketleri ve hâlleri değiştiren Allah’ım! Bizim hâlimizi de en iyi hâle çevir! Hâller ve vecdler, matlûbun yani ele geçirilmek istenilenin başlangıçlarıdır. Maksat değildir. (Mektûbât-ı İmâm-ı Rabbânî) En güzel hâl, şeriate uymaktır. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"tasavvuf","osmanli":"حال"},{"kelime":"Hâl Tercemesi","anlam":"Bir kimsenin biyografisi, kısa hayat hikâyesi, özgeçmişi.","kategori":"tasavvuf","osmanli":"سى ترجمه حال"},{"kelime":"HALÂ’","anlam":"(Bkz. Helâ)","kategori":"dil","osmanli":"خلاء"},{"kelime":"HALÂL","anlam":"(Bkz. Helâl)","kategori":"fikih","osmanli":"حلال"},{"kelime":"HALÂLLAŞMAK","anlam":"(Bkz. Helâlleşme) HALÂLPEZÎR: ﭘزير حلال (F) Helâl kabul edilen. HALÂS: خلاص (A) Kurtulma.","kategori":"fikih","osmanli":"حلاللشمق"},{"kelime":"HÂLÂT","anlam":"Hâller, durumlar.","kategori":"dil","osmanli":"حالات"},{"kelime":"HÂLE","anlam":"4.asırda yaşayıp, din bilgilerinde Selef-i Sâlihîne, yanı hicretin ilk iki asrında yaşayan âlimlere uyan âlimler.","kategori":"dil","misal":"Teyze, annenin kız kardeşi. HALEF: خلف (A) Sonra gelen, yerine geçen. HALEF-İ SÂDIKÎN: صادقين خلف (A) Sâdık, doğru halefler. Hicrî 3 ve Halef-i müttekîn.","osmanli":"خاله"},{"kelime":"HALEL","anlam":"Bozma, bozukluk, düzensizlik. İ’tikâdî ve zarûrî bir meselede halel bulunursa, necât-ı uhrevî devletinden mahrumdur. (Îmânda ve zarûrî bilinen husûslarda bir a’rıza olursa, âhirette kurtuluş mümkin değildir.) Ammâ, amelî konularda müsahale (gevşeklik, ihmâl) olursa, tövbesiz dahî âhirete gidilse, hesâba çe-kilme, azarlanma olursa dahî, işin sonu kurtu-luştur. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"خلل"},{"kelime":"HALF","anlam":"Yemin, hılf. (Bkz. Yemîn)","kategori":"dil","osmanli":"حلف"},{"kelime":"HALHAL","anlam":"Kadınların ayak bilekle-rine taktıkları bilezik.","kategori":"osmanli","osmanli":"خلخال"},{"kelime":"HÂLÎ","anlam":"Boş, sıyrılmış.","kategori":"dil","misal":"Tövbe kapısı açıktır. Hak teâlâ ra’ûf ve rahîmdir. Kusur işlemekten kimse hâlî değildir. Ümmîd-vâr olalar. (Mektûbât-ı Ma’sûmiyye)","osmanli":"خالى"},{"kelime":"HÂLİDİYYE","anlam":"Meşâyih-i Nakşibendiy-ye’den Mevlânâ Hâlid-i Bağdâdî hazretlerinin tasavvuftaki yolu.","kategori":"tasavvuf","osmanli":"خالديه"},{"kelime":"HALÎF","anlam":"Bir kimse ile ahidleşen, müttefik.","kategori":"dil","osmanli":"خليف"},{"kelime":"HÂLİF","anlam":"Half eden, yemin eden.","kategori":"dil","osmanli":"خالف"},{"kelime":"HALÎFE","anlam":"1.Halef olan, yerine geçen. 2.İslâm devletinin reisi. 3.Bir tasavvuf mürşidinin yetiştirip başkalarını yetiştirmekle vazifelendirdiği talebesi.","kategori":"dil","misal":"Yeryüzünde bir halîfe yaratacağım. (Bakara sûresi: 30) Sizi yeryüzünün halîfeleri kılan O’dur. (En’âm sûresi: 165 - Neml sûresi: 62) Ey Dâvûd! Biz seni yeryüzünde halîfe yaptık. O hâlde insanlar arasında adaletle hükmet. (Sâd sûresi: 26) Benden sonra halîfe olan Cennet’tedir; Ondan sonra halîfe olan Ce…","osmanli":"خليفه"},{"kelime":"HÂLIK","anlam":"Halkeden, yaratan. Allahü teâlânın Esmâ-i hüsnâsından (elHâlık).","kategori":"akaid","misal":"O öyle Allah ki, Hâlıktır, Bâridir, Musavvirdir. (Haşr sûresi: 24) O’ndan başka ilâh yoktur. Her şeyin hâlıkı ancak O’dur. (En’âm sûresi: 102) Pek ufak bir parçasını gördüğümüz bu kâinâtın bir hâlıkı ve anlamaya aklımızın ermediği pek muazzam bir kudret sahibi vardır. Bu hâlıkın hiç değişmemesi ve sonsuz var olması lâzımdır. İşte bu hâlık, Allahü teâlâdır. (Şerh-i Emâlî) Rahmân, Kuddûs, Müheymin ve Hâlık gibi yalnız…","osmanli":"خالق"},{"kelime":"HALÎL","anlam":"Zevc.","kategori":"dil","osmanli":"حليل"},{"kelime":"HALÎLuLLAH","anlam":"“Allahü teâlânın dostu.","kategori":"akaid","misal":"İbrâhim aleyhisselâm Halîlullah’tır. Çünki, bunun kalbinde, Allah sevgisinden başka hiçbir mahlûkun (yaratılmışın) sevgisi yoktu. (İtikadnâme)","osmanli":"الله خليل"},{"kelime":"HALÎLÜRRAHMÂN","anlam":"Rahmânın dostu” mânâsına İbrâhim aleyhisselâmın lakabı.","kategori":"dil","misal":"Kına ve keten ile ilk boyanan Halîlürrahmân’dır. Siyahla ilk boyanan Firavun’dur. (Hadîs-i şerîfDeylemî)","osmanli":"الرحمن خليل"},{"kelime":"HALÎM","anlam":"1.Hilm sahibi, yumuşak, sert-lik göstermeyen, kızmayan. 2.Hep hilm sahibi olan; günah işleyenlerin, günah işlemelerini ve emirlerine muhâlefet-lerini, karşı geldiklerini gördüğü hâlde gazab-lanmaya ve onları cezâlandırmaya gücü yettiği hâlde, acele etmeyen mânâsına Allahü teâlâ-nın Esmâ-i hüsnâsından (el-Halîm). Bilin ki, Allahü teâlâ mağfiret edicidir, halîmdir. (Bakara sûresi: 235) Azîm, Halîm olan Allah’tan başka ilâh yoktur. Büyük ar-şın Rabbi olan Allah’tan başka ilâh yoktur. (Hadîs-i şerîf-Müslim) El-Halîm ism-i şerîfini okuyan denizde ise bo-ğulmaktan, bir vâsıtada ise helâk olmaktan kur-tulur. (El-İstigâsetü’l-Kübrâ)","kategori":"dil","misal":"İbrâhim (aleyhisselâm) Allahü teâlâdan çok korktuğu için çok âh ederdi. Halîm idi. (Tevbe sûresi: 114) Allahü teâlâ halîm, iffetli kimseyi sever; çirkin şeyler konuşan, ısrarla halktan bir şey isteyen kimseye gazab eder. (Hadîs-i şerîf-Taberânî) Halîm kimse, gadaba sebeb olan şeyler karşı-sında kızmaz, heyecâna gelmez. Korkak olan, kendine zarar verir. Gadablı kimse ise, hem kendine, hem başkalarına zarar verir. (Berîka)","osmanli":"حليم"},{"kelime":"HÂLİS","anlam":"Saf, temiz, hîlesiz, katkısız; menfaat düşüncesi karışmadan sırf Allah için olan, riya ve gösteriş bulunmayan.","kategori":"akaid","misal":"Dikkat edin, hâlis din yalnız Allah’ındır. (Zümer sûresi: 3) Hayvanlarda da size ibretler vardır. Bağırsaklarındakiler ile kan arasından, hâlis ve içimi kolay süt içiririz. (Nahl sûresi: 66)","osmanli":"خالص"},{"kelime":"HALÎT","anlam":"Bir mülk üzerinde, hakk-ı mürûr, hakk-ı şürb gibi haklarda ortak olan-lardan her biri.","kategori":"muamelat","osmanli":"خليط"},{"kelime":"HALÎTA","anlam":"Karışım, alaşım.","kategori":"dil","osmanli":"خليطه"},{"kelime":"HALÎTÂN","anlam":"Kuru üzüm ve hurma-nın, birlikte soğuk suda bırakıldıktan sonra ısıtılıp, hepsinin süzülmesiyle elde edilen ve içilmesi helâl olan içki.","kategori":"fikih","osmanli":"خليطان"},{"kelime":"HALK","anlam":"1.Yaratmak, yoktan var etmek. 2.Mahlûk, yaratılmış, insan topluluğu.","kategori":"dil","misal":"Biz insanı en güzel biçimde halk ettik. (Tîn sûresi: 4) O (Allahü teâlâ), hanginizin daha güzel amel (ve hareket) edeceğini (hakkı-nızda) imtihan etmek için ölümü ve hayâtı halk edendir. (Mülk sûresi: 2) Ey insanlar! Doğrusu biz sizi bir erkekle bir dişiden halk ettik. Ve birbirinizle tanışmanız için sizi milletlere ve kabilelere ayırdık... (Hu-curât sûresi: 13) Allahü teâlâ her şeyi bir sebeb ile halk etmekte-dir. Âdet-i İlâhiyyesi böyledir. (Berîka) Halkı dara düşürmek, sıkıştırmak ve incitmek haramdır. (Mektûbât-ı İmâm-ı Rabbânî) Halk ile konuşmalar yumuşak ve tatlı olmalı-dır. Hiç kimseye sertlik göstermemelidir. Halka hizmet, zikir (Allahü teâlâyı anmak ile meşgul olmak)den efdaldir (daha fazîletlidir, daha se-vabtır). (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خلق"},{"kelime":"HALK","anlam":"Saç ve kılları dipten traş etme. Halk ve Taksîr: تقسير و حلق (A) Hac veya um-rede ihramdan çıkabilmek için saçın kesil-","kategori":"ibadet","misal":"mesi ve kısaltılması.","osmanli":"حلق"},{"kelime":"HALKA","anlam":"Bir şeyi tutturmaya yarayan ve umumiyetle sert madenden yapılan çem-ber; çember meydana getirecek şekilde dizil-miş topluluk; dairevî.","kategori":"dil","misal":"Kâbe etrâfında halka olup kılarken, imâmın iki yanındakilerden başkaları, Kâbe’ye imâmdan daha yakın olabilirler. (Ni’met-i İslâm) Namazda, ayakta iken erkeklerin sağ eli, sol el üzerine koyup, sağ elin küçük ve baş parmak-larını, sol bilek etrâfına halka yapması sünnet-tir. (İbni Âbidîn)","osmanli":"حلقه"},{"kelime":"HALL","anlam":"Çözmek.","kategori":"dil","osmanli":"حل"},{"kelime":"HALLÂK","anlam":"Yaratan, her şeyi yoktan vâr eden Allahü teâlâ.","kategori":"akaid","misal":"Şübhesiz ki senin Rabbin (seni de onları da) Hallak’tır (yaratandır). (Senin de onların da hâlini ve her şeyi) kemâliyle bilendir. (Hicr sûresi: 86) Gökleri ve yeri yaratan (Allah) onlar gibisini yaratmaya kâdir değil midir? Elbette (kâdirdir ve) hallâktır, her şeyi hakkıyla bilendir. (Yâsîn sûresi: 81) Can alıcı melek geldiğinde, mâsûm (günahsız) kimseyi şefâat tâcını ve gömleğini giymiş, gözünün perdesi kalkmış gö…","osmanli":"خلاق"},{"kelime":"HALVET","anlam":"1.Yalnızlık, başbaşa kalma. 2.Cinsî temasa mâni bir şey bulunmadığı hâlde bir kadın ile erkeğin başbaşa kalması. 3.Tasav-vufta ilerlemek için muayyen bir müddet ten-hâda yalnız kalma.","kategori":"dil","misal":"Allah’a ve kıyâmet gününe inanan, yabancı bir kadınla, yalnız kalıp halvet etmesin. (Ha-dîs-i şerîf-Tirmizî) Evde erkek mahremi olmayan kadınlara imâm olamaz. Çünki, halvet olur. Eğer cemâ’at ara-sında, bir erkek veya imâmın mahremi kadın bulunursa, yabancı kadınlar da cemâ’ate gire-bilir. Mescidde halvet hâsıl olmaz. (İbni Âbidîn) Mescid gibi dışardan içerisi görünen umûma açık yerlerde yalnız kalmak halvet olmaz. (İbni Âbidîn) Halvette şöhret, şöhrette âfet vardır. (Mektû-bât-ı İmâm-ı Rabbânî)","osmanli":"خلوت"},{"kelime":"HALVETİYYE","anlam":"Evliyânın büyüklerinden VIII.","kategori":"tasavvuf","misal":"hicrî asırda yaşamış Muhammed bin Nûr elHalvetî hazretlerinin tasavvuftaki yolu.","osmanli":"خلوتيه"},{"kelime":"HÂM","anlam":"Câhiliye devrinde soyundan on nesil yavru verdiği veya bir erkek yavrusu yeti-şip binme çağına geldiği için mukaddes kabul edilen ve sırtına yük vurulmayan erkek deve. Allahü teâlâ, bahîre (kulağı çentilen), sâibe (salıverilen), vasîle (ikiz doğuran) ve hâm se-bebiyle hayvanların adanmasını meşru kıl-mamıştır. Fakat münkirler, Allah namına yalan söyleyerek O’na iftira ediyorlar, çok-larının da aklı ermez. (Mâide sûresi: 103)","kategori":"dil","osmanli":"حام"},{"kelime":"HAM (Hım’)","anlam":"Kayınpeder; zevcin erkek akrabası.","kategori":"dil","misal":"Çokluk hâli hımâ’ gelir.","osmanli":"خم"},{"kelime":"HÂMÂN","anlam":"Firavunun veziri veya mi-marbaşısı.","kategori":"dil","misal":"Firavun; “Hâmân, benim için yüksek bir kule yap; belki Mûsâ’nın ilâhına muttâli ola-yım. Doğrusu ben onu yalancılardan sanı-yorum” dedi. (Kasas sûresi: 38) Andolsun ki, biz, Mûsâ aleyhisselâmı mûcizelerimizle ve apaçık bir hüccetle Fir’âvn’a Hâmân’â ve Ka-run’a gönderdik de, onlar; “Bu çok yalancı bir sihirbazdır’ dediler. (Mü’min sûresi: 23-24)","osmanli":"هامان"},{"kelime":"HAMD","anlam":"En üstün senâ, övgü; Allahü teâlânın yaratıp gönderdiğine râzı olup övmek.","kategori":"akaid","misal":"[Yani nimet karşılığı da, elem karşılığı da hamd edilir.] (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"حمد"},{"kelime":"HAMELE","anlam":"Taşıyanlar, yüklenenler. Hamele-i Kur’ân’ın diğer insanlar üzerine fazî-leti, Hâlık’ın mahlûk üzerine olan fazîleti gibi-dir. (Mektûbât-ı Ma’sûmiyye)","kategori":"dil","osmanli":"حمله"},{"kelime":"Hamele-i Kur’ân","anlam":"Kur’ân-ı kerîmi ezbere bilenler, Kur’ân-ı kerîm hâfızları.","kategori":"dil","osmanli":"قرآن حمله"},{"kelime":"HÂMÎ","anlam":"Himâye eden, koruyan.","kategori":"dil","osmanli":"حامى"},{"kelime":"HÂMİD","anlam":"Allahü teâlâYA hamdeden.","kategori":"akaid","osmanli":"حامد"},{"kelime":"HAMÎD","anlam":"1.Çok hamd edilen. 2.Her dilde ve her kalbde övülen, hamd ve senâya müstehak mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elHamîd).","kategori":"akaid","misal":"Şüphesiz Allahü teâlâ ganîdir, hamîddir. (İbrâhim sûresi: 8) ElHamîd ism-i şerîfini söyleyen, işinde, sözünde ve ahlâkında başkalarının övgüsünü kazanır. (Elİstigâsetü’l-Kübrâ)","osmanli":"حميد"},{"kelime":"HAMÎL","anlam":"1.Esir düşen kadının kucağında bulunup kendisine ait olduğunu iddia ettiği çocuk. 2.Kefil. 3.Bulunup bakılan çocuk.","kategori":"osmanli","osmanli":"حميل"},{"kelime":"HÂMİLE","anlam":"Yüklü. Gebe kadın.","kategori":"dil","osmanli":"حامله"},{"kelime":"HAMÎS","anlam":"Büyük ordu, tam teşkilatlı ordu. İslâm tarihinde ordunun beş (hamse) kısma ayrılmasından dolayı bu ismi almıştır.","kategori":"dil","osmanli":"خميس"},{"kelime":"HÂMİŞ","anlam":"Bir kitabın kenarına eklenen izâh veya ilâve.","kategori":"dil","osmanli":"هامش"},{"kelime":"HAMİYYET","anlam":"1.Dini, milleti, vatanı, yakınları himâye etme hissi. 2.İnsanlık; fazilet.","kategori":"tasavvuf","misal":"Hamiyyet sahibi kişi dâimâ şehvete götüren yollardan nefsini korur, hamiyyet duygusu ona bekçilik eder. Hamiyyeti olmayan, mukaddes şeyleri korumak isteğini taşımayan kimse ise şehvete götüren işlerden kaçınmak şöyle dur-sun, kendi şahsiyetini hattâ belki din, devlet ve milletini bile fedâ eder. (Ahlâk-ı Celâlî)","osmanli":"حميت"},{"kelime":"HÂMIZ","anlam":"Asit.","kategori":"dil","osmanli":"خامض"},{"kelime":"HAML","anlam":"Taşıma; yükleme; ağırlık; hâmilelik.","kategori":"dil","osmanli":"حمل"},{"kelime":"HAMMÂL","anlam":"Ücretle yük taşıyan.","kategori":"dil","osmanli":"حمال"},{"kelime":"HAMR","anlam":"Fermantasyona uğramak suretiyle elde edilen ve sarhoşluk veren içki, şarab.","kategori":"osmanli","misal":"Hamr dört mezhebte de haramdır. Helâl diyenin imanı gider. İdrar gibi kaba necâsettir. Satması câiz değildir. (İbni Âbidîn)","osmanli":"خمر"},{"kelime":"HÂMûŞ","anlam":"Susan, suskun, sessiz.","kategori":"dil","osmanli":"خاموش"},{"kelime":"HÂN","anlam":"Eski Türk devletlerinde hâkâna bağlı küçük hükümdar.","kategori":"osmanli","osmanli":"خان"},{"kelime":"HANBELÎ","anlam":"Amelde İmâm Ahmed bin Hanbel’in mezhebine mensub.","kategori":"ibadet","osmanli":"حنبلى","alternatif":["hanbeli"]},{"kelime":"Hanbelî Mezhebi","anlam":"Ehl-i sünnetin amelde dört hak mezhebinden İmâm Ahmed bin Hanbel’in içtihadlarından meydana gelen mezheb, yol.","kategori":"dil","osmanli":"مذهبى حنبلى","alternatif":["hanbeli"]},{"kelime":"HÂNEDÂN","anlam":"1.Sülâle; hükümdar ailesi. 2.Cömert ve misafirperver kimse.","kategori":"dil","osmanli":"خاندان"},{"kelime":"HANEFÎ","anlam":"Amelde İmâm-ı A’zâm Ebû Hanife’nin mezhebine mensub.","kategori":"ibadet","osmanli":"حنفى","alternatif":["hanefi"]},{"kelime":"Hanefî Mezhebi","anlam":"Ehl-i sünnetin amelde dört hak mezhebinden İmâm-ı A’zâm Ebû Hanife’ye ulaşan bir tanesi.","kategori":"dil","osmanli":"مذهبى حنفى","alternatif":["hanefi"]},{"kelime":"HÂNEKÂH (Hânegâh)","anlam":"Tasavvufun öğretildiği; tasavvuf yolcusunun terbiye gördüğü; tarikat mensublarının beraber bulunduğu mekân.","kategori":"tasavvuf","misal":"Tekke, dergâh.","osmanli":"خانهﮔاه"},{"kelime":"HANÎF","anlam":"1.Yanlış ve sapık olan şeye hiç dalmadan doğruya meyleden. 2.İslâmiyet’ten önce putlara tapınmayan, hac yapan, sünnet olan, kısacası Hazret-i İbrâhim’in dininde bulu-nan. 3.(tek başına kullanıldığında) Müslüman, tevhid inancında.","kategori":"dil","misal":"Çokluk hâli hunefâ gelir. İbrâhim ne Yahudi, ne de Hristiyan idi. O hanîf idi. (Âl-i İmrân sûresi: 67) Hanîflerin en meşhûrlarından birisi Arab hatîb-lerinden olan Kus bin Sâide’dir. Onun Mekke-i Mükerreme’de kurulan Ukaz panayırında meş-hûr konuşmasının bir kısmı şöyledir: Her şey fânîdir (geçicidir). Bâki (devamlı olan) ancak Allahü teâlâdır. Birdir, ortağı ve benzeri yoktur. İbâdet edilecek ancak O’dur. Evvel gelip geçen-lerde bize ibret alacak şey çoktur. Büyük-küçük hep göçüp gidiyor. Giden geri gelmiyor. Kesin olarak inandım ki, herkese olan bana da ola-caktır. (Ben de öleceğim). (Kısâs-ı Enbiyâ-Cev-det Paşa)","osmanli":"حنيف"},{"kelime":"HANNÂN","anlam":"Çok acıyan, esirgeyen, rahmetin en incesini gösteren mânâsına Allahü teâlânın isimlerinden (elHannân).","kategori":"akaid","osmanli":"حنان"},{"kelime":"HANNÂNE","anlam":"Resûlullah aleyhisselâmın Mescid-i Nebevî’de dayanarak hutbe okuduğu hurma kütüğü.","kategori":"ibadet","misal":"Resûlullah aleyhisselâm, Medîne’de Mescid-i Nebevî’de, hutbeyi, Hannâne’ye dayanarak okurlardı. Minber yapılınca, Hannâne’nin yanına gitmedi. Ondan ağlama seslerini, bütün cemâat işitti. Bunun üzerine Resûlullah efendimiz minberden inip, Hannâne’ye sarılınca, sesi kesildi; “Eğer sarılmasaydım, benim ayrılığımdan kıyâmete kadar ağlardı” buyurdu. (Mir’at-ı Kâinât)","osmanli":"حنانه"},{"kelime":"HANNÂS","anlam":"İnsanlara vesvese veren şeytân. (Ey Habîbim!) De ki: İnsan ve cinden olan ve insanların göğüslerine (imanına) vesvese ve-ren hannâsın şerrinden insanların mâbûduna ve insanların bütün işlerinin sahibine ve in-sanların Rabbine sığınırım. (Nâs sûresi: 1-6) Şeytân köpek gibidir. Köpek kaçar ise de başka taraftan yine gelir. Nefs ise kaplan gibidir. Sal-dırması ancak öldürmekle biter. İnsanlara ves-vese veren şeytâna bunun için hannâs denil-miştir. İnsan hannâsın bir vesvesesine uymazsa bundan vazgeçer. Başka vesveseye başlar. Çok hayırlı işe mâni olmak için, az hayırlı şeyi de vesvese yapar, fısıldar. Büyük günaha sürükle-mek için, küçük hayır yapmayı da vesvese eder. Şeytânın vesvesesi olan küçük hayırlı iş, insana tatlı gelir ve acele ile yapmak ister. Acele etmek ise şeytândandır. (Berîka)","kategori":"dil","osmanli":"خناس"},{"kelime":"HANûT","anlam":"Cenâze teçhizinde saç ve sakal arasına konan, ayrıca ölüyü tahnît etmekte kullanılan ve çürümeyi geciktirici kokulu bir madde.","kategori":"ibadet","osmanli":"حنوط"},{"kelime":"HARÂC (Haraç)","anlam":"1.Müslüman olmayan vatandaşlardan seneden seneye alınan toprak vergisi.","kategori":"hadis","misal":"Beytülmâlin üçüncü kısmında gayr-i müslimlerden alınan, haraç ve cizye ve âşirin bunlardan aldığı mal bulunur. Bunlar, yol, köprü, han, mekteb, mahkeme gibi umûmî ihtiyâclara ve millî müdâfe’aya sarf edilir. Memleket hudûdunu bekleyen, memleket içindeki yolları bekleyen Müslümanlara, köprü, mescid, havuz, nehr yapmaya ve ta’mîrlerine, imâma, müezzine, hademe-i hayrâta, İslâm ilmlerini, yani din ve fen bilgilerini ok…","osmanli":"خراج"},{"kelime":"HARAC (Harec)","anlam":"Bir işin yapılmasına mâni olan veya yapılırken karşılaşılan zahmet ve meşakkat.","kategori":"muamelat","misal":"Allahü teâlâ din hususunda üzerinize bir harac yüklemedi. (Hac sûresi: 77) Her Müslümanın ibâdet yaparken ve haramdan sakınırken, kendi mezhebi âlimlerinin “fetvâ böyledir”, “en iyisi budur”, “en doğru söz budur” gibi bildirdiklerine uyması lâzımdır. Kendi arzusu ile yaptığı bir şey, buna uymasına mâni (engel) olur ve bu mâni olmanın önlenmesinde harac, meşakkat bulunursa, kendi mezhebinde doğru olduğu bildirilen ba…","osmanli":"خرج"},{"kelime":"HARAÇLI TOPRAK","anlam":"Mah-sulünden haraç alınan arâzî.","kategori":"muamelat","misal":"Bir şehr zor ile alınıp da, kâfirlere bırakılan veya sulh ile alınıp, kâfirlerin olan toprak ile hükû-metin kirâya verdiği beytülmâl toprağı haraçlı toprak olur. (İbni Âbidîn)","osmanli":"طوﭘراق خراجلى"},{"kelime":"HARÂM","anlam":"1.İslâm dininde yapılması katiyetle yasaklanan şey.","kategori":"fikih","misal":"De ki, Rabbim; bütün fuhşiyâtın açığını ve gizlisini, her türlü günahı, haksız isyânı ve Allahü teâlâya hiçbir zaman bir burhan indirmediği herhangi bir şeyi ortak koşmanızı ve bilmediğiniz şeyleri Allahü teâlâya isnâd etmenizi, harâm etti. (A’râf sûresi: 33) Vurularak öldürülmüş, yukardan düşmüş, boynuzlanmış ve canavar parçalayarak murdâr ölmüş olan hayvanlar size haram kılındı. (Mâide sûresi: 3) Altın ve ipek, üm…","osmanli":"حرام","alternatif":["haram"]},{"kelime":"HARÂMZÂDE","anlam":"Gayrımeşru çocuk, piç.","kategori":"fikih","osmanli":"زاده حرام"},{"kelime":"HARÂRET","anlam":"Sıcak.","kategori":"dil","osmanli":"حرارت"},{"kelime":"HARB","anlam":"Savaş.","kategori":"dil","osmanli":"حرب"},{"kelime":"HARBE","anlam":"Mızrak.","kategori":"dil","osmanli":"حربه"},{"kelime":"HARBÎ","anlam":"Dârülharb vatandaşı olan kimse. Bir harbî emân (izin, pasaport) ile İslâm ül-kesine girerse malına, canına dokunulmaz. (İbni Âbidîn)","kategori":"osmanli","osmanli":"حربى"},{"kelime":"HARC","anlam":"Harcanan para, gider, masraf HARCIRÂH: راه خرج (F) Memurlara tayin veya vazifeye gönderme sebebiyle verilen yol mas-","kategori":"fikih","misal":"rafı, yolluk.","osmanli":"خرج"},{"kelime":"HAREKE","anlam":"Arab alfabesinde sesli harfi göstermek üzere harfin üzerine veya altına konan işaret.","kategori":"dil","osmanli":"حركه"},{"kelime":"HAREM","anlam":"1.Evlerde hanımların yaşadığı ve yabancı erkeklerin girmesine müsaade edilmeyen yer. 2.Zevce. 3.Mekke-i Mükerreme ve etrafında Hazret-i İbrâhim zamanından kalma taşlarla sınırlanan, gayrımüslimlerin girmesinin yasak olduğu, hac kurbanların kesildiği ve ihram… Hac için, ömre için, ticâret için veya herhangi bir şey için uzaktan gelenlerin Mîkat denilen yerleri ihrâmsız geçerek Harem’e girmeleri harâmdır. Mîkat’tan geçerken bir iş için Hill’de (Mîkat yeri ile Harem sınırı arasındaki yerde) kalmağı niyet edenlerin ve Hill’de oturanların hacdan başka niyetle Harem’e girmeleri câizdir. (İbni Âbidîn)","kategori":"dil","osmanli":"حرم"},{"kelime":"HAREM-İ MEKKE","anlam":"Mekke-i Mükerreme ve etrafında Hazret-i İbrâhim zamanından kalma taşlarla sınırlanan, gayrımüslimlerin girmesinin yasak olduğu, hac","kategori":"dil","misal":"kurbanların kesildiği ve ihram yasaklarının cari bulunduğu mıntıka.","osmanli":"مكه حرم"},{"kelime":"Harem-i Şerîf","anlam":"Mukaddes harem. Kâbe-i Muazzama’nın etrafındaki mescid.","kategori":"dil","misal":"(Bkz. Mescid-i Harâm)","osmanli":"شريف حرم"},{"kelime":"HAREMEYN","anlam":"“İki harem” mânâsına, hürmete lâyık iki belde, Mekke-i Mükerreme ve Medîne-i Münevvere.","kategori":"dil","misal":"Ey bâd-ı sabâ uğrarsa yolun semt-i Haremeyn’e Selâmımı arzeyle Resûlüs Sekaleyn’e. (Lâ edrî)","osmanli":"حرمين"},{"kelime":"HÂRİC","anlam":"1.Dış, dıştaki. 2.Bir malı elinde bulunduran zilyede karşı, mülkiyet iddiasında bulunan kimse.","kategori":"muamelat","osmanli":"خارج"},{"kelime":"HÂRİKA","anlam":"1.Mukaddes şey veya yer. 2.Harem. 3.Avlu. 4.Bir evin, kuyunun etrafı.","kategori":"dil","misal":"Yırtan, parçalayan. Güzelliği ve büyüklüğü ile insanda hayret uyandıran şey. HÂRİKuLÂDE: العاده خارق (A) Âdeti yırtan. Eşi benzeri görülmemiş, fevkalâde, şaşırtıcı, insan gücünün üzerinde. İnsanların bütün hareketleri, işleri, Allahü teâlâ-nın âdet-i ilâhiyyesi içinde (bir sebeble) mey-dana gelmektedir. Allahü teâlâ sevdiği kulla-rına ikrâm ve en azılı düşmanlarını aldatmak için, bunlara âdetini bozarak hârikulâde şeyleri yaratmıştır. Hârikulâde şeyler peygamberlerde görülürse mûcize, evliyâ denilen diğer sevdiği kullarında görülürse kerâmet denir. Hârikulâde şeylerin peygamberlerde görülmesi lâzımdır. Ev-liyâda ise, şart değildir. (Abdülhakîm Arvâsî) HARÎM: حريم (A) Şehirden uzak, sahipsiz yerde kuyu kazan, bu-nun harîmine mâlik olur. Yirmi metre yarı ça-pındaki dâire içi, merkezindeki kuyunun harîmi olur. Şehir içindeki kuyunun harîmi olmaz. (Me-celle-i Ahkâm-ı Adliyye)","osmanli":"خارقه"},{"kelime":"HARÎR","anlam":"İpek.","kategori":"dil","misal":"Sabredenlerin mükâfatı Cennet ve oradaki harirdir. (İnsân sûresi: 12) Bir erkek, baştan ayağa harîr giyinse, başka bi-risi bu hâline, mübârek olsun dese, küfründen korkulur. (Miftahü’l-Cenne)","osmanli":"حرير"},{"kelime":"HARÎS","anlam":"Hırslı, bir şeye çok düşen, istekli.","kategori":"dil","misal":"Andolsun ki size kendinizden öyle bir pey-gamber gelmiştir ki, sizin sıkıntıya uğrama-nız O’na çok ağır gelir. Çünki O sizin hidâye-tiniz için çok harîstir, mü’minlere karşı çok şefkatli ve merhametlidir. (Tevbe sûresi: 128) İki harîs doymaz. Biri ilmin harîsi, diğeri de malın harîsidir. (Hadîs-i şerîf-Taberânî) Gönlün ferah olup, duânın makbûl olmasını istersen; dünyaya harîs olmayan, her işi Al-lah rızâsı için yapan âlimlerle beraber ol. (Ey Oğul İlmihâli)","osmanli":"حريص"},{"kelime":"HARS","anlam":"1.Yalan söylemek. 2.Tahmin etme. 3.Henüz biçilmemiş ekin veya toplanmamış meyveyi zekât hesabı için göz kararı tahminen tayin.","kategori":"ibadet","osmanli":"حرص"},{"kelime":"HÂRûN (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde adı geçen Benî İsrâîl peygamberlerinden.","kategori":"dil","misal":"(Mûsâ aleyhisselâm dedi ki): “Ya Rabbî! Ailemden kardeşim Harun’u bana vezir yap, beni onunla destekle, onu vazifemde bana ortak kıl ki seni daha çok tesbih edelim ve çokça analım.” (Taha sûresi: 29-34) Âmin, Harun aleyhisselâmdan başkasına verilmemiştir. Zira Mûsâ aleyhisselâm duâ ettiğinde, Harun aleyhisselâm “Âmin” derdi. (Hadîs-i şerîfHâris)","osmanli":"هرون"},{"kelime":"HÂS","anlam":"Osmanlılarda, beytülmâl arâzîsinin taksiminde yıllık geliri iki yüz bin akçe ile bir milyon akçe arasında olan ve maaş olarak devlet adamlarına tahsis edilen kısmı.","kategori":"muamelat","osmanli":"حاص"},{"kelime":"HÂŞÂ","anlam":"Asla, kat’iyen, hiçbir zaman; dine veya edebe aykırı bir sözün söylenme zarureti olduğu zaman “Allah saklasın”, “Allah göstermesin”, “uzak olsun” mânâsına kullanılan söz.","kategori":"akaid","misal":"Hâşâ zulm etmez, kuluna Hudâsı. Herkesin çektiği kendi cezâsı!","osmanli":"حاشا"},{"kelime":"HASÂD","anlam":"Tarlanın mahsulünü kaldır-mak. Hısâd.","kategori":"dil","misal":"Hasad günü mahsulün hakkını verin! (En’âm sûresi: 141)","osmanli":"حصاد"},{"kelime":"HASBİHÂL","anlam":"Görüşüp dertleşme; hâlleşme.","kategori":"dil","misal":"Bir kalb dünyaya bağlansa, ibâdet zevkını duymaz, Onunçün Zâtî bu şi’ri, getirdi hasbihâl üzre. (Zâtî) HASBÜNALLAHÜ VE Nİ’MEL-VEKÎL: الوكيل ونعم الله خسبنا (A) “Allahü teâlâ bize ye-ter, O ne güzel vekildir” mânâsına bir tevek-kül sözü. Bir kısım insanlar, mü’minlere; “Düşmanla-rınız olan insanlar, size karşı asker topladı-lar; aman sakının onlardan!” dediklerinde bu, onların imanlarını bir kat daha arttırdı ve; “Hasbünallahü ve ni’mel-vekîl” dediler. (Âl-i İmrân sûresi: 173)","osmanli":"حال حسب"},{"kelime":"HASEB","anlam":"1.Şeref, asâlet, ahlâk ve soy temizliği. 2.Şahsî hususiyet, vasıf, itibar.","kategori":"tasavvuf","misal":"Dünyanın şerefi zenginlik, âhiretin şerefi ise takvâdır. Sizin şerefiniz müstağni olmanız (dünyadan yüz çevirmeniz) kereminiz takvâ; hasebiniz ahlâkınız; nesebiniz de amellerinizidir. (Hadîs-i şerîfDeylemî) Zât-ı hazret-i pâdişâhî hasebü’l-hilâfe (halîfe olmak itibariyle), dîn-i İslâmın hâmîsi ve bilcümle tebe’a-yı Osmâniyyenin hükümdâr ve pâdişâhıdır. (Kanun-ı Esâsî, madde: 4)","osmanli":"حسب"},{"kelime":"HASED","anlam":"Kıskançlık, çekememek; başkalarının sahip olduğu nimetin elinden gitmesini istemek.","kategori":"tasavvuf","misal":"Hased ettiği zaman hasedcinin şerrinden karanlığı yırtan nûrun Rabbine sığınırım. (Felâk sûresi: 5) Hased etmekten sakınınız. Biliniz ki, ateşin odunu yok etmesi gibi hased de iyilikleri yok eder. (Hadîs-i şerîfEbû Ya’lâ) Hased edenin ömrü üzüntü ile geçer. Hased ettiği kimsede nîmetin azalmadığını, hattâ arttığını görerek sinir buhranları geçirir. Hasedden kurtulmak için ona hediye göndermeli, onu medhetmeli, ona k…","osmanli":"حسد"},{"kelime":"HAŞEFE","anlam":"Erkeklik uzvunun baş tarafı, sünnet derisi altındaki yuvarlak kısım; bitkinin başçık kısmı.","kategori":"hadis","misal":"Haşefe, yani zekerin ucu ferce dâhil olunca erkek ve kadın cünüb olur. (İbni Âbidîn)","osmanli":"حشفه"},{"kelime":"HASEN","anlam":"Güzel, hoş.","kategori":"dil","osmanli":"حسن"},{"kelime":"HASENÂT","anlam":"İyilikler, güzellikler; Allahü teâlânın beğendiği işler.","kategori":"akaid","misal":"Hasenât, günahları yok eder. (Hûd sûresi: 115) Günahlar hasenâtı yakar, kül eder. (Hadîs-i şerîfHarâitî)","osmanli":"حسنات"},{"kelime":"HASENE","anlam":"İyilik; Allahü teâlânın beğendiği iş, sevab.","kategori":"akaid","misal":"Ey Rabbimiz bize dünyada hasene ver. Âhirette de hasene ver. (Bakara sûresi: 201) Allahü teâlânın korkusundan kötülüğü terk eden kimseye bir hasene yazılır. Fakat başka bir sebeble terk ederse hasene yazılmaz. (Kim-yâ-i Seâdet)","osmanli":"حسنه"},{"kelime":"HAŞEVİYYE","anlam":"Nassların zâhirine bağlı kalarak tecsim ve teşbihe inanan, yani Allahü teâlâyı mahlûklara benzeterek cisim olduğu","kategori":"akaid","misal":"söyleyen, akıl yürütmeyi tamamen inkâr eden fırka. Haşviyye. Hışviyye. Allahü teâlâyı mahlûklara, cisimlere benzetme fikri ilk olarak Haşeviyye tarafından ortaya atılmış, sonra bu bozuk inanış diğer bozuk fırkalara geçmiştir. (elMilel ve’n-Nihâl) Ehl-i sünnet âlimlerine göre; peygamberler günah işlemekten mâsundurlar (korunmuşlardır). Fakat bu konuda Haşeviyye aksi kanâattedir. Onlara göre peygamberler günah işlerle…","osmanli":"خشويه"},{"kelime":"HASÎB","anlam":"1.Soylu, itibarlı. 2.Hesab gören. 3.Her mahlûkun varlığına, varlığının devamına ve kemâline, âhirette hesâbını görmeye kâfi olan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elHasîb). O peygamberler ki, Allah’ın emir ve yasaklarını insanlara tebliğ ederler ve O’ndan korkarlar. Hasîb olarak Allahü teâlâ kâfidir. (Ahzâb sûresi: 39)","kategori":"akaid","osmanli":"حسيب"},{"kelime":"HÂSIL","anlam":"Husûle gelen, meydana çı-kan, peyda olan, üreyen, türeyen, biten, çıkan. Muhabbetten Muhammed oldu hâsıl, Muhammedsiz muhabbetten ne hâsıl! (Bezmiâlem Vâlide Sultan)","kategori":"osmanli","osmanli":"حاصل"},{"kelime":"HÂŞİME","anlam":"Başa ve yüze isabet eden ve kemiğin kırıldığı yara.","kategori":"dil","osmanli":"هاشمه"},{"kelime":"HÂŞİMÎ","anlam":"Hazret-i Peygamber aleyhisselâmın dedesi Hâşim bin Abdi Menâf ’ın soyundan gelen.","kategori":"dil","misal":"(Bkz. Benî Hâşim) Hâşimî’ye zekât verilmez. Sadaka verilebilir. Ebû İsme’nin İmâm-ı Âzam’dan rivâyetine göre, Hâşimî’ye kendi zamanında zekât vermek câizdir. Çünki zekâtın bedeli olarak hakları olan ve ganimetlerden 1/5’inin 1/5’i insanların ganimet işlerinde gösterdikleri ihmal sebebiyle onların eline geçmemiştir. (İbni Âbidîn)","osmanli":"هاشمى"},{"kelime":"HASÎS","anlam":"Hasâset sahibi, cimri, pinti, eli sıkı.","kategori":"tasavvuf","misal":"Allahü teâlâ, Cennet’e buyurdu ki: “Hasîs, sende, bana komşu olamaz.” (Hadîs-i şerîfDeylemî)","osmanli":"خسيس"},{"kelime":"HÂŞİYE","anlam":"Taraf, yan, kenar; bir met-nin kenarına veya altına izah sadedinde ya-zılan yazı, dipnot.","kategori":"dil","osmanli":"حاشيه"},{"kelime":"HASLET","anlam":"İnsanın yaratılışındaki huy, mizaç, tabiat, karakter.","kategori":"dil","misal":"İki haslet mü’minde birleşemez: Hasîslik ve fenâ ahlâk. (Hadîs-i şerîf-Taberânî)","osmanli":"خصلت"},{"kelime":"HAŞMET","anlam":"Büyüklük, hey-bet, debdebe, ihtişam; nezâket; hiddet, kızgın-lık; alçakgönüllülük.","kategori":"dil","misal":"Resûlullah aleyhisselâmın peygamberliği bildi-rilmeden evvel de, sonra da haşmeti, büyük-lüğü ve heybeti herkesin gözlerinde ve gönülle-rinde yer etmiş idi. Kureyşli müşrikler, Eshâb-ı kirâma eziyyet ederlerdi. Resûlullah’ı “sallallahü teâlâ aleyhi ve sellem” gördükleri zaman O’na da eziyet edelim diye kalblerinden geçirirlerdi. Fakat O’nu görünce, heybetinden O’na hürmet ve hizmet ederlerdi. Resûlullah’ı ansızın gören kimseyi korku kaplar, titremeye başlardı. Bir gün huzuruna gelen bir kimse titremeye baş-layınca; “Titreme; ben pâdişâh değilim.” bu-yurmuştur. (Şevâhidü’n-Nübüvve)","osmanli":"حشمت"},{"kelime":"HASNÂ","anlam":"Çok iffetli kadın veya kız.","kategori":"osmanli","osmanli":"حسناء"},{"kelime":"HASR","anlam":"1.Sıkıştırma, dar bir yerin içine alma. 2.Hareketten men etme, etrafını çevirme. 3.Mahsus kılma, kılınma. 4.Vakfetme, tahsîs etme. 5.Zaman ayırma. 6.Konuşurken veya okurken tutulup kalma.","kategori":"dil","osmanli":"حصر"},{"kelime":"HAŞR","anlam":"1.Toplanma, bir araya gelme. 2.Kıyamet günü mezardan kalkıp, Arasât mey-danında toplanma.","kategori":"dil","misal":"Allah’tan korkun ve bilin ki muhakkak he-piniz haşr olunacaksınız. (Bakara sûresi: 203) Ey ümmetim ve Eshâbım! Siz ölülerinizin kefenini bol tutunuz. Zîrâ benim ümmetim kefenleriyle haşr olunurlar. Hâlbuki başka ümmetler çıplaktırlar. (Hadîs-i şerîf-Hatîb)","osmanli":"حشر"},{"kelime":"HAŞR SûRESİ","anlam":"Kur’ân-ı kerîmin elli dokuzuncu sûresi.","kategori":"dil","misal":"Medîne-i Münevvere’de nâzil oldu. Yirmi dört âyet-i kerîmedir. İsmini ikinci âyet-i kerîme-sinde geçen ve toplanmak mânâsına haşr ke-limesinden almıştır. Bu kelime Müslümanlara karşı ahidlerini bozan Beni Nadr Yahudileri-nin topluca sürgüne gönderilmesinden kinâ-yedir. Bu sebeble Sûretü’n-Nadîr veya Sûretü Beni’n-Nadîr de denir. Yahudilerin hıyânetleri ve münâfıkların hâlleri, sonunda da Allahü teâlânın büyüklüğü bildirilmektedir. (Beydâvî) Kim Haşr sûresini okursa, Allahü teâlâ onun, geçmiş ve gelecek günahlarını affeder. (Hadîs-i şerîf-Beydâvî) Kim sabahleyin (sabah nama-zından sonra) üç defâ “E’ûzübillâhissemî’il alîmi mineşşeytânirracîm” der sonra Haşr sûresinin sonundaki üç âyeti okursa, Allahü teâlâ kendisine yetmiş bin melek gönderir. Bunlar akşama kadar o kişiye duâ ve istiğ-fâr ederler. Eğer o gün vefât ederse, şehîd olarak ölür. Akşamleyin (akşam namazından sonra) okuyan kimse de aynı şekildedir. (Ha-dîs-i şerîf-Tirmizî)","osmanli":"سى سوره حشر"},{"kelime":"HASRET","anlam":"Özleme, özlem, özleyiş, göreceği gelme, ele geçirilemeyen veya elden kaçırılan bir nimete üzülme.","kategori":"dil","osmanli":"حسرت"},{"kelime":"HÂSS","anlam":"1.Belli bir şeye mahsus, hususî. 2.Katışıksız, saf. 3.Hükümdara ait. 4.Tek ba-şına bir mânâyı ifade etmek üzere ve bir ferde delâlet eden lafız (söz).","kategori":"dil","misal":"Hâss, kat’î (kesin) mânâ ifâde eder. Sözden maksat, tek şeydir. Ahmed, Yûsuf gibi hususî isimler; insan, ağaç, meyve gibi cins isimler; bir, iki, üç gibi sayı isimleri hep hâss lafızlar-dır. “Her kırk koyunda bir koyun zekât ola-rak verilir” hadîs-i şerîfinde; kırk, hâss lafız-dır. Bu sebeble koyunun zekât nisâbı (ölçüsü) kırktır. Ondan az veya çok olması ihtimâli yok-tur. (Usûl-i Serahsî)","osmanli":"خاص"},{"kelime":"HÂSSA","anlam":"1.Bir kimseye ya da bir şeye has vasıf. 2.Kuvvet. 3.Hususî, hükümdara mahsus.","kategori":"tasavvuf","misal":"Atın, binicisine itâ’ati, koşma hususiyeti meş-hûrdur. Atta bu hâssa olmasa, ona eşek gibi yük vurulurdu. (Ahlâk-ı A’lâî) İnsanda ilk yaratılan idrâk âleti lems (dokunma) hâssasıdır. İnsan, bu hâssası ile, soğuğu, sıcağı, yaşı, kuruyu, yumuşağı, katıyı ve benzerlerini idrâk eder, anlar. (Ahlâk-ı A’lâî)","osmanli":"خاصه"},{"kelime":"HASSÂS","anlam":"En ince noktalarına kadar hisseden, anlayan; duygulu; titiz.","kategori":"miras","osmanli":"حساس"},{"kelime":"HASSÂSİYYET","anlam":"Hassaslık, duygu-luluk; duyarlılık; titizlik.","kategori":"dil","osmanli":"حساسيت"},{"kelime":"HAŞYET","anlam":"Korkma, çekinme.","kategori":"dil","misal":"Allahü teâlâdan (en çok) haşyet edenler âlim-lerdir. (Fâtır sûresi: 28)","osmanli":"خشيت"},{"kelime":"HAT","anlam":"Çok hassas (0,263 cm) bir uzun-luk ölçüsü. On iki hat bir parmak, on iki par-mak da bir ayak gelir.","kategori":"dil","osmanli":"خط"},{"kelime":"HATÂ","anlam":"Yanlışlık, sehv.","kategori":"dil","misal":"Bir mü’min, bir mü’mini hatâ dışında öl-düremez. Kim bir mü’mini hatâ ile öldü-rürse, bir mü’min köle azat etmesi, bir de ölünün ailesine diyet vermesi gerekir. (Nisâ sûresi: 92) Ümmetimden, hatâ, unutma ve ikrah (zorlanma) kaldırmıştır. (Hadîs-i şerîf-Buhârî, İbn-i Mâce) Hatâ ederek oruç bozulursa, meselâ abdest alır-ken boğazına su kaçsa oruç bozulur ve bayram-dan sonra bir günü için yalnız bir gün kazâ et-mek lâzım olur. Keffaret lâzım gelmez. Günah da olmaz. (İbni Âbidîn) Meşveret olunan kimsenin, bilmediğini veya bildiğinin aksini söylemesi günahdır. Hatâ ile söylemesi günah olmaz. (Berîka)","osmanli":"خطاء"},{"kelime":"HATAR","anlam":"Tehlike.","kategori":"dil","misal":"Rukbî denilen hibe, yani, sen ölürsen benim olsun. Ben ölürsem senin olsun diyerek evini birisine vermek, Tarafeyne göre bâtıldır. Her biri, ötekinin ölümünü terakkub ettiği, bekle-diği için, rukbî denilmiştir. Çünki mülk edin-meği hatara, zarara ta’lîk etmek (bağlamak) sahîh değildir. (el-İhtiyâr)","osmanli":"خطر"},{"kelime":"HATARA","anlam":"Fikirler, düşünceler. (Bkz. Hâtır, Havâtır)","kategori":"dil","osmanli":"خطره"},{"kelime":"HÂTEM","anlam":"Yüzük; mühür.","kategori":"dil","osmanli":"خاتم"},{"kelime":"HÂTIB","anlam":"1.Hitap eden, hutbe söyle-yen. 2.Nişanlı.","kategori":"dil","osmanli":"خاطب"},{"kelime":"HATÎB","anlam":"Hutbe okuyan.","kategori":"dil","misal":"Bir kimse gusl abdesti alır, sonra Cumâ’ya gelir, kendisine mukadder olan namazı kı-lar, sonra hatîb hutbesini bitirinceye kadar susar, sonra imâmla beraber namaz kılarsa, onunla diğer Cum‘a arasındaki günahları ile beraber, üç günlük fazlasının günahları da afv ve mağfiret olunur. (Hadîs-i şerîf-Meşârık) Hatîbin, hutbe ile namaz arasında, dünya kelâmı söylemesi tahrîmen mekrûhtur. (İbni Âbidîn)","osmanli":"خطيب"},{"kelime":"HÂTİM","anlam":"Sağlamlaştıran; kâdı, hâkim.","kategori":"osmanli","osmanli":"حاتم"},{"kelime":"HATÎM","anlam":"Kâbe-i Muazzama’nın şimâl duvarı hizâsında, bir kısmı vaktiyle Kâbe’ye dâhil olan yarım dâire şeklindeki duvarcık ile çevrili yer.","kategori":"dil","misal":"İsmâil aleyhisselâmın ve annesi Hazret-i Hacer’in kabri, Hatîm’dedir. Tavâf ederken Hatîm duvarının dışından dolaşılır. Mescid-i Harâm’da kılınan namazların en kıymetlisi, Hatîm’de kılınan namazdır. (İbni Âbidîn)","osmanli":"خطيم"},{"kelime":"HÂTIR (Hâtıra)","anlam":"Kalbe gelip bir müddet kalan düşünce.","kategori":"tasavvuf","misal":"(Bkz. Hatara, Havâtır) Hâtırların zararlısı Allahü teâlâyı unutturanlardır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خاطر"},{"kelime":"HATÎRA","anlam":"Kâbe-i Muazzama’nın ku-zeybatı duvarı ile Hatîm arasındaki boşluk. HATÎTA: خطيطه (A) Bir malın semeninde ya-","kategori":"ibadet","misal":"pılan tenzilat, iskonto.","osmanli":"خطيره"},{"kelime":"HATM","anlam":"1.Mühürlemek, bitirmek. 2.Kur’ân-ı kerîmi başından sonuna kadar okumak.","kategori":"dil","misal":"Hatm anında 60 bin melek salevât getirir. Biriniz hatm ettiği zaman desin ki: “Alla-hümme ânis vahşetî fi kabrî” (Allah’ım, kab-rimde yalnızlığımı gider) (Hadîs-i şerîf-Dey-lemî) Kur’ân-ı kerîmi hatmeden kimsenin bir makbul duâ hakkı vardır. İster dünya-lık, ister âhiretlik olsun. (Hadîs-i şerîf-Bey-hekî, Taberânî) Resûlullah aleyhisselâm Mekke’de bulunduğu sırada rivâyete göre bir müddet vahy gelme-mişti. Bu sebeble müşrikler; “Rabbi, Muham-med’i terk etti, O’na darıldı” diyerek, Hazret-i Peygamber’i üzmeye, Müslümanlar arasında fitne çıkarmaya çalışıyorlardı. O zaman Duhâ sûresi nâzil oldu. Bu sûre nâzil olunca, Resûlul-lah aleyhisselâm sevincinden; “Allahü ekber” bu-yurdu. Bu sebeble Mekke halkı, Kur’ân-ı kerîmi hatmederken, Duhâ sûresinden îtibâren Nâs sû-resine kadar her sûrenin sonunda “Allahü ek-ber” demeyi âdet edinmişlerdir. (İbn-i Abbâs, Kurtubî, Süyûtî, Hâzin, Celâleyn)","osmanli":"ختم"},{"kelime":"Hatm-i Hâcegân","anlam":"Nakşibendî büyüklerinin sıkıntılı zamanlarda ferahlamaya vesile olması için toplu olarak yaptıkları, Kur’ân-ı kerîm ve mahsus evradın okunduğu bir tarikat vazifesi.","kategori":"ibadet","misal":"Hatm-i Hâce.","osmanli":"ﮔان خواجه ختم"},{"kelime":"Hatm-i Tehlîl","anlam":"Yetmiş bin adet keli-me-i tevhîd (Lâ ilâhe illallah) okumak.","kategori":"akaid","misal":"Mazhâr-ı Cân-ı Cânân hazretleri, bir kadının kabri yanına oturmuştu. Kabre yüzünü dönüp, hâtırına başka bir şey getirmeyip; yalnız onu düşündü. “Bu mezarda Cehennem ateşi var. Ruhuna, hatm-i tehlîl sevabı bağışlayacağım. İmanı varsa, affolur” buyurdu. Hatm-i tehlîlin sevabını bağışladıktan sonra; “Elhamdülillah imanı varmış, kelime-i tayyibe tesirini gösterip azaptan kurtuldu” buyurdu ve; “Bir kimse, kendisi veya ba…","osmanli":"تهليل ختم"},{"kelime":"HATMİ","anlam":"Ebegümecine benzeyen, on-dan daha büyük bir çiçek olup kök ve çiçek-leri ıtrıyat ve tabâbette (hekimlikte) kullanılır. Cenazenin başını ve sakalı hatmi ile yıkanır. Bulunmazsa sabun ve benzeri şeylerle yıka-nır. (İbni Âbidîn)","kategori":"ibadet","misal":"İhramlı iken hatmi ile başını yıkamak câiz de-ğildir. (İbni Âbidîn)","osmanli":"حتمى"},{"kelime":"HATT","anlam":"1.Çizgi. 2.sınır. 3.Yazı; âyet-i kerîmeleri, hadîs-i şerîfleri veya güzel sözleri değişik yazı tarzı ile göze hoş gelecek şekilde yazma sanatı.","kategori":"hadis","osmanli":"خط"},{"kelime":"HATTÂT","anlam":"Hattı (el yazısı) ile, kitapları çoğaltarak geçinen, hattı güzel olan sanatkâr.","kategori":"dil","osmanli":"خطاط"},{"kelime":"HÂTuN","anlam":"Kadın.","kategori":"osmanli","osmanli":"خاتون"},{"kelime":"HATVE","anlam":"Adım.","kategori":"dil","osmanli":"خطوه"},{"kelime":"HAVA PARASI","anlam":"Bir malı veya me-muriyeti, bir başkasına devretmenin karşılı-ğında alınan bedel. Peştemallik.","kategori":"dil","misal":"İmâm veya herhangi memur, hava parası ala-rak, vazifesini başkasına devredebilir. Buna bey’ (satış) denmez. Ferâg etmek denir. Çünki bey’de alınan ve verilen iki şeyin mal olmaları lâzımdır. Âmirin, ferâg işini kabul etmesi şart-tır. Hava parası alarak kirâcının binâyı devret-mesi câiz değildir. (İbni Âbidîn)","osmanli":"ﭘاراسى هوا"},{"kelime":"HAVÂDİS","anlam":"Yeni sözler, yeni vak’alar; olup bitenler; meraklı haberler. Hâdise’nin çokluk hâli.","kategori":"hadis","osmanli":"حوادث"},{"kelime":"HAVÂLE","anlam":"1.Gönderme, nakletme, bir işi başkasına gördürme. 2.Borçlunun, alacaklıya, borcumu falan kimseden al deyip, bu ikinci kimsenin, yani alacaklının, bu teklife, sözleşme yerinde razı olması şeklinde cereyan eden akid. Gücü yetenin borcunu geciktirmesi zulümdür. Biriniz borç başkasına havâle edilince kabul etsin. (Hadîs-i şerîfBuhârî)","kategori":"muamelat","osmanli":"حواله"},{"kelime":"HAVÂLÎ","anlam":"Etraf, civar, çevre, yöre.","kategori":"osmanli","osmanli":"حوالى"},{"kelime":"HAVÂRIK","anlam":"Alışılmışın haricinde olan, insanda hayranlık uyandıran şeyler.","kategori":"dil","misal":"Bütün bu havârık ve kerâmât, kalbin Allahü teâlâyı hâtırlaması yanında, hiç gibidir. (Avârif)","osmanli":"خوارق"},{"kelime":"HAVÂŞÎ","anlam":"1.Bir kitabın altına veya ke-narına yazılan ilâve notlar. 2.Usûl ve furû dı-şında kardeş, dayı, amca gibi akraba.","kategori":"fikih","misal":"Hâşi-ye’nin çokluk hâli.","osmanli":"حواشى"},{"kelime":"HAVÂSS","anlam":"1.Duyu organları. 2.Herkeste olmayan üstün meziyetlere sahip kişiler; seçilmişler, ilim ve tasavvufta yüksek dereceye ulaşmış zâtlar.","kategori":"dil","misal":"Müdrike (anlama) mânâsına gelen hâsse’nin çokluk hâli. Dimâg, havâs-ı bâtınanın mahallidir. (Mektû-bât-ı Ma’sûmiyye) Hâss veya hâssa’nın çokluk hâli. Farzların yerine getirilmesinde havâs ve avâm ve enbiyâ ve evliyâ müsâvîdir. (Mektûbât-ı Ma’sûmiyye)","osmanli":"خواص"},{"kelime":"HAVF","anlam":"Korku.","kategori":"dil","osmanli":"خوف"},{"kelime":"Havf ve Recâ (Havf u Recâ)","anlam":"Korku ve ümit. Allahü teâlânın azâbından korkmak ve rahmetinden ümitli olmak.","kategori":"akaid","misal":"Havf gençlikte, recâ yaşlılıkta çok olmalıdır. (Tarîku’n-Necât) Hazret-i Ömer buyurdu ki: Bütün insanların Cehennem’e, bir kişinin Cennet’e gireceğini söyleseler, umarım ki o bir kişi ben olurum; aksine bütün insanların Cennet’e, bir tek kişinin Cehennem’e gideceğini söyleseler, korkarım ki o kişi ben olurum. İşte havf ve recâ böyle olmalıdır. (Kimyâ-i Seâdet)","osmanli":"رجاء و خوف"},{"kelime":"HÂVÎ","anlam":"İhtivâ eden, içine alan.","kategori":"dil","osmanli":"حاوى"},{"kelime":"HÂVİYE","anlam":"Cehennem’in münâfık ve mürtedlerin azap göreceği yedinci tabakası.","kategori":"akaid","misal":"Ameli hafîf olana (yani iyilikleri hafif, günahları ağır gelene) gelince; artık onun yeri hâviyedir. Bildin mi hâviye nedir? O, yakıcı bir ateştir. (Kâria sûresi: 8-11)","osmanli":"هاويه"},{"kelime":"HAVL","anlam":"Hareket. (Bkz. Lâ havle, Keli-me-i Temcîd)","kategori":"dil","misal":"Havl ve kuvvetten kendini tamâmen ihrâc edip, bütün işleri Hak teâlâya havâle edeler. (Mek-tûbât-ı Ma’sûmiyye)","osmanli":"حول"},{"kelime":"HAVRÂ","anlam":"“Topluluk” mânâsına Yahudi mâbedi.","kategori":"dil","misal":"Müslümanlar tarafından sulh yoluyla alınan şehirlerde kilise ve havra yapılması caizdir. (İbni Âbidîn)","osmanli":"حوراء"},{"kelime":"HAVZ","anlam":"1.Etrafı çitle çevrili yer. 2.Suya girme. 3.Sakınılacak işe sokulma, girişme. 4.Havuz, göl.","kategori":"dil","misal":"Size iki şey bırakıyorum. Bunlara yapışır-sanız, benden sonra doğru yolda kalırsınız. Biri, ötekinden daha büyüktür. Bu, Allah’ın kitabıdır. İkincisi, Ehl-i beytimdir. (Cen-net’te) Havz(-ı Kevser) başında bana kavu-şuncaya kadar, ikisi birbirinden ayrılmaz. (Hadîs-i şerîf-Müslim, Tirmizî) Bir gün Mevlânâ Celâleddîn Rûmî havz ke-narındaydı. Yanında kitaplar vardı. Şems-i Tebrîzî gelip kitapları sordu. “Sen bunları an-lamazsın.” dedi. Şems-i Tebrîzî kitapları suya attı. Mevlânâ, âh babamın bulunmaz yazıları gitti, diyerek çok üzüldü. SŞems-i Tebrîzî elini uzatıp herbirini aldı. Hiçbiri ıslanmamış gö-rüldü. Mevlânâ; “Bu nasıl iştir?” dedi. Şems-i Tebrîzî; “Bu zevk ve hâldir. Sen anlamazsın.” buyurdu. (Menâkıbü’l-Ârifîn)","osmanli":"حوض"},{"kelime":"Havz-ı Kebîr","anlam":"Eni ve boyu on zrâ (4,8 metre) kare şeklindeki su havuzu.","kategori":"dil","misal":"İmâm ile cemaat arasında, iki saftan ziyâde ala-cak boş meydan veya havz-ı kebîr bulunursa, bunun gerisinde olanların uyması câiz olur ise de, yalnız kılması mekrûh olur. Havzın ve mey-danın iki yanlarında cematin bulunması şart değildir. (İmdâd Hâşiyesi-Tahtâvî) Görünen veya görünmeyen necâset, Hanefî’de akar suya ve büyük havuza, düşerse, pisliğin üç eserinden biri, yani rengi, kokusu veya tadı belli olmayan her tarafından abdest ve gusl câiz olur. Meselâ leş varsa veya insan veya hayvân bevl yaparsa veya yırtıcı hayvân içerse, aşağı tarafında bir eseri görülmezse câiz olur. (İbni Âbidîn)","osmanli":"كبير حوض"},{"kelime":"HAY’ALE","anlam":"Ezânda Hayye ale’s-salâh ve Hayye ale’l-felâh” demek.","kategori":"ibadet","osmanli":"حيعله"},{"kelime":"HAYÂ","anlam":"Utanma, sıkılma, âr, nâmus.","kategori":"tasavvuf","misal":"Allahü teâlâdan hayâ ediniz! Hakîki mânâda Allahü teâlâdan hayâ etmek, kötü düşüncelerden uzak durmak, helâl lokma yemek ve ölümü hatırlamaktır. Âhireti isteyenler dünyanın zînetinden süsünden uzaklaşır. İşte bunları yapmak, Allahü teâlâdan hakkıyla korkmak demektir. (Hadîs-i şerîfTirmizî, Taberânî) Osman, pek hayâ sahibidir. Melekler de ondan hayâ eder. (Hadîs-i şerîfİbni Asâkir, Ebû Nuaym)","osmanli":"حياء"},{"kelime":"HAYÂL","anlam":"1.Bir şeyi gördükten sonra veya görmeden önce zihinde şekillendirme, hâfızanın yardımıyla zihinde bir şeyler canlandırma. 2.Kuruntu, vehm.","kategori":"tasavvuf","misal":"Hayâl olmasaydı, herkes birbirini unutur, kimse kimseyi tanımazdı. (Ahlâk-ı Alâî)","osmanli":"خيال"},{"kelime":"HAYÂLÂT","anlam":"Hayâller.","kategori":"tasavvuf","misal":"Yunan feylesoflarından Sofistâî denilen mugâlatacılar (safsatacılar), bu kâinâtı, evhâm ve hayâlât sandı. “Hayâlimiz olmasa, bir şey olmazdı. Eşyanın varlığı, bizim inancımıza bağlıdır, hakîkatte hiçbir şey yoktur. Gökleri yer kabul edersek, yer olurlar; yerler de, itikâdımıza göre gök olur. Tatlıyı acı bilirsek, acı olur. Acılık, bizim inancımıza göre tatlı olur” dediler. Bu ahmaklar, ihtiyârı, isteği olan Yaratanı…","osmanli":"خيالات"},{"kelime":"HAYÂLÎ","anlam":"1.Hayâle mensub, hayâl ile alâkalı. 2.Karagöz oynatan kişi.","kategori":"tasavvuf","misal":"Evliyânın keşfleri, hayâlî şeyler değildir. Kalbe ilhâm edilen şeylerdir. Hayâlî olan keşflere i’timâd edilmez. Vehm ve hayâl, kalbe gelen bilgilerin anlaşılmasına yardımcı olurlar. (Mektûbât-ı Ma’sûmiyye)","osmanli":"خيالى"},{"kelime":"HAYÂT","anlam":"1.Diri olmak, dirilik. 2.Bir canlının doğumundan ölümüne kadar geçen zaman.","kategori":"dil","misal":"Mal ve dünyadan size verilen şey, yalnız hayatta bulunduğunuz müddetçe, onunla geçinmektir. Îmân edip Rablerine tevekkül edenler için âhirette Allahü teâlânın indinde dünya nîmetinden hayırlı ve dâimî çok sevab vardır. (Şûrâ sûresi: 36) Dünya hayâtı, oyun ve boş şeylerdir. Allah’tan korkanlar için âhiret hayâtı elbette hayırlıdır. Böyle olduğunu niçin anlamıyorsunuz? (En’âm sûresi: 32) Öldükten sonra da, hayâtta old…","osmanli":"حيات"},{"kelime":"HAYÂTÎ","anlam":"Hayâta, yaşayışa ait, hayatla alâkalı; hayat için çok ehemmiyetli olan;","kategori":"tasavvuf","misal":"esas, temel. Nefsî, yani hayâtî günah, adam öldürmek, bir uzvunu telef etmektir. Önce tövbe etmek, sonra kendini onun velisine teslim etmek lâzımdır. Velisi isterse afv eder. İsterse mal karşılığı sulh yapar. İsterse, mahkemeye verip, hâkimden cezâlandırılmasını ister. Kendisinin karşılık yapması, câiz değildir. (Berîka)","osmanli":"حياتى"},{"kelime":"HAYBER GAZÂSI","anlam":"7.senesinde, ŞamMedîne yolu üzerinde Medîne’ye 150 km.","kategori":"dil","misal":"Hicret’in uzaklıktaki Hayber’de yaşayan ve Müslümanlara karşı müşriklerle ittifak yapan Yahudiler ile yapılan muharebeler.","osmanli":"حيبرغزاسى"},{"kelime":"HAYDER (Haydar)","anlam":"Arslan; Hazret-i Ali’nin lakabı.","kategori":"dil","misal":"Hayber’in fethinde bulunup büyük kahramanlıklar gösteren Hazret-i Ali, Yahudilerin meşhûr pehlivanı Merhab ile karşılaştı. Merhab kendini medheden sözler söyledikten sonra Hazret-i Ali; “Ben oyum ki, anam bana Hayder adını takmıştır. Ben ormanların heybetli görünüşlü arslanı gibiyimdir. Seni bir hamlede yere serecek er kişiyimdir” diye şiirler söyleyerek Merhab’ın karşısına dikildi. Bu şiir Merhab’a o gece kendisini…","osmanli":"خيدر"},{"kelime":"HAYDûD","anlam":"Eşkıya, soyguncu. Aslı Macarca başıbozuk asker mânâsına ‘hajduk’ kelimesinden gelir.","kategori":"dil","osmanli":"حيدود"},{"kelime":"HAYHuY","anlam":"Herkesin bir anda konuşması veya eğlenmesi sebebiyle meydana gelen gürültü, patırtı, karışıklık.","kategori":"fikih","osmanli":"هوى هاى"},{"kelime":"HAYL","anlam":"1.At. 2.At sürüsü. 3.Süvâri ta-kımı. 4.Düzensiz kalabalık, gürûh.","kategori":"dil","osmanli":"خيل"},{"kelime":"HAYR","anlam":"İyilik; iyi, faydalı iş; fayda. Kim zerre mikdarı bir hayır işlerse, onun mükâfâtını görecek. Kim de zerre mikdarı şer işlerse, onun cezâsını görecektir. (Zilzâl sûresi: 7-8) Hayra yol gösteren, o hayrı ya-pan gibidir. (Hadîs-i şerîf-Tirmizî) Ya hayr söyle, ya sus! (Hadîs-i şerîf-Müsnedü Ahmed)","kategori":"hadis","osmanli":"خير"},{"kelime":"HAYRÂN","anlam":"1.Şaşmış, şaşa kalmış, şa-şırmış. 2.Çok tutkun. 3.Afyon sarhoşu.","kategori":"dil","misal":"Ölmeden önce ölerek, kabri ve haşri görüp, Mâlikülmülk huzurunda, kalbi hem hayrân gerek! (Niyazî Mısrî)","osmanli":"حيران"},{"kelime":"HAYRÂT","anlam":"1.İyilikler. 2.Sevab için ku-rulan müesseseler.","kategori":"dil","misal":"Hayr’ın çokluk hâli. Cennet’e müştak olan kimse hayrâta ko-şar, Cehennem’den korkan kimse şehvet-ten kaçar. (Hadîs-i şerîf-İbni Asâkir) Resûlul-lah sallallahü aleyhi ve sellem; “Allahümme innî es’elü-ke fi’lel hayrât ve terkelmünkerât ve hubbel-mesâkin ve izâ eredte fitneten fî kavmî fe-teveffenî gayre meftûn” duâsını okurdu. (Yâ Rabbî! Bana hayrlı işler yapmak, çirkin şeyleri terk etmek ve fakîrleri sevmek nasip eyle! Kavmim arasında fitne çıkarmak istediğin zaman, fitneye karışmadan canımı al!) (Hadîs-i şerîf-Tirmizî)","osmanli":"خيرات"},{"kelime":"HAYRET","anlam":"1.Taaccüb, şaşkınlık, ne ya-pacağını bilememe. 2.Tasavvuf yolcusunun kalb gözü açıldığı zaman karşılaştığı şaşkınlık hâli.","kategori":"tasavvuf","misal":"Hem havâ üzre döşendi bir döşek, Adı sündüs döşeyen anı melek. Çün göründü bana bu işler ayân, Hayret içre kalmış idim ben yakîn. (Mevlid-i Süleymân Çelebi) Keşfler, tecellîler, tasavvuf yolunun yolcularında hâsıl olur. O yolun sonunda olanlar, hayrette ve ibâdettedirler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"حيرت"},{"kelime":"HAYY","anlam":"1.Diri, canlı. 2.Dâimâ hayât sahibi ve diri olan, hep var, var-lığı ezelî ve ebedî (sonsuz) olan mânâsına Al-lahü teâlânın Esmâ-i hüsnâsından (el-Hayy). Allah’tan başka hiçbir ilâh yoktur. O, hayy ve kayyûmdur. (Bütün mahlûkâtın idaresini yürüten, hepsini hesâba çekendir.) (Bakara sûresi: 255) Hayy ve kayyûm olan Allah’tan başka ilâh yoktur. (Âl-i İmrân sûresi: 2) O hayydir. O’ndan başka hiçbir ilâh yoktur. O hâlde dinde ihlâs sahibi (her şeyi Allahü teâlânın rızâsına uygun yapan kimse) olarak duâ edin. Hamd (övgü) âlemlerin Rabbi olan Allah’a mahsûstur. (Mü’min sûresi: 65) Hastalanan kimse, el-Hayyü ism-i şerîfini bir tabağa yazar ve ona su koyar ve ondan üç gün içerse, Allahü teâlânın izniyle şifâ bulur. (el-İs-tigâsetü’l-Kübrâ)","kategori":"dil","misal":"Biz her şeyi sudan hayy kıldık. (Enbiyâ sû-resi: 30)","osmanli":"حى"},{"kelime":"HAYZ (Hayız)","anlam":"Kadınlarda âdet (aybaşı) görme hâli.","kategori":"osmanli","misal":"(Ey Resûlüm!) Sana hayzdan sorarlar. De ki: O bir ezâdır. Hayzlı iken kadınlardan el çekin, temizlenmelerine kadar onlara yaklaşmayın. Temizlendikleri zaman, Allah’ın size buyurduğu yoldan yaklaşın. (Bakara sûresi: 222) Hayız müddetince kadın namaz kılmaz ve oruç tutmaz. (Hadîs-i şerîfBuhârî) Sekiz yaşını doldurmuş bir kızın veya âdet zamanı son dakikasından îtibâren tam temizlik (hiç kan gelmeden en az on beş gün)…","osmanli":"حيض"},{"kelime":"HAZÂN","anlam":"Sonbahar, güz.","kategori":"dil","osmanli":"خزان"},{"kelime":"HAZER (Hazar)","anlam":"Seferde olmama. Seferde namazı tamam kılan, hazerde eksik kılan gibidir.","kategori":"ibadet","misal":"(Hadîs-i şerîfDârekutnî)","osmanli":"حضر"},{"kelime":"HÂZIK","anlam":"Hazâkatli, mütehassıs, işinin ehli, usta, işinde her yönü ile ehil.","kategori":"dil","misal":"Bir kimse hasta olacağını veya hastalanaca-ğını çok zan ederse, orucunu bozabilir. Çok zan etmek, ölüm alâmetlerini görmekle veya kendi tecrübesi ile yâhud tabîb-i müslim-i hâ-zıkın haber vermesi ile anlaşılır. Kâfir ve fâsık tabibe muâyene ve tedavi câizdir. Fakat bun-ların sözleri ile ibâdet bozulmaz. (İbni Âbidîn)","osmanli":"حاذق"},{"kelime":"HAZÎN","anlam":"Hüzünlü, kederli, gamlı; acıklı, tesirli.","kategori":"dil","osmanli":"حزين"},{"kelime":"HÂZİN","anlam":"Hazîne muhafızı, hazine-dar, bekçi.","kategori":"dil","misal":"Bu büyükler, tatlı yemekleri, lezîz şerbetleri, nefîs kumaşları, hazîn sesleri, nazîf kokuları, latîf manzaraları, melîh sûretleri, tatsızların-dan, çirkinlerinden daha çok istiyor ve sevi-yorlar. (Mektûbât-ı Ma’sûmiyye)","osmanli":"خاذن"},{"kelime":"HAZÎNE","anlam":"Kıymetli eşya yığını; saklı ve gömülü bulunan kıymetli eşya; devlet parasının saklandığı yer.","kategori":"osmanli","osmanli":"خزينه"},{"kelime":"HAZÎNEDÂR","anlam":"Hazînenin idare ve muhafazasına memur kimse.","kategori":"osmanli","osmanli":"دار خزينه"},{"kelime":"HÂZIR VE NÂZIR","anlam":"Bulunan ve gören.","kategori":"dil","misal":"Allahü teâlâ, her zamanda ve her yerde hâzır ve nâzırdır derler. Hâlbuki Allahü teâlâ zamanlı ve mekânlı değildir. O hâlde bu söz görünüşü üzere kalmaz, mecaz olur. Yani zamansız ve mekânsız, hiçbir yerde olmayarak hâzırdır ve nâzırdır, demektir. Allahü teâlâ ezelî ve ebedî hâzır ve nâzırdır. Allahü teâlâdan başkasının, meselâ meleklerin, peygamberlerin aleyhimüs-selâm ve evliyânın ve sâlih mü’minlerin ruhla-rının hâzır ve nâzır olmaları, Hızır aleyhisselâ-mın sıkıntıda olanların yardımına koşması ise zamanlı ve mekânlıdır. Ezelî ve ebedî değildir. Devamlı da değildir. Hâzır olmalarından önce yok idiler. Bir zaman sonra da oradan tekrar yok olurlar. Bu bakımdan Allahü teâlânın hâ-zır olması ile ruhların hâzır olması arasında çok fark vardır. (Abdülhakîm Arvâsî)","osmanli":"ناظر و حاضر"},{"kelime":"HAZM (Hazım)","anlam":"Hazmetme, sindirme. Başta ve gövdedeki yaraya konulan ilâcın, sıvı olsun, katı olsun, beyne ve hazm yoluna gittiği bilinirse, oruc bozulur.","kategori":"ibadet","misal":"(İbni Âbidîn)","osmanli":"هضم"},{"kelime":"HAZNE","anlam":"Hazîne; depo.","kategori":"dil","osmanli":"خزنه"},{"kelime":"HAZREC","anlam":"Medîne-i Münevvere’deki Arapların mensub olduğu iki kabileden biri.","kategori":"dil","misal":"(Diğeri Evsdir.)","osmanli":"حزرج"},{"kelime":"HAZRET","anlam":"Zât mânâsına hürmet ifâdesi.","kategori":"dil","osmanli":"حضرت"},{"kelime":"HECE","anlam":"1.Bir sesli harften veya bir defada söylenen bir sessiz ile bir veya birkaç sessiz harften meydana gelen ses; bir kimseyi kötüleme, hicv. Secde âyeti hece hece okununca ve yazılınca da secde yapılmaz. (İbni Âbidîn)","kategori":"dil","osmanli":"هجه"},{"kelime":"HEDEF","anlam":"1.Nişan noktası. 2.Varılmak istenen gaye. 3.Yüksek. 4.Tembel, işe yaramaz.","kategori":"dil","misal":"HEDEFVÂR: هدفوار (F) Hedef gibi, hedefe benzer.","osmanli":"هدف"},{"kelime":"HEDİYE (Hediyye)","anlam":"Bir kimseye ikrâm için hîbe olarak verilen mal; paha, fiyat.","kategori":"muamelat","misal":"Taksîmi mümkün olan bir şeyde ortakların, hisselerini ayırmadan başkalarına hediye etmeleri câiz değildir. (Fetâvâ-i Hindiyye) Resûlullah aleyhisselâm, sadaka kabul etmez, fakat hediye kabul ederdi. Hediye getirene karşılık fazlasını kat kat verirdi. (Mevâhib-i Ledünniyye)","osmanli":"هديه"},{"kelime":"HEDY","anlam":"Hac ve umre yapanların yerine göre şükür veya ceza olarak Harem hududu içinde kestiği hayvan.","kategori":"ibadet","misal":"Haccı ve umreyi Allah için tamamlayın. Eğer hacdan men olunursanız, size gücünüzün yettiği bir kurban gerekir. Bu kurban (hedy), yerine varmadan başınızı tıraş etmeyin. (Bakara sûresi: 196) Hedy, hacc-ı kıran ve temettu’da şükür için Kâbe’ye hediye edilen vâcib hayvandan başka, hac sırasındaki bir ihram yasağını çiğnemekten dolayı keffaret olarak kesilir. En aşağısı bir koyundur. Sığır veya deve de olur. (İbni Âbidî…","osmanli":"هدى"},{"kelime":"HEKİM","anlam":"Tabib, hakîm.","kategori":"dil","osmanli":"حكيم"},{"kelime":"HELÂK","anlam":"1.Mahvolma, ölme. 2.Har-canma. 3.Çok yorulma.","kategori":"dil","osmanli":"هلاك"},{"kelime":"HELEZON","anlam":"Kıvrımlı, yılankavi şekil, spiral. Helezûn.","kategori":"dil","osmanli":"هلزون"},{"kelime":"HELÎLE","anlam":"Tohumları müshil olarak kul-lanılan bir bitki. Halîle.","kategori":"dil","osmanli":"هليله"},{"kelime":"HEMÂN","anlam":"1.Hemen, derhal, o anda, çar-çabuk. 2.Öylece, böylece.","kategori":"dil","osmanli":"همان"},{"kelime":"HEMÎN","anlam":"Her zaman, hep bu şekilde, tıpkı bu. (Hem=beraber; în=bu).","kategori":"dil","misal":"Geldi çün ol rahmeten li’l-âlemîn, Vardı nûr, anda karâr kıldı hemîn. (Mevlid-i Süleyman Çelebi)","osmanli":"همين"},{"kelime":"HEMM","anlam":"Gam, keder, tasa, kaygı.","kategori":"dil","misal":"Lâ havle velâ kuvvete okumak, doksandokuz derde devâdır. Bunların en hafîfi, hemmdir. (Hadîs-i şerîf-İbni Asâkir, Ukaylî) Resûlullah aleyhisselâm namaz kıldıklarında sağ eliyle başlarını mesh eder ve şöyle duâ eylerlerdi: “Bismillahillezi lâ ilâhe gayruhu errahmâ-nirrahîm. Allahümme ezhib annî hemme ve’l-hüzn.” [O Allah’ın adıyla başlarım; On-dan başka ilah yoktur. O Rahmân ve Rahîm-dir. Allah’ım hem ve hüznü (gam ve kederleri) benden gider!] (Hadîs-i şerîf-Hatîb)","osmanli":"هم"},{"kelime":"HEMŞÎRE","anlam":"“Sütleri bir olan” mânâ-sına kızkardeş.","kategori":"dil","osmanli":"شيره هم"},{"kelime":"HEMZE","anlam":"Elif harfinin diğer ismi; elif harfinin sessiz hâli olup vav, ye ve he üzerine konularak bu harfi kesmeli gibi okutan işa-ret; te’sir, bi’r gibi.","kategori":"dil","osmanli":"همزه"},{"kelime":"HENDEK GAZÂSI","anlam":"5.Yılında Medîne’nin şimâlinde müşriklerle yapılan ve Selmân-ı Fârisî’nin tavsiyesiyle hendek kazılıp mevzilenildiği için bu ismi alan muharebe.","kategori":"dil","misal":"Hicretin","osmanli":"غزاسى خندق"},{"kelime":"HENDESE","anlam":"Geometri.","kategori":"dil","misal":"Zekâ bir melekedir. Bir alışkanlıktır. Bunun yar-dımı ile insan, bilinen şeylerden, bilinmeyenleri çıkarır. Delilleri bir araya toplayarak, aranılan şeyleri bulur. Bunu kazanmak için, ma’lûm şey-ler yardımı ile meçhul olan şeyleri bulmaya ça-lışmak, hesâb (matematik) ve hendese problem-leri çözmek lâzımdır. (Ahlâk-ı A’lâî, Berîka)","osmanli":"هندسه"},{"kelime":"HERC","anlam":"Karışıklık, kargaşa.","kategori":"dil","misal":"Halk için iyi veya kötü, bir hükümet gere-kir. Fâcir hükümet bile hercden daha hayır-lıdır. Denildi ki: “Herc nedir Yâ Resûlallah?” Buyurdu ki: “Öldürme ve yalandır.” (Hadîs-i şerîf-Taberânî)","osmanli":"هرج"},{"kelime":"HERÇİ","anlam":"Her ne, her ne şekilde.","kategori":"dil","osmanli":"هرﭼه"},{"kelime":"HEROİK","anlam":"Uyuşturucu; aklı giderip, hissi gidermeyen ve keyif vermeyen uyuştu-rucu madde. Müfsid.","kategori":"dil","osmanli":"هروئك"},{"kelime":"Hesâb Günü","anlam":"Öldükten sonra, dünyada iken yapılan işlerden dolayı insanla-rın sorguya çekilecekleri gün. Kıyâmet günü.","kategori":"akaid","osmanli":"ﮔونى حساب"},{"kelime":"HESÂB (Hisâb)","anlam":"1.Sayma. 2.Öldükten sonra, dünyada yaptıkları işlerden dolayı insanların sorguya çekilmesi.","kategori":"ibadet","misal":"(Ona şöyle diyeceğiz): Oku kitabını, bugün üzerine hesâb görücü olarak nefsin sana yeter. (İsrâ sûresi: 14) İnsanlar niyetlerine göre diriltilecek ve hesaba çekileceklerdir. (Hadîs-i şerîfBuhârî, Müslim, Tirmizî) Hesâb, mîzân (amellerin tartılması) ve Cehennem üzerine kurulacak olan ve nasıl olduğunu bilmediğimiz sırat köprüsü haktır. Muhbir-i sâdık (her sözü doğru olan Resûlullah efendimiz) bunları haber vermiştir.…","osmanli":"حساب"},{"kelime":"HEVÂ","anlam":"Arzu, heves, hoşlanma.","kategori":"dil","misal":"Hevâdan sakının. Şüphesiz hevâ kişiyi sağır ve kör eder. (Hadîs-i şerîf-Secezî)","osmanli":"هوا"},{"kelime":"HEVES","anlam":"Bir şeye duyulan arzu, şevk; gelip geçici istek; zevk, eğlence.","kategori":"dil","misal":"Allah bes, bâkî heves! (Allah yeter, gerisi boş!). (Sâmi Paşa)","osmanli":"هوس"},{"kelime":"HEYBET","anlam":"Korku ile beraber hürmet uyandıran hâl veya görünüş. Mehâbet.","kategori":"dil","osmanli":"هيبت"},{"kelime":"HEYûLÂ","anlam":"1.Bülbül. 2.Bin (sayısı). 3.Pek çok.","kategori":"dil","misal":"Eski felsefecilere göre, ci-simlerin aslı kabul edilen madde. Allahü teâlâya, kâinâtın heyûlâsı ve aslı demek kadar alçaklık olmaz. (Mektûbât-ı Ma’sûmiyye) HEZÂR:هزار (F) Aldın hezâr bütgedeyi eyledin mescid, Nâkus yerlerinde okuttun ezânları. (Bâkî)","osmanli":"هيولاء"},{"kelime":"HEZÎMET","anlam":"Bozgun, mağlubiyet.","kategori":"dil","osmanli":"هزيمت"},{"kelime":"HEZL","anlam":"Şaka, oyuncak, alay, latife, yerme; bir muamelede hakiki maksadını saklayarak görünüşte farklı beyanda bulunmak.","kategori":"muamelat","misal":"O bir hezl değildir. (Târık sûresi: 14) “Allahümmağfirlî hatâî ve âmdî ve hezlî ve ciddî ve lâ tahriminî berekete mâ kadeytenî ve lâ tüftinî fîmâ haremtenî.” (Allah’ım, benim hata ile veya bilerek, şaka veya ciddi olarak yaptığım günahlarımı bağışla. Bana ikram ettiğin bereketinden beni mahrum etme. Bana vermediğin şeyde de beni fitneye düşürme.) (Hadîs-i şerîfBuhârî, Müslim, Ebû Ya’lâ) Üç şey vardır ki, ciddisi de…","osmanli":"هزل"},{"kelime":"HİBE","anlam":"Bağışlama, teberru, bir malı karşılıksız temlik, hediye.","kategori":"muamelat","misal":"Teberru ancak kabz (teslim) ile tamam olur. Mesela bir adam birine bir şey hibe etse kab-le’l-kabz (teslimden evvel) hibe tamam olmaz. (Mecelle, madde: 57)","osmanli":"هبه"},{"kelime":"HİCÂB","anlam":"1.Utanma, sıkılma. 2.Perde, örtü, zar. 3.Konak, makam.","kategori":"dil","misal":"(Bkz. Setr-i Avret) Hanımlardan bir şey istediğiniz zaman hi-câb arkasından isteyin. Bu, hem sizin kalble-riniz, hem de onların kalbleri için daha iyi-dir. (Ahzâb sûresi: 53) İnsanın Allahü teâlânın rızâsına kavuşmasına mâni’ olan en büyük hicâb, onun nefsidir. (Mek-tûbât-ı Ma’sûmiyye)","osmanli":"حجاب"},{"kelime":"HİCÂZ","anlam":"Arabistan yarımadasının batısında Mekke ve Medîne’nin yer aldığı, Kızıl Deniz, Tihâme ve Necd ile çevrelenmiş memleket.","kategori":"dil","osmanli":"حجاز"},{"kelime":"HİCR","anlam":"Kâbe-i Muazzama’nın şimâl duvarı hizâsında, bir kısmı vaktiyle Kâbe’ye dâhil olan yarım dâire şeklindeki duvarcık ile çevrili yer.","kategori":"dil","misal":"Hatîm. Hicr-i İsmâil. Hicr-i Kâbe. Beyt’e (Kâbe’ye) girmek istersen Hicr’de namaz kıl! Orası Beyt’in bir parçasıdır. Çünki kavmin Kâbe’yi tamir ettiği zaman paraları yetmediği için orasını tamamlayamadılar. Onu Beyt’in dışında bıraktılar. Kapısını da, dilediklerini içeri alıp, dilediklerini almamak için yüksek yaptılar. Kavmim, câhiliyetten henüz ayrılmış olmasaydı, Hicr’i Kâbe’nin içine alır, kapısını da yere bitiş…","osmanli":"حجر"},{"kelime":"HİCR SûRESİ","anlam":"80.âyet-i kerîme-sinde geçen ve Sâlih aleyhisselâmın kavminin yaşadığı Şam tarafındaki Hicr adlı memleket-ten alır.","kategori":"dil","misal":"Kur’ân-ı kerîmin on beşinci sûresi. Mekke-i Mükerreme’de nâzil oldu. Doksan do-kuz âyet-i kerîmedir. İsmini İ’tikâd bilgilerine, ahlâka, insanların ve cinnîlerin yaratılışına, târihî ve bilhassa Âdem, İbrâhim, Lût, Şuayb ve Sâlih aleyhi-messelâm ile alâkalı malumat verilmektedir. (Tefsir-i Mazharî)","osmanli":"سى سوره حجر"},{"kelime":"HİCRÂN","anlam":"Ayrılık; ayrılığın sebeb olduğu acı, keder.","kategori":"fikih","misal":"“Kişi sevdiği ile beraber olur” hadîs-i şerîfi, hicrân ateşi ile yananlara tesellî vermektedir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"هجران"},{"kelime":"HİCRET","anlam":"Bir yerden başka bir yere gitmek, göç; Resûlullah aleyhisselâmın Mek-ke-i Mükerreme’den Medîne-i Münevvere’ye göç etmesi.","kategori":"dil","misal":"Hicret iki türlüdür: İkisinden biri, senin günahları terk etmendir. Diğeri ise Allah ve Resûlüne hicret etmendir. (Hadîs-i şerîfMüsnedü Ahmed) Herc (karışıklık), fitne zamanında yapılan ibâdet, benim yanıma (Mek-ke’den Medîne’ye) hicret etmek gibidir. (Hadîs-i şerîfMüslim) Dinini muhâfaza için hicret eden, Cennet ile müjdelendi. Bir mahallede sâlih, ârif kimse kalmayıp, bozukluk ve bid‘at, dinde olmayan şeylerin yap…","osmanli":"هجرت"},{"kelime":"HİCRÎ","anlam":"Hicret’e mensub. Resûlullah aleyhisselâmın hicreti ile başlayan seneye göre olan tarih.","kategori":"dil","osmanli":"هجرى"},{"kelime":"Hicrî Kamerî Sene","anlam":"Resûlullah aleyhisselâmın Medine’ye hicret ettiği senenin 1 Muharrem gününü (Mîlâdî 16 Temmuz 622 Cum‘a gününü) başlangıç olarak alan ve ayın dünya etrâfında on iki defâ dönmesini (354-367 güneş günü) bir yıl kabul eden takvim senesi.","kategori":"dil","osmanli":"سنه قمرى هجرى"},{"kelime":"Hicrî Şemsî Sene","anlam":"Resûlullah aleyhisselâmın hicret ederek Medîne’ye girdiği Eylül ayının 20’nci Pazartesi günü başlayan ve dünyanın güneş etrâfında bir defâ dönmesini (365,242 güneş gününü) esas alan takvim senesi.","kategori":"dil","osmanli":"سنه شمسى هجرى"},{"kelime":"Hicrî Sene","anlam":"Resûlullah aleyhisselâmın Mekke-i Mükerreme’den Medîne-i","kategori":"dil","misal":"Münevvere’ye hicret ettiği seneyi başlangıç olarak alan takvim senesi.","osmanli":"سنه هجرى"},{"kelime":"HİCV","anlam":"Birini sözle, şiir veya nesir yoluyla kötüleme, yerme.","kategori":"dil","misal":"Hassân bin Sâbit, bir defâsında kâfirlerin yüz karasını ortaya koyan bir hicvini okuduktan sonra, Peygamber efendimiz; “Ey Hassân! Müşriklerin, kâfirlerin yüz karalarını ortaya koy! Cebrâil seninledir. Eshâbım silahla harb ettikleri gibi sen de dil ile harb et” buyurdular. (İbni Hişâm)","osmanli":"هجو"},{"kelime":"HIDÂ‘","anlam":"Hîle. Hud’a.","kategori":"dil","misal":"Münâfıklar akıllarınca Allahü teâlâya hıdâ’ yaparlar. Allah da hıdâ’larını başlarına ge-çirir. (Nisâ sûresi: 142)","osmanli":"خداع"},{"kelime":"HIDÂNE","anlam":"1.Çocuğu kucağa almak, besleyip büyütmek üzere yanında bulundur-mak. 2.Nikâhın ölüm veya boşanma ile sona ermesinden sonra, çocuğu yanına almaya salâhiyetli olma.","kategori":"dil","misal":"Babası olmayan çocuğun hıdânesi anneye ait-tir. Boşanmada hıdâne başkası ile evli olmayan annenin hakkıdır. Anne yoksa veya başkasıyla evli ise, çocuk anneanneye, sonra babaanneye verilir. Bundan sonra kız kardeşe, sonra teyzeye verilir. Nafakası ise babaya aittir. Oğlan yedi yaşına gelince, kız bülûğa erince, babasına ve-rilir. (İbni Âbidîn)","osmanli":"حضانه"},{"kelime":"HİDÂNE","anlam":"(Bkz. Hıdâne)","kategori":"dil","osmanli":"حضانه"},{"kelime":"HİDÂYET","anlam":"Doğru yol, doğru yola iletme, yol gösterme; insana Allah tarafından ilham edildiğine inanılan doğru yol.","kategori":"akaid","misal":"Hidâyeti vererek, dalâleti satın aldılar. Bu alışverişlerinde bir şey kazanmadılar. Doğru yolu bulamadılar. (Bakara sûresi:16) Hidâyet yolunu öğrendikten sonra, peygambere uymayıp mü’minlerin yolundan ayrılanı, saptığı yola sürükleriz ve çok fenâ olan Cehennem’e sokarız. (Nisâ sûresi: 114) Kendilerine ilim ve hidâyet verdiğimiz kimseler, ilimlerini insanlardan saklarsa, Allah’ın ve lânet edenlerin lânetleri bunların…","osmanli":"هدايت"},{"kelime":"HIFZ","anlam":"Saklama, koruma; ezberleme. Bir kimse benim hadîsimi dinler, hemen hıfz eder ve tatbik ederse mahşerde Kur’ânla haş-rolur. (Hadîs-i şerîf-Hatîb)","kategori":"hadis","misal":"Îmân beş kal’anın içinde hıfz olunur. 1) Yakîn, 2) İhlâs, 3) Farzları yapma ve haramlardan sa-kınma, 4) Sünnete yapışmak, 5) Edebi gözet-mektir. Her kim bu beş şeyi hıfz ederse, îmâ-nını hıfz etmiş olur. Şâyet birini bile terk ederse düşman gâlib olur. (Miftahü’l-Cenne)","osmanli":"حفظ"},{"kelime":"HİKÂYE","anlam":"Anlatma, bir hâdisenin sözlü veya yazılı anlatılması.","kategori":"hadis","osmanli":"حكايه"},{"kelime":"HIKD","anlam":"Başkasına kin tutma, düşman-lık besleme.","kategori":"dil","misal":"Üç şeyden biri bulunmayan kimsenin bü-tün günahlarının af ve mağfiret olunması umulur: Şirke, küfre yakalanmadan ölmek, sihir yapmamak ve din kardeşine hıkd. (Ha-dîs-i şerîf-Taberânî)","osmanli":"حقد"},{"kelime":"HİKMET","anlam":"1.Bilgelik, ilim, iyiyi kötü-den, doğruyu yanlıştan ayırabilme kuvveti.","kategori":"hadis","misal":"Allahü teâlâ dilediği kimseye hikmet verir. Hikmet verilen kimseye muhakkak çok ha-yır verilmiştir. (Bakara sûresi: 269) Hikmetin başı Allah korkusudur. (Hadîs-i şerîf-Beyhekî, Deylemî) Hikmet, mü’minin kayıp malı-dır. Nerede bulursa alsın. (Hadîs-i şerîf-Tir-mizî) Şiirin bazısı hikmettir. (Hadîs-i şerîf-Ebû Dâvûd) Peygamberlik. Allahü teâlâ ona (Dâvûd aleyhisselâma) sal-tanat ve hikmet verdi. (Bakara sûresi: 251) Sünnet (Kitab ile beraber). Daha önce apaçık bir sapıklık içinde bulu-nuyorlarken, Allahü teâlâ içlerinden, on-lara, âyetlerini okur, onları tertemiz yapar, onlara Kitabı ve hikmeti öğretir bir peygam-ber gönderdiği gibi mü’minlere büyük bir lütûfta bulunmuştur. (Âl-i İmrân sûresi: 164) Sebeb; ilahî emir ve yasakların herkesçe an-laşılması mümkün olmayan maksadı. Hak teâlânın fi’li illet ve sebebden hâlidir. Fa-kat hikmet ve maslahattan hâlî değildir. (Mek-tûbât-ı İmâm-ı Rabbânî)","osmanli":"حكمت"},{"kelime":"HİLÂF","anlam":"Karşı, muhâlif, zıt; muhalefet, zıtlık; fıkhî meselelerde kişinin muhatap-","kategori":"fikih","misal":"larını kendi kanaati istikametinde deliller bu- larak ikna ve ilzama çalışmasını ihtiva eden ilim (ilm-i hilâf). İcmâ’, dört şer’î delilden biridir. Hiç hilâf olmadığı zaman, kat’î kesin olur. Bir hilâf bulunursa, bu hilâf şâz ve nâdir olsa bile, bu icmâ’ zannî olur. Kat’î olmaz. (Mir’atü’l-Usûl)","osmanli":"خلاف"},{"kelime":"Hilâf-ı Evlâ","anlam":"1.Mendub ve müstehâbı terk etmek. 2.İki işten daha az sevablı olanı.","kategori":"fikih","misal":"Cenazenin sağında solunda yürünmez. Bunda bir beis yoktur, da denilmiştir. Bu söz yürümenin hilâf-ı evlâ olduğunu gösterir. Zira bunda mendubu (yani cenaze ardından yürümeyi) terk etmek vardır. (İbni Âbidîn)","osmanli":"اولى خلاف"},{"kelime":"HİLÂFET","anlam":"1.Birinin yerine geçme, halef olma. 2.İslâm devletinin reisliği. 3.Bir tasavvuf mürşidinin yetiştirdiği talebe-sini başkalarını da yetiştirmekle vazifelendir-mesi.","kategori":"dil","misal":"Benden sonra hilâfet otuz senedir. Sonra sultanlık gelir. (Hadîs-i şerîf-Tirmizî) (Bkz. Halîfe) Kendisine hilâfet verilecek zâtın bâtınının (yani kalbi ve diğer dört latîfesinin) nisbete ve hâl-lere kavuşmuş olması, kötü huylardan temiz-lenmiş, iyi huylarla süslenmiş olması ve sabr, tevekkül, kanâat, rızâ, teslim sahibi olması dün-yaya düşkün olmaması lâzımdır. (Mekâtib-i Abdullah-ı Dehlevî)","osmanli":"خلافت"},{"kelime":"Hilâfet-i Mutlaka","anlam":"(Bkz. Halîfe-i Mutlaka)","kategori":"dil","osmanli":"مطلقه خلافة"},{"kelime":"HİLÂL","anlam":"Yeni ay.","kategori":"dil","misal":"Hilâli görünce oruca başlayınız! Hilâli gö-rünce bayram ediniz. Eğer hava bulutlu olursa (Şâban ayını) otuz gün sayınız. (Ha-dîs-i şerîf-Müslim)","osmanli":"هلال"},{"kelime":"HÎLE","anlam":"1.Çare, çıkış yolu. 2.Aldatmak, yanıltmak, hud’a.","kategori":"dil","misal":"Hîle ile rızık artmaz. Malın bereketini giderir. Hîle ile azar azar biriktirilen şeyler, ansızın ge-len bir felâketle, birden bire giderek geride yal-nız günahları kalır. Her sanatta hîle yapmamak farzdır. Çürük iş yapmak ve gizlemek haram-dır. (Kimyâ-i Saadet)","osmanli":"حيله"},{"kelime":"Hîle-i Bâtıla","anlam":"Şeriatın emirlerini yerine getirmekten kaçınmak için yapılan hîle.","kategori":"fikih","misal":"Nisâba mâlik kimsenin, bir sene tamam olmadan önce, malını güvendiği birine temlik etmesi, sene tamam olduktan sonra geri alması, böylece zekâtın farz olmasına mâni’ olmak için hî-le-i bâtıla yapması câiz değildir. (İbni Âbidîn)","osmanli":"باطله حيلهء"},{"kelime":"Hîle-i Şer‘iyye","anlam":"İslâmiyet’e uy-makta mâni, fesat bulunduğu zaman, bu va-zifeyi yapabilmek için, dinin gösterdiği başka yoldan gitmek. Şer’î çare. Mahreç.","kategori":"dil","misal":"Bir zengin, bir fakîrde olan alacağını, ona ve-receği zekât yerine sayamaz. Çünki, ayn (mev-cut) olan malın zekâtı, deyn (borç) olan maldan verilmez. Fakirdeki alacağını zekâtına saymak isteyen kimse, fakîre zekâtını verip, sonra borcu için bunu tekrar geri alır. Böyle hîle-i şer’iyye yapmak câizdir. (Eşbâh)","osmanli":"شرعيه حيلهء"},{"kelime":"HILF","anlam":"1.Yemîn, sözleşme, half, hilf. 2.Birlik, ittifak, yardımlaşma.","kategori":"dil","osmanli":"حلف"},{"kelime":"HİLKAT","anlam":"Yaratılış, yaratılma; doğuş-tan gelen vasıf, cibilliyet, tabiat. (Bkz. Fıtrat) İnsanın hilkatından maksat, kulluk vazifele-rini yapmaktır. (Mektûbât-ı İmâm-ı Rabbânî) Yûsuf aleyhisselâmın hilkati ve hüsn (güzellik) ve cemâli (yüz güzelliği), bu dünyada meydana gelen hilkat, hüsn ve cemâl cinsinden değildir. Onun cemâli, cemâl-i behişetiyân cinsinden idi. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"dil","osmanli":"خلقت"},{"kelime":"HİLL","anlam":"Hac veya umre için ihrâma giri-len mîkât denilen yerler ile Harem yani Mekke şehri sınırı arasına verilen isim.","kategori":"ibadet","misal":"Harem adı verilen yerde ihramlı iken yapılması haram (yasak) edilen şeyler, burada helâl ol-duğu için Hill adı verilmiştir. Mîkâttan geçer-ken bir iş için Hill’de kalmayı niyet edenlerin ve Hill’de oturanların hacdan başka niyetle ih-râmsız Harem’e girmeleri câizdir. Meselâ Cidde şehri Hill’dedir. Hac için, Hill’de oturanlar Hill’de; Harem’de oturanlar Harem’de ihrâma girerler. (Mevkûfât)","osmanli":"حل"},{"kelime":"HİLM","anlam":"Yumuşak huylu olmak, sâkin-lik, kızmamak.","kategori":"dil","misal":"İlim, mü’minin dostudur. Akıl delili, amel bekçisi, hilim veziri, sabır ser’askeri, rıfk babası, yümuşaklık ta kardeşidir. (Hadîs-i şerîf-Hakîm, Deylemî) Kıyâmette yüksek derece isteyen, kendisine zulmedeni affet-sin, kendisine vermeyene versin, kendisini yoklamayanı yoklasın ve kendisine cahilice davranana hilm ile muamele etsin. (Hadîs-i şerîf-Hatîb, İbni Adiyy) İlmin hilme eklenme-sinden daha fazîletli iki şey birbirine eklen-memiştir. (Hadîs-i şerîf-Taberânî) Tövbeyi ihmal etmekten sakın! Allah’ın hilmine al-danma! (Hadîs-i şerîf-Deylemî)","osmanli":"حلم"},{"kelime":"HİLTİT","anlam":"Adale ve sinir gerginliğini gidermek için kullanılan fena kokulu, esmer bir çeşit reçine, şeytân tersi.","kategori":"tasavvuf","misal":"Hiltit adındaki zamkı yanında taşıyan kimseye cin gelmez. Sara hastası, bunu koklarsa, şifâ bulur. (SüyûtîKitâbürrahme)","osmanli":"حلتيت"},{"kelime":"HİLYE","anlam":"İnsandaki dış güzellikler, de-ğerli hasletler.","kategori":"dil","osmanli":"حليه"},{"kelime":"HİLYE-İ SEÂDET","anlam":"Hazret-i Peygamber’in görünüşü, sıfatları, isimleri ve güzel huyları.","kategori":"akaid","osmanli":"سعادت حليهء"},{"kelime":"HİMÂ","anlam":"Kimsenin giremediği, umumi-yetle hükümete ait otlak veya koru.","kategori":"dil","osmanli":"هما"},{"kelime":"HIMÂR","anlam":"Başörtüsü.","kategori":"dil","misal":"Mü’min kadınlara söyle:… Hımârlarını ya-kalarının üzerine kadar örtsünler. (Nur sû-resi: 31)","osmanli":"خمار"},{"kelime":"HİMÂR","anlam":"Erkek eşek, hamîr. HİMÂYE: حمايه (A) Koruma, esirgeme. HİML: حمل (A) Bir deve yükü.","kategori":"dil","osmanli":"حمار"},{"kelime":"HİMMET","anlam":"1.Gayret; mânevî yardım, ihsan; bir şeye bütün mesaisini teksif etme, o noktaya odaklanma. 2.Evliyânın tesir ve yardımı.","kategori":"dil","misal":"Bir kimsenin himmeti Ağzından girenden ibaretse birinin himmeti, Bağırsaklarından çıkan kadardır onun kıymeti. (İmâm Şâfiî) Evliyânın himmeti, yaktı beni kül eyledi Sofiyim buldum safâyı dü cihanım kalmadı. Ahmedî der; “Yâ ilâhî! Sana şükrüm çok durur Hamdülillah aşk-ı Hak’tan gayrı vârım kalmadı. (Sultan I. Ahmed) Ubeydullah-i Ahrâr buyuruyor ki: Himmet et-mek, Allahü teâlânın isimleri ile münâsebeti olan bir zâtın, kalbinde yalnız bir işin yapılmasını bulundurması demektir. Bu şeye teveccüh eder. Kalbine bundan başka hiçbir şey getirmez. Yal-nız, o işin yapılmasını ister. Allahü teâlâ da o işi yaratır. Allahü teâlânın âdeti böyledir. Kâ-firlerin himmet ettikleri şeylerin de hâsıl olduk-ları görülmüştür. Allahü teâlâ, bana bu kuvveti ihsân etmiştir. Fakat, bu makamda edeb lâzım-dır. Edeb de, bendenin kendisini Hak teâlânın irâdesine tâbi’ etmesidir. Hakk’ı kendi irâdesine tâbi’ etmemektir. Hak teâlânın fermânına mun-tazır olmaktır. İrâdesi te’allûk edip fermân bu-yurunca, himmet etmektir. (Reşahât)","osmanli":"همت"},{"kelime":"HİMYER","anlam":"Yemende bir şehir.","kategori":"dil","misal":"Nûh aleyhisselâmdan sonra Arabistan yarım adasında yerleşenlere Arab-ı bâide denir. Âd, Semûd ve Amâlika bunlardandır. Hûd aleyhis-selâm Âd kavmine, Sâlih aleyhisselâm Semûd kavmine gelmişlerdir. Hepsi Sâm soyundandır. Bunlardan sonra, gelip Yemene yerleşen Kah-tân evlâdlarına Arab-ı âribe denir. Bunlar Ye-men’de Himyer devletini kurdu. Bu devlet çö-künce, önce Habeşliler, sonra İranlılar Yemene vâlî ta’yîn ettiler. Etrâfa dağılan Himyerîlerden Medîne’de Evs ve Hazrec kabileleri meydâna geldi. Şam tarafına gelenler, Gassân devletini kurup Hristiyan oldular. Irak’a gelenler Hîre devletini kurdu. (Mir’at-ı Kâinât)","osmanli":"حمير"},{"kelime":"HİNDû","anlam":"1.Siyah (renkli insan). 2.Si-yah ben, benek. 3.Hindistan’ın Mecusî halkı.","kategori":"dil","misal":"HİNDûLuK: هندولق (T) Hindistan’da Brahma dininden gelen prensiplerin, bir takım efsane ve hurafelerle karışmasından meydana gelen, kâinâtın yüce yaratıcısı Brahma’dan başka Şiva, Râma ve Krişna adında üç tanrının yeryüzünü idare ettiğine inanılan bir din. Hinduizm.","osmanli":"هندو"},{"kelime":"HINS","anlam":"1.Günaha yönelme. 2.Yemîni bozma.","kategori":"dil","osmanli":"حنث"},{"kelime":"HİPNOTİK","anlam":"Uyutucu; aklı da, hissi de gideren madde. Mürkıd. Münevvim.","kategori":"dil","osmanli":"هﭙنوتيك"},{"kelime":"HİPOTEZ","anlam":"Faraziyye.","kategori":"muamelat","osmanli":"هﭙوتز"},{"kelime":"HİRÂ","anlam":"Mekke-i Mükerreme’nin 3 mil kuzeydoğusunda Hazret-i Peygamber’e ilk vahyin geldiği dağ ile mağara.","kategori":"dil","misal":"Cebelü’n-Nûr. Nur Dağı.","osmanli":"حرا"},{"kelime":"HİRÂM","anlam":"Salınma, salınarak edalı edalı yürüme.","kategori":"dil","osmanli":"خرام"},{"kelime":"HIRİSTİYAN","anlam":"Mesîh kelimesinin Yunancası Hristos’dan gelen ve Îsâ aleyhisselâma inananlara havâriler devrinde Antak-ya’da verilen isim; Îsâ aleyhisselâmın dininden olan.","kategori":"dil","misal":"İsevî. Mesîhî. Nasrânî.","osmanli":"خريستيان"},{"kelime":"HIRİSTİYANLIK","anlam":"Îsâ aleyhisselâmın dini.","kategori":"dil","misal":"İsevîyye. Mesîhiyye. İsevîlik. Nasrânîlik.","osmanli":"خريستيانلق"},{"kelime":"HIRKA","anlam":"İnce yünden veya pamuk-ludan, umumiyetle kapitone dikişli önü açık üstlük, kısa ceket.","kategori":"dil","osmanli":"خرقه"},{"kelime":"HIRKA-İ SEÂDET","anlam":"Hazret-i Peygamber aleyhisselâmın, Eshâb-ı kirâmdan Kâ’b bin Züheyr’e, yazdığı kasîdeden dolayı hediye ettiği ve Topkapı Sarayı’nda saklanan hırka.","kategori":"dil","osmanli":"سعادت خرقه"},{"kelime":"HIRKA-İ ŞERÎF","anlam":"Hazret-i Peygamber aleyhisselâmın, Tâbiînden Veysel Karenî’ye hediye ettiği ve İstanbul’da saklanarak Ramazan ayında Hırka-ı Şerif Câmii’nde ziyarete açılan hırka.","kategori":"dil","osmanli":"شريف خرقۀ"},{"kelime":"HIRS","anlam":"Bir şeye aşırı düşkünlük, şid-detli istek, tutku.","kategori":"dil","misal":"Hırstan sakınınız. Zira hırs, Âdem aleyhis-selâmın Cennet’ten çıkarılmasına sebeb ol-muştur. (Hadîs-i şerîf-İbni Asâkir)","osmanli":"حرص"},{"kelime":"HIRSIZLIK","anlam":"Başkasına ait bir malı mülk edinme kasdıyla gizlice alma.","kategori":"muamelat","misal":"Sirkat.","osmanli":"خريسيزلق"},{"kelime":"HIRZ","anlam":"1.Korunmuş yer, sığınak; malı ve canı koruyan. 2.Takıldığı zaman insanı ko-ruduğuna inanılan muska, nazar boncuğu vs.","kategori":"dil","osmanli":"حرز"},{"kelime":"HİSÂB (Hesâb)","anlam":"Sayma; öldükten sonra, dünyada yaptıkları işlerden dolayı insanların sorguya çekilmesi.","kategori":"ibadet","misal":"(Bkz. Hesâb)","osmanli":"حساب"},{"kelime":"HİSÂR","anlam":"1.Kuşatma, etra-fını alma. 2.Kale, etrafı istihkâmlı kale, bend.","kategori":"dil","misal":"(A. Hasr’dan)","osmanli":"حصار"},{"kelime":"HİSBET (Hisbe)","anlam":"1.Bir şeyi hasbî olarak, yani Allah rızası için yapma. 2.El ile emr-i maruf ve nehy-i münker; İslâm devletinin muhasebe dairesi; hükûmetin emr-i maruf ve nehy-i münker ile vazifelendirdiği merci, ahlâk zâbıtası. Emr-i ma’rûf ve nehy-i münkeri el ile yapmak hükûmet adamlarına, dil ile yapmak din adamlarına, kalb ile yapmak da her Müslümana farzdır. El ile yapmaya, hisbet denir. Dili ile yapmaya, va‘z ve nasihat denir. Hisbet yaparak çalgıları, içki şişelerini kırmak yalnız hükûmet me’murlarının vazifesi olduğu için, başkaları kırarsa öderler. Hisbet yapmak, el ile mâni olmak din adamlarına farz değil ise de, günah işlenirken…","kategori":"akaid","osmanli":"حسبت"},{"kelime":"HISN","anlam":"Kale, hisar, muhafazaya mah-sus yer.","kategori":"dil","osmanli":"حصن"},{"kelime":"HİSSE","anlam":"Bölünebilen bir mal veya şeyin her ortağa ait olan kısmı, pay.","kategori":"miras","misal":"Bir sığırı veya deveyi, yedi kişiye kadar Müslüman, bâliğ kimseler, ortak olarak satın alıp kesebilirler. Sekiz kişinin yedi sığırı ve iki kişinin iki koyunu ortak satın almaları câiz olmaz. Çünki her birinin her hayvanda hissesi vardır. (Fetâvâ-i Hindiyye) Bir mülk-i müşterek ta’mîr ve termîme muhtaç oldukta sahipleri hisselerine göre bi’l-iştirâk ta‘mîr ederler. (Mecelle, m.1308)","osmanli":"حصه"},{"kelime":"Hisse-i Şâyi‘a","anlam":"Yaygın hisse. Bir şeye ortak olanların taksim edilmemiş paylarından her biri.","kategori":"ibadet","misal":"Bir kimse evini iki kişiye hediye etse, câiz olmaz. Çünki taksimi mümkün olmayan şeyi hisse-i şâyia olarak vermek câiz değildir. (İbni Âbidîn)","osmanli":"شايعه حصهء"},{"kelime":"HİSSE SENEDİ","anlam":"Bir şirketin sermayesinin halka satılmak üzere ayrılmış ve satılan kimsenin şirkete ortak olması neticesini doğuran parçalarından her birini gösteren sened.","kategori":"hadis","osmanli":"سندى حصه"},{"kelime":"HİSSEDÂR","anlam":"Hissesi olan, hisse sâbibi.","kategori":"miras","osmanli":"دار حصه"},{"kelime":"HİSSÎ","anlam":"His (duygu) ile alâkalı.","kategori":"dil","osmanli":"حسى"},{"kelime":"HİSTERİ","anlam":"Sinir buhranı gibi emâ-relerle dışa vurulan nevroz, sinir hastalığı.","kategori":"dil","osmanli":"هسترى"},{"kelime":"HIŞVÎ (Haşevî)","anlam":"Âyet ve hadîslere hep zâhirî mânâ verenler.","kategori":"dil","misal":"(Bkz. Haşeviyye)","osmanli":"خشوى"},{"kelime":"HİTÂBE","anlam":"Bir topluluk önünde yapılan yol gösterici ve heyecanlı konuşma.","kategori":"dil","osmanli":"خطابه"},{"kelime":"HİTÂN","anlam":"(Bkz. Hıtân)","kategori":"dil","osmanli":"ختان"},{"kelime":"HITÂN (Hitân)","anlam":"Sünnet olma.","kategori":"hadis","osmanli":"ختان"},{"kelime":"HIYÂNET","anlam":"Hâinlik; mukaddes bir şeye hürmetsizlik; itimadı kötüye kullan-mak; vefasızlık.","kategori":"dil","misal":"Kendilerine hıyânet edenlerle uğraşma! Allah, hâinlikte direnen günahkârları sev-mez. (Nisâ sûresi: 107) Ümmetim hıyanet etmezse düşman onun karşısında ebedi-yen duramaz. (Hadîs-i şerîf-Deylemî) Ticâ-rete hıyânet karışırsa bereket gider. (Hadîs-i şerîf-Kimyâ-i Seâdet)","osmanli":"خيانت"},{"kelime":"HIYÂR","anlam":"Seçme hakkı, muhayyerlik, obsiyon; yapılan bir akdden yani sözleşme-den vazgeçebilmek hakkı. (Bkz. Muhayyerlik)","kategori":"dil","osmanli":"خيار"},{"kelime":"HİZÂ","anlam":"Karşı; sıra.","kategori":"dil","misal":"Cemâ‘at ile kılan adam, aynı imâma uyan her-hangi bir kadınla, bir rükn mikdarı bir hizâda durursa ve aralarında kalın perde veya par-maktan kalın bir direk yâhud bir insan sığa-cak kadar açıklık yoksa, erkeğin namazı bozu-lur. Aynı imâma uymayan bir kadının, erkekle bir hizâda kılmaları mekrûhtur. (İbni Âbidîn)","osmanli":"حذاء"},{"kelime":"HİZB","anlam":"1.Bölük, parça; parti. 2.Kur’ân-ı kerîmin 20 sayfadan meydana gelen cüzleri-nin dörtte biri olan beş sahife.","kategori":"dil","misal":"Kim Allah’ı, Peygamberini ve mü’minleri yâr edinir yardımda bulunursa, şüphesiz onlar, Allahü teâlânın hizbidir. Üstün gele-cek olanlar onlardır. (Mâide sûresi: 56) Bun-ları şeytân kaplamış ve Allah’ı hatırlamayı kendilerine unutturmuştur. Bunlar şeytâ-nın hizbidirler. Hizbü’ş-Şeytân muhakkak hüsrâna düşenlerdir. (Mücâdele sûresi: 19)","osmanli":"حزب"},{"kelime":"HIZIR (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde açıkça ismi geçmemekle beraber kendisinden işaretle bahsedilen ve hadîs-i şerîflerle bildirilen bir Benî İsrâîl peygamberi veya velîsi.","kategori":"dil","misal":"Kur’ân-ı kerîmde açıkça ismi geçmemekle beraber kendisinden işaretle bahsedilen ve hadîs-i şerîflerle bildirilen bir Benî İsrâîl peygamberi veya velîsi. Hazret-i Hızır, Zülkarneyn aleyhisselâmın askerinin kumandanı ve teyzesinin oğludur. Mûsâ aleyhisselâm ile görüşüp yolculuk etti. Muhammed aleyhisselâmın ümmetinden değildir. Fakat vefâtından sonra rûhu insan şeklinde gözüküp garîblere, kimsesizlere yardım etmektedir. Mûsâ aleyhisselâm ile karşılaşmaları ve birlikte yolculuk yapmaları Kur’ân-ı kerîmin Kehf sûresi 60-82. âyetlerinde bildirilmiştir. (Râzî, İbn-i Hacer…","osmanli":"خضر"},{"kelime":"HİZMET","anlam":"1.Bir şey uğruna çalışma, vazife. 2.Birinin işini görme. 3.Ücret karşılı-ğında iş görmek üzere yapılan akid.","kategori":"dil","misal":"Bir kavmin efendisi, ona hizmet edendir. (Hadîs-i şerîf-Ebû Nuaym, Hâkim) Anne ve babanız sizin hizmetinize muhtaç iseler, on-lara hizmeti canınıza minnet biliniz. (Ha-dîs-i şerîf-Riyâdu’n-Nâsihîn)","osmanli":"خدمت"},{"kelime":"HOCA","anlam":"Muallim; Müslüman din adamı. Aslı Farsça efendi mânâsına ‘hâce’ kelimesidir.","kategori":"ibadet","osmanli":"خواجه"},{"kelime":"HÔD","anlam":"1.Kendi. 2.Miğfer.","kategori":"dil","osmanli":"خود"},{"kelime":"HODBÎN","anlam":"Kendini gören, kendini beğenmiş, bencil, egoist.","kategori":"dil","osmanli":"بين خود"},{"kelime":"HODGÂM","anlam":"Kendini arzulayan, ken-dini beğenmiş, bencil, egoist. Hôd-pesend. HOKKA: حقه (A) İçine bilhassa mürekkep konu-","kategori":"dil","misal":"lan ağaç, metal, porselen veya camdan oyul- muş yuvarlak küçük kutu. Aslı Arabca oyul-muş mânâsına hukka kelimesidir.","osmanli":"خودﮔام"},{"kelime":"HOMOSEKSÜEL","anlam":"Hemcinsine seksüel alâka duyan.","kategori":"dil","osmanli":"هوموسكسوئل"},{"kelime":"HOPARLÖR","anlam":"Ses yükseltici âlet.","kategori":"dil","osmanli":"هوﭘارلور"},{"kelime":"HOPPA","anlam":"Yersiz davranan, dileğince hareket eden, delişmen.","kategori":"dil","osmanli":"هوﭘا"},{"kelime":"HOR","anlam":"Ehemmiyetsiz, değersiz, bayağı, âdî. HORASÂN: خراسان (F) “Güneşin doğduğu memleket” mânâsına İran’ın doğusunda bu-","kategori":"dil","misal":"lunan geniş belde.","osmanli":"خور"},{"kelime":"HÖRGÜC","anlam":"Deve sırtındaki çıkıntı. Aslı Eski Türkçe’de yükselen mânâsına örgüş kelimesidir.","kategori":"dil","osmanli":"هورﮔوج"},{"kelime":"HOŞNûD","anlam":"Râzı, memnun, şikâyeti olmayan.","kategori":"dil","osmanli":"خوشنود"},{"kelime":"HOYRAT","anlam":"Kaba insan. Aslı Yunanca horyatis kelimesidir.","kategori":"dil","osmanli":"خويراد"},{"kelime":"Hubb-i Sivâ","anlam":"Allahü teâlâdan başka şeylerin sevgisi. (Bkz. Mâsivâ)","kategori":"akaid","osmanli":"سوا حب"},{"kelime":"HuBûBAT","anlam":"Habbeler, taneler, tohum-lar; buğday, arpa, çavdar gibi taneli bitkiler, ta-hıl. Habb’ın çokluk hâli olan hubûb’un cem‘idir.","kategori":"dil","osmanli":"حبوبات"},{"kelime":"HuCCET (Hüccet)","anlam":"1.Sened, vesîka, delil, burhân; mahkemelerde kâdının verdiği hükmün yazıldığı vesika. 2.Sözü ilimde sened olan âlim. 3.Şiîlikte İmâm ve ondan sonra dinin en salâhiyetli kişisi için kullanılan tabir.","kategori":"osmanli","misal":"Lâilâhe illallah öyle bir sözdür ki, Allah katında lehinize hüccet olur. (Hadîs-i şerîfMüslim) Mu’âz radıyallahü anh, Yemen’e gidince ictihâd edeceğini bildirdiği zaman, Resûlullah aleyhisselâmın râzı olup hamd etmesi, kıyâsın huccet olduğunu göstermektedir. (Şerhu Menâr)","osmanli":"حجت"},{"kelime":"Hüccet-ül İslâm","anlam":"(Bkz. Huccetü’l-İslâm)","kategori":"dil","osmanli":"الاسلام حجة"},{"kelime":"HuCCETÜ’L-İSLÂM","anlam":"Üç yüz bin hadîs-i şerîfi, senedleri (rivâyet edenleri) ile birlikte ezbere bilen İslâm âlimi; dinde söz sahibi mânâsına İmâm-ı Gazâlî hazretlerinin lakabı.","kategori":"hadis","osmanli":"الاسلام حجة"},{"kelime":"HuCEC","anlam":"Vesikalar; deliller. Huccet’in çokluk hâli.","kategori":"dil","osmanli":"حجج"},{"kelime":"HÜCEYRE","anlam":"Hücrecik, küçük delik.","kategori":"dil","osmanli":"حجيره"},{"kelime":"HÜCRE","anlam":"1.Oda. 2.Medreselerde tale-benin kalmasına mahsus oda.","kategori":"osmanli","osmanli":"حجره"},{"kelime":"HÜCRE-İ SEÂDET","anlam":"Medîne-i Münevvere’de Mescid-i Nebevî içinde Hazret-i Peygamber aleyhisselâmın kabrinin bulunduğu oda.","kategori":"dil","misal":"Peygamber efendimiz, hicretin 11 (m. 632) senesi Rebî‘ulevvel ayının onikinci pazartesi günü hanımlarından Hazret-i Âişe’nin odasında vefât etti. Hazret-i Ebû Bekr’in rivâyet ettiği; “Peygamberler vefât ettikleri yere defnolunurlar” hadîs-i şerîfi gereğince, buraya defnedildi. (Kısâs-ı Enbiyâ)","osmanli":"سعادت حجرۀ"},{"kelime":"HÜCûM","anlam":"Askerin düşman üzerine taarruzu; iki hasım tarafın birbirlerinin üze-rine yürümeleri.","kategori":"dil","osmanli":"حجوم"},{"kelime":"HÜCûM","anlam":"Saldırış, saldırma; birine çatma.","kategori":"dil","osmanli":"هجوم"},{"kelime":"HuCuRÂT SûRESİ","anlam":"Kur’ân-ı kerîmin kırk dokuzuncu sûresi.","kategori":"dil","misal":"Medîne’de nâzil oldu. On sekiz âyet-i kerîmedir. Dördüncü âyet-i kerîmede geçen ve Resûlullah’ın evinin kasdedildiği hücreler mânâsına Hucurât kelimesinden dolayı sûreye bu isim verilmiştir. Sûrede, bir kısım ahlâk ve âdâb kâideleri ile Resûlullah aleyhisselâma ve insanların birbirlerine karşı nasıl davranacakları bildirilmektedir. Kim Hucurât sûresini okursa, Allahü teâlâya itâat edenlerin sevâbı kadar sevab verili…","osmanli":"سى سوره حجرات"},{"kelime":"HûD (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen peygamberlerden.","kategori":"dil","misal":"Âd kavmine, kardeşleri Hûd’u gönderdik. O dedi ki: “Ey kavmim! Allah’a kulluk edin; sizin O’ndan başka tanrınız yoktur. Hâla ona karşı gelmekten sakınmayacak mısınız?” (A’râf sûresi: 65)","osmanli":"هود"},{"kelime":"HûD SûRESİ","anlam":"Kur’ân-ı kerîmin on birinci sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Yüz yirmi üç âyet-i kerîmedir. Bir kısmında Hûd aleyhisselâmdan bahsedildiği için bu ismi almıştır. İman esaslarından ve bazı peygamberlerin kıssalarından bahsedilir. (Mefâtihü’l-Gayb) Hûd sûresi beni ihtiyârlattı. (Hadîs-i şerîfTirmizî)","osmanli":"سى سوره هود"},{"kelime":"HÜDÂ","anlam":"Doğru yolu gösterme, hidâyet; Kur’ân-ı kerîm.","kategori":"dil","osmanli":"هدى"},{"kelime":"HuDÂVENDİGÂR","anlam":"Efendi, sa-hip, hükümdar.","kategori":"dil","osmanli":"خداوندﮔار"},{"kelime":"HÜDÂVENDİGÂR","anlam":"(Bkz. Hudâvendigâr)","kategori":"dil","osmanli":"خداوندﮔار"},{"kelime":"HuDDÂM","anlam":"1.Hizmet edenler, hademe. 2.Cincilerin faaliyetlerinde yardım aldık-ları cinler.","kategori":"akaid","misal":"Âhiretin tâlibleri dörttür: Zâhidler, fakirler, hud-dâm ve âbidler. (Mekâtîb-i Şerîfe) İ‘anet ve imdâd (yardım ve meded) akrandan olursa naks (noksanlık), huddâmdan (hizmet-çiden) olursa, kemâldir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خدام"},{"kelime":"HuDû‘","anlam":"Boyun eğmek, alçak gö-nüllülük.","kategori":"dil","misal":"Namazın kusursuz olması; dinî hükümleri bil-diren fıkıh kitaplarında genişçe yazılmış olan farzlarını, vâciblerini, sünnetlerini ve müstehâb-larını yerlerine getirmekle olur. Namazı tamam-lamak için, bu dört şeyden başka yapılacak bir şey yoktur. Namazda huşû‘ yani her uzvun tevâzû göstermesi, bu dört şeyi yapmakla hâ-sıl olur. Kalbin hudû‘u da, yine bunları tamam yapmakla olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خضوع"},{"kelime":"HuDûD","anlam":"Sınırlar.","kategori":"dil","osmanli":"حدود"},{"kelime":"HuDûR (Huzur)","anlam":"Hâzır olma; kalbde devamlı Allahü teâlâyı bulundurma, Allahü teâlâ ile beraber olmak, O’nu unutmamak.","kategori":"akaid","misal":"(Bkz. Huzûr)","osmanli":"حضور"},{"kelime":"HuFRE","anlam":"Kazılmış çukur, oyuk, delik. Kâfirin kabri, Cehennem’den bir hufredir. (Hadîs-i şerîf-Tirmizî)","kategori":"hadis","osmanli":"حفره"},{"kelime":"HuKBE","anlam":"Seksen sene. Her senesi üç-yüzaltmış gün, her günü seksen dünya senesi. Bir namazı özürsüz vaktinden sonra kılan, seksen hukbe Cehennem’de yanacaktır. (Ha-dîs-i Şerîf-Deylemî)","kategori":"ibadet","osmanli":"حقبه"},{"kelime":"HuKEMÂ","anlam":"(Bkz. Hükemâ, Hakîm)","kategori":"dil","osmanli":"حكماء"},{"kelime":"HÜKKÂM","anlam":"Hüküm verenler. Hâkim’in çokluk hâli.","kategori":"dil","osmanli":"حكام"},{"kelime":"HÜKM (Hüküm)","anlam":"1.Hâkimiyet sürme. 2.Herhangi bir mevzu hakkında varılan karar, emir.","kategori":"fikih","misal":"Her birine hükm ve ilim vermiştik. (Enbiyâ sûresi: 79) İşte onlar kendilerine Kitab, hükm ve nübüvvet verdiğimiz kimselerdir. (En‘âm sûresi: 89) Allahü teâlânın mü’minler hakkındaki hükmüne hayret ettim. Ona genişlik takdîr eder ve kulu buna râzı olursa, kulun hakkında hayırlı olur. Şâyet darlık ile hükmeder de yine kulu buna râzı olursa, bu da hakkında hayırlıdır.…","osmanli":"حكم"},{"kelime":"Hükm-i Küllî","anlam":"Umumî kâide. Allahü teâlâya âit hüküm, emir.","kategori":"akaid","misal":"Zamanın değişmesi ile, örf ve âdete dayanan ahkâm değişebilir. Nassa, delile dayanan ahkâm, zamanla değişmez. Hükm-i küllî değişmeyip, bu hükmün hâdiselere tatbiki zamanla değişebilir. (Dürerü’l-Hükkâm)","osmanli":"كلى حكم"},{"kelime":"HÜKMÎ","anlam":"Hükme ait, hükümle alâkalı; bir karara dayanan; itibarî.","kategori":"fikih","osmanli":"حكمى"},{"kelime":"HÜKMÎ TEMİZLİK","anlam":"Kadından kan gelmesine rağmen hayz veya nifas kabul edilmeyen hâl.","kategori":"fikih","misal":"Tuhr-i hükmî. (Bkz. Tam Temizlik)","osmanli":"تميزلك حكمى"},{"kelime":"HuKûK","anlam":"1.Haklar. 2.Cemiyette yaşayan insanların hak ve mükellefiyetlerini tanzim eden, böylece adalet ve emniyetin tecellisine hizmet eden ve devlet müeyyidesine bağlanmış kâideler bütünü.","kategori":"fikih","osmanli":"حقوق"},{"kelime":"HÜKÜMDÂR","anlam":"Hüküm sahibi; şah, pâdişâh.","kategori":"osmanli","osmanli":"حكمدار"},{"kelime":"HÜKûMET","anlam":"1.Hüküm sürme, hü-küm verme. 2.Devletin hem sınırları içinde, hem de dış devletlere karşı fonksiyonunla-rını yerine getiren salahiyetli uzuv. 3.Bakan-lar kurulu.","kategori":"dil","osmanli":"حكومت"},{"kelime":"HuL‘","anlam":"1.Gidermek, indirmek. 2.Zevce ile anlaşarak mal karşılığı boşanmak.","kategori":"dil","misal":"Geçimsizlik erkekten geliyorsa hul‘ karşılığında bir şey almak tahrîmen mekrûh olur. Kadın-dan geliyorsa mehirden çok istemek mekrûh-tur. (İbni Âbidîn)","osmanli":"خلع"},{"kelime":"HuLBE","anlam":"Maydanozgillerden olup, kokulu tohumu gıda (pastırma çemeni) ve ilaç olarak kullanılan kimyon benzeri bir ot. Buy. Çemen.","kategori":"dil","osmanli":"حلبه"},{"kelime":"HuLEFÂ-İ RÂŞİDÎN","anlam":"1.Râşid, rüşd sahibi, olgun halefler. 2.Resûlullah aleyhisselâmın tebliğ, saltanat ve irşâddan ibaret üç vazifesini bir arada yerine getirebilen ilk dört halîfe. Allahü teâlâdan korkunuz. Başınızdaki emir, Habeşî köle olsa bile, itâat ediniz! Benden sonra Müslümanlar arasında ayrılıklar olacaktır. O karışıklık zamanlarında benim sünnetime ve Hulefâ-i Râşidîn’in sünnetlerine sarılınız. Benim halîfelerim doğru yolu gösterirler. Onların gösterdiği yolda olunuz! Sonradan çıkarılan şeylerden sakınınız! (Hadîs-i şerîfTirmizî) Hutbede, Hulefâ-i Râşidîn’in isimlerini zikretmek, Ehl-…","kategori":"dil","osmanli":"راشدين خلفاء"},{"kelime":"HuLK (Huluk)","anlam":"Huy, ahlâk, tabiat.","kategori":"tasavvuf","misal":"Ey Habîbim! Sen şüphesiz yüksek bir hulk üzeresin. (Kalem sûresi: 4) İmanı en kâmil olanınız, hulk bakımından en güzel olanınızdır. (Hadîs-i şerîfDeylemî, Hatîb)","osmanli":"خلق"},{"kelime":"HuLKûM","anlam":"Boğaz, nefes borusu.","kategori":"dil","osmanli":"حلقوم"},{"kelime":"Huluk-ı Azîm","anlam":"Kur’ân-ı kerîmin bildirdiği ve Peygamber sallallahü aleyhi ve sellemin sahip olduğu güzel huylar.","kategori":"dil","osmanli":"قلخ ميظع"},{"kelime":"HuLûL","anlam":"1.Gelme, gelip çatma. 2.Girme, yer etme; bir cismin başka bir cisme girmesi, iki şeyin birleşmesi.","kategori":"muamelat","misal":"Akidlerde, borçlunun ölmesiyle, vâde hulûl eder. Alacaklının ölmesi ile vâde hulûl etmiş olmaz. (İbni Âbidîn) İlahın, Îsâ aleyhisselâma tamamen hulûl et-tiği inanışı yanlıştır. Çünki, ilah, cisim ve araz (sıfat) olamaz. İlahın, bir cisme hulûl etmesi, imkânsızdır. Eğer, ilah cisim olsaydı, başka bir cisme de hulûl ederdi. Cisme hulûl eden şey, ci-sim olur ve hulûl edince iki cismin maddeleri birbirine karışır. Bu da, ilahın parçalanmasını îcâb ettirir. Eğer ilah, araz olsaydı, bir mahalle, mekâna muhtaç olurdu. Bu ise, ilahın başka-sına muhtaç olması demektir. Başkasına muh-taç olan ise, ilah olamaz. (Mefâtihü’l-Gayb)","osmanli":"حلول"},{"kelime":"HuLûS","anlam":"Hâlislik, saflık; gönül temizliği, samimiyet, ihlâs.","kategori":"tasavvuf","misal":"Ve dahî, duâların ve herhangi bir amelin kabul olunmasının şartı ve sebebi beştir: Îmân, İlm, Niyet, Hulûs, yani ihlâs. Kul hakkı. Önce, Ehl-i sünnet i‘tikâdında olmak, sonra yapılacak ibâdetin sıhhatinin şartlarını bilmek lâzımdır. (Miftahü’l-Cenne)","osmanli":"خلوص"},{"kelime":"HuLVAN","anlam":"1.Meşru ücret dışında rüş-vet, falcılık gibi haksız yollarla elde edilen ka-zanç. 2.Kadının mehrinden babasının veya bir başkasının aldığı mikdar.","kategori":"osmanli","osmanli":"حلوان"},{"kelime":"HuLYÂ (Hülyâ)","anlam":"Kuruntu, hayal, vehim.","kategori":"tasavvuf","osmanli":"خوليا"},{"kelime":"HÜMÂYûN (Hümâyûn)","anlam":"1.Mübarek, kutlu. 2.Pâdişâha ait.","kategori":"osmanli","osmanli":"همايون"},{"kelime":"HuMK","anlam":"Ahmaklık.","kategori":"dil","misal":"Gadrle, zenbü humk ve kizbü ketmü hıyânetden, Münezzehdir, müberrâdır cemî’i Enbiyâullah. (Erzurumlu İbrâhim Hakkı)","osmanli":"حمق"},{"kelime":"HuMMÂZ","anlam":"Oksalatlı sebzeler; ku-zukulağı.","kategori":"ibadet","osmanli":"حماض"},{"kelime":"HuNEFÂ","anlam":"Doğru yolda olanlar, Allahü teâlânın birliğine inananlar.","kategori":"akaid","misal":"Hanîf ’in çokluk hâli.","osmanli":"حنفاء"},{"kelime":"HÜNER","anlam":"Marifet, bilme; ustalık.","kategori":"tasavvuf","misal":"Kimseye bâkî değildir, mülk-i dünya sîm ü zer, Bir harâb olmuş kalbi, tâmir etmektir hüner. (Mustafa Feyzî Efendi)","osmanli":"هنر"},{"kelime":"HuNEYN GAZÂSI","anlam":"8.yılında Mekke-i Mükerreme’nin fethinden sonra Havâzin kabilesi müşrikleriyle yapı-lan muharebe.","kategori":"dil","misal":"Hicretin","osmanli":"غزاسى حنين"},{"kelime":"HuRÂFE","anlam":"Vakit geçirmek için anlatılan gülünç veya meraklı sözler; inanılmaz, uydurma rivâyetler.","kategori":"hadis","misal":"Resûlullah aleyhisselâm bir gece hanımlarına bir şey anlattı. Onlardan birisi; “Bu, sanki hurâfe sözüdür” dedi. Hazret-i Peygamber; “Hurâfe nedir, biliyor musunuz? uzre kabilesinden bir adam idi. Cahiliyye devrinde cinler onu esir aldılar. Bir zaman onların içinde kaldı. Sonra serbest bıraktılar. O da onlar içinde gördüğü tuhaflıkları anlatırdı. Halk buna; “Hadîs-i hurâfe (Hurâfe’nin sözü)” dediler.” (Şemâil-i Tirmi…","osmanli":"خرافه"},{"kelime":"HûRÎ","anlam":"“Gözünün beyazı çok beyaz” mânâsına Cennet nimetleri arasında sayılan güzel kız. Hûrî’l-Iyn.","kategori":"akaid","misal":"Müttekileri (Cennet’te) hûrîlerle evlendiri-riz. (Duhân sûresi: 54) Namaz için kamet ge-tirildiğinde sema kapıları açılır ve duâlar ka-bul olunur. Namazın sonunda “Allahümme ecirni minennar ve edhilnil Cennete ve zev-vicini minel hûrî’l-Iyn” (Ey Allah’ım! Beni ateşten koru, Cennet’e sok ve hûrî’l-ıyn ile evlendir!) demez ise; melekler; “Yazık şuna! Cehennem’den korunmasını istemekten âciz kaldı.” Cennet de; “Yazık şuna Cennet’i iste-mekten âciz oldu.” Hûrîler ise; “Yazık şuna, Allah’dan kendisi için hûrî’l-ıyn istemekten âciz kaldı” derler. (Hadîs-i şerîf-Taberânî)","osmanli":"حورى"},{"kelime":"HuRMA","anlam":"Daha ziyade sıcak memleket-lerde yetişen Nahle ağacının çok çeşitli ve bes-leyici meyvesi. Arabcası Temr ve Rutab gelir. Oruçlu olan kimse hurma ile iftar etsin. Çünki hurma bereketlidir. (Hadîs-i şerîf-Mek-tûbât-ı Rabbânî)","kategori":"hadis","misal":"Nahlenin meyvesi olan hurma yinince, insanın parçası, dokusu olur. Oruçlu kimse iftar zama-nında şehvetlerden ve dünyanın geçici zevkle-rinden temiz olduğu için, hurmadan pekçok istifâde eder. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خرما"},{"kelime":"HuRMET (Hürmet)","anlam":"1.İtibar, değer verme, sayma, ikram. 2.Haramlık, bir şeyin dinen haram olması.","kategori":"ibadet","misal":"Mendil gibi, para gibi şeyler üzerinde canlı resmi bulunmasının zararı yoktur. Çünki, canlı resmini, hurmet olunan yerlerde kullanmak câiz değildir, hurmet edilmeyen şeyler üzerinde câizdir. (Fetâvâ-yı İbni Hacer) Lukatanın zayi ve telef olacağından korkulursa, yerden alınıp kaldırılması farz olur. Çünki Müslüman’ın malının hürmeti nefsinin hürmeti gibidir. (İbni Âbidîn)","osmanli":"حرمت"},{"kelime":"Hurmet-i Musâhere","anlam":"Sıhrî evlenme yasağı.","kategori":"dil","misal":"Erkeğin herhangi bir kadına cimâ veya şehvetle çıplak tenine dokunması hâlinde, bu kadının nesep ile ve süt ile olan anası ve kızları ile; kadının da o erkeğin oğlu ve babası ile evlenmesinin ebedî haram olması. Dâmâd ile kayınvâlidesi arasında hurmet-i musâhere hâsıl olursa, zevcesini boşaması lâzım olur. Dâmâd, bu kadın ile sonsuz olarak, bir daha evlenemez. (Bezzâziyye)","osmanli":"مصاهره حرمت"},{"kelime":"HÜRR (Hür)","anlam":"Köle olmayan erkek. Cum‘a namazının bir kimseye farz olması için lâzım olan dokuz şarttan biri de hür olmaktır.","kategori":"ibadet","misal":"(İbni Âbidîn)","osmanli":"حر"},{"kelime":"HuRûF","anlam":"Harfler.","kategori":"dil","osmanli":"حروف"},{"kelime":"Hurûf-i Cümmel","anlam":"Rakam kıymetine göre değerlendirilen harfler, ebced harfleri.","kategori":"dil","misal":"Ebced hevvez huttî kelimelerindeki harfler.","osmanli":"جمل حروف"},{"kelime":"HuRûFÎYYE (Hurûfîlik)","anlam":"Şia’nın aşırılarından Fadlullah-ı Hurûfî’nin kurduğu ve Kur’ân-ı kerîme harflerine göre bâtınî (gizli) mânâlar verdikleri için bu ismi alan bozuk fırka.","kategori":"dil","osmanli":"حروفيه"},{"kelime":"HuRûMİYYE","anlam":"Bâtıniyye (İsmâiliyye) fırkasının birçok haramlara helâl dedikleri için verilen ad.","kategori":"dil","misal":"(Bkz. Bâtıniyye)","osmanli":"حروميه"},{"kelime":"HÜSN","anlam":"Güzellik, iyilik.","kategori":"dil","osmanli":"حسن"},{"kelime":"HÜSN-İ CEMÂL","anlam":"Güzellik ve yüz güzelliği.","kategori":"dil","misal":"Mahlûklarda olan hayr ve kemâl, hüsn ü cemâl, vâcib-i teâlâ ve tekaddesdendir. (Mektûbât-ı Ma‘sûmiyye)","osmanli":"جمال حسن"},{"kelime":"HÜSN-İ HÂTİME","anlam":"İyi son. Son nefeste, ruhunu iman ile teslim etme, iman ile âhirete gitme.","kategori":"akaid","misal":"Bir insanın hüsn-i hâtime ile mi yâhud sû-i hâtime ile mi öleceği, son nefeste belli olur. Bütün ömrü boyunca, kâfir olarak yaşayıp sonunda îmâna kavuşan olduğu gibi, ömrü îmânla geçip, Allahü teâlâ korusun sonunda îmânsız giden de olur. Kıyâmette son nefesteki hâle bakılır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خاتمه حسن"},{"kelime":"HÜSN-İ ZAN","anlam":"Bir şey hakkında iyi kanâat sahibi olma. O şey hakkında iyi düşünme.","kategori":"dil","misal":"Cömert, ancak Allahü teâlâya hüsn-i zannı olduğundan cömertlik yapar. Hasis ise an-cak Allahü teâlâya sû-i zannı sebebiyle cim-rilik yapar. (Hadîs-i şerîf-Ebû Şeyh) İbâdetin efdali, Allahü teâlâya hüsn-i zan etmektir. Al-lahü teâlâ buyurur ki: “Ben kulumun zannı gibiyim.” (Hadîs-i şerîf-Ebû Dâvûd, Tirmizî, Begavî, Hakîm, Taberânî, Ebû Nuaym) Bütün Müslümanlara hüsn-i zan etmek, iyi na-zarla bakmak, iyi karşılamak lâzımdır. Sözleri, mümkün olduğu kadar iyiye yormalıdır. Müs-lümanın hayırlı ve sâlih olduğuna inanmak, ibâdet olur. (Berîka)","osmanli":"ظن حسن"},{"kelime":"HÜSRÂN","anlam":"Zarar, ziyan, kayıp, hasâr, hasâret; mahrumiyet acısı.","kategori":"dil","osmanli":"خسران"},{"kelime":"HuŞû‘","anlam":"1.Tevâzû, alçak gönüllülük. 2.Korku ve hürmet ile Allahü teâlâya boyun eğmek.","kategori":"tasavvuf","misal":"Îmân edenlerin, Allahü teâlâyı ve Hak’tan ineni (Kur’ân-ı kerîmi) zikr için, kalblerinin huşû‘ zamanı hâlâ gelmedi mi? (Hadîd sûresi: 16) Mü’minler herhâlde kurtulacaklardır. Onlar namazlarını huşû‘ ile kılanlardır. (Mü’minûn sûresi: 1, 2) Ve dahî, namazın kemâl-i mertebe kabul olmasının şartı. (Harâmlardan sakınmak ve) huşû‘ ve takvâ ve mâlâyaniyi terk ve terk-i kes…","osmanli":"خشوع"},{"kelime":"HuSûF","anlam":"Ay tutulması.","kategori":"dil","osmanli":"خسوف"},{"kelime":"HuSûL","anlam":"Hâsıl olma, meydana çıkma.","kategori":"fikih","osmanli":"حصول"},{"kelime":"HuSûMET","anlam":"Düşmanlık; hasım-lık, dâvâ açmak.","kategori":"dil","misal":"Husûmet, kalb hastalıklarındandır. Uhûd Gazâsı’nda, Resûlullah aleyhisselâm, mübârek yüzünü yaralayan ve mübârek dişini kıranlara lânet etmedi, husûmet beslemedi: “Yâ Rabbî! Bunlara hidâyet et (doğru yola kavuştur) an-lamıyorlar, bilmiyorlar” diye duâ etti. “Al-lahü teâlâ için affedeni, Allahü teâlâ yük-seltir” buyurdu. (Berîka) Dâvâlıyla şâhidler arasında bir husûmet bulunsa, aleyhde şâhidlikleri kabul edilmez. (İbni Âbidîn) Birisine husûmet mevzuunda vekâlet verilmiş olsa vekil aleyhde değil, lehde olan dâvâlarda vekil olabilir. (İbni Âbidîn)","osmanli":"خصومت"},{"kelime":"HuSûS","anlam":"Mevzu, iş, madde; bir mev-zunun mühim yanı; şekil, yol.","kategori":"dil","osmanli":"خصوص"},{"kelime":"HuSûSÎ","anlam":"Bir şeye mahsûs.","kategori":"dil","osmanli":"خصوصى"},{"kelime":"HuTAME","anlam":"Cehennem’in beşinci tabakası.","kategori":"akaid","misal":"Arkadan çekiştirmeyi, yüze karşı eğlenmeyi ve başkalarını ayıplamayı ve servet biriktirip onu saymayı âdet edinenlere yazıklar olsun! O malın kendisini ebedî kılacağını mı zanneder? Hayır! Yemîn ederim ki o, Huta-me’ye atılır. Hutamenin ne olduğu sana söylendi mi? O, Allahü teâlânın tutuşturulmuş, yandıkça tırmanıp kalblerin tâ üstüne çıkan ateşidir. (Hümeze sûresi: 1-7)","osmanli":"حطمة"},{"kelime":"HuTBE","anlam":"1.Hitâbe, nutuk, konuşma, va‘z. 2.Cum‘a namazlarından evvel, bayram namazlarından sonra, hatîbin minber deni-len yüksekçe yerde cemâate karşı okuduğu, ayrıca nişan, nikâh gibi muayyen merâsim-ler vesilesiyle yapılan hamd, salevât, nasihat ve duâdan ibâret bir ibâdet. “Ey iman edenler! Cum‘a günü namaz için çağırıldığınız zaman hemen Allahü teâlâyı zikretmeye koşun ve alış-verişi bırakın” (Cum‘â sûresi: 9) meâlindeki âyet-i kerîmede sözü edilen zikr, âlimlere göre hutbedir veya hutbe ile birlikte namazdır. Buna göre hutbe de Cum‘a namazı gibi farzdır ve hutbe okunmayan Cum‘a namazı eda edilmiş sayılmaz. (Dürer) Namazı uzatın ve hutbeyi kısaltın! Namazı uzatmak ve hutbeyi kısaltmak, kişinin fa-kihliğinin alâmetidir. (Hadîs-i şerîf-Müslim, Müsnedü Ahmed)","kategori":"ibadet","osmanli":"خطبه"},{"kelime":"HÜVALLÂHÜLLEZİ","anlam":"Haşr sûresinin son üç âyeti.","kategori":"dil","misal":"Sabahleyin ve akşam üç defa “E‘ûzü billâ-hi’s-semî‘l-alîmi mine’ş-şeytânirracîm” deyip, sonra Haşr sûresinin sonundaki üç âyeti okuyan kimseye, melekler duâ ve istiğfâr eder. (Hadîs-i şerîfTirmizi, Dârimî, Müsned)","osmanli":"الذى الله هو"},{"kelime":"HÜVİYYET","anlam":"Kimlik, mahiyet, haki-kat, asıl.","kategori":"dil","osmanli":"هويت"},{"kelime":"HuY","anlam":"Mîzâc, tabiat, ahlâk.","kategori":"tasavvuf","osmanli":"خوى"},{"kelime":"HuZÂ‘A","anlam":"Cahiliye devrinde bir ara Mekke ve Kâbe’yi elinde tutan, Kureyş tarafından Mekke’den çıkarılan Arab kabilesi.","kategori":"dil","osmanli":"خضاعه"},{"kelime":"HuZEYL (Hüzeyl)","anlam":"Arabcayı fasîh konuşmasıyla tanınan, ismini ilk vatanları olan Mekke ve Medîne arasındaki Huzeyl dağından","kategori":"dil","misal":"alıp sonraları Tâif havalisinde yerleşen büyük bir Arab kabilesi.","osmanli":"هزيل"},{"kelime":"HuZûR (Hudûr)","anlam":"Hâzır olma; rahatlık, sükûnet; kalbde devamlı Allahü teâlâyı bulundurma, Allahü teâlâ ile beraber olmak, O’nu unutmamak.","kategori":"akaid","misal":"Büyüklerin huzuru, sohbeti ile şereflenmeyen zavallıların hâli haraptır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"حضور"},{"kelime":"Huzûr-ı İlâhî","anlam":"Allahü teâlânın nezdi.","kategori":"akaid","misal":"Huzur-ı ilâhîde bulunan meleklere Mukarre-bîn denir. (İtikadnâme)","osmanli":"الهى حضور"},{"kelime":"İ‘ÂDE","anlam":"1.Geri verme. 2.Şartlarından birisi eksik olan ibâdeti vakti içinde yeniden yapma.","kategori":"fikih","osmanli":"اعاده"},{"kelime":"İ‘ÂRE","anlam":"Ödünç verme, karşılıksız olarak ve dönülebilecek şekilde bir kişiye sözleşme es-nasında faydalanması için verilen mal. Âriyet.","kategori":"dil","osmanli":"اعاره"},{"kelime":"İ‘CÂM","anlam":"Arabca bir kelimenin nokta ve harekelerinin konulması.","kategori":"dil","osmanli":"اعجام"},{"kelime":"İ‘CÂZ","anlam":"Âciz bırakma, acze düşürme; şaşırtma; mûcize sayılacak derecede düzgün söz söyleme.","kategori":"ibadet","misal":"Arabca’yı iyi bilen kimse, Kur’an-ı kerimin i‘câzını açıkça anlar. Kadı Bakıllânî dedi ki, i‘câz, hem belâgatinin yüksek olmasından, hem de nazmının garîb, yani o zamana kadar hiç görülmemiş olduğundandır. Bazıları, i‘câz, gaybdan haber vermesidir, dedi. Bazı âlimlere göre, Kur’an-ı kerimin i‘câzı, çok uzun ve tekrarlı olduğu halde, hiçbir yerinde ihtilaf, uygunsuzluk bulunmamasıdır. Bazılarına göre, Kur’an-ı kerimi…","osmanli":"اعجاز"},{"kelime":"İ‘DÂM","anlam":"Ademe gönderme, yok etme; kanun gereği öldürme.","kategori":"dil","osmanli":"اعدام"},{"kelime":"İ‘LÂM","anlam":"1.Bildirme, belli etme, anlatma. 2.Mahkemenin bir dâvâ neticesinde verdiği resmî karar yazısı.","kategori":"osmanli","osmanli":"اعلام"},{"kelime":"İ‘LÂN","anlam":"1.Aleniyet kazandırma, açığa vurma, meydana çıkarma, belli etme. 2.Yayma; yaymak için gazeteye verme. 3.Gazetelerde bu yolda veya reklâm için yazılmış yazı.","kategori":"akaid","osmanli":"اعلان"},{"kelime":"İ‘MÂL","anlam":"1.Yapma, üretme. 2.Bir sözü ihmâl etmeyip, bir mânâya çekme.","kategori":"dil","osmanli":"اعمال"},{"kelime":"İ‘RÂB","anlam":"1.Düzgün konuşma. 2.Kelimenin sonundaki harekenin, cümle içindeki vazifesine göre değişmesi. 3.Kelimeyi gramer bakımından tahlîl etme.","kategori":"dil","osmanli":"اعراب"},{"kelime":"İ‘SÂR","anlam":"1.Usr (zorluk) gösterme, zor-laştırma. 2.Fakirlik. 3.Alacaklının fakiri sı-kıştırması.","kategori":"dil","osmanli":"اعصار"},{"kelime":"İ‘TİBÂR","anlam":"1.Ehemmiyet verme. 2.Hürmet gösterme. 3.İbret alma; benzetme, kıyas etme. 4.Birinin sözünü makbul tutmak. 5.Şeref, haysiyet. 6.Bir şeyin hakikî değil, kararlaştırılan değeri. 7.Ticarette söz veya imzaya olan itimad.","kategori":"fikih","misal":"Kredi.","osmanli":"اعتبار"},{"kelime":"İ‘TİBÂRÂT","anlam":"1.İ‘tibârlar, haysiyetler. 2.Farzedilen şeyler.","kategori":"fikih","osmanli":"اعتبارات"},{"kelime":"İ‘TİBÂRÎ KIYMET","anlam":"Paranın, hisse senedinin, tahvilin, poliçenin hakiki kıymeti değil de, üzerinde yazılı olan değer.","kategori":"dil","osmanli":"قيمت اعتبارى"},{"kelime":"İ‘TİDÂL","anlam":"1.İstikamet, doğruluk. 2.Mu-tedil olma, ortadan hareket etme, aşırılıklardan uzak olma. 3.Rükû‘ ve secdeden kalkıp tam doğrulma.","kategori":"dil","osmanli":"اعتدال"},{"kelime":"İ‘TİKÂD","anlam":"1.İnanmak, inanç. 2.Doğru olduğuna kalben inanmak. 3.Dinin hükümlerine inanma.","kategori":"akaid","misal":"Allahü teâlânın bildirdiği her din iki kısımdır. Biri, kalb ile inanılması lâzım olan bilgiler, diğeri beden ile veya kalb ile yapılacak ibâdet bilgileridir. Bunlardan i‘tikâd esasları her dinde aynıdır, dinin aslı ve temelidir. Din ağacının gövdesidir. Amel ise, ağacın dalları yaprakları gibidir. Her Müslümanın önce i‘tikâdını düzeltmesi, Ehl-i sünnet velcemâat âlimlerinin bildirdikleri gibi inanması lâzımdır. Cehe…","osmanli":"اعتقاد"},{"kelime":"İ‘tikâdda Mezheb","anlam":"Îmân edilecek, inanılacak husûslarda tâbi olunan, uyulan yol. İ‘tikâdda mezhebler, Ehl-i sünnet ve cemâat ile Ehl-i bid‘at olmak üzere iki kısma ayrılır. Her Müslümanın, Ehl-i sünnetin iki îmâmın-dan birine yani İmâm-ı Mâturîdî ve İmâm-ı Eş‘ârî mezheblerinden birine uyması lâzımdır. Îmâna dair bilgilerde bu iki imâmdan birine uymak insanı bid‘at i‘tikâddan kurtarır. Çünki Ehl-i sünnet âlimleri aklın ermediği bilgilerde yalnız Kur’ân-ı kerîme ve hadîs-i şerîflere uy-muşlar, akıllarını yalnız bu ikisini anlamakta kullanmışlardır. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"hadis","osmanli":"مذهب اعتقادده"},{"kelime":"İ‘TİKÂF","anlam":"1.Bir şeye devam etme. 2.İbâdet niyetiyle câmide bir müddet bulunmak.","kategori":"ibadet","misal":"İ‘tikâf, nezr olursa vâcib, Ramazan ayının son on gününde sünnet, bunların dışında herhangi bir zamanda namaz kılmayı beklemek, gözkulak günah işlemesin niyetiyle mescidde bulunmak ise müstehâbdır. İ‘tikâfa girene mu‘tekif denir. Peygamber efendimiz orucun farz kılınmasından sonra ömürlerinin sonuna kadar her Ramazanın son on gününde i‘tikâfta bulunmuşlardır. Bu, i‘tikâfın sünnet ile sâbit olmasının delilidir. Kadın…","osmanli":"اعتكاف"},{"kelime":"İ‘TİMÂD","anlam":"Dayanma, güvenme, emniyet. İ‘timâd-ı Nefs: نفس اعتماد (A) Kendine güvenmek. İslâm dini, çalışmayı ve Allahü teâlâya tevek-kül etmeyi (güvenmeyi) emreder. İ‘timâd-ı nefs,","kategori":"akaid","misal":"İslâmiyet’in emirlerine karşı gelmektir. Mantık ilmine de uygun olmayan i‘timâd-ı nefs, egoist-liğe (bencilliğe) ve kendini beğenmeye yol açar. “Başkasının yumruğunu yemeyen kendi yum-ruğunu batman taşı sanır” atasözü, îtimâd-ı nefsin yanlış olduğunu göstermektedir. Hakîkî bir Müslüman i‘timâd-ı nefs yerine, elden gel-diği kadar sebeblere yapıştıktan sonra Allahü teâlâya tevekkül eder, güvenir. (Dînî Müceddidler)","osmanli":"اعتماد"},{"kelime":"İ‘TİRÂF","anlam":"Kabul etme; suçu işledi-ğini ikrar etme.","kategori":"dil","osmanli":"اعتراف"},{"kelime":"İ‘TİRÂZ","anlam":"Karşı çıkma; engel olma.","kategori":"dil","osmanli":"اعتراض"},{"kelime":"İBÂD","anlam":"1.Abdlar, kullar. 2.Âbidler, ibâ-det edenler.","kategori":"dil","misal":"Erzâk-ı ibâde (kulların rızklarına) Allahü teâlâ kefîldir. Eğer az bir çalışmakla tahsîli mümkin olursa ne a‘lâ, ne güzel. Ve illâ ardına düşme-yeler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عباد"},{"kelime":"İBÂDÂT","anlam":"İbâdetler.","kategori":"akaid","misal":"İbâdât, fıkıh ilminin dört büyük kısmından bi-ridir. Beşe ayrılır: Namaz, oruç, zekât, hac ve cihat. Herbirinin dalları çoktur. (İbni Âbidîn)","osmanli":"عبادات"},{"kelime":"İBÂDET","anlam":"1.Kulluk. 2.Allahü teâlânın kullarından istediği şeyleri yerine getirmek, emir ve yasaklarına uymak.","kategori":"akaid","misal":"Cinleri ve insanları, beni tanımaları, bana ibâdet etmeleri için yarattım. (Zâriyât sûresi: 56) Allahü teâlâyı, görür gibi ibâdet et! Sen O’nu görmüyorsan da, O seni görüyor. (Hadîs-i şerîfBuhârî, Müslim) Muhammed aleyhisselâmın bildirdiği ibâdetlerin hepsi, insanlara fâideli şeylerdir. İnsanlara yaradığı için emr edilmiştir. Yoksa hiçbir ibâdetin Allahü teâlâya fâidesi yokdur. Candan teşekkür ederek, minnet ile ibâ…","osmanli":"عبادت"},{"kelime":"İbâdet-i Bedeniyye","anlam":"Beden ile ya-pılan ibâdetler.","kategori":"akaid","misal":"Namaz, ibâdet-i bedeniyye olduğundan başkası yerine kılınamaz. Herkesin kendisi kılması lâ-zımdır. Ağır hasta ve çok ihtiyâr kimse, namaz yerine fakire fidye (bedel, belli mikdarda mal veya para) veremez. Hâlbuki oruç yerine fidye vermesi lâzımdır. (İbni Âbidîn)","osmanli":"بدنيه عبادت"},{"kelime":"İbâdet-i Mâliyye","anlam":"Zekât, sadaka-i fıtr gibi mal ile yapılan ibâdetler.","kategori":"ibadet","misal":"Bir kimse birkaç yemini bozarsa, hepsi için ayrı ayrı keffâret yapması lâzımdır. Keffâretler, zekât gibi ibâdet-i mâliyyedir. Malını fakirlere bir ve-kil vâsıtası ile vermesi câiz olur. Fakat kendisi-nin malı ayırırken veya fakire verilinceye kadar niyet etmesi lâzımdır. (İbni Âbidîn)","osmanli":"ماليه عبادت"},{"kelime":"İBÂDETHÂNE","anlam":"İbâdet yapmak için toplanılan yer. (Bkz. Ma‘bed)","kategori":"akaid","osmanli":"عبادتخانه"},{"kelime":"İBÂDİYYE (İbâziyye)","anlam":"Bid‘at fırkalarından Hâriciyye’nin bir kolu.","kategori":"dil","misal":"adamları hicrî 153 yılında halîfeye isyân edip, Trablusgarb’ı ele geçirdiler. (elMilel ve’n-Nihâl) Kur’ân-ı kerîmin lafzına (zâhirî mânâsına) bağlanan İbâdiyye’ye göre; îmân ve İslâm bir bütündür. Amel, imândan bir parçadır. Bu sebeble günah işleyen kimse, îmândan çıkar. Kur’ân-ı kerîm mahlûktur. İbâdiyye peygamberlere îmân ederler fakat şefâati inkâr ederler. Allahü teâlânın âhirette görülmeyeceğini söylerler. (elF…","osmanli":"عباضيه"},{"kelime":"İBÂHA (İbâhe)","anlam":"1.Bir şeyi mübâh kılma, helâl kılma, bir işin yapılıp yapılmamasını serbest kılma. 2.Yedirme, doyurma.","kategori":"fikih","misal":"Eşyâda aslolan ibâhadır.(elEşbah) Bir kimseyi yemeğe çağırınca, önüne konan şey ibâha olur. Ancak yediği mülk olur. Başkalarına veremez. (İbni Âbidîn)","osmanli":"اباحه"},{"kelime":"İBÂHÎ","anlam":"Haramları mübah sayan İbâhiyye fırkasına mensub olan kimse. (Bkz. İbâhiyye) İBÂHİYYE: اباحيه (A) İslâmiyet’in haram ve ya-","kategori":"dil","misal":"sak kıldığı şeyleri mübâh sayan bid‘at fırkası. Bâtiniyye, İsmâiliyye. Karâmita.","osmanli":"اباحى"},{"kelime":"İBÂHİYYE","anlam":"İslâmiyet’in haram ve ya-","kategori":"fikih","misal":"sak kıldığı şeyleri mübâh sayan bid‘at fırkası. Bâtiniyye, İsmâiliyye. Karâmita.","osmanli":"اباحيه"},{"kelime":"İBÂRET","anlam":"1.Meydana gelmiş. 2.Bir şeyin aynı.","kategori":"dil","osmanli":"عبارت"},{"kelime":"İBÂRET-İ NASS","anlam":"124.âyet-i kerîmesinde meâlen; “Namaz kılın, zekât verin” buyurulmuştur.","kategori":"hadis","misal":"Nassın (âyet-i kerîme ve hadîs-i şerîfin) yalnız ibâresinden anlaşılan mânâya delâlet etmesi. Nûr sûresi: Burada ibâret-i nass, yalnız namaz ve zekâtın farz olduğunu ifâde etmekte, başka bir mânâ bildirmemektedir. (Usûl-i Serahsî)","osmanli":"نص عبارة"},{"kelime":"İBDÂ‘","anlam":"(Allahü teâlâya mahsusen) âlet, madde, zaman ve mekân bahis mevzuu olmadan vücud vermek.","kategori":"akaid","osmanli":"ابداع"},{"kelime":"İBN","anlam":"Oğul.","kategori":"dil","osmanli":"ابن"},{"kelime":"İBRÂ","anlam":"Berî kılma, alacağından vazgeçme. Bir kimse alacağını borçluya hibe etse veya borç-luyu ibrâ etse borçlu borçtan kurtulur. (Düre-rü’l-Hükkâm)","kategori":"muamelat","osmanli":"ابراء"},{"kelime":"İBRÂHÎM (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi bildirilen ulülazm peygamberlerden.","kategori":"dil","misal":"(Ey Resûlüm!) Kitabda (Kur’ân-ı kerîmde) İbrâhîm’in kıssasını anlat. Çünki o sıddîk (doğruluğu tam) bir peygamber idi... (Meryem sûresi: 41) Ben babam (dedem) İbrâhîm’in duâsı, kardeşim Îsâ’nın müjdesi ve annemin rüyâsıyım. (Hadîs-i şerîfMüsnedü Ahmed)","osmanli":"ابراهيم"},{"kelime":"İBRÂHÎM SûRESİ","anlam":"29.âyetleri Medîne’de, diğerleri Mekke’de nâzil oldu.","kategori":"dil","misal":"Kur’ân-ı kerîmin on dördüncü sûresi. Elli iki âyet-i kerîmedir. 28 ve Otuz beşten kırk bire kadar olan âyetler İbrâhim aleyhisselâmın duâsını ihtivâ ettiği için bu ismi almıştır. Sûrede; Allahü teâlâya, peygamberlerine ve âhiret hayâtına îmân konuları ve İbrâhîm aleyhisselâmın duâsı bildirilmektedir. (İbn-i Abbâs, Taberî) İbrâhîm sûresini baştan sona kadar okuyana, sayısız çok sevab verilir. (Hadîs…","osmanli":"سى سوره ابراهيم"},{"kelime":"İBRÂNÎ","anlam":"“Nehrin öte yakasından olan” veya “Eber’in çocukları” mânâsına bir Sâmî kabilesi olup, İbrâhîm aleyhisselâm tarafından Filistin’e getirilmiştir.","kategori":"dil","osmanli":"عبرانى"},{"kelime":"İBRÂZ","anlam":"Bürûz ettirme, meydana çı-karma, gösterme.","kategori":"dil","misal":"İnsan bilmez mi, şol vakti ki, kabrlerdeki mevtâ dirile. Ve sudurda (göğüsde) olan hayr ve şer temyîz ve ibrâz ola. (Mektûbât-ı Ma‘sûmiyye)","osmanli":"ابراز"},{"kelime":"İBRET","anlam":"Karşılaşılan, görülen veya işitilen bir hâdiseden ders almak.","kategori":"hadis","misal":"Gerçekten onların (peygamberlerin) kıssalarında, akıl sahibleri için birer ibret vardır. (Bu Kur’ân) uydurulacak bir söz değildir, ancak kendinden evvel (inen kitabların) tasdîki ve (dine âit) her şeyin tafsîlidir. O, îmân edecek bir kavim için, bir hidâyet ve bir rahmettir. (Yûsuf sûresi: 111) Davarlarda (deve, sığır, koyun, keçide) da sizin için elbette bir ibret vardır. Karınlarında bulunan sütten size içiririz.…","osmanli":"عبرت"},{"kelime":"İBRÎK","anlam":"Toprak veya mâdenden, kulplu ve emzikli su kabı.","kategori":"dil","osmanli":"ابريق"},{"kelime":"İBTÂL (İptal)","anlam":"1.Bâtıl, boş, hükümsüz bırakma, bırakılma, bozma; boşa çıkarma. 2.Lağvetme, feshetme.","kategori":"fikih","misal":"Müşteri, bâyii (satıcıyı), borçlusu üzerine havâle etse ve müşterinin borçlusu bunu kabul etse, mebî bâyie red olunduğu zaman, hâkim bu havâleyi ibtâl eder. (İbni Âbidîn)","osmanli":"ابطال"},{"kelime":"İBTİDÂ","anlam":"Başlama; başlangıç; ilkin, en başta.","kategori":"dil","misal":"Hak teâlânın ibtidâ halk ettiği nesne nûr-i Mu-hammedî “sallallahü aleyhi ve sellem” idi. (Mek-tûbât-ı Ma‘sûmiyye)","osmanli":"ابتداء"},{"kelime":"İBTİDÂÎ","anlam":"İlke mensub, ilk dere-cede; basit.","kategori":"dil","osmanli":"ابتدائى"},{"kelime":"İBTİLÂ","anlam":"1.Bir şeye düşkünlük, müb-telâ olmak. 2.İmtihan, denenme.","kategori":"dil","misal":"İşte orada îmân sahipleri ibtilâdan geçiril-miş ve şiddetli bir sarsıntıya uğratılmışlar-dır. (Ahzâb sûresi: 11)","osmanli":"ابتلاء"},{"kelime":"ÎCÂB","anlam":"1.Lâzım gelme, gerek olma, ihtiyaç. 2.Bir akdin kurulması için tarafların birin-den gelen ilk söz.","kategori":"dil","misal":"İslâmiyet, kıyâmete kadar bütün îcâbları kar-şılayacak en mükemmel ve en üstün bir din-dir. (Seâdet-i Ebediyye) Îcâb, karşıdakinin anlayacağı bir lisan ile, sat-tım, hediye ettim gibi; kabul ise, aynen kabul ettim, râzı oldum gibi geçmiş zaman bildiren sözlerle olur. (Bedâyî‘)","osmanli":"ايجاب"},{"kelime":"ÎCÂD","anlam":"Vücud verme, yoktan var etme, vücûda getirme, yaratma.","kategori":"dil","misal":"(Cenâb-ı Hak, sizin ve vücûde getirdiğiniz iş-lerinizin hâlıkıdır) meâlindeki âyet-i kerî-meye uygun olarak, kulların her hareketi, her işi, Cenâb-ı Hakk’ın halk ve îcâd etmesi ile ve kuvvet vermesi ile, yapdırması ile hâsıl oluyor, diyor. Cenâb-ı Hakk’ın yaratması, insan irâde ve ihtiyârını kullandıkdan sonra oluyor. İşin irâde-i cüz’iyye ve kesb denilen bu kısmı in-sana âid olup, bunu Allahü teâlâ halk ve îcâd etmez. Çünki bu, bir varlık değildir. Halk ve îcâd, hâricde var olan şeylerde olur. (Mektû-bât-ı Ma‘sumiyye)","osmanli":"ايجاد"},{"kelime":"ÎCÂR","anlam":"1.Kirâya verme, kirâya verilme. 2.Kirâ parası, bedeli, ücret.","kategori":"muamelat","misal":"(Bkz. İcâre)","osmanli":"ايجار"},{"kelime":"İCÂRE","anlam":"Muayyen bir menfaati muayyen bir bedel karşılığında satma, kirâlama.","kategori":"muamelat","misal":"İcârenin sahîh olması için ücretin ve menfaatin bildirilmesi şarttır. (İbni Âbidîn)","osmanli":"اجاره"},{"kelime":"ÎCÂZ","anlam":"Sözü kısa söyleme; az söz ile çok şey anlatma.","kategori":"dil","misal":"Kur’ân tercemesi, Kur’ân değildir. Çünki Kur’ân, ma'lûm mûciz olan nazmdır. Terceme edilince, îcâzı zâil olmaktadır. Bir şiir terceme edilince, şiir olmaktan çıkar. (Şerhu Ezkârı Nevevî)","osmanli":"ايجاز"},{"kelime":"İCÂZET","anlam":"İzin.","kategori":"dil","osmanli":"اجازت"},{"kelime":"İcâzet-i Mutlaka","anlam":"Çeşitli ilim-lerde üstâdın talebesine yetiştiğine ve başka-larını da yetiştirebileceğine dâir verdiği izin veya bu izni ifâde eden vesika.","kategori":"dil","osmanli":"مطلقا اجازت"},{"kelime":"İCMÂ'","anlam":"1.Birleşme, toplanma. 2.Ümmetim dalâlet üzerinde icmâ‘ etmez.","kategori":"fikih","misal":"(Hadîs-i şerîfTirmizî, İbn-i Mâce, Dârimî, Müsnedü Ahmed) İctihâd işlerinde icmâ‘ sahibi olmak için, müctehid olmak lâzımdır. Kur’ân-ı kerîmin ve namaz rek‘atlarının ve zekât mikdarının ve ekmeği ödünc almanın ve hamama gitmenin bizlere nakl edilmesi gibi, ictihâda lüzum olmayan şeylerde, müctehid olmayanların bid‘at sahibi ve fâsık olmamak şartıyla icmâ‘ları da muteberdir. Eshâ…","osmanli":"اجماع"},{"kelime":"İcmâ‘-i Ümmet","anlam":"Bir asırda bulunan müctehidlerin bir şer‘î meselenin hükmünde ittifak etmesi.","kategori":"fikih","osmanli":"امت اجماع"},{"kelime":"İCMÂL","anlam":"İhtisar etme, kısaltma, özet-leme; cem, umumî yekûn.","kategori":"dil","osmanli":"اجمال"},{"kelime":"İCRÂ","anlam":"1.Akıtma, akıtılma; yapma. 2.(Devlet işlerini vs.) yürütme. 3.(Kanunları vs.) tatbik etme. 4.(Mahkeme kararlarını, hükümet emirlerini vs.) yerine getirmek, infaz, tenfiz.","kategori":"osmanli","osmanli":"اجراء"},{"kelime":"İCTİBÂ","anlam":"Seçmek, seçilmek; tasavvufta, vâsıtanın şart olmadığı cezbe (çekilme) ile ilerleme.","kategori":"tasavvuf","misal":"İctibâ yolunda riyâzetler çekmek (nefsin isteklerini yapmamak), kavuşmak nîmetine şükretmek içindir. (Mektûbât-ı İmam-ı Rabbânî)","osmanli":"اجتباء"},{"kelime":"İCTİHÂD","anlam":"İnsan gücünün yettiği kadar zahmet çekerek, çalışma; Kur’ân-ı kerîmde ve hadîs-i şerîflerde açıkça bildirilmemiş olan işlerin hükümlerini açıkça bildirilenlere benzeterek meydana çıkarma.","kategori":"dil","misal":"Resûlullah sallallahü aleyhi ve sellem, Hazret-i Muâz bin Cebel’i, Yemen’e hâkim olarak gönderirken; “Orada nasıl hüküm edeceksin?” buyurunca; “Allahü teâlânın kitabı ile” dedi. “Allah’ın kitabında bulamazsan?” buyurdu. “Allah’ın Resûlünün sünneti ile” dedi. “Resûlullah’ın sünnetinde de bulamazsan?” buyurunca; “İctihâd ederek, anladığımla” dedi. Resûlullah efendimiz, mübârek elini Muâz’ın göğsüne koyup; “Elhamdülill…","osmanli":"اجتهاد"},{"kelime":"İCTİMÂ‘","anlam":"Toplanma, cem‘ olma. İCTİMÂ‘Î: اجتماعى (A) Sosyal, cemiyetle alâkalı. İCTİNÂB: اجتناب (A) Sakınma, çekinme, uzak-","kategori":"dil","misal":"laşma, ihtiraz, tevakkî.","osmanli":"اجتماع"},{"kelime":"IDDET (İddet)","anlam":"1.Sayma, ta‘dâd etme. 2.Kocası ölen veya boşanan kadının evlenmeden beklemesi gereken müddet.","kategori":"dil","misal":"(Bkz. İddet)","osmanli":"عدت"},{"kelime":"İDDET (Iddet)","anlam":"Kocasının ölümüyle dul kalan veya talâk ve fesh sebebiyle nikâhı bozulan kadının yeniden evlenebilmesi için beklemesi gereken zaman.","kategori":"dil","misal":"Hâmile kadının iddeti, çocuğu olunca biter. Allahü teâlâ âyet-i kerîmede meâlen buyurdu ki: “Hâmile kadınların iddetleri ise çocuklarını doğurmaları ile son bulur.” (Talâk sûresi: 4) Hâmile olmayıp kocası ölen kadın, dört ay on gün iddet bekler. Allahü teâlâ âyet-i kerîmede meâlen buyurdu ki: “Sizden vefât edenlerin geride bıraktıkları zevceler kendi kendilerine dört ay on gün beklerler (beklesinler).” (Bakara sûres…","osmanli":"عدت"},{"kelime":"İDDİ‘Â","anlam":"Mahkemede bir hakkın sâbit olduğu dâvâsında bulunma; ayak direme.","kategori":"osmanli","osmanli":"ادعاء"},{"kelime":"İDHÂL","anlam":"1.Dâhil etme, içeri sokma, girme, girdirme. 2.Memleket dışından mal getirme.","kategori":"dil","osmanli":"ادخال"},{"kelime":"İDRÂK","anlam":"Bir şeyin aslını, mâhiyetini, hakîkatini bilmek, anlamak.","kategori":"dil","misal":"O’nu (Allahü teâlâyı) gözler (dünyada) idrâk edemez. O ise, gözleri bilir anlar. O, ihsân sahibi bilicidir. (En‘âm sûresi: 103) İnsanı hayvandan ayıran, ilim ve idrâktir (Berîka)","osmanli":"ادراك"},{"kelime":"İDRÂR","anlam":"Sidik, bevl.","kategori":"dil","osmanli":"ادرار"},{"kelime":"İDRÎS (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde adı geçen peygamberlerden.","kategori":"dil","misal":"İsmâil, İdris ve Zülkifl hakkında anlattığımızı da hâtırla. Onların her biri sebredenlerdendi. (Enbiyâ sûresi: 85) Ben (Mîrâc gecesinde) dördüncü kat semâda (gökte) İdrîs (peygamber) ile karşılaştım. Cibrîl bana; “Bu gördüğün İdrîs’dir. Ona selâm ver” dedi. Ben de ona selâm verdim. O da benim selâmıma cevap verdi. Sonra bana; “Merhabâ sâlih kardeş, sâlih peygamber” dedi. (Hadîs-i şerîfBuhârî, Müslim) Şît aleyhisselâ…","osmanli":"ادريس"},{"kelime":"ÎFÂ","anlam":"Ödeme; yerine getirme.","kategori":"dil","misal":"Namazın bir rüknünü terk eden, bu rüknü na-maz içinde îfâ etmezse, namaz bozulur. (İbni Âbidîn) Îfâ etmek niyeti ile va‘d yapmak câizdir, hattâ sevâbdır. Böyle va‘di ifâ etmek vâcib değildir, müstehabdır. İfâ etmemek tenzîhen mekrûh olur. (Berîka)","osmanli":"ايفاء"},{"kelime":"İFÂDA","anlam":"Hacıların Arafat’tan güneşin batışını müteakip sökün ederek Mina’ya veya Kurban bayramı günü Mina’dan Mek-ke’ye akın etmeleri.","kategori":"ibadet","osmanli":"افاضه"},{"kelime":"İFÂDE","anlam":"Anlatma, anlatış.","kategori":"dil","osmanli":"افاده"},{"kelime":"İFFET","anlam":"Namus, ar, temizlik.","kategori":"dil","misal":"Sizin sadakalarınız, fî-sebîlillah (Allah yo-lunda) cihâd eden, ilim tahsîl eden ve ibâ-det gibi hayırlı bir işle meşgul olan ve yer-yüzünde ticâret ve sanat gibi bir işle meşgul olmaya müsâit vakitleri olmayan fakirler içindir. Onlar dilenmekten çekindikleri için, cahiller onları zengin zannederler. Ey Resû-lüm! Sen onları sîmâlarından tanırsın. Onlar, iffetlerinden dolayı insanları rahatsız edip sadaka istemezler. Malınızdan, bunlara in-fak ederseniz, muhakkak Allahü teâlâ ver-diğinizi ve niçin verdiğinizi bilir. (Bakara sûresi: 273-274) İffetli olunuz ki, kadınları-nız da iffetli olsun. (Hadîs-i şerîf-İbni Adiyy)","osmanli":"عفت"},{"kelime":"İFLÂS","anlam":"1.Arayıp bulamamak. 2.Hiç malı kalmamak; borcu malının tamamını kaplayıp fazla gelmek.","kategori":"muamelat","misal":"Kirâcı, san‘atını değişdirirse, iflâs ederse, başka şehre yerleşirse kirâ akdi fesh olur. (İbni Âbidîn) Fıkh öğrenmeyip, hadîs öğrenen, dinde iflâs eder. İlmi, emîn olan, sâlih kimselerden öğrenmelidir. (Fetâvâ-yı Hindiyye)","osmanli":"افلاس"},{"kelime":"İFRÂD","anlam":"1.Müfred (tek olarak) söylemek. 2.Ayırmak. 3.Göndermek, yollamak.","kategori":"dil","osmanli":"افراد"},{"kelime":"İFRÂT","anlam":"(A. Fart’tan) Aşırı gitme, ileri varma, haddini aşma.","kategori":"dil","misal":"Şecâatın (kahramanlığın) ifrâtı, tehevvürdür (aşırı öfkedir). (Berîka) İfrat ve tefrît’in ikisi de kötüdür. Doğru ve en iyisi ortada olandır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"افراط"},{"kelime":"İFRÂZ","anlam":"1.Bir bütünden bir parça ayırma; ayırma; aynlma. 2.Vücuttan, kan, ce-rahat, irin, ter gibi ayrılıp çıkan şey, salgı.","kategori":"dil","misal":"Çok-luk hâli ifrâzât gelir.","osmanli":"افراز"},{"kelime":"İFSÂD","anlam":"1.Bozma. 2.Bozgunculuk yapma, kargaşa çıkarma.","kategori":"dil","misal":"Bey‘in (satışın) îcâbı olmayarak, satıcıya veya müşterîye fâidesi olan bir şart, meselâ bâyi‘in müşteriye bir şey hediye etmesini şart koşmak, bey‘i (satış akdini) ifsâd eder. (İbni Âbidîn) Allahü teâlâ ifsâd edenleri sevmez. (Mâide sûresi: 64)","osmanli":"افساد"},{"kelime":"İFTÂR","anlam":"1.Oruç açma.","kategori":"ibadet","misal":"Bir kimse, bu ayda (Ramazân-ı şerîfte) bir oruçluya iftâr verirse, günahları affolur. Hak teâlâ onu Cehennem ateşinden âzâd eder, kurtarır. O oruçlunun sevâbı kadar, ona sevab verilir. (Hadîs-i şerîfBuhârî) Sizden biriniz iftar ettiği vakit, hurma ile iftar etsin. Çünki hurma berekettir. Hurma bulamayan da su ile iftar etsin. Zira su tertemizdir. (Hadîs-i şerîfİbn-i Mâce, Ebû Dâvûd, Tirmizî, Nesâî) İftar edince, (Ze…","osmanli":"افطار"},{"kelime":"İFTİHÂR","anlam":"Fahretme, öğünme; koltuk kabartma; şeref, şan.","kategori":"dil","osmanli":"افتخار"},{"kelime":"İFTİKÂR","anlam":"1.Fakîr olmak, muhtaç olmak.","kategori":"akaid","misal":"Hâlık (yaratıcı) ve râzık (rızıklandırıcı) Allahü teâlâdır. İnsana hâlık ve râzık demek küfrdür. İnsanın sıfat-ı asliyesi acz ve iftikârdır. (Birgivî Vasîyetnâmesi) Fakîrlik gösterme; alçakgönüllülük, tevâzu. Sâlike lâzım olan, devam-ı zül (devamlı alçalma) ve iftikâr (alçak gönüllülük) ve inkisâr (kırık-lık) ve tedarru‘ (kendini alçaltma, yalvarma) ve ilticâ’ (sığınma) ve kulluk vazifelerini yapıcı, şeriatin hudûdunu muhâfaza edici ve sünnet-i seniyyeye mütâbe‘at (uyucu), hayrlı işlerde ni-yeti düzeltici, kalbini (bâtınını) temizleyici ve zâhiri teslim ve ayblarını ve günahlarını görücü ve Allahü teâlânın intikâmından korkucu ve titrer olmaktır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"افتقار"},{"kelime":"İFTİRÂ","anlam":"Birine yapmadığı bir kötü işi yükleme, suç atma, bühtân, ifk.","kategori":"dil","misal":"Bak, Allah’a karşı nasıl olmadık yalan ve if-tirâ ederler. Apaçık olan bu günahları on-lara kâfidir. (Nisâ sûresi: 50) Bir kimse için söylenen kusur onda varsa, bu söz gîbet olur. Yoksa iftirâ olur. (Hadîs-i şerîf-Müslim) İftirâ etmek ve nemmâmlık yapmak, yani söz taşımak, gîbet etmekten daha fenâdır. (Mektû-bât-ı Ma‘sûmiyye)","osmanli":"افتراء"},{"kelime":"İFTİRÂK","anlam":"1.Ayrılma, dağılma; ayrı-lık, hicran. 2.Perişan olma.","kategori":"dil","osmanli":"افتراق"},{"kelime":"İFTİRÂŞ","anlam":"Namazda secde ederken ayakları ve kolları yere yayma, döşeme.","kategori":"ibadet","osmanli":"افتراش"},{"kelime":"İFTİTÂH","anlam":"Fethetme (açma), fetholma (açılma), başlama.","kategori":"dil","osmanli":"افتتاح"},{"kelime":"İFTİTÂH TEKBÎRİ","anlam":"Başlama tekbîri. Namazın evvelinde “Allahü ekber” demek.","kategori":"ibadet","misal":"Bir kimse iftitâh tekbîrini imâm ile beraber alırsa; sonbahar günlerinde, ağaçların yaprakları, rüzgâr estikçe nasıl dökülürse, o kişinin günahları da öyle dökülür. (Miftahü’l-Cenne)","osmanli":"تكبيرى افتتاح"},{"kelime":"İĞFÂL","anlam":"Gaflete düşürüp yanlış iş yap-tırma; aldatma, doğru yoldan saptırma.","kategori":"dil","misal":"Şeytân dedi ki: Ya Rabbi! İzzetin hakkı için canı çıkıncaya kadar insanları iğfâl edece-ğim. Rab de buyurdu ki: İzzetim celâlim hakkı için istiğfâr ettikçe, ben de onları af-fedeceğim. (Hadîs-i şerîf-Hâkim, Ebû Nuaym) Her kim birisinin karısını iğfal etse, o kadını geri verinceye kadar o kimse hapsedilir ve ha-pishanede ölür. (İbni Âbidîn)","osmanli":"اغفال"},{"kelime":"İĞTİSÂL","anlam":"Gusl abdesti almak. (Bkz.","kategori":"ibadet","misal":"Abdestte ve iğtisâlde lüzumundan fazla su kullanmak, israf olup, haramdır. (Tahtâvî)","osmanli":"اغتسال"},{"kelime":"ÎHÂ","anlam":"Vahyetme; mânâyı veya sözü gizli ve hızlı bir şekilde karşısındakinin kalbine yerleştirme.","kategori":"tasavvuf","osmanli":"ايحا"},{"kelime":"İHÂNET","anlam":"Aşağı görmek, aşağılamak. Âdil sultana ihânet edene, Allahü teâlâ ihâ-net eder. (Hadîs-i şerîf-Taberânî)","kategori":"hadis","misal":"Fâsık kimsenin, âlim olsa da imâm yapılması mekrûh olur. Çünki, İslâmiyet’e uymakta gev-şek davranır. Buna ihânet vâcib olur. (Merâ-kı’l-Felâh)","osmanli":"اهانت"},{"kelime":"İHÂTA","anlam":"Kuşatma, çevirme.","kategori":"dil","misal":"Allahü teâlâ her şeyi ihâta etmiştir. Her şeye yakındır ve her şeyle beraberdir. Fakat bizim alıştığımız, bildiğimiz ve anladığımız ihâta, ya-kınlık ve beraberlik gibi değildir. Bunlar, O’na lâyık değildir. Mahlûkların hiçbiri O’nu ve sı-fatlarını ve fiillerini anlayamaz, bilemez. Bun-lara anlamadan inanmak lâzımdır. (Mektûbât-ı İmam-ı Rabbânî)","osmanli":"احاطه"},{"kelime":"İHBÂR","anlam":"Haber verme, bildirme.","kategori":"dil","osmanli":"اخبار"},{"kelime":"İHDÂS","anlam":"Meydana getirme, ortaya çı-karma.","kategori":"dil","misal":"Kim bizim dinimizde olmayan bir şey ih-dâs ederse, reddolunur. (Hadîs-i şerîf-Buhârî, Müslim, Nesâî) Tarikat talimine icazet için, bid‘at ihdas etme-mek, ahkam-ı İslâmiyeye uymak ve şeyhlerini sevmek, şart koşulmuştur. (Mektûbât-ı Ma’sû-miyye)","osmanli":"احداث"},{"kelime":"İHLÂS","anlam":"Hâlis, temiz, doğru muhabbet ve bağlılık; iş ve ibadeti yalnız Allah için yapmak.","kategori":"akaid","misal":"Sabır ve ihlâs, köleler âzâd etmekten efdaldır. Allah sabırlı ve ihlâslı kullarını Cennet’e hesapsız sokar. (Hadîs-i şerîfTaberânî) İhlâs ile yapılan bir iş, senelerle yapılan ibâdetlerin kazancını hâsıl eder. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اخلاص","alternatif":["ihlas"]},{"kelime":"İHLÂS SûRESİ","anlam":"Kur’ân-ı kerîmin yüz on ikinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Dört âyet-i kerîmedir. Esâs, Necât, Cemâl, Nisbe, Samed, Îmân, Tevhîd, Tefrîd, Tecrîd, Necâd, Vilâyet ve Mârifet sûresi de denir. Müşriklerin Allahü teâlânın sıfatlarını sormaları üzerine nâzil olmuştur. Sûrede; İslâm dininin tevhîd inancı en özlü ve en mânidar şekilde ifâde edilmiştir. (Ey Resûlüm!) de ki: O Allah birdir, Sameddir. O doğurmamıştır, doğurulmamıştır. Hiçbir şey O’nun dengi (ve be…","osmanli":"سى سوره اخلاص","alternatif":["ihlas"]},{"kelime":"İHMÂL","anlam":"Ehemmiyet vermeme, sav-saklama.","kategori":"dil","misal":"Cemâatle namazı ihmâl edenleri ta‘zîr etmeli-dir. (İbni Âbidîn) Müezzin ve İmâm gibi kimselere vakfın geliri şart kılınıp, bunlar lâyık olmazlar veya vazi-felerini ihmâl ederlerse, vakfedenin bu şarttan dönmesi câiz olur. (İbni Âbidîn)","osmanli":"اهمال"},{"kelime":"İHRÂM","anlam":"1.Hac veya umre yapmak üzere muayyen bir mahalden itibaren bazı şeyleri kendisine haram kılma. 2.Hac veya umre yaparken üzerine giyilen iki parçalı elbise.","kategori":"ibadet","misal":"Hac ayları bilinen Şevval, Zilka‘de ayları ile Zilhicce’den on gündür. İşte kim o aylarda haccı, ihrâma girerek kendine farz yaparsa artık hacda kadına yaklaşmak, günah işlemek ve kavga etmek yoktur. (Bakara sûresi: 197) Hac, umre, ticaret veya herhangi bir şey için uzaktan gelenlerin, mîkât denilen yerleri, ihrâmsız geçerek, Harem’e yani Mekke-i Mükerreme’ye girmeleri, haramdır (günahtır). Geçenin tekrar mîkâta gel…","osmanli":"احرام","alternatif":["ihram"]},{"kelime":"İHSÂ","anlam":"1.Yalnız bir ilim ve sanat ile uğ-raşıp onda geniş bilgi elde etme. 2.Husyelerini keserek hadım etme, kısırlaştırma.","kategori":"dil","misal":"Kasap hayvanlarını, semizlemeleri için, ihsâ etmek câizdir. Diğer hayvanları ve insanları ihsâ harâmdır. (İbni Âbidîn, Berîka, Hadîka)","osmanli":"اخصاء"},{"kelime":"İHSÂN","anlam":"1.Sağlamlaştırma, tahkim etme, zevcesini namahremden koruma, kadının? ve Müslüman için başından zifafla neticelenmiş bir evlilik geçmiş olma, muhsan olma. Zinâ suçunda recm cezasının icra edilmesi için zinâ eden erkek ile kadından her biri için ihsân şartı aranmaz. Bunlardan hangisi muhsan ise, onun hakkında recm, diğeri hakkında da celd cezası tatbik edilir. (İbni Âbidîn)","kategori":"dil","osmanli":"احصان"},{"kelime":"İHTÂR","anlam":"Hatırlatma, dikkatini çekme. Âlimlere ve yüksek memurlara ihtâr etmek ceza olarak yetişir. (İbni Âbidîn)","kategori":"dil","osmanli":"اخطار"},{"kelime":"İHTİKÂN","anlam":"Lavman yapmak.","kategori":"dil","misal":"İhtikan yapmak, kulağına yağ damlatmak orucu bozar ise de keffâret lâzım olmaz. (İhtiyâr)","osmanli":"احتقان"},{"kelime":"İHTİKÂR","anlam":"İnsan ve hayvan için lü-zumlu gıdâ maddelerini toplayıp, stok ederek, pahalandığı zaman satmak, karaborsacılık. Bir kimse gıdâ maddelerini kırk gün ih-tikâr ederse, Allahü teâlâ ona darılır. (Ha-dîs-i şerîf-Hâkim)","kategori":"akaid","osmanli":"احتكار"},{"kelime":"İHTİLÂF","anlam":"Hilâf olma, farklılık, ay-rılık; uymama, uyuşmazlık.","kategori":"dil","misal":"Ümmetimin (âlimlerinin ictihadî meseleler-deki) ihtilâfı rahmettir. (Hadîs-i şerîf-Beyhekî) Halîfe Hârûn Reşîd, İmâm-ı Mâlik hazretle-rine; “Senin kitaplarını çoğaltıp her yere gön-dereceğim ve herkesin bunlara uymasını em-redeceğim” deyince; “Yâ Halîfe! Böyle yapma, âlimlerin ihtilâfı, Allahü teâlânın rahmetidir. Hepsi hidâyet üzeredir. Her Müslüman dilediği âlime uyar” buyurdu. (Tahtâvî)","osmanli":"اختلاف"},{"kelime":"İHTİLÂL","anlam":"1.Halel gelme, bozuk-luk, bozulma, karışıklık, düzensizlik. 2.Siyasî iktidarı devirmek veya sistemi değiştirmek üzere ayaklanma.","kategori":"dil","osmanli":"اختلال"},{"kelime":"İHTİLÂM","anlam":"Uykuda cünüb olma.","kategori":"dil","misal":"Bir kimse gece uykuda ihtilâm olup sabahlasa veya gündüz uyuyup ihtilâm olsa orucu bo-zulmaz. (Halebî)","osmanli":"احتلام"},{"kelime":"İHTİLÂT","anlam":"1.Birkaç şeyin birbirine ka-rışması. 2.Birbirine mahrem olmayan erkek ve kadınların, Müslümanlarla gayrı müslimlerin beraber oturup kalkması.","kategori":"dil","misal":"Kâfirleri ve bid‘at sahiplerini ve açıkça günah işlemeye devam eden fâsıkları sevmememiz emrolundu. Bunlarla konuşmamalı, evlerine, toplantılarına gitmemeli, selâm vermemeli, ar-kadaşlık yapmamalıdır. Zarûret ve ihtiyâc ol-duğu zaman, zarûret mikdarı kadar, bu yasak-lara izn verilmiştir. Bu zaman, onlarla ihtilât câiz olur ise de, kalbin yine onları sevmemesi lâzımdır. (Makâmat-ı Mazhariyye)","osmanli":"اختلاط"},{"kelime":"İHTİRÂS","anlam":"Şiddetli hırs, arzu, aşırı heves, istek, gözün ve gönlün doymaması. (Bkz. Hırs)","kategori":"dil","misal":"Âdemoğlu yaşlanır. Fakat onda iki haslet gençleşir: Mala ve ömre ihtirâs. (Hadîs-i şerîf-İbn-i Mâce) Âhirete îmânı olanın, dünyaya ihtirâsı ol-maz. Âhirette cezâ göreceğini kesin olarak bi-len kimse, dünyayı âhirete tercîh etmez. (Ede-bü’d-Dünyâ ve’d-Din)","osmanli":"احتراص"},{"kelime":"İHTİSÂB","anlam":"1.Hesap sorma, mes’ûli-yet. 2.Emr-i ma‘rûfu ve nehy-i münkeri el ile yapmak; hükümetçe tayin edilen memur vâ-sıtasıyla dinin emir ve yasaklarına riayeti te-min etme. (Bkz. Hisbet)","kategori":"dil","osmanli":"احتساب"},{"kelime":"İHTİSÂR","anlam":"1.Hasretme, kısaltma, özet-leme. 2.Sadeleştirme, basitleştirme.","kategori":"dil","osmanli":"اختصار"},{"kelime":"İHTİSÂS","anlam":"1.Husus kazanma, bir ilim veya sanat üzerinde fazla çalışarak onda derinleşmiş olma, uzmanlık. 2.Kendine mahsus kılma.","kategori":"akaid","osmanli":"اختصاص"},{"kelime":"İHTİVÂ","anlam":"Hâvî olma, içine alma, içinde bulundurma.","kategori":"dil","osmanli":"احتواء"},{"kelime":"İHTİYÂÇ","anlam":"Ruh ve beden için lâzım olan şey.","kategori":"akaid","misal":"Yerde olan her şeyi sizin ihtiyâcınızı karşılamak için yarattım. (Bakara sûresi: 28) Kim din kardeşinin ihtiyâcını görürse Allah da onun ihtiyâcını görür. (Hadîs-i şerîfTirmizî)","osmanli":"احتياج"},{"kelime":"İhtiyâç Eşyası","anlam":"İnsanı ölüm-den koruyan, rahat ve dine uygun yaşaması","kategori":"dil","misal":"için asgari lâzım olan şeyler. Hâcet-i asliyye. Havâicü’l-asliyye. İhtiyaç eşyasının birincisi nafakadır. Nafaka yi-yecek, giyecek ve evdir. Diğerleri; binek hayvanı veya arabası, silahları, hizmetçileri ve evde kul-lanılan eşya ve sanat aletleri ve lüzumlu (mes-lek) kitapları ve ödeyeceği borçlarıdır. İhtiyâç eşyası, insanın hâline ve zamana göre değişir. (İbni Âbidîn) Altın ile gümüş, ister para olarak kullanılsın, is-ter kadınların süsü gibi helâl olarak kullanılsın, ister erkeklerin altın yüzük takması gibi harâm olarak kullanılsın, ister ev, yiyecek, kefen satın almak için saklanılsın, ister kılınç gibi ihtiyâc eşyası olsun, zekât nisâbının hesâbına katıla-caktır. (Dürrü’l-Müntekâ)","osmanli":"اشياسى احتياج"},{"kelime":"İHTİYÂR","anlam":"1.İstediğini seçme. 2.Kat-lanma.","kategori":"dil","misal":"(Bkz. İrâde) Kulun ihtiyârı zayıftır, demeleri, Allahü teâlâ-nın ihtiyârına göre zayıftır mânâsında ise doğ-rudur. Yok, eğer emr ve yasak olunan işleri yap-maya kâfi değildir demek istiyorlarsa bu doğru değildir. Zîrâ kula, gücü yetmeyecek şey ve iş teklif edilmedi. (Mektûbât-ı İmâm-ı Rabbânî) Yaşlı. İhtiyarlara hürmet göstermek, Allah’a hür-metten sayılır. Kim ki ihtiyarlara hürmet et-mezse benden değildir. (Hadis-i şerif-Deylemî)","osmanli":"اختيار"},{"kelime":"İHTİYÂT","anlam":"1.Sakınma, tedbirli ve te-darikli davranma. 2.Yedek.","kategori":"dil","misal":"Bulutlu gecelerde orucun bozulmasından ko-runmak için ihtiyatlı davranmalı, iftârı biraz geciktirmelidir. Yıldızlar görünmeden önce iftâr eden de iftârda acele etmiş olur. (Nûrü’l-Îzâh) Müslümanlara merhamet edip, kâfirlerin pis olduğunu anlamamalı ve kâfirlerle karışan, alış veriş eden Müslümanları, pis bilmemeli-dir. Bunların yemek ve içmelerinden sakınma-malı, Müslümanlardan kaçınmak, ayrılmak yoluna sapmamalıdır. Bu hâl, ihtiyât değildir. Bu hâlden kurtulmak, ihtiyâttır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"احتياط"},{"kelime":"İHVÂN","anlam":"1.Erkek kardeşler. 2.Dostlar, arkadaşlar. 3.Aynı tarikatin mensubları.","kategori":"tasavvuf","misal":"Ah’ın çokluk hâli.","osmanli":"اخوان"},{"kelime":"İHYÂ","anlam":"Diriltme, hayat verme, canlandırma.","kategori":"tasavvuf","misal":"çirmek, kıymetlendirmek. Sünnetimi ihyâ edenler ve onu insanlara öğretenler benim halîfelerimdir. Allah onlara rahmet eylesin! (Hadîs-i şerîfİbni Asâkir) Dört geceyi ihyâ edene Cennet vâcib olur: Arefe, terviye, kurban bayramı ve Ramazan bayramı gecesi. (Hadîs-i şerîfİbni Asâkir) Bir kimse (sahipsiz) bir yeri ihyâ ederse, o yer onundur. (Hadîs-i şerîfAbdurrezzâk) Receb’in ilk Cum‘a (Regâib) gecesini ihyâ edene, Alla…","osmanli":"احياء"},{"kelime":"İKÂB (Ikâb)","anlam":"Cezâ, azap, eziyet. Biliniz ki, muhakkak Allahü teâlânın ikâbı pek çetindir.","kategori":"akaid","misal":"Farzı terk eden veya haram işleyen, tövbesiz ölür ve şefâate, affa kavuşmazsa, ikâb olunur. (Dürr-i Yektâ)","osmanli":"عقاب"},{"kelime":"İKÂLE","anlam":"1.Oturma. 2.Kal- dırma, ayakta durdurma. 3.Meydana koyma; yerine geçirme.","kategori":"dil","misal":"Bozma; iki kişinin, aralarında yaptıkları herhangi bir akdi, an-laşmayı bozması, feshetmesi. Ticârette ihsânın bir şekli de alışveriş ettiği kimse pişman olursa, ikâle etmektir. (Kimyâ-i Seâdet) İKÂME: اقامه (A. Kıyam’dan)","osmanli":"اقاله"},{"kelime":"İKÂMET","anlam":"1.Oturmak, bir yerde kalmak. 2.Sefer müddeti gittiği yerde muayyen bir zaman kalma. 3.Cemaatle namaza başlamadan müezzinin okuması sünnet olan ezâna benzer sözler, kâmet.","kategori":"ibadet","misal":"İkâmetin, ezândan farkı, fazla olarak “Hayyealelfelâh”dan sonra iki defâ “Namaz başladı” mânâsına olan “kad kâmetissalâtü\" denmesidir. İmâm olmak, müezzinlik yapmaktan ve ikâmet okumak, ezân okumaktan efdaldir. (İbni Âbidîn)","osmanli":"اقامت"},{"kelime":"ÎKÂZ","anlam":"Uyandırma; uyarma, tembih etme. Mü’min bir hastalığa yakalanır, sonra da Al-lah ona o hastalıktan şifâ verdiğinde, bu geç-miş günahlarına keffâret ve ileride işleyeceği","kategori":"dil","misal":"kusurlar için de bir îkaz olur. (Hadîs-i şerîf-Ebû Dâvûd, Müslim) Ehl-i sünnet denilen hakîkî Müslümanların birbirlerini sevmeleri, zarar vermemeleri, yar-dımlaşmaları, tatlı dil ve yazılar ile birbirle-rini îkâz etmeleri lâzımdır. (Seâdet-i Ebediyye)","osmanli":"ايقاظ"},{"kelime":"İKBÂL","anlam":"1.Birine doğru dönme, birini karşılama, birine kıymet verme. 2.Baht, talih, işlerin yolunda gitmesi, talihlilik, mut-luluk. 3.Arzu, istek.","kategori":"dil","misal":"Tasavvuf bilgilerinden maksat, kendini zorla-madan, uğraşmadan, her an Allahü teâlâya ikbâldir. Her an O’nu hatırlamaktır. (Ubey-dullah-ı Ahrâr) Ey sahib-i ikbâl-ü câh! İtmeyesin cânib-i zulme nigâh! (Osman Gazi Vasîyetnâmesi-Tâcüttevârih)","osmanli":"اقبال"},{"kelime":"İKDÂM","anlam":"1.Kadem etme, gayret ve se-batla çalışma, devamlı çalışma. 2.İlerleme, ileri gitme.","kategori":"dil","misal":"Hizmet-i îşâna ikdâm olmadıkca, sohbet he-vesinde olmamalı. (Mektûbât-ı Ma‘sûmiyye)","osmanli":"اقدام"},{"kelime":"İKFÂR","anlam":"Bir Müslümanın dinden çıktığına hükmetme, tekfîr.","kategori":"fikih","osmanli":"اكفار"},{"kelime":"İKLÎM (Iklîm)","anlam":"1.Memleket, kıta. 2.Bir yerin hava şartları.","kategori":"fikih","osmanli":"اقليم"},{"kelime":"İKMÂL","anlam":"1.Kemâle erdirme, tamam-lama, bitirme. 2.Eksiğini doldurma.","kategori":"dil","misal":"Sinn-i bülûğun mebdei, erkekte on-iki ve kızda dokuz yaşları doldurmaktır. Müntehâsı, ikisi-nin de onbeş yaştır. Onbeş yaşını ikmâl edince bâlig sayılırlar. (Mecelle, m. 986)","osmanli":"اكمال"},{"kelime":"İKNÂ‘","anlam":"Kanâat getirtme, kâni‘ kılma, râzı etme, kandırma, kandırılma, inandırma, inandırılma.","kategori":"dil","osmanli":"اقناع"},{"kelime":"İKRÂ’","anlam":"Kıraat ettirme, okutma.","kategori":"dil","misal":"Kırâet ise bir lisân fi‘l-i ihtiyârîsidir ki, âkıl ve nâtık bir insanın ağzından mehareci mahsûsaya i‘timâd ile çıkan ve kasd-ü fehmine iktirân eden savtı ile yapılır. Ve nitekim Cibrîl’in fi‘li bile kırâet değil bir ikrâ’ yani kırâet ettirmektir. (Hak Dini Kur’an Dili)","osmanli":"اقراء"},{"kelime":"İKRÂH","anlam":"1.Kerîh görme, iğrenme, tik-sinme. 2.Birini korkutarak bir şeye zorlama.","kategori":"dil","misal":"Cizye vermeyi kabul eden Ehl-i kitâbı, İs-lâm dinine girmek için ikrâh etmek yok-tur. (Bakara sûresi: 256) Mü’mini ve zımmîyi (İslâm idaresi altında ya-şayan Müslüman olmayan vatandaşı) ikrâh et-mek, korkutmak büyük günahtır. (İbni Âbidîn)","osmanli":"اكراه"},{"kelime":"İKRÂM","anlam":"1.Kerem etme, hürmet gös-terme. 2.Ağırlama; yiyecek, içecek, hediye yâ-hud başka bir şey verme.","kategori":"dil","misal":"Kim mü’min kardeşine ikrâm ederse, Allahü teâlâ da ona ikrâm eder. (Hadîs-i şerîf-Ta-berânî) Ekmeğe ikram edin. Zira Allahü teâlâ göklerin ve yerin bereketini ona ver-miştir. (Hadîs-i şerîf-Ebû Nuaym) Tanıdığın bir Müslüman sana gelince, elinden geldiği kadar iyi ve tatlı karşıla, yemek ikrâm eyle. Kapıya çık kendisini karşıla. Selâm ve-rince selâmını al. Sohbetten sonra giderken, onu uğurla ve duâ eyle. (Ey Oğul İlmihâli)","osmanli":"اكرام"},{"kelime":"İKRÂMİYYE","anlam":"1.Bahşişler; bağış-lar. 2.İkram olarak verilen para. 3.Piyango-dan çıkan şey.","kategori":"dil","osmanli":"اكراميه"},{"kelime":"İKRÂR","anlam":"1.İtiraf etme, sakla-mayıp söyleme. 2.Lisan ile bildirme. 3.Tasdik etme, kabul etme. 4.Birinin, kendisinde olan hakkını, alacağını haber vermek.","kategori":"dil","misal":"(A. Karar’dan) Allah’a îmân, dil ile ikrâr, kalb ile tasdîk ve âzâ ile amel etmektir. (Hadîs-i şerîf-Deylemî) Mürûr-i zamana uğrayan bir alacağı, borçlu ikrâr edince, ödemesi her zaman lâzım olur. (Mecelle, m. 1660)","osmanli":"اقرار"},{"kelime":"İKTİDÂ’","anlam":"Tâbi olmak, uymak.","kategori":"dil","misal":"İşte o peygamberler Allahü teâlânın hidâyet ettiği kimselerdir. Sen de onlara iktidâ’ et. (En‘âm sûresi: 90) Benden sonra, Ebû Bekr’e ve Ömer’e iktidâ ediniz. (Hadîs-i şerîf-Tir-mizî, Hâkim) Kendisinde imâmlık şartları bulunmadığı hâlde imâmlık yapan kimseye iktidâ’ etmemelidir. (İbni Âbidîn) Büyüklerimizin yolunun esâsı ikidir: Birincisi; Resûl-i ekrem aleyhisselâmın sünnetine imtisâl (uyma), ikincisi iktidâ ettiği şeyhe muhabbet. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اقتداء"},{"kelime":"İKTİDÂR","anlam":"Kudretli olma, gücü yetme. İKTİDARSIZLIK: اقتدارسزلق (T) Erkeğin cinsî te-masta bulunmasına mâni olan hastalık. Innet.","kategori":"dil","osmanli":"اقتدار"},{"kelime":"İKTİSÂD","anlam":"1.Orta yol, orta hâl, aşırı gitmeme. 2.Tutumlu olma, gereği kadar ölçülü harcama. 3.Biriktirme, artırma.","kategori":"dil","misal":"Dağlar gibi dalgalar onları kuşattığı zaman, dini tamâmen Allahü teâlâya hâs kılarak (ihlâsla) O’na yalvarırlar. Allahü teâlâ on-ları karaya çıkararak kurtardığı vakit, içle-rinden bir kısmı iktisâd yolunu tutar. (Lok-mân sûresi: 32) İslâmiyet, ferdin iktisâdî hürriyetine saygı gös-terir. Hususî teşebbüslere ve sermâyeye izin ve-rir. Kısaca İslâmiyet, ferdî hürriyete elverişli bir iktisâd sistemini emreder. (Seâdet-i Ebediyye) İktisâd eden darlık çekmez. (Hadîs-i şerîf-Ta-berânî) İstihsal (üretim) ve istihlâk (tüketim) faâ-liyetlerinin nasıl düzenlendiğini tetkik eden ilim. Ekonomi.","osmanli":"اقتصاد"},{"kelime":"İKTİZÂ","anlam":"1.Lâzım gelme, gerekme. 2.Lâzım getirme, gerektirme. 3.İh-tiyaç. 4.İşe yarama.","kategori":"dil","misal":"(A. Kazâ’dan)","osmanli":"اقتضاء"},{"kelime":"İKTİZÂ-İ NASS","anlam":"Nassın gereği. Nassın (âyet-i kerîme ve hadîs-i şerîfin) lafzının doğru anlaşılması için ibarede yer almamış bir mânâya delâlet ettiğinin kabul olunması.","kategori":"hadis","misal":"“Ümmetimden hatâ (yanılma), nisyân (unutma) ve zor karşısında yaptıkları şeyler kaldırıldı.” hadîs-i şerîfinin lafzında yalnız hatâ ve nisyânın kaldırıldığı bildirilmektedir. Hâlbuki bu hâller insandan ayrılmaz. İnsanda her zaman görülebilmektedir. Bu sebeble iktizâ-i nass, insandan kaldırılanın hatâ, nisyân olmayıp, hatâ ve nisyân ile yapılan işten doğan günah ve mes’ûliyet olduğunu ifâde etmektedir. Dolayısıyla ha…","osmanli":"نص اقتضاء"},{"kelime":"ÎLÂ","anlam":"1.Yemîn. 2.Erkeğin zevcesine mu- ayyen bir müddet veya ebediyyen yâhud müd- det söylemeksizin yaklaşmayacağına yemin etmesi. 3.Sıkıntı ve derde uğrama.","kategori":"dil","misal":"Kadınlarına yaklaşmamaya îlâ edenler için dört ay beklemek vardır. Eğer erkekler (o müddet içinde keffâret yaparak zevcelerine) dönerlerse şüphe yok ki, Allahü teâlâ","osmanli":"ايلاء"},{"kelime":"İLÂH","anlam":"Mâbud, tanrı.","kategori":"dil","misal":"Onlar, (kâfirler, müşrikler) o kimselerdir ki, Allah ile beraber başka bir ilâh tanırlar. On-lar, yakında (başlarına gelecek âkıbeti) bile-ceklerdir. (Hicr sûresi: 96) Onlar, âlimlerini ve râhiplerini Allah’tan başka ilâhlar edindi-ler. Meryem’in oğlu Mesîh’i de (ilâh edindi-ler.) Hâlbuki onlar da ancak bir olan Allah’a ibâdet etmekle emrolunmuşlardı. Allahü teâlâdan başka hiçbir ilâh yoktur. O, müş-riklerin ortak koştuğu şeylerden tamâmen münezzehtir. (Tevbe sûresi: 31)","osmanli":"اله"},{"kelime":"İLÂHÎ","anlam":"1.“İlâhım!”, “Tanrım!” mânâ-sına yakarış hitâbı. 2.İlâh ile alâkalı. 3.Hususî bestesi ile söylenen dinî manzume, münâcat veya naatlar.","kategori":"dil","misal":"İlâhî! Dostlarını şöyle kıldın ki onları bilen seni buldu. Seni bulmayan onları bilmedi. (Abdul-lah Ensârî) Yüzüm karasına bakma ilâhî Cehennem nârında yakma ilâhî. (Tuhfetü’l-Uşşâk) Allah’a âit, Allah’dan gelen, Allah’ın gönderdiği. Tasavvuf, insanlık sıfatlarından çıkarak, melek sıfatları ile bezenmek ve ilâhî ahlâkı huy edin-mektir. (er-Riyâdü’t-Tesavvufiyye )","osmanli":"الهى"},{"kelime":"İlâhî Dinler","anlam":"Asılları Allahü teâlâ tarafından bildirilmiş olan dinler; ilâh inancı bulunan dinler.","kategori":"akaid","misal":"Hak dinler. Semâvî dinler.","osmanli":"دينلر الهى"},{"kelime":"İLÂHİYYÂT","anlam":"Dinde inanılacak hususları bildiren kelâm ilminin, Allahü teâlânın varlığı, zâtı, sıfatları ve fiillerinden bahseden kısmı, kelâm ilmi, din ilimleri, teoloji.","kategori":"akaid","osmanli":"الهيات"},{"kelime":"İLÂHİYYE","anlam":"1.Kâinâtı yaradan bir tan-rının varlığına inanan, ancak dinleri kabul et-meyen felsefi sistem. 2.Her şeyin Allah’ın birliğinde münde-miç olduğu mânâsına gelen bir tabir.","kategori":"akaid","misal":"Tanrıcılık. Yaradancılık. Deizm.","osmanli":"الهيه"},{"kelime":"İLÂVE","anlam":"1.Katma, ek, ekleme. 2.Arttırma.","kategori":"dil","misal":"ÎLCÂ’: الجاء (A) Sevk etme, mecbur etme, zorlama. İLELEBED: الأبد الى (A) Ebediyete kadar, son- suz olarak, ilânihâye.","osmanli":"علاوه"},{"kelime":"İLHÂD","anlam":"Dinden çıkma; mânâları açık ve kat‘î olan âyet-i kerîmelere ve hadîs-i şerîflere, te’vîl etse dahi yanlış mânâ vererek ve mânâları şüpheli olanlara te’vîl etmeden yanlış mânâ vererek dinden çıkma.","kategori":"hadis","misal":"Kim Mescid-i Harâm’da zulm ile ilhâda yeltenirse, biz ona pek acıklı bir azap tattırırız. (Hac sûresi: 25) Din bilgilerinin doğrusu, Ehl-i sünnet vel cemâat âlimlerinin bildirdikleri bilgilerdir. Bunlara uymamak, zındıklık ve ilhâddır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"الحاد"},{"kelime":"İLHÂM","anlam":"Allah tarafından insanın gönlüne doğma.","kategori":"akaid","misal":"Allah kimin hayrını dilemişse onu dinde bilgi ve ince anlayış sahibi yapar. Ve doğru yolunu kendisine ilham eder. (Hadîs-i şerîfEbû Nuaym) İlhâm, peygamberlerin aleyhimüsselâm ve sâlih Müslümanların kalblerine gelir. Resûlullah sallallahü aleyhi ve sellemin mübârek kalbine gelen ilhâm, her Müslüman için seneddir. Herkesin bunlara uyması lâzımdır. (Hadîka) Hakîm Alî Tirmizî buyurdu ki, Yaşım ilerledikçe, ilmim, ameli…","osmanli":"الهام"},{"kelime":"İLKÂH","anlam":"Aşılama; dölleme, döllenme. İLLET (Illet): علت (A) Bir şeyin veya hükmün meydana gelmesine doğrudan te’sir eden iş,","kategori":"dil","misal":"sebeb. İlletin bulunduğu yerde; te’sir ettiği, meydana getirdiği şey veya hüküm de bulunur. İllet bu-lunmayınca bunlar da bulunmaz. Satış akdi, mülkiyet için illettir. Akd yapılınca, satıcı sat-tığı eşyanın bedeli olan şeye, alıcı da mala sa-hip olur. Satış akdi olmayınca, alıcı da, satıcı da hiçbir şeye mâlik olamazlar. Yani mülkiyet denen şey meydana gelmez. Aynı şekilde, nikâh da evliliğin meydana gelmesinin illetidir. Nikâh varsa, evlilik vardır. Nikâh yoksa, evlilik de yok-tur, yani evlilik hâli yaşansa bile meşrû değil-dir. (Usûl-i Serahsî)","osmanli":"القاح"},{"kelime":"İLLET (Illet)","anlam":"Bir şeyin veya hükmün meydana gelmesine doğrudan te’sir eden iş,","kategori":"fikih","misal":"sebeb. İlletin bulunduğu yerde; te’sir ettiği, meydana getirdiği şey veya hüküm de bulunur. İllet bulunmayınca bunlar da bulunmaz. Satış akdi, mülkiyet için illettir. Akd yapılınca, satıcı sattığı eşyanın bedeli olan şeye, alıcı da mala sahip olur. Satış akdi olmayınca, alıcı da, satıcı da hiçbir şeye mâlik olamazlar. Yani mülkiyet denen şey meydana gelmez. Aynı şekilde, nikâh da evliliğin meydana gelmesinin illetid…","osmanli":"علت"},{"kelime":"İlm-i Ahlâk","anlam":"İyi huylar edinme ve kötü huylardan sakınma yollarını öğreten ilim.","kategori":"tasavvuf","misal":"(Bkz. Ahlâk)","osmanli":"اخلاق علم"},{"kelime":"İlm-i Bâtın","anlam":"Kalb ilmi, mânâ ilmi, tasavvuf ilmi.","kategori":"tasavvuf","misal":"İlm-i bâtın evliyânın yükseklerinin ilmidir. Bu ilim, kötü huylardan arınıldığında kalbe do-ğan bir nurdan ibârettir. Bu sâyede çok şeyler görülür, derin ve ince mânâlara vâkıf olunur. Geniş ufuklar açılır. (Kimyâ-i Seâdet)","osmanli":"باطن علم"},{"kelime":"İlm-i Bedî‘","anlam":"Sözün, garip (alışılmadık) hitap ve kelimelerle söylenerek güzelleştirilmesi.","kategori":"dil","osmanli":"بديع علم"},{"kelime":"İlm-i Belâgât","anlam":"Düzgün ve yerinde söz söyleme yolunu öğreten ilim.","kategori":"dil","osmanli":"بلاغت علم"},{"kelime":"İlm-i Beyân","anlam":"Terkiblerin maksada delâletteki açıklığını ortaya koyan ve belâgât ilminin hakîkat, mecâz, kinâye, teşbîh ve istiâre gibi mevzuları üzerinde duran ilim.","kategori":"muamelat","osmanli":"بيان علم"},{"kelime":"İlm-i Ferâiz","anlam":"Vefât eden kimsenin bıraktığı mirasın nasıl taksim edileceğini öğreten ilim (Bkz.","kategori":"miras","misal":"Ferâiz)","osmanli":"فرائض علم"},{"kelime":"İlm-i Hadîs","anlam":"Hazret-i Peygamber’in sözlerinden, fiillerinden ve görüp de mâni olmadığı şeylerden bahseden ilim.","kategori":"hadis","misal":"(Bkz. Hadîs)","osmanli":"حديث علم"},{"kelime":"İlm-i Hâl (İlmihâl)","anlam":"Herkesin bilmesi, inanması ve yapması gereken îmân, amel ve ahlâk bilgilerini kısaca ve açıkça anlatan ilim ve bu ilmin kitabı.","kategori":"akaid","osmanli":"حال علم"},{"kelime":"İlm-i Husûlî","anlam":"Bir şeyi onun sû-reti, görüntüsü zihinde bulunduğu müd-detçe bilmek.","kategori":"fikih","osmanli":"حصولى علم"},{"kelime":"İlm-i İlâhî","anlam":"Allahü teâlânın ezelî ilmi.","kategori":"akaid","osmanli":"الهى علم"},{"kelime":"İlm-i Kelâm","anlam":"İman bilgilerini öğreten ilim.","kategori":"akaid","osmanli":"كلام علم"},{"kelime":"İlm-i Lügat","anlam":"İsmin ve fiillerin değişik hâllerini tetkik eden ilim.","kategori":"dil","misal":"Sebîl ve tarîk yol mânâsına gelmekle beraber, birincisi hayırda kullanılır. İlm-i lügati bilmek de, Arab lügatini ve bunun evdâ‘ını, sahîhini, mervîsini, mütevâtirini, red yollarını, mevdû‘ lügatları, fasîh, redî ve mezmûm şekillerini bilmek ve müfred, şâz, nâdir, müsta‘mel, mühmel, mu‘reb, ma‘rife, iştikak, hakîkat, mecâz, müşterek, ızdâd, mutlak, mukayyed, ibdâl, kalb denilen lügat bilgilerinde üstad olmak demekti…","osmanli":"لغت علم"},{"kelime":"İlm-i Me‘ânî","anlam":"Söz ve terkiplerin hâle ve makama uygun ve i‘cazlı söylenmesinden bahseden edebî ilim.","kategori":"tasavvuf","misal":"Başın sağ olsun ile gözün aydın sözlerinin nerede söyleneceğini bilmek, ilm-i me‘âni sayesindedir. (Mevdûâtu’l-Ulûm)","osmanli":"معانى علم"},{"kelime":"İlm-i Nâfi‘","anlam":"“Faydalı ilim” mânâsına insana aczini, kusurunu, Rabbinin büyüklüğünü bildiren, kalbde Allah korkusunu ve mahlûklara karşı tevâzû, alçak gönüllülüğü artıran, kul haklarına ehemmiyet vermeyi temin eden sonsuz saadeti ve Allahü teâlânın rızâsını kazanmaya vesîl…","kategori":"akaid","osmanli":"نافع علم"},{"kelime":"İlm-i usûl-i Tefsîr","anlam":"Tefsir ilminin metodlarından, kâidelerinden, müfessirde bulunması gereken şartlardan, âyet-i kerîmelerin nâsih ve mensûhundan, hâss ve âmmından ve kelâm-ı ilahîden murad-ı ilahînin nasıl çıkarıldığından bahseden ilim.","kategori":"dil","osmanli":"تفسير اصول علم"},{"kelime":"İLMÂM","anlam":"Temettü haccı yapan âfâkînin, umreden sonra ailesini ziyaret edip haccı tamamlamak üzere tekrar Harem’e dönmesi.","kategori":"ibadet","osmanli":"المام"},{"kelime":"İLMİYYE","anlam":"Din âlimlerinin teşkil et-tiği sınıf.","kategori":"dil","osmanli":"علميه"},{"kelime":"İLTİCÂ","anlam":"Sığınma.","kategori":"dil","misal":"Ey âsîlerin, günahkârların sığınağı! Sana sığın-dım; sayısız hatâlar işledim. Şimdi sana ilticâ eyledim. (Mevlânâ Hâlid-i Bağdâdî) Bu dünya bir köprüdür gelen bir bir geçer durmaz, Hani âba u ecdâdın ne oldu kimseler sormaz, Hani annen baban nerde bu dünya kimseye kalmaz, Gelenler hep sefer eyler muhakkak dâr-ı bekâya, Yüzün dön ilticâ eyle Cenâb-ı zât-ı Mevlâya. (Tâceddîn-i Velî)","osmanli":"التجاء"},{"kelime":"İLTİFÂT","anlam":"1.Yüzünü çevirip bakma, te-veccüh etme, yüz gösterme. 2.Dikkat. 3.Ha-tır sorma, gönül alma. 4.Sözü, başka bir şahsa çevirme.","kategori":"dil","osmanli":"التفات"},{"kelime":"İLTİHÂB","anlam":"1.Alevlenme, tutuşma. 2.Vü-cudun bir tarafına kan hücumuyla, oranın şi-şip kızarması, cerahatlenme, yangı.","kategori":"dil","osmanli":"التهاب"},{"kelime":"İLTİMÂS","anlam":"Tavsiye, rica, kayırmak, tutmak, haksız olarak yardımda bulunmak, bir şeyin yapılmasını istemek.","kategori":"dil","osmanli":"التماس"},{"kelime":"İLTİZÂM","anlam":"Lâzım olma, gerektirme; üstlenme; devlete ait vâridatın toplanmasını ihâle ile ve ücret karşılığında üzerine alma.","kategori":"osmanli","osmanli":"التزام"},{"kelime":"İltizâm-ı Nass","anlam":"233.âyetinin ibâresinden evlâdını emziren annelerin nafakası mevlûdün leh (çocuğun doğmasına vesîle olan kimse, yani baba) üzerine olduğu anlaşılır. Mevlûdün leh tâbirinin kullanılıp da, vâlid (baba) tâbirinin kullanılmamış olması, nikâhı altında doğan çocuğun nesebinin kendisinden sübûtunu (sâbit olduğunu) iltizâm eder. (Büyük Haydar EfendiUsûl-i Fıkh)","kategori":"hadis","misal":"Âyet-i kerîme ve hadîs-i şerîflerin lafızlarının iltizâm ettiği ve ne maksatla söylendiğinin işitenlerin anlamasına yardımcı olan mânâ. Nassın lâzım kılması. Bakara sûresinin","osmanli":"نص التزام"},{"kelime":"İLYÂS (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen Benî İsrâîl peygamberlerden.","kategori":"dil","misal":"İlyâs da şüphe yok ki, peygamberlerdendi. Kavmine dedi ki: “(Allah’a karşı gelmekten) sakınmaz mısınız? Yaratanların en iyisi olan, sizin de Rabbiniz, sizden önce gelen atalarınızın da Rabbi olan Allah’ı bırakıp da Ba‘l’e mi tapınırsınız?”. (Saffât sûresi: 123-126) Hızır yerde ve İlyas denizdedir. Onlar her gece Zülkarneyn’in insanlar ile Ye’cûc ve Me’cûc arasında yaptığı sed üzerinde birleşirler. Yılda bir kere de…","osmanli":"الياس"},{"kelime":"İLZÂM","anlam":"1.Cevap veremez hâle getirme, susturma. 2.İltizam ettirme, gerektirme. 3.İs-pat etme.","kategori":"dil","misal":"Bir kimse, Peygamberlerin dediği doğru ise, biz kurtulduk demiş olsa, bu sözü şübhe yolu ile söylerse küfrdür. Eğer ilzâm tarîkiyle söylerse küfr değildir. (Birgivî Vasîyyetnamesi)","osmanli":"الزام"},{"kelime":"ÎMÂ","anlam":"İşâret etme; işaretle yapma, an-latma, dolayısıyla anlatma.","kategori":"dil","misal":"Bir özür sebebiyle başını yere koyamayan kimse, namazda rükû‘ için biraz, secde için rükû‘dan daha çok eğilerek kılar. Yatarak başı ile îmâ edemeyecek kadar ağır hastalığı yirmi dört sa-atten çok devam eden kimseden, aklı başında olsa bile, namaz sâkıt olur (düşer, kılması lâ-zım gelmez). (Halebî, İbn-i Âbidîn)","osmanli":"ايماء"},{"kelime":"İMÂD","anlam":"1.Direk, dikme, sütun. 2.Temel, esas. 3.Kuvvet. 4.Bir kavmin ileri geleni. 5.Bina.","kategori":"dil","osmanli":"عماد"},{"kelime":"İMÂM","anlam":"1.Cemâat ile kılınan namazda kendine uyulan kimse. 2.İslâmî ilimlerin her birinde en yüksek mertebeye ulaşan derin…","kategori":"ibadet","misal":"Cemâate, Kur’ân-ı kerîmi iyi okuyanınız imâm olsun. Bunda eşit olunca sünneti en iyi bileniniz, bunda da eşit olunca, en yaşlı olanınız imâm olsun! (Hadîs-i şerîfMüslim, Tirmizî) İmâm kalkan gibidir. Namazı tam kıldırırsa; hem onun, hem sizin lehinize olur. Noksan kıldırırsa, sizin namazınız yine tamdır. Noksanlık ondan sorulur. (Hadîs-i şerîfTaberânî)","osmanli":"امام","baglamlar":[{"baglam":"namaz","anlam":"Cemaatle namazda öne geçip namaz kıldıran kimse."},{"baglam":"mezhep","anlam":"Mezhep kurucusu büyük müctehid âlim (İmâm-ı A'zam, İmâm-ı Şâfiî gibi)."},{"baglam":"siyaset","anlam":"Müslümanların devlet başkanı, halîfe."}]},{"kelime":"İMÂM-I A‘ZAM EBû HANÎFE","anlam":"Ehl-i sünnet ve’l-cemâatın ameldeki dört mezhebinden biri olan Hanefî mezhebinin kurucusu ve Ehl-i sünnet itikadını sistematik halde kaleme alan Tâbiîn âlimi","kategori":"hadis","osmanli":"ابو اعظم امام حنيفه"},{"kelime":"İMÂM-I AHMED BİN HANBEL","anlam":"Ehl-i sünnetin amelde dört hak mezhe-binden biri olan Hanbelî mezhebinin reîsi ve Müsned kitabıyla tanınan hadîs âlimi.","kategori":"hadis","osmanli":"بن احمد امام حنبل"},{"kelime":"İMÂM-I MÂLİK","anlam":"Ehl-i sünnetin ameldeki dört mezhebinden biri olan Mâlikî mezhebinin reîsi ve zamanımıza intikal eden en eski fıkıh ve hadîs kitabı olan Muvatta‘ın müellifi.","kategori":"hadis","osmanli":"مالك امام"},{"kelime":"İmâm-ı Müslimîn","anlam":"Müslümanların imâmı, devlet reîsi, halîfe.","kategori":"ibadet","misal":"İmâmü’l-Müslimîn. (Bkz. Halîfe)","osmanli":"مسلمين امام"},{"kelime":"İMÂM-I ŞÂFİÎ","anlam":"Ehl-i sünnetin ameldeki dört mezhebinden biri olan Şâfiî mezhebinin reîsi.","kategori":"hadis","osmanli":"شافعى امام"},{"kelime":"İMÂM NİKÂHI","anlam":"Osmanlılar za-manında İmâmlar nikâh kıyma ile vazifelen-dirildiği için, dinî nikâha halk tarafından ve-rilen isim.","kategori":"dil","osmanli":"نكاحى امام"},{"kelime":"İMÂME","anlam":"1.Sarık.","kategori":"ibadet","misal":"İmâme takınız, hilminiz artar. Sarıklar Arapların taçlarıdır. (Hadîs-i şerîfBeyhekî). İmâme, küfr ile iman arasında ayırd edici bir alâmettir. (Hadîs-i şerîfTaberânî) Resûlullah aleyhisselâm imâmeyi sarar ve ucunu arkadan iki kürek arasına sarkıtırdı. (Râmû-zü’l-Ehâdis) Tesbihin başındaki uzun tâne. Çubuk, kamçı ve sigara ağızlığının başına takılan başlık.","osmanli":"عمامه"},{"kelime":"İMÂMET","anlam":"İmâmlık, reislik, başkanlık, rehberlik.","kategori":"ibadet","osmanli":"امامت"},{"kelime":"İmâmet-i Kübrâ","anlam":"Büyük İmâmlık. Devlet reisliği, hilâfet.","kategori":"ibadet","misal":"(Bkz. Hilâfet)","osmanli":"كبرى امامة"},{"kelime":"İmâmet-i Sugrâ","anlam":"Küçük İmâmlık. Namaz İmâmlığı.","kategori":"ibadet","misal":"(Bkz. İmâm)","osmanli":"صغرى امامة"},{"kelime":"İMÂMEYN","anlam":"“İki imâm” mânâsına daha ziyade fıkıh tarihinde İmâm-ı A‘zâm Ebû","kategori":"ibadet","misal":"Hanîfe’nin iki güzide talebesi İmâm-ı Ebû Yûsuf ile İmâm-ı Muhammed için kullanılan tabir. Müftî ve hâkim, İmâm-ı A‘zâm Ebû Hanîfe’nin sözüne uygun olarak fetvâ verir. Aradığını onun sözlerinde açıkça bulamazsa, İmâm-ı Ebû Yûsuf ’un sözünü alır. Onun sözlerinde de bulamazsa, İmâm-ı Muhammed Şeybânî’nin sözünü alır. İmâmeyn’in sözü bir tarafta, İmâm-ı A‘zam’ın sözü karşı tarafta ise, müftî her iki tarafa göre fetvâ v…","osmanli":"امامين"},{"kelime":"İMÂMİYYE","anlam":"Hazret-i Ali’nin halîfe olması nass ile açıkça emrolunduğuna; bu emri yerine getirmeyen sahâbilerin küfre düştüğüne; Hazret-i Peygamber’den sonra Hazret-i Ali ve sırasıyla onun iki oğlu ile torunlarını meşru ve masum imâm kabul eden, İmâmlığın Hazret-i Hüseyn…","kategori":"dil","misal":"Şiîliğin kollarından biri. İsnâaşeriyye. Ca‘feriyye. (Bkz. İsnâ Aşeriyye)","osmanli":"اماميه"},{"kelime":"ÎMÂN","anlam":"1.İnanmak, Al- lahü teâlâdan başka mâbud, ilâh olmadığına, Muhammed aleyhisselâmın O’nun kulu ve Resûlü olduğuna ve O’nun Allahü teâlâdan getirdiklerine kalb ile inanıp dil ile söylemek. Fakat Allah size îmânı sevdirdi. Onu kalblerinizde süsledi. Küfrü (îmânsızlığı), fâsıklığı (günahkârlığı), isyânı size çirkin gösterdi. (Hucurât sûresi: 7) Hakîkat şudur ki, îmân edenler ve Rablerine güvenip dayananlar üzerinde onun (şeytânın) hiç…","kategori":"akaid","osmanli":"ايمان","alternatif":["iman"]},{"kelime":"Îmân Duâsı","anlam":"Küfre düşmekten korunmak için her Müslümanın sabah ve akşam okuması tavsiye edilen duâ.","kategori":"akaid","misal":"İçinizdeki şirk karıncanın yürüyüşünden daha gizlidir. Sana yaptığında senden şirkin küçüğünü de büyüğünü de giderecek bir şeyin yolunu göstereyim mi? Şöyle dersin: Allahümme innî e‘ûzü bike min en üşrike bike şey’en ve ene a‘lemü ve estağfirüke limâ lâ a‘lemü inneke ente allâmülguyûb (Allah’ım Sana bilerek ortak koşmaktan yine Sana sığınırım. Bilmediğim şeyler için de Senden bağışlanmamı dilerim). (Hadîs-i şerîfHâk…","osmanli":"دعاسى ايمان","alternatif":["iman"]},{"kelime":"Îmân-ı Gaybî","anlam":"“Gayba iman” mânâsına Allahü teâlânın zâtı, sıfatları, âhiret, melekler, Cennet, Cehennem, Mîzân, Sırat gibi gözle görülmeyen şeylere görmeden inanmak.","kategori":"akaid","misal":"Îmân-ı gaybî, îmân-ı şühûdîden (görerek inanmak) daha üstündür. Çünki peygamberlerin îmânı, îmân-ı gaybîdir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"غيبى ايمان"},{"kelime":"Îmân-ı Şühûdî","anlam":"Basîret (kalb gözü) ile müşâhede ederek, görerek olan îmân.","kategori":"akaid","misal":"Dünya durdukça ve dünya hayâtı ile yaşadıkça gayba inanmaktan başka çâre yoktur. Çünki bu dünyada hakîkî îmân-ı şühûdîye kavuşmak mümkün değildir. Âhiret hayâtı başlayıp, vehm ve hayâlin kuvveti kalmayınca, görerek hâsıl olan îmân-ı şühûdî kıymetli olur. Muhammed aleyhisselâm dünyada iken yani Mîrâc Gecesinde âhiret âlemine götürülerek baş gözü ile Allahü teâlâyı görmekle şereflendiği için O’nun îmânı şühûdîdir deme…","osmanli":"شهودى ايمان"},{"kelime":"İMÂRET","anlam":"1.İmar etmek, şen ve ba-yındır olmak, bina ve yapı. 2.Fakirler ve tale-belerin bedava yemek yiyip barınmaları için yapılan vakıf eseri.","kategori":"muamelat","misal":"İmârethâne.","osmanli":"عمارت"},{"kelime":"İMDÂD","anlam":"Meded etmek, yardım; yar-dıma gönderilen kuvvet.","kategori":"dil","osmanli":"امداد"},{"kelime":"İMDİ","anlam":"Şimdi.","kategori":"dil","osmanli":"امدى"},{"kelime":"İMHÂ","anlam":"Mahvetme, mahvedilme, yok etme.","kategori":"dil","osmanli":"امحاء"},{"kelime":"İMKÂN","anlam":"Mümkün olmak, olabilecek vaziyette bulunma; olabilirlik.","kategori":"dil","osmanli":"امكان"},{"kelime":"İMSÂK","anlam":"1.Tutma, el çekme. 2.Oruca başlama.","kategori":"ibadet","misal":"Oruca imsak vakti başlanır ki, fecr-i sâdık denilen beyazlığın [güneşin ilk ışığının], zâhirî ufuk hattı üzerinde görüldüğü vakitdir. (Seâdet-i Ebediyye)","osmanli":"امساك"},{"kelime":"İMSÂK VAKTİ","anlam":"Oruca başlama zamanı.","kategori":"ibadet","misal":"Ufkun bir yerinde beyazlığın başladığı vakit.","osmanli":"وقتى امساك"},{"kelime":"İMTİHÂN","anlam":"1.Deneme, sınama, tec-rübe etme. 2.Bir şeyin hakikatini anlamak için çok geniş düşünmek. 3.Bir hususta salahiyetli olup olmadığını anlamak için için yapılan mu-ayene ve teftiş. 4.Sıkıntıya, mihnete düşme.","kategori":"dil","misal":"Bu dünya sofrasının en tatlı yemeği, derd ve musîbetlerdir. Bu tatlı ni‘metleri, acı ilâclarla kaplamışlar, bununla imtihân yolunu açık tut-muşlardır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"امتحان"},{"kelime":"İMTİSÂL","anlam":"1.İcâb edeni, ge-rekeni yapma; uyma, muvafakat etme. 2.Bir numuneye göre hareket etme. 3.Bir şeyin su-retine girme.","kategori":"dil","misal":"Evâmir-i ilâhiyyeye adem-i imtisâl, ya şeriatin bildirdiği haberleri yalan addederek, i‘timâd et-memek veya Hak teâlânın emirlerine ehemmi-yet vermemek sebebiyledir. Çirkinliğini düşün-mek gerektir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"امتثال"},{"kelime":"İMTİSÂS","anlam":"Mass etme, emme, eme-rek çekme, absorbe etme, soğurma, soğu-rulma, emilme.","kategori":"dil","osmanli":"امتصاص"},{"kelime":"İMTİYÂZ","anlam":"Ayrılmak, ayrı olmak; bir kimseye başkalarına tanınmayan hak, üstün-lük, ayrıcalık.","kategori":"dil","osmanli":"امتياز"},{"kelime":"İMZÂ","anlam":"1.Bir hükmü yerine getirme, icrâ ve infâz etme. 2.Yazılı bir vesikanın altına tasdik makamına el yazısı ile yazılan isim veya konulan işaret.","kategori":"fikih","osmanli":"امضاء"},{"kelime":"İNÂD","anlam":"Israr, direnme, ayak direme, de-diğinden vazgeçmeme.","kategori":"dil","misal":"Allahü teâlânın en sevmediği kimse, hakkı kabul etmemekte inâd edendir. (Hadîs-i şerîf-Berîka) Ebû Cehl ve Ebû Leheb inâdlarından dolayı Muhammed aleyhisselâmın peygamber oldu-ğuna inanmadılar. (Şeyhzâde)","osmanli":"عناد"},{"kelime":"INÂN ŞİRKETİ (İnan Şirketi)","anlam":"Ortakların birbirine vekil olup, kefil olmadıkları şirket.","kategori":"muamelat","misal":"Inân şirketinde ortakların birbirine kefîl olmaları da ayrıca şart edilebilir. Sermâye hisselerinin eşit olması şart değildir. Kârın nasıl taksim edileceği bildirilmezse, şirket fâsid olur. Inân şirketi bir veya çeşitli ticâret işleri yapabilir. Kâr nisbeti hisseye göre değil, şartnâmeye göredir. (İbni Âbidîn)","osmanli":"شركتى عنان"},{"kelime":"İNÂYET","anlam":"Lütuf, ihsân, iyilik, yardım. Bu fakirde bu yola girmek arzusu belirince, Al-lahü teâlâ inâyetiyle onu Hâcegân yolunun bü-yüklerinden birine ulaştırdı. Bu azîzin (Mu-hammed Bâkî-billâh’ın) sohbetiyle şereflendirip,","kategori":"dil","misal":"büyüklerin yolunu nasip etti. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عنايت"},{"kelime":"İNBİSÂT","anlam":"Bast hâline geçme, geniş-leme, yayılma; açık yüzlü olma; ferahlama, rahatlama, neşelenme; genleşme. (Bkz. Bast)","kategori":"dil","osmanli":"انبساط"},{"kelime":"İNCÎL","anlam":"Allahü teâlânın, Îsâ aleyhisselâma gönderdiği mukaddes kitab.","kategori":"dil","misal":"İncîl, asil mânâsına necl kelimesinden gelir. Birçok ilim ve hikmetin aslı demektir. Aynı zamanda reşha, yani sızıntı hâlinde çıkan su demektir. Zira Allahü teâlâ, onun vasıtasıyla silinmiş, izleri kaybolmuş hakkı ortaya çıkarmıştır. (Kurtubî)","osmanli":"انجيل"},{"kelime":"İND-İ İLÂHÎ","anlam":"Allahü teâlânın katında.","kategori":"akaid","osmanli":"الهى عند"},{"kelime":"İNFİLÂK","anlam":"(A. Felak’tan) Yarılma, açılma; patlama.","kategori":"dil","osmanli":"انفلاق"},{"kelime":"İNHİTÂT","anlam":"Düşme, aşağı inme, aşa-ğılama, yaşlılığa yüz tutma.","kategori":"dil","osmanli":"انحطاط"},{"kelime":"İNKÂR","anlam":"Bilmeme, tanımama; yaptı-ğını ve söylediğini gizleme; reddetme, ka-bul etmeme.","kategori":"dil","misal":"Bu bizim indirdiğimiz Kur’ân-ı kerîm insan-lar için çok hayırlı ve faydalı bir kelâmdır (sözdür). (Ey Mekkeliler!) Şimdi onu inkâr mı ediyorsunuz. (Enbiyâ sûresi: 50)","osmanli":"انكار"},{"kelime":"İNKILÂB","anlam":"Kalbetme, bir hâlden, başka bir hâle dönme, değişme.","kategori":"tasavvuf","osmanli":"انقلاب"},{"kelime":"İNKİSÂR","anlam":"Kırıklık, kırılma; gücenme; bedduâ, ilenme, ilenç.","kategori":"dil","misal":"Ben, kalbleri benim için inkisârda olanla-rın yanındayım. (Hadîs-i Kudsî-Keşfü’l-Hafâ) İNKİŞÂF: انكشاف (A) Keşf olma, açılma, açı- lım; meydana çıkma; tasavvufta manevî bir hâlin görünmesi. İlim, inkişâftan ibârettir. Bu inkişâf ihâta ile olursa, ilm-i husûlîdir (çalışarak ele geçen ilim-dir). (Mektûbât-ı İmâm-ı Rabbânî) İNNÂ LİLLAH VE İNNÂ İLEYHİ RÂCİ‘ûN: راجعون اليه وانا لله انا (A) Belâ ve musîbet gelince veya kötü bir haber duyunca okunan, Bakara sûresinin; “Biz Allahü teâlâya âidiz ve yine O’na döneceğiz” meâlindeki yüz elli altıncı âyet-i kerîmesi. (Bkz. İstirca‘) Bir belâ gelince; “İnnâ lillah ve innâ ileyhi râci‘ûn” demek yalnız bu ümmete mahsûs bir ihsândır. Geçmiş ümmetlerden hiç bi-risine verilmemiştir. Yoksa Yâkûb aleyhis-selâm, Yûsuf aleyhisselâmın ayrılığı musîbeti başına gelince; “Ey Yûsuf ’un firâkıyla (ay-rılığı ile) beni kaplayan hüzün ve hasretim” demez; “İnnâ lillâh ve innâ ileyhi râci‘ûn” derdi. (Hadîs-i şerîf-Taberânî)","osmanli":"انكسار"},{"kelime":"İNNÎ","anlam":"İnne’li. Hâdise ve tecrübelerden elde edilen netice.","kategori":"hadis","misal":"Her şeyin varlığı Ondandır. O, kendini de, her şeyi de göstermektedir. Bunun içindir ki, Rabbimi, Rabbim vâsıtası ile tanıdım ve her şeyi O’nunla tanıdım deriz. Böyle olduğu münâzara ilmindeki (Limmî) üsûlü ile anlaşılmaktadır. Âlimlerin çoğuna göre (innî) delili ile anlaşılır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"انى"},{"kelime":"İNNÎN","anlam":"İnnet sahibi. İhtiyârlık, tenâsül hastalığı veya sihir sebebi ile cimâ yapamayan.","kategori":"fikih","misal":"Kendinde bir mâni, kusur bulunmayan kadın, kocanının innîn olduğunu anlarsa, nikâhın feshi (bozulması) için, çok zaman sonra bile dâvâ açabilir. (İbni Âbidîn)","osmanli":"عنين"},{"kelime":"İNS","anlam":"İnsan, beşer.","kategori":"dil","osmanli":"انس"},{"kelime":"İNŞÂ","anlam":"1.Yapma, vücuda getirme, ter-kib etme. 2.Yaratma. 3.Yazı dersi.","kategori":"dil","osmanli":"انشاء"},{"kelime":"İNŞÂALLAH","anlam":"Olması beklenen bir iş hakkında söylenen “Allahü teâlâ dilerse (olur)” meâlinde söz.","kategori":"akaid","misal":"Bir şeyi yarın yapmaya azmettiğin, karar verdiğin zaman, onu yarın yaparım deme. İnşâallah yarın yaparım de! (Kehf sûresi: 23, 24) Bir kimse ile bir şey kararlaştırırken inşâallah deyip, sonradan o iş yerine getirilemezse yalancı olunmamış olur. (Ey Oğul İlmihâli)","osmanli":"الله انشاء"},{"kelime":"İNSÂF","anlam":"Merhamet ve adâlet daire-sinde hareket, doğruluk, hakkı kabul etme. İnsâf, dinin yarısıdır. (Hadîs-i şerîf-İhyâ) Allah korkusu kalbine yerleşmiş olan kimse, insanlar hakkında insâflı muâmelede bulunur. İnsanlar ise, kendilerine insâf ile iyi muâme-lede bulunan kimseyi severler. (Edebü’d-Dünyâ ve’d-Din)","kategori":"hadis","osmanli":"انصاف"},{"kelime":"İNSÂN","anlam":"Rûh ve bedenden meydana gelen akıl sahibi varlık.","kategori":"akaid","misal":"Biz insanı muhakkak ki çamurun özünden yarattık. Sonra Âdem’in neslini sağlam bir yerde (rahimde) döllenmiş yumurta yaptık. Sonra o nutfeyi kan pıhtısı hâline getirdik. Ondan sonra kan pıhtısını bir parça et yaptık; o et parçasını da kemikler hâline çevirdik. Sonra ona başka bir yaratılış (ruh) verdik. Bak ki, şekil verenlerin en güzeli olan Allahü teâlânın şânı ne kadar yücedir. (Mü’minûn sûresi: 12-14) Cinleri ve…","osmanli":"انسان"},{"kelime":"İnsân-ı Kâmil","anlam":"Kemâle ermiş, ol-gun insan; dinin emir ve yasaklarına riayet","kategori":"dil","misal":"ederek Hazret-i Peygamber’in güzel ahlâkıyla ahlâklanan, hareketleri ve sözleri hep Allahü teâlânın ilhâmı ile olan insan.","osmanli":"كامل انسان"},{"kelime":"İNŞİKÂK","anlam":"(A Şakk’dan) Yarılma, çatlama; ikiye ayrılma.","kategori":"dil","osmanli":"انشقاق"},{"kelime":"İNŞİRÂH","anlam":"Şerh olma, açılma; açık-lık, ferahlık.","kategori":"dil","osmanli":"انشراح"},{"kelime":"İNTİBÂ‘","anlam":"1.Matbu olma, basılma. 2.Zi-hinde iz bırakma, izlenim.","kategori":"dil","osmanli":"انطباع"},{"kelime":"İNTİBÂK","anlam":"(A. Tıbk’dan) Mutâbık gelme, uyma, uygun gelme.","kategori":"dil","osmanli":"انتباق"},{"kelime":"İNTİHÂR","anlam":"Kendini öldürme. Bir kimse bir demirle intihâr etse, Cehennem’de ebedî olarak demiri elinde karnını dürter durur.","kategori":"akaid","misal":"İntihâr eden kimse hemen ölse bile, yıkanır ve namazı kılınır. (İbni Âbidîn) Malını, mevkiini kaybettiği için veya düşman eline esir düştüğü için intihâr eden ahmaklarda şecâat (yiğitlik) değil korkaklık vardır. (Berîka)","osmanli":"انتحار"},{"kelime":"İNTİKÂL","anlam":"1.Nakletme, bir yerden başka bir yere geçme; göçme. 2.Ölme.","kategori":"dil","misal":"Mürted olup dârülharbe gidenin malları vâris-lerine intikâl eder. (Bahrü’l-Fetâvâ)","osmanli":"انتقال"},{"kelime":"İNTİKÂM","anlam":"1.Öc alma. 2.Allahü teâlânın; zâlim, inâdcı ve kibirli (büyüklenen) kimseleri şiddetli bir azap ile cezâlandırması.","kategori":"akaid","misal":"Haramları, büyük ve küçük günah diye ikiye ayırmışlar ise de, küçük günahlardan da, büyük günah gibi kaçınmak, hiçbir günahı küçümsememek gerekir. Çünki, Allahü teâlâ intikâm alıcıdır. Gadabını, düşmanlığını günahlar içinde gizlemiştir. Küçük sayılan bir günah, intikâmına, gadabına sebeb olabilir. (RiyâdünNâsıhîn)","osmanli":"انتقام"},{"kelime":"İNTİSÂB","anlam":"1.Mensub olma, bağlanma. 2.Bir işe, bir mesleğe, bir yola girme. 3.Bir mürşid-i kâmile bağlanma, talebe olma, ta-rikata girme.","kategori":"dil","misal":"Bî‘atin ikincisi, intisâb etmek, bereketlenmek için bir Velîye “rahmetullahi teâlâ aleyh” veya onun hakîkî mensuplarına bî‘at etmektir. (Mekâtib-i Şerîfe li-Abdillah Dehlevî)","osmanli":"انتساب"},{"kelime":"İNTİSÂR","anlam":"Kendisine haksızlık eden-den, yalnız hakkını geri alıp, fazlasını almamak. Resûlullah efendimiz sallallahü aleyhi ve sellem bir kimsenin zâlime bedduâ ettiğini görünce; “İntisâr eyledin” buyurdu. (Berîka)","kategori":"akaid","osmanli":"انتصار"},{"kelime":"İNTİŞÂR","anlam":"Neşrolunma, yayılma, da-ğılma; üreme; gizli bir şeyin ağızdan ağıza ya-yılması; umûmîleşme.","kategori":"dil","osmanli":"انتشار"},{"kelime":"İNTİZÂM","anlam":"Nizamlı, tertipli, düz-gün olma.","kategori":"dil","osmanli":"انتظام"},{"kelime":"İNZİVÂ","anlam":"Bir köşeye çekilme, çekilip hiç bir işe karışmama; dünya işlerinden vazgeçme. Kutb-ı medâra inzivâ (gizlenmek) lâzımdır. Resûlullah zamanında kutb-ı medâr var idi. (Mektûbât-ı Ma‘sûmiyye)","kategori":"dil","osmanli":"انزواء"},{"kelime":"İPEK","anlam":"İpek böceğinin kozasından elde edilen ipliklerle dokunan kıymetli bir ku-maş. Harîr.","kategori":"dil","misal":"İpeği dünyada giyen erkek âhirette giyemeye-cektir. (Hadîs-i şerîf-Buhârî, Müslim, Tirmizî)","osmanli":"ايﭙك"},{"kelime":"İPOTEK","anlam":"Gayrımenkul bir malı, borç karşılığında rehnetme.","kategori":"muamelat","osmanli":"اﭘوتك"},{"kelime":"ÎRÂD","anlam":"1.Getirme. 2.Söyleme.","kategori":"dil","misal":"(A. Vürûd’dan) “Allahü teâlâ semâvâtın ve arzın nûrudur” âyet-i kerîmesinin mânâsı, sonradan yaratıl-mışlar, yokluklar olup, baştanbaşa zulmet ve şerlerdir. Ve onlarda olan hayr ve kemâl, hüsn ve cemâl vâcib-i teâlâ ve tekaddesdendir. Lâ-kin bu nûr zıller vâsıtası ile olup, “Allahü teâlâ-nın mü’minin kalbindeki nûru, fener içindeki mum gibidir” âyet-i kerîmesi bunu irâd buyu-rur. (Mektûbât-ı Ma‘sûmiyye)","osmanli":"ايراد"},{"kelime":"İrâde-i Cüz’iyye","anlam":"Allahü teâlânın, bir işi yapmak ve yapmamak hususunda insanlara ihsân ettiği dileme ve seçme kuvveti.","kategori":"dil","misal":"İnsanların işleri yalnız irâde-i cüz’iyye ile meydana gelmez. İnsan işlerin olmasını irâde eder, meselâ elinin hareket etmesini ister, kudretini kullanır, hareket meydana gelir. Fakat insan bunu yarattı denilemez. İrâde-i cüz’iyye insanın kalbinde hâsıl olmaktadır. İnsanın işleri ezeldeki takdîr ile meydana geliyor ise de, meydana gelmeleri için önce kul îrâde-i cüz’iyyesini kullanmaktadır. İşin yapılmasını veya yap…","osmanli":"جزئيه ارادۀ"},{"kelime":"İRÂDE (İrâdet)","anlam":"1.Dileme, isteme. 2.Emir, ferman. 3.Allahü teâlânın sübûtî sıfatlarından.","kategori":"akaid","misal":"Allahü teâlânın dilemesi. (Muhakkak ki senin Rabbin) her neyi irâde ederse irâde ettiği gibi yapar. (O’nun irâdesi hiç şaşmaz. Helâk etmek irâde ettiklerini muhakkak helâk eder, kurtuluşa erdirmeyi irâde ettiklerini kurtuluşa erdirir.) (Burûc sûresi: 16) Allahü teâlâ kulların ihtiyârî yani istekli hareketlerini, işlerini yaratması için kullarında ihtiyâr (seçme, isteme hususiyeti) ve irâde yaratmış, bu irâde ve ihti…","osmanli":"اراده"},{"kelime":"İRÂDÎ HAREKET","anlam":"İrade, istek ile yapılan hareket. İhtiyarî hareket.","kategori":"dil","osmanli":"حركت ارادى"},{"kelime":"İRFÂN","anlam":"Bilme, anlama; marifet; kalble bilip tanıma; Allahü teâlânın ihsânı olan mânevî, vehbî ilim.","kategori":"tasavvuf","misal":"Çalışarak elde edilen ilimler ile anlaşılan, bilinen şeylerden başka bilgiler de vardır, bunlar irfân ile anlaşılır. Âlimlerin sahip oldukları ilme mukâbil, ârif denen Allahü teâlânın sevdiği kullarında da irfân denen bir hâssa vardır. İrfân, tasavvufta fenâ mertebesiyle şereflenenlerde bulunur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عرفان"},{"kelime":"İRİN","anlam":"Bir canlının herhangi bir yerinde iltihaplanma neticesi ölmüş hücre artıkların-dan ve bozulmuş akyuvarlardan müteşekkil, mikroplu veya mikropsuz, umumiyetle boz ve sarımtırak renkte koyuca sıvı, cerahat.","kategori":"dil","osmanli":"ايرين"},{"kelime":"IRK","anlam":"1.Damar. 2.Kök, asıl; kavim.","kategori":"dil","osmanli":"عرق"},{"kelime":"IRKÇILIK","anlam":"Muayyen bir ırkın, yalnızca fizyolojik ve genetik sebeblerle diğerlerine üstünlüğü ve imtiyazı bulunduğunu kabul eden felsefî ve siyasî fikir cereyanı.","kategori":"fikih","misal":"Kavmiyetçilik. ElKavmiyye.","osmanli":"عرقﭽيلق"},{"kelime":"İRS","anlam":"Vefât eden bir kimsenin geriye bı-raktığı terekesinden (malından) evlât ve ak-rabâsından sağ kalanlara düşen hisse, pay. Mîrâs. (Bkz. Mîrâs)","kategori":"miras","misal":"İrs, karâbete (soy ile veya nikâh ile olan akra-bâlığa, hısımlığa) dayanır. Böyle bir yakını, ak-rabâsı bulunmazsa, vefât edenin vasîyetinden artan malı beytülmâle (devlet hazînesine) ka-lır. (İbni Âbidîn)","osmanli":"ارث"},{"kelime":"İRSÂD","anlam":"1.Gözetleme. 2.Hükümdarın beytülmâle ait bir arâzînin gelirinin bir amme hizmetine veya bir başka cihete tahsisi.","kategori":"muamelat","osmanli":"ارصاد"},{"kelime":"İRSÎ","anlam":"Miras ile alâkalı; genetik.","kategori":"miras","osmanli":"ارثى"},{"kelime":"İRTİBÂT","anlam":"1.Rabtedilme, bağlanış, bağlanma. 2.Alâka. 3.Bağlantı, ibarelerin bir-birini tutması. 4.Ribât etme, düşmana karşı hududu bekleme.","kategori":"dil","misal":"İnsanın rûhu, âlem-i emirdeki asıl mertebesi ile irtibât kurabilecek gücü kazanınca, in-san bir ânda çeşitli yerlerde görünebilir. (Ne-fehâtü’l-Kurb)","osmanli":"ارتباط"},{"kelime":"İRTİCÂ‘","anlam":"1.Ric‘at etme; geri dönme. 2.Eski hayat tarzına dönme, gericilik.","kategori":"dil","osmanli":"ارتجاع"},{"kelime":"İRTİDÂD","anlam":"Dinden dönme; Müslüman iken, İslâm dinini terk etme. Ridde.","kategori":"dil","misal":"İçinizden kim irtidâd eder de kâfir olarak ölürse, yaptığı (iyi) işler dünyada da âhi-rette de boşa gitmiştir. Onlar o ateşin (Ce-hennem’in) arkadaşlarıdır. Onlar orada (bir daha çıkmamak üzere) ebedî (sonsuz) kalıcı-dırlar. (Bakara sûresi: 217) Doğru yol göste-rildikten sonra Peygambere (aleyhisselâm) uymayan ve îmânda ve amelde mü’minler-den ayrılan kimseyi küfr ve irtidâdda bıra-kır ve Cehennem’e atarız. O Cehennem çok kötü bir yerdir. (Nisâ sûresi: 104) İrtidâd ede-nin boynunu vurun! (Hadîs-i şerîf-Buhârî) Müslüman kâfir olursa, yani irtidâd ederek İslâmiyet’ten çıkarsa, önceki ibâdetleri ve se-vabları yok olur. Tekrar îmâna gelirse, yeniden hac etmesi lâzım olur. Namazlarını, oruçlarını zekâtlarını kazâ etmesi lâzım olmaz. Önce-den kazâya bırakmış olduklarını kazâ etmesi lâzımdır. Çünki irtidâd edince, önceki günah-lar yok olmaz. İrtidâd edenin nikâhı fesh olur, gider. (Berîka)","osmanli":"ارتداد"},{"kelime":"İRTİFÂ‘","anlam":"Yükselme; yüksek-lik, yükselti; yukarı kalkma, kaldırma.","kategori":"dil","osmanli":"ارتفاع"},{"kelime":"İRTİYÂB","anlam":"Şüphelenme, duraklama.","kategori":"dil","osmanli":"ارتياب"},{"kelime":"IRZ","anlam":"1.Düşürme, düşürülme; yok etme; hükümsüz bırakma. 2.Talâk, köle âzâdı, ibrâ gibi mülkiyet veya zevciyet gibi bir hakkın düşmesi neticesini doğuran hukukî ta-sarruf. 3.Çocuk düşürme. 4.Öle-nin yapamadığı ibâdetlerin affedilmesi ümi-diyle, öldükten sonra bıraktığı mallarından fakirlere fidye verme.","kategori":"dil","misal":"Şan, şeref; namus, iffet, temizlik. ISKÂT (İskat): اسقاط (A) Iskât-ı cenîn. (Bkz. İskât)","osmanli":"عرض"},{"kelime":"İŞÂ","anlam":"1.Yatsı vakti. 2.Akşam yemeği.","kategori":"dil","misal":"(Bkz. Işâ)","osmanli":"عشاء"},{"kelime":"ÎSÂ (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen ve yeni bir din getiren ülülazm peygamberlerden.","kategori":"dil","misal":"Melekler dedi ki: “Ey Meryem! Allah sana kendisinden bir kelimeyi müjdeliyor. Adı Meryem oğlu Îsâ’dır. Mesîh’tir. Dünyada da, âhirette de itibarlı ve Allah’ın kendisine yakın kıldıklarındandır. İnsanlarla, beşikte iken de, yetişkin iken de konuşacaktır ve o, iyilerdendir”. (Âl-i İmrân sûresi: 45-46) Kendinden önce gelen Tevrat’ı doğrulayıcı olarak peygamberlerin izleri üzerine, Meryem oğlu Îsâ’yı gönderdik. Ve ona,…","osmanli":"عيسى"},{"kelime":"İşâ-i Evvel","anlam":"“İlk yatsı vakti” mânâsına İmâmeyne yani İmâm Ebû Yûsuf ve İmâm Muhammed’e göre yatsı namazı vaktinin başladığı zaman.","kategori":"ibadet","misal":"Yatsı namazının vakti, İmâmeyne göre, işâ-i evvelden, yani garbdaki zâhirî ufuk hattı üzerinde, kırmızılık gayb olduktan sonra başlar. Diğer üç mezhebde de böyledir. (Seâdet-i Ebediyye)","osmanli":"اول عشاء"},{"kelime":"Işâ-i Sânî","anlam":"İkinci yatsı vakti. Garb-daki mer’î (zâhirî) (görünen) ufuk hattı üze-rinde, şafak karardıktan sonra kırmızılığın kaybolması ile başlayan ve umumiyetle güne-şin üst kenarının ufk-ı mer’î (sathî) altında, 17 derece yüksekliğe indiği vakit.","kategori":"akaid","misal":"Yatsı namazının vakti, İmâm-ı A‘zâm’a göre ışâ-i sânîden, yani garb ufkunda beyazlık kaybol-duktan sonra başlar. Fecrin ağarmasına, yani imsak vaktine (şark ufkunda ilk aydınlığın gö-rünmesine) kadar devam eder. (İbni Âbidîn)","osmanli":"ثانى عشاء"},{"kelime":"İşâ-i Sânî","anlam":"“İkinci yatsı vakti” mânâ-sına İmâm-ı A‘zâm’a göre yatsı namazı vakti-nin başladığı zaman.","kategori":"ibadet","misal":"Yatsı namazının vakti, İmâm-ı A‘zâm’a göre işâ-i sânî yani güneş zâhirî ufuk hattı üzerinde, şafak tam karardıktan yani beyazlık gayb ol-duktan sonra başlar, fecrin doğmasına, imsâk vaktine kadar devam eder. Beyazlığın gayb ol-ması, güneşin üst kenarının, ufk-ı sathînin al-tında, ondokuz dereceye indiği vakittir. (Seâ-det-i Ebediyye)","osmanli":"ثانى عشاء"},{"kelime":"İSÂBET","anlam":"1.Rast gelme, doğruca gidip erişme, yerini bulma. 2.Doğru bir fikir söy-leme. 3.Düşme, tutma, dokunma.","kategori":"dil","misal":"(A. Okla hedefi vurmak mânâ-sına savb’dan) İctihâdı doğru olanlara iki veya on sevâb, isâbet etmeyenlere de, bir sevâb vardır. (Ha-dîs-i şerîf-Müsnedü Ahmed)","osmanli":"اصابت"},{"kelime":"ÎSÂL","anlam":"Vusul buldurma, buldurulma; vardırma, vardırılma, ulaştırma, ulaştırılma. Turuk-ı îsâl (kavuşturma yolları), zikr-i nefyü ispat (Lâ ilâhe illallah), zikr-i zât (Allah), tevec-cüh ve murâkabedir. (Mektûbât-ı Ma’sûmiyye)","kategori":"ibadet","osmanli":"ايصال"},{"kelime":"ÎŞÂN","anlam":"Onlar. Türkistan ve Tataristan’da bir tasavvuf büyüğü için kullanılan ta‘zim sözü.","kategori":"tasavvuf","misal":"Îşâna muhabbet, Allahü teâlânın en büyük nimetlerindendir ve saadetin sermayesidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ايشان"},{"kelime":"ÎSÂR","anlam":"1.Kendi muhtac olduğu şeyi verme; cömertlik; ikram; bahşiş. 2.İhtiyar etme, seçme. 3.Yumuşatma. 4.Dökme, serpme, saçma.","kategori":"tasavvuf","misal":"Namaz vakti gelince abdestsiz kimsenin abdest suyunu başkasına îsâr etmesi câiz değildir. (Eşbâh) Resûlullah’ın Eshâbının hâli cömertlikten öte, îsâr idi. Kerem ve ihsân sahiplerinin âdeti, îsâr etmektir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ايثار"},{"kelime":"İŞÂRET-İ NASS","anlam":"Nassın (âyet-i kerîme ve hadîs-i şerîfin) görünen mânâsından başka, ayrıca maksûd olmayan, kastedilmeyen bir mânâyı da bildirmesi, lafzın, ibâresinden çıkan hükme değil, bu hükümden hareketle, dolaylı olarak anlaşılan hükme delâlet etmesi.","kategori":"hadis","misal":"emzikli kadınların yiyecek ve giyeceklerinin boşayan erkeklere âit olduğunu bildirmektedir. Ayrıca, âyet-i kerîme, işâret-i nass yoluyla çocuğun nesebinin babaya âit olduğunu da ifâde etmektedir. (Serahsî)","osmanli":"نص اشارة"},{"kelime":"İŞBÂ‘","anlam":"Doyma, doyurma.","kategori":"dil","osmanli":"اشباع"},{"kelime":"İSBÂT","anlam":"1.Delil göstere-rek doğruyu meydana çıkarma. 2.İtiraf, ik-rar etme. 3.Sâbit ve muhkem kılma. 4.Bâki kılma. 5.Şâhid, delil.","kategori":"dil","misal":"(A. Sübut’dan) Red eder ve mu‘cize, bir zâtın Peygamber oldu-ğunu ispat etmez der isen, mu‘cizeleri tevâtür ile bize haber verilen diğer Peygamberlere de inanmaman lâzım gelir. (Tefsîr-i Kebîr)","osmanli":"اثبات"},{"kelime":"İSBI‘","anlam":"1.Parmak. 2.Bir parmaklık, ka-rınları bitişik altı arpa (1/6 zrâ‘ 1,925 cm) mik-darında bir uzunluk ölçüsü.","kategori":"dil","osmanli":"اصبع"},{"kelime":"ÎSEVÎ","anlam":"Îsâ aleyhisselâmın dinine inanan kimse.","kategori":"dil","misal":"Hazret-i Îsâ, göğe çıkarıldıktan kırk sene sonra, Romalılar Kudüs’ü alıp, yağma ve harâb ettiler. Yehûdîleri öldürdüler. Bir kısmını esir aldılar. Kudüs’de Yehûdî kalmadı. Îsâ aleyhisselâmın oniki havârîsi, başka yerlere dağıldı. Gökden inmiş olan İncîl kayboldu. Sonradan, İncîl diye bozuk kitâblar yazıldı. Bunlardan dördü her tarafa yayıldı. Îsevî dîni, Îsâ alâ nebiyyinâ ve aleyhissalâtü vesselâm görse tanımıyacak…","osmanli":"عيسوى"},{"kelime":"İSFÂR","anlam":"Sabah namazını ortalık aydınlanıncaya kadar geciktirerek kılmak.","kategori":"ibadet","misal":"Sabah namazını isfâr ediniz. Bunun ecri, sevâbı çoktur. (Hadîs-i şerîfNasbu’r-Râye)","osmanli":"اسفار"},{"kelime":"İSFİRÂR","anlam":"Sararma.","kategori":"dil","osmanli":"اصفرار"},{"kelime":"İsfirâr-ı Şems","anlam":"Güneşin sarar-ması. Tozsuz, dumansız, berrak bir havada güneş ışığının geldiği yerlerin veya kendisi-nin bakacak kadar sararmaya başlamasından, yani güneşin alt kenarının görünen ufuktan bir mızrak boyu (güneş merkezinin hakîki ufka 5 derece yaklaşması) yükseklikte olduğu vakitten, güneş batıncaya kadar geçen (takri-ben 40 dakikalık) zaman.","kategori":"dil","misal":"İkindi namazının vakti, öğle vakti bitince başla-yarak, güneşin üst kenarının ufk-i mer’i (görü-nen ufuk) den kaybolduğu görülünceye kadar-dır. İsfirâr-ı şems vaktinden sonra her namazı kılmak ve ikindiyi bu vakte geciktirmek haram-dır. Fakat o günün ikindi namazı gecikmiş ise yine bu vakitte de kılınır. Kazâya bırakılmaz. Önceden hazırlanmış cenâzenin namazı, sec-de-i tilâvet de bu vakitte câiz değildir. Hazırlan-ması bu vakitlerde biten cenâzenin namazını, bu vakitlerde kılmak câiz olur. (İbni Âbidîn)","osmanli":"شمس اصفرار"},{"kelime":"İŞGÂL","anlam":"1.Meşgul etme, işle uğraş-tırma. 2.İşten alıkoyma. 3.Tutma, zabt etme, istilâ etme.","kategori":"dil","misal":"Vakf mezârlıklara türbe yapmanın câiz olma-ması, fakîrlerin yerlerini işgâl etmemek içindir. (Fetâvâ-i Feyziyye)","osmanli":"اشغال"},{"kelime":"İSHÂK (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen ve Şam ile Filistin ahâlisine gönderilen peygamberlerden.","kategori":"dil","misal":"Biz İbrâhim’e oğlu İshâk’ı ve İshâk’ın oğlu Yâkûb’u hibe ettik ve herbirine hidâyet ve nübüvvet (peygamberlik) verdik. (En‘âm sûresi: 84)","osmanli":"اسحاق"},{"kelime":"İSKA’","anlam":"Arâzî veya hayvan sulama.","kategori":"muamelat","osmanli":"اسقاء"},{"kelime":"İSKÂN","anlam":"1.Sakin kılma, oturtma, ev sa-hibi etme. 2.Yerleştirme.","kategori":"dil","osmanli":"اسكان"},{"kelime":"İskât Devri (İskat ve Devr)","anlam":"Vefât eden bir Müslümanın sağlığında kılamadığı namaz, tutamadığı oruç ve veremediği zekât gibi borçlardan kurtulması için birkaç fakirin kendilerine ölünün vasî veya velîsi tarafından verilen fidyeyi alıp, gönül rızâsıyla tekrar geri vermek sûretiyle yapılan…","kategori":"ibadet","misal":"Tutulmamış oruçların ve ölüm hastalığına yakalanmış bir kimsenin kazâ edemediği namazları için iskât devri yapmanın lâzım olduğunda bütün âlimlerin söz birliği vardır. Peygamber efendimiz sallallahü aleyhi ve sellem; “Ümmetim dalâlet üzerinde birleşmez” ve “Mü’minlerin güzel gördüğü şey, Allah indinde de güzeldir” buyurdu. (Birgivî, Halebî, Tahtâvî, İbn-i Âbidîn, Berîka)","osmanli":"دورى اسقاط"},{"kelime":"İŞKENCE","anlam":"1.Kitap cildi presi. 2.Ezi-yet verme, azap etme.","kategori":"dil","osmanli":"اشكنجه"},{"kelime":"ISLÂHÂT","anlam":"İyi hâle, işe yarar hâle getirmek için yapılan çalışmalar, düzenleme-ler. Islâh’ın çokluk hâli.","kategori":"dil","osmanli":"اصلاحات"},{"kelime":"İSLÂM","anlam":"1.Boyun bükerek teslim olmak. 2.Allahü teâlânın peygamberleri vasıtasıyla bil-dirdiği hak din. 3.Muhammed aleyhisselâmın bildirdiği din.","kategori":"dil","misal":"(Bkz. İslâmiyet)","osmanli":"اسلام"},{"kelime":"İslâm Ahlâkı","anlam":"İslâm dininin bildirdiği ahlâk.","kategori":"tasavvuf","misal":"Müslümanlar birbirine hürmet eder, yardımlaşırlar. Din ve dünya işlerinde birbirlerinin sıkıntılarını giderirler. Kul ve hayvan haklarını gözetirler. Kânunlara karşı gelmezler. İslâm ahlâkı üzere yaşayarak herkesin sevgi ve saygısını toplarlar. (Ahlâk-ı A‘lâî)","osmanli":"اخلاقى اسلام"},{"kelime":"İslâm Âlimi","anlam":"Dinî ilimleri bütün incelikleri ile, zamanın fen bilgilerini de lü-zumu kadar bilen âlim. (Bkz. Âlim)","kategori":"dil","osmanli":"عالمى اسلام"},{"kelime":"İslâm Hukuku","anlam":"1.Kaynağını Muhammed aleyhisselâmın bildirdiği dinden alan ve bu istikamette din âlimleri tarafından meydana getirilen hukuk sistemi. 2.Dinin emir ve yasaklarını bildiren fıkhın, ibâdetler dışında kalan ve daha ziyade ferdler arası münasebetleri tanzim eden k…","kategori":"fikih","osmanli":"حقوقى اسلام"},{"kelime":"İslâm-ı Hakîkî","anlam":"Nefsin itminâna (Allahü teâlânın emirlerine itâate) kavuşmasından sonraki Müslümanlık.","kategori":"akaid","misal":"Bir Müslüman Allahü teâlânın ihsânı ile şeriatin (İslâmiyet’in) hakîkatine kavuşur, İslâm-ı hakîkî ile şereflenirse, peygamberlere tam uyar ve o büyüklere vâris olur. (Mektûbât-ı İmâm-ı Rabbânî) Cümle âlem bir yere gelse ve Rabbini inkâr etse, İslâm-ı hakîkî sahibi olan inkâr etmez ve kalbine aslâ şek ve şüphe gelmez. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"حقيقى اسلام"},{"kelime":"İslâm-ı Mecâzî","anlam":"Nefsin, itminâna gelmeden yani Allahü teâlânın rızâsına uygun hareket etmeye başlamadan önce, kişide bulunan ve Cennet’e girmek için yeterli olan İslâmiyet.","kategori":"akaid","misal":"Vilâyet-i hâssa (evliyâlığın en yüksek makamı) ile şereflenmedikçe, İslâm-ı mecâzîden kurtulup, İslâm-ı hakîkiye kavuşulmaz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مجازى اسلام"},{"kelime":"İSLÂMIN ŞARTI","anlam":"İslâm dinine girmiş olanlara yani Müslümanlara farz olan, muhakkak yapılması gereken beş esas vazife.","kategori":"fikih","misal":"İslâm’ın şartları beştir. Yani İslâm binâsı beş şeyin üzerine binâ kılınmıştır. Evvelkisi, kelime-i şahadet getirmek ve mânâsını öğrenip inanmak. İkincisi her gün beş vakt namaz kılmak. Üçüncüsü zekât vermek. Dördüncüsü Ramazan ayında oruç tutmak. Beşincisi kudreti var ise, ömründe bir kere hacca gitmek. (Miftahü’l-Cenne)","osmanli":"شرطى اسلامك"},{"kelime":"İSLÂMİYET (İslâmiyyet)","anlam":"Allahü teâlânın Cebrâil ismindeki melek vâsıtası ile, sevgili Peygamberi Muhammed aleyhisselâma gönderdiği, insanların dünyada ve âhirette rahat ve mes‘ûd olmalarını sağlayan usûl ve kâideler, emirler ve yasaklar.","kategori":"akaid","misal":"Allahü teâlâ Peygamberini hidâyet ve hak din İslâmiyet ile gönderdi. İslâm dinini diğer dinler üzerine üstün kıldı. (Muhammed aleyhisselâmın hak) peygamber olduğuna şâhid olarak Allahü teâlâ yeter. (Feth sûresi: 28) Bir zaman gelir ki, İslâmiyet’e yapışmak, elinde ateş tutmak gibi güç olur. (Hadîs-i şerîf- Beyhekî)","osmanli":"اسلاميت"},{"kelime":"İSM","anlam":"Suç, günah.","kategori":"dil","misal":"Ey iman edenler! Zannın çoğundan kaçının. Çünki zannın bir kısmı ism’dir. Birbirinizin kusurunu araştırmayın... (Hucûrât sûresi, 12)","osmanli":"اثم"},{"kelime":"İsm-i A‘zâm","anlam":"“En büyük isim” mânâsına Allahü teâlânın bütün sıfatlarını kendinde toplayan ve duâ edildiği zaman kabul olunacağı çok umulan ism-i şerîfi için kullanılan tabir.","kategori":"akaid","misal":"Allahü teâlânın bir ism-i a‘zamı (vardır ki) kim onunla duâ ederse Allah onun duâsını kabul eder. İşte o ism-i a‘zam Kur’ân-ı kerîmde üç sûrededir: ElBakara, Âl-i İmrân ve Tâhâ. (Hadîs-i şerîfİbn-i Mâce)","osmanli":"اعظم اسم"},{"kelime":"İSM (İsim)","anlam":"Varlıklara alâmet olan kelime, herhangi bir şeyi bir diğerinden ayırmak, tanımak yâhud zihne getirmek için kullanılan lafz.","kategori":"fikih","misal":"Sizler kıyâmet günü kendinizin ve babalarınızın adları ile çağırılırsınız. Öyle ise çocuklarınıza güzel isimler veriniz. (Hadîs-i şerîfİbn-i Mâce) Kendisine okuma yazma öğretmesi, güzel isim koyması ve büluğ çağına erişince evlendirmesi, çocuğun, babası üzerindeki haklarındandır. (Hadîs-i şerîfBeyhekî, Hâkim)","osmanli":"اسم"},{"kelime":"İSMÂİL (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen peygamberlerden.","kategori":"dil","misal":"(Resûlüm!) Kitab’da İsmâil’i de an! Gerçekten o, sözüne sâdıktı, resûl ve nebî idi. Halkına namazı ve zekâtı emrederdi. Rabbi nezdinde de hoşnudluk kazanmış bir zât idi. (Meryem sûresi: 54-55) Allahü teâlâ Âdemoğullarından Hazret-i İsmâil’i seçti. İsmâil’in evlâdından Kinâne’yi; Kinâneoğullarından Kureyş’i; Kureyş’ten Hâşimoğullarını; Hâşimoğullarından da beni seçti ve ayırdı. (Hadîs-i şerîfMüslim, Tirmizî, Müsnedü…","osmanli":"اسماعيل"},{"kelime":"İSMÂİLİYYE","anlam":"Oniki İmâmdan Cafer-i Sâdık’ın vefatından sonra küçük oğlu Mûsâ Kâzım’ı değil de, kendisinden evvel vefat eden büyük oğlu İsmail’i İmâm tanıyan; Kur’ân-ı kerîmin zâhirî ve bâtınî mânâsı olduğunu söyleyerek ibâhiyye inancına varan, hulûl ve tenâsühü kabul eden…","kategori":"dil","misal":"İsmâiliyye, ilk zamanlar, birçok bilgileri, eski Yunan felesoflarından aldılar. Meselâ, yaratıcı ne vardır, ne de yoktur. Ne âlimdir, ne câhildir. Ne kâdirdir, ne âcizdir. Bütün sıfatları da böyledir dediler. Çünki, bunlar var denirse, mahlûklara benzetilmiş olur. Yokdur denirse, yokluk kondurulmuş olur dediler. Yaratan, kadîm de değildir, hâdis de değildir dediler. Bunların başına geçen Hasen Sabbâh, gitdikleri yol…","osmanli":"اسماعيليه"},{"kelime":"ISMARLAMA","anlam":"Bir san‘at sahibine bir şeyi târif ederek istediği şekilde yaptırmak. Sipariş. (Bkz. İstisnâ‘)","kategori":"dil","osmanli":"اصمارلامه"},{"kelime":"ISMET (İsmet)","anlam":"Masumluk; günah işlememe ve günahtan korunmuş olma mânâsına peygamberlerin sıfatı.","kategori":"akaid","osmanli":"عصمت"},{"kelime":"İŞMOİL (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi açıkça geçmemekle beraber, Tâlût kıssasında kendisine işaret olunan Benî İsrâil peygamberlerinden.","kategori":"dil","misal":"İşmoil aleyhisselâm Tâlût’u İsrâiloğullarına hükümdâr tayin edip vefât etti. (İbnü’l-Esîr, Taberî, Mirhond)","osmanli":"اشموئيل"},{"kelime":"İSNÂ AŞERİYYE","anlam":"Halîfeliğin Hazret-i Ali ile onun soyundan gelen oniki İmâma (eimme-i isnâ aşer‘e) ait olduğuna inanan; inanç ve fıkıh hususunda bu İmâmlardan Ca‘fer-i Sâdık’tan geldiğini kabul ettikleri rivâyetleri esas alan Şiî fırkası.","kategori":"dil","misal":"İmâmiyye. Ca‘feriyye. İsnâ aşer, Arabca ‘on iki’ demektir. İsnâ aşeriyye fırkası, imâmlığın sâdece on iki imâma âit olduğuna, son imâmın İmâm-ı Mehdî olduğuna ve bunun hâlen sağ olduğuna, kıyâmetten önce ortaya çıkarak zulümle dolmuş olan dünyayı adâletle düzelteceğine inanırlar. Bunu bir inanç esâsı olarak kabul ederler. İsnâ aşeriyye fırkasına göre, mutlak olarak temiz toprağa secde etmek vâcibdir. Halıya, kilime,…","osmanli":"عشريه اثنا"},{"kelime":"İSNÂD","anlam":"1.Dayandırma, sened gösterme. 2.Söylediği sözü bir başkasına dayandırmak, bir şeyi, birisi için yaptı demek. 3.Hadîs-i şerîf metninin sırasıyla kimler tarafından nakl edile geldiğini bildirme.","kategori":"hadis","misal":"Benden işittiğiniz şeyleri rivâyet ediniz. Ancak hakkı söyleyiniz. Kim benim söylemediğimi bana isnâd ederse, onun için Cehennem’de bir ev binâ edilir ve o kimse, o evin içine tıkılır. (Hadîs-i şerîfMüsnedü Ahmed) Bir kimseye küfür isnâd edildiğinde eğer o kimse kâfir değilse, küfür isnâd edenin kendisi kâfir olur. (İbni Âbidîn)","osmanli":"اسناد"},{"kelime":"İSPİRTO","anlam":"Esas itibariyle şaraptan imbiklenerek elde edilen ve içilmesi haram olan sıvı.","kategori":"fikih","misal":"Etil alkol.","osmanli":"اسﭙيرطو"},{"kelime":"İSRÂ","anlam":"1.Gece yürüyüşü, geceleyin yaya veya binekli olarak yapılan yürüyüş. 2.Hazret-i Peygamber’in Mi‘rac gecesi gece Burak isimli bir binitle Mekke-i Mükerreme’den Kudüs’teki Beyt-i Makdis’e götürülmesi. Kulu (Muhammed aleyhisselâmı) bir gece Mescid-i Haram’dan, kendisine bir takım âyetlerimizi göstermek üzere, çevresini mü-barek kıldığımız Mescid-i Aksâ’ya isrâ eden (yürüten, götüren) Allahü teâlânın şânı yü-cedir. (İsrâ sûresi: 1)","kategori":"akaid","osmanli":"اسراء"},{"kelime":"İSRÂ SûRESİ","anlam":"Kur’ân-ı kerîmin on yedinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Yüz on bir âyet-i kerîmedir. Resûlullah aleyhisselâmın mîrâc (göklere çıkarılma) mûcizesinin geceleyin Mekke’den Kudüs’e kadar olan kısmı bu sûrenin birinci âyetinde anlatıldığı için sûreye İsrâ adı verilmiştir. İsrâ, gece yolculuğu demektir. Sûreye ‘Sübhân’ ve ‘Benû İsrâîl’ sûresi de denir. İsrâ sûresindeki belli başlı mevzular mîrâc mûcizesi, Benî İsrâil’in Rablerine nankörlükleri sebebiyle ba…","osmanli":"سى سوره اسراء"},{"kelime":"İSRÂF","anlam":"Gereksiz yere harcama, sarf etme.","kategori":"muamelat","misal":"Ekini hasad ettiğiniz zaman fakirlerin hakkını verin ve isrâf etmeyin. Allahü teâlâ isrâf edenleri elbette sevmez. (En‘âm sûresi: 141) İstediğini ye, istediğini giyin! İnsanı yanlış yola götüren, isrâf ve tekebbürdür (büyüklenmedir). (Hadîs-i şerîfBuhârî) İsrâf, malı telef etmek, faydasız hâle getirmek, dine ve dünyanın mübâh olan işlerine faydalı olmayacak şekilde sarf etmektir. Malı denize, kuyuya, ateşe ve elden…","osmanli":"اسراف"},{"kelime":"İSRÂFİL (aleyhisselâm)","anlam":"Dört bü-","kategori":"dil","misal":"yük melekten biri. Kıyâmet kopacağı vakit sûr denilen boruya üfürmekle vazifeli olan melek. İsrâfil aleyhisselâm Sûr’a iki defâ üfürecektir. Birincisinde Allahü teâlâdan başka her diri ölecektir. İkincisinde hepsi tekrar dirilecektir. (İtikadnâme) İsrâfil aleyhisselâm Sûr’a üfürünce Sûr’dan büyük bir ses çıkacak ve yedi kat göklere ve yerin her tarafına ulaşacaktır. İşitenlerin hepsi yerde olsun göklerde olsun ölece…","osmanli":"اسرافيل"},{"kelime":"İSRÂİL","anlam":"“Allahü teâlânın kulu” veya “Gece yürüyen” mânâsına Yâkûb aleyhisselâmın adı.","kategori":"akaid","misal":"Tevrat indirilmeden önce, İsrâil’in kendisine haram kıldığı şeylerden başka yiyeceğin her türlüsü İsrâiloğulları için helâl idi. De ki, eğer doğru sözlü iseniz, o zaman Tevrat’ı getirip onu okuyun. (Âl-i İmrân sûresi: 93) İbrâhim aleyhisselâmın vefâtından sonra, oğlu İshâk aleyhisselâm, ondan sonra oğlu Yâkûb aleyhisselâm peygamber oldular. Yâkûb aleyhisselâmın bir ismi de İsrâil olduğundan. On iki oğlundan gelenler…","osmanli":"اسرائيل"},{"kelime":"İŞRÂK","anlam":"1.Güneşin doğması. 2.Işıklanma, parlama. 3.Güneşli yere konma. 4.Kalbe mânâların doğması, akıl yürütme veya başka bir vâsıta olmadan bilginin doğ-rudan içe doğması.","kategori":"dil","misal":"(A. Şark’tan)","osmanli":"اشراق"},{"kelime":"İşrâk Vakti","anlam":"Güneşin ufuk hattın-dan beş derece (bir mızrak boyu) yükselme-sinden, yani güneşin çıplak gözle bakılama-yacak kadar parlamasından itibâren başlayan zaman, bayram namazı vakti.","kategori":"ibadet","misal":"Güneşin doğmaya başlamasından işrâk vak-tine kadar (takriben 40 dakika kadar) her türlü namazı kılmak tahrîmen mekrûhtur. (Mec-ma‘ü’l-Bahreyn) Ramazân ve Kurban bayramlarının birinci gün-lerinde, güneş doğduktan ve farz olsun, nâfile olsun namaz kılmak mekrûh olan vakit çıktık-tan sonra, yani işrâk vaktinde, iki rek‘at bayram namazı kılmak, erkeklere vâcibdir. (İbni Âbidîn)","osmanli":"وقتى اشراق"},{"kelime":"İŞRÂKIYYûN","anlam":"İşrâkıyye felsefe ekolünün mensubları.","kategori":"dil","osmanli":"اشراقيون"},{"kelime":"İSRÂR","anlam":"1.Sır tutma. 2.Gizleme, ses-siz, gizli okuma.","kategori":"dil","misal":"Sabah, akşam ve yatsı namazarında İmâmın kırâatı izhâr; öğle ve ikindi namazında, isrâr etmesi vâcibdir. (Ni’met-i İslâm)","osmanli":"اسرار"},{"kelime":"IŞRET (İşret)","anlam":"1.Yaşama, geçinme. 2.Tasavvufta insanlar arasına karışma.","kategori":"tasavvuf","misal":"Işrette olan tasavvufçular da geriye dönmüştürler. Fakat tam dönmüş değillerdir. Bâtınları yukarıya bakmaktadır. Zâhirleri yani bedenleri halk arasında, bâtınları ise Hak teâlâ iledir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اشرت"},{"kelime":"İSTAVROZ","anlam":"Hristiyanlığın alâmeti, işâreti sayılan şekil ve bu şekilde yapılmış haç.","kategori":"dil","misal":"İstavroz. Çelipa. (Bkz. Haç)","osmanli":"استاوروز"},{"kelime":"İSTİ‘DÂD","anlam":"Bir şeyin elde edilmesine olan yatkınlık, doğuştan gelen kâbiliyet, kav-rayış, anlayış.","kategori":"dil","misal":"İsti‘dâd Allahü teâlânın ihsânıdır. Hazret-i Ebû Bekr isti‘dâdı sebebi ile Peygamberimize sallal-lahü aleyhi ve sellem bir şey sormadan inanı-verdi. Ebû Cehl’de isti‘dâd kuvveti bulunmadı-ğından, o kadar alâmet ve mûcizeler gördüğü hâlde, Peygamberliğe inanmak saadeti ile şe-reflenemedi. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"استعداد"},{"kelime":"İSTİ‘MÂL","anlam":"Kullanma.","kategori":"dil","osmanli":"استعمال"},{"kelime":"İŞTİBÂK","anlam":"1.Örülme, örgülenme, birbirine geçme. 2.Zâhir olma. 3.Perişanlık, dağınıklık. 4.Güneşin gurubundan sonra semâda yıldızların kum tanesi gibi görünmesi.","kategori":"ibadet","osmanli":"اشتباك"},{"kelime":"İSTİBDÂD","anlam":"1.Kendi başına olma, müstakil bulunma. 2.Keyfî ve baskıcı idare.","kategori":"osmanli","misal":"Despotizm.","osmanli":"استبداد"},{"kelime":"İSTİBDÂL","anlam":"1.Değiştirme, değiştirilme; bir şey verip yerine başka bir şey alma. 2.Harap olmuş vakıf binâsını satıp, se-meni ile başkasını alma.","kategori":"muamelat","osmanli":"استبدال"},{"kelime":"İSTİBRÂ","anlam":"1.Berî kılma; temizlenme. 2.Erkeklerin küçük abdesti yaptıktan sonra yürüyerek, öksürerek veya sol tarafa yatarak, idrar yolunda damlalar bırakmaması. 3.Nikâh-lanan câriyeye, hâmile olup olmadığı anlaşıl-ması için bir temizlik müddeti geçip tekrar hayız görünceye kadar yaklaşmama.","kategori":"ibadet","osmanli":"استبراء"},{"kelime":"İSTİBSÂR","anlam":"Basiretli olma.","kategori":"dil","osmanli":"استبصار"},{"kelime":"İSTİDLÂL","anlam":"Delil getirme, bir delile dayanarak netice çıkarma; delil ile anlama; eserden müessire veya müessirden esere gitme. İstidlâl ile kazanılan bilgiler kesbîdir yani çalış-mak, sebeblere yapışmak, düşünmek, aklı kul-lanmak sûretiyle elde edilir. Meselâ; duman gö-rülen yerde ateşin bulunduğunun veya ateşin bulunduğu yerde dumanın da bulunacağının bilinmesi istidlâl yoluyla bilmektir. (Mevâkıf) Fen bilgilerini iyi öğrenen, aklı başında bir kimse, yalnız düşünmekle, Allahü teâlânın var olduğunu anlar. Îmâna kavuşur. Eseri görerek müessirin, yani eseri yapanın varlığını anla-mamak ahmaklık olur. Her insanın böyle dü-şünerek îmâna gelmesini dinimiz emretmekte-dir. Selef-i sâlihîn (ilk iki asrın Müslümanları),","kategori":"akaid","misal":"bu emri sözbirliği ile bildirmişlerdir. Hicretin 400 senesinden sonra çıkan bazı sapık fırka-dakiler, nazar (inceleme) ve istidlâl etmeye lü-zum yoktur dediler ise de bunların sözlerinin kıymeti yoktur. (Berîka)","osmanli":"استدلال"},{"kelime":"İSTİDRÂC","anlam":"1.Derece derece ilerleme. 2.Hakkı olmadığı hâlde talihi sayesinde işi yo-lunda gitme; kötü işte muvaffak olma. 3.Kâ-fir ve fâsıklarda görülen ve onu derece derece felâkete sürükleyen hârikulâde hâl.","kategori":"dil","misal":"Bir kimse peygamberlere tâbi olmadan doğru yolda yürümek isterse, muhakkak eğri yola sa-par. Eğer eline bir şeyler geçerse, istidrâcdır. Sonu zarar ve ziyândır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"استدراج"},{"kelime":"İSTÎFÂ","anlam":"1.Alacağını tamamen alma. 2.Ruhunu kabzetme.","kategori":"dil","osmanli":"استيفاء"},{"kelime":"İSTİFÂDE","anlam":"1.Fâidelenme, kazanma, fayda bulma. 2.Bir şey öğrenme; bilgisini genişletme.","kategori":"akaid","osmanli":"استفاده"},{"kelime":"İŞTİGÂL","anlam":"Meşgul olma, bir şeyle uğ-raşma.","kategori":"dil","misal":"Resûlullah “sallallahü aleyhi ve sellem,” Bi‘set-ten önce, zikr-i kalbîye iştigâl üzere idi. (Kalb ile zikr üzere idi.). (Mektûbât-ı Ma‘sûmiyye)","osmanli":"اشتغال"},{"kelime":"İSTİGÂSE","anlam":"Yardım, imdat, meded isteme; aracı koyma; Allahü teâlâdan bir şey isterken, sevdiği kullarını aracı koyma.","kategori":"akaid","misal":"O vakit Rabbinizden istigâsede bulunuyordunuz da; O size; “Gerçekten ben arka arkaya bin melâike ile imdâd ediyorum” diye duânızı kabul buyurmuştu. (Enfâl sûresi: 9) Kıyâmet günü insanlar, önce Âdem ile, sonra Mûsâ ile ve sonra Muhammed (aleyhimüsselâm) ile istigâse ederler. (Hadîs-i şerîf- Buhârî) İstigâse olunan, yardım istenilen yalnız Allahü teâlâdır. Ancak peygamberler, velîler, sâlih kullar ve benzerleri vâsıt…","osmanli":"استغاثه"},{"kelime":"İSTİĞFÂR","anlam":"1.Allahü teâlâdan gufran (mağfiret, bağışlanma) istemek; tövbe etmek. 2.“Estağfirullah” demek.","kategori":"akaid","misal":"Biri günah işler veya kendine zulmeder, sonra pişman olup, Allahü teâlâya istiğfârda bulunursa, Allahü teâlâyı çok merhametli, afv ve mağfiret edici bulur. (Nisâ sûresi: 109) Allahü teâlâ seherde istiğfâr edenlerin sesini sever. (Hadîs-i şerîfDeylemî) Fisebilillâh kılıç kuşanana melekler istiğfâr ederler. (Hadîs-i şerîfHatîb)","osmanli":"استغفار","alternatif":["istigfar"]},{"kelime":"İŞTİHÂ","anlam":"1.Meyil, istek. 2.İştah, yemek yeme isteği.","kategori":"dil","misal":"(A. Şehvet’ten)","osmanli":"اشتهاء"},{"kelime":"İŞTİHÂR","anlam":"Şöhret bulma, tanınma.","kategori":"dil","osmanli":"اشتهار"},{"kelime":"İSTİHÂRE","anlam":"1.Hayır isteme; hayra yorma, tefeül etme. 2.Hayrette kalma; hayran olma. 3.Bir işin hayırlı olup olmayacağını rü-yada anlamak için abdest alıp iki rekat namaz kılarak ve mahsus duâsını okuyarak yatmak. İstişâre eden pişman olmaz, istihâre eden zarar etmez. (Hadîs-i şerîf-Taberânî) Yola çıkarken vâsıtayı satın mı almalı, yoksa kirâlamalı mı; karadan mı gitmeli denizden mi; filân kimse ile arkadaş olmalı mı olmamalı mı diye istihâre etmelidir. Çünki vâcib ile mekrûhta istihârenin yeri yoktur. (İbni Âbidîn) Her mü’minin istihâre yapması sünnettir. İs-tihâre yedi gece yapılır. Rüyâda beyaz veya ye-şil görmek hayra; siyâh veya kırmızı görmek şerre alâmettir. İstihâreden sonra kalbinde o işi yapma arzusu artmışsa, istihâre müsbettir. (Seâdet-i Ebediyye)","kategori":"hadis","osmanli":"استخاره"},{"kelime":"İSTİHÂZA (İstihâda)","anlam":"Kadınlarda âdet hayz ve nifâs dışında gelen ve oruç ile namaza mânî olmayan kan.","kategori":"ibadet","misal":"Hanefî mezhebinde, üç günden (72 saatten) beş dakika bile az olan ve yeni başlayan için on günden çok sürünce, onuncu günden sonra ve yeni olmayanlarda âdetten çok olup, on günü de aşınca, âdetten sonraki günlerde gelmiş olan ve hâmile ve âyise (ihtiyar) kadından, dokuz yaşından küçük kızlardan gelen kan hayz olmaz. Buna istihâza veya fâsid kan denir. İstihâza günlerinde bulunan bir kadın, idrarını tutamayan ve sık…","osmanli":"استحاضه"},{"kelime":"İSTİHLÂK","anlam":"Helâk etme; harcayarak tüketme; tükenme; tüketim.","kategori":"dil","osmanli":"استهلاك"},{"kelime":"İSTİHSÂL","anlam":"2.Elde etme, ele ge-çirme, ele geçirilme.","kategori":"dil","misal":"l.Hâsıl etme, meydana getirme, üretme; üretim.","osmanli":"استحصال"},{"kelime":"İSTİHSÂN","anlam":"1.Güzel bulma, gü-zel görme. 2.İslâm hukukunun kaynakların-dan biri, açık (celî) kıyasın şer‘î meseleyi çöz-mediği zaman, kapalı (hafî) kıyasa müracaat etme veya zaruret, örf yâhud maslahat sebe-biyle umumî kâidekâideyi terk edip istisnaî hükme varma. Kıyas-ı celîye ve küllî kâideye göre mevcut ol-mayan, yok olan bir şey üzerine akid yapmak bâtıldır, hükümsüzdür. Bu sebeble istisnâ‘ yani bir sanat sahibine sipâriş vererek, târif ederek bir şey meselâ bir ayakkabı yaptırmak üzere akid yapılamaz. Çünki, ayakkabı akid esnâ-sında henüz mevcut değildir, yoktur. Fakat bu türlü akde göre muâmele, iş yaptırmak her de-virde yapılageldiğinden ve bu hususta icmâ‘ (müctehid âlimlerin sözbirliği) meydana geldi-ğinden, kıyas-ı celî terk edilmiş, böyle bir muâ-melenin câiz olduğuna, olabileceğine hükmo-lunmuştur. (Serahsî) Zevcin, zevcesi için de kendi mülkünden onun izni (haberi) olmadan fıtrasını vermesi istihsâ-nen câizdir. (İbni Âbidîn)","kategori":"fikih","osmanli":"استحسان"},{"kelime":"İSTİHZÂ","anlam":"Biriyle eğlenmek, alay etmek. Münâfıklar (hakka inanmadıkları hâlde inan-mış görünenler) mü’minler ile karşılaştıkla-rında, biz de sizin gibi mü’minleriz derler. Kendilerini saptıran, insan şeytânları olan reisleri (veya dostları) ile yalnız kaldıkla-rında; “Biz sizin dininiz üzereyiz. Biz ancak mü’minlerle istihzâ ediyoruz” derler. Allahü teâlâ onların bu istihzâlarının cezâsını ve-rir. (Bakara sûresi: 14-15) (Dünyada) insan-larla istihzâ eden birine, âhirette Cennet’ten bir kapı açılır ve; “Buyur gel” denir. O kişi sıkıntılı ve telaşlı olarak gelir. Fakat kapı kapanır. Sonra başka bir kapı açılır. O kişi yine sıkıntılı ve üzgün bir hâlde bu kapıya gelir, o da kapanır. Bu hâl o kadar devam eder ki, artık o kişiye “gel” diye seslendik-leri hâlde gidemez hâle gelir. (Hadîs-i şerîf-İbnü Ebiddünyâ)","kategori":"hadis","misal":"İstihzâ, insanın vekârını (ağır başlılığını) kay-bettirir. Yüzünden hayâyı (utanmayı) kaldırır, karşı tarafta kin ve nefret uyandırır. Dostluğun tadını kaçırır. İnsanı Allahü teâlâdan uzaklaş-tırır. Hâtıraları öldürür. Kusurları çoğaltır. Gü-nahları açığa çıkartır. (Kimyâ-i Seâdet)","osmanli":"استهزاء"},{"kelime":"İŞTİKÂK","anlam":"1.Türeme. 2.Çatallaşma. 3.Yarılmış şeyin bir şıkkını alma. 4.Bir kök-ten gelen kelimelerin birbirleriyle olan alâ-kası, etimoloji. 5.Aynı kökten gelmiş birkaç kelimeyi bir araya getirme sanatı.","kategori":"dil","osmanli":"اشتقاق"},{"kelime":"İSTİKBÂL","anlam":"1.Gelecek zaman, âtî. 2.Karşılama. 3.Yönelme.","kategori":"dil","misal":"Alırım, satarım gibi müdâri fiil söylenince hâl, yani şimdi mânâsı düşünülürse câiz olup, is-tikbâl mânâsı düşünülür veya mânâ düşünül-mezse câiz olmaz. (İbni Âbidîn)","osmanli":"استقبال"},{"kelime":"İSTİKBÂL-İ KIBLE","anlam":"Kıbleye yönelme, namazda Mekke-i Mükerreme’deki Kâbe-i Muazzama’ya doğru durma.","kategori":"ibadet","misal":"Namaz kılarken istikbâl-i kıble farzdır. Yani namaz, Kâbe-i Muazzama tarafına dönerek kılınır. Namaz, Allah için kılınır. Secde yalnız Allah için yapılır. Kâbe’ye karşı yapılır. Kâbe için yapılmaz. (İbni Âbidîn)","osmanli":"قبله استقبال"},{"kelime":"İSTİKLÂL","anlam":"1.Az bulma, kâfi görmeme. 2.Kendi başına olma, kimseye bağlı bulun-mama, rey sahibi olup keyfî iş görme.","kategori":"dil","misal":"(A. Yüklenip götürmek mânâ-sına kall’den)","osmanli":"استقلال"},{"kelime":"İSTİKRÂR","anlam":"1.Karar bulma, yerleşme. 2.İyice belli olma.","kategori":"dil","misal":"Nefs mutmainne olunca, dimâgdan göğüs tah-tına istikrâr peydâ eder (yerleşir). (Mektûbât-ı Ma‘sûmiyye)","osmanli":"استقرار"},{"kelime":"İSTÎLÂ","anlam":"1.Kaplama, yayılma. 2.Bir yeri kuvvet kullanarak ele geçirme. 3.İslâm devlet reisliği (halîfelik) makamını ele geçirme. 4.Sahipsiz menkul veya gayrimenkulü mülk edinme.","kategori":"muamelat","osmanli":"استيلاء"},{"kelime":"İSTÎLÂD","anlam":"Câriyesini ümmü veled kılma, câriyesinden çocuk sahibi olma.","kategori":"dil","osmanli":"استيلاد"},{"kelime":"ISTILÂH","anlam":"Bir ilim ve fende bir lafzın lügat mânâsından çıkarılarak ittifakla başka bir mânâda kullanılması.","kategori":"dil","misal":"Istılahta, kelimenin iki mânâsı arasında irtibat bulunabilir veya bulunmayabilir. Savm, tutmak mânâsına gelmekle beraber, şeriat ilminde oruç için kullanılmaktadır. Dâbbe, yerde yürüyen her hayvan mânâsına gelmekle beraber, örf bunu at, katır, eşek gibi dört ayakları hayvanlara hasretmektedir.","osmanli":"اصطلاح"},{"kelime":"İSTİLÂM","anlam":"1.Öpme, el sürme; selâm-lama. 2.Kâbe’yi tavafa başlarken veya tavaf sı-rasında Hacerü’l-Esved’e el sürmek veya el işa-retiyle öper gibi yapma.","kategori":"ibadet","misal":"Hac veya umrede tavaf esnâsında Hacerü’l-Es-ved önüne gelindiğinde, onu öpmek, bu müm-kün olmazsa elleri namaza girer gibi kaldırıp tekbir, tehlîl getirerek (Allahü ekber, lâilâhe il-lallahü vallahü ekber diyerek) onu selâmlamak ve avucunun içini öpmek, haccın sünnetlerin-dendir. (İbni Âbidîn)","osmanli":"استلام"},{"kelime":"İSTİMRÂR","anlam":"1.Devam etme, sürüp gitme. 2.Hayız veya nifâs hâ-linde gelen kanın azami müddeti geçerek de-vam etmesi.","kategori":"dil","misal":"(A. Mürûr’dan) Bir kadından; on beş gün içinde hiç temiz gün olmadan, kan istimrâr ederse, âdetine göre hesâb olunur. Yani, âdetinden sonra başlaya-rak bir evvelki ay içindeki temizlik günü ka-dar temizlik ve sonra âdeti kadar hayz kabul edilir. Âdeti beş gün kan, yirmi beş gün temiz-lik olan kadında kan istimrâr ederse, ilk görü-len beş gün kan hayz, peşinden gelen yirmi beş gün temiz kabul edilir. Kızda ilk görülen kan istimrâr ederse, ilk on gün hayz, sonra yirmi gün temiz kabul edilir. (İbni Âbidîn)","osmanli":"استمرار"},{"kelime":"İSTİNÂD","anlam":"1.Dayanma. 2.Güvenme, i‘timâd. 3.Sened, delil, hüccet sayma.","kategori":"hadis","osmanli":"استناد"},{"kelime":"İSTİNBÂT","anlam":"1.Bir söz veya işteki gizli mânâyı ortaya koymak. 2.Kur’ân-ı kerîmde ve hadîs-i şerîflerde açıkça bildiril-memiş hükümleri ictihâd yoluyla meydana çıkarmak.","kategori":"dil","misal":"(A. Nebat’dan) Allahü teâlânın kitabını (Kur’ân-ı kerîmi) beyân eden Resûlullah efendimizden başkası olmadığı gibi, Kur’ân-ı kerîm ve hadîs-i şerîflerden dinî hükümleri istinbât edenler de ancak ümmetin büyük imâmlarıdır. (Şevâhidü’l-Hak)","osmanli":"استنباط"},{"kelime":"İSTİNCÂ’","anlam":"Vücuddan necâset çıkınca bu yerleri yıkama, temizleme.","kategori":"fikih","misal":"Başkasının yanında avret yerini açmadan su ile istincâ yapamayan kimse, pislik fazla olsa bile su ile istincâdan vazgeçer. Avret yerini açmaz. Namazı öyle kılar. Açarsa fâsık (günahkâr) olur. Haram işlemiş olur. Tenhâ bir yer bulunca, su ile istincâ yapar ve namazı iâde eder. (İbni Âbidîn)","osmanli":"استنجاء"},{"kelime":"İSTİNŞÂK","anlam":"1.Abdest ve gusül alırken buruna su çekme. 2.Şiddetle koklama.","kategori":"ibadet","misal":"On şey sünnettir: Bıyığı kısaltmak, sakalı uzatmak, misvâk kullanmak, mazmaza (abdestte ağıza su almak), istinşâk, tırnak kesmek, ayak parmaklarını yıkamak, koltuk altını temizlemek, kasıkları temizlemek, su ile istincâ. (Hadîs-i şerîfMüslim)","osmanli":"استنشاق"},{"kelime":"İSTİRÂHAT","anlam":"1.Ric‘at etme, geri dönme, dönmek isteme. 2.Belâ ve musîbet zamanında veya kötü bir haber duyunca Bakara sûresi’nin 156.âyet-i kerîmesinde geçen ve “Muhakkak ki Allahü teâlânın kullarıyız, vefât ettikten sonra diriltilme ve neşr ile yine O’na döne-ceğiz” meâlindeki “İnnâ lillahi ve innâ ileyhi” râci‘ûn sözünü okuyarak ilahî iradeye boyun eğdiğini göstermek. (Bkz. İnnâ Lillâh ve İnnâ İleyhi Râci‘ûn)","kategori":"dil","misal":"Rahat etme, dinlenme. İSTİRCÂ‘: استرجاع (A)","osmanli":"استراحت"},{"kelime":"İŞTİRÂK","anlam":"Şirket olma, ortaklık.","kategori":"muamelat","osmanli":"اشتراك"},{"kelime":"İSTİRHÂM","anlam":"1.Merhamet dileme; yalvarma, yalvarış. 2.İsteme, ricâ etme.","kategori":"dil","osmanli":"استرحام"},{"kelime":"İSTİŞFÂ","anlam":"1.Şifâ isteme.","kategori":"dil","osmanli":"استشفاء"},{"kelime":"İSTİŞFÂ","anlam":"1.Yardım isteme. 2.Aracı, şefaatçi yapma.","kategori":"dil","misal":"(Bkz. Şefâat) “Yâ Rabbî! Sana senin Peygamberin ile istişfâ’ ediyorum. Ey insanlara rahmet olan Peygam-ber! Rabbin huzurunda bana şefâat et!” de-yince, Cenâb-ı Hak, yapılan duâyı kabul bu-yurur. (Mevâhibü’l-Ledünniyye)","osmanli":"استشفاع"},{"kelime":"İSTİSKÂ","anlam":"1.Suya şiddetle ihtiyaç hissetme, susama. 2.Kıtlık, kuraklık vaktinde, sahrâya çıkıp, yağmur yağdırması için Allahü teâlâya duâ etme, yağmur duâsına çıkmak (Bkz. Resûlullah efendimiz, Eshâb-ı kirâm ve asırlardan beri İslâm âlimleri, yağmur duâsı yaptılar. İstiskâ için; ara vermeden üç gün çıkmak, eski, yamalı giymek, çıkmadan sadaka vermek, üç gün oruç tutmak, çok tövbe ve istiğfâr etmek, kul haklarını ödemek, hayvanları da çıkarıp, yavrularından ayrı bulundurmak, ihtiyârları ve çocukları da çıkarmak sünnettir. İstiskâ için hamd ile, günahlara pişman olup tövbe ederek duâ ya…","kategori":"akaid","osmanli":"استسقاء"},{"kelime":"İSTİSNÂ‘","anlam":"1.Ayırma, ayrı tutma, kâidenin dışında tutma. 2.İnşâallah (Allah isterse) demek.","kategori":"akaid","misal":"(A. Sünâ’dan) Yemîn, talâk, ıtk, icab, kabul gibi bir sözü söy-lerken istisnâ’ yaparsa, bu söz muteber olmaz. (İbni Âbidîn)","osmanli":"استثناء"},{"kelime":"İSTİSNÂ’","anlam":"(A. Sınâ‘dan) Ismarlama; terzi gibi bir sanat sahibinden muayyen bir işin, muayyen hususiyetlerde yapılmasını istemek. İstisnâ‘da malzeme sanat sahibine âittir. Malze-meyi müşteri verirse işçilik olur. (İbni Âbidîn)","kategori":"dil","osmanli":"استصناع"},{"kelime":"İSTİVÂ","anlam":"1.Müsâvi, eşit olma. 2.İtidal, istikamet ve karar üzere olma. 3.Kaba kuş-luk zamanı. 4.Yükselme; üstün olma. 5.İstilâ etme, kaplama.","kategori":"dil","misal":"Sonra Rabbiniz arş üzerine istivâ etti. (A‘râf sûresi: 54) Bu âyet-i kerîme müteşâbihtir. Selef-i sâlihîn, müteşâbih âyet-i kerîmelerin mânâla-rını Allahü teâlâya havâle etmişlerdir. Nitekim birisi gelip, Mâlik bin Enes’e radıyallahü anh Allahü teâlânın istivâsı hakkında sorunca, ba-şını eğdi bir müddet sonra onda ter görüldü ve: “İstivâ ma‘lûmdur, bilinir. Keyfiyyeti (nasıl ol-duğu) meçhuldür, bilinmez. Ona îmân etmek gerekir. Ondan sormak bid‘attir, dalâlettir, sa-pıklıktır. Zannediyorum sen bid‘at ehlisin” dedi ve emrederek o şahsı oradan uzaklaştırdı. Fakat sonra gelen Ehl-i sünnet âlimleri, zamanların-daki bid‘at fırkalarının böyle âyet-i kerîmeleri yanlış izahlarına cevap vermek zarûreti ortaya çıkınca böyle âyet-i kerîmeleri te’vîl ihtiyâcını duydular. Dinin esaslarına uygun olarak izah ettiler. İstivâyı da Allahü teâlânın hâkimiyeti gibi uygun bir mânâ ile te’vîl ettiler. Çünki Al-lahü teâlâ, bir mekânda bulunmaktan, orada yerleşmekten münezzehdir. (Kurtubî)","osmanli":"استواء"},{"kelime":"İŞTİYÂK","anlam":"Şevklenme, göreceği gelme, özleme, hasret.","kategori":"dil","osmanli":"اشتياق"},{"kelime":"İSYÂN","anlam":"İtaatsizlik; karşı gelme; baş kaldırma, âsî olma.","kategori":"dil","misal":"Fakat Allahü teâlâ size îmânı sevdirmiş ve onu kalblerinize zînet yapmıştır. Küfrü, fıskı ve isyânı da size çirkin göstermiştir. İşte doğru yolda olanlar bunlardır. (Hucurât sûresi: 7) Âdemoğlu secde âyetini okuyup secde ederse, şeytân ağlayarak uzaklaşır ve; “Vay hâlime; Âdemoğlu secde etmeye me’mur oldu ve he-men secde etti. Bu sebeble Cennet onundur. Ben de secde ile emrolundum; ama ben is-yân ettim. Bu sebeble Cehennem de benim-dir” der. (Hadîs-i şerîf-Müslim)","osmanli":"عصيان"},{"kelime":"ITÂB (İtâb)","anlam":"1.Azarlamak, azar. 2.İşlenen bazı hafif günahlar için Cehennem ateşi yerine tatbik edilecek ilâhî azap.","kategori":"akaid","osmanli":"عتاب"},{"kelime":"İTHÂM","anlam":"Töhmetlendirme, suçlandırma, birine bir kabahat yükleme.","kategori":"dil","osmanli":"اتهام"},{"kelime":"İTKÂN","anlam":"1.Bir şeyi sağlam yapma. 2.Bir şeyi delilleri ve hakikati ile bilme. 3.Küllî kâi-deyi, cüz’î hâdiseye tatbik etme.","kategori":"hadis","osmanli":"اتقان"},{"kelime":"İTMÂM","anlam":"Tamamlama, bitirme, tamam etme, edilme.","kategori":"dil","osmanli":"اتمام"},{"kelime":"İTMÎNÂN","anlam":"1.Emin olma. 2.Birine inanma. 3.Huzur, sükûn ve rahata kavuşma.","kategori":"dil","misal":"Biliniz ki, kalbler yalnız Allahü teâlâyı zik-retmekle itmînân bulur. (Ra‘d sûresi: 30)","osmanli":"اطمينان"},{"kelime":"İTTİBÂ‘","anlam":"Tâbi‘ olma, bağlanma, uyma, arkasından gitme; itaat etme.","kategori":"dil","misal":"Ey sevgili Peygamberim! Onlara de ki; eğer Allahü teâlâyı seviyorsanız ve Allahü teâlâ-nın da sizi sevmesini istiyorsanız, bana it-tibâ‘ ediniz! Allahü teâlâ, bana ittibâ‘ eden-leri sever. (Âl-i İmrân sûresi: 31) Peygamber efendimize ittibâ‘nın ufak bir zer-resi, bütün dünya lezzetlerinden ve bütün âhi-ret nîmetlerinden daha üstündür. Hakîkî üstün-lük; O’nun sünnet-i seniyyesine ittibâ‘ etmektir. (Mektûbât-ı İmâm-ı Rabbânî) Dört hak mezhebten birine ittibâ‘ etmeyen kimse, Ehl-i sünnetten ayrılmış olur. (Tahtâvî)","osmanli":"اتباع"},{"kelime":"İTTİHÂD","anlam":"1.Vahdet etme, birleşme, bir olma. 2.Aynı fikirde olma.","kategori":"dil","misal":"Allahü teâlâ hiçbir şeyle ittihâd etmez. Hiç-bir şey de O’nunla ittihâd etmez. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اتحاد"},{"kelime":"İTTİHÂM","anlam":"Töhmet altında olma, suçlu olma; suçlandırma.","kategori":"dil","osmanli":"اتهام"},{"kelime":"İTTİKÂ","anlam":"Takvâ sahibi olma, Allahü teâlâdan korkma, haramlardan sakınma.","kategori":"akaid","misal":"Küçük hatâlar müstesnâ günahların büyüklerinden ve fuhşiyattan kaçınanlara gelince; muhakkak Rabbin mağfireti bol olandır. O, sizi daha topraktan yarattığı zaman ve annelerinizin karnında ceninler iken sizi (bütün hâllerinizi) en iyi bilendir. O hâlde kendinizi temize çıkarmayın. O, ittikâ edenleri en iyi bilendir. (Necm sûresi: 32) Ey Âdemoğulları! Size aranızdan âyetlerimi anlatacak peygamberler gelir de kim ittik…","osmanli":"اتقاء"},{"kelime":"İTTİSÂL","anlam":"1.Bitişik olma. 2.Hadîs-i şerîfin bütün râvîlerinin bildirilmesi, senedindeki râvîler zincirinde hiç kopukluk olmaması.","kategori":"hadis","osmanli":"اتصال"},{"kelime":"İYÂL","anlam":"(Bkz. Iyâl)","kategori":"dil","osmanli":"عيال"},{"kelime":"IYÂL (Ayâl)","anlam":"1.Âileler, nafakası üzerine borç olanlar. 2.Zevceler.","kategori":"dil","misal":"Iyâl için yapılacak masraflar, yiyecek, giyecek ve ev olup, şehrin âdetine, piyasaya, akrabâ ve arkadaşlara göre ayarlanır. Zamana ve hâle göre değişir. Her memlekette başkadır. (İbni Âbidîn) Ehlü ıyâlin rızâ ve gönüllerini almak için, haram işleyerek âhiret azâbını ihtiyâr eden (tercîh eden) kimsenin bu yaptığı akla uygun değildir. (Mektûbât-ı İmâm-ı Rabbânî) Tek başıma olsam, şâha gedâya uymam, Virân olası hânede…","osmanli":"عيال"},{"kelime":"IYÂN","anlam":"Açık, âşikâr. (Bkz. Ayân)","kategori":"dil","osmanli":"عيان"},{"kelime":"Iyd-ı Edhâ","anlam":"Kurban bayramı. Zilhicce ayının onuncu, on birinci, on ikinci ve on üçüncü günleri.","kategori":"ibadet","misal":"Iyd-ı edhâda bayram namazına giderken “Allahü ekber Allahü ekber, lâ ilâhe illallahü vallahü ekber. Allahü ekber ve lillâhi’l-hamd” diye yüksek sesle Tekbîr-i teşrik getirmek, namazdan önce bir şey yimemek, namazdan sonra, önce kurban eti yemek sünnettir. (Halebî)","osmanli":"اضحى عيد"},{"kelime":"Iyd-ı Fıtr","anlam":"Ramazan bayramı. Şev-vâl ayının birinci günü. Iydü’l-fıtr. Bu günde oruç tutulmayıp iftar edildiği için bu ismi al-mıştır. Fıtr, oruç açmak demektir.","kategori":"ibadet","misal":"Sabahleyin câmi’e giderken bayram tekbîrlerini ıyd-ı fıtrda sessiz, ıyd-ı edhâda (kurban bay-ramında) açıktan, yüksek sesle söylemek sün-nettir. (Halebî)","osmanli":"فطر عيد"},{"kelime":"IYNE (Îne)","anlam":"Bir malı veresiye satıp, bunu aynı mecliste, bir müşteriden peşin ve ucuz satın almak.","kategori":"osmanli","misal":"Iyne satışında zengin on lira değerindeki malı, (krediye ihtiyacı olan) fakire meselâ oniki liraya veresiye satar. Fakir, malı alıp, başkasına, peşin on liraya satarak, on lira almış olur. Zengine oniki lira borçlu olur. İmâm-ı Ebû Yûsuf ’a göre kerahatsiz câizdir. İmâm-ı Muhammed’e göre câiz değildir. (İbni Âbidîn) İkinci semen ayn yani peşin olduğu için, böyle satışa, ıyne satışı denilmiştir. İki semen, önceden ka…","osmanli":"عينه"},{"kelime":"İZÂFÎ","anlam":"1.İzâfetle alâkalı. 2.Bağlı bu-lunduğu şey ile değişen, nisbî, rölatif.","kategori":"dil","misal":"Orta yol deyince, iki şey anlaşılır: Birisi, herke-sin anladığı gibi, bir şeyin tam ortasıdır. Dâire-nin merkezi, kutru böyledir. İkincisi, izâfî, tak-dîrî orta olmaktır. Yani belli bir şeyin ortasıdır. O şeyin ortası olduğu için, her şeyin ortası ol-mak lâzım gelmez. (Ahlâk-ı Alâî)","osmanli":"اضافى"},{"kelime":"ÎZÂH","anlam":"Vüzuha kavuşturma, açık an-latma, açıklama.","kategori":"dil","osmanli":"ايضاح"},{"kelime":"İZÂLE","anlam":"Zevâle erdirme, zâil etme, gi-derme, ortadan kaldırma, yok etme; kurtulma. Bir zarar kendi misliyle izâle olunamaz [taz-min edilir]. (Mecelle, m. 25)","kategori":"ibadet","misal":"Kadınların başlarındaki saçlarını, kazımakla veya kesmekle yâhud ilâc ile izâle, yani yok etmeleri tahrîmen mekrûhtur. (Eşbâh Şerhi)","osmanli":"ازاله"},{"kelime":"İZÂR","anlam":"1.Belden aşağıya mahsus örtü, peştamal, futa; kefenin baştan ayağa kadar olan ve genişliği bir metreyi bulan parçası; erkek ihrâmının belden aşağı sarılan kısmı. 2.İsmet, iffet. 3.Zevce.","kategori":"dil","misal":"Erkeğin kefeninin üç parça olması sünnettir: İzâr, kamîs (entârî gibi uzun gömlek) ve lifâfe (başı ve ayakları geçecek uzunlukta ve baş üstünden ve ayak altından uçları büzülüp bezle bağlanan parça). (Halebî)","osmanli":"ازار"},{"kelime":"İZDİVÂC","anlam":"Evlenme, birbirine eş olma. İZDİYÂD: ازدياد (A) Ziyadeleşme, artma, çoğalma. Tâlib-i izdiyâd olmak (artmasını istemek) mevcûda râzı olmamak değildir. (Mektûbât-ı","kategori":"dil","misal":"Ma‘sûmiyye)","osmanli":"ازدواج"},{"kelime":"İZHÂR","anlam":"1.Zâhir etme, açığa vurma, meydana çıkarma. 2.Yalandan gösteriş yapma. 3.Kıraatte hurûf-i halk denilen harflerden iki harfi birbirinden ayırarak ihfâsız, idgâmsız okuma, her harfi gunnesiz olarak kendi mah-recine göre çıkarma, iki harfin arasını ayırıp uzak tutma. İzhâr harfleri elif, he, ha, hı, ayn ve ğayn’dır. Tenvin ve sâkin nun bu harflerden önce gelirse, ızhâr olur. “Men âmene” gibi. Tenvin ve sâkin nun, vav ve ye harflerden önce gelir ve aynı ke-limede bulunursa yine “ızhâr” olur. “Kınvânün” gibi. Sakin mim, mim ve be harflerinin dışında bir harfin önüne gelirse yine “ızhâr” olur. “Em lehüm” gibi. (Karabaş Tecvidi)","kategori":"akaid","osmanli":"اظهار"},{"kelime":"IZTIBA’","anlam":"Tavaf ederken ihrâmın üst kısmını, sağ koltuk altından geçirip sol omuz üzerine koyma.","kategori":"ibadet","misal":"Sonunda sa’y yapılan tavaf-ı kudüm ve umre gibi her tavafın bütün şavtlarında ıztıba‘ sünnettir. Sa‘yi geri bırakır ve elbisesini giymezse, tavaf-ı ziyaret de böyledir. (İbni Âbidîn)","osmanli":"اضطباء"},{"kelime":"İZTIBÂ‘ (İdtıbâ)","anlam":"Hac ve umrede erkeklerin ihramın üst parçasının bir ucunu sağ koltuk altına alıp diğer ucunu sol omuz üzerine atması.","kategori":"ibadet","misal":"İztıbâ‘, tavaf-ı kudümde erkeğe sünnettir. (Ni‘met-i İslâm)","osmanli":"اضطباع"},{"kelime":"İZZET","anlam":"1.Aziz olma, üstünlük, yücelik. 2.Değer, kıymet. 3.Kuvvet. 4.Hürmet, itibar.","kategori":"dil","misal":"Onlar ki, mü’minleri bırakıp kâfirleri dost ediniyorlar. Gücü kuvveti onların yanında mı arıyorlar? Şüphe yok ki, bütün izzet ve kudret Allah’ındır. (Nisâ sûresi: 139) Çünki bildin mü’minin kalbinde bir Allah var, Niçin izzet etmedin ol beyte kim Allah var. (Lâ edrî)","osmanli":"عزت"},{"kelime":"KÂ‘BE","anlam":"Mekke-i Mükerreme şehrinde Mescid-i Harâm’ın ortasında bulunup, aynı zamanda Müslümanların kıblesi olan taştan yapılmış dört köşeli binâ.","kategori":"dil","misal":"Allahü teâlâ, Kâ‘be’yi, o Beyt-i Harâm’ı insanlar için din işlerinde bir düzen ve dünyada cinâyetten emin bir yer kıldı. (Mâide sûresi: 97) Kâ‘be-i Muazzama’ya bakmak sevâbdır. İlk görüldüğünde yapılan duâlar kabul olunur. Peygamber efendimiz aleyhisselâm Kâ‘be-i Muazzama’yı gördüğü zaman; “Ey Allah’ım! Bu beytin şerefini, saygısını, heybetini arttır. Hac ve umre yapanların da şerefini, din gayretini, azametini ve k…","osmanli":"كعبه"},{"kelime":"KA‘DE","anlam":"Oturuş; namazda teşehhüd (tahiyyat okumak) üzere oturmak.","kategori":"ibadet","osmanli":"قعده"},{"kelime":"KA‘DE-İ AHÎRE","anlam":"Namazda son oturuş.","kategori":"ibadet","misal":"Ka‘de-i ahîrede; erkekler sağ ayağını dikip sol ayağı üzerine oturur. Kadınlar, teverrük eder. Yani kaba etlerini yere koyup ayaklarını sağ tarafından çıkararak oturur. (Halebî) Ka‘de-i ahîrede, tehiyyât okuyacak kadar oturmak farz, tehiyyat okumak ise vâcibdir. (Miftahü’l-Cenne)","osmanli":"آخره قعدۀ"},{"kelime":"KA‘DE-İ ûLÂ","anlam":"Üç ve dört rek‘at namazların ikinci rek’atından sonraki oturuş. Ka‘de-i ûlâda, oturmak vâcib, tahiyyat duâ-sını okumak ise, sünnettir. (Miftahü’l-Cenne)","kategori":"ibadet","osmanli":"اولى قعدۀ"},{"kelime":"KÂ‘İDE","anlam":"1.Esas, temel. 2.Usûl, nizam, yol. 3.Ayaklık, taban.","kategori":"fikih","osmanli":"قاعده"},{"kelime":"KABA AVRET","anlam":"Erkek ve kadınların başkalarına örtmesi gereken yerlerinden açılması ve bakılmasının yasaklığı daha fazla olan kısımlar.","kategori":"fikih","misal":"Erkeklerin sev’eteyn denilen ön ve arka uzuvları ve kaba etleri; kadınların göğüs, koltuk ve yanları, uyluk ve dizleri, sırtı kaba avrettir. Kaba avret olmayan yeri açık gezene nasihat verilir. Fitne çıkacak ise, emr-i ma‘rûf yapılmaz. Kaba avreti açık olana sert söylenir. İnâd ederse zor ile örttürülür. (İbni Âbidîn)","osmanli":"عورت قبا"},{"kelime":"KABA NECÂSET","anlam":"Muayyen bir mikdardan fazlasının namaz kılmaya engel olduğu pislik.","kategori":"ibadet","misal":"bulaştığı zaman değil, namaza dururken olan mikdarıdır. Dirhem mikdarı, kaba necâsette 4,8 gram ağırlıktadır. Akıcı necâsetlerde açık el ayasındaki suyun yüzü genişliği kadar satıhtır. (İbni Âbidîn)","osmanli":"نجاست قبا"},{"kelime":"KABÂHAT","anlam":"Çirkinlik; çirkin hareket, uygunsuz iş, kusur, suç.","kategori":"dil","osmanli":"قباحت"},{"kelime":"KABAK","anlam":"İki batman, 12 okkalık eski bir zahîre ölçüsü.","kategori":"akaid","osmanli":"قباق"},{"kelime":"KÂBE KAVSEYN","anlam":"1.İki yay arası, bir yayın kirişinin bağlandığı iki nokta veya yayın tutulduğu yer ile kirişi arası (iki kaş arası). 2.Çok az bir mesafe.","kategori":"dil","misal":"O (Muhammed aleyhisselâm Mi‘rac gecesi) Rabbine Kâbe Kavseyn veya daha yakın oldu. (Necm sûresi: 9) Kâbe Kavseyn tahtının sultânı sen, ben bir hiçim, Misafirinim dememi saygısızlık sayarım. (Mevlânâ Hâlid-i Bağdâdî)","osmanli":"قوسين قاب"},{"kelime":"KÂBİL","anlam":"Hazret-i Âdem’in oğullarından olup kıskançlık sebebiyle kardeşi Hâbil’i öldürmekle cinayet çığırını açan kimse.","kategori":"fikih","osmanli":"قابيل"},{"kelime":"KABÎLE","anlam":"Aynı soydan sayılan ve bir başa itaat eden insan topluluğu, boy.","kategori":"ibadet","osmanli":"قبيله"},{"kelime":"KÂBİLİYYET","anlam":"1.Anlama, anlayış, kabul edebilirlik, alabilirlik, isti‘dâd, iz‘ân. 2.Beceriklilik, eli işe yatkınlık; kapasite.","kategori":"tasavvuf","osmanli":"قابليت"},{"kelime":"KABİR (Kabr)","anlam":"Ölen insanın defnedilmesi, gömülmesi için kazılan yer, mezar.","kategori":"akaid","misal":"Sonra onun canını aldı ve kabre soktu. (Abese sûresi: 21) Kabir, Cennet bahçelerinden bir bahçe veyâhud Cehennem çukurlarından bir çukurdur. (Hadîs-i şerîfTirmizî) Kabir ziyaret ederken, kabir üzerinde oturmak, uyumak mekrûhtur. Bir kabre Kur’ân-ı kerîm okumak için, yanındaki eski kabirlerin üstüne basmak ve oturmak îcâb ederse, mekrûh olmaz. Yeni kabir üzerine, yine oturulmaz. Kabir üzerine çiçek ve ağaç dikmek mey…","osmanli":"قبر"},{"kelime":"Kabr-i Seâdet","anlam":"Hazret-i Peygamber aleyhisselâmın defnedildiği kabir.","kategori":"akaid","misal":"Kabr-i saadetin bulunduğu yer Hazret-i Âişe vâlidemizin odası idi. Peygamber efendimiz burada vefât etti. “Peygamberler, vefât ettikleri yere defn edilirler” hadîs-i şerîfine uyularak buraya defn edilmiştir. Burada, Hazret-i Ebû Bekr ve Hazret-i Ömer’in kabr-i şerîfleri de vardır. (Mir’at-ı Haremeyn)","osmanli":"سعادت قبر"},{"kelime":"KABRİSTÂN","anlam":"Mezarlık, ölülerin gö-müldüğü yer. Makbere.","kategori":"dil","misal":"Kabristânda bulunan ağaç, orası kabristân yapılmadan evvel yetişmiş ise, toprak sahibi-nin mülkü olur. Ağacı ve meyvelerini diledi-ğine verir. Sahipsiz toprak olup, halk tarafın-dan kabristân yapılmış ise, ağaçlar, meyveler ve toprak, önceden gelen âdete göre kullanı-lır. Ağaçlar, kabristân yapıldıktan sonra yetiş-miş ise, bunları diken ma‘lûm ise, o kimsenin mülkü olurlar. Bunları ve meyvelerini fakîrlere sadaka verir. Ağaçlar, kendiliklerinden yetişmiş iseler, diken kimse bilinmiyorsa, hâkimin karârı ile amel olunur. (Fetâvâ-i Hindiyye)","osmanli":"قبرستان"},{"kelime":"KABûL","anlam":"1.Râzı olmak; tasdik. 2.Birini karşılamak, ağırlamak. 3.verilen şeyi alma. 4.Bir yere alınma. 5.Akidde yapılan icaba rızâ göstermek.","kategori":"dil","misal":"Alıcı ve satıcıdan râzı olduğunu hangisi daha önce söylerse, buna icâb, ikincisine kabul de-nir. (İbni Âbidîn) Bir kimse birisine, falan malını bana şu kadar liraya sat diye yazıp, o da, o malı sattım diye cevap yazsa, alış veriş sahîh, geçerli olmaz. Bi-rincisinin kabul ettim diye tekrar yazması lâ-zımdır. (Mir’at-ı Mecelle)","osmanli":"قبول"},{"kelime":"KÂBuS","anlam":"1.Uykuda basan ağırlık, ka-rabasan, kötü rüya. 2.Felâket.","kategori":"dil","osmanli":"كابوس"},{"kelime":"KABZ","anlam":"1.Elle tutma, teslim alma. 2.Sıkıntıya, gönül darlığına düşme.","kategori":"muamelat","misal":"Teberru, ancak kabz ile tamam olur. Meselâ bir adam birine bir şey hibe etse kable’l-kabz (alma-dan önce) hibe tamam olmaz. (Mecelle, m. 57) Tasavvuf yolunda olanlarda zaman zaman görülen darlık, yürek sıkıntısı. Bahâeddîn-i Nakşibend kuddise sirruh, kabz hâ-linde istiğfârı yani bağışlanmayı istemeyi, bast hâlinde de şükretmeyi emretmiştir. (Reşahât) Ruhun Azrâil aleyhisselâm tarafından alınması. Dışarı çıkma zorluğu, peklik.","osmanli":"قبض"},{"kelime":"KABZA","anlam":"1.Tutma yeri, sap, tutamak. 2.Bir tutam.","kategori":"dil","misal":"Sakalı, bir kabza, yani dudak kenarından sa-kalın başladığı yerden dört parmak eni kadar uzatmak sünnettir. (Berîka)","osmanli":"قبضه"},{"kelime":"KADÂEN","anlam":"Kazâ suretiyle, kâdînin (mahkemenin) hükmü bakımından.","kategori":"osmanli","misal":"Bir kere cimâ‘ ile zevcenin hakkı ödenmiş olur. Tekrarlamak diyâneten vâcibdir. Kadâen vâcib olmaz. Yani kadın, hâkime müracaat edemez. Tekrarını talep etmek zevcenin de hakkı olup, talep edince zevc üzerine diyâneten vâcib olur. (İbni Âbidîn)","osmanli":"قضاًء"},{"kelime":"KADEH","anlam":"Bardak; küçük bardak, içki bardağı.","kategori":"dil","osmanli":"قدح"},{"kelime":"KADEM","anlam":"1.Ayak. 2.Adım, hatve. 3.Ya-rım arşın (30 cm) uzunluğunda bir ölçü. 4.Uğur, bereket.","kategori":"dil","osmanli":"قدم"},{"kelime":"Kadem-i Şerîf","anlam":"Hazret-i Peygamber’in ayak izi.","kategori":"akaid","misal":"No’la tâcım gibi başımda götürsem dâim, Kadem-i nakşını ol Hazret-i Şâh-ı Rusûlün, Gül-i gülzâr-ı nübüvvet o kadem sahibidir, Ahmedâ durma yüzün sür kademine o gülün. (Sultan I. Ahmed)","osmanli":"شريف قدم"},{"kelime":"KADEME","anlam":"1.Basamak. 2.Derece, sıra.","kategori":"dil","misal":"Hutbede sultânların isimlerinin bir kademe aşa-ğıda okunması, sultânların tevâzu‘larındandır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قدمه"},{"kelime":"KADER","anlam":"1.Ölçü, mikdar. 2.İslâmiyet’te, ilerde olacak hâdiseleri Allahü teâlânın ezelden bilmesi mânâsına bir iman esası, alın yazısı.","kategori":"akaid","misal":"Şüphesiz biz, her şeyi bir kader ile yarattık. (Kamer sûresi: 78)","osmanli":"قدر"},{"kelime":"Kadere Rızâ","anlam":"İnsanın, Allahü teâlâ-nın kendisi hakkında takdîr ettiği şeylere rızâ göstermesi, hoşnud olması, başına gelen belâ ve musîbetlere sabredip, boyun eğmesi.","kategori":"akaid","misal":"Allahümme innî es’elüke’s-sıhhate ve’l-emâ-nete ve hüsne’l-hulki ve’r-rıdâe bi’l-kader (Allah’ım, Senden sıhhat, afiyet, emânet, gü-zel ahlâk ve kadere rızâ istiyorum.) (Hadîs-i şerîf-Taberâni) Allahü teâlâ, kulunu rızkı ile imtihan eder: Kul, kaderine rızâ gösterirse geçimi bereketli olur. Göstermezse olmaz. (Hadîs-i şerîf-Deylemî) İslâm dini ve bütün semâvî dinler her işin Al-lahü teâlânın takdîri ve irâdesi ile olduğunu bildirdi. Fakat insan bir işin ezelde nasıl tak-dîr edildiğini bilmediği için, Allahü teâlânın emrine uyarak çalışması ve kadere rızâ gös-termesi lâzımdır. Kazâ ve kadere inanmak, ka-dere rızâ göstermek insanın çalışmasına mâni olmaz, bilakis çalışmasını kamçılar. (Mektû-bât-ı Ma‘sûmiyye)","osmanli":"رضا قدره"},{"kelime":"KADERÎ","anlam":"1.Kader ile alâkalı. 2.Kulun, yaptığı işlerin yaratıcısı olduğuna inanan fırkaya mensub","kategori":"akaid","osmanli":"قدرى"},{"kelime":"KADERİYYE","anlam":"Hicrî II. asırda Basra’da Vâsıl bin Atâ tarafından kurulan ve insanın yaptığı işlerin yaratıcı olduğuna inanan bid‘at fırkası.","kategori":"akaid","misal":"Kaderiyye, bu ümmetin mecûsîleridir. (Hadîs-i şerîfEbû Ya’lâ)","osmanli":"قدريه"},{"kelime":"KADI (Kâdî)","anlam":"Kadâ eden, İslâm hukukuna göre hüküm veren hâkim.","kategori":"osmanli","misal":"Kadılar üç kısımdır: Biri Cennet’te, ikisi Cehennem’dedir. Hakkı bilen ve ona göre hüküm veren kadı Cennet’tedir. Hakkı bilen fakat ona göre hüküm vermeyen kadı Cehennem’dedir. Bilmediği hâlde hüküm veren kâdı da Cehennem’dedir. (Hadîs-i şerîfİbn-i Mâce, Ebû Dâvûd, Tirmizî) Kadı yerine oturunca, onun yanına iki melek iner ve zulmetmedikçe ona yol gösterirler. Onu muvaffak kılmaya çalışırlar. Eğer zulmederse, oradan…","osmanli":"قاضى"},{"kelime":"KADIASKER (Kazasker)","anlam":"“Askerî kâdı” mânâsına Abbasîlerdeki kâdiyülkudâtın vazifesini Osmanlılarda yerine getiren, adliye ve ilmiye teşkilâtının başında bulunan, icabında askerî denilen devlet ricâlinin muhakemesini yapıp miraslarını taksim eden ve Divan-ı Hümâyun âzâsı yüksek hâki…","kategori":"osmanli","osmanli":"عسكر قاضى"},{"kelime":"KÂDİM","anlam":"Kadem (ayak) basan, varan.","kategori":"osmanli","osmanli":"قادم"},{"kelime":"KADÎM","anlam":"1.Kıdem sahibi, önceliği olan. 2.Varlığının evveli, başlangıcı olmayan mânâsına Allahü teâlânın zâtına âit sıfatlardan (elKadîm).","kategori":"osmanli","misal":"Hezâr (binlerce) gıpta o devr-i kadîm efendisine, Ne kendi benzer kimseye, ne kimse benzer kendisine. (Yahya Kemal)","osmanli":"قديم"},{"kelime":"KÂDİR","anlam":"1.Gücü yeten, kudret sahibi. 2.Allahü teâlânın sıfatlarından biri; gücü her şeye yeten, hakîkî kudret sahibi (elKâdir).","kategori":"osmanli","misal":"Allahü teâlâ ölüyü diriltmeye, taşı konuşturmaya ve yürütmeye ve uçurmaya kâdirdir. Gökleri ve Kürsî’yi ve Arş’ı ve yeri ve bütün kâinâtı kısa zamanda yok etmeye ve tekrar yaratmaya kâdirdir. Zîrâ bunların hepsi mümkündür, sonradan yaratılmıştır. (Birgivî Vasîyetnâmesi)","osmanli":"قادر"},{"kelime":"KADÎR","anlam":"Kudreti tam, kâmil kudret sahibi, her şeye gücü yeten mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elKadîr).","kategori":"akaid","misal":"Bütün mülk ve saltanat, yed-i kudretinde olan Allahü teâlâ, her türlü noksanlıktan uzaktır. O, her şeye kadîrdir. (Mülk sûresi: 1)","osmanli":"قدير"},{"kelime":"KÂDİRÎ","anlam":"Tasavvufta Abdülkâdir Geylânî hazretlerinin yoluna mensub kimse.","kategori":"tasavvuf","misal":"(Bkz. Kâdiriyye)","osmanli":"قادرى"},{"kelime":"KÂDİRİYYE","anlam":"Hicrî 561 (m.1266) senesinde vefat eden Abdülkâdir-i Geylânî hazretlerinin tasavvuftaki yolu.","kategori":"tasavvuf","misal":"Tarîkatler başlıca ikidir. Zikr-i hafî yani sessiz zikir yapan ve zikr-i cehrî yani yüksek sesle zikir yapan tarîkatler. Birincisi Hazret-i Ebû Bekr’den gelmiş olup, çeşitli isimler almışlardır. Zikr-i cehrî ise, Hazret-i Ali’den on iki imâm vâsıtasıyla gelmiştir. Bunların sekizincisi olan İmâm-ı Ali Rızâ’dan Ma’rûf-i Kerhî almış ve Cüneyd-i Bağdâdî’nin çeşitli halîfelerinin silsilelerinde bulunan meşhûr mürşidlerin…","osmanli":"قادريه"},{"kelime":"KÂDİYÂNİYYE (Kâdıyânîlik)","anlam":"On dokuzuncu asırda Hindistan’da İngilizlerin tertibiyle, kendisini mehdî, mesîh ve son peygamber ilan eden Mirzâ Gulâm Ahmed tarafından kurulan ve kurucusunun doğum yeri olan Kâdiyan kasabasına nisbetle bu adla anılan fırka ve yeni din.","kategori":"dil","misal":"Ahmediyye.","osmanli":"قاضيانيه"},{"kelime":"KÂDİYÜ’L-KuDÂT (Kâdı’l-Kudât)","anlam":"","kategori":"osmanli","misal":"(A) “Kadılar kadısı” mânâsına Abbasîler devrinden itibaren bütün kâdıları tayin ve bunların verdiği hükümleri temyîzen kontrol etme üzere tayin olunan yüksek memur. Başkadı. (Bugünün Adalet Bakanı ile Yargıtay ve Danıştay Başkanlarının pozisyonuna denk gelir.)","osmanli":"القضات قاضى"},{"kelime":"KADR","anlam":"1.Kıymet, değer. 2.Ölçülme, tak-dir edilme. 3.Alışverişte malın kile (ölçek) veya vezn (ağırlık) ile ölçülmesi.","kategori":"muamelat","misal":"Bir peşin satışta kadr varsa (yani iki mal ağır-lık veya hacim ile ölçülüyorsa), cinsleri de aynı ise, mallardan birinin fazla olması hâlinde fâiz mevzubahis olur. Müsâvî (eşit) olsalar bile iki maldan birinin veresiye olması hâlinde fâiz olur. (İbni Âbidîn)","osmanli":"قدر"},{"kelime":"KAF SûRESİ","anlam":"Kur’ân-ı kerîmin el-linci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Kırk beş âyet-i kerîme-dir. Kaf harfi ile başladığı için Sûre-i Kaf de-nilmiştir. Sûrede; kâfirlerin inkârlarında inâd etmeleri, Allahü teâlânın varlık ve kudretinin delilleri, geçmiş bazı kavimlerin isyânları, in-sanın yaratılışı, Allahü teâlânın insanlara ya-kınlığı, ölüm ve ölümden sonraki hayat anla-tılmaktadır. (Mefâtihü’l-Gayb, Taberî) Kim Kaf sûresini okursa, Allahü teâlâ ona ölüm acılarını ve sarhoşluğunu hafifletir. (Hadîs-i şerîf- Beydâvî)","osmanli":"سى سوره ق"},{"kelime":"KÂFÎ","anlam":"Kifâyet eden, elveren, yetişen; yeter, yetecek.","kategori":"dil","osmanli":"كافى"},{"kelime":"KÂFİLE","anlam":"1.Birlikte yolculuk eden topluluk; zümre, fırka. 2.Takım takım, sıra sıra gönderilen şeylerin her parçası.","kategori":"dil","osmanli":"قافله"},{"kelime":"KÂFİR","anlam":"1.Küfreden, iyilikleri, nimetleri, hakkı inkâr eden, örten. 2.İslâmiyet’te inanıl-ması lâzım olan şeylerin hepsine veya birine inanmayan, dinin emirlerini beğenmeyen, ha-fife alan, alay eden. Kâfirler, Allahü teâlânın emirleri ile Pey-gamberlerin emirlerini birbirinden ayırmak istiyorlar. Bir kısmına inanırız, bir kısmına inanmayız diyorlar. Îmân ile küfür arasında bir yol açmak istiyorlar. Onların hepsi kâfir-dir. Kâfirlerin hepsine Cehennem azâbını, çok acı azapları hazırladık. (Nisâ sûresi: 150-151) Kâfirleri yüzleri üzerine sürünerek Ce-hennem’e göndeririz. (Meryem sûresi: 86) Kâfirin hiçbir iyiliği, hayrâtı, hasenâtı âhirette faydalı olmaz. Îmânı olmayanın hiçbir iyiliğine sevab verilmez. (Hâdimî)","kategori":"akaid","osmanli":"كافر"},{"kelime":"KÂFİRûN SûRESİ","anlam":"Kur’ân-ı kerîmin yüz dokuzuncu sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Altı âyet-i kerîmedir. Kâfirlerin hâllerinden bahsedildiğinden sûre bu ismi almıştır. (Taberî, Râzî) (Habîbim! Onlara) de ki: Ey kâfirler! Ben sizin tapmakta olduklarınıza (putlarınıza) tapmam. Siz de, benim ibâdet etmekte olduğuma (Allah’a) ibâdet ediciler değilsiniz. Ben sizin taptıklarınıza (hiçbir zaman) tapmış değilim. Siz de benim kulluk etmekte olduğuma (hiçbir vakit) kulluk edicilerden d…","osmanli":"سى سوره كافرون"},{"kelime":"KÂFİYE","anlam":"Şiirde mısra sonundaki ke-limelerin ve seslerin mânâ bakımından ayrı olan benzerlikleri.","kategori":"dil","osmanli":"قافيه"},{"kelime":"KÂFİYE","anlam":"İbni Hâcib’in Arab gramerine ait, okutulması İslâmî ilimler tedrisatında bir merhale teşkil eden meşhur eseri.","kategori":"ibadet","osmanli":"كافيه"},{"kelime":"KÂFİYE [1]","anlam":"Şiirde mısra sonundaki kelimelerin ve seslerin mânâ bakımından ayrı olan benzerlikleri.","kategori":"dil","osmanli":"قافيه"},{"kelime":"KÂFİYE [2]","anlam":"İbni Hâcib’in Arab gramerine ait, okutulması İslâmî ilimler tedrisatında bir merhale teşkil eden meşhur eseri.","kategori":"ibadet","osmanli":"كافيه"},{"kelime":"KÂFûR","anlam":"Uzak Doğu’da yetişen bir çeşit tropik ağaçtan elde edilen, kalb ve teneffüs antiseptiği olarak tıpta kullanılan, beyaz ve yarı saydam, kokulu, kolaylıkla parçalanan, kuvvetli bir madde.","kategori":"ibadet","misal":"Şüphesiz iyiler, kâfûr katılmış bir kadehten (Cennet şarabı) içerler. (İnsân sûresi: 5) Cenâze, sedr ağacı yaprağı veya çögen (sabun otu) ile kaynatılıp ılıtılmış veya kâfûr konmuş su ile, bunlar yok ise, yalnız su dökerek, başı ve sakalı, hatmi veya sabun ile yıkanır. (İbni Âbidîn)","osmanli":"كافور"},{"kelime":"KAHBE","anlam":"1.Namussuz kadın, fâhişe, zâniye. 2.Hîlekâr, kalleş, kancık, dönek (adam).","kategori":"osmanli","osmanli":"قحبه"},{"kelime":"KÂHİN","anlam":"1.Kehânet eden, tabiatüstü güçleri olup gaybdan ve gelecekten haber ver-diğini, gizli şeyleri bildiğini iddiâ eden kimse. 2.Yahudilikte Hârûn aley-hisselâmın soyundan geldiğine inanılan din adamı.","kategori":"dil","misal":"Falcı. (Bkz. Kehânet) Kohen. Bir adam bir kâhine gelip bir şey sorsa, o adamın kırk gün tövbesi kabul olmaz (veya tövbe nasip olmaz). Onu tasdik ederse kâfir olur. (Hadîs-i şerîf-Taberânî) Kâhinlere, falcılara inanmamalıdır. Bilinmeyen şeyleri bunlara sormamalıdır. Bunları gayb-ları bilir sanmamalıdır. Gaybı ancak, Allahü teâlâ ve O’nun bildirdikleri bilir. (Mektûbât-ı İmâm-ı Rabbânî) «Her kim bir kâhine giderse...» hadîsi, arrâf ve müneccimlere şâmildir. Araplar ince bir ilimle meşgul olan herkese kâhin derler. Bazıları mü-neccim ve tabibe de kâhin derler. (İbni Âbidîn) KAHKAHA: قهقهه (A) Etraftakiler işitecek ka- dar yüksek sesle gülmek. Rükû’ ve secdeleri olan namazda kahkaha ile gülmek, namazı da, abdesti de bozar. Namazda tebessüm, namazı da abdesti de bozmaz. Te-bessüm, insanın kendisinin de işitmeyeceği ka-dar gülmesidir. (İbni Âbidîn)","osmanli":"كاهن"},{"kelime":"KAHR","anlam":"1.Mahvetme, helâk etme. 2.Çok kederlenme, çok üzüntü duyma.","kategori":"akaid","misal":"Gençlikte, Allahü teâlânın kahrından, azâbın-dan korkmalı, titremeli, ihtiyarlıkta merhame-tine sığınmalıdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قهر"},{"kelime":"KAHRAMÂN","anlam":"1.Yiğit, cesur, bahâdır. 2.Fars mitolojisinde Rüstem’in yendiği kimse. 3.Hüküm sahibi, iş buyuran.","kategori":"dil","misal":"Bir kahramân lâzımdır ki, sünnete yardım edip, bid‘ati durdursun, kaçırsın. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قهرمان"},{"kelime":"KÂHRÜBÂ","anlam":"1.Saman kapan, saman kapıcı, kehribar. 2.Elektrik.","kategori":"dil","osmanli":"كاهربا"},{"kelime":"KAHT","anlam":"Kıtlık, kuraklık, gıdâ madde-lerinin azlığı.","kategori":"dil","osmanli":"قحط"},{"kelime":"KAHTÂN","anlam":"Nuh aleyhisselâmın oğlu Sâm’ın soyundan Yemen’e yerleşen ve soyu Arabların Âribe denilen kısmını teşkil eden kimse.","kategori":"dil","misal":"Kahtândan bir adam çıkıp da asâsı ile insanları sevk etmedikçe kıyâmet kopmaz. (Hadîs-i şerîfBuhârî)","osmanli":"قحطان"},{"kelime":"KÂİL","anlam":"1.Kavl sahibi, söyleyen, diyen. 2.Râzı olmuş, boyun eğmiş. 3.İnanmış, aklı yatmış.","kategori":"dil","misal":"Vahdet-i vücûda kâil olanlar, Hak celle ve âlâya mutlak derler. (Mektûbât-ı Ma’sûmiyye) Üç nişan olur velîlerde, demiş, erbâb-ı dil, Biri ol ki, görenin gönlü ona mâil olur. O’nun ikinci nişânı, oldur ki, iyi bil, Her ne dese, dinleyenler, sözüne kâil olur. Üçüncüsüne gelince, cümle a’zâsı anın, Şer’ ile âdâb ile, her zaman, âmil olur.","osmanli":"قائل"},{"kelime":"KÂİM","anlam":"1.Kıyâm eden, ayakta olan, ayakta duran. 2.Uyanık olan. 3.Namaz kılan. 4.Ye-rine geçen.","kategori":"ibadet","misal":"Bu din, Kureyş’ten on iki halîfe gelip gidin-ceye kadar kâim olarak devam eder. Her bi-rinde ümmet birleşmiş vaziyettedir. Ondan sonra ise herc-ü-merc başlar. (Hadîs-i şerîf-Buhârî, Taberânî) Bir kimse ahlâkının güzel-liği ile, geceleri kâim, gündüzleri sâim olan-ların mertebesine erişir. (Hadîs-i şerîf-Hâkim) Allahü teâlâ bir ev halkını sevdiğinde, ara-larında mülâyemet kâim olur. (Hadîs-i şerîf-İbni Ebiddünyâ)","osmanli":"قائم"},{"kelime":"KÂİNÂT","anlam":"1.Var olan şeylerin cüm-lesi, hepsi, yaratıklar, mevcudat. 2.Dünya, âlem, cihan.","kategori":"dil","osmanli":"كائنات"},{"kelime":"KÂKÜL","anlam":"Alnın üzerine sarkıtılan kısa kesilmiş saç, perçem, zülf.","kategori":"dil","misal":"Resûlullah aleyhisselâmın mübârek saçları uzundu. Önceleri kâkül bırakırdı; sonradan ikiye ayırır oldu. (Mevâhib-i Ledünniyye)","osmanli":"كاكل"},{"kelime":"KÂL","anlam":"“Söyledi” mânâsına zâhir ilimleri için kullanılan bir tabir. Zıddı hâl gelir.","kategori":"akaid","osmanli":"قال"},{"kelime":"KALB","anlam":"1.Kan deverânının merkezi olan uzuv, yürek. 2.Gönül; kalbe yerleştirilmiş nûrânî ve mânevî kuvvet.","kategori":"tasavvuf","misal":"Biliniz ki kalbler zikr ile (Allahü teâlâyı anmakla) rahat bulur. (Ra’d sûresi: 30) Kalbleri bozuk olanlar, hakkı örtmek, fitne, fesâd çıkarmak için Kur’ân-ı kerîmden yanlış mânâ çıkarır, yanlış yola saparlar. (Âl-i İmrân sûresi: 7) Kalb, hükümdardır. Hükümdar temiz olursa, teb’ası da temiz ve sağlam olur. hükümdar fesâda uğrarsa, teb’ası da fesâda uğrar. (Hadîs-i şerîfEbû Nuaym) Kalb, Allahü teâlâdan başkasına tutu…","osmanli":"قلب"},{"kelime":"Kalb Gözü","anlam":"Akıl ile anlaşılamayan şeyleri görüp anlayabilen bir kuvvet.","kategori":"tasavvuf","misal":"Evliyâ, kalb gözleri ile görüp anlar ve birbirlerine anlatırlar. Kalb gözüne kavuşmak için, Müslüman olmak ve tasavvuf yolunda çalışmak lazımdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ﮔوزى قلب"},{"kelime":"Kalb Hastalığı","anlam":"Kötü ahlâk, kötü huy; kalbin Allahü teâlâdan başkasına bağlanması.","kategori":"tasavvuf","misal":"“Kalblerinde hastalık vardır” meâlindeki âyet-i kerîmede bildirilen kalb hastalığına yakalanmış olanların hiçbir ibâdeti ve tâati fayda vermez. Bilakis zarar verir. “Çok Kur’ân-ı kerîm okuyanlar vardır ki, Kur’ân-ı kerîm bunlara lânet eder” hadîs-i şerîfi meşhurdur. “Çok oruç tutanlar vardır ki, oruçtan kazancı, yalnız açlık ve susuzluktur” hadîs-i şerîfi sahîhtir. Kalb hastalıklarının mütehassısları olan tasavvuf b…","osmanli":"ليغي خسته قلب"},{"kelime":"Kalb-i Hakîkî","anlam":"Kalbde bulunan mânevî (nûrânî) kuvvet.","kategori":"tasavvuf","osmanli":"حقيقى قلب"},{"kelime":"Kalb-i Sanevberî","anlam":"Kalbin fizikî hâli. Yürek.","kategori":"tasavvuf","misal":"Kalb-i sanevberî, kalb-i hakîkînin (gönül) yuvası gibidir. (Abdülhakîm Arvâsî)","osmanli":"صنوبرى قلب"},{"kelime":"Kalb-i Selîm","anlam":"Kötü vasıflardan arınmış, güzel vasıflarla bezenmiş kalb.","kategori":"tasavvuf","misal":"O gün, mal ve çocuklar fayda vermez. Ancak, Allahü teâlâya kalb-i selîm ile gelenler müstesnâdır. (Şu’arâ sûresi: 88, 89) Kalb-i selîm hakkında âlimler farklı söylemiştir. Hepsini bir araya getirerek denebilir ki, kalb-i selîm, şüphe ve şirkten, bid‘atlerden uzak, sünneti huzur ile kabul eden, mal ve evlât âfetlerinden kendisini kurtarmış, Allahü teâlâya iman eden, kıyametin ve haşrin hak olduğuna inanan, hâsılı gün…","osmanli":"سليم قلب"},{"kelime":"Kalb Temizliği","anlam":"Kalbin, dine uymayan şeylerden ve dünyaya düşkünlükten kurtulması.","kategori":"tasavvuf","osmanli":"تميزليغى قلب"},{"kelime":"KALEM","anlam":"1.Yazı yazmaya mahsus âlet. 2.Levh-i Mahfûz üzerine Allahü teâlânın ilm-i ezelîsi ile takdîr ettiği şeyleri yazan, keyfiyeti bilinemeyen yazı âleti.","kategori":"dil","misal":"Nûn, kalem ve onunla yazılanlara andol-sun ki. (Kalem sûresi: 1) Allahü teâlânın ilk yarattığı şey kalemdir. Ona yaz buyurdu. Ne yazayım? dedi. Kaderi yaz buyurdu. O da Levh-i Mahfûz üzerine olacakları yazdı. (Hadîs-i şerîf- Ebû Dâvûd, Tirmizî)","osmanli":"قلم"},{"kelime":"KALENDER","anlam":"1.Yaratılış itibariyle mütevâzı olan; hayat şartları bakımından titizlik göstermeyen. 2.Kalenderiyye tarikatine mensub kimse.","kategori":"tasavvuf","misal":"Kalender, bâtınını temizlemek, nefsini yok etmek için çalışır. Çok ibâdet yapmaz. Sôfî ise, bunun ikisine de çalışır. Mahlûkları görmez. Kalenderden daha üstündür (Mekâtib-i ŞerîfeAbdullah Dehlevî)","osmanli":"قلندر"},{"kelime":"KALENSÜVE","anlam":"1.Ustanın muavini, yardımcısı; ustalık ehliyetini kazanmış, ancak müstakil dükkânı bulunmayıp ustasına yardım eden. 2.Sarayda kıdemli câriye.","kategori":"dil","misal":"Tepesi külâh şeklinde takke; her çeşit başlık, serpuş. Resûlullah aleyhisselâm, ekseriya beyaz ka-lensüve giyerdi. Sarıklarının altında ve sa-rıksız olarak kalensüve giyerler, o olmadan da sarık sararlardı. (Hadîs-i şerîf-Taberânî, İbni Asâkir) İmâme (sarık), kalensüve, peçe, maske ve eldi-ven üstüne mesh etmek câiz değildir. (Halebî) KALFA: قلفه (T)","osmanli":"قلنسوه"},{"kelime":"KÂLÎ","anlam":"Borç; borcu borçla satma.","kategori":"muamelat","osmanli":"قالى"},{"kelime":"KALTABAN","anlam":"Pezevenk, namussuz. Sefîh, pelîd, ahmak, mubâhî, avânî, lûtî, zındık, hırsız, deyyûs, kaltaban, ey şerâb içici, ey fâizci diyen ta’zîr olunur.","kategori":"fikih","misal":"(Behcetü’l-Fetâvâ)","osmanli":"قلتبان"},{"kelime":"KAMER","anlam":"[Gökteki] Ay.","kategori":"dil","osmanli":"قمر"},{"kelime":"KAMERÎ SENE","anlam":"Ayın yerküresi etrâfında on iki defâ dönmesi esnâsında or-taya çıkan 354 günden ibaret sene. (Bkz. Hicrî Kamerî Sene)","kategori":"dil","osmanli":"سنه قمرى"},{"kelime":"KÂMET","anlam":"1.Boy, endam. 2.Kalkmak, ayakta durmak. 3.Farz namazlardan önce okunması sünnet olan ve ezâna benzeyen sözler.","kategori":"ibadet","misal":"Erkeklerin, farz namazlardan önce kâmet okumaları sünnet-i müekkededir. (Halebî)","osmanli":"قامت"},{"kelime":"KÂMİL","anlam":"Kemâl sahibi, tam, eksik-siz, olgun.","kategori":"dil","misal":"Îmânı kâmil olanınız, ahlâkı güzel olanınız-dır. (Hadîs-i şerîf-Müslim) Her mü’min Peygamberimizi malından ve ca-nından daha çok sever. Bu sevgisinin bir alâ-meti, sünnetleri yapıp mekrûhlardan kaçınmak-tır. Bir mü’min bütün bunları yerine getirdikten sonra, mübahlarda da ne kadar ona uyarsa o derece kâmil bir Müslüman olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"كامل"},{"kelime":"KAMÎS","anlam":"1.Gömlek, entâri. 2.Kefenin parçalarından olup, entâri gibi uzun, dikişsiz gömlek.","kategori":"dil","misal":"Resûlullah kamîs giymeyi severdi. Kamîsi-nin kolları, bileklerine kadar uzundu. (Ha-dîs-i şerîf-Tirmizî) Namazda, secdeye yatarken kamîs ve panto-lon paçalarını yukarı çekmek mekrûhtur ve bunları yukarı çekip, kıvırıp namaza durmak da mekrûhtur. (Halebî) (Bkz. Kefen) Erkeğin kefeninin üç parça olması sünnettir. Bunlar: 1) İzâr; genişliği bir metreden fazla ve baştan ayağa kadar olan bez parçası. 2) Kamîs; uzunluğu, omuzlardan ayaklara ka-dar olan uzunluğun iki katıdır. Bu uzunluk ortadan ikiye katlanıp, kat yerinden, baş geçe-cek kadar, düz kesilir. Kol ve etek yerleri kesil-mez. 3) Lifâfe; uzunluğu başı ve ayağı geçen, baş üstünden ve ayak altından uçları büzülüp bezle bağlanan parça. (İbni Âbidîn)","osmanli":"قميص"},{"kelime":"KAN ALDIRMA","anlam":"(Bkz. Hacâmat)","kategori":"ibadet","osmanli":"آلديرمه قان"},{"kelime":"KANDİL","anlam":"1.İçine sıvı yağ ile fitil bulu-nan kaptan müteşekkil aydınlanma aleti, kın-dîl. 2.İslâm dininin kıymet verdiği ve şerefine kandiller yakıldığı için bu ismi alan Mevlid, Berât, Mi’râc ve Regâib gibi mübârek geceler. (Bkz. Mübârek Geceler)","kategori":"dil","osmanli":"قنديل"},{"kelime":"KÂNûN","anlam":"1.Tabiî hâdiseleri birbirine bağlayan mecburî münasebet. 2.Devletin hükümdar, meclis gibi yüksek otoritesi tarafından adalet ve cemiyet nizamını temin için konulan ve insanların uymakla mükellef olduğu prensip. 3.Her hangi bir mevzudaki kanun prensiplerinin y…","kategori":"fikih","osmanli":"قانون"},{"kelime":"KAPİTALİZM","anlam":"Hususî teşebbüs ve piyasa serbestisine dayanan bir istihsal (üre-tim) sistemi; buna bağlı olarak teşekkül eden iktisadî, siyasî, hukukî ve sosyal sistem. Sos-yal adâleti kaldıran, insan haklarını sömüren ikinci ekonomik sistem.","kategori":"dil","osmanli":"قاﭘيتاليزم"},{"kelime":"KÂR","anlam":"1.İş. 2.Bir şeyden elde edilen men-faat. 3.Bir malı satarken, maliyeti üzerine ek-lenen fazlalık.","kategori":"dil","osmanli":"كار"},{"kelime":"KÂR HADDİ","anlam":"Bir malı satarken, devlet taarfından kâra konulan sınır.","kategori":"osmanli","misal":"Si’r. Narh. Medîne-i Münevvere’de pahalılık oldu. “Yâ Resûlallah! Fiyatlar yükseliyor. Kâr haddi koysanız” denildi. Resûlullah aleyhisselâm; “Fiyatları takdir eden Allahü teâlâdır. Rızkı genişleten, daraltan, gönderen yalnız O’dur. Ben, kimsenin benden bir hakkı olmadan Allahü teâlâya ulaşmayı arzu ediyorum” buyurdu. (Hadîs-i şerîfEbû Dâvûd, Tirmizî, Nesâî) Herkes malını, dilediği fiyatla satabilir. İslâmiyet’te kâr…","osmanli":"حدى كار"},{"kelime":"KARÂMITA","anlam":"Milâdî IX. asırda Şia’nın aşırılarından Hamdân Karmât (277/890) tarafından kurulan ve İsmailiyye (Bâtıniyye) kollarından ilhad fırkası.","kategori":"dil","misal":"Karmatî’nin çokluk hâli. Kûfe’de tüccârlık yapan ve gözleri kırmızı olduğu için Karmât denilen Hamdân, faaliyetlerine dârülhicre adındaki tekke ile başladı. İbâhiyyeci ve komünizmi (müşterek mülkiyeti) esas alan fikirlerini yaydı. Günde dört vakit namaz, senede iki gün (Nevruz ve mihrican) oruç vardır. Kıble Kudüs’tür; hacca da Kudüs’e gidilir. Şarap helâldir. Mukaddes gün pazardır. Cennet ve Cehennem dünyadadır. 22…","osmanli":"قراميطه"},{"kelime":"KARANTİNA","anlam":"Sâri (salgın) hasta-lıklara mâni olmak üzere, bulaşıcı bir hasta-lık şüphesi taşıyanları bir müddet başkaları ile etmas ettirmeme.","kategori":"dil","misal":"Peygamberimiz sallallahü aleyhi ve sellem, has-taların karantinaya alınmaları, perhiz yapma-ları ve temizlenmeleri gibi birçok tedavi yolları göstermiştir. (Hedyü’l-İslâmî)","osmanli":"قرانتينه"},{"kelime":"KARÂR","anlam":"1.Durma. 2.Rahat. 3.Devamlı-lık. 4.Ölçülülük. 5.Tahmin. 6.Tam ölçü, ne az, ne çok. 7.Neticeye bağlama.","kategori":"dil","osmanli":"قرار"},{"kelime":"KARARNÂME","anlam":"Verilen kararı bil-diren yazı.","kategori":"dil","osmanli":"قرارنامه"},{"kelime":"KARDİNAL","anlam":"Katolik mezhebinde Papa’nın yardımcısı sıfatıyla merkezde idarî işlerle vazifeli piskoposlara verilen isim.","kategori":"akaid","osmanli":"قاردينال"},{"kelime":"KÂRGİR","anlam":"1.İş tutan, iş yapan. 2.Taş veya tuğladan yapılmış bina.","kategori":"dil","osmanli":"كارﮔير"},{"kelime":"KÂRÎ’","anlam":"Kıraat eden. Kur’ân-ı kerîmi ezberleyen veya okuyan.","kategori":"dil","misal":"Nice kârî’ler vardır ki, Kur’ân-ı kerîm onlara lânet eder. (Hadîs-i şerîfKeşfü’l-Hafâ)","osmanli":"قارئ"},{"kelime":"KARÎB","anlam":"1.Kurb sahibi, yakın, uzak ol-mayan. 2.Akraba.","kategori":"dil","misal":"O’nun vâsi’, muhît, karîb ve bizim ile beraber olduğuna inanırız. Fakat, bu sıfatların ne de-mek olduğunu bilemeyiz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قريب"},{"kelime":"KARÎN","anlam":"1.Yakın. 2.Bir şeye nâil. 3.Hısım, komşu, arkadaş gibi yakın kimseler. 4.Pâdişâhın devamlı yakınında bulunan.","kategori":"osmanli","osmanli":"قرين"},{"kelime":"KÂRİN HACI","anlam":"Hac ile umreye birlikte niyet edip, önce umre yaparak ihrâmdan çıkmadan hacceden kişi.","kategori":"ibadet","misal":"Kârin hacılar taş atıp, tıraş oluncaya kadar ihrâmı çıkarmayacağı için, ihrâmın men ettiği şeylerden her gün sakınmaları lâzım olur. Bu şeylerden sakınamayacak kimselerin mütemettî’ hacı olması uygundur. (İbni Âbidîn)","osmanli":"حاجى قارن"},{"kelime":"KARIŞ","anlam":"1.Parmaklar açık ve gergin tu-tulduğunda başparmak ucu ile serçe parmak ucu arasındaki açıklık. 2.12 parmak (24 cm) uzunluğunda bir uzunluk ölçüsü.","kategori":"dil","osmanli":"قارش"},{"kelime":"KARİYYE","anlam":"Köy, karye.","kategori":"dil","osmanli":"قريه"},{"kelime":"KARN","anlam":"1.Boynuz. 2.Asır, çağ.","kategori":"dil","misal":"KARNÂ: (A) Fercinde bulunan bir kemikten dolayı zevcelik vazifesini yerine getireme-yen kadın.","osmanli":"قرن"},{"kelime":"KARS","anlam":"Çitileme yoluyla necâseti temizleme.","kategori":"fikih","osmanli":"قرص"},{"kelime":"KÂRûN","anlam":"İsrâiloğullarında zenginliği ile meşhur ve sonradan faydasız zenginliğin sembolü olan kişi.","kategori":"dil","misal":"Hakikatte Kârûn Mûsâ’nın (aleyhisselâm) kavminden idi. Fakat onlara karşı azgın-lık etti. Biz ona öyle hazineler vermiştik ki onların anahtarları(nı taşımak) dahi güç sa-hibi bir topluluğa ağır gelirdi. Hani kavmi ona şöyle demişti: “Şımarma, çünki Allah şımaranları sevmez. Allah’ın sana verdiği ile âhiret yurdunu ara! Dünyadan da na-sibini unutma! Allah sana ihsan ettiği gibi sen de ihsan et! Yeryüzünde de fesat isteme. Çünki Allah fesat çıkaranları sevmez.” Dedi ki: “Bu bana ancak bende olan bir ilim dola-yısıyla verilmiştir.” O bilmedi mi ki şüphe-siz Allah, ondan önce kuvvetçe kendisinden daha güçlü, topladıkları mal daha çok nice nesilleri helâk etmiştir? Suçlulara günahları sorulmaz. Derken ziyneti içinde kavminin karşısına çıktı. Dünya hayatını isteyenler dediler ki: “Keşke Karun’a verilen gibi, bize de verilseydi. Gerçekten de o büyük bir na-sip sahibidir.” Kendilerine ilim verilenler ise dediler ki: “Vah size! İman edip sâlih amel işleyenler için Allah’ın sevabı daha hayırlı-dır. Ona da ancak sabredenler kavuşturu-lur.” Sonra Biz, onu da evini de yere geçir-dik. Allah’a karşı kimse ona yardım edemedi. Dün onun yerinde olmayı temenni edenler, sabah şöyle diyorlardı: “Vay, demek ki Al-lah kullarından dilediğine rızkı genişletir ve daraltır! Eğer Allah bize lütfetmeseydi, bizi de elbette yere geçirirdi. Vay, demek ki kâ-firler ıslah olmazlar!” (Kasas sûresi: 76-82) Kârûn, Mûsâ aleyhisselâmın ümmetinden ve akrabâsından idi. Ondan kimyâ öğrenerek, çok mal mülk sahibi oldu. Tevrat’ı pek iyi okurdu. Fakîr iken iyi huylu idi. Zengin olunca kibirli oldu. Emrolunan zekâtı vermedi. Mûsâ be-nimle zinâ etti demesi için bir kadına iki kese altın verdi. Kadın, herkesin arasında, Allah’tan korkarak doğruyu söyledi. Kârûn, bütün malı ile yere battı. (Tefsir-i Kurtubî)","osmanli":"قارون"},{"kelime":"KARZ","anlam":"Borç, kredi, ödünç akdi.","kategori":"muamelat","osmanli":"قرض"},{"kelime":"KARZ-I HASEN","anlam":"Mislî (çarşıda benzeri bulunan) bir şeyi, bir zaman sonra, benzerini geri ödemek üzere Allah rızası için birine verme.","kategori":"muamelat","misal":"Verdiğinin kat kat fazlasını kendisine ödemesi için Allahü teâlâya kim karz-ı hasen verir? (Bakara sûresi: 245) Bir adam Cennet’e girince, Cennet kapısının üstünde; “Sadaka veren, on katını alır; karz-ı hasen veren de verdiğinin on sekiz katını alır” yazısını görür. (Hadîs-i şerîfMüsnedü İmâm-ı Ahmed) Karz-ı hasen verirken; şu gün ödeyeceksin şeklinde zaman tâyin etmemeli. Çünki zaman tâyin ederse, malı, misli yani…","osmanli":"حسن قرض"},{"kelime":"KASABÂT","anlam":"1.Akciğer nefes boruları. 2.Kasaba’nın çokluk hâli.","kategori":"dil","osmanli":"قصبات"},{"kelime":"KASAS","anlam":"1.Bildirme, anlatma, hikâye etme. 2.İz sürme.","kategori":"dil","osmanli":"قصص"},{"kelime":"KASÂS","anlam":"Kıssalar, hikâyeler.","kategori":"dil","osmanli":"قصاص"},{"kelime":"KASAS SûRESİ","anlam":"Kur’ân-ı kerî-min yirmi sekizinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Seksen sekiz âyet-i kerî-medir. Mûsâ aleyhisselâmın kıssası geniş şe-kilde bildirildiği için sûreye Sûretü’l-Kasas denilmiştir. Ayrıca Mûsâ aleyhisselâmın ço-cukluğundan îtibâren hayâtı, mücâdeleleri, tevhîd ehlinin zaferi ve dünya servetine gü-venilmemesi bildirilmektedir. (Tefsir-i Maz-harî, Taberî, Mefâtihü’l-Gayb) Kim Kasas sûresini okursa, Mûsâ aleyhis-selâmı tasdik (kabul) ve tekzîb (inkâr) eden-lerin adedince ona sevab verilir. Gökte ve yerde hiçbir melek yoktur ki, kıyâmet günü onun sâdıklardan olduğuna şâhid olmasın. (Hadîs-i şerîf-Beydâvî)","osmanli":"سى سوره قصص"},{"kelime":"KASEM","anlam":"Yemîn. (Bkz. Yemîn)","kategori":"dil","osmanli":"قسم"},{"kelime":"KÂSÎ","anlam":"Kasvetli; sıkıntılı, duygusuz.","kategori":"dil","osmanli":"قاسى"},{"kelime":"KÂSİD","anlam":"Kesâda uğramış, işlemez, revâç-sız, kıymetsiz; çarşıda pazarda geçmez olan para. (Bkz. Kesâd)","kategori":"dil","osmanli":"كاسد"},{"kelime":"KASÎDE","anlam":"En az 15 beyitlik ve bütün beyitlerin ikinci mısra’ları en başta bulunan mısra’ ile kâfiyeli bulunmak üzere daha çok medhiye tarzında yazılan manzume.","kategori":"muamelat","osmanli":"قصيده"},{"kelime":"KASÎDE-İ BÜRDE","anlam":"“Hırka kasîdesi” mânâsına meşhur velî Busayrî’nin Hazret-i Peygamber için yazdığı ve rüyada huzurlarında okuyup mükâfat olarak sırtına bürde-i saadetini koyduğu için bu isimle anılan; bereketiyle Busayrî’nin felçten kurtulmasına sebeb olduğu için Kasîde-i Bür…","kategori":"akaid","misal":"Kasîde-i Bürde’den bazı beytlerin tercümesi şöyledir: Hazret-i Muhammed’in kerem yağmurlarından, Bir damla olmak ister, bilcümle peygamberân. Zâhirî ve bâtınî, rûhânî ve cismânî, Varlıkların hepsinden odur Hakk’a sevgili. Hudutsuzdur zâtının fazîlet ve kemâli, Mümkün değil anlatmak dil ile kemâlini.","osmanli":"برده قصيدهء"},{"kelime":"KASÎDE-İ EMÂLÎ","anlam":"“İmlâ etti-rilen (söyleyip yazdırılan) kasîde” mânâsına 575 (m. 1180) senesinde vefât eden Ferga-nalı âlim Ali Ûşî tarafından yazılan ve İslâm inançlarını 67 beyitte manzum olarak anlatan meşhûr kasîde. Bedü’l-Emâlî.","kategori":"dil","misal":"Kasîde-i Emâlî’nin beytlerinden bazısının Türkçe tercümesi şöyledir: Mevlâmız mahlûkların ilâhıdır biliniz. Kemâl sıfatlarla muttasıftır Rabbimiz. Münezzehtir Rabbimiz, hanımdan hizmetçiden, Oğlu ve kızı yoktur, berîdir her birinden. Cennet ile Cehennem ebedî olacaktır. İçlerinde olanlar devamlı kalacaktır. Îmândan sayılmazlar bütün hayırlı işler, İbâdetler îmânın parçası değildirler. Ehl-i sünnet üzere tevhîd hakkında yazdım, Fevkalâde bal gibi te’sirli oldu nazmım. Bu nazm mü’min kalblere rahatlık, neş’e verir, Âb-ı zülâl gibidir, ruhlara hayât verir.","osmanli":"امالى قصيدهء"},{"kelime":"KÂŞİF","anlam":"Keşfeden, bulan, meydana çıkaran.","kategori":"dil","osmanli":"كاشف"},{"kelime":"KASR","anlam":"1.Kısaltma. 2.Saray.","kategori":"dil","osmanli":"قصر"},{"kelime":"KAT‘","anlam":"Kesmek.","kategori":"dil","osmanli":"قطع"},{"kelime":"Kat‘î Delîl","anlam":"1.Bir işin neticesini ve bir hâdisenin aslını açık ve doğru bir şekilde gösteren şey, beyyine, burhan-ı kat’î. 2.Açık anlaşılan muhkem âyetler, tevâtürle bildirilen mânâsı açık hadîsler ve açık icmâ ile bildirilen hükümler.","kategori":"dil","osmanli":"دليل قطعى"},{"kelime":"Kat‘-ı Rahm","anlam":"Sıla-i rahmi, yani ak-rabâ ile görüşmeyi kesme.","kategori":"dil","misal":"İçlerinde kat‘-i rahm edenin bulunduğu bir kavme rahmet inmez. (Hadîs-i şerîf-İbn-i Neccâr) Kat‘-ı rahm, büyük günahtır. Erkek olsun, ka-dın olsun zî rahm-i mahrem (nikâhı haram olan) akrabâyı ziyaret etmek vâcibdir. (Hadîka)","osmanli":"رحم قطع"},{"kelime":"KÂTI‘-İ TARÎK","anlam":"Yol kesici; silah kuvveti ile şehirde veya şehirler arası yolları kesip yolculara saldıran kişi. Eşkıyâ.","kategori":"dil","misal":"Kâtı‘-i tarîk, mal soymadan ve can kaybı yap-madan ele geçerse, dövülür ve tövbe hâli görü-lünceye veya ölünceye kadar hapsolunur. Eğer sirkat (hırsızlık) nisâbı kadar mal soymuş ise, had cezâsı olarak sağ eli ile sol ayağı veya ters-leri kesilir. Eğer mal almayıp, insan öldürdü-ler ise, had cezâsı olarak öldürülür. Hem nisâb mikdarı mal almış, hem de adam öldürmüş ise, asılarak öldürülür. (İbni Âbidîn)","osmanli":"طريق قاطع"},{"kelime":"Kâtı‘-i Tarîk-i İlâhî","anlam":"“İlahî yolun kesicisi” mânâsına insanların hidâye-tine engel olan.","kategori":"dil","misal":"İnsanların îmân etmesine, İslâmiyet’i öğrenme-lerine ve İslâmiyet’e uymalarına mâni olan din düşmanları kâtı´-i tarîk-i ilâhîdirler. Din bil-gilerinde hakîkî âlimlerin bildirdiklerine tâbi olmayan ve kendi akıllarına ve keyflerine göre hüküm veren sapık din adamları, kâtı-ı tarîk-ı ilâhîdirler. (Mektûbât-ı İmâm-ı Rabbânî) Tasavvufta yetişmemiş, kemâle ermemiş ve ken-disine mürşid ismini ve süsünü veren sahte tarî-katçılar kâtı´-i tarîk-i ilâhîdirler. Onların sohbet-leri öldürücü zehirdir. (Mektûbât-ı Ma’sûmiyye)","osmanli":"الهى طريق قاطع"},{"kelime":"KÂTİB","anlam":"Kitâbet ehli, yazı ustası; yazı yazan, yazıcı.","kategori":"dil","osmanli":"كاتب"},{"kelime":"KÂTİL","anlam":"Katleden, insan öldüren. Kâtil, öldürdüğü şahsın malına vâris olamaz. (Hadîs-i şerîf-Ebû Dâvûd, Tirmizî, Nesâî, Dâ-rekutnî, Beyhekî)","kategori":"hadis","osmanli":"قاتل"},{"kelime":"KATL","anlam":"İnsan öldürme.","kategori":"dil","misal":"(Kısas ve zinâ gibi şeylerden dolayı meşrû) bir hak olmadıkça, Allah’ın haram ettiği cânı katl etmeyin... (En’âm sûresi: 151) Katl, ekber-i kebâirdendir (büyük günahlar). (Ha-dîs-i şerîf-Buhârî) Beş türlü katl haramdır: 1) Amden, bilerek, is-teyerek katl; 2) Şebeh-i âmd olan, yani amd ile öldürmeye benzeyen katl; 3) Hata ile, yanlışla katl; (ki bu da ya kâtilin yanılması veya mer-minin sapması iledir); 4) Hatâya sebeb olan şeyle katl; 5) Tesebbüben katl (başka niyet ile yapılan şeyin ölüme sebeb olması). Amden kat-lin cezâsı kısâstır. Vârisi diyete râzı olursa veya affederse kısâs düşer. Diğerlerinde diyet ve kef-fâret cezâsı vardır. (İbni Âbidîn)","osmanli":"قتل"},{"kelime":"Katl Keffâreti","anlam":"Taammüden katl hâricindeki adam öldürme suçlarında diyete ilâveten kâtile verilen bir köle âzâdı, buna kâdir olamazsa altmış gün arka arkaya oruç tutma cezâsı.","kategori":"ibadet","misal":"Keffâret-i Katl.","osmanli":"كفارتى قتل"},{"kelime":"KATMER","anlam":"Kat kat, yapraklı; çok fazla. Bir kimse, Allahü teâlânın lutfüne, ihsânına ka-vuşarak, katmerli câhilliğinden ve yanlış inan-cından kurtulursa, kendinde bulunan iyiliklerin, güzelliklerin, kendi malı olmadığını, başka yer-den geldiklerini, bunların varlıkta kalmalarına","kategori":"akaid","misal":"kendisinin sebeb olmadığını anlar. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قاتمر"},{"kelime":"KATOLİK","anlam":"“Cihanşümul, üniversel” mânâsına Roma kilisesi için kullanılan tabir; Roma patriği olan Papa’yı rûhânî lider olarak tanıyan ve Roma kilisesinin prensiplerini inanç sistemi kabul eden kimse.","kategori":"akaid","osmanli":"قاتوليك"},{"kelime":"KATRE","anlam":"Damla, damlayan şey.","kategori":"dil","misal":"Yâ Rabbî! Bu nasıl iştir ki, kendin için evliyâ yaptın. Onların bâtınları, yani kalbleri âb-ı hayâttır. Bir katre tadan, ebedî hayatı bulmuş, saadet-i ebediyyeye kavuşmuş olur. (Menâkıb ve Makâmât-i Ahmediyye-i Saîdiyye)","osmanli":"قطره"},{"kelime":"KAVÂ‘İD","anlam":"1.Kâide’nin çokluk hâli, kâideler, usûller. 2.Gramer, dilbilgisi.","kategori":"fikih","osmanli":"قواعد"},{"kelime":"KAVÂNÎN","anlam":"Kânûnlar. Kânûn’un çok-luk hâli.","kategori":"dil","osmanli":"قوانين"},{"kelime":"KAVED","anlam":"Amden katlde kâtilin kısas ola-rak öldürülmesi. (Bkz. Kısas)","kategori":"dil","misal":"Kaved, yalnız kılınç ile veya (acı vermeden en seri öldüren) silah ile yapılır. Başka dürlü öl-dürmek câiz değildir. (İbni Âbidîn)","osmanli":"قاود"},{"kelime":"KAVL (Kavil)","anlam":"1.Söz. 2.Anlaşma. 3.Rey, görüş, ictihad.","kategori":"fikih","misal":"Hanefî müftîler, İmâm-ı A’zâm Ebû Hanîfe’nin kavli ile hareket etmelidir. Onun kavli bulunmazsa, İmâm Ebû Yûsuf ’a uymalıdır. Bundan sonra, İmâm Muhammed’in kavli ile amel olunur. İmâm Ebû Yûsuf ile İmâm Muhammed’in kavli bir tarafta, İmâm-ı A’zâm’ın kavli karşı tarafta ise, müftî her iki tarafa göre fetvâ verebilir. (İbni Âbidîn)","osmanli":"قول"},{"kelime":"KAVLÎ","anlam":"Kavl (söz) ile alâkalı, söz ola-rak, sözde, fiilî olmayan.","kategori":"dil","osmanli":"قولى"},{"kelime":"KAVM","anlam":"Aynı soydan gelen insanlar, ırk. Rabbin zengindir, rahmet sahibidir. Dilerse sizi yok eder ve sizi başka bir kavmin zür-riyetinden yarattığı gibi sizden sonra yeri-nize dilediği bir kavmi yaratır. (En’âm sûresi:","kategori":"dil","misal":"133) (Ey Mekke!) Senden güzel ve benim için daha sevgili bir şehir yoktur. Kavmim beni senden çıkarmasaydı, başka bir yerde yer-leşmezdim. (Hadîs-i şerîf-Tirmizî)","osmanli":"قوم"},{"kelime":"KAVME","anlam":"Rükû’dan kalkarak dikilip durmak.","kategori":"ibadet","misal":"Kavme ve celsede ta’dil-i erkân (sübhanallah diyecek kadar durmak) dahi vâcibdir. Unutarak terki, secde-i sehv gerektirir. Rükû’, sücûd, kavme ve celsede ta’dil-i erkân ve tümânînet (uzuvlar hareketsiz hâle gelip bir tesbih mikdarı durmak) vâcibdir. Bu ikisine farz veya sünnet diyenler de olmuştur. (İbni Âbidîn) Peygamber efendimiz, bir gün Eshâb-ı kirâmına; “Hırsızların büyüğü kimdir bilir misiniz?” buyurdu. “Bilmi…","osmanli":"قومه"},{"kelime":"KAVMİYYET","anlam":"Irkçılık, asabiyye. Kavmiyyetçilik dâvâsı güden bizden değil-dir. Kavmiyyet için savaşan bizden değildir. Kavmiyyet üzere ölen bizden değildir. (Ha-dîs-i şerîf-Müslim, Ebû Dâvûd, İbn-i Mâce)","kategori":"dil","osmanli":"قوميت"},{"kelime":"KAVS","anlam":"Yay.","kategori":"dil","osmanli":"قوس"},{"kelime":"KAY’","anlam":"Kusma, gaseyân, istifrâğ.","kategori":"dil","misal":"Az olup yayılmayan derideki kan ve ağızda hâsıl olup, ağız dolusu olmayan kan ve dışarı çıkan az kay, abdesti bozmadıkları için, necs değildirler. (Halebî)","osmanli":"قىء"},{"kelime":"KAYD (Kayıt)","anlam":"Bağ, şart.","kategori":"fikih","osmanli":"قيد"},{"kelime":"KAYDSIZ (Kayıtsız)","anlam":"Bağsız, şartsız, bilâkayd; aldırmaz, lâkayd, alâkasız.","kategori":"fikih","osmanli":"قيدسز"},{"kelime":"KAYSER","anlam":"Eski Roma imparatorları-nın lâkabı, sezar, kayzer.","kategori":"dil","misal":"Ümmetimden kayserin şehrine (Kostanta-niyye) gazâya giden ilk asker mağfiret olun-muştur. (Hadîs-i şerîf-Buhârî)","osmanli":"قيصر"},{"kelime":"KAYYIM","anlam":"1.Ayakta duran, ayakta tutan. 2.Yaş küçüklüğü, dâvâ mevzuu olma gibi hukukî bir sebeble bir malın idaresini veya bir işin yapılmasını üzerine alan. 3.Câmi ve mescidlerin hademesi.","kategori":"hadis","misal":"İlim, mü’minin dostudur. Akıl, delili; amel, kayyımıdır. (Hadîs-i şerîf-Deylemî) Allah bir kulu sevdiğinde, mescide kayyım eder; sevmezse hamama hizmetçi eder. (Ha-dîs-i şerîf-İbni Neccâr)","osmanli":"قيم"},{"kelime":"KAYYûM","anlam":"Yaratıcı ve mahlûkları yerle-rinde ve varlıkta durdurucu; kıyâm binefsihi","kategori":"tasavvuf","misal":"(varlığı kendi zâtı sayesinde olma) sıfatının sahibi, ezelî ve ebedî olan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Kayyûm). O, kendinden başka ilâh bulunmayan Al-lahü teâlâdır. Hayy ve Kayyûm’dur. (Ba-kara sûresi: 255) Her gün on altı defâ tenhâ bir yerde el-Kayyûm ism-i şerîfi ahmağa okunursa, Allahü teâlânın izniyle ahmaklığı gider, hâfızası kuvvetlenir. (El-İstigâsetü’l-Kübrâ)","osmanli":"قيوم"},{"kelime":"Kayyûm-i Âlem","anlam":"Kayyûmiyyet makamında bulunan velî zât.","kategori":"tasavvuf","misal":"Kutb-ı irşâd, kayyûm-ı âlemdir. Îmân sahibi olmak, hidâyete kavuşmak, ibâdet yapabilmek, günahlara tövbe edebilmek kutb-i irşâdın feyzleri ile olur. Kayyûm-ı âlem olan ârif, bir asırda birden çok olmaz. Belki uzun asırlardan, devirlerden sonra zuhûr eder. (Mektûbât-ı Ma’sûmiyye)","osmanli":"عالم قيوم"},{"kelime":"KAYYûMİYYET","anlam":"1.Ayakta tutucu olma. 2.İnsanların âhiret işleri, derece ve sa-adetleri imdadına tevdi edilmiş olma mânâ-sına gelen tasavvufî tabir.","kategori":"akaid","osmanli":"قيوميت"},{"kelime":"KAZÂ","anlam":"1.Vuku bulacağı ezelde Cenâb-ı Hak tarafından irade ve takdir buyrulan şeylerin zamanı gelince bu iradeye muvafık olarak meydana gelmesi. Anayababaya ihsan, ömrü artırır. Yalan, rızkı azaltır. Duâ, kazâyı geri çevirir. (Hadîs-i şerîfHennâd) Kazâ, kaderin husûsî bir kısmıdır. Kader, anbara doldurulmuş buğday gibidir. Kazâ ise, onu ölçerek vermek gibidir. Ömer radıyallahü anh, Şâm’a geldi. Şehrde vebâ hastalığı olduğunu işitince, şehre girmedi. “Allahü teâlânın kazâsından kaçıyor musun?” dediklerinde; “Allahü teâlânın kazâsından, kaderine kaçıyorum” buy…","kategori":"akaid","osmanli":"قضاء","alternatif":["kaza"]},{"kelime":"Kazâ-i Muallak","anlam":"Zamana ta’lik edilmiş (bağlanmış) kazâ.","kategori":"akaid","misal":"yaratılmasını şarta bağlı olarak takdîr ettiği ve şart meydana gelince yarattığı şeyler. Kazâ, iki kısımdır. Kazâ-i muallak, kazâ-i mübrem. Birincisi şarta bağlı olarak yaratılacak şeylerdir ki, bunların yaratılma şekli değişebilir veya hiç yaratılmaz. Kazâ-i muallak da iki kısımdır. Birincisinin bağlı olduğu sebebler Levh-i Mahfûz’da gösterilmiş, meleklere bildirilmiştir. İkincisinin sebeblerini ancak Allahü teâlâ…","osmanli":"معلق قضاء"},{"kelime":"Kazâ-i Mübrem","anlam":"29.âyet-i kerîmesi kazâ-i mübremi bildirmektedir.","kategori":"akaid","misal":"İbrâm olunmuş (kat’ileşmiş) kazâ. Allahü teâlânın şarta bağlı olmaksızın yaratılmasını takdîr ettiği, yaratıl-ması muhakkak olan şeyler. Kazâ, yani Allahü teâlânın yarattığı şeyler iki kısımdır: Kazâ-i muallak, kazâ-i mübrem. Kazâ-i mübrem hiçbir zaman değişmez. Mu-hakkak yaratılır. Kaf sûresinin “Sözümüz de-ğiştirilmez” meâlindeki (Mektûbât-ı İmâm-ı Rabbânî) Necmeddîn Kübrâ hazretleri, 618 (m. 1221) yı-lında Harezm’e Cengiz askeri Tatarlar hücum edince, talebelerine; “Memleketinize gidiniz. Şarktan fitne ateşi geliyor. Her tarafı yakacak-tır. İslâm târihinde bu kadar fitne görülmemiş-tir” buyurdu. Talebeleri; “Duâ buyurun da bu belâ Müslüman memleketlerinden uzaklaşsın” deyince; “Bu, kazâ-i mübremdir. Duâ bunu gi-dermez” buyurdu. (Molla Câmî)","osmanli":"مبرم قضاء"},{"kelime":"Kazâ Orucu","anlam":"Vaktinde tutulmayan veya tutulamayan Ramazan orucunu, Ramazan ayından sonra gününe gün tutmak.","kategori":"ibadet","misal":"Kazâ orucu arka arkaya olduğu gibi ayrı ayrı günlerde de tutulabilir. Hastalık veya ihtiyarlık sebebiyle orucunu tutamayıp fidye veren kimse, daha sonra kuvvetlenir veya sağlığına kavuşursa, Ramazan oruçlarını ve tutamadığı oruçlarını tutar. (İbni Âbidîn)","osmanli":"اوروجى قضا","alternatif":["kaza"]},{"kelime":"Kazâ ve Kader","anlam":"Allahü teâlânın meydana gelecek hâdiseleri ilm-i ezelîsi ile ezelde bilip takdîr etmesi ve zamanı gelince bu hâdiseleri yaratması.","kategori":"akaid","misal":"Allahü teâlâ buyurdu ki: “Bir kimse benim kazâ ve kaderime râzı olmazsa, benden başka Rab arasın!” (Hadîs-i şerîfBeyhekî) Îmânın şartlarından biri de kazâ ve kadere hayr ve şerrin Allahü teâlâdan geldiğine inanmaktır. (İtikadnâme)","osmanli":"وقدر قضا","alternatif":["kaza"]},{"kelime":"KAZÂRÂ","anlam":"Kazâ olarak, kazâ suretiyle, bilmeyerek, yanlışlıkla, elden çıkarak.","kategori":"akaid","misal":"Ezkazâ. Kazâen.","osmanli":"قضارا"},{"kelime":"KAZF","anlam":"1.Fırlatmak, atmak. 2.İffetli erkek veya kadına zinâ isnâd etmek.","kategori":"hadis","misal":"İffetli Müslüman kadınlara kazf edip sonra dört şâhit getiremeyenlere seksen değnek vurun. Bunların şâhidliklerini ebediyyen kabul etmeyin. Bunlar asıl fâsıklardır. (Nûr sûresi: 4) İnsanı tehlikeye düşüren yedi şeyden sakının. Allahü teâlâya şirk koşmak, sihirle uğraşmak, haksız yere adam öldürmek, fâiz yemek, yetim malı yemek, harbde düşmandan kaçmak ve muhsan (nâmuslu) Müslüman kadınlara kazf etmek. (Hadîs-i şerîf…","osmanli":"قذف"},{"kelime":"Kazf Haddi","anlam":"Erkek veya kadına zînâ isnâd edip ispat edemeyenlere verilen cezâ.","kategori":"hadis","misal":"Kazf edilen kimsenin talebi üzerine, kazf edene seksen sopa vurulur. (İbni Âbidîn)","osmanli":"حدى قذف"},{"kelime":"KÂZİB","anlam":"1.Kezbeden, yalan söyleyen, yalancı. 2.Yalan, uydurma.","kategori":"dil","misal":"Sabah namazının vakti için muteber olan fecr-i sâdıktır. Fecr-i sâdık, ufukta yayılan, yani ziyâsı gökyüzüne dağılan fecrdir. Fecr-i kâzib, mute-ber değildir. Fecr-i kâzib, gökyüzünde kurd kuy-ruğu gibi uzayan fecrdir. Ondan sonra yine ka-ranlık basar. (İbni Âbidîn)","osmanli":"كاذب"},{"kelime":"KÂZM","anlam":"Gadabını, öfkesini yenme.","kategori":"tasavvuf","misal":"O takvâ sahipleri ki, bollukta da darlıkta da Allah için harcarlar; kâzm ederler (öfkele-rini yenerler) ve insanları affederler. Allah ih-sân sahiplerini sever. (Âl-i İmrân sûresi: 134)","osmanli":"كظم"},{"kelime":"KÂZûRAT","anlam":"Kazûre’nin çokluk hâli, pislik, murdârlık; insan pisliği.","kategori":"dil","osmanli":"قاذورات"},{"kelime":"KAZZÂZ","anlam":"İpekçi.","kategori":"dil","osmanli":"قزاز"},{"kelime":"KEBÂB","anlam":"Doğrudan doğruya ateşte veya kap içerisinde pişirilen et veya herhangi bir nesne, kebap.","kategori":"dil","osmanli":"كباب"},{"kelime":"KEBÂİR","anlam":"Büyük günahlar. Kebîre’nin çokluk hâli.","kategori":"dil","misal":"Kebîre sahibi îmândan çıkmaz. Kebîre sahi-binin hâli Allahü teâlânın irâdesine kalmıştır. Dilerse bağışlar, dilerse azap eder. (Mektûbât-ı İmâm-ı Rabbânî) Büyük günah işleyenin îmânı gitmez. Harama helâl derse, îmânı gider. Günahlar ikiye ayrılır: Kebâir, büyük günahlardır. Meselâ: 1) Bir şeyi Allahü teâlâya ortak etmek. Buna şirk denir. Şirk, küfrün en kötüsüdür. 2) Bir insanı veya kendini öldürmek. 3) Sihir yani büyü yapmak. 4) Yetim malı yemek. 5) Fâiz alıp vermek. 6) Muhârebede düşman karşısından kaçmak. 7) Temiz kadınları kazf etmek, yani nâmussuz de-mek. Her günahın büyük olmak ihtimâli vardır. Hepsinden kaçınmak lâzımdır. (Şerh-i Mevâkıf)","osmanli":"كبائر"},{"kelime":"KEBED","anlam":"Karaciğer.","kategori":"dil","osmanli":"كبد"},{"kelime":"KEBÎR","anlam":"Büyük. Allahü teâlânın Esmâ-i hüsnâsından (elKebîr).","kategori":"akaid","misal":"O’ndan (Allah’tan) başka taptıkları hiç şüphesiz bâtıldır, yok olucudur. Şüphesiz Allahü teâlâ yücedir, elKebîr’dir. (Lokmân sûresi: 30) ElKebîr ism-i şerîfini söyleyene, ilim ve mârifet kapısı açılır. (Elİstigâsetü’l-Kübrâ)","osmanli":"كبير"},{"kelime":"KEBÎRE","anlam":"Büyük günah.","kategori":"dil","osmanli":"كبيره"},{"kelime":"KEDER","anlam":"1.Bulanıklık. 2.Tasa, kaygı, gö-nül üzüntüsü, gamm, gussa.","kategori":"dil","misal":"Kim kadere iman ederse, kederden emin olur. (Hadîs-i şerîf-Hâkim)","osmanli":"كدر"},{"kelime":"KEFÂET","anlam":"1.Küfv olma, denklik, bir şeye yeter ve denk olma. 2.Erkeğin dinî, ikti-sadî ve ictimaî bakımdan evleneceği kıza denk veya üstün olması.","kategori":"dil","misal":"Kefâet, evlenecek erkeğin altı şeyde kadından üstün veya müsâvî olmasıdır. Bunlar sanat, ser-vet, nesep, hürriyet, din ve diyânettir. Küfvü ol-mayan erkek ile nikâhlanan kızın velîsi, nikâhı feshettirebilir. (Ni’met-i İslâm)","osmanli":"كفائت"},{"kelime":"KEFÂLET","anlam":"Kefillik, kefîl olmak; bir kimsenin, borcunu ödememesi veya taahhüdünü yerine getirmemesi hâlinde mes’û-liyeti üstlenme.","kategori":"muamelat","misal":"Kefâletin ihtivâ ettiği birçok güzel taraflar vardır. Bunlardan birisi, malının zâyi olacağı korkusunda bulunan alacaklı kişinin bu düşüncesini ondan atma; diğeri ödeyemediği takdirde şahsına bir zarar geleceği korkusu taşıyan borçlunun bu korkusunu gidermektir. Bu da her iki taraf için bir nimettir. Kefâlet, âlicenâblığın gereğidir. (Fethü’l-Kadîr) Kısas ve diğer şahsî cezâlara kefâlet sahih değildir. Amma diyete k…","osmanli":"كفالت"},{"kelime":"KEFEN","anlam":"Vefât eden kimsenin yıkandık-tan sonra sarılarak defnedildiği bez parçaları. Kefeni güzel yapınız; çünki ölü kefeniyle haş-rolunur. (Hadîs-i şerîf-Müslim, Ebû Dâvûd, Tirmizî, Nesaî, İbn-i Mâce, Hatîb)","kategori":"hadis","misal":"Kefen, erkek için üç, kadın için beş parçadır. Er-keğin kefeni; izâr (genişliği bir metreden fazla baştan ayağa kadar olan bez parçası), kamîs (entâri gibi uzun gömlek) ve lifâfe (başı ve ayak-ları geçecek uzunlukta, baş üstünden ve ayak altından uçları büzülüp bezle bağlanan kısım). Kadınların kefeni ise, kamîs, îzâr, lifâfe, himâr (baş örtüsü) ve göğüs bezidir. (Zeylâî)","osmanli":"كفن"},{"kelime":"Kefen-i Kifâye","anlam":"Fakir ve borçlular için erkeklere iki ve kadınlara üç parçadan ibaret kefen.","kategori":"muamelat","osmanli":"كفايه كفن"},{"kelime":"KEFFÂRET","anlam":"Örtmek. Bir günaha karşı tutulmak üzere yapılan şey, verilen sadaka veya tutulan oruç.","kategori":"ibadet","misal":"Kim kısas hakkından vazgeçerse bu, onun günahlarına keffâret olur. (Mâide sûresi: 45) Kim abdest alır da, abdestini güzel yapar, sonra yanılmadan ve abes şeyle meşgul olmadan namaz kılarsa, bu bundan önceki seyyiesine keffaret olur. (Hadîs-i şerîfMüsnedü İmâm-ı Ahmed). Kim ilim öğrenmeye çalışırsa bu onun geçmiş günahlarına keffaret olur. (Hadîs-i şerîfTirmizî) Keffâretler, bir bakımdan ibâdet, bir bakımdan cezâ vaz…","osmanli":"كفارت"},{"kelime":"Keffâret-i Yemîn","anlam":"Bir işi yapmak veya yapmamak hususunda Allahü teâlânın ismini söyleyerek yemîn eden kimsenin yemînini bozunca cezâ olarak yapması gerekli olan şey.","kategori":"akaid","misal":"Allah, kasıtsız olarak ağzınızdan çıkıveren yeminlerinizden dolayı sizi mes’ûl tutmaz; fakat bilerek yaptığınız yeminlerden dolayı mes’ûl tutar. Bunun da keffâreti, ailenize yedirdiğiniz yemeğin orta hâllisinden on fakire (sabahlı akşamlı) yedirmek, yâhud onları giydirmek, yâhud da bir köle azat etmektir. Bunları bulamayan üç gün oruç tutmalıdır. Keffâret-i yemîn işte budur. Yemînlerinize riayet edin. (Mâide sûresi:…","osmanli":"يمين كفارت"},{"kelime":"KEFÎL","anlam":"Kefâlet altına giren, başkasına ait bir işi veya borcu üzerine alan.","kategori":"muamelat","misal":"İçlerinden hangisi Meryem’i himâyesine alacak diye kur’a çekmek üzere kalemlerini atarlarken sen onların yanında değildin. (Âl-i İmrân sûresi: 44) Kefil, borçlu gibidir. (Hadîs-i şerîfTirmizî) Kefîle kefîl olmak sahîhtir. Alacaklı borcu üçünden de isteyebilir. (İbni Âbidîn)","osmanli":"كفيل"},{"kelime":"KEFÎR","anlam":"İnek ve deve sütlerinin ma-yalanmasından elde edilen alkollü bir içki.","kategori":"dil","misal":"Kısrak, inek ve deve sütleri mayalanıp tadı kes-kin olunca, müselles gibi olur. Birincisine kı-mız, diğer ikisine kefîr denir. Her ikisi de bira gibi haramdır. (Men-i Müskirat-İskilipli Âtıf)","osmanli":"كفير"},{"kelime":"KEHÂNET","anlam":"İleride olacak şeyleri ha-ber verme. Kâhinlik. (Bkz. Kâhin)","kategori":"dil","misal":"Hased, nemîme ve kehânet sahipleri, ben-den değildir. (Hadîs-i şerîf-Taberânî) Öğrenmesi harâm olan bilgilerden biri sihr ve kehânettir. (İbni Âbidîn)","osmanli":"كهانت"},{"kelime":"KEHF","anlam":"1.Mağara. 2.Sığınak, sığınacak yer.","kategori":"dil","osmanli":"كهف"},{"kelime":"KEHKEŞÂN","anlam":"Samanyolu.","kategori":"dil","osmanli":"كهكشان"},{"kelime":"KELÂM","anlam":"1.Söz, konuşmak, söylemek, tesir etmek. 2.Îmân ve i’tikâd bilgilerini delilleri ile anlatan ilim.","kategori":"akaid","misal":"Kelâm sıfatı basîttir. Hiç değişmez. Harfli, sesli değildir. Emir, yasak, haber vermek gibi ve Arabî, Fârisî, İbrânî ve Süryânî olmak gibi başkalaşması, parçalanması yoktur. Böyle şekiller almaz. (İtikadnâme) (Bkz. İlm-i Kelâm)","osmanli":"كلام"},{"kelime":"Kelâm-ı İlâhî","anlam":"Allahü teâlânın kelâmı; Kur’ân-ı kerîm.","kategori":"dil","misal":"Kelâm-ı ilâhî çeşitli şeyleri bildirir. Kıssaları yani olayları bildirirse haber olur. Böyle olmazsa inşâ olur. Yapılması lazım olan şeyleri bildirirse emir olur. Yasakları bildirirse nehy olur. (İtikadnâme) Allahü teâlâ Kur’ân-ı kerîmi harf ve kelime olarak gönderdi. Bu harfler mahlûktur (yaratılmıştır). Bu harf ve kelimelerin mânâsı kelâm-ı ilâhîyi taşımaktadır. Bu harflere kelimelere Kur’ân-ı kerîm denir. Kelâm-ı…","osmanli":"الهى كلام"},{"kelime":"Kelâm-ı Lafzî","anlam":"Kelâm-ı ilâhînin harf ve ses içinde bulunan hâli.","kategori":"akaid","osmanli":"لفظى كلام"},{"kelime":"Kelâm-ı Nefsî","anlam":"Kelâm-ı ilâhînin harf ve ses içine sokulmadan evvelki hâli.","kategori":"tasavvuf","misal":"Allahü teâlâ da ses zarları, ağız dil olmaksızın, kendi kelâmını, büyük kudreti ile, harf ve ses içinde kullarına göndermiştir. Emrlerini, nehylerini harf ve ses içinde meydâna çıkarmıştır. Her iki kelâm da O’nundur. Yani kelâm-ı nefsî ve kelâm-ı lafzîsi hep O’nun kelâmıdır. Her ikisine de kelâm demek doğrudur. Nitekim bizim de, nefsî ve lafzî kelâmımızın ikisi de, sözümüzdür. Nefsîye hakîkî deyip, lafzîye mecâz dem…","osmanli":"نفسى كلام"},{"kelime":"Kelâm İlmi","anlam":"","kategori":"akaid","misal":"Îmân ve i’tikâd bilgilerini delilleri ile anlatan ilim. İlm-i Kelâm.","osmanli":"علمى كلام"},{"kelime":"Kelâmullah","anlam":"“Allahü teâlânın sözü”","kategori":"akaid","misal":"mânâsına Kur’ân-ı kerîm âyetleri için kulla- nılan tabir.","osmanli":"الله كلام"},{"kelime":"KELB","anlam":"Köpek.","kategori":"dil","misal":"Şâfi’î’de kelbin yaladığı kap ve kılları yaş iken elbiseye veya başka şeye değerlerse, o şeyi altı kere temiz su ile ve bir kere topraklı su ile yıka-mak lâzımdır. Tabaklansa bile postu üzerinde namaz kılınmaz. (Misbâhu’n-Necât)","osmanli":"كلب"},{"kelime":"KELDÂNÎ","anlam":"1.İlkçağda merkezi Bâbil olan büyük bir devlet kurmuş olan Sâmî ırkından bir kavim. 2.Irak’ın kuzeyinde yaşayan ve Nasturî mezhebine mensub Hristiyanlar.","kategori":"dil","osmanli":"كلدانى"},{"kelime":"KELEF","anlam":"1.Yüzdeki benek, siyah veya kırmızı noktalar, çil. 2.Şiddetli sevgi.","kategori":"dil","osmanli":"كلف"},{"kelime":"KELİMÂT","anlam":"Kelime’nin çokluk hâli.","kategori":"dil","misal":"Hurûf ve kelimât-ı Kur’ân’ı yer değişmeksizin Allahü teâlânın kelâm-ı nefsîsidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"كلمات"},{"kelime":"KELİME","anlam":"1.Bir veya birkaç heceden meydana gelen mânâlı veya vazifeli, söz. 2.Lâkırdı. 3.Gramerde isim, fiil ve harf olarak üçe ayrılan söz kısımlarının hepsi.","kategori":"dil","misal":"Allahü teâlâ, Kur’ân-ı kerîmi, harf ve kelime olarak gönderdi. (Fethü’l-Kadîr)","osmanli":"كلمه"},{"kelime":"Kelime-i Şehâdet","anlam":"“Şâhidlik sözü” mânâsına İslâm’ın birinci şartı olan “Eşhedü en lâ ilâhe illallah ve eşhedü enne Muhammeden abduhu ve resûluh” (Görmüş gibi bilir ve inanırım ki, Allahü teâlâdan başka, varlığı lâzım olan, ibâdet ve itâ‘at olunmaya hakkı olan, hiç ilâh, hiçbir…","kategori":"akaid","misal":"sellem, Allahü teâlânın hem kulu, hem peygamberidir) sözü. İhlâs ile kelime-i şehâdet getiren Cennet’e girer. (Hadîs-i şerîfTaberânî) Kelime-i şehâdet söylemenin dört şartı vardır: Dil ile söylerken, kalb hazır olmak. Mânâsını bilmek. Hulûs-i kalb ile (ihlâsla) söylemek. Tâzîm ile söylemek. (Miftahü’l-Cenne)","osmanli":"شهادت كلمهء"},{"kelime":"Kelime-i Tayyibe","anlam":"“Hoş söz” mânâsına “Lâ ilâhe illallah, Muhammedün resûlullah” (Allahü teâlâdan başka ilâh yoktur; Muhammed aleyhisselâm O’nun peygamberidir) sözü.","kategori":"akaid","misal":"Kelime-i tayyibe bir sadakadır. Namaza gitmek için sahibinin attığı her adım da bir sadakadır. Yolda gelip geçene ezâ veren şeyleri gidermek de sadakadır. (Hadîs-i şerîfMüslim)","osmanli":"طيبه كلمهء"},{"kelime":"Kelime-i Tehlîl","anlam":"“Lâ ilâhe illallah” sözü.","kategori":"dil","misal":"(Bkz. Kelime-i Tevhîd, Tehlîl)","osmanli":"تهليل كلمهء"},{"kelime":"Kelime-i Temcîd","anlam":"“Yüceltme sözü” mânâsına “Lâ havle ve lâ kuvvete illâ billahil aliyyil azîm” (Güç ve kuvvet ancak Allahü teâlâdandır) sözü.","kategori":"akaid","misal":"İmâm-ı Rabbânî hazretleri, din ve dünya zararlarından kurtulmak için, her gün beş yüz kere Kelime-i temcîd okurdu. (Tefsir-i Mazharî) Korkulu zamanlarda ve cin çarpmasını def etmek için Kelime-i temcîd okuyunuz. (Mektûbât-ı İmâm-ı Rabbânî) Derdlerden kurtulmak ve murâda kavuşmak için; beş yüz kere Kelime-i temcîd ile, evvelinde ve âhirinde yüzer defâ salevât-ı şerîfe (Allahümme salli alâ seyyidinâ Muhammedin ve alâ…","osmanli":"تمجيد كلمهء"},{"kelime":"Kelime-i Tenzîh","anlam":"“Nezih kılma kelimesi” mânâsına Allahü teâlânın her türlü noksan sıfatlardan uzak ve temiz olduğunu ifâde eden “Sübhânallah” sözü.","kategori":"akaid","misal":"İstigfâr etmek, günahların örtülmesini istemektir. Kelime-i tenzîhi okumak, günahların yok olmasını istemektir. O nerede, bu nerede? Sübhânallah şaşılacak bir kelimedir. Söylemesi çok kısadır. Ma’nâları ve fâideleri ise pek çoktur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تنـزيه كلمهء"},{"kelime":"Kelime-i Tevhîd","anlam":"“Birleme kelimesi” mânâsına “Lâ ilâhe illallah, Muhammedün Resûlullah” (Allahü teâlâdan başka ilâh yoktur.","kategori":"akaid","misal":"Ölüm hâline gelene kelime-i tevhîdi telkîn edin. Kim bunu ölürken söylerse, Cennet ona vâcib olur. Nefsim yed-i kudretinde olana yemin ederim ki, semâvât, arz ve onlarda olanlar, arasındakiler ve altındakiler ve getirilseler, mîzânın (terazinin) bir kefesine konulsalar, kelime-i tevhîd diğer kefeye konulsa, muhakkak onlara ağır basardı. (Hadîs-i şerîfTaberânî) Her Müslümanın, kelime-i tevhîdin mânâsına hiç şüphe etm…","osmanli":"توحيد كلمهء"},{"kelime":"KEM","anlam":"1.Az, eksik, noksan. 2.Fena, kötü; bozuk.","kategori":"tasavvuf","osmanli":"كم"},{"kelime":"KEMÂL","anlam":"Olgunluk, mükemmellik, ek-siksiz olma, fazîlet.","kategori":"dil","misal":"İmanın kemâli, güzel ahlâk iledir. (Hadîs-i şerîf-Ebû Şeyh) Sünnetlerin farzları tamamlayacağından mak-sat; farzlar yapılırken bunların kemâllerine se-beb bir şey kaçırılırsa, sünnetler, kılınan farzın kemâl bulmasına sebeb olur. (Şerhu Fütû-hi’l-Gayb-Abdülhak Dehlevî) Ne sâl (yaş) iledir, ne mâl iledir, Beyim ululuk kemâl iledir. (Es’ad Muhlis Paşa)","osmanli":"كمال"},{"kelime":"Kemâl Sıfatları","anlam":"Allahü teâlânın zâtında ve işlerinde hiçbir kusur, karışıklık, değişiklik ve noksanlık olmadığını gösteren hayât, ilim, sem’ (işitmek), basar (görmek),","kategori":"akaid","misal":"kudret, irâde, kelâm (söylemek) ve tekvîn (yaratmak) sıfatları. Subûtî sıfatlar. Hakîkî sıfatlar. Kâmil sıfatlar. Allahü teâlânın kemâl sıfatları, Allahü teâlânın zâtı ile kâimdirler, yani ebedîdirler. Allahü teâlânın bu sıfatlarının künhü (hakîkati) anlaşılamaz. Çünki sonradan yaratılan, sınırlı, zamanlı ve mekânlı olan; mahlûk olmayanı, sınırsız, zamansız ve mekânsız olanı anlayamaz. (Âmentü ŞerhiKâdızâde) Her var…","osmanli":"صفتلرى كمال"},{"kelime":"KEMÂLÂT","anlam":"Kemâller, olgunluklar, fazîletler, ahlâk ve huy güzellikleri.","kategori":"tasavvuf","misal":"Allahü teâlâ evliyâ kullarını öyle saklamıştır ki, kendileri bile kalblerindeki kemâlâttan habersizdir. Nerede kaldı ki, başkaları onların hâlini bilsin. (Mektûbât-ı İmâm-ı Rabbânî) Kem âlât ile kemâlât olmaz! (Nâbî)","osmanli":"كمالات"},{"kelime":"Kemâlât-ı Nübüvvet","anlam":"Evliyâlığın çok yüksek sıfatlarından olup Peygamberliğe âit üstünlükleri bildirir.","kategori":"akaid","misal":"Bir müslüman, Allahü teâlânın ihsânı ile şeriatin hakikatine kavuşur, İslâm-ı hakîkî ile şereflenirse, Peygamberlere tam uyarak ve o büyüklere vâris olarak, kemâlât-i nübüvvet denilen makama kavuşabilir. Şeriatin sûreti, kemâlât-ı vilâyet meyvelerini meydâna getiren mübârek bir ağaç olduğu gibi, kemâlât-ı nübüvvet de, mübârek bir ağaç gibi olan şeriatin hakikatinin meyveleri gibidir. Vilâyet, sanki, namazın abdesti…","osmanli":"نبوت كمالات"},{"kelime":"Kemâlât-ı Vilâyet","anlam":"Evliyâlığa âit üstünlükler, olgunluklar.","kategori":"tasavvuf","misal":"Kemâlât-ı nübüvvet, kemâlât-ı vilâyetten çok üstündür. Kemâlât-ı vilâyetteki ilerleme, kemâlât-ı nübüvvetteki ilerlemenin bir sûreti, görünüşüdür. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ولايت كمالات"},{"kelime":"KEMÎNE","anlam":"1.Noksan, eksik. 2.Âciz, ha-kir; zavallı.","kategori":"dil","osmanli":"كمينه"},{"kelime":"KENZ","anlam":"1.Define, hazine; yeraltında saklı kalmış değerli eşya, para veya altın. 2.Malları üst üste yığıp stok etme.","kategori":"dil","misal":"Gizli bir kenz idim; bilinmeyi, tanınmayı sevdim. (Hadîs-i Kudsî-Kenz-i Mahfî) “Altınlarını, gümüşlerini kenz yapıp Allah yolunda dağıtmayanlara çok acı azap var-dır” meâlindeki âyet-i kerîme (Tevbe sûresi: 34) gelince, Resûlullah aleyhisselâm; “Zekât müs-lümanların mallarını temizlemek için em-rolundu. Zekâtı verilen mal kenz olmaz” bu-yurdu. (Ebû Dâvûd, Taberânî, Hâtib)","osmanli":"كنـز"},{"kelime":"KERÂHİYYET","anlam":"Mekrûhluk, mekrûh oluş; fıkıh kitaplarında yenilmesi, giyilmesi, yapılması uygun olan ve olmayan şeyleri bildiren kısım.","kategori":"fikih","osmanli":"كراهيت"},{"kelime":"KERÂMÂT","anlam":"Kerâmet’in çokluk hâli, ikramlar, üstünlükler; evliyadan hâsıl olan fevkalâde hâller.","kategori":"tasavvuf","osmanli":"كرامات"},{"kelime":"KERÂMET","anlam":"1.İkrâm, üstünlük, saygınlık. 2.Allahü teâlânın ikrâmı olarak sevgili kullarından (evliyâlardan) âdet (yani tabiat kanunları) dışında meydana gelen hâdiseler. Ehl-i sünnet itikadına göre evliyânın kerâmetleri haktır. Kerâmetin hak olduğunu inkâr eden bid‘at ehli olur. Bunlar hârikulâde olarak zuhur eder. Az müddette uzak yere varır. İhtiyaç zamanında yiyece…","kategori":"ibadet","misal":"Bir kimse başkalarıyla çekişirse, mürüvvetten düşer, kerâmeti gider. (Hadîs-i şerîfHâtib)","osmanli":"كرامت"},{"kelime":"KEREM","anlam":"Asalet, şereflilik; cömertlik, ihsan sahibi olma.","kategori":"tasavvuf","misal":"Allahü teâlâ öyle bir ihsân sahibidir ki, kerem ve ihsânlarını dost ve düşman herkese saçmaktadır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"كرم"},{"kelime":"KERHEN","anlam":"1.İğrenerek. 2.İstemeye-rek, hoşlanmayarak; zorla, zoraki, zorlanarak.","kategori":"muamelat","misal":"Sana borcum olan mehrini bana hediye etmez-sen, babanın evine hiç gidemezsin dese, zevcesi de hediye etse, sahîh olmaz. Çünki kerhen he-diye vermek sahîh olmaz. (Fetâvâ-yı Bezzâziyye)","osmanli":"كرهًا"},{"kelime":"KERÎH","anlam":"1.İğrenç; çirkin. 2.Pis kokan. 3.Mekrûh.","kategori":"dil","misal":"Kan alma ücretinin habîs olduğunu söyleyen-ler, insanların bunu kerîh görmesinden dolayı böyle söylemiştir. (İbni Âbidîn) Kokusu tabiatlar bakımından kerîh görüldüğü için tütün şer’an değil, ama taban mekrûhtur. (İbni Âbidîn) Peygamberimiz “sallallahü aleyhi ve sellem” Kur’ân-ı kerîm okurken, cenâze götürürken, harb ederken, va’z ederken bağırmağı kerîh gö-rürdü. (Ey Oğul İlmihâli) Resûlullah aleyhisselâm koyunun zeker, haya, ferc, bez, öd kesesi, sidik torbası ve kanını kerîh gördü. Bunun mânâsı tahrîmen mekrûhtur. (İbni Âbidîn)","osmanli":"كريه"},{"kelime":"KERÎM","anlam":"1.Kerem sahibi, şerefli, cömert. 2.Kudreti var iken affeden, va’d ettiğini yapan, lütf ve ihsânı ümit edilenin üstünde olan, ne kadar verdiğini ve kime verdiğini hesâb etmeyen, kendisine sığınanı koruyan ve isteyeni zenginleştiren mânâsına Allahü teâlânın Es-mâ-i hüsnâsından (elKerîm). Şükreden ancak kendisi için şükretmiş olur. Nankörlük eden ise bilsin ki Rabbim müstağnidir, kerîmdir. (Neml sûresi: 40) Allahü teâlâ kerimdir; affettikten sonra tek…","kategori":"tasavvuf","osmanli":"كريم"},{"kelime":"KERVÂN","anlam":"deve, at ve katırlarla kara nakliyatı yapan kafile. Aslı kârbân gelir.","kategori":"dil","osmanli":"كروان"},{"kelime":"KES","anlam":"Kimse, kişi, şahıs.","kategori":"dil","osmanli":"كس"},{"kelime":"KESÂD","anlam":"Paranın değerinin düşmesi; paranın geçmez olması; ticaretin durgunlaşması, arzın zayıflaması, kıtlık.","kategori":"muamelat","misal":"Maden ve kâğıt paralar kesâd olursa, İmâm Ebû Yûsuf ’a göre pazarlıktaki, İmâm Muhammed’e göre, revaçtan kalktığı zamandaki kıymeti verilir. Fetvâ İmâm Ebû Yûsuf kavline göredir. (İbni Âbidîn)","osmanli":"كساد"},{"kelime":"KESÂN","anlam":"Kimseler, kişiler, insanlar. (Kes’in çokluk hâli.)","kategori":"dil","osmanli":"كسان"},{"kelime":"KESB","anlam":"1.Kazanma, elde etme, kazanç. 2.İnsandaki seçme hareketi, istek, ihtiyâr.","kategori":"akaid","misal":"En üstün kesb yolu silahla ve kalemle cihâddır. İkincisi ticaret, üçüncüsü ziraat, dördüncüsü sanattır. Kesbin beşinci yolu hizmettir. (Kimyâ-i Seâdet) Allah her şahsı, ancak gücünün yettiği ölçüde mükellef kılar. Herkesin kesbettiği hayır kendine, kesbettiği şer de kendinedir. (Bakara sûresi: 286) Allahü teâlâ, insanları yarattığı gibi, insanların işlerini de yaratıyor. İ…","osmanli":"كسب"},{"kelime":"KESEL","anlam":"Tembellik, isteksizlik, gevşek-lik, uyuşukluk.","kategori":"dil","misal":"Yâ Rabbî! Beni keselden koru! (Hadîs-i şerîf-Buhârî, Müslim) Terk-i kesel, yani namazın fiillerini edâda üşen-mekliği terk etmek, namazın kemâli mertebe ka-bul olmasının şartlarındandır. (Miftahü’l-Cenne)","osmanli":"كسل"},{"kelime":"KESÎF","anlam":"1.Sık, tok.","kategori":"dil","misal":"(A. Kesâfet’den) Abdestte, kesîf sakalın üstünü yıkamak farz-dır. (İbni Âbidîn) Kalın, kaba, yoğun. Şeffaf (saydam) olmayan, katı. Hadîs-i şerîfler, peygamberlerin, Rableri ya-nında diri olduklarını gösteriyor. Onların ce-sedleri, ruhları gibi latîf olmuştur. Kesîf değildir. Madde ve ruh âleminde görünebilirler. (Min-hatü’l-Vehbiyye) Koyu. Kan gibi, kesîf necâsetin bir dirhem kadarı elbi-seye el ayasından fazla yayılırsa namaza mâni değildir. (İbni Âbidîn)","osmanli":"كثيف"},{"kelime":"KESÎR","anlam":"1.Çok çok olan, bol. 2.Sık olan, çok defa olan.","kategori":"dil","misal":"Amel-i kesîr namazı bozar (İbni Âbidîn)","osmanli":"كثير"},{"kelime":"KEŞİŞ","anlam":"Hristiyanlıkta dünyadan elini eteğini çekip manastırda yaşayan din adamı, derviş. Aslı Eski Arabca kıssîs (çok yaşlı) gelir.","kategori":"dil","osmanli":"كشيش"},{"kelime":"KEŞKEK","anlam":"Buğdayın iyice haşlanıp ezilmiş koyun etiyle karıştıralarak yapılan bir yemek. Herîse. Aslı Farsça kaşk-âb (arpa suyu) gelir. Cebrâil aleyhisselâm, kuvvet için keşkek ye-memi tavsiye etti. (Hadîs-i şerîf-Teshîlü’l-Menâfi)","kategori":"hadis","osmanli":"كشكك"},{"kelime":"KESRET","anlam":"1.Çokluk, bolluk, ziyâde-lik. 2.Sıklık.","kategori":"dil","osmanli":"كثرت"},{"kelime":"KESRET-İ VÜCûD","anlam":"Varlığın çokluğu. Mevcudâtı mertebelere ayırıp, her mertebenin hâli ve hükmünü başka bilerek, dinin hükümlerine uymayı elden bırakmamak gerektiğini ifade eden tasavvuf tabiri.","kategori":"fikih","misal":"Şeriat kesret üzerine kurulmuştur. Çeşitli emirler kesret ile olur. Peygamberlerin aleyhimüsselâm gönderilmesi, Cennet ni’metleri ve Cehennem azapları, hep kesrete bağlıdır. Allahü teâlâ (Bilinmeyi, tanınmayı sevdim) buyurmuş, kesreti istemiş ve zâhir olmağı sevmiştir. Bunun için vahdet-i vücûd yanında, kesret-i vücûd da doğrudur. Birincisine hakîkat ve diğerine mecâz âlemi derler. Fakat Allahü teâlâ kudretine hikme…","osmanli":"وجود كثرة"},{"kelime":"KEVÂKİB","anlam":"Yıldızlar. Kevkeb’in çok-luk hâli.","kategori":"dil","osmanli":"كواكب"},{"kelime":"KEVSER","anlam":"1.Çok sayıda, yüksek kıymette. 2.Kur’ân-ı kerîmde Muhammed aleyhisselâma verildiği bildirilen büyük ihsân; Kıyamet günü ümmet-i Muhammed’in başında toplanacağı rivâyet olunan havuz veya nehir. ait pek çok hayır, iyilik. 4) Kur’ân-ı kerîm. 5) İslâmiyet. 6) Muhammed aleyhisselâmın eshâb ve ümmetinin çokluğu. 7) Mübârek zürriyetinin çokluğu ve insanlara faydalı olması. (Sâvî Hâşiyesi)","kategori":"dil","osmanli":"كوثر"},{"kelime":"KEYFİYYET","anlam":"Bir şeyin mâhiyeti, esâsı, içyüzü, nasıl olduğu.","kategori":"dil","misal":"“Allah Arş üstündedir” buyurur Rabbimiz, Lâkin keyfiyyetini, anlayamaz aklımız. (Emâlî Kasîdesi)","osmanli":"كيفيت"},{"kelime":"KEYSÂNİYYE (Kîsaniyye)","anlam":"Şia’nın kollarından olup, kurucusu Muhtâr esSekâfî’nin bir adı da Keysân olması sebebiyle bu ismi alan; Hazret-i Ali’nin oğlu Muhammed bin elHanefiyye’nin imâmetini (halîfeliğini) kabul eden bir bid‘at fırkası.","kategori":"dil","osmanli":"كيسانيه"},{"kelime":"KİBÂR","anlam":"1.Büyükler, ulular. 2.İnce, terbiyeli, görgülü, nâzik.","kategori":"dil","misal":"Kebîr’in çokluk hâli.","osmanli":"كبار"},{"kelime":"KIBLE","anlam":"1.Yön, istikamet; yönelme. 2.Müslümanların namaz kılarken yöneldikleri taraf. 3.Kâbe-i Muazzama istikameti.","kategori":"ibadet","misal":"Şimdi seni herhâlde hoşnud olacağın bir kıbleye döndürüyoruz. Yüzünü artık Mescid-i harâm tarafına çevir. Siz de nerede bulunursanız yüzlerinizi o yana döndürün. (Bakara sûresi: 144) Sizden biriniz abdest bozarken kıbleyi karşısına veya arkasına almasın. (Hadîs-i şerîfBuhârî, Müslim, Ebû Dâvûd, Tirmizî, Nesâî) Kıble, Kâbe’nin binâsı değildir, arsasıdır. Yani yerden Arş’a kadar, o boşluk…","osmanli":"قبله"},{"kelime":"Kıble Açısı","anlam":"Kıble hattı ile bir beldeden geçen tûl (boylam) arasındaki açı olup, pusulada kıbleyi bulmak için güney istikametinden bu kadar sapılır.","kategori":"ibadet","osmanli":"آﭼيسى قبله"},{"kelime":"Kıble Hattı","anlam":"Harita üzerinde bir şehir ile Mekke arasında çizilen ve kıble istikâmetini gösteren hat.","kategori":"ibadet","osmanli":"خطى قبله"},{"kelime":"Kıble Saati (Kıble Vakti)","anlam":"Herhangi bir yerde, güneşin kıble hattı üzerine geldiği vakit olup, bu vakitte güneşe dönen, kıbleye dönmüş olur.","kategori":"ibadet","osmanli":"وقتى قبله"},{"kelime":"KİBRÎT-İ AHMER","anlam":"1.Kırmızı kükürt. 2.Simya ilminde toprağa, demire veya bakıra sürtünce altına çevireceği zannedilen madde. 3.Müridin kalbini temizleyip saf hâle getiren mürşid-i kâmil.","kategori":"tasavvuf","misal":"Bugün, bu iki nimete birlikte kavuşmak, hattâ yalnız İslâmiyet’in zâhirine uymak ele geçmez bir hazîne gibi olmuştur. Kibrît-i ahmerden daha kıymetlidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"احمر كبريت"},{"kelime":"KİBRİYÂ","anlam":"Allahü teâlâya mahsûs aza-met, büyüklük, üstünlük, yücelik.","kategori":"akaid","misal":"Azamet ve kibriyâ, büyüklük ve üstünlük bana mahsustur. Bu ikisinde bana ortak olanı Cehennem’e atarım, hiç acımam. (Ha-dîs-i Kudsî-Buhârî) Kibriyâ sıfatı Allahü teâlâya mahsûstur. İnsan, nefsini ne kadar aşağılarsa, Allahü teâlânın ya-nında kıymeti o kadar yükselir. Kendine kıy-met verenin, Allahü teâlâ katında kıymeti ol-maz. (Berîka)","osmanli":"كبرياء"},{"kelime":"KIDEM","anlam":"1.Kadîm olma, eskilik. 2.Zaman, rütbe ve memuriyet bakımından eskilik. 3.Varlığının başlangıcı olmayacak kadar eskilik mânâsına Allahü teâlânın zâtî sıfatlarından.","kategori":"akaid","misal":"âciz olmayı beraberinde getirir. Âcizlik ise, Allahü teâlâ için aslâ düşünülemez. Kıdem sıfatının zıddı hudûstur, sonradan olmaktır. Kıdem, Allahü teâlânın zâtı hakkında vâcib oduğundan, zıddı olan hudûs aklen mümkün değildir. (Mevâkıf)","osmanli":"قدم"},{"kelime":"KİFÂYE","anlam":"Kifâyet, yeter, lüzumu kadar. Aksırıp (Elhamdülillah) diyene (Yerhamükal-lah) demek, namazın dışında üç kere farz-ı kifâye, fazlası müstehabdır. (Rıyâdu’n-Nâsihîn)","kategori":"dil","osmanli":"كفايه"},{"kelime":"KİFÂYET","anlam":"1.Yetişme, elverme; yeter-lik. 2.İktidar, işe yararlık.","kategori":"dil","osmanli":"كفايت"},{"kelime":"KÎL-Ü-KÂL","anlam":"Dedikodu. (Kîl=De-nildi; Kâl=Dedi) (Bkz. Gîbet)","kategori":"dil","osmanli":"قال و قيل"},{"kelime":"KİLÂBİYYE (Küllâbiyye)","anlam":"240 (m. 854) senesinde Basra’da vefat eden İbni Küllâb’ın kurduğu; Allahü teâlânın sıfatlarının ne ebedî, ne ezelî olduğunu söyleyerek ve Kur’an-ı kerimin bu harflerden müteşekkil olduğunu inkâr ederek","kategori":"dil","osmanli":"كلابيه"},{"kelime":"KÎLE","anlam":"Ölçek, buğday, arpa gibi zahîre için kullanılan ölçü.","kategori":"akaid","misal":"Kile ile satılan şeylerden, aynı cinsten olma-yanlar, birbiri ile (meselâ arpa buğdaya karşı-lık) satılırken, hacimleri aynı olsa da, veresiye satmak fâizdir. (Erbâin-i Nesefî)","osmanli":"كيله"},{"kelime":"KİLİSE","anlam":"1.Hristiyanlara mahsûs ibâdet yeri. 2.Roma İmparatorluğu’nun resmî dini oluşu ve konsiller vesilesiyle ortaya çıkan teşkilâtlı Hristiyanlık; inananların dinî ve dünyevî hayatlarını tanzim eden ve…","kategori":"dil","misal":"Kilisede namaz kılmak mekrûhtur. Soğuk ve başka sebeble açık yerde namaz kılınamaz ve başka yer bulunamazsa, kilisede hem yalnız, hem cemâat ile kılmak câiz olur. Kilisede bulunan haç gibi küfür alâmetleri boşaltılırsa namaz kılmak mekrûh olmaz. (İbni Âbidîn)","osmanli":"كليسه"},{"kelime":"KILLET","anlam":"Azlık; kıtlık.","kategori":"dil","misal":"Mü’minlerde üç şeyden biri bulunur. Kıl-let, hastalık, zillet yani îtibârsızlık. (Hadîs-i şerîf-İhyâu Ulûm)","osmanli":"قلة"},{"kelime":"KIMIZ","anlam":"Kısrak sütünün mayalanması (fermantasyon) ile elde edilen ve içerisinde","kategori":"osmanli","misal":"% 1-3 oranında alkol bulunan ekşi, tarihî bir Türk içkisi. Aslı Aramice ekşitilmiş, mayalanmış mânâsına hımis gelir. Kısrak, inek ve deve sütleri mayalanıp tadı keskin olunca, müselles gibi olur. Birincisine kımız, diğer ikisine kefir denir. Her ikisi de bira gibi haramdır. (Men-i Müskiratİskilipli Âtıf)","osmanli":"قيميز"},{"kelime":"KİN","anlam":"Gizli düşmanlık, garaz. (Bkz. Hıkd) KİNÂYE: كنايه (A) Bir şeyi, açık mânâları başka olan kelimelerle anlatmak; bir sözü hem açık,","kategori":"dil","misal":"hem de kapalı mânâsıyla kullanmak. Kur’ân-ı kerîmde; “Elini boynuna bağlanmış yapma, tamamen de açma” (İsra sûresi: 29) meâlindeki âyet-i kerîmede cimrilik ve israfın yasaklandığına kinâye vardır. (Tefsir-i Kurtubî) Cimâ’ı ve abdest bozmayı anlatmak lazım ol-duğu zaman, açık olarak söylememeli, kinâye olarak söylemelidir. Edepli olan, sâlih olan, fuhş söylemeye mecbur olunca, kinâye olarak söyle-melidir. (Hadîka) Kinâye, îmâ ile kazf eden ta’zîr olunur. Kinâye yolu ile söğen ta’zîr olunmaz. (İbni Âbidîn)","osmanli":"كين"},{"kelime":"KINA","anlam":"Saç, sakal, el veya ayakları boya-yıp süslemek veya yaraları iyileştirmek, ağrıyı gidermek maksadıyla kullanılan ve bir ağacın kabuklarından elde edilen kokulu madde. Aslı Arabca hinnâ gelir.","kategori":"dil","misal":"Kına yakın da, güzelliğiniz, gençliğiniz ve nikâh muhabbetiniz artsın. (Hadîs-i şerîf-Ebû Nuaym) Resûlullah aleyhisselâm vahy geldiği zaman, mü-bârek başı ağrırdı. Başına kına bağlardı. Bir yeri yara olsa, oraya kına kordu. (Kimyâ-i Saadet)","osmanli":"قنا"},{"kelime":"KİNÂYE","anlam":"Bir şeyi, açık mânâları başka olan kelimelerle anlatmak; bir sözü hem açık,","kategori":"dil","misal":"hem de kapalı mânâsıyla kullanmak. Kur’ân-ı kerîmde; “Elini boynuna bağlanmış yapma, tamamen de açma” (İsra sûresi: 29) meâlindeki âyet-i kerîmede cimrilik ve israfın yasaklandığına kinâye vardır. (Tefsir-i Kurtubî) Cimâ’ı ve abdest bozmayı anlatmak lazım olduğu zaman, açık olarak söylememeli, kinâye olarak söylemelidir. Edepli olan, sâlih olan, fuhş söylemeye mecbur olunca, kinâye olarak söylemelidir. (Hadîka) Kinâ…","osmanli":"كنايه"},{"kelime":"KINYE","anlam":"Ticaret için değil de bizzat şahsı için tedârik ettiği ve zekâta tâbi olmayan mal.","kategori":"ibadet","osmanli":"قنيه"},{"kelime":"KİRÂ","anlam":"Bir şeyin menfaatine, yani kullanılmasına bedel olarak verilen ücret.","kategori":"muamelat","misal":"(Bkz. İcâre)","osmanli":"كراء"},{"kelime":"KIRÂAT (Kırâet)","anlam":"1.Okumak. 2.Namazın şartlarından olup kıyamda Kur’ân-ı kerîm okumak.","kategori":"dil","misal":"Namazda Kur’ân-ı kerîmden size kolay geleni kırâat edin! (Müzzemmil sûresi: 20) Kırâat cihetinden insanların en güzeli, Kur’ân-ı kerîm okurken hüzünlenendir. (Hadîs-i şerîfTaberânî) Namazın farzlarından birisi de okumaya kudreti olan için kırâattir. Kırâattan murad, Kur’ân-ı kerîmden bir âyet okumaktır. Nâfilelerle vitrin her rek’atinde, farzların ise iki rek’atinde farzdır. (İbni Âbidîn) Kendi işitecek kadar sesli…","osmanli":"قرائة"},{"kelime":"KIRÂD (Kırâz)","anlam":"Karşılıklı borçlanma, müdârebe (emeksermaye) şirketi.","kategori":"muamelat","misal":"Mukâraza.","osmanli":"قراض"},{"kelime":"KİRÂMEN KÂTİBÎN","anlam":"Her insanın iyilik ve kötülüklerini yazmak üzere Allahü teâlâ tarafından vazifelendirilmiş ve insanın iki omuzu üzerinde duran iki melek.","kategori":"akaid","misal":"Kirâmen kâtibîn denilen meleklerden sağ taraftaki melek, soldakinin âmiridir ve iyi işleri, ibâdetleri yazar. Soldaki melek, kötülükleri yazar. (İtikadnâme) Kirâmen kâtibîn, insandan yalnız cimâda ve helâda ayrılırlar. Helâda iken yapılanları, Allahü teâlâ meleklere bildirir. Helâdan çıkınca yazarlar. (Miftahü’l-Cenne) Bir kimseye selâm verirken, çok kimseye verir gibi vermelidir. Çünki mü’min yalnız değildir. Kirâm…","osmanli":"كاتبين كراما"},{"kelime":"KIRÂN HAC","anlam":"Umre için girilen ihrâm ile haccın da yapılmaya niyet edildiği hac türü.","kategori":"ibadet","misal":"Kırân Hacc’a niyet eden kimse, önce umre için tavâf ve sa’y edip, sonra ihrâmı çıkarmadan ve traş olmadan hac günleri için tekrar tavaf ve sa’y yapar. temmettü haccı yapan gibi şükür kurbanı keser. Hac çeşitlerinden en efdali kırân haccıdır. (Mevkûfât)","osmanli":"حج قران"},{"kelime":"KIRÂT","anlam":"Müslüman memleketlerinde metal para ile eczacılık, aktarlık vs.","kategori":"muamelat","misal":"malzemesini tartmak için kullanılan ağırlık birimi.","osmanli":"قراط"},{"kelime":"Kırât-ı Şer’î","anlam":"Zekât nisâbı hesab edilirken kullanılan ve kabuksuz, uçları kesilmiş, kuru beş arpaya (0,24 gr.) denk gelen ölçü birimi.","kategori":"ibadet","osmanli":"شرعى قراط"},{"kelime":"Kırât-ı urfî (Kırât-ı Örfî)","anlam":"Mikdarı beldelere ve örfe göre değişen, günlük muamele ve para basımında kullanılan, bazı âlimlere göre dört, bazı âlimlere göre beş orta boy arpa ağırlığına denk gelen ölçü birimidir.","kategori":"muamelat","osmanli":"عرفى قراط"},{"kelime":"KİRDİGÂR (Kirdikâr)","anlam":"Sâni, yapan; Allahü teâlâ.","kategori":"akaid","osmanli":"كردﮔار"},{"kelime":"KIRKLAR","anlam":"Ricâlü’l-Gayb denilen Al-lahü teâlânın insanlardan gizlediği kırk velî. (Bkz. Büdelâ, Ebdâl)","kategori":"dil","misal":"Resûlullah aleyhisselâm; “Ümmetim ara-sında her zaman kırk kişi bulunur. Bunla-rın kalbleri, İbrâhim aleyhisselâmın kalbi gibidir. Allahü teâlâ, onların sebebi ile, kul-larından belâları giderir. Bunlar, bu dere-ceye namaz ile, oruc ile ve zekât ile yetiş-mediler” buyurdu. İbn-i Mes’ûd radıyallahü anh sordu ki: “Yâ Resûlallah! Ne ile bu dere-ceye vardılar?” “Cömertlikle ve Müslüman-lara nasihat etmekle yetiştiler” buyurdu. (Ha-dîs-i şerîf-Ebû Nu’aym)","osmanli":"قرقلر"},{"kelime":"KÎSÂNİYYE","anlam":"(Bkz. Keysâniyye)","kategori":"dil","osmanli":"كيسانيه"},{"kelime":"KISÂS","anlam":"Kasden adam öldürme, uzuv kesme ve yaralamada, işlenen fiilin aynısının suçluya da tatbik olunması.","kategori":"dil","misal":"Ey îmân edenler! Kasden öldürülenler için size kısâs yapmak farz kılındı. Hür ile hür, köle ile köle, kadın ile kadın kısâs olunur. Öldürülmüş olanın kardeşinden (vârisin-den), kâtilin lehine olarak bir şey bağışlanır da kısas düşürülürse; ölenin velîsi hakkın-dan ziyâde olmayarak, örfe göre (tâyin edil-miş) diyet (para cezâsı) almalıdır. Kâtil de, ölenin velîsine îcâb eden diyeti güzel bir şe-kilde ödemelidir. İşte böyle affederek diyet almak, Rabbiniz tarafından size bir hafiflik ve merhâmettir. Kim bu bağışlama ve diyet alıştan sonra, kâtil ile veya kâtilin akrabâsı ile düşmanlık yaparak tecâvüzde bulunursa (kan dâvâsı güderse), onun için âhirette çok acıklı bir azap vardır. Ey akıl sahipleri! Bu kısasta sizin için bir hayât vardır. Ümit edilir ki, siz sakınırsınız. (Bakara sûresi: 178, 179)","osmanli":"قصاص"},{"kelime":"Kısas-ı Enbiyâ","anlam":"Peygamberlerin hayatlarını anlatan kitaplar için kullanılan tabir. KISKANÇ: قسقانﭻ (T) Allahü teâlânın başkasına","kategori":"akaid","misal":"ihsân ettiği nîmetin verilen kimseden alınma- sını, onun elinden çıkmasını ve yalnız kendinde olmasını isteyen kimse. Hasûd. (Bkz. Hased) Kıskanç insan, ömrü boyunca rahatsızdır. Böyle insanlar, kendinden aşağıdakilere bakmaz, hep kendisinden yüksek ve varlıklı olanlara bakar ve onları kıskanır. (Akkermânî)","osmanli":"انبياء قصص"},{"kelime":"KISKANÇ","anlam":"Allahü teâlânın başkasına","kategori":"akaid","misal":"ihsân ettiği nîmetin verilen kimseden alınma- sını, onun elinden çıkmasını ve yalnız kendinde olmasını isteyen kimse. Hasûd. (Bkz. Hased) Kıskanç insan, ömrü boyunca rahatsızdır. Böyle insanlar, kendinden aşağıdakilere bakmaz, hep kendisinden yüksek ve varlıklı olanlara bakar ve onları kıskanır. (Akkermânî)","osmanli":"قسقانﭻ"},{"kelime":"KISMET","anlam":"1.Bölme, hisselere ayırma, taksim etme. 2.Nasip, Allahü teâlânın ezelde herkes için dileyip takdir ettiği şey. 3.Şirket-i mülk olan mal aynı cinsten ise kısmeti kendi aralarında uyuşarak yaparlar. 4.Erkeğin, zevceleri arasın…","kategori":"akaid","misal":"Uyuşamazlarsa kısmeti hâkim yapar. Hacim veya vezn ile ölçülen şeyleri, ölçmeden bölmek fâiz olur. Mallar başka cinsten veya (hamam gibi) ayrılması zararlı ise, kısmeti uyuşarak yaparlar. Yahud satılıp parası bölünür. Ev gibi mislî olmayan malın menfaatinin kısmetine muhâyee denir. (Şerh-i MecelleÂtıf Bey)","osmanli":"قسمت"},{"kelime":"KISRAK","anlam":"Dişi at.","kategori":"dil","osmanli":"قسراق"},{"kelime":"KISSA","anlam":"Bir haberi nakletme, bir hâdiseyi anlatma, hikâye etme.","kategori":"hadis","misal":"Çokluk hâli kısas (kasas) gelir.","osmanli":"قصه"},{"kelime":"KISSÎS","anlam":"Hristiyan din adamı. Keşiş. Aslı Aramice ‘çok yaşlı’ mânâsına gelir.","kategori":"dil","osmanli":"قسيس"},{"kelime":"KİSVE","anlam":"1.Giyecek. 2.Hususî kıyafet. 3.Dış görünüş.","kategori":"dil","misal":"Onların (annelerin) âdet olduğu şekli ile yiyeceği ve kisvesi; çocuk kendisinin olana (babaya) âittir. Kimse gücü yettiğinden faz-lasıyla mes’ûl tutulmaz. (Bakara sûresi: 233) Zevciyet nafakasında kisve, senede iki göm-lek ve iki himâr (baş örtüsü) ve iki milhâfedir. Milhâfe (ferâce veya manto), kadının sokağa çı-karken giydiği bir şeydir. Bunların biri yazlık, biri kışlıktır. Şimdi kisveye, iç donu, cübbe (ka-lın manto), yatak, yorgan da ilâve etmek lâzım-dır. Kış mevsiminde, gömlek yünden, manto ve himâr ipekten olur. Ayakkabı, zaman ve mem-leketin âdetine göre dâhil edilir. Zevcin bunları getirmesi lâzımdır. (Bahr) Vahdet-i vücûd ehli, halk (yaratılanlar), hak-kın bu kisve ile meydâna çıkışı ve hakkın bu âsâr (eserler) ve ahkâm ile tahakkukudur de-yip, hiçbir şeyde kötülük ve kötülüğün aslı yok-tur. Eğer var ise, nisbî ve izâfîdir derler (var ka-bul edilendir, derler). (Mektûbât-ı Ma’sûmiyye)","osmanli":"كسوه"},{"kelime":"Kitâb-ı Mukaddes","anlam":"Hem Eski Ahid adıyla Tevrat ile buna bağlı kitaplar, hem de Yeni Ahid adıyla dört İncil ile havârilerin macera ve mektuplarından teşekkül eden Hristiyanların mukaddes kitabı.","kategori":"dil","misal":"Îsâ aleyhisselâma İncîl isminde bir kitap nâzil oldu. Fakat Yahudiler bu kitabı seksen sene içinde yok ettiler. Kitâb-ı mukaddes içinde bulunan hakîki bilgilere birçok yanlış düşünceler, efsâneler ve hurâfeler eklenmiştir. (Manastırlı Müderris Hâcı Abdullah Abdi Bey)","osmanli":"مقدس كتاب"},{"kelime":"Kitâb ve Sünnet","anlam":"Kur’ân-ı kerîm ve hadîs-i şerîfler.","kategori":"hadis","misal":"Sünnet kelimesinin dinimizde üç mânâsı vardır: Kitâb ve sünnet birlikte söylenince, kitap, Kur’ân-ı kerîm, sünnet de, hadîs-i şerîfler demektir. Farz ve sünnet denilince, farz, Allahü teâlânın emirleri, sünnet ise, Hazret-i Peygamber’in sünneti, yani emirleri demektir. Sünnet kelimesi yalnız olarak söylenince, şeriat demektir. (Cevhere)","osmanli":"وسنت كتاب"},{"kelime":"KİTÂBET","anlam":"1.Yazı yazma, kaleme alma. 2.Kâtiblik, yazıcılık. 3.Kölenin muayyen bir bedel ödemek veya yerine getirmek karşılı-ğında âzâd edileceğine dâir sahibi ile yaptığı akid.","kategori":"dil","misal":"(Bkz. Mükâteb)","osmanli":"كتابت"},{"kelime":"KİTÂBÎ","anlam":"1.Kitaba bağlı, kitapta ya-zılı olan, kitapa nisbet edilen, kitapla alâkalı. 2.Semâvî kitablardan birine tâbi olan kimse.","kategori":"dil","misal":"Müslüman erkeğin kitâbî kadını nikâh etmesi câizdir. Başka kâfir kadınla ve mürted olmuş, dinden çıkmış kadınla evlenmesi câiz değildir. (İbni Âbidîn)","osmanli":"كتابى"},{"kelime":"KİTÂBİYYE","anlam":"Ehl-i kitâbdan olan kadın.","kategori":"osmanli","osmanli":"كتابيه"},{"kelime":"KİTÂBuLLAH","anlam":"Allah’ın kitabı. Kur’ân-ı kerîm.","kategori":"dil","osmanli":"الله كتاب"},{"kelime":"KITÂL","anlam":"Vuruşma, birbirini öl-dürme; savaş, mukatele.","kategori":"dil","misal":"Bâgîler ile kıtâl farzdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قتال"},{"kelime":"KITMÎR","anlam":"1.Hurma çekirdeğinin zarı. 2.Eshâb-ı Kehf ’in köpeği.","kategori":"dil","misal":"Ondan gayrı duâ ettikleriniz (putlar) ise bir kıtmire bile mâlik değildirler (yaratamazlar). (Fâtır sûresi: 13) (Bkz. Eshâb-ı Kehf) Eshâb-ı Kehfe tâbi olduğu için Kıtmîr’e Allahü teâlâ kıymet verip, Kur’ân-ı kerîmde ona işâ-ret etmiştir ve Kıtmîr, Eshâb-ı Kehf ile birlikte Cennet’e girecektir. (Rûhü’l-Beyân) İbni Abbas der ki: “Eshâb-ı Kehf, geceleyin kaç-tılar. Yedi kişi idiler. Beraberinde köpeği bulu-nan bir çobanın yanından geçtiler. O da dinle-rini kabul ederek arkalarından gitti.” Ka’b der ki: Onlar, bir köpeğin yanından geçtiklerinde köpek onlara havladı. Onu kovdular. Ancak, geri döndü, defalarca onu kovdular. Bu sefer kö-pek, arka ayaklan üzerine dikilip ön ayaklarını duâ eden bir kimsenin yaptığı şekilde semaya doğru kaldırıp dile geldi ve; Benden korkma-yın, çünki ben Allah’ın sevdiklerini seviyorum. Siz uyuyun, ben de sizi koruyayım, size bekçilik edeyim, dedi. Müfessirlerin ekserisine göre bu-rada sözü edilen köpek, gerçek bir köpektir. Mu-katil’e göre onlardan birisinin av veya bekçi kö-peği idi. Rengine dair ihtilâflar vardır. Taş veya gök renginde idi denilmiştir. Köpeğin adı husu-sunda da ihtilaf vardır. Hazret-i Ali’den Rey-yân, İbn-i Abbas’tan Kıtmir, Evzaî’den Müşîr, Abdullah bin Selam’dan Basît, Ka’bdan Silıya, Vehb’den Nîkyâ rivâyeti gelmişse de, Kıtmîr yay-gın kabul görmüştür. (Tefsir-i Kurtubî)","osmanli":"قطمير"},{"kelime":"KIYÂM","anlam":"1.Ayakta durmak. 2.Namazın içindeki farzlardan olup iftitah tekbiriyle muayyen bir mikdar Kur’ân-ı kerîm okuyacak kadar ayakta kalma.","kategori":"dil","misal":"Kıyâm, üç şeyle tamam olur: Ayakta durmak; secde yerine bakmak ve iki tarafına sallanmamak. (Miftahü’l-Cenne) Kıyâmı yapamayan hasta, oturarak, oturamayan, sırt üstü yatıp başı ile îmâ, işâret ederek kılar. Yüzü, semâya karşı değil kıbleye karşı olması için başı altına yastık konur. Ayaklarını diker. Kıbleye karşı uzatmaz. (İbni Âbidîn)","osmanli":"قيام"},{"kelime":"KIYÂMET","anlam":"1.Ayağa kalkmak, dikilmek. 2.Dünya hayatının son bularak bütün insanların dirilerek ayağa kalktığı zaman, âhiretin başlangıcı.","kategori":"akaid","misal":"(Bkz. Sâat) Ey insanlar! Rabbinizin azâbından korkun. Muhakkak kıyâmetin zelzelesi (sarsıntısı) pek büyük bir şeydir. Onu gördüğünüz gün, analar, emzirdikleri çocuklarını bırakıp unutur, hâmile kadınlar çocuklarını düşürür. O günün dehşetinden sen insanları sarhoş bir hâlde görürsün, hâlbuki onlar sarhoş değillerdir.…","osmanli":"قيامت","alternatif":["kiyamet"]},{"kelime":"Kıyâmet Alâmetleri","anlam":"Kıyâmetin kopmasının yaklaştığına dâir Resûlullah aleyhisselâmın haber verdiği büyük ve küçük alâmetler, işâretler.","kategori":"akaid","misal":"On büyük alâmet görülmeyince kıyâmet kopmaz. Bunlar: Duhan (duman), Deccâl, Dâbbetü’l-erd, güneşin batıdan doğması, Îsâ aleyhisselâmın gökten inmesi, Ye’cüc ve me’cüc’ün çıkması, doğuda, batıda ve Arabistan’da yer batması, bunlardan sonra Yemen’den bir ateş çıkıp, insanları bir araya getirmesidir. (Hadîs-i şerîfMüslim) Kıyâmet alâmetleri, büyük ve küçük olmak üzere iki kısımdır. Küçük alâmetlerin sayıları pekçok olu…","osmanli":"علامتلرى قيامت","alternatif":["kiyamet"]},{"kelime":"KIYÂS","anlam":"1.Bir şeyi diğer bir şeyle ölçme, bir şeyi başka şeye benzetme, mukayese etme. 2.Hakkında nass (âyet-i kerîme ve hadîs-i şerîf) bulunmayan bir meselenin hükmünü, buna benzeyen ve hakkında nass bulunan başka bir meselenin hükmüne benzeterek anlama. Haşr sûresi ikinci âyet-i kerîmesinde meâlen; “Ey ilim sahipleri! Îtibâr ediniz (yâni bilmediklerinizi bildiklerinize kıyas ediniz)” buyurulmuştur. Îtibâr etmek, benzetmek demektir. Bu âyet-i kerîme, kıyas ve ictihâdı emretmektedir. (Beydâvî)","kategori":"fikih","osmanli":"قياس"},{"kelime":"Kıyâs-ı Fukahâ","anlam":"Şer’î delillerin dördüncüsü olan ve hakkında hüküm bulunmayan meseleyi, bulunan bir meseleye, aralarındaki müşterek illet dolayısıyla benzeterek çözme.","kategori":"fikih","osmanli":"فقهاء قياس"},{"kelime":"KIYEMÎ","anlam":"Kıymetle alâkalı; çarşıda ben-zeri bulunmayan, bulunsa da fiyatları farklı olan mal.","kategori":"dil","misal":"Uzunluk ile ölçülenlerden tarla, elde doku-nan kumaş, halı ve elbise, ev, dükkân, el yaz-ması kitab, irili ufaklı olan karpuz kıyemîdir-ler. (İbni Âbidîn)","osmanli":"قيمى"},{"kelime":"KIYMET","anlam":"1.Değer, itibar, üstünlük. 2.Bir malın piyasadaki fiyatı, o maldan anlayan müşterilerin verdikleri değer.","kategori":"dil","misal":"İnsanın kıymeti, îmân ve mârifet iledir. Mal ve mevki ile değildir. (Mektûbât-ı Ma’sûmiyye) Semen-i misl. Kıyemî malı telef eden kıymetini öder. (İbni Âbidîn)","osmanli":"قيمت"},{"kelime":"KIYMETLİ MAL","anlam":"Kullanması, alınıp satılması mübah ve mümkün olan mal.","kategori":"fikih","misal":"Mütekavvim mal.","osmanli":"مال قيمتلى"},{"kelime":"KIZILBAŞLIK","anlam":"Şiîliğin gulat (aşırı) kollarından olup, kurucusu Şah İsmail, Hazret-i Hüseyn’in kanını sembolize eden kırmızı sarık sardığı için Anadolu’da bu isimle anılan ve inançlarında İslâm, Zerdüşt, Mazdekî, Bâbekî, Yahudi ve Şaman geleneklerinin karışımının yer aldığ…","kategori":"dil","osmanli":"باشلق قزل"},{"kelime":"KÖLE","anlam":"Bir kimsenin mülkiyeti altında olup onun hizmetini gören kimse.","kategori":"muamelat","misal":"Allah’a ibâdet edin, O’na hiçbir şeyi ortak koşmayın. Bir de anababaya iyilik edin. Akrabâya, yetimlere, yoksullara, yakın komşuya, uzak komşuya, yakın arkadaşa, yolcuya ve ellerinizdeki kölelere de iyilik edin. Çünki Allah büyüklenen ve övünen kimseyi sevmez. (Nisâ sûresi: 36) Şu iki güçsüz, yani köle ve kadın hakkında Allah’tan korkunuz. (Hadîs-i şerîfMüsnedü İmâm-ı Ahmed)","osmanli":"كوله"},{"kelime":"KOLONYA","anlam":"Hafif koku ihtiva eden, bayılmalarda, fenalaşmalarda, başağrılarında, mikrop kırıcı hususiyeti bakımından da temizlik için kullanılan, içine karıştırılan kokuya göre “limon kolonyası”, “lavanta çiçeği kolonyası” gibi adlar alan tuvalet ispirtosu.","kategori":"tasavvuf","misal":"İhtiyaç için hazırlanan karışımlardaki iki maddeden biri temiz ise ve necs olanın yerine temizini kullanmakta zorluk varsa, bir kavle göre bu karışım da temiz olacağından, ispirtolu ilaç, kolonya, mürekkep, vernik ve boyaların temiz olduğu anlaşılmaktadır. (elFıkhu ale’l-Mezâhibi’l-Erbaa)","osmanli":"قولونيا"},{"kelime":"KOMİSYONCu","anlam":"Bir iş, bir akde ücret (komisyon) karşılığı aracılık eden kimse. Dellâl.","kategori":"dil","misal":"Dellâl, yani komisyoncu, mal sahibinin izni ile malı kendi sattığı zaman, komisyon ücretini bâ-yiden alır. Müşteriden bir şey isteyemez. Çünki hakikatte malı satan kendisidir. Burada, tüc-carlar arasındaki âdete bakılmaz. Eğer komis-yoncu, bâyi ile müşteri arasında aracılık yapıp, malı bâyi satarsa, komisyon ücretini, âdete göre bâyi veya müşteri yâhud her ikisi ortaklaşa ve-rirler. (İbni Âbidîn)","osmanli":"قومسيونجى"},{"kelime":"KOMŞu","anlam":"Bitişik evlerde veya yakın çev-rede oturan kimse. Câr. Hemcivâr. Hemsâye. Üç şey mü’minin saadetindendir: Geniş ev, iyi komşu ve uslu binek (Hadîs-i şerîf-Taberânî,","kategori":"hadis","misal":"Hâkim) Zımmî (gayr-i müslim vatandaş) kom-şunun bir hakkı, Müslüman komşunun iki hakkı, akrabâ olan komşunun üç hakkı var-dır. (Hadîs-i şerîf-Ebû Nuaym) Dünyada en kıymetli şey; Müslüman, sâlih, Al-lahü teâlânın ve mahlûkların haklarını bilen ve gözeten komşudur. (Seyyid Alizâde)","osmanli":"قومشو"},{"kelime":"KOMÜNİZM","anlam":"İstihsâl vâsıtalarının (üretim araçlarının) cemiyetin malı olmasını, istihlâk (tüketim) mallarının ihtiyaca göre paylaşılmasını iddia eden, cemiyeti tek sınıf olarak telâkki eden, aile yapısı ve dinî inançları reddeden siyasî, ictimaî ve iktisadî sistem.","kategori":"dil","misal":"İştirâk-i emvâl. İhtilâlci sosyalizm.","osmanli":"قومونيزم"},{"kelime":"KONAK","anlam":"1.Bir insanın normal bir günde normal yürüyüşle bir günde yürüye-bileceği mesafe. 2.Tasavvufta ilerlerken her iki derece arası.","kategori":"dil","misal":"Merhale. Menzil. Allahü teâlâya yakın olmak, ulaşmak husu-sunda tasavvuf büyükleri; “İnsanı kavuşturan konaklar sonsuzdur, bitmez tükenmez” demiş-lerdir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قوناق"},{"kelime":"KONTRAT","anlam":"Akid, sözleşme, mu-kavele.","kategori":"dil","osmanli":"قونطراط"},{"kelime":"KÖTÜ DİN ADAMI","anlam":"İlmini dünya kazancına, mala, mevkîye kavuşmaya vâsıta eden, ilmi ile amel etmeyen, insanları ibâdete ve âhirete yönelmeye teşvik etmeyen din adamı.","kategori":"akaid","osmanli":"آدامى دين كوتو"},{"kelime":"KÖTÜ HuY","anlam":"Dinin ve aklın beğen-mediği huy. Sû-i hulk. Ahlâk-ı seyyie.","kategori":"tasavvuf","misal":"Sıcak su buzu erittiği gibi, iyi huy da, hatâ-ları eritir. Sirke balı bozduğu gibi, kötü huy; iyilikleri mahveder. (Hadîs-i şerîf-Taberânî) Kötü huylar, kalbi, ruhu hasta eder. Hastalı-ğın artması, kalbin, ruhun ölümüne sebeb olur. Kötü huyların en kötüsü olan şirk, küfür (Al-lahü teâlâya ortak koşmak) ise, kalbin, ruhun en büyük zehiridir, hemen öldürür. Îmânı ol-mayanın kalbi temiz olmaz. Ölmüş, kokmuş olan kalbin temiz olması düşünülemez. (Berîka)","osmanli":"خوى كوتو"},{"kelime":"KuBÂ MESCİDİ","anlam":"Hazret-i Muhammed aleyhisselâmın hicreti esnâsında Medîne-i Münevvere yakınındaki Kubâ köyünde inşâ edilen İslâm tarihinin ilk mescidi.","kategori":"dil","misal":"Bir kimse evinde güzel bir gusl abdesti alarak Kubâ mescidine gelir de bu mübârek mescidde namaz kılmaktan başka bir niyeti olmazsa bir umre etmiş gibi kendisine sevab verilir. (Hadîs-i şerîfTirmizî, Nesâî) Kur’ân-ı kerîmde takvâ üzerine kurulu olduğu bildirilen mescid, Kubâ Mescididir (Hadîs-i şerîfMüslim, Tirmizî, Nesâî) Resûlullah aleyhisselâm Medîne’de iken, her hafta gelip, burada iki rek’at tehıyyetülmescid na…","osmanli":"مسجدى قوبا"},{"kelime":"KÜBRÂ","anlam":"Daha (en, pek, çok) büyük. Ekber’in müennesi.","kategori":"dil","osmanli":"كبرى"},{"kelime":"KÜBREVİYYE","anlam":"618 (m. 1221) se-","kategori":"dil","misal":"nesinde Harezm’de Cengiz askerlerince şe-hid edilen Necmeddîn Kübrâ hazretlerinin tasavvuftaki yolu.","osmanli":"كبرويه"},{"kelime":"KuBûR","anlam":"Kabirler, mezarlar. (Bkz.","kategori":"akaid","misal":"Kabir)","osmanli":"قبور"},{"kelime":"KÜÇÜK GÜNAH","anlam":"Fitne çıkarmak, adam öldürmek, zinâ etmek gibi büyük günahlara göre daha küçük sayılan günahlar; mekrûh.","kategori":"ibadet","misal":"Küçük günahı işlemekte ısrar etmek büyük günahtır. (Miftahü’l-Cenne) Haramları, büyük günah ve küçük günah diye ikiye ayırmışlar ise de, küçük günahlardan da, büyük günah gibi kaçınmak, hiçbir günahı küçümsememek gerekir. Çünki Allahü teâlâ intikam alıcıdır. İstediğini yapmakta hiç kimseden çekinmez. Gazâbını, düşmanlığını günahlar içinde gizlemiştir. Küçük sanılan bir günah, intikâmına, gadabına sebeb olabilir. (Ri…","osmanli":"كناه كوﭼوك"},{"kelime":"KÜÇÜK HAVuZ","anlam":"Hanefî mezhebine göre alanı yirmi üç metrekâreden az olan havuz.","kategori":"fikih","misal":"Havz-ı Sagîr. (Bkz. Havz) Hanefî’de küçük havuza, Şâfiî’de ise kulleteynden az olan suya, az necâset düşerse, üç sıfatı değişmese de necs olur. İnsan içemez ve temizlikte kullanılamaz. Üç sıfatı değişirse bevl gibi olup hiçbir şeyde kullanılanamaz. (İbni Âbidîn)","osmanli":"حوض كوﭼوك"},{"kelime":"KÜÇÜK MESCİD","anlam":"Kıble du-varı ile arka duvarı arası yirmi metreden az olan mescid, Mescid-i Sagîr.","kategori":"dil","misal":"Kırda ve büyük câmi’de ayaklar ile secde yeri arasından, küçük mescidde ve odada ise, ayak-ları ile kıble dıvarı arasından geçen, günaha gi-rer. (İbni Âbidîn)","osmanli":"مسجد كوﭼوك"},{"kelime":"KuDDİSE SIRRuH","anlam":"Tasavvuf büyüklerinin adı anıldığı zaman söylenen ve “Al-","kategori":"tasavvuf","misal":"lah sırrını takdis etsin!” mânâsına gelen ta’zim sözü. (İki kişi için “Kuddise Sırruhümâ”, ikiden çok kişi için “Kuddise Sırruhüm” denir.)","osmanli":"سره قدس"},{"kelime":"KuDRET","anlam":"Güç, güçlü olma, gücü yetme. Gerçekten, göklerin ve yerin yaratılışında, gece ile gündüzün birbiri ardınca gelişinde, akıl sahipleri için, Allah’ın varlığını, kudret ve azametini gösterir, kesin deliller vardır. (Âl-i İmrân sûresi: 190)","kategori":"dil","misal":"Kul her işinde, yapıp yapmamakta serbest olup, ikisinden birini elbette seçecek; iş, iyi veya fenâ olacak, günah veya sevab kazanacaktır. Allahü teâlâ kullarına, emirlerini ve yasaklarını ye-rine getirecek kadar kudret ve ihtiyâr (beğen-mek, seçmek gücü) vermiştir. Daha çok verme-sine, lüzum yoktur. Lüzumu kadar vermiştir. Buna inanmayan, Kolay şeyleri anlamayan kimsedir. Kalbi hasta olduğundan, İslâmiyet’e uymamaya bahâne aramaktadır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قدرت"},{"kelime":"KuDSÎ","anlam":"1.Mukaddes. 2.İlâhî, Allah ile alâkalı.","kategori":"akaid","osmanli":"قدسى"},{"kelime":"KuDSÎ HADÎS","anlam":"Mânâsı Allah’dan, ifadesi Hazret-i Peygamber’e ait olan hadîs. Hadîs-i kudsî.","kategori":"hadis","osmanli":"حديث قدسى"},{"kelime":"KuDÜS","anlam":"Filistin’de Dâvûd aleyhisselâm tarafından kurulan ve Süleymân aleyhisselâm tarafından inşâ ettirilen Beyt-i Makdis’in (Mescid-i Aksâ’nın) bulunduğu mukaddes şehir.","kategori":"ibadet","misal":"Kuds. İlyâ.","osmanli":"قدس"},{"kelime":"Küfr Alâmeti","anlam":"Kâfirlerin ibâdet olarak yaptıkları ve kâfirlik alâmeti olan şeyler.","kategori":"fikih","misal":"Küfr alâmetlerinden bazıları, zünnâr, haç ve papaz serpuşudur. Küfr alâmetleri âdet olup, Müslümanlar arasında yayılırsa, İslâm âdeti olmaz. Küfr alâmeti olmaktan çıkmaz. Bilerek ve isteyerek zünnâr takan, dinden çıkar. (Şeyhzâde Hâşiyesi)","osmanli":"علامتى كفر"},{"kelime":"Küfr-i Cehlî","anlam":"İşitmediği, düşünmediği için, Allahü teâlâya ve inanılması lâzım olan şeylere inanmamak.","kategori":"akaid","misal":"Küfr-i Cehlîye düşen kimsenin îmânı ve nikâhı bozulmaz. Yalnız tövbe ve istiğfâr yani tecdîd-i îmân etmesi, îmânını tâzelemesi ihtiyâtlı olur. (Berîka)","osmanli":"جهلى كفر"},{"kelime":"Küfr-i Hükmî","anlam":"İslâmiyet’in küfr alâmeti dediği sözleri söylemek ve işleri yapmak.","kategori":"fikih","misal":"Akıllı, bilgili, edebiyatçı olduğunu göstermek için veya yanındakileri güldürmek, hayrete düşürmek, sevindirmek veya alay etmek için söylenen sözlerde küfr-i hükmîden korkulur. Gadab, kızgınlık ve hırs ile söylenen sözler de böyledir. Bunun için insan, sözünün ve işlerinin nereye varacağını düşünmelidir. Her şeyde dinini kayırmalıdır. (Berîka)","osmanli":"حكمى كفر"},{"kelime":"Küfr-i İnâdî","anlam":"Bilerek, inâd ederek kâfir olmak. Küfr-i cühûdî.","kategori":"akaid","misal":"Küfr-i inâdî ile dinden çıkanların, tövbe etme-leri için yalnız Kelime-i şehâdet söylemeleri kâfi değildir. Küfre sebeb olan şeyden de tövbe et-meleri lâzımdır. Erkek veya kadın bir Müslü-man, âlimlerin söz birliği ile bildirdikleri bir sözün veya işin küfre sebeb olduğunu bilerek, ciddî olarak veya hezl, yani güldürmek için söy-lerse veya yaparsa, mânâsını düşünmese dahi küfr-i inâdî olduğu için îmânı gider. (Berîka)","osmanli":"عنادى كفر"},{"kelime":"KÜFRÂN-I Nİ‘MET","anlam":"Ni’meti inkâr etmek, nankörlük etmek.","kategori":"akaid","misal":"İslâm dininin emir ve yasaklarına uymak şü-kür, uymamak küfrân-ı nîmettir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"نعمت كفران"},{"kelime":"KuL","anlam":"1.Köle. 2.İbâdet eden.","kategori":"akaid","misal":"(Bkz. Abd, Köle) Ben kulum. Kullar gibi yere oturur yerim. (Hadîs-i şerîf-İbni Adiyyi) Bir kimsenin Allahü teâlâya kul olması için, O’ndan başka şeylere kul olmaktan ve bağlan-maktan tam kurtulması lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قول"},{"kelime":"Kul Hakkı","anlam":"Bir kimsenin, başkası üzerindeki hakkı, alacağı. (Bkz. Hukûku’l-Ibâd) Şehidin, kul hakkı dışındaki bütün günah-ları bağışlanır. (Hadîs-i şerîf-Müslim, Tirmizî, Taberânî, Hâkim)","kategori":"hadis","misal":"İşlenen günahlarda kul hakkı varsa, buna tövbe için; kul hakkını hemen ödemek, hak sahibi ile helâllaşmak, ona iyilik ve duâ etmek de lâ-zımdır. Mal sahibi, hakkı olan ölmüş ise, ona duâ, istiğfâr edip, çocuklarına, vârislerine ve-rip ödemeli, bunlara iyilik yapmalıdır. (Mek-tûbât-ı İmâm-ı Rabbânî)","osmanli":"حقى قول"},{"kelime":"KÜLFET","anlam":"1.Zahmet, sıkıntı, zorluk, yor-gunluk, zorlu iş. 2.Merâsim, seremoni.","kategori":"dil","misal":"Külfet nimete ve nimet külfete göredir. (Me-celle, m. 88)","osmanli":"كلفت"},{"kelime":"KuLLETEYN","anlam":"İki kulle (büyük testi). Eni boyu ve derinliği altmışar santimetre veya çapı 48, derinliği 96 santimetre olan bir küp veya silindir şeklindeki havuz içindeki su; iki büyük testi dolusu (500 rıtl=220 kg.) su.","kategori":"dil","misal":"Hanefî mezhebinde akar suya ve büyük ha-vuza, Şâfiî mezhebinde kulleteyn mikdarı olan suya, Mâlikî mezhebinde herhangi mikdardaki bir suya pislik düşerse, pisliğin üç eserinden biri, yani rengi, kokusu veya tadı belli olma-yan her tarafından abdest ve gusl câiz olur. Hanefî mezhebinde küçük havuza, Şâfiî’de ise kulleteynden az olan suya, az necâset düşerse üç sıfatı, yani rengi, tadı, kokusu değişmese de necs olur. İnsan içmez ve temizlikte kullanıl-maz. (İbni Âbidîn)","osmanli":"قللتين"},{"kelime":"KÜLLÎ","anlam":"1.Küll’e ait, umumî, bütün. 2.Çok.","kategori":"akaid","misal":"KÜLLÎ İRÂDE: اراده كلى Allahü teâlânın ezelî ve ebedî irâde sıfatı. İrâde-i külliyye. (Bkz. İrâde)","osmanli":"كلى"},{"kelime":"KÜLLÎ İRÂDE","anlam":"Allahü teâlânın ezelî ve ebedî irâde sıfatı.","kategori":"akaid","misal":"İrâde-i külliyye. (Bkz. İrâde)","osmanli":"اراده كلى"},{"kelime":"KuLLuK","anlam":"Kölelik; ibâdet; abdiyet, ubûdiyyet.","kategori":"tasavvuf","misal":"Kulun dileği ve isteği sadece sahibi ve sahibinin dileği olmalıdır. Başka hiçbir dileği bulunmamalıdır. Böyle olmazsa, kulluk bağını koparmış, kölelikten kaçmış olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قوللق"},{"kelime":"KuLûB","anlam":"Kalbler, gönüller. Kalb’in çokluk hâli.","kategori":"tasavvuf","osmanli":"قلوب"},{"kelime":"KuMAR","anlam":"Birkaç kimsenin ortaya mal veya para koyarak, kazanana verilmesini şart etmesi, para veya başka bir menfaat karşılığı oynanan oyun, piyango, toto, loto, müşterek bahis.","kategori":"akaid","misal":"Ey îmân edenler! Şarap, kumar, dikili taşlar, fal ve şans okları birer şeytân işi, pisliktir. Bunlardan uzak durun ki, kurtuluşa eresiniz. (Mâide sûresi: 90) Yarışan iki kimseden yalnız birinin. (Beni geçersen, sana şunu vereceğim. Ben kazanırsam, senden bir şey istemem) demesi veya yarışmaya karışmayan birinin. (İkinizden kazanana şunu vereceğim) demesi câizdir. (Kazanamayan, kazanana şunu verecek) denirse, kumar o…","osmanli":"قمار"},{"kelime":"KuMİS","anlam":"Kısrak sütünün mayalan-ması ile elde edilen tadı keskin alkollü bir içki. Kımız. Aslı Aramice ekşitilmiş, mayalanmış mânâsına hımis’tir.","kategori":"dil","osmanli":"قوميس"},{"kelime":"KÜMûN ve BÜRûZ","anlam":"1.Sak-lanma, gizlenme ve gösterme, görünme. 2.Cin-nin insan vücuduna girmesi. 3.Tasavvufta, ev-liyânın ruhunun, terbiye ve kemâle getirme maksadıyla talebesinin vücuduna tealluk et-mesi, girmesi.","kategori":"tasavvuf","misal":"Bazı evliyânın kümûn ve bürûz etmesi, tenâ-süh değildir. Çünki, tenâsühde ruh, ikinci bir bedene hayat vermek, onda his ve hareket hâ-sıl etmek için tealluk eder. Bürûzda ise, ruhun başka bir bedene te’alluk etmesi; bu bedeni ol-gunlaştırmak içindir. Bu fakîre göre, kümûn ve bürûza lüzum yoktur. Bir velî, bir câhili terbiye etmek için, Allahü teâlânın verdiği bir kuvvetle, kendi yüksek sıfatlarını, o kimseye aks edip te-veccüh ve iltifatla yerleştirir. Böylece, o aşağı de-recedeki insan, yükselerek kâmil olur. (Mektû-bât-ı İmâm-ı Rabbânî)","osmanli":"بروز و كمون"},{"kelime":"KuNûT","anlam":"İbâdet, taat; huşû; kıyam; sükût; duâ.","kategori":"ibadet","misal":"Namazın makbûlü, tûl-i kunût ile olanıdır. (Hadîs-i şerîfMüslim, Tirmizî, Ebû Dâvûd)","osmanli":"قنوت"},{"kelime":"KuNûT DuÂSI","anlam":"Hanefî mezhebinde, vitir namazının üçüncü rek’atinde zamm-ı sûre okunduktan sonra; Şâfi’î mezhebinde, sabah namazının farzının ikinci rek’a-tinde rükû’dan kalktıktan sonra ve Ramazân-ı şerîf ayının yarısından sonra vitir namazının üçüncü rek’atinde rükû’dan k…","kategori":"ibadet","misal":"Resûlullah aleyhisselâm zamanında Bi’r-i Mâûne vak’asında, Sahâbe-i kirâmdan (Peygamberimizin sohbetinde yetişen mübârek arkadaşlarından) yetmiş kurrâ (hafız), Âmiroğullarının reîsi Ebû Berâ Âmir bin Mâlik’in yeğeni Âmir bin Tufeyl ve adamları tarafından şehîd edilmişlerdi. Peygamber efendimiz bu hâdiseye çok üzüldüler. Bu elîm hâdiseyi yapan kabilelere, belâ için bir ay sabah namazında o müşrikler aleyhine duâ buyu…","osmanli":"دعاسى قنوت"},{"kelime":"KuR’ÂN-I KERÎM","anlam":"Allahü teâlânın Cebrâil aleyhisselâm vâsıtasıyla Muhammed aleyhisselâma Arabca olarak indirdiği ve bu ana kadar tevâtürle, yani yalan söylemeleri mümkün olmayan bir cemaatin bildirmesi ile gelen son semâvî kitap.","kategori":"dil","misal":"De ki, insanlar ve cinler birbirlerine yardımcı olarak, bu Kur’ân-ı kerîmin bir benzerini ortaya koymak için bir araya gelseler, yemîn olsun ki, yine de benzerini ortaya koyamazlar. (İsrâ sûresi: 88) Evlerinizde Kur’ân-ı kerîmi çok okuyun. Kur’ân-ı kerîm okunmayan evde hayır az, şer çok olur. (Hadîs-i şerîfDâre Kutnî) Kur’ân-ı kerîme, ehliyeti olmadan mânâ veren, isabet de etse hata etmiştir. (Hadîs-i şerîfTirmizî E…","osmanli":"كريم قرآن"},{"kelime":"KuRB","anlam":"1.Yakınlık. 2.Tasavvufta, Allahü teâlâya yakın olma, âlem-i ervâhta Allahü teâlâ ile kul arasında geçen ahde vefâ gösterme.","kategori":"akaid","misal":"Kurb ve visâl (kavuşma) lezzeti, Cennet nîmetlerinin lezzetinden daha çok olduğu gibi, bu’d ve hırmân (uzaklık ve mahrumluk) azâbı da Cehennem azâbından daha kötüdür. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"قرب"},{"kelime":"Kurb-i İlâhî","anlam":"Allahü teâlâya yakınlık.","kategori":"akaid","misal":"Evliyâlık, kurb-ı ilâhî demektir. Evliyânın vilâyetten, muhabbetten, marifetten ve kurb-i ilâhîden ellerine her ne geçerse, bunları Peygamberlere tâbi’ ve tufeyl olmak sâyesinde kazanırlar. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"الهى قرب"},{"kelime":"Kurb-i Nübüvvet","anlam":"Tasavvufta nübüvvet (peygamberlik) yoluna âit yakınlık, Allahü teâlâdan gelen feyz ve bereketlere, arada vâsıta ve perde bulunmamak sûretiyle kavuşma.","kategori":"akaid","misal":"Kurb-i nübüvvet, insanı aslın aslına ulaştırır. Peygamberler aleyhimüssalevâtü vetteslîmât ve bunların sahâbîleri Allahü teâlâya bu yoldan kavuşmuşlardır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"نبوت قرب"},{"kelime":"KuRBÂN","anlam":"1.Allahü teâlâya yakınlık. 2.Mukîm, akıllı, bâliğ, hür ve zengin Müslüman erkek ve kadın tarafından, Allah rızâsı için kurban niyetiyle kurban bayramının ilk üç gününden birinde kesilmesi emrolunan koyun, keçi, sığır ve deve gibi hayvanlardan her biri. 3.Bir… İmkânı olduğu hâlde kurban kesmeyen kimse bizim namazgâhımıza yaklaşmasın.","kategori":"ibadet","misal":"(Hadîs-i şerîfİbn-i Mâce, Müsnedü Ahmed) Peygamber efendimize Kevser sûresi nâzil olup (inip); “O hâlde Rabbin için namaz kıl ve kurban kes!” buyrularak kurban kesmesi emrolundu. Peygamber efendimiz biri kendisi, biri de ümmeti için iki kurban keserler, kurban kesmeyi ve kurban kesenleri överlerdi. (İbni Âbidîn) Kurban keserken üç kere bayram…","osmanli":"قربان","alternatif":["kurban"],"baglamlar":[{"baglam":"ibâdet","anlam":"Kurban bayramında, Allah rızâsı için kesilen hayvan; vâcib olan ibâdet."},{"baglam":"adak","anlam":"Adak olarak kesilen kurban; nezir kurbanı."},{"baglam":"hac","anlam":"Hac ibâdetinde kesilen kurban; temettü' ve kırân haccında vâcib."}]},{"kelime":"Kurban Bayramı","anlam":"İslâmiyet’teki iki bayramdan biri, Zilhicce ayının onuncu, onbirinci, onikinci ve onüçüncü günleri.","kategori":"ibadet","misal":"Allahü teâlâ, Ramazan ve Kurban Bayramı günlerinde yeryüzünde rahmetiyle tecellî eder. Öyle ise namaz ve ziyaret için evlerden dışarıya çıkın ki, rahmet size dokunsun. (Hadîs-i şerîfİbni Asâkir) Kurban bayramı namazından önce bir şey yememek, namazdan sonra önce kurban eti yemek, namaza giderken yüksek sesle, özrü olan için yavaşça tekbir getirmek sünnettir. (İbni Âbidîn)","osmanli":"بايرامى قربان","alternatif":["kurban"]},{"kelime":"Kurban Bayramı Geceleri","anlam":"Kurban bayramının birinci, ikinci ve üçüncü günlerinden sonraki geceler.","kategori":"ibadet","misal":"Ramazan ve Kurban bayramı gecelerini İhyâ edenin kalbleri, kalblerin öldüğü günde öl-mez. (Hadîs-i şerîf-Taberânî)","osmanli":"كيجه بايرامى قربان لرى"},{"kelime":"KuRBET","anlam":"1.Yakınlık. 2.Tâ’at olan bir ameli, Allahü teâlânın rızasını kazanmak niyetiyle yapmak.","kategori":"akaid","misal":"Kurbet, ameli kim için yaptığını bilmek olup, niyet şart değildir. Her ikisine de lüzum yoksa tâ’at denir. Her ikisine de lüzum varsa ibâdet olur. Meselâ namaz, oruç, zekât, hac ibâdettir. Vakıf, köle âzâd etmek, sadaka vermek gibi hâllerde niyet şart değildir. Bunlara vaziyete göre tâ’at ve kurbet denir; ibâdet denmez. Mahlûkatı, tedkîk edip de Allahü teâlânın varlığını anlamak, tâ’attir, kurbet ve ibâdet değildir.…","osmanli":"قربة"},{"kelime":"KuREYŞ","anlam":"Hazret-i Peygamber aleyhisselâmın mensub olduğu Arabistan’da yaşayan Arab kabilelerinin en ileri gelenlerinden.","kategori":"dil","misal":"Arab-ı Müsta’ribe meydana geldi. Bunlardan Mudâr ve Rebîa meşhur oldu. Mudar’dan da Kinâne, Kureyş, Hevâzin, Sakîf, Temim, Müzeyne kabileleri meydana geldi. Bunlardan Fihr bin Mâlik, köpekbalığı mânâsına gelen Kureyş adıyla anıldı. Fihr, Resûlullah aleyhisselâmın onbirinci atasıdır. Fihr’in soyundan Kusay, IV. asırda Kâbe’nin etrafına yerleştirip, Kâbe hizmetini Huzâ’alılardan alarak kabilesine ayrıca itibar kazandı…","osmanli":"قريش"},{"kelime":"KÜRR","anlam":"2420.64 litre (=2348. 1978.56 litre (=1563.","kategori":"ibadet","misal":"Daha ziyade Iraklıların kul-landığı 60 kafîz (=40 irdeb=720 sâ’) mikda-rında hacim ölçüsü. Hanefîlere göre 280 kg.) buğday, diğerlerine göre ise 840 kg.) buğday alır.","osmanli":"كر"},{"kelime":"KuRRÂ","anlam":"Kârîler, Kur’ân-ı kerîm okuyucuları; kırâat âlimleri.","kategori":"dil","misal":"Kurrâ-i Seb´a: سبعه قراء (A) Kur’ân-ı kerîmin yedi farklı kırâetini (kırâet-i seb’ayı) bildiren yedi kırâet âlimi. Kurrâ olan büyük hâfızlar, yedi tânedir. Birincisi, Nâfi bin Abdurrahmân bin Ebû Nuaym; ikincisi, Abdullah bin Kesir bin Muttalib; üçüncüsü, Ebû Amr bin Alâ; dördüncüsü, İbn-i Âmir; beşincisi, Âsım bin Behdele Ebû Bekr-i Esed; altıncısı, Hamzâ bin Habib bin Ammâret ibni İsmâil ve yedincisi, Ali bin Hamz…","osmanli":"قراء"},{"kelime":"KÜRSÎ","anlam":"1.Taht. 2.Allahü teâlânın azameti, kudreti ve büyüklüğünü gösteren ve Arşın altında olduğu bildirilen Allahü teâlânın yarattığı en büyük varlıklardan biri; Allahü teâlânın hâkimiyeti, hükümranlığı. O’nun (Allahü teâlânın) kürsîsi, göklerden ve yerden geniştir. (Bakara sûresi: 255) Kürsîye dört çeşit mânâ verilmiştir: Birincisine göre gökleri ve yeri kaplayan büyük bir cisimdir. Hatta Hasen elBasrî, “Kürsî Arş ile aynı şeydir. Üzerine oturulması sebebiyle tahta bazen arş, bazen de kürsî denmektedir” der. İkincisine göre Kürsî, Allahü teâlânın hükümranlığı, kudreti ve mülkü demektir. Üçüncüsüne göre, Kürsî Allah…","kategori":"akaid","osmanli":"كرسى"},{"kelime":"KÜRSÜF","anlam":"Bâkire kızların yalnız hayz zamanında, evli veya dul kadınların ise her zaman, edep yerine koydukları bez veya saf nebâtî pamuk.","kategori":"dil","misal":"Kadınların kürsüf kullanmaları ve buna koku sürmeleri müstehâbtır. (Halebî)","osmanli":"كرسف"},{"kelime":"KuRŞuN DÖKMEK","anlam":"Nazar veya sihirden ileri geldiği zannedilen hasta-lık ve rahatsızlıkların giderilmesi için müra-caat edilen çarelerden biri.","kategori":"dil","misal":"Nazar değen veya korkan çocuk için, çöp yakıp etrafında döndürerek tütsülemek veya ergimiş mumu başı üzerinde suya dökmek ve kurşun dökmek câizdir. (Fetâvâ-i Hindiyye)","osmanli":"دوكمك قرشون"},{"kelime":"KuRû‘","anlam":"Hayız veya hayızdan temizlik (tuhr). Kar’ kelimesinin çokluk hâlidir.","kategori":"dil","misal":"Boşanmış kadınlar, üç kurû’ beklerler. (Ba-kara sûresi: 228) Hanefiler ve bir rivâyete göre Ahmed İbn Han-bel kurû’ kelimesinden hayzı, Şâfiî ve Malikîler ise kadının hayızdan temizlenmesi (tuhr) mânâ-sını anlamışlar ve boşanmış kadınların iddetle-rini bu esasa göre hesablamışlardır. (Kurtubî)","osmanli":"قروع"},{"kelime":"KuRûN-I VÜSTÂ","anlam":"“Ortaçağlar” mânâsına Roma İmparatorluğu’nun ikiye ayrıldığı Milâttan Sonra 395 yılından İstanbul’un Osmanlılar tarafından alındığı 1453 yılına kadar süren devir.","kategori":"osmanli","osmanli":"وسطى قرون"},{"kelime":"KuRuŞ","anlam":"Bir altın Osmanlı lirasının yüzde biri mikdarında gümüş para; gümüş Avusturya taleri veya altın Holanda florinine Osmanlı ülkesinde verilen isim.","kategori":"osmanli","misal":"Aslı Almanca ‘grosh’ olup, bir altın solidus (12 gümüş denarius) değerinde paradır.","osmanli":"قروش"},{"kelime":"KuŞLuK VAKTİ","anlam":"Gündüzün ilk dörtte biri geçince başlayıp zevâl (güneşin te-pede olduğu) vaktin hemen evveline kadar de-vam eden zaman. (Bkz. Duhâ Vakti)","kategori":"dil","osmanli":"وقتى قشلق"},{"kelime":"KuSMA","anlam":"Midede bulunan maddele-rin isteyerek veya istemeyerek ağız yolu ile dı-şarı çıkması. İstifrâğ. Kay. Gaseyân.","kategori":"dil","misal":"Ağız dolusu kusma abdesti ve orucu bozar. (Miftahü’l-Cenne)","osmanli":"قوصمه"},{"kelime":"KuSVÂ","anlam":"1.Son derecede bulunan; son, nihayet; son sınır; erişilecek olan en son nokta. 2.Resûlullah aleyhisselâmın devesi.","kategori":"dil","misal":"Resûlullah aleyhisselâm, Mekke’den hicret etti-ğinde bindiği devesi Kusvâ’yı Hazret-i Ebubekr radıyallahü anhden 400 dirheme satın almıştı. Başka yük ve sağmal develeri de vardı. (Muh-tasaru’s-Siyer li-İbni Cemaa) Resûlullah aleyhisselâm Kusvâ adlı devesinin üzerinde, Medîne-i Münevvere’ye girince, uğ-radığı her mahalle halkı ve her kabile, devesi-nin yularından tutarak kendilerine misâfir ol-masını çok istediler. Resûlullah aleyhisselâm devenin yularını tutmayınız. O me’mûrdur, buyurdu. Nihâyet deve sonradan mescidin ya-pıldığı yere varıp, oraya çöktü. O arsa Sehl ve Süheyl adında iki yetîmin mülkü idi. Deve çök-tüğü o yerde biraz durdu. Sonra sağına soluna baktı ve kalkıp biraz yürüdü. Sonra deve ilk çöktüğü yere bakıp, tekrar oraya gelip, orada çöktü. Resûlullah aleyhisselâm devenin üzerin-den indi. Hâlid bin Zeyd radıyallahü anh de-venin üzerindeki eşyaları evine götürdü. Daha sonra devenin ilk çöktüğü o arsa iki yetîmden satın alındı ve orada Mescid-i Nebî yapıldı. (Şevâhidü’n-Nübüvve)","osmanli":"قصوى"},{"kelime":"KuTB","anlam":"1.Değirmen taşının mili. 2.De-ğirmen milin etrafında döndüğü gibi; kâinâtın da etrafında döndüğü farzedilen, yani kâinâtta işlerin görülmesine veya insanların doğru yolu bulmasına vâsıta kılınan büyük zât. (Bkz. Kutb-i Medâr, Kutb-i İrşâd).","kategori":"fikih","osmanli":"قطب"},{"kelime":"Kutb-i Ebdâl","anlam":"Kutb-i aktâb, kutb-i medâr.","kategori":"dil","osmanli":"ابدال قطب"},{"kelime":"Kutb-i İrşâd","anlam":"İnsanların irşâdına ve hidâyetine vesîle kılınan velî zâtların reisi.","kategori":"tasavvuf","misal":"Kutb-i irşâd, âlemin irşâdı ve hidâyeti için feyzlerin gelmesine vâsıta olur. Kutb-i irşâdın her zaman bulunması lâzım değildir. Öyle zamanlar olur ki, âlem îmândan ve hidâyetten büsbütün mahrum kalır. Resûlullah sallallahü aleyhi ve sellem, zamanının kutb-i irşâdı idi. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ارشاد قطب"},{"kelime":"Kutb-i Medâr","anlam":"Âlemin nizâmı ile alâkalanan, bolluk-kıtlık, sağlık-hastalık, ba-rış-savaş, rızık, yağmur ve benzeri olaylarla va-zifeli kılınan büyük zât. Kutbü’l-Aktâb. Kut-bü’l-Ebdâl. Kutbü’l-Vücûd. Gavs. Gavsü’l-A’zâm. Kutb-i medâr, âlemde, dünyada her şeyin var olması ve varlıkta durabilmesi için feyz gelme-sine vasıta olur. Her şeyin yaratılması rızıkla-rın gönderilmesi, dert ve belâların giderilmesi, hastaların iyileşmesi, bedenlerin âfiyette olması, kutb-i medârın feyzleri ile olur. Îmân sahibi ol-mak, hidâyete kavuşmak, ibâdet yapabilmek,","kategori":"dil","misal":"günahlara tövbe etmek ise kutb-i irşâd’ın feyz-leri ile olur. Kutb-i medârın her zamanda bu-lunması lâzımdır. Âlemin ondan boş kalması mümkün değildir. Çünki âlemin nizâmı ona bağlı kılınmıştır. Eğer bu kutublardan biri gi-derse (ölürse), yerine başkası tâyin edilir. İrşâd kutbu böyle değildir. Çünki âlemin rüşd, hi-dâyet ve îmândan boş olduğu zamanlar olur. Peygamber efendimiz, zamanının irşâd kutbu idi. O zamanın kutb-i ebdâlleri de, Hazret-i Ömer ve Üveys-i Karnî idiler. (Mektûbât-ı İmâm-ı Rabbânî) Kutb-i medâra inzivâ lâzımdır. Bunları herkes tanımaz. Hattâ bazıları kendilerini bile bilmez-ler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مدار قطب"},{"kelime":"KuTBİYYET","anlam":"Kutbluk denilen yüksek evliyâlık mertebesi.","kategori":"tasavvuf","misal":"(Bkz. Kutb)","osmanli":"قطبيت"},{"kelime":"KÜTÜB-İ SİTTE","anlam":"1.“Altı kitab” mânâsına İslâm tarihinde sıhhati bakımından umumî bir kabul görmüş olan meşhur altı hadîs-i şerîf kitabı; Bunlar; Buhârî ile Müslim’in Sahîh’leri, Tirmizî, Ebû Dâvûd ve Nesâî’nin Sünen’i; İmâm Mâlik’in Muvattâ’ı veya İbn-i Mâce’nin Sünen’idir. 2.Hanefî mezhebinin aslını bildiren İmâm Muhammed’in altı kitabı.","kategori":"hadis","misal":"Bunlar elMebsût (elAsl), ezZiyâdât, elCâmi’usSagîr, esSiyerü’s-Sagîr, elCâmi’ulKebîr ve esSiye-rü’l-Kebîr’dir.","osmanli":"سته كتب"},{"kelime":"KuVVE-İ DERRÂKE","anlam":"İdrâk edici, anlayıcı kuvvet, akıl, müdrike.","kategori":"dil","misal":"Akıl, bir kuvve-i derrâkedir. İyiyi kötüden, fâi-deliyi zararlıdan ayırmak için yaratılmıştır. (Ab-dülhakîm Arvâsî)","osmanli":"دراكه قوه"},{"kelime":"LÂ HAVLE","anlam":"Sıkıntılı hâllerde zararı def etmek ve rahatlamak için söylenen ve “Güç ve kuvvet ancak Allah’a mahsustur” mânâsına gelen cümlenin ilk sözleri.","kategori":"akaid","misal":"Bir hadîs-i şerîfte; “Lâ havle velâ kuvvete okumak, doksandokuz derde devâdır. Bunların en hafifi, hemmdir.” Hemm, gam, hüzün, sıkıntı demektir. (Seâdet-i Ebediyye)","osmanli":"حول لا"},{"kelime":"LÂ İLÂHE İLLALLAH","anlam":"“Allah’tan başka ilâh yoktur” mânâsına gelen ve İslâm dininin esas rüknü olan söz.","kategori":"akaid","misal":"Kelime-i tevhid.","osmanli":"لله الا اله لا"},{"kelime":"LA‘NET (Lânet)","anlam":"Bedduâ, ilenç; bir kimsenin kötülüğünü, Allahü teâlânın af ve merhametinden mahrum olmasını, hıyânet edenlerin veya kötülüklerin gerektiği cezâya çarptırılmasını istemek.","kategori":"akaid","misal":"Allahü teâlâ ve Resûlüne eziyyet edenlere, dünyada ve âhirette de la’net olsun. (Ahzâb sûresi: 57) Kadın elbisesi giyen erkeğe ve erkek elbisesi giyen kadına la’net olsun. (Hadîs-i şerîfTaberânî) Fitne uykudadır. Allah, onu uyandırana la’net etsin. (Hadîs-i şerîfRâfiî’) Mü’mine la’net etmek onu öldürmek gibidir. (Hadîs-i şerîfTaberânî) Hiç kimseye la’net etme. Zîrâ la’net eylediğin adam, la’nete müstehak değil ise,…","osmanli":"لعنت"},{"kelime":"LÂF","anlam":"Lâkırdı, söz; konuşma.","kategori":"dil","osmanli":"لاف"},{"kelime":"LAFZ (Lafız)","anlam":"Söz. (Mânâlı olursa “kelime”, edatlarda olduğu gibi mânâsı başkalarıyla meydana gelirse “harf ” kısmına ayrılır.) Hatırla ki insanın hem sağında, hem solunda oturan onun amellerini tesbit etmekte olan iki de melek vardır.","kategori":"dil","misal":"Ve Allah lafz-ı mübârekinin mânâsını bîçûn ve bîçûnegî (ötelerin ötesi) mülâhaza edip, hiçbir sıfatı ile düşünmeyesin. (Mektûbât-ı Ma’sûmiyye)","osmanli":"لفظ"},{"kelime":"LAFZÎ","anlam":"1.Sözlü. 2.Kelimenin söylenişine ve yapısına ait.","kategori":"dil","misal":"Kelâm-ı lafzî ve kelâm-ı nefsî ise ezelî ve kadîmdir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"لفظى"},{"kelime":"LAĞV","anlam":"1.Faydasız, beyhude, boş. 2.Yanılma, atlama. 3.Kaldırma, hükümsüz bırakma.","kategori":"muamelat","misal":"Hükûmetin uşru, mal sahibine bağışlaması, afv, lağv etmesi câiz değildir. (İbni Âbidîn)","osmanli":"لغو"},{"kelime":"LAHD (Lahid)","anlam":"Çukur, mezar, kabir; kabir kazıldıktan sonra, kabrin taban sathından kıble cihetine kabir boyunca, içine ölü sığacak kadar genişlik ve derinlikte kazılan yer.","kategori":"akaid","misal":"Lahd yapmak sünnettir. Meyyit, lahd içine, sağ yanı üzere konur. Şak yapılmaz. Yani kabir kazıldıktan sonra ortasına çukur açıp, meyyit buraya konmaz. Toprak çürük, nemli ise, erkeği lahdin veya doğruca kabrin içine tabut ile koymak câiz olur. Toprak kuru ve sağlam ise, erkeği tabut ile gömmek mekrûh olur. Tabut ile gömünce tabut içine biraz toprak konur. Kadınları, her zaman tabut ile gömmek efdaldir. (Câmi’u’l-Fet…","osmanli":"لحد"},{"kelime":"LAHN","anlam":"1.Kâideye uygun ve güzel ses, nağme, melodi. 2.Ahenk. 3.Lügat; dil. 4.Kırâat ederken yanlışlık yapma.","kategori":"muamelat","misal":"(Bkz. Elhân, Zelle-tü’l-Kâri) Lahn ve nağme bulunmayan güzel sesi dinle-mek mutlaka mubahtır, mahzuru yoktur. Sıkıntı gidermek için lahn ile kendi kendine okumak câiz diyenler vardır. Fakat başkalarını eğlen-dirmek veya para kazanmak için okumak ha-ramdır. (Ahlâk-ı Alâ’î) Ezânı lahn ile, kelimelerini bozarak teganni yap-mak suretiyle okumak, tıpkı Kur’ân-ı kerîmde olduğu gibi helâl değildir. (İbni Âbidîn)","osmanli":"لحن"},{"kelime":"LAHZA","anlam":"Göz ucu ile bakış; göz ucu ile bir kere bakıncaya kadar geçen zaman.","kategori":"dil","osmanli":"لحظه"},{"kelime":"LAKAB","anlam":"Bir kimseye, kendi asıl adın-dan başka takılan ad.","kategori":"dil","misal":"Ey îmân edenler! Birbirinizi ayıplamayınız ve birbirinizi kötü lakaplarla çağırmayınız. (Hucurât sûresi: 11) Müslüman bir kimseye kötü lakap takmak veya takılan kötü lakabla onu çağırmak dil âfetle-rindendir. İyi lakabla çağırmakta bir beis yok-tur. (Birgivî Vasîyetnâmesi) Hazret-i Osmân’ın künyesi İbni Abdillah, lakâbı Zinnûreyndir. Bu lakâb, Resûlullah’ın “sallal-lahü aleyhi ve sellem” iki kızıyla evlenmesi se-bebiyle verildi. (Şevâhidü’n-Nübüvve)","osmanli":"لقب"},{"kelime":"LÂKIT","anlam":"Bir çocuğu, terk edildiği yer-den alıp kaldıran kimse. Mültekıt.","kategori":"dil","osmanli":"لاقط"},{"kelime":"LAKÎT","anlam":"Buluntu çocuk.","kategori":"dil","misal":"Lakîti terk etmek günah, görünce alıp ölüm-den kurtarmak şehirde sünnet, tenhâ yerde ise farzdır. Dârülislâm’da bulunan çocuk, hür ve mü’min olur. Lakît için, bu benim çocuğum diyen bir adamın sözü kabul edilir. Kadın söy-lerse iki şâhid istenir. İlim öğretilir. Sonra sa-nata verilir. Hükûmetten izin almadan sünnet ettirilmez, malı satılamaz. Hükûmetten izinsiz yapılan masraflar, çocuğa teberrû yani hediye olur. (Bedâyî’)","osmanli":"لقيط"},{"kelime":"LÂL","anlam":"Dilsiz; söz söyleyemeyen, dili tu-tulmuş, tat, ahraz.","kategori":"dil","osmanli":"لال"},{"kelime":"LALA","anlam":"1.Bir çocuğu gezdiren, oyalayan uşak. 2.Bir çocuğun terbiyesiyle memur zât; şehzâde hocası.","kategori":"dil","osmanli":"لالا"},{"kelime":"LÂT","anlam":"Câhiliyye devrinde Kâbe’de bulunan putlardan biri.","kategori":"dil","osmanli":"لات"},{"kelime":"LATÎF","anlam":"1.Yumuşak, hoş, güzel, nâzik. 2.Lûtf ve ihsânı bol, dâimâ güzel muâmelede bulunucu mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Latîf). 3.Gözle görülmeyen, nurânî.","kategori":"dil","misal":"Bu büyükler, tatlı yemekleri, lezîz şerbetleri, nefîs kumaşları, hazîn sesleri, nazîf kokuları, latîf manzaraları, melîh sûretleri, tatsızların-dan, çirkinlerinden daha çok istiyor ve sevi-yorlar. (Mektûbât-ı Ma’sûmiyye) Gözler O’nu idrâk edemez. Ama O, gözleri idrâk eder. O latîftir. (Her şeyden) haber-dârdır. (En’âm sûresi: 142) Allah kullarına çok latîftir. Kimi dilerse onu rızıklandırır. Kuvvetli, güçlü ancak O’dur. (Şûrâ sûresi: 19) El-Latîf ism-i şerîfini söylemeye devam ede-nin üzüntü ve elemi gider, rahat ve huzur bu-lur. (El-İstigâsetü’l-Kübrâ) Melekler cismdir, latîftir. Gaz hâlinden daha da latîftirler. Nûrânîdirler. Diridirler, akıllıdır-lar, insanlardaki kötülükler meleklerde yoktur. (İtikâdnâme)","osmanli":"لطيف"},{"kelime":"LATÎFE","anlam":"1.Hoş, tatlı söz, şaka. 2.Maddeli, zamanlı ve ölçülü olmayan Âlem-i emirdeki beş mertebeden her biri.","kategori":"tasavvuf","misal":"Latîfenin fazlası iyi görülmemiştir. Çünki, latîfenin çokluğu gülmeyi artırır. Çok gülmek kalbi öldürür, heybeti giderir. Böyle latîfelerden sakınmalıdır. (Kimyâ-i Seâdet) Zevcesine latîfe söylemeli ve kadın gibi olup, oyunlar yapmalıdır. (Ma’rifetnâme) Âlem-i emrde bulunan beş latîfenin insanda birer sûreti, benzeri vardır. Bu beş latîfey…","osmanli":"لطيفه"},{"kelime":"LÂTİN","anlam":"Osmanlıların Güney Avrupalı Katoliklere verdiği isim.","kategori":"osmanli","osmanli":"لاتين"},{"kelime":"LÂTİNCE","anlam":"HindAvrupa dil ailesinden olup Antik devirde İtalya’daki Latium mıntıkasında konuşulan, Roma İmparatorluğu’nun resmî dili olan, daha sonra Katolik Kilisesi’nin âyin ve resmî metinlerinde kullanılan lisan.","kategori":"dil","osmanli":"لاتينجه"},{"kelime":"LAVMAN","anlam":"Makattan ilaç verme, ihtikan.","kategori":"dil","osmanli":"لاومان"},{"kelime":"LÂYIK","anlam":"Liyâkatli, yakışan, yaraşır, yakışık. O’ndan başka hiçbir şey, ibâdet olunmaya lâyık değildir. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"لايق"},{"kelime":"LÂZIM","anlam":"1.Lüzum eden; bağlayıcı. 2.Ta-rafların tek başına feshetme imkânı bulunma-yan satış, kirâ gibi akid.","kategori":"muamelat","misal":"Zıddı gayr-ı lâzım gelir.","osmanli":"لازم"},{"kelime":"LEBBEYK","anlam":"1.“Buyurunuz, emir sizindir, efendim!” mânâsına kullanılan bir ta’zim kelimesi. 2.Hac ve umre için ihrama girerken söylenmesi başlayıp, cemre-i Akabe’de son bulan sünnet bir zikr.","kategori":"dil","misal":"Kul; “Ya Rabbi, ya Rabbi” dediği zaman, Allah o kimseye “Lebbeyk, kulum iste, o isteğin sana verilecektir” şeklinde buyurur. (Hadîs-i şerîfDeylemî) (Bkz. Telbiye) (Telbiye şöyledir:) Lebbeyk Allahümme lebbeyk, lebbeyk lâ şerîke leke lebbeyk in-ne’l-hamde ve’n-ni’mete leke ve’l-mülk lâ şerîke lek, (Allah’ım! Senin emri…","osmanli":"لبيك"},{"kelime":"LEBS","anlam":"1.Giyecek şey. 2.İki şeyi bir bi-rinden ayırt edememe, iltibas.","kategori":"dil","osmanli":"لبس"},{"kelime":"LEDÜNNÎ","anlam":"Allahü teâlânın marifetine ve sırlarına ait.","kategori":"akaid","osmanli":"لدنى"},{"kelime":"LEHV","anlam":"Oyun, eğlence, faydasız iş. Biliniz ki, dünya hayâtı elbette la’b (oyun) ve lehv ve zînet yani süslenmek ve tefâhur yani öğünme ve malı parayı ve evlâdı ço-ğaltmaktır. (Hadîd sûresi: 20) Her türlü lehv bâtıldır. Yalnız zevce ile oynamak, at ve si-lah ile tâlim için yarış yapmak müstesnâdır. (Hadîs-i şerîf-Tirmizî)","kategori":"hadis","osmanli":"لهو"},{"kelime":"LEM-YEZEL","anlam":"Zevâl bulmaz, zâil ol-maz, sona ermez, bâkî, kalıcı mânâsına Al-lahü teâlânın sıfatlarından.","kategori":"akaid","osmanli":"يزل لم"},{"kelime":"LEMS","anlam":"El ile dokunup duyma, el ile tutma; dokunma ile duyulan.","kategori":"dil","misal":"Allahü teâlâ, Kur’ân-ı kerîmde, cimâ’ için lems kelimesini söylemiştir. (Hadîka)","osmanli":"لمس"},{"kelime":"LERZE","anlam":"Titreme, titreyiş.","kategori":"dil","misal":"Göç zamanıdır dedi mevt, ammâ ki cân bîhaber, Asker-i a’zâya lerze düştü, sultân bîhaber. (Niyâzî Mısrî)","osmanli":"لرزه"},{"kelime":"LEŞ","anlam":"Kendiliğinden ölen veya İslâmiyet’e göre kesilmeyen ve yenmesi haram hayvanlar.","kategori":"fikih","misal":"Şöyle ki, Kur’ân’da yenmesi haram olanlar, leş ve akıcı kan ve pis domuz ve Allah’tan başkasının adı ile kesilmiş olandır. (En’âm sûresi: 145) Kasden besmele çekmeden kesilen hayvan, Besmelesiz tutulan av hayvanı, kitapsız kâfirlerin kestiği veya avladığı balıktan başka hayvan, kesmeyip de, bir yerine bıçak saplayarak, ensesine ve alnına vurarak veya boğarak veya ilâçlayarak öldürülen kara hayvanları leş olur. Bunla…","osmanli":"لش"},{"kelime":"LETÂFET","anlam":"Lâtiflik, hoşluk, tatlılık; yu-muşaklık; nezâket.","kategori":"dil","misal":"Allahü teâlâ, kıyâmette, ilâhlık makamında te-celli buyurup, yedi kat gökleri sağ kudret eline alıp buyurur ki: “Ey alçak dünya! Senin içinde rablık dâvâsı edenler ve ahmakların rab tanı-dıkları âcizler nerededir ve senin güzellik ve letâfetinle aldattığın ve âhireti unutturduğun kimseler nerededir?” (Kimyâ-i Seâdet) İslâm âlimi Müceddidî ise, bütün latîfelerinde keyfiyyetler, hâller, safâ ve letâfet ve nûrlar, sır-lar hâsıl olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"لطافت"},{"kelime":"LETÂİF","anlam":"Lâtîfe’nin çokluk hâli.","kategori":"tasavvuf","osmanli":"لطائف"},{"kelime":"LEVHÂ","anlam":"1.Bir yere asılmak üzere ya-zılmış veya yapılmış yazı veya resim. 2.(Me-cazen) Manzara, görünüş.","kategori":"dil","osmanli":"لوحه"},{"kelime":"LEVHÜ’L-MAHFûZ (Levh-i Mahfûz)","anlam":"“Korunmuş levha” mânâsına Allahü teâlânın takdir ettiği her şeyin yazılı bulunduğu, nasıl olduğu insanlarca bilinmeyen ve her türlü te’sirden korunmuş levha.","kategori":"akaid","misal":"Dünyada olacak her şey, dünya yaratılmadan evvel ezelde Levhü’l-mahfûza yazılmış, takdir edilmiştir. Bunu size bildiriyoruz ki, hayatta kaçırdığınız fırsatlar için üzülmeyesiniz ve kavuştuğunuz kazançlardan, Allah’ın gönderdiği nîmetlerden mağrûr olmayasınız. (Hadîd sûresi: 23) Allah gökleri ve yeri yaratmadan önce Levhü’l-Mahfûz’a şöyle yazmıştır. “Ben Rahman’ım. Kim sı-la-i rahmi devam ettirirse, ben ona ihsanımı…","osmanli":"المحفوظ لوه"},{"kelime":"LEVLÂKE","anlam":"Resûlullah aleyhisselâma hitâben “Lev lâke lev lâke lemâ halaktü’l-eflâk (Sen olmasaydın, sen olmasaydın, gökleri yaratmazdım) şeklinde vâki olan hadîs-i kudsî.","kategori":"hadis","misal":"Levlâke hadîs-i kudsîsi, Hâtemü’r-Rüsül sallallahü aleyhi ve sellemin şânında vâki’ olmuştur ki, hûb (sevgi) olmasaydı, yaratılış açığa çıkmaz ve âlem devamlı yoklukta kalırdı. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"لولاك"},{"kelime":"LEYL","anlam":"Gece.","kategori":"dil","misal":"Teheccüd ve kıyâm-ı leyl (gece kalkmak), tarî-ka-i aliyyenin (Nakşibendiyye’nin) zarûriyyâtın-dandır. (Mektûbât-ı Ma’sûmiyye)","osmanli":"ليل"},{"kelime":"LEZÎZ","anlam":"Lezzetli, tatlı, hoşa gider (şey). Allahü teâlânın mübâh ettiği, yani müsâade ettiği şeyler pek çoktur. Bunlarda bulunan lez-zet, harâmda bulunanlardan fazladır. (Mek-tûbât-ı Rabbânî)","kategori":"akaid","osmanli":"لذيذ"},{"kelime":"Lİ‘ÂN (Lian)","anlam":"1.La’netleşme. 2.Nûr sûresinin 6-9.","kategori":"dil","misal":"âyet-i kerîmeleri arasında tanzim olunan ve zevcesinin zinâ ettiği kanaatinde olup, bunu ispat edemeyen erkeğin, çocuğun nesebini reddetmek için müracaat ettiği; mahkemede iki tarafın da karşılıklı lânetleşmesi şeklinde cereyan eden usûl. Mülâ’ane. Li’ân için önce erkek “Sözüm doğrudur” diye yemin eder. Dört kere tekrar eder, beşincide; “Yalan söylüyorsam Allahü teâlânın lâneti benim üzerime olsun” der. Sonra kadın…","osmanli":"لعان"},{"kelime":"Lİ-ÜMM","anlam":"Anne bir (kardeş).","kategori":"dil","osmanli":"لأم"},{"kelime":"LİBERAL","anlam":"Serbest.","kategori":"dil","osmanli":"لبرال"},{"kelime":"LİBERALİZM","anlam":"Bütün ferdlerin geniş bir hürriyet içinde yaşamasını müdafaa eden, devletin ferdin hayatına ve ekonomik yaşantıya müdahale etmesine karşı çıkan siyasî, ictimaî ve iktisadî bir ideoloji.","kategori":"tasavvuf","osmanli":"لبراليزم"},{"kelime":"LİFÂFE","anlam":"1.Sargı. 2.Kefenin bir parçası.","kategori":"dil","misal":"(Bkz. Kefen) Lifâfe baştan ve ayaklardan aşırı uzunlukta olup kefenin en geniş parçasıdır. Baş üstün-den ve ayak altından uçları büzülüp bezle bağ-lanır. (Halebî)","osmanli":"لفافه"},{"kelime":"LÎK","anlam":"Lâkin, fakat, amma, ancak.","kategori":"dil","osmanli":"ليك"},{"kelime":"LİSÂN","anlam":"1.Ağızdaki dil. 2.Konuşulan dil, lügat.","kategori":"dil","misal":"Bir kez Allah dese aşk ile lisân, Dökülür cümle güneh misl-i hazân (Mevlid-i Süleyman Çelebi)","osmanli":"لسان"},{"kelime":"LİSÂN-I HÂL","anlam":"Hâl ile anlatma, hareketlerinden çıkan netice.","kategori":"dil","osmanli":"حال لسان"},{"kelime":"LİVÂ","anlam":"Sancak, bayrak, alem, ordu ku-mandanının yerini belli etmek üzere bir mız-rağın ucuna asılı bez. (Bkz. Râye)","kategori":"dil","misal":"Resûlullah aleyhisselâm gazâlarda iki türlü bay-rak kullanırdı. Râyesi siyah idi. Livâsı daha kü-çük olup beyaz idi. Râyesi siyâh idi. Livâsı daha küçük olup, beyaz idi. (Mevâhib-i Ledünniyye)","osmanli":"لواء"},{"kelime":"LİVÂTA","anlam":"Lûtîlik, Lût kavminin ameli, erkekler arasındaki cinsî sapıklık, homosek-süellik.","kategori":"dil","misal":"Livâta çoğaldığı zaman, Allahü teâlâ yed-i kudretini mahlûkâtın üzerinden kaldırır. (Hadîs-i şerîf-Taberânî) Sizden önce âlemlerden hiçbirinin yapma-dığı hayâsızlığı mı yapıyorsunuz? (A’râf sûresi: 80) meâlindeki âyet-i kerîmede geçen çirkin işin livâta olduğunu âlimler bildirdiler. (Celâleyn)","osmanli":"لواطه"},{"kelime":"LOHuSALIK","anlam":"Kadınlarda doğumdan sonra rahimden gelen kanla ortaya çıkan ve namaz, oruç gibi ibâdetlerin yapılmasını engelleyen hususî bir hâl.","kategori":"ibadet","misal":"Nifâs.","osmanli":"لق لحوصه"},{"kelime":"LOKMAN HAKÎM","anlam":"Kur’ân-ı kerîmde ismi ve hikmetli nasihatleri zikredilen peygamber veya velî.","kategori":"dil","misal":"Muhakkak biz Lokman’a hikmet verdik ve sana verilen hikmet nîmetine şükret dedik. (Lokmân sûresi: 12)","osmanli":"حكيم لقمان"},{"kelime":"LÜGAT","anlam":"1.Lisan, dil. 2.Kelime, söz.","kategori":"dil","osmanli":"لغة"},{"kelime":"LuKATA","anlam":"Yolda veya başka bir yerde bulunup da, sahibi bilinmeyen mal.","kategori":"dil","misal":"Lukata, bulanın elinde emânet hükmündedir; yani mülk edinmek için değil, başkası nâmına muhâfaza etmek için alınır. Ancak sahibi bu-lunmazsa beytülmâle verilir. Beytülmâl yoksa fakirlere sadaka verir; fakir ise kendi de kulla-nabilir. (İbni Âbidîn)","osmanli":"لقطه"},{"kelime":"LÜLE","anlam":"1.Çeşme, musluk gibi şeylere ta-kılan küçük boru. 2.Halka gibi dürülmüş şey. 3.Kâğıt külah.","kategori":"dil","osmanli":"لوله"},{"kelime":"LûT (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi bildirilen ve Ürdün ile Filistin arasında bulunan Lût gölü yanındaki Sedûm şehri halkına gönderilen peygamberlerden.","kategori":"dil","misal":"Peygamberleri yalanlayan Lût kavmi üzerine taş yağdıran bir rüzgar gönderdik. Ancak, Lût ailesi müstesna. Onları katımızdan bir nimet olarak seher vaktinde kurtardık. Şükredene işte böyle mükafat veririz. (Kamer sûresi: 33-35) Lût kavminin işini (livâta) yapan mel’ûndur. (Hadîs-i şerîfMüsnedü Ahmed)","osmanli":"لوط"},{"kelime":"LûTÎ","anlam":"Lût kavminin çirkin işini (li-vâta) yapan. (Bkz. Livâta)","kategori":"dil","osmanli":"لوطى"},{"kelime":"LÜTuF","anlam":"(Bkz. Lûtf)","kategori":"dil","osmanli":"لطف"},{"kelime":"LÜZûM","anlam":"1.Lâzım olma, gereklik. 2.Bir işe yarama. 3.Sayma.","kategori":"dil","osmanli":"لزوم"},{"kelime":"MA‘BED","anlam":"İbâdet yapmak üzere topla-nılan yer. İbâdethâne. Tapınak.","kategori":"akaid","misal":"Yahudilerin ma‘bedlerine sinagog ve havra; Hristiyanların ma‘bedine kilise, bî’a veya sav-me’a denir. Müslümanların ma‘bedine mescid ve câmi’ denir. (İbni Âbidîn) Yeryüzünde yapılan ilk ma‘bed, Mekke şehrin-deki Kâbe’dir. Buraya Mescid-i Harâm da de-nir. (Ezrâkî) Beytülmakdis gibi bazı ma‘bedleri, makamları ziyaret ettirmek için müste’minlerden para alın-ması câiz değildir. İsterse bu hususta bir âdet mevcud olsun. (İbni Âbidîn)","osmanli":"معبد"},{"kelime":"MA‘BûD","anlam":"Kendisine ibâdet olunan, tapınılan.","kategori":"akaid","misal":"Yerde ve gökte, Allahü teâlâdan başka, ibâdet edilmeye hakkı olan ve tapılmaya lâyık hiçbir şey ve hiçbir kimse yoktur. Hakîki ma‘bûd an-cak Allahü teâlâdır. (İtikadnâme)","osmanli":"معبود"},{"kelime":"MA‘DEN","anlam":"1.Yaratıldığı günden beri, yer altında bulunan bir takım ecza ve cisim-ler. 2.Bir şeyin aslı.","kategori":"dil","osmanli":"معدن"},{"kelime":"MÂ-İ CÂRÎ","anlam":"“Akıcı su” mânâsına bir saman çöpünü götürecek kadar devamlı akmakta olan ve üzerinde herhangi bir pisli-ğin durması mümkün bulunmayan çay, dere, ırmak, nehir veya yer altından çıkarılan artez-yen suları. (Bkz. Akıcı Su)","kategori":"dil","misal":"Mâ-i cârî temizdir. Kendisiyle her türlü temiz-lik yapılır. (Ni’met-i İslâm)","osmanli":"جارى ماء"},{"kelime":"MÂ-İ MÜSTA‘MEL","anlam":"“Kullanılmış su” mânâsına abdest ve guslde yâhud kurbet olarak kullanılan su.","kategori":"ibadet","misal":"Mâ-i müsta‘mel ile necâset temizlenir. Fakat abdest alınmaz ve gusl edilmez. İçmek ve hamur yapmak mekrûhtur. (İbni Âbidîn) Mâ-i Müsta‘mel, üç mezhebte (Hanefî, Şâfiî, Hanbelî’de) tâhirdir (temizdir); fakat mutahhir (temizleyici) değildir. Mâlikî mezhebinde hem tâhir hem de mutahhirdir. (elMîzânü’l-Kübrâ)","osmanli":"مستعمل ماء"},{"kelime":"MA‘İYYET (Maiyet)","anlam":"1.Beraberlik. 2.Hizmetinde ve yanında bulunanlar. 3.Her an Allahü teâlâ ile beraber olma, huzur, cem‘iyyet.","kategori":"akaid","osmanli":"معيت"},{"kelime":"MA‘KûL","anlam":"(A. Akl’dan) Akıllıca, akla uy-gun, akıllıca iş gören, anlayışlı, mantıklı.","kategori":"dil","osmanli":"معقول"},{"kelime":"MA‘LûM","anlam":"Bilinen şey. Allahü teâlâ, bazı kimselerin îmâna gelmeyeceğini bilir.","kategori":"akaid","misal":"Belli olan şeyi ispat etmeye lüzum yoktur. İnsana en ma’lûm olan şey, kendi varlığıdır. (Ahlâk-ı A’lâî)","osmanli":"معلوم"},{"kelime":"MA‘MûL","anlam":"İ‘mal edilmiş, yapılmış, işlenmiş","kategori":"dil","misal":"Sanat sahipleri, sanâyiciler, imâlâtçılar, ham ve işlenmiş, ma‘mûl eşyanın zekâtını verirler. (İbni Âbidîn)","osmanli":"معمول"},{"kelime":"MA‘MûR","anlam":"(A. Umrân’dan) İmar olunmuş, bayındır, şenlikli.","kategori":"dil","osmanli":"معمور"},{"kelime":"MA‘NEVÎ","anlam":"Ma’nâya ait; ruh ve gönülle alâkalı.","kategori":"akaid","misal":"Zevc, “Dışarı çıkarsan talâk vâki olur” der de kadın çıkarsa talâk vâki olmaz. Çünki kadına ma’nevî izâfeti terk etmiştir. (İbni Âbidîn) Kâmillerin, velîlerin ruhları, diri iken olduğu gibi, öldükten sonra da, yüksek mertebededirler. Allahü teâlâya ma’nevî olarak yakındırlar. (Tefsir-i Abdilaziz Dehlevî)","osmanli":"معنوى"},{"kelime":"Ma‘nevî Bağ","anlam":"Herhangi bir şe-kilde, iki şey arasında zihinde kurulan irti-bat. Ma’nevî râbıta.","kategori":"dil","misal":"Her şeyden, her mahlûktan (yaratılandan) Al-lahü teâlâya giden bir yol vardır. Çünki her mahlûkun kendisi ve sıfatları, O’nun kudreti-nin (kuvvetinin, gücünün) eseridir. Bu eserin sahibini bulan uyanık bir kimse, o gizli yolu ve o ma’nevî bağı görür, anlar. İnsan, her şeyin bir yapıcısı olduğunu, hiçbir şeyin kendiliğinden meydana gelmediğini düşünerek, âleme ve için-dekilere baktığı zaman, bunların da bir yara-tıcısı vardır şeklinde ma’nevî bir bağ kurarak, her şeyin yaratıcısının Allahü teâlâ olduğunu kolayca anlar. (Mektûbât-ı Ma’sûmiyye)","osmanli":"باغ معنوى"},{"kelime":"Ma‘nevî Fâide","anlam":"Ruha, kalbe ve gö-nüle âit fâide.","kategori":"tasavvuf","osmanli":"فائده معنوى"},{"kelime":"Ma‘nevî Temizlik","anlam":"İnsanın iç temizliği, kalb temizliği; kalbini her türlü bo-zuk inanış ve düşüncelerden fenâ huylardan arındırmak.","kategori":"tasavvuf","osmanli":"تميزلك معنوى"},{"kelime":"MA‘RİFET (Mârifet)","anlam":"Ârif olma, bilme, tanıma, gönülle bilme; Allahü teâlânın sıfatlarını ve isimlerini hakkıyla bilme, tanıma.","kategori":"akaid","misal":"Benden sonra ümmetim üzerine şu üç dalâletten korkarım: Hevalara uymak, karın ve fercin şehvetine uymak ve marifetten sonra gaflete düşmek. (Hadîs-i şerîfHâkim) İmâm-ı A’zâm buyuruyor ki: “Sübhâneke mâ abednâke hakka ibâdetike ve lâkin arafnâke hakka marifetike” (Ey Allah’ım! Seni noksan sıfatlardan tenzîh ederim. Biz, sana hakkıyla ibâdet edemedik. Fakat, akıl ile anlaşılamayacağını iyi anladık). Buradaki ma’rîfet…","osmanli":"معرفت"},{"kelime":"MA‘SİYYET (Masiyet)","anlam":"Kötülük; itaatsizlik, isyân, günah olan işler, Allahü teâlânın beğenmediği şeyler; haramlar, günahlar.","kategori":"akaid","misal":"İyiler de, kötüler de, iyilik yapar. Fakat yalnız sıddîklar (iyiler), ma’siyetten sakınır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"معصيت"},{"kelime":"MA‘ŞûK","anlam":"(A. Aşk’dan) Sevilen, sevil-miş (erkek).","kategori":"dil","osmanli":"معشوق"},{"kelime":"MA‘SûM","anlam":"Ismet sahibi, suçsuz, gü-nahsız; günah işlemekten korunmuş kimse. (Bkz. İsmet)","kategori":"dil","misal":"Peygamberler büyük ve küçük günahlardan ma’sûmdurlar. Hiç günah işlemezler. İnsanlar-dan ma’sûm olan yalnız peygamberlerdir. (Mif-tahü’l-Cenne)","osmanli":"معصوم"},{"kelime":"MA‘ZûR","anlam":"Özür sahibi, meşru bir ma-","kategori":"fikih","misal":"zereti olan kimse.","osmanli":"معذور"},{"kelime":"MÂBEYN","anlam":"1.İki şeyin arası, aradaki şey, ara. 2.Eskiden sarayda ve büyük evlerde haremle (kadınlar dâiresi ile) selâmlık (er-kekler dâiresi) arasındaki oda. 3.Sarayda, vü-kelânın ve diğer zevatın müracaat edecekleri ve pâdişâhın yakınlarının bulunduğu dâire.","kategori":"osmanli","osmanli":"بين ما"},{"kelime":"MÂCERÂ","anlam":"Cereyan eden, geçen, olup geçen şey, serüven, sergüzeşt.","kategori":"dil","osmanli":"ماجرا"},{"kelime":"MADDE","anlam":"Ağırlığı olan ve boşlukta yer kaplayan varlık.","kategori":"dil","misal":"Madde, Allahü teâlânın kuvvet ve kudreti ile varlıkta kalmaktadır. Kendi kendine duran madde yoktur. Bütün cisimleri, her şeyi var-lıkta durduran, Allahü teâlâdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ماده"},{"kelime":"MADDÎ","anlam":"Madde ile alâkalı, elle tutu-lur, gözle görülür, manevî olmayan.","kategori":"dil","osmanli":"مادى"},{"kelime":"MÂDEM","anlam":"Öyle ki.","kategori":"dil","misal":"Âfet-i gamdan aceb, dünyada kim âzâdedir? Herkesin bir derdi var, mâdem ki, âdem-zâdedir.","osmanli":"دم ما"},{"kelime":"MÂDÎ","anlam":"Geçmiş, mazî; geçmiş za-man kipi.","kategori":"dil","misal":"Îcâb ve kabulün ikisi de, o yerde âdet olan ke-limelerle ve mâdî şeklinde olunca, niyet etme-leri lâzım değildir. (İbni Âbidîn)","osmanli":"ماضى"},{"kelime":"MAFSAL","anlam":"1.İki şeyin ayrılma yeri. 2.Kemiklerin oynak yeri, eklem.","kategori":"dil","misal":"(A. Fasl’dan)","osmanli":"مفصل"},{"kelime":"MAĞBûN","anlam":"1.Alış verişte aldanmış, aldatılmış. 2.Şaşkın, şaşırmış","kategori":"muamelat","osmanli":"مغبون"},{"kelime":"MAĞFİRET","anlam":"Örtme; Allahü teâlânın, kullarının günahlarını örtmesi, bağışlaması.","kategori":"akaid","misal":"Ey günahı çok olan kullarım! Allah’ın rahmetinden ümidinizi kesmeyiniz. Allah, günahların hepsini affeder. O, sonsuz mağfiret ve nihâyetsiz merhâmet sahibidir. (Zümer sûresi: 53) Rabbinizden mağfiret istemeye ve Cennet’e girmeye koşunuz. Bunun için çalışınız! Cennet’in büyüklüğü, gökler ve yer küresi kadardır. Cennet, Allahü teâlâdan korkanlar için hazırlandı... (Âl-i İmrân sûresi: 133) Allahü teâlâ buyurur: “Ben ke…","osmanli":"مغفرت"},{"kelime":"MAĞFûR","anlam":"Allah tarafından günahları affedilmiş olması için duâ edilen kimse.","kategori":"akaid","osmanli":"مغفور"},{"kelime":"MAĞLûB","anlam":"Galebe edilmiş, kendisine üstün gelinmiş, yenilmiş, yenilen kimse.","kategori":"dil","osmanli":"مغلوب"},{"kelime":"MAĞRİB","anlam":"Güneşin gurub ettiği (bat-tığı) yer; Garb, batı tarafında olan memleket-ler; Afrika’nın Mısır ötesindeki şimal (kuzey) kısmı (Fas).","kategori":"dil","osmanli":"مغرب"},{"kelime":"MAĞRûR","anlam":"Aldanmış; gururlu. (Bkz. Gurûr)","kategori":"dil","misal":"Allahü teâlânın hilmine mağrur olmayın. (Yani işlediğiniz günahtan musibet gelmedi diye aldanmayın.) Bilmiş olunuz ki, Cen-net ile Cehennem, size nalınınızın tamasın-dan daha yakındır. (Hadîs-i şerîf-Ebû Kâsım) Mala mülke mağrûr olma, deme var mı ben gibi! Bir muhâlif yel eser, savurur harman gibi.","osmanli":"مغرور"},{"kelime":"MÂH","anlam":"1.Ay, kamer. 2.Senenin on ikide bir kısmı, ay, şehr.","kategori":"dil","osmanli":"ماه"},{"kelime":"MAHAL","anlam":"(A. hulûl’den) Yer, mekân.","kategori":"dil","osmanli":"محل"},{"kelime":"MAHALLE","anlam":"Bir şehir veya kasabanın, bölündüğü kısımlardan her biri","kategori":"dil","misal":"Mahalle mescidinde, yüksek yerde ezan oku-ması sünnettir. (İbni Âbidîn)","osmanli":"محله"},{"kelime":"MAHALLÎ","anlam":"Mahalle ait, lokal.","kategori":"dil","osmanli":"محلى"},{"kelime":"MAHBûB","anlam":"(A. Hubb’dan) Muhabbet edi-len; sevilen, sevgili.","kategori":"dil","misal":"Sevgili, sevenin gözünde, belki aslında, her za-man ve her hâlde, sevgili olduğu için, sevenin gözünde, belki aslında mahbûb olur. (Mektû-bât-ı İmâm-ı Rabbânî)","osmanli":"محبوب"},{"kelime":"Mahbûb-i Hudâ","anlam":"Allahü teâlânın habîbi, sevgilisi mânâsına Muhammed aleyhisselâm için kullanılan bir tabir.","kategori":"akaid","misal":"Muhammed Resûlullah sallallahü aleyhi ve sellem, Mahbûb-i Hüdâ’dır. Gelmiş ve gelecek bütün varlıkların her bakımdan en üstünüdür. (Mektûbât-ı İmâm-ı Rabbânî) Sakın terk-i edebden kûy-i Mahbûb-i Hüdâdır bu, Nazargâh-ı ilâhîdir makâm-ı Mustafâdır bu. (Nâbî)","osmanli":"خدا محبوب"},{"kelime":"MAHBûBİYYET","anlam":"Sevgili olmak. Peygamber efendimize tâbi olmanın en yüksek derecesi mahbûbiyyet ve ma’şûkiyyet kemâlâtına sahip olmaktır ki, bu, Allahü teâlânın çok sevdiklerine mahsûstur.","kategori":"akaid","misal":"Bunun ele geçmesi için muhabbet lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"محبوبيت"},{"kelime":"MAHBûS","anlam":"Hapsolunmuş, bir yere kapatılmış.","kategori":"dil","misal":"Su yakın ise de, su yanında düşman, yırtıcı, ze-hirli hayvan, ateş veya nöbetçi varsa veya ken-disi mahbûs ise veya abdest alırsan seni öldürü-rüz, malını alırız diye korkuturlarsa, teyemmüm ederek kılar ise de, bu sebebler kul tarafından oldukları için, gusl ve abdest alınca, bu na-mazları tekrar kılması lâzımdır. (İbni Âbidîn)","osmanli":"محبوس"},{"kelime":"MAHCûB","anlam":"1.Kapalı, örtülü, perdeli, mestur. 2.Utanan, utanmış, utangaç.","kategori":"akaid","misal":"(A.Hicâb’dan) Allahü teâlânın râzı olmadığı şeyleri, öldürücü zehir bilmelidir. Kusurlarını düşünüp, bunları yaptığına mahcûb olmalı, utanmalıdır. (Mek-tûbât-ı İmâm-ı Rabbânî)","osmanli":"محجوب"},{"kelime":"MAHCûR","anlam":"1.Hacr edilmiş, yasaklanmış; men edilmiş. 2.Çocukluk, sefîhlik (israf), borçluluk, delilik, kölelik, bunaklık vs. gibi çeşitli sebebler yüzünden malına tasarruf etme hakkından men edilmiş kimse. (Bkz. Hicr) Çocuk, köle ve deli kendiliğinden; borçlu ve sefih ise mahkeme kararıyla mahcur sayılır. (Fetâvâ-i Hindiyye)","kategori":"ibadet","osmanli":"محجور"},{"kelime":"MAHDûD","anlam":"Tahdîd edil-miş, sınırlanmış.","kategori":"dil","osmanli":"محدود"},{"kelime":"MAHDûM","anlam":"1.Hizmet edilmiş, efendi. 2.Oğul, evlât.","kategori":"dil","osmanli":"مخدوم"},{"kelime":"MAHFAZA","anlam":"(A. Hıfz’dan) İçinde öteberi saklanan küçük kutu, kab, zarf.","kategori":"dil","osmanli":"محفظه"},{"kelime":"MAHFÎ","anlam":"(A. Hafî’den) Gizli, saklı.","kategori":"dil","osmanli":"مخفى"},{"kelime":"MAHFİL (Mahfel)","anlam":"1.Toplantı yeri. 2.Câmide müezzin, hükümdar gibi kişilerin namaz kılması için yapılmış etrafı parmaklıkla çevrili, yerden yüksek mekân.","kategori":"ibadet","osmanli":"محفل"},{"kelime":"MAHFûZ","anlam":"1.Hıfzolunmuş, saklanmış, korunmuş, gözetilmiş. 2.Gizlenmiş. 3.Hâfızaya alınmış, ezberlenmiş.","kategori":"dil","misal":"(A. Hıfz’dan) Evliyâ hatâ yapmaktan mahfûz değildir. (Mek-tûbât-ı Ma’sûmiyye)","osmanli":"محفوظ"},{"kelime":"MÂHİR","anlam":"Mahâretli, hünerli, elinden iş gelir, becerikli.","kategori":"akaid","osmanli":"ماهر"},{"kelime":"MÂHİYYET","anlam":"Öz, asıl, esas, bir şe-yin aslı, içyüzü.","kategori":"dil","osmanli":"ماهيت"},{"kelime":"MAHKEME","anlam":"Hüküm verilen yer, dâvâların görülüp, hükme bağlandığı meclis.","kategori":"osmanli","misal":"Ölüm, dayak gibi cezâlara mahkeme karar verir. (İbni Âbidîn)","osmanli":"محكمه"},{"kelime":"MAHKûM","anlam":"1.Kendisine hükmolunan, birinin hükmü altında bulunan. 2.Mahkemede hüküm giymiş.","kategori":"fikih","misal":"Allahü teâlâyı mecbur bilmek şöyle dursun, O’nu birisine mahkûm bilmek, üzerinde bir hâkim bulunacağını söylemek, çok çirkin bir sözdür. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"محكوم"},{"kelime":"MAHLûK","anlam":"Halk edilmiş, yaratılmış, yoktan vâr edilmiş.","kategori":"dil","misal":"Kadîm ve ezelî olan, bâkî ve ebedî olur. Hâdis ve mahlûk olan, fânî ve muvakkat olur, yani yok olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مخلوق"},{"kelime":"MAHLûKÂT","anlam":"Mahlûklar, yaratılanlar. Evliyânın iki alâmeti vardır: et-Ta’zîmü li-em-rillah ve’ş-şefakatü li-halkıllah. Yani Allahü teâlânın emirlerine ta’zim ve mahlûkâtına şef-kat. (Ma’rifetnâme)","kategori":"akaid","osmanli":"مخلوقات"},{"kelime":"MAHLûL","anlam":"1.Hallolunmuş, çözülmüş, dağılmış. 2.Erimiş, eritilmiş, eriyik. 3.Sahipsiz maaş veya me’murluk ya da kirâcı-sız toprak. 4.Mirasçısı bulunmayan ve hükü-mete kalan miras.","kategori":"dil","osmanli":"محلول"},{"kelime":"MAHMASA","anlam":"Açlıktan öl-mek üzere olma hâli.","kategori":"dil","misal":"Kim mahmasa hâlinde, çâresiz kalırsa, gü-naha meyl (yönelme) maksadı olmaksızın haram etlerden yiyebilir. Çünki Allah çok bağışlayıcı, affedicidir. (Mâide sûresi: 3)","osmanli":"مخمصه"},{"kelime":"MAHMEL (Mahmil)","anlam":"Seyahatlerde, deve gibi hayvanların üzerinde daha ziyade kadınlar için yapılmış kapalı mekân.","kategori":"osmanli","misal":"Hayvan üzerinde seyahat eden kimse mümkün ise, namazını, hayvanı kıbleye karşı durdurup kılar. Mümkün değil ise, hareket cihetlerinde kılar. Hayvan üzerindeki mahmel denilen sandık gibi şeylerin içinde kılmak da böyledir. (Ni’met-i İslâm) Mahmel üzerinde nasıl namaz kılınacağını sormak için, İmâm-ı Muhammed Bâkır’ın huzuruna gittim. Henüz ben bir şey söylemeden, Resûlullah aleyhisselâm binek hayvanı ne tarafa giders…","osmanli":"محمل"},{"kelime":"MAHMûD","anlam":"1.Övülmüş, övülen. 2.Resûlullah aleyhisselâmın isimlerinden.","kategori":"dil","osmanli":"محمود"},{"kelime":"MAHREC","anlam":"1.Hurûc edilen, çıkılan yer. 2.Ağızda harflerin çıktığı yer.","kategori":"dil","osmanli":"مخرج"},{"kelime":"MAHREK","anlam":"Hareketli bir noktanın veya bir gök cisminin takip ettiği yol. Yörünge. Orbit.","kategori":"dil","osmanli":"محرك"},{"kelime":"MAHREM","anlam":"1.Şeriatin haram ettiği şey. 2.Nikâh düşmeyen, evlenilmesi haram olan akraba. 3.Kadının örtünmesi gerekmeyen yakın erkek akrabası. 4.Samimi, içli dışlı. 5.Gizli, herkese söylenmeyen, herkesin bilmemesi gereken.","kategori":"dil","misal":"Kadın, yanında bir mahremi olmadan sefere gidemez. (Hadîs-i şerîfBuhârî, Müslim, İbn-i Mâce, Dârimî) Mahrem olan şeylerinizi herkese söylemeyin. Sonunda pişman olur, âh edersiniz. (Abdülhakîm Arvâsî)","osmanli":"محرم"},{"kelime":"Mahrem Akrabâ","anlam":"Ebedî mahrem olan, nikâh ile alınması ebedî haram olan onsekiz erkek ve kadın.","kategori":"fikih","osmanli":"اقرباء محرم"},{"kelime":"MAHRûM","anlam":"1.Bahtsız, nasipsiz. 2.İstediğini, dilediğini elde edemeyen MAHRûMİYYET: محروميت (A) Mahrumluk, dilediğini, istediğini elde edememe.","kategori":"dil","misal":"(A. Hirmân’dan)","osmanli":"محروم"},{"kelime":"MAHRûT","anlam":"Koni.","kategori":"dil","osmanli":"مخروط"},{"kelime":"MAHŞER","anlam":"Haşr olunacak, toplanılacak yer.","kategori":"akaid","misal":"Mü’minler için (kıyamette) nurdan kürsüler kurulur. Bir bulut üzerlerine gölge yapar ve onlara mahşer günü, gündüzün bir saati gibi gelir. (Hadîs-i şerîfTaberânî) Mahşerde imanı olup, ameli ve ahlâkı güzel olanlara mükâfât ve ihsanlar olacaktır. Kötü huylu, bozuk amellilere ise, ağır cezâlar verilecektir. (İtikadnâme)","osmanli":"محشر"},{"kelime":"MAHSûL","anlam":"1.Husûl bu-lan, hâsıl olan, meydana gelen, elde edilen şey.","kategori":"fikih","misal":"(A. Husûl’den) İş zamanını eğlence ile geçirmek, çiftçinin to-hum ekmemesi ve mahsûl almaması gibidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"محصول"},{"kelime":"MAHV","anlam":"1.Yok etme, ortadan kaldırma; harap etme, perişan etme; batma, bitme, yok olma. 2.Tasavvufta beşerî nakîsalardan, eksiklikler-den, kusurlardan kurtulma hâli, ispatın zıddı.","kategori":"dil","misal":"Kalbe gelen bütün keşfleri, hâlleri bize verseler, fakat kalbimizi Ehl-i sünnet i’tikâdı ile süsle-meseler, kendimi mahv olmuş ve hâlimi harap bilirim. (Mektûbât-ı Ma’sûmiyye)","osmanli":"محو"},{"kelime":"MAHYA","anlam":"Mübarek gecelerde, câmilerde iki minâre veya minâre ile kubbe arasına gerilen ve halatlara asılı kandillerle yazılan yazı ve şekiller.","kategori":"ibadet","misal":"(Aslı Farsça aylık demek olan mâhiye’dir.)","osmanli":"محيا"},{"kelime":"MAHZEN","anlam":"İçinde eşya sak-lanacak yer; yer altı, bodrum.","kategori":"dil","osmanli":"مخزن"},{"kelime":"MAHZûN","anlam":"Hüzünlü, ta-salı, kaygılı, mükedder.","kategori":"dil","osmanli":"محزون"},{"kelime":"MAHZûR","anlam":"Dinde yasak edilmiş, haram. Çokluk hâli mahzûrât gelir. Zarûretler, mahzûrâtı mübâh kılar. Yani yapıl-ması men ve yasak edilmiş bazı şeyler vardır ki, bunları yapmak, zarûret hâlinde mübâh hük-münde olur. Meselâ; açlıktan helâk olmak kor-kusundan dolayı, başkasının yiyeceğini rızâsı olmaksızın yemek böyledir. (Dürerü’l-Hükkâm)","kategori":"fikih","osmanli":"محذور"},{"kelime":"MÂÎ","anlam":"Sıvı, akışkan.","kategori":"dil","osmanli":"مائى"},{"kelime":"MÂİDE SûRESİ","anlam":"114.âyet-i kerîmelerde Îsâ aleyhisselâm zamanında gökten indirilmesi istenen bir sofradan bahsedildiği için sûre bu ismi almıştır. Akidler mânâsına Ukûd; hükümler çeşitli âyetlere serpiştirildiği için Müba’sire Sûresi de denir. Sûrede; Âdem ve Mûsâ aleyhimesselâm kıssaları ile Îsâ aleyhisselâmın mûcizesi, hac, abdest, gusül, teyemmüm, c…","kategori":"dil","misal":"Kur’ân-ı kerîmin beşinci sûresi. Medîne’de nâzil oldu. Yüz yirmi âyet-i kerîmedir. Mâide, sofra demektir. 112 ve","osmanli":"سى سوره مائده"},{"kelime":"MÂİL","anlam":"1.Bir yana eğilmiş, eğik, eğri. 2.Hevesli, istekli, düşkün. 3.Andı-rır, benzer.","kategori":"dil","misal":"Ubeydullah-ı Ahrâr hazretleri vahdet-i vü-cûde mâil oldukları hâlde, şeriate yapışmakta ve şeriati yaymakta, misli yok idi. (Mektûbât-ı Ma’sûmiyye)","osmanli":"مائل"},{"kelime":"MAKÂL","anlam":"Söz, lâkırdı; söy-leme, söyleyiş.","kategori":"dil","misal":"Li-külli zemenin ricâl ve makâl (Hazret-i Ali) [Her devirdeki farklı insanlar için söylenecek farklı sözler, hükümler vardır.]","osmanli":"مقال"},{"kelime":"MAKÂLE","anlam":"1.Söz, nutuk. 2.Tek bir bahis üzerine kaleme alınan yazı.","kategori":"dil","osmanli":"مقاله"},{"kelime":"MAKÂM","anlam":"1.Durulacak yer, mevki. 2.Rütbe, memuriyet, mansıb. 3.Enbiya veya evliyadan bir zâtın mezarı ol-duğu zannedilen yer. 4.Musiki usûlü. 5.Tasav-vuf yolunda bulunan kimsenin bu yolda iler-lerken kazandığı mânevî derecelerden her biri.","kategori":"dil","misal":"(A. Kıyâm’dan) Vera’ın tamam olması için, lisanını gıybetten korumalı, suizandan kaçınmalı, kimse ile alay etmemeli, yabancı kadınlara bakmamalı, doğru söylemeli, Allahü teâlânın nimetlerinin çoklu-ğunu düşünerek, kendini ucbdan kurtarmalı, malı boş yerlere harcamamalı, nefsi için mevki, makam istememeli, namazları vaktinde kılmalı, Ehl-i sünnet âlimlerinin bildirdikleri îmân ve iyi işleri öğrenip, kendini bunlara uydurmalı-dır. (Mektûbât-ı İmâm-ı Rabbânî) Mal için makam için hep uğraştım, Sonsuz nîmetlerden oldum, âh yazık! (Mevlânâ Hâlid-i Bağdâdî) Dinimizde öyle bir yüksek makam vardır ki, insan bu makama varınca kendini ve her şeyi unutur. Bu da fenâ makamıdır. (Mektûbât-ı Ma’sûmiyye)","osmanli":"مقام"},{"kelime":"Makâm-ı İbrâhim","anlam":"Mekke’de Mes-cid-i Harâm içindeki Kâbe kapısı karşısında bulunan ve İbrâhim aleyhisselâmın, Kâbe’yi inşâ ederken veya insanları hacca da’vet eder-ken üstüne çıktığı rivâyet olunan yer.","kategori":"dil","misal":"Biz, Beyt’i (Kâbe’yi) insanlar için toplanma ve emniyet yeri kıldık. Siz de Makam-ı İbrâ-him’i namaz yeri edinin! (Bakara sûresi: 125) Vâcib olan iki rek’atlik tavaf namazını Ma-kam-ı İbrâhim’in arkasında kılmak müstehab-dır.(İbni Âbidîn)","osmanli":"ابراهيم مقام"},{"kelime":"MAKÂMÂT-I AŞERE","anlam":"“On makam” mânâsına tasavvufta fenâ makamının başlangıcında olan ve fenâ makamına kavuşmak için lâzım olan on şey.","kategori":"tasavvuf","misal":"Makâmât-ı aşere şunlardır: Tövbe, zühd (mübâhların fazlasını terk etmek), tevekkül (meşrû sebeblere yapışarak, bütün işleri Hakk’a ısmarlamak), kanâat (nafakada zarûretten çok istememek), uzlet (insanlardan uzaklaşmak), zikr (Allahü teâlâyı anmak), teveccüh (bütün arzu ve isteklerinden sıyrılarak Allahü teâlâya yönelmek), sabır (nefsin kötü arzularına mukavemet), murâkabe (kendini hesâba çekmek) ve rızâ (Allahü teâl…","osmanli":"عشره مقامات"},{"kelime":"MAKBûL","anlam":"1.Kabul olunmuş, alınmış, alınan. 2.Beğenilen, hoş karşılanan; geçer.","kategori":"dil","misal":"Allahü teâlâ yüzbin sene ibâdet eden makbûl bir kulunu, bir günah için, sonsuz olarak red edebilir ve hiçbir şeyden çekinmez. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مقبول"},{"kelime":"MAKBûZ","anlam":"1.Kabzolun-muş, alınmış. 2.Kabz hâline girmiş, sıkılmış, daraltılmış. 3.Bir şeyin alındığına karşı veri-len mühürlü, imzalı kâğıt.","kategori":"dil","misal":"(A. Kabz’dan) Vekîl öderken beyyine (iki şâhid) bulunmazsa veya makbûz almazsa, mes’ûl olmaz. (Fetâvâ-yı Hindiyye)","osmanli":"مقبوض"},{"kelime":"MAKSAD","anlam":"Kasd edilen, gâye, he-def, niyet.","kategori":"dil","misal":"Haramlardan korunmak maksadı ile nikâh-lanan kimseye, Allahü teâlânın yardımı hak olur. (Hadîs-i şerîf-İbn-i Müneyy)","osmanli":"مقصد"},{"kelime":"MAKSûD","anlam":"Kasd olunan, kavuşmak istenilen, arzu edilen, meram. Maksad. “Maksûdun, ma’bûdundur” sözü meşhurdur. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"dil","misal":"Erişir menzil-i maksûduna aheste giden, Tiz reftâr olanın pâyine dâmen dolaşır. (Hâtemî)","osmanli":"مقصود"},{"kelime":"MAKTû‘","anlam":"Kesilmiş, götürü, pazarlıksız. MAKTû‘ HADÎS: حديث مقطوع (T) Tâbiîn veya Tebe-i tâbiînden rivâyet edilen söz. Resûlullah","kategori":"hadis","misal":"aleyhisselâmın söylediğine dair bir delil varsa merfû hadîs olarak kabul edilir.","osmanli":"مقطوع"},{"kelime":"MAKTû‘ HADÎS","anlam":"Tâbiîn veya Tebe-i tâbiînden rivâyet edilen söz.","kategori":"hadis","misal":"aleyhisselâmın söylediğine dair bir delil varsa merfû hadîs olarak kabul edilir.","osmanli":"حديث مقطوع"},{"kelime":"MAKTûL","anlam":"Katlolunan, öldürülen. İki Müslüman, kılıçları ile karşılaştıkları za-man, kâtil de, maktûl de, Cehennem’dedir. Zîrâ maktûl de karşısındaki adamı öldür-meyi murâd etmişti. (Hadîs-i şerîf-Müslim) Maktûlün velîlerinden biri affederse veya velî ile kâtil belli bir mal, para ile uyuşursa, kısas yapılmaz, uyuşulan mal alınır. (İbni Âbidîn)","kategori":"hadis","osmanli":"مقتول"},{"kelime":"MÂL","anlam":"İnsanın ihtiyaç duyduğu ve üzerinde tasarruf edebildiği kıymetli şey; servet.","kategori":"tasavvuf","misal":"İmâm Ebû Hanife’ye göre menfaat, mal değildir. Mal, ihtiyaç vaktinde faydalanmak için biriktirilebilen şeydir. İmâm Şâfiî’ye göre ise menfaat maldır. (İbni Âbidîn) Mal, tab’-ı insanî maîl olup da vakt-i hâcet için iddihar olunabilen şeydir ki, menkule ve gayrimenkule şâmil olur. (İster taşınsın, ister taşınmaz olsun, insanın yaratılışında isteyip de ihtiyaç zamanı için biriktirilen şey maldır.). (Mecelle, m. 126)","osmanli":"مال"},{"kelime":"Mâl-ı Habîs","anlam":"Pis mal. Gasb edilen, çalınan, fâiz, rüşvet, kumar ile alınan, çalgı çalmak, ağıt söylemek ücreti ve şarap satışı bedeli olarak alınan, fâsid bey’ ile satın alınan mal.","kategori":"muamelat","misal":"Mâl-ı habîsi kullanmak, haramdır. Sahiplerine geri verilmeleri, sahipleri bilinmiyorsa, fakirlere sadaka verilmeleri lâzım olur. (Hadîka)","osmanli":"خبيث مال"},{"kelime":"MÂLÎ","anlam":"Mala ve paraya dair, mal ile alâkalı.","kategori":"dil","misal":"Kul hakkı beş dürlüdür: Mâlî, nefsî, ırzî, mah-remî ve dinî. Sirkat, gasb, aldatmak ile ve ya-lan söylemekle mâl satmak, kalp akça vermek, başkasının mâlına ziyân vermek, yalancı şâ-hidlikle veya zâlime haber vermekle veya rüş-vet vermekle, mâlına zarar vermek, mâlî olan kul haklarıdır. Bunun için tövbe etmek ve sa-hibi ile helâllaşmak lâzımdır. (Berîka)","osmanli":"مالى"},{"kelime":"MÂLİK","anlam":"1.Mülk sahibi, sahip olan, mülk edinen. 2.Cehennem meleklerinin en büyüğü, âmiri, bekçisi.","kategori":"muamelat","misal":"Allahü teâlâ din gününün mâlikidir. (Fâtiha sûresi: 3) Mâlik olunmayan şeyin satılması sahih olmaz. (Hadîs-i şerîfBeyhekî) Nisâba mâlik olduktan bir sene sonra malın zekâtı verilir. (İbni Âbidîn)","osmanli":"مالك"},{"kelime":"MÂLİKÎ","anlam":"Ehl-i sünnetin ameldeki dört mezhebinden İmâm Mâlik bin Enes’in mezhebine tâbi olan olan kimse.","kategori":"hadis","misal":"(Bkz. İmâm-ı Mâlik)","osmanli":"مالكى","alternatif":["maliki"]},{"kelime":"Mâlikî Mezhebi","anlam":"Ehl-i sünnetin ameldeki dört mezhebinden İmâm Mâlik bin Enes’in kurduğu mezheb.","kategori":"dil","misal":"(Bkz. İmâm-ı Mâlik)","osmanli":"مذهبى مالكى","alternatif":["maliki"]},{"kelime":"MÂLİYYET (Mâliyet)","anlam":"1.Mal sayılma, mal vasıflarını hâiz olma. 2.Alış fiyatına taşıma, işçilik ücretleri, vergi gibi masrafların eklenmesiyle meydana gelen fiyat.","kategori":"ibadet","misal":"Bir Müslüman, zimmînin şarabını gasp ederek onu sirke yapsa, sirke onun olur; şarabın sirke yapılan gündeki kıymetini tazmin eder. Her ne kadar Müslüman için değil ise de, şarabın maliyeti kâfirin hakkında mevcuttur. (İbni Âbidîn) Mâl oluş fiyatı. Satıcı, “Bu malın maliyeti şu kadardır” diyerek müşteriyi aldatsa, müşt…","osmanli":"ماليت"},{"kelime":"MANASTIR","anlam":"Hristiyanlıkta keşiş adı verilen ve inzivaya çekilen din adamları ile kendisini dine adayan kimselerin bir arada yaşadığı, umumiyetle şehirlerden uzak ve ulaşılması zor yerlerde kurulan binâ. Deyr. Aslı Yunanca inziva yeri mânâsına “monas-terion”dan gelir.","kategori":"dil","misal":"Resûlullah aleyhisselâm bir mektûbunda bu-yurdu ki: “Gayrımüslimlerin dinî reislerini, makamlarından indirmeyin. Onları ibâdet ettikleri yerden çıkartmayın. Bunlardan seyâhat edenlere mâni olmayın. Bunların manastırlarının hiçbir tarafını yıkmayın. Bunların kiliselerinden mal alınıp Müslü-man mescidleri için kullanılmasın...” (Mec-mua-i Münşeâtü’s-Salâtin) Harbde, insanlara karışmayan manastırdaki rahipler, kilisedeki hademeler öldürülmez. (İbni Âbidîn)","osmanli":"مناستر"},{"kelime":"MANGIR","anlam":"Bakır para. Aslı Arabca sivri uçla oyulmuş, hakkedilmiş mânâsına mankûr kelimesinden gelir.","kategori":"dil","osmanli":"مانغير"},{"kelime":"MÂNİ‘","anlam":"1.Men’ eden, engelleyen. 2.Din ve dünyaya ait zararları gideren, men’ eden mânâsına Allahü teâlânın Esmâ-i hüsnâsın-dan (el-Mâni’).","kategori":"akaid","misal":"El-Mâni’ ism-i şerîfini söyleyen kimse, kendi-sine gelecek belâdan korunmuş olur. (El-İsti-gâsetü’l-Kübrâ)","osmanli":"مانع"},{"kelime":"MANİFATuRA","anlam":"Kumaş tüccarı.","kategori":"dil","osmanli":"مانيفاطوره"},{"kelime":"MANTIK","anlam":"1.Söz. 2.Doğru muhakeme ve doğru düşünceyi öğreten ilim. 3.Lüzum, maksat veya hüküm ile iş, vâsıta veya delil arasında tutarlılık.","kategori":"dil","misal":"(A. Nutk’dan) Müslüman mantıklı hareket eder. Çünki o kendi fikrine göre değil, büyük İslâm âlimlerinin bil-dirdiklerine göre hareketlerini ayarlar. (Seâ-det-i Ebediyye)","osmanli":"منطق"},{"kelime":"MANZARA","anlam":"Bakılıp seyredilen yer; görünüş.","kategori":"tasavvuf","misal":"Cansız resimleri, meselâ ağaç, manzara resimleri, nerede bulunursa bulunsun, namaz mekrûh olmaz. (İbni Âbidîn)","osmanli":"منظره"},{"kelime":"MANZûM","anlam":"1.Nazmolun-muş, tanzîm edilmiş, dizilmiş, düzenlenmiş, sıralanmış. 2.Şiir şeklinde.","kategori":"dil","misal":"(A. Nazm’dan)","osmanli":"منظوم"},{"kelime":"MANZûME","anlam":"1.Sıra, dizi, takım; sistem. 2.Vezinli, kafiyeli söz, şiir.","kategori":"dil","misal":"(A. Nazm’dan)","osmanli":"منظومه"},{"kelime":"MARAZ","anlam":"Hastalık.","kategori":"dil","misal":"Taâmın evvelinde, Besmele-i şerîfeyi söyleme-yen kimse için üç zarar vardır: Şeytân, kendi-siyle birlikte taâm yer. Yediği taâm, bedenine maraz olur. Taâmda bereket olmaz. (Kudûrî)","osmanli":"مرض"},{"kelime":"Maraz-ı Mevt","anlam":"Ölüm hastalığı. İnsanı ölüm korkusuna sevk edip iş görmek-ten men eden ve başladığı tarihten itibaren en az bir yıl içinde ölüme götüren hastalık veya muharebede, batan gemide, salgın bulunan şehirde olma gibi buna benzer tehlikeli hâller. Maraz-ı mevtte hibe, ibrâ gibi teberruat vasîyet hükümlerine tâbidir; yani borçtan kalan kısmın üçte birinden câridir. Satış, kirâ gibi karşılıklı muameleleri ise piyasa fiyatı üzerinden mute-berdir. Maraz-ı mevtte evlenilen kadına verilen mehr-i mislden fazla olamaz. Maraz-ı mevtte bâin talâkla boşanan kadın, iddeti içinde ko-casına vâris olur. (İbni Âbidîn)","kategori":"dil","osmanli":"موت مرض"},{"kelime":"MARKSİZM","anlam":"Alman iktisatçı Karl Marks (v.1888) tarafından materyalizm esa-sına dayalı olarak kurulan, istihsal vâsıtalarının ferdlerde değil de, devlette olmasını müdafaa edip ferdî teşebbüse karşı çıkan, sınıf farkını reddeden iktisadî ve felsefî görüş.","kategori":"dil","osmanli":"مارقسيزم"},{"kelime":"MÂŞÂALLAH","anlam":"“Bu, Allahü teâlânın dilediği ve ihsân ettiği şeydir” mânâsına beğenilen şeyler görüldüğünde söylenilen mübârek bir söz.","kategori":"akaid","misal":"Bir kimse hoşa gidecek bir şey gördüğünde; “Mâşâallah, lâ kuvvete illâ billâh” derse, ona nazar değemez. (Hadîs-i şerîfBeyhekî) Bâzı kimseler bir şeye bakıp, beğendiği zaman gözlerinden çıkan şuâ zararlı olup, canlı ve cansız her şeyin bozulmasına sebeb oluyor. Bunun misâlleri çoktur. Fen, belki bir gün bu şuâları ve tesirleri anlayabilecektir. (Seâdet-i Ebediyye)","osmanli":"ماشاءالله"},{"kelime":"MASAL","anlam":"Fevkalâde hâdiselerle dolu hikâye.","kategori":"hadis","misal":"Aslı Arabca mesel’dir.","osmanli":"مصال"},{"kelime":"MASDÂR","anlam":"1.Bir şeyin sudur ettiği, çıktığı yer, kaynak, temel. 2.Gramerde fiillerin şahıs ve zaman göstermeyen, fakat müspet ve menfî hâlleri bulunabilen isim şekli.","kategori":"dil","misal":"(A. Sudûr’dan) Masâdıru’t-Teşrî: ‘ التشريع مصادر (A) “Şeriatin kaynakları” mânâsına Kur’an-ı kerim, sünnet, icmâ‘, kıyas gibi şer‘î delilleri ifade eden tâbir.","osmanli":"مصدر"},{"kelime":"MÂSİVÂ","anlam":"Allahü teâlâdan başka her şey; âlem, tabiat, mahlûklar.","kategori":"akaid","misal":"Bir kimse, mâsivâ derdi ile sabahlarsa onun Allahü teâlâ ile alâkası yoktur. (Hadîs-i şerîf-İbni Neccâr) Akla hayâle gelen, düşünülen, görülen her şey mâsivâdır. (Mektûbât-ı İmâm-ı Rabbânî) Bize ve size hepsinden önce lâzım olan şey, kalbi Allahü teâlâdan başka şeylerin tama-mından kurtarmaktır. Kalbin bu selâmete ere-bilmesi için, Hak teâlâdan başka hiçbir şeyin kalbden geçmemesi lâzımdır. Kalbden hiçbir şe-yin geçmemesi için de mâsivâyı unutmak lâ-zımdır. Bunları unutmaya fenâ denir. (Mektû-bât-ı İmâm-ı Rabbânî)","osmanli":"ماسوى"},{"kelime":"MASKARA","anlam":"1.Göz boyası. 2.Göz bo-yama ve şaklabanlıkla insanı eğlendiren kimse.","kategori":"dil","misal":"Aslı Arabca masharâ’dir.","osmanli":"مصقره"},{"kelime":"MASKE","anlam":"Tanınmamak veya başka sebeble yüze takılan örtü.","kategori":"fikih","osmanli":"ماسكه"},{"kelime":"MASRAF","anlam":"Sarf edilen yer; harcanan para, gider.","kategori":"muamelat","misal":"Maraz-ı mevt, ölüm hastalığı olup, borçlarından geri kalan malının üçte birini satabilir. Borçları malından çok olsa bile, nafaka ve tedavisine masraf yapabilir. (Rûhu’l-Mecelle)","osmanli":"مصرف"},{"kelime":"MASRİF (Masraf)","anlam":"Zekât verilecek yer.","kategori":"ibadet","osmanli":"مصرف"},{"kelime":"MASûN","anlam":"(A. Savn’dan) Sıyânet olunmuş, korunmuş, korunan; sâlim, sağlam.","kategori":"dil","misal":"İstikâmet zarardan, seni hep eyler masûn, Hak eder sâdıkların, hasmını elbette zebûn.","osmanli":"مصون"},{"kelime":"MATÂL (Metâl)","anlam":"Borcunu ödemekte gecikme, mümâtale, matl.","kategori":"muamelat","osmanli":"مطال"},{"kelime":"MATBû‘","anlam":"1.Tab’ olunmuş, basılmış, 2.Hoş, lâtif, makbul, güzel.","kategori":"dil","osmanli":"مطبوع"},{"kelime":"MÂTEM","anlam":"1.Musibet sebebiyle kederli ve hüzünlü olma. 2.Ölünün arkasından ağlama, ziynetlenmeyi terk ederek üzüntüsünü gösterme, bir takım hususî işaretlerle kederini izhar etme, yas tutma. Ölünün peşinden yüksek sesle ağlayarak…","kategori":"fikih","misal":"Namazları, müstehab zamanlarında, şart ve edeblerine uygun olarak cemaat ile kılmalı ve birinci tekbiri İmâm ile birlikte almaya çalışmalıdır ve birinci safta yer bulmalıdır. Bunlardan biri yapılmazsa, mâtem tutmalıdır. (Mektûbât-ı Ma’sûmiyye)","osmanli":"ماتم"},{"kelime":"MATERYALİZM","anlam":"Cemiyet ve ferd hayatını tanzim eden tek unsurun madde ol-duğuna inanan; metafiziği, yaratıcıyı ve dini reddeden felsefe cereyanı. Maddecilik. Mad-diyyûn.","kategori":"dil","osmanli":"ماترياليزم"},{"kelime":"MATLûB","anlam":"Taleb edilen, kavuşmak istenen. (Bkz. Maksad)","kategori":"dil","misal":"Tâlib, matlûba tam bağlanınca, rehber ara-dan büsbütün kalkar. Böylece tâlibi matlûba aracı olmadan kavuşturur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مطلوب"},{"kelime":"MATRÂN","anlam":"Hristiyanlıkta yüksek rütbeli bir din adamı.","kategori":"dil","misal":"Metropolit.","osmanli":"مطران"},{"kelime":"MÂYÎ","anlam":"1.Şüphe ma- halli, zannedilen şey. 2.Evliya olduğuna hüsnü zan edilenler.","kategori":"dil","misal":"Su gibi, akıcı, sıvı Mutlak su ile ve mukayyed su ile ve her te-miz mâyi’ (sıvı) ile necâset temizlenir. (Halebî) MAZANNE: مظنه (A. Zann’dan)","osmanli":"مايع"},{"kelime":"MAZBATA","anlam":"(A. Zabt’dan) Kararname; tutanak.","kategori":"dil","osmanli":"مضبطه"},{"kelime":"MAZHAR","anlam":"1.Bir şeyin zu-hur ettiği, göründüğü, çıktığı yer. 2.Nâil olma, şereflenme. 3.Tasavvuf erbabının oturarak uyurken dayandığı kısa değnek.","kategori":"tasavvuf","misal":"(A. Zuhûr’dan)","osmanli":"مظهر"},{"kelime":"MÂZÎ","anlam":"Geçmiş zaman. Hibe, hediye ettim, verdim, sadaka ettim, sattım, satın aldım sözleri ile de nikâh sahîh olur.","kategori":"ibadet","misal":". dım (geçmiş zaman) olarak söylemesi lâzım- dır. (İbni Âbidîn)","osmanli":"ماضى"},{"kelime":"MAZLûM","anlam":"Zulme uğramış.","kategori":"dil","misal":"Üç kimsenin duâsı muhakkak kabul olur. Mazlûmun, misâfirin ve ana babanın. (Ha-dîs-i şerîf-Tirmizî) Kâfir bile olsa, mazlûmun bedduâsından korkunuz. Çünki onunla Al-lahü teâlânın arasında bir perde yoktur. (Ha-dîs-i şerîf-Hâkim) Hırsıza acımalı, günah işleyip azaba düşeceğine şefkat etmelidir. Kendinin zâlim olmayıp, maz-lûm olduğuna şükretmelidir. (Kimyâ-i Seâdet) Alma mazlûmun âhını, Çıkar âheste âheste. (Atasözü)","osmanli":"مظلوم"},{"kelime":"MAZMAZA","anlam":"Abdest ve gusül alırken ağzı su ile yıkama.","kategori":"ibadet","misal":"Hanefî mezhebinde mazmaza guslün farzlarından ve abdestin sünnetlerindendir. (Halebî)","osmanli":"مضمضه"},{"kelime":"MAZMûN","anlam":"1.Tazmin edil-mesi, ödenmesi lâzımgelen şey. 2.Mânâ, mef-hum. 3.Nükteli, sanatlı, ince söz.","kategori":"dil","misal":"(A. Zımn’dan)","osmanli":"مضمون"},{"kelime":"MAZMûN-İ NASS","anlam":"“Nassın zımnındaki” mânâsına bir nassın veya ifadenin tazammun (ihtivâ) ettiği mânâ.","kategori":"fikih","misal":"“Yedi yerde eller kaldırılır” hadîs-i şerîfinde geçen yerlerden biri de sa’ydır. Bunun mazmûn-ı nassı Safâ ve Merve’dir. Böylece el kaldırılacak yer sekiz olur. (İbni Âbidîn)","osmanli":"نص مضمون"},{"kelime":"ME‘ÂNÎ","anlam":"1.Ma’nâlar. 2.Söz ve terkiblerin muktezâ-i hâl ve makama (vaziyetin icabına) mutâbık (uygun) ve i’câzlı söylenmesi olup, belâgâtın bir kısmıdır. (Başın sağ olsun ile gözün aydın sözlerinin nerede söyleneceğini bilmek gibi.) (Bkz. İlm-i Meânî)","kategori":"dil","osmanli":"معانى"},{"kelime":"ME’CûC","anlam":"Kur’ân-ı kerîmde bir set arkasında bırakıldığı anlatılan ve kıyâmete yakın yeryüzüne yayılacağı bildirilen yassı yüzlü, küçük gözlü, kısa boylu, büyük kulaklı bir kavim.","kategori":"dil","misal":"(Bkz. Ye’cûc ve Me’cûc)","osmanli":"مأجوج"},{"kelime":"ME’MûR","anlam":"1.Emir almış. 2.Emrolunmuş. 3.Devlet hizmetinde maaş veya ücretle çalıştırılan kimse.","kategori":"osmanli","osmanli":"مأمور"},{"kelime":"ME’ZûN","anlam":"1.İzinli, izin almış. 2.Ders vermeye veya bir sanat işlemeye sala-hiyetli; diplomalı.","kategori":"dil","osmanli":"مأذون"},{"kelime":"MEBÂHİS","anlam":"Bahisler, bir mevzunun kısımları. Mebhas’in çokluk hâli.","kategori":"dil","osmanli":"مباحث"},{"kelime":"MEBDE","anlam":"1.Evvel, başlangıç, prensip, ilk unsur; ilmin ilk kısmı. 2.Tasavvufta sâli-kin ilâhî hakikate erişmek için hareket ettiği başlangıç noktası.","kategori":"tasavvuf","osmanli":"مبدأ"},{"kelime":"MEBDE-İ TE‘AYYÜN","anlam":"İlâhî kemâl-lerin, yüksekliklerin ilm-i ilâhîde başlangıcı ve ilk kaynağı. (Bkz. Ayn-ı Sâbite)","kategori":"dil","misal":"Allahü teâlâdan gelen feyzler, nîmetler hep mebde-i teayyünden gelir. (Mektûbât-ı İmâm-ı Rabbânî) Mebde-i teayyün âşık ile ma’şûk arasında ber-zahtır (yâni köprüdür) (Mektûbât-ı Ma’sûmiyye) MEBDE VE ME‘ÂD: معاد و مبدأ (A) Başlangıç ve netice; dünya ve âhiret; mahlûkların nereden ve nasıl vücûda geldiği, onları kimin yarattığı, yaratılış hikmetleri, sonunda ne olacakları ve ölümden sonraki hâlleri.","osmanli":"تعين مبدأ"},{"kelime":"MEBHAS","anlam":"Bahis; mevzunun muh-telif kısmı.","kategori":"dil","osmanli":"مبحث"},{"kelime":"MEBÎ‘","anlam":"(A.Bey‘den) Satılan mal.","kategori":"dil","misal":"Mebî’, akid (sözleşme) yapılınca, müşterinin mülkü olur ise de, teslim alınmadan önce kul-lanılması câiz değildir. Bunun için teslim alma-dan önce tam mülkü değildir. Teslim almadan zekât hesâbına katılmaz. (Bahr)","osmanli":"مبيع"},{"kelime":"MEBLAĞ","anlam":"Bâliğ olunan, erişilen; para tutarı.","kategori":"dil","osmanli":"مبلغ"},{"kelime":"MEBRûR","anlam":"Hayırlı, makbul, beğenilmiş.","kategori":"dil","misal":"Büyük günahı afv ettirmek için, tövbe-i nasûh yapmak veya hacc-i mebrûr yapmak lâzım-dır. (İbni Âbidîn)","osmanli":"مبرور"},{"kelime":"MEBSûT","anlam":"Yayılmış, açıklanmış.","kategori":"dil","osmanli":"مبسوط"},{"kelime":"MECÂZ","anlam":"Bir kelimenin hakikî mânâsının haricinde kullanılması.","kategori":"dil","misal":"“köy” zikredilmesine rağmen, içerisinde yaşayan insanlar kasdedilmiştir. (Hâşiye-i Şeyhzâde) Kelâmda asl olan mânâ-i hakîkattır. Ma’nâ-i hakîkî (ilk konulduğu mânâ) kastedilmesi mümkün olmadığı zaman mecâzî mânâ ele alınır. Evlâd (çocuklar) lafzı, asıl mânâsı itibâriyle ahfâd (torunlar) lafzını içerisine almaz. Fakat bir kimse malını evlâdına vakfetse, ancak evlâdı bulunmasa, bu takdirde, evlâdından ahfâdı kastedili…","osmanli":"مجاز"},{"kelime":"MECBûR","anlam":"Cebrolunmuş, zorlanmış.","kategori":"dil","misal":"İnsanların kudret ve ihtiyârına inanmayan, insanları âciz ve mecbur zan eden, din âlimlerinin sözlerini anlamamıştır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مجبور"},{"kelime":"MECBûRÎ","anlam":"Yapmak zo-runda bulunulan iş; ister istemez, zorla.","kategori":"dil","misal":"Hastalık gibi, mecburî bir sebeble oruc tutul-mazsa (gizli yimeli ve özr bitince) hemen kazâ etmelidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مجبورى"},{"kelime":"MECBûRİYYET","anlam":"Zor altında olma, zorlanma, mecburluk.","kategori":"dil","osmanli":"مجبوريت"},{"kelime":"MECCÂNEN","anlam":"Bedava, parasız, ücretsiz. Parasız, meccânen mal satmak bâtıldır. (İbni Âbidîn)","kategori":"dil","osmanli":"مجانًا"},{"kelime":"MECELLE","anlam":"Mecmua; benzeri mahiyette yazıların, fikirlerin toplandığı kitap.","kategori":"dil","osmanli":"مجله"},{"kelime":"MECÎD","anlam":"1.Mecd sahibi, şânı ulu, yüce. 2.Büyüklüğü, yüceliği ve işlerinin güzelliği ile tanınan, övülen mânâsına Allahü teâlânın Es-mâ-i hüsnâsından (el-Mecîd).","kategori":"dil","misal":"(Bkz. Mâcid) Allahü teâlâ, nîmetler vermesi sebebiyle övü-lendir, Mecîd’dir. (Hûd sûresi: 73) Baras hastası, Eyyâm-ı Beyd’de (kamerî ayın 13, 14 ve 15’inde) oruç tutup iftar vaktinde, el-Mecîd ism-i şerîfini söylerse, Allahü teâlâ ondan sebebli veya sebebsiz olarak bu hasta-lığı giderir. (El-İstigâsetü’l-Kübrâ) MECİDİYYE مجيديه (A) Osmanlı padişahı Sul-tan Abdülmecid adına kesilmiş olan altın ve gümüş sikke; daha ziyâde 20 kuruşluk ve 26 gram gelen gümüş sikkelere verilen isim.","osmanli":"مجيد"},{"kelime":"MECLİS","anlam":"1.Oturulacak, toplanılacak yer. 2.Görüşülecek bir mesele için bir araya gelmiş insan topluluğu. 3.Devlet işlerini görüşmek üzere milletvekillerinin toplandığı yer.","kategori":"osmanli","osmanli":"مجلس"},{"kelime":"MECLİS-İ ŞER’","anlam":"“Şeriat mec-lisi” mânâsına kâdının dâvâlara bakacağı yer, mahkeme.","kategori":"osmanli","osmanli":"شرع مجلس"},{"kelime":"MECNûN","anlam":"1.Cinnet geçiren, deli, di-vâne. 2.Tasavvufî aşk mevzuunu işleyen meşhur kıs-sanın kahramanı Leylâ’nın aşığı Kays’ın lakabı.","kategori":"dil","misal":"(Bkz. Cünûn) Mecnûn olanlar ibâdet için ehil değildirler. (Dürer) MECRÂ: مجرى (A) Damar; su yolu, suyun akı- tıldığı yer.","osmanli":"مجنون"},{"kelime":"MECûS","anlam":"Daha ziyâde Ateşperestler için kullanılan bir tâbir. Aslı Farsça Zerdüşt râhibi mânâsına megus’tur.","kategori":"dil","osmanli":"مجوس"},{"kelime":"MECûSİ","anlam":"Mecûs dinine mensub; Zerdüşt, ateşperest; Ehl-i kitâb ve putperest olmayan.","kategori":"dil","misal":"O îmân edenler, o Yahûdîler, o Sâbiîler, o Nasrânîler, o Mecûsiler, o müşrikler (var ya), muhakkak ki Allah, kıyâmet günü aralarında hükmünü verecek, hak ve bâtılı ayıracaktır. Çünki Allah her şeye şâhid bulunuyor. (Hac sûresi: 17) Her çocuk fıtrat üzere (Müslümanlığa elverişli) dünyaya gelir. Bunları sonra anaları, babaları, Hristiyan, Yahudi ve Mecûsi yapar. (Hadîs-i şerîfTaberânî, Ebû Ya’lâ, Müsned, Beyhekî) Ezan…","osmanli":"مجوسى"},{"kelime":"MECZûB","anlam":"1.Cezbeye kapılmış, cezbedilmiş. 2.Allahü teâlânın sevgisi ile kendinden geçmiş tasavvuf yolcusu.","kategori":"tasavvuf","misal":"Evliyâdan bir kısmı öldükten sonra Huzûr-i ilâhîde her şeyi unuturlar. Dünyâdan ve dünyada olanlardan haberleri olmaz. Duâları duymazlar. Bir şeye vâsıta, sebeb olmazlar. Dünyadaki, diri olan evliyâ arasında da böyle meczûblar bulunur. (Makâmât-ı Saîdiyye) Tasavvuf yolunda ilerlemek isteyenlerin, arada vâsıta olmadan maksada kavuşmaları çok güçtür. Bunlara bütün tasavvuf derecelerini geçmiş olan bir Ehl-i sünnet âli…","osmanli":"مجذوب"},{"kelime":"MEDD","anlam":"1.Uzatmak, çekmek. 2.Tecvid ilminde uzatmayı gerektiren harflerden (elif, vav, yâ) bir harfi uzatarak okuma.","kategori":"dil","misal":"Elif sâkin olup, kendisinden evvelki harfin ha-rekesi fetha ise, yâ sâkin olup kendisinden ev-velki harfin harekesi kesre ise ve vav sâkin olup, kendisinden evvelki harfin harekesi damme ise, med harfi olur. Med harfinden sonra uzatılması gereken harfi daha fazla uzatarak okutana se-beb-i med denir.","osmanli":"مد"},{"kelime":"MEDED","anlam":"1.Yardım, imdat. 2.Muhare-bede takviye kuvveti.","kategori":"dil","misal":"İnsan muhtaç olduğu zaman kurttan, kuştan meded umar. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مدد"},{"kelime":"MEDENÎ","anlam":"1.Medîne (şehir) halkından. 2.Cemiyet hâlinde yaşamaya alışkın; terbiyeli, nâzik, görgülü.","kategori":"dil","misal":"İnsan medenî olarak yaratılmıştır. Hayvanlar medenî yaratılmadı. Şehirde birlikte yaşamaya mecbur değildirler. İnsan, nâzik zayıf yaratıldığı için, pişmemiş yemek yiyemez. Gıdâ, elbise ve binânın hazırlanması lâzımdır. Yani sanatlara ihtiyâcı vardır. Bunun için de araştırmak, düşünmek, tedkîk etmek, tecrübe yapmak ve çalışmak lâzımdır. Fen ve sanat, insa…","osmanli":"مدنى"},{"kelime":"MEDENİYYET","anlam":"Memleketleri îmâr edip, insanları rahat ve huzura kavuşturmak için lâzım olan sanatların ve adâletin tesisi. Medeniyet; tâmir-i bilâd ve terfih-i ibâddır, yani beldeleri îmâr etmek, binâlar, fabrikalar yapa-rak, memleketleri kalkındırmak ve fenni ve her çeşit gelirleri milletlerin hürriyetleri, rahat ve huzur içinde yaşamaları için kullanmak de-mektir. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"dil","osmanli":"مدنيت"},{"kelime":"MEDFûN","anlam":"Defnolunmuş, gömülmüş.","kategori":"dil","osmanli":"مدفون"},{"kelime":"MEDH","anlam":"Övme, iyi taraflarını anlatma Din kardeşinizden bir şey istediğinizde söze onu medh ile başlamayın. Onu bıçak-lamış gibi olursunuz. (Hadîs-i şerîf-İbni Nec-câr) Bir fâsık medh olunduğu zaman Rab-bin gazâbından Arş titrer. (Hadîs-i şerîf-Ebû Ya’lâ) En hoş kazanç o tüccarındır ki, konuş-tuğunda yalan söylemez, emniyete hıyânet etmez, va’dinden dönmez, borcunu geciktir-mez, alacaklarını sıkıştırmaz, malını aşırı medh etmez ve alırken de kötülemez. (Ha-dîs-i şerîf-Deylemî)","kategori":"hadis","misal":"Kalb hastalıklarından biri de medh ve senâ olunmağı sevmektir. Bunun hakîkî üstünlük, iyilik olmadığını, olsa da geçici olduğunu dü-şünmelidir. (Berîka)","osmanli":"مدح"},{"kelime":"MEDHİYYE","anlam":"Birini övmek için yazılmış şiir.","kategori":"dil","osmanli":"مدحيه"},{"kelime":"MEDÎN","anlam":"Borçlu.","kategori":"muamelat","osmanli":"مدين"},{"kelime":"MEDÎNE-İ MÜNEVVERE","anlam":"Hicaz’ın şimalinde Hazret-i Peygamber’in hicret edip vefatına kadar yaşadığı, kabr-i şerîfinin de bulunduğu İslâm tarihinde mühim yeri olan şehir.","kategori":"dil","misal":"Onlar (münâfıklar); “Eğer Medîne’ye dönersek, andolsun en şerefli ve kuvvetli olanımız oradan en hakir ve zaîf olanı muhakkak çıkaracaktır” diyorlardı. Hâlbuki şeref, kuvvet ve gâlibiyet Allah’ındır, Peygamberinindir, mü’minlerindir. Fakat münâfıklar bunu bilmezler. (Münâfikûn sûresi: 8) Medîne demirci ocağı gibi kiri pası ayırır. (Hadîs-i şerîfBuhârî) Medîne-i Münevvere, Mekke-i Mükerreme’nin batısında ve Kızıldeni…","osmanli":"منورة مدينهء"},{"kelime":"MEDLûL","anlam":"Delilin (alâmetin, işâretin) delâlet ettiği, gösterdiği şey; bir kelimeden veya bir işâretten anlaşılan.","kategori":"fikih","misal":"Delil, medlûlden ezhârdır. (Delil, delil getirilmiş şeyden açıktır). Hak sübhânehudan daha açık bir şey yoktur. (Mektûbât-ı İmâm-ı Rabbânî) Delil bulunmayınca, medlûlün de bulunmayacağı söylenemez. Çünki, Allahü teâlânın varlığına delil olan âlem yaratılmadan önce, medlûl olan yaratanın yok olduğu söylenmiş olur ki, bu bâtıl olup, hükümsüzdür. Çünki, Allahü teâlâ, âlem yaratılmadan önce de vardı. O’nun başlangıcı ve…","osmanli":"مدلول"},{"kelime":"MEDRESE","anlam":"Ders görülen yer. İslâm ta-rihinde tedrisat yapılan ilim merkezi. Mektep. Cenâze ve bayram namazları kılınan yerlere, câmi avlularına, medrese ve tekkelere, hayızlı kadın ve cünüb girebilir. (İbni Âbidîn)","kategori":"ibadet","misal":"Din ilimlerinden başka, hey’et (astronomi), he-sab (matematik), hendese (geometri), hikmet, tıp gibi ilim dallarına da mühim yer veren med-reseler; din ve dünya ilimlerini, birlikte yürü-türdü. (İslâm Târihi Ansiklopedisi)","osmanli":"مدرسه"},{"kelime":"MEDY","anlam":"75.645 litre = 73383.57 gr. 61.83 litre = 48870 gr.","kategori":"ibadet","misal":"Bir hacim ölçüsü olup, 22,5 sâ’ (Hanefîlere göre ; diğer mezheblere göre ) mukâbilidir.","osmanli":"مدى"},{"kelime":"MEDYEN","anlam":"Şuayb aleyhisselâmın tebliğde bulunduğu, Kur’ân-ı kerîmde ismi geçen ve bugün Ürdün’de yer alan bir belde.","kategori":"dil","osmanli":"مدين"},{"kelime":"MEDYûN","anlam":"Borçlu, borçlanmış.","kategori":"muamelat","misal":"Dâyine (alacaklıya), medyûnun medyûnu hasm olmaz. Yani bir kimse alacağını, o kişiye borçlu olandan isteyemez. (Mecelle, m. 1640)","osmanli":"مديون"},{"kelime":"MEFHûM","anlam":"Fehmedilen, anlaşılan, kalble bilinen mânâ, kavram.","kategori":"tasavvuf","misal":"Lafzın, zikredilmeyen bir hükme delâleti.","osmanli":"مفهوم"},{"kelime":"MEFKûD","anlam":"1.Yok, mevcud olmayan. 2.Nerede bulunduğu ve hayatta olup olmadığı bilinmeyen kimse.","kategori":"dil","misal":"(A. Fakd’dan) Heme ûst (Her şey O’dur) sözünün mânâsı, eşya ma’dum (adem, yok) ve mefkûd olup, Hak sübhânehû mevcûddur, demektir. (Mektûbât-ı İmâm-ı Rabbânî) Mefkûd kendi hakkında sağ, başkaları hak-kında ölü hükmündedir. Ölümüne hükmedil-medikçe malları vârislere geçmez. Kirâ, vekâlet ve nikâhı bozulmaz. Ölüm tehlikesi esnasında kaybolmuşsa hâkimin takdir ettiği bir zaman sonra, değilse emsallerinin hepsi vefat ettikten sonra ölümüne hükmedilir; mirası intikal eder; zevcesi ölüm iddeti bekler. Sağ olarak çıkıp ge-lirse, vârislerin ellerindekini ve zevcesini geri alır. (Mebsut-ı Serahsî)","osmanli":"مفقود"},{"kelime":"MEGÂZÎ","anlam":"(A. Gazâ’dan) Gazâlara (savaş-lara) dâir bilgiler, menkıbeler, hikâyeler.","kategori":"dil","misal":"Megâzî sâhasında ilk yazılan kitap Vâkıdî’nin Megâzî’sidir. (Keşfüzzünun)","osmanli":"مغازى"},{"kelime":"MEHÂL","anlam":"1.Korku yeri. 2.Vâde, mehil.","kategori":"dil","misal":"MEHÂREC: مخارج (Bkz. Mehâric) MEHÂRET: مهارت (Bkz. Mahâret)","osmanli":"مهال"},{"kelime":"MEHÂRİC","anlam":"1.Hurûc ede-cek, dışarı çıkacak, çıkılacak yer. 2.Osmanlı ulemâsında bir rütbe. 3.Bayağı kesirin paydası.","kategori":"osmanli","misal":"(A. Hurûc’dan)","osmanli":"مخارج"},{"kelime":"MEHÂRİC-İ HuRûF","anlam":"Harfle-rin mahreçleri (ağızdan ses olarak çıktığı yer), seslerin çıkış yerleri.","kategori":"dil","misal":"Kur’ân-ı kerîmi tecvîd üzere okumasını bilmek farz olup, tecvîdi bilmeyen mehâric-i hurûfu gö-zetemez. Harflerin ağızdaki yerlerini gözeteme-yen bir kimsenin okuduğu Kur’ân-ı kerîm ve kıl-dığı namaz sahîh olmaz. (Fetâvâ-i Ebussuud)","osmanli":"حروف مخارج"},{"kelime":"MEHÂSİN","anlam":"Güzellikler.","kategori":"dil","osmanli":"محاسن"},{"kelime":"MEHDÎ","anlam":"1.Hidâyete eren, doğru yolu tutan. 2.Kıyâmete yakın geleceği, Hazret-i Peygamber tarafından haber verilen, İslâmiyet’i ve adâleti yeryüzüne hâkim kılacak olan mübârek zât. Kıyâmete yakın ismi ismime, babasının adı, babamın adına uyan, Ehli beytimden Mehdî gelir. Arza hâkim olur adâletle dol-durur. (Hadîs-i şerîf-Ebû Dâvûd, İbn-i Mâce, Müsnedü Ahmed) Allahü teâlâ, İslâmiyet’i nasıl Resûlullah efen-dimizle sallallahü aleyhi ve sellem başlatmışsa, Hazret-i Mehdî ile sona erdirecektir. Sayıları Bedr Gazâsı’nda bulunan Eshâb-ı kirâm kadar olan bir grup insan Hazret-i Mehdî’ye bî’at edecek (emrine girecek) ve her zâlim onun karşısında mağlup olacaktır. Zamanı son derece imrenilecek bir şekilde adâletle dolacaktır. (el-Kavlü’l-Muh-tasar fî Alâmât’il-Mehdî )","kategori":"dil","misal":"Ya Rabbî! Muaviye’ye ilim ihsan et! Ve onu hâdi ve mehdî kıl! Onun sebebiyle de hidâ-yet ver! (Hadîs-i şerîf-Tirmizî)","osmanli":"مهدى"},{"kelime":"Mehr-i Misl","anlam":"“Emsal mehir” mânâsına mehir söylenmeden veya mehir vermemek şartı ile yapılan bir nikahtan sonra, kadının, ictimâî hayattaki emsalleri veya baba tarafından akrabâsının kadınlarına bakılarak hak kazandığı mehir.","kategori":"dil","osmanli":"مثل مهر"},{"kelime":"Mehr-i Muaccel","anlam":"“Peşin mehir” mânâsına mikdarı nikâh kıyılırken tayin edilen ve nikâhtan hemen sonra peşin olarak ödenen mehir.","kategori":"dil","misal":"Mehr-i muaccelini almayan kadın, kocasının evine gitmeyi reddedebilir (İbni Âbidîn)","osmanli":"معجل مهر"},{"kelime":"Mehr-i Müeccel","anlam":"“Vâdeli mehir, te’cil edilmiş mehr” mânâsına, vâdesi dolduğunda, vâdesi bildirilmemişse ölüm veya boşanmadan sonra kadının hakkı olan mehr.","kategori":"dil","osmanli":"مؤجل مهر"},{"kelime":"MEHR (Mehir)","anlam":"Erkeğin evleneceği kadına vermesi gereken mal, para veya menfaat.","kategori":"dil","misal":"Mehrin en azı on dirhem yani yedi miskal ağırlığındaki gümüş değerinde olan bir miskal (beş gram yani üçte iki lira) altından az olmamalıdır. Mehrin en çoğu ise tahdîd edilmemiştir. (Hidâye)","osmanli":"مهر"},{"kelime":"MEHTÂB","anlam":"1.Ay ışığı. 2.On dört gece-lik ay. 3.Şenlik gecesinde yakılan renkli kibrit veya fişek, maytap.","kategori":"dil","misal":"Rahat gece, tatlı mehtâb bul bana, Her şeyden anlatayım, o zaman sana. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تاب مه"},{"kelime":"MEJDEK","anlam":"Milâdî IV. asırda İran’da ko-münizmin ilk umdelerini ortaya atmasıyla ta-nınan ihtilâlci.","kategori":"dil","misal":"Zerdüşt dinine mensub Mejdek, herkesin mal ve kadınının ortak olduğunu iddia etmiş; İran Şahı Kubâd buna inanmıştır. Yerine geçen Şah Nûşirvân, Mejdek’i seksenbin adamı ile birlikte öldürdü. (Burhân-ı Kâtı‘)","osmanli":"مﮋدك"},{"kelime":"MEKÂN","anlam":"Yer, mahal, otu-rulan yer.","kategori":"dil","osmanli":"مكان"},{"kelime":"MEKÂRİM","anlam":"Cömertlikler; iyi ahlâklar.","kategori":"tasavvuf","misal":"Mekremet’in çokluk hâli.","osmanli":"مكارم"},{"kelime":"MEKÎL","anlam":"Kile (ölçek) ile, yani hacim ile ölçülen mal.","kategori":"ibadet","misal":"Buğday, arpa, hurma ve tuz dâimâ mekîldir. Tartı ile kullanılmaları mekîl olmalarını değiştirmez. Müsâvî (eşit) olmaları lâzım olduğu zaman hacimlerinin müsâvî olması lâzım olur. (İbni Âbidîn)","osmanli":"مكيل"},{"kelime":"MEKKE-İ MÜKERREME","anlam":"Hicaz’da Hazret-i İbrâhim’in Kâbe-i Muazza-ma’yı inşa ettiği, Hazret-i Muhammed’in doğduğu ve hicrete kadar yaşadığı, Müslümanların kıblegâhı olan mukaddes şehir, kutlu Mekke.","kategori":"dil","misal":"sonra onların ellerini sizden, sizin ellerinizi onlardan çekti. Allahü tealâ ne yaparsanız hakkıyla görendir. (Feth sûresi: 24) Şüphesiz âlemler için bereket ve hidâyet kaynağı olarak insanlar için kurulan ilk ev (mâbed) Mekke’deki (Kâbe)dir. (Âl-i İmrân sûresi: 96) (Ey Mekke!) Vallahi sen Allahü teâlânın yarattığı yerlerin en hayırlı, Rabbim katında en sevgili olanısın. Senden çıkarılmamış olsaydım, çıkmazdım. Bana…","osmanli":"مكرمة مكهء"},{"kelime":"MEKKE’NİN FETHİ","anlam":"8.senesinde müşriklerin Hudeybiye Anlaşma-sı’nı bozması üzerine Müslümanların Mekke üzerine yürüyerek kazandığı büyük zafer.","kategori":"dil","misal":"Hicretin","osmanli":"فتحى نك مكه"},{"kelime":"MEKKÎ","anlam":"1.Mekkeli. 2.Mekke-i Mükerreme’de nâzil olan âyet-i kerîme ve ekserisi Mekke’de nâzil olan sûre-i celîle.","kategori":"dil","misal":"Mekkî ve Medenî âyet-i kerîmelerin kendilerine mahsus husûsiyetleri vardır. Mekkî âyet-i kerîmeler, umûmiyetle; Allahü teâlâya, meleklerine, kitablarına, peygamberlere aleyhimüsselâm âhiret, gününe îmân gibi İslâmiyet’in esâsı, temeli olan hususlar, ferdin ve milletin terbiyesi, şirkin, putlara tapınmanın bozukluğu, yanlışlığı, delillerle açıklanması gibi hususlardan bahseder. Mekkî âyet-i kerîmeler kısadırlar. Mede…","osmanli":"مكى"},{"kelime":"MEKR","anlam":"Hîle yapmak, tuzak kurmak, al-datmak; içten içe fesat çıkarmak.","kategori":"dil","misal":"(Habîbim) onların (kâfirlerin) seni tekzîbine (yalanlamalarına) ve senden yüz çevirmele-rine mahzûn olma, üzülme. Onların sana yaptıkları mekrden dolayı, gönlün daral-masın. (Çünki, Allah seni, onların mekrin-den muhâfaza eder, korur, onlara karşı sana yardım eder.) (Neml sûresi: 70)","osmanli":"مكر"},{"kelime":"Mekr-i İlâhî","anlam":"1.Allahü teâlânın, bir kimseye hakkında hayırlı olmayan nimetler vermesi, istidrâc olarak nimet şeklinde gösterilen musibetler. 2.Allahü teâlânın, mekr yapanların mekrini kendi aleyhlerine çevirmesi, kurdukları tuzakları bozması, mekrlerine karşılık onları ce… Allahü teâlânın mekrinden emîn mi oldular. Hüsrâna uğrayanlardan (küfr yani îmânsızlık ve günahlar ile, ibret almamak ve tefekkürü terk etmek sûretiyle zararda olanlardan) başkası Allahü teâlânın mekrinden emîn olmaz. (A’râf sûresi: 99) Resûlullah aleyhisselâm daima; “Allahümme yâ mukallibelkulûb, sebbit kalbî alâ dinik” (Ey Allah’ım! Kalbleri iyiden kötüye, kötüden iyiye çeviren, ancak sensin. Kalbimi, dininde sâbi…","kategori":"akaid","osmanli":"الهى مكر"},{"kelime":"MEKRûH","anlam":"1.Kerih görülen, beğenilmeyen. 2.İslâmiyet’in sübûtu veya delâleti zannî bir delil ile kat’î olarak yâhud olmayarak yapılmamasını istediği, beğenmediği, ibâdetin sevabını gideren şey. Bazen harama da mekrûh denir. “Bir kimse özrü yokken İmâm Cum‘a günü Cum‘a namazını kıldırmadan evinde öğle namazını kılarsa mekrûh olur” sözü, haramdır mânâsınadır. Buna amelî farz da denir. Yapılması yasaklanmıştır; ama inkârı küfr değildir ve ateşle azap yoktur. Bazen hem kerâhet-i tahrîmiyeye, hem de kerâhet-i tenzîhiyyeye mekrûh adı verilir. Ke…","kategori":"fikih","osmanli":"مكروه","alternatif":["mekruh"]},{"kelime":"MEKTEB","anlam":"1.Yazı yazacak yer, yazıhane. 2.Talebenin ders gördüğü yer.","kategori":"dil","osmanli":"مكتب"},{"kelime":"MEKTûB","anlam":"1.Yazılmış. 2.Haberleşme maksadıyla birine gönderilen yazı, nâme, biti.","kategori":"dil","osmanli":"مكتوب"},{"kelime":"MEKTûBÂT","anlam":"1.Mektublar. 2.Din büyüklerinin yakınlarına ve sevdiklerine gön-derdiği, nasîhat mektublarından meydana ge-len kitap.","kategori":"dil","osmanli":"مكتوبات"},{"kelime":"MELÂİKE","anlam":"Melek’in çokluk hâli, melekler.","kategori":"akaid","misal":"(Bkz. Melek)","osmanli":"ملائكه"},{"kelime":"MELÂMÎ","anlam":"1.Her çeşit gösterişten uzak, dünya malından yüz çeviren, dervişçe yaşayan; farzları yapıp, nâfileleri gizli yapmaya çok dikkat ederek daha ziyâde kalb temizliği ve zühde ehemmiyet veren. 2.Hamdun Kassâr’a nisbet edilen Melâmiyye tarîkatine mensub.","kategori":"tasavvuf","osmanli":"ملامى"},{"kelime":"MELCE","anlam":"İlticâ edecek, sığınacak yer.","kategori":"dil","osmanli":"ملجأ"},{"kelime":"MELEK","anlam":"1.Haberci, elçi. 2.Nurdan ya-ratılmış, yiyip içmeyen, erkeklik veya dişiliği olmayan, günah işlemeyen, yalnızca ilâhî emir-leri yerine getiren latif varlıklar. Melekler Allah’ın sözünün önüne geçmez-ler. Hep O’nun emri ile hareket ederler. (En-biyâ sûresi: 27) O’nun (Allahü teâlânın) ka-tındaki melekler, kendisine ibâdet etmekten ne kibirlenirler ne de yorulurlar. Gece gün-düz hep Allahü teâlâyı tesbîh ederler, usan-mazlar. (Enbiyâ sûresi: 19,20) Bir kimse bir mü’minin ihtiyâcını karşılamak için yürüse, Allahü teâlâ yetmiş bin meleği ona sâyebân eder. Eğer sabah vakti ise akşama kadar, ak-şam vakti ise sabaha kadar ona rahmet ile duâ ederler. Allahü teâlâ her bir ayağını kal-dırdıkta onun bir günahını affeder ve bir derece yükseltir. (Hadîs-i şerîf-İbni Hibbân) Sayısı en çok mahlûk, meleklerdir. Bunların sayı-larını Allahü teâlâdan başka kimse bilmez. Gök-lerde, meleklerin ibâdet etmedikleri boş bir yer yoktur. Göklerin her yeri, rükû’da veya secdede olan meleklerle doludur. Göklerde, yerlerde, ot-larda, yıldızlarda, canlılarda, cansızlarda, yağ-mur damlalarında, ağaçların yapraklarında, her zerrede, her harekette, her şeyde melekle-rin vazîfeleri vardır. Her yerde Allahü teâlânın emirlerini yaparlar. (İtikadnâme)","kategori":"akaid","osmanli":"ملك"},{"kelime":"MELEKûT","anlam":"(A. Melik’ten) Meliklik, hü-kümdarlık, saltanat.","kategori":"akaid","osmanli":"ملكوت"},{"kelime":"MELEL","anlam":"Usanç, bıkma, melâl.","kategori":"dil","osmanli":"ملل"},{"kelime":"MELÎH","anlam":"Melâhat sahibi, güzel, sevimli. Bu büyükler, tatlı yemekleri, lezîz şerbetleri, nefîs kumaşları, hazîn sesleri, nazîf kokuları, latîf manzaraları, melîh sûretleri, tatsızların-dan, çirkinlerinden daha çok istiyor ve sevi-yorlar. (Mektûbât-ı Ma’sûmiyye)","kategori":"dil","osmanli":"مليح"},{"kelime":"MELİK(Melîk)","anlam":"1.Mülk sahibi, hükümdar. 2.Zâtında, sıfatlarında, hiçbir şeye muhtaç olmayan, her şey varlığında ve varlıkta kalmasında O’na muhtaç olan, her şeyin sâhibi, yaratıcısı mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elMelik). O Allahü teâlâ hak ma’bûd’dur. O’nun ortağı yoktur. O Melik’tir…","kategori":"muamelat","misal":"(Mâide sûresi: 20) Kalb meliktir. Melik temiz olursa, teb’ası da temiz ve sağlam olur. Melik fesâda uğrarsa, teb’ası da fesâda uğrar. (Hadîs-i şerîfEbû Nuaym)","osmanli":"ملك"},{"kelime":"MEMÂLİK","anlam":"Memleket’in çokluk hâli.","kategori":"dil","osmanli":"ممالك"},{"kelime":"MEMDûD","anlam":"Meddolunmuş, çekilmiş, uzatılmış, uzamış, uzatılan.","kategori":"dil","osmanli":"ممدود"},{"kelime":"MEMLEKET","anlam":"Ülke, devlet toprağı, vatan.","kategori":"osmanli","misal":"Bir memleket harb ile alınırsa, toprağın beşte biri beytülmâlın olur. (İbni Âbidîn)","osmanli":"مملكت"},{"kelime":"MEMLûK","anlam":"1.Birinin mülkü, malı. 2.Kul, köle.","kategori":"muamelat","misal":"(Bkz. Esîr, Köle)","osmanli":"مملوك"},{"kelime":"MEMNû’","anlam":"Men edilmiş, yasak; haram.","kategori":"fikih","misal":"Zarûretler, memnû’ olan şeyleri mubâh kılar. Mâni zâil, yok oldukta memnû’ avdet eder (geri gelir). Meselâ bir kimsenin avret mahalline (yerine) bakmak memnû’ ise de, yara ve başka hastalık hâlinde zarûret hâli sebebiyle hekim (doktor) ve cerrâh ebe gibi kimselerin bakması mubâh olur. (Mecelle, 21)","osmanli":"ممنوع"},{"kelime":"MEMNûN","anlam":"1.Tatmin olmuş, 2.Min-net altında bulunan. 3.Sevinçli.","kategori":"dil","osmanli":"ممنون"},{"kelime":"MEN‘","anlam":"Yasak etme, bırakmama; dur-durma; esirgeme, vermeme, önleme.","kategori":"dil","osmanli":"منع"},{"kelime":"MENÂFİ‘","anlam":"Faydalar, kârlar, çıkarlar. Menfe’at’in çokluk hâli.","kategori":"dil","osmanli":"منافع"},{"kelime":"MENÂHÎ","anlam":"Yasaklar, men olunan şey-ler. Menhî’nin çokluk hâli.","kategori":"dil","osmanli":"مناهى"},{"kelime":"MENÂKIB","anlam":"1.Meşhurların hayâtını, söz ve işlerini övgüyle anlatan rivâyet ve hikâyeler. 2.Hadîs kitaplarında peygamberler ve eshâbının hayâtlarına dâir rivâyetleri hâvi kısımlar.","kategori":"hadis","misal":"Menkabenin çokluk hâli. (Bkz. Menkıbe) Evliyânın menâkıbını dinlemek, onlara olan muhabbeti, sevgiyi artırır; Eshâb-ı kirâmın (Peygamber efendimizin arkadaşlarının) menkıbeleri îmânı kuvvetlendirir. (Minâh-i Seyyid Sıbgatullah)","osmanli":"مناقب"},{"kelime":"MENÂSİK","anlam":"İbâdetler; haccederken belli zaman ve mekânda yapılması gereken vazîfeler.","kategori":"ibadet","misal":"Tavâf ve sa’y hac ile umrenin menâsikindendir. (Ni’met-i İslâm) Tavâf (Kâbe etrâfında yedi kere dönmek) ve sa’y (Safâ ve Merve arasında gelip gitmek) hac ve ömrenin menâsikindendir. (Ni’met-i İslâm)","osmanli":"مناسك"},{"kelime":"MENÂT","anlam":"Hükmün dayanağı, gerek-","kategori":"fikih","misal":"çesi, illeti.","osmanli":"طانم"},{"kelime":"MENÂZİL","anlam":"Nüzûl edilen (inilen) yer-ler; evler. Menzil’in çokluk hâli.","kategori":"dil","osmanli":"منازل"},{"kelime":"MENÂZIR","anlam":"Seyredilecek, görülecek yerler. Manzara’nın çokluk hâli.","kategori":"tasavvuf","osmanli":"مناظر"},{"kelime":"MENBÂ‘","anlam":"1.Kaynak. 2.Pı-nar, su kaynağı.","kategori":"dil","misal":"(A. Nebe’ân’dan)","osmanli":"منبع"},{"kelime":"MENDûB","anlam":"Yapılması hâlinde sevab hâsıl olan, yapılmazsa günah olmayan şeyler.","kategori":"fikih","misal":"Abdesti, namaz vakti girmeden evvel almak mendûbdur. (Halebî)","osmanli":"مندوب"},{"kelime":"MENFÎ","anlam":"1.Nefyedilmiş, sür-gün edilmiş, sürgün. 2.Bir şeyin olmayacak tarafı, aksi, tersi; negatif, olumsuz.","kategori":"dil","osmanli":"منفى"},{"kelime":"MENHÎ","anlam":"Nehyedilen, yasaklanan. Abdest alırken bazı menhîler vardır. Bunları yapmak haram veya mekrûhtur. Sağ el ile süm-kürmek, kıbleye ve mushafa karşı ayak uzat-mak mekrûhtur. Mushaf yüksekte ise, mekrûh olmaz. Tahâretlenmek için birinin yanında av-ret mahallini açmak haramdır. (Halebî)","kategori":"ibadet","osmanli":"منهى"},{"kelime":"MENÎ","anlam":"Umumiyetle cinsî temas veya ihtilâm sebebiyle erkekten veya kadından gelen","kategori":"fikih","misal":"ve guslü gerektiren sıvı. Erkek olsun, kadın olsun, menî şehvetle çıkınca, gusl abdesti lâzım gelir. Dayak yemek, ağır bir şey kaldırmak veya bir yerden düşmek gibi sebeblerle (şehvetsiz) menî çıkınca, Hanefî ve Mâlikî mezheblerinde gusül abdesti almak lâzım olmaz. Şâfiî mezhebinde ise, lâzım olur. (İbni Âbidîn) Hanefî mezhebinde menî, mezy ve idrardan sonra çıkan vedî ismindeki beyaz, bulanık, koyu sıvı, kaba necâs…","osmanli":"منى"},{"kelime":"MENKûL","anlam":"Nakledilebilen, taşınabilen. Menkûl, bir mahalden mahall-i âhara (bir yer-den başka bir yere) nakli mümkün olan şeydir ki nukûd (altın ve gümüşe) ve urûza (ticaret eş-yasına) ve hayvanât ve mekîlât ve mevzûnâta (hacimle veya ağırlıkla ölçülenlere) şâmil olur. (Mecelle, m. 128) (Bkz. Nakl)","kategori":"ibadet","osmanli":"منقول"},{"kelime":"MENN","anlam":"Bir ölçek. Batman. Müd. Menn, bir sa’nın (takriben 3500 gr.) Hanefî mezhebinde dörtte biri, diğer üç mezhebde üçte biri mikdârındadır.","kategori":"dil","osmanli":"من"},{"kelime":"MENNÂN","anlam":"Çok ihsân eden, çok minnet sâhibi mânâsına Allahü teâlânın isimlerinden (elMennân).","kategori":"akaid","osmanli":"منان"},{"kelime":"MENŞE’","anlam":"(A. Neş’et’den) Bir şeyin neşet et-tiği, çıktığı yer, esas, kök, köken.","kategori":"dil","osmanli":"منشأ"},{"kelime":"MENSûB","anlam":"Bir kimseye, bir şeye nisbeti olan, bir şeyle alâkası bulu-nan, bağlı, bağlanmış.","kategori":"dil","osmanli":"منسوب"},{"kelime":"MENSûH","anlam":"1.Nesholunmuş, hükmü yürürlükten kaldırılmış. 2.Âyet-i kerîme veya hadîs-i şerîflerden, nâsih tarafından neshedilen, yani hüküm zamanının bittiği bir başkasıyla bildirilenler. Müctehid olmayanın, işittiği bir hadîse uyması câiz değildir. Bu hadîs, mensûh veya te’vîlli olabilir. (Kifâye) Meyyit için hiç kimsenin ücretli veya ücretsiz oruç tutması ve namaz kılması sahîh olmaz. Bu husustaki hadîs-i şerîf mensûhdur. (İbni Âbidîn)","kategori":"hadis","osmanli":"منسوخ"},{"kelime":"MENŞûR","anlam":"1.Neşrolunmuş, dağıtıl-mış, yayılmış. 2.Padişahın verdiği rütbe, vazife veya salâhiyeti ihtiva eden ferman. 3.Prizma.","kategori":"osmanli","osmanli":"منشور"},{"kelime":"MENZÎL","anlam":"1.İniş yeri, yol-lardaki konak yeri. 2.Ev. 3.Bir günlük yol, ko-nak (35 km). 4.Mesâfe.","kategori":"dil","misal":"(A. Nüzûl’den)","osmanli":"منـزل"},{"kelime":"MER‘Â","anlam":"Otlak, çayırlık, hayvan otlatmaya mahsus arâzî.","kategori":"muamelat","osmanli":"مرعى"},{"kelime":"MERÂSİM","anlam":"Resmî muameleler; tören-ler, seremoniler. Resm’in çokluk hâli.","kategori":"dil","osmanli":"مراسم"},{"kelime":"MERBûT","anlam":"1.Raptolunmuş, bağlanmış, bağlı. 2.Ulaşmış, bitişmiş, bitişik. 3.İliştirilmiş, eklenmiş.","kategori":"dil","misal":"(A. Rabt’dan)","osmanli":"مربوط"},{"kelime":"MERCÂN","anlam":"1.Sıcak denizlerde yaşa-yan ibtidaî bir canlı. 2.Mercan yatağından çı-karılan ve boncuk yapılan kırmızı renkli şey.","kategori":"dil","osmanli":"مرجان"},{"kelime":"MERD","anlam":"1.Adam, insan; erkek. 2.Özü, sözü doğru, dürüst.","kategori":"dil","osmanli":"مرد"},{"kelime":"MERDûD","anlam":"Reddedilen, kabul edil-meyen.","kategori":"dil","misal":"Bir kimse, dinde olmayan bir şey, bir yenilik meydana çıkarırsa, bu şey merdûddur. (Ha-dîs-i şerîf-Buhârî, Müslim, İbn-i Mâce, Müs-nedü İmâm-ı Ahmed) Allahü teâlânın düşmanlarını sevmek, insanı Allahü teâlâdan uzaklaştırır. Teberrî etmedikçe, tevellî olmaz; yani düşmandan uzaklaşmadıkça, dosta dostluk olmaz. Düşmanlık, düşmanlara yapılmalıdır. Dostlara düşmanlık merdûddur. (Mektûbât-ı İmâm-ı Rabbânî) İnsanoğlu son nefeste ruhunu teslim edeceği za-man, susayarak ve yüreği yanıp tutuşarak dört yanına bakar. İnsan bu hâldeyken, şeytân fırsat bulup, îmânını almak için, başının ucuna gelir. O merdûd, elinde bir kadeh tutar. İçinde buzlu su, hastanın başının ucunda o kadehi çalkalar ve; “(Hâşâ) Âlemlerin yaratıcısı yoktur dersen, bu suyu sana veririm” der. (Dürretü’l-Fâhire)","osmanli":"مردود"},{"kelime":"MERFû‘","anlam":"Ref ’ olunmuş, kaldırılmış, yükseltilmiş.","kategori":"hadis","osmanli":"مرفوع"},{"kelime":"MERFû‘ HADÎS","anlam":"Senedi muttasıl olsun veya olmasın “Resûlullah böyle buyurdu” veya “Resûlullah böyle yaptı” yâhud “Böyle emrolunduk” gibi lafızlarla doğrudan Hazret-i Peygamber’e izâfe edilen hadîs-i şerîf.","kategori":"hadis","misal":"(Bkz. Hadîs)","osmanli":"حديث مرفوع"},{"kelime":"MERHABA","anlam":"1.“Rahat olunuz” veya “Hoş geldiniz” mânâsına alâka ve iltifat tâbiri. 2.Büyük kadeh.","kategori":"dil","misal":"Aslı ‘merhâ bih’ gelir. Kişi, bir kavme geldiğinde kendisine “Mer-haba” denirse, kıyâmette Rabbine kavuştuğu günde kendisine “Merhaba” denir. (Hadîs-i şerîf-Hâkim) Bir adam Müslüman karde-şine “Merhaba” derse, melekler ona “Sana da merhaba” derler. Hiç şüphe yok ki, kul, mü’min kardeşinin yüzüne karşı abus (asık) bir çehre takınırsa melekler ona lânet ederler. (Hadîs-i şerîf-Hâtib) Merhaba ilim talibine! Zîrâ onun etrafını melekler görür sarar ve kanatları ile onu gölgelendirirler. Şöyle ki, birbiri üstüne gelirler ve bu şekilde dünya göğüne ulaşıncaya kadar devam ederler. Sebebi de ilme olan muhabbetleridir. (Ha-dîs-i şerîf-Taberânî) Merhaba sana ey Beytul-lah! Ne büyüksün ve hürmetin ne yücedir. Lâkin hiç şüphe yok ki, mü’min, Allah in-dinde senden daha muhteremdir. (Hadîs-i şerîf-Beyhekî) Merhabâ ey uşşâka sâkî merhabâ Merhabâ ey âli sultân merhabâ Merhabâ ey derde dermân merhabâ Merhabâ ey şefî’-i rûz-i cezâ Merhabâ sen rahmetenli’l-âlemîn. (Mevlid-i Süleymân Çelebi) Canıma bir merhabâ sürdü ezelde dest-i dast, Şöyle mest oldum ki gayrın merhabâsın bilme-dim (Ahmed Paşa)","osmanli":"مرحبا"},{"kelime":"MERHALE","anlam":"2.İki menzil arası. 3.Bir kimsenin bir günde yürüdüğü yol.","kategori":"dil","misal":".1.Menzil, ko-nak. (6 fersah, 18 mil, tak-riben 34 km.) Hanefî mezhebinde müddet-i sefer üç merha-ledir. (Merâkı’l-Felâh Hâşiyesi)","osmanli":"مرحله"},{"kelime":"MERHAMET","anlam":"1.Acımak, affetmek, nimetlendirmek. 2.Şefkat, kalb inceliği.","kategori":"hadis","misal":"Sonra, iman edip birbirine sabrı ve merha-meti tavsiye edenlerden olmaktır. İşte bun-lar eshâb-ı yemîndir. (Beled sûresi: 17) Allahü teâlâ merhameti yüz parçaya ayırdı. Doksan dokuzunu kendi katında alıkoydu. Yeryü-züne birtek parça indirdi. Bu bir parça yü-zünden mahlûkât birbirine merhamet eder-ler. (Hadîs-i şerîf-İbn-i Mâce) Şeytân; “Allahü teâlâ rahîmdir, affeder” diyerek insanı günah işlemeye sürükler. Hâlbuki kıyâ-met günü düşmanlara merhamet olunmaya-caktır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مرحمت"},{"kelime":"MERHEM","anlam":"1.Deriye içirilerek veya sü-rülerek kullanılan tereyağı kıvamında yağlı ilâç. 2.Acıyı, sertliği giderecek ve avundura-cak olan sebeb.","kategori":"dil","osmanli":"مرهم"},{"kelime":"MERHûM","anlam":"1.Merhamet olunmuş, acınmış. 2.Allah’ın rahmetine ka-vuşmuş, ölmüş, ölü.","kategori":"dil","osmanli":"مرحوم"},{"kelime":"MERÎ","anlam":"Mîde ile bül’ûm (gırtlak) ara-sında bulunan yemek borusu.","kategori":"dil","osmanli":"مرى"},{"kelime":"MERİDYEN","anlam":"Kutublardan geçmek üzere ekvatora dik olarak çizildiği farzedilen çember.","kategori":"fikih","misal":"Tûl. Boylam.","osmanli":"ن مريديه"},{"kelime":"MERKEB","anlam":"1.Sırtına bini-len şey, binit. 2.Vapur. 3.Eşek.","kategori":"ibadet","misal":"(A. Rükûb’dan)","osmanli":"مركب"},{"kelime":"MERSAD","anlam":"1.Rasat yeri, gözetleme yeri. 2.Vakfı tamir etme karşılığı kirâcının kazan-dığı ve bu meblağ kendisine ödenmedikçe ak-din devamı neticesini doğuran hak.","kategori":"dil","osmanli":"مرصد"},{"kelime":"MERSİYE","anlam":"Ağıt, ölenin arkasından duyulan acıyı ve onun üstünlüklerini bildi-ren manzûme.","kategori":"dil","osmanli":"مرثيه"},{"kelime":"MERTEBE","anlam":"1.Derece, ba-samak. 2.Makam, pâye. 3.Mikdâr.","kategori":"dil","misal":"Mukarreb olan büyükler nefislerine köle olmak-tan kurtulmuşlardır. Allahü teâlâ için hâlis kul olmuşlardır. Bu mertebe mukarreblerin en üs-tün derecesidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مرتبه"},{"kelime":"Mertebe-i Vehm","anlam":"Var olmadığı hâlde, var görünen.","kategori":"dil","misal":"Bir ipin ucuna bir taş bağlayıp, öteki ucun-dan tutup, ipi elimiz etrâfında çevirirsek, dö-nen taş, karşıdan dâire şeklinde görünür. Dö-nen taş, nokta-i cevvâledir (dönen noktadır). Görünen dâire de vehmîdir, hayâlîdir. Aslında dâire yoktur. Yalnız bir görünüştür. İşte Allahü teâlâ bütün mahlûkları mertebe-i vehmde ya-ratmıştır. Fakat görünüşlerini devâm ettirmek-tedir. Âlem mevhumdur sözünün mânâsı bu-dur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"وهم مرتبهء"},{"kelime":"MERVE","anlam":"1.Çakıl taşı. 2.Kâbe-i Muazzama’nın yakınında bulunan ve aralarında sa’y denilen ibâdetin yapıldığı iki tepeden biri.","kategori":"ibadet","misal":"(Bkz. Safâ)","osmanli":"مروه"},{"kelime":"MERYEM SûRESİ","anlam":"Kur’ân-ı kerîmin on dokuzuncu sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Doksan sekiz âyet-i kerîmedir. Hazret-i Meryem ve onun Îsâ aleyhisselâmı dünyaya getirmesi anlatıldığından, sûre bu ismi almıştır. Sûrede; Îsâ aleyhisselâmın, Hazret-i Meryem’den babasız olarak dünyaya gelmesi kıssası, Mûsâ, İsmâil, İdrîs peygamberlerin aleyhimüsselâm medhi ve bunlardan sonra gelen bazı kavimlerin kötülükleri, inkârcıların kıyâmet günü uğrayacakları azap bildirilmekt…","osmanli":"سى سوره مريم"},{"kelime":"MES‘Â","anlam":"Kâbe-i Muazzama yakınında Safâ ile Merve tepeleri arasındaki hac ve umre yapanların sa’y ettikleri yer.","kategori":"ibadet","osmanli":"مسعاء"},{"kelime":"MEŞ‘ARÜ’L-HARÂM (Meş‘ar-i Harâm)","anlam":"Mekke-i Mükerreme’de, Müzdeli-fe’nin sonunda Cebel-i Kuzah yakınında bir yer.","kategori":"fikih","misal":"Meş‘arü’l-harâmın yanında Allah’ı zikredin. (Bakara sûresi: 198) Hacda Arafat dönüşü gece Müzdelife’de yatılıp, fecr açılırken sabah namazı hemen kılınarak Meş‘arü’l-Harâm’da ortalık aydınlanıncaya kadar vakfeye durmak vâcibdir. (Dürrü’l-Muhtâr)","osmanli":"مشعر الحرام"},{"kelime":"MES’ELE","anlam":"1.Sorulup karşılığı istenilen şey. 2.Çözülmesi istenilen şey, prob-lem. 3.Ehemmiyetli iş.","kategori":"dil","misal":"(A. Su’âl’den)","osmanli":"مسئله"},{"kelime":"MES’ûLİYYET","anlam":"Mes’ûl olma hâli, sorumluluk.","kategori":"dil","osmanli":"مسؤليت"},{"kelime":"MESÂ","anlam":"Akşam vakti; öğle sonrasından güneşin batışına kadar olan zaman.","kategori":"dil","osmanli":"مساء"},{"kelime":"MESÂÎ","anlam":"Çalışmalar.","kategori":"dil","osmanli":"مساعى"},{"kelime":"MEŞAKKAT","anlam":"Zorluk, güçlük, zahmet. Meşakkat, teysiri celb eder (kolaylığı getirir). Yani su’ûbet (zorluk), sebeb-i teshîl (kolaylaş-tırma sebebi) olur ve darlık vaktinde vüs’at (ge-nişlik) gösterilmek lâzım gelir. Karz ve havâle ve haciz gibi pek çok ahkâm-ı fıkhiyye bu asla müteferri’dir (bağlıdır) ve fukahânın ahkâm-ı şer’iyyede gösterdikleri ruhas (ruhsatlar) ve tahfîfât (hafifletmeler) hep bu kâ’ideden istih-râc olunmuştur (çıkarılmıştır). (Mecelle, m. 17) Meşakkat sebebiyle borcunun tamâmını bir-den ödemek imkânı bulunmayan borçluya, borcunu taksitle ödemesi için müsâade edilir. (Dürerü’l-Hükkâm)","kategori":"ibadet","osmanli":"مشقت"},{"kelime":"MESÂNE","anlam":"Prostat, bevl kesesi.","kategori":"dil","osmanli":"مثانه"},{"kelime":"MESÂNÎ","anlam":"Kur’ân-ı kerîmde âyet sayısı yüzden az olan sûreler. Bir şeyin tekrarı, çift, mükerrer mânâsına mesnâ’nın çokluk hâli.","kategori":"dil","osmanli":"مثانى"},{"kelime":"MESÂNİD","anlam":"1.Mesnedler, rütbeler, dereceler; mevkiler. 2.Rivâyet edenlerin ismine göre ter-tib edilmiş hadîs kitapları.","kategori":"hadis","misal":"Mesned’in çok-luk hâli. Müsned’in çokluk hâli. (Bkz. Müsned)","osmanli":"مساند"},{"kelime":"MEŞÂYIH","anlam":"Şeyhler. Şeyh kelimesinin çokluk hâli.","kategori":"dil","misal":"Bir kimse, ervâh-ı meşâyıh (meşâyıhın ruhları) hep hâzırdır, bilirler dese, îmânı gider. Allahü teâlânın izni ile hâzır olurlar dese küfr olmaz. (Miftâhü’l-Cenne)","osmanli":"مشايخ"},{"kelime":"Meşâyıh-ı Kirâm","anlam":"Büyük velîler, büyük zâtlar.","kategori":"muamelat","osmanli":"كرام مشايخ"},{"kelime":"MESBûK","anlam":"Geri kalan. Cemâatle namaz kılınırken imâma birinci rek’atte yetişemeyen yani ilk rek’atin rükû’undan sonra imâma uyan kimse.","kategori":"ibadet","misal":"İmâm iki tarafa selâm verdikten sonra, mesbûk ayağa kalkarak yetişemediği rek’atleri kazâ eder ve kırâatleri birinci, sonra ikinci, sonra üçüncü rek’at kılıyormuş gibi okur. Oturmağı ise, dördüncü, üçüncü ve ikinci rek’at sırası ile, yani sondan başlamış olarak yapar. (Halebî)","osmanli":"مسبوق"},{"kelime":"MESCİD","anlam":"Secde edilen yer; Müslümanların ibâdet yaptıkları mekân, câmi.","kategori":"ibadet","misal":"De ki: “Rabbim adâleti emr buyurdu. Her mescidde yüzünüzü kıble tarafına çevirin ve dinde samîmi olarak O’na ibâdet edin. İlkin sizi nasıl O yarattı ise, yine O’na döneceksiniz. (A’râf sûresi: 29) Ey âdemoğulları! Her mescid huzurunda namaz kılacağınız zaman zînetinizi (avretinizi örten elbisenizi) giyiniz. Yiyiniçin, ama israf etmeyin. Çünki Allahü teâlâ israf edenleri sevmez. (A’râf sûresi: 31) Her kim Allahü teâl…","osmanli":"مسجد"},{"kelime":"Mescid-i Aksâ","anlam":"“(Mekke’ye nisbeten) En uzak mescid” mânâsına Kudüs’te Süleymân aleyhisselâm tarafından yaptırılan, Müslümanların ilk kıblesi olan ve İslâmiyet’te Mescid-i Harâm ile Mescid-i Nebî’den sonra mübârek sayılan üçüncü mâbed.","kategori":"ibadet","misal":"(Her türlü noksanlıktan) münezzeh bulunan (Allah), kulunu (Muhammed sallallahü aleyhi ve sellemi) geceleyin (Mekke’deki) Mescid-i Harâm’dan alıp, kendisine âyetlerimizi gösterelim diye; etrâfını mübârek kıldığımız Mescid-i Aksâ’ya götürdü. Muhakkak O Semî‘dir (işitendir) ve Basîrdir (görendir). (İsrâ sûresi: 1) Resûlullah efendimiz Mîrâc gecesi, Mescid-i Ak-sâ’da peygamberlere İmâm olup, yatsı yahud sabah namazını k…","osmanli":"اقصى مسجد"},{"kelime":"Mescid-i Harâm","anlam":"“Hürmete layık, adam öldürmenin haram olduğu mescid mânâsına Kâ’be-i Muazzama’nın etrâfında üstü açık olan câmi.","kategori":"ibadet","misal":"(Namazda) Yüzünü Mescid-i Harâm tarafına çevir. Bu emir Rabbinden gelen bir gerçektir. Allah sizin yaptıklarınızdan gâfil değildir. (Bakara sûresi: 149) Mescid-i Harâm’da namaz kılmanın fazîleti, benim bu mescidimde yüz namaz kılmaktan daha fazîletlidir. (Hadîs-i şerîfMüsnedü İmâm-ı Ahmed) Mescid-i Harâm’ın duvarları yoktu. Kâ’be’nin etrâfında bir meydancık ve sonra evler vardı. Halîfe Ömer, Kâ’be etrâfına bir metre…","osmanli":"حرام مسجد"},{"kelime":"Mescid-i Hîf (Mescid-i Hayf)","anlam":"“Hayıflanma mescidi” mânâsına Mekke-i Mükerreme yakınında Minâ’da Cemre-i Akabe’nin güneyindeki mescid.","kategori":"ibadet","misal":"Mescid-i Hîf ’te yetmiş peygamber namaz kıldı. Onlardan birisi Mûsâ aleyhisselâmdır, sanki ben onu katvani iki aba giymiş gibi deve üzerinde ihramlı görür gibiyim. (Hadîs-i şerîfTaberânî) Resûlullah aleyhisselâm Mina’da iken dedi ki: “Yarın biz inşâallah Beni Kinâne hayfine (Kinâne oğullarının Müslümanları boykot edip küfrde ısrâra yemîn ettikleri yere) ineceğiz.” (Buhârî, Müslim) Bu yere yapılan mescide Mescid-i Ha…","osmanli":"حيف مسجد"},{"kelime":"Mescid-i Kıbleteyn","anlam":"2.senesinde Şa’ban ayının 15.Günü Benî Seleme’nin mescidinde öğle namazını kıldırıyordu.","kategori":"ibadet","misal":"“İki kıbleli mescid” mânâsına Medîne-i Münevve-re’de kıblenin Mescid-i Aksâ’dan Mescid-i Haram’a çevrildiğini bildiren âyet-i kerîmenin indiği mescid. Resûlullah aleyhisselâm hicretin Namazın üçüncü rek’atinde namazda Mescid-i Harâm’a dönülmesini emreden âyet-i kerîme (Bakara sûresi: 144) gelerek Resûlullah aleyhisselâm hemen yüzünü Kâ’be cihetine çevirdi. Bu mescid daha sonra Mescid-i Kıbleteyn olarak anıldı.","osmanli":"قبلتين مسجد"},{"kelime":"Mescid-i Kubâ","anlam":"Resûlullah aleyhisselâmın hicret esnâsında Medîne-i Münevvere yakınındaki Kubâ köyünde yaptırdığı mescid.","kategori":"dil","misal":"Câmilerin efdali Kâbe-i Muazzama, sonra bunun etrâfındaki Mescid-i Harâm, sonra Medîne-i Münevvere’deki Mescid-i Nebî, sonra Kudüs’teki Mescid-i Aksâ ve sonra Medîne-i Münevvere şehri yanındaki Mescid-i Kubâ’dır. (Dürrü’l-Muhtâr)","osmanli":"قباء مسجد"},{"kelime":"Mescid-i Nebevî (Mescid-i Nebî)","anlam":"Resûlullah aleyhisselâmın Medîne-i Münevve-re’de inşâ ettiği mescid.","kategori":"dil","misal":"Mescid-i Resûl. Mescid-i Saâdet. Mescid-i Şerîf.","osmanli":"نبوى مسجد"},{"kelime":"Mescid-i Seâdet","anlam":"(Bkz.","kategori":"ibadet","misal":"Mescid-i Nebevî)","osmanli":"سعادت مسجد"},{"kelime":"Mescid-i Şerîf","anlam":"(Bkz.","kategori":"ibadet","misal":"Mescid-i Nebevî)","osmanli":"شريف مسجد"},{"kelime":"MESEL","anlam":"1.Benzer, numûne, örnek. 2.Do-kunaklı, mânâlı ve ibretli söz. 3.Terbiye ve ah-lâka faydalı hikâye, masal.","kategori":"dil","osmanli":"مثل"},{"kelime":"MESELÂ","anlam":"Misâl olarak, şunun gibi, söz gelişi, meselen.","kategori":"dil","osmanli":"مثلا"},{"kelime":"MEŞGûL","anlam":"1.Bir işle uğra-şan, iş görmekte olan. 2.İşgal edilmiş, doldu-rulmuş, tutulmuş. 3.Tutuk, dalgın; dolgun.","kategori":"akaid","misal":"Şerîate tâbi’ olanlar ise, latîf cevâhir ve kıymetli elmaslar ile meşgul olan mücevherciler gibidir. Bunların işi az, kazançları pek çoktur. (Mektû-bât-ı İmâm-ı Rabbânî)","osmanli":"مشغول"},{"kelime":"MEŞGûLİYYET","anlam":"Meşgûl olma, uğ-raşılan şey; iş güç.","kategori":"dil","misal":"Ne büyük ni’mettir ki, çeşitli meşgûliyyet ve bağlılıklarınız, sizleri bu devletten alıkoyma-mış ve dağınık işleriniz, onlara muhabbetinize mâni’ olmamış. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مشغوليت"},{"kelime":"MESH","anlam":"1.Elini sürmek, sıvazlamak; sil-mek; su veya yağla ovuşturmak. 2.Bir uzva veya sargıya ıslak eli sürme. 3.Abdestte ayakları yıkamayıp, mestin üze-rini ıslatma.","kategori":"dil","misal":"Yetimin başını meshediniz. (Hadîs-i şerîf-Hatîb) Namaza kalktığınızda su bulamamışsanız temiz toprağa teyemmüm edin. Yüzlerinizi, ellerinizi onunla meshedin. (Mâide sûresi: 6) Mest üzerine mesh müddeti mukîm için yirmi dört saat, misâfir için üç gün üç gece yani yetmiş iki saattir. (Hadîs-i şerîf-Ebû Dâvûd, Tirmizî) (Habeş hükümdarı) Necâşî, Resûlullah aleyhisselâma siyah bir çift mest hediye etti. Resûlullah aleyhisselâm bunları giydikten sonra abdest alıp üzerlerine mesh etti. (Hadîs-i şerîf-Ebû Dâvûd, Ahmed, Tirmizî)","osmanli":"مسح"},{"kelime":"MESH","anlam":"İnsanken hayvana dönüşmek gibi bir şeyin sûretinin değişmesi.","kategori":"dil","misal":"Kıyâmete yakın mesh, hazf (yere batma) ve kazf (taş yağması) vardır. (Hadîs-i şerîf-İbn-i Mâce)","osmanli":"مسخ"},{"kelime":"MESH MÜDDETİ","anlam":"Mest üzerine mesh etme müddeti.","kategori":"dil","misal":"Mesh müddeti Hanefî’de ikâmette 24 saat, se-ferde 72 saattir. (Ni’met-i İslâm)","osmanli":"مدتى مسح"},{"kelime":"MEŞHED","anlam":"1.Şehid düşülen yer; şehid-lik. 2.Şâhidlik yapılan, hazır olunan yer, meclis.","kategori":"dil","misal":"Büyük günün (kıyâmet gününün) meşhe-dinden dolayı kâfirlerin vay hâline! (Mer-yem sûresi: 37)","osmanli":"مشهد"},{"kelime":"MEŞHûR","anlam":"Şöhretli, şöhret kazanmış, ün salmış, tanınmış.","kategori":"akaid","osmanli":"مشهور"},{"kelime":"MEŞHûR HADÎS","anlam":"İslâmiyet’in ilk asrında bir kişi bildirmişken, ikinci asırda şöhret bulan, yani bir kimsenin Resûlullah’tan, ondan da, en az üç kimsenin ve bunlardan da başkalarının işittiği hadîs-i şerîfler. (Bkz. Ha-dîs) Hanefî mezhebinde meşhur hadîs, bağ-layıcılık bakımından mütevâtir hadîs gibidir.","kategori":"hadis","osmanli":"حديث مشهور"},{"kelime":"MESÎH","anlam":"“Meshedilmiş” mânâsına Îsâ aleyhisselâmın unvanı.","kategori":"dil","misal":"Meryem oğlu Mesîh bir peygamberden başka bir şey değildir. Ondan evvel de peygamberler gelip geçmiştir. Anası çok sâdıka (doğru) bir kadındı... (Mâide sûresi: 75) Meryem oğlu Mesîh Îsâ beni müjdeledi. (Hadîs-i şerîfTaberânî) Mesîh kelimesinin türediği mesh; silmek, suyla uzvu ıslatmak, yağla ovmak, hastalığı gidermek, saç taramak, seyahat etmek, yarmak gibi mânâlara gelir. Buna göre Îsâ aleyhisselâma niçin Mesîh den…","osmanli":"مسيح"},{"kelime":"MEŞÎHAT","anlam":"1.Yaşlılık, ihtiyarlık; şeyh-lik, hocalık. 2.Osmanlı Devleti’nde Şeyhülislâmlık.","kategori":"dil","misal":"Sâlik, istek ve arzularından kurtulup, Hakkın irâdesiyle hareket edince, meşîhat makamına yakışır. Bu hâl ise, vilâyetin birinci kemâlidir. (Mektûbât-ı Ma’sûmiyye)","osmanli":"مشيخت"},{"kelime":"Meşîhat-ı İslâmiyye","anlam":"Osmanlı Devleti’nde Şeyhülislâmlık.","kategori":"osmanli","misal":"Bâb-ı fetvâ.","osmanli":"اسلاميه مشيخت"},{"kelime":"MESKûK","anlam":"28.senesinde Tabe-ristân’da Hertek şehrinde, bu hesâb üzere altın ve gümüş bastı.","kategori":"dil","misal":"Belli ağırlıkta basılmış para. Sikke. (Çokluk hâli meskûkât.) Belli ağırlıkta basılmış olan altın paralara dînâr, gümüş paralara dirhem denir. Eshâb-ı kirâm zamanında, eski Arab meskûkâtı kullanıldığı gibi, basılmamış altın ve gümüş parçaları da, dartarak kullanılırdı. Hazret-i Ömer, orta-lama ağırlıkta başka tek bir dirhem kabul etti. Hazret-i Osman, hicretin (Mir’âtü’l-Haremeyn)","osmanli":"مسكوك"},{"kelime":"MESKûN","anlam":"(A. Sükûn’dan) Sâkin olunan yer; insan oturan yer, şenlikli.","kategori":"dil","osmanli":"مسكون"},{"kelime":"MEŞKûR","anlam":"Şükre, teşekküre değer, makbul, beğenilmiş, övülmüş.","kategori":"dil","misal":"Cenâb-ı Hak sa’yinizi meşkûr eylesin! (Mektû-bât-ı İmâm-ı Rabbânî)","osmanli":"مشكور"},{"kelime":"MESLEK","anlam":"1.Sülûk edilen yer, yol; gidiş. 2.Mâişet için tutulan yol. 3.Sistem.","kategori":"tasavvuf","osmanli":"مسلك"},{"kelime":"MESNED","anlam":"1.İstinâd edilen, dayanılan şey. 2.Rütbe, derece, pâye, makam.","kategori":"dil","osmanli":"مسند"},{"kelime":"MESNEVÎ","anlam":"1.İkili. 2.Mevlânâ Celâleddîn-i Rûmî’nin vilâyet ince-liklerini anlatan ve yirmidört bin beytten mü-teşekkil altı defter olan meşhur eseri. Üç kitabın eşi yoktur. Bunlar, Kur’ân-ı kerîm ve Buhârî-i şerîf ve Celâleddîn-i Rumî’nin Mes-nevî’sidir. (Mekâtib-i Şerîfe)","kategori":"tasavvuf","misal":"Her iki mısranın birbiriyle kâfiyeli olduğu bir edebî nazım şekli.","osmanli":"مثنوى"},{"kelime":"MESNûN","anlam":"Sünnet olan. Farz veya vâcib haricinde Resûlullah aleyhisselâmın yaptığı kuşluk namazı, Muharrem orucu, umre gibi ameller.","kategori":"ibadet","misal":"Vâiz, İmâm, cemâate öğretmek için, mesnûn olan duâları, sesle okur. Cemâat de, sessiz tekrar eder. Cemâat öğrenince, İmâm da sessiz okumalıdır. (Bezzâziyye)","osmanli":"مسنون"},{"kelime":"MEŞREB","anlam":"1.İçecek yer. 2.Yaradılış, tabiat, mizaç; huy, ahlâk. 3.Gidiş.","kategori":"tasavvuf","misal":"Muhammedî meşreb olanlardan da, milyonda birine bu keskin görüş verilirse yine büyük ni’mettir. (Mektûbât-ı İmâm-ı Rabbânî) İnsanların akılları değişik, anlama kâbiliyyetleri farklı olduğundan, herkes yaratıcıyı aradığında, Onu kendi tabiatına, meşrebine, ilim ve idrâkına uygun bir tarzda tasavvur etmiştir. Onu kendi anlayışına ve meşrebine göre ta’rîf etmiştir. Çünki insan, aklının aczi ve noksanlığı sebebi ile anl…","osmanli":"مشرب"},{"kelime":"MEŞRû‘","anlam":"1.Kanuna, şerîate (dine) uygun. 2.Dinin koyduğu ve kabul ettiği (şey). 3.Vâcib ve mendub dışında dinin koyduğu veya kabul ettiği (şey).","kategori":"dil","misal":"Ananın, babanın meşrû’ emirlerine itaat etmek farzdır. (Fetâvâ-i Hayriyye) Meşrû’lar dört kısmdır: Farz, vâcib, sünnet, nâ-file. (İbni Âbidîn) Kabirdeki meyyite telkîn yapmak meşru’dur (Cevhere) Ana-babanın meşrû emirlerine âsî olanlar mel’ûndur. (Ey Oğul İlmihâli)","osmanli":"مشروع"},{"kelime":"MEŞRûBÂT","anlam":"İçilecek şeyler. Meş-rûb’un çokluk hâli.","kategori":"dil","osmanli":"مشروبات"},{"kelime":"MEŞRûTİYYET","anlam":"(A. Şart’tan) Bir hü-kümdara muayyen bazı şartlar karşılığında itaat sözü verme; bir anayasa çerçevesinde ka-nun yapma salâhiyetinin hükümdardan alına-rak halkı temsil eden meclise verildiği idare şekli, parlamenter monarşi.","kategori":"osmanli","osmanli":"مشروطيت"},{"kelime":"MEST","anlam":"1.Ayakkabı. 2.Abdestte ayağın yıkanması farz olan yerini örten ve su geçirmeyen ayakkabı.","kategori":"ibadet","misal":"Mest üzerine mesh haktır. (Fıkh-ı Ekber) Mestin, bir saat yol yürüyünce, ayaktan çıkmayacak şekilde sağlam ve ayağa uygun olması lâzımdır. Bu sebeble ağaçtan, camdan, mâdenden mest olmaz. Ama kalın çoraptan mest olur. (İbni Âbidîn)","osmanli":"مست"},{"kelime":"MESTûR","anlam":"Setredilmiş, giz-lenmiş.","kategori":"dil","osmanli":"مستور"},{"kelime":"MESTûR","anlam":"(A. Satr’dan) Satırlanmış, ya-zılmış, çizilmiş.","kategori":"dil","osmanli":"مسطور"},{"kelime":"MESTûRE","anlam":"1.Tesettür etmiş, örtülü kadın. 2.Şâhidlerin bu işe ehil olup olmadığını anlamak için hâkim tarafından gizli olarak ait oldukları makâma yazılan yazı.","kategori":"osmanli","misal":"Kadınlar cihâda mestûre olarak ve zevci veya mahremi ile gider. (İbni Âbidîn)","osmanli":"مستوره"},{"kelime":"MEŞVERET","anlam":"İstişâre etme, danışma; danışma meclisi.","kategori":"osmanli","misal":"Onlar ki, Rableri için da’vete icâbet etmekte namazı dosdoğru kılmaktadırlar. Ve işlerinde meşveret eder, kendilerine verdiğimiz rızıktan (hak yolunda) sarf ederler. (Şûrâ sûresi: 38) Meşveret, insanı pişman olmaktan koruyan bir kale gibidir. (Berîka)","osmanli":"مشورت"},{"kelime":"METÂ‘","anlam":"1.Faydalanılan şey. 2.İktisadî kıymeti olan (şey), mal.","kategori":"dil","misal":"Dünya hayâtı ancak insanları aldatıcı metâ-dır. (Âl-i İmrân sûresi: 185) İçinde metânız bulunan eve girmenizde ve-bal yoktur. (Nûr sûresi: 29)","osmanli":"متاع"},{"kelime":"METBû‘","anlam":"Kendisine tâbî’ olunan, uyulan. İlim amelden efdaldir. Zira ilim metbû’dur, amel ise ona tâbî’dir. (Miftâhü’l-Cenne)","kategori":"dil","misal":"Resûlullah aleyhisselâma uymanın en yüksek derecesi; insan vücûdunun her zerresinin tâbî’ olmasıdır. Tâbî’, metbû’a o kadar benzer ki, tâbî’ olmaklık aradan kalkar. Bunlar da, sanki Resû-lullah gibi, aynı kaynaktan her şeyi alır. (Mek-tûbât-ı Ma’sûmiyye)","osmanli":"متبوع"},{"kelime":"METÎN","anlam":"1.Metânetli, sağlam, dayanıklı; kendisine güvenilir. 2.Kudretli, kâmil olan, hiç-bir sûrette za’f, âcizlik, güçsüzlük meydana gel-meyen mânâsına Allahü teâlânın Esmâ-i hüs-nâsından (el-Metîn). Mahlûkâtına (yarattıklarına) rızık verici yal-nız Allahü teâlâdır. (O), kuvvet sahibidir, metîndir. (Zâriyât sûresi: 58)","kategori":"akaid","osmanli":"متين"},{"kelime":"METOD","anlam":"Usûl, sistem.","kategori":"fikih","osmanli":"متود"},{"kelime":"METRES","anlam":"Gayrı meşru münasebette bulunulan kadın.","kategori":"osmanli","osmanli":"مترس"},{"kelime":"MEVÂKÎT","anlam":"1.Bir iş için tayin edi-len zaman veya mekânlar. 2.Mekke dışından hacca gelenlerin (âfâkîlerin) hac veya umre için ihrâma girdiği yerler.","kategori":"ibadet","misal":"Mîkât’ın çokluk hâli.","osmanli":"مواقيت"},{"kelime":"MEVÂZÎN","anlam":"Ölçü âletleri, ölçekler. Mîzân’ın çokluk hâli.","kategori":"dil","osmanli":"موازن"},{"kelime":"MEVCûD","anlam":"1.Var olan, bu-lunan. 2.Hazır olan, hazır bulunan.","kategori":"dil","misal":"(A. Vücûd’dan)","osmanli":"موجود"},{"kelime":"MEVCûDÂT","anlam":"Var olan şeyler, mah-lûklar, yaratıklar; kâinât. Mevcûd’un çokluk hâli. Resûlullah aleyhisselâm, Rabbülâlemînin mah-bûbu, mevcûdatın öncesinin ve sonrasının en iyisidir. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"dil","osmanli":"موجودات"},{"kelime":"MEVDû‘","anlam":"Tevdî‘ olunan, emânet edilmiş, üstüne verilmiş.","kategori":"muamelat","osmanli":"مودوع"},{"kelime":"MEVDû‘ HADÎS (Mevzû Hadîs)","anlam":"","kategori":"hadis","misal":"(T) Vaz‘ edilmiş, konulmuş hadîs. Bir hadîs imâmının sıhhat şartlarına uymayan hadîs-i şerîf. (Bkz. Hadîs) Mevdû‘ hadîs, şeriat kâidelerine aykırı ise, hiçbir suretle, hatta amellerinin fazileti bâbında dahi rivâyet câiz değildir. Umumî bir kâideye dâhil olursa rivâyetine bir mâni yoktur. Fakat ancak mevdû‘ hadîs olduğu beyan edilerek rivâyet edilebilir. (İbni Âbidîn)","osmanli":"حديث موضوع"},{"kelime":"MEVHûM","anlam":"Vehm olunan, aslı esâsı yokken zihinde kurulmuş olan, kuruntuya da-yanan; var olmadığı hâlde varmış gibi görü-nen. Hayâlî. (Bkz. Vehm)","kategori":"dil","misal":"Âfet-i gamdan aceb, dünyada kim âzâdedir? Herkesin bir derdi var, mâdem ki, âdem-zâdedir. Bir hûmâ-yı zevki bin sayyâd-ı gam ta’kîb eder, Böyle bir mevhûma bilmem, halk neden üftâ-dedir?","osmanli":"موهوم"},{"kelime":"MEVKÎ‘","anlam":"1.Bir şeyin vuku’a geldiği yer. 2.Tasnif edilen yerlerden her biri, makam.","kategori":"dil","osmanli":"موقع"},{"kelime":"MEVKûF","anlam":"1.Tevkîf edilmiş, tutuklanmış. 2.Vakfedilen şey.","kategori":"hadis","misal":"Mahall-i Vakf.","osmanli":"موقوف"},{"kelime":"MEVKûF HADÎS","anlam":"Sahâbilerden rivâyet edilen hadîs.","kategori":"hadis","misal":"Mevkûf hadîs, merfû olmadığı, yani rivâyet eden sahâbi Resûlullah’tan şöyle işittim, şöyle emrolunduk, şöyle yaparlardı gibi sözlerle rivâyet olunmuşsa, dinde delildir.","osmanli":"حديث موقوف"},{"kelime":"MEVKûFÂT","anlam":"1.Vakfedilmiş mallar. 2.Vakfın, gelirden arta kalan ve hazineye intikâl eden kısmı. 3.Muayyen bir zaman bekletilmiş mal ve para. 4.Mevkûfâtî Mehmed Efendi’nin Halebî’nin Mültekâ’sından tercüme ve şerh yoluyla hazırladığı, Osmanlı mahkemelerinde kanun olarak tatbik edilen meşhur fıkıh kitabı.","kategori":"hadis","osmanli":"موقوفات"},{"kelime":"MEVLÂ","anlam":"1.Efendi. 2.Mâlik. 3.Köle; azatlı köle. 5.Velâyet sahibi (iş gören). 6.Komşu.","kategori":"dil","misal":"Allah ne güzel mevlâdır. (Enfâl sûresi: 40) Bir kavmin mevlâsı, onlardandır. (Hadîs-i şerîf-Buhârî) Akraba, vâris. Allah ve Resûlü, mevlâsı olmayanın mevlâ-sıdır. (Hadîs-i şerîf-Buhârî, Tirmizî) Dost. Ben kimin mevlâsı isem Ali de onun mevlâ-sıdır. (Hadîs-i şerîf-Tirmizî, İbn-i Mâce, Müs-nedü İmâm-ı Ahmed) Muvâlat (kardeşlik) akdi yapılan. Mev-le’l-muvâlât. Mevlâlarınıza dahi hisselerini veriniz. (Nisâ sûresi: 33)","osmanli":"مولى"},{"kelime":"MEVLÂNÂ","anlam":"1.“Efendimiz” mânâ-sına büyüklere karşı kullanılan hürmet sözü. 2.Celâleddîn Rûmî, Hâlid Bağdâdî gibi tasav-vuf büyüklerinin lakabı.","kategori":"dil","osmanli":"مولانا"},{"kelime":"MEVLE’L-MuVÂLÂT","anlam":"1.Kendisine vâris olmayan birine velî olan ve bunun ile muvâlâtı kabul eden kimse. 2.Vârisi bulunmayan bir kimse ile, suç işlerse diyetini vermek, ölürse vâris olmak üzere yapılan muvâlât akdinin her iki tarafı. (Bkz. Müvâlât, Velî) Meyyitin bıraktığı miras, ferâiz ilmindeki sıra takip edilerek, zevülerhâmdan kimse yoksa, mevlelmuvâlâta verilir. (Mevkûfât)","kategori":"miras","osmanli":"الموالات مولى"},{"kelime":"MEVLEVİYYET","anlam":"1.Mevlâlık, efendi-lik. 2.Tasavvufta bir derece. 3.Osmanlı Devle-ti’nde yüksek rütbeli kâdılıklara verilen isim.","kategori":"tasavvuf","osmanli":"مولويت"},{"kelime":"MEVLÎ","anlam":"Velâyet altında bulunan kimse. Kadın için mevliye kullanılır.","kategori":"dil","osmanli":"مولى"},{"kelime":"MEVLİD","anlam":"1.Dünyaya gelme. 2.Doğum yeri ve zamanı. 3.Hazret-i Peygam-ber’in hayatını anlatan edebî ve manzum eser.","kategori":"dil","misal":"(A. Velâdet’ten) Resûlullah sallallahü aleyhi ve sellem mevlid ge-celerinde eshâbına ziyâfet verir, dünyâya teşrîf ettiği ve çocukluğu zamanında olan şeyleri an-latırdı. Hazret-i Ebû Bekr, halîfe iken, mevlid gecesinde, Eshâb-ı kirâmı toplayıp, Resûlullah’ın dünyâya teşrîfindeki fevkalâde hâlleri konuşur-lardı. Dünyânın her yerindeki müslimânlar, Peygamberimizin ve Eshâb-ı kirâmın yapdık-ları gibi, mevlid gecesinde, Resûlullah’ı anlatan kitâbları okurlar ve Resûlullah’ın dünyâya teş-rîf etdiği bu şerefli gecede şenlik yapar, sevinir-lerdi. İslâm âlimleri, bu geceye çok ehemmiyet vermişlerdir. Bu geceyi bütün mahlûklar, me-lekler, cin, hayvanlar ve cansız maddeler, bir-birlerine müjdelemekte, Fahr-i âlem dünyâya teşrîf etti diye sevinmekdedirler. Mevlânâ Celâ-leddîn-i Rûmî, ‘Mevlid okunan yerden belâlar, sıkıntılar gider’ buyurmuşdur. Mevlidi, nazm, şi’r olarak okumak dahâ te’sîrli ve fâideli olur. (Seâdet-i Ebediyye)","osmanli":"مولد"},{"kelime":"MEVSİM","anlam":"1.Yılın, dünya ekseninin gü-neşe göre eğik olmasından ileri gelen dört kıs-mından her biri. 2.Zaman, devre. 3.Haccın edâ edildiği Zilhicce’nin ilk on günü. 4.Pazar yeri.","kategori":"ibadet","osmanli":"موسم"},{"kelime":"MEVSûK","anlam":"(A. Vüsûk’dan) Vesikaya daya-nan, sağlam, inanılır, güvenilir.","kategori":"dil","osmanli":"موثوق"},{"kelime":"MEVT","anlam":"Ölüm. Rûhun bedenden ayrılması.","kategori":"akaid","misal":"(Bkz. Ölüm)","osmanli":"موت"},{"kelime":"MEVTÂ","anlam":"(A. Mevt’ten) Ölüler, ölmüşler; ölü. Meyyit’in çokluk hâli.","kategori":"dil","osmanli":"موتى"},{"kelime":"MEVZûN","anlam":"Vezn (ağırlık) ile ölçü-len (mal).","kategori":"dil","misal":"Altın ile gümüş daima mevzûndur. Buğday, arpa, hurma ve tuz dâimâ mekîldir (hacim ile ölçülür). Bunlardan başka şeylerin mekîl veya mevzûn olmaları, âdete bağlıdır. Çarşıda, pa-zarda nasıl ölçülüyorsa, öyle olduğu kabul edi-lir. (İbni Âbidîn)","osmanli":"موزون"},{"kelime":"MEY","anlam":"Şarab.","kategori":"dil","misal":"Aşk sarhoşları ile bulun, mey yoksa da, koku geçer. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مى"},{"kelime":"MEYDÂN","anlam":"1.Geniş, açık, düz yer, alan. 2.Müsâbaka veya yarış yeri. 3.Fırsat, imkân.","kategori":"dil","osmanli":"ميدان"},{"kelime":"MEYHÂNE","anlam":"1-Şarap içilen ve satılan yer. 2-(Tasavvufta) Aşk sarhoşluğunun yaşan-dığı yer, tekke.","kategori":"tasavvuf","osmanli":"ميخانه"},{"kelime":"MEYL","anlam":"2.Sevme, tutulma.","kategori":"dil","misal":"l.Eğilme, yönelme, eğiklik; akıntı.","osmanli":"ميل"},{"kelime":"MEYYİT","anlam":"Ölü.","kategori":"dil","misal":"Kırk kişi bir meyyite duâ ederse, Allah onu mağfiret eder. (Hadîs-i şerîf-Buhârî) Âdet olarak, riyâ, gösteriş olarak değil de, Al-lah rızâsı için, fakirlere yemek, sadaka verip, se-vablarını meyyitin ruhuna göndermek iyi olur ve büyük ibâdet olur. (Mektûbât-ı Ma’sûmiyye)","osmanli":"ميت"},{"kelime":"MEZÂHİB","anlam":"Yollar, ekoller. Mezheb’in çokluk hâli.","kategori":"fikih","osmanli":"مذاهب"},{"kelime":"MEZÂR","anlam":"1.Ziyaret yeri, zi-yaretgâh. 2.Kabir.","kategori":"ibadet","osmanli":"مزار"},{"kelime":"MEZC","anlam":"Katma, karıştırma.","kategori":"dil","osmanli":"مزج"},{"kelime":"MEZHEB","anlam":"Gidilecek yol; görüş, doktrin; bir âlimin itikâdî ve amelî hususlardaki görüşlerinin bütünü.","kategori":"dil","misal":"Dört mezhebten birine uymak Kur’ân-ı kerîme ve Resûlullah sallallahü aleyhi ve selleme uymaktır. Çünki, mezheb imâmları Kur’ân-ı kerîmde açıkça bildirilen hükümleri, Peygamber efendimizin Kur’ân-ı kerîme dair beyanlarını bildirdikleri gibi, Kur’ân-ı kerîmde ve hadîs-i şerîflerinde açıkça bildirilmeyen hususların hükümlerini yine Kur’ân-ı kerîm ve hadîs-i şerîflerin ışığı altında ortaya koymuşlardır. (Hadîka)","osmanli":"مذهب","alternatif":["mezhep"]},{"kelime":"Mezheb İmâmı","anlam":"Kur’ân-ı kerîmde ve hadîs-i şerîflerde açıkça bildirilmiş olan din bilgilerini, Eshâb-ı kirâmdan işiterek veya nakl ile toplayan, açıkça bildirilmemiş olanları da, kendi koydukları usûllere (metod) göre açıkça bildirilmiş olanlara benzeterek çıkaran derin âli…","kategori":"dil","misal":"(Bkz. Müctehid)","osmanli":"امامى مذهب","alternatif":["mezhep"]},{"kelime":"Mezheb Taklîdi","anlam":"Müctehid olmayan Müslümanların, amellerini bir müctehidin mezhebine tâbi olarak yapması.","kategori":"dil","misal":"Mezheb taklîdi; Kur’ân-ı kerîm ve sünnetten ayrılmak değildir. Bilakis mezheb imâmının Kitâb ve sünnetten bildirdiklerine uymak, yani Kitâb ve sünnete uymak demektir. (Hadîka) Bir kimse bir mezhebe tâbi olunca, ihtiyâc olmadıkça başka mezhebi taklit etmez. Fakat bir işi yapmakta kendi mezhebine uymak güç olursa, o işi başka mezhebi taklit ederek yapması câiz olur. (Berîka)","osmanli":"تقليدى مذهب","alternatif":["mezhep"]},{"kelime":"Mezhebde Müctehid","anlam":"Mutlak bir müctehidin koyduğu usûle göre ictihad yapabilen âlim.","kategori":"fikih","misal":"İmâm Muhammed Şeybânî, fıkıh âlimlerinin ikinci tabakasından olup, mezhebte müctehiddir. (İbni Âbidîn)","osmanli":"مجتهد مذهبده"},{"kelime":"MEZHEBSİZ","anlam":"Müctehid olmadığı hâlde, dört hak mezhebten hiç birine tâbi olmayan, mezhebleri kabul etmeyen ve dinî delillerden kendi anlayışına göre hüküm çıkarıp, buna göre amel eden veya böyle birine uyan kimse.","kategori":"dil","misal":"Mezhebsizlik, dinsizliğe giden bir köprüdür. (Makâlât-i Kevserî)","osmanli":"مذهبسز"},{"kelime":"MEZÎ (Mezy)","anlam":"Erkekten şehvetlenince gelen beyaz, şeffâf, kokusuz, yapışkan sıvı.","kategori":"muamelat","misal":"Hanefî ve Şâfiî mezhebinde mezî çıkınca cünüp olmaz; fakat abdest bozulur. (Mevkûfât) Mezî ve vedî, Hanefî ve Mâlikî mezhebinde kaba necâsettir. (İbni Âbidîn)","osmanli":"مزى"},{"kelime":"MEZİYYET","anlam":"İyilik; üstünlük.","kategori":"dil","osmanli":"مزيت"},{"kelime":"MEZKûR","anlam":"Zikrolunmuş, adı geçmiş, anılmış, mebhûs, mezbûr.","kategori":"tasavvuf","osmanli":"مذكور"},{"kelime":"MEZMûM","anlam":"Zemmedilmiş; yerilmiş, kötülenmiş, beğenilmemiş, çirkin.","kategori":"dil","misal":"Kâfirlerin yaptıkları ve kullandıkları şeyler iki kısımdır: Birisi âdet olarak yani her kavmin her memleketin âdet olarak yaptıkları şeylerdir. Bun-lardan haram olmayıp, insanlara faydalı olan-ları yapmak ve kâfirlere benzemeği düşünme-yerek kullanmak günah değildir. Pantolon, fes ve çeşitli ayakkabı, çatal, kaşık kullanmak, ye-meği masada yemek ve herkesin önüne tabaklar içinde koymak ve ekmeği bıçaklarla dilimlere ayırmak ve çeşitli eşya ve âletleri kullanmak, hep âdete bağlı şeyler olup, mübâhtır, serbest-tir. Bunları kullanmak, bid‘at olmaz, günah ol-maz. Bunlardan faydalı olmayanları, mezmûn olanları kullanmak ve yapmak harâm olur. Kâ-firlerin kullandıkları şeylerin ikinci kısmı, on-ların ibâdet olarak yaptıkları, kâfirlik alâmeti olan şeylerdir ki, bunları yapmak ve kullanmak küfr (îmânsızlık) olur, haramdır. (İbni Âbidîn, Birgivî Vasîyetnâmesi)","osmanli":"مذموم"},{"kelime":"MEZY","anlam":"(Bkz. Mezî)","kategori":"dil","osmanli":"مزى"},{"kelime":"Mİ‘MÂR","anlam":"(A.Umrân’dan) İnşâat plânlarını yapan ve bunların kurulmasına bakan sanatkâr. MİNÂ: مناء (A) Arafat ile Mekke arasında,","kategori":"ibadet","misal":"İbrâhîm aleyhisselâmın, kurban etmek için, oğlu İsmâîl’i getirdiği ve hac menâsikinden şeytânın taşlanıp ihramdan çıkılan köy. Terviye günü Mekke’den Minâ’ya gidilir. Arefe sabahı Arafat’a çıkılır. Kurban bayramının bi-rinci günü güneş doğmadan önce Müzdelife’den Minâ’ya hareket edilir. Burada Mescid-i Hîf ’e en uzak olan Cemre-i Akabe denilen şeytâna yedi taş atılır. Sonra eğer kırân veya temettü haccı ise kurban kesilir. Saçını traş edip ihramdan çı-kar. Bayramın ikinci ve üçüncü günü üç şey-tâna yedişer taş atılır. Bunların hepsi vâcibdir. Bayram geceleri Minâ’da kalmak Hanefî’de sün-net, diğer mezheblerde vâcibdir. (İbni Âbidîn)","osmanli":"معمار"},{"kelime":"Mi‘râc Gecesi","anlam":"27.Beş vakit namaz Mi’râc gecesi farz oldu.","kategori":"ibadet","misal":"Resûlullah aleyhisselâmın Mekke’den Kudüs’teki Mescid-i Ak-sâ’ya, buradan da göklere ve bilinmeyen âlemlere götürülüp getirildiği Receb’in (Hadîs-i şerîfBuhârî, Müslim, Müsned) Mi’râc gecesi bir kavme rasladım; dudakları ateşten bir makasla kırpılıyordu. Kimdir diyerek Cebrâil’e sordum. Dedi ki: “Ehl-i dünyadan herkese iyilik emreden; fakat kendileri yapmayan hatiplerdir. Kitabı okudukları hâlde idrâk etmezler.” (Hadîs-i şerîfTaberânî)","osmanli":"سى كيجه معراج"},{"kelime":"Mİ‘RÂC (Miraç)","anlam":"1.Merdiven. 2.Hicretten altı ay kadar evvel Resûlullah aleyhisselâmın Kudüs’deki Mescid-i Aksâ’ya; oradan da göklere ve bilinmeyen yerlere götürülmesi. Beş vakit namaz mi’râc gecesi farz oldu. Peygamber efendimiz sallallahü aleyhi ve sellem, mi’râcda cennetleri ve cehennemleri ve Allahü teâlâyı gördü. Yalnız bu görmesi, dünyâ görmesi ile değil, âhiret görmesi ile oldu. Çünki o gece zaman ve mekân çevresinden dışarı çıktı. Bu görmeye dünyada gördü demek, mecâz olarak denilmiştir. Dünyadan gidip gördüğü ve yine bu dünyaya geldiği için böyle denilmiştir. (Mektûbât-ı İ…","kategori":"ibadet","osmanli":"معراج"},{"kelime":"Mİ‘YÂR","anlam":"Ölçü âleti.","kategori":"dil","misal":"Akıl; his kuvveti ile anlaşılabilen veya hissedi-lenlere benzeyen ve onlara bağlılıkları bulunan şeyleri birbirleri ile ölçerek, iyilerini kötülerin-den ayırmaya yarayan bir mi’yârdır. (el-Mun-kizu minemine’d-Dalâl) Tasavvuf yolunda bulunanların vecd ve hâlleri, keşf ve ilhâmları, İslâmiyet terazisi ile tartılma-dıkça, on para etmez. Kur’ân-ı kerîm ve hadîs-i şerîf mi’yârı ile yoklamadıkça, kabul edilmez. (Mektûbât-ı İmâm-ı Rabbânî) Ramazan ayı, bu aydaki farz orucun mi’yârı-dır. Bu ayda Ramazan orucundan başka bir oruç tutulamaz. Bunun içindir ki, Hanefîlere göre bir kimse Ramazan-ı şerîfte nâfile oruca niyet etse, o yine Ramazan orucundan sayılır. (Mebsût-i Serahsî)","osmanli":"معيار"},{"kelime":"MİFTÂH","anlam":"Anahtar.","kategori":"dil","osmanli":"مفتاح"},{"kelime":"MİHENG","anlam":"1.Altın veya gümüşün aya-rını anlamaya yarayan taş. 2.Birinin veya bir şeyin kıymetini anlamaya yarayan vâsıta, mi’yâr.","kategori":"dil","misal":"Aslı mihek’tir.","osmanli":"محنك"},{"kelime":"MİHMÂN","anlam":"Misâfir.","kategori":"dil","osmanli":"مهمان"},{"kelime":"MİHR","anlam":"Güneş.","kategori":"dil","osmanli":"مهر"},{"kelime":"MİHRÂB","anlam":"1.Oda, hücre, çardak, baş köşe. 2.Mescid, câmi vb. ibâdet yerlerinin kıble tarafında imâmın namaz kıldığı yer.","kategori":"ibadet","misal":"Rabbi Meryem’e hüsn-i kabul gösterdi. Onu güzel bir bitki gibi yetiştirdi. Zekeriyya’yı da onun hâmisi kıldı. Zekeriyya, onun yanına, mihrâba her girişinde orada bir rızık bulur ve; “Ey Meryem! Bu sana nereden geliyor?” der; o da; “Bu, Allah tarafındandır. Allah, dilediğine sayısız rızık verir” dedi. (Âl-i İmrân sûresi: 37) İmâmın mihrâb…","osmanli":"محراب"},{"kelime":"MİHVER","anlam":"Durduğu yerde dönmekte olan bir şeyin, dolayında döndüğü farzolunan doğru çizgi, eksen.","kategori":"fikih","osmanli":"محور"},{"kelime":"MÎKÂT","anlam":"Bir işin zamanı, yeri. Hac ve umre için Mekke’ye gelenlerin ihrâma gir-dikleri mevki. Medîneliler, Zülhuleyfe; Irak-lılar, Zât-ı Irk; Şamlılar, Cuhfe; Necidliler, Ka-ren; Yemenliler, Yelemlem’de ihrâma girerler. (Ni’met-i İslâm)","kategori":"ibadet","misal":"Hac, umre, ticaret veya herhangi bir şey için uzaktan gelenlerin, mîkât denilen yerleri ih-ramsız geçerek Mekke-i Mükerreme Haremine girmeleri haramdır. Geçenin, geri mîkâta gelip ihrâma girmesi ve bir cezâ kurbanı kesmesi lâ-zımdır. (Mevkufat) Olunca vâsıl-ı haddî mîkât İki ihrâmdan aç; iki kanat. (Nâbî)","osmanli":"ميقات"},{"kelime":"MIKNATIS","anlam":"1.Muayyen bir yer. 2.Ke- nar; taraf.","kategori":"dil","misal":"Demir ve benzeri mâ-denleri çekmek hassası bulunan demir çubuk. MINTIKA: منطقه (A)","osmanli":"مقناطيس"},{"kelime":"MİKYÂS","anlam":"Kıyas edecek âlet, ölçek, ölçü âleti.","kategori":"fikih","osmanli":"مقياس"},{"kelime":"MİL","anlam":"Bir mesâfe ölçüsü. Hanefîlere göre bir kara mili 1920; diğer üç mezhebe göre 1680 metredir.","kategori":"fikih","misal":"Su bulamayan veya sudan bir mil uzak olan kimse, teyemmüm eder. (Dürer)","osmanli":"ميل"},{"kelime":"MÎLÂD","anlam":"1.Doğum günü. 2.Îsâ aleyhisselâmın doğumu. 3.Yeni bir başlangıç.","kategori":"dil","osmanli":"ميلاد"},{"kelime":"MÎLÂDÎ SENE (Mîlâdî Yıl)","anlam":"9.Şarl, 970 [m.","kategori":"dil","misal":"365,242 günlük güneş yılını esas alan ve başlangıcı Îsâ aleyhisselâmın doğduğu zannedilen tarih olan takvim senesi. Mîlâdî sene, Îsâ aleyhisselâmın doğum günü zan edilen zamandan başlar ise de, Fransa kralı 1563] senesinde, mîlâdî yıl başının 1 Ocak’tan [Kânûn sânîden] başlamasını emretti. Mîlâdın birinci kânûn [aralık] yirmibeşinde olduğu sanıldığına göre, bugünkü mîlâdî sene bundan beş sene sonra başlamaktadır (KozmoğrafyaHasîb Bey) Mîlâdî sene, müslümanların senesi olan hirdî sene gibi doğru ve kat’î olmayıp,…","osmanli":"سنه ميلادى"},{"kelime":"MİLHAFE","anlam":"1.Yorgan. 2.Bürünülecek şey; kadınların sokağa çıkarken üzerine giydiği uzun ve geniş dış elbisesi, manto, ferâce, câr.","kategori":"osmanli","misal":"Senede, biri yazlık, biri kışlık olmak üzere iki milhafe alması, erkeğin zevcesine olan nafakasındandır. (Bahr)","osmanli":"ملحفه"},{"kelime":"MİLLET","anlam":"1.Din; yol; sünnet. 2.Müşterek kök ve bağları bulunan insan topluluğu; sınıf.","kategori":"hadis","misal":"Kendini bilmeyenden başka İbrâhim’in (aleyhisselâm) milletinden kim yüz çevirir. Gerçekten biz onu dünyada seçtik. O, âhirette dahi gerçek sâlihlerdendir. (Bakara sûresi: 130) (Ehl-i kitâb); bir de “Yahudi veya Hristiyan olun ki, hidâyet bulasınız” derler. Sen de, deki: “Hayır biz hak yol üzere bulunan İbrâhim (aleyhisselâm) milletiyiz. O, hiçbir zaman müşriklerden (puta tapanlardan) olmadı. (Bakara sûresi: 135) (Yû…","osmanli":"ملت"},{"kelime":"MİLLİYET","anlam":"Bir millete mensûbiyet.","kategori":"dil","misal":"MİLLİYETÇİLİK: (T) مليتجيلك Mensub olduğu milleti sevmek, onun ilerlemesi için çalışmak, millî değerleri, müesseseleri, gelenekleri ko-rumak ve devam ettirmek arzusu.","osmanli":"مليت"},{"kelime":"MİNÂ","anlam":"Arafat ile Mekke arasında,","kategori":"dil","misal":"İbrâhîm aleyhisselâmın, kurban etmek için, oğlu İsmâîl’i getirdiği ve hac menâsikinden şeytânın taşlanıp ihramdan çıkılan köy. Terviye günü Mekke’den Minâ’ya gidilir. Arefe sabahı Arafat’a çıkılır. Kurban bayramının birinci günü güneş doğmadan önce Müzdelife’den Minâ’ya hareket edilir. Burada Mescid-i Hîf ’e en uzak olan Cemre-i Akabe denilen şeytâna yedi taş atılır. Sonra eğer kırân veya temettü haccı ise kurban ke…","osmanli":"مناء"},{"kelime":"MİNBER","anlam":"1.Yüksek yer. 2.Câmide hatibin hutbe okuması için yapılmış merdivenli yüksek yer.","kategori":"ibadet","misal":"Minber üzerinde hutbe okumak sünnettir. Minber mihrâbın solunda olmalıdır. Resûlullah aleyhisselâm önceleri hurma kütüğü üzerinde hutbe okurdu. Sonra istirahat yerinden başka üç basamaklı bir minber yapılmıştır. (İbni Âbidîn)","osmanli":"منبر"},{"kelime":"Minber-i Nebevî","anlam":"Resûlullah efen-dimizin hutbe okudukları minber. Minber-i Şerîf, Minber-i Münîr.","kategori":"dil","osmanli":"ربنم ىوبن"},{"kelime":"MİNHA","anlam":"1.Atiyye, hediye, karşılık-sız bağış, burs. 2.Hâkimlere veya memurlara rüşvet kabilinden verilen hediye. 3.Sütünden ya da meyvesinden muvakkaten istifâde için karşılıksız verilen mal.","kategori":"dil","osmanli":"منحه"},{"kelime":"MİNHÂC","anlam":"Yol, şeriat.","kategori":"ibadet","osmanli":"منهاج"},{"kelime":"MİNNET","anlam":"1.İyilik etmek. 2.İyiliğe karşı şükran duyma. 3.Birisine yaptığı iyiliği başa kakma.","kategori":"dil","misal":"Allahü teâlâ mü’min kullarına minnette bulu-narak onlara da salavatı emretmiştir. Tâ ki bu suretle daha ziyâde fazîlet ve şeref kazansın-lar. Yoksa Peygamber aleyhisselâm onların sa-lavâtından müstağnidir. (İbni Âbidîn) Ucbun (ibâdetlerini beğenme hastalığının) zıddına minnet denir. Minnet, ni’mete kendi eliyle, kendi çalışmasıyla kavuşmadığını, Al-lahü teâlânın lutfü ve ihsânı olduğunu düşün-mektir. Böyle düşünmek, ucb tehlikesi olduğu zaman farz olur. Diğer zamanlarda ise müs-tehabdır. (Berîka) Sadakalarınızın sevâbını minnet ve ezâ ile heder etmeyin, boşa çıkarmayın. (Bakara sûresi: 264) Allahü teâlâ kıyâmette minnet edenlere bakmaz (ihsanda bulunmaz). (Ha-dîs-i şerîf-İbni Adiy)","osmanli":"منت"},{"kelime":"MİNNETDÂR","anlam":"Birinden gördüğü iyi-liğe karşı müteşekkir kalan.","kategori":"dil","misal":"Kur’ân-ı kerîmi toplayan, Şeyhayn’dır (Haz-ret-i Ebû Bekr ve Hazret-i Ömer’dir). Bugün bilinen İslâm ilimlerinin hepsini, Şeyhayn or-taya koydu. Arabı, Acemi hidâyete getiren, Şey-hayn’dır. Şeyhayn’a bütün insanlar minnettâr-dır. Bunu anlayamamak, güneşi görmemeye benzer. (Kurretü’l-Ayneyn)","osmanli":"منتدار"},{"kelime":"MÎR","anlam":"Bey, âmir, baş; kumandan; vâli.","kategori":"muamelat","misal":"Arabca emîr’den.","osmanli":"مير"},{"kelime":"MÎRÂS","anlam":"Vefât eden kimsenin, bıraktığı mallar ile bunlar üzerinde muayyen şahısların hakları.","kategori":"miras","osmanli":"ميراث"},{"kelime":"MÎRÎ","anlam":"Devlet malı, beylik.","kategori":"muamelat","osmanli":"ميرى"},{"kelime":"MÎRÎ TOPRAK","anlam":"Beytülmâle, yani devlete ait arâzî.","kategori":"muamelat","misal":"(Bkz. Arâzî-i Mîriyye) Uşurlu veya haraçlı toprağın sâhibi ölüp, hiçbir vârisi kalmazsa, bu toprak beytü’l-mâlin olur. Mîrî toprak olur. (Seâdet-i Ebediyye)","osmanli":"طوﭘراق ميرى"},{"kelime":"MİRZA","anlam":"1.İran’a mahsus, Kırım, Tür-kistan ve Hindistan’da da rastlanan bir asâlet unvânı.","kategori":"dil","misal":"İsmin başına gelirse, umumiyetle ki-şinin Ehl-i beyt-i nebevîden; ismin sonuna gelirse asilzâde olduğu anlaşılır.","osmanli":"ميرزا"},{"kelime":"MÎSÂK","anlam":"1.Söz verme, sözleşme, and-laşma. 2.Allahü teâlânın, Âdem aleyhisselâma ve bü-tün zürriyetine (ondan gelecek insanlara); “Ben sizin Rabbiniz değil miyim?” diye hitap bu-yurması, onların da; “Evet, sen Rabbimizsin” diye cevap vermeleri. (Bkz. Ahd)","kategori":"dil","misal":"Benî İsrâil’den vaktiyle yalnızca Allah’a ibâ-det, ana-babaya, akrabaya, yetimlere ve fakir-lere iyilik hususunda mîsâk almıştık. (Bakara sûresi: 283) Peygamberlerden, nübüvvet va-zifesini yerine getirmeleri hususunda mîsâk almıştık. (Ahzâb sûresi: 7) Aranızda mîsâk olduğu hâlde, zevcelerine verdiğiniz mehri nasıl geri alırsınız? (Nisâ sûresi: 21) Akıllı insan, mîsâklarını bozmaz. (Ra’d sûresi: 21) Allah’a mîsâk ediyorum demek, yemîn olur. (Halebî)","osmanli":"ميثاق"},{"kelime":"MİSÂL","anlam":"1.Örnek; benzer, andırır. 2.Rüya. 3.İlk harfi ‘vav’ ve ‘ye’ ile başlayan, harf-i illet olan kelime (vasî, yümn gibi).","kategori":"dil","osmanli":"مثال"},{"kelime":"MİSK","anlam":"Asya’nın Haten bölgesinde yaşa-yan bir cins erkek ceylânın göbek altındaki bir bezden çıkarılan güzel kokulu madde. Müşk.","kategori":"dil","osmanli":"مسك"},{"kelime":"MISKA","anlam":"(Bkz. Muska, Rukye)","kategori":"dil","osmanli":"مصقه"},{"kelime":"MİSKÂL","anlam":"1.Az olsun çok ol-sun kendisiyle ölçülen şey. 2.Bir çeşit ağırlık ölçüsü.","kategori":"dil","misal":"(A. Sıklet’ten) Kim zerre miskâli iyilik yapmışsa onu gö-rür. Kim de zerre miskâli kadar kötülük yap-mışsa onu görür. (Zilzâl sûresi: 7-8) Şer’î ve örfî olmak üzere iki hesap şekil vardır. Birincisi 20, ikin-cisi 24 kırattır. Dinî işlerde şer’î miskal esas alı-nır ki, Hanefî mezhebinde 4,8; Mâlikî mezhe-binde 4,456; Şâfiî mezhebinde ise 3,45 gramdır. Gümüşten yüzük edinin; fakat onun gümüşü, bir miskalden az olsun. (Hadîs-i şerîf-Tirmizî) Üzerine bulaşan necâset, bir miskalden az ise yıkamak sünnettir. Bir miskal bulaşmış ise yı-kamak vâcib, fazlasını yıkamak farzdır. (Miftâ-hü’l-Cenne) Altının, zekât verilmesi farz olan mikdârı yirmi miskaldir. (Bedâyî)","osmanli":"مثقال"},{"kelime":"MİSKÎN","anlam":"1.Çok fakir ve yardıma muhtaç kimse. 2.Cüzzâm hastası. 3.Uyuşuk, tembel; zavallı. 60.âyet-i kerîmesinde sayı-lan zekât verilecek sekiz sınıftan biri de mis-kîndir.","kategori":"dil","misal":"Tevbe sûresinin Hanefî ve Mâlikî mezhebinde fakir, nisâb mikdarı malı olmayan; miskîn ise hiç geliri ve malı olmayan kimsedir. İmâm Ebû Yûsuf ve Muhammed’e göre fakir ile miskin aynı mânâdadır. Şâfiî ve Hanbelî’de kendisi-nin ve ailesinin nafakasını karşılamaya yete-cek malı olmayan kimse fakir; elindeki ile kıt kanaat geçinebilen kimse miskîndir. Fazla ihtiyarlık ve devamlı hastalık gibi se-beblerle oruç tutmaya güç yetiremeyenler üzerine, bir miskîn doyuracak kadar fidye vermek lâzımdır... (Bakara sûresi: 184) Ak-rabâya, miskîne ve yolda kalmışa hakkını ver. Bununla beraber (malını) büsbütün sa-çıp savurma! (İsrâ sûresi: 26) Her şeyin bir anahtarı vardır. Cennet’in anahtarı da, fakîr ve miskînleri sevmektir. Fakîr ve miskîn-ler, sabırları sebebiyle kıyâmet günü Allahü teâlâya yakın bulunacaklardır. (Hadîs-i şerîf-Dâre Kutnî)","osmanli":"مسكين"},{"kelime":"MİSL","anlam":"1.Benzer, kat, emsal.","kategori":"dil","osmanli":"مثل"},{"kelime":"MİSLÎ","anlam":"Çarşıda, pazarda aynı evsâf ve fiyatta benzeri bulunan mal, kıyemî olma-yan (mal).","kategori":"dil","misal":"Ağırlıkla, hacim ve uzunlukla ölçülenlerden fabrikada, tezgâhta yapılan şeyler ve sayı ile ölçülenlerden, aynı büyüklükte olanlar ve aynı büyüklükteki yumurta ve karpuz mislî maldır. (İbni Âbidîn) Mislî malı telef eden, benzerini, mislî olmayan malı telef eden, kıymetini öder. (İbn-i Âbidîn)","osmanli":"مثلى"},{"kelime":"MİŞNÂ","anlam":"2.asırda haham Yahu…","kategori":"dil","misal":"Yahûdî inancına göre Hazret-i Mûsâ’nın sözlerinin yazıya geçirilmiş hâli ve Tevrat’tan sonra gelen mukaddes metin Talmûd’un iki kısmından biri. İbrânice “tekrar” demektir. Yahudi itikadına göre, Mûsâ aleyhisselâma Tûr Dağı’nda Tevrat yanısıra verilen bazı ilimler, yani sözlü emirler vardır. Bunlar, Hârûn, Yûşâ ve Elîazar vasıtasıyla sonraki peygamberlere; sonra da hahamlardan hahamlara rivâyet edildi. ME 538’den itibâren çeşitli Mişnâlar yazıldı. Bütün Mişnâları içinde toplayan en son ve en meşhur Mişnâ, MS","osmanli":"ميشنا"},{"kelime":"MISRÂ","anlam":"1.Kapı kanadı. 2.Bir şiiri meydana getiren satırlardan herbiri.","kategori":"dil","osmanli":"مصراع"},{"kelime":"MİSTİK","anlam":"Esrarlı; tasavvufla alâkalı.","kategori":"tasavvuf","osmanli":"مستيك"},{"kelime":"MİSVÂK","anlam":"1.Ovma âleti. 2.Bir karış büyüklüğünde kesilmiş, dişleri te-mizlemek için kullanılan ve Erak denilen ağaç-tan veya zeytin dalından yapılan ağaç fırça. Misvâk; ağzı temizlemeye, Cenâb-ı Hakk’ın rızâsına kavuşmaya vesîledir. (Hadîs-i şerîf-Bey-hekî) Misvâk kullanarak kılınan namaz, mis-vâk kullanmadan kılınan namazdan yet-miş kat üstündür. (Hadîs-i şerîf-İbni Neccâr) Abdest alırken misvâk kullanmak sünnet-i mü-ekkededir. Misvâk, düz ve ikinci küçük parmak kalınlığında, bir karış boyunda olmalıdır. Mis-vâk, Arabistan’da yetişen Erak ağacının dalıdır. (Düzgün ucundan iki santimetre kadar, ka-buğu soyulup, burası birkaç saat suda tutulur. Sonra ezilince, fırça gibi açılır). Erak ağacı bu-lunmazsa, zeytin dalından yapılır. Nar ağacın-dan yapılmamalıdır. (İbni Âbidîn)","kategori":"dil","misal":"(A. Sivâk’ten)","osmanli":"مسواك"},{"kelime":"MÎZÂN","anlam":"1.Terâzi, ölçü âleti. 2.Kıyâmet günü insanların günah ve sevâbını tartan ve keyfiyeti bilinmeyen terâzi.","kategori":"akaid","misal":"Biz kıyâmet gününe mahsûs adâlet mîzânları kurarız. Artık hiç kimse hiçbir şeyle haksızlığa uğratılmayacaktır. (Yapılan amel) hardal tânesi kadar bile olsa, onu getiririz (mîzâna koyarız). (Enbiyâ sûresi: 47) Artık kimin (sevab) mîzânı ağır gelirse onlar korktuklarından emîn, umduklarına kavuşanların tâ kendileridir. Kimin de mîzânı h…","osmanli":"ميزان"},{"kelime":"MİZMÂR","anlam":"1.Kaval, düdük, üflemeli çalgı. 2.Nefes borusu, hançere.","kategori":"dil","misal":"(Ey Ebû Mûsâ el-Eş’ârî) Keşke dün akşam se-nin kıraatini dinlerken beni bir görseydin! Gerçekten sana, Hazret-i Dâvûd’un mizmâr-larından bir mizmâr verilmiş. (Hadîs-i şerîf-Buhârî, Müslim, Tirmizî) Def, mizmar ve diğerlerinin dinlenmesi ha-ramdır. Eğer ansızın onu dinlerse ma’zur sa-yılır. (İbni Âbidîn) Ağıtçının, davul ve mizmar çalanın kazancı, eğer şartsız alırsa ve parayı veren de kendi rızâ-sıyla vermişse helâldir. (Hindiyye)","osmanli":"مزمار"},{"kelime":"MOLLA","anlam":"1.Kâdı. 2.Büyük âlim.","kategori":"osmanli","misal":"Aslı “efendimiz” mânâsına mevlânâ’dır.","osmanli":"ملا"},{"kelime":"Mu‘ACCEL","anlam":"Ta’cil edilmiş, peşin. Nikâh yapılırken mehrin hepsi mu’accel olabilir. Hepsi müeccel olabilir. Bir kısmı mu’accel, bir kısmı müeccel olabilir. Mehr mu’accel ise, ka-dın mehrini almadan zevci ile sefere gitmeye, vatye ve halvete mâni olabilir. Müeccel ise ola-maz. (Fetâvâ-yı Hindiyye)","kategori":"dil","osmanli":"معجل"},{"kelime":"Mu‘ADDİL","anlam":"1.Ta’dil eden, değiştiren. 2.Mahkemede şâhidleri tezkiye edip, âdil olup olmadığını beyân eden kimse.","kategori":"osmanli","osmanli":"معدل"},{"kelime":"Mu‘ÂDELE","anlam":"Miras taksiminde paylar toplamı ile, meselenin mahrecinin (paydası-nın) eşit olması hâli. Denklem.","kategori":"miras","osmanli":"معادله"},{"kelime":"Mu‘ÂDİL","anlam":"Müsâvî, denk, eş-değer.","kategori":"dil","misal":"Arz-ı ribâtta edâ olunan namaz, ikibin kere bin (iki milyon) namaza müâdildir (eşdeğer-dir). (Mektûbât-ı Ma’sûmiyye)","osmanli":"معادل"},{"kelime":"Mu‘ALLİM","anlam":"Ta’lim eden, öğ-reten, öğretmen, hoca.","kategori":"dil","osmanli":"معلم"},{"kelime":"Mu‘ÂMELÂT","anlam":"İnsanların birbirleri arasında olan alışveriş, kirâ, şirket, fâiz, mîrâs gibi işler.","kategori":"muamelat","misal":"edilir. Diyânâtta, yani helâl veya harâmda ise âdil ve bâliğ bir Müslümanın sözüne inanılır. (Dürrü’l-Muhtâr)","osmanli":"معاملات"},{"kelime":"Mu‘ÂMELE","anlam":"1.Davranma, davranış. 2.Alışveriş, birbiriyle akidleşme. 3.Resmî dâirede yapılan kayıt işi.","kategori":"muamelat","osmanli":"معامله"},{"kelime":"Mu‘ÂMELE SATIŞI","anlam":"Ödünç verirken şart edilmediği hâlde, borçlunun sonradan yüksek fiyatla alacaklıdan mal satın alması.","kategori":"fikih","misal":"Karz-ı hasen bulamayan kimsenin, fâize düşmeden kredi bulabilmesi için yapılır. (Bkz. Iyne)","osmanli":"صاتيشى معامله"},{"kelime":"Mu‘AMMÂ","anlam":"1.A’mâlaştırıl-mış, körleştirilmiş; görünmez kılınmış. 2.Gizli, örtülü, anlaşılmaz veya anlaşılması güç şey. 3.Divan edebiyâtında başta Esmâ-i Hüsnâ olmak üzere mevzuu bir isim olan manzûm bilmece.","kategori":"dil","misal":"(A. A’mâ’dan) Baktım beşerin hâline dünyaya gücendim, Hallolmadı gitti bu mu‘ammâya gücendim. Akvâm-ı beşer bir peder evlâdı değil mi? Âlemde olan sûriş-ü gavgâya gücendim. (Ali Emirî) Mu‘ammâ’ya bir misâl: Bende yok sabr-ü sükûn, sende vefâdan zerre İki yoktan ne çıkar, fikr edelim bir kere. (Cevap: Nâbî. Nâ ve bî Farsçada menfî ya-par. Yani iki tane ‘yok’ birleşince Nâbî olur.)","osmanli":"معمى"},{"kelime":"Mu‘ATTAL","anlam":"1.Ta‘tîl edilmiş, bırakılmış; kullanılmaz; 2.Boş, işsiz.","kategori":"dil","misal":"(A. Atâlet’ten)","osmanli":"معطل"},{"kelime":"Mu‘ATTALA","anlam":"Ta‘tîl itikadına sahip, yani “Allah âleme karışmaz, her şey vakti geldikte kendi tabiatiyle olur” şeklinde inanan fırka.","kategori":"akaid","osmanli":"معطله"},{"kelime":"Mu‘ÂVVİZETEYN","anlam":"“İki e’ûzüler” mânâsına Felâk ve Nâs sûrelerine beraberce verilen isim.","kategori":"dil","misal":"Resûlullah aleyhisselâm bir rahatsızlık hisset-tiklerinde mu‘avvizeteyni okur; ellerine üfler ve vücuduna sürerdi. (Hadîs-i şerîf-Müslim) Korkulu zamanlarda Mu‘avvizeteyn’i çok oku-mak da çok faydalıdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"معوذتين"},{"kelime":"Mu‘ÂYENE","anlam":"Gözden ge-çirme, yoklama.","kategori":"dil","osmanli":"معاينه"},{"kelime":"Mu‘AYYEN","anlam":"Ta’yin edilmiş, belli, belirli; kararlaştırılan","kategori":"dil","misal":"Câmi’de kendine mu‘ayyen yer ayırmak mekrûh-tur. (İbni Âbidîn)","osmanli":"معين"},{"kelime":"Mu‘AZZAM","anlam":"(A. Azamet’ten) Ulu, çok bü-yük, azamet sahibi.","kategori":"dil","osmanli":"معظم"},{"kelime":"MÜ’MİN","anlam":"1.Îmân eden, tasdik eden, inanan; emniyet veren.","kategori":"akaid","misal":"Ey mü’minler! Hepiniz, Allahü teâlâya tövbe ediniz de, dünya ve âhiret saâdetine kavuşunuz. (Nûr sûresi: 31) Mü’minler birbirini sevmekte, birbirine acımakta, birbirini korumakta bir vücûd gibidir. Vücûdun herhangi bir uzvu rahatsız olursa, diğer âzâları da bu yüzden humma ve uykusuzluğa tutulurlar. (Hadîs-i şerîfMüslim) Mü’min o kimsedir ki, kendi için sevdiğini din kardeşi için de sever. (Hadîs-i şerîfRisâle-i Mün…","osmanli":"مؤمن"},{"kelime":"MÜ’MİN SûRESİ","anlam":"57.âyetleri Medîne-i Münevvere’de nâzil oldu.","kategori":"dil","misal":"Kur’ân-ı kerîmin kırkıncı sûresi. Mekke-i mükkerremede nâzil oldu. Seksen beş âyet olup, 56 ve 28-45. âyet-i kerîmelerinde, Fir’avn’ın âilesinden mü’min bir kişinin vasıfları anlatıldığı için, Sûretü’l-Mü’min denilmiştir. Gâfir sûresi de denir. Sûrede; îmân etmenin önemi, günahları bağışlayan, tövbeleri kabul eden, bununla beraber cezâsı şiddetli olan Allahü teâlânın inkârcılara vereceği cezâlar, Allahü…","osmanli":"سى سوره مؤمن"},{"kelime":"MÜ’MİNûN (Mü’minîn)","anlam":"Îmân edenler, inananlar.","kategori":"akaid","misal":"Mü’min’in çokluk hâli.","osmanli":"مؤمنون"},{"kelime":"MÜ’MİNûN SûRESİ","anlam":"Kur’ân-ı kerîmin yirmi üçüncü sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Yüz on sekiz âyet-i kerîmedir. Sûrenin ilk âyetlerinde kurtuluşa eren mü’minlerin ibâdetlerinden, yaşayışlarından ve kavuşacakları âhiret nîmetlerinden bahsedildiği için Sûretü’l-Mü’minûn denilmiştir. Sûrede ayrıca, Allahü teâlânın insanları yarattığı, onlara neler bağışladığı, Nûh, Mûsâ, Hârûn ve Îsâ aleyhimüsselâmın karşılaştıkları güçlükler, inkârcıların uğrayacakları felâketler, Allahü teâlâ…","osmanli":"سى سوره مؤمنون"},{"kelime":"Mu‘TÂD","anlam":"(A. Âdet’ten) Normal, âdete uy-gun, alışılagelmiş olan.","kategori":"dil","osmanli":"معتاد"},{"kelime":"Mu‘TEBER","anlam":"1.İ‘tibarlı, hatırı sayılır. 2.İnanılır, güvenilir. 3.Câri, yürürlükte olan, geçer.","kategori":"ibadet","osmanli":"معتبر"},{"kelime":"Mu‘TEMED","anlam":"İ‘timad edilen (şey veya kimse); sözüne güvenilir (kimse).","kategori":"dil","osmanli":"معتمد"},{"kelime":"Mu‘TEZİLE (Mûtezile)","anlam":"“İ‘tizâl edenler (ayrılanlar)” mânâsına hicrî II.","kategori":"dil","misal":"Mu’tezile, insan dilediği işi kendi yaratır dedi. Kazâ ve kaderi inkâr etti. (İtikadnâme)","osmanli":"معتزله"},{"kelime":"MÜBÂDELE","anlam":"Bir şeyi diğer bir şeyle değişmek, değiştirmek; satış.","kategori":"dil","misal":"Satış, malı mala rızâ ile mübâdele etmektir. (Halebî)","osmanli":"مبادله"},{"kelime":"MuBÂH","anlam":"1.Açıklanan, açığa vurulan, helâl kılınan. 2.Dînen yapılması emir olunmayan ve yasak da edilmeyen şeyler.","kategori":"fikih","misal":"Bir kimse kapısının önüne su veya buz koysa, oradan geçen kimselerin zengin olsun fakir olsun ondan içmeleri mubâh olur. (İbni Âbidîn) Allahü teâlânın mubâh ettiği şeyler pek çoktur. Harâm ettiği şeyler ise, pek azdır. Mubâhlarda bulunan lezzet, harâmda bulunanlardan kat kat fazladır. (Mektûbât-ı İmâm-ı Rabbânî) Şeriatin mubâh gördüğü hususlarda, halîfen…","osmanli":"مباح","alternatif":["mubah"]},{"kelime":"MÜBÂHÂT","anlam":"Övünme, tefâhür.","kategori":"fikih","osmanli":"مباهات"},{"kelime":"MÜBÂHELE","anlam":"Lânetleşme. Resûlullah aleyhisselâma Necrân’dan bir Hristiyan hey’eti gelmişti.","kategori":"dil","misal":"etmekten kaçındılar ve; “Biz senden râzıyız. Eshâbından bir emîn kimseyi bizimle beraber gönder, vergimizi ona verelim” dediler ve gittiler. Resûlullah aleyhisselâm buyurdu ki: “Eğer onlar mübâhele etselerdi, maymuna ve hınzıra dönerlerdi. Vâdîleri ateş içinde kalırdı. Allahü teâlâ Necrân’ı, ahâlisini, hattâ ağaçlar üzerindeki kuşlarını da helâk ederdi.” (Tefsîr-i Mazharî)","osmanli":"مباهله"},{"kelime":"MÜBÂLAĞA","anlam":"(A. Bülûğ’dan) Bir şeyi ol-duğundan çok büyütme veya küçük gös-terme, abartma.","kategori":"dil","misal":"Resûlullah aleyhisselâm hakk-ı civâra (komşu-ların haklarına) o kadar mübâlağa buyururlar idi ki, Eshâb-ı kirâm, komşuların miras alaca-ğını zannettiler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مبالغه"},{"kelime":"MÜBÂREK","anlam":"Bereketli, feyizli, hayırlı, fâidesi bol, kutlu.","kategori":"dil","misal":"Şüphesiz, âlemler için mübârek ve hidâyet kaynağı olarak insanlar için kurulan ilk ev (mâbed), Mekke’deki (Kâbe)dir. (Âl-i İm-rân sûresi: 96) Bu mübarek zeytin ağacının, meyvesinden de, yağından da istifâde edi-niz! (Hadîs-i şerîf-Tirmizî, Taberânî) Kalbin huzur ve sükûnuna yardım eden her şey mübârektir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مبارك"},{"kelime":"Mübârek Geceler","anlam":"İslâmiyet’in kıymet verdiği ve yapılan ibâdetlerin daha faziletli sayıldığı geceler.","kategori":"ibadet","misal":"Mübârek geceler, Kadr, Mevlid, Berât, Mi’râc ve Regâib ile Muharrem ve Zilhicce’nin ilk onar gecesi, ayrıca Fıtr ve Kurban bayramı geceleridir. Mübârek gecelere hürmet göstermelidir. Bu da, günah işlememek ve ibâdet yapmakla olur. Allahü teâlâ kullarına çok acıdığı için, bazı gecelere kıymet vermiş, bu gecelerdeki, duâ ve tövbeleri kabul edeceğini bildirmiştir. Kullarının çok ibâdet yapması, duâ ve tövbe etmeleri iç…","osmanli":"لر كيجه مبارك"},{"kelime":"MÜBÂŞERET","anlam":"1.Bir işe başlama, girişme. 2.Temas, dokunma. 3.Kar-şılaşmak.","kategori":"dil","misal":"Esbâba (sebeblere) mübâşeret tevekkülü boz-maz. (Mektûbât-ı Ma’sûmiyye)","osmanli":"مباشرة"},{"kelime":"Mübâşeret-i Fâhişe","anlam":"Kadın ile erkeğin, sev’eteyninin, yani tenâsül uzuvları-nın birbirine sürtünmesi.","kategori":"osmanli","misal":"Mübâşeret-i fâhişe, erkeğin de kadının da ab-destini bozar. (Halebî)","osmanli":"فاحشه مباشرة"},{"kelime":"MÜBDÎ’","anlam":"1.Bir şeyi önce yap-mak; başlatmak. 2.Bir şeyi benzersiz ve ör-neksiz yapmak; îcâd etmek. 3.Her şeyi yok-tan yaratan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Mübdî’).","kategori":"akaid","misal":"(A. İbdâ’dan)","osmanli":"مبدئ"},{"kelime":"MÜBECCEL","anlam":"Tebcîl edilmiş, yüceltilmiş, muhterem, azîz, büyük hürmet gösterilen. (Bkz. Tebcîl)","kategori":"dil","osmanli":"مبجل"},{"kelime":"MÜBERRÂ","anlam":"1.Tebşîr edici, müjdeleyici. 2.Kabirde, mü’minlere suâl so- ran melek. 3.Resûlullah aleyhisselâmın lakabı.","kategori":"dil","misal":"(A. Berâ’dan) Berî kılınmış, temize çıkmış, aklanmış; ayrılmış, sıyrılmış. MÜBEŞŞİR: مبشر (A. Bişr’den) (Bkz. Münker ve Nekîr) Şüphesiz biz seni şâhid, mübeşşir ve nezîr (azab ile korkutucu) olarak gönderdik. (Feth sûresi: 8)","osmanli":"مبرى"},{"kelime":"MÜBEYYİN","anlam":"1.Beyân eden, açıklayan. 2.Mücmel bir âyet-i kerîmeyi beyân eden.","kategori":"muamelat","misal":"“Sabahın beyaz ipliği gecenin siyah ipliğinden ayırd edilinceye kadar yiyip için; sonra akşama kadar oruca devâm edin” meâlindeki âyet-i kerîmedeki (Bakara sûresi: 187) fecrin kelimesi mübeyyindir ve önceki kapalılığı açıklamaktadır. (Riyâdü’n-Nâsıhîn)","osmanli":"مبين"},{"kelime":"MÜBHEM","anlam":"İyice belli olmayan; âşikâr olmayan, şüpheli.","kategori":"dil","osmanli":"مبهم"},{"kelime":"MÜBÎN","anlam":"1.Beyân eden, açıklayan, gizlisaklı bırakmayan; apaçık. 2.Hak ile bâtılın arasını beyân eden mânâsına Allahü teâlânın sıfatlarından (elMübîn).","kategori":"muamelat","misal":"Bunlar Kur’ân’ın, Kitab-ı mübînin ayetleridir. (Neml sûresi: 1) Şeytânın size mübîn bir düşman olduğunu söylememiş miydim? (A’râf sûresi: 22)","osmanli":"مبين"},{"kelime":"MÜBTEDÎ","anlam":"İbtidâ eden, yeni başlayan; ilim tahsilinde başlangıçta olan.","kategori":"dil","osmanli":"مبتدى"},{"kelime":"MÜBTEDİ‘","anlam":"Bid‘at sahibi. Ehl-i bid‘at. Resûlullah’ın Mekke’den Beytü’l-Mukaddes’e götürüldüğüne (İsrâ’ya) inanmayanın imanı gider. Göklere ve bilinmeyen yerlere götürül-düğüne (Mi’rac’a) inanmayan ise, dâl ve mü-btedi’ olur. (Bahr)","kategori":"akaid","osmanli":"مبتدع"},{"kelime":"MÜCÂDELE","anlam":"1.Cidâl etme, çekişme, uğraşma, savaşma. 2.Karşısındaki-nin câhilliğini veya haksızlığını ortaya koy-mak ve kendisinin akıl, fazîlet ve şeref bakı-mından üstün olduğunu isbât etmek için iki kişinin bir şey üzerinde tartışması. Mücâhid, Allah yolunda nefsiyle mücadele edendir. (Hadîs-i şerîf-Tirmizî, Müsned) Hak-sız olduğu hâlde mücâdeleden vazgeçen kim-seye Allahü teâlâ Cennet’in kenar yerinde bir ev inşâ ettirir. Haklı olduğu hâlde mücâde-leden kaçınan kimseye ise, Cennet’in orta-sında bir köşk inşâ ettirir. (Hadîs-i şerîf-Tir-mizî, İbn-i Mâce) Mücâdeleyi terk edin; zîrâ onun kârı azdır. Mücâdeleyi terk edin, fay-dası az olduğu gibi dostlar arasına hüsûme-tin (düşmanlığın) girmesine sebeb olur. (Ha-dîs-i şerîf-Taberânî)","kategori":"dil","osmanli":"مجادله"},{"kelime":"MÜCÂDELE SûRESİ","anlam":"Kur’ân-ı kerîmin elli sekizinci sûresi.","kategori":"dil","misal":"Medîne’de nâzil oldu. Yirmi iki âyet-i kerîme-dir. Birinci âyetinde geçen Mücâdele kelime-sinden dolayı sûreye, Sûretü’l-Mücâdele de-nilmiştir. Sûrede; cemiyet ve muâşeret âdâbı ve Resûl-i ekremin aleyhinde gizli teşebbüs-lerde bulunan Yahûdîler ile bunların destek-çileri olan münâfıkların kötülendiği bildiril-mektedir. (Mefâtihü’l-Gayb) Kim Mücâdele sûresini okursa, kıyâmet günü Allahü teâlânın râzı olduğu kimselerden ya-zılır. (Hadîs-i şerîf-Beydâvî)","osmanli":"سى سوره مجادله"},{"kelime":"MÜCÂHEDE","anlam":"1.Uğraşma; çarpışma. 2.Din uğruna düşmanla mücâdele etme; nefse zor gelen işleri yapma.","kategori":"tasavvuf","misal":". Bizim uğrumuzda mücâhede edenlere ge-lince, elbette biz onlara yollarımızı göste-ririz. Şüphesiz ki Allah, her hâlde muhsin-lerle (iyilik edenlerle) beraberdir. (Ankebût sûresi: 69) Gerçek mü’minler; Allahü teâlâya ve Resûlüne îmân edip, sonra şüphe etmeye-rek, Allah uğrunda mal ve canlarıyla mücâ-hede edenlerdir. İşte sâdık olanlar bunlardır. (Hucurât sûresi: 15) İnsanların en efdali, canı ve malı ile Allah yolunda mücâhede eden mü’mindir. (Hadîs-i şerîf-Buhârî, Müslim) Nefsin İslâmiyet’in dışına taşmasını önlemek için, onunla iki cihâd vardır: Birincisi, ona uy-mamak, onun arzularını yapmamaktır. Buna, riyâzet çekmek denir. Riyâzet, vera’ ve takvâ ile olur. Takvâ, harâmlardan sakınmaktır. Vera’ ha-ramlardan ve mübâhları ihtiyaçtan fazla kul-lanmaktan da sakınmaktır. Cihâdın ikincisi, onun istemediği şeyleri yapmaktır. Buna mü-câhede denir. Bütün ibâdetler mücâhededir. Bu iki cihâd, nefsi terbiye eder. İnsanı olgunlaştı-rır. Ruhları kuvvetlendirir. Sıddıkların, şehid-lerin ve sâlihlerin yoluna kavuşturur. Allahü teâlâ kullarının ibâdetlerine muhtaç değildir. Kullarının günah işlemesi O’na hiç zarar ver-mez. Kullarının nefslerini terbiye etmek, nefsle cihâd etmek için bunları emretmiştir. (Berîka)","osmanli":"مجاهده"},{"kelime":"MÜCÂHİD","anlam":"Cihâd eden, Allah yolunda düşman ile çarpışan.","kategori":"akaid","misal":"Allah, mücâhidleri, oturup ibâdet edenlerden üstün tutmuştur. (Nisâ sûresi: 95) Mücâhid, seferden dönene kadar, gündüz oruçlu, gece kâim olan kimse gibidir. (Hadîs-i şerîfİbn-i Mâce)","osmanli":"مجاهد"},{"kelime":"MÜCÂZÂT","anlam":"(A. Cezâ’dan) Karşılık; bir suça karşı ceza çektirme.","kategori":"dil","osmanli":"مجازات"},{"kelime":"MÜCEDDÎD","anlam":"1.Tecdid eden, yenileyen. 2.Zaman içinde dine giren bid‘at ve hurâfeleri temizlemek, unutulmuş farz ve sünnetleri or-taya çıkarmak üzere hadîs-i şerîfin işaretiyle her yüz senede bir gönderilen âlim. Her yüz senede bir müceddîd zâhir olur (or-taya çıkar). Ümmetimin işlerini yeniler. (Ha-dîs-i şerîf-Ebû Dâvûd) Sultanlar içinde Ömer bin Abdülazîz, din bil-gilerinde İmâm-ı Şâfiî, tasavvufta (bir Müslü-manın İslâm ahlâkı ile ahlâklanması için lâ-zım olan bilgileri ve yolları öğreten ilimde) Ma’rûf-i Kerhî, esrâr (sırlar, gizli) bilgilerinde İmâm-ı Muhammed Gazâlî, feyz vermekte ve kerâmetler göstermekte Abdülkâdir-i Gey-lânî, hadîs ilminde Celâlüddîn-i Süyûtî, tarî-kat, hakîkat ve akâid yani îmâna dair bilgilerin inceliklerini açıklamakta ve kalblere akıtmakta İmâm-ı Rabbânî, müceddid idiler. Hepsi, İslâ-miyet’in yayılmasına, kuvvetlenmesine hizmet ettiler. (Mekâtib-i Şerîfe)","kategori":"dil","osmanli":"مجدد"},{"kelime":"Müceddîd-i Elf-i Sânî","anlam":"Hicrî ikinci bin yılının yenileyicisi mânâsına İmâm-ı Rabbânî hazretlerinin lakabı.","kategori":"ibadet","misal":"Bu isim kendisine, zamanının büyük âlimlerinden Abdülhakîm Siyalkûtî tarafından verilmiştir. (Berekât)","osmanli":"ثانى الف مجدد"},{"kelime":"MÜCEDDİDİYYE","anlam":"Nakşibendî tarikatının Müceddid-i elf-i sânî İmâm-ı Rabbânî Ahmed Fârukî’den sonra aldığı isim.","kategori":"ibadet","osmanli":"مجدديه"},{"kelime":"MÜCEHHEZ","anlam":"(A. Cihâz’dan) Techîz olun-muş, donanmış, donatılmış, hazırlanmış.","kategori":"dil","osmanli":"مجهز"},{"kelime":"MÜCERRED","anlam":"1.Tecrîd edilmiş, soyulmuş, çıplak. 2.Tek, yalnız, ayrı. 3.Karışık ve katışık olmayan. 4.Soyut. 5.Bekâr, evli olmayan.","kategori":"dil","misal":"Çokluk hâli mücerredât gelir.","osmanli":"مجرد"},{"kelime":"MÜCESSİME","anlam":"Allahü teâlâya cisim ve mekân izâfe eden bir bid‘at fırkası.","kategori":"akaid","misal":"Allahü teâlânın yakın olması ve birlikte olması, bizim bildiğimiz ve anladığımız gibi değildir. Yakın ve berâber denilince, aklımıza, düşüncemize ve anlayışımıza gelen ve keşf ile anlaşılan her şeyden, Allahü teâlâ uzaktır. Bunlara hiç benzemez. Allahü teâlâyı böyle düşünmek, Mücessime’ye kaymaya sebeb olur. Allahü teâlânın bize yakın olduğuna ve bizimle berâber olduğuna îmân ederiz. Fakat, bu yakınlığın ve bu berâb…","osmanli":"مجسمه"},{"kelime":"MÜCEVHER","anlam":"Cevher ile, kıymetli taş ile süslenmiş","kategori":"dil","osmanli":"مجوهر"},{"kelime":"MûCİR","anlam":"Îcâr eden, kirâya veren, âcir.","kategori":"muamelat","misal":"Kirâya veren mal sâhibi. (Bkz. Âcir, İcâre, Kirâ)","osmanli":"موجر"},{"kelime":"MuCÎZ","anlam":"İcâzet veren, izin veren. Mu‘CİZ: معجز (A) Acze düşüren, âciz bırakan. Mu‘CİZE: معجزه (A) Âciz bırakan, karşı konul-","kategori":"dil","misal":"maz; hârika hâdise. İnsanların âciz olduğu hu- suslarda, Peygamberlerden peygamberliklerine delil olarak Allahü teâlânın izniyle meydana gelen hârikulâde hâller. Bir şeyin mûcize olabilmesi için şu şartlar lâ-zımdır: Allahü teâlâ o şeyi mûtâd sebebler dı-şında yaratmış olmalıdır. Hârikulâde olmalıdır. Başkalarının yapamaması lâzımdır. Peygamber olan zâtın istediğine uygun olmalıdır. İsteyip de hâsıl olan mûcize kendisini yalanlamamalıdır. Mûcize, peygamber olduğunu söylemeden önce hâsıl olmamalıdır. Bir peygamberin ümmetinden meydana gelen hârikulâde hâller, kerâmetler o peygamberin mûcizesidir. (İsbâtü’n-Nübüvve) Resûlullah’ın sallallahü aleyhi ve sellem mûcize-leri binden fazla olup bazıları şunlardır: Mîrâc, şakk-ı kamer (ayın ikiye bölünmesi), mübârek parmaklarından su fışkırması, Kâbe-i Muaz-zama içindeki putların mübârek parmağının işâreti ile yüz üstü düşmesi, ölülerin diriltil-mesi, yaralılara ve hastalara şifâ verme. (Şevâ-hidü’n-Nübüvve)","osmanli":"موجز"},{"kelime":"MÜCMEL","anlam":"İcmâl edilmiş, icmâlen, kısaca bildirilmiş.","kategori":"fikih","misal":"Kur’ân-ı kerîmde meâlen buyruldu ki: “İnsan, hırslı ve sabrı az yaratıldı.” (Meâric sûresi: 19) Âyet-i kerîmede hırslı ve sabrı az mânâsına olan “helû” lafzı mücmel olup, ondan sonra gelen; “Ona bir sıkıntı dokunursa, feryâd eder. Ona hayır (mal) isâbet ederse cimrilik eder” (Meâric sûresi: 20, 21) âyet-i kerîmeleri ile açıklanmıştır. (Usûl-i Serahsî) Ahkâm (hükümlerle alâkalı) âyetlerinin ekserisi, mücmeldir. Bunla…","osmanli":"مجمل"},{"kelime":"MÜCTEBÂ","anlam":"1.İctibâ edilmiş, seçil-miş. 2.Resûlullah aleyhisselâmın sıfatlarından.","kategori":"akaid","misal":"MÜCTEHEDÜN FİH: فيه مجتهد (A) Hakkında çeşitli ictihâdlar bulunan, üzerinde ihtilâf edi- len, hakkında açık nass ve üzerinde icmâ’ bu-lunmayıp, müctehid âlimler arasında ihtilâf mevzuu olan. Muhtelefün fih.","osmanli":"مجتبى"},{"kelime":"MÜCTEHİD","anlam":"1.İctihâd eden, cehd ile çok çalışan. 2.Kur’ân-ı kerîmden, hadîs-i şerîf ve diğer dinî delillerden hüküm çıkarabilecek dereceye yükselmiş âlim.","kategori":"dil","misal":"(Bkz. İctihâd) Müctehid, hatâ ederse bir sevab, isâbet ederse iki veya on sevab alır. İki sevabdan birincisi, ictihâd etmek sevâbıdır. İkincisi, doğruyu bulmak sevâbıdır. (Hadîs-i şerîfMec-ma’üzZevâid)","osmanli":"مجتهد"},{"kelime":"MÜDÂHALE","anlam":"(A. Duhûl’den) Karışma, araya girme, el katma, sokulma.","kategori":"dil","osmanli":"مداخله"},{"kelime":"MÜDÂHENE","anlam":"1.Aldatma; iki yüzlülük; dalkavukluk. 2.Dünyalık ele ge-çirmek için dinden tâviz vermek.","kategori":"dil","misal":"Müdâhene edenler, kabirden maymun ve hınzır şeklinde kalkacaktır. (Hadîs-i şerîf-Ebû Nuaym) Haram işleyene veya yanında bulunanlara olan saygısı, yahud dine olan bağlılığının gevşekliği, müdâheneye sebeb olur. Dinine veya dünya-sına veya başkalarına zarar olmadığı zaman, haram ve mekrûh işleyene mâni olmak lâzım-dır. Mâni olmamak, susmak harâm olur. Mü-dâhene etmek, haram işlemeye râzı olmağı gös-terir. (Berîka) Muhabbete müdâhene sığmaz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مداهنه"},{"kelime":"MÜDÂRÂ","anlam":"1.İdâre etme, yüze gülme; dost görünme. 2.Başkalarının fikrine uymuş gibi görünme; alttan alma. 3.Dinini zarardan korumak için, dünya menfaatinden vazgeçme.","kategori":"hadis","misal":"Allahü teâlâ bana, farzları yerine getirmeyi emrettiği gibi, insanlara müdârâ etmeyi de emretti. (Hadîs-i şerîf-Hâkim) İki cihan dirliği şu iki sözde saklıdır. Dostlara merdlik, düşmanlara müdârâ. (Sâ’dî-i Şîrâzî)","osmanli":"مدارا"},{"kelime":"MuDÂREBE","anlam":"Sermâye birinden, emek diğerinden olmak üzere sözleşilen şirket.","kategori":"muamelat","misal":"Mudârebe şirketinde sermâyenin; altın, gümüş veya başka geçer para olması lâzımdır. Kâr önceden sözleşilen oranda paylaşılır. Sermâye, iş yapanlara emânettir. Telef olursa ödemezler. (İbni Âbidîn)","osmanli":"مضاربه"},{"kelime":"MÜDÂRİ‘","anlam":"Şimdiki ve gelecek za-man sîgası (kipi).","kategori":"dil","osmanli":"مضارع"},{"kelime":"MÜDÂRİB","anlam":"Müdârebe (emeksermaye) şirketinde emek sâhibi ortak.","kategori":"muamelat","osmanli":"مضارب"},{"kelime":"MÜDÂVİM","anlam":"(A. Devam’dan) Devâm eden, bir işte aralıksız çalışan; bir yere devâmlı ola-rak gidip gelen (kimse).","kategori":"dil","osmanli":"مداوم"},{"kelime":"MÜDÂYENE","anlam":"Ödünç alıp verme, karşılıklı borçlanma.","kategori":"muamelat","osmanli":"مداينه"},{"kelime":"MÜDDESSİR SûRESİ","anlam":"Kur’ân-ı kerîmin yetmiş dördüncü sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Elli iki âyet-i kerîmedir. İlk âyet-i kerîmede geçen Müddessir kelime-sinden dolayı sûreye, Sûretü’l-Müddessir de-nilmiştir. Müddessir; örtüsüne bürünen, de-mektir. Vahyin ilk zamanlarında Resûlullah aleyhisselâmı bir titreme alır; örtüye bürü-nürdü. Bu sebeble sûre, “Ey örtüsüne bürünen (peygamber)” hitâbıyla başlar. Sûrede, Peygam-ber efendimize; inkâr yolunda olanları uyar-ması, Allahü teâlâyı tekbir etmesi, yüceltmesi, sabırlı olması vs. emredilip, inkârcıların uğ-rayacakları cezâlar bildirilmiş, iyilerle kötüle-rin mukâyesesi yapılmıştır. (Mefâtihü’l-Gayb) Kim Müddessir sûresini okursa, Allahü teâlâ, Muhammed aleyhisselâmı tasdik (inanan) ve tekzîb edenlerin (inanmayanların) adedinin on katı sevab verir. (Hadîs-i şerîf-Beydâvî)","osmanli":"سى سوره مدثر"},{"kelime":"MÜDDET","anlam":"Zaman, vakit; bir şeyin uzayıp sürdüğü zaman.","kategori":"dil","misal":"Günahı, sevâbından çok olan mü’minlerin, Ce-hennem’e girip, günahlarına karşılık, bir müd-det azap görmeleri câiz ise de, bunlar, Cehen-nem’de sonsuz kalmayacaklardır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مدت"},{"kelime":"MÜDERRİS","anlam":"Tedris eden, ders veren. Medrese hocası.","kategori":"osmanli","osmanli":"مدرس"},{"kelime":"MÜDEVVEN","anlam":"Tedvin olunmuş, der-lenip bir araya getirilmiş (kanun).","kategori":"dil","osmanli":"مدون"},{"kelime":"MuDILL","anlam":"1.Dalâlete düşüren, doğru yoldan çıkarıp, eğri yola saptıran. 2.Dalâleti ihtiyâr edenleri bu yolda bırakan, onları dalâ-lete düşüren mânâsına Allahü teâlânın isim-lerinden (El-Mudıll). Allahü teâlânın isimleri aynı zamanda sıfatla-rıdır. Allahü teâlânın Hâdî (hidâyete kavuştu-rucu) Mudıll sıfatları vardır. İnsanlardan ba-zılarına Hâdî, bazılarına Mudıll sıfatı ile tecellî eder. Niye böyle olduğunu biz bilemeyiz. (Mek-tûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"مضل"},{"kelime":"MÜDRİK","anlam":"1.İdrâk eden, iyice anlayan. 2.İftitah tekbirinde imâma yetişen ve nama-zın tamâmını imâmla kılan kimse.","kategori":"dil","osmanli":"مدرك"},{"kelime":"MÜDRİKE","anlam":"İdrak edici, anlayıcı, bi-lici kuvvet. Nutk. Akl. Kuvve-i âlime. (Bkz. Kuvve-i Âlime)","kategori":"dil","misal":"Ruh, yalnız insanlarda bulunur. Bunun da iki kuvveti vardır. İnsan, bu iki kuvvet ile hay-vanlardan ayrılmaktadır. Bu iki kuvvetten bi-risi idrâk edici olan Kuvve-i âlime ve müdrike denilen bilici kuvvettir. İkincisi, kuvve-i âmile denilen yapıcı kuvvettir. (Ahlâk-ı Alâî)","osmanli":"مدركه"},{"kelime":"MÜECCEL","anlam":"Te’cil edilen, sonraya bı-rakılmış, ertelenmiş, peşin olmayan.","kategori":"dil","misal":"Bey’, peşin semen (para) ile câiz olduğu gibi müeccel semen ile de câizdir. Te’cil ancak se-men ile mebi’ (mal) aynı cinsten olmadıkları ve ikisi hacm ile veya tartarak ölçülmedikleri ve semen, ayn (belli) olmayıp, deyn (belirsiz) ol-duğu zaman ve muayyen (belli) bir vakte kadar olmak şartı ile câiz olur. (Dürerü’l-Hükkâm) Nikâhta mehrin hepsi muaccel olabildiği gibi, hepsi müeccel veya bir kısmı muaccel, bir kısmı müeccel olabilir. (Ni’met-i İslâm)","osmanli":"مؤجل"},{"kelime":"MÜEDDEB","anlam":"Te’dîb edil-miş, edeplendirilmiş, edepli, terbiyeli; oku-muş, bilgili.","kategori":"dil","osmanli":"مؤدب"},{"kelime":"MÜEKKED","anlam":"Te’kîd edilmiş, sağlamlaştırılmış; tekrar edilmiş.","kategori":"dil","osmanli":"مؤكد"},{"kelime":"MÜEKKED SÜNNET","anlam":"Te’kid edilmiş sünnet, kuvvetli sünnet; Resûlullah aleyhisselâmın devam edip, bazen terk ettikleri ve terk edenlere bir şey demedikleri sünnet.","kategori":"hadis","misal":"Sabah namazının sünneti, öğlenin dört rek’atlik ilk sünneti ve iki rek’at son sünneti akşam namazının sünneti, yatsı namazının son iki rek’at sünneti ile iftitah tekbirinde elleri kaldırmak, ezân okumak, kâmet getirmek, namazı cemâatle kılmak müekked sünnetlerdendir. Müekked sünneti, özürsüz olarak devamlı terk etmek mekrûh olur. (İbni Âbidîn)","osmanli":"سنت مؤكد"},{"kelime":"MÜELLİF","anlam":"(A. Ülfet’ten) Kitab te’lif eden, eser sahibi.","kategori":"dil","osmanli":"مؤلف"},{"kelime":"MÜESSESE","anlam":"(A. Esâs’dan) Binâ, kuru-luş; kurum.","kategori":"dil","osmanli":"مؤسسه"},{"kelime":"MÜESSİR","anlam":"1.Te’sir yapan, iz bırakan. 2.İşleyen, hükmünü yürüten. 3.Çok hissedilen, içe işleyen. 4.Dokunan, dokunaklı. 5.Eser sâhibi.","kategori":"dil","osmanli":"مؤثر"},{"kelime":"MÜESSİS","anlam":"(A. Esâs’dan) Kurucu, tesis eden, kuran.","kategori":"dil","osmanli":"مؤسس"},{"kelime":"MÜEYYED","anlam":"1.Te’yîd edilmiş, kuvvetlendirilmiş, sağlam; doğrulanmış. 2.Yar-dım gören.","kategori":"dil","osmanli":"مؤيد"},{"kelime":"MÜEZZİN","anlam":"Ezân okuyan.","kategori":"ibadet","misal":"Müezzin, sesinin mikdârınca mağfirete nâil olur; kuru ve yaş her şey ona şâhidlik eder. (Hadîs-i şerîfEbû Dâvûd, Nesaî) Ezânın sahih olması için, müezzin, Müslüman ve akıllı olmalı, namaz vakitlerini bilmeli ve sözüne inanılan âdil bir kimse olmalıdır. Akıllı çocuğun, a’mânın, veled-i zinânın, vakitleri ve ezân okumasını bilen câhil köylünün müezzin olması, kerâhatsiz câizdir. Cünübün, kadının, fâsıkın, sarhoşun, kü…","osmanli":"مؤذن"},{"kelime":"MuFASSAL","anlam":"1.Tafsilli, taf-silâtlı, uzun uzadıya anlatılan. 2.Kur’ân-ı kerîmin sonunda Hucûrat sûresinden sonuna kadar olan kısa sûreler.","kategori":"akaid","misal":"(A. Fasl’dan)","osmanli":"مفصل"},{"kelime":"MuFÂVADA","anlam":"1.Müzâkere etme. 2.Birine tam salâhiyet verme. 3.Sermâyedeki hisseleri, kâr ve kullanma hakkı, ortaklar arasında eşit olan, ortakların birbirine kefil ve vekil olduğu, herbirinin sermâyesinden başka parasının bulunmadığı şirket. Şirket-i mufâvada, kefâleti dahi mütezammındır [ihtivâ eder]. Binâenaleyh müfâvizlerin [mufâvada şirketi ortaklarının] kefâlete ehliyetleri dahi şartdır. (Mecelle, m. 1334)","kategori":"miras","osmanli":"مفاوضه"},{"kelime":"MÜFESSİR","anlam":"1.Tefsir eden. 2.Kur’ân-ı kerîmi tefsir eden, Allahü teâlânın kelâmından, murâd edilen mânâyı anlayan âlim.","kategori":"dil","osmanli":"مفسر"},{"kelime":"MÜFLİS","anlam":"İflâs eden, borcu malından çok kimse.","kategori":"muamelat","misal":"Kim müflisin yanında malını aynen bulursa, herkesten önce o mala lâyıktır. (Hadîs-i şerîfBuhârî, Müslim, Ebû Dâvud, Tirmizî, Nesâî) İmâmeyne göre müflis alacaklıların talebi üzerine hâkim tarafından hacr altına alınır. Sonra, onun bilgisi ile, mallarını sattırarak, nafakası lâzım olanların nafakasını öder. Geri kalan ile borçlarını öder. Parası yetişmezse, ihtiyacından fazla eşyasını satar. Bu da yetişmezse, ihtiyâc…","osmanli":"مفلس"},{"kelime":"MÜFRED","anlam":"1.Ferd hâlinde, tek, yalnız. 2.Basit, mürekkep olmayan. 3.Tekil. 4.İki mısraı arasında kâfiye bulunmayan beyit.","kategori":"dil","misal":"Sübhane rabbike âyet-i kerîmesini, namazda, duâların hepsinde müfred olarak (rabbike di-yerek) okumak, yalnız kunût duâsında cem’ (rabbinâ şeklinde) okumak sünnettir. (Fetâvâ-i Hayriyye)","osmanli":"مفرد"},{"kelime":"MÜFRİD","anlam":"İfrad yapan mânâsına İfrad haccına; yani ihrâma girerken umreye de niyet etmeyip, yalnız hac yapmaya niyet eden kimse.","kategori":"ibadet","misal":"Mekke’de oturanlar yalnız müfrid hacı olur. (Mevkûfât)","osmanli":"مفرد"},{"kelime":"MÜFSİD","anlam":"1.Fesad çıkaran. 2.İfsâd eden, bozan; ef ‘âl-i mükellefînden olup, bir ibâdeti, ameli, akdi bozan şey. 3.Uyuşturucu.","kategori":"dil","misal":"Ölçüyü ve tartıyı adâletle yapın; insanlara eşyalarını eksik vermeyin; yeryüzünde müf-sidler olarak dolaşmayın. (Hûd sûresi: 85) Dünya kelâmı konuşmak, kendisi işitecek ka-dar gülmek, sakız çiğnemek, farzın birini özür-süz terk etmek, namazın müfsidlerindendir. (Miftâhü’l-Cenne) Bir satışta, akdin icab ettirmediği ve taraflardan birine faydası olan şart müfsiddir ve akdi de fâ-sid eder. Evini satarken, bir müddet içinde otur-mayı şart etmek, müfsid şarttır. (İbni Âbidîn) Esrar gibi müfsid maddelerin, ilaç için az mik-darda alınıp satılması câizdir. (İbni Âbidîn)","osmanli":"مفسد"},{"kelime":"MÜFTERÎ","anlam":"İftirâ atan.","kategori":"dil","osmanli":"مفترى"},{"kelime":"MÜFTÎ (Müftü)","anlam":"1.İftâ eden, fetvâ veren. 2.Müctehid, ictihad sahibi. 3.Şehir ve kasabalarda halkın dinî suallerine cevap vermek üzere hükûmet tarafından tayin edilen vazifeli.","kategori":"fikih","misal":"Fâsıkın, müftî olması câiz değildir. Bunun verdiği fetvâlara güvenilmez. Çünki fetvâ vermek, din işlerindendir. Din işlerinde fâsıkın sözü kabul edilmez. Dört mezhebte de böyledir. Böyle müftîlere bir şey sormak câiz değildir. Müftînin Müslüman ve akıllı olması da, söz birliği ile şarttır. (İbni Âbidîn)","osmanli":"مفتى"},{"kelime":"MuĞLAK","anlam":"1.Kapalı, kilitli. 2.Çapraşık, anlaşılmaz","kategori":"dil","osmanli":"مغلق"},{"kelime":"MuĞNÎ","anlam":"1.Müstağni kılan, zengin eden, doyuran. 2.Hikmeti îcâbı, her şeyin ih-tiyâcını giderici, tamamlayıcı ve lütfuyla do-yurucu mânâsına Allahü teâlânın Esmâ-i hüs-nâsından (el-Muğnî).","kategori":"akaid","osmanli":"مغنى"},{"kelime":"MuHABBET","anlam":"Sevgi, sevme. Benim muhabbetim bir kulun kalbine girerse, azîz ve celîl olan Allahü teâlâ, onun cesedini ateşe haram kılar.","kategori":"akaid","misal":"Sünnete uygun nikâhdan sonra, erkek tarafı avret tarafına güzel ve kıymetli şeyler göndere, muhabbete sebebdir. (Miftâhü’l-Cenne) Muhabbete müdâhene (ikiyüzlülük) sığmaz. (Mektûbât-ı İmâm-ı Rabbânî) Muhabbetten Muhammed oldu hâsıl, Muhammedsiz muhabbetten ne hâsıl? (Bezmiâlem Vâlide Sultan) Muhabbet edene muhabbet edilir. Seven sevilir, unutmayan unutulmaz. (Ali Hâfız Efendi)","osmanli":"محبت"},{"kelime":"MuHÂBERE","anlam":"1.Haberleşme. 2.Üçte bir, dörtte bir gibi bir nisbet karşılığında ya-pılan ziraat şirketi; Şâfiî mezhebinde tohu-mun emek sahibinden olduğu ziraat şirketi.","kategori":"muamelat","osmanli":"مخابره"},{"kelime":"MuHÂCİRÎN","anlam":"Mekke’den Medî-ne’ye hicret eden müslümanlar.","kategori":"dil","osmanli":"مهاجرين"},{"kelime":"MuHADDİS","anlam":"Hadîs âlimi. Çok sayıda hadîs-i şerîfi senedi ve metniyle ezberleyen, râvilerin cerh ve ta’dîl (güvenilir olup olmadıkları) bakımından hâllerini bilen, bu ilimde ihtisas kazanmış âlim.","kategori":"hadis","misal":"Çokluk hâli muhaddisîn gelir.","osmanli":"محدث"},{"kelime":"MuHÂFAZA","anlam":"(A. Hıfz’dan) Hıfzetme, saklama, koruma, kayırma.","kategori":"dil","osmanli":"محافظه"},{"kelime":"MuHÂFIZ","anlam":"(A. Hıfz’dan) Muhafâza eden, değiştirmeyen saklayan, koruyan; bekçi.","kategori":"dil","osmanli":"محافظ"},{"kelime":"MuHÂKEME","anlam":"1.Bir hükme varmak üzere bir işi zihinde tetkik etme, akla vurma. 2.Bir ihtilâfı çözmek üzere mahkemede tarafları dinleyip, delilleri değerlendirmek suretiyle yapılan muamele, yargılama.","kategori":"fikih","osmanli":"محاكمه"},{"kelime":"MuHAKKAK","anlam":"1.Tahkik olunmuş, hakikati, gerçekliği, doğruluğu belli olmuş; doğru. 2.Her hâlde, ne olursa ol-sun, mutlaka.","kategori":"dil","misal":"(A. Hakk’dan) Şartlarına uygun yapılan tövbe, muhakkak ka-bul olur. (Kimyâ-i Se’âdet)","osmanli":"محقق"},{"kelime":"MuHÂL","anlam":"İmkânsız, vuku’u mümkün olmayan; boş söz.","kategori":"dil","misal":"Cem’-i zıddeyn muhâldir. İki zıd şeyin muhab-beti bir kalbde, bir arada bulunamaz. İki zıd-dan birini sevmek, diğerine düşmanlığı îcâb et-tirir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"محال"},{"kelime":"MuHÂLEFET","anlam":"(A. Hilâf’dan) Karşı gelme, itâ‘at etmeme; uymama, zıt gitme.","kategori":"dil","misal":"Temiz mest ve na’lın ile namaz kılmak, çıplak ayakla kılmaktan efdaldir. Yahûdîlere muhâ-lefet olur. (İbni Âbidîn)","osmanli":"مخالفت"},{"kelime":"MuHÂLİF","anlam":"Muhâlefet eden, aykırılık gösteren, uymayan, uygun olmayan; zıt düşü-nen, karşı çıkan, itirâz eden.","kategori":"dil","misal":"Mu‘âmelâttaki hükümler için, bir beldenin, nassa (âyet-i kerîme veya hadîs-i şerîfe) muhâlif olma-yan âdetleri de delil olur. (Dürerü’l-Hükkâm) Cihanda Cennet-i me’vâ muvâfık yâr-ı hem-demdir, Muhâlif şahsına âdeme karîn olmak cehennemdir.","osmanli":"مخالف"},{"kelime":"MuHAMMED (aleyhisselâm)","anlam":"Allahü teâlânın insanlara gönderdiği son peygamber.","kategori":"dil","misal":"Bid‘atler yayıldığı ve bu ümmetin sonra gelenleri evvelkilere la’net okuduğu zaman, ilmi olan ilmini yaysın. Zîrâ o gün ilmi gizliyen Allahın Muhammed aleyhisselâma indirdiğini (Kur’ân-ı kerimi) gizleyen gibidir. (Hadis-i şerifİbni Asâkir) Her Peygamber, kendi zemânında, kendi mekânında, kendi kavminin hepsinden, her bakımdan üstündür. Muhammed “aleyhisselâm” ise, her zemânda, her memleketde, ya’nî dünyâ yaratıldığı…","osmanli":"محمد"},{"kelime":"MuHAMMEDÎ","anlam":"1.Muhammed aleyhisselâma ait, onunla alâkalı. 2.Muhammed aleyhisselâmın dinine mensub.","kategori":"dil","misal":"Müslüman.","osmanli":"محمدى"},{"kelime":"MuHANNES","anlam":"Kadın gibi davranan erkek; korkak.","kategori":"osmanli","misal":"Muhannesi evinize sokmayınız! (Hadîs-i şerîfBuhârî) Bir erkeğe; “Ey muhannes” diyene yirmi sopa vurun. (Hadîs-i şerîfTirmizî)","osmanli":"مخنث"},{"kelime":"MuHÂREBE","anlam":"Harbetme, savaşma; harb, savaş, savaşta yapılan çarpış-malardan her biri.","kategori":"dil","osmanli":"محاربه"},{"kelime":"MuHARREM","anlam":"1.Haram kılınmış. 3.Kamerî senenin ilk ayı ve eşhuru’l-hurûm, yani dört haram aydan biri.","kategori":"fikih","misal":"Hürmete lâyık. Daha evvel bu aya mu’temir ve mûcib denirdi. Câhiliye devri Arapları bu aylarda savaşmayı kendilerine yasaklamışlardı. Sonradan Kur’ân-ı kerîm bunu kaldırmıştır. Muharrem, haram kökünden, hürmete lâyık ve yasak gibi mânâlara gelir. Haram, harem, ihram, hürmet, muhterem, hurma, mahrum hep aynı köktendir. Bu ayda silahlar elden bıra…","osmanli":"محرم"},{"kelime":"MuHARREMÂT","anlam":"Yapılması dinen yasaklananlar, evlenilmesi haram olanlar mânâsına muharrem’in çokluk hâli.","kategori":"fikih","misal":"Muharremâttan olan kimselerin yedisi nesepten, yedisi sütten, dördü de sıhriyyet ile olan akrabâlarıdır. (Mevkûfât)","osmanli":"محرمات"},{"kelime":"MuHÂSARA","anlam":"(A. Hasr’dan) Kuşatma, etrafını çevirme.","kategori":"dil","misal":"Kumandan kâfir şehrini muhâsara edince, önce İslâm’a da’vet olunur. (İbn-i Âbidîn)","osmanli":"محاصره"},{"kelime":"MuHÂSEBE","anlam":"1.Hesâb-laşma, hesâbını tutma, hesâb işi; hesâb dâi-resi. 2.Kendini hesâba çekme.","kategori":"dil","misal":"(A. Hisâb’dan) Çokluk hâli muhâsebât gelir. Meşâyıh-ı kirâmdan birçoğu, muhâsebe yo-lunu seçmişlerdir. Her gece, yatacağı zaman, o gün yapmış olduğu işlerini, sözlerini, hareket-lerini, hareketsizliklerini, düşüncelerini, her bi-rinin niçin olduğunu anlarlar. Kusurlarını ve günahlarını temizlemek için, tövbe ve istiğfâr ederler. Allahü teâlâya boyun bükerler, yalva-rırlar. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"محاسبه"},{"kelime":"MuHÂSİB","anlam":"Hesab yapan; muha-sebe memuru.","kategori":"dil","osmanli":"محاسب"},{"kelime":"MuHAŞŞÎ","anlam":"1.İhâta olunmuş, etrâfı çev- rilmiş, kuşatılmış. 2.Bir şeyin içinde bulunan.","kategori":"dil","misal":"Hâşiye (bir kitaba dip-not mâhiyetinde ilâve) yazan. (Bkz. Hâşiye) MuHÂT: محاط (A)","osmanli":"محشى"},{"kelime":"MuHÂT","anlam":"Sümük; sümüksü yapış-kan nesne.","kategori":"dil","osmanli":"مخاط"},{"kelime":"MuHÂTAB","anlam":"1.Hitâb olu-nan, kendisine söz söylenilen. 2.Gramerde ikinci şahıs. 3.Osmanlılar zamanında Rama-zan ayında Saray’da yapılan ve huzur dersleri denilen dinî müzâkerelerde mukarririn sua-line cevap vermek üzere şeyhülislâm tarafın-dan seçilmiş müderris.","kategori":"osmanli","osmanli":"مخاطب"},{"kelime":"MuHÂYEE","anlam":"Nöbetleşme. Bir malın, mülkiyeti bâki kalmak üzere, menfaatinin müşterek mâlikler arasında taksimi.","kategori":"muamelat","misal":"Meselâ bir eve mâlik olan iki kişi, bir sene biri, öteki sene diğeri oturmak üzere muhâyee edebilir. Mislî eşyada muhâyee olmaz. Ev, tarla, zamanla veya mekân ile muhâyee olunur. Mekânda ve öncelikle uyuşulmazsa, kur’â çekilir. Ağaç, yün, süt gibi ayn olan şeylerde muhâyee olmaz. Eğer, bunları muhâyee edip, hisselerinde hâsıl olan farkı helâllaşsalar, câiz olmaz. (İbni Âbidîn)","osmanli":"مهايئه"},{"kelime":"MuHAYYER","anlam":"(A. Hayr’dan) Seçmeli, be-ğenmeye bağlı, isteğe bağlı hâl.","kategori":"dil","osmanli":"مخير"},{"kelime":"MuHAYYERLİK","anlam":"Hıyâr hakkı sâ-hibi. İki tarafın her birinin akidden vazgeçe-bilme hakkı.","kategori":"dil","misal":"Müşteri, a’zâmî üç gün için muhayyer olabilir. Bir kimse satın aldığı bir malda kusur bulsa, tam fiyatı ile almakta veya geri vermekte mu-hayyerdir. Satan râzı olursa fiyatını düşürerek satın alabilir. Malı görmeden almışsa; söyle-diği vasıf yoksa; aldatılmışsa; iki veya üç mal-dan birini seçmek mevzubahis ise muhayyer-lik vardır. (Mecmâ‘ül-Enhür)","osmanli":"مخيرلك"},{"kelime":"MuHAYYİRE (Dâlle)","anlam":"1.Hayrette kalmış kadın. 2.Âdet zamanını unutan kadın.","kategori":"osmanli","misal":"(Bkz. Dâlle)","osmanli":"محيره"},{"kelime":"MuHBİR","anlam":"Haber veren, ha-berci; ihbâr eden.","kategori":"dil","osmanli":"مخبر"},{"kelime":"MuHBİR-İ SÂDIK","anlam":"Hep doğru söyleyici, doğru haber verici mânâsına Resûlullah aleyhisselâmın lakabı.","kategori":"dil","misal":"Muhbir-i sâdık ne bildirdi ise ve Ehl-i sünnet âlimleri rahmetullahi teâlâ aleyhim ec-mâ’în kitablarında ne yazdı ise onları yapmaya canlabaşla çalışmalıdır. (Mektûbât-ı İmâm-ı Rabbânî) Muhbir-i sâdık Muhammed aleyhisselâm; “Helekel müsevvifûn.” buyurdu. Yani; “Sonra yaparım diyenler helâk oldular.” (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"صادق مخبر"},{"kelime":"MuHDÎ","anlam":"1.Hediye eden. 2.Hidâyete götüren mânâsına Resûlullah aleyhisselâmın lakabı (elMuhdî).","kategori":"dil","osmanli":"مهدى"},{"kelime":"MuHDİS","anlam":"1.İhdâs eden, ortaya çıka-ran. 2.Hades vâki olan, namaz abdesti olma-yan kimse.","kategori":"ibadet","misal":"Muhdisin Kur’ân-ı kerîmi tutması haramdır. Ezberden okuması câizdir, olur. (İbni Âbidîn) Cünüb ve hayızlının câmiye girmesi harâmdır. Muhdisin girmesi mekrûhtur. (Dürer)","osmanli":"محدث"},{"kelime":"MÜHENDİS","anlam":"Hendese (geometri) bilen.","kategori":"dil","osmanli":"مهندس"},{"kelime":"MÜHEYMİN","anlam":"1.Gö-zetici, koruyucu. 2.Her mahlûkun ömrünü, amelini, rızkını, ecelini, nefeslerini, sözlerini bilen, gören, onların bütün hâllerinden ha-berdâr olan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Müheymin). Her kim gusül abdesti aldıktan veya namaz-dan sonra el-Müheymin ism-i şerîfini söylerse, kalbi aydınlanır, himmet ve şerefe kavuşur. Hâ-fızası kuvvetlenir, unutkanlığı gider. (El-İstigâ-setü’l-Kübrâ)","kategori":"akaid","osmanli":"مهيمن"},{"kelime":"MÜHİM","anlam":"Ehemmiyetli, önemli; düşündüren, düşündürücü; lüzumlu. MÜHLET: مهلت (A) Bir işin yapılması için ve-","kategori":"dil","misal":"rilen zaman. Mürted olana nasihat etmek, şübhesini gider-mek müstehabdır. Mühlet isterse, üç gün habs olunur. (İbni Âbidîn)","osmanli":"مهم"},{"kelime":"MuHÎT","anlam":"1.İhâta eden, kuşa-tan. 2.Himâye eden, görüp gözeten. 3.İlmi ve kudreti her şeyi ihâta eden mânâsına Allahü teâlânın sıfatlarından (el-Muhît).","kategori":"akaid","misal":"(A. Havt’dan) Göklerde ve yerde ne varsa hepsi Allah’ın-dır. Allahü teâlânın ilmi ve kudreti her şeyi muhîttir. (Nisâ sûresi: 126)","osmanli":"محيط"},{"kelime":"MuHKEM","anlam":"1.Tahkîm edil-miş, sağlam kılınmış, sağlamlaştırılmış. 2.Bakı-lıp neticelendirilmiş ve hükmü değiştirilemez hâle gelmiş bir dâvâ. 3.İçinde hüküm bulu-nan, mânâsı açık olan âyet.","kategori":"dil","misal":"(Bkz. Muhkemât)","osmanli":"محكم"},{"kelime":"MuHKEMÂT","anlam":"Kur’ân-ı kerîmde mânâsı meydanda olan, anlaşılabilen âyet-i kerîmeler.","kategori":"dil","misal":"Muhkemin çokluk hâli. (Bkz. Âyet) (Ey Habîbim!) Sana Kur’ân’ı, Allahü teâlâ inzâl etti. Onun bir kısmı muhkemât olup, bunlar Kur’ân’ın esâsıdır. Bir kısmı da müteşâbihtir. Fakat kalblerinde eğrilik bulunanlar (muhkem âyetleri bırakırlar da) fitne aramak ve isteklerine göre te’vîl etmek için müteşâbih olan âyetlerine tâbi olurlar. Hâlbuki onun te’vîlini Allahü teâlâdan başka kimse bilmez. İlimde rüsûh sâhibi âlimler;…","osmanli":"محكمات"},{"kelime":"MuHLAS","anlam":"Uğraşmadan, zorlanmadan kazanılan ve devamlı olan ihlâsın sâhibi, her şeyi Allahü teâlânın rızâsıyla yapan.","kategori":"akaid","misal":"İblis; “Senin mutlak kudretine and olsun ki, onlardan (Allahü teâlânın kullarından) muhlas olanlar hâriç, hepsini mutlaka azdıracağım” dedi. (Sâd sûresi: 82, 83) Uğraşmadan, zorlamadan, külfetsiz ele giren ihlâs, devamlıdır ve hakkulyakîn mertebesinde ele geçer. Devamlı ihlâs sahiplerine muhlas denir. Zahmet çekerek elde edilen, devamsız ihlâsın sâhiplerine muhlis denir. Muhlas olana, ibâdet yapmak, tatlı ve kolay o…","osmanli":"مخلص"},{"kelime":"MuHLİS","anlam":"İhlâs sahibi. Amelini Allah rızâsı için yapan kimse.","kategori":"akaid","misal":"Şeriate tam uyabilmek ise, ilim,amel ve ihlâs ile olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مخلص"},{"kelime":"MuHSAN","anlam":"1.Başından zifafla neticelenmiş sahih bir nikâh geçmiş, âkıl, bâliğ, hür, Müslüman erkek. 2.İffetli erkek.","kategori":"fikih","misal":"Zinâ haddi (cezâsı) iki çeşittir. Birisi muhsan ve muhsane içindir. Haddi recm, yani bir meydanda ölünceye kadar taşlanmaktır. İkincisi muhsan ve muhsane olmayan içindir. Haddi, yüz sopadır. (Dürer) Muhsan veya muhsaneye zinâ iftirası atmanın cezası seksen sopadır. (Dürrü’l-Muhtâr)","osmanli":"محصن"},{"kelime":"MuHSİN","anlam":"İhsân eden.","kategori":"dil","misal":"(O takvâ sahipleri ki) bollukta ve darlıkta harcayıp yedirenler, öfkelerini yenenler, in-sanların kusurlarını bağışlayanlardır. Al-lah muhsinleri sever. (Âl-i İmrân sûresi: 134)","osmanli":"محسن"},{"kelime":"MuHTÂC","anlam":"İhtiyâc sahibi.","kategori":"dil","osmanli":"محتاج"},{"kelime":"MuHTÂR","anlam":"1.İhtiyâr sahibi, söz ve fiillerinde serbest olup, istediği gibi davranan ve dilediğini yapan. 2.Resûlullah aleyhisselâmın lakabı (elMuhtâr).","kategori":"dil","misal":"Kul, istekli hareketlerini yapıp yapmamakta muhtârdır. Bir işi önce ihtiyâr eder, diler; Allahü teâlâ o işi yaratır. (İtikâdnâme) İhtiyâr edilen, seçilen. Köy veya mahallenin resmî işlerini yürüten. Seçilmiş. bir şer’î meselede mezhebteki muhtelif kavillerden, sonra gelen tercih ehli âlimler tarafından deliline veya zaruret ya da örfe göre seçilerek fetvâya esas alınan…","osmanli":"مختار"},{"kelime":"MuHTÂRİYYE","anlam":"Kurucusu Muhtâr es-Sakafî’nin adıyla anılan Şia’nın kollarından biri. Keysâniyye. Bedâiyye.","kategori":"dil","osmanli":"مختاريه"},{"kelime":"MuHTASAR","anlam":"1.İhtisâr edilmiş, kı-saltılmış. 2.Uzun bir kitabın ihtisâr edilmesi suretiyle yazılan kitab.","kategori":"dil","osmanli":"مختصر"},{"kelime":"MuHTEKİR","anlam":"İhtikâr eden, insan ve hayvan yiyecek maddelerini piyasadan top-layıp pahalanınca satan kimse. Karaborsacı. (Bkz. İhtikâr)","kategori":"dil","misal":"Muhtekir ne fenâ bir kuldur. Allahü teâlâ fi-yatları ucuzlatırsa adamın keyfi kaçar, yüksel-tirse o zaman ferahlar. (Hadîs-i şerîf-Taberânî) Muhtekir mel’ûndur. (Hadîs-i şerîf-İbn-i Mâce)","osmanli":"مختكر"},{"kelime":"MuHTELİF","anlam":"2.Türlü, çe-şitli; çeşit çeşit.","kategori":"dil","misal":"l.İhtilâf eden, biribirine uymayan, zıt.","osmanli":"مختلف"},{"kelime":"MuHTEREM","anlam":"İhtiram olunmuş, hürmete değer; dokunulmaz.","kategori":"dil","osmanli":"محترم"},{"kelime":"MuHTEŞEM","anlam":"İhtişamlı, tantanalı, debdebeli, gösterişli.","kategori":"dil","osmanli":"محتشم"},{"kelime":"MuHYÎ","anlam":"1.İhyâ eden, hayat veren, dirilten. 2.Varlıklara maddî ve manevî hayat veren, canlandıran, dirilten mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elMuhyî).","kategori":"akaid","misal":"ElMuhyî ism-i şerîfini söyleyen kimsenin korktuğu kimselerle arasında ülfet meydana gelir. (Elİstigâsetü’l-Kübrâ)","osmanli":"محيى"},{"kelime":"MÜJDE","anlam":"Sevinçli haber; sevinçli ha-ber getirene verilen bahşiş, muştu, muştuluk.","kategori":"dil","osmanli":"مﮋده"},{"kelime":"MuKÂBİL","anlam":"1.Mukâbele eden, karşı karşıya gelen, karşısında bulunan. 2.Bir şeye karşı, bir şeye karşılık yapılan.","kategori":"ibadet","osmanli":"مقابل"},{"kelime":"MuKADDEM","anlam":"1.Takdim edi-len, küçükten büyüğe sunulan. 2.Kıdemli olan, önde bulunan. 3.Kıymetli, üstün. 4.Daha önce.","kategori":"tasavvuf","misal":"Resûlullah’ın “sallallahü aleyhi ve sellem” Bi’set-ten mukaddem (Risâleti bildirilmeden evvel) zikr-i kalbî ile meşgul olduğu mervi’dir. (Mek-tûbât-ı Ma’sûmiyye)","osmanli":"مقدم"},{"kelime":"MuKADDER","anlam":"1.Takdir edilmiş; Allahü teâlânın ilm-i ezelîsinde takdir buyurulmuş, kaderde olan. 2.Hacim, tartı, sayı veya uzunluk ölçüsüyle ölçülebilen şey.","kategori":"akaid","misal":"(Bkz. Kazâ ve Kader) Dünya için çok kaygı çekmeyin, mukadder olan olur. Takdir olunan rızkın sana gelir. (Hadîs-i şerîf-Beyhekî) İnsan bir şeyi niçin arzu eder durur? Çok vâki’ olur ki, temennî eylediği emr (iş), kendi hakkında mukadder değildir. (Mektûbât-ı Ma’sûmiyye)","osmanli":"مقدر"},{"kelime":"MuKADDES","anlam":"Takdis edilmiş, dinen mübârek, kudsî; ayıptan, çirkin ve kötü şey-lerden uzak; temiz.","kategori":"dil","misal":"Ümmetim, ümmet-i merhûmedir. Mukad-destir, mübârektir, kıyâmette ona azap yok-tur. Azapları ancak dünyada aralarındaki fit-nelerledir. (Hadîs-i şerîf-İbni Asâkir)","osmanli":"مقدس"},{"kelime":"Mukaddes Emânetler","anlam":"Hazret-i Peygamber ve önceki peygamberler ile din büyüklerine, mukaddes yerlere ait eşyâlar. Emânât-ı Mukaddese.","kategori":"akaid","osmanli":"امانتلر مقدس"},{"kelime":"Mukaddes Kitablar","anlam":"Allahü teâlânın Cebrâîl aleyhisselâm vâsıtasıyla peygamberlerine gönderdiği kitaplar.","kategori":"akaid","misal":"Allahü teâlâ tarafından nesh edilmiş ve kullar tarafından değiştirilmiş mukaddes kitablara hakâret etmek, alay etmek câiz olmadığı gibi, bunları okumak ve dinlemek de câiz değildir. (Berîka)","osmanli":"كتابلر مقدس"},{"kelime":"MuKADDİM","anlam":"1.Takdim eden, önce-lik veren. 2.Mahlûklardan bazısını bazısın-dan önce var ve yok eden; dilediğini kendine yakınlaştıran, dilediğini uzaklaştıran, kendi-sine yakın kıldığı meleklerini, peygamberle-rini aleyhimüsselâm ve âlimlerini üstün kılan mânâsına Allahü teâlânın Esmâ-i hüsnâsın-dan (el-Mukaddim). Muhârebe ânında bir kimse el-Mukaddim ism-i şerîfini söylediğinde kuvvet ve zafer bu-lur. (El-İstigâsetü’l-Kübrâ)","kategori":"akaid","osmanli":"مقدم"},{"kelime":"MÜKÂFÂT","anlam":"İyi karşılık, ödül.","kategori":"dil","misal":"Oruç yalnız benim içindir, onun mükâfâtını ben veririm. (Hadîs-i Kudsî-Şir’atü’l-İslâm) Cömertlikten doğan güzel huylar vardır. Bun-lardan biri de mükâfâttır. Yani iyiliğe karşı iyi-lik etmektir. (Ahlâk-ı Alâî)","osmanli":"مكافات"},{"kelime":"MuKALLİD","anlam":"1.Taklit eden, başkala-rına benzemeye çalışan. 2.(Kılıç vs.) kuşan-mış. 3.İtikadda anne-babasından gördüğü, duyduğu gibi hareket eden. 4.Müctehid olma-yan, amellerini bir müctehide uyarak yapan. 1.Kanunlaştırılmış. 2.Muayyen.","kategori":"fikih","misal":"Mukallidin îmânı sahîhtir, doğrudur. Bunlar, farzı, vâcibi, sünneti, müstehâbı bilmez. Ana-sından, babasından gördüğü gibi inanır ve ibâdet eder. Bu gibilerin îmânından korkulur. (Miftâhü’l-Cenne) Mukallidlerin, delilini bilmese de müctehidin sö-züne göre hareket etmesi vâcibdir. (İbni Âbidîn) MuKANNEN: مقنن (A)","osmanli":"مقلد"},{"kelime":"MuKARREB","anlam":"1.Yaklaştırılmış. 2.Cennet’te dereceleri en yüksek olan. 3.Tasavvufta, nefslerinin sevgisinden kurtulmuş, kalbinde Allahü teâlâdan başka hiçbir şeyin sevgisi kalmayan, yalnız Allahü teâlâyı isteyen. Âhireti istemek, ebrâr için sevabtır. Mukarreb-ler âhireti istemeği de günah bilir. Zât-ı ilâhî-den başka bir şey istemez. Bunun için fenâ hâ-sıl olmak lâzımdır. Zât-ı ilâhînin sevgisi insanı kaplamalıdır. Bu sevgiye kavuşanlara, ni’met-ler ve musîbetler, müsâvî olur. Ebrârın iyilik olarak yaptıkları, mukarrebler yanında günah olur. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","misal":"izzet, şeref, itibar ve nimet itibarıyla yakın olanlar, melekler, peygamberler ve sâlihler. Hayırda önde olanlar; Allahü teâlâya yaklaş-makta da ileride olanlardır. Bunların hepsi mukarreblerdir. (Vâkıa sûresi: 10-11) Mukarrebler ve muvahhidler verâ sâhibi olup, Allahü teâlâ için olmayan her şeyden, yemek-ten, içmekten, yatmaktan, söylemekten sakı-nırlar. (Kimyâ-i Seâdet)","osmanli":"مقرب"},{"kelime":"MuKÂTİL","anlam":"Mukâtele eden, muha-rib, savaşçı.","kategori":"dil","osmanli":"مقاتل"},{"kelime":"MuKÂVELE","anlam":"Kavilleşme. Söz-leşme, yazılı sözleşme; akid.","kategori":"dil","misal":"Kirâcı, kirâ ile tuttuğu yerin ücretini ödemezse, mal sahibi mukâveleyi feshedebilir. (Fetâvâ-i Hindiyye)","osmanli":"مقاوله"},{"kelime":"MuKÂVEMET","anlam":"(A. Kıyâm) Karşı durma, dayanma, karşı koyma, direnme, direniş.","kategori":"dil","osmanli":"مقاومت"},{"kelime":"MuKAVVÂ","anlam":"1.Kavîleştiril-miş, sağlamlaştırılmış. 2.Kalın ve sert karton.","kategori":"dil","misal":"(A. Kuvvet’ten)","osmanli":"مقوى"},{"kelime":"MuKÂYESE","anlam":"1.Kıyas etme, ölçme, ölçü. 2.Karşılaştırma.","kategori":"fikih","osmanli":"مقايسه"},{"kelime":"MuKAYYED","anlam":"Kayıtlanmış, takyid edilmiş, bağlanmış, mutlak olmayan, bir sıfat, hâl, gâye veya şarta bağlı olan.","kategori":"akaid","misal":"Nisâ sûresinin doksan ikinci âyet-i kerîmesinde bir mü’mini hatâ ile öldürenin, keffâret olarak mü’min bir köle âzâd etmesi, buna gücü yetmezse, iki ay aralıksız oruç tutması lâzım geldiği bildirilmiştir. Âyet-i kerîmede köle kelimesi mukayyeddir. Çünki, mü’min sıfatıyla kayıtlanmıştır. (Mebsût) Mâide sûresinin seksen dokuzuncu âyet-i kerîmesinde yemin keffâreti için bir köle âzâd etmek, yahud on fakiri doyurmak, ya…","osmanli":"مقيد"},{"kelime":"Mukayyed Su","anlam":"Cinsi ve sıfatı birlikte söylenen ve herhangi bir şeyle kayıtlanmış sular.","kategori":"akaid","misal":"Mukayyed sular iki türlü olup, biri kavun, karpuz suları gibidir. Bunlar hilkaten (yaratılış îcâbı) böyledirler. Diğeri ise; mutlak su iken, daha sonra bir şeyle karışma netîcesi mukayyed olmuşlardır. Et suyu, sabun suyu, safranlı sulardır. Mukayyed su ile abdest ve gusül abdesti alınmaz. (İbni Âbidîn) Suyun ismi değişmediği zaman, su koyu olursa, akıcılığı kalmazsa, mukayyed su olur. Akıcılığı kalırsa, üç hususiyet…","osmanli":"صو مقيد"},{"kelime":"MÜKELLEF","anlam":"1.Mükellefiyet (külfet) sâhibi. 2.Dînin emir ve yasakları ile muhatab olacak yaş, akıl gibi fizikî ve rûhî vasıfları ta- şıyan kimse.","kategori":"fikih","misal":"(Bkz. Ef ’âl-i Mükellefîn) Mükellef olan erkek ve kadının birinci vazîfesi; Ehl-i sünnet âlimlerinin yazdıkları akâid bilgilerini öğrenmek ve bunlara uygun olarak inanmaktır. (Mektûbât-ı İmâm-ı Rabbânî) Hanefî mezhebinin âlimleri dediler ki: Mükellef olan her Müslümanın, her gün beş vakit namaz kılması farzdır. Farz olduğu, Kur’ân-ı kerîmde ve hadîs-i ş…","osmanli":"مكلف"},{"kelime":"MÜKEMMEL","anlam":"(A. Kemâl’den) Kemâle er-dirilmiş, kemâl bulmuş, tam, olgun, kusursuz, eksiksiz; güzel, hoş.","kategori":"dil","osmanli":"مكمل"},{"kelime":"MÜKEMMİL","anlam":"Kemâle getiren, olgun-laştıran, yetiştiren.","kategori":"dil","misal":"Kâmil ve mükemmil bir rehbere tâbi kimse, Al-lahü teâlânın rızâsına kavuşur. (Mekâtib-i Şerife) MÜKERREM: مكرم (A) Kerem sahibi, muhte- rem, azîz.","osmanli":"مكمل"},{"kelime":"MuKÎM","anlam":"1.İkâmet eden, oturan. 2.Seferî olmayan. 3.Doğduğu veya evlendiği veya hep kalmak niyeti ile yerleştiği yerde oturan veya en az üç günlük uzaklıktaki bir yerde giriş çıkış günlerinden başka Hanefî’de on beş (üç mezhebte dört) gün veya daha fazla kalmaya niyet… Seferî olan kimsenin dört rek’at olan farz namazları iki rek’at kılması Hanefî’de vâcib, Mâlikî’de sünnet-i müekkede, Şâfiî’de efdal (iyi) dir. Seferî olanın mukîm olan imâma uyması, Hanefî’de, vaktin farzını edâ ederken câiz, Şâfiî’de hem edâ hem kazâ ederken câiz, Mâlikî’de ikisinde de mekrûhtur. (elFıkhu ale’l-Mezâhi-bi’l-Erbaa)","kategori":"ibadet","osmanli":"مقيم"},{"kelime":"MuKÎT","anlam":"1.Rızık veren, geçindiren. 2.Amelleri zâyi etmeyip koruyan, yarattıkla-rına rızk veren mânâsına Allahü teâlânın Es-mâ-i hüsnâsından (el-Mukît).","kategori":"dil","osmanli":"مقيط"},{"kelime":"MÜKRÎ","anlam":"Kirâya veren, kirâlayan.","kategori":"muamelat","osmanli":"مكرى"},{"kelime":"MuKTEDİR","anlam":"Kudret sahibi, her şeye gücü yeten. Allahü teâlânın Esmâ-i hüsnâsın-dan (el-Muktedir).","kategori":"akaid","misal":"Allahü teâlâ, her şeye muktedirdir. (Kehf sûresi: 45)","osmanli":"مقتدر"},{"kelime":"MÜLÂKAT","anlam":"(A. Lika’dan) Kavuşma; bu-luşma; birleşme; görüşme.","kategori":"dil","osmanli":"ملاقات"},{"kelime":"MÜLÂKÎ","anlam":"(A. Lika’dan) Buluşan, kavu-şan; görüşen.","kategori":"dil","osmanli":"ملاقى"},{"kelime":"MÜLÂYİM","anlam":"(A. Le’m’den) Uygun, muvâ-fık; yumuşak huylu.","kategori":"dil","misal":"Eğer diyerek şarta bağlanan hibe, bâtıl olur. Üzere diyerek şarta bağlanan hibe sahîh olup, şartı mülâyim ise sahîh, muhâlif ise bâtıl olur. (Fetâvâ-yı Feyziyye)","osmanli":"ملايم"},{"kelime":"MÜLCÎ","anlam":"(A. İlcâ’dan) İlcâ eden, zorlayan, zorla yaptıran.","kategori":"dil","osmanli":"ملجى"},{"kelime":"Mülcî İkrâh","anlam":"Zorlayıcı ikrâh. Ölümle veya bir uzvunu yok etmek, şiddetli vurma ve hapsetme gibi tehditlerle bir kim-seyi istemediği şeyi yapmaya zorlama. İkrâh-ı Mülcî. (Bkz. İkrâh)","kategori":"dil","misal":"Mülcî ikrâh, tam, ağır olup, insanın rızâsını ve ihtiyârını yok eder. Zorlanan şeyin yapılması zâruri olur. Mülcî ikrâh ile olan akidler sahîh olmaz. (Dürerü’l-Hükkâm)","osmanli":"اكراه ملجى"},{"kelime":"MÜLEFFIK","anlam":"1.Telfîk yapan, birbirine ekleyen. 2.Mezheblerin kolaylıklarını araştırıp, toplayan ve şartlarına uymadan taklit eden kimse.","kategori":"dil","misal":"(Bkz. Telfîk) Müleffıkın ibâdetinin sahîh olmayacağı sözbirliği ile bildirilmiştir. Bir ibâdetin bir şartı bir mez-hebe, başka şartı da başka mezhebe göre sahîh olursa, bu ibâdet sahîh olmaz. Abdest alırken, başının bir parçasını mesh eden kimse, ıslak köpeğe değdikten sonra namaz kılsa, sahîh ol-maz. Çünki, abdesti başın tamamının meshe-dilmesini arayan Mâlikî’ye göre sahîh değildir. Köpeğe dokununca, Şâfiî’ye göre üstü necis ol-muştur. (İbni Âbidîn)","osmanli":"ملفق"},{"kelime":"MÜLEYYİN","anlam":"(A. Lînet’den) Telyîn eden, lî-net veren, yumuşatan, yumuşatıcı.","kategori":"dil","osmanli":"ملين"},{"kelime":"MÜLHİD","anlam":"İlhâda düşen, mânâları açık ve kat’î olan âyet-i kerîmelere ve hadîs-i şerîflere, te’vîl etse dahi, yanlış mânâ vererek ve mânâları şüpheli olanlara te’vîl etmeden yanlış mânâ vererek dinden çıkan.","kategori":"hadis","misal":"Hazret-i Alî’yi üç halîfeden üstün tutana Şî’î denir. Eshâb-ı kirâma söğene mülhid denir. Şî’î, Ehl-i kıbledir. Mülhid ise, kâfir olmaktadır. (İbni Âbidîn) Bâtınla meşgul olup, zâhiri terk eden (zâhirin, bedenin yapacağı emrleri terk eden) mülhiddir. Ve ahvâli istidrâcdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ملحد"},{"kelime":"MÜLK","anlam":"1.İnsanlar üzerindeki hâkimiyet, meliklik, saltanat.","kategori":"muamelat","misal":"Bütün mülk elinde bulunan Allahü teâlânın şânı ne yücedir! O, her şeye hakkiyle kâdirdir (gücü yetendir). (Mülk sûresi: 1) Bugün mülk kimindir? Vâhid ve kahhâr olan Cenâb-ı Allah’ındır. (Mü’min sûresi: 16) De ki: “Mülkün gerçek sahibi olan Allah’ım! Sen mülkü dilediğine verirsin ve mülkü dilediğinden geri alırsın. Dilediğini yüceltir, dilediğini de alçaltırsın. Her türlü iyilik senin elindedir. Gerçekten sen her şey…","osmanli":"ملك"},{"kelime":"Mülk-i Habîs","anlam":"Helâl yolla kazanılan mal ile, haram yolla kazanılan malın karışmasından meydana gelen ve birbirinden kolayca ayrılamayan mal.","kategori":"akaid","misal":"Çeşidli kimselerden gasp, hırsızlık, fâiz, kumar, rüşvet, zulüm, hıyânet gibi sebeblerle aldığı haram malları birbirleri ile veya kendi helâl malı ile yahud kendinde emânet bulunan mallar ile karıştırırsa ve bunları birbirlerinden kolayca ayıramazsa, bu karışımlar, kendi mülkü olur. Bu karışımlara mülk-i habîs denir. Harâm malları ayırabilirse kendilerini, sâhiplerine veya bunların vârislerine vermesi, ayıramaz ise,…","osmanli":"حبيث ملك"},{"kelime":"Mülk Şirketi","anlam":"İki veya daha çok kimsenin, miras veya hediye sûreti ile veya parasını muayyen nisbette verip satın alarak, bir mala berâber mâlik olmaları; yahud mallarını ayrılmayacak şekilde karıştırıp ortak olmaları.","kategori":"muamelat","misal":"Mülk şirketi ile müşterek olan malların geliri, sâhipleri arasında hisselerine göre taksim olunur. (Mecelle)","osmanli":"شركتى ملك"},{"kelime":"MÜLKİYET","anlam":"İnsana, eşya üzerinde başkasının rızâsını almadan dilediği gibi tasarrufta bulunabilme ve başkalarının taarruzunu men etme salâhiyeti veren hak.","kategori":"muamelat","misal":"Mevzuuna göre ayn, menfaat ve deyn mülkiyeti; sâhiplerinin sayısına göre müstakil ve müşterek mülkiyet; mevzuunun şümûlüne göre tam veya nâkıs mülkiyet olmak üzere tasnif edilebilir.","osmanli":"ملكيت"},{"kelime":"MÜLTEKIT","anlam":"Atılmış bir çocuğu (lakît), bulunduğu yerden alıp kaldıran (iltikat eden) kimse.","kategori":"dil","osmanli":"ملتقط"},{"kelime":"MÜLTEZEM","anlam":"1.İltizâm olunmuş, lüzumlu, gerekli görülen; kayırılan. 2.Kâbe-i Muazzama’nın kapısı ile Hacerü’l-Es-ved arasında kalan Kâbe duvarı.","kategori":"dil","misal":"(A. Lüzüm’dan) Hac esnâsında Minâ’da şeytân taşlandıktan sonra, Mescid-i Haram’a gelinir.Tavâf-ı sadr veya vedâ tavâfı yapıldıktan sonra, Zemzem suyu içilir.Kâbe’nin kapı eşiği öpülür. Göğüs ve sağ yanak, Mültezem denilen yere sürülür. Sonra Kâbe perdesine yapışıp duâ edilir. Ağlaya-rak mescid kapısından dışarı çıkılır. (Mevkûfât)","osmanli":"ملتزم"},{"kelime":"MÜMÂRESE","anlam":"Alışma, alı-şıklık, yatkınlık, el yatkınlığı; egzersiz.","kategori":"dil","osmanli":"ممارسه"},{"kelime":"MÜMÂS","anlam":"Temas eden, do-kunan, ilişen; teğet.","kategori":"dil","osmanli":"مماس"},{"kelime":"MÜMESSİL","anlam":"1.Temsîl eden, benzeten; aktör. 2.Birinin yerine ve adına iş gören.","kategori":"dil","osmanli":"ممثل"},{"kelime":"MÜMEYYİZ","anlam":"Temyîz eden. Faydalı ve zararlıyı birbirinden ayırabilen; akıllı. (Bkz. Temyîz)","kategori":"dil","misal":"Mümeyyiz olmayan çocukların bütün tasarruf-ları bâtıldır. Mümeyyiz çocuğun hibe kabulü gibi faydalı işlerdeki tasarrufları, velîsi izin ver-mese de sahîhtir. Borç verme gibi zararlı işler-deki tasarrufları, velîsi izin verse de, sahîh de-ğildir. Satış ve kirâ gibi hem faydalı, hem zararlı tasarrufları velîsinin izniyle sahîhtir. (Mecelle)","osmanli":"مميز"},{"kelime":"MÜMÎT","anlam":"İmâte eden, öldüren. Allahü teâlânın Esmâ-i hüsnâsından (el-Mümît).","kategori":"akaid","misal":"El-Mümît ism-i şerîfini söyleyenin nefsi itaate gelir. (el-İstigâsetü’l-Kübrâ)","osmanli":"مميت"},{"kelime":"MÜMKİN","anlam":"İmkân dahi-linde, olabilir, olabilen.","kategori":"dil","osmanli":"ممكن"},{"kelime":"MÜMKİNÂT","anlam":"Olabilen, olabilir şey-ler. Mümkin’in çokluk hâli.","kategori":"dil","osmanli":"ممكنات"},{"kelime":"MÜMTÂZ","anlam":"İmtiyazlı, ayrı tutulmuş, üstün tutulmuş; seçkin.","kategori":"dil","osmanli":"ممتاز"},{"kelime":"MÜN‘AKİD","anlam":"İn‘ikad eden, bağlanan. Şartları tam olarak yerine getirilmiş akid veya hukukî tasarruf. (Bkz. Akd)","kategori":"dil","misal":"Bey‘ yani satış ve nikâh akdi, sözleşmesi îcâb ve kabul ile mün’akid olur. (İbni Âbidîn) Şarabın mebî olduğu satış akdi mün‘akid ol-maz. Zira şarab Müslüman için mübâh mal değildir. (İbni Âbidîn)","osmanli":"منعقد"},{"kelime":"MÜNÂCÂT","anlam":"1.Allahü teâlâya yakarmak, duâ edip yalvarmak. 2.Allahü teâlâya yakarış ve mağfiret niyâzının mevzu edinildiği şiir ve nesir eseri.","kategori":"akaid","misal":"Sizlerden biri namaza durduğunda, Rabbi ile münâcat hâlindedir. (Hadîs-i şerîfTaberânî) “İlâhî! Herkesi sıkıntıdan kurtaran yalnız sensin. Bizi dünyada ve âhirette sıkıntıda bırakma! Muhtaçlara, her şeyi gönderen yalnız sensin! Dünyada ve âhirette bize, hayırlı ve faydalı şeyleri gönder! Dünya ve âhirette, bizi kimseye muhtaç bırakma!” diye Allahü teâlâya münâcâtta bulunmalıdır. (Riyâdü’n-Nâsıhîn) Gel ey dâ’î, hemen…","osmanli":"مناجات"},{"kelime":"MÜNÂFIK","anlam":"1.Nifâk eden, ikiyüzlü, riyâkâr. 2.Îmân etmediği hâlde, Müslüman-ları aldatmak için, inanmış görünen kimse.","kategori":"akaid","misal":"Ey münâfıklar! Allahü teâlâ sizi kendi hâli-nize bırakmaz. Hâlis mü’minleri münâfık-lardan ayırır. (Âl-i İmrân sûresi: 179) Dört şey münâfıklık alâmetidir: Emânet olunana hıyânet etmek, yalan söylemek, vâdini boz-mak ve ahdine vefâ göstermemek (verdiği sözde durmamak) ve mahkemede doğruyu söylememek. (Hadîs-i şerîf-Buhârî) Mü’mi-nin niyeti amelinden hayırlıdır. Münafı-ğın ameli ise niyetinden hayırlıdır. (Hadîs-i şerîf-Taberânî) Münâfık, İslâmiyet’ten bahseder, fakat onunla amel etmez ve ona uymaz. (Huzeyfetü’l-Yemânî)","osmanli":"منافق"},{"kelime":"MÜNÂFİKûN SûRESİ","anlam":"Kur’ân-ı kerîmin altmış üçüncü sûresi.","kategori":"dil","misal":"Medîne’de nâzil oldu. On bir âyet-i kerîmedir. Sûrede münâfıkların hâlleri anlatıldığından, Sûretü’l-Münâfikûn denilmiştir. (Mefâti-hü’l-Gayb) Kim Münâfikûn sûresini okursa, nifâktan kurtulur. (Hadîs-i şerîfBeydâvî)","osmanli":"سى سوره منافقون"},{"kelime":"MÜNÂKAŞA","anlam":"Çekişme, tartışma. Kur’ân-ı kerîm üzerine münakaşa etmeyin, çünki o münakaşa küfürdür.","kategori":"dil","misal":"Münâkaşa, dostun dostluğunu azaltır. Düşmanın düşmanlığını artırır. (Mektûbât-ı Ma’sûmiyye)","osmanli":"مناقشه"},{"kelime":"MÜNÂKEHÂT","anlam":"Nikâhlanmalar. Fıkıh ilminin dört büyük kısmından, evlenme, boşanma, nafaka gibi hususlar.","kategori":"dil","osmanli":"مناكحات"},{"kelime":"MÜNÂSEBET","anlam":"(A. Nisbet’ten) İki şey arasında bir nisbet, alâka, yakınlık bulunması. MÜNÂSİB: مناسب (A. Nisbet’ten) Yerinde; ya-","kategori":"dil","misal":"kışık, yaraşık.","osmanli":"مناسبت"},{"kelime":"MÜNÂZARA","anlam":"(A. Nazar’dan) Doğruyu ortaya çıkarmak maksadı ile bir kâideye uy-gun olarak karşılıklı yapılan ilmî konuşma. Mübâhese. Müzâkere.","kategori":"fikih","misal":"Münâzara edecek kişi, gerçeği aramakta kaybını arayan kimse gibi olmalıdır. (Mevdûâtu’l-Ulûm) MÜNÂZE‘A (Münâzaa): منازعه (A) Nizâlaşma, çekişme, anlaşmazlık. Bir kimseyi sevdiğin zaman onunla mücâdele ve münâze‘a etme. (Hadîs-i şerîf-Ebû Nuaym) Eshâb-ı kirâm arasındaki muhârebeler ve münâ-ze‘alar, düşmanlık ve kin gütmek ile olmamıştır. Hep ictihâd ve te’vîl ile olmuştur. Bunun için, ayıplamanın yeri yoktur. Nerde kaldı ki, kötü-lensin. (Mektûbât-ı Ma’sûmiyye)","osmanli":"مناظره"},{"kelime":"MÜNEBBİH","anlam":"1.Tenbih eden, uyaran. 2.Uyarıcı ilaç.","kategori":"dil","osmanli":"منبه"},{"kelime":"MÜNECCİM","anlam":"1.İlm-i nü-cûmda (astronomide) mâhir kimse, astronom. 2.Yıldızların hareketlerini gözetleyerek geleceğe dâir haber verdiğini iddiâ eden kimse, astrolog.","kategori":"ibadet","misal":"Ramazan hilâlinin tesbitinde müneccimlerin sö-züne îtibâr edilmez; rüyet lâzımdır. (İbni Âbidîn) Şeb-i yeldâyı müneccimle muvakkit ne bilir, Mübtelâ-yı gama sor kim geceler kaç sa’at. (Lâedrî) Müneccimlere, kâhinlere, falcılara inanma-malı, bilinmeyen şeyleri bunlara sormamalı-dır. Bunları gaybleri bilir sanmamalıdır. Uğur-suzluğa inanmamalı, te’sir eder sanmamalıdır. (Rûhü’l-Beyân)","osmanli":"منجم"},{"kelime":"MÜNEVVER","anlam":"(A.Nûr’dan) Tenvîr edilmiş, nurlandırılmış, aydınlanmış.","kategori":"dil","misal":"Allahü teâlâ bir kimseye nûr vermezse, o kimse münevver olamaz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"منور"},{"kelime":"MÜNEVVİM","anlam":"Tenvîm eden, uyutan, uyku veren, uyutucu. Münebbih’in zıddı. MÜNEVVİR: منور (A. Nûr) Tenvîr eden, nur-","kategori":"dil","misal":"landıran, parlatan, aydınlatan.","osmanli":"منوم"},{"kelime":"MÜNEZZEH","anlam":"Tenzîh edilmiş, nezih kı-lınmış, temiz; kusur ve ihtiyaçtan uzak, berî. Allahü teâlâ noksanlık olan her şeyden mü-nezzehtir. Ayıblardan ve kudretsizlikten uzak-tır. Müşriklerin şirklerinden ve iftirâların-dan münezzehtir. (Haşr sûresi: 23)","kategori":"dil","misal":"Allahü teâlâ vardır ve birdir. Ortağı ve ben-zeri yoktur. Mekândan münezzehtir. (Mifta-hü’l-Cenne)","osmanli":"منـزه"},{"kelime":"MÜNHAL","anlam":"1.İnhilâl eden, açılan, çözülen. 2.Boş kalan, açık olan, me-muru bulunmayan.","kategori":"dil","osmanli":"منحل"},{"kelime":"MÜNÎB","anlam":"İnâbe eden, iman, ibadet, itâ‘at, zikir, istiğfâr, tövbe ve duâ ederek Allah’a yönelen.","kategori":"akaid","osmanli":"منيب"},{"kelime":"MÜNÎR","anlam":"1.Nurlandıran, ışık veren, parlak. 2.Allahü teâlânın sıfatlarından. 1.İnkıtâ’ etmiş, kesilmiş. 2.Kendisine zekât verilen sınıflardan biri, cihâd ve hac yolunda muhtaç kalanlar.","kategori":"hadis","misal":"(A. Nûr’dan) MÜNKATI‘: منقطع (A)","osmanli":"منير"},{"kelime":"MuNKATI‘","anlam":"(Bkz. Münkatı’)","kategori":"hadis","osmanli":"منقطع"},{"kelime":"MÜNKATI‘ HADÎS","anlam":"İsnâdı mut-tasıl olmayan, râvileri arasında bazıları bildi-rilmemiş hadîs.","kategori":"hadis","osmanli":"حديث منقطع"},{"kelime":"MÜNKER","anlam":"İnkâr edilmiş. Yapılması câiz olmayan, dinen ve aklın çirkin gördüğü şey, dinen yasak edilmiş, günah.","kategori":"fikih","misal":"Münkeri işleyeni görüp de gücü yettiği hâlde tatlı dil ile nehy etmemek îmânın gitmesine sebeb olur. (Miftahü’l-Cenne)","osmanli":"منكر"},{"kelime":"MÜNKER VE NEKİR","anlam":"Kabirde insanı sorguya çeken melekler.","kategori":"akaid","misal":"(İnsanın âşinâ olmadığı bir şekilde görünüp yadırganacağı için bu isimle anılırlar.) Münker ve nekir melekleri, suâl ve cevaptan sonra meyyite (ölüye); “Cehennem’deki yerine bak, Allahü teâlâ değiştirerek, sana Cennet’teki yeri ihsân eyledi” derler. Bakar ikisini birlikte görür. (Hadîs-i şerîfBuhârî)","osmanli":"ونكر منكر"},{"kelime":"MÜNKEŞÎF","anlam":"1.İnkişâf eden, açılan, açılmış, meydana çıkmış; açık, görü-nen. 2.Keşfolunmuş, yeni bulunmuş.","kategori":"dil","osmanli":"منكشف"},{"kelime":"MÜNKİR","anlam":"İnkâr eden; inanmayan, ka-bul etmeyen. (Bkz. İnkâr)","kategori":"dil","osmanli":"منكر"},{"kelime":"MuNTAZAM","anlam":"(A. Nizâm’dan) İntizamlı, sıralanmış, düzgün, derli toplu.","kategori":"dil","osmanli":"منتظم"},{"kelime":"MÜNTEHÂ","anlam":"(A. Nihâyet’den) Nihayet bul-muş; bir şeyin varabildiği en uzak yer, son de-rece, son uç.","kategori":"dil","osmanli":"منتهى"},{"kelime":"MÜNTEKİL","anlam":"İntikal eden, geçen.","kategori":"dil","osmanli":"منتقل"},{"kelime":"MÜNTEŞİR","anlam":"1.İntişâr eden, saçılan, yayılan, dağılan. 2.Erkeklik uzvunun uyanmış hâli.","kategori":"dil","osmanli":"منتشر"},{"kelime":"MÜNZEVÎ","anlam":"İnzivâ eden. İnsanlar-dan uzakta bir köşeye çekilerek ibâdet ve te-fekkürle meşgul kimse.","kategori":"dil","osmanli":"منـزوى"},{"kelime":"MÜNZİR","anlam":"1.İnzâr eden, ikaz eden, sa-kındıran. 2.Faydalı ve zararlı şeyleri bildirip, inkâr ve isyan edenlerin kötü akibetlerini ha-ber vererek insanları ikaz eden mânâsına Al-lahü teâlânın, Kur’ân-ı kerîmin ve Resûlullah aleyhisselâmın sıfatlarından. Biz O’nu (Kur’ân-ı kerîmi) mübarek bir ge-cede indirdik. Zira biz münziriz. (Duhân sûresi: 1-4)","kategori":"dil","osmanli":"منذر"},{"kelime":"MuRABBA’","anlam":"(A. Rub’dan) Terbi’ olunmuş, dörde çıkarılmış; dörtlü; dört köşeli, kare.","kategori":"dil","osmanli":"مربع"},{"kelime":"MuRÂBIT","anlam":"1.Hududda nöbet bekle-yen. 2.Kalbini Allah’a bağlayıp devamlı ibâdet ve tefekkürle meşgul olan.","kategori":"tasavvuf","osmanli":"مرابط"},{"kelime":"MuRÂD","anlam":"1.İrâde olunan, istenilen, arzu edilen. 2.Tasavvuf yolunda bulunanlardan çalışmadan Allahü teâlânın yardım ve dilemesi ile yüksek makamlara kavuşanlar.","kategori":"dil","misal":"Ubûdiyyet, kendi irâdesinden kurtulup, Hak teâlânın murâdı ile olmaktır. (Mektûbât-ı Ma’sûmiyye) Murâdı olan kimse, yatacağı zaman abdest al-malı. Temiz bir örtü üzerinde oturup, üç def ’a salevât okumalı. Sonra, herbirine Besmele çe-kerek on Fâtiha ve sonra onbir İhlâs okumalı. Sonra, üç salevât okumalı. Sonra sağ yanı üzere, yüzü kıbleye karşı ve sağ elini sağ yanağı altına koyarak yatıp uyumalıdır. Niyet ettiği şeyin na-sıl olacağını, bi-iznillah rüyada görür. (Fetâvâ-i Kâriü’l-Hidâye) İctibâ yolunun sâlik-leri. Nâzeninler. Murâd olunanların başı ve sevilenlerin ön-deri Muhammed aleyhisselâmdır. (Mektûbât-ı İmâm-ı Rabbânî) Tasavvuf yolunda bulunanlar ya mürîd olur-lar, ya murâd olurlar. Mürîdler; Allahü teâlâya yakınlık derecelerine ulaşmak için riyâzetler ve mücâhedeler çekerler. Murâdları ise, nazlı nazlı okşıyarak götürürler ve sıkıntı çektirmeden ya-kınlık derecelerine ulaştırırlar. (Avârif)","osmanli":"مراد"},{"kelime":"MuRÂHIK","anlam":"(Bkz. Mürâhık)","kategori":"dil","osmanli":"مراحق"},{"kelime":"MÜRÂÎ","anlam":"Riyâ eden, riyâkâr, iki yüzlü, kendisini olduğunun aksine gösteren, göste-riş yapan. (Bkz. Riyâ)","kategori":"dil","misal":"Cihânda iki dürlüdür, mürâî, ki aldatır bun-lar, fakîri, bayı. Birisi, yürür eski kisvetle, ki, zâhid sanılsın bu sûretle. İkincisi ise, ehl-i riyânın, işit imdi alâmetle-rin anın. Gider ardınca dâim nîgı nâmın, diler makbûlü ola hâsu âmmın. (Lâedrî)","osmanli":"مرائى"},{"kelime":"MÜRCİE","anlam":"1.İrcâ edenler, geriye bı-rakanlar. 2.“Günah işlemek insana zarar ver-mez.","kategori":"dil","misal":"Âsî, fâsık azap görmeyecektir” itikadıyla meşhur olan bid‘at fırkası. Ümmetimden iki sınıf vardır ki, Kevser ha-vuzunun başına varamazlar; Cennet’e de gi-remezler. Bunlar Kaderiyye ve Mürcie’dir. (Hadîs-i şerîf-Tirmizî, Taberâni)","osmanli":"مرجئه"},{"kelime":"MÜRECCEB","anlam":"1.Mübarek, kutlu. 2.Receb ayı için kullanılan ta’zim sözü.","kategori":"dil","misal":"(A. Rücub’dan) (Receb-i Mürecceb.)","osmanli":"مرجب"},{"kelime":"MÜRECCİH","anlam":"(A. Rüchân’dan) Tercih eden, üstün tutan.","kategori":"dil","osmanli":"مرجح"},{"kelime":"MÜREKKEB","anlam":"Terkîb edilmiş, iki veya daha fazla şeyin karışmasından meydana ge-len, birleşik, parçalanabilen. Basitin zıddı.","kategori":"dil","misal":"Ruh basîttir. Mürekkeb değildir. Böyle olsaydı, basît olan bir şey bunda yerleşmezdi. Çünki ruh parçalanırsa, bunda yerleşen basît şeyin de parçalanması lâzım gelir. Basît olan şey ise parçalanamaz. (Ahlâk-ı A’lâî)","osmanli":"مركب"},{"kelime":"MÜREYSİ GAZVESİ","anlam":"Hicretin beşinci senesinde Benî Mustalık üzerine","kategori":"dil","misal":"yapılan ve ezvâc-ı tâhirattan Cüveyriyye’nin esir alındığı muharebe.","osmanli":"سى غزوه مريثى"},{"kelime":"MÜRÎD","anlam":"İrâde eden. Tasavvufta Allahü teâlânın irâdesine tâbi olarak kendi irâdesini bırakan; Rabbin rızâsına kavuşmak için bir mürşid-i kâmilin terbiyesi altına girmeyi irâde eder.","kategori":"tasavvuf","misal":"Mürîd, mürşidinin yanında cenâze yıkayıcısının elindeki ölü gibi olmalıdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مريد"},{"kelime":"MÜRKID","anlam":"Uyutucu ilâç; aklı ve hissi gideren nesne.","kategori":"dil","osmanli":"مرقد"},{"kelime":"MÜRSEL","anlam":"1.İrsâl olunmuş, gönderil-miş. 2.Şeriat ile gönderilen peygamber.","kategori":"hadis","misal":"(Bkz. Mürselîn)","osmanli":"مرسل"},{"kelime":"Mürsel Hadîs","anlam":"Tâbiîn’den biri-nin, rivâyet eden Sahâbî’yi atlayarak, doğruca, “Resûlullah buyurdu ki” diyerek bildirdiği hadîs-i şerîfler. (Bkz. Hadîs)","kategori":"hadis","osmanli":"حديث مرسل"},{"kelime":"MÜRSELÎN","anlam":"1.Gönderilenler, 2.Yeni bir şeriat ile gönderilen peygamberler.","kategori":"akaid","misal":"Ebû Bekr ve Ömer, nebiyyîn ve mürselînden başka, önce gelen ve sonra gelen bütün Cennetliklerin, saçları ağarmaya başlayanların efendileridir. (Hadîs-i şerîfİbn-i Mâce)","osmanli":"مرسلين"},{"kelime":"MÜRŞİD","anlam":"1.İrşâd eden, yol gösteren, rehber, kılavuz. 2.İyi bir Müslüman olmaları için, insanları terbiye eden, âlim ve velî.","kategori":"tasavvuf","misal":"Allah kime hidayet ederse, işte o, hakka ulaşmıştır. Kimi de hidayetten mahrum ederse artık onun için mürşid bir dost bulamazsın. (Kehf sûresi: 17) Tasavvuf yolunda nihâyete varan büyükler iki türlüdür: Birincisi Resûlullah’ın sallallahü aleyhi ve sellem izinde giderek kemâle erdikten sonra insanları irşâd için halkın derecesine indirilmiş olan mürşidlerdir. İkincisi, yükseldikleri derecelerde bırakılıp, insanların…","osmanli":"مرشد"},{"kelime":"Mürşid-i Kâmil","anlam":"Tasavvufta kemâle gelerek, evliyâlık mertebelerinin sonuna ulaşmış, kâbiliyeti olanları bu yolda yetiştirmeye ehil rehber zât.","kategori":"tasavvuf","misal":"Mürşid-i kâmilin bakışları, kalb hastalarına (kalbi Allahü teâlâdan başka şeylere tutulmuş olanlara) şifâ verir. Onun teveccühü yani kalbini bir kimseye çevirmesi; kötü, çirkin huyları insanların kalbinden siler, süpürür. (Mektûbât-ı İmâm-ı Rabbânî) Mürşid-i kâmil, mürîdi evvel ehl-i hâl ider Sonra, Fahr-i kâinâtın bezmine idhâl ider Nice yıllar sa’y ile eremediği menzile Bir nefeste mürşid-i kâmil onu îsâl ider. (A…","osmanli":"كامل مرشد"},{"kelime":"MÜRTECİ‘","anlam":"1.İrticâ eden, geri dönen. 2.İslâmiyet’ten yüz çevirip, câhiliyet devri ya-şayışına dönen; gerici.","kategori":"dil","misal":"(Bkz. İrticâ)","osmanli":"مرتجع"},{"kelime":"MÜRTED","anlam":"İrtidâd eden, Müslüman iken dinden çıkan kimse. (Bkz. İrtidâd) Yaratılmışların içinde Allah’ın en sevme-diği kimse mürteddir. (Hadîs-i şerîf-Tem-mâm) Mürteddi katlediniz. (Hadîs-i şerîf-Ebû Dâvûd)","kategori":"hadis","misal":"Mürtedin Müslüman iken yapmış olduğu ibâ-detlerin, iyiliklerin hepsi yok olur. Ölmeden önce tövbe edip tekrar Müslüman olursa, geri gelir ise de, yeniden hac etmesi lâzım olur. Mürted iken kazâya kalan namaz ve oruçlarını kazâ etmez. Önceden kazâya bırakmış olduklarını kazâ etmesi lâzımdır. Çünki mürted olunca, önceki günahlar yok olmaz. (Berîka)","osmanli":"مرتد"},{"kelime":"MÜRTEKİB","anlam":"İrtikâb eden, günah iş-leyen, suçlu.","kategori":"dil","osmanli":"مرتكب"},{"kelime":"MÜRTEZÂ (Murtedâ)","anlam":"İrtidâ olunan, beğenilmiş, râzı olunmuş mânâsına Hazret-i Ali’nin lakabı.","kategori":"dil","osmanli":"مرتضى"},{"kelime":"MÜRûR","anlam":"Geçme, bir yandan girip öte yandan çıkma; geçip gitme; sona erme. Ödünç vermekten veya satıştan ve kirâdan, ve-dî’a, âriyet, vergi, mülk, akar ve mirastan olan şahsî alacakları için, onbeş hicrî sene özürsüz terk edilmiş da’vâlar, borçlu inkâr ederse, dinlen-mez. Yani mürûr-i zamana uğrarlar. (Mecelle) Hak teâlâ üzerinden zaman mürûr eylemez (geçmez). Zaman ve mekân onun mahlûku-dur. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"miras","osmanli":"مرور"},{"kelime":"MÜRÜVVET","anlam":"Yiğitlik, mert-lik; insanlık, erkeklik; faydalı olmak.","kategori":"dil","misal":"İnsanın, bir din kardeşi konuşurken sus-ması mürüvvettendir. (Hadîs-i şerîf-Hatîb) Cimâ’ için ve abdest bozmak için kullanılan kelimeleri açıkça söylemek mekrûhtur. Çünki bunları söylemek, mürüvvete ve diyânete uy-gun değildir; hayâyı, utanmayı giderir ve baş-kalarını gücendirir. (Hadîka) Haram işlememek, günahlardan sakınmak, in-saf ile hüküm vermek, zulmetmemek, hakkı ol-mayana göz dikmemek, kölesi olmayan kimseyi karşılıksız çalıştırmamak, zayıfa karşı kuvvet-liye yardım etmemek, alçak olanı şerefliye ter-cih etmemek, vebâl ve günah olan şeylere se-vinmemek, kötü isim yapacak olan hareketlerde bulunmamak mürüvvetin şartlarındandır. (Ede-bü’d-Dünya ve’d-Dîn) Kimim var hazretinden gayri arz eyleyeyim hâlim, Yüce zâtına âittir mürüvvet, yâ Resûlallah! (Adlî)","osmanli":"مروت"},{"kelime":"MÜŞÂ‘","anlam":"1.Birden fazla kişi arasında müşterek olan, şâyi hisseleri ihtiva edip, ayrılmamış şey. 2.Müşterek malın her bir kimsedeki hissesi.","kategori":"ibadet","osmanli":"مشاع"},{"kelime":"MÜSÂ‘ADE","anlam":"1.Yardım. 2.İzin. 3.Elverişli bulunma.","kategori":"dil","misal":"(A. Su‘ûd’dan) Zamanımız hocalarına Allahü teâlâ insâf ver-sin de, hiçbir bid‘ate güzel demesinler ve hiçbir bid‘atin işlenmesine müsâ‘ade etmesinler. (Mek-tûbât-ı İmâm-ı Rabbânî)","osmanli":"مساعده"},{"kelime":"MûSÂ (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen peygamberlerden.","kategori":"dil","misal":"Allahü teâlâ Mûsâ aleyhisselâm ile gerçekten konuştu. (Nisâ sûresi: 165) Mi’râc’a götürüldüğüm gece, Mûsâ aleyhisselâmı gördüm. Esmer, uzun boylu, kıvırcık saçlı idi. (Hadîs-i şerîfBuhârî)","osmanli":"موسى"},{"kelime":"MÜSÂDERE","anlam":"Bir mala zorla el koyma. Sultânın müsâdere etmesi ikrâh olur. Bunları vermek câiz olur. (İbni Âbidîn)","kategori":"dil","misal":"İhtikâr yapanın malları müsâdere edilip, piyasa fiyatından halka satılır. (İbni Âbidîn)","osmanli":"مصادره"},{"kelime":"MÜSÂFEHA","anlam":"Tokalaşma, el sıkışma. İki Müslümanın, sağ elin avuç içlerini birbi-rine yapıştırıp, iki baş parmağın yanlarını bir-birine değdirerek el sıkışması.","kategori":"dil","misal":"İki erkek veya iki kadın Müslüman karşılaş-tıkları zaman, müsâfeha ederlerse, ayrılma-dan önce, günahları mağfiret olunur. (Ha-dîs-i şerîf-Ebû Dâvûd) Baş parmakta bulunan damardan muhabbet (sevgi) yayılır. Müsâfeha ederken birbirine mu-habbet geçer. (Tahtâvî)","osmanli":"مصافحه"},{"kelime":"MÜSÂFİR","anlam":"(Bkz. Misâfir)","kategori":"dil","osmanli":"مسافر"},{"kelime":"MÜŞÂHEDE","anlam":"1.Şâhid olma, görme, anlama. 2.Kalb gözü ile görme; eşyayı tevhid diliyle anlama; Hak teâlânın kalbde tecellisi.","kategori":"dil","misal":"Cennet’in zîneti, hûrîler ve gılmanlar iledir. Ve cemâlullahı müşâhede iledir. (Miftahü’l-Cenne) Çok-luk hâli müşâhedât gelir. Ahvâl ve mevâcid (hâller ve kendinden geçme) ve müşâhedât ve tecelliyât (hakîkatlerin kalbe yerleşmesi) tasavvuf yolunun başlangıcında ve arada meydana gelir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مشاهده"},{"kelime":"MÜŞÂHERE","anlam":"Aylık üzerinden kirâlama.","kategori":"muamelat","osmanli":"مشاهره"},{"kelime":"MÜSÂHERE (Musâhara)","anlam":"Sıhrî hısımlık, evlenme yoluyla meydana gelen akrabalık; kadının kan hısımlarıyla koca arasında kurulan akrabalık.","kategori":"dil","osmanli":"مساهره"},{"kelime":"MÜSÂKÂT","anlam":"Bağda üzüm, bahçelerde","kategori":"muamelat","misal":"meyve ve bostanlarda sebze yetiştirmek için, toprak sahibi ile çalışacak kimse arasında yapılan şirket, sulama ortaklığı.","osmanli":"مساقات"},{"kelime":"MuSALLÂ","anlam":"1.Namaz kılınan yer. 2.Daha ziyâde cenâze ve bayram namazları için toplanılan yer, namazgâh.","kategori":"dil","misal":"Kâbe’yi, insanlar için toplanma ve emniyet yeri kıldık. Makam-ı İbrâhim’i de musallâ edinin, dedik. (Bakara sûresi: 125) Cenâze ve bayram namazı kılmak için yapı-lan musallâ, İmâma uymanın câiz olması hak-kında mesciddir. Başka bir şey hakkında mes-cid değildir. Binâenaleyh böyle bir musallâya cünüb ve hayızlı kimselerin girmeleri helâldir. (İbni Âbidîn)","osmanli":"مصلى"},{"kelime":"MuSALLAT","anlam":"(A. Salâtet’den) Teslît olun-muş, birinin üzerine düşmüş, sataşmış, iliş-miş; sataşan, rahat bırakmayan.","kategori":"ibadet","osmanli":"مسلط"},{"kelime":"MuSALLÎ","anlam":"Namaz kılan; beş vakit namazına devam eden.","kategori":"ibadet","misal":"Musallînin yukarısında veya karşısında veya sağ ve sol ve arka tarafları hizâsında hayvan, insan resmi bulunması, üstünde veya elbisesinde insan veya hayvan resmi bulundurması mekrûhtur. (İbni Âbidîn)","osmanli":"مصلى"},{"kelime":"MÜSÂMAHA","anlam":"Hoş görü, başkasının kabahatini görmezden gelme, tolerans, tesâmuh. İnsanlara müsâmaha edin ki size müsamaha ile muamele edilsin. (Hadîs-i şerîf-Taberânî, Abdürrezzâk)","kategori":"hadis","osmanli":"مسامحه"},{"kelime":"MÜSÂMERE","anlam":"Gece eğlencesi, yatsıdan sonra oturup sohbet etme.","kategori":"tasavvuf","osmanli":"مسامره"},{"kelime":"MuSANNEF","anlam":"Sınıflandırılmış, kısım-lara ayrılmış, tasnif edilmiş. Hadîs-i şerîfleri mevzularına göre tertip eden eser.","kategori":"hadis","osmanli":"مصنف"},{"kelime":"MÜSÂVÂT","anlam":"Eşitlik, denk-lik; aynı hâlde ve derecede olma.","kategori":"dil","osmanli":"مساوات"},{"kelime":"MÜSÂVÂT ŞİRKETİ","anlam":"Kullanma hakkı, hisse mikdarı ve kâr taksiminin bütün şerikler için müsavî (eşit) olduğu şirket türü.","kategori":"muamelat","misal":"(Bkz. Mufâvada)","osmanli":"شركتى مساوات"},{"kelime":"MÜSÂVÎ","anlam":"Eşit, denk.","kategori":"dil","misal":"Mekke şehri alınmadan önce din düşman-ları ile harb edenler ve mallarını, Allah yo-lunda harc edenler ile, Mekke alındıktan sonra bunları yapanlar, müsâvî değildir. Bi-rinciler elbette daha yüksektir. Allahü teâlâ hepsine Hüsnâyı, yani Cennet’i söz verdi. (Hadîd sûresi: 10) Ağırbaşlı kimse, medh olunmayı sevmez, yeril-mekten de üzülmez. Fakirle zenginleri müsâvî tutar. Tatlıyı acıyı ayırmaz. (Ahlâk-ı A’lâî)","osmanli":"مساوى"},{"kelime":"MÜŞÂVİR","anlam":"Meşveret edilen, kendisine danışılan.","kategori":"dil","osmanli":"مشاور"},{"kelime":"MuSAVVİR","anlam":"1.Tasvir eden, sûret ya-pan. 2.En güzel sûreti veren mânâsına Allahü teâlânın Esmâ-i hüsnâsından (el-Musavvir).","kategori":"dil","misal":"O Allahü teâlâ hâlıktır, bârîdir, musavvir-dir. (Haşr sûresi: 24)","osmanli":"مصور"},{"kelime":"MÜSBET","anlam":"(A. Sübût’dan) Tesbît edilmiş, delil gösterilmiş, pozitif, olumlu.","kategori":"dil","osmanli":"مثبت"},{"kelime":"MÜŞEBBİHE","anlam":"Kur’ân-ı kerîmdeki müteşâbih âyetleri görünen lugat mânâsına göre alıp, Allahü teâlâyı cisim ve varlıklara benzeten bid‘at fırkası.","kategori":"dil","misal":"Müşebbihe esasta ikiye ayrılır. Birincisi Allahü teâlânın zâtını insana benzetenlerdir. İkincisi ise, Allahü teâlânın sıfatlarını insanların ve diğer yaratılmışların sıfatlarına benzetenlerdir. (Milel ve Nihâl)","osmanli":"مشبهه"},{"kelime":"MÜŞEKKİK","anlam":"1.Şekkeden, şüpheye düşen. 2.Bir cins içindeki ferdlerin hepsinde müsâvî mikdarda bulunmayan sıfat.","kategori":"dil","misal":"Akıl da ilim gibi müşekkik olup, insanlarda eşit olarak bulunmaz. Hiç yanılmayan, hatâ etme-yen selîm akıl, peygamberlerde aleyhimüsselâm bulunur. (Abdülhakîm Arvâsî)","osmanli":"مشكك"},{"kelime":"MÜSEKKİN","anlam":"(A. Sükûn’dan) Teskîn edici, uyuşturucu, yatıştırıcı, ağrı kesici.","kategori":"dil","osmanli":"مسكن"},{"kelime":"MÜSELLES","anlam":"Üçlü. Tâze iken yani gaz kabarcıkları çıkmadan, köpürmeden önce ısıtılıp, üçte ikisi uçup üçte biri kalan ve içilmesi İmâm Muhammed’e göre haram olan üzüm suyu.","kategori":"ibadet","misal":"Kısrak, inek, deve sütleri mayalanıp, tadı keskin olunca, müselles gibi olurlar. Birincisine kumis, ikincisine kefir denir. Bira gibi haramdırlar. (İskilipli Âtıf Efendi)","osmanli":"مثلث"},{"kelime":"MÜSELSEL","anlam":"Teselsül eden, zincirleme, ardı ardına.","kategori":"dil","osmanli":"مسلسل"},{"kelime":"MÜSEMMÂ","anlam":"Tesmiye olunan, ismi olan; adı konmuş, belli edilmiş, muayyen. MÜSEMMEN: مثمن (A) Semen karşılığında sa-","kategori":"dil","misal":"tılmış veya semeni, bedeli tayin edilmiş şey.","osmanli":"مسمى"},{"kelime":"MÜSENNEM","anlam":"Tesnîm edilmiş, kabar-tılmış, balık sırtı veya deve hörgücü gibi gibi yuvarlak ve kabarık.","kategori":"dil","misal":"Kabri müsennem yapmak mendubdur. Vâcib diyen de vardır. Buhârî’nin rivâyet ettiği bir ha-dîs-i şerîfte, Süfyan, Resûlullah aleyhisselâmın kabrinin böyle olduğunu söylemiştir. İmâm Şâ-fiî, tastîh, yani dört köşe yapmanın efdal oldu-ğunu söylemiştir. (İbni Âbidîn)","osmanli":"مسنم"},{"kelime":"MÜŞERREF","anlam":"Şereflendi-rilmiş, şerefli.","kategori":"dil","misal":"İslâm-ı hakîkî ile müşerref olduktan sonra, nü-büvvet kemâlâtından nasip almaya isti’dâdlı olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مشرف"},{"kelime":"MûSEVÎ","anlam":"Mûsâ’ya mensub; Mûsâ aleyhisselâmın dinine tâbi.","kategori":"dil","misal":"(Bkz.Mûsevîlik)","osmanli":"موسوى"},{"kelime":"MûSEVİYYE","anlam":"Mûsâ aleyhisselâmın dini.","kategori":"dil","misal":"Mûsevîlik.","osmanli":"موسويه"},{"kelime":"MÜŞEVVEŞ","anlam":"(A. Şevâş’den) Teşvîş edil-miş, belirsiz, karışık, düzensiz, karmakarışık.","kategori":"dil","osmanli":"مشوش"},{"kelime":"MÜSEVVİF","anlam":"Tesvîf eden, geciktiren, sonraya bırakan.","kategori":"dil","misal":"Vakit, keskin bir kılınç gibidir. Yarına çıkacağı-mız belli değildir. Mühim işleri bugün yapmalı, mühim olmayanları yarına bırakmalıdır. Çünki hadîs-i şerîfte; “Müsevvifler helâk oldu” buy-ruldu. Boş zamanı kıymetlendirmelidir. Bu za-manlarda Allahü teâlânın beğendiği şeyleri yap-malıdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مسوف"},{"kelime":"MÜŞFİK","anlam":"Şefkatli, merhametli, acıyan.","kategori":"dil","misal":"Hoca müşfik ve mâhir; talebe zekî ve çalışkan olursa öğrenilmeyecek bir mesele yoktur. (Ab-dülhakîm Arvâsî)","osmanli":"مشفق"},{"kelime":"MuSHAF (Mıshâf)","anlam":"Kur’ân-ı kerîmin tamamının yazılı olduğu kitap.","kategori":"dil","misal":"Muhammed aleyhisselâm, âhireti teşrîf ettiği sene, halîfe Hazret-i Ebû Bekr ezber bilenleri toplayıp ve yazılı olanları getirtip bir hey’ete bütün Kur’ân-ı kerîmi kâğıd üzerine yazdırdı. Böylece mushaf meydana geldi. Otuz üç bin Sahâbî, bu mushafın her harfinin, tam yerinde olduğuna söz birliği ile karar verdi. (Seâdet-i Ebediyye) Mushafı hiç okumayıp, hayır ve bereket için evde saklamak câizdir. (Fetâvâ-yı Hindiyye)","osmanli":"مصحف"},{"kelime":"MÜSHİL","anlam":"1.Teshîl eden, ko-laylaştıran. 2.İshal veren.","kategori":"dil","osmanli":"مسهل"},{"kelime":"MuSÎBET","anlam":"İsâbet eden. Felâket, âfet, belâ, sıkıntı.","kategori":"dil","misal":"Ey insan! Sana gelen her iyilik, Allahü teâlâ-nın ihsânı olarak, nîmeti olarak gelmektedir. Her dert ve musîbet de kötülüklerine kar-şılık gelmektedir. Hepsini yaratan, gönde-ren Allahü teâlâdır. (Nisâ sûresi: 79) Kendi-sine bir musîbet isâbet ettiği zaman “İnnâ lillâhi ve innâ ileyhi râciûn” (Şüphesiz biz Allah’dan geldik, ve yine ona döndürüleceğiz) diyen sabırlılara müjdeler olsun! (Bakara sûresi: 156) Allahü teâlâ kuluna bir musî-bet vermişse, bu musîbet sebebiyle bir gü-nahını affeder ve ona bir derece verir (Ha-dîs-i şerîf-Ebû Nuaym)","osmanli":"مصيبت"},{"kelime":"MûSÎKÎ","anlam":"Ölçülü sesler vâsıtasıyla te-sir ve heyecan ortaya koyan ses sanatı. Mü-zik. Musıka.","kategori":"dil","misal":"İlm-i mûsikî, riyâzî (matematikî) bir ilimdir. Onunla nağmelerin hâlleri, meydana gelişi, bestelerin te’lifi ve âletlerin yapılması bilinir. Bu ilmin mevzuu ruhlara tesiri yönünden ses-tir. Semeresi, insanı rahatlandırmak yâhud hü-zünlendirmektir. (İbni Âbidîn) Kelimeleri mûsikî perdesine uydurmak için, ha-reke, harf ve med eklemek veya çıkarmak, kı-raati bozmak demektir. Böyle okunan ezânı ve Kur’ân-ı kerîmi dinlemek de günahtır. Bunları yapmadan, yani kelimeleri bozmadan tegannî etmek, yani sesi güzelleştirmek câizdir ve iyi-dir (İbni Âbidîn) Mûsîkî, zevk ve eğlence için olursa câiz değil-dir. Yalnız harbe giden askerlerin uğurlanması ve karşılanması sırasında veya düğün için da-vul çalınmasında beis yoktur. (İbni Âbidîn)","osmanli":"موسيقى"},{"kelime":"MuSKA","anlam":"Hastalığa, nazara, cin ve vahşi hayvanlara karşı insanı koruyacağı inancıyla yazılan ve muşambaya sarılan kâğıt. Aslı Arabca nüsha gelir. (Bkz. Rukye, Mıska, Ta’viz) Hastaya ve hayvan sokana, şifâ için Kur’ân-ı kerîm okumak veya kâğıda yazıp muska ola-rak taşıması yâhud tas içinde ıslatıp, bu suyu içmesi, bu su ile, ağrıyan yeri yıkaması câiz-dir. Meşhûr duâlar ile muska ve ilâç câizdir. (Fetâvâyı Hindiyye)","kategori":"dil","misal":"Rukye, okuyup üflemek veya üzerinde taşımak demektir. Âyet-i kerîme ile ve Resûlullah’tan gelen duâlar ile Rukye yapmaya, ta’vîz denir. Ta’vîz câizdir ve inanan, güvenen kimseye fâide verir. Ta’vîz yazılı muskayı sarılı olarak cünü-bün taşıması ve helâya girmesi câizdir. (Halebî) Ne olduğu bilinmeyen şeyleri yazmak, okumak ve kendisine okutmak, bunları muska yapmak câiz değildir. (Dürrü’l-Muhtâr)","osmanli":"مصقه"},{"kelime":"MÜSKİR","anlam":"Sekr veren, sarhoş edici; şuuru kaybettiren, aklı gideren ve keyf ve-ren madde.","kategori":"dil","misal":"Her müskir haramdır. Her kim dünyada içki içer ve içmekte devam eder ve tövbe edeme-den ölürse, o kimse âhirette Cennet şerbet-lerinden içemeyecektir. (Hadîs-i şerîf-Müslim)","osmanli":"مسكر"},{"kelime":"MÜSKİRÂT","anlam":"Sekr veren, sarhoş edici maddeler. Müskir’in çokluk hâli.","kategori":"muamelat","osmanli":"مسكرات"},{"kelime":"MuSLİH","anlam":"Islâh eden, düzelten, eski hâline getiren.","kategori":"dil","osmanli":"مصلح"},{"kelime":"MÜSLİM","anlam":"1.İslâm olan, tes-lim olan, selâmette olan. 2.İslâm dinine mensub; Allah’a teslim olan; Al-lahü teâlânın peygamberleri vasıtasıyla gön-derdiklerine iman edip, emir ve yasaklarına uyan kimse. Allahü teâlânın şerîki yoktur. bana sadece bu emrolundu. Ben müslimlerin evveliyim ilkiyim. (En’am sûresi: 163) İbrâhim aley-hisselâm ne Yahudi ve ne de Nasrânî idi. O dosdoğru inanan bir müslim idi. (Âl-i İm-rân sûresi: 67) 3.Muhammed aleyhisselâmın dinine tâbi olan.","kategori":"dil","misal":"Bedevîler; “İman ettik!” dediler. De ki: “Siz iman etmediniz, ama müslim olduk deyin. Henüz iman kalplerinize yerleşmedi. Eğer Allah’a ve elçisine itaat ederseniz, Allah iş-lerinizden hiçbir şeyi eksiltmez”. (Hucurât sûresi: 14) Müslim demek, Müslümanlara eli ile, dili ile zarar vermeyen kimse demektir. (Hadîs-i şerîf-Buhârî, Müslim)","osmanli":"مسلم"},{"kelime":"MÜSLİME","anlam":"2.İslâm dinine mensub kadın; Muhammed aleyhisselâmın dininde olan kadın.","kategori":"osmanli","misal":"İslâm olan, teslim olan, selâmette olan kadın. Müslüman kadın.","osmanli":"مسلمه"},{"kelime":"MÜSLÜMAN (Müslimân)","anlam":"İslâm dinine mensub; Muhammed aleyhisselâmın dininde olan, müslim.","kategori":"dil","misal":"Müslüman, Müslümanın kardeşidir. Ona zulmetmez, onun yardımına koşar, onu küçük ve kendinden aşağı görmez. Onun kanına, malına, ırzına, nâmusuna zarar vermesi haramdır. (Hadîs-i şerîfEşi’atü’l-Lemeât) Bir Müslüman, Allahü teâlânın emir ve yasaklarına ne kadar dikkat edip tatbik ediyorsa, Allahü teâlâ da onu, o mikdar azîz eder. Diğer Müslümanların kalbine de onun sevgisini verir. (İbrâhim Havvâs)","osmanli":"مسلمان"},{"kelime":"MÜSNED","anlam":"1.İsnâd edilen. 2.Hadîs-i şerîflerin ilk râvisinin ismine göre tertip edilen hadîs kitaplarına verilen isim.","kategori":"hadis","osmanli":"مسند"},{"kelime":"MÜSNED HADÎS","anlam":"Hazret-i Peygamber’e kadar bütün râvilerin ismi eksiksiz bildirilen hadîs-i şerîf.","kategori":"hadis","misal":"(Bkz. Hadîs-i Müsned)","osmanli":"حديث مسند"},{"kelime":"MÜSRİF","anlam":"(A. Sarf ’dan) İsraf eden, gerek-siz yere harcama yapan, savurgan.","kategori":"muamelat","misal":"Müsrif baba velî olamaz. (Dürer, İbni Âbidîn)","osmanli":"مسرف"},{"kelime":"MÜŞRİF","anlam":"1.Bir vakfa, mü-tevellînin tasarruflarını kontrol altında tut-mak üzere tayin olunan kimse, nâzır. 2.Vak-fın kasasına nezâret eden vazifeli, hazinedar, anbar memuru.","kategori":"dil","osmanli":"مشرف"},{"kelime":"MÜŞRİK","anlam":"Allahü teâlâya şirk (ortak) koşan.","kategori":"akaid","misal":"Mekke kâfirleri, Muhammed ölecek, O’ndan kurtulacağız diyorlardı. Allahü teâlâ da evet sen öleceksin. Fakat, o müşrikler de, elbette ölecekler. Kendileri elbet ölecek olan kimselerin, başkasının ölümünü beklemeleri, açık bir câhilliktir. (Zümer sûresi: 30) Müşriklerin kendileri değil, i’tikâdları ve kalbleri pistir. İ’tikâdları düzelirse, kendileri de temiz olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مشرك"},{"kelime":"MÜSTA‘CEL","anlam":"Acele, hemen yapıl-ması icab eden.","kategori":"dil","osmanli":"مستعجل"},{"kelime":"MuSTAFÂ","anlam":"1.Seçilmiş, ayıklanmış, saflaştırılmış. 2.Her türlü kirden, kötülükten, kusurdan arındırılmış mânâsına Resûlullah aleyhisselâmın lakabı.","kategori":"dil","misal":"Ümmetim dedi sana çün Mustafâ, Ver salevât sen de âna bul safâ. (Mevlid-i Süleymân Çelebi)","osmanli":"مصطفى"},{"kelime":"MÜSTAĞFÎR","anlam":"İstiğfâr eden, Allahü teâlâdan günahlarının bağışlanmasını iste-yen. (Bkz. İstiğfâr)","kategori":"akaid","misal":"(O takvâya erenler); “Ey Rabbimiz, biz îmân ettik. Artık bizim günahlarımızı bağışla ve bizi o ateşin azâbından koru” diyenler, sab-redenler (îmânlarında) gerçek olanlar, Allahü teâlâya itaatle boyun eğenler, infâk edenler, seherlerde müstağfîr olanlardır. (Âl-i İmrân sûresi: 16, 17)","osmanli":"مستغفر"},{"kelime":"MÜSTAHZAR","anlam":"2.Zihinde tutulmuş.","kategori":"dil","misal":"(A. Huzur’dan) l.Hu-zura getirilmiş, istihzar edilmiş, hazırlanmış, hazır.","osmanli":"مستحضر"},{"kelime":"MÜŞTÂK","anlam":"İştiyaklı, özleyen. Kim Allahü teâlâya müştâk ise, O’nun kelâ-mına kulak versin. (Mektûbât-ı Ma’sûmiyye)","kategori":"ibadet","osmanli":"مشتاق"},{"kelime":"MÜSTATÎL","anlam":"Dikdörtgen.","kategori":"dil","osmanli":"مستطيل"},{"kelime":"MÜSTE’CİR","anlam":"İsticâr eden, bir malı veya hizmeti kirâlayan.","kategori":"muamelat","misal":"Hayvan, binmek ve yük taşımak için; elbise, giymek için kirâlanır. Şarta uymayıp, hayvan, ev ve elbise zarar görürse, müste’cir tazmîn eder, öder. Hayvanı, çekerek veya döğerek sakat ederse öder. (Fetâvâ-yı Hindiyye) Sanat sahipleri işçilik ücretini müste’cirden alıncaya kadar, eşyayı vermeyebilir. Eşya telef olup, teslim edemezse ücret alamaz. (Fetâvâ-yı Hindiyye)","osmanli":"مستأجر"},{"kelime":"Müste’min Kâfir","anlam":"Müslüman bir memlekete onların izni ile giren Müslüman olmayan kimse, ecnebî.","kategori":"dil","misal":"Dârülislâma müste’min olarak gelen bir kâfir, burada yaşamakta olan bir zımmî gibi, yani gayr-i müslim vatandaş gibi korkusuz yaşar. Onun haklarına mâlik olur. Müste’mine veya zımmîye olan borcunu ödemeyen Müslüman hapsolunur. (İbni Âbidîn)","osmanli":"كافر مستأمن"},{"kelime":"MÜSTE’MİN (Müste’men)","anlam":"1.İs-ti’mân eden, emân dileyen, sığınan. 2.Kendi memleketinden başka bir devletin topraklarına izinle giren kimse.","kategori":"osmanli","osmanli":"مستأمن"},{"kelime":"MÜSTECÂB","anlam":"İcâbet edilmiş, mak-bûl, kabul olunan, geri çevrilmeyen.","kategori":"dil","misal":"Kişinin din kardeşi için gıyâbında (arkasın-dan) yapılan duâ müstecâbdır. Başucunda âmin diyen bir melek bulunur. O kişi mü’min kardeşine hayır duâ ettikçe, melek; âmin, hayrın misli senin için de olsun der. (Ha-dîs-i şerîf-İbn-i Mâce)","osmanli":"مستجاب"},{"kelime":"MÜSTEFİD","anlam":"İstifâde eden, faydalanan.","kategori":"dil","osmanli":"مستفيد"},{"kelime":"MÜSTEFÎZ","anlam":"İstifâze eden, feyz alan, feyizlenen.","kategori":"dil","osmanli":"مستفيض"},{"kelime":"MÜSTEHAB","anlam":"Sevilen, beğenilen. Hazret-i Peygamber’in bazen yapıp, bazen terk ettiği ve yapılınca sevab verilen, yapılmayınca günah olmayan şey.","kategori":"akaid","misal":"İmâmın, son sünneti, farz kıldığı yerde kılması mekrûhtur. Cemâatin kılması mekrûh değil ise de, başka yerlerde kılmaları müstehabdır. Müstehâbı yapmayanın namazı noksan olmaz; sevâbından mahrum kalır. (Merâkı’l-Felâh)","osmanli":"مستحب","alternatif":["mustehab","mustehap"]},{"kelime":"MÜSTEHAK","anlam":"İstihkâk eden, hak etmiş, hak kazanmış, lâyık.","kategori":"akaid","misal":"İbâdete, karşısında alçalmaya müstehak olan, hakkı olan ancak O’dur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مستحق"},{"kelime":"MÜSTEHÂZA","anlam":"İstihâzalı kadın, hayz ve nifâs âdeti dışında kendisinden kan gelen kadın.","kategori":"osmanli","osmanli":"مستحاضه"},{"kelime":"MÜSTEHCEN","anlam":"Açık saçık, edepsizce.","kategori":"dil","osmanli":"مستهجن"},{"kelime":"MÜŞTEREK","anlam":"İştirak eden, ortak (olan), ortaklaşa.","kategori":"dil","osmanli":"مشترك"},{"kelime":"MÜŞTERÎ","anlam":"İştirâ eden, satın alan, alıcı. Akid tamam olunca, mebî (satılan mal) müş-terînin mülkü olur. (Dürrü’l-Muhtar)","kategori":"muamelat","osmanli":"مشترى"},{"kelime":"MÜSTESNÂ","anlam":"1.İstisnâ edi-len, ayrı tutulan. 2.Üstün.","kategori":"dil","osmanli":"مستثنى"},{"kelime":"MÜSTEŞRİK","anlam":"İstişrak ehli, Şark memleketlerini, din, dil ve tarihleri başta olmak üzere her yönden araştırıp tesbite çalı-şan Batılı ilim adamı. Oryantalist. Şarkiyâtçı.","kategori":"dil","osmanli":"مستشرق"},{"kelime":"MÜSTEVÎ","anlam":"1.Düz, her ta-rafı bir; düzlem. 2.Müzekker ve müennes hâli bir olan kelime.","kategori":"dil","misal":"(A. Sevî’den)","osmanli":"مستوى"},{"kelime":"Mut‘a Nikâhı","anlam":"Şâhidsiz olarak bir kadına belli para (mut‘a) verip, belli zaman için beraber yaşamağı sözleşmek.","kategori":"dil","misal":"Resûlullah aleyhisselâm mut‘a nikâhını yasakladı. (Hadîs-i şerîfBuhârî, Müslim, Tirmizî) Ey müslümanlar! Kadınlar ile mut‘a nikâhı yapmanıza izin vermiştim. Fakat, şimdi bunu, Allahü teâlâ harâm etti. Kimin yanında böyle kadın varsa, onu salıversin ve ona vermiş olduğu malı geri almasın! (Hadîs-i şerîfMüslim, İbn-i Mâce) Mut‘a nikâhının harâm olduğunda bütün âlimlerin sözbirliği vardır. (elMîzânü’l-Kübrâ) Şiîlerin C…","osmanli":"نكاحى متعه"},{"kelime":"MuTAFFİF","anlam":"Eksik ölçen, tartıda hîle yapan.","kategori":"dil","osmanli":"مطفف"},{"kelime":"MuTAHHAR","anlam":"(A. Tahâret) Tâhir kılın-mış, temizlenmiş, temiz. Muhammed aley-hisselâmın lakabı.","kategori":"ibadet","misal":"Nefs, emmârelikten kurtulup, itmînâna kavu-şur. Müzekkâ ve mutahhar olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مطهر"},{"kelime":"MuTAHHİR","anlam":"Tathîr edici, temizle-yici, temizleyen.","kategori":"dil","misal":"Abdestte ve gusülde kullanılmış mâ-i müsta’mel denilen su; Hanefî, Şâfiî ve Hanbelî mezheble-rinde yalnız tâhirdir (temizdir). Fakat mutah-hir değildir. Mâlikî mezhebinde ise, hem tâ-hir hem de mutahhirdir. (el-Mîzânü’l-Kübrâ)","osmanli":"مطهر"},{"kelime":"MuTÂLEBE","anlam":"Talepte bulunma, isteme.","kategori":"dil","osmanli":"مطالبه"},{"kelime":"MÜTÂLEBE","anlam":"Talebde bu-lunma, hakkını isteme; dâvâ.","kategori":"dil","osmanli":"مطالبه"},{"kelime":"MuTASYON","anlam":"Canlıların karak-terlerini nesilden nesile aktaran genetik ma-teryalde, yani kromozom veya genlerde mey-dana gelen ve kalıcı olabilen ânî değişiklikler.","kategori":"dil","osmanli":"موتاصيون"},{"kelime":"MuTBAH","anlam":"(A. Tabh’dan) Mutfak, yemek pişirilen yer. Aslı matbâhdır.","kategori":"dil","misal":"Fakîr nafakası için, kilidi olan bir oda, mutbah ve hâlâ yetişir. (Nikâye)","osmanli":"مطبخ"},{"kelime":"MÜTE‘ASSIB (Mutaassıb)","anlam":"Te‘assub eden, dinine, mezhebine, milletine, fikrine aşırı bağlılıkla, yanlış bir şeyi müdâfaada körü körüne inâd ve ısrâr eden, haksız yere düşmanlık eden.","kategori":"fikih","osmanli":"متعصب"},{"kelime":"MÜTE‘AYYİN","anlam":"(A. Ayn’dan) Te‘ayyün eden, ta’yin edilen, belli, meydanda olan.","kategori":"dil","osmanli":"متعين"},{"kelime":"MÜTECÂVİZ","anlam":"1.Tecâvüz eden, geçen, aşan. 2.Sataşan, saldıran.","kategori":"dil","misal":"(A. Cevâz’dan)","osmanli":"متجاوز"},{"kelime":"MÜTEESSİR","anlam":"1.Tesir görmüş. 2.Teessüre kapılmış, kederli.","kategori":"dil","osmanli":"متأثر"},{"kelime":"MÜTEHAKKİM","anlam":"Tahak-küm eden, zorlayan; hâkimlik taslayan.","kategori":"dil","osmanli":"متحكم"},{"kelime":"MÜTEHARRİK","anlam":"1.Hareket eden. 2.Harekesi olan harf.","kategori":"dil","osmanli":"متحرك"},{"kelime":"MÜTEHASSİS","anlam":"Hislenen, duygulanan; insan sözüne kulak verip dinleyen.","kategori":"dil","osmanli":"متحسس"},{"kelime":"MÜTEKADDİM","anlam":"(A. Kudûm’den) Tekad-düm eden, ileri geçen, eski.","kategori":"dil","misal":"MÜTEKADDİMûN (Mütekaddimîn): متقدمون (A) Kadîm olanlar, önce gelenler. Kelâmda, İmâm-ı Gazâlî’ye; fıkıhta Şemsüleimme Hul-vânî’ye kadar gelen İslâm âlimleri.","osmanli":"متقدم"},{"kelime":"MÜTEKAVVİM","anlam":"(A. Kıymet’ten) Takav-vüm eden, kıymetlendirilen, sağlam; malî de-ğeri olan.","kategori":"dil","osmanli":"متقوم"},{"kelime":"MÜTEKAVVİM MAL","anlam":"Kıymetli, fiyatı belli; kullanılması mübâh ve mümkün olan mal.","kategori":"fikih","misal":"Bir satışın sahîh olması için malın mütekavvim olması lâzımdır. Müslümanlar için şarap, domuz ve besmelesiz kesilen veya kesmeden öldürülen hayvan, mütekavvim mal değildir. Denizdeki henüz tutulmamış balık mütekavvim mal değildir. Çünki tutulmadığı için kullanılması veya satılması mümkün değildir. (Bahr)","osmanli":"مال متقوم"},{"kelime":"MÜTEKELLİM","anlam":"1.”Söyleyici” mânâsına Allahü teâlânın isimlerinden (el-Mü- tekellim). 2.Kelâm âlimi.","kategori":"akaid","misal":"İslâmiyet’in iman bilgilerini, naklî ve aklî delillerle izah edip ispatlayan âlim. Çokluk hâli mütekellimûn (mütekellimîn) gelir.","osmanli":"متكلم"},{"kelime":"MÜTEMETTİ‘","anlam":"1.Temettu‘ eden, fay-dalanan, kâr eden. 2.Hac aylarında umre ya-pıp, ihrâmdan çıktıktan sonra memleketine gitmeyerek, sonra tekrar ihrâma girerek hac yapan.","kategori":"ibadet","misal":"(Bkz. Hac) Kârin ve mütemetti’ hacıların şükür kurbanı kesmesi vâcibdir. Kesmeyeceklerse, Zilhicce’nin yedi, sekiz ve dokuzuncu günlerinde ve bayram-dan sonra yedi gün daha oruç tutmaları lâzım olur. Hepsi on gün olur. (Mevkûfât)","osmanli":"متمتع"},{"kelime":"MÜTERCİM","anlam":"Tercüme eden, yazıyla bir dilden başka bir dile çeviren.","kategori":"dil","osmanli":"مترجم"},{"kelime":"MÜTEŞÂBİH","anlam":"1.Birbirine benzeyen iki şeyden her biri. 2.Mânâsı açık olmayan lafz.","kategori":"dil","misal":"Kur’ân-ı kerîm âyetleri ve hadîs-i şerîfler iki nev’dir. Bunların bir kısmının mânâsı açık-tır. Bunlar muhkemdir. Bir kısmının mânâsı ise, açıkça anlaşılmaz. Bunlar, ayrıca tefsire, izaha muhtaçtır. Bunlara müteşâbih adı ve-rilir. Bunları tefsir etmek mecburiyeti, İslâm dininde ictihâd müessesesinin kurulmasına sebeb olmuştur. Sana Kur’ân’ı indiren O’dur (Allah’tır). Bu-nun bir kısım âyetleri açık ve kesindir. Bun-lar Kur’ân’ın esâsıdır. Diğer bir kısım âyetler de vardır ki müteşâbihdir. İşte kalblerinde şüphe bulunanlar, fitne aramak ve te’vîline gitmek için Kur’ân’ın müteşâbih âyetlerine uyarlar. Hâlbuki, o müteşâbihin te’vîlini yalnız Allah bilir. İlimde derinleşmiş olan kimseler ise; “Biz ona (müteşâbihe) inandık. Açık ve kapalı bütün âyetler Rabbimiz ta-rafındandır” derler. Bunları ancak akılları tam olanlar iyice düşünür. (Âl-i İmrân sûresi: 7) Muhkem olan (mânâsı açık olan âyetlere) uyunuz. Müteşâbihâta inanınız. Bunlara inandık hepsini Rabbimiz bildirmiştir de-yiniz. (Hadîs-i şerîf-Hâkim) Müteşâbih iki kısımdır. 1) Lafzı (sözü) mü-teşâbih olan âyetler olup yirmi dokuz sûrenin evvellerindeki Sâd, Tâhâ, Elîf lâm mîm, Yâsîn gibi harflerdir. 2) Mânâsı müteşâbih olan âyet-lerdir ki, görünen mânâsını vermek günah olur. Meselâ İsrâ sûresinde; “Allah’ın eli onların el-lerinin üstündedir.” meâlindeki âyet-i kerîme gibi. Allahü teâlâ bununla neyi murâd ediyor ise öylece inandım demelidir. Bunun mânâ-sını ben anlayamam, ancak Allahü teâlâ bi-lir demek en iyi yoldur. Müteşâbih âyetlerin mânâsını ancak Allahü teâlâ ve Allahü teâlâ-nın kendilerine İlm-i ledün ihsân ettiği derin âlimler, bildirdildiği kadar anlayabilir. Meselâ tefsir âlimleri müteşâbihâttan olan “el” kelime-sine “kudret, gücü yetmek” mânâsını vermiş-lerdir. (Kâdızâde-Âmentü Şerhi)","osmanli":"متشابه"},{"kelime":"MÜTEŞÂBİHÂT","anlam":"1.Birbirine ben-zeyenler. 2.Mânâsı açık olmayan nasslar.","kategori":"dil","misal":"Mü-teşâbih’in çokluk hâli.","osmanli":"متشابهات"},{"kelime":"MÜTEŞEKKİL","anlam":"Teşekkül et-miş, şekillenmiş.","kategori":"dil","osmanli":"متشكل"},{"kelime":"MÜTESELSİLEN","anlam":"Zincirleme, sı-rayla, birbiri peşi sıra.","kategori":"dil","misal":"Ortaklar, şirketin borçlarından ve taahhüdle-rinden müteselsilen ve bütün malları ile mes’ûl-dürler. (İbni Âbidîn)","osmanli":"متسلسلا"},{"kelime":"MÜTEVÂRİS","anlam":"Tevârüs eden, miras kalan.","kategori":"miras","misal":"Minârede ve Cum‘a hutbesi okunacağı zaman, birkaç müezzinin birlikte ezân okumalarına (Ezân-ı Cavk) denir. Sesin çoğalması için, bir ağızdan okumaları, mütevâris olduğu için, yani asrlardan beri yapıldığı için, sünnet-i hasenedir, câizdir. (İbni Âbidîn)","osmanli":"متوارث"},{"kelime":"MÜTEVASSIT","anlam":"1.Tavassut eden, aracı olan. 2.Ortada olan.","kategori":"dil","osmanli":"متوصط"},{"kelime":"MÜTEVÂTÎ","anlam":"Birbirine benzeyen, bir cins içindeki ferdlerin hepsinde müsâvî, eşit mikdarda bulunan sıfat, hususiyet.","kategori":"akaid","osmanli":"متواطى"},{"kelime":"MÜTEVÂTİR","anlam":"Tevâtür ile bildirilmiş; her devirde yalan üzerinde ittifak etmesi câiz olmayan bir topluluk tarafından haber verilen şey.","kategori":"fikih","osmanli":"متواتر"},{"kelime":"MÜTEVÂTİR HADÎS","anlam":"Birçok sahâbînin Resûl-i ekremden ve başka birçok kimsenin de bunlardan işittiği ve kitaba yazılıncaya kadar, böyle hep, çok kimselerin haber verdiği hadîs-i şerîfler.","kategori":"hadis","misal":"(Bkz. Hadîs)","osmanli":"حديث متواتر"},{"kelime":"MÜTEVÂZI‘","anlam":"Tevâzu’ eden, alçak gönüllü.","kategori":"tasavvuf","osmanli":"متواضع"},{"kelime":"MÜTEVECCİH","anlam":"Teveccüh eden, bir tarafa yönelen.","kategori":"dil","misal":"Simâ’ ancak, Allahü teâlâya müteveccih olan-lara câizdir. (Dürrü’l-Me’ârif)","osmanli":"متوجه"},{"kelime":"MÜTEVELLÎ","anlam":"Bir vakfın işlerini şer’î hükümler ve vakfın şartları dâiresinde idare etmek üzere, vakfeden veya hâkim tarafından tâyin edilen kimse.","kategori":"ibadet","misal":"Mahalle câmisinin gelirini toplaması, tâmirini, masraflarını idâre etmesi için mahalle halkının bir mütevellî tâyin etmesi câiz ve lâzımdır. (İbni Âbidîn) Vakfeden kimse bir mütevellî tâyin edip, malı buna teslim eder. Bir vakfın bir nâzırı ve bir mütevellîsi olsa, mütevellî, nâzırın haberi olmadan bir şey yapamaz. (İbni Âbidîn)","osmanli":"متولى"},{"kelime":"Mutlak Bey‘","anlam":"Ayn olan malı, deyn karşılığı satmak; yani en azından mebî’in tayin edildiği satış.","kategori":"muamelat","misal":"Kitaplarda bey’ dendiği zaman bu anlaşılır.","osmanli":"بيع مطلق"},{"kelime":"Mutlak Fenâ","anlam":"Allahü teâlâdan başka her şeyin kalbden çıkıp, isimlerinin bile unu-tulması. (Bkz. Fenâ)","kategori":"akaid","misal":"Allahü teâlâdan başka şeylere kul olmaktan büs-bütün kurtulabilmek için, mutlak fenâya kavuş-mak lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"فنا مطلق"},{"kelime":"Mutlak Müctehid","anlam":"Kur’ân-ı kerîm ve hadîs-i şerîflerden kendi ictihâd usûlüne göre hüküm çıkarabilen âlim.","kategori":"fikih","misal":"(Bkz. Müctehid) Fıkıh âlimleri yedi tabaka, yedi derecedir. En yüksek derecesi dinde müctehid olanlardır. Bunlara mutlak müctehîd denir. Dört mezheb imâmları mutlak müctehîdlerdir. (Mecmûâ-i Zühdiyye)","osmanli":"مجتهد مطلق"},{"kelime":"Mutlak Nezr","anlam":"Şarta bağlı olmayan adak.","kategori":"fikih","misal":"Allahü teâlâ için bir sene oruç tutacağım demek mutlak nezr olup, bunu söylerken adak kasdı olmasa da, söz arasında dilinden çıksa bile, yapması vâcibdir. Çünki, talakta (boşamada) ve adakta niyetsiz, düşünmeden söylemek, ciddî isteyerek söylemek gibidir. Hattâ; “Allahü teâlâ için bir gün oruç tutmak üzerime borç olsun” diyeceği yerde; “Bir ay oruç tutmak” diye ağzından çıksa, bir ay tutması lâzım olur. (Dürrü’l-Muh…","osmanli":"نذر مطلق"},{"kelime":"Mutlak Su","anlam":"Başına başka bir sıfat getirilmeksizin, yaratıldıkları hâl üzere bulunan sular.","kategori":"akaid","misal":"Yağmur, kar, deniz, göl, kuyu ve ırmak suları mutlak sular olup, hem temiz hem de temizleyicidir. İçilir, abdest ve gusl alınır. (İbni Âbidîn)","osmanli":"صو مطلق"},{"kelime":"MuTTASIL","anlam":"1.İttisâl eden, ulaşan, kavuşan, bitişen. 2.Aralıksız, hiç dur-madan, biteviye.","kategori":"dil","misal":"(A. Vasl’dan)","osmanli":"متصل"},{"kelime":"MuTTASIL HADÎS","anlam":"İsnâdı ke-sintisiz, bütün râvîleri bildirilen hadîs-i şerîf.","kategori":"hadis","osmanli":"حديث متصل"},{"kelime":"MÜTTEFİK","anlam":"İttifak eden, anlaşan.","kategori":"dil","osmanli":"متفق"},{"kelime":"MÜTTEKÎ","anlam":"Takvâ sahibi, Allahü teâlâdan korkup, haramlardan, dinde yasak edilen şeylerden sakınan.","kategori":"akaid","misal":"Azâbıma dilediğim kimseyi uğratırım. Merhâmetim, her şeyi kaplamıştır. Bu rahmetim (âhirette), müttekîlere, zekâtlarını verenlere ve bizim âyetlerimize îmân edenleredir. (A’râf sûresi: 166) Müttekîler ve fakihlerin meclisinde oturmak berekettir, dini kuvvetlendirir, insanın nurunu arttırır. (Hadîs-i şerîfİbni Neccâr, Hatîb) Müttekîlerin verâ’ı; harâm ve şüpheli olmayan fakat, helâl olup, şüpheli veya harâma sebeb ol…","osmanli":"متقى"},{"kelime":"MuVÂCEHE-İ SEÂDET","anlam":"Resûlullah aleyhisselâmın kabrinin bulunduğu Hücre-i Seâdet’in kıble tarafında ziyâret sırasında önünde durulan duvar.","kategori":"ibadet","misal":"Muvâcehe-i Şerîfe.","osmanli":"سعادت مواجههء"},{"kelime":"MuVAFFAK","anlam":"Ele geçirmiş, elde etmiş, başarmış, işi rast gitmiş; Allah’ın yardımıyla gâyesine ulaşmış.","kategori":"akaid","osmanli":"موفق"},{"kelime":"MuVAFFAKİYYET","anlam":"Ele geçirme, elde etme, başarma; Allah’ın yardı-mıyla gâyesine ulaşma.","kategori":"akaid","osmanli":"موفقيت"},{"kelime":"MuVÂFIK","anlam":"Uygun, yerinde, münâsib.","kategori":"dil","misal":"Bedr esirlerinin katline Fârûk radıyallahü anh hükmetmişti. Vahy, Fârûk’un re’yine muvâfık geldi. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"موافق"},{"kelime":"MuVAHHİD","anlam":"1.Birleyici, birleştirici. 2.Tevhid inancına sahip, Allahü teâlânın birliğine inanan. 3.Tasavvufta, Allahü teâlâdan başka bir şey görmeyen, kendini ve başkalarını unutan.","kategori":"akaid","misal":"(A. Vahdet’ten) (Bkz. Tevhîd) Bir kimse, başkaları görmek için ibâdet eder veya Allahü teâlâ için eder ammâ başkasının görmesi de hoşuna giderse veya ibâdetinde baş-kasından bir karşılık, meselâ bir âferin sözü bek-lerse, o kimse şirkten kurtulmuş ve hâlis mu-vahhid olmaz. (Mektûbât-ı İmâm-ı Rabbânî) Muvahhidlerin gönlüne Allah’tan başka bir şey gelmez. Kulakları, Allah’tan başka bir şey duy-maz. Gözleri, Allah’tan başka bir şey görmez. Her ne duyar ne görürse, ondan ibret alır ve Allahü teâlânın büyüklüğünü düşünerek, O’na olan bağlılıkları artar. (Kimyâ-i Seâdet)","osmanli":"موحد"},{"kelime":"MuVAKKAT","anlam":"Belli bir vakte bağlı, geçici. Yedi kadın ile muvakkat olarak evlenilemez. Aradaki sebeb kalkınca, evlenmesi helâl olur. Bunlardan beşi, nikâh sebebi ile harâmdır. Bir adam, zevcesinin kızkardeşleri, halası, teyzesi veya kardeşinin kızı ile evlenemez. Bunlar, süt ile olunca da haramdır. Zevcesi ölür veya boşa-nırsa, evlenebilir. Müslüman oluncaya kadar müş-rik kadınla evlenilmez. Hür kadın ile evli iken, câriye ile de nikâh kıyılamaz. (Ni’met-i İslâm)","kategori":"dil","osmanli":"موقت"},{"kelime":"Muvakkat Nikâh","anlam":"Geçici nikâh. Bir adamın, yüz sene de olsa, belli bir zaman sonra hanımını boşamağı şart koşarak yapılan nikâh.","kategori":"dil","misal":"Söylemeyip, yalnız kalbinden geçirse, nikâh sahîh olur. (Bkz. Mut‘a Nikâhı) Muvakkat nikâh, dört mezhebde de haramdır. (elMîzânü’l-Kübrâ)","osmanli":"نكاح موقت"},{"kelime":"MÜVAKKİT","anlam":"MÜVÂLÂT: موالات (Bkz. Muvâlât) MÜVÂRESE: موارثه (A) Birbirinden miras alma. MÜVÂSÂT: مواسات (A) Yumuşak davranmak,","kategori":"miras","misal":"iyi geçinmek.","osmanli":"موقت"},{"kelime":"MuVATTÂ’","anlam":"İmâm-ı Mâlik bin Enes’in yazdığı hadîs kitabı.","kategori":"hadis","misal":"Muvattâ’, muvâfakat edilmiş mânâsına gelir. İmâm Mâlik, hazırladığı bu kitabı, üstadlarına arzedip, onların muvâfakatini aldıktan sonra bu ismi vermiştir. İslâm tarihinde yazılıp bugüne intikal eden eski kitaptır.","osmanli":"موطاء"},{"kelime":"MuVÂZÎ","anlam":"Paralel. MuVAZZAF: موظف (A) Vazifeli, memur. MuVAZZAH: موضح (A) Tavzih edilmiş, açık,","kategori":"dil","misal":"açıklanmış.","osmanli":"موازى"},{"kelime":"MÜYESSER","anlam":"Kolay gelen, kolaylıkla olan.","kategori":"dil","misal":"Bütün günahlara tövbe etmek nasip olur ve vera’ ile takvâ müyesser olursa, büyük ni’met, yüksek devlet ele geçmiş olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ميسر"},{"kelime":"MuZAFFER","anlam":"Zafer, üstünlük kazanmış, üstün.","kategori":"akaid","osmanli":"مظفر"},{"kelime":"MÜZÂKERE","anlam":"Bir iş hak-kında konuşma.","kategori":"dil","misal":"Din dersi müzâkere edenlere selâm verilmez. (İbni Âbidîn)","osmanli":"مذاكره"},{"kelime":"MÜZÂRE‘A","anlam":"Zirâat şirketi. Harman yapılan ürünleri yetiştirmek için, tarla yani toprak birinden, çalışma, işçilik diğerinden olmak ve mahsûlü sözleşilen nisbette aralarında paylaşmak üzere, kurulan şirket.","kategori":"muamelat","misal":"Müzâre’aya verilmiş bir toprağı, toprak sahibi başkasına satarsa, alan kimse toprak kurtuluncaya yani mahsûl kaldırılıncaya kadar bekler. Yâhud mahkeme yolu ile satışı bozdurur. (İbni Âbidîn)","osmanli":"مزارعه"},{"kelime":"MÜZDELİFE","anlam":"Mekke-i Mükerreme’de, Minâ ile Arafât arasında bulunan, Âdem aleyhisselâmla Hazret-i Havvâ’nın yeryüzünde ilk buluştuğu rivâyet olunan yer.","kategori":"dil","misal":"Hac esnâsında Arafât’tan dönüşte Müzdelife’de bir müddet durmak vâcibdir. (Bahr) Arefe gecesi Müzdelife’de yatmak sünnettir. Arafât’tan Müzdelife’ye gelip burada yatsı vakti olunca, akşam ve yatsının farzları birleştirilerek cemâat ile kılınır. Akşam namazını Arafât’ta veya yolda kılanların Müzdelife’de tekrar cemâat ile veya yalnız olarak yatsı ile birlikte kılması lâzımdır. Müzdelife’de fecr ağardıktan sonra vakfe…","osmanli":"لفه مزد"},{"kelime":"MÜZEKKÂ","anlam":"1.Tezkiye edil-miş, temizlenmiş. 2.Allah’ın adı anılarak ke-silmiş hayvan. 3.Zekâtı verilmiş.","kategori":"ibadet","misal":"(A. Zekât’dan)","osmanli":"مزكى"},{"kelime":"MÜZEYYEN","anlam":"(A. Zînet’den) Ziynetlendi-rilmiş, süslenmiş.","kategori":"dil","osmanli":"مزين"},{"kelime":"MÜZMİN","anlam":"(A. Zemân’dan) Üzerinden za-man geçmiş, eskimiş, kronik.","kategori":"dil","osmanli":"مزمن"},{"kelime":"MÜZZEMMİL SûRESİ","anlam":"Kur’ân-ı kerîmin yetmiş üçüncü sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Yirmi âyet-i kerîmedir. İlk âyet-i kerîmede geçen elMüzzemmil kelimesinden dolayı Sûretü’l-Müzzemmil denilmiştir. Müzzemmil, örtünüp bürünen demektir. (Mefâtihü’l-Gayb) Kim Müzzemmil sûresini okursa, Allahü teâlâ ondan dünyada ve âhirette zorluğu kaldırır. (Hadîs-i şerîfKâdı Beydâvî Tefsîrî)","osmanli":"سى سوره مزمل"},{"kelime":"NÂB","anlam":"Ön dişlerin yanlarındaki altlı üstlü uzun ve sivri dört diş, köpek dişi.","kategori":"dil","osmanli":"ناب"},{"kelime":"NÂDÂN","anlam":"Câhil; terbiyesi kıt, kaba. Devr-i zamane cünbüşi nâdânlık üzredir. Nâdân komaz ki merdüm-i dânâ huzur ede. (Bâkî)","kategori":"dil","misal":"[Zamanın işleri câhillerin elindedir; bu yüz-den bilgin kişinin huzur içinde olmasına câ-hiller engel olur.]","osmanli":"نادان"},{"kelime":"NÂDİM","anlam":"(A. Nedâmet’den) Nedamet du-yan, pişman olan.","kategori":"dil","osmanli":"نادم"},{"kelime":"NÂDİR","anlam":"Seyrek, ender bulunur.","kategori":"tasavvuf","osmanli":"نادر"},{"kelime":"NÂF","anlam":"1.Göbek. 2.Orta.","kategori":"dil","osmanli":"ناف"},{"kelime":"NAFAKA","anlam":"İnsanın yaşayabilmesi için, yiyecek, giyecek ve ev gibi lâzım olan şeyler.","kategori":"dil","misal":"Farzları yapamayacak kadar az yimek, câiz değildir. Kendinin ve çolukçocuğunun nafakasını kazanacak ve borçlarını ödeyecek kadar, çalışıp kazanmak farzdır. (elİhtiyâr) Allahü teâlâ, kullarına ıyâlim demiş yani çok merhametli olduğu için, herkesin rızkını nafakasını kendi üzerine almıştır. Allahü teâlâ bu ıyâlinden birkaçının rızıkları, nafakaları ve bunların yetişmeleri, rahat yaşamaları için, bir kulunu görevlendir…","osmanli":"نفقه"},{"kelime":"NÂFİ‘","anlam":"1.Menfaatli, faydalı. 2.Allahü teâlânın sıfatlarından (en-Nâfi’).","kategori":"akaid","osmanli":"نافع"},{"kelime":"NÂFİLE","anlam":"1.Fazlalık. 2.Farz ve vâcib olmayan, yapana sevab kazandıran ibâdetler.","kategori":"fikih","misal":"Beş vakit namazın sünnetleri ve diğer vâcib olmayan namazlar hep nâfiledir. Müekked olan ve olmayan bütün sünnetler nâfiledir. (İbni Âbidîn) Farz ibâdet yanında, nâfile ibâdetlerin hiç kıymeti yoktur. Deniz yanında damla bile değildir. Mel’ûn şeytân, mü’minleri aldatarak, farzları küçük gösteriyor. Nâfile ibâdetlere yol gösteriyor. Zekât verdirmeyip, nâfile sadakaları güzel gösteriyor. Hâlbuki zekât niyetiyle fakire…","osmanli":"نافله"},{"kelime":"NÂFİZ","anlam":"1.Nüfuz eden, delen, delip ge-çen, geçerli, içeriye giren, işleyen. 2.Tesir ya-pan, sözü geçen. 3.Sahih, muteber.","kategori":"dil","misal":"Bâliğ olan akıllı insanın alış-verişi her zaman nâfizdir. Bâliğ olmayan akıllı çocuğun alış-ve-rişi, ancak velî veya vasîsinin izin vermesi ile nâfiz olur. (İbni Âbidîn)","osmanli":"نافذ"},{"kelime":"NAĞME","anlam":"Sesi mûsikî perdelerine uy-durmak.","kategori":"dil","misal":"Kur’ân-ı kerîmi nağme ile, yani sesi mûsikî per-delerine uydurarak okumak, harfleri bozmaz ise, âlimler mekrûh demiştir. Zîrâ fâsıkların nağmelerine teşebbühdür. Eğer harfler değişir ise, harâmdır. (Halebî)","osmanli":"نغمه"},{"kelime":"NÂHİYE","anlam":"1.Yan taraf, kenar. 2.Civar, çevre. 3.Büyükçe köy.","kategori":"dil","osmanli":"ناحيه"},{"kelime":"NAHL SûRESİ","anlam":"Kur’ân-ı kerîmin on altıncı sûresi.","kategori":"dil","misal":"Son üç âyeti Medîne’de, diğer âyetleri Mekke’de nâzil oldu. Yüz yirmi sekiz âyet-i kerîmedir. Altmış sekizinci âyette bal arısından söz edildiği için, Sûretü’n-Nahl denilmiştir. Sûrede; Allahü teâlânın kudretini gösteren yaratıklardan bahsetmek sûretiyle insanlar gafletten uyanmaya da’vet edilmekte, bu âlemdeki nice varlıkların insanlara hizmetçi ve fayda verici olduğu bildirilmekte, insanların seçkin bir varlığa sa…","osmanli":"سى سوره نحل"},{"kelime":"NAHR","anlam":"1.Boğazlama. 2.Kurbanlık deveyi göğsü üstünden (evdâcını yani iki büyük damarını) kesmek.","kategori":"ibadet","misal":"Deveyi kesmekte sünnet olan nahrdır. Sığır ve koyun zebhedilir. Deveyi zebh, sığırı ve koyunu nahr etmek mekrûh olur. (Ni’met-i İslâm)","osmanli":"نحر"},{"kelime":"NÂHûR","anlam":"İbrâhim aleyhisselâmın amcası ve üvey babası olan Âzer’in asıl ismi.","kategori":"dil","osmanli":"ناخور"},{"kelime":"NAHV","anlam":"Cümle bilgisi. Kelimelerin cümle içinde fiil, fâil (özne), mef ’ûl (nesne, tümleç) olma gibi hâllerinden ve buna göre sonlarının aldıkları i’râbdan (harekelerden) bahseden ilim.","kategori":"dil","misal":"(Bkz. İlm-i Nahv)","osmanli":"نحو"},{"kelime":"NÂİL","anlam":"Muradına eren, ele ge-çiren, kavuşan.","kategori":"dil","misal":"Ramezân-ı şerîf ayında oruc tuttuğun zaman bütün a’zâlarınla tut ki, orucun oruc olsun ve orucun fazîletine ve derecesine nâil olasın. (Ey Oğul İlmihali)","osmanli":"نائل"},{"kelime":"NAKD","anlam":"1.Altın veya gümüş basılı para. 2.Metal para.","kategori":"dil","misal":"Nakit.","osmanli":"نقد"},{"kelime":"NAKDEYN","anlam":"“İki nakit” mânâsına ba-sılmış para hâlindeki altın ve gümüş için kul-lanılan tabir.","kategori":"dil","misal":"Fülûs denilen bakır, bronz paralar (ve kâğıt li-ralar) aynı sayıda (yani itibârî kıymetleri aynı olarak) kendi cinsleri veya altın, gümüş karşılı-ğında satılınca dâimâ semen olurlar. Nakdeyn karşılığında satılınca fâizin iki şartı da yok ise de iki karşılıktan birisinin, ayrılmadan önce kabz edilmesi lâzımdır. (İbni Âbidîn)","osmanli":"نقدين"},{"kelime":"NAKİ‘","anlam":"Hurma veya kuru üzüm soğuk suda bırakılıp şekeri suya çıktıktan sonra sü-zülerek elde edilen içki.","kategori":"dil","misal":"Kuru üzümden yapılan naki‘nin tadı keskin olursa, damlası dahi haram olur. Gazlanmaz ve tadı keskin olmazsa, içilmesi sözbirliği ile helâl olur. (İbni Âbidîn)","osmanli":"ناقع"},{"kelime":"NAKÎB","anlam":"1.Bir kavmin veya cemaatin reisi veya vekili. 2.Tekkede şeyhin yardımcısı. 3.Müfettiş.","kategori":"dil","osmanli":"نقيب"},{"kelime":"NÂKIL","anlam":"Nakleden, birinden duyduğunu veya okuduğu şeyi anlatarak bildiren.","kategori":"dil","misal":"Fıkıh usûlü âlimlerine göre, müftînin mücte-hid olması lâzımdır. Müctehid olmayıp, mukal-lid bir âlime müftî denilmesi mecâzîdir, hakîkî olarak değildir. Bunlar nâkıldır. Nâkıller, fetvâ-ları, meşhûr fıkıh kitaplarından alır. Bu kitap-lar, meşhûr olan mütevâtir haberler gibi kıy-metlidir. (İbni Âbidîn)","osmanli":"ناقل"},{"kelime":"NÂKİL","anlam":"Nükûl eden, dâvâda kendisine teklif edilen yemini etmekten kaçınan.","kategori":"dil","osmanli":"ناكل"},{"kelime":"NÂKIS","anlam":"Eksik, noksan, kusurlu. Allahü teâlânın zâtında, sıfatlarında ve fiille-rinde ortağı ve benzeri yoktur. O’nda kemâl sı-fatlar olmasaydı, eksik ve âciz olurdu. Âciz ve nâkıs olmak, Allahü teâlâ hakkında muhâldir, imkânsızdır. (Miftahü’l-Cenne)","kategori":"akaid","misal":"Tasavvuf yolunda çalışmak isteyenin önce i’tikâ-dını, inancını, Ehl-i sünnet ve’l-cemâat âlimle-rinin bildirdiklerine göre düzeltmesi lâzımdır. Sonra herkese lâzım olan fıkıh bilgilerini öğren-melidir. Bundan sonra bu öğrendiklerini yap-malıdır. Ondan sonra her zaman Allahü teâlâyı zikretmeli, anmalıdır. Fakat zikir yapmasını kâ-mil ve mükemmil bir zâttan öğrenmesi şarttır. Nâkıs olandan öğrenirse, kemâle eremez, mak-sada ulaşamaz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ناقص"},{"kelime":"NAKKÂŞ","anlam":"(A. Nakş’dan) Nakış yapan, süslü desen ve resimler yapan.","kategori":"dil","osmanli":"نقاش"},{"kelime":"NAKL","anlam":"Bir şeyi başka bir yere götürme; taşıma, aktarma, intikal ettirme.","kategori":"dil","osmanli":"نقل"},{"kelime":"NAKL-İ SADÂ","anlam":"“Sesin nakli” mânâ-sına ciğerden gelen havanın ses tellerini (ip-likçiklerini), bunların da su ve hava molekül-lerini titreştirerek muntazam küreler hâlinde dalgalarla yayması.","kategori":"dil","osmanli":"صداء نقل"},{"kelime":"NAKS","anlam":"Noksanlık, eksiklik; eksiltme, azaltma.","kategori":"dil","osmanli":"نقص"},{"kelime":"NAKŞ","anlam":"1.Resim. 2.Süsleme. 3.İpekle, sırma ile işleme.","kategori":"dil","osmanli":"نقش"},{"kelime":"NAKŞÎ","anlam":"Nakşîbendiyye tarikatine mensub olan.","kategori":"tasavvuf","misal":"Nakşîbendî.","osmanli":"نقشى"},{"kelime":"NAKŞİBENDİYYE","anlam":"Behâeddîn-i Buhârî hazretlerinin tasavvuftaki yolu.","kategori":"tasavvuf","misal":"Nakşibendiyye yolunun büyükleri ile beraber olanda, huzur ve cem’iyyet (topluluk) ve dünyaya şuursuzluk ve Allahü teâlânın cezbeleri hâsıl olur. Kalbine, ruhuna birçok şeyler ihsân edilir. (Mektûbât-ı İmâm-ı Rabbânî) Tarikat-i Nakşibendiyye, sünnete uymak ve bid‘atlerden kaçınmaktan ibarettir. (Mektûbât-ı Ma’sûmiyye) Nakşibendiyye, nasıl kafile sürücüdür? Kafilesini gizlice maksada götürür.","osmanli":"نقشبنديه"},{"kelime":"NÂKûS","anlam":"Hristiyanlarda ibâdet vaktini bildirmek üzere kilisede çalınan çan.","kategori":"dil","osmanli":"ناقوس"},{"kelime":"NÂM","anlam":"İsim, ad; şöhret, lâkab.","kategori":"dil","osmanli":"نام"},{"kelime":"NÂMAHREM","anlam":"1.Evlenilmesi haram olmayan. 2.Kadının yanına tesettürsüz çıkamayacağı, başbaşa kalmasının haram olacağı kişi. 3.Yabancı.","kategori":"dil","misal":"Mahrem olmayan. Namaz kılan kimsenin yanına, aynı İmâma uyan bir kadın durursa, ister nâmahrem ol-sun, ister vâlide veya hemşire gibi mahrem ol-sun, gerekse zevcesi veya câriyesi olsun, erkeğin namazını ifsâd eder. (İbni Âbidîn)","osmanli":"نامحرم"},{"kelime":"NAMAZ (Nemâz)","anlam":"Duâ, hayırla duâ; Müslümanların yaptıkları, tekbir ile başlayıp selâm ile son bulan, belli fiil ve sözleri ihtiva eden ibadet, Allah’a karşı tesbih, ta’zim ve şükrün ifadesi.","kategori":"ibadet","misal":"Belli zamanlarda namaz kılmak, mü’minlere farz oldu. (Nisâ sûresi: 102) Namaz dinin direğidir. Namaz kılan kimse, dinini kuvvetlendirir. Namaz kılmayan, elbette dinini yıkar. (Hadîs-i şerîfDeylemî) Namaza mâni olan, güçlük çıkaran vazifede bereket olmaz. Namaza elverişli olan vazifelerde bereket vardır. (Kimyâ-i Seâdet)","osmanli":"نماز","alternatif":["nemaz","salat","salah"]},{"kelime":"NÂMERD","anlam":"Merd olmayan, alçak; korkak.","kategori":"dil","osmanli":"نامرد"},{"kelime":"NÂMÎ","anlam":"Bir şeyin, bir malın ticaret veya yavrulama yoluyla nemâlı, artıcı olması.","kategori":"muamelat","osmanli":"نامى"},{"kelime":"NÂMûS","anlam":"1.Irz, edeb, ar, hayâ. 2.Kanun, nizam. 3.Temizlik, doğruluk.","kategori":"tasavvuf","osmanli":"ناموس"},{"kelime":"NÂN","anlam":"Ekmek.","kategori":"dil","osmanli":"نان"},{"kelime":"NÂR","anlam":"1.Ateş. 2.Cehennem.","kategori":"akaid","misal":"Ameli ve iyiliği ile kim dünya hayâtını ve zînetini isterse, onlara dünyada güzel amellerinin karşılığını bol bol veririz. Ecirlerinden hiçbir şey eksik bırakılmaz. (Fakat) onlar için âhirette, karşılık olarak, sâdece nâr vardır. (Hûd sûresi: 15) Kalbinde hardal tânesi kadar îmân olan hiçbir kimse nâra girmez; kalbinde hardal tânesi kadar kibr (yâni küfr) bulunan hiçbir kimse de Cennet’e girmez. (Hadîs-i şerîfMüslim)","osmanli":"نار"},{"kelime":"NARH","anlam":"Çarşıda pazarda satılan her türlü mal için hükûmet tarafından konulan fiyat. Si’r. Kâr haddi.","kategori":"dil","misal":"Medîne-i Münevvere’de pahalılık oldu. Yâ Resû-lallah fiyatlar yükseliyor. Bize narh koyunuz de-nildi. Resûlullah efendimiz; “Fiyatları takdir eden Allahü teâlâdır. Rızkı genişleten, da-raltan, gönderen yalnız O’dur. Ben Allahü teâlâdan bereket isterim” buyurdu. (Hadîs-i şerîf- Ebû Dâvud, Tirmizî, Nesâî) Esnafın hepsi fiyatları, fâhiş olarak yani mal oluş fiyatının iki misline arttırdığı, millete za-rar ve zulüm hâline geldiği zaman, hükûme-tin, tüccarlara danışarak uygun bir narh koy-ması câiz (uygun) olur. (İbni Âbidîn)","osmanli":"نرخ"},{"kelime":"NÂRÎ","anlam":"1.Ateşe mensub; ateşle alâkalı. 2.Cehennemlik. 3.Cin, peri.","kategori":"akaid","osmanli":"نارى"},{"kelime":"NÂS","anlam":"İnsanlar. Hareket mânâsına “nevs” veya unutmak mânâsına “nisyân”dan.","kategori":"dil","misal":"İnsanların göğüslerine dâimâ vesvese veren o sinsi insan ve cin şeytânının şerrinden Nâ-sın Rabbine, insanların melîkine, insanların mâbûduna sığınırım, de! (Nâs sûresi: 1-6)","osmanli":"ناس"},{"kelime":"NASÂRÂ","anlam":"Îsâ aleyhisselâma inananlar, İsevîler, Hristiyanlar.","kategori":"dil","misal":"Şüphe yok ki, daha önce peygamberlere îmân edenler Yahudiler ve Nasarâ ve Sâbiîler olsun bunlardan her kim Allah’a ve âhiret gününe îmân eder ve Hazret-i Muhammed’in dini üzerine sâlih bir amel işlerse, elbette bunların Rableri katında mükâfâtları vardır. Onlara bir korku yoktur ve onlar mahzûn da olacak değillerdir. (Bakara sûresi: 62) İsrâiloğulları yetmiş bir fırkaya ayrılmıştı. Bunlardan yetmişi Cehennem’e gidip…","osmanli":"نصارى"},{"kelime":"NÂŞÎ","anlam":"Neşet eden, ileri gelen; ötürü, dolayısıyla, sebebiyle.","kategori":"fikih","osmanli":"ناشى"},{"kelime":"NASÎB","anlam":"1.İsâbet eden, ele geçen, ka-vuşulan. 2.Hisse, kısmet.","kategori":"fikih","misal":"Kim iyi bir işe aracılık ederse onun da o iş-ten bir nasibi olur. Kim kötü bir işe aracılık ederse, onun da ondan bir nasibi olur. Al-lah her şeyin karşılığını vericidir. (Nisâ sû-resi: 85) Namazını mescidde kılan, evi için de bir nasip ayırsın. Zira Allah ona evinde kıldığı namazdan da hayır vericidir. (Ha-dîs-i şerîf-Müslim) Nasîbindir gezdiren yer yer seni, Arşa çıksan, âkıbet yer, yer seni. (İbni Kemâl) Sunulmadı bana kahve deme sen, Nasîbin var ise gelir Yemen’den. (Nâbi)","osmanli":"نصيب"},{"kelime":"NÂSİH","anlam":"Nesheden. Daha önce âyet-i kerîme veya hadîs-i şerîf ile bildirilen bir hükmü (mensûhu) kaldıran başka bir âyet-i kerîme veya hadîs-i şerîf.","kategori":"hadis","osmanli":"ناسخ"},{"kelime":"NASÎHAT","anlam":"İbretli söz, ders, tavsiye, ihtar, öğüt.","kategori":"dil","misal":"Muhakkak ki, Allahü teâlâdan korkan na-sihat alacaktır. (A’lâ sûresi: 10) Din nasihat-tir. (Hadîs-i şerîf-Buhârî, Müslim) Nasihat vermek kolaydır. Nasihati kabul etmek güçtür. Çünki, nefislerine uyanlara, dünya zevk-lerinin peşinde koşanlara, nasihat acı; haram-lar ise tatlı gelir. (Kimyâ-i Seâdet)","osmanli":"نصيحت"},{"kelime":"NÂSIR","anlam":"1.Nusret eden, yardım eden, yardımcı. 2.Allahü teâlânın sıfatlarından (en-Nâsır).","kategori":"akaid","misal":"Allahü teâlâ nâsırların en hayırlısıdır. (Âl-i İmran sûresi: 150)","osmanli":"ناصر"},{"kelime":"NASÎR","anlam":"1.Nusret eden, çok yardım eden, yardımcı. 2.Allahü teâlânın sıfatların-dan (en-Nasîr).","kategori":"akaid","misal":"Allahü teâlâ ne güzel mevlâ (efendi) ve ne güzel nasîrdir. (Hac sûresi: 78)","osmanli":"نصير"},{"kelime":"NÂŞİZE","anlam":"Nüşûz eden, baş kaldıran. Ko-casının izni olmaksızın evinden kaçan ve ken-disini zevcinden haksız yere men eden kadın. Nâşizeye nafaka verilmez. Geri gelince nafaka da başlar. (İbni Âbidîn)","kategori":"dil","osmanli":"ناشزه"},{"kelime":"NASRÂNÎ","anlam":"Îsâ aleyhisselâma inanan, İsevî, Mesîhî, Hristiyan.","kategori":"dil","misal":"İbrâhim aleyhisselâm ne Yahudi, ne Nasrânî idi. Fakat o Rabbini bir tanıyan dosdoğru bir mü’min idi. (Âl-i İmrân sûresi: 67) Hazret-i Îsâ’nın tebliğ ettiği Îsevîlik veya nasrânîlik az zaman sonra Yahudiler tarafından sinsice değiştirildi. Bolüs adındaki bir Yahudi, Hazret-i Îsâ’ya inandığını söyleyerek, nasrânî dinini yaymaya çalışıyor görünerek hakîki İncil’i yok etti ve Îsâ, Allah’ın oğludur dedi. Daha başka şeyle…","osmanli":"نصرانى"},{"kelime":"NASS","anlam":"1.Te’vîle ihtiyaç duymayan açık ve kat’i söz. 2.Âyet-i kerîmeler ve hadîs-i şerîf- ler.","kategori":"fikih","misal":"Çokluk hâli nüsûs gelir. Mevrid-i nassda (nass olan yerlerde) ictihâda mesağ (izin) yoktur. (Mecelle, m.14)","osmanli":"نص"},{"kelime":"NASûH","anlam":"1.Nasihatçi. 2.Hâ-lis, temiz.","kategori":"dil","misal":"(A. Nush’dan)","osmanli":"نصوح"},{"kelime":"NÂTIK","anlam":"Nutk sahibi, konuşan.","kategori":"dil","osmanli":"ناطق"},{"kelime":"NÂTIKA","anlam":"1.Düşünüp söyleme hassası, kuvveti. 2.Düzgün, dokunaklı söz söyleme.","kategori":"dil","misal":"NATÜRALİZM: ناتوراليزم (Fr) Tabiatı tek haki- kat, bilgi ve değer kaynağı kabul eden; kâinâtta hâdiselerin meydana gelişinde tabiat kuvvet-leri haricinde tesir tanımayan felsefe cereyanı. Tabiiyye. Tabiatçılık.","osmanli":"ناطقه"},{"kelime":"NAVLuN","anlam":"Gemi sahibine verilen yük ve yol ücreti.","kategori":"dil","osmanli":"ناولون"},{"kelime":"NAZAR","anlam":"1.Bakmak, göz atmak. 2.Düşünme, tedkik etme. 3.İltifat, itibar. 4.Göz değmesi, isâbet-i ayn.","kategori":"hadis","misal":"Allahü teâlâ, sizin sûretlerinize, mallarınıza, nazar etmez; kalblerinize ve amellerinize na-zar eder. (Hadîs-i şerîf-Müslim, İbn-i Mâce) Resûlullah aleyhisselâm, misvâkını ve tarağını yanından ayırmazdı. Saçını ve sakalını tararken aynaya nazar eylerdi. (Mevâhib-i Ledünniyye) Bu dünyaya getirilmemizden maksat, Allahü teâlânın marifetini elde etmektir. Ma’rifet iki nev’dir. Birincisi, fen yolu ile, yani nazar ve is-tidlâl ile hâsıl olur. Bunu, İslâm âlimleri bil-dirdi. İkincisi, keşf ve şühûd ile (kalbde) hâ-sıl olur. Bu, tasavvuf erbâbından (evliyâdan) gelir. Birincisi, ilim olup, akıl ve fikir ile hâsıl olur. İkincisi, hâl olup kendindedir. (Mektûbât-ı İmâm-ı Rabbânî) Kalb hastalıklarının giderilmesi, Allah adam-larının tedâvisi ile olur. Bunların sözleri ilâc-dır. Nazarları şifâdır. Onlarla beraber bulunan-lar kötü olmaz. (Mektûbât-ı İmâm-ı Rabbânî) Gözün, baktığı şeye zarar vermesi.","osmanli":"نظر"},{"kelime":"Nazar Değmesi","anlam":"Bazı kimselerin gözlerinden çıkan zararlı şuâların, canlı ve cansız bir şeye bakıp beğendikleri zaman bozulmalarına sebeb olması.","kategori":"fikih","misal":"Nazar değmesi haktır. Nazarı değen kimse, hattâ herkes, beğendiği bir şeyi görünce “Mâşâallah” demeli, ondan sonra o şeyden bahsetmelidir. Önce mâşâallah deyince nazar değmez. (Mekâtib-i Şerîfe) Nâs sûresini devamlı okumayı alışkanlık hâline getiren kimse, dâimâ sıhhat ve âfiyette olur. Nazar değmesine karşı okunursa, şifâ bulur. (Fevâid-i Osmâniyye)","osmanli":"دﮔمهسى نظر"},{"kelime":"NAZARGÂH","anlam":"Nazar edilen, bakılan veya bakılacak yer.","kategori":"dil","osmanli":"نظرﮔاه"},{"kelime":"Nazargâh-ı İlâhî","anlam":"Allahü teâlânın nazar ettiği yer.","kategori":"akaid","misal":"Kalb, nazargâh-ı ilâhîdir. Kalbin nûrlanmasına çok çalışalar. (Mektûbât-ı Ma’sûmiyye) Sakın terk-i edebden kûy-i mahbûb-i Hüdâ’dır bu, Nazargâh-ı İlâhîdir Makâm-ı Mustafâ’dır bu. (Nâbi)","osmanli":"الهى نظرﮔاه"},{"kelime":"NAZARİYYE","anlam":"Nazara, düşünceye ait olup tatbikata geçmemiş; ilim, sanat veya her-hangi bir meseleye dair tatbik olunmadıkça","kategori":"dil","misal":"gerçekliği ve doğruluğu bilinemeyecek olan kâideler. Teori. Müslümanlık nazariyyeler dini değil, amelî bir dindir. İslâmiyet, insanın rahîm ve gafûr (mer-hametli ve affedici) olan, doğru yolu gösteren Allahü teâlâya kendini teslim etmesi demektir. (Muhammed Emîn)","osmanli":"نظريه"},{"kelime":"NAZARLIK","anlam":"Nazar değmemesi için bir kimseye veya eşyaya takılan nesne.","kategori":"dil","osmanli":"نظرلق"},{"kelime":"NÂZİ‘ÂT SûRESİ","anlam":"Kur’ân-ı kerîmin yetmiş dokuzuncu sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Kırk altı âyet-i kerîmedir. Sûrenin ilk kelimesi olan ve söküp koparan ve çekip alan mânâsına gelen Nâziât kelimesi sûreye isim olmuştur. Sûrede; kıyâmetin şiddeti ve onu inkâr edenlerin dirilişi, yeri göğü yaratan Allahü teâlânın insanları yeniden diriltmeye kâdir olduğu bildirilmektedir. (Mefâtihü’l-Gayb)","osmanli":"سى سوره نازعات"},{"kelime":"NAZÎF","anlam":"(A. Nezâfet’den) Temiz.","kategori":"dil","misal":"Bu büyükler, tatlı yemekleri, lezîz şerbetleri, nefîs kumaşları, hazîn sesleri, nazîf kokuları, latîf manzaraları, melîh sûretleri, tatsızların-dan, çirkinlerinden daha çok istiyor ve sevi-yorlar. (Mektûbât-ı Ma’sûmiyye)","osmanli":"نظيف"},{"kelime":"NÂZİK","anlam":"1.İnce, nârin. 2.Terbiyeli. 3.Gü-zel, zarif.","kategori":"dil","misal":"Kelimenin aslı nâzük’tür.","osmanli":"نازك"},{"kelime":"NÂZİL","anlam":"1.Nüzûl eden, inen. 2.Vahiy yoluyla peygamberlere gönderilen.","kategori":"dil","misal":"(Bkz. Nüzûl)","osmanli":"نازل"},{"kelime":"NÂZIM","anlam":"(A. Nazm’dan) Tanzim eden, nizâma koyan, düzenleyen; manzume yazan.","kategori":"dil","osmanli":"ناظم"},{"kelime":"NÂZIR","anlam":"1.Nazar eden, gören, görücü. 2.Vakfın işlerini, şer’î hükümlere ve vakfedenin koyduğu şartlara göre idare etmek üzere vâkıf veya hâkim tarafından tayin edilen mütevellî-nin vakıf işlerindeki tasarruflarını murâkabe (kontrol) etmesi ve gerektiğinde ona re’yi ile yardımcı olması için vazifelendirilen kimse. Bazen mütevellîye de nâzır denmiştir. Vakfın nâzırı veya herhangi vazifelisi, suç işle-medikçe azl olunamazlar. Vakfı kirâya vermek, mütevellînin vazifesidir. Hâkim, vâli karışamaz. Bir vakfın bir nâzırı ve bir mütevellîsi olsa, mü-tevellî, nâzırın haberi olmadan bir şey yapa-maz. Kayyım, mütevellî ve nâzır aynı hakka sahiptirler. (Fetâvâ-i Hayriyye) 3.Bir devlet dairesinin en üst makamında bu-lunan ve hükümet a’zâsı olan şahıs; hükümet, kabine azâlarının her biri.","kategori":"ibadet","misal":"Allahü teâlâ hayy, alîm, kâdir ve mütekellim olarak sonsuz zamanlarda hep hâzırdır ve nâ-zırdır. Hayat, ilim, kudret ve kelâm sıfatları za-mansız ve mekânsız olduğu gibi, hâzır ve nâ-zır olması da zaman ve mekâna bağlı değildir. Allahü teâlânın sıfatlarının hepsi böyledir. Al-lahü teâlânın hâzır olması gibi hiç kimse hâ-zır değildir. (Abdülhakîm Arvâsî)","osmanli":"ناظر"},{"kelime":"NAZM","anlam":"1.Tertip, sıra; dizme. 2.Vezinli ve kâfiyeli söz söyleme.","kategori":"dil","osmanli":"نظم"},{"kelime":"Nazm-ı İlâhî","anlam":"Allahü teâlâ tarafından yanyana dizilen mübârek sözler, Kur’ân-ı kerîm.","kategori":"dil","misal":"Kur’ân-ı kerîm nazm-ı ilâhîdir, Arabcadır. Bu arabî kelimeler, Allahü teâlâ tarafından nazmedilmiş olarak âyetler hâlinde gelmiştir. (Zerkânî)","osmanli":"الهى نظم"},{"kelime":"NEBÂT","anlam":"Toprakta biten, bitki.","kategori":"dil","osmanli":"نبات"},{"kelime":"NEBÂTÂT","anlam":"1.Bitkiler. 2.Botanik.","kategori":"dil","misal":"Ne-bât’ın çokluk hâli.","osmanli":"نباتات"},{"kelime":"NEBÂTÎ","anlam":"Nebâta (bitkiye) mensub, ne-bat (bitki) ile alakalı.","kategori":"dil","osmanli":"نباتى"},{"kelime":"NEBÎ","anlam":"Haberci. Peygamber, yeni bir din getirmeyip, daha önce gönderilmiş olan bir Resûlün dinine da’vet eden peygamber.","kategori":"akaid","misal":"Emirleri tebliğ etmekte ve insanları Allahü teâlânın dinine çağırmakta, resûl ile nebî arasında bir ayrılık yoktur. Peygamberlere iman etmek; aralarında hiçbir fark görmeyerek, hepsinin doğru sözlü olduğuna inanmak demektir. Onlardan birine inanmayan kimse, hiçbirine inanmamış olur. (İtikadnâme)","osmanli":"نبى"},{"kelime":"NEBİZ","anlam":"Hurma veya kuru üzümü soğuk suda bırakıp, şekeri suya geçince, kaynayın-caya kadar ısıtıldıktan sonra soğuyunca süzü-lerek elde edilen sıvı.","kategori":"dil","misal":"Nebizin tadı keskin olsa da, sarhoş yapmadıkça, içmesi helâl olur. Isıtılmazsa, köpürünce ve tadı keskin olunca haram olur. (İbni Âbidîn)","osmanli":"نبيذ"},{"kelime":"NEBZE","anlam":"Az şey, bir parça. NECÂBET: نجابت (A) Soyluluk, asalet. NECÂSET: نجاست (A) Maddî pislik, kir.","kategori":"dil","misal":"Namaza mâni olup olmama yönünden; hafif necâset ve kaba necâset, görülüp görülmeme yönünden; mer’î (görülen) ve gayr-i mer’î (gö-rülmeyen) ve akıcı olup olmama yönünden; mâî (akıcı) ve câmid (katı) olmak üzere kı-sımlara ayrılır. Katı necâset, insan derisinde, elbisesinde ise veya bevl, kan gibi akıcı necâ-set, mest üzerinde olsa da, ancak yıkamakla te-mizlenir. Kan, şarap, ispirto, bevl (idrar) gibi sıvı necâsetten biri bulaşmış toprak, katı necâ-set demektir.Katı necâset, kemer, çanta, mest, ayakkabı üzerinde olunca, oğmakla, silmekle temizlenir. (İbni Âbidîn)","osmanli":"نبذه"},{"kelime":"NECÂSET","anlam":"Maddî pislik, kir.","kategori":"fikih","misal":"Namaza mâni olup olmama yönünden; hafif necâset ve kaba necâset, görülüp görülmeme yönünden; mer’î (görülen) ve gayr-i mer’î (görülmeyen) ve akıcı olup olmama yönünden; mâî (akıcı) ve câmid (katı) olmak üzere kısımlara ayrılır. Katı necâset, insan derisinde, elbisesinde ise veya bevl, kan gibi akıcı necâset, mest üzerinde olsa da, ancak yıkamakla temizlenir. Kan, şarap, ispirto, bevl (idrar) gibi sıvı necâsetten bir…","osmanli":"نجاست"},{"kelime":"Necâset-i Galîza","anlam":"Kaba necâset. Kan, irin, kusmuk, meni, mezî, vedî, insan dışkısı ve idrarı, eti yenmeyen hayvanların dışkı, idrar ve salyası, kümes hayvanlarının dışkısı, şarap, leş gibi necis maddelerin namaza mâni mikdarı.","kategori":"ibadet","misal":"Namaz kılanın vücudunda, elbisesinde veya namaz kıldığı yerde katı ise bir dirhemden (4,8 gr.) sıvı ise el ayası büyüklüğünden fazla necaset-i galîza bulunması, namazın sıhhatine mânidir.","osmanli":"غليظه نجاست"},{"kelime":"NECÂŞÎ","anlam":"Ortaçağda Habeş hüküm-dârlarına verilen unvan.","kategori":"dil","misal":"Resûlullah aleyhisselâm zamanındaki Ne-câşî’nin adı Eshame idi. Nasrânî (Hristiyan) iken Müslüman oldu. Cenâze namazını Resû-lullah sallallahü aleyhi ve sellem Medîne’de kıl-dırdı. (İbni Hişâm)","osmanli":"نجاشى"},{"kelime":"NECÂT","anlam":"Kurtulma, kurtuluş.","kategori":"dil","misal":"Kalbde aşk ateşi parlamadıkça ve şirketi yakan aşk ateşi ihsân edilmedikçe, bu ağır yükten necât mümkin değildir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"نجات"},{"kelime":"NECCÂR","anlam":"Dülger, marangoz. NECCÂRİYYE: نجاريه (A) Hicretin üçüncü as-rında Hüseyin bin Muhammed en-Neccâr ta-","kategori":"dil","misal":"rafından kurulan; kader hâriç, bir çok mese- lede Mûtezile’ye uyan, Allah’ın zâtı ile mevcut, ama sıfat-ı sübûtiyyesinin bulunmadığını, Kur’ân-ı kerîmin mahlûk olduğunu ve Cen-net’te Allahü teâlânın görülmeyeceğini söyle-yen bid‘at fırkası.","osmanli":"نجار"},{"kelime":"NECDÎ","anlam":"1.Arabistan’daki Necd mıntı-kasına mensub. 2.Vehhâbî mezhebinden olan.","kategori":"dil","osmanli":"نجدى"},{"kelime":"NECES","anlam":"Pislik, murdârlık, necaset; aslı itibariyle necis olan şey.","kategori":"fikih","osmanli":"نجس"},{"kelime":"NECÎB","anlam":"Asil; soyu temiz.","kategori":"dil","osmanli":"نجيب"},{"kelime":"NEDÎM","anlam":"1.Arkadaş. 2.Hoş sohbeti ve hikâyeleriyle büyükleri eğlendiren.","kategori":"dil","osmanli":"نديم"},{"kelime":"NEF‘","anlam":"Menfaat, fayda, kâr.","kategori":"dil","misal":"İlm, yalnız olduğu hâlde nef ‘ verebilir, amel ise, ilmsiz nef ‘ veremez. (Ey Oğul İlmihâli)","osmanli":"نفع"},{"kelime":"NEFER","anlam":"1.Tek kişi. 2.Rütbesiz asker.","kategori":"dil","osmanli":"نفر"},{"kelime":"NEFH","anlam":"Üfürme, üfleme.","kategori":"dil","osmanli":"نفخ"},{"kelime":"NEFHA","anlam":"1.Üfleme, üfürme. 2.İsrâfil aleyhisselâmın, kıyâmetin kopup insanların öleceği ve tekrar diriltilecekleri zaman, nasıl olduğu bizce bilinmeyen sûra üflemesi. Sûr’a nefha edileceği o gün (mezarlardan kalkıp, mahşer denilen alana) bölük bölük gelirsiniz. (Nebe’ sûresi: 18) Onların beklediği sâdece bir sayhadır (sûr’a ilk üfürülüştür) ki, onlar (ticârette ve) birbirleriyle çekişip (itişip) dururlarken, kendilerini yakalayıverir. (İşte o zaman) bunlar bir vasîyyette bile bulunamazlar. (Hattâ o vakit, onlar çarşıda ticârette iken) âilelerine dahi dönecek (halde) değildirler (…","kategori":"dil","osmanli":"نفخه"},{"kelime":"NEFRET","anlam":"Tiksinmek, ürküp kaçmak. Kolaylaştırın, zorlaştırmayın. Müjdeleyin, nef-ret ettirmeyin. (Hadîs-i şerîf-Müslim)","kategori":"hadis","misal":"Takvâ, haramlardan nefret etmek, haram iş-lemeği hatıra bile getirmemektir. (Mektûbât-ı Ma’sûmiyye)","osmanli":"نفرت"},{"kelime":"Nefs-i Emmâre","anlam":"Kötülüğü emreden nefs.","kategori":"tasavvuf","misal":"İnsanın bütün kötülükleri nefs-i emmârede toplanmıştır. Nefs-i emmâre hiç iyilik yapmak istemez. Hep kötülük yapmak ister. Kendisine ve başkalarına zararlı olan şeyleri sever. İnsanın dünya ve âhirette saâdete kavuşması için nefsine uymaması, onu zayıflatıp, zarar yapmayacak hâle getirmesi lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اماره نفس"},{"kelime":"Nefs-i Nâtıka","anlam":"İnsanı hep kötülük ve aşağılık işler yapmaya sürükleyen nefs.","kategori":"tasavvuf","misal":"Nefs-i nâtıkayı zaifletecek birinci ilâç, İslâmiyet’in emir ve yasaklarına uymaktır. Haramların hepsi; dünya malına, mevkiine, zevklerine düşkün olmak, nefsin gıdâsıdır. Onu besler, kuvvetlendirirler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ناطقه نفس"},{"kelime":"Nefs Muhâsebesi","anlam":"İnsanın, dâimâ kötülük ve günah işlemek isteyen nefsini hesâba çekip, kontrol etmesi ve gerektiğinde onu cezâlandırması.","kategori":"tasavvuf","misal":"(Bkz. Muhâsebe)","osmanli":"سى محاسبه نفس"},{"kelime":"NEFS (Nefis)","anlam":"1.İnsanın kendisi, kişi, beden. 2.İnsan ve cinde, iyi ve kötüyü ayırt etmeksizin, bedenin hayatta kalması için gereken fonksiyon.","kategori":"tasavvuf","misal":"Her nefs, ölümü tadıcıdır. (Âl-i İmrân sûresi: 185) Cenâb-ı Hakk’ın huzurundan korkup, nefsini nefsânî arzularından men eden kimsenin varacakları yer muhakkak Cennet’tir. (Nâziât sûresi: 40) Akıllı, nefsine boyun eğdiren ve ölümden sonrası için çalışandır. Âciz ise nefsini kötü arzularında alabildiğince serbest bırakan…","osmanli":"نفس"},{"kelime":"NEFSÎ","anlam":"Nefisten doğan, nefs ile alâkalı; kişiye ait.","kategori":"tasavvuf","osmanli":"نفسى"},{"kelime":"NEFY","anlam":"1.Sürme, sürgün etme. 2.Yok etme, 3.Menfîlik, müsbetin zıddı.","kategori":"dil","misal":"Küfrün bâtıl olduğunu çekinmeden söylemeli, onların tapındıkları bâtıl ilâhları, tanrıları, en ağır dille nefy ve red etmelidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"نفى"},{"kelime":"NEFY VE İSBÂT","anlam":"Yok etme ve sâbit kılma mânâsına “Lâ ilâhe illallah” zikri.","kategori":"tasavvuf","misal":"Nefy ve ispat zikrini çok yapınız. Bu güzel kelimeyi tekrar ederken bütün dilek ve düşüncelerinizi gönülden çıkarınız! Maksadınız, dileğiniz ve sevdiğiniz birden fazla (Allahü teâlâdan başka) olmasın. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"واثبات نفى"},{"kelime":"NEHÂR","anlam":"Gündüz.","kategori":"dil","osmanli":"نهار"},{"kelime":"NEHY","anlam":"Yasak, yasak edilen şey. Resûlümün getirdiği emirleri alınız, itâat ediniz! Nehy ettiği şeylerden sakınınız! (Haşr sûresi: 7)","kategori":"dil","misal":"Dünyada felâketlerden, âhirette Cehennem azâbından kurtulmak için iki şey lâzımdır: Dinin emrettiği şeylere sarılmak, nehiylerin-den sakınmak! Nehyedilen şeylerden sakınmak, daha kıymetlidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"نهى"},{"kelime":"Nehy-i İktizâî","anlam":"Haram. (Bkz.","kategori":"fikih","misal":"Haram)","osmanli":"اقتضائى نهى"},{"kelime":"NEKÎR","anlam":"1.Bilinmeyen, tanınmayan. 2.Kabirde ölüye sual soran meleklerden biri.","kategori":"dil","misal":"(Bkz. Münker ve Nekir) Kabre konan meyyit, Münker ve Nekir melek-lerinin sorularına doğru cevap verince, onlar; “Doğru söyledi, bizim elimizden kurtuldu” der-ler. Bu kimsenin kabri nûr ile dolar. Cennet ko-kuları gelir. Kıyâmete kadar neş’eli ve sevinçli olur. (Düretü’l-Fâhire)","osmanli":"نكير"},{"kelime":"NEKROFİLİ","anlam":"Ölülerle cinsî temasa girme sapkınlığına verilen isim. Ölü sevicilik.","kategori":"dil","osmanli":"نكروفيلى"},{"kelime":"NEMÂ","anlam":"Malın artması, çoğalması; artma ve çoğalmaya elverişli hâlde bulunma.","kategori":"dil","misal":"Zekâtı verilecek malda aranan şartlardan bi-risi de nemâ bulmasıdır. Zekâtta nemâ aran-dığı için toprak mahsulleri bir defa elde edilip zekâtı verildikten sonra sahibinin elinde senelerce kalsa, bir daha zekâtı verilmez. Ama hayvan her sene yavruladığı için daima nemâlanmak-tadır ve her sene zekâtı verilir. (Bedâiü’s-Sanâyî)","osmanli":"نما"},{"kelime":"NEMÎME","anlam":"İnsanlar arasında söz ta-şıma, koğuculuk, müzevirlik. (Bkz. Nemmâm) Nemîme ile gezenlerden Allah ikrah eder. (Hadîs-i şerîf-İbni Asâkir)","kategori":"hadis","misal":"Nemîmeye ruhsat vermek (söz taşıyana izin vermek), nemîmeden eşeddir (söz taşımaktan kötüdür). (Mektûbât-ı Ma’sûmiyye) Yalan, gıybet, nemîme ve yalan yere yemin gibi şeyler orucu bozmazlar. Ancak sevâbını gide-rirler. (Miftahü’l-Cenne)","osmanli":"نميمه"},{"kelime":"NERD","anlam":"Tavla oyunu.","kategori":"dil","misal":"Nerd, satranç, ondört taş oynamak ve bütün çalgıları çalmak ve dinlemek, raks etmek, hok-kabazlık, şaklabanlık etmek, başkaları ile alay etmek, el çırpmak, hep oyun olup, tahrîmen mekrûhturlar. (İbni Âbidîn)","osmanli":"نرد"},{"kelime":"NESEB","anlam":"Soy, insanı anne ve babaya bağlayan kan bağı.","kategori":"dil","misal":"Hem o Allah’tır ki, sudan bir insan yaratıp onu nesep ve sıhriyyet akrabâlıklarına ayırdı. Rabbinin her şeye gücü yeter. (Furkân sûresi: 54) İnsanın şerefi ilim ve edeb iledir; mal ve nesep ile değildir. (Mektûbât-ı Ma’sûmiyye)","osmanli":"نسب"},{"kelime":"NESH","anlam":"1.Fesh etme, kaldırma, hüküm-süz bırakma. 2.Âyet-i kerîme veya hadîs-i şerîf ile sâbit olan şer’î bir hükmün zamanının bittiğinin, daha sonra başka bir delille beyan olunması. Hükmü kaldırılan delile, nâsih; kaldırılan hükme mensûh denir. Resûlullah aleyhisselâm Medîne-i Münevvere’ye hicret ettikten sonra bir müddet Kudüs’teki Mes-cid-i Aksâ’ya yönelerek namaz kıldı. Sonra bu sünnet, “Şimdi, yüzünü Mescid-i Haram ta-rafına çevir. Nerede bulunursanız bulunun yüzünüzü o mescid tarafına çevirin.” meâ-lindeki Bakara sûresinin 144.âyet-i kerîmesi ile nesh edilmiştir.","kategori":"dil","misal":"Muhammed aleyhisselâm peygamberlerin so-nuncusudur. O’nun dini, bütün dinleri nesh et-miştir. (Mektûbât-ı İmâm-ı Rabbânî) Allahü teâlâ, hikmet sahibi ve kullarına çok merhametli olduğu için, kullarının fâideleri için bazı hükümleri nesh edebilir. Zamanın değiş-mesi ile insanların maslahatları, faydalarına olan şeyler değişebileceği için, bazı hükümlerde neshin meydana gelmesi aklen câizdir, müm-kündür. Bu hâl naklen de mümkündür ve ol-muştur da. Nitekim, Âdem aleyhisselâm zama-nında kız kardeşle evlenmek câiz iken, ondan sonra gelen şeriatlerde bu husus nesh edilmiş-tir. Yâkûb aleyhisselâm zamanında iki kız kar-deşi bir erkeğin alması câiz iken, İslâmiyet bunu nesh etmiştir. (Mefâtihü’l-Gayb) (Mefâtihü’l-Gayb) Nesh, Resûlullah aleyhisselâm hayatta iken olur. Kıssa ve haberlerde nesh olmaz. Yalnız emir ve yasaklarda olur. Neshin şartı, nâsihin ya ki-tab veya sünnet olması lâzımdır. İcmâ ile kı-yas, nâsih ve mensûh olamaz. Hanefîlere göre kitab kitab ile, sünnet sünnet ile, sünnet, kitab ile, kitab da mütevâtir veya meşhûr sünnet ile nesh edilmiş olabilir. (İbni Âbidîn) Bir hükmün neshedildiği ya Resûlullah aley-hisselâmın bildirmesi ile veya Eshâb-ı kirâmın açıkça bildirmesi ile veya iki müteâriz (birbirine zıt görünen) delilin nüzûl veya vürûd tarihleri ile veya hakkında icmâ vuku bulması ile bili-nir. İctihad ile bilinmez. (Mir’at)","osmanli":"نسخ"},{"kelime":"NESÎ’","anlam":"Tehir etme, yer değiştirme, geri bırakma.","kategori":"dil","misal":"Nesî’, küfrde ziyâde olmayı gösterir. Kâfir-ler bununla aldatılır. Bir ayı helâl sayar-lar. Başka sene ise, bu ayı haram sayarlar. (Tevbe sûresi: 37) İslâmiyet’ten evvel ve İslâmiyet’in ilk zamanla-rında, kamerî sene aylarından Recep, Zilkâ’de, Zilhicce ve Muharrem aylarında harb etmek haram idi. Arablar, Receb veya Muharrem ay-larında harb edebilmek için, nesî’ yapar; yani ayların yerini değiştirir, ileri veya geri alırlardı. Resûlullah aleyhisselâm Vedâ hutbesinde nesî’yi yasakladı ve; “Ey Eshâbım! Haccı tam za-manında yapıyoruz. Ayların sırası, Allahü teâlânın yarattığı zamandaki gibidir” bu-yurdu. (Halebî)","osmanli":"نسئ"},{"kelime":"NESİL (Nesl)","anlam":"Bir kimsenin usûl ve füruu, soyu sopu.","kategori":"fikih","osmanli":"نسل"},{"kelime":"NESÎM","anlam":"Hafif rüzgâr.","kategori":"dil","osmanli":"نسيم"},{"kelime":"NEŞR","anlam":"1.Yayma, dağıtma. 2.Ölülerin diriltilmesi; Kıyamet günü ölülerin diriltilip, haşrolunarak (mahşer yerinde topla-narak), hesabları görüldükten sonra, cennet-liklerin Cennet’e ve Cehennemliklerin Cehen-nem’e dağılması. (Bkz. Haşr) Rüzgârları gönderip de bulutu harekete ge-çiren Allah’tır. Biz onu ölü bir bölgeye gön-deririz de ölümünden sonra toprağa onunla hayat veririz. Neşr de böyle olacaktır. (Fâtır sûresi: 9) Resûlullah efendimizin; kabir ve kıyâmet hâlle-rinden, haşrden ve neşrden, Cennet’ten ve Ce-hennem’den haber verdiği şeylerin hepsi doğru-dur. Âhirete inanmak, Allahü teâlâya inanmak gibi, îmânın şartıdır. Âhireti inkâr edenin, Al-lahü teâlâyı inkâr etmiş gibi îmânı gider. (Mek-tûbât-ı İmâm-ı Rabbânî)","kategori":"dil","misal":"İnsanlar ilmi neşretmekten daha fazîletli bir sadaka vermemişlerdir. (Hadîs-i şerîf-Taberânî) Bid‘atler yayılıp, sünnetler terk edildiği zamanda, İslâm ilimlerinin tahsîli ve neşri, en mühim iş-lerdendir ve Muhammed aleyhisselâmın sünne-tini yaymak en mühim maksattandır. (Mektû-bât-ı Ma’sûmiyye)","osmanli":"نشر"},{"kelime":"NEŞRİYYÂT","anlam":"Basılıp dağıtılan yazılar. NE‘ûZÜ BİLLAH: بالله نعوذ (A) “Allahü teâlâya sığınırız” mânâsına, tehlikeli hâllerden ve îmânı","kategori":"akaid","misal":"gideren şeylerden sakınma ve korkma mânâ- sını ifâde eden bir söz.","osmanli":"نشريات"},{"kelime":"NESSÂC","anlam":"1.Dokumacı. 2.Yalancı.","kategori":"dil","misal":"NESTûRİYYE: نسطوريه (A) İstanbul patriği Nes-torius tarafından kurulan Hrisiyanlığın en eski mezheblerinden. Nestûrîlik. Nestûriyye, bir Allah’a, Allah’ın ilim sıfatının Hazret-i Îsâ’ya hulûl ettiğine, Hazret-i Mer-yem’ın ilâh anası değil, insan anası olduğuna inanır. 428’de İstanbul patriği olan Nestori-us’un fikirleri İstanbul Konsili’nde kabul edildi ise de, 431 tarihli Efesus Konsili’nde reddo-lundu. Aforoz edilen Nestorius, Mısır’a gide-rek 439’da orada öldü. Bugün sayıca çok aza-lan Nestûriyye mezhebi mensubları, Kuzey Irak ve Kürdistan’da yaşamakta; ibâdetlerinde Süryânîceyi kullanmaktadır. Âsûriyye, Keldâ-niyye diye de anılır.","osmanli":"نساج"},{"kelime":"NEV‘","anlam":"Çeşit, cins.","kategori":"dil","osmanli":"نوع"},{"kelime":"NEVÂ","anlam":"1.Ses, ahenk.","kategori":"dil","misal":"2.Çare.","osmanli":"نوا"},{"kelime":"NEVÂDİR","anlam":"1.Az olan şeyler, nâdireler. 2.Hanefî mezhebinin, İmâm-ı Muhammed’in Zâhirü’r-Rivâye adlı kitapları kadar kadar açıkça ve sağlam gelmiş olmayan hükümleri. Nevâdir haberler, İmâm-ı Muhammed’in usûl haberlerini bildiren ve Zâhirü’r-Rivâye adlı 6 ki-tabı gibi açıkça ve sağlam gelmiş olmadığından, bu haberlere gayru zâhiri’r-rivâye (zâhir olma-yan haberler) de denir. Bunlar İmâm Muham-med’in el-Keysâniyyât, el-Cürcâniyyat, el-Rak-kiyyat ve El-Haruniyyat ile Hasen bin Ziyâd’ın Muharrer ve İmâm-ı Ebû Yûsuf ’un Emâlî adlı kitabı ile bildirilmişlerdir. (İbni Âbidîn)","kategori":"dil","osmanli":"نوادر"},{"kelime":"NEVÂYÎ","anlam":"1.Yeni üslûp. 2.XV.","kategori":"fikih","misal":"asırda Maveraünnehr’de konuşulan Türkçe, Çağa-tay Türkçesi.","osmanli":"نوايى"},{"kelime":"NEVBEHÂR","anlam":"İlkbahar.","kategori":"dil","osmanli":"نوبهار"},{"kelime":"NEVHA","anlam":"Ölüye sesle ağlama.","kategori":"dil","osmanli":"نوحه"},{"kelime":"NEVRûZ","anlam":"1.“Yeni Gün” mânâsına Zerdüşt dininin iki bayramından gece ile gün-düzün eşitlendiği 21 Mart’a denk gelen birin-cisi. 2.Şiî inancında Hazret-i Ali’nin doğum günü. 3.İlkbaharın başlangıcı.","kategori":"dil","misal":"Eski İran’da yılbaşı. Nevrûz, Mecûsilerin bayramıdır. O gün mecûsi-lerin yanına gidip, onların yaptıklarını yapmak küfürdür. O gün bayram yapan Müslümanların îmânı gider de haberi olmaz. (Mecma’ül-Enhür) Nevrûz veya Mihrican (23 Eylül) günlerinde bun-ların isimlerini söyleyerek hediye vermek haram-dır. Bu günleri bayram bilerek bir şeyi vermek küfr (dinden çıkmak) olur. (Dürrü’l-Muhtar)","osmanli":"نوروز"},{"kelime":"NEVZÂD","anlam":"Yeni doğmuş.","kategori":"dil","osmanli":"نوزاد"},{"kelime":"NEZÂFET","anlam":"Temizlik.","kategori":"dil","misal":"Nezafet imanın (dinin) yarısıdır. (Hadîs-i şerîf-Müslim, Tirmizî, Dârimî, Müsnedü Ahmed))","osmanli":"نظافت"},{"kelime":"NEZÂKET","anlam":"Kibarlık, zariflik, ince-lik, terbiye.","kategori":"dil","osmanli":"نزاكت"},{"kelime":"NEZÂRET","anlam":"1.Bakma. 2.Gözetme, kontrol. 3.Muayyen hususlarda hükümete bağlı olarak devlet işlerini yürüten ofislerinin bağlı olduğu makam, bakanlık, vekillik.","kategori":"osmanli","osmanli":"نظارت"},{"kelime":"NEZR","anlam":"Yalnızca Allah rızası için veya bir isteğin yerine gelmesi yâhud bir korkunun giderilmesi için, farz veya vâcib olan bir ibâdete benzeyen ve başlı başına ibâdet olan bir işi yapacağına dâir Allahü teâlâya söz verme.","kategori":"fikih","misal":"Namaz, oruç, hacca gitmek ve başka ibâdetler nezr olunur. Nezr, ibâdettir. Nezrin yerine getirilmesini İslâmiyet emretmektedir. Getirilmezse günah olur. (İbni Âbidîn) Talâkta, nikâhta ve nezrde niyetsiz, düşünmeden söylemek ciddî isteyerek söylemek gibidir. Nezrin yerine getirilmesi vâcibdir. (İbni Âbidîn) Fakir olsun, zengin olsun, nezr eden, nezr edilerek kesilen hayvanın etinden yiyemez. Zekât vermesi câiz olmaya…","osmanli":"نذر"},{"kelime":"Nİ‘MET","anlam":"İyilik, hoşluk; rızık, saadet; insanın sahip olup dünya ve âhirette kendisine fayda verecek imkân ve insan.","kategori":"akaid","misal":"Her ni‘metin şükründen muhakkak sorulacaksınız. (Tekâsür sûresi: 8) Allahü teâlâ bir kulunu ni‘metlendirirse, o nîmetinin eserini kulunun üzerinde görmek ister. (Hadîs-i şerîfHâkim) Ni‘met ne kadar çok ise şükretmek lüzumu da çok olur. Zenginlerin zenginlik derecesine göre fakirlerden daha çok şükretmesi lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî) Ni‘met bir külfet mukabilidir. (Mecelle)","osmanli":"نعمت"},{"kelime":"NİDÂ","anlam":"Çağırma, bağırma, seslenme.","kategori":"dil","osmanli":"نداء"},{"kelime":"NİFÂK","anlam":"Münâfıklık, kalben iman etmediği hâlde, iman etmiş gibi görünme; ikiyüzlülük.","kategori":"akaid","misal":"Bedevîler, küfür ve nifak bakımından hem daha beter, hem de Allahü teâlânın Resûlüne indirdiği sınırları tanımamaya daha lâyıktır (onlar buna daha müsâittirler). Allahü teâlâ, alîmdir, hakîmdir. (Tevbe sûresi: 97) Yalan, nifak kapılarından biridir. (Hadîs-i şerîfHarâitî) Ya Rabb! Şekten, şirkten, nifâk ve şikâktan ve bir de kötü ahlâktan sana sığınırım, Hadîs-i şerîfBezzâr) Kalbinde küfür olan kimsenin mü’min olduğu…","osmanli":"نفاق"},{"kelime":"NİFÂS","anlam":"Çocuk doğuran kadının rahminden kan gelme hâli.","kategori":"osmanli","misal":"Nifâs günlerinde namaz, oruç, câmi içine girmek, Kur’ân-ı kerîm okumak ve tutmak, Kâbe’yi tavâf, cimâ’ haram olur. Oruçları kazâ eder, namazları kazâ etmez. (İbni Âbidîn) Elleri, ayakları, başı belli olan düşükte gelen kan da nifâstır. Nifâs zamanının azı yoktur. Kan kesildiği zaman, gusül edip namaza başlar. En çok zamanı Hanefî mezhebine göre kırk gündür. Kırk gün tamam olunca, kan kesilmese de gusl edip namaza ba…","osmanli":"نفاس"},{"kelime":"NİGÂH","anlam":"Bakış, bakma.","kategori":"dil","osmanli":"نگاه"},{"kelime":"NİHÂN","anlam":"Saklı, görünmeyen.","kategori":"dil","osmanli":"نهان"},{"kelime":"NİHÂYET","anlam":"1.Son. 2.Tasavvufta, velâyet mertebelerinin sonu.","kategori":"tasavvuf","osmanli":"نهايت"},{"kelime":"NÎK","anlam":"İyi, hoş, güzel, beğenilen. Zıddı ‘bed’ gelir.","kategori":"dil","osmanli":"نيك"},{"kelime":"NİKÂH","anlam":"Evlilik için bir erkek ile kadın arasında yapılan akid.","kategori":"dil","misal":"(Size) helâl olan kadınlardan nikâh ediniz. (Nisâ sûresi: 3) Nikâh yapmak benim sünnetimdir. Sünnetimden yüz çeviren benden değildir. (Hadîs-i şerîfİbn-i Mâce) Nikâhlanacak taraflar bizzat veya vekil yâhud velî vâsıtasıyla iki şahit huzurunda icab ve kabulde bulunmalıdır. (İbni Âbidîn)","osmanli":"نكاح","baglamlar":[{"baglam":"aile hukuku","anlam":"İslâm'da evlilik akdi; şâhitler huzurunda îcâb ve kabul ile gerçekleşen meşru birleşme."},{"baglam":"fıkhî hüküm","anlam":"Nikâhın şartları, mânileri, çeşitleri (sahîh, fâsid, bâtıl) ve hükümleri."}]},{"kelime":"Nikâh-ı Sahîh","anlam":"İn’ikad (sözleşme) ve sıhhat şartlarının tam olarak bulunduğu nikâh.","kategori":"dil","osmanli":"صحيح نكاح"},{"kelime":"NİKÂR","anlam":"1.Kin. 2.İnâd.","kategori":"dil","misal":"Sôfiyye-i kirâmın yolu kimseye karışmamak ol-saydı, bunların birisi (Sôfiyye arasından nikâr kalkınca bunlarda hayr kalmaz) buyurmazdı. (Mektûbât-ı Ma’sûmiyye)","osmanli":"نقار"},{"kelime":"NÎRÂN","anlam":"1.Aydınlıklar. 2.Ateşler, Cehennem.","kategori":"akaid","misal":"Nâr ve nûr’un çokluk hâli.","osmanli":"نيران"},{"kelime":"NİSÂ SûRESİ","anlam":"Kur’ân-ı kerîmin dördüncü sûresi.","kategori":"dil","misal":"Medîne’de nâzil oldu. Yüz yetmiş altı âyet-i kerîmedir. Nisâ, kadınlar demektir. Sûrede; toplum içinde kadınların hukûkî ve ictimâî yer ve değerlerinden bahsedildiği için, Sûre-tü’n-Nisâ denilmiştir. Sûrede; İslâmiyet’te âile, kadın ve kadın hakları, müşrikler ve ehl-i kitabın sapık inançları, savaş yüzünden babalarını kaybeden yetimlerle dulların hukûku ve mîrâs hükümleri bildirilmektedir. (Mefâtihü’l-Gayb)","osmanli":"سى سوره نساء"},{"kelime":"NİSÂB","anlam":"1.Asıl, esas, kök. 2.Gereken asgari mikdar, sınır. 3.Dinî hükümlerde ara-nan zenginlik ölçüsü.","kategori":"dil","misal":"Zekâtın nisâbı altında yirmi miskal (96 gram); gümüşün nisâbı ikiyüz dirhem (672 gram); ti-caret eşyasında bu kıymette maldır. (Bedâyî) Uşrda nisâb İmâm Ebû Hanife’ye göre bir sa’, İmâmeyn’e göre beş vesktir. Bu mikdardan aşağı mahsulde uşr vermek farz olmaz. Ko-yunun nisâbı kırk, sığırın nisâbı otuz, devenin nisâbı beştir. Fıtra ve kurbanın vâcib olması-nın nisâbı, hâcet-i asliyye denilen aslî ihtiyaçlar dışında 20 miskal altın kıymetinde para veya maldır. (İbni Âbidîn) Hırsızlık haddinin nisâbı Hanefî’de bir miskal (4,8 gr.) altın veya on dirhem (33,6 gr.) hâlis gümüştür. Bundan daha kıymetsiz mal çala-nın eli kesilmez. (İbni Âbidîn) Hem altını, hem de gümüşü olup, birisi veya her biri, nisâb mikdarından az ise, bu vakit, herhangi birinin, diğeri üzerinden kıymeti alı-narak birisinin nisâbı doldurulabilir ise, öteki yerine de, bu verilir. (İbni Âbidîn)","osmanli":"نصاب"},{"kelime":"NİŞÂN","anlam":"1.İz, alâmet. 2.Hedef, vurulacak yer, hedefe silah doğrultma. 3.Hâtıra için dikilen taş. 4.Padişah tuğrası. 5.Madalya.","kategori":"fikih","misal":"Herkesin elinde bulunanın, kendi malı olduğunu kabul etmelidir. Haram olduğunu gösteren bir nişân bulunmadıkça, helâl bilmeli ve satın almalıdır. (Kimya-i Se’adet)","osmanli":"نشان"},{"kelime":"NİSBET","anlam":"1.Münasebet, yakınlık, bağ-lılık, mensub olma. 2.Kıyas, ölçü.","kategori":"fikih","misal":"Kendisini babasından başkasına nisbet eden, Cehennem’e hazırlansın. (Hadîs-i şerîf-Ta-berânî) Kim bir Müslümanı küfre nisbet ederse, o adam kâfir değilse, kendisi kâfir olur. (Hadîs-i şerîf-Ebû Dâvûd) Bâtındaki, yani kalbdeki nisbetin artmasına çalışınız. Allah ismini bazen de kelime-i tehlîli çok zikrederek, bazan salavât getirerek, Kur’ân-ı kerîm okuyarak Allahü teâlâya yaklaşmaya ça-lışınız. (Mekâtib-i Şerife)","osmanli":"نسبت"},{"kelime":"NISF","anlam":"1.Yarım, yarı. 2.İslâm mîrâs hukûkunda eshâb-ı ferâiz adı verilen yani Kur’ân-ı kerîmde payları bildirilenlerden bazı kimselere verilen yarım hisse. Meyyitin (ölen kişinin) oğlu yok ise, kızı mîrâsın nısfını alır. (Mevkûfat)","kategori":"miras","osmanli":"نصف"},{"kelime":"NİSYÂN","anlam":"Unutma.","kategori":"dil","misal":"Ya Rabbî, Hata ve nisyân ettiklerimizden do-layı bizi mes’ûl tutma! (Bakara sûresi: 286) Allah, ümmeten hatâ ve nisyân ederek, bir de ikrâh olunarak işlediği günahın mes’ûli-yetini kaldırmıştır. (Hadîs-i şerîf-İbn-i Mâce, İbni Hibbân, Hâkim) Hâfıza-i beşer nisyân ile ma’lûldür. (Atasözü)","osmanli":"نسيان"},{"kelime":"NİYÂZ","anlam":"Yalvarma, yakarma, dilekte bulunma, isteme.","kategori":"dil","osmanli":"نياز"},{"kelime":"NİYYET (Niyet)","anlam":"Kasd etme, karar verme, kalbin bir şeye yönelmesi, ne yaptığını bilme.","kategori":"tasavvuf","misal":"Namaza niyet kalb ile olur. Ağız ile niyet etmek (Hanefî’de) bid‘attir. Çok kimseler, yalnız ağız, söz ile niyet ederek, kalb ile niyet etmiyorlar. Böylece, namazın farzlarından biri olan kalb ile niyet yapılmıyor. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"نيت"},{"kelime":"NİZÂM","anlam":"Düzen, uygunluk; kanun.","kategori":"dil","osmanli":"نظام"},{"kelime":"NOEL","anlam":"Hristiyanlıkta Îsâ aleyhisselâmın doğum günü kabul edilen gün ve bugüne isabet eden dinî gün.","kategori":"dil","misal":"Noel, Gregoryen takvimini kullanan Katolik, Protestan, Süryânî ve Rumlara göre 24-25 Aralık gecesi; Julyen takvimini kullanan Rus, Balkan ve Ermeni kiliselerine göre 6-7 Ocak gecesidir. İki takvim arasında 13 gün fark vardır. Esasında Hazret-i Îsâ’nın doğum günü belli değildir. Roma imparatoru Konstantin zamanında, Eski Romalıların güneş bayramı olan 25 Aralık’ın, Îsâ aleyhisselâmın doğum günü olarak kabul edilmesi…","osmanli":"نوئل"},{"kelime":"NOKSÂN","anlam":"Eksiklik; eksik, kusurlu.","kategori":"dil","osmanli":"نقصان"},{"kelime":"NOKTA-İ CEVVÂLE","anlam":"Bir ipin ucuna taş, demir gibi bir cisim bağlayıp elle döndürüldüğünde meydana gelen daire üze-rinde dönen cisim.","kategori":"dil","misal":"Vehm ve hayâl, nokta-i cevvâleyi hariçte dâire şeklinde görür. Hâlbuki hakîkatte dâire yok-tur. Nokta vardır. Fakat vehm ve hayâl bakı-mından, hariçte dâirenin bulunması hakîkîdir. Bunun gibi vahdet-i vücûd (mahlûkâtı tek bir varlık olarak görme) her bakımdan hakîkîdir. Birden ziyâde varlık ise vehm ve hayâl bakımın-dan hakîkîdir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"جواله نقطهء"},{"kelime":"NÜBÜVVET","anlam":"Peygamberlik; nebîlik.","kategori":"akaid","misal":"Allahü teâlânın emir ve yasaklarını insanlara bildirmek üzere seçtiği kimselere verilen vazife. (Bkz. Nebî)","osmanli":"نبوت"},{"kelime":"Nübüvvet Yolu","anlam":"Tasavvufta insanları Rabbin rızâsına kavuşturan iki yoldan birincisi.","kategori":"akaid","misal":"Nübüvvet yolu aslı aslına kavuşturur. Eshâb-ı kirâm bu yoldan kavuştular. Sonra gelenlerden pek az kimse de bu yoldan maksada ermiştir. Ebû Bekr-i Sıddîk, nübüvvet yolunda Resûlullah’ın vekilidir. (Mekâtib-i Şerife)","osmanli":"يولى نبوت"},{"kelime":"NÜCEBÂ","anlam":"Ricâlü’l-Gayb denilen Allahü teâlânın insanlardan gizlediği ve dara düşenlere yardım eden velî zâtlardan.","kategori":"akaid","misal":"Allahü teâlânın bu ümmete ikrâm ettiği kerâmetlerden birisi, bu ümmet arasında aktâb, evtâd ve nücebâ ve ebdâl vardır. (Mevâhib-i Ledünniyye) Nükabâ üç yüz kişidir. Nücebâ yetmiş kişidir. Büdelâ kırk kişidir. Ahyâr yedi kişidir. Amed dörttür. Gavs birdir. İnsanlara bir şey lâzım olsa, önce nukabâ duâ eder. Kabul olmazsa, nücebâ duâ eder. Yine kabul olmazsa, ebdâl, daha sonra ahyâr, sonra amed duâ ederler. Kabul olma…","osmanli":"نجباء"},{"kelime":"NÜCûM","anlam":"Yıldızlar. Necm’in çokluk hâli.","kategori":"dil","osmanli":"نجوم"},{"kelime":"NÜFûS","anlam":"Ruhlar, canlar; kişiler.","kategori":"akaid","misal":"Nefs’in çokluk hâli.","osmanli":"نفوس"},{"kelime":"NÜFûZ","anlam":"1.İçe işleme, delme. 2.Sözü geçme.","kategori":"dil","osmanli":"نفوذ"},{"kelime":"NÜH","anlam":"Dokuz.","kategori":"dil","osmanli":"نه"},{"kelime":"NûH (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde adı geçen ülülazm peygamberlerden ve Tufan’dan sonra türeyen bütün insanların atası.","kategori":"dil","misal":"Ey Nuh! Sana ve seninle beraber olanlara bizden bir selâmet ve bereketle gemiden in! (Hûd sûresi: 8) Nuh aleyhisselâm dokuzyüz elli yıl yaşadı. Ölüm meleği ona geldiğinde; “Ey peygamberlerin büyüğü Nuh! Ey uzun ömürlü ve ey duâsı kabul olan! Dünyayı nasıl gördün?” diye sordu. “İki kapılı bir evin bir kapısından girip, diğerinden çıkmış gibi” buyurdu. (Hadîs-i şerîfİbni Asâkir)","osmanli":"نوح"},{"kelime":"NuKûD","anlam":"Basılmış altın ve gümüş para. Zaman içinde metal ve kâğıt para için de kul-lanılmıştır. Nakd’in çokluk hâli.","kategori":"dil","osmanli":"نقود"},{"kelime":"NÜKûL","anlam":"Dönme, cayma, vazgeçme. Ayıplı mal satıcıya iâde edilir, geri verilirse, bu satıcı da, kendine satana geri çeviremez. İki-sinden birinin ikrâr etmesi veya nükûl etmesi lâzımdır veya şâhidlerin dinlenmesiyle hâkim karar verir. (Dürerü’l-Hükkâm)","kategori":"dil","osmanli":"نكول"},{"kelime":"NuKûŞ","anlam":". Nakışlar, resimler, süsleme-ler. Nakşın çokluk hâli.","kategori":"dil","osmanli":"نقوش"},{"kelime":"NÜMÂ","anlam":"Gösteren, bildiren. (Misal: Kıblenümâ, kıbleyi gösteren.)","kategori":"ibadet","osmanli":"نما"},{"kelime":"NûR","anlam":"1.Işık, aydınlık. 2.Tam ve kusursuz olarak zâhir olup her şeyi ortaya çıkarıcı, yaratıcı veya göktekileri ve yer-dekileri nûru ile hidâyet edici, doğru yolu gös-terici, gökleri; güneş, ay ve yıldızlarla yeri; pey-gamberler aleyhimüsselâm, âlimler, mü’minler (inananlar) ile yâhud bitkilerle ve ağaçlarla tezyîn eden, süsleyen mânâsına Allahü teâlâ-nın Esmâ-i hüsnâsından (en-Nûr). Allahü teâlâ göklerin ve yerin nûrudur. (Nûr sûresi: 35) En-Nûr ism-i şerîfini söyleyenin kalbi nurlanır. (El-İstigâsetü’l-Kübrâ) Feyz, bereket, ihsân. (Kâfirler) Allah’ın nûrunu ağızlarıyla sön-dürmek istiyorlar. Hâlbuki onlar istemese de Allah nûrunu tamamlayacaktır. (Tevbe sûresi: 32) İnsan yemesini azalttığı zaman içi nur dolar. (Hadîs-i şerîf-Deylemî) Kur’ân-ı kerîm. O hâlde Allah’a, O’nun peygamberlerine ve indirdiğimiz o nûr’a îmân edin. Allah ne yaparsanız hakkıyla haberdârdır. (Te-gâbün sûresi: 8) Îmân. Allahü teâlânın nûr vermediği kimsenin nûru olmaz. (Nûr sûresi: 40)","kategori":"dil","misal":"(Allahü teâlâ) aya bir nur vermiş; güneşi de ışık kaynağı yapmıştır. (Nûh sûresi: 16)","osmanli":"نور"},{"kelime":"NûR SûRESİ","anlam":"Kur’ân-ı kerîmin yirmi dördüncü sûresi.","kategori":"dil","misal":"Medîne’de nâzil oldu. Altmış dört âyet-i kerîmedir. Otuz beşinci âyetinde Allahü teâlânın, göklerin ve yerin nûru olduğu bildirildiği için, Sûretü’n-Nûr denilmiştir. Sûrede, zinâ suçu işleyen kadın ve erkekler ile zinâ iftirâsında bulunanların cezâları, evlere girerken izin istemek, selâm vermek gibi muâşeret kuralları, harama bakmanın kötülüğü, kadınların örtünmeleri ile Müslümanların Peygamber efendimize saygı gös…","osmanli":"سى سوره نور"},{"kelime":"NûRÂNÎ","anlam":"Nûrlu, ışıklı, parlak, mü-nevver. Zulmânî (karanlık) kelimesinin zıddı. NuSAYRİYYE: نصيريه (A) Onbirinci imâm Ha-","kategori":"dil","misal":"sen bin Ali el-Askerî’nin adamlarından İbni Nusayr’ın kurduğu, Şia’nın hulûl [Allah’ın in-san şeklinde görünmesi] itikadını benimseyen ve Suriye havâlisinde yayılıp tutunan aşırı kol-larından bir fırka. Nusayrîlik.","osmanli":"نورانى"},{"kelime":"NûŞ","anlam":"1.Tatlı; bal. 2.Zevk, safâ. 3.İçen.","kategori":"dil","osmanli":"نوش"},{"kelime":"NuSAYRİYYE","anlam":"Onbirinci imâm Ha-","kategori":"ibadet","misal":"sen bin Ali elAskerî’nin adamlarından İbni Nusayr’ın kurduğu, Şia’nın hulûl [Allah’ın insan şeklinde görünmesi] itikadını benimseyen ve Suriye havâlisinde yayılıp tutunan aşırı kollarından bir fırka. Nusayrîlik.","osmanli":"نصيريه"},{"kelime":"NuSH","anlam":"Nasihat, öğüt. (Bkz. Nasihat) Nush ile uslanmayanı etmeli tekdîr,","kategori":"dil","misal":"Tekdîr ile uslanmayanın hakkı kötektir. (Ziya Paşa)","osmanli":"نصح"},{"kelime":"NuSRET","anlam":"Yardım, imdâd.","kategori":"dil","misal":"Ben demek yani nefsine güvenmek kendini üs-tün görmek felâkettir. Nusret-i ilâhînin gelme-sine mâni olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"نصرت"},{"kelime":"NÜSÜK","anlam":"İbadet; haccederken belli zaman ve mekânda yapılması gereken vazife.","kategori":"ibadet","misal":"De ki: “Şüphesiz benim namazım, nüsüküm, hayâtım ve ölümüm âlemlerin Rabbi olan Allah içindir”. (En’âm sûresi: 162)","osmanli":"نسك"},{"kelime":"NÜŞûR","anlam":"Dağıtmalar, yaymalar; öl-dükten sonra dirilmeler. Neşr’in çokluk hâli.","kategori":"dil","osmanli":"نشور"},{"kelime":"NuSûS","anlam":"1.Doğruluğu şüphe götür-meyen sözler. 2.Âyet-i kerîme ve hadîs-i şerîf-ler.","kategori":"dil","misal":"Nass’ın çokluk hâli. Kıyas ve ictihâd, bid‘at değildir. Çünki bunlar. (Nusûs)un, yani âyetlerin mânâlarını meydâna çıkarmaktadırlar. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"نصوص"},{"kelime":"NuTFE","anlam":"1.Saf, duru su. 2.Meni, sperm, döl suyu.","kategori":"dil","misal":"İnsan toprak olup, topraktan nebât hâsıl olur, nebâttan hayvan yer ve hayvanı insan yer ve bundan nutfe hâsıl olup, yine insan peydâ olur. (Mektûbât-ı Ma’sûmiyye)","osmanli":"نطفه"},{"kelime":"NuTK","anlam":"Söz, söz söyleme kuvveti, akıl. Sükût (susmak), nutk (söylemek) gibi değil-dir. Fakat birtakım meselelerde sükût, nutk gi-bidir. (Eşbâh)","kategori":"dil","osmanli":"نطق"},{"kelime":"NÜVE","anlam":"Çekirdek; bir şeyin özü.","kategori":"dil","osmanli":"نوه"},{"kelime":"NÜZûL","anlam":"1.İnme. 2.Tasavvuf yolunda ilerleyerek, sebebler âlemini görmeyip yalnız sebeblerin sahibini yani Allahü teâlâyı bilme hâline ulaşan bir velînin insanları irşâd ve terbiye için, tekrar sebebler âlemine inmesi. İnsanları Allahü teâlânın rızâsına kavuşturan rehber ne kadar çok nüzûl ederse, rehberliği, irşâdı o kadar kuvvetli olur. İrşâd edebilmek için tâlib ile rehberin yakın olması lâzımdır. Bu da rehberin aşağı dereceye yani tâliblerin derecesine nüzûl etmiş olması ile olur. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"tasavvuf","osmanli":"نزول"},{"kelime":"ÖDÜNÇ VERMEK","anlam":"Bir malı kullanıp iade etmek veya tüketip mislini ver-mek üzere yapılan akid. Âriyet veya karz. (Bkz. Karz-ı Hasen, Âriyet)","kategori":"muamelat","osmanli":"ﭻندوا كمريو"},{"kelime":"ÖFKE","anlam":"Kızma, sinirlenme, hiddet.","kategori":"dil","misal":"(Bkz. Gadab) Cennet, Allahü teâlâdan korkanlar için ha-zırlandı. Bunlar az bulunsa da, mallarını Allah yolunda verirler. Öfkelerini belli et-mezler. Herkesi affederler. Allahü teâlâ ih-sân edenleri sever. (Âl-i İmrân sûresi: 133) Kızdığı zaman öfkesini yenerek yumuşak davranan kimseyi Allahü teâlâ sever. (Ha-dîs-i şerîf-İsfehânî)","osmanli":"اوفكه"},{"kelime":"OĞLAN","anlam":"1.Erkek çocuk. 2.Evlenmemiş kız ve erkek çocuğu, bâkir.","kategori":"dil","osmanli":"اوغلان"},{"kelime":"ÖLÇEK","anlam":"Umumiyetle sıvılarla hubu-batın, yani mekîl malların, alınıp satılması için kullanılan ölçülere verilen isim. Keyl. Hacim ölçüsü.","kategori":"ibadet","misal":"Hububatın zekâtı ölçek ile verilir. (Ni’met-i İslâm)","osmanli":"اولﭽك"},{"kelime":"ÖLÜM","anlam":"Rûhun bedene olan bağlılığının sona ermesi, ruhun bedenden ayrılması, mevt.","kategori":"akaid","misal":"Şân ü şöhret şerâfetinle dolsun, Halk-ı zaman hep emrinde bulunsun, Âhiri ölümdür ne hayaldesin. (Alvarlı Muhammed Lütfi)","osmanli":"اولوم"},{"kelime":"Ölüm Hastalığı","anlam":"İnsanı ölüm kor-kusuna sevk edip iş görmekten men eden ve başladığı tarihten itibâren en az bir yıl içinde ölüme götüren hastalık veya muharebede, ba-tan gemide, salgın bulunan şehirde olma gibi buna benzer tehlikeli hâller. Maraz-ı mevt.","kategori":"dil","osmanli":"خستهلغى اولوم"},{"kelime":"Ölüm Hastası","anlam":"İnsanı ölüm kor-kusuna sevk edip iş görmekten men eden ve başladığı tarihten itibaren en az bir yıl içinde ölüme götüren hastalık veya muharebede, ba-tan gemide, salgın bulunan şehirde olma gibi buna benzer tehlikeli hâller içinde bulunan kimse. Marîz-ı mevt.","kategori":"dil","osmanli":"خستهسى اولوم"},{"kelime":"ÖMR (Ömür)","anlam":"Hayat, yaşama, yaşayış.","kategori":"tasavvuf","misal":"Herkesin ömrü ve ömürlerin kısalması hep yazılıdır. (Fâtır sûresi: 11) İnsanların en iyisi, ömrü uzun, ameli güzel olan kimsedir. İnsanların en kötüsü, ömrü uzun, ameli kötü olandır. (Hadîs-i şerîfHâkim) Kıymetli ömrü lüzumsuz mübâhlara bile harcamamalıdır. Haramla geçirmemek ise elbette lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî) Ömür tamam olup defter dürülür, Sırat köprüsü ve mîzân kurulur, Hakk’ın dergâhında elbet dur…","osmanli":"عمر"},{"kelime":"ÖMRÎ","anlam":"Ömür ile kayıtlı. Farz olmakla beraber, yapılması hemen gerekmeyen.","kategori":"fikih","misal":"Zekâtın farz olması ömrî, yani gecikmelidir. Binaenaleyh ne zaman verilse eda sayılır. Fakat vermeden ölürse günahkâr olur. (İbni Âbidîn)","osmanli":"عمرى"},{"kelime":"ON LATÎFE","anlam":"On parça. İnsanı meydana getiren bir topluluk nümûnesi.","kategori":"tasavvuf","misal":"İnsana âlem-i sagîr (küçük âlem) denir. Bu âlem-i sagîr, on latîfeden meydana gelmiştir. Bunların beşi âlem-i emrdendir. (Bu âlemde madde ve ölçmek yoktur.) Bu beş latîfe, Kalb, Rûh, Sır, Hafî ve Ahfâ’dır. Bu beş latîfenin asılları, kökleri âlem-i kebîrdedir. (Âlem-i kebîr), büyük âlem demektir. İnsandan başka her şey demektir.) İnsanı meydana getirmiş olan on parçadan dördü katı, sıvı, gaz maddeleri ile enerjidir.…","osmanli":"لطيفه اون"},{"kelime":"ÖRF","anlam":"Dinin ve aklın güzel gördüğü, beğendiği şey; İslâm hukûkunun kaynakla-rından; (Bkz. Âdet)","kategori":"dil","misal":"Zamanın değişmesiyle, örf ve âdete dayanan ahkâm değişebilir. Nassa dayanan ahkâm za-manla değişmez. (Mecelle)","osmanli":"عرف"},{"kelime":"ORGAN NAKLİ","anlam":"Bir canlıdan bir doku veya organın, yerinden çıkartılarak başka bir canlıya nakledilmesi anlamında bir tıp terimi. Transplantasyon.","kategori":"dil","misal":"Hür insan ve hiçbir parçası mütekavvim mal değildir. Alınıp satılamaz, hibe ve vakfoluna-maz. İhtiyaç olduğu zaman organ nakli câiz-dir. Nitekim çocuğu emzirmek meşrudur. Kan nakline de cevaz verilmiştir. Eşbâh’da anlatıl-dığı üzere hâmile bir kadının vefatı üzerine İmâm Ebû Hanife karnının yarılmasını em-retmiş; çıkarılan çocuk çok yaşamıştır. (Seâ-det-i Ebediyye)","osmanli":"نقلى اورغان"},{"kelime":"ORTA YOL","anlam":"Din ve dünya işlerinde ifrad ve tefridden (aşırılıklardan) uzak yol. Orta yol deyince, iki şey anlaşılır: Birisi, herke-sin anladığı gibi, bir şeyin tam ortasıdır. Dâire-nin merkezi, kutru böyledir. İkincisi, izâfî, tak-dîrî orta olmaktır. Yani belli bir şeyin ortasıdır. O şeyin ortası olduğu için, her şeyin ortası ol-mak lâzım gelmez. Ahlâk bilgisinde kullanı-lan, bu ikinci ortadır. Bunun için, iyi huy, her-kese göre farklı olur. Hattâ, zamana ve mahalle göre de değişir. Birinde güzel olan bir huy, baş-kasında iyi olmayabilir. Bir zamanda iyi deni-len bir huy, başka zamanda iyi olmayabilir. O hâlde iyi huy, tam ortada olmak değil, ortala-mada olmaktır. Kötü huy da, bu ortalamanın iki tarafına ayrılmaktır. “İşlerin en iyisi, onla-rın ortasıdır” hadîs-i şerîfi de bunu bildirmekte-dir. Bundan dolayı, her iyi huya karşı, iki kötü huy bulunur. (Ahlâk-ı A’lâî)","kategori":"hadis","osmanli":"يول اورته"},{"kelime":"ORTODOKS","anlam":"1.”Doğru inanç sa-hibi” mânâsına Rum kilisesi için kullanılan tabir. 2.Rum kilisesine ve bunun temsil ettiği Ortodoksluk adlı mezhebe mensub","kategori":"dil","osmanli":"اورتودوقس"},{"kelime":"ORuÇ","anlam":"Fecrin (tan yerinin) ağarmasından (imsaktan), güneş batıncaya kadar yemeği, içmeği ve cimâ’ı terk etmeyi gerektiren ibâdet.","kategori":"ibadet","misal":"Hicretten 18 ay sonra, Şâban ayının onuncu günü, Bedr Gazâsı’ndan bir ay evvel farz oldu. (Seâdet-i Ebediyye) Orucun farzı üçtür: 1) Niyet etmek, 2) Niyeti ilk ve son vakitleri arasında yapmak. 3) İmsâk vaktinden güneş batmasına kadar olan zamanda orucu bozan şeylerden sakınmaktır. (Miftahü’l-Cenne) Oruç tutmanın on bir faydası vardır: Cehennem’e kalkan olur. Diğer ibâdetlerin kabulüne sebeb olur. Bedenin zikri olur…","osmanli":"اوروﭺ"},{"kelime":"Oruç Kazâsı","anlam":"Bir özür sebebiyle veya kasden farz olan orucu tutmayan kimsenin, Ramazan ayından sonra bu orucu tutması.","kategori":"ibadet","osmanli":"قضاسى اوروﭺ"},{"kelime":"Oruç Keffâreti","anlam":"Ramazân-ı şerîfte bilerek orucu bozmanın cezâsı.","kategori":"ibadet","misal":"Oruç keffâreti olan, bir köle âzâd eder. Köle âzâd edemeyen ard arda altmış gün oruç tutar. Keffâret orucu, hastalık, yolculuk gibi bir özürle veya bayram günlerine rastlamak sebebiyle bozulursa veya Ramazâna rastlarsa yeniden altmış gün tutmak lâzım olur. Kadın hayız ve nifas sebebiyle bozunca yeniden başlamaz. Temizlenince geri kalan günleri tutarak altmışa tamamlar. (Ni’met-i İslâm) Devamlı hasta veya çok yaşlı o…","osmanli":"كفارتى اوروﭺ"},{"kelime":"OSMOS","anlam":"İki sıvı veya iki gazın bazı cisimlerin gözenekleri arasından geçerek bir-birine karışması.","kategori":"dil","osmanli":"اوصموص"},{"kelime":"OSMOTİK","anlam":"Osmos ile alakalı.","kategori":"dil","osmanli":"اوصموتك"},{"kelime":"OYuN","anlam":"Beden veya zihin gücünün sadece zevk almak, dinlenmek ve eğlenmek maksadıyla yaptığı işler. La’b.","kategori":"dil","misal":"Dünya hayatı bir oyun ve eğlenceden başka bir şey değildir. Müttekîler için âhiret yurdu muhakkak ki daha hayırlıdır. Hâlâ akıl er-diremiyor musunuz? (En’am sûresi: 32) Her türlü oyun bâtıldır (şer’en muteber değildir). Yalnız, zevce ile oynamak, at ve silah ile ta-lim, yarış yapmak ve yüzmek böyle değil-dir. (Hadîs-i şerîf-Tirmizî, Ebû Dâvûd, İbn-i Mâce, Müsnedü İmâm-ı Ahmed) Allah rah-met etsin kardeşim Yahya’ya, küçükken iki çocuk kendisini oyuna çağırdıklarında; “Ben oyun için mi yaratıldım” buyurdu. O küçük iken bir oyun için böyle söylerse, yetişkinin günah işlemesindeki hâli nice olur. (Hadîs-i şerîf-İbni Asâkir) Oyun ile vakit geçirmek; tavla, satranç, on-dört taş oynamak mekrûhtur. Devamlı yapı-lırsa veya farzları yapmaya mâni’ olurlarsa ve kumâr ile yapılırsa, sözbirliği ile harâm olur-lar. (İbni Âbidîn)","osmanli":"اويون"},{"kelime":"ÖZR (Özür)","anlam":"1.Mazeret, mâni, engel; haraç, güçlük, meşakkat; kusur, eksiklik. 2.Af talebi, suçun bağışlanmasını istemek.","kategori":"fikih","misal":"Abdesti bozan bir şey, bir namaz vakti durdurulamayıp, devam ederse, özr olur. (İbni Âbidîn) Farz ve vâcib namazlar, şehir haricinde, ancak özr olunca hayvan üzerinde kılınabilir. Özr, inince arkadaşlarının gidip yalnız kılması, canı, malı, hayvanı için hırsız korkusu olması, yerin çamur olması, hayvana binmekten âciz olmak gibi şeylerdir. Müslüman kardeşinin özrünü kabul e…","osmanli":"عذر"},{"kelime":"Özr Sâhibi","anlam":"Edâsı farz olan herhangi bir namaz vakti içinde, namaz vaktinin başından sonuna kadar, abdest alıp yalnız farzı kılacak kadar bir zaman, abdestli kalamayan kimse.","kategori":"ibadet","misal":"Özr görüldüğü andan itibaren o kişi özr sahibi olur. Özür sahibinin özrü, sonraki her namaz vaktinde bir kere biraz çıkınca özrü devam ediyor sayılır. Bir farz namazın vaktinde hiç gelmezse yani bir namaz vakti başından sonuna kadar özürsüz geçerse, o kimse özür sahibi olmaktan kurtulur. (Halebî) Özür sahibi her namaz vakti için ayrı abdest alır. Abdestini bozan başka bir şey olmadıkça bu abdest ile o vakit içinde d…","osmanli":"صاحبى عذر"},{"kelime":"ÖZRLÜ (Özürlü)","anlam":"1.Dinen yapılması uygun olmayan bir işi yapmaya mecbur olan kimse.","kategori":"fikih","misal":"P","osmanli":"عذرلى"},{"kelime":"PANTEİZM","anlam":"Allahü teâlâ ile âlemi birleşmiş kabul eden felsefî inanç.","kategori":"akaid","osmanli":"ايزم ﭘانته"},{"kelime":"PAPA","anlam":"“Baba” mânâsına Katolik mezhebine mensub Hristiyanların en yüksek rûhânî (dinî) lideri.","kategori":"dil","misal":"Katoliklerce, Îsâ aleyhisselâmın yeryüzündeki hâkimiyetinin mümessili sayılan Havârî Aziz Petrus’un vekili kabul edilir. Kardinaller meclisi tarafından seçilir. Aynı zamanda Vatikan Devleti’nin reisidir. Katolik olmayan Hristiyanlar için Papa, yalnızca Roma patriğidir.","osmanli":"ﭘاﭘا"},{"kelime":"PAPAZ (Papas)","anlam":"“Baba” mânâsına Hristiyan din adamlarına verilen ad.","kategori":"dil","osmanli":"ﭘاﭘاز"},{"kelime":"PARA","anlam":"Mübâdele vasıtası olarak kulla-nılan, biriktirme ve tasarruf etmeye yarayan, çeşitli mâdenlerden veya kağıttan imal edil-miş değer ölçüsü.","kategori":"dil","misal":"Bir zaman gelecek ki, insanlar yalnız malın, paranın gelmesini düşünüp helâlini hara-mını düşünmeyecekler. (Hadîs-i şerîf-Kim-yâ-i Seâdet)","osmanli":"ﭘارا"},{"kelime":"PASKALYA","anlam":"Hristiyan inancına göre, Îsâ aleyhisselâmın çarmıha gerildikten sonra dirilerek göğe yükselmesinin kutlandığı bayram.","kategori":"dil","misal":"Aslı İbranice, esirgeme mânâsına pesay’dır. Paskalya, 21 Mart’tan sonraki ilk dolunayın ardından gelen Pazar günüdür. Gregoryen takvimine göre 22 Mart-22 Nisan arasında gerçekleşir. Şark kiliseleri bundan 13 gün sonra kutlar.","osmanli":"ﭘاسقاليه"},{"kelime":"PATRİK","anlam":"Ortodoks mezhebine mensub Hristiyanların, en büyük rûhânî (dinî)","kategori":"dil","misal":"lideri. Başpiskopos. Aslı, “hükümran baba” mânâsına patriark’dır. Patriğin salahiyetli sadece kendi patriklik mıntıkasıyla mahduttur. Bu bakımdan patrik ile papa arasında fark vardır. Her mıntıkadaki kilise, kendi patriğini seçmek üzere Sen Sinod teşkil eder. Sen Sinod, patriği seçer. Ortodoksluk dışındaki Şark kiliselerinin reislerine de patrik denir.","osmanli":"ﭘاتريك"},{"kelime":"PAZARLIK ETMEK","anlam":"Alış-ve-rişte satan ile alan arasında malın fiyâtı veya bir işin ücreti hususunda yapılan anlaşma. Birbirinizi kıskanmayınız. Alış-verişte bir-birinizi aldatmayınız. Birbirinize dargın durmayınız. Birbirinizden yüz çevirmeyi-niz. Birinizin bitmek üzere olan pazarlı-ğını bozmayınız. Müslüman Müslümanın kardeşidir. Ona zulmetmez. Onu yardımsız bırakmaz. Onu hor ve aşağı görmez. (Ha-dîs-i şerîf-Müslim)","kategori":"dil","misal":"Resûlullah aleyhisselâmın torunları İmâm-ı Hasen ve Hüseyn her aldıklarında pazarlık eder, ucuz almaya uğraşırlardı. Kendilerine; “Bir günde binlerle dirhem sadaka veriyorsu-nuz da, bir şey satın alırken niçin uzun pazar-lık ederek yoruluyorsunuz? dediklerinde; “Ver-diklerimizi Allah rızâsı için veriyoruz. Ne kadar çok versek yine azdır. Fakat alış-verişte aldan-mak, aklın ve malın noksan olmasıdır” buyu-rurlardı. (Kimyâ-i Seâdet)","osmanli":"ايتمك ﭘازارلق"},{"kelime":"PEÇE","anlam":"Kadınların sokakta gezerken yüzlerine örttükleri seyrek dokunmuş örtü.","kategori":"tasavvuf","misal":"Nikâb. Sarık, külah, peçe ve eldiven gibi şeylerin üzerine mesh câiz değildir. Çünki bunları çıkarıp altlarını yıkamakta güçlük yoktur. (İbni Âbidîn) Tavaf sırasında kadın yüzünü peçe ile örtmez. (Fethü’l-Kadîr)","osmanli":"ﭘﭽه"},{"kelime":"PERİ","anlam":"Cin. (Bkz. Cin)","kategori":"dil","osmanli":"ﭘرى"},{"kelime":"PERuK","anlam":"Başa giyilen saçlı serpuş. Peruka. Kadınların insan saçından peruk takmaları hadîs-i şerîf ile yasaklanmıştır.","kategori":"hadis","osmanli":"ﭘروق"},{"kelime":"PEŞİN SATIŞ","anlam":"Pazarlık yerin-den ayrılmadan önce mebî ve semenin da ayn olması.","kategori":"dil","misal":"Veresiye olduğu söylenmeyen bütün satışlar pe-şin satıştır. Peşin satış yapıp, semeni sonra te’cîl etmek de câizdir. (İbni Âbidîn)","osmanli":"صاتش ﭘشين"},{"kelime":"PEYGAMBER","anlam":"1.Haberci, haber getiren. 2.Allahü teâlânın, emirlerini ve yasaklarını kullarına bildirmeleri için insanlar arasından seçtiği ve kendilerine mûcizeler verdiği üstün zât. Allahü teâlâ, Âdem aleyhisselâmdan beri, her bin senede, bir Peygamber vâsıtası ile, insanlara bir din göndermişdir. Bu Peygamberlere “salevâtullahi teâlâ aleyhim ecma’în” (Resûl) denir. Her asrda, en temiz bir insanı Peygamber yaparak, bunlar ile dinleri kuvvetlendirmişdir. Resûllere tâbi’ olan bu Peygamberlere de, (Nebî) denir. Bütün Peygamberler, hep aynı îmânı söylemiş, hepsi ümmetlerinden aynı şeylere îmân etme…","kategori":"akaid","osmanli":"ﭘيغمبر"},{"kelime":"PÎR","anlam":"1.Yaşlı, ihtiyâr. 2.Mürşid-i kâmil, tasavvuf yolunda rehber zât.","kategori":"tasavvuf","misal":"Pîrini incitenden sen de incinmezsen, köpek sen-den daha iyidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ﭘير"},{"kelime":"PİSKOPOS","anlam":"Hristiyanlıkta bir kilise mıntıkasından mes’ûl yüksek din adamı, baş-papaz. Yunanca episkopos, ‘gözeten’ demektir.","kategori":"dil","osmanli":"ﭘسقوﭘوس"},{"kelime":"PİŞMANLIK","anlam":"Kişinin işlediği bir kabahat sebebiyle vicdânen üzüntü duyması; nedâmet.","kategori":"dil","misal":"Pişmanlık tövbedir. (Hadîs-i şerîf-Hâkim) Her geçen an, ömrümüz azalmakta, ecel (ölüm) zamanını yaklaştırmaktadır. Bugün aklımızı ba-şımıza toplamazsak, yarın âh etmekten ve piş-manlıktan başka elimize bir şey geçmez. (Mek-tûbât-ı İmâm-ı Rabbânî)","osmanli":"ﭘيشمانلق"},{"kelime":"PİYANGO","anlam":"Mal, para sahiplerinin haklarının mikdarlarını değiştirmek veya or-taklardan birinin hakkını yok etmek, yâhud hakkı olmayana pay vermek için kur’a çeke-rek oynanan bir cins kumar.","kategori":"dil","misal":"İki veya daha çok kimse, aralarında para top-ladıktan sonra kendi aralarında piyango çekip kazananların, vermiş oldukları paradan fazla almaları kumar olur. Geri kalan kısmı hayır kuruluşlarına bağışlamaları, bu piyangoyu kumarlıktan kurtarmaz. (Seâdet-i Ebediyye)","osmanli":"ﭘييانغو"},{"kelime":"POLİÇE","anlam":"Borcu, belli bir zaman sonra kendine veya adı yazılı başka bir kimseye ödemesi için alacaklının borçluya gönderdiği ödeme emri.","kategori":"muamelat","osmanli":"ﭘوليﭽه"},{"kelime":"PROTESTAN","anlam":"Protestanlık mezheblerinden birine mensub.","kategori":"fikih","misal":"Protesto eden demektir. İsmini, Roma kilisesinin hâkimiyetine karşı çıkan Alman papaz Martin Luther’i papanın aforoz etmesi üzerine, bu hareketi protesto edenlerden almıştır.","osmanli":"ﭘروتستان"},{"kelime":"PuL","anlam":"En küçük bakır para. Fels. (Bkz. Fülûs)","kategori":"dil","osmanli":"ﭘول"},{"kelime":"PuSuLA","anlam":"1.Yön tayinine yarayan âlet. 2.Üzerine yazı yazılmış küçük kâğıt parçası.","kategori":"fikih","osmanli":"ﭘوصوله"},{"kelime":"PuT","anlam":"Allahü teâlâya inanmayanların taptıkları resim veya heykel.","kategori":"akaid","misal":"Kureyş kâfirleri, putların kendilerine şefâat edeceklerini söylüyorlar. Onlara söyle ki, Allahü teâlânın izni olmadan hiç kimse şefâat edemez. (Zümer sûresi: 44) Putları, tapınılan heykelleri kırmak ve akrabâya iyilik etmek için gönderildim. (Hadîs-i şerîfEbû Nuaym)","osmanli":"ﭘوت"},{"kelime":"PuTPEREST","anlam":"Puta tapınan. (Allahü teâlâ) O’nu (Muhammed aleyhisselâmı) hak ve hakîkat olan dini tebliğ vazifesiyle göndermiştir ki, Hak din diğer dinlere gâlib gelsin.","kategori":"akaid","misal":"İdrîs aleyhisselâm diri olarak Cennet’e çıkarılınca, onu çok sevenler, ayrılık acısına dayanamadı. Resmini yapıp seyr eyledi. Daha sonra gelenler bu resimleri tanrı sandı. Çeşitli heykeller de yapıldı. Böylece putperestlik ortaya çıktı. (Mir’at-ı Kâinât) R","osmanli":"ﭘوتﭙرست"},{"kelime":"RA‘D SûRESİ","anlam":"Kur’ân-ı kerîmin on üçüncü sûresi.","kategori":"dil","misal":"Mekkî veya Medenî oluşu ihtilaflıdır. İki âyeti dışındakiler Medîne’de indiği de söylenir. Kırk üç âyet-i kerîmedir. Sûrenin on üçüncü âyetinde gök gürültüsü mânâsına gelen er-Ra‘d kelimesi sûreye isim olmuştur. Sûrede; Allahü teâlânın varlığı, birliği, ilminin sonsuzluğu, îmân etmekle mes’ûd olanların ve inkâr eden kötü tâlihlilerin vasıfları ve âkıbetleri ve Allahü teâlânın, Peygamber efendimizin peygamberliğine ş…","osmanli":"سى سوره رعد"},{"kelime":"RAB","anlam":"1.Efendi, sahip, mâlik, terbiye eden. 2.Allahü teâlânın sıfatlarından.","kategori":"dil","misal":"De ki: “Allah her şeyin rabbi iken, hiç ben Allah’tan başka rab mı isterim? Herkesin ka-zanacağı ancak kendine âittir. Hiçbir günah-kâr, başkasının günahını çekmez. Sonunda dönüşünüz Rabbinizedir. O vakit Allah, dünyada ayrılığa düştüğünüz şeyleri size haber verecektir.” (En’âm sûresi: 164) Allah bütün göklerin ve yerin ve aralarındakile-rin rabbidir. O hâlde O’na ibâdet et ve O’na ibâdet etmekte sabret... (Meryem sûresi: 65) Kazâ ve kaderime râzı olmayan, beğenme-yen ve gönderdiğim belâlara sabretmeyen benden başka Rab arasın. Yeryüzünde ku-lum olarak bulunmasın. (Hadîs-i Kudsî-Ta-berânî, Beyhekî)","osmanli":"رب"},{"kelime":"RÂB","anlam":"Süt baba; üvey baba.","kategori":"dil","osmanli":"راب"},{"kelime":"RABBÂNÎ","anlam":"1.Rabbe ait, Allahü teâlâdan gelen. 2.Kendisine ilim ve hikmet verilmiş, ilmi ile âmil âlim, ârif; Rabbe hâlis kul.","kategori":"akaid","misal":"Evliyânın sözünde Rabbânî te’sir vardır. (Abdülhakîm Arvâsî) Hiçbir insanın, Allah’ın kendisine Kitap, hikmet ve peygamberlik vermesinden sonra (kalkıp) insanlara; “Allah’ı bırakıp bana kul olun!” demesi mümkün değildir. Bilakis (şöyle demesi gerekir): “Kitabı öğrettiğinize, okuduğunuza göre, Rabbânîler olunuz.” (Âl-i İmrân sûresi: 79)","osmanli":"ربانى"},{"kelime":"RABBENÂ ÂTİNÂ","anlam":"Kur’ân-ı kerîmde zikredilen ve namazların teşehhüdünde okunması sünnet olan duâlardan.","kategori":"dil","misal":"Aslı “Rabbenâ âtinâ fi’d-dünya haseneten ve fi’l-âhireti haseneten ve kınâ azabe’n-nâr” (Bakara sûresi: 201) olup, meâli; “Ey Rabbimiz! Bize dünyada da iyilik ver, âhirette de iyilik ve bizi ateşin azâbından koru!” şeklindedir.","osmanli":"آتنا ربنا"},{"kelime":"RABBENÂ LEKEL HAMD","anlam":"“Ey Rabbimiz hamd sanadır “ mânâsına namazda rükû’dan doğrulunca okunması sünnet olan söz.","kategori":"ibadet","misal":"İmâmdan evvel hareket etmeyin. Tekbir alınca alın. “Veleddâllîn” deyince “âmîn” deyin. Rükû’ edince rükû’ edin. “Semi’allahü limen hamideh” deyince “Rabbenâ lekel hamd” deyin ve İmâmdan evvel başınızı kaldırmayın. (Hadîs-i şerîfMüslim) Cemâatle namazda, imâm; “Semiallahü limen hamideh” deyince, cemâat çok yavaşca “Rabbenâ lekel hamd” der. İmâm bunu söylemez. (Halebî) Tahmidin en faziletlisi Allahümme rabbenâ velekel…","osmanli":"الحمد لك ربنا"},{"kelime":"RABBÎ","anlam":"“Rabbim” mânâsına bir yakarış kelimesi.","kategori":"dil","osmanli":"ربى"},{"kelime":"RÂBITA","anlam":"1.İki şeyi birbirine bağlayan şey, irtibat vâsıtası. 2.Bir velînin şeklini, sûretini hayâline getirerek onun kalbindeki feyz ve mârifetlere kavuşma yolu.","kategori":"tasavvuf","misal":"“Ey îmân edenler. Allah’a bağlanınız ve sâdıklarla beraber olunuz” meâlindeki âyet-i kerîmede râbıtaya işâret vardır. (Risâle-i Hâlidiyye) Râbıta, kalbin Allahü teâlâdan başka şeyleri sevmekten, onları düşünmekten kurtulmasına vesîle olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"رابطه"},{"kelime":"RABT","anlam":"Bağlama, iliştirme.","kategori":"dil","osmanli":"ربط"},{"kelime":"RADÂ‘ (Redâ’)","anlam":"Süt emme, süt kardeşliği.","kategori":"dil","osmanli":"رضاع"},{"kelime":"RÂDİ‘","anlam":"Süt kardeş; süt çocuğu.","kategori":"dil","misal":"Radî’, süt anababa ve akrabâsının hepsiyle evlenemediği gibi, süt anababa da radî’nin evlâdı, zevc veya zevcesi ile evlenemez. (İbni Âbidîn)","osmanli":"راضع"},{"kelime":"RADIYALLAHÜ ANH","anlam":"Sahâbîler için söylenen ve “Allah ondan râzı olsun!” mânâsına bir övgü ifadesi.","kategori":"dil","misal":"İki kişi için Radıyallahü anhümâ, ikiden fazlası için Radıyallahü anhüm denir. Hanım sahâbîler için radıyallahü anhâ, iki tanesi için radıyallahü anhümâ, ikiden fazlası için radıyallahü anhünne gelir.","osmanli":"عنه الله رضى"},{"kelime":"RÂFİ‘","anlam":"1.Ref ’ eden, yükselten. 2.Mü’min-lerin ve evliyânın derecelerini yükselten ve huzurunda başlarını kaldırarak pak cemâline bakmak ile mertebelerini yükselten mânâsına Allahü teâlânın Esmâ-i hüsnâsından (er-Râfi’). (Ey Meryem oğlu Îsâ) Seni kendime râfi’yim (Âl-i İmrân sûresi: 55) Er-Râfi‘ ism-i şerîfini söyleyen, zâlimlerin zul-münden emin olur. Beş yüz kere söyleyenin maddî mânevî ihtiyâcı giderilir. (El-İstigâse-tü’l-Kübrâ)","kategori":"dil","osmanli":"رافع"},{"kelime":"RÂGIB","anlam":"Rağbet eden, istekli.","kategori":"dil","osmanli":"راغب"},{"kelime":"RAGÎBET","anlam":"Rağbet olunan, istenen; ihsan, ikrâm. Çokluk hâli regâib gelir.","kategori":"dil","misal":"Receb-i şerîfin ilk Cum‘a gecesine Regâib gecesi denir. Çünki Allahü teâlâ bu gecede, mü’min kullarına ragibetler yapar. O gece yapılan duâ, namaz, oruç, sadaka gibi, ibâdetlere kat kat se-vab verilir. O geceye hürmet edenleri affeyler. (Mevlid Risâlesi-Abdülhakîm Arvâsî)","osmanli":"رغيبت"},{"kelime":"RÂH","anlam":"Yol; meslek, usûl.","kategori":"fikih","osmanli":"راه"},{"kelime":"RÂH-I İCTİBÂ","anlam":"Tasavvufta Allahü teâlâya kavuşturan yollardan biri.","kategori":"akaid","misal":"Seçilmişlerin yolu. (Bkz. İctibâ)","osmanli":"اجتباء راه"},{"kelime":"RÂHİB","anlam":"1.Ruhban sınıfına mensub, Hristiyan din adamı. 2.Evlenmeyip, manastırda yaşayan ve yalnız ibadetle meşgul din adamı.","kategori":"dil","misal":"Evleniniz, çoğalınız. Ben sizin çokluğunuzla diğer ümmetlere karşı iftihar ederim. Hristiyan râhibleri gibi olmayınız. (Hadîs-i şerîfBeyhekî)","osmanli":"راهب"},{"kelime":"RAHÎM","anlam":"1.Çok ve devamlı merha-met sahibi. 2.Âhirette günahkâr Müslümanlara acıyan mânâsına Allahü teâlânın Esmâ-i hüsnâsın-dan (er-Rahîm).","kategori":"dil","misal":"Andolsun ki, size kendinizden öyle bir pey-gamber gelmiştir ki, sizin sıkıntıya uğrama-nız O’na çok ağır gelir. Çünki O, size çok düşkün, mü’minlere karşı raûf (şefkatli) ve rahîmdir. (Tevbe sûresi: 128) Şüphesiz ki, Allahü teâlâ Gafûrdur, Rahîm-dir. (Zümer sûresi: 53) Ben ziyâdesi ile tövbe kabul edici ve Rahîmim. (Bakara sûresi: 53) Şeytân; “Allahü teâlâ Rahîm’dir, affeder” diye-rek insanı günah işlemeye sürükler. (Mektû-bât-ı İmâm-ı Rabbânî) Her kim her gün yüz kere Rahîm ism-i şerîfini söylerse, kalbinde rikkat ve mahlûkâta karşı merhamet peydâ olur. (El-İstigâsetü’l-Kübrâ)","osmanli":"رحيم"},{"kelime":"RAHİMEHuLLAH","anlam":"“Allah ona rahmet eylesin” mânâsına umumiyetle vefat etmiş din büyükleri için kullanılan ta’zim sözü.","kategori":"akaid","misal":"İki kişi için, rahimehumallah; daha çok kimse için, rahimehumullah; kadın için rahimehallah denir.","osmanli":"الله رحمه"},{"kelime":"RAHMÂN","anlam":"“Dünyada dost olsun düşman olsun, lâyık olsun olmasın, mü’min olsun kâfir olsun, bütün mahlûklara merhamet edip, rızık ve nimetler veren” mânâsına Allahü teâlânın Esmâ-i hüsnâsından (erRahmân).","kategori":"akaid","misal":"Her kim namazdan sonra yüz defâ Rahmân ism-i şerîfini söylerse, Allahü teâlâ onun kalbinden nisyan ve gafleti çıkarır. (Elİstigâse-tü’l-Kübrâ)","osmanli":"رحمن"},{"kelime":"RAHMÂNÎ","anlam":"Rahman olan Allah’a mensub; Allah’tan gelen ve hayırlı olan.","kategori":"akaid","misal":"Zıddı şeytânî gelir.","osmanli":"رحمانى"},{"kelime":"RAHMET","anlam":"1.Acıma, merhamet, şef-kat gösterme. 2.Bereketli, faydalı yağmur.","kategori":"dil","misal":"(Ey Resûlüm!) De ki: “Ey (günah işlemekle) nefslerine karşı haddi aşmış kullarım! Al-lah’ın rahmetinden ümidi kesmeyiniz. Çünki Allahü teâlâ (şirk ve küfürden başka dilediği kimselerden) bütün günahları magfiret bu-yurur, bağışlar. Şüphesiz ki O, Gafûr’dur, Rahîm’dir. (Zümer sûresi: 53) Yâ Rabbî! Bize rahmetini ihsân eyle. İhsân sahibi ancak sen-sin. (Âl-i İmrân sûresi: 8) Biz seni ancak âlem-lere rahmet olarak gönderdik. (Enbiyâ sûresi: 107) Allahü teâlâ rahmeti yüz parçaya ayır-mış, doksan dokuzunu kendisinde bırakmış, yeryüzüne bir parça indirmiştir. İşte bütün mahlûklar bu parça sebebiyle birbirlerine merhamet ederler. (Hadîs-i şerîf-Müslim) Allahü teâlâdan korkmalı, fakat O’nun rahme-tinden ümidi kesmemelidir. Ümid, korkudan çok olmalıdır. Böyle olanın ibâdetleri zevkli olur. (Berîka) Allahü teâlâ rüzgârı, rahmetinden önce müj-deci olarak gönderir. Rüzgârlar, ağır olan bu-lutları sürükler. Bulutlardan ölü olan toprağa su yağdırırız. O yağmurla yerden meyveler çıkarırız. Ölülerini de mezârlarından böyle çıkaracağız. umulur ki, düşünüp ibret alır-sınız. (A’râf sûresi: 57)","osmanli":"رحمت"},{"kelime":"Rahmet Kapısı","anlam":"Duâların kabul edildiği, lutf, ihsân ve bereket kapısı.","kategori":"ibadet","misal":"Ey mü’minler topluluğu müjdeler olsun, müjdeler olsun size. İşte Rabbiniz sema kapılarından bir rahmet kapısını size açtı. Ve sizinle meleklerine karşı iftihar ederek onlara şöyle buyuruyor: “Benim kullarıma bakınız. Bir farzı eda ettiler, diğerini bekliyorlar.” (Hadîs-i şerîfİbn-i Mâce) Bir kimse âmir olur da, miskine, mazluma veya hacet sahibine kapısını kaparsa, Allahü teâlâ onun en şiddetli ihtiyacı zamanında ra…","osmanli":"تمحر ىسوپاق"},{"kelime":"Rahmet Melekleri","anlam":"Yeryüzünde dolaşan ve mü’minlerin ölümü ânında hâzır olan melekler.","kategori":"akaid","misal":"Resim, köpek ve cünüp kimse bulunan eve rahmet melekleri girmez. (Hadîs-i şerîfHâkim) Hangi evde Kur’ân-ı kerîm okunursa, orada bereket, bolluk olur, şeytânlar uzaklaşır, melekler oraya hücûm eder. Hangi evde Kur’ân-ı kerîm okunmazsa, o evde darlık, sıkıntı, huzursuzluk başgösterir. Rahmet melekleri oradan uzaklaşır ve şeytânlar orayı istilâ eder. (İhyâ)","osmanli":"ملكلرى رحمت"},{"kelime":"RAHMETEN Lİ’L-ÂLEMÎN","anlam":"“Âlemlere rahmet” mânâsına Resûlullah aleyhisselâmın isimlerinden.","kategori":"dil","misal":"Biz seni ancak rahmeten li’l-âlemîn gönderdik. (Enbiyâ sûresi: 107) Geldi çün ol rahmeten li’l-âlemîn Vardı nûr anda karâr kıldı hemîn (Mevlid-i Süleymân Çelebi)","osmanli":"للعالمين رحمة"},{"kelime":"RAHMETuLLAHİ ALEYH","anlam":"“Allah’ın rahmeti onun üzerine olsun” mânâsına daha ziyade din büyükleri için söylenen hürmet sözü.","kategori":"akaid","misal":"İki kişi için rahmetullahi aleyhimâ, daha çok kimse için rahmetullahi aleyhim; kadın için rahmetullahi aleyhâ, kadınlar için rahmetullahi aleyhinne denir.","osmanli":"عليه الله رحمة"},{"kelime":"RAKÎB","anlam":"1.Murâkabe eden, kontrol eden. 2.Her şeyi hakkıyla gören, gözeten, koruyan, bir an onlardan habersiz olmayan, murâka-besi devamlı olan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (er-Rakîb). Allahü teâlâ her şeyi rakîbdir. (Ahzâb sû-resi: 52)","kategori":"ibadet","osmanli":"رقيب"},{"kelime":"RÂM","anlam":"İtaat eden, boyun eğen.","kategori":"dil","osmanli":"رام"},{"kelime":"RASADHÂNE","anlam":"Gökyüzünün ast-ronomik olarak rasat edildiği, gözlendiği yer. RÂSID: راصد (A. Rasad’dan) Rasad eden, gözleyen.","kategori":"dil","osmanli":"رصدخانه"},{"kelime":"RÂŞİD","anlam":"1.Rüşd sahibi, doğru yolda olan. 2.Akıl ve idrak vererek, peygamber ve kitap göndererek insanlara rüşd yolunu gös-teren mânâsına Allahü teâlânın Esmâ-i hüs-nâsından (er-Râşid). Allah size imanı sevdirmiş ve onu gönülle-rinize sindirmiştir. Küfrü, fıskı ve isyanı da size çirkin göstermiştir. İşte râşidler bunlar-dır. (Hucurât sûresi: 7)","kategori":"akaid","osmanli":"راشد"},{"kelime":"RÂSİH","anlam":"1.Rüsûh sahibi, sarsılmaz, sâbit. 2.Kur’ân-ı kerîmin ve hadîs-i şerîflerin derin ve ince mânâlarını, işâretlerini, müteşâbihle-rini anlayan (âlim).","kategori":"dil","misal":"(Bkz. Ulemâ-i Râsihîn) Onun (Kur’ân’ın) bazı âyetleri muhkemdir ki, bunlar Kitab’ın esasıdır. Diğerleri de müteşâbih âyetlerin peşine düşerler. Hâl-buki onun te’vîlini ancak Allah bilir. Râsih âlimler ise inandık; hepsi Rabbimiz tarafın-dadır, derler. (Âl-i İmrân sûresi: 7) “Ümme-timin âlimleri, İsrâil oğullarının Peygam-berleri gibidir” şerefi ile müşerref olan, râsih ilmli âlimlerdir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"راسخ"},{"kelime":"RÂSİM","anlam":"Resim yapan, çizgi çizen.","kategori":"dil","osmanli":"راسم"},{"kelime":"RÂTİBE","anlam":"1.Maaş; vazife. 2.Farz namazdan önce ve sonra kılınan sünnet namaz.","kategori":"hadis","misal":"Nâfile ve râtibeler, yalnız namaz kılmaya veya sünnetten başka bir namaza niyet ederek kılınca, sahih olur. (Eşbâh)","osmanli":"راتبه"},{"kelime":"RAûF","anlam":"1.Re’fet sahibi, merhamete lâyık olmayanlara da merhamet gösteren. 2.Kullarına karşı merhâmeti çok olan ve yap-tıkları iyilikleri zâyî etmeyen mânâsına Al-lahü teâlânın Esmâ-i hüsnâsından (er-Raûf). Muhâcirlerden (Mekke’den göç eden) ve Ensârdan (Medîneli Müslümanlardan) sonra, kıyâmete kadar gelen mü’minler; “Yâ Rabbî! Bizi affet ve bizden önce gelen din kardeş-lerimizi affet. Kalblerimizde, îmân eden-lere karşı hiçbir kin bırakma! Rabbimiz! Şüphesiz ki sen Raûf ’sun, Rahîm’sin” der-ler. (Haşr sûresi: 10) Kızgınlık ânında kim on defâ er-Raûf ism-i şerî-fini söyler ve Peygamber efendimize salevât-ı şerîfe okursa öfkesi geçer, sâkinleşir. (El-İstigâ-setü’l-Kübrâ)","kategori":"dil","misal":"Size kendinizden öyle bir peygamber gel-miştir ki, sizin sıkıntıya uğramanız, O’na çok ağır ve güç gelir. Size (îmânınıza ve hâ-linizin salâhına, iyi olmasına) çok düşkün-dür. Mü’minlere karşı raûf ve rahîmdir. (Tevbe sûresi: 128)","osmanli":"رؤف"},{"kelime":"RAVDA-İ MÜBÂREKE","anlam":"“Mübârek, bereketli bahçe” mânâsına Medîne-i Münevvere’deki Mescid-i Nebevî’de Resûlullah aleyhisselâmın kabri ile minber arasındaki kısım.","kategori":"dil","misal":"(Bkz. Ravda-i Mutahhara)","osmanli":"مباركه روضهء"},{"kelime":"RAVDA-İ MuKADDESE","anlam":"“Mukaddes bahçe” mânâsına Medîne-i Münevvere’deki","kategori":"hadis","misal":"Mescid-i Nebevî’de Resûlullah aleyhisselâmın kabri ile minber arasındaki kısım. (Bkz. Rav-da-i Mutahhara)","osmanli":"مقدسه روضهء"},{"kelime":"RAVDA-İ RIDVÂN","anlam":"“Rıdvan adlı meleğin bahçesi” mânâsına Cennet için","kategori":"hadis","misal":"kullanılan tabir.","osmanli":"رضوان روضهء"},{"kelime":"RAVDA (Ravza)","anlam":"Bahçe, çayır, çimenlik.","kategori":"hadis","osmanli":"روضه"},{"kelime":"RÂVEND","anlam":"Kökleri ve sapları ilâç olarak kullanılan karabuğdaygillerden bir nebat.","kategori":"hadis","osmanli":"راوند"},{"kelime":"RÂVÎ","anlam":"Rivâyet eden, nakleden; duy-duğu veya gördüğü bir sözü, bir işi, bir olayı başkasına haber veren; Hadîs-i şerîfleri, me-tin ve sened ile birlikte nakleden hadîs âlimi.","kategori":"hadis","osmanli":"راوى"},{"kelime":"RÂYİC","anlam":"1.Revaçta, halk arasında ge-çerli olan. 2.Bir malın piyasa kıymeti, alınıp satıldığı fiyat.","kategori":"dil","misal":"Mangır [fülûs] râyic iken, mehr olarak şu ka-dar bin mangır diyerek nikâh yaptıktan sonra, mangır kâsid [geçmez] olsa, zevce vefât etse, vâ-rislerine kesâd günü olan kıymetleri kadar al-tın, gümüş kıymetleri verilir. (Feyziyye)","osmanli":"رايج"},{"kelime":"RÂZ","anlam":"Sır, gizlenilen şey.","kategori":"dil","osmanli":"راز"},{"kelime":"RÂZIK","anlam":"1.Rızk veren, yiyecek, içecek gibi kendisi ile faydalanılan şeyi veren. 2.Ya-rattığı her mahlûkun rızkını yaratıp gönde-ren mânâsına Allahü teâlânın isimlerinden (er-Râzık).","kategori":"akaid","misal":"Allahü teâlâ râzıkların en hayırlısıdır. (Hacc sûresi: 58)","osmanli":"رازق"},{"kelime":"REBÎ‘uL-ÂHİR","anlam":"Hicrî kamerî se-nenin dördüncü ayı.","kategori":"akaid","osmanli":"الآخر ربيع"},{"kelime":"REBÎ‘uL-EVVEL","anlam":"Hicrî kamerî se-nenin üçüncü ayı.","kategori":"dil","misal":"Rebî‘ bahar mânâsınadır. Birinci rebî‘ çiçek-lerin açıp mantarların bittiği; ikinci rebî‘ ise meyvelerin yetiştiği mevsimdir. Halk arasında bu iki aya Mevlid Kandili’nden dolayı Büyük Mevlid ve Küçük Mevlid denir. Resûl-i ekrem aleyhisselâm (mîlâdın beş yüz yetmiş birinci yılı Nisan ayının yirmisine rast-layan) Rebî‘ul-evvel ayının on ikinci Pazar-tesi gecesi, sabaha karşı Mekke-i Mükerreme şehrinde dünyaya gelmiştir. Dünyanın her ta-rafındaki Müslümanlar, her sene, bu geceyi, mevlid kandili olarak kutlamaktadır. (Mevâ-hib-i Ledünniyye)","osmanli":"اول ربيع"},{"kelime":"RECÂ","anlam":"1.Ümid etmek, ummak. 2.Allahü teâlânın rahmetini ummak, rahme-tinden ümit kesmemek.","kategori":"dil","misal":"Sebebine yapışmadan bir şey beklemeye te-mennî denir. Sebebine yapıştıktan sonra bek-lemeye recâ denir. Temennî, insanı tembelliğe götürür; recâ ise, çalışmaya sebeb olur. (Berîka) (Bkz. Havf ve Recâ) Havf ile recâ yemin etmişler ki, kimde yerle-şirlerse o adam Cehennem kokusu koklama-yacak ve kimden ayrılırsa o adam Cennet ko-kusu koklamayacaktır. (Hadîs-i şerîf-Beyhekî)","osmanli":"رجاء"},{"kelime":"RECEB","anlam":"Hicrî kamerî ayların yedincisi, üç ayların birincisi, eşhurü’l-haramın (haram olan dört ayın) birincisi.","kategori":"fikih","misal":"Göze büyük ve heybetli görünen kimseye hürmet mânâsına gelir. Bu ayda sular bollaşır, nehirler coşar ve bu hâdise göze büyük gözükürdü. Câhiliye devrinde Receb ayına çok hürmet edilirdi. Recebü’l-Mücerreb demek âdettir. Regâib ve Miraç kandilleri bu aydadır. Receb büyük bir aydır. Allah bu ayda hasenatı kat kat eder. Kim Recebden bir gün oruç tutarsa, sanki bir yıl oruç tutmuş gibi olur. Kim ondan yedi gün oruç tuta…","osmanli":"رجب"},{"kelime":"RECM","anlam":"1.Taşlama. 2.Kovma. 2.Zinâ eden kadın ve erkeği, şartları varsa, taşlayarak öldürme.","kategori":"dil","misal":"Andolsun ki biz, (dünyaya) en yakın olan göğü kandillerle donattık. Bunlarla şeytân-ları recm ettik ve onlara alevli ateş azâbını hazırladık. (Mülk sûresi: 5) Zinâ yapan muhsanlar dövülür ve recm olu-nur. Muhsan olmayanlar ise dövülüp sürgün edilir. (Hadîs-i şerîf-Buhârî, Hâkim) Muhsan, yani âkıl-bâliğ, hür, Müslüman ve başından zifafla neticelenmiş bir nikâh geçmiş bir erkek veya kadın zinâ eder, bu da dört hür, erkek, Müslüman ve âdil şâhid ile ispat edilmiş ise veya kendileri tarafından dört kere itiraf edilmiş ise, recm olunur. (İbni Âbidîn)","osmanli":"رجم"},{"kelime":"REDÂ‘","anlam":"Süt emme. (Bkz. Rıdâ‘)","kategori":"dil","osmanli":"رضاع"},{"kelime":"REDDİYE","anlam":"1.Geri veriş, geri çevirme. 2.Bir fikri reddetmek için söylenen söz; yazılan yazı, kitap. 3.Ferâizde (İslâm mîrâs hukûkunda), Eshâb-ı ferâiz adı verilen Kur’ân-ı kerîmde hisseleri bildirilen mîrâsçılar hisselerini aldıktan sonra terike artmış ise ve kalanı alacak kimse yoksa, artan terikenin yine aynı mirasçılar arasında payları oranında taksim edilmesi. Bu sûretle hisse alanlara Eshâb-ı red denilir. Zevc ve zevce dışındaki Eshâb-ı ferâiz redd…","kategori":"miras","osmanli":"رديه"},{"kelime":"REF‘","anlam":"Yukarı kaldırma, yükseltme. Kitabda İdrîs’i de (aleyhisselâm) an. Çünki o, çok sâdık bir peygamberdi. Biz onu yük-sek bir mekâna (göklere veya Cennet’e) ref‘et-tik. (Meryem sûresi: 56, 57) Doğrusu Allah onu (Îsâ aleyhisselâmı) ref‘ edip himâyesine almıştır. Allah Azîz’dir. Hükmünde hikmet sahibidir. (Nisâ sûresi: 158) Biz, dilediğimizi derecelerle ref‘ ederiz ve her ilim sahibinin üstünde bir âlim vardır. (Yûsuf sûresi: 76) (Ey Resûlüm! Biz) Senin şânını (ismini ezân ve ikâmetlerde okunmakla) ref‘ etmedik (yük-seltmedik) mi? (İnşirâh sûresi: 4)","kategori":"dil","osmanli":"رفع"},{"kelime":"REFÂH","anlam":"Bolluk, genişlik, sıkıntıdan uzak olma.","kategori":"dil","osmanli":"رفاح"},{"kelime":"REFÎ‘","anlam":"1.Ref eden, yükselten. 2.Allahü Teâlânın sıfatlarından (er-Refî‘)","kategori":"akaid","osmanli":"رفيع"},{"kelime":"REFÎK","anlam":"1.Refâkat eden, yol-daş, dost, arkadaş. 2.Rıfk sahibi, yumuşak huylu.","kategori":"dil","misal":"(A. Rıfk’dan) Kim Allahü teâlâya ve Resûl’e itâat ederse, işte onlar Allah’ın kendilerine lütuflarda, ih-sânlarda bulunduğu peygamberler, sıddîkler, şehîdler ve sâlih kişilerle beraberdir. Bunlar ne güzel refiktirler. (Nisâ sûresi: 69) Evden evvel komşu, yoldan evvel refik ve göçten evvel azık. (Hadîs-i şerîf-Hatîb) Vefatından sonra geriye kırk hadîs bırakan Cennet’te benim refikimdir. (Hadîs-i şerîf-Deylemî) (Bkz. Rıfk) Allahü teâlâ refîktır, rıfkı (yumuşaklığı) se-ver. Sertlik edenlere vermediği şeyleri ve başka hiçbir şeye vermediğini yumuşak davranana ihsân eder. (Hadîs-i şerîf-Buhârî, Müslim, Ebû Dâvûd)","osmanli":"رفيق"},{"kelime":"Refîk-i A‘lâ","anlam":"1.En yüksek dost, Allahü teâlâ. 2.Peygamberlerin, evliyânın, şehidlerin ve sâlih kimselerin ruhlarının bulunduğu yer.","kategori":"akaid","misal":"Ölüm hastalığında Resûl-i ekrem aleyhisselâm, dünyada kalmakla, âhirete kavuşmak hususunda serbest bırakıldığı vakit; “Allah’ım, senden Refîk-i a‘lâ’yı isterim” buyurdu. (Hadîs-i şerîfBuhârî, Müslim) Ruhun bedendeki hâlinden başka hâlleri vardır. Mü’min öldükten sonra, ruhu, Refîk-i A’lâ denilen mertebede bulunur. Bedenle alâkası d…","osmanli":"الاعلى رفيق"},{"kelime":"REFORM","anlam":"1.Yeniden şekil verme; dü-zeltme, ıslah etme. 2.XVI.","kategori":"dil","misal":"asırda Katolik kili-sesinin ve doktrininin hâkimiyetine karşı çı-kanların yürüttüğü faaliyet.","osmanli":"رفورم"},{"kelime":"REFREF","anlam":"1.İnce, yumuşak kumaş; dö-şek. 2.Resûlullah aleyhisselâmın Mi’râc esnâ-sında bindikleri yaygı.","kategori":"dil","misal":"Söyleşirken Cebrâil ile kelâm, Geldi Refref önüne verdi selâm. (Mevlid-i Süleymân Çelebi)","osmanli":"رفرف"},{"kelime":"REGÂİB GECESİ","anlam":"Mübârek gecelerden. Receb ayının ilk Cum‘a gecesi.","kategori":"ibadet","misal":"Regâib, rağbet olunan, istenen, ihsan, ikrâm mânâsına ragîbetin çokluk hâlidir. Beş gece vardır ki onlarda yapılan duâ geri çevrilmez: Recebin ilk Cum‘a gecesi olan Regaib Gecesi, Şâbanın on beşinci gecesi olan Berat Gecesi, Cum‘a gecesi, Ramazan bayramı gecesi, Kurban bayramı gecesi. (Hadîs-i şerîfİbni Asâkir) Allahü teâlâ, Regâib gecesinde mü’min kullarına, ragîbetler yapar. Regâib gecesinde yapılan duâ red olmaz…","osmanli":"سى كيجه رغائب"},{"kelime":"REHBER","anlam":"Yol gösteren, kılavuz; mürşid.","kategori":"tasavvuf","misal":"Allahü teâlânın sevgili Peygamberi Muhammed aleyhisselâm; insanların rehberi, her bakımdan en güzeli, en iyisi ve en üstünüdür. (Mektûbât-ı İmâm-ı Rabbânî) Allahü teâlâyı tanımaya çalışmak, bunun için, İslâm ahlâkını bilen ve Cenâb-ı Hakk’a kavuşturma yolunu gösteren bir rehber aramak ve ona uymak, İslâmiyet’in emirlerindendir. (Kim-yâ-i Seâdet) İnsanlara rehberlik eden kimsede şu hasletler bulunmazsa, o rehberlik y…","osmanli":"رهبر"},{"kelime":"REHN (Rehin)","anlam":"Bir sebebten dolayı bir şeyi habsetmek, alıkoymak; ödenecek mal karşılığında bir malı, alacaklıda veya başka emin bir kimse elinde emânet bırakmak.","kategori":"muamelat","misal":"Rehn, borç ödeninceye kadar habs olunur. Önce borç ödenir; sonra rehn geri verilir. (İbni Âbidîn) Alacaklı; rehnin, borçlunun mülkünden çıkmasına sebeb olamaz, satamaz, kirâya veremez. Rehni, ancak borçlunun izni ile kullanabilir. (Dürerü’l-Hükkâm) Borçlu, rehndeki malını, alacaklının izni olmadan satamaz. Satmak için isteyemez. (İbni Âbidîn)","osmanli":"رهن"},{"kelime":"REÎS","anlam":"Baş, başkan. Aslı re’s gelir.","kategori":"dil","osmanli":"رئيس"},{"kelime":"REK‘AT","anlam":"Bir defa rükû‘ edip yüz üstü kapanmak.","kategori":"ibadet","misal":"İki rek‘atten az namaz olmaz. Akşamın farzı ile vitirden başka, her namaz çift rek‘atlidir. (Tahtâvî)","osmanli":"ركعت"},{"kelime":"REKÂBET","anlam":"1.Gözleme, gözetleme. 2.Ra-kib olma, yarışa çıkma, birbirini çekememe. 1.Gevşeklik, zayıflık. 2.Sefihlik, akıl hafifliği, malını ak- lın ve dinin uygun görmediği yere sarf etme. 3.Kekemelik, tutukluk.","kategori":"ibadet","misal":"REKÂKET: ركاكت (A. Rakîk’den)","osmanli":"رقابت"},{"kelime":"REMEL (Reml)","anlam":"Hac ibâdeti yerine getirilirken, tavâfın ilk üçünde, erkeklerin kısa adımlarla, omuzları silkerek, çalımlı yürümeleri.","kategori":"ibadet","misal":"Remel, haccın sünnetlerindendir. Resûlullah aleyhisselâm, Mekke’yi feth edip Kâbe’yi tavâf esnâsında, Eshâbı ile birlikte remel yaparak tavâf ettiler. Bu şekilde yapmalarının sebebi; karşıdan onları seyreden ve Müslümanların zayıf düştükleri kanâatinde olan Mekkeli müşriklere, mü’minlerin güçlü ve azimli olduklarını göstermek içindi. İşte bu sünnet, o hâdisenin hâtırâsıdır. (Fethü’l-Kadîr)","osmanli":"رمل"},{"kelime":"REŞÎD","anlam":"1.Rüşd sahibi. 2.Mahlûkâta (yarattıklarına) doğru yolu göste-rip, dilediğini bu yolda bulunduran mânâsına Allahü teâlânın Esmâ-i hüsnâsından (er-Reşîd). Er-Reşîd ism-i şerîfini söyleyenin yaptığı amel-ler kabul olur. (El-İstigâsetü’l-Kübrâ)","kategori":"dil","misal":"Âkıl-bâliğ olup, malını yerli yerince tasarruf etme kabiliye-tini haiz. Çocuk bâliğ olunca, malını kullanmaya hak kazanır. Fakat reşîd olduğunun alâmetleri gö-rülmezse, yirmi beş yaşına kadar malı kendine teslim edilmez. (İbni Âbidîn)","osmanli":"رشيد"},{"kelime":"RESÎDE","anlam":"Erişmiş, yetişmiş, olgunlaşmış.","kategori":"dil","osmanli":"رسيده"},{"kelime":"RESM","anlam":"1.Yazma, çizme. 2.Eser, iz. 3.Plan, proje. 4.Usul. 5.Vergi.","kategori":"fikih","osmanli":"رسم"},{"kelime":"RESMÎ","anlam":"1.Devlet ile alâkalı. 2.Merasimle olan. 3.Resme, yazıya dair. 4.Çok ciddî, teklifli.","kategori":"osmanli","osmanli":"رسمى"},{"kelime":"RESûL","anlam":"1.Risâlet eden, gönderilen, haberci, elçi. 2.Peygamber.","kategori":"dil","misal":"Onlara o şehir (Antakya) halkını misâl getir. Hani oraya (Îsâ aleyhisselâmın gönderdiği) resûller gelmişti. Biz o zaman kendilerine iki resûl göndermiştik de onları yalanlamış-lardı. Biz de bir üçüncü ile bunları takviye etmiştik de; “Hakîkat, biz size gönderilmiş resûlleriz” demişlerdi. (Yâsîn sûresi: 13, 14) Birisinden ödünç istemek için vekil olunmaz. Bunun için, resûl göndermek câizdir. Malı is-terken, kendi için isterse, vekîl olur ki, câiz de-ğildir. Falanca kimse, senden ödünç istiyor di-yerek alırsa, resûl olur. Alışveriş için vekil edilen kimse, kendi için söz keserse, vekîl olur. Gönderen kimse için söz keserse, resûl olur. (İbni Âbidîn) Umumiyetle yeni bir şeriat ge-tiren peygamber için kullanılan tabir. Resûl size ne verdiyse onu alın, size ne ya- sakladıysa ondan da sakının. Allahü teâlâ-dan korkun. Çünki Allah’ın azâbı çetindir. (Haşr sûresi: 7)","osmanli":"رسول"},{"kelime":"Resûl-i Ekrem","anlam":"“En şerefli peygamber” mânâsına Muhammed aleyhisselâmın lakabı.","kategori":"akaid","misal":"Resûl-i ekrem (sallallahü aleyhi ve sellem) bütün âlemlere rahmet, canlı ve cansız her mahlûka peygamber olarak gönderilmiştir. (Abdülhak-ı Dehlevî)","osmanli":"اكرم رسول"},{"kelime":"RESûLuLLAH","anlam":"“Allahü teâlânın resûlü, elçisi” mânâsına Muhammed aleyhisselâmın lakabı.","kategori":"akaid","misal":"Muhammed, sizin erkeklerinizden hiçbirinin babası değildir. Fakat o, Resûlullah ve hâtemennebiyyîndir. (Ahzâb sûresi: 40) Muhammed Resûlullah’tır. (Feth sûresi: 29) Ben gümüşten mühür edindim ve üzerine “Muhammedün Resûlullah” nakşettirdim. Kimse böyle bir mühür kullanmasın. (Hadîs-i şerîfBuhârî)","osmanli":"الله رسول"},{"kelime":"REVÂ","anlam":"Yakışır, uygun, yerinde.","kategori":"dil","osmanli":"روا"},{"kelime":"REVÂC","anlam":"1.Râyiç olma, sürüm, geçer-lilik. 2.Kıymet.","kategori":"dil","osmanli":"رواج"},{"kelime":"REVÂFID","anlam":"Râfizîler. Şia’nın kolla-rından. Hazret-i Ebû Bekr ve Hazret-i Ömer’i hayırla andığı için İmâm Zeyd’i terk eden ve Zeyd’in “terkedenler” mânâsına Râfıdîler de-diği topluluk. Hazret-i Ebû Bekr ve Ömer’in","kategori":"dil","misal":"halîfeliğini kabul etmeyenlerin müşterek ismi olmuştur.","osmanli":"روافض"},{"kelime":"REVÂKIYYûN","anlam":"Zenon adında bir Yunan filozofunun kurduğu ve revak altında ders verdiği için bu ismi alan, insanın kendisini akla, tabiatın düzenine, yani kadere uydurarak yaşaması gerektiğini müdafaa eden, vazife hissini ve faziletli insanın mesud olabileceğini vurgulayan…","kategori":"akaid","misal":"Stoacılar.","osmanli":"رواقيون"},{"kelime":"REVÂTİB","anlam":"1.Râtibeler, rütbeler, vazi-feler, maaşlar. 2.Beş vakit namazın önünde ve arkasında kılınan nâfile namazlar.","kategori":"ibadet","misal":"Revâtib sünnetler nâfile niyeti ile veya yalnız namaza niyet etmekle sahîh olur. Yani o vak-tin sünneti olur. Ayrıca sünnet diye niyet et-meye lüzum yoktur. (Eşbâh)","osmanli":"رواتب"},{"kelime":"REVŞEN","anlam":"Gidiş, yürüyüş; usûl.","kategori":"fikih","osmanli":"روشن"},{"kelime":"REYHÂN","anlam":"1.Fesleğen. 2.Güzel koku.","kategori":"dil","misal":"REZÂLET: رذالت (A) Rezillik, kepazelik, alçak-lık, arsızlık, utanılacak hâl, utanç verici şey- ler, kötü ahlâka, kötü iş yapmaya sebeb olan şeyler, hâller.","osmanli":"ريحان"},{"kelime":"REZÎL","anlam":"Alçak, itibârsız, hayasız; çok utanılacak bir hâle düşen; maskara.","kategori":"tasavvuf","misal":"Kim din kardeşinin ayıbını ararsa, Allah da onu rezil eder. (Hadîs-i şerîfMüsnedü İmâm-ı Ahmed)","osmanli":"رذيل"},{"kelime":"Rİ‘ÂYET","anlam":"1.Gütme, gözetme. 2.Sayma; hürmet, i’tibâr. 3.Ağırlama.","kategori":"ibadet","osmanli":"رعايت"},{"kelime":"RİBÂ","anlam":"1.Artma, çoğalma, fazlalık. 2.Alışveriş, ödünç, rehn gibi akidlerde, iki taraftan birinin diğerine taahhüd ettiği karşılıksız fazlalık veya belli malların birbiriyle veresiye satılması. Allahü teâlâ bey’i (alışverişi) helâl ve ribâyı ise haram kılmıştır. (Bakara sûresi: 275) Allahü teâlâ ribâ karışan malı yok eder ve sadakaları verilen malı artırır (ona bereket verir). (Bakara sûresi: 276) Aralarında, zinâ ve ribâ yayılan bir memlekette bulunanlara, Allahü teâlânın azâbı helâl oldu. (Hadîs-i şerîfHâkim) Fâiz (ribâ) almak ve vermek, insanın son nefesinde îmânsız gitmesine sebeb olabilir. (Kutbüddîn…","kategori":"muamelat","osmanli":"رباء"},{"kelime":"RİBH","anlam":"Fâide, kâr.","kategori":"dil","osmanli":"ربح"},{"kelime":"RİC‘Î TALÂK","anlam":"Dönülebilir boşama. Erkeğin zifafa girmiş olduğu zevcesini açık bir sözle, bir ivaza (bedele, karşılığa) bağlamaksızın bir defa boşaması.","kategori":"dil","misal":"Ric‘î talâkta zevc (koca), iddet zamanı içinde (talâktan sonra ilk temizlik müddetinin başından, üçüncü hayzın sonuna kadar olan müddette, hayız görmeyenlerde üç ay içinde) söz ile veya fiilen eski nikâhına rücû‘ edebilir (dönebilir). Evliliği devam eder. Şâhid lâzım olmaz ise de iki âdil şâhide haber vermesi müstehâb olur. (İbni Âbidîn)","osmanli":"طلاق رجعى"},{"kelime":"RİCS","anlam":"Pis, murdâr; çirkin.","kategori":"dil","misal":"Ey îmân edenler! İçki, kumar, (tapmaya mah-sus) dikili taşlar, fal okları, ancak şeytânın amelinden birer “rics”tir. Onun için bunlar-dan kaçının ki kurtulasınız. (Mâide sûresi: 90) (Ey Resûlüm!) Deki: Bana vahy olunan-lar (bildirilenler) içinde, yiyen bir kimsenin yiyeceği arasında dediğiniz gibi haram edil-miş bir şey bulmuyorum. Yalnız haram ola-rak şunlar var: Leş, yâhud akıcı kan, yâhud domuz eti ki o şüphesiz ricstir... (En’âm sûresi: 145) Resûlullah aleyhisselâm hâcete çıktıkla-rında; “Allahümme innî E’ûzü bike mine’r-ri-csi’l-habîsi’l-muhbisi mine’ş-şeytâni’r-racîm” (Ya Rabbi! Her türlü ricsden ve habislikten ve kovulmuş şeytânlıktan sana sığınırım) derdi. (Hadîs-i şerîf-Tirmizî)","osmanli":"رجس"},{"kelime":"RİDÂ","anlam":"Belden yukarıya giyilen elbise, üst elbisesi.","kategori":"dil","misal":"Bir rida ile namaz, ancak ihram gibi geniş olursa, câizdir. (Hadîs-i şerîfTaberânî) Kibriyâ (büyüklük) Allahü teâlânın ridâsı, azamet ise izarıdır. Bunlarda Allahü teâlâ ile ortak olmaya çalışana kıyamet günü acınmaz. (Hadîs-i şerîfBuhârî)","osmanli":"رداء"},{"kelime":"RIDÂ‘ (Redâ‘)","anlam":"İki buçuk yaşından küçük çocuğun bir kadından süt emmesi.","kategori":"dil","misal":"Evlenmede nesepten haram olanlar, rıdâ’dan da haram olur. (Hadîs-i şerîfTirmizî) Rıdâ’ sebebiyle çocuğun, süt anası ve süt babası ile ve bunların anaları, babaları ve kardeşleri ve çocukları ve her kuşaktan torunları ile evlenmesi ebedî haramdır. (Alâüddîn-i Haskefî)","osmanli":"رضاع"},{"kelime":"RİDDET","anlam":"Dönme, irtidâd etme, İslâm dininden çıkma. İslâmiyet’te had cezası gerek-tiren suçlardan. (Bkz. İrtidâd)","kategori":"dil","misal":"Riddet, niyetle yani kalbinden dinden çıkmaya karar vermekle yâhud küfr olan söz veya fiil ile İslâm’dan alâkayı kesmek ile olur. (el-Mizâ-nü’l-Kübrâ)","osmanli":"ردت"},{"kelime":"RIDVÂN","anlam":"1.Razı olma, memnun olma. 2.Cennet meleklerinin reisi.","kategori":"dil","misal":"Takvâ sahipleri için Rableri yanında, için-den ırmaklar akan, ebediyyen kalacakları cennetler, tertemiz eşler ve Allah’ın rıdvânı vardır. (Âl-i İmrân sûresi: 15) RIDVÂNuLLAHİ TEÂLÂ ALEYHİM EC- Daha (A) رضوان الله تعالى عليهم اجمعين MAÎN: ziyade Eshâb-ı kirâmın isimleri anılınca söy-lenen, “Allahü teâlânın rızâsı onlar üzerine ol-sun” mânâsına, duâ ve hürmet ifâdesi. Bir kişi için rıdvânullahi teâlâ aleyh, iki kişi için rıd-vânullahi teâlâ aleyhimâ denir. Hanımlar için rıdvânullahi teâlâ aleyhinne denir.","osmanli":"رضوان"},{"kelime":"RIFK","anlam":"Yumuşaklık, refiklik.","kategori":"dil","misal":"Allahü teâlâ refiktir; rıfkı sever! (Hadîs-i şerîf-Buhârî, Müslim, Ebû Dâvûd)","osmanli":"رفق"},{"kelime":"RİKKAT","anlam":"Rakiklik, yufkalık, incelik; merhamet, acıma.","kategori":"dil","misal":"İslâm âlimleri, dini, îmânı kuvvetlendiren ve ahlâkı güzelleştiren, şiirleri, kasîdeleri, ilâhî-leri ve mevlidleri dinlemek; kalbdeki Allah sevgisini ve rikkati arttırır buyurmuşlardır. (Mekâtib-i Şerife)","osmanli":"رقت"},{"kelime":"RİND","anlam":"Kalender, dünya işlerini hoş gö-ren kimse, aldırışsız. Çokluk hâli rindân gelir. Perde ardındaki esrârı açmak, uygun değildir, Yoksa, rindler meclisinde, verilmeyecek ha-ber yoktur.","kategori":"dil","misal":"(Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"رند"},{"kelime":"RİSÂLE","anlam":"1.Mektûb. 2.Bir meseleye, bir ilme ve fenne dâir yazılan müstakil küçük kitap. 1.Elçilik, habercilik. 2.Pey- gamberlik.","kategori":"dil","misal":"RİSÂLET: رسالت (A) (Bkz. Peygamberlik) Resûl-i Ekrem aleyhisselâmın ganimetin beşte birindeki hakları risaletleri sebebiyledir. Vefat-larıyla her ne kadar risaletleri kesilmemiş ise de, fakat Resûl olarak kendilerinden sonra hiç bir kimsenin kendilerinin yerine geçmesi müm-kün olmadığı için risalet sebebi yok olmuştur. (İbni Âbidîn) Fahr-i âlem girdi çün kırk yaşına, Kondu pes, risâlet tâcı başına. (Mevlid-i Süleyman Çelebi)","osmanli":"رساله"},{"kelime":"RİSÂLETPENÂHÎ","anlam":"Resûlullah aleyhisselâm için kullanılan hürmet tabiri. RİVÂYET: روايت (A) Bir sözü haber vermek,","kategori":"dil","misal":"nakletmek; haber verilen şey. Hazret-i Ali radıyallahü anhtan gelen rivâyet-lerde şöyle buyruldu: “Kalbler, kaplara benzer. Hayırlı olan, hayırla dolu olandır.”","osmanli":"رسالتﭘناهى"},{"kelime":"RITL","anlam":"130 dirhem-i şer’îlik (436.8 gram) bir ağırlık ölçüsü.","kategori":"dil","misal":"130 dirhem-i şer’îlik (436.8 gram) bir ağırlık ölçüsü. Abdestte ve gusülde, lüzumundan fazla su kullanmak israf olup, haramdır. Sekiz rıtl su ile sünnete uygun gusledilebilir. (İbni Âbidîn)","osmanli":"رطل"},{"kelime":"RİVÂYET","anlam":"Bir sözü haber vermek,","kategori":"hadis","misal":"nakletmek; haber verilen şey. Hazret-i Ali radıyallahü anhtan gelen rivâyetlerde şöyle buyruldu: “Kalbler, kaplara benzer. Hayırlı olan, hayırla dolu olandır.”","osmanli":"روايت"},{"kelime":"RİYÂ","anlam":"Gösteriş, iki yüzlülük; kendini olduğundan başka gösterme. (Bkz. Mürâî) Veyl (şiddetli azap) namaz kılanlara ki, na-mazlarından gâfildirler. Namazı ehemmiyet-siz sayarlar. Riyâkarlık ederler. Namazlarını insanların yanında riyâ ile kılarlar. (Tenhâda yalnız kılınca terk ederler.) Zekât ve âriyet (ödünç) vermeyi de men ederler. (Mü’min sûresi: 4-7) Kim riyâ yaparsa, Allah onun bu riyâsını açık eder. (Hadîs-i şerîf-Taberânî) Riyâ sahibinin üç alâmeti vardır. Yalnız iken tembeldir. İnsanlar arasında iken çalışkan ve hareketli görünür. Övüldüğü zaman çok çalı-şır. Zemmedildiği, kötülendiği zaman çalışma-sını azaltır. (Hazret-i Ali)","kategori":"hadis","osmanli":"رياء"},{"kelime":"RİYÂKÂR","anlam":"İkiyüzlü, içi dışı bir olmayan.","kategori":"dil","osmanli":"رياكار"},{"kelime":"RİYÂSET","anlam":"Reislik, başlık. RİYÂZİYYE: رياضيه (A) Hesap ilmi, matematik. RÖNESANS: سانس رونه (Fr) “Yeniden doğuş”","kategori":"dil","misal":"mânâsına Avrupa’da XV. asırdan sonra ilim, sanat, edebiyat ve felsefe sahasında açılan par-lak yeni çığıra ve yaşanan parlak değişiklik-lere verilen isim.","osmanli":"رياست"},{"kelime":"RİYÂZET","anlam":"1.Terbiye etmek; ıslah et-mek; idman. 2.Nefsin isteklerini yapmamak mânâsına tasavvuf tabiri.","kategori":"tasavvuf","misal":"İnsanlar, riyâzet deyince, açlık çekmeği ve oruç tutmağı anladılar. Hâlbuki dinimizin emrettiği kadar yemek için dikkat etmek, binlerce sene nâfile oruç tutmaktan daha güç ve daha fay-dalıdır. Bir kimsenin önüne lezzetli tatlı yemek-ler konsa, iştihâsı olduğu hâlde ve hepsini ye-mek istediği hâlde, dinimizin emrettiği kadar yiyip, fazlasını bırakması, şiddetli bir riyâzettir ve diğer riyâzetlerden çok üstündür. Bir kimse, bin sene ibâdet etse ve sıkıntılı riyâzetler çekse ve sıkı mücâhede (nefse zor gelen şeyler) yapsa, eğer bir Peygamber-i zîşâna uymamış ise, bü-tün bu çalışmalarının bir arpa kadar kıymeti olmaz. Çölde görülen serâb gibi, hiçbir şeye ya-ramaz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"رياضت"},{"kelime":"RIZÂ","anlam":"Râzı olma, hoşnudluk, memnunluk; tasavvufta kaderin tecellileri karşısında kalbin huzur ve sükûn içinde bulunması.","kategori":"tasavvuf","misal":"Zahmet ve meşakkatlere, sıkıntılara katlanarak aradığımı, annemin rızâsını almakta buldum. Çok basit gibi gelen anne rızâsını almanın bütün işlerin evvelinde lâzım olduğunu anladım. (Bâyezîd-i Bistâmî)","osmanli":"رضاء"},{"kelime":"RIZK (Rızık)","anlam":"Nasib, hisse; insanın yaşaması ve ebedî saadete kavuşması için gereken maddî ve manevî nimet.","kategori":"miras","misal":"Dünyadaki maddî ve mânevî bütün rızıklarını aralarında taksim ettik. (Zührûf sûresi: 32) Allahü teâlâ tarafından rızkı gönderilmeyen yeryüzünde bir canlı yoktur. (Hûd sûresi: 6) İstemeksizin ve uğraşmaksızın Allah sana bir rızık gönderirse onu alın! Zira Allahü teâlâ onu sana ikram etmiştir. (Hadîs-i şerîfİbni Hibbân) Rızık mukadderdir, ezelde takdir edilmiş, ayrılmıştır. Fazla ve noksan ihtimâli yoktur. Rızkın noks…","osmanli":"رزق"},{"kelime":"RÜ’YÂ","anlam":"1.Görmek. 2.Uykuda görülen şeyler, düş, insanın kalbinin ve his uzuvlarının dünya işleriyle olan meşguliyetinin kısmen kesildiği, uyku, bayılma ve istiğrak (mânevî coşkunlukla kendinden geçme) gibi hâllerde gördüğü şeyler. Ey İbrâhim! Gerçekten rüyana sadâkat gösterdin. (Sâffât sûresi: 105) En doğru rüya, seher vakti görülendir. (Hadîs-i şerîfBeyhekî) Sâlih rüya Allah’tan, karışık olan da şeytândandır. (Hadîs-i şerîfBuhârî) Rü’yâ üç çeşittir: 1) İnsanın günlük işlerinin bilhassa arzu edip de kavuşamadığı bazı isteklerinin uykuda ortaya çıkması ile gördüğü rüyalar. Psikoloji ilminde mevzu edilen rüyalar bu çeşittir. 2) Şeytânın insanı…","kategori":"tasavvuf","osmanli":"رؤيا"},{"kelime":"RÜ’YET","anlam":"Görmek; tasavvufta kalb gözüyle Allahü teâlâyı görmek şeklinde ifade edilen, kalbde yakîn hâsıl olması.","kategori":"tasavvuf","osmanli":"رؤيت"},{"kelime":"RuB‘","anlam":"Dörtte bir.","kategori":"dil","osmanli":"ربع"},{"kelime":"RuB‘-I DÂİRE","anlam":"Namaz vakitlerinin hesaplanmasında, yükseklik ölçülmesinde ve bazı trigonometrik hesapların yapılmasında kullanılan el âleti.","kategori":"ibadet","misal":"Üsturlâb.","osmanli":"دائره ربع"},{"kelime":"RuBû‘","anlam":"Dörtte birler. Rub‘un çokluk hâli. RuBYE: روبيه (F) Umumiyetle Hindistan ve ci-varındaki memleketlede geçer akçe olan para.","kategori":"dil","misal":"Rupi. Aslı dörtte bir mânâsına rubu’dur.","osmanli":"ربوع"},{"kelime":"RuBûBİYYET","anlam":"(Bkz. Rübûbiyyet)","kategori":"dil","osmanli":"ربوبيت"},{"kelime":"RÜBûBİYYET (Rubûbiyyet)","anlam":"Rablik, efendilik; ilâhlık, ma’bûdluk, her dilediğini yapma büyüklüğü.","kategori":"dil","misal":"İmâm-ı A’zâm, İmâm-ı Ca’fer-i Sâdık’tan sual edip; “Yâ İbn-i Resûlillah! Allahü teâlâ, insanların istekli işlerini, onların arzularına bırakmış mıdır” dedikte, cevabında; “Allahü teâlâ, rubûbiyyetini kullara bırakmaktan münezzehtir” buyurdu. Yine sual edip; “Onlara cebreder mi” dedikte, cevabında; “Cebr yoktur. Yaratmağı kullara bırakmak da yoktur. İkisi arası olagelmektedir” buyurdu. (Mektûbât-ı Ma’sûmiyye) Allahü…","osmanli":"ربوبيت"},{"kelime":"RuCû‘","anlam":"(Bkz. Rücû‘)","kategori":"dil","osmanli":"رجوع"},{"kelime":"RÜCû‘","anlam":"1.Dönme, yönelme. 2.Ric’î talâkla boşadığı zevcesine kavlen veya fiilen geri dönmek. 3.En yüksek mertebeye ulaşmış olan bir velî-nin tekrar geri insanlar arasına dönmesi mânâ-sına tasavvufî tabir.","kategori":"dil","misal":"Ric’î talâkta koca, iddet zamanı içinde, söz ile veya fiilen, eski nikâha rücû’ edebilir. (İbni Âbidîn) Tövbe ederek, Allahü teâlâya rücû’ etmek, O’nun rızâsını kazanma yolunun başlangı-cıdır. Hiçbir insan, tövbenin dışında kalmaz. (Kimyâ-i Seâdet)","osmanli":"رجوع"},{"kelime":"RûH","anlam":"1.Can; bedene hayatiyet (canlılık) veren kuvvet.","kategori":"akaid","misal":"Ey Resûlüm! Sana rûhtan soruyorlar. De ki: Rûh, Rabbimin emrindendir. (O’nun yarattığı varlıklardan biridir. Bu husûsta) size, az bir ilimden başkası verilmemiştir. (İsrâ sûresi: 85) Mü’minlerin rûhları yedinci kat göktedir. Ve oradan Cennet’teki makamlarına bakarlar. (Hadîs-i şerîfDeylemî) Rûhun nasıl olduğunu dinimiz açıkça bildirmedi. Rûh madde değildir. Sıfat da değildir. İnsan öldükten sonra rûhu yok olmaz. İdr…","osmanli":"روح"},{"kelime":"RûHÂNÎ","anlam":"1.Rûha ait, ruh ile alâkalı. 2.Gözle görülemeyen, cismi olmayan. 3.Bir mezhebin işlerine ait.","kategori":"akaid","osmanli":"روحانى"},{"kelime":"RûHÂNİYÂN","anlam":"Rahmet melekleri. Mukarrebûn (huzur-i ilâhîde bulunan melekler), Kerrûbiyân (azap meleklerinin büyükleri) ve Rûhâniyân meleklerinin hepsi, diğer meleklerin havâssı yani üstünleridir.","kategori":"akaid","misal":"Bunlar, peygamberlerden başka, bütün insanlardan daha üstündür. (İtikâdnâme)","osmanli":"روحانيان"},{"kelime":"RûHÂNİYYET","anlam":"1.Rûhla alâkalı. 2.Vefat eden bir mü’minin rûhunun manevî kudretinin devam etmesi. 3.Rûhânîlik, din adamlığı.","kategori":"dil","misal":"Hadîs-i şerîfte; “Kavmi arasında bir âlim, üm-meti arasında peygamber gibidir” buyruldu. Kalbin, feyz ve mârifetlere kavuşmasında; Allah adamının diri ve ölü olması arasında hiç fark yoktur. Onun kemâlâtı, rûhâniyyetinden hiç ayrılmaz. Rûhâniyyet de, zamana ve mekâna, ölülüğe ve diriliğe bağlı değildir. (Râbıta-ı Şerife) Üveysiyye, rûhâniyyetten feyz almak demektir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"روحانيت"},{"kelime":"RûHÂNİYYûN","anlam":"Rûhânîler. Gözle görünmeyen, latîf mahlûklar.","kategori":"akaid","misal":"Ruhânîyyûn üç sınıftır: Hep iyilik yapan, ahyâr. Melekler böyledir. Hep kötülük yapan, eşrâr. Şeytânlar böyledir. İyilik de, kötülük de yapan, evsât. Cinler böyledir. (Lugat-i Nâci)","osmanli":"روحانيون"},{"kelime":"RûHBÂN","anlam":"1.Korkma, çekinme. 2.Evlenmeden bekâr yaşamayı tercih eden, dünyadan yüz çevirip, insanlardan uzak yaşayan kimseler. 3.Hristiyan din adamları, râhibler.","kategori":"dil","misal":"İnsanların îmân edenlere düşmanlık bakımından en şiddetlisi, andolsun ki, Yahudilerle Allah’a eş koşanları bulacaksın. Onların îmân edenlere sevgisi bakımından daha yakınını da andolsun “Biz nasrânîleriz” diyenleri bulacaksın. Bunun sebebi şudur: Çünki onların içinde keşişler ve ruhbanlar vardır. Şüphe yok ki onlar kibirlenmezler. (Mâide sûresi: 82) İslâmiyet’te ruhbanlık yoktur. (Hadîs-i şerîfMenâhicü’l-İbâd)","osmanli":"رهبان"},{"kelime":"RûHBÂNİYYET (Ruhbanlık)","anlam":"1.Evlenmeksizin dünyadan yüz çevirme. 2.Hristiyan din adamlığı.","kategori":"akaid","misal":"Allahü teâlâ beni ruhbâniyyetle göndermedi. Allah katında dinin hayırlısı kolay tevhid yoludur. (Hadîs-i şerîfİbni Sa’d, Taberânî) Cihad, Müslümanların ruhbâniyyetidir. (Hadîs-i şerîfNesâî)","osmanli":"رهبانيت"},{"kelime":"RuHSAT","anlam":"1.İzin, kolaylık. 2.Bir meşakkat, zaruret ve ihtiyaç sebebiyle, hafifletilmiş şer’î hüküm.","kategori":"akaid","misal":"Namazda ayakta duramayanın oturarak kılması; hasta veya yolcunun Ramazan orucu tutmayıp, sonra kazâ etmesi ruhsattır. Allahü teâlâ misafirlere ve gebe ile emzikli kadınlara oruç tutmamak hakkında ruhsat vermiştir. (Hadîs-i şerîfEbû Dâvûd, Tirmizî, Nesâî) Azîmetleri yapın; ruhsatları da kabul edin. Din kolaylıktır. (Hadîs-i şerîfHâtib, Taberânî) Bir kimsenin nefsi, kolaylıkları yapmak istemezse, bunun azîmetleri bıra…","osmanli":"رخصت"},{"kelime":"RÜKN","anlam":"1.Bir şeyin en kuvvetli, sağlam tarafı, esas, kâide, prensip. 2.İbâdet, akid gibi her çeşit dinî işin sahih olması için gereken aslî unsur.","kategori":"fikih","misal":"İnanılacak şeyleri kalb ile tasdik imanın rüknüdür. Kalb ile tasdik olmazsa iman olmaz. Tehdid altında bulunanın dil ile imanını söylememesi onun imanına zarar vermez. Çünki dil ile ikrâr imanın aslî rüknü değildir. (Şerh-i Mevâkıf) Namazın beş rüknünden birincisi kıyâm, ikincisi kırâet, üçüncüsü, rükû’; dördüncüsü, secdeler; beşincisi, ka’de-i âhiredir. Her kim bu beş rüknden birini terk ederse, namazı bozulur. Nam…","osmanli":"ركن"},{"kelime":"Rükn-i Irâkî","anlam":"Kâbe’nin Bağdad’a karşı olan köşesi.","kategori":"fikih","osmanli":"عراقى ركن"},{"kelime":"Rükn-i Şâmî","anlam":"Kâbe’nin Şam’a karşı olan köşesi.","kategori":"fikih","osmanli":"شامى ركن"},{"kelime":"Rükn-i Yemânî","anlam":"Kâbe’nin Yemen tarafında olan köşesi.","kategori":"fikih","misal":"Hacerü’l-Esved ile Rükn-i Yemânî’ye el sürmek günahları bol bol döker. (Hadîs-i şerîfNesaî)","osmanli":"يمانى ركن"},{"kelime":"RÜKû‘","anlam":"1.Eğilmek, beli bükmek, yüz üstü kapanmak; boyun eğmek, itaat etmek. 2.Namazın farzlarından olup, kıyamdan sonra elleri dizlere koyup eğilme.","kategori":"ibadet","misal":"Namazları kılınız ve zekât veriniz ve rükû‘ edenlerle birlikte rükû‘ ediniz. (Bakara sûresi: 43) Rükû‘ ve secdeleri tam yapınız! (Hadîs-i şerîfBuhârî, Müslim)","osmanli":"ركوع"},{"kelime":"RuKYE","anlam":"Şifâ âyetleri ve duâlarını yazmak, okuyup hasta üzerine üflemek veya üzerinde taşımak.","kategori":"dil","misal":"Rukyelerinizi bana arzedin! İçinde şirk olmadıktan sonra rukyenin bir zararı yoktur. (Hadîs-i şerîfMüslim) Kur’ân-ı kerîm ve duâ ile rukye yapmak ve kullanmak câiz olup insanı korur. Kur’ân-ı kerîm, maddî ve mânevî her derde şifâdır ve her harfi mübârektir ve muhteremdir. (İbni Âbidîn)","osmanli":"رقيه"},{"kelime":"RûM SûRESİ","anlam":"Kur’ân-ı kerîmin otuzuncu sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Altmış âyet-i kerîmedir. İranlılarla yapılan savaşta mağlub olan Rumların, sonra gâlip gelecekleri anlatıldığından, Sûretü’r-Rûm denilmiştir. Sûrede; Allahü teâlânın sıfatlarının bir kısmı, Müslümanların İslâm dinine sarılmaları ve kavuşacakları maddî mânevî feyzler bildirilmektedir. Kim Rûm sûresini okursa, semâda ve yerde Allahü teâlâyı tesbih eden meleklerin adedinin on katı sevab kazanır, ge…","osmanli":"سى سوره روم"},{"kelime":"RûMÎ","anlam":"1.Rum (Roma) ile alâkalı, Ro-malı. 2.Rum (Anadolu) ülkesinden.","kategori":"dil","osmanli":"رومى"},{"kelime":"RÜMûZ","anlam":"İşaretler; mânâsı gizli olan sözler. Remz’in çokluk hâli.","kategori":"dil","osmanli":"رموز"},{"kelime":"RÜŞD","anlam":"1.Olgunluk, maddî ve manevî olarak doğru yolda bulunma. 2.Tevhid inancı. 3.Malını gerektiği gibi sarf edebilme olgun-luğu.","kategori":"dil","misal":"(Cinlerden bir topluluk) dediler ki: “Biz, rüşde ulaştıran benzeri görülmemiş bir Kur’ân din-ledik. Biz de O’na îmân ettik. Bundan sonra Rabbimize aslâ hiçbir şeyi ortak koşmaya-cağız.” (Cin sûresi: 1, 2) Sefeh’in zıddı. Çocuk âkıl-bâliğ olunca yani iyiyi kötüden ayı-rabilme ve evlenecek, erginlik çağına gelince, malını kullanmaya hak kazanır. Rüşdü görül-mezse, malı yirmi beş yaşına kadar kendisine teslim edilmez. İki imâma (İmâm-ı Ebû Yûsuf ve İmâm-ı Muhammed’e) ve diğer üç mezhebe (Şâfiî, Mâlikî ve Hanbelî) göre, rüşdü görülme-dikçe ihtiyarlasa dahi malı kendisine verilmez. Onun malından hâkimin izin verdiği kimse ta-sarruf eder, kullanır. (İbni Âbidîn)","osmanli":"رشد"},{"kelime":"RûŞEN","anlam":"1.Aydın, parlak. 2.Belli, mey-danda","kategori":"dil","osmanli":"روشن"},{"kelime":"RÜŞEYM","anlam":"Cenînin embriyon hâli.","kategori":"dil","osmanli":"رشيم"},{"kelime":"RÜŞVET","anlam":"Gayrımeşru bir iş gördürmek üzere iş sahibine verilen para, mal, menfaat.","kategori":"dil","misal":"Rüşveti veren de alan da Cehennem’dedir. (Hadîs-i şerîf-İbni Sa’d) Malını, canını, hakkını kurtarmak, zâlimin zul-münden kurtulmak için ve ikrâh edilince rüş-vet vermek câizdir. Fakat, bunu istemek ve al-mak da harâm olur. (İbni Âbidîn)","osmanli":"رشوت"},{"kelime":"RÜTBE","anlam":"Sıra, basamak, derece, pâye, mertebe, mevkî.","kategori":"dil","misal":"Rütbe ve nimeti çok olan önce selâm verir. (İbni Âbidîn) İmâm-ı Rabbânî’den Buhârî, Mişkât, Hidâye, Şerh-i Mevâkıf kitaplarını okudum. Gençleri ilim öğrenmeye teşvik ederdi. Önce ilim, sonra tarîkat buyururdu. Benim, ilimden kaçındığımı, tarîkatten zevk aldığımı görünce, hâlime mer-hamet ederek, kitap oku! İlim öğren! Câhil sofu, şeytânın maskarası olur. Rütbelerin en üstünü, ilim rütbesidir buyurdu. (Hadarâtü’l-Kuds)","osmanli":"رتبه"},{"kelime":"RûY-İ ZEMÎN","anlam":"Yeryüzü.","kategori":"dil","osmanli":"زمين روى"},{"kelime":"RûZ","anlam":"Gün; gündüz.","kategori":"dil","osmanli":"روز"},{"kelime":"RûZ-İ MAHŞER","anlam":"Mahşer günü. Kıyâmet koptuktan sonra insanların diriltilip hesâb için toplandıkları gün, kıyâmet günü.","kategori":"akaid","misal":"(Bkz. Mahşer)","osmanli":"محشر روز"},{"kelime":"RûZNÂME","anlam":"1.Günlük. 2.Günlük gelirlerin ve masrafların veya hâdiselerin ya-zıldığı defter.","kategori":"hadis","osmanli":"روزنامه"},{"kelime":"SÂ’","anlam":"Bir hacim ölçüsü birimi.","kategori":"ibadet","misal":"Sadaka-i fıtr, buğday, arpadan yarım, kuru üzüm ve hurmadan bir sa’dır. (İbni Âbidîn) Abdestte ve gusülde, lüzumundan fazla su kullanmak israf olup, haramdır. Sekiz rıtl su ile sünnete uygun gusledilebilir. Resûlullah sallallahü aleyhi ve sellem, bir müd su ile abdest alır, bir sâ’ hacminde su ile guslederdi. (Halebî)","osmanli":"صع"},{"kelime":"ŞA‘BÂN","anlam":"Arabî ayların sekizincisi, mü-barek üç aylardan ikincisi.","kategori":"dil","misal":"Şu’be’den gelir. Bu ayda kabileler su talebi veya haram aydan çıktıklarından dolayı harb ve yağma için şu’belere ayrılıp dağılırlardı. Üç aylardan olduğu için hürmeten Şa’bânü’l-Mu-azzam denirdi. Berat Kandili bu aydadır. Şa’bân ayı, Receb ile Ramazan ayı arasanda bulunan insanların çoğunun değerini bilme-diği bir aydır. Onda kulların amelleri Al-lah’a arzedilir. Ben amelimin ancak oruçlu iken Allah’a arz edilmesini isterim. (Hadîs-i şerîf-Beyhekî) Resûlullah aleyhisselâm Şa’bân ayını, pek az günleri müstesna, oruçlu geçi-rir; hatta (bazen) Şa’bân ayında baştan so-nuna kadar oruç tutardı. (Hadîs-i şerîf-Buhârî, Müslim, Tirmizî, Nesâî)","osmanli":"شعبان"},{"kelime":"ŞA‘BÂNİYYE","anlam":"Hicrî X. asırda yaşamış Halvetî şeyhi Şa’bân Velî’nin tasavvuftaki yolu.","kategori":"tasavvuf","misal":"Halvetiyye’nin kollarından.","osmanli":"شعبانيه"},{"kelime":"SA‘DİYYE","anlam":"1.Göğüs. 2.Her şeyin başı, ucu.","kategori":"tasavvuf","misal":"Hicrî yedinci asır velîle-rinden Sa‘deddin Cibâvî’nin tasavvuftaki yolu. SADR: صدر (A)","osmanli":"صعديه"},{"kelime":"SA‘ÎD","anlam":"Saadetli, mutlu; uğurlu; Allahü teâlânın kendisinden râzı olduğu kimse, Cennetlik.","kategori":"akaid","misal":"Sa‘îd olanlara gelince, onlar Cennet’tedirler. (Hûd sûresi: 108) Şakîler dünyaya sarılır, sa’îdler, bâkî olana (ebedî, sonsuz olan âhirete) sarılır. (Abdülhakîm Arvâsî)","osmanli":"سعيد"},{"kelime":"SA‘Y","anlam":"1.Çalışma. 2.Hızlı yürüme.","kategori":"ibadet","misal":"İnsan için ancak sa’yi (ile elde ettiğine erişmek) vardır. (Necm sûresi: 39) Hac ve umrede Kâbe-i Muazzama’yı tavaftan sonra yakınındaki Safâ ile Merve tepeleri arasında usûlüne göre Safâ’dan başlayarak Merve’ye ve Merve’den Safâ’ya yedi kere gidip gelme. Sa’y, hac ve umrenin vâciblerindendir. (Ni’met-i İslâm)","osmanli":"سعى"},{"kelime":"ŞA‘YÂ (aleyhisselâm)","anlam":"İsrâiloğullarına gönderilen ve Mûsâ aleyhisselâmın dinini yayıp, Tevrat-ı şerîfin hükümlerini bildiren peygamberlerden.","kategori":"dil","osmanli":"شعيا"},{"kelime":"SABÎ","anlam":"Bülûğ çağına gelmemiş çocuk. Kıza sabiyye denir.","kategori":"dil","misal":"“Ey Yahya! Kitab’a (Tevrat’a) vargücünle sa-rıl!” (dedik) ve henüz sabî iken ona (ilim ve) hikmet verdik. (Meryem sûresi: 12)","osmanli":"صبى"},{"kelime":"SÂBIK","anlam":"Sebkat eden, öne geçen; ön-ceki; müsabaka eden, yarışan. Çokluk hâli sâbıkûn gelir.","kategori":"dil","misal":"Sonra Kitab’ı, kullarımız arasından seçtik-lerimize verdik. Onlardan kimi kendisine zulmeder, kimi ortadadır, kimi de Allah’ın izniyle hayırlarda sâbık olmak (öne geçmek) için yarışır. İşte büyük fazilet budur. (Fâtır sûresi: 32) (Müslümanlığa girmekte) Sâbıkûn-dan olan (öne geçen) ilk muhacirler ve ensar ile onlara güzellikle tabi olanlardan Allah razı olmuştur, onlar da Allah’tan razı ol-muşlardır. Allah onlara, içinde ebedî kala-cakları, zemininden ırmaklar akan cennet-ler hazırlamıştır. İşte bu büyük kurtuluştur. (Tevbe sûresi: 100) Mü’minler sâbikûnun sırlarını anlayamaz. Kur’ân-ı kerîmde ayrı harflerle gösterilen işâret-ler, bunlara mahsus sırlardır. Rahat ve rahmet, bunlar içindir. Kıyâmet gününün korkusundan emîn olanlar bunlardır. Kıyâmetin dehşetinden, başkaları gibi ürkmezler. Kıyâmette bunlara husûsî muâmele yapılır. Kendilerine ayrıca ikrâm olunur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سابق"},{"kelime":"SÂBİKûN","anlam":"Geçmişler, öne geçenler. Sâbık’ın çokluk hâli.","kategori":"dil","misal":"Sâbikûn, tamam enbiyâ olup, eshâbı ve hakîkî vâ-risleri de dâhildir. (Mektûbât-ı İmâm-ı Rabbânî) Sâbikûn-ı Evvelûn: اولون سابقون Dinlerini muhâ- faza için yurtlarından ayrılan, Resûlullah sal- lallahü aleyhi ve selleme son derece bağlılık gösterenler.","osmanli":"سابقون"},{"kelime":"SÂBİRÎN","anlam":"Sabırlılar, sabredenler.","kategori":"tasavvuf","misal":"Sâbir’in çokluk hâli.","osmanli":"صابرين"},{"kelime":"SÂBİT","anlam":"Sübût bulan, devamlı var olan; sahih.","kategori":"fikih","osmanli":"ثابت"},{"kelime":"SABR (Sabır)","anlam":"Hiç bıkmadan emirleri yapmak, yasaklardan sakınmak, başa gelen belâ ve musîbetlere tahammül etmek ve katlanmak.","kategori":"tasavvuf","misal":"Peygamberlerden ülü’l-azm olanların sabrettikleri gibi sen de sabret! Onlara azap verilmesi için duâ etmekte acele eyleme. (Ahkâf sûresi: 35) Rablerine sabah akşam duâ eden ve O’na kavuşmak isteyenlerle birlikte bulun ve sabreyle. Onlardan başka bir yere bakma. (Kehf sûresi: 28) Sabreden zafere kavuşur. (Hadîs-i şerîfKeşfü’l-Hafâ) Sabr, dinin yarısıdır. (Kimyâ-i Seâdet)","osmanli":"صبر"},{"kelime":"ŞÂD","anlam":"Sevinçli, memnun, mesrûr. ŞÂDÂB: آب شاد (F) Suya kanmış, sulu; taze. ŞÂDÜMÂN: شادمان (F) Sevinçli, memnun, mesrur.","kategori":"tasavvuf","osmanli":"شاد"},{"kelime":"SAD SûRESİ","anlam":"Kur’ân-ı kerîmin otuz sekizinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Seksen sekiz âyet-i kerî-medir. Sad harfi ile başladığı için sûreye Sû-retü’s-Sad denilmiştir. Sûrede; müşriklerin bozuk yolda oldukları, Nûh, Sâlih, Hûd, Şuayb, Dâvûd, Süleymân, Eyyûb, İbrâhim, İshak, Yâ-kub, İsmâil, İlyâs, Zülkifl ve Âdem aleyhimüs-selâmın kıssaları, hak yolda peygamberlerin çektikleri eziyetler ve sonunda nusret-i ilâhiy-yeye (Allahü teâlânın yardımına) kavuştukları bildirilmektedir. (Mefâtihü’l-Gayb, Kurtubî) Kim Sad sûresini okursa, Allahü teâlânın, Dâvûd aleyhisselâmın emrine verdiği dağ-ların ağırlığının on katı sevab verilir. Ve bü-yük küçük bütün günahlara ısrardan muhâ-faza edilir. (Hadîs-i şerîf- Beydâvî)","osmanli":"سى سوره ص"},{"kelime":"SADÂ","anlam":"Ses.","kategori":"dil","osmanli":"صداء"},{"kelime":"SADAKA","anlam":"1.Allahü teâlânın rızâsına niyet ederek ve karşılık beklemeden muhtaç olanlara, fakirlere, hibe edilen mal, para ve her türlü iyilikte, ihsânda bulunma. Ey îmân edenler! Sadakalarınızı; insanlara gösteriş için malını harcayan, Allah’a ve âhiret gününe inanmayan kimse gibi başa kakmak ve eziyet etmek sûretiyle boşa çıkarmayın... (Bakara sûresi: 264) Hoş söz, bir sadakadır. (Hadîs-i şerîfMüslim) Ölüler için duâ ve istiğfâr ederek ve onlar için sadaka vererek, imdâdlarına yetişmek lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî) 2.Zekât.","kategori":"akaid","osmanli":"صدقه","alternatif":["sadaka"]},{"kelime":"SADAKA RESûLuLLAH","anlam":"“Resûlullah doğru söyledi” mânâsına bir hadîs-i şerîf okuduktan sonra söylenen ifade.","kategori":"hadis","osmanli":"الله رسول صدق","alternatif":["sadaka"]},{"kelime":"SADÂRET","anlam":"1.Sadr olma, başta olma. 2.Sadrazamlık.","kategori":"dil","osmanli":"صدارت"},{"kelime":"SADER","anlam":"1.Çıkma. 2.Hacılar, Mekke’den memleketlerine çıktıklarından dolayı Kurban bayramının dördüncü günü için kullanılan bir tabir, Yevmu’s-Sader.","kategori":"ibadet","osmanli":"صدر"},{"kelime":"SÂDIK","anlam":"Doğru, yalan ve uydurma ol-mayan; doğru sözlü, sözünde duran.","kategori":"dil","misal":"Ey mü’minler! Allahü teâlâdan korkun ve dâimâ her zaman sâdıklar ile birlikte bu-lunun. (Tevbe sûresi: 120) Bu (Allahü teâlâ-nın Cennet’te cemâlini göstereceği) zaman, sâdıka sıdkının fayda vereceği zamandır. (Mâide sûresi: 119) Sâdık dost ve hâlis kimyâ, Az bulunur, hiç arama. (İmâm-ı Şâfiî)","osmanli":"صادق"},{"kelime":"SADÎK","anlam":"Arkadaş, dost.","kategori":"dil","misal":"Şimdi artık bizim ne şefaatçilerimiz var, ne de yakın bir sadîkımız. (Şu’arâ sûresi: 101)","osmanli":"صديق"},{"kelime":"SÂDIR","anlam":"Sudûr eden, öne çıkan.","kategori":"dil","osmanli":"صادر"},{"kelime":"SADİST","anlam":"Başkasına eziyet ve sıkıntı vermekten, sapık işleri yapmaktan zevk alan ruh hastası kimse.","kategori":"akaid","osmanli":"صديست"},{"kelime":"SAF (Saff)","anlam":"1.Dizi, sıra. 2.Namazda cemaatin aynı hizada durması.","kategori":"ibadet","misal":"Saflarınızı düzeltiniz. Dosdoğru yapınız. (Hadîs-i şerîfEbû Dâvûd) Cemâatle namaz kılarken öndeki safta boş yer var iken, arka safta durmak ve safta yer yok iken, saf arkasında yalnız durmak mekrûhtur. Safta yer olmayınca, yalnız başına durmayıp, rükû’a kadar birini bekler. Kimse gelmezse, öndeki safa sıkışır. Öndeki safa sığmazsa, güvendiği birini arkaya çeker. Güvendiği kimse yoksa, yalnız durur. (İbni Âbidîn)","osmanli":"صف"},{"kelime":"SAFÂ","anlam":"1.Saflık, berraklık. 2.Şenlik, neş’e, eğlence. 3.Kâbe-i Muazzama’nın yakınında hac ve umre esnâsında sa’y denilen vazifenin yapıldığı iki tepeden biri.","kategori":"dil","misal":"Dünyaya ve buna düşkün olanlara inanılmaz. Çünki, bunlarda vefâ ve safâ bulunmaz. (Mek-tûbât-ı İmâm-ı Rabbânî) Diğeri Merve’dir. Şüphe yok ki, Safâ ile Merve Allah’ın şeâi-rindendir (Allahü teâlâya ibâdet etmeye vesîle olan nişâneler, alâmetlerdendir). İşte kim o Beyti (Kâbe’yi) hac veya umre niyetiyle zi-yaret ederse, bunları güzelce tavâf etme-sinde bir günah yoktur. (Bakara sûresi: 158) Haccın vâciblerinden birisi, Safâ ile Merve te-pesi arasında sa’y ederken Safâ’dan başlamak-tır. Safâ tepesine çıkınca, Kâbe’ye döner. Tekbir, tehlîl ve salevât getirir. Sonra iki kolunu omuz hizâsında ileri uzatıp ve avuçlarını semâya doğru açıp duâ eder. Sonra Merve’ye doğru yü-rür. Safâ’dan Merve’ye dört, Merve’den Safâ’ya üç kere gidilir. (Dürer)","osmanli":"صفاء"},{"kelime":"ŞAFAK","anlam":"Gurûbdan, güneş battıktan sonraki aydınlık.","kategori":"dil","misal":"Şafağa, geceye ve onda basan karanlığa, do-lunay olmuş aya yemin ederim ki, hâlden hâle geçersiniz. (İnşikâk sûresi: 16) Yatsıyı hava iyice kararıp, kırmızı şafak iyice kaybo-lunca kılın! (Hadîs-i şerîf-Ebû Dâvûd, Beyhekî) Akşam namazının vakti güneşin batmasından şafak kayıp oluncaya kadardır. İmâmeyn’e göre şafak, kızıllıktır. Üç İmâmın kavilleri de budur. Lâkin bilumum memleketlerde teâmül İmâ-meyn’in kavli üzeredir. (İbni Âbidîn)","osmanli":"شفق"},{"kelime":"SAFHA","anlam":"1.Bir şeyin yüzü, sayfa. 2.Bir hâdisede bir biri ardına görülen hâllerin her biri, merhale.","kategori":"ibadet","misal":"Çokluk hâli safâhât gelir.","osmanli":"صفحه"},{"kelime":"SÂFÎ","anlam":"1.Duru, temiz, katık-sız. 2.Samîmî. 3.Net.","kategori":"dil","misal":"(A. Safâ’dan) Ve dahî, Cennet’te dört ırmak akar. Bunların menba’ı bir, akışı ayrı ayrı olup, bunların her birinin lezzeti, birbirine uymaz. Onların bi-risi, sâfî su ve birisi, hâlis süt ve birisi Cennet şerâbı ve birisi de saf baldır. (Hüccetü’l İslâm)","osmanli":"صافى"},{"kelime":"ŞÂFİ‘Î","anlam":"1.İmâm Muhammed bin İdris eşŞâfiî’ye nisbet edilen fıkıh mezhebi. 2.Bu mezhebe mensub olan.","kategori":"ibadet","misal":"(Bkz. İmâm-ı Şâfiî)","osmanli":"شافعى"},{"kelime":"Şâfi‘î Mezhebi","anlam":"Ahl-i sünnetin ameldeki dört hak mezhebinden biri.","kategori":"dil","misal":"İmâm-ı Şâfiî hazretlerinin mezhebi, yolu.","osmanli":"مذهبى شافعى"},{"kelime":"SAFİYY","anlam":"Resûlullah aleyhisselâmın ga-nimet taksîminden önce kılıç, zırh ve at gibi seçip aldığı şeyler.","kategori":"dil","misal":"Resûlullah aleyhisselâm, Bedr muhârebesinde zülfikâr isimli kılıcı safiyy olarak almışlardı. (Kitabü’l-Emval-Ebû Ubeyd)","osmanli":"صفى"},{"kelime":"SAFİYYuLLAH","anlam":"“Allahü teâlânın temiz kıldığı, seçtiği” mânâsına, Âdem aleyhisselâmın lakabı.","kategori":"akaid","misal":"Âdem aleyhisselâm Safiyyullah olduğundan, temiz ve habîs ruhları, Cennetlik veya Cehennemlikleri ayırır, fark ederdi. (Meâricü’n-Nübüvve)","osmanli":"الله صفى"},{"kelime":"SAFİZM","anlam":"Kadının kadına şehvetle bakması ve dokunması.","kategori":"osmanli","misal":"Safizm, yabancı erkeklerin bakması ve dokunması gibi haramdır. Allah’tan korkan kadınların, kocasından başkasına, erkek ve kadın, kim olursa olsun yabancıya süslenmeleri câiz değildir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"صفيزم"},{"kelime":"SAFVET","anlam":"Saflık, temizlik, hâlislik, paklık.","kategori":"dil","misal":"Safvet niyete bağlıdır. Niyeti hayır olanın âkıbeti (sonu) de hayır olur. Niyeti bozuk olanın âkıbeti de bozuktur. (Abdülhakîm Arvâsî)","osmanli":"صفوت"},{"kelime":"SAĞCI","anlam":"1.Mevcut düzenden yana olan. 2.Kapitalist liberalist düşünceye sahip. 3.Amel defteri sağ elinden verilen, mü’min, eshâb-ı yemîn.","kategori":"dil","misal":"Zıddı solcu gelir.","osmanli":"صاغجى"},{"kelime":"ŞÂGİL","anlam":"Meşgul eden, işgal eden; bir mülkte oturan.","kategori":"muamelat","misal":"Tabağı, hayvanı, evi hediye ve teslim edip de, yemeğini, semerini, evdeki eşyayı hediye etmez ise, câiz olmaz. Bunların aksi câiz olur. Çünki, yemek, semer ve eşya, verenin mülkü ile meşgul değil, şâgildirler. (İbni Âbidîn)","osmanli":"شاغل"},{"kelime":"SAGÎR","anlam":"1.Küçük. 2.Bulûğ çağına er-memiş çocuk.","kategori":"dil","misal":"Çokluk hâli sagâir gelir.","osmanli":"صغير"},{"kelime":"SAHÂBE","anlam":"Resûlullah aleyhisselâmı sağ iken gören mü’minler.","kategori":"dil","misal":"Sahâbî’nin çokluk hâli. Hürmet ve saygı için, “Resûlullah’ın kıymetli ve mübârek arkadaşları” mânâsına Sahâbe-i kirâm denir. Ayrıca onların ismi anıldığında; “Allahü teâlâ onlardan râzı olsun” mânâsına radıyallahü anhüm ecmaîn söylenir. (Bkz. Eshâb) Sahâbe-i kirâm aleyhimürrıdvân, peygamberlerden ve meleklerden sonra insanların en efdali, en üstünüdür. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"صحابه"},{"kelime":"SAHÂBÎ","anlam":"Resûlullah aleyhisselâmı diri iken ve peygamberliğini ilan ettikten sonra bir an gören, eğer âmâ (kör) ise bir an konuşan, büyükküçük, kadınerkek mü’min.","kategori":"dil","misal":"(Sahip ve sohbet’ten) (Bkz. Eshâb)","osmanli":"صحابى"},{"kelime":"SÂHÎ","anlam":"Aklı başında, sahv hâlinde. Sekr hâlinde olmayan.","kategori":"dil","osmanli":"صاحى"},{"kelime":"ŞÂHÎ","anlam":"1.Şaha ait, hükümdara men-sub, şah ile alakalı. 2.Şahlık, hükümdarlık, pâdişâhlık.","kategori":"dil","osmanli":"شاهى"},{"kelime":"SÂHİB","anlam":"1.Sohbet eden, arkadaş. 2.Vekîl eden, müvekkil. 3.Bir işin veya malın yâhud sıfatın mâliki.","kategori":"tasavvuf","misal":"Hediye, âriyet, rehn, emanet, ödünç vermek ve dâvâ açmakta, şirket yapmakta, vekil sahibinin adını söyleyerek iş görür. Söylemezse, işleri sahîh olmaz. (İbni Âbidîn)","osmanli":"صاحب"},{"kelime":"ŞÂHİD","anlam":"Şâhidlik eden, görüp bilen. Bi-rinin başkasında hakkının bulunduğunu ispat için şehâdet (şâhidlik) ederim demek sûretiyle hâkimin huzurunda ve hasmın karşısında ha-ber veren. (Bkz. Şehâdet)","kategori":"dil","misal":"Ey îmân edenler! Dâimâ adâletle hareket ediniz. Adâleti yerine getirmeye çalışınız. Allah için şâhidler olunuz. (Nisâ sûresi: 135) Yalancı şâhid, daha şehâdet ettiği yerden aya-ğını kaldırmadan Cehennemliklerden yazı-lır. (Hadîs-i şerîf-Ebû Nuaym, Hâkim) Şâhidin âdil olması, yani büyük günah işle-memesi ve küçük günaha devam etmemesi lâ-zımdır. (Vikâye)","osmanli":"شاهد"},{"kelime":"SAHÎFE","anlam":"1.Bir yaprak kâğıdın bir yüzü. 2.Küçük kitap, risâle; önceki peygam-berlere gönderilen küçük kitaplardan her biri. 3.Hazret-i Peygamber zamanında sahâbîlerin yazdığı küçük hacimde hadîs-i şerîf kitabı.","kategori":"dil","misal":"Çokluk hâli suhuf gelir.","osmanli":"صحيفه"},{"kelime":"SAHÎH","anlam":"1.Sıhhatli, sağlam; tam, kusursuz; gerçek, doğru. 2.Şartlarına uygun yapılan ve dinen muteber amel.","kategori":"fikih","misal":"Hanefî mezhebinde elbisede veya namaz kılınan yerde bulunan necâset, bir miskalden [beş gramdan] az ise, namaz sahîh olur. Bu mikdardan çok ise, namaz sahîh olmaz. (Dürrü’l-Muhtâr)","osmanli":"صحيح"},{"kelime":"Sahîh Bey‘","anlam":"Aslı ve sıfatı dine uygun olan satış.","kategori":"muamelat","misal":"Sahîh bey’in meydana gelmesi için alıcı ve satıcının aynı kimse olmaması yani bir kimsenin hem satıcıya, hem alıcıya vekîl olarak kendi kendisine satış yapmaması, akd yapılması yani birinin îcâb yani teklif edip, karşısındakinin onu ayrılmadan önce kabul etmesi yani söz kesilmesi, mebîin (malın) ve semenin (bedelin) mal olmaları, mütekavvim (kullanılmasına dînen izin verilen ve kullanılması mümkün) mal olmaları lâzı…","osmanli":"بيع صحيح"},{"kelime":"Sahîh Ced","anlam":"Ölenin babasının babası veya babasının babasının babası gibi derecesi yakın olsun uzak olsun aralarında kadın bulunmayan dede.","kategori":"fikih","misal":"Yani araya kadın girmeyen büyük baba. Cedd-i Sahîh. Sahih dede. Sahîh ced, ya ölenin babası ile bulunur veya bulunmaz. Bulunması hâlinde babanın varlığı cedd-i sahîhi mîrâstan düşürür. Meyyitin (ölünün) babası bulunmazsa, sahîh ced baba gibi olur ve babanın hakkı olan hisselerden alır. (Mevkûfât)","osmanli":"جد صحيح"},{"kelime":"Sahîh Cedde","anlam":"Ölenin annesinin an-nesi veya annesinin annesinin annesi gibi de-recesi yakın olsun uzak olsun aralarında erkek bulunmayan nine. Cedde-i Sahîha. Sahih nine. Meyyitin babası olmaz, oğlu varsa, sahîh cedde altıda bir alır. (Mevkûfât)","kategori":"dil","osmanli":"جده صحيح"},{"kelime":"Sahîh Hadîs","anlam":"Âdil ve mazbut (rivâyet şartlarını taşıyan) râvîlerin muttasıl (kopukluk olmayan) bir şekilde rivâyet ettiği, şâz ve illetli olmayan hadîs-i şerîf.","kategori":"hadis","misal":"İmâm-ı A’zâm, talebesine; “Sahîh hadîsler benim mezhebimdir” buyurdu. Hadîs ilminde âlim, mütehassıs olan, nâsih ve mensûh hadîsleri ayırabilen, kuvvetli ve za’îf hadîsleri anlayabilen bir kimse, sahîh hadîslere uyarsa, Hanefî mezhebinden çıkmaz. Mezheb reîsinin sözünü yapmış olur. (Ravdatü’l-Ulemâ)","osmanli":"حديث صحيح"},{"kelime":"SAHÎH-İ BuHÂRÎ","anlam":"Kur’ân-ı kerîmden sonra, doğru oldukları, bütün İslâm âlimleri tarafından tasdik edilmiş olan meşhur altı hadîs kitabından birincisi.","kategori":"dil","misal":"Sahîh-i Buhârî’de yedi bin iki yüz yetmiş beş hadîs-i şerîf vardır. Bunlar altı yüz bin hadîs arasından seçilmiştir. (Ahmed Nâim)","osmanli":"بخارى صحيح"},{"kelime":"Sahîh Kan","anlam":"Sekiz yaşını bitirip, dokuz yaşına bastıktan birkaç gün veya ay, yâhud seneler sonra, sıhhatli bir kızın veya âdet zamanı son dakikasından îtibâren tam temizlik (on beş gün) geçmiş olan kadının önünden çıkan ve Hanefî mezhebine göre, en az üç gün (yetmiş iki…","kategori":"fikih","misal":"Dem-i sahîh. (Bkz. Hayz) Bir kız, sahîh kan ve sahîh temizlik gördükten sonra istimrar ederse (kan devam ederse), bu kız âdeti belli olan kadın olur. Meselâ beş gün kan görse, sonra kırk gün temiz olsa, istimrâr başından beş gün hayz, sonra kırk gün temiz kabul edilir. Kan kesilinceye kadar böyle devam eder. (İbni Âbidîn)","osmanli":"قان صحيح"},{"kelime":"Sahîh Temizlik","anlam":"Ergenlik çağına erişmiş bir kızda veya kadında, âdet zamanından sonra başlayan ve içinde hiç kan görülmeyen, öncesi ve sonrası hayız günleri olan on beş veya daha fazla sayıdaki temiz gün.","kategori":"ibadet","misal":"Âdeti beş gün olan bir kadın, sahîh temizlikten sonra altı gün kan görürse, bu altı gün yeni hayız olur ve yeni âdeti olur. (İbni Âbidîn)","osmanli":"تميزلك صحيح"},{"kelime":"SAHÎHAYN","anlam":"Buhârî ile Müslim’in Kütüb-i Sitte’den esSahîh adlı hadîs kitaplarının ikisine birden verilen isim.","kategori":"hadis","osmanli":"صحيحين"},{"kelime":"SÂHİR","anlam":"Sihir yapan. (Bkz. Büyü) Sâhir tövbe etmezse Cehennem’dedir. (Riyâ-dü’n-Nâsihîn)","kategori":"akaid","misal":"Sâhir, sihir ile istediğini elbette yapar, sihir mu-hakkak te’sir eder diyenin ve inananın îmânı gi-der. Sihir, Allahü teâlâ takdir etmiş ise, te’sir ede-bilir, demelidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ساحر"},{"kelime":"SAHûR","anlam":"Güneşin batmasından imsak vaktine kadar olan zamanın son altıda biri, seher vakti; oruç tutmak için yemeğe kalkılan vakit; bu vakitte yenen yemek.","kategori":"ibadet","misal":"Sahur yiyiniz. Çünki onda bereket vardır. (Hadîs-i şerîfMüslim) Bir yudum su ile de olsa sahur yapınız. (Hadîs-i şerîfİbn-i Hibbân) Ramazân-ı şerîfte, iftarı erken yapmak, sahuru geciktirmek sünnettir. İftârda acele etmek ve sahuru geciktirmek, belki insanın aczini, yiyip içmeye ve dolayısıyla her şeye muhtaç olduğunu göstermektedir. İbâdet etmek de zâten bu demektir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سحور"},{"kelime":"SAHV","anlam":"Uyanıklık, aklı başında, şu-uru yerinde olma hâli, sekr hâlinin zıddı. Ta-savvufta kendini kaybetme hâlinden kurtu-lup, ayılma hâli. Fenâdan sonraki bekâ hâli. Sahv hâlinde olan, emirlere uygunsuz davra-nabilir. Ancak bu davranış, Allahü teâlânın lütf etmesi ve koruması ile yalnız müstehab-ları yapmamak olup, bundan ileriye gitmez. (Mekâtib-i Şerife)","kategori":"akaid","misal":"Sahv hâlinde olanlarda sekr hiç bulunmaz san-mamalıdır. Sahv hâlinde biraz sekr bulunması, yemeğe lezzet vermek için tuz karıştırmaya benzer. Tuzsuz taam tadsız olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"صحو"},{"kelime":"SÂÎ","anlam":"Sâime (senenin ekserisinde ça-yırda otlayan) hayvanların zekâtını topla-makla vazifeli kimse.","kategori":"ibadet","osmanli":"ساعى"},{"kelime":"SÂÎB","anlam":"Velâ gibi âzâda bağlı her hak-tan vazgeçilerek azatlanan köle.","kategori":"dil","osmanli":"سائيب"},{"kelime":"ŞÂİBE","anlam":"Leke, kusur; nok-san, ayıp.","kategori":"dil","osmanli":"شائبه"},{"kelime":"SÂİBE (Deve)","anlam":"1.Hiç bir kimsenin mülkü olmayan ve mülke teallûku bulunmayan mal. 2.Câhiliye devrinde bir hastalıktan ve tehlikeden kurtulmak gayesiyle yapılan adağı yerine getirmek için serbest bırakılan ve yük vurulmayan erkek veya dişi deve.","kategori":"muamelat","osmanli":"سائبه"},{"kelime":"SÂİL","anlam":"İsteyen, yoksul, dilenci.","kategori":"dil","misal":"Sâili azarlayıp koğma. (Duhâ sûresi: 10)","osmanli":"سائل"},{"kelime":"SÂİM","anlam":"Oruç tutan, oruçlu.","kategori":"ibadet","osmanli":"صائم"},{"kelime":"SÂİME","anlam":"Senenin yarısından fazlasında, üretmek ve sütü için kırda, çayırda parasız otlayan dört ayaklı (koyun, keçi, sığır cinsin-den) hayvanlar.","kategori":"dil","misal":"Sâime hayvan sayısı nisâb mikdarı olduktan (zekât sınırına ulaştıktan) bir yıl sonra zekâtı verilir. Yük taşımak ve binmek için olursa, sâime denilmez ve zekâtı lâzım olmaz. (Fethü’l-Kadîr)","osmanli":"سائمه"},{"kelime":"SÂİR (Sâire)","anlam":"1.Seyreden, yürüyen. 3.Diğer, başka.","kategori":"tasavvuf","misal":"2.Artan, geri kalan.","osmanli":"سائره"},{"kelime":"ŞAKA","anlam":"Birini güldürmek veya eğlen-dirmek maksadıyla söylenen söz veya yapı-lan iş. Lâtife.","kategori":"tasavvuf","misal":"Üç şey vardır ki, ciddisi de ciddî, şakası da ciddîdir: Nikâh, talâk ve ric’at (kişinin ric’î talâkla boşadığı hanımına geri dönmesi). [Bir rivâyette üçüncünün yerinde ıtk (köle âzâdı) vardır.] (Hadîs-i şerîf-Ebû Dâvûd, Tirmizi, İbn-i Mâce, Hâkim, Kâdî) Şakası çok olanın vakarı gider. (Hadîs-i şerîf-İbni Asâkir) Kâfirlik ve şeriati inkâr alâmeti olan şeylerden meşhur olanlarını bilmeyerek veya şaka olarak veya herkesi güldürmek için yapan da, kâfir olur. (Birgivî Vasıyyetnâmesi)","osmanli":"شاقا"},{"kelime":"SÂKÎ","anlam":"(A. Saky’dan) Su veren, su dağı-tan, sulayan.","kategori":"dil","osmanli":"ساقى"},{"kelime":"ŞAKÎ","anlam":"1.Şakâvet ehli, haydut, yol kesen. 2.Cehennemlik; bedbaht, habîs.","kategori":"dil","misal":"Eşkıya’nın müfred (tek) hâli. Zıddı saîd’dir. Şakî olanlara gelince: Onlar Cehennem ate-şindedirler ki, orada onların (çok acı) bir nefes alıp vermeleri vardır. (Hûd sûresi: 106) Şakî, Ramazan ayında (bu ayın hakkını ver-memek suretiyle) Allahü teâlânın Rahme-tinden mahrum kalan kimsedir. (Hadîs-i şerîf-Taberânî) Allahü teâlâ, kalblerimizi, Habîbinin Eshâbı-nın sevgisi ile doldursun! O büyükleri, sâlih ve müttekî olanlar sever. Münâfık ve şakî olan sev-mez. (Şifâ-i Şerif) Dünyâda herkes, sa’îd veyâ şakî olduğunu, amelinden anlayabilir.(Mektûbât-ı Şerefüd-din Münîrî)","osmanli":"شقى"},{"kelime":"ŞÂKÎ","anlam":"Şikâyet eden, şikâyetçi, müştekî.","kategori":"dil","osmanli":"شاكى"},{"kelime":"ŞAKÎK","anlam":"Öz kardeş.","kategori":"dil","misal":"Şakikler; oğul, oğul oğlu, baba ve dededen biri bulunduğu zaman vâris olamazlar yani ölüden kalan maldan alamazlar. (Mevkûfât)","osmanli":"شقيق"},{"kelime":"SAKÎL","anlam":"1.Ağır. 2.Can sıkan. 3.Çirkin.","kategori":"dil","osmanli":"ثقيل"},{"kelime":"SAKÎM","anlam":"1.Hasta, hasta-lıklı. 2.Yanlış.","kategori":"dil","misal":"(A. Sakâmet’den)","osmanli":"سقيم"},{"kelime":"ŞÂKİR","anlam":"1.Şükreden; iyilik yapana, ni-met verene teşekkür eden. 2.Hayır işleyene, şükredene karşılığını veren, iyiliği zâyi etmeyen mânâsına Allahü teâlâ-nın sıfatı.","kategori":"dil","misal":"Şüphesiz biz insanoğluna (doğru) yolu gös-terdik. İster şükredici olsun ister nankör. (İnsân sûresi: 3) Siz şükreder ve iman ederseniz Allahü teâlâ size niçin azap etsin? Allah şâkirdir, alîm-dir. (Nisâ sûresi: 147)","osmanli":"شاكر"},{"kelime":"SÂKIT","anlam":"Sukut eden, düşen.","kategori":"dil","misal":"Yatarak başı ile îmâ edemeyecek kadar ağır hastalığı yirmidört saatten çok devam eden kimseden, aklı başında olsa bile, namaz sâ-kıt olur. (Halebî) Zimmî, müslüman olursa, cizye vermesi sâkıt olur. (İbni Âbidîn)","osmanli":"ساقط"},{"kelime":"SÂKİT","anlam":"Sükût eden, susan.","kategori":"dil","misal":"Sâkite bir söz isnâd olunmaz. Lâkin ma’raz-ı hâcette sükût, beyândır. (Mecelle, m. 67)","osmanli":"ساكت"},{"kelime":"SAKK","anlam":"Çek, sened, berat, şer’î mahkemeden verilen hüccet gibi her çeşit resmî vesika.","kategori":"osmanli","misal":"Çokluk hâli sukûk gelir.","osmanli":"صك"},{"kelime":"ŞAKK-I SADR","anlam":"“Göğsün yarılması” mânâsına Resûlullah aleyhisselâmın göğsünün yarılması mûcizesi.","kategori":"dil","misal":"Şakk-ı sadr iki defâ vukû bulmuştur. Birincisi, Peygamber efendimiz küçük yaşta ve süt annesi Halîme Hâtun’un yanında iken, ikincisi Mîrâca çıkarken. Kur’ân-ı kerîmde meâlen; “(Habîbim) göğsünü (kalbini) senin için (açıp da) genişletmedik mi?” buyurulması buna işaret eder. (İnşirâh sûresi: 1) Muhammed aleyhisselâm, süt annesinin yanında bulunduğu sırada çocuklarla birlikte iken, Cebrâil aleyhisselâm gelip, onu arkas…","osmanli":"صدر شق"},{"kelime":"ŞÂKûL","anlam":"Bir şeyin semaya doğru isti-kameti, dikey, diklemesine, çekül.","kategori":"dil","osmanli":"شاقول"},{"kelime":"SÂL","anlam":"Yıl.","kategori":"dil","osmanli":"سال"},{"kelime":"SALÂ","anlam":"Namaza çağırma; minârelerde Cum‘a namazından evvel, kandil geceleri veya cenaze için okunan duâ veya salât u selâm. Aslı es-salât.","kategori":"ibadet","misal":"Salâ okunması asr-ı saadette olmayıp, sonra-dan dine sokulan bir bid‘attır. Okunması mû-teber kaynak kitablarda yazılı değildir. (Ab-dülhakîm Arvâsî)","osmanli":"صلاء"},{"kelime":"SALÂH","anlam":"Sâlih olmak, iyilik, dürüst-lük; iyi huylarla süslenme, dinine bağlı olma. Babanın malını oğulları arasında pay eder-ken, reşîd ve sâlih iyi veya ilim tahsîlinde olan","kategori":"dil","misal":"çocuklarına daha çok vermesi câizdir. Salâh-ları müsâvî ise, müsâvî dağıtmalıdır. (Fetâvâ-i Hindiyye)","osmanli":"صلاح"},{"kelime":"SALÂHİYYET","anlam":"Bir işi yapabilme ehliyeti, yetki.","kategori":"fikih","osmanli":"صلاحيت"},{"kelime":"SALÂT","anlam":"1.Allahü teâlâdan rahmet, meleklerden istiğfâr, mü’minlerden duâ. 2.İslâm’ın beş esâsından (temelinden) birisi olan namaz.","kategori":"akaid","misal":"Allahü teâlâ ve melekleri Peygambere (Muhammed aleyhisselâma) salât ederler. Ey mü’minler! Siz de O’na salât ediniz. (Allahü teâlânın Peygamber efendimiz sallallahü aleyhi ve sellemi salâtının O’nu melekler arasında senâ etmesi, övmesi demek olduğu da rivâyet edilmiştir.) (Ahzâb sûresi: 56) (Resûlüm) sana vahyolunan Kur’ân-ı kerîmi oku. Salâtı, şartlarını yer…","osmanli":"صلاة"},{"kelime":"Salât u Selâm","anlam":"Resûlullah aleyhisselâmın ismi anıldığında, işitildiğinde veya yazıldığında ta’zim için söylenen ve yazılan aleyhisselâm, sallallahü aleyhi ve sellem gibi içinde salat ve selâm kelimelerinin geçtiği söz ve duâ.","kategori":"ibadet","misal":"Ey mü’minler! O’na (peygambere) salât ve selâm edin. (Ahzâb sûresi: 56)","osmanli":"سلام صلاة"},{"kelime":"SALÎB","anlam":"Hristiyanlıkta dinin alâmetlerinden kabul edilmiş, birbirini dik kesen iki doğrunun meydana getirdiği şekil.","kategori":"dil","misal":"Meryem oğlu Îsâ’yı öldürmediler, salîbe germediler. Fakat onlara öyle göründü. Bu husustaki bilgileri ancak zandan ibârettir. Onu asmadılar, onu öldürmediler. Bilakis Allah onu katına yükseltti. Allah azîzdir, hakîmdir (hikmet sahibidir). (Nisâ sûresi: 156-158) Canlı resmi, namaz kılanın başında, önünde, sağ ve sol hizâsında duvara çizilmiş veya beze kağıda yapılarak asılmış veya konmuş ise namaz kılmak mekrûhtur. C…","osmanli":"صليب"},{"kelime":"SÂLİH","anlam":"İyi, güzel, elverişli, faydalı.","kategori":"dil","osmanli":"صالح"},{"kelime":"SÂLİH (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen ve Semûd kavmine gönderilen peygamberlerden.","kategori":"dil","misal":"Sâlih (aleyhisselâm) ve onunla olan mü’minlere necât (kurtuluş) verdik. Onlar küfür ve günahtan sakınırlardı. (Neml sûresi: 53)","osmanli":"صالح"},{"kelime":"Sâlih Amel","anlam":"Allahü teâlânın be-ğendiği iş. (Bkz. Amel-i Sâlih)","kategori":"akaid","osmanli":"عمل صالح"},{"kelime":"Sâlih İnsan","anlam":"İman, amel ve ahlâkında Rabbin rızâsını, sevgisini kazanmak için çalışan Müslüman.","kategori":"akaid","misal":"Kim Allah’a ve Resûlullah’a itaat ederse, işte onlar, Allah’ın kendilerine lütuflarda bulunduğu peygamberler, sıddîkler, şehidler ve sâlih kişilerle beraberdir. Bunlar ne güzel arkadaştır! (Nisâ sûresi: 69) Ümmetimin sâlihlerinin Cennet’e girmeleri, namaz ve oruçları sebebiyle değil, cömertlik, Müslümanlara karşı kalblerinde kötülük beslememeleri ve Müslümanlara nasihatleri sâyesindedir. (Hadîs-i şerîfDâre Kutnî) Sâ…","osmanli":"انسان صالح"},{"kelime":"SÂLİHÂT","anlam":"Allahü teâlânın beğendiği hayırlı ameller.","kategori":"akaid","misal":"Sâliha’nın çokluk hâli.","osmanli":"صالحات"},{"kelime":"SÂLİK","anlam":"Sülûk eden, tasavvuf yolcusu.","kategori":"tasavvuf","misal":"Maksada kavuşmak için çalışan sâlikin hep şeriate, İslâmiyet’e uyması şarttır. Tasavvuf yolunda en önemli vazife olan zikr-i ilâhî şeriatin emirlerinden biridir. İslâmiyet’in yasaklarından sakınmak da bu yolda lâzımdır. Farzları yapmak, sâlikin ilerlemesini kolaylaştırır. Tasavvuf yolunu iyi bilen ve sâlike yol gösteren âlim aramayı da dinimiz emretmektedir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سالك"},{"kelime":"Sâlik-i Meczûb","anlam":"Tasavvufta, cezbesi, yani hak yola çekilmesi, sülûkünden sonra olan sâlik.","kategori":"tasavvuf","misal":"Tâliblerin, arada vâsıta olmadan kavuşmaları çok güçtür. Cezbe ve sülûk nîmetlerine kavuşmuş, fenâ ve bekâ ile şereflenmiş olan bir vâsıtanın yardımı lâzımdır. Bu vâsıtanın sözleri, ölmüş kalbleri diriltmek için devâdır. Bakışları şifâdır. Taş kesilmiş kalbler, onun muhabbetine kavuşmakla yumuşak olur. Böyle devletli bir rehber ele geçmezse, sâlik-i meczûb da, büyük bir nîmettir. Bu da tâlibleri yetiştirebilir. Onun…","osmanli":"مجذوب سالك"},{"kelime":"SÂLİM","anlam":"1.Sağ; sağlam, eksik-siz. 2.Korkusuz, emîn. 3.İçinde illet harfle-rinden biri (elif, vav, ye) bulunmayan kelime.","kategori":"dil","osmanli":"سالم"},{"kelime":"SÂLİS","anlam":"Üçüncü.","kategori":"dil","osmanli":"ثالث"},{"kelime":"SALLALLAHÜ ALEYHİ VE SELLEM","anlam":"","kategori":"akaid","misal":"وسلم عليه (A) “Allah ona salât ve selâm etsin” mânâsına Resûlullah’ın isminden sonra söy-lenen ta’zim sözü. (Bkz. Salât)","osmanli":"الله صلى"},{"kelime":"SALSÂL","anlam":"Pişmediği hâlde, güneşte beklediği için, pişmiş gibi görünen kuru-muş çamur.","kategori":"dil","misal":"Andolsun ki, biz insanı hame-i mesnûn-dan (balçık çamurundan), salsâlden yarat-tık. (Hicr sûresi: 26) Âdem aleyhisselâm yeryüzünde yaratılan ilk in-san ve ilk peygamberdir. Bütün insanların ba-basıdır. Çeşitli memleketlerden getirilen toprak-ları melekler su ile çamur yapıp, insan şekline koydu. Mekke ile Tâif arasında kırk yıl yatıp salsâl oldu. Önce Muhammed aleyhisselâmın nûru alnına kondu. Sonra Muharremin onuncu Cum‘a günü ruh verildi. (Meâricü’n-Nübüvve)","osmanli":"صلصال"},{"kelime":"SALTANAT","anlam":"1.Sultanlık, İslâm memleketlerinde hükümdarlığın aynı ailede olduğu idare şekli; devlet, hükümet; hâkimiyet, otorite. 2.İhtişam, tantana, debdebe; bolluk, zenginlik.","kategori":"dil","osmanli":"سلطنة"},{"kelime":"ŞÂMÂN","anlam":"İyi ve kötü ruhlarla irtibata geçtiğine inanılan, medyumluk kabiliyetine sahip ve Orta Asya dinlerinde rahiplik yapan kimse.","kategori":"akaid","osmanli":"شامان"},{"kelime":"SÂMİ‘","anlam":"İşiten, dinleyen. Allahü teâlâ-","kategori":"akaid","misal":"nın Esmâ-ı hüsnâsından (esSabûr).","osmanli":"سامع"},{"kelime":"SÂMÎ","anlam":"Nûh aleyhisselâmın üç oğlundan büyüğü olan Sâm’ın soyundan gelenler için kullanılan tabir.","kategori":"dil","misal":"Eski çağlardaki Asur, Bâbil, Keldânî, Fenike, Kartaca, Amâlika, Âd, Semûd gibi kavimler, ayrıca Arablar, Yahudiler, Süryanîler günümüzdeki Sâmî kavimleridir. (Mir’at-ı Kâinât)","osmanli":"صامى"},{"kelime":"SÂMİRÎ","anlam":"Yahudiliğin Sâmiriyye mezhebine mensub olan kimse.","kategori":"dil","osmanli":"سامرى"},{"kelime":"ŞÂN","anlam":"1.Hâl, keyfiyet. 2.İzzet, îtibâr, şeref.","kategori":"dil","misal":"(Şe’n.) O (Allahü teâlâ) her an bir şân üzeredir. (Rahmân sûresi: 29) Haramlardan sakınmak; akıllıların şânı, şeref-lilerin tabiatındandır. (Hazret-i Ali) Her anda o bir şânda, Mevlâ görelim neyler, Neylerse güzel eyler. (İbrahim Hakkı Erzurumî) Her şey hakkında tefekkür edin. Fakat Al-lahü teâlânın zâtı hususunda tefekkür etme-yin. Zira, Arş ve Kürsî ile yedinci kat gök arasında yedibin perde vardır. Ve Allahü teâlânın şânı bunların üstündedir. (Hadîs-i şerîf-Beyhekî) Bu ümmeti şânı yücelik, din-darlık, yükseliş, zafer ve yeryüzü hâkimiye-tiyle müjdele! Onlardan her kim âhiret işini dünya için yaparsa âhiretten hiçbir nasibi olmaz. (Hadîs-i şerîf-Müsned)","osmanli":"شان"},{"kelime":"SANÂYİ‘ ŞİRKETİ","anlam":"İki veya daha fazla sanat sahibinin başkasından iş kabul ederek ücretini paylaşmak üzere veya fabrika kurup îmâlât kârını paylaşmak üzere kurdukları şirket, ortaklık.","kategori":"muamelat","misal":"Sanâyi’ şirketinde iş, işçilik eşit, kâr farklı olabilir. Bir şirketin alacağı siparişi, her ortak yapar, her ortak iş kabul eder ve satış yapar. Her birinin kazancına ve zararına, her ortak, sözleşmedeki nisbette ortaktır. (Dürerü’l-Hükkâm)","osmanli":"شركتى صنايع"},{"kelime":"SANDuKA","anlam":"Umumiyetle mühim şahsiyetlerin mezarları üzerine mermerden veya çuha kaplı tahtadan yapılan mahfaza.","kategori":"dil","osmanli":"صندوقه"},{"kelime":"SANEM","anlam":"2.Gü-zel, çok güzel. 3.Edebiyatta sevgili.","kategori":"tasavvuf","misal":"Put; odundan, altından ve gü-müşten yapılan insan heykeli. (Bkz. Put)","osmanli":"صنم"},{"kelime":"SANEVBERÎ","anlam":"Kozalak şeklinde, koni biçiminde.","kategori":"dil","osmanli":"صنوبرى"},{"kelime":"SÂNÎ","anlam":"İkinci.","kategori":"dil","osmanli":"ثانى"},{"kelime":"SÂNİ‘","anlam":"İstisnâ‘ (sipariş) akdinde malı imal edecek taraf.","kategori":"dil","osmanli":"صانع"},{"kelime":"SAPIK","anlam":"Doğru yoldan sapan; itikadında Ehl-i sünnet ve cemâat mezhebinden ayrılan.","kategori":"hadis","misal":"Resûlullah’ın sallallahü aleyhi ve sellem ve Eshâbının (arkadaşlarının) yolunda gidenler Cehennem’den kurtulacağı müjdelenen kimselerdir. Sapıkların Kitâbdan ve sünnetten çıkardıkları bildirilen her sözü, her yazıyı doğru sanmamalı, yaldızlı propagandalarına aldanmamalıdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"صاﭘيق"},{"kelime":"ŞAPKA","anlam":"Avrupalıların başa giydikleri serpuş. Aslı, Latince ‘külah’ mânâsına ‘cap-pa’dan gelen Slavca veya ‘örülmüş’ mânâsına Arabca şebike’den gelen bir kelimedir. Kalensüve. Kâfirlerin dinî âyinlerini beğenmek ve zarûret yok iken zünnâr kuşanmak ve papaslara mah-sûs olan şapka, salib [haç] gibi küfr alâmetle-rini kullanmak ve bunlara, muhabbet, küfrdür. (Miftahü’l-Cenne)","kategori":"ibadet","osmanli":"شاﭘقه"},{"kelime":"SAPMA AÇISI","anlam":"Pusula istika-meti ile hakikî kutup istikameti arasındaki zâviye (açı).","kategori":"fikih","misal":"Her yerin sapma açısı başkadır. Bir yerin sapma açısı da her sene değişmektedir. O hâlde bir yerde cihet, pusula ile bulunursa kıble açısına, sapma açısını eklemek veya çıkarmak lazımdır.","osmanli":"آﭼيسى صاﭘمه"},{"kelime":"SÂR","anlam":"Yer.","kategori":"dil","osmanli":"سار"},{"kelime":"SAR‘A","anlam":"Muvakkaten şuurun kaybedilmesine sebeb olan bir sinir hastalığı, epilepsi.","kategori":"fikih","osmanli":"صرعه"},{"kelime":"SARF","anlam":"1.Çevirme döndürme. 2.Nakd hâlindeki veya işlenmiş altını, gümüşü veya parayı birbirleri ile mübâdele etme. 3.Arabî kelime bilgisi.","kategori":"muamelat","misal":"Sarf satışında satanın ve alanın sözleşmeden sonra, ayrılmadan kabz etmeleri yani eline veya cebine almaları lâzımdır. (Dürerü’l-Hükkâm) Morfoloji. Kelimelerde meydana gelen değişikliklerden ve birbirlerinden türemelerinden bahseden ilim.","osmanli":"صرف"},{"kelime":"SÂRÎ","anlam":"(A. Sirâyet’den) Sirâyet eden, bula-şan, bulaşıcı.","kategori":"dil","osmanli":"سارى"},{"kelime":"ŞÂRÎ‘","anlam":"1.Teşrî eden, kanun koyan. 2.Şe-riat koyan mânâsına Allahü teâlânın veya şe-riat sahibi mânâsına Resûlullah aleyhisselâmın sıfatı.","kategori":"akaid","misal":"(Bkz. Teşrî‘)","osmanli":"شارع"},{"kelime":"SÂRÎ HASTALIK","anlam":"Bulaşıçı hastalık. Maraz-ı sârî.","kategori":"dil","osmanli":"لق خسته سارى"},{"kelime":"SARÎH","anlam":"Belli, açık, meydanda olan; kendisinden kasd edilen mânânın açıkça an-laşıldığı lafız (Söz).","kategori":"dil","misal":"Yalnız boşamakta kullanılan seni boşadım, sen bana haramsın gibi sarîh bir lafzı (sözü) şaka olarak veya şaşırarak da söylediği anda, yanında değil ise, mektup veya vekîli ile bildi-rince, bir talâk (boşama) olur. (İbni Âbidîn)","osmanli":"صريح"},{"kelime":"ŞÂRİH","anlam":"Şerheden, açan; bir kitabın metnini izah eden. (Bkz. Şerh)","kategori":"dil","osmanli":"شارح"},{"kelime":"SARIK","anlam":"Kavuk, fes, takke gibi baş-lıkların üzerine sarılan tülbent veya şal. (Bkz. İmâme)","kategori":"dil","osmanli":"صاريق"},{"kelime":"SÂRIK","anlam":"Sirkat eden, hırsız, çalan.","kategori":"dil","osmanli":"سارق"},{"kelime":"SARRÂF","anlam":"1.Sarf eden. 2.Altın ve gümüş alım satımıyla uğraşan. 3.Mücevherci, kuyumcu.","kategori":"muamelat","osmanli":"صراف"},{"kelime":"ŞART","anlam":"Yerine getirilmesi gereken şey.","kategori":"fikih","misal":"Bikadri’l-imkân şarta mürâ’ât olunmak lâzım gelir. [İmkân derecesinde şarta riayet etmek lâzımdır.] (Mecelle, m. 83)","osmanli":"شرط"},{"kelime":"Şart-ı Vâkıf","anlam":"Vakfedenin, vakfın işleyişi ile alâkalı her çeşit arzusu.","kategori":"muamelat","misal":"Şart-ı vâkıf, nass-ı şâri’ gibidir sözü meşhûrdur. Bu söz, kâdî, vâkıfın şartlarına uymayan bir hüküm veremez, herkesin bu şartlara uyması lâzımdır demektir. Yalnız, yedi şart müstesnâdır. Bu yedi şartı kâdî değiştirebilir. Meselâ, hiyânet eden mütevellîyi ve nâzırı azl etmesi vâcib olur. (İbni Âbidîn)","osmanli":"واقف شرط"},{"kelime":"Şartlı Satış","anlam":"Şarta bağlanan satış, satışı şarta ta’lîk.","kategori":"fikih","osmanli":"صاتيش شرطلى"},{"kelime":"ŞATH","anlam":"Ciddî bir şeyi, mizahî dille anlatan edebî söz.","kategori":"tasavvuf","misal":"Şatah.","osmanli":"شطح"},{"kelime":"SATHÎ","anlam":"1.Bir şeyin dış yüzü ile alâ-kalı. 2.Derinliği olmayan, absit.","kategori":"dil","misal":"Sathî, derin-lemesine olmayan.","osmanli":"سطحى"},{"kelime":"ŞATHİYYÂT","anlam":"1.Alaylı, eğlenceli edebî parçalar. 2.Tasavvuf sarhoşluğu ile söylenen abartılı ve mizahî ifadeler.","kategori":"tasavvuf","misal":"Allahü teâlâ için söylenen kurb, ma’iyyet, ihâta, sereyân, vasl, ittisâl, tevhîd ve ittihâd gibi sözler, müteşâbihât ve şathiyyât cinsindendirler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"شطحيات"},{"kelime":"SATRANÇ","anlam":"İki kişi arasında, altmış dört kareye bölünmüş dört köşe tahta üzerinde onaltışardan otuz iki taşla oynanan, zekâya da-yalı bir oyun. Aslı Farsça şüdirenc gelir.","kategori":"dil","misal":"Kumar, satranç, tavla ve benzerleri gibi oyunları oynayan kimselere selâm vermeyin. Şayet selâm vermişlerse, almayın. (Hadîs-i şerîf-Deylemî) Satranç oynamak câiz değildir. Ebû Yûsuf, Mâ-lik ve Şâfiî’ye göre altı şarta riayet edilirse câiz-dir. (İbni Âbidîn)","osmanli":"سطرنﭻ"},{"kelime":"SAVM","anlam":"Oruç. Fecrin ağarmasından, güneşin batışına kadar yiyip içmeği ve cimâ’ı terk etmek. (Bkz. Oruç)","kategori":"ibadet","osmanli":"صوم"},{"kelime":"SAVME‘A","anlam":"Hristiyanların ibâdet yeri.","kategori":"dil","misal":"Kilise. Bîa. (Bkz. Kilise)","osmanli":"صومعه"},{"kelime":"SAYD","anlam":"Avlanma; av hayvanı.","kategori":"ibadet","misal":"Deniz saydı yapmak ve onu yemek size helâl kılındı ki hem size, hem de yolcu olanlarınıza faydalı olsun. Kara saydı ise ihramda bulunduğunuz müddet içerisinde size haram edildi. (Mâide sûresi: 96)","osmanli":"صيد"},{"kelime":"SÂYE","anlam":"1.Gölge 2.Koruma, sahip çıkma, himâye.","kategori":"ibadet","osmanli":"سايه"},{"kelime":"ŞAYİ‘","anlam":"1.Herkes tarafından bilinen; yayılmış, duyulmuş; şuyû bulan. 2.Taksim edil- memiş müşterek hisse.","kategori":"ibadet","osmanli":"شايع"},{"kelime":"ŞÂZİLİYYE (Şâzeliyye)","anlam":"Hicrî VI. asırda Tunus’ta yaşamış olan velî Ebü’l-Hasen Şâzilî’nin Ebû Bekr Şiblî vâsıtasıyla Hazret-i Ali’ye ulaşan ve zikr-i cehrîye istinâd eden tasavvuftaki yolu.","kategori":"tasavvuf","osmanli":"شاذليه"},{"kelime":"ŞÂZZ","anlam":"Tek, eşsiz, benzersiz; kâide dışı, kâideye uymayan, marjinal.","kategori":"dil","misal":"Fıkıhta mütevâtir bir nassa aykırı her haber ve icma’ ehlinden olmayan birinin, icmaya uy-mayan sözü şâzz kabul edilir. İcma’ ehlinden ise, o icma zannî olur.","osmanli":"شاذ"},{"kelime":"Se‘âdet-i Dâreyn","anlam":"İki cihan (dünya ve âhiret) hoşnudluğu.","kategori":"akaid","osmanli":"دارين سعادت"},{"kelime":"Se‘âdet-i Ebediyye","anlam":"Sonsuz, ebedî mutluluk, bahtiyârlık. Cennetliklerden olma. Cehennem’den kurtulmak ve saadet-i ebediyyeye kavuşmak, Peygamberlere aleyhimüsselâm tâbî olmaya bağlıdır. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"ابديه سعادت"},{"kelime":"ŞEB","anlam":"Gece.","kategori":"dil","osmanli":"شب"},{"kelime":"SEB‘İYYE","anlam":"Gulât-ı Şia’nın (Şiîliğin aşırı) kollarından olup, şeriat sahibi peygamberle-","kategori":"akaid","misal":"rin yedi tane ve yedincisinin mehdî olduğuna, her asırda yedi İmâmın bulunduğuna inandığı için bu ismi alan [seb’‘, yedi demektir] fırka. İsmâiliyye’ye bağlı olup, meşhur Hasan Sabbâh’ın da mezhebidir.","osmanli":"سبعيه"},{"kelime":"SEBBİYYE","anlam":"Şia’nın kollarından olup, Sahâbilerden bir kısmını sebb ettikleri (sövdükleri) için bu isimle anılan bir fırka.","kategori":"dil","osmanli":"سبيه"},{"kelime":"SEBE’","anlam":"Kur’ân-ı kerîmde anlatılan ve Belkis adındaki kadın hükümdarın hüküm sürdüğü Yemen’de bir memleket.","kategori":"dil","misal":"SEBE’","osmanli":"سبأ"},{"kelime":"SEBE’ SûRESİ","anlam":"Kur’ân-ı kerîmin otuz dördüncü sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Elli dört âyet-i kerîmedir. On beşinci âyet-i kerîmede geçen Yemen’de ya-şayan kabilenin adı olan Sebe’ kelimesinden dolayı, Sûretü’s-Sebe’ denilmiştir. Sûrede; Al-lahü teâlânın ilminin genişliği, Allahü teâlâ-nın Sebe halkına lütufları ve onların nankörlük göstermeleri yüzünden uğradıkları felâket-ler, güzel ve faydalı işlerden başka hiçbir şe-yin insanı Allahü teâlâya yaklaştırmayacağı, âhirette izin verilenler hâriç kimsenin kim-seye faydası dokunmayacağı bildirilmektedir. (Mefâtihü’l-Gayb, Kurtubî) Kim Sebe’ sûresini okursa, hiçbir resûl ve nebî kalmaz ki, kıyâmet günü ona arka-daş olmasın ve müsâfeha etmesin. (Hadîs-i şerîf-Beydâvî)","osmanli":"سى سوره سبأ"},{"kelime":"SEBEB","anlam":"Vâsıta; bir işte te’siri olmayan fakat o işin yapılmasını, vücûdunu, var olmasını îcâb ettiren şey.","kategori":"fikih","misal":"Allahü teâlâ, herkese lâyık olanı, umduğunu verir. Sebebleri görenin işlerini, arzularını sebeb ile yaratır. Sebebleri değil de, bunların sahibini görene sebebsiz verir. Nitekim hadîs-i kudsîde; “Kullarım beni zannettikleri gibi bulur.” buyurmaktadır. Evliyâ yalnız sebeblerin sahibini, sebeblere kuvvet ve te’sir edeni görüp, sebebleri görmez. (Mektûbât-ı İmâm-ı Rabbânî) Vakt, namazın sebebidir. Vakit girince namaz f…","osmanli":"سبب"},{"kelime":"ŞEBEH","anlam":"1.Benzerlik; benzer, denk. 2.Kı-yasat illeti tesbit etme yollarından biri.","kategori":"dil","osmanli":"شبه"},{"kelime":"SEBÎL","anlam":"1.Yol. 2.Su dağıtılan yer ve da-ğıtılan şeyler.","kategori":"dil","misal":"Gelip-geçenlerin su ihtiyâçlarını Allah rızâsı için ücretsiz olarak karşılamak üzere inşâ edilen çeşme.","osmanli":"سبيل"},{"kelime":"SEBZ","anlam":"Yeşil.","kategori":"dil","osmanli":"سبز"},{"kelime":"SEC‘","anlam":"Nesirde cümle sonlarının kâfiye şeklinde birbirine uygunluğu.","kategori":"dil","osmanli":"سجع"},{"kelime":"SECÂVEND","anlam":"Kur’ân-ı kerîmin, mânâsına uygun ve doğru okunabilmesi için durak ve geçiş yerlerini gösteren cim, mim, ze, tı, sad gibi işâretler.","kategori":"dil","osmanli":"سجاوند"},{"kelime":"SECC","anlam":"Kurbanlık hayvanların kanını akıtmak.","kategori":"ibadet","osmanli":"ثج"},{"kelime":"ŞECC","anlam":"Bir kimsenin başını veya yü-zünü yaralama.","kategori":"dil","osmanli":"شج"},{"kelime":"SECCÂD","anlam":"Çok secde eden.","kategori":"ibadet","osmanli":"سجاد"},{"kelime":"SECCÂDE","anlam":"Yere serilip üzerinde namaz kılınan küçük halı, kilim, hasır, bez gibi temiz sergi, namazlık.","kategori":"ibadet","misal":"Üzerinde Kâbe resmi, câmi resmi veya mübârek yazılar bulunan halıları, seccâdeleri yere sermek câiz değildir. Bunları zînet (süs) için duvara asmak câiz olur. (Abdülhakîm Arvâsî)","osmanli":"سجاده"},{"kelime":"ŞECCE","anlam":"Baş ve yüzde meydana gelen yaralanma.","kategori":"dil","osmanli":"شجه"},{"kelime":"SECDE","anlam":"1.Eğilme, yere kapanma, yüzünü yere sürme; boyun eğme. 2.Namazın içindeki farzlarından; alnı, burnu, el ayalarını, dizleri ve ayak parmaklarını yere koyma.","kategori":"ibadet","misal":"Gökte ve yerde olan her şey, Allahü teâlâya secde eder. (Ra’d sûresi: 15) Eğer Allah’a ibâdet etmek istiyorsanız, güneşe de aya da secde etmeyin. Onları yaratan Allah’a secde edin! (Fussilet sûresi: 37) Onları alınlarındaki secde eserinden tanırsın! (Feth sûresi: 29) Kul şu yedi âzâ üzerine secde eder; yüzü, iki avuc…","osmanli":"سجده","baglamlar":[{"baglam":"namaz","anlam":"Namazın rükünlerinden; alın, burun, iki el, iki diz ve ayak parmaklarını yere koyarak yapılan ibâdet."},{"baglam":"tilâvet","anlam":"Kur'ân'daki secde âyetlerini okuyan veya dinleyene vâcib olan secde."},{"baglam":"sehiv","anlam":"Namazda yanılma sebebiyle namazın sonunda yapılan iki secde."},{"baglam":"şükür","anlam":"Bir nimete kavuşunca veya bir belâdan kurtulunca şükür için yapılan secde."}]},{"kelime":"Secde-i Sehv","anlam":"Yanılma secdesi. Namazda bir farzın veya vâcibin, vaktinden önce veya sonra yapılması yâhud vâcibin terkinde yapılması lâzım gelen secde.","kategori":"ibadet","misal":"Birkaç kere secde-i sehv îcâb etse, bir kere yapmak yetişir. (Halebî)","osmanli":"سهو سجدۀ"},{"kelime":"Secde-i Şükr","anlam":"Şükür secdesi. Bir nimete kavuşan veya bir dertten kurtulan kimsenin Allahü teâlâ için yaptığı secde.","kategori":"akaid","misal":"Secde-i şükr, tilâvet secdesi gibidir. (Tahtâvî)","osmanli":"شكر سجدۀ"},{"kelime":"Secde-i Tilâvet","anlam":"Okuma secdesi. Kur’ân-ı kerîmin on dört yerindeki secde âyetinden birini okuyan veya duyanın yapması vâcib olan secde.","kategori":"dil","osmanli":"تلاوت سجدۀ"},{"kelime":"SECDE SûRESİ","anlam":"Kur’ân-ı kerî-min otuz ikinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Otuz âyet-i kerîmedir. On beşinci âyetinde geçen Secde kelimesin-den dolayı Sûretü’s-Secde denilmiştir. Sûrede; Allahü teâlânın her şeyi güzel yarattığı, öldük-ten sonra tekrar dirilmeyi inkâr edenlerin âhi-rette pişman olacakları, Hazret-i Mûsâ’nın İs-râiloğullarına yol gösterici olarak gönderildiği bildirilmektedir. (Mefatihü’l-Gayb, Taberî) Kim Secde ve Mülk sûrelerini yatsı nama-zından sonra okursa, Kadir Gecesini ihyâ et-miş gibi sevab verilir. (Hadîs-i şerîf-Beydâvî)","osmanli":"سى سوره سجده"},{"kelime":"ŞECER","anlam":"Ağaç, sapı olan her çeşit bitki.","kategori":"dil","osmanli":"شجر"},{"kelime":"ŞECERE","anlam":"1.Küçük ağaç; tek bir ağaç. 2.Soy kütüğü, soy ağacı.","kategori":"dil","osmanli":"شجره"},{"kelime":"ŞECERE-İ TAYYİBE","anlam":"“Temiz ağaç” mânâsına bütün iyiliklerin ve güzelliklerin kaynağı mânâsına İslâmiyet’e verilen sıfat.","kategori":"akaid","misal":"İslâmiyet öyle bir şecere-i tayyibedir ki, onun meyveleri ile bütün âlem dünyada da, âhirette de faydalanmaktadır. Bütün faydalar ondan çıkmaktadır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"طيبه شجرهء"},{"kelime":"SEDÂ","anlam":"Kumaşın uzunlamasına olan ip-leri, çözgü, arış. Enlemesine olan, luhme (atkı, argaç) gelir.","kategori":"dil","osmanli":"سدا"},{"kelime":"ŞEDD","anlam":"Sıkı bağlama, sıkma.","kategori":"dil","osmanli":"شد"},{"kelime":"SEDD-İ ZÜLKARNEYN","anlam":"Kur’ân-ı kerîmde Zülkarneyn adıyla bildirilen peygamber veya velînin, Ye’cûc ve Me’cûc adlı kavmi engellemek için yaptırdığı set.","kategori":"dil","misal":"(Zülkarneyn) Sonra yine bir yol buldu (doğudan kuzeye gitti). Nihâyet iki dağ arasına ulaştığı zaman onların önünde hemen hiç söz anlamayan bir kavim buldu. Onlar (tercümanları vâsıtasıyla); “Ey Zülkarneyn! Ye’cüc ve Me’cûc tâifesi bu yerde fesat edicilerdir. Acabâ biz sana masrafını tâyin etsek de bizimle onların arasında set yapsan” dediler. (Zülkarneyn); “Rabbimin bu işte bana verdiği kudret, sizin vereceğiniz ha…","osmanli":"ذوالقرنين سد"},{"kelime":"ŞEF‘","anlam":"1.Çift olan her şey. 2.Namazların her iki rek’ati.","kategori":"ibadet","misal":"Vetr’in zıddı. Şef‘e ve vetre yemin olsun. (Fecr sûresi: 3) Resûlullah aleyhisselâmdan rivâyet edildiğine göre Kur’ân-ı kerîmde geçen şef ‘, kurban kesme; vetr arefe günüdür veya şef ‘ ve vetr’den kasıt namazdır; bazen tek bazen çift rek’attir. İbni Abbas ve Tâbiîn ulemâsına göre şef ‘den kasıt çifter çifter yaratıldıkları için mahlûklar; vetr-den kasıt Allahü teâlâdır. Başka izahlara göre: Vetr, Hazret-i Âdem, şef ‘ Havva’dır. Vetr, Kâbe; şef ‘ Safâ ile Merve’dir. Vetr, yedi Cehennem, şef ‘ sekiz cennettir. Şef ‘ gün ve geceler, vetr ise ardında gece olmayan kıyamet günüdür. Şef ‘ Mekke ve Medîne mescidleri, vetr ise Mescid-i Aksâdır. Şef ‘ erkek-dişi varlıklar, vetr, cansız-lardır. (Kurtubî) Namazların her şef ‘inde zamm-ı sûrelerin mus-haftaki sırasına riayet edilmezse mekrûh olur. (İbni Âbidîn)","osmanli":"شفع"},{"kelime":"SEFÂHET","anlam":"Aklın az ve hafîf olması. Malını dinin ve aklın beğenmediği yerlere sarf etme, lüzumsuz harcama.","kategori":"muamelat","misal":"Sefâhet ehliyet ârızasıdır. Sefâhet ehli mümey-yiz çocuk gibidir; kendisine bir vasî tayin edilir.","osmanli":"سفاهت"},{"kelime":"SEFÂLET","anlam":"1.Sefillik, aşağılık. 2.Çok fakirlik.","kategori":"dil","osmanli":"سفالت"},{"kelime":"SEFER","anlam":"1.Yol almak, ibâdet, cihad, gezmek, öğrenmek, ticaret, sıla-i rahm gibi sebeblerle yapılan yolculuk.","kategori":"fikih","misal":"Mü’minlerin hepsinin toptan sefere çıkmaları doğru değildir. Her topluluktan bir taife, dini öğrenip, kavimlerini geri döndüklerinde ikaz etmek için geride kalmalıdır. (Tevbe sûresi: 122) Sefer edin, sıhhat bulun! (Hadîs-i şerîfİbnü’s-Sünni, Ebû Nuaym)","osmanli":"سفر"},{"kelime":"Sefer Der Vatan","anlam":"Nakşibendiyye yolunun on bir temel esâsından biri. Sâlikin kötü ahlâk, beşer tabiatının sıfatlarından kur-tulması, beşerî sıfatlardan meleklere âit sıfat-lara, kötü, çirkin vasıflardan, iyi, güzel ah-lâka geçmesi.","kategori":"akaid","misal":"Sefer der vatan nasip olunca, başkaları arasında düşüncenin dağılması da vatan gibi olan yalnız-lığa sefer eder gider. Dışardaki zihin dağınıklığı, kalbe sızamaz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"وطن در سفر"},{"kelime":"SEFERÎ","anlam":"1.Seferde olan, misâfir, yolcu. 2.Bulunduğu şehirden veya köyden gideceği yolun iki veya bir kenarındaki evlerin dı-şına çıkarken, senenin kısa günlerinde, insan veya deve yürüyüşü ile, son evden îtibâren üç günde gidilecek yere (Hanefî’de 104, diğer üç mezhebte 80 km) gitmeye niyet eden kimse. (Bkz. Vatan) Hür kadının, zevci (beyi) veya ebedî mahrem (evlenmesi haram olan) akrabâsından biri ya-nında bulunmadan, yalnız veya başka kadın-larla yâhud âkil, bâliğ ve sâlih olmayan mah-remi ile üç günlük yola gitmesi (üç mezhebte de) haramdır. Şâfiî mezhebinde kadınlar mah-remsiz olarak, farz olan hacca gidebilir. (Ha-dîka, Berîka)","kategori":"dil","osmanli":"سفرى"},{"kelime":"SEFERÎLİK","anlam":"Senenin kısa günlerinde insan veya deve yürüyüşü ile üç günde gidi-lecek yere gitmeye niyet ederek bulunduğu yerin kenar evlerinin dışına çıkmak. (Bkz. Müsâfir, Sefer)","kategori":"dil","osmanli":"سفريلك"},{"kelime":"ŞEFÎ‘","anlam":"1.Şefâ’at eden, bir suçun, günahın bağışlanması için vâsıta, aracı olan. 2.Şüf ’a hakkına, yani bir gayrımenkul satıldığı zaman o bedelle öncelikli olarak alma hakkına sahip olan kimse.","kategori":"dil","misal":"(Bkz. Şefâat) (Bkz. Şüf ‘a)","osmanli":"شفيع"},{"kelime":"SEFÎH","anlam":"1.Ayak takımı, kendisini bilmez. 2.Malını dinin ve aklın uygun görmediği yere harc eden, aklı az olan.","kategori":"dil","misal":"Ya Rabbî! İçimizdeki sefîhlerin yaptıkla-rından dolayı bizi helâk eder misin? (A’râf sûresi: 155) (Bkz. Sefâhet) Mallarınızı sefihlere vermeyiniz. (Nisâ sûresi: 5) Bir kimsede üç şeyden biri bulunmazsa ameli (ibâdeti) kıymet ifâde etmez ve hesâba değmez. Haramdan alıkoyacak takvâ, Allah korkusu, sefihe uymaktan men edecek hilm (yumuşaklık), halk arasında hüsn-i muâmele ile yaşayacağı bir ahlâk. (Hadîs-i şerîf-Müs-nedü İmâm-ı Ahmed) Sefîh, mümeyyiz çocuk gibidir. Mahkeme ka-rarıyla hacredilebilir. Sefih, hibe gibi aleyhine muameleleri hiç yapamaz. Hibe kabulü gibi le-hine muameleleri yapabilir. Satış, kira gibi hem lehine, hem aleyhine olan muameleleri vasîsi-nin izniyle yapabilir. (İbni Âbidîn)","osmanli":"سفيه"},{"kelime":"SEFÎL","anlam":"2.Alçak. 3.Akıllı, uslu.","kategori":"dil","misal":"(A. Sefâlet’den) l.Sefalet çeken, çok fakir.","osmanli":"سفيل"},{"kelime":"SEFÎR","anlam":"1.Elçi; bir ecnebi devlet nezdinde gönderilen temsilci; 2.Bir tasavvuf mürşidinin, halife olabilecek vasıfları kendisinde gördüğü ve bunun için yetiştirdiği talebesi.","kategori":"tasavvuf","misal":"Tasavvufta hilâfetin üçüncü çeşiti, sefâret-i mahzâdır. Bu zamanda mecâzen hilâfet ıtlâk olunur. Sefîr-i mahzâ, tarîkat umurunun kâffesinde emre imtisâl eder; re’yine hiçbir şey tefviz edilmez. Sefir, tedricen terakki eder ve mukayyed halîfeliğe hak kazanır. (Sevânihü’l-Efkâr)","osmanli":"سفير"},{"kelime":"ŞEFKAT","anlam":"Acımak, merhamet etmek, esirgemek.","kategori":"dil","misal":"Büyüklerine hürmet, küçüklerine şefkat et-meyen bizden değildir. (Hadîs-i şerîf-Taberânî) ŞEHÂDET: شهادت (A) Şehîdlik, şehîd olmak. (Bkz. Şehîd)","osmanli":"شفقت"},{"kelime":"Şehâdet Kelimesi","anlam":"Kelime-i Şehâdet. Müslümanlığa girmeyi ifade eden ve İslâm’ın beş şartından birincisi olan “Eşhedü enlâ ilâhe illallah ve eşhedü enne Muhamme-den abdühû ve resûlüh” mübârek sözü. (Bkz. Kelime-i Şehâdet)","kategori":"dil","misal":"Şehâdet kelimesini okumanın yüz otuz kadar fâidesi vardır. Bunlardan birisi de sırat köprü-sünü yıldırım gibi geçmektir. (Miftahü’l-Cenne)","osmanli":"سى كليمه شهادت"},{"kelime":"Şehâdet Kelimesi","anlam":"(Bkz. Kelime-i Şehâdet)","kategori":"dil","osmanli":"كلمهسى شهادت"},{"kelime":"Şehâdet Kelimesi [1]","anlam":"Kelime-i Şehâdet. Müslümanlığa girmeyi ifade eden ve İslâm’ın beş şartından birincisi olan “Eşhedü enlâ ilâhe illallah ve eşhedü enne Muhammeden abdühû ve resûlüh” mübârek sözü.","kategori":"fikih","misal":"Şehâdet kelimesini okumanın yüz otuz kadar fâidesi vardır. Bunlardan birisi de sırat köprüsünü yıldırım gibi geçmektir. (Miftahü’l-Cenne)","osmanli":"سى كليمه شهادت"},{"kelime":"SEHÂVET (Sehâ)","anlam":"Cömertlik; malını, hayırlı yerlere seve seve verme.","kategori":"tasavvuf","misal":"Sehâvet, Cennet’te bir ağaçtır. Cömert olan onun bir dalını yakalamıştır. O dal onu, Cennet’e götürmeden bırakmaz. (Hadîs-i şerîfDârekutnî)","osmanli":"سخاوت"},{"kelime":"SEHER","anlam":"Fecrin ağarması.","kategori":"dil","misal":"Rüyanın en gerçeği, seherde görünendir. (Hadîs-i şerîf-Tirmizî)","osmanli":"سحر"},{"kelime":"Seher Vakti","anlam":"Duâların kabule yakın olduğu, gecenin son altıda biri.","kategori":"ibadet","misal":"Onlar, geceleri pek az (bir zaman) uyurlar, seher vakitlerinde hep istiğfâr (tövbe) ederlerdi. (Zâriyât sûresi: 17, 18) Allahü teâlâ buyurur: “Arzdaki halka azap murad ettikte, camileri şenletenlere, benim için birbirini sevenlere, seher vaktinde istiğfâr edenlere bakıp, azâptan vazgeçerim” (Hadîs-i şerîfBeyhekî) Gece seher vaktinde ve namazlardan sonra yapılan duâ kabul olunur. (Hadîs-i şerîfŞir’atü’l-İslâm) Seher…","osmanli":"وقتى سحر"},{"kelime":"ŞEHÎD","anlam":"1.Şâhid olan, müşâhade eden. 2.Din yolunda hayatını veren kimse; haksız yere öldürülen kimse. 3.Bütün mahlûkâtın açık ve gizli şeylerini bi-len, kıyâmet gününde leh ve aleyhlerinde olan amellere şâhidlik eden mânâsına Allahü teâlâ-nın Esmâ-i hüsnâsından (eş-Şehîd). Evden kaçan çocuk üzerine eş-Şehîd ism-i şerîfi söylenirse, hâli düzelir, hak yola döner. Ana-baba, isyankâr evlâdının alnından tutar ve Allahü teâlânın eş-Şehîd ism-i şerîfini okursa, o çocuk Allahü teâlânın izniyle itâatkâr olur. (El-İstigâsetü’l-Kübrâ)","kategori":"dil","misal":"Vefat ederken Cennet’i müşahade ettikleri için bu isim verilmiştir. (Bkz. Şehîd-i Hakîkî; Şehîd-i Dünyâ; Şehîd-i Âhiret) Allah yolunda şehîd olanlara ölü demeyiniz. Onlar diridirler. Kendilerine her zaman rızk verilir. Onlarda azap olunmak korkusu yok-tur. Nîmetlerden mahrum kalmak üzüntüsü de yoktur. (Âl-i İmrân sûresi: 170) Şehid için Allah’ın indinde altı haslet vardır: Kanının ilk damlasında günahları mağfiret olur. Ka-bir azâbından emindir. Kendisine iman hul-leleri giydirilir. Cennet’te makamını görür. Kıyamet korkusundan emin olur ve hûrî-lerle evlendirilir. (Hadîs-i şerîf-Beyhekî) Al-lah yolunda ölmenin dışında şehidlik yedi nevidir: Allah yolunda ölen şehiddir. Taun-dan ölen şehiddir. Denizde boğulan şehid-dir. Zatülcenb sahibi şehiddir. İç illetinden ölen şehiddir. Yangında ölen şehiddir. Yı-kıntı altında kalan da şehiddir. Doğum es-nasında ölen kadın da gene şehiddir. (Ha-dîs-i şerîf-Ebû Dâvûd) Şehîdin, kul haklarından başka bütün günah-ları affolur. Kul haklarını da, Allahü teâlâ kıyâ-mette helâllaştıracaktır. Cihâdda ve hac yolunda ve sınır boylarında nöbette ölenlere, kıyâmete kadar bu ibâdetlerin sevâbı devamlı verilir. Be-denleri çürümez. Her biri kıyâmette yetmiş ki-şiye şefâat eder (İbn-i Âbidîn)","osmanli":"شهيد"},{"kelime":"SEHİM (Sehm)","anlam":"Hisse, pay, nasip; hisse senedi; kur’a veya kumar oku; ok; her vârisin alacağı miras payı.","kategori":"miras","osmanli":"سهم"},{"kelime":"ŞEHR (Şehir)","anlam":"1.Halkının çoğu ticaret, sanat ve idarî işlerle uğraşan iskân mer- kezi. 2.Âmiri yani ahkâm-ı şer’iyyeyi yerine getirmeye ve mazlumu zâlimden kurtarmaya muktedir idarecisi, câmisi, minberi ve hükûmet tarafından tayin edilen hatîbi bulunan yer. Medîne. Cum‘a namazının birinci şartı, namazı şehirde kılmaktır. Kasabalar, çarşısı ile câmisi, minberi ve hükûmet tarafından tayin edilen hatîbi bulunan köyler de Cum‘a namazı için ayrı birer şehir hükmündedir. (İbni Âbidîn)","kategori":"muamelat","osmanli":"شهر"},{"kelime":"ŞEHREMİNİ","anlam":"Osmanlılarda belediye reisi.","kategori":"osmanli","osmanli":"امينى شهر"},{"kelime":"ŞEHRİYÂRÎ","anlam":"1.Şehriyar ile alâkalı, hükümdara mahsus. 2.Şehriyarlık, hükümdarlık. 1.Şehvet ile alakalı. 2.Şeh- vete düşkün kimse.","kategori":"dil","misal":"ŞEHVÂNÎ: شهوانى (A)","osmanli":"شهريارى"},{"kelime":"SEHV","anlam":"Yanılma.","kategori":"dil","osmanli":"سهو"},{"kelime":"ŞEHVET","anlam":"Nefsin yaşamak için lâzım olan ve kendisine tatlı gelen şeyleri istemesi; aşırı arzu, iştah; cinsî istek.","kategori":"tasavvuf","misal":"Cehennem şehvet perdesiyle kuşatılmıştır. Oraya şehvetler yapılmakla girilir. Cennet de nefsin hoşlanmadığı ibâdetlerle kuşatılmıştır; buraya da ibâdet meşakkatleriyle girilir. (Hadîs-i şerîfBuhârî) Gençlik çağı, nefsin kaynadığı, şehvetlerin oynadığı, insan ve cin şeytânlarının saldırdığı bir zamandır. Böyle bir çağda yapılan az bir amele pekçok sevab verilir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"شهوت"},{"kelime":"SEKAR","anlam":"Cehennem’i meydana getiren tabakalardan üçüncüsü.","kategori":"akaid","misal":"Sekar’ın ne olduğunu bilir misin? Hem o Cehennem, bedeninden hiçbir eser bırakmaz hem yine eski hâline getirip (aynı azâbı yapmaya) devam eder. (Müddessir sûresi: 26,27)","osmanli":"سقر"},{"kelime":"ŞEKÂVET","anlam":"1.Eşkıyalık, yol kesicilik. 2.Kâfir veya fâsık olma, cehennemlik olma.","kategori":"dil","misal":"Seâdetin zıddı. Ahlâk güzelliği kişinin saadetindendir. Ah-lâkının fenâlığı ise şekâvet alâmetidir. (Ha-dîs-i şerîf-Beyhekî)","osmanli":"شقاوت"},{"kelime":"SEKERÂT","anlam":"Sarhoşluklar; kendinden geçmeler.","kategori":"dil","osmanli":"سكرات"},{"kelime":"SEKR","anlam":"1.Sarhoşluk. 2.Şuursuzluk, ken-dinde olmama hâli.","kategori":"tasavvuf","misal":"Tasavvufta sâlikin kendi-sini Allah sevgisi kapladığında, kendisini unu-tacak derecede mânevî sarhoşluk. Sekr sahipleri mâzûrdurlar yani sorguya çekil-mez, azap edilmezler. Hallâc-ı Mansûr “Enel-hak” sözünü sekr hâlinde söylemiş olup, mâzûr-dur. Yalnız sahv sahipleri taklit olunur. Sahv bilgilerine uyanlar kurtulur. Sekr bilgilerine uyulmaz. Bunlara uyanlar mâzûr olmaz, sor-guya çekilirler, cezâlandırılırlar. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سكر"},{"kelime":"ŞEKûR","anlam":"1.Çok şükreden, iyilik bilen; iyiliğe hayırla mukabele eden. 2.Kendisi için yapılan az tâate yüksek derece-ler ihsân eden, sayılı günlerde yapılan ibâdete, sayısız mükâfât veren mânâsına Allahü teâlâ-nın Esmâ-i hüsnâsından (eş-Şekûr). Îmân ehli, Adn adlı Cennetlere girerler. Orada altın bilezikler ve inci ile süslenecek-ler. Elbiseleri de ipektir. Ehl-i Cennet, bu nî-metleri görünce derler ki: “Geçim ve âkıbet derdini bizden gideren Allah’a hamd olsun. Gerçekten Rabbimiz Gafûr’dur, Şekûr’dur.” (Fâtır sûresi: 33, 34) “Lâ ilâhe illallah” di-yenler için, mezârlarında vahşet (yalnızlık), mahşer meydanında dehşet (korku) yoktur. Sûr’un üflenmesi ânında başlarından top-rakları nasıl silkerek kalktıklarını sanki gö-rür gibiyim. Hüznü bizden gideren Allah’a hamdederiz. Muhakkak ki bizim Rabbimiz gafûr (pekçok mağfiret edici, bağışlayıcı) ve şekûrdur. (Hadîs-i şerîf-Taberânî) Eş-Şekûr ism-i şerîfini söyleyenin vücûduna âfiyet gelir, sıhhat ve selâmete kavuşur. Geçimi bollaşır. (El-İstigâsetü’l-Kübrâ)","kategori":"ibadet","misal":"Şâkir’in mü-bâlağalı hâli. Şüphesiz ki bunda (Sebe’ halkının hikâye-sinde; günahları, nefislerinin arzu ve istekle-rini yapmamaya, şehvetlerine uymamaya, ibâ-det ve tâatları yapmanın meşakkatine, belâ ve musîbetlere) çok sabreden (bütün hâllerde ve vakitlerde Allahü teâlânın lutfettiği nîmetlere), şekûr olan herkes için, elbette ibretler var-dır. (Sebe’ sûresi: 19) Resûlullah sallallahü aleyhi ve sellem ayakları şişinceye kadar namaz kılardı. Eshâb-ı kirâm, “Yâ Resûlallah! Allahü teâlâ senin gelmiş geç-miş bütün günahlarını affetmiştir” dedikle-rinde; “Şekûr bir kul olmayayım mı?” bu-yurdu. (Müslim)","osmanli":"شكور"},{"kelime":"SELÂM","anlam":"1.Ayıp, kusur, noksanlık ve hastalıktan beri olma. 2.Muhabbetin ifadesi olarak yapılan hayır duâ.","kategori":"hadis","misal":"Zâtı ayıplardan (ku-surlardan), sıfatları noksanlıklardan ve işleri kötülüklerden uzak, temiz olan mânâsına Al-lahü teâlânın Esmâ-i hüsnâsından (es-Selâm). “O, selâmdır”. (Haşr sûresi: 23) Resûlullah aleyhisselâm, namazdan sonra Allahümme ente’s-selâm ve minke’s-selâm... (Ey Allah’ım! Sen selâmsın ve selâm sendendir.) diyecek ka-dar otururdu. (Hadîs-i şerîf-Müslim, Tirmizî) Eceli gelmeyen bir hastaya elem ve hastalık-ları için yüz yirmi bir defâ Selâm (es-Selâm) ism-i şerîfi okunursa, Allahü teâlânın izniyle o kimse şifâ bulur veya hastalığı hafifler. (el-İsti-gâsetü’l-Kübrâ) Biz bu dünyadan gider olduk, Kalanlara selâm olsun. Bizim için hayır duâ, Kılanlara selâm olsun. (Yûnus Emre)","osmanli":"سلام"},{"kelime":"SELÂMET","anlam":"Her türlü korku ve teh-likeden uzak olma, kurtulma.","kategori":"dil","misal":"Susan, selâmette olur. (Hadîs-i şerîf-Beyhekî) Nefsin arzularını terk eden temiz olur, âfetlerden selâmet bulur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سلامت"},{"kelime":"SELÂMLAŞMA","anlam":"İki Müslümanın karşılaştığı zaman birinin diğerine “selâmün aleyküm” veya “esselâmü aleyküm” [Selâmet üzerinize olsun] demesi, onun da “ve aley-küm selâm” [Selâmet, sizin de üzerinize ol-sun] diye cevap vermesi.","kategori":"dil","misal":"Îmân etmedikçe Cennet’e giremezsiniz. Bir-birinizle sevişmedikçe tam îmâna kavuşa-mazsınız. Size bir şey göstereyim mi? onu yaparsanız, sevişirsiniz. Aranızda selâmı çok yayınız. (Hadîs-i şerîf-Müslim) Müslü-manın Müslüman üzerinde beş hakkı var-dır. Selâmına cevap vermek, hastasını yok-lamak, cenâzesinde bulunmak, da’vetine gitmek ve aksırıp; “Elhamdülillah” deyince; “Yerhamükallah” diyerek cevap vermek. (Ha-dîs-i şerîf-Buhârî, Müslim) İki Müslüman karşılaşınca, birinin “Selâmün aleyküm” demesi sünnet, diğerinin cevap ola-rak “Ve aleyküm selâm” demesi farz-ı kifâye-dir. (Riyâdü’n-Nâsıhîn)","osmanli":"سلاملاشمه"},{"kelime":"SELÂMÜN ALEYKÜM","anlam":"İki Müs-lüman karşılaşınca veya ayrılırken birinin di-ğerine; “Ben Müslümanım. Benden sana za-rar gelmez, selâmettesin. Dünyada ve âhirette","kategori":"akaid","misal":"selâmette ol, sıhhat ve âfiyet üzerinize olsun!” mânâsına söylenen söz. Selâm, insanın iki yanındaki kirâmen-kâtibîn ve hafaza meleklerini de ihtiva edecek şekilde çokluk hâliyle söylenir.","osmanli":"عليكم سلام"},{"kelime":"SELÂSE","anlam":"Üç.","kategori":"dil","osmanli":"ثلاثه"},{"kelime":"SELB","anlam":"1.Kapıp alma. 2.İnkâr etme.","kategori":"dil","osmanli":"سلب"},{"kelime":"SELBÎ","anlam":"Menfi, negatif.","kategori":"dil","osmanli":"سلبى"},{"kelime":"SELEF","anlam":"1.Öncekiler; önce gelenler; geçmiş. 2.Daha ziyade Eshâb-ı kirâm, Tâbiîn ve Te-be-i tâbiîn için kullanılan tabir. 3.Selem satışına Hicaz ve başka bazı mıntıka-larda verilen isim.","kategori":"dil","misal":"İki kız kardeşi bir arada nikâhlamak size yasak kılındı. Allah seleften olanları affetti (yani geçen geçmiştir). (Nisâ sûresi: 23) Âlimlerin çoğuna göre, selefin ihtilâf ettiği bir meselede, sonra gelen âlimlerin icmâ’ yapma-ları câizdir. (Şerhu Menâr)","osmanli":"سلف"},{"kelime":"Selef-i Sâlihîn","anlam":"Hicrî ilk asrın Müslümanları, Eshâb-ı kirâm, Tâbiîn ve Te-be-i tâbiînin büyükleri.","kategori":"dil","misal":"Selef-i sâlihînin halefleri olan Ehl-i sünnet âlimleri zamanımıza kadar, hattâ bugün bile yazdıkları kitablarında Selef-i sâlihînin mezhebi olan Ehl-i sünnet i’tikâdını müdâfaa etmişlerdir. (Şeyhzâde)","osmanli":"صالحين سلف"},{"kelime":"SELEFİYYE","anlam":"Selef-i sâlihîn itikadına mensub oldukları iddiasıyla ortaya çıkarak Mâtüridî ve bilhassa Eş’ârî mezhebini reddeden, şefaat, tevessül, istigâse, kabir ziyareti, tasavvuf gibi hususlarda Ehl-i sünnetten ayrılan, müteşâbih âyetler hususunda ifrata düşerek Müces…","kategori":"akaid","misal":"XIII. asırda yaşamış İbn-i Teymiyye’nin görüşlerine dayanan fırka. Vehhâbîlik. İslâmiyet’te Selefiyye mezhebi diye bir şey yoktur. İslâmiyet’te yalnız selef-i sâlihîn mezhebi vardır. Selef-i sâlihîn, hadîs-i şerîf ile medh ve senâ buyurulmuş olan ilk iki asrın Müslümanlarıdır. (Seâdet-i Ebediyye)","osmanli":"سلفيه"},{"kelime":"SELEM","anlam":"Peşin para ile veresiye mal alma.","kategori":"muamelat","misal":"Bir kimse bir şeyde selem yaparsa, bunu muayyen kile, ölçü ve vadeyle yapsın. (Hadîs-i şerîfBuhârî, Müslim, Ebû Dâvûd, Tirmizî, Nesâî) Selem, söz kesilirken ve malı teslim edinceye kadar geçen zaman içinde, çarşıda benzeri hep bulunan ve sıfatı, iyilik ve aşağılık derecesi ve mikdarı belli edilebilen, yani hacm, tartı, metre ve sayı ile ölçülen ve tayin edilince teayyün eden (belli olan) malda sahîh olur. (İbni Âbid…","osmanli":"سلم"},{"kelime":"SELÎM","anlam":"Sağlam, kusursuz, doğru, sahîh.","kategori":"fikih","osmanli":"سليم"},{"kelime":"SELVÂ","anlam":"“Bıldırcın eti” mânâsına Mûsâ aleyhisselâm zamanında İsrâiloğullarına Tîh sahrasında Allahü teâlânın gönderdiği iki rızıktan biri.","kategori":"akaid","misal":"(Bkz. Menn ve Selvâ)","osmanli":"سلوى"},{"kelime":"SEM‘","anlam":"İşitme, işitici olma. Allahü teâlâ-nın subûtî sıfatlarından.","kategori":"akaid","osmanli":"سمع"},{"kelime":"ŞEM‘ûN (aleyhisselâm)","anlam":"Benî İsrâil peygamberlerinden.","kategori":"dil","misal":"Resûlullah aleyhisselâm buyurdu ki: “Geçmiş zamanda Şem’ûn (aleyhisselâm) adında bir peygamber vardı. Allahü teâlânın rızâsı için bin ay devamlı cihâd edip, silahını omuzundan çıkarmadı.” Eshâb-ı kirâm; “Keşke bizim ömrümüz de uzun olsaydı da, biz de din uğrunda Allah için cihâd etseydik.” dediler. Bunun üzerine Kadr sûresi nâzil olup; “Size verilen Kadir Gecesi, bin aydan daha hayırlıdır (sevâbı daha çoktur).” buyr…","osmanli":"شمعون"},{"kelime":"SEMÂ","anlam":"Gökyüzü.","kategori":"dil","osmanli":"سماء"},{"kelime":"ŞEMÂİL","anlam":"1.Huylar, tabiatler, ahlâk- lar. 2.Tasavvufta güzelliğin ve büyüklüğün bir araya gelmesi.","kategori":"tasavvuf","misal":"Şâmile’nin çokluk hâli.","osmanli":"شمائل"},{"kelime":"ŞEMÂİL-İ ŞERÎFE","anlam":"Resûlullah aleyhisselâmın mübârek tabiat, ahlâk, âdet ve yaşayışı.","kategori":"tasavvuf","misal":"Şemâil, huy, ahlâk, tabiat mânâsına şimâl’in çokluk hâlidir.","osmanli":"شريفه شمائل"},{"kelime":"SEMÂVÂT","anlam":"1.Gökler. 2.Müridin kemâle gelip yükseldiği merhaleler.","kategori":"dil","misal":"Semâ’nın çokluk hâli.","osmanli":"سماوات"},{"kelime":"SEMÂVÎ","anlam":"1.Semâya ait. 2.Allahü teâlâdan gelen; insanın elinde olmayarak hâsıl olan.","kategori":"akaid","misal":"İnsanı bir şey yapmaya zorlayan semâvî sebebe, yani insanın elinde olmayarak hâsıl olan sebebe zarûret denir. Şeriatin emir ve yasak etmesi ve tedavi edilemeyen şiddetli ağrı ve bir uzvun yâhud hayâtın telef olmak tehlikesi ve başka bir şey yapamamak mecburiyeti hep zarûrettir. (Dürerü’l-Hükkâm)","osmanli":"سماوى"},{"kelime":"Semâvî Din","anlam":"Allahü teâlâ tarafın-dan peygamber veya melek vasıtasıyla gönde-rilen din, ilahî vahye dayanan din.","kategori":"akaid","osmanli":"دين سماوى"},{"kelime":"Semâvî Kitab","anlam":"Allahü teâlâ tarafından insanları irşad için gönderilmiş peygamberlere indirilen mukaddes kitap.","kategori":"akaid","misal":"Semâvî kitapların bize bildirileni yüz dörttür. Bunlardan on suhuf Şist (Şit) aleyhisselâma otuz suhuf İdris aleyhisselâma, on suhuf İbrâhim aleyhisselâma indirildi. Mushaflar; Tevrat Mûsâ aleyhisselâma, Zebur kitabı Dâvûd aleyhisselâma, İncîl kitabı Îsâ aleyhisselâma ve Kur’ân-ı kerîm Muhammed aleyhisselâma nâzil olmuş, inmiştir. (Ma’lûmâtı-i Nâfia)","osmanli":"كتاب سماوى"},{"kelime":"SEMEN","anlam":"Alış-verişte mebî’ye (satın alı-nan şeye) karşılık verilen mal veya para, be-del, tutar, fiyat.","kategori":"dil","misal":"Altın ile gümüş semen olarak yaratılmıştır. Her ne hâlde olurlarsa olsunlar dâimâ semendirler. (İbni Âbidîn)","osmanli":"ثمن"},{"kelime":"Semen-i Misl","anlam":"Satılan malın piya-sadaki fiyatı.","kategori":"dil","osmanli":"مثل ثمن"},{"kelime":"Semen-i Müsemmâ","anlam":"Bâyi’ satıcı ile müşterinin karşılıklı rızâ ile mebî mal için ha-kikî kıymetine uygun olsun veya olmasın, ta-yin ettikleri, yani uyuştukları bedel.","kategori":"dil","osmanli":"مسما ثمن"},{"kelime":"SEMEND","anlam":"Çevik ve güzel at.","kategori":"dil","osmanli":"سمند"},{"kelime":"SEMER","anlam":"Yatsı namazından sonra sohbet etmek üzere oturma, müsâmere.","kategori":"ibadet","osmanli":"سمر"},{"kelime":"SEMÎ‘","anlam":"İşitilecek şeyleri ne kadar gizli olsa da işiten, hamd ve senâda bulunanların, hamdini işitip mükâfat veren, kullarının duâlarını işiten ve icâbet eden, münâfık ve yalancıların kalbden söyledikleri sözleri işiten mânâsında Allahü teâlânın Esmâ-i hüsnâsından (…","kategori":"akaid","misal":"O’nun (Rabbinin) sözlerini değiştirecek kimse yoktur. Semî‘ de, Alîm de O’dur. (En’âm sûresi: 115) Allahü teâlâ Semî‘dir. O, ne kadar gizli olursa olsun her şeyi işitir. O’nun işitmesi bizim işitmemiz gibi kulakla ve hava titreşimi ile değildir. İşitmesi, kulak zarına ses dalgalarının vurmasıyla olmaz. Bundan münezzeh (uzak)dir. (İ‘tikâdnâme) Duhâ namazından sonra beş yüz kere Semî‘ ism-i şerîfini okuyan kimsenin du…","osmanli":"سميع"},{"kelime":"SEMİ‘ALLAHÜ LİMEN HAMİDEH","anlam":"","kategori":"akaid","misal":"حمده (A) “Allahü teâlâ, hamd eden kimsenin hamdini işitti” mânâsına namazda rükû’dan kalkarken söylenen tesbih. Rükû’dan kalkarken “Semi’allahü limen hami-deh” demek, imâma ve yalnız kılana sünnettir. Cemâat bunu söylemez. (Halebî)","osmanli":"لمن الله سمع"},{"kelime":"ŞEMMÂS","anlam":"Kilisede vazife yapan, çan çalmak, kandil yakmak gibi hizmetlerde bu-lunan bir çeşit görevli din adamı.","kategori":"dil","osmanli":"شماس"},{"kelime":"ŞEMS","anlam":"Güneş.","kategori":"dil","osmanli":"شمس"},{"kelime":"ŞEMSÎ SENE","anlam":"365.242 vasatî güneş günü.","kategori":"dil","misal":"Güneş senesi. Yer kü-resinin güneş etrâfında bir devir yaptığı (bir kere döndüğü) sene. Sene-i şemsiyye.","osmanli":"سنه شمسى"},{"kelime":"SEMûD KAVMİ","anlam":"Âd kavminin başına gelen felâketten kurtulup Şam ile Hicâz arasına yerleşen, Sâlih aleyhisselâmın peygamber olarak gönderildiği, inanmadıkları için korkunç bir sesle helâk edilen Arab kavmi.","kategori":"akaid","misal":"Biz Semûd’a (nesepte) kardeşleri Sâlih’i peygamber olarak gönderdik. (Hûd sûresi: 61)","osmanli":"قومى ثمود"},{"kelime":"SENÂ","anlam":"Hamd, medh, övgü.","kategori":"dil","misal":"Hamd, senâ etmenin, övmenin en üstün şekli-dir. Sevinç hâlinde de sıkıntı hâlinde de hamd edilmektedir. Şükr ise nîmet zamanlarında olup, devamlı değildir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ثناء"},{"kelime":"ŞENÂ‘AT","anlam":"Kötülük, fenalık.","kategori":"tasavvuf","misal":"Her iki sebeb ile de, ibâdet etmemenin şenâ’a-tini, çirkinliğini düşünmemiz lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"شناعت"},{"kelime":"SENÂYÂ","anlam":"Ön dişler, iki üstte, iki altta olmak üzere dört tane ön diş.","kategori":"dil","osmanli":"ثنايا"},{"kelime":"SENE","anlam":"1.Ayın dünya etrafında on iki defa dolaşması, yıl. 2.Kuraklık.","kategori":"dil","osmanli":"سنه"},{"kelime":"SENED","anlam":"1.Delil, dayanak; bir hakkı tesbit eden yazılı vesîka. 2.Hadîs-i şerîfleri rivâyet edenlerin silsilesine verilen ad.","kategori":"hadis","misal":"Fâiz yiyene, yedirene, fâiz senedini yazana, bu senede şahid olana lânet olsun. (Hadîs-i şerîfNesâî) Siz bir hadîs yazdığınızda, onu senedi ile birlikte yazınız. Eğer o hadîs doğru ise, ecirde o ravi ile ortak olursunuz. Eğer yanlış ise onun vebâli isnâd edilen râvinin üzerine olur. (Hadîs-i şerîfHâkim)","osmanli":"سند"},{"kelime":"ŞENÎ‘","anlam":"Fena, kötü, ayıp. Bir müslümanı kabâhatli sanarak, dedikodu yapmak, söğmek, pek şenî’, çok çirkindir.","kategori":"tasavvuf","misal":"(Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"شنيع"},{"kelime":"SENİYY","anlam":"Ön (süt) dişlerini atmış olan hayvan. Beş yılını tamamlamış deve, iki yılını tamamlamış sığır, bir yaşını tamamlamış davar.","kategori":"dil","osmanli":"سنى"},{"kelime":"SENİYYE","anlam":"1.Yüksek, yüce.","kategori":"hadis","misal":"2.Resûlullah aleyhisselâma ait söz veya işler için kullanılan övgü ifadesi (sünnet-i seniyye, kis-ve-i seniyye vs).","osmanli":"سنيه"},{"kelime":"ŞER‘","anlam":"Şeriat, ahkâm-ı İslâmiyye.","kategori":"fikih","misal":"(Bkz. Şerî‘at)","osmanli":"شرع"},{"kelime":"ŞER‘AN","anlam":"Şeriatın hükmüne göre.","kategori":"fikih","osmanli":"شرعا"},{"kelime":"Şer‘î Dirhem","anlam":"Yetmiş tane orta boy arpa ağırlığında bir ölçü. Dirhem-i şer’î.","kategori":"dil","osmanli":"درهم شرعى"},{"kelime":"Şer‘î Mahkeme","anlam":"Hukukî ihtilafları hâlletmek üzere hükümdar tarafından tayin edilen kâdı’nın vazife yaptığı, İslâm hukukuna göre hüküm verilen mahkeme.","kategori":"osmanli","misal":"Mahkeme-i Şer’iyye.","osmanli":"محكمه شرعى"},{"kelime":"ŞER (Şerr)","anlam":"Dinin ve aklın zararlı gördüğü şey, kötülük, fena iş.","kategori":"tasavvuf","misal":"Zerre kadar hayır yapan onun mükâfâtını; zerre kadar şer yapan da onun karşılığını, cezâsını görecektir. (Zilzâl sûresi: 7, 8) Bir adam malının zekâtını öderse, malın şerri ondan gider. (Hadîs-i şerîfEvsat) İman, Allah’a, meleklerine, kitaplarına, peygamberlerine, Cennet, Cehennem’e, amellerin tartılacağına, öldükten sonra dirilişe, hayrı ile, şerri ile kadere inanmaktır. (Hadîs-i şerîfNesaî, Beyhekî) Hak şerleri ha…","osmanli":"شر"},{"kelime":"SERASKER","anlam":"1.Ordu kumandanı. 2.Osmanlılarda harbiye nâzırı.","kategori":"osmanli","osmanli":"سرعسكر"},{"kelime":"SERDÂR","anlam":"Kumandan; lider, önder.","kategori":"dil","osmanli":"سردار"},{"kelime":"ŞEREF","anlam":"Manevî büyüklük, yükseklik, ululuk; üstünlük; haysiyet.","kategori":"dil","misal":"Dünyanın şerefi zenginlik, âhiretin şerefi ise takvadır. Erkek ve dişiden yaratılan sizlerin şerefiniz müstağni olmanız; kereminiz takva, hasebiniz ahlâkınız, nesebiniz de amelleri-nizidir. (Hadîs-i şerîf-Deylemî) Kaybetti peygamberin âilesi olma şerefini, Kötülerle arkadaşlık ettiği için Hazret-i Lût’un eşi, Eshâb-ı Kehf’in köpeği onlarla olunca beraber, Kavuştu haşr olma şerefine mü’minlerle beraber. (Sa’dî Şîrâzî)","osmanli":"شرف"},{"kelime":"ŞEREFE","anlam":"Minarelerde gövdeden dışarıya fırdolayı çıkıntı ve müezzinin ezan okuduğu yer.","kategori":"ibadet","misal":"Kapısı hep kıbleye bakar. Aslı Arabca şürfe (çıkıntı) gelir.","osmanli":"شرفه"},{"kelime":"SEREYÂN","anlam":"Yayılma, dağılma, sirâ-yet etme.","kategori":"dil","misal":"Allahü teâlâ için söylenen kurb (yakın olmak), maiyyet (beraberlik), ittisâl (kavuşma), ihâta (çevirme) ve sereyân gibi sözlere inanmalı, na-sıl olduklarını düşünmemeli ve araştırmama-lıdır. Allahü teâlâ bilir demelidir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سريان"},{"kelime":"ŞERH","anlam":"1.Yarmak, açmak. 2.Bir metni izah etmek.","kategori":"dil","misal":"Bir şeyin geniş olarak, kapsamlı şekilde anlatılması.","osmanli":"شرح"},{"kelime":"ŞERÎ‘AT (Şeriat)","anlam":"1.Peygamberlere gelen ilâhî hükümler, din. 2.İslâmiyet.","kategori":"akaid","misal":"Sonra da seni din konusunda bir şerî‘at sahibi kıldık. Sen ona uy; bilmeyenlerin isteklerine uyma! (Câsiye sûresi: 18) (Ey insanlar!) Her birinize bir şerî‘at ve bir yol verdik. Allah dileseydi, sizi tek bir ümmet yapardı. (Mâide sûresi: 48) Allah kendisine hayır dilediği kimseyi dinde fakih yapar. Ben ancak size şerî‘ati beyan etmekteyim. Anlama kâbiliyetini veren Allah’dır. Ve bu ümmet, hak din üzerine bulunmakta…","osmanli":"شريعت"},{"kelime":"ŞERÎF","anlam":"1.Şerefli; temiz; soylu. 2.Ta-rihte Hazret-i Hasen’in neslinden gelenler için kullanılan unvan.","kategori":"dil","osmanli":"شريف"},{"kelime":"Şerîf-i Abbâsî","anlam":"Hazret-i Peygamber aleyhisselâmın amcası Abbâs’ın neslinden gelenlere tarihte verilen unvan.","kategori":"dil","osmanli":"عباسى شريف"},{"kelime":"Şerîf-i Câferî","anlam":"Hazret-i Ali ve Hazret-i Fâtıma’nın kızı Zeyneb ile Abdullah bin Câfer Tayyâr’ın neslinden gelenlere tarihte verilen unvan.","kategori":"dil","osmanli":"جعفرى شريف"},{"kelime":"ŞERÎK","anlam":"Eş; ortak.","kategori":"dil","misal":"Hamd Allah’a mahsusdur. O, veled edinmedi ve mülkünde O’na şerik olmadı. O’nun yar-dımcıya da ihtiyacı yoktur. O’na taz’imle tek-bir et! (Hadîs-i şerîf-İbnü’s-Sünnî) Resûlullah aleyhisselâm taksim edilmiş olan her müş-terek ev ve bahçede şüf ’a olduğuna hükmet-miştir. Şerîke haber vermeden satamaz. Sa-tarsa, şerîk satılanın tamamına herkesten daha layıktır. (Hadîs-i şerîf-Müslim) Mudârebe şirketi, şeriklerden bir kısmı sermâye vermek, bir kısmı da iş yapmak üzere kurulur. Kâr, önceden sözleşilen oranda paylaşılır. Ser-mâye, iş yapanlara emânettir; telef olursa öde-mezler. (İbni Âbidîn) A’mâl (Sanâyı’) şirketinde, sipârişi, her şerîk ya-par. Her şerîk iş kabul eder ve satış yapar. Her-birinin kazancına ve zarârına, her şerîk, söz-leşmelerindeki oranda ortaktır. (İbni Âbidîn)","osmanli":"شريك"},{"kelime":"ŞERİKE","anlam":"Şirket.","kategori":"muamelat","osmanli":"شركه"},{"kelime":"SERÎR","anlam":"1.Yatılan, oturulan yer, kanape, masa, taht. 2.Teneşir.","kategori":"dil","misal":"Şehir dışında özr ile farz ve vâcib namazı hay-van üzerindeki mâhmil içinde kılarken, hayvan durdurulup mâhmilin altına direk konursa serîr gibi olup yerde kılmak demektir. Kıbleye karşı ayakta kılmak lazımdır. (İbni Âbidîn)","osmanli":"سرير"},{"kelime":"ŞERÎR","anlam":"Şerli kimse, pek kötü adam.","kategori":"dil","osmanli":"شرير"},{"kelime":"SERİYYE","anlam":"Düşman üzerine gönderilen küçük askerî birlik, müfreze; Hazret-i Peygamber’in bizzat iştirak etmediği askerî sefer.","kategori":"akaid","osmanli":"سريه"},{"kelime":"SERKEŞ","anlam":"Dikbaşlı, inâdcı; itaatsiz.","kategori":"dil","osmanli":"سركش"},{"kelime":"SERMÂYE","anlam":"Ana para.","kategori":"dil","misal":"Ortaklardan bir kısmı sermâye vermek, bir kısmı da iş yapmak üzere kurulan şirketlere müdârebe şirket denir. Kâr, önceden sözleşilen oranda paylaşılır. Sermâye, iş yapanlarda emâ-nettir. (Dürerü’l-Hükkâm)","osmanli":"سرمايه"},{"kelime":"SERVER-İ ÂLEM","anlam":"“Âlemin efen-disi” mânâsına. Muhammed aleyhisselâm için kullanılan bir sıfat.","kategori":"dil","misal":"Server-i âlemin sallallahü aleyhi ve sellem isim-leri, hâlleri, Tevrat’ta ve İncîl’de yazılı idi. Ya-hudi ve Hristiyanlar, teşrif etmesini bekliyordu. Fakat kendi cinslerinden gelmeyip, Arabdan gel-diği için bazıları kıskandı, inkâr etti. Hâlbuki birçok âlimleri ve akıllıları, insaf edip Müslü-man oldu. (Seâdet-i Ebediyye)","osmanli":"عالم سرور"},{"kelime":"SERZENİŞ","anlam":"Başa kakma, takaza.","kategori":"dil","osmanli":"سرزنش"},{"kelime":"SETR","anlam":"Örtme, kapama, gizleme.","kategori":"dil","osmanli":"ستر"},{"kelime":"SETR-İ AVRET","anlam":"Edep yerini örtme. Namazın şartlarından olup, vücudda örtülmesi emredilen yerlerin örtülmesi.","kategori":"fikih","misal":"Setr-i avret üç şeyle tamam olur: Erkekler göbeği altından dizi altına varıncaya kadar olan yerlerini örtmekle; kadınlar yüz, el ve bir rivâyete göre ayaktan başka bütün bedenlerini örtmek ve göstermemekle; câriyeler sırtını ve göbekten diz altına kadar örtmekle. (Miftahü’l-Cenne)","osmanli":"عورت ستر"},{"kelime":"SETTÂR","anlam":"“Kulların günahını örten” mânâsında Allahü teâlânın sıfatlarından (esSettâr).","kategori":"akaid","misal":"Ey Müslüman! Sen de Resûlullah’ın sallallahü aleyhi ve sellem güzel huyları ile ahlâklanmalısın! Hattâ Allahü teâlânın ahlâkı ile ahlâklanmak, her Müslümana lâzımdır. Çünki Resûl aleyhisselâm; “Allahü teâlânın ahlâkı ile ahlâklanınız!” buyurdu. Meselâ Allahü teâlânın sıfatlarından birisi Settâr’dır. Müslümanın da din kardeşinin aybını, kusurunu örtmesi lâzımdır. (Mevâhib-i Ledünniyye)","osmanli":"ستار"},{"kelime":"SEV’E","anlam":"Edeb yeri.","kategori":"tasavvuf","osmanli":"سوئه"},{"kelime":"SEV’ETEYN","anlam":"“İki çirkin yer” mânâsına kadın ve erkeğin galiz (kaba) avret mahalli olan ön ve arka uzuvları; iki abdest bozma uzvu.","kategori":"ibadet","misal":"Sev’eteyn dört mezhebte de kaba avrettir. Namazda ve namaz dışında başkalarına göstermek haramdır. (İbni Âbidîn)","osmanli":"سوئتين"},{"kelime":"SEVÂB","anlam":"Allahü teâlânın iyilik yapana va’d ettiği mükâfât, karşılık.","kategori":"akaid","misal":"Allahü teâlâ, dünyada iyilik ve ibâdet yapanlara sevab vereceğini vâd etmiştir. İyilik ve ibâdet yapana âhirette sevab verilmesi, vâcib ve lâzım değildir. Allahü teâlâ lutf ederek, merhamet ederek, bunlara âhirette sevab vereceğini vâd etmiştir. Allahü teâlâ vâdinden dönmez. Muhakkak yapar. (Berîka) Sâlih amellerin sevâbını bütün mü’minlerin ruhuna hediye etmek iyi ve makbûldür. Herbirine ayrı sevab ulaşır. Hakkında…","osmanli":"ثواب"},{"kelime":"ŞEVK","anlam":"Hasret, özleme. Tasavvufta, sevgili ile buluşma arzusu; Allah’a kavuşma hasreti.","kategori":"akaid","osmanli":"شوق"},{"kelime":"SEVM-İ ŞİRA‘","anlam":"Alış-veriş pazar-lığı. Bâyi’in (satıcının) ve müşterinin, mebî’e (satılan mala) fiyat koymaları, bir fiyatta an-laşmaları.","kategori":"dil","misal":"Sevm-i şira’ yoluyla uyuşup malı götür, beğenir-sen al deyip müşteri de beğenirsem alırım diye-rek alıp götürürken mebi’ (mal) telef ve zâyi olsa müşteri kıymetini veya mislini öder. (Dâmâd)","osmanli":"شراع سوم"},{"kelime":"ŞEVVÂL","anlam":"Arabî ayların onuncusu. Kaldırmak demek olan şevl kökündendir ve dişi develerin çiftleşmek için kuyruğunu kal-dırması bu ayda cereyan ettiği için böyle isim-lendirilmiştir. Müslümanların iki büyük bay-ramından biri olan (Ramazan Bayramı) yani Iydü’l-Fıtr ile başlar.","kategori":"ibadet","misal":"Ramazân-ı şerîf ayında oruç tutup, ardın-dan Şevvâl ayından da altı gün daha oruç tutan, bir yıl oruç tutmuş gibi olur. (Hadîs-i şerîf-Müslim)","osmanli":"شوال"},{"kelime":"ŞEY","anlam":"Nesne, maddî veya manevî varlık. Çokluk hâli eşya gelir.","kategori":"dil","osmanli":"شئ"},{"kelime":"SEYF","anlam":"Kılıç.","kategori":"dil","osmanli":"سيف"},{"kelime":"SEYFuLLAH","anlam":"“Allah’ın kılıcı” mânâsında Hâlid bin Velid’e Resûlullah aleyhisselâm tarafından Mûte Harbi’nden sonra verilen lakab.","kategori":"akaid","osmanli":"الله سيف"},{"kelime":"ŞEYH","anlam":"1.İhtiyâr. 2.Bir ilim dalında ihtisas etmiş olan. 3.İnsanlara manevî olarak rehberlik edebile-cek kemâle sahip velî.","kategori":"dil","misal":"Şeyhlerinize hürmet ediniz. Onlara hür-met, Allah’a hürmet sayılır. Kim ki şeyh-lere hürmet etmezse, benden değildir. (Ha-dîs-i şerîf-Deylemî) Mürşid-i kâmil. Çokluk hâli meşâyıh veya şüyûh gelir. (Bkz. Meşâyıh)","osmanli":"شيخ"},{"kelime":"Şeyh-i Ekber","anlam":"“En büyük şeyh” mânâsına evliyânın büyüklerinden hicrî VII.","kategori":"tasavvuf","misal":"asırda yaşamış Muhyiddîn-i Arabî’nin lakabı.","osmanli":"اكبر شيخ"},{"kelime":"Şeyh-i Necdî","anlam":"“Necdli ihtiyar” mânâsına iblisin, şeytânın lakabı.","kategori":"dil","misal":"Şeytân, Resûlullah aleyhisselâma, hep Şeyh-i Necdî ihtiyâr şeklinde görünürdü. Kâfirler Mekkede Dârünnedve denilen yerde toplanıp, Resûlullah’ı öldürmeye karar verdikleri zaman, şeytân Şeyh-i Necdî şeklinde görünüp, nasıl öl-düreceklerini öğretmişti. Onlar da, bu Necdli ihtiyarın dediğini yapalım demişlerdi. O gün-den beri, şeytâna Şeyh-i Necdî denilmektedir. (Müsâmerât)","osmanli":"نجدى شيخ"},{"kelime":"ŞEYHAYN","anlam":"“İki şeyh” mânâsına siyerde Hazret-i Ebû Bekr ile Hazret-i Ömer; hadîs ilminde İmâm Buhârî ile Müslim; Hanefî fıkhında Ebû Hanîfe ile Ebû Yûsuf ’un lakabı.","kategori":"hadis","osmanli":"شيخين"},{"kelime":"ŞEYHÜLİSLÂM","anlam":"1.Dinî ilimlerde söz sahibi büyük âlim. 2.Osmanlılarda ilmiye sınıfının da başı sayılan pâyitaht müftüsü.","kategori":"ibadet","osmanli":"الاسلام شيخ"},{"kelime":"SEYR","anlam":"1.Yürümek; bakmak. 2.Tasavvuf yolunda ilerleme, manevî yürüyüş.","kategori":"tasavvuf","misal":"Başka tarîkatlerde seyre nefsin tezkiyesinden yani temizlenmesinden başlanır. Cesedi temizlerler. Bundan sonra âlem-i emre sıra gelir. Bizim yolumuzda ise, seyr kalbden başlar. Kalb de âlem-i emrdendir. Bunun içindir ki, başkalarının yolunun sonu bizim büyüklerimizin yolunun başında yerleştirilmiştir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سير"},{"kelime":"Seyr-i Âfâkî","anlam":"Tasavvuf yolunda bulunan kimsenin; ilminin, bilgisinin ve kendi ihtiyârı (dilemesi, istemesi) olmaksızın dış âlemde ilerlemesi.","kategori":"tasavvuf","misal":"Seyr-i âfâkîde kötülüklerden temizlenmek ve seyr-i enfüsîde iyi ahlâk ile ahlâklanmak vardır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"آفاقى سير"},{"kelime":"Seyr-i Enfüsî","anlam":"Tasavvuf yolunda bulunan kimsenin kendinde ilerlemesi, kötü huylardan temizlenen nefsin, iyi huylarla bezenmesi, süslenmesi.","kategori":"tasavvuf","misal":"Ebû Saîd-i Harrâz dedi ki: Seyr-i âfâkî (kendinin dışında ilerleme) insanı matlûbdan (aranılandan) uzaklaştırır; seyr-i enfüsî ise insanı, matlûba kavuşturur. (Mektûbât-ı İmâm-ı Rabbânî) İnsan her şeyi, kendini sevdiği için sever. Çocuğunu, malını sevmek onlardan istifâde edeceği içindir. Seyr-i enfüsîde, insanı, Allahü teâlânın sevgisi kaplayarak, insan, kendini sevmekten kurtulduğu için evlâd ve mal sevgisi de bun…","osmanli":"انفسى سير"},{"kelime":"Seyr-i Fi’l-Eşyâ (Seyr Der Eşyâ)","anlam":"","kategori":"tasavvuf","misal":"(A) Tasavvufta nihâyete kavuşan bir velînin geri döndükten sonra daha önce unutmuş olduğu eşyanın bütün bilgilerine yeniden sahip olması. Seyr-i fi’l-eşya, da’vet makamını elde etmek içindir. Da’vet makamı, Peygamberlere mahsustur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"الاشياء فى سير"},{"kelime":"Seyr-i Fillah","anlam":"Allahü teâlânın isimlerinde ve sıfatlarında ilerleme.","kategori":"akaid","misal":"yani O’nun sevdiklerini sevmek ve O’nun sevdikleri kendine sevgili olmak. Allahü teâlâya kavuşmakta zulmet perdelerinin kalkması için mahlûkların hepsini aşmak, yani seyr-i âfâkîyi ve seyr-i enfüsîyi tamamlamak lâzımdır. Nûrdan perdelerin aradan kalkması için de seyr-i fillah gerekir. (Mesmuat-ı Hâce Ubeydullah-ı Ahrâr)","osmanli":"الله فى سير"},{"kelime":"Seyr-i İlallah","anlam":"Allahü teâlâya doğru olan yolda ilerlemek, mânevî ilimde durmadan yükselmek.","kategori":"akaid","misal":"Seyr-i âfâkî (kötü hâllerden kurtulma) ve seyr-i enfüsî (iyi hâllerle süslenme) yi içine alan tasavvuf yolculuğu.","osmanli":"الله الى سير"},{"kelime":"Seyr-i Mahbûbî","anlam":"Tasavvuf yolculuğunda muhabbetin son haddini bulması.","kategori":"tasavvuf","misal":"Seyr-i âfâkîde ele geçen şeylere, uzun bir sülûke ve sıkı riyâzetlere ve çetin mücâhedelere lüzum kalmadan kavuşur. Çünki, sevmek, sevgiliye, itâat etmeği ister. Sevgi son haddini bulunca, itâat da tamam olur. Sevgiliye, insan gücünün yetişebildiği kadar, tam bir itâat hâsıl olunca makamât-i aşere [Tevbe, zühd, vera’, sabr, fakr, şükr, havf, recâ, tevekkül ve rıdâ] ele geçer. Bu seyr-i mahbûbî ile, seyr-i âfâkî gibi…","osmanli":"محبوبى سير"},{"kelime":"Seyr-i Murâdî","anlam":"Murâdların, seçilmişlerin Allahü teâlânın lutf ve ihsânı ile çekilerek kavuştukları yol.","kategori":"akaid","misal":"Tasavvuf yoluna girip ilerlemek, yol gösteren rehberi sevmeye bağlıdır. Seyr-i murâdî ile ve kuvvetle çekilerek vilâyetin yüksek derecelerine kavuşturulan bu rehberin bakışları, kalb hastalıklarına şifâdır. Onun teveccühü yani sevgisine kavuşmak, mânevî hastalıkları giderir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"مرادى سير"},{"kelime":"Seyr-i Mürîdî","anlam":"Tasavvufta, yüksek makamları irade edenlerin Allahü teâlânın lütuf ve ihsânı ile çekilerek kavuştukları yol.","kategori":"tasavvuf","osmanli":"مريدى سير"},{"kelime":"Seyr ü Sülûk","anlam":"Tasavvuf yolculuğu, tasavvuf yolunda ilerlemek.","kategori":"tasavvuf","misal":"Seyr ve sülûktan maksat, nefsi kötü huylar-dan ve çirkin sıfatlardan temizlemektir. Bu çir-kin sıfatların başı nefse düşkün olmak ve onun arzularına, isteklerine tutulmaktır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سلوك سير"},{"kelime":"SEYRÂN","anlam":"1.Gezinme. 2.Bakıp seyretme, temâşâ.","kategori":"tasavvuf","osmanli":"سيران"},{"kelime":"ŞEYTÂN","anlam":"“Kovulmuş, uzaklaştırılmış” mânâsına kibri sebebiyle Allahü teâlânın “Âdem’e secde ediniz” emrine isyân edip, karşı geldiği için, O’nun rahmetinden uzaklaştırılan İblis’in lakabı.","kategori":"akaid","misal":"Şeytân insana çok şeyi söz verir ve birçok şeyi hatırlatır. Şeytânın söz verdiği şeylerin hepsi yalandır. (Nisâ sûresi: 121) Şeytân sizi fakir olacaksınız diye korkutur. Size cimriliği emreder. Allah ise kendisinden mağfiret ve fadl vâ’d ediyor. (Bakara sûresi: 268) Gadab şeytândandır. Şeytân ise, ateştendir. Su ateşi söndürür. Sizden birisi kızdığı zaman abdest alsın. (Hadîs-i şerîfMüsnedü İmâm-ı Ahmed) Birçok iste…","osmanli":"شيطان"},{"kelime":"SEYYÂH","anlam":"(A. Seyâhat’ten) Yolcu; gezgin.","kategori":"dil","osmanli":"سياح"},{"kelime":"SEYYÂR","anlam":"1.Gezici; gezen, do-laşan, 2.Hareket ettirilip, istenilen tarafa ta-şınabilen.","kategori":"dil","osmanli":"سيار"},{"kelime":"SEYYÂRE","anlam":"1.Güneş’in etrafında dola-şan gezegen. 2.Kervan, kafile.","kategori":"dil","osmanli":"سياره"},{"kelime":"SEYYİÂT","anlam":"1.Fenalıklar, kötülükler. 2.Suçlar, günahlar.","kategori":"tasavvuf","misal":"Seyyie’nin çokluk hâli.","osmanli":"سيآت"},{"kelime":"SEYYİB","anlam":"1.Efendi. 2.Hazret-i Hüseyin’in neslinden gelenlere Memlûk Devleti’nden itibaren verilmesi âdet olmuş unvan.","kategori":"osmanli","misal":"Dul erkek. SEYYİBE: ثيبه (A) Dul kadın. SEYYİD: سيد (A) Bir kavmin seyyidi, ona hizmet edendir. (Hadîs-i şerîf-Hâkim) Allah katında günle-rin seyyidi Cum‘a’dır (Hadîs-i şerîf-Buhârî)","osmanli":"ثيب"},{"kelime":"SEYYİE","anlam":"Kötülük, günah.","kategori":"dil","misal":"Her güzel, her iyi şey, sana Allahü teâlâdan geliyor. Her seyyieye de nefsin sebeb olu-yor. (Nisâ sûresi: 79) Hiçbir kimse yoktur ki, tertemiz abdestini alsın, sonra (şu) mescid-lerden birine gitsin de Allah, ona attığı her adım karşılığında bir sevab yazmasın; her adım karşılığında onun bir seyyiesini affet-mesin! (Hadîs-i şerîf-Müslim)","osmanli":"سيئه"},{"kelime":"SEZÂ","anlam":"Münâsip, yaraşır, uygun. SEZÂB: آب سز (F) Su teresi, sedef otu. SEZÂVÂR: سزاوار (F) Münâsip, yaraşır, yakışır. SEZERYAN: سزريان (L) Doğumdaki zorluk se-","kategori":"dil","misal":"bebi ile anne karnının yarılarak doğumun gerçekleşmesi.","osmanli":"سزاء"},{"kelime":"Şİ‘Î (Şiî)","anlam":"1.Taraftar. 2.Hazret-i Ali’nin bütün sahâbîlerden üstün olduğu inancında bulunan fırkalardan birine mensub.","kategori":"dil","misal":"(Bkz. Şî’a)","osmanli":"شيعى"},{"kelime":"SIBGATuLLAH","anlam":"“Allah’ın rengi” mânâsına, Allahü teâlanın dilediği renk, vasıf, tarzda yaratması; Allahü teâlânın dini, İslâm ahlâkı.","kategori":"akaid","misal":"Sıbgatullah ile boyanın. Sıbgatullahdan daha iyi boya olur mu? (Bakara sûresi: 138)","osmanli":"الله صبغة"},{"kelime":"SİCİL","anlam":"Hâdise ve muamelelerin kayde-dildiği resmî kayıt.","kategori":"hadis","osmanli":"سجل"},{"kelime":"SIDDÎK","anlam":"1.Sıdk sahibi, pek doğru, hiçbir zaman yalan söylemeyen, işinde ve sö-zünde doğru olan. 2.Resûlullah aleyhisselâmın Mi’racını tered-dütsüz tasdik ettiği için Hazret-i Ebû Bekr’in lakabı.","kategori":"dil","misal":"Doğru sözlü olmak iyiliğe götürür. İyilik Cen-net’e götürür. Kişi doğru söyleye söyleye Allahü teâlânın katında sıddîk olarak yazılır. (Hadîs-i şerîf-Müslim, Ebû Dâvûd) Ey Ebû Bekir! Allahü teâlâ sana “Sıddık” ismi verdi. (Hadîs-i şerîf-Deylemî) Resûlullah’ın mi’râcını işitir işitmez, inanarak kâfirleri şaşkına çevirdiği için Resûlullah sallal-lahü aleyhi ve sellem o gün Ebû Bekr’e; “Sıd-dîk” dedi. (Ahmed Cevdet Paşa)","osmanli":"صديق"},{"kelime":"SIDK","anlam":"1.Doğruluk. 2.Pey-gamberlerin sıfatlarından.","kategori":"akaid","misal":"Yalan’ın zıddı. Rabbinin sözü, sıdk ve adalet bakımından tamamlanmıştır. O’nun sözlerini değişti-recek kimse yoktur. O işitendir, bilendir. (En’âm sûresi: 115) Sıdk, Cennet amelidir. (Hadîs-i şerîf-Müsned) Bütün peygamberler sıdk sahibidirler. Her söz-leri doğrudur. Aslâ yalan söylemezler. (Mifta-hü’l-Cenne)","osmanli":"صدق"},{"kelime":"SİDR","anlam":"Nebk (Arabistan kirazı) ağacı; bu ağacın yaprağının kurutulup dövülmesiyle elde edilen temizleme maddesi, sabun.","kategori":"muamelat","osmanli":"سدر"},{"kelime":"ŞİFÂ","anlam":"Hastalıktan kurtulma, iyileşme, iyi olma.","kategori":"dil","misal":"Balda insanlar için şifâ vardır. (Nahl sûresi: 69) Şifâyı veren Allahü teâlâdır. (Hadîs-i şerîf-Ebû Dâvûd) Resûlullah aleyhisselâm üç türlü ilâç kullanırdı: Kur’ân-ı kerîm veya duâ okurdu. Fen ile bulu-nan ilâçları kullanırdı. Her ikisini karışık kulla-nırdı. “Kur’ân-ı kerîmden şifâ beklemeyene şifâ nasip olmaz” buyururdu. (Mevâhib-i Le-dünniyye)","osmanli":"شفاء"},{"kelime":"Şifâ Âyetleri","anlam":"Hastalara şifâ için okunması sünnette bildirilen altı âyet-i kerîme.","kategori":"dil","misal":"Şifâ âyetleri, Tevbe sûresi on dördüncü âyetinin sonu, Yûnus sûresi elli yedinci âyetinin ortası, Nahl sûresi altmış dokuzuncu âyetinin orta kısmı, İsrâ sûresi seksen ikinci âyetinin baş tarafı, Şu’arâ sûresinin sekseninci âyeti ve Fussilet sûresi kırk dördüncü âyetinin ortasıdır. Bunlar âyetleri bir tabağa yazılıp, su koyarak eritilir. Şifâ âyetlerini abdestli olarak bir kâğıda yazıp, bu kâğıdı, bir kaptaki suya ko…","osmanli":"آيتلى شفاء"},{"kelime":"Sıfât-ı Hakîkiyye","anlam":"Allahü teâlânın sübûtî sıfatları.","kategori":"akaid","misal":"(Hayat, İlm, Sem’, Basar, Kudret, İrâde, Kelâm ve Tekvîn.)","osmanli":"حقيقيه صفات"},{"kelime":"Sıfât-ı İlâhiyye","anlam":"Allahü teâlânın bütün sıfatları.","kategori":"akaid","misal":"Allahü teâlânın sıfatları sıfat-ı zâtiyye (zâtında bulunan sıfatlar) ve sıfat-ı sübûtiyye olmak üzere ikiye ayrılır. Bir de Allahü teâlâda bulunması câiz olmayan, muhal buluna sıfatlar vardır. Bunlara sıfat-ı selbiyye denir. (Seâdet-i Ebediyye)","osmanli":"الهيه صفات"},{"kelime":"Sıfât-ı Kâmile","anlam":"Allahü teâlânın sübûtî sıfatları. (Hayat, İlm, Sem’, Basar, Kud-ret, İrâde, Kelâm ve Tekvîn.)","kategori":"akaid","osmanli":"كامله صفات"},{"kelime":"Sıfât-ı Selbiyye","anlam":"Allahü teâlâda bulunması câiz olmayan sıfatlar.","kategori":"akaid","misal":"(Bkz. Selbî sıfatlar)","osmanli":"سلبيه صفات"},{"kelime":"Sıfât-ı Sübûtiyye","anlam":"Allahü teâlânın zâtında (kendisinde) bulunmakla birlikte başka varlıklarda da sınırlı olarak bulunan sıfatları.","kategori":"akaid","misal":"Allahü teâlânın sıfat-ı sübûtiyyesi sekiz tanedir: Hayât [diri olmak], ilim [bilmek], sem’ [işitmek], basar [görmek], kudret [gücü yetmek], irâde [istemek], kelâm [söylemek] ve tekvîn [yaratmak]. Allahü teâlânın sıfat-ı sübûtiyyesi de zâtı gibi ezelî ve ebedîdir. Mahlûkların sıfatları gibi değildirler. Akıl ile zan ile dünyadakilere benzetilerek anlaşılamazlar. Allahü teâlâ bu sıfatlarından insanlara sınırlı olarak…","osmanli":"ثبوتيه صفات"},{"kelime":"Sıfât-ı Zâtiyye","anlam":"Allahü teâlânın zâtında (kendisinde) bulunup diğer varlıklarda bulunmayan, yalnız Allahü teâlâya mahsûs sıfatları.","kategori":"akaid","misal":"Allahü teâlânın sıfat-ı zâtiyyesi, altı tânedir. Bunlar; Vücûd (var olmak), Kıdem (varlığının öncesi, başlangıcı olmamak), Bekâ (varlığının sonu olmamak), Vahdâniyyet (zâtında, sıfatlarında ve işlerinde tek olmak; ortağı ve benzeri olmamak), Muhâlefetün lilhavâdis (hiçbir mahlûka, yaratılmışa hiçbir bakımdan benzememek), Kıyâm binefsihî (varlığının kendinden olması, var olmak için hiçbir şeye muhtaç olmamak).","osmanli":"ذاتيه صفات"},{"kelime":"SIFAT (Sıfât)","anlam":"Bir şeyin hâli, vasfı, keyfiyeti; nişan, alâmet.","kategori":"akaid","misal":"Varlıklar birbirlerinden sıfatlarıyla ayırt edilmektedir. (Şerh-i Mevâkıf)","osmanli":"صفات"},{"kelime":"ŞİFÂYÂB","anlam":"Şifâ bulan, iyileşen.","kategori":"dil","osmanli":"شفاياب"},{"kelime":"SİFR","anlam":"1.Yazılı şey; kitap, cüz; mektup. 2.Tevrat’ın beş kitabından her biri.","kategori":"dil","osmanli":"سفر"},{"kelime":"ŞİGÂR","anlam":"İki kadının mehr konuşulmadan ve birinin mehri diğerininkine karşılık gelmek üzere evlendirildiği cahiliye devrine ait bir nikâh türü.","kategori":"dil","misal":"Nikâhu’ş-Şıgâr.","osmanli":"شغار"},{"kelime":"SİGORTA","anlam":"Muayyen bir prim karşı-lığında, muhtemel bir tehlikenin vereceği za-rarı tazmin etmek üzere yapılan akid. Te’min. Sigorta fâsid bir akiddir. Dârülharbde, harbî ile sözleşip, sigorta parası almak câizdir. (İbni Âbidîn)","kategori":"osmanli","osmanli":"سيغورته"},{"kelime":"SIHR","anlam":"Evlilik yolu ile teşekkül eden akrabalık.","kategori":"dil","osmanli":"صهر"},{"kelime":"SİHR (Sihir)","anlam":"Tabiat kanunları dışında gizli sebebler kullanarak, göz boyayarak, hârikalâde şeyleri yapmaya yarayan güç.","kategori":"fikih","misal":"(Mûsâ aleyhisselâma inanan sihirbâzlar Fir’avn’a;) “Bize zorla yaptırdığın sihrin vebâlini mağfiret buyurması için Rabbimize îmân ettik” dediler. (Şu’arâ sûresi: 50) Sihrden kaçının! O, helâk edicidir. (Hadîs-i şerîfBuhârî) Siz, kan, saç ve tırnaklarınızı toprağa gömünüz de, büyücüler onlarla sihr yapmasınlar. (Hadîs-i şerîfDeylemî) Bazı sözler sihr gibidir. (Hadîs-i şerîfMüslim, Ebû Dâvûd,Müsnedü İmâm-ı Ahmed) Sihr…","osmanli":"سحر"},{"kelime":"ŞİİR (Şi’r)","anlam":"Vezinli ve kâfiyeli söz.","kategori":"dil","misal":"Biz ona şiir öğretmedik. Bu onun için gerekmez de! (Yasin sûresi: 69) Sözde sihir, şiirde hikmet vardır. (Hadîs-i şerîfİbni Asâkir) Resûlullah aleyhisselâm şi’r söylemezdi. (Mevâhib-i Ledünniyye)","osmanli":"شعر"},{"kelime":"SİKÂ","anlam":"(A. Vüsûk’dan) Güvenilir. Adâlet ve zabt sıfatlarını taşıyan güvenilir râvi veya vesika.","kategori":"dil","osmanli":"ثقه"},{"kelime":"ŞİKÂK","anlam":"Anlaşmazlık, niza, düşmanlık.","kategori":"dil","osmanli":"شقاق"},{"kelime":"SİKÂYE (Sikâyet)","anlam":"Su verme, sulama. Kâbe-i Muazzama’nın hizmetlerinden hacılara su içirme vazifesi:","kategori":"ibadet","osmanli":"ثقايه"},{"kelime":"SİKKE","anlam":"Para üzerine vurulan damga; dar-bedilmiş madenî para. Çokluk şekli “sikek” gelir.","kategori":"dil","osmanli":"سكه"},{"kelime":"SILA","anlam":"1.Birleşmek, kavuşmak. 2.Hediye, bahşiş. 3.İçinde bulunduğu cümleyi sonra-kine bağlamaya yarayan fiil sigası. 4.Fıkıh ve tasavvufu birleştiren mânâsına İmâm-ı Rab-bânî hazretlerinin lakabı.","kategori":"tasavvuf","misal":"Ümmetimden sıla isminde bir zât gelecek, onun şefâati ile insanlar bölük bölük Cennet’e gireceklerdir. (Hadîs-i şerîf-Cemü’l-Cevâmi’)","osmanli":"صله"},{"kelime":"Sıla-i Rahm","anlam":"Akrabâyı kavuş-turma. Akrabayı ziyaret etme, gözetme ve on-lara yardım etme.","kategori":"dil","misal":"Sıla-ı rahm ömrü arttırır; belâyı savar. (Ha-dîs-i şerîf-Beyhekî) Müslüman olan ve sıla-i rahmde bulunan bir kimseye, yetmiş nâfile hac sevâbı verilir. (Ey Oğul İlmihâli)","osmanli":"رحم صلهء"},{"kelime":"SİLAH","anlam":"Öldürme ve müdafaa için kul-lanılan her çeşit âlet.","kategori":"dil","osmanli":"سلاح"},{"kelime":"SİLSİLE","anlam":"Zincir. Usûl-i hadîs ilminde, hadîs-i şerîfi rivâyet eden râviler zinciri.","kategori":"hadis","misal":"Silsiletü’r-Rüvvât.","osmanli":"سلسله"},{"kelime":"SİLSİLE-İ ALİYYE","anlam":"Yüce zincir. Resûlullah aleyhisselâmdan ilim ve feyz alarak gelen büyük âlimler silsilesi.","kategori":"dil","misal":"Silsiletü’z-Zeheb.","osmanli":"عليه سلسله"},{"kelime":"SİMÂ‘","anlam":"(Bkz. Semâ’)","kategori":"dil","osmanli":"سماع"},{"kelime":"ŞİMÂL","anlam":"1.Kuzey. 2.Sol, sol taraf.","kategori":"dil","osmanli":"شمال"},{"kelime":"SİMSÂR","anlam":"Müşteri ile satıcı arasında aracılık yapan kimse, dellât, komisyoncu.","kategori":"dil","osmanli":"سمسار"},{"kelime":"SİMYÂ","anlam":"1.Bakır ve benzeri madenler-den kibrit-i ahmer adındaki hususî bir madde vasıtasıyla altın elde etmeyi maksat edinen bir ilim. 2.Kimyâ. 3.Kıymetsiz kalbi kıymetli hâle getirdiği için mecazen tasavvuf için kul-lanılan bir tabir.","kategori":"tasavvuf","osmanli":"سميا"},{"kelime":"SINÂ‘AT","anlam":"Âlet ile icra edilen işler; bu işin inceliklerine vâkıf olma.","kategori":"muamelat","osmanli":"صناعت"},{"kelime":"SİNAGOG","anlam":"Yahudi mâbedi. Havra.","kategori":"dil","osmanli":"سيناقوق"},{"kelime":"SÎNE","anlam":"1.Göğüs. 2.Yürek, kalb.","kategori":"tasavvuf","osmanli":"سينه"},{"kelime":"SİNN","anlam":"1.Yaş. 2.Diş.","kategori":"dil","osmanli":"سن"},{"kelime":"SİNN-İ BÜLûĞ","anlam":"Büluğ yaşı.","kategori":"dil","misal":"Sinn-i bülûğun başlangıcı, erkekte on iki ve kızda dokuz yaşlarını doldurmaktır. Müntehâsı (sonu), ikisinin de on beş yaştır. On beş yaşını tamamlayınca bâliğ sayılırlar. (Halebî)","osmanli":"بلوغ سن"},{"kelime":"SIR","anlam":"1.Gizli, gizlenilen şey. 2.Âlem-i emrin (maddesiz, zamansız ve ölçüye girmeyen âlemin) beş mertebesinden biri.","kategori":"dil","misal":"Kıyâmet günü Allah katında hıyânet edilen emânetlerin en büyüklerinden biri, erke-ğin, hanımının sırrını yaymasıdır. (Hadîs-i şerîf-Müslim, Ebû Dâvûd) Meclisler emanet-tir. Sırrı ifşa edilmez. (Hadîs-i şerîf-Harâitî) İlm-i ledün, Allahü teâlânın sırlarından bir sırdır. Kullarından dilediğinin kalbine bıra-kır. (Hadîs-i şerîf-Deylemî) Ta-savvuf yolculuğunda ruhun üstündeki derece. Âlem-i emrin birinci basamağı kalbdir. Bu yolda (tasavvuf yolunda) kalbi geçtikten sonra sıra-sıyla ruh, sır, hafî ve ahfâ mertebelerinde iler-lenir. Âlem-i emrin bu beş latîfesini anlamak ve bunlar üzerinde bilgi edinmek, ancak Mu-hammed aleyhisselâmın izinde gidenlerin bü-yüklerine nasip olmuştur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سر"},{"kelime":"ŞÎR","anlam":"1.Arslan. 2.Süt.","kategori":"dil","osmanli":"شير"},{"kelime":"ŞİRÂ","anlam":"Satın almak.","kategori":"dil","osmanli":"شراء"},{"kelime":"SIRÂT","anlam":"1.Yol, köprü. 2.Cennet’e geçilmek üzere, Cehennem üzerine kurulmuş, mâhiyeti kesin bilinmeyen köprü.","kategori":"akaid","misal":"Namaz sırat köprüsü üzerinde nurdur. (Hadîs-i şerîfDârekutnî) Sırât köprüsü, Allahü teâlânın emri ile, Cehennem’in üstünde kurulacaktır. Herkese, bu köprüden geçmesi emrolunacaktır. O gün bütün peygamberler; “Yâ Rabbî! Selâmet ver!” diye yalvaracaklardır. cennetlik olanlar, köprüden kolayca geçerek, Cennet’e gideceklerdir. Bunlardan bazısı şimşek gibi, bazısı rüzgâr gibi, bazısı koşan at gibi geçecektir. Sırât köprü…","osmanli":"صراط"},{"kelime":"SIRÂT-I MÜSTEKÎM","anlam":"“Doğru yol” mânâsında İslâmiyet için kullanılan tabir.","kategori":"akaid","misal":"Ey âdemoğulları! Şeytâna itâat etmeyin; o size apaçık bir düşmandır, diye size öğüd vermedim mi? Bir de bana ibâdet edin; sırât-ı müstekim budur (diye emretmedim mi?). (Yâsîn sûresi: 60, 61) (Ey Resûlüm!) Sen, hemen sana vahyedilen (indirilen) Kur’ân’a yapış (onunla amel et!). Şüphesiz ki sen, sırât-ı müstekim üzerindesin. (Zuhrûf sûresi: 43) Ey Mikâil, Cebrâil ve İsrâfil’in Rabbi olan, gökleri ve yeri yaratan, gizl…","osmanli":"مستقيم صراط"},{"kelime":"SİRÂYET","anlam":"Bulaşma, geçme; yayılma.","kategori":"dil","osmanli":"سرايت"},{"kelime":"ŞİRB","anlam":"1.İçme, sulama. 2.Sulama hakkı; ekin ve hayvan sulama nöbeti.","kategori":"dil","osmanli":"شرب"},{"kelime":"SÎRET","anlam":"Ahlâk, gidişât, hâl, hareket, tavır, yaşayış.","kategori":"tasavvuf","misal":"İki haslet var ki, bunlar münâfıkta (içi dışı başka olanda) bulunmaz; güzel sîret ve ahlâk ile din ilmi. (Hadîs-i şerîfTirmizî)","osmanli":"سيرت"},{"kelime":"Sîret-i Nebevî","anlam":"Resûlullah aleyhisselâ-mın hayâtı, ahlâk-ı hasenesi.","kategori":"tasavvuf","misal":"Sîret-i Nebevî’yi bütün Müslümanların öğren-mesi ve o şekilde yaşaması lâzımdır. Böylece, dünyada ve âhirette felâketlerden, sıkıntılardan kurtulmak ve o iki cihân efendisinin şefâatine kavuşmak nasip olur. (Berîka)","osmanli":"نبوى سيرت"},{"kelime":"ŞİRK","anlam":"Allahü teâlâya eş, ortak koşmak.","kategori":"akaid","misal":"Muhakkak ki, Allahü teâlâ kendisine şirk koşanı mağfiret etmez. Şirkten başka her günahı dilediği kulundan affeder. (Nisâ sûresi: 48 ve 166) Allahü teâlâya şirk koşmak, kebâirin (büyük günahların) en şiddetlisidir. (Hadîs-i şerîfBuhârî, Nesaî, Beyhekî) Kıyâmet günü muhakkak affolunmayacak günah, şirktir. (Berîka)","osmanli":"شرك"},{"kelime":"SİRKAT","anlam":"Hırsızlık. Serika.","kategori":"dil","osmanli":"سرقت"},{"kelime":"Sirkat Haddi","anlam":"Şartları tahakkuk etmiş ise, bir sirkatten dolayı hırsıza uzuv kesme cezasının verilmesi.","kategori":"dil","osmanli":"حدى سرقت"},{"kelime":"Sirkat Nisâbı","anlam":"Sirkat (hırsızlık) suçundan dolayı had cezası verilebilmesi için çalınan malın asgari taşıması gereken kıymet. Hanefî mezhebinde sirkat nisâbı 10 dirhem gümüş; yani 33,6 gram gümüş paradır. Bu-nun kıymeti, bir miskal (4,8 gr.) altın olup, bir altın liranın üçte ikisi kıymetindedir. Di-ğür üç mezhebte sirkat nisâbı 3 dirhem (7,26","kategori":"dil","misal":"gr.) gümüş veya rubu’ dînâr (0,87 gr.) altındır. 3 dirhem gümüş veya ¼ dinar altından aşağı değerdeki malı çalanın eli hiçbir mezhebte ke-silmez. (İbni Âbidîn)","osmanli":"نصابى سرقت"},{"kelime":"ŞİRKET","anlam":"Ortaklık, ortak olmak; iki veya daha çok malın birbiriyle karışması veya iki veya daha çok kimsenin kâr maksadıyla kurdukları ortaklık.","kategori":"muamelat","osmanli":"شركت"},{"kelime":"Şirket-i A‘mâl","anlam":"İki veya daha fazla sanat sahiplerinin, başkasından iş kabul ederek ücretini veya bir fabrika kurup îmâlât kârını paylaşmak üzere kurdukları şirket, ortaklık.","kategori":"muamelat","misal":"Şirket-i A’mâlde iş, işçilik müsâvî, kâr farklı olabilir. Şirketin alacağı siparişi, her şerîk yapar. Her şerîk iş kabul eder ve satış yapar. Herbirinin kazancına ve zarârına, her şerîk, sözleşmelerindeki nisbetle ortaktır. Sanâyı’ şirketi, müfâvada ve ınân şeklinde olabilir. Dükkân birinin, âlât edavât ötekinin olmak üzere şirket sahîh olur. (İbni Âbidîn)","osmanli":"اعمال شركت"},{"kelime":"Şirket-i Mülk","anlam":"İki veya daha çok kimsenin, miras veya hediye sureti ile veya parasını muayyen nisbette verip satın alarak, ayn veya deyn olan bir mala beraber sahip olmaları yâhud mallarının, ayrılamayacak şekilde, karışması suretiyle ortak olmaları.","kategori":"muamelat","misal":"Mülk şirketi. Şirket-i mülkün birinci çeşidinde, ortak malın her parçasında, her tanesinde ortaktırlar. İkincisinde ise, her birinin taneleri diğerinin taneleri ile karışmıştır. Birincisinde, ortak hissesini dilediğine satabilir. İkincisinde ise, ancak ortaklarına veya onlardan izin alarak dilediğine satabilir. Ortak binâdan ve tarladan, kendi malının mikdarı nisbetinde ve diğerlerinin hisselerine zarar vermeyecek ş…","osmanli":"ملك شركت"},{"kelime":"ŞÎT (aleyhisselâm)","anlam":"Âdem aleyhisselâmın oğlu ve kendisinden sonra gönderilen peygamber.","kategori":"dil","misal":"Çamur ve taş ile Kâbe’yi ilk yapan kişi Şît aleyhisselâmdır. (Kurtubî) Şît aleyhisselâma elli suhuf verildi. Şît ismi İbrânice olup Arabca’da Allah’ın hibesi (hediyesi) mânâsındadır. (Meâricü’n-Nübüvve)","osmanli":"شيت"},{"kelime":"SİTÂRE","anlam":"Setreden, perde. (Bkz. Settâre)","kategori":"dil","osmanli":"ستاره"},{"kelime":"SİTTE","anlam":"Altı.","kategori":"dil","osmanli":"سته"},{"kelime":"SİVÂD-İ A‘ZÂM","anlam":"“Büyük ileri ge-lenler topluluğu” mânâsına Müslüman âlim-lerin ekserisinin bulunduğu yol için kullanı-lan tabir.","kategori":"dil","misal":"Ümmetim dalâlet üzere ittifak etmeyecektir. Siz bir ihtilaf gördüğünüzde, sivâd-i a’zâma tâbi’ olunuz. (Hadîs-i şerîf-İbni Mâce) Bugün dört mezhebten ayrılmak, Sivâd-i a’zam-dan ayrılmaktır. (el-İnsâf)","osmanli":"اعظم سواد"},{"kelime":"SIYÂM","anlam":"Oruç. Fecrin ağarmasından (imsaktan) güneş batıncaya kadar, yemeyi, iç-meyi ve cimâ’ı terk etmek. (Bkz. Oruç)","kategori":"ibadet","osmanli":"صيام"},{"kelime":"SİYÂSET","anlam":"1.Devleti idare etme sanatı. 2.İnsanların hâlini ve zamanın şartlarını bilerek hareket etme.","kategori":"fikih","misal":"Politika.","osmanli":"سياست"},{"kelime":"SİYER","anlam":"1.Huylar, yüksek vasıflar. 2.Resûlullah aleyhisselâmın hâl tercemesini mevzu edinen ilim.","kategori":"dil","misal":"Sîret’in çokluk hâli.","osmanli":"سير"},{"kelime":"SİYONİZM (Sihyûniyye)","anlam":"Arz-ı Mev’ud (Tevrat’ta İsrailoğullarına va’dedilen) Filistin’de bir Yahudi devleti kurmak maksadıyla 1898’de İsviçre’de faaliyete başlayan ve adını Kudüs’deki üzerinde bulunduğu Siyon dağından alan siyasî cemiyet.","kategori":"dil","misal":"SÔFÎ (Sûfî): صوفى (A) Tasavvuf ehli. Kalbini gafletten, pislikten saflaştıran (arındıran) veya buna gayret eden; velî; derviş. Türkçede bundan gelen sofu kelimesi, aşırı dindar veya mutaassıp kimse için kullanlır. Tasavvuf kelimesi de bundan müştaktır. Bu yolun yolcuları, zühd alâmeti olarak sôf denilen yünlü kaba kumaştan elbise giydiği için sôfî diye anılmıştır. (Risâle-i Kuşeyriyye)","osmanli":"سييونيزم"},{"kelime":"Sôfiyye-i Aliyye","anlam":"Büyük, yüce sô-filer. Tasavvuf büyükleri.","kategori":"tasavvuf","misal":"Ahkâm-ı şer’iyye ile tam bezenmek, ibâdetleri yapmakta ve yasaklardan kaçmakta kolaylık, nefsin fânî olmasına bağlıdır. Bu da sôfiyye-i aliyyenin hizmetine ve onların muhabbetine bağlıdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عليه صوفيه"},{"kelime":"SOFTA","anlam":"1.Medrese talebesi. 2.İlmiye mensubu; molla. 3.Dindar kişi. 4.Bir fikre ta-assupla bağlanan kimse.","kategori":"osmanli","misal":"Aslı Farsça yanmış mânâsına suhte’dir.","osmanli":"صوفطه"},{"kelime":"SOFu","anlam":"Çok dindar kimse; tarikat mensubu.","kategori":"tasavvuf","misal":"Câhilsofu, şeytânınmaskarası olur. (Hadarâtü’l-Kuds)","osmanli":"صوفى"},{"kelime":"SOHBET","anlam":"1.Arkadaşlık; beraberlik. 2.Bir araya gelip hoşça konuşma.","kategori":"tasavvuf","misal":"Eshâb-ı kirâm, Resûlullah’ın daha ilk sohbetinde öyle şeyler kazanmışlardır ki, ümmet arasındaki velîlerin, bunlara en sonda kavuştukları bilinmektedir. Bunun içindir ki, Tâbiîn’in (Eshâb-ı kirâmı görenlerin) en üstünü olan Veysel Karânî, Hazret-i Hamzâ’nın kâtili olan Vahşî’nin, Resûlullah’ın bir kerecik sohbetinde bulunmakla yükseldiği mertebeye yetişememiştir. Çünki sohbetin fazîl…","osmanli":"صحبت"},{"kelime":"ŞÖHRET","anlam":"Meşhur olma, adı duyu-lup yayılma.","kategori":"dil","misal":"Bir kimse dünyada şöhret elbisesi giyerse (şöhret sahibi olmak istediği için iyilik ya-parsa), Allah ona her kıyâmette aynı elbiseyi giydirerek sû-i şöhretle teşhir eder ve niha-yet onu ateş alır. (Hadîs-i şerîf-İbn-i Mâce) Peygamber efendimiz sallallahü aleyhi ve sellem; “Din ve dünya işlerinde iyi tanınarak par-makla gösterilmek, bir kimseye zarar olarak yetişir. Bu zarardan ancak Allahü teâlânın koruduğu kurtulabilir” buyurdu. Bunun için şöhret sahibi olmaktan çok korkmalı, titremeli-yiz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"شهرت"},{"kelime":"SOLCu","anlam":"1.Mevcut düzenin değiş-mesinden yana olan. 2.Sosyalist ekonomik ve siyasî nizama taraftar kimse. 3.Amel def-teri sol elinden verilen, şakî, kâfir, eshâb-ı şimâl.","kategori":"dil","misal":"Zıddı sağcı gelir.","osmanli":"صولجى"},{"kelime":"SOSYAL ADÂLET","anlam":"Herkesin, bilgi ve kâbiliyeti ve gördüğü iş nisbetinde ça-lıştığının karşılığını alması, başkaları tarafın-dan sömürülmemesi. (Bkz. Adâlet)","kategori":"dil","misal":"Sosyal adalet kelimesini sosyalizm ve sosyalist kelimeleri ile karıştırmamalıdır. Söylemesi bir-birine benzeyen bu iki kelimenin mânâları bir-birinden çok uzaktır. Hatta birbirinin zıddıdır, tersidir. (Seâdet-i Ebediyye)","osmanli":"عدالت صوصيال"},{"kelime":"SOSYALİZM","anlam":"İktisadî teşekkülleri tamamen devlete veren, istihsal vâsıtalarını devletleştirmeyi müdafaa eden; böylece sosyal teşkilatlanmayı eşitlik ölçüsüne göre düzeltme iddiasında bulunan ekonomik teori.","kategori":"osmanli","misal":"Sosyalizm başlıca iki kısma ayrılır: Birincisi serbest seçimle hükümeti ele geçirmeyi hedefleyen demokratik sosyalizmdir. Yeni bir seçimle iktidardan gidebilirler. İkincisi, ihtilalci sosyalizm, yani komünizmdir. Sosyalistlerde bütün gelir kaynakları teknik, ziraat, ticaret, kültür devletleştirilmiştir. Şahsî teşebbüs yasaktır. Herkes kapitalist devletin vereceği işi yapmaya, gösterdiği yerde çalışmaya mecburdur. (S…","osmanli":"صوصياليزم"},{"kelime":"SÖZLEŞME","anlam":"Akid.","kategori":"dil","osmanli":"سوزلشمه"},{"kelime":"Sû’","anlam":"Kötü, fena.","kategori":"tasavvuf","osmanli":"سوء"},{"kelime":"Şu‘ARÂ SûRESİ","anlam":"Kur’ân-ı kerîmin yirmi altıncı sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. İki yüz yirmi yedi âyet-i kerîmedir. İçinde şâirlerden bahsedildiği için, Sûretü’ş-Şu’arâ denilmiştir. Sûrede; Hazret-i Mûsâ ile Fir’avn arasında geçen olaylar, İbrâhim, Nûh, Hûd, Sâlih, Lût ve Şuayb aleyhimüsselâmın kavimlerindeki inkârcılara karşı verdikleri mücâdelelerden bahsedilmektedir. (Mefâtihü’l-Gayb, Tefsir-i Mazharî) Kim Şu’arâ sûresini okursa, Nûh’u tasdik edenlerin, Hûd, Sâlih, Şuay…","osmanli":"سى سوره شعراء"},{"kelime":"Şu‘AYB (aleyhisselâm)","anlam":"Medyen ve Eyke ahâlisine gönderilen ve Kur’ân-ı kerîmde ismi zikredilen peygamber.","kategori":"dil","misal":"Medyen halkına, kardeşleri Şuayb’ı gönderdik. Onlara şöyle söyledi: “Ey kavmim! Allah’a kulluk edin, sizin O’ndan başka tanrınız yoktur. Size Rabbinizden açık bir delil gelmiştir; artık ölçüyü, tartıyı tam yapın, insanların eşyalarını eksik vermeyin. Düzeltilmesinden sonra yeryüzünde bozgunculuk yapmayın. Eğer inananlar iseniz bunlar sizin için daha hayırlıdır.” (A’râf sûresi: 85)","osmanli":"شعيب"},{"kelime":"Sû’-İ HÂL","anlam":"Kötü hâl. Birini tezlîl için zahmetle etme iştigâl, Arkadaş kazanmaya, mâni sû’i hâl.","kategori":"akaid","misal":"[Bir kimseyi aşağılamak zahmeti ile uğraşma; çünki, arkadaş kazanmaya kötü hâl mâni olur.]","osmanli":"حال سوء"},{"kelime":"Sû’-İ ZAN","anlam":"Kötü zan. Birini kötü bilmek, kötü gözle bakmak, kötülemek, kötülüğü hükm etmek.","kategori":"fikih","misal":"Ey iman edenler! Zannın çoğundan kaçının. Çünki zannın bir kısmı (sû’-i zan) günahtır. Birbirinizin kusurunu araştırmayın. Biriniz diğerinizi arkasından çekiştirmesin. Biriniz, ölmüş kardeşinin etini yemekten hoşlanır mı? İşte bundan tiksindiniz. O hâlde Allah’tan korkun. Şüphesiz Allah, tevbeyi çok kabul edendir, çok esirgeyicidir. (Hucurât sûresi: 12) Sû’-i zandan sakının. Çünki sû’-i zan, insanın içinden geçen en…","osmanli":"ظن سوء"},{"kelime":"Şu’ûN","anlam":"İşler, yeni çıkan hâdiseler.","kategori":"hadis","misal":"Şe’n’in çokluk hâli.","osmanli":"شئون"},{"kelime":"Şu‘ûR","anlam":"1.Anlama, anlayış, hissetme, duyma, idrâk, bilme. 2.Tasavvufta, uyanık olma, kendi varlığından haberdar olma.","kategori":"miras","misal":"Sekr hâlinde bulunan evliyânın uygunsuz sözleri söylemeleri suç sayılmayabilir. Fakat hep şuûrlu olanların böyle sözler söylememeleri lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî) İç bâde güzel sev varsa akl ü şuûrun Dünya var imiş, ya ki yoğ imiş ne umûrun! (Ziya Paşa)","osmanli":"شعور"},{"kelime":"SÜBHA","anlam":"1.Tesbih. 2.Duâ ve nâfile namaz.","kategori":"ibadet","misal":"Akşam namazından sonraki iki rek’atlık sübhayı evinizde kılınız. (Hadîs-i şerîfİbn-i Mâce) Tamam kılınmamış olan bir namaz sübhâsı ilave edilerek tamamlanır. (Hadîs-i şerîfHâkim)","osmanli":"سبحه"},{"kelime":"SÜBHÂN","anlam":"Tesbihe lâyık yegâne zât olan Allah.","kategori":"akaid","misal":"SÜBHÂNE RABBİKE ÂYET-İ KERÎMESİ: oku- kerîm Kur’ân-ı سبحان ربك آية كريمه سى duktan, duâ ettikten, ders ve va’zlardan sonra okunması sünnet olan âyet-i kerîme.","osmanli":"سبحان"},{"kelime":"SÜBHÂNEKE","anlam":"Her namazın ilk rek’a-tinde, ayrıca ikindi ve yatsı namazlarının sünnetlerinin üçüncü rek’atinde, besmele çekmeden önce okunan duâ.","kategori":"ibadet","misal":"Sübhâneke duâsının mânâsı şöyledir: “Ey Allah’ım! Seni noksanlıklardan tenzîh eder; bütün kemâl sıfatlarıyla tavsîf ederim. Sana hamd ederim. Senin ismin yücedir. (Ve senin şânın her şeyin üstündedir.) Senden başka ilâh yoktur. İftitah tekbirinden hemen sonra Sübhâneke okumak münferid veya cemaatle kılan için sünnettir. (Halebî)","osmanli":"سبحانك"},{"kelime":"ŞÜBHELİ DELİL","anlam":"Zannî, birkaç mânâ çıkarılabilen, açıkça anlaşılamayan de-lil. (Bkz. Zannî Delil)","kategori":"dil","osmanli":"دليل لى شبهه"},{"kelime":"ŞÜBHELİ ŞEYLER","anlam":"Helâl ve haram olduğu açıkça bildirilmeyen şeyler; şüpheliler.","kategori":"fikih","misal":"Helâl olan şeyler bellidir, haram olan şeyler de bellidir. İkisi arasında şüpheli şeyler vardır. Bunlardan kaçınınız ki harama düşmeyesiniz. (Hadîs-i şerîfBuhârî, Müslim, Ebû Dâvûd, İbn-i Mâce, Taberânî) Haramlardan sakınmaya takvâ, şüpheli şeylerden sakınmaya vera’ denir. Şüpheli olmak korkusu ile mübahların çoğunu terk etmeye de zühd denir. Ebû Bekr radıyallahü anh buyurdu ki: “Biz, harama düşme korkusundan yetmiş…","osmanli":"شيلر لى شبهه"},{"kelime":"SÜBûT","anlam":"1.Sâbit olma; istikrar, gerçek-leşme, meydana gelme. 2.Şüphe bulunma-yan husus.","kategori":"dil","osmanli":"ثبوت"},{"kelime":"SÜBûTu ZANNÎ","anlam":"Gerçekliği, şüphe götürmeyecek delillerle değil de, zan ile sâbit olan. Zanniyyü’s-Sübût.","kategori":"dil","osmanli":"ظنى ثبوتي"},{"kelime":"SuÇ","anlam":"Hukukun yasakladığı ve cezaî bir müeyyideye bağladığı fiil; cürüm.","kategori":"dil","osmanli":"صوﭺ"},{"kelime":"SÜDÜS","anlam":"Altıda bir. Ferâiz ilminde yani İslâm mîras hukûkunda bildirilen altıda bir hisse.","kategori":"miras","osmanli":"سدس"},{"kelime":"ŞÜF‘A","anlam":"Başkasına satılmış olan bir mülkü, satış değeri ile satın almak hakkı.","kategori":"muamelat","misal":"Şüf’a hakkı mâlikine şefî’ denir. Bu da üç kişidir: Malda ortak olan, malda komşu olan, malda irtifak, faydalanma hakkı bulunan. (İbni Âbidîn) Şüf ’a menkullerde olmaz, gayrımenkullerde olur. (İbni Âbidîn)","osmanli":"شفعه"},{"kelime":"SÜFLÎ","anlam":"1.Aşağıda bulunan. 2.Alçak, bayağı.","kategori":"dil","misal":"Rûh, bedenden ayrıldıktan sonra, ulvî ise, yükselir. Süflî ise, alçalır. (Mektûbât-ı İmâm-ı Rabbânî) SÜFLİYYET: سفليت (A) Süflîlik, alçaklık, bayağılık.","osmanli":"سفلى"},{"kelime":"SÜFTECE","anlam":"Yolcuya borç verip, gittiğin yerde, falancaya ödeyeceksin demek suretiyle cereyan eden havâle.","kategori":"muamelat","misal":"Süftece yoluyla borç vermek tahrîmen mekrûhtur. Çünki emânet olarak vermeyip süftece yolunu tercih etmenin sebebi, paranın yolda kaybolması, çalınması veya elinden alınması gibi tehlikelere karşı, alanın mes’ûliyetini sağlamak ve parasını emniyete almaktır. Çünki emânet olarak verseydi, onun adına zâyi olacaktı. Borç olarak vermesiyle bunu alan nâmına olmasını sağlamış ve böylece verdiği borçtan menfaat te’min etme…","osmanli":"سفتجه"},{"kelime":"SuGRÂ","anlam":"1.Daha küçük, pek küçük. 2.Mantıkta küçük önermeye verilen isim.","kategori":"dil","misal":"Değişen şeyler, hâdisdir [yok iken var olmuş-tur]. O hâlde, âlem hâdisdir. Bu üç cümleden ilk ikisi mukaddemedir. Mantık ilminde, birin-cisine sugrâ, ikincisine kübrâ denir. Üçüncüsü de netîcedir. (Nebrâs)","osmanli":"صغرى"},{"kelime":"SÜHREVERDİYYE","anlam":"Milâdî onüçüncü asırda Bağdad’da yaşamış evliyânın büyüklerinden Ebû Hafs Ömer bin Muhammed Şihâbüddîn Sühreverdî hazretlerinin tasavvuftaki yolu.","kategori":"tasavvuf","osmanli":"سهرورديه"},{"kelime":"SuHT","anlam":"Haram mal, haram kazanç.","kategori":"akaid","osmanli":"سوخت"},{"kelime":"ŞÜHûD","anlam":"1.Şâhid olma, görme. 2.Ta-savvuf yolunda ilerleyenin kalb ve ruh ile çe-şitli mertebeleri görmesi.","kategori":"tasavvuf","misal":"Cezbe (çekilmek) ancak bir üst makama olur. Daha üst makamlara çekilmez. Şühûd da böy-ledir. Bir makam görülebilir. O hâlde kalb ma-kamında bulunup sülûk yapmadan cezb edi-lenler ancak, kalbin üstündeki ruh makamına çekilirler. Rûhun şühûdünü şühûd-i hak bilir-ler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"شهود"},{"kelime":"SuHuF","anlam":"1.Sahîfeler. 2.Dört büyük ilâhî kitab dışında gönderilen kitapçıklar, for-malar. 3.Amel defteri.","kategori":"akaid","misal":"Peygamberlere aleyhimüsselâm Allahü teâlâ tarafından gelen yüz dört kitaptan ilk yüz tânesi. Yüz suhûftan, on suhûfu Hazret-i Âdem’e, elli suhûfu Şit aleyhisselâma, otuz suhufu İdrîs aley-hisselâma, on suhûfu İbrâhim aleyhisselâma in-miştir. Bunların hepsini Cebrâil aleyhisselâm indirmiştir. (Miftahü’l-Cenne) İnsanların dünyada iken yap-tıkları iyilik ve kötülüklerinin yazıldığı ve kıyâ-met günü herkesin eline verilecek olan defter. (Bkz. Amel Defteri) Suhuflar getirilip açıldığında, gökyüzü ye-rinden koparıldığında her kişi (hayır ve şer-den) neler yapıp getirdiğini anlar. (Tekvîr sû-resi: 10-14)","osmanli":"صحف"},{"kelime":"SÜKNÂ","anlam":"Oturulacak yer, mesken, ev. Nafaka, İslâmiyet’te, taâm (yiyecek, içecek şey-ler), kisve (elbise, yani giyecek şeyler) ve süknâ demektir. Zevcin (kocanın) zevcesine (hanı-mına) yapacağı bu masraflar şehrin âdetine, piyasaya ve akrabâ ve arkadaşlara göre ayar-lanır. Zamana ve hâle göre değişir. Her mem-lekette başkadır. (İbni Âbidîn)","kategori":"ibadet","osmanli":"سكنى"},{"kelime":"Şükr Secdesi","anlam":"Kendisine nîmet gelen veya bir dertten ve sıkıntıdan kurtulan kimsenin, Allahü teâlâ için yaptığı secde.","kategori":"akaid","misal":"Şükür secdesi, yeni bir nimete nail olan veya Allahü teâlâ kendisine mal, evlât ihsan eden, yâhud bir musibetten kurtulan kimselere müstehabdır. Bu secde için kıbleye dönülür ve Allahü teâlâya şükür için secde edilir. Secdede Allah’a hamd ile tesbih ve tekbir getirilir. Ondan sonra secde-i tilâvette olduğu gibi secdeden baş kaldırılır. Namazdan hemen sonra şükür secdesi yapmak, câhiller namazdan zannedeceği için mek…","osmanli":"سى سجده شكر"},{"kelime":"SÜKûN","anlam":"1.Sâkinlik, durgunluk, ha-reketsizlik; rahat, huzur. 2.Tecvîd ilminde ce-zimli veya harekesi olmayan harfler.","kategori":"dil","osmanli":"سكون"},{"kelime":"SÜKûNET","anlam":"1.Durgunluk, dinme, azalma. 2.Rahat.","kategori":"dil","osmanli":"سكونت"},{"kelime":"SÜKûT","anlam":"Susmak; cevap vermemek. Sükût ikrardan sayılır. (Hadîs-i şerîf-Nesâî) Helâl Allah’ın kitabında helâl ettiği, harâm da Allah’ın kitabında harâm kıldığı şeydir. sükût ettiği de affettiğidir. (Hadîs-i şerîf-İbn-i","kategori":"hadis","misal":"Mâce) Biriniz kızdığı zaman, sükût etsin. (Hadîs-i şerîf-Müsnedü İmâm-ı Ahmed)","osmanli":"سكوت"},{"kelime":"SuLB","anlam":"1.Omurga kemiği, bel kemiği. 2.Zürriyet. 3.Sert, katı; maddenin katı hâli.","kategori":"dil","osmanli":"صلب"},{"kelime":"SuLEHÂ","anlam":"Sâlihler, günah işlememeye gayret edenler. (Bkz. Sâlih)","kategori":"dil","misal":"Benim dostum ancak Allahü teâlâdır ve su-lehâ olan mü’minlerdir. (Hadîs-i şerîf-Müslim) İyi huylu olmak, iyi huyunu korumak için su-lehâ ile, güzel huylularla arkadaşlık etmelidir. İnsanın huyu, arkadaşının huyu gibi olur. Ahlâk, hastalık gibi sârîdir. Kötü huylu ile arkadaşlık etmemelidir. Hadîs-i şerîfte; “İnsanın dini, ar-kadaşının dini gibi olur” buyruldu. (Berîka)","osmanli":"صلحاء"},{"kelime":"SÜLEYMÂN (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen ve Beyt-i Makdis’i inşa eden Benî İsrâil peygamberinlerden.","kategori":"dil","misal":"Süleyman’ın emrine de şiddetli esen rüzgârı verdik. Onun emriyle içinde bereketler yarattığımız yere doğru eserdi. Biz her şeyi biliriz. Dalgıçlık yapan ve bundan başka işler de gören şeytânlardan da onun buyruğu altına verdik. Onların hepsini gözetiyorduk. (Enbiyâ sûresi: 81-82) Süleyman (aleyhisselâm) mal, mülk ve ilim arasında muhayyer bırakıldı. İlmi seçtiğinden dolayı da mal, mülk kendisine tâbi kılındı. (Hadîs…","osmanli":"سليمن"},{"kelime":"SuLH","anlam":"Barış.","kategori":"dil","misal":"Eğer onlar sizi bırakıp bir tarafa çekilir de sizinle savaşmazlar ve size sulh teklif eder-lerse, artık Allah size, onların aleyhinde bir yola girme hakkı vermemiştir. (Nisâ sûresi: 90) Sulh hayırlıdır. (Nisâ sûresi: 128) Düşman ordusu kuvvetli ise, mal vererek bile sulh yapmak câiz olur. (İbni Âbidîn)","osmanli":"صلح"},{"kelime":"SuLTA","anlam":"Otorite, güç, hâkimiyet.","kategori":"dil","osmanli":"سلطه"},{"kelime":"SÜLûK","anlam":"Allahü teâlânın rızasına kavuşmak için bir rehberin irşadı altında çıkılan manevî yolculuk, tasavvuf yoluna girmek.","kategori":"tasavvuf","misal":"Evliyâlık kemâlâtına kavuşmak sülûk, kalbin zikretmesi ve murâkabe (nefsi kontrol) ve râbıta (bir büyüğe kalben bağlanma) ile olur. Ne kadar ilerlerse ilerlesin, İslâmiyet’ten dışarı çıkamaz. İslâmiyet’e uymakta sarsıntı olursa, bütün vilâyet (evliyâlık) dereceleri yıkılır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سلوك"},{"kelime":"Sülûk Yolu","anlam":"Tasavvufta, Allahü teâlânın rızasına kavuşmak için tutulan yollardan biri olup, bir rehberin irşadı vasıtasıyla kemale kavuşmayı ifade eder.","kategori":"tasavvuf","misal":"(Bkz. Vilâyet Yolu) İnsanı Allahü teâlânın sevgisine kavuşturan yol ikidir. Biri nübüvvet yolu olup, aslın aslına kavuşturur. Eshâb-ı kirâmın hepsi, bu yoldan vâsıl oldular. Sonra gelenlerden pek az zât da, bu yoldan ermiştir. Bu yolda sebebe, vâsıtaya lüzum yoktur. Sâlik, kâmil bir zâtın sohbetinde kemâle geldikten sonra, feyzi asıldan alıp ilerler. İkinci yol, vilâyet yoludur. Kutblar, Evtâd, Nücebâ, Büdelâ ve diğ…","osmanli":"يولى سلوك"},{"kelime":"SÜLÜS","anlam":"Üçte bir. Ferâiz ilminde yani İslâm mîrâs hukûkunda üçte bir hisse.","kategori":"miras","osmanli":"ثلث"},{"kelime":"SÜLÜSÂN","anlam":"Üçte iki. Ferâiz ilminde yani İslâm mîrâs hukûkunda üçte iki hisse.","kategori":"miras","osmanli":"ثلثان"},{"kelime":"ŞÜMûL","anlam":"İçine alma, kaplama, şâ-mil olma.","kategori":"dil","osmanli":"شمول"},{"kelime":"SÜMÜN","anlam":"1.Sünnetler. 2.Hüküm bildiren hadîs-i şerîfleri toplayan hadîs kitablarına verilen isim.","kategori":"miras","misal":"Sekizde bir. Ferâiz ilminde yani İslâm mîrâs hukûkunda sekizde bir hisse. SÜNEN: سنن (A) (Bkz. Sünnet). Sünen kelimesi yalnız olarak söylenince, dört âlimin kitablarından biri anlaşılır. Bunlar; Ebû Dâvûd, Tirmizî, Nesâî ve İbn-i Mâce’dir. Bunlardan başkasının “Sünen” kitabı söylenir-ken, yazarının da adı birlikte söylenir; Sünen-i Dâre Kutnî, Sünen-i Kebîr-i Beyhekî gibi. (Taş-köprüzâde)","osmanli":"ثمن"},{"kelime":"SuN‘","anlam":"Yapmak, ustalıkla yapmak, eser meydana getirmek, sanatlı iş.","kategori":"dil","osmanli":"صنع"},{"kelime":"SuN‘-İ İLAHÎ","anlam":"Allahü teâlânın kimsenin yaptığına benzemeyen güzel eseri. Sen dağları görürsün de, onları yerinde du-rur sanırsın. Oysa onlar bulutların yürümesi gibi yürümektedirler. (Bu,) bir sun’-ı ilâhî-dir, her şeyi sapasağlam yapan Allah’ın işi-dir. Şüphesiz ki O, yaptıklarınızdan tama-mıyla haberdardır. (Neml sûresi: 88)","kategori":"dil","osmanli":"الهى صنع"},{"kelime":"SuN‘Î İLKAH","anlam":"Yapay dölleme.","kategori":"dil","osmanli":"القاه صنع"},{"kelime":"SÜNEN","anlam":"1.Sünnetler. 2.Hüküm bildiren hadîs-i şerîfleri toplayan hadîs kitablarına verilen isim.","kategori":"hadis","misal":"Sünen kelimesi yalnız olarak söylenince, dört âlimin kitablarından biri anlaşılır. Bunlar; Ebû Dâvûd, Tirmizî, Nesâî ve İbn-i Mâce’dir. Bunlardan başkasının “Sünen” kitabı söylenirken, yazarının da adı birlikte söylenir; Sünen-i Dâre Kutnî, Sünen-i Kebîr-i Beyhekî gibi. (Taşköprüzâde)","osmanli":"سنن"},{"kelime":"SÜNNET","anlam":"1.Yol, çığır; kanun; âdet.","kategori":"hadis","misal":"Resûlullah aleyhisselâmın sözleri, işleri ve görüp de mâni olmadığı şeyler. Edille-i şer’iyyenin, yani dinde kaynak olan dört aslî delilden ikincisi. Kitab ile beraber söylenince (kitab ve sünnet), bu anlaşılır. Aranızda iki şey bırakıyorum. Onlara sımsıkı sarılırsanız, yoldan sapmazsınız. Biri Allah’ın Kitabı, diğeri de benim Sünnetimdir. Bunlar, Kevser Havuzuna varıncaya kadar birbirinden ayrılmazlar. (Hadîs-i şer…","osmanli":"سنت","baglamlar":[{"baglam":"hadis","anlam":"Hz. Peygamber'in söz, fiil ve takrirleri; İslâm'da Kur'ân'dan sonra ikinci kaynak."},{"baglam":"fıkıh","anlam":"Farz ve vâcibden sonra gelen hüküm derecesi; yapana sevap, terk edene günah olmayan amel."},{"baglam":"tıp","anlam":"Erkek çocuğun sünnet derisinin kesilmesi ameliyatı; Hz. İbrâhîm'den beri uygulanan fıtrat sünneti."}]},{"kelime":"Sünnet-i Hasene","anlam":"Güzel çığır. İlk asırda aslı olduğu hâlde, kendisi bulunmayıp, dinin emirlerinin yapılmasını kolaylaştıran işler.","kategori":"hadis","misal":"Bir kimse, İslâm’da bir sünnet-i hasene ihdâs ederse, bunun sevâbına ve bunu yapanların sevablarına kavuşur. (Hadîs-i şerîfMüslim, Tirmizî) Minâre, müstehab olan sünnet-i hasenedir. Çünki, müezzinin, ezânı yükseğe çıkıp okuması sünnettir. Minâre, bu sünnete yardım etmektedir. (Berîka)","osmanli":"حسنه سنت"},{"kelime":"Sünnet-i Hüdâ","anlam":"Hidâyet sünneti. Resûlullah aleyhisselâmın devamlı yaptığı, bazen terk ettiği ve terk edenlere bir şey demediği sünnet.","kategori":"hadis","misal":"Sünnet-i hüdâyı özürsüz terk etmek günah olmaz. Devamlı terk eden kıyamet günü azarlanır. (İbni Âbidîn)","osmanli":"خدا سنت"},{"kelime":"Sünnet-i Kifâye","anlam":"Başka bir-iki kişi-nin işlemesiyle, diğerlerinden sâkıt olan sün-net. Sünnet-i ale’l-Kifâye.","kategori":"hadis","misal":"Selâm vermek, itikâfa girmek ve dinin izin ver-diği işlerin evvelinde Besmele-i şerîfeyi söylemek, terâvih namazını câmide cemâatle kılmak sün-net-i kifâyedir. (Miftahü’l-Cenne)","osmanli":"كفايه سنت"},{"kelime":"Sünnet-i Müekkede","anlam":"Kuvvetli sünnet. Resûlullah aleyhisselâmın devamlı yaptıkları, bazen terk ettikleri, terk edenlere bir şey demedikleri ameller.","kategori":"hadis","misal":"Sabah, öğle ve akşam namazının sünnetleri, yatsı namazının son iki rek’at sünneti, sünnet-i müekkededir. Ayrıca ezân okumak, kâmet getirmek, cemâate devam etmek, abdest alırken misvâk kullanmak, müekked sünnetlerdendir. (Berîka) Sünnet-i Müekkedi, özürsüz olarak devamlı terk etmek mekrûh olur. (İbni Âbidîn)","osmanli":"مؤكده سنت"},{"kelime":"Sünnet-i Seniyye","anlam":"Senâ edilen, övülen sünnet; İslâmiyet.","kategori":"hadis","misal":"Seâdete ermek için; sünnet-i seniyyeye yapışmak ve bid‘atlerden kaçınmak lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ثنيه سنت"},{"kelime":"Sünnet-i Zevâid","anlam":"Zâid (ziyade) sünnet.","kategori":"hadis","misal":"Resûlullah aleyhisselâmın elbiseleri, oturması, kalkması, iyi şeyleri yapmaya sağdan başlaması sünnet-i zevâiddendir. Bunları yapanlara da sevab verilir. Bunlara sevab verilmesi için, niyet etmek lâzım değildir. Sünnet-i zevâidi ve nâfile ibâdetleri terk etmek mekrûh olmaz. (İbni Âbidîn)","osmanli":"زوائد سنت"},{"kelime":"Sünnet Olmak","anlam":"Çocuğun sünnet derisinin çepeçevre kesilmesi.","kategori":"hadis","misal":"Sünnet olmak, Resûlullah aleyhisselâmın mühim sünnetlerindendir. İslâmiyet’in şiârıdır. (Dürrü’l-Muhtar)","osmanli":"اولمق سنت"},{"kelime":"SÜNNÎ","anlam":"Resûlullah aleyhisselâmın ve Eshâbının inandığı gibi inanan Müslüman.","kategori":"dil","misal":"Ehl-i sünnet ve cemaat itikadında olan. (Bkz. Ehl-i Sünnet ve Cemâat)","osmanli":"سنى"},{"kelime":"SûR","anlam":"1.Şehrin etrafına çekilen yük-sek duvar, kale, hisar. 2.Kıyâmet kopacağı zaman, dört büyük melekten biri olan İsrâ-fil aleyhisselâmın üfleyeceği, nasıl olduğu bi-linmeyen boru. Sûra bir kere üfürülünce, yeryüzü ve dağ-lar, yerlerinden kaldırılıp silkilecektir. O gün kıyâmet kopacak, gök yarılacak ve dağıla-caktır. (Hâkka sûresi: 13-16) Kıyâmetin yok edici sûrundan sonra, ikinci bir sûr üflenir. Bu sese bütün beşeriyyet (yaratılmışlar) tâbi olur. Bu emir ile kalkıp, hâzır olurlar. (Zü-mer sûresi: 62) Allahü teâlâ, Sûr üfürüldükten sonra, kıyâme-tin kopmasını murâd buyurduğu (dilediği) va-kit; dağlar uçar, bulutlar gibi yürümeye başlar. Denizlerin bazısı bazısına taşar. Güneşin nûru giderek simsiyah olur. Dağlar, toz hâline gelir. Âlemler birbirine girer. Yıldızlar, dizili incinin kopup dağıldığı gibi olur. Gökler gülyağı gibi erir ve değirmen döner gibi deverânla şiddetli bir şekilde hareket eder. Yerde ve gökte diri kimse kalmaz. Bütün canlılar ölür. Yerde taş taş üs-tünde kalmaz. Bütün bunlardan sonra, aradan kırk sene gibi bir zaman geçer. Allahü teâlâ, İs-râfil aleyhisselâmı diriltir. O da sûru üfürür. Bu ikinci sûr ile, her bir ruh kendi cesetlerine girer-ler. Dağlarda ölmüş olan, vahşî hayvanların ve kuşların yemiş olduğu insanların ruhları kendi cesetlerini bulur. İnsanlar, kabirlerinden kalk-tıkları vakit, yerleri dümdüz olmuş bir kâğıt sa-hifesi gibi görür... (Dürretü’l-Fâhire)","kategori":"akaid","osmanli":"صور"},{"kelime":"ŞûRÂ","anlam":"Meşveret etme, danışma; meş-veret için toplanma.","kategori":"dil","osmanli":"شورى"},{"kelime":"ŞûRÂ SûRESİ","anlam":"Kur’ân-ı kerîmin kırk ikinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Elli üç âyet-i kerîmedir. Otuz sekizinci âyetinde geçen Şûrâ kelimesinden dolayı, Sûretü’ş-Şûrâ denilmiştir. Sûrede; Allahü teâlânın kudret ve azameti, müşriklerin âhiretteki cezâları, Allahü teâlânın lütfu ve affının çokluğu bildirilmektedir. (Kurtubî, Mefâtihü’l-Gayb) Kim Şûrâ sûresini okursa, meleklerin istiğfâr ve merhamet istedikleri kimselerden olur. (Hadîs-i şerîfBeydâvî)","osmanli":"سى سوره شورى"},{"kelime":"SûRE","anlam":"Kur’ân-ı kerîmin 114 müstakil kısmından her biri.","kategori":"dil","misal":"Kulumuza gönderdiğimiz Kur’ân’dan şüphe ediyorsanız, siz de ona benzer bir sûre söyleyiniz. Bunu yapabilmek için güvendiklerinizden yardım isteyiniz. Buna benzer bir sûre söyleyemezsiniz. (Bakara sûresi: 23) Kim yatacağı zaman Kur’ân-ı kerîmden herhangi bir sûre okursa, Allahü teâlâ ona; uyanıncaya kadar her şeyden kendisini koruyacak bir melek gönderir. (Hadîs-i şerîfTirmizî) Sünnetlerin ve vitrin her rek’atinde ve…","osmanli":"سوره"},{"kelime":"SûRESİ [1]","anlam":"Kur’ân-ı kerîmin yetmiş sekizinci sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil oldu. Kırk âyet-i kerîmedir. Kıyâmet haberlerini ihtivâ ettiği için sûreye bu mânâya gelen Sûretü’n-Nebe’ denilmiştir. Nebe, haber demektir. Amme kelimesi ile başladığı için Amme sûresi de denir. Sûrede; Allahü teâlânın insanlara olan eşsiz lütufları, kıyâmet günü ve o gün meydana gelecek hâdiseler, Cehennem’in şiddeti ve Cehennemlikler, Allahü teâlâya hesap verdikten sonra kâfirlerin pişm…","osmanli":"سى سوره نبأ"},{"kelime":"SûRESİ [2]","anlam":"Kur’ân-ı kerîmin otuz dördüncü sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Elli dört âyet-i kerîmedir. On beşinci âyet-i kerîmede geçen Yemen’de yaşayan kabilenin adı olan Sebe’ kelimesinden dolayı, Sûretü’s-Sebe’ denilmiştir. Sûrede; Allahü teâlânın ilminin genişliği, Allahü teâlânın Sebe halkına lütufları ve onların nankörlük göstermeleri yüzünden uğradıkları felâketler, güzel ve faydalı işlerden başka hiçbir şeyin insanı Allahü teâlâya yaklaştırmayacağı, âhirette iz…","osmanli":"سى سوره سبأ"},{"kelime":"SûRET","anlam":"1.Tasvir, resim. 2.Dıştan görünen şekil, dış görünüş. 3.Kopya, nüsha.","kategori":"dil","misal":"Canlı sûreti ile köpek ve cünüp kimsenin bulunduğu eve rahmet melekleri girmez. (Hadîs-i şerîf-Buhârî, Taberânî) Üzerinde canlı sûreti bulunan elbise ile namaz kılmak tahrîmen mekrûhtur. (İbni Âbidîn) Allahü teâlâ sizin sûretlerinize ve malları-nıza değil; ancak amellerinize ve niyetleri-nize bakar. (Hadîs-i şerîf-Müslim) Zâhidâ! Sûret gözetme, içeri gelen cânâ bak. (Ahmed Kuddûsî) Âlem-i misâl, bütün âlemlerin en genişidir. Âlemlerin hepsinde bulunan her şeyin âlem-i misâlde bir sûreti vardır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"صورت"},{"kelime":"SÜREYYÂ","anlam":"Semânın kuzey tarafında parlak bir yıldız kümesi, Ülker yıldızı, Pervîn. Îmân süreyyâ yıldızına çıksa, Fâris oğul-larından biri, elbette alıp getirir. (Hadîs-i şerîf-Buhârî)","kategori":"hadis","osmanli":"ثريا"},{"kelime":"SÜRGÜN","anlam":"Suç işleyen kimseyi, ceza olarak bulunduğu yerden başka yerde muay-yek bir zaman ikamete tâbi tutma.","kategori":"dil","osmanli":"سوركون"},{"kelime":"SûRÎ","anlam":"Görünüşte;, mecaz.","kategori":"dil","osmanli":"صورى"},{"kelime":"SÜRME","anlam":"Göze çekilen ve kirpik dip-lerine sürülen bir çeşit siyah madde, kühl. Kocası vefat eden kadın, kınalanmasın, sürme çekmesin, koku sürmesin, boyalı el-bise giymesin, süs ve ziynet takmasın. (Ha-dîs-i şerîf-Müslim, Taberânî)","kategori":"osmanli","misal":"Resûlullah aleyhisselâm geceleri gözlerine sürme çekerdi. (İbni Adiyy)","osmanli":"سرمه"},{"kelime":"SuRRE","anlam":"1.Para kesesi, cüzdan. 2.Çelebi Sultan Mehmed’den itibaren Osmanlı pâdişâhlarının her yıl hac mevsiminde Haremeyn-i şerîfeyn (Mekke ve Medîne) halkına ve buralarda geçici olarak bulunan Müslümanlara, mukaddes yerlerin ve hac yollarının emniyetini sağlayan Mek…","kategori":"dil","osmanli":"صره"},{"kelime":"SuRRE ALAYI","anlam":"Osmanlı padişahlarının mukaddes beldelere gönderdiği hediyeleri götüren topluluk.","kategori":"osmanli","osmanli":"آلايى صره"},{"kelime":"ŞuRû‘","anlam":"Başlamak, girişmek.","kategori":"dil","osmanli":"شروع"},{"kelime":"SÜRûR","anlam":"Sevinç.","kategori":"dil","osmanli":"سرور"},{"kelime":"SÜRYÂNÎLER","anlam":"Sâmî ırkından Su-riye’nin ve Irak’ın kuzeyinde yaşayan eski bir halk. İlk asırlarda Hristiyanlığa girmiş; büyük bir kısmı (Süryânî-i Kadim) Monofiziyye iti-kadındadır. Bir kısmı ise sonraki asırlarda Ka-tolik veya Protestan olmuştur. Süryâniyyûn","kategori":"dil","osmanli":"سريانيلر"},{"kelime":"SÜT ANNE","anlam":"İki buçuk yaşından küçük olan çocuğu emziren kadın.","kategori":"dil","misal":"Süt çocuğu; süt annesi ve babası ve bunların nesep ve rıdâ’dan (sütten) olan mahremleri ile ebedî evlenemez. (Ni’met-i İslâm)","osmanli":"آنه سوت"},{"kelime":"SÜT KARDEŞ","anlam":"Aynı kadından süt emmiş çocuk.","kategori":"dil","misal":"İki buçuk yaşından küçük iki çocuk aynı kadından süt emince, süt kardeşi olurlar. Birbirleri ile evlenemezler. (Ni’met-i İslâm)","osmanli":"قردش سوت"},{"kelime":"ŞuYû‘","anlam":"1.Yayılma, duyulma. 2.Bir mala müştereken mâlik olma.","kategori":"miras","osmanli":"شيوع"},{"kelime":"SûZ","anlam":"1.Yanma; ateş, sıcaklık. 2.Dert, ız-tırap, acı.","kategori":"dil","misal":"SÜAL: (Bkz. Su'âl)","osmanli":"سوز"},{"kelime":"TA‘ALLuK (Te‘alluk)","anlam":"Bağlanma. Tenâsüh, ruhun bedene te‘alukundan önce, başka bir cesede te’allukudur ki, böyle inanmak küfürdür.","kategori":"akaid","misal":"(Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تعلق"},{"kelime":"TA‘ÂM","anlam":"Yiyecek; insanın yaşayabilmesi için lâzım olan nafakanın bir kısmı.","kategori":"dil","misal":"Nafaka, şeriatte, ta’âm, kisve ve süknâ demektir. Kitapların çoğunda, yalnız ta’âm mânâsına kullanılmak âdet olmuştur. (İbni Âbidîn)","osmanli":"طعام"},{"kelime":"TA‘DÎL-İ ERKÂN","anlam":"“Rüknlerin denkleştirilmesi” mânâsına namazda, kıyâm, rükû’, kavme, secdeler ve celsede her âzânın normale geçip hareketsiz hâle getirilmesi.","kategori":"ibadet","misal":"Ta’dîl-i erkân, İmâm-ı A’zâm ile İmâm-ı Muhammed’e göre vâcibdir. Fakat İmâm-ı Ebû Yûsuf ’a göre farz olduğundan buna riâyet edilmeyince, namaz fâsid olur. (İbni Âbidîn)","osmanli":"اركان تعديل"},{"kelime":"TA‘LÎK","anlam":"Asma, askıya alma; vâdeye bağlama; bir işin olmasını veya olmamasını muayyen bir vakte veya hâdiseye bağlama.","kategori":"hadis","misal":"Talâkı veya köle âzâdını bir zamana veya hâdiseye ta‘lîk ederse, o iş olursa veya o zaman gelince talâk vâki ve köle azat olur. (İbni Âbidîn) “Babam kabul ederse seninle evlendim” veya “Bir ay sonra evimi sana sattım” şeklinde ta’lîk yapılarak yapılan akid sahih olmaz. (İbni Âbidîn) Va’dler sûret-i ta‘lîki iktisâ ile lâzım olur. [Vaad edilen şey, bir şeye ta‘lîk edilmişse, yerine getirilmesi lâzım olur.] Meselâ sen…","osmanli":"تعليق"},{"kelime":"TA‘LÎKÂT","anlam":"Bir kitabın izahı olarak kenarına veya ayrı olarak yazılan notlar.","kategori":"dil","osmanli":"تعليقات"},{"kelime":"TA‘RÎZ","anlam":"Üstü kapalı, dolaylı söz; bir kelimeyi iki mânâsından uzak olanı ile kullanma.","kategori":"dil","misal":"Bir kimse, diğer bir şahsın sözü geçince, onu kastederek; “Bizi şu şu ayıplardan kurtaran Allahü teâlâya hamdolsun” derse, ta’rîz yoluyla onu gıybet etmiş olur. (İbni Âbidîn) İhtiyaçtan dolayı doğru söylenemediği zaman, yani doğru söylenince bir zarar doğacaksa, ta’rîz yapmak câiz olur. Yemeğe çağrılan kişi, yemekte bir münker varsa, “Ben yedim” dese, maksadı “Ben dün yedim” olsa yalan değildir. Latife de böyledir.…","osmanli":"تعريض"},{"kelime":"TA‘VÎZ","anlam":"1.Hakkından, iddi-asından bir başkası lehine vazgeçme. 2.Kur’ân-ı kerîmde bildirilen ve Peygamberi-mizden naklen gelen duâları şifa ve koruma niyetiyle kendisine veya bir başkasına okumak veya bunları yazıp üzerinde taşımak. Resûlullah aleyhisselâm kendisine ta‘vîz yap-mıştır. (İbni Âbidîn)","kategori":"dil","misal":"(A. İvaz’dan) Ta‘vîz ile boşama sahihtir. Zevcesine “Sen bin dirheme boşsun demişse”, zevce de kabul ederse, ta’viz olur. talâk vâki olur. (İbni Âbidîn)","osmanli":"تعويض"},{"kelime":"TA‘YÎN","anlam":"1.Belli etme; kararlaştırma. 2.Akid yapılırken, malın cinsini, mikdarını ve yerini belli etmek. 3.Bir memuriyete yerleştirme, vazifelendirme, atama.","kategori":"hadis","misal":"Resûlullah aleyhisselâm Iraklılara Zât-ı Irk’ı mîkat tayin etti. (Hadîs-i şerîf-Ebû Dâvûd, Nesâî, Müsnedü Ahmed) Alış-verişte bir mal ta’yin edilirse, teayyün eder yani ta’yin edilen malın kendisini vermek, teslim etmek lâzımdır. Benzerini, hattâ iyisini alması için müşteri zorlanamaz. (Dürerü’l-Hükkâm)","osmanli":"تعيين"},{"kelime":"TA‘ZÎM","anlam":"Hürmet gösterme, üstün tutma, büyük bilme.","kategori":"dil","misal":"Saçı sakalı ağarmış Müslümana, Kur’ân-ı kerîm okuyup hükümleri ile ifrat ve tefrid-den uzak bir şekilde amel edene ve âdil idâ-reciye ta‘zim, Allahü teâlâya ta‘zim sayılır. (Hadîs-i şerîf-Ebû Dâvûd) Allahü azîmü’ş-şânın evliyâsını ve enbiyâsını ve ulemâsını, bunların sözlerini ve fıkıh kitab-larını ve fetvâları ta‘zim etmeyip tahkîr etmek, küfürdür yani îmânın gitmesine sebeb olur. (Miftahü’l-Cenne) Canlı resmi, duvara asılı ise, ta’zim ve teşebbüh (Hristiyanlara benzeme) sebebiyle mekrûhtur. Yerde ise, üzerine secde edilmedikçe namazı mekrûh etmez. Zira bunda ta’zim etme yok-tur. (İbni Âbidîn)","osmanli":"تعظيم"},{"kelime":"TA‘ZÎR","anlam":"(A. Azar’dan) “Azarlama” mânâ-sına had ve kısas dışındaki şer’î suçlardan do-layı cezalandırma.","kategori":"dil","misal":"Suç işleyeni hükûmet memuru (polis, hâkim) ta‘zîr eder. Suçu işlerken görüp, sözle men ede-mezse, her Müslümanın ta‘zîr etmeye hakkı var-dır. (İbni Âbidîn) Ta‘zîr cezaları suça ve şahsa göre çeşitlidir: Ten-bîh, ihtâr, tekdîr, döğme, habs, sürgün ve öldür-meye kadar gider. (İbni Âbidîn) Hakaret eden, söğen, rüşvet alan, Ramazan ayında özürsüz açıkça oruç yiyen ta’zîr olu-nur. (Dürer)","osmanli":"تعذير"},{"kelime":"TA‘ZİYE","anlam":"Ölen kimsenin yakınlarına başsağlığı dileme, teselli etme.","kategori":"dil","misal":"Bir din kardeşini musibette ta‘ziye eden bir mü’min yoktur ki, Allahü teâlâ ona kıyamette Cennet hullesi giydirmesin. (Hadîs-i şerîfHâkim,Tirmizî) Meyyit sahiplerinden büyük, küçük erkeklere ve yaşlı kadınlara rast gelince, ta‘ziye etmek, yani, başın sağ olsun demek gibi, sabır tavsıye etmek müstehabdır. Ta‘ziye için, “A’zamallahü ecrek ve ahsene azâek ve gafere limeyyitik” denir ki; (Allahü teâlâ, sevâbını, derecen…","osmanli":"تعزيه"},{"kelime":"TABAKÂT","anlam":"1.Tabakalar. 2.Tefsir, hadîs, kelâm, fıkıh ve tasavvuf âlimlerini derecelerine göre sıralayıp, hayatlarını ve eserlerini tetkik eden ilim; bu ilimde yazılmış kitap. Tabakâtü’l-Müfessirîn, Tabakâtü’l-Muhaddisîn, Tabakâtü’l-Fukahâ gibi isimler alır.","kategori":"tasavvuf","osmanli":"طبقات"},{"kelime":"TÂBİ‘","anlam":"İttibâ’ eden, uyan.","kategori":"dil","misal":"Ey sevgili peygamberim! Onlara de ki: “Eğer Allahü teâlâyı seviyorsanız ve Allahü teâlâ-nın da, sizi sevmesini istiyorsanız, bana tâbi olunuz! Allahü teâlâ bana tâbi olanları se-ver”. (Âl-i İmrân sûresi: 31) İki cihan saadetine kavuşmak, ancak ve yal-nız, dünya ve âhiretin efendisi olan Muham-med aleyhisselâma tâbi’ olmaya bağlıdır. O’na tâbi’ olmak için, îmân etmek ve dinimizin emir ve yasaklarını öğrenmek ve yapmak lâzımdır. (Mektûbât-ı İmâm-ı Rabbânî) Cemaat ile namaz kılarken farz olan hareket-lerde İmâma tâbi’ olmak farzdır. Vâcib olan-larda vâcibdir. Sünnetlerde tâbi olmak sünnet-tir. Tâbi’ olmak, İmâmla beraber veya sonra yapmak veya önce başlayınca, İmâmı bekle-mek demektir. (İbni Âbidîn)","osmanli":"تابع"},{"kelime":"TÂBİ‘ÎN","anlam":"Sahâbe-i kirâmı gören ve hadîs-i şerîfle medhedilen ikinci devir mensubu","kategori":"hadis","misal":"Müslümanlar. Aslı (merfu hâli), Tâbi‘ûn olup, bu şekilde söylenişi meşhur olmuştur.","osmanli":"تابعين"},{"kelime":"TABİ‘İYYE","anlam":"Kâinâtın yaratılmış olma-dığını, kendi kendine teşekkül ettiğini söyle-yen felsefî cereyan. Naturalizm.","kategori":"dil","osmanli":"طبيعيه"},{"kelime":"TABÎB-İ MÜSLİM-İ HÂZIK","anlam":"","kategori":"dil","misal":"(A) Mütehassıs Müslüman tabib. Hastanın, abdest veya gusl ile veya hareket et-mek ile hastalığının artacağı veya iyi olması uzayacağı kendi tecrübesi ile veya tabib-i müs-lim-i hâzıkın söylemesi ile anlaşılırsa, teyem-müm eder. (İbni Âbidîn)","osmanli":"حاذق مسلم طبيب"},{"kelime":"TABu","anlam":"Mukaddes olduğu için dokunulması yasaklanmış şey, söylenmesi ya da yapılması yasak olunmuş söz ve iş. Aslı Polinezya di-linde işaretlenmiş, tayin edilmiş mânâsına gelir.","kategori":"dil","osmanli":"تابو"},{"kelime":"TÂC (Taç)","anlam":"1.Serpuş, külah. 2.Saltanat sembolü olarak başa giyilen başlık. 3.Tarikatlarda şeyhlerin giydiği hususî serpuş, tâc-ı şerif.","kategori":"tasavvuf","misal":"Sarıklar, Arabların tâcıdır. Onlar sarığı terk edince, Allahü teâlâ da izzetlerini alır. (Hadîs-i şerîfEbû Nuaym)","osmanli":"تاج"},{"kelime":"TAFDÎLİYYE","anlam":"İlk devirde Hazret-i Ali taraflarlarından olup, Hazret-i Ali’yi Eshâb-ı kirâmın hepsinden üstün tutan ve bu sebeble Hazret-i Ali’nin ikaz ettiği fırka.","kategori":"dil","misal":"Bugün Şiî denince, bu anlaşılır; zira diğerleri iman dairesinden hariçtir.","osmanli":"تفضيليه"},{"kelime":"TÂHÂ SûRESİ","anlam":"131.âyetler Medîne-i Münevvere’de inmiştir.","kategori":"dil","misal":"Kur’ân-ı kerîmin yirminci sûresi. Mekke-i Mükerreme’de nâzil oldu. inmiş olup 135 ayetten ibârettir. 130 ve Huruf-i mukattaadan olan Tâ-Hâ hafleri ile başladığı için bu ismi almıştır. Bu kelime hakkında ihtilaf vardır. Umumiyetle “Tâhir ve Hâdi olan Peygamber” mânâsına Resûlullah’a hitap olduğu rivâyet edilir. Evvelâ Resûlullah aleyhisselâmın mes’ûliyetinden bahsolunur. Çektiği sıkıntılar sebebiyle tesell…","osmanli":"سى سوره طه"},{"kelime":"TAHAKKuK","anlam":"Bir şeyin hakikat oldu-ğunun ortaya çıkması, bir şeyin mâhiyetinin anlaşılması.","kategori":"dil","osmanli":"تحقق"},{"kelime":"TAHÂRET","anlam":"1.Temizlik. 2.Namazda, bedenin, elbisenin ve namaz kılacak yerin temiz olması; necâset denilen maddî pisliklerden ve hades denilen abdestsizlik, cünüplük, hayz, nifas gibi mânevî pisliklerden abdest ve gusl alarak, su yoksa, teyemmüm ederek yapılan temizlik. Allahü teâlâ da tahâret yapanları sever. (Tevbe sûresi: 108) Su ile tahâret almak, fıtrattandır (önceki peygamberlerin ve mü’minlerin âdetidir). (Hadîs-i şerîfBuhârî, Müslim) Necâsetten tahâret, bedende, elbisede ve namaz kılacak yerde pislik bulunmamaktır. (Halebî) Özür olmadıkça sağ el ile tahâretlenmemelidir. (Halebî) İki eli çolak olan tahâretlenemez. Kolları toprağa, yüzünü duvara sürerek teyemmüm eder ve namaz…","kategori":"ibadet","osmanli":"طهارت","alternatif":["taharet"]},{"kelime":"Tahâret-i Kâmile","anlam":"Tam temizlik. Abdest veya boy abdesti alınarak yapılan temizlik.","kategori":"ibadet","misal":"Özr sahibi, özre sebeb olan şeyi durduğu zaman, abdest alıp, o şey tekrar başlamadan önce, mestlerini giyse, tahâret-i kâmile ile giymiş olur.","osmanli":"كامله طهارت"},{"kelime":"TÂHİR","anlam":"Tahâret sahibi, temiz, temiz olan.","kategori":"fikih","misal":"Her temiz toprak bana mescid ve tâhir kılındı. (Hadîs-i şerîfMüsnedü İmâm-ı Ahmed)","osmanli":"طاهر"},{"kelime":"TAHKÎK","anlam":"Bir şeyin hakikatini anlama. TAHKÎKu’L-MENÂT: المنات تحقيق (A) Sebebi tahkik etme. Bir hükmün illetinin tesbitin-","kategori":"dil","misal":"den sonra, o illetin şümûlüne giren vasıfları tayin etme. Şarabın haram edilmesinin illeti sarhoş et-mesidir. Diğer içkilerde de bu illetin bulu-nup bulunmadığını anlamaya çalışmak tah-kîku’l-menâttır.","osmanli":"تحقيق"},{"kelime":"TAHKÎM","anlam":"Birisini hüküm vermek üzere hakem kılma; sağlamlaştırma.","kategori":"dil","misal":"İki kimsenin, aralarında uyuşamadıkları kul hakkı için bir veya birkaç Müslümanı tahkîm etmeleri caizdir. Hâkemin âdil ve fıkıh bilgisi olması şarttır. (İbni Âbidîn)","osmanli":"تحكيم"},{"kelime":"TAHKÎR ETMEK","anlam":"Hakîr tutma, hor görme, kötüleme, aşağılama, birine veya bir şeye söz ve hareketle hakâret etme, hürmet gereken şeyi aşağı tutma.","kategori":"dil","misal":"İnsanın îmânının gitmesine, dinden çıkmasına sebeb olan şeylerden biri de dînen ta’zim edil-mesi lâzım olan şeyleri tahkîr etmek ve tah-kîr edilmesi lâzım olan şeyleri ta’zim etmek-tir. (İbni Âbidîn)","osmanli":"تحقير"},{"kelime":"TAHLÎF","anlam":"Yerine halef bırakmak, halîfe vasîyet etmek.","kategori":"miras","osmanli":"تخليف"},{"kelime":"TAHLÎL","anlam":"(A. Hilâlden) Ayırmak; hilâlle-mek. Abdest alırken el ve ayak parmakları arasına sol, sakalın sarkan kısmının içine ise sağ elin yaş parmaklarını tarak gibi sokarak karıştırmak. (Bkz. Hilâllemek)","kategori":"ibadet","misal":"Resûlullah aleyhisselâm abdest alırken ayak parmaklarının arasını küçük parmağı ile tahlîl ederdi. (Hadîs-i şerîf-Tirmizî) Resûlullah aleyhisselâm abdest aldıklarında, bir avuç su ile çeneleri altından sakallarını tahlîl eder ve şöyle buyururlardı: “Rabbim bana böylece emretti”. (Hadîs-i şerîf-Ebû Dâvûd, Tirmizî)","osmanli":"تحليل"},{"kelime":"TAHLÎL","anlam":"Helâl kılma.","kategori":"fikih","misal":"Namazın tahlîli (yani namazdan çıkmanın helâl olması), selâm ve benzeri şeylerle olur. Hac-cın tahlîli ise traş ve tavafladır. (İbni Âbidîn) Üç talâkla boşanmış kadının, önceki kocası ile evlenmesinin tahlîli, kadının bir başka erkekle evlenip, zifafa girdikten sonra bu evliliğin talâk, fesh veya ölüm ile sona ermiş bulunması (hulle) ile olur. (Ni'met-i İslâm)","osmanli":"تحليل"},{"kelime":"TAHLİYE","anlam":"Süsleme, bezeme. Tasavvuf ehlinin yolu, ilim ve amel ile tamam olur.","kategori":"tasavvuf","misal":"İlimlerinin özü nefsin ortaya koyduğu mânileri yenmek, kötü huylardan uzaklaşmak, böylece, kalbden mâsivâyı (Allahü teâlâdan başka her şeyi) çıkararak onu Allahü teâlânın zikri ile tahliye etmektir. (Kimyâ-i Seâdet)","osmanli":"تحليه"},{"kelime":"TAHMÎD","anlam":"Hamd etme. “Elhamdü-lillah” deme.","kategori":"dil","misal":"Farz namazdan sonra otuz üç tesbih (sü-bhânallah) otuz üç tahmîd, otuz üç tekbîr (Allahü ekber) ve bir de tehlîl (Lâ ilâhe illal-lahü vahdehü lâ şerîke leh, lehül mülkü ve le-hül-hamdü yuhyî ve yümît ve hüve alâ külli şey’in kadîr) söyleyiniz. (Hadîs-i şerîf-Müslim)","osmanli":"تحميد"},{"kelime":"TAHRÎC","anlam":"Çıkarma, meydana koyma; hadîs-i şerîflerin veya ictihadların kaynağını, nasıl geldiklerini, kimlerin naklettiklerini, sıhhat derecelerini ortaya çıkarma.","kategori":"hadis","osmanli":"تخريج"},{"kelime":"TAHRÎM","anlam":"Haram kılma, haram etme; namaz, hac gibi bazı işleri haram kılan bir ibâdete başlama.","kategori":"ibadet","osmanli":"تحريم"},{"kelime":"TAHRÎM SûRESİ","anlam":"Kur’ân-ı kerîmin altmış altıncı sûresi.","kategori":"dil","misal":"Medîne-i Münevvere’de nâzil oldu. On iki âyet-i kerîmedir. Bu sûrede; bütün mü’minlerin, emri altında olanları Cehennem’e götürecek davranışlardan korumaları, âhirette kâfirlerin özür bahâne ileri sürmelerinin fayda sağlamayacağı, mü’minlerin tövbe-i nasûh (bir daha günaha dönmemek üzere kesin tövbe) etmeleri gibi konular bildirilmektedir. (Tefsir-i Mazharî, Mefâtihü’l-Gayb) Kim Tahrîm sûresini okursa, Allahü teâlâ…","osmanli":"سى سوره تحريم"},{"kelime":"TAHRÎME","anlam":"Namaza Allahü ekber diyerek başlama; iftitâh tekbîri.","kategori":"ibadet","misal":"Tahrime tekbîri farzdır. Namazın şartlarındandır. Başka kelime söylemekle olmaz. (İbni Âbidîn)","osmanli":"تحريمه"},{"kelime":"TAHRÎMEN MEKRûH","anlam":"Ha-","kategori":"fikih","misal":"rama yakın mekrûh. Âyet-i kerîme veya ha- dîs-i şerîfteki delilinden zan ile anlaşılan yasak. (Bkz. Mekrûh) Dinde vâcib olan bir emri kasden, bilerek ve özürsüz terk etmek tahrîmen mekrûhtur. Tahrîmen mekrûh işlenerek kılınan namazın iâdesi vâcibdir. Eğer unutarak işlerse, sehv secdesi yapar. (İbni Âbidîn)","osmanli":"مكروه تحريما"},{"kelime":"TAHSÎL","anlam":"(A. Husûl’den) Hâsıl etme, elde etme; ilim öğrenme.","kategori":"fikih","misal":"Edeler dâimâ tahsîl-i irfân Olalar her biri, bir kâmil insan. (Muallim Receb Efendi)","osmanli":"تحصيل"},{"kelime":"Tahsil-i İrfan","anlam":"Tasavvuf bilgilerini elde etme, öğrenme.","kategori":"tasavvuf","osmanli":"عرفان تحصيل"},{"kelime":"TAHSÎS","anlam":"(A. Hass’dan) Hususîleştirme; bir şeyi üstün tutup, tercih etme. Usûl-i fıkhda, umumî bir lafzın, bu mânâdan çıkarılıp hususî bir mânâ ve muayyen ferdlere hasredilmesi. Tahsîs eden delile muhasses denir.","kategori":"dil","misal":"Âyet-i kerîmede meâlen; “Boşanmış kadın-lar kendi kendilerine üç hayız müddeti id-det beklerler.” buyuruldu (Bakara sûresi: 228) “Ey îmân edenler! Mü’min kadınları nikâh-layıp da, kendilerine dokunmadan boşarsa-nız, artık sizin için onları bekleteceğiniz bir iddet yoktur” mealindeki âyet-i kerîme (Ahzâb sûresi: 49) ile “boşanmış kadınlar” lafzı umumî mânâsından çıkarılıp, sadece zifafa giren ka-dınlara tahsîs edilmiştir. (Kurtubî) İbrâhim aleyhisselâmı salâtta tahsîs eylemek, [namazda teşehhüdde anmak], onun şânına ta’zim içindir. Ondan sonra gelen her Peygamber, o büyük Peygambere uymakla emrolunmuştur. (Mektûbât-ı Ma’sûmiyye)","osmanli":"تخصيص"},{"kelime":"TAHVÎL","anlam":"1.Değiştirme, çevirme; havâle etme. 2.Devletin veya bir müessesenin borç temin edebilmek için çıkartıp halka sattığı fâizli sened.","kategori":"muamelat","osmanli":"تحويل"},{"kelime":"TÂİB","anlam":"Tövbe eden, günahlarına piş-man olan.","kategori":"dil","misal":"Allahü teâlâ tâibleri ve (fevâhişten yani pis-lik ve günahlardan) temizlenenleri sever. (Ba-kara sûresi: 222) Günahtan tâib, sanki hiç gü-nah işlememiş gibidir. (Hadîs-i şerîf-Hâkim, İbni Ebiddünyâ, İbni Asâkir) Tâiblerin makamı, bütün makamların en fazî-letlisi ve üstünüdür. Hakîki tâib, cenâb-ı Hak katında bütün halkın en azîzi, en kıymetlisi ve en sevgilisidir. (Miftahü’n-Necât)","osmanli":"تائب"},{"kelime":"TÂİF","anlam":"Tavâf eden; Kâbe-i Muazza-ma’nın etrafında yedi defa dönen.","kategori":"ibadet","osmanli":"طائف"},{"kelime":"TAKAS","anlam":"(A. Kass’dan) Malın mal ile mü-bâdelesi. Mukâyada satışı. Trampa.","kategori":"dil","misal":"Aynı, ayna yani gayri ez nakdeyn (altın ve gü-müşten başka ayn olan) mala mübadele etmek (değişmek) tir ki, lisan-ı Türkîde (Türkçede) trampa denilir. (Mecelle, m. 122) İki kişinin birbirinden aynı cins alacağı olsa, birbirlerine takas etseler, alacağın karşılığı ka-dar mikdar düşer. (İbni Âbidîn)","osmanli":"تقاص"},{"kelime":"TAKDÎR","anlam":"1.Ölçme, de-ğer biçme; değer verme; tâyin etme. 2.Allahü teâlânın, olacak hâdiseleri ezelde ilm-i ezelîsi ile bilip tâyin etmesi.","kategori":"hadis","misal":"(Bkz. Kazâ ve Kader) O, gece karanlığından sabahı yarıp çıka-randır. Geceyi de istirahat için, güneşi ve ayı da vakitler için bir hesâb olarak yarattı. İşte bütün bunlar azîz ve alîm olan Allahü teâlânın takdîridir. (En’âm sûresi: 96) O Allah ki, göklerin ve yerin tasarrufu hep O’nun-dur. Hiçbir çocuk edinmemiştir. Mülkünde de O’nun hiçbir ortağı yoktur. Her şeyi ya-rattı ona bir nizâm verdi. Onun mukad-derâtını takdîr buyurdu. (Furkân sûresi: 2) Dünyada olacak her şey, dünya yaratılma-dan önce ezelde Levh-i mahfûza yazılmış, takdîr edilmiştir. Bunu size bildiriyoruz ki, hayatta kaçırdığınız fırsatlar için üzülmeye-siniz ve kavuştuğunuz kazançlardan, Allah’ın gönderdiği nîmetlerden mağrur olmayası-nız, Allahü teâlâ kibirli olanları ve bencil-leri sevmez. (Hadîd sûresi: 22) İbâdet yapı-nız. Herkese ezelde takdîr edilmiş olan şeyi yapmak kolay olur. (Hadîs-i şerîf-Müslim) İnsan tedbir alır, sebeblere yapışır, takdîri bil-mez. Allah’ın takdîri, kulun tedbîri ile değiş-mez. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تقدير"},{"kelime":"TAKDÎS","anlam":"Mukaddes kılma, mukaddes sayma; hürmet gösterme; şükretme.","kategori":"ibadet","misal":"Rabbin meleklere; “Yeryüzünde bir halîfe yaratacağım” demişti. Onlar da; “Ya Rabbî! Biz seni hamd ile tesbih ve takdîs edip dururken, yeryüzünde fesat çıkaracak, kan dökecek birini mi var edeceksin?” dediler. Allahü teâlâ da onlara, “Sizin bilmediğinizi ben bilirim” buyurdu. (Bakara sûresi: 30)","osmanli":"تقديس"},{"kelime":"TAKIYYE","anlam":"(A. Vikâye’den) Korunma, sa-kınma; iki yüzlülük; sevmediği kimse ile dost geçinme. İkrâh olunan, zor kullanılan kimse-nin, hakîkatte sahip olduğu görüş ve inancını saklaması. Şia inancında, her Şiî’nin, kendi-sinden olmayanlara karış inancını saklama-sını ifade eden prensip.","kategori":"dil","misal":"Şiîler, Hazret-i Ali’nin Halîfe Hazret-i Ebû Bekr, Ömer ve Osman’a tabiiyetinin takıyye sebebiyle olduğunu; imâm meydana çıkıp harb etmeye başlayınca, takıyye yapması haram olduğunu; bunun için, Hazret-i Hüseyin’in takıyye yap-madığını söylemektedir. (Tuhfe-i İsnâ Aşeriyye)","osmanli":"تقيه"},{"kelime":"TAKKE","anlam":"Yarım küre biçiminde ince, hafif, siperliksiz başlık. Aslı, kubbe mânâsına tâk’dan tâkiyye veya başı vikâye ettiği (koru-duğu) için takıyye’dir.","kategori":"dil","misal":"Resûlullah aleyhisselâm sarığını takkesiz sa-rar, bazen sarıksız fitilli takke giyerdi. (Mevâ-hib-i Ledünniyye)","osmanli":"تاقيه"},{"kelime":"TAKLÎD","anlam":"Bir numuneye benzemeye ça-lışma. Delilini sormadan, bir başkasının sö-züne uyma. İnanılacak şeylerde düşünmeden, anlamadan, yalnız başkasından işiterek, göre-rek inanma, îmân etme. Amelde, delilini araş-tırmadan bir müctehidin ictihâdlarına (mez-hebine) uyma.","kategori":"fikih","misal":"Kur’ân-ı kerîmde; “Bilenlerden sorun” buy-ruldu. Bunun için müctehide sormak, bir mez-hebi taklit etmek, bağlanmak vâcib oldu. (İbni Âbidîn) Müctehid olmayanların dört mezhebten birini taklit etmeleri lâzımdır. Dört mezhebten birine uymayan iş bâtıldır. (Hadîka)","osmanli":"تقليد"},{"kelime":"TAKRÎR","anlam":"1.Bir yerde yeleşme, karar kılma. 2.Anlatma. 3.İkrâr etme, kabullenme.","kategori":"dil","osmanli":"تقرير"},{"kelime":"TAKSÎT","anlam":"Bir borcun muayyen zamanlarda ödenecek her bir kısmı.","kategori":"muamelat","osmanli":"تقسيط"},{"kelime":"TAKVÂ","anlam":"Allahü teâlâdan korkarak, emrettiklerini yapma ve yasaklarından kaçınma.","kategori":"akaid","misal":"Allahü teâlâ onların kalblerini takvâ ile imtihan etti. (Hucurat sûresi: 2) İman çıplaktır. Elbisesi takvâ, süsü hayâ, sermayesi fıkıh ve meyvesi ameldir. (Hadîs-i şerîfDeylemî) Resûlullah aleyhisselâm, yolda giderken kaval sesi işitti. Mübârek kulaklarını kapadı. Yanında olan, Abdullah bin Ömer’in de kapamasını emir buyurmadı. Demek ki, işitmemek takvâdır, azîmettir. İşitmek ise, fetvâdır. Âlimler arasında ihtilâf…","osmanli":"تقوى"},{"kelime":"TAKVÎM","anlam":"1.Kıymetlendirme, kıvama getirme. 2.Zamanı, astronomik hesaplara da-yanarak, gün, ay, yıl şeklinde gösteren sistem.","kategori":"dil","osmanli":"تقويم"},{"kelime":"TAKYÎD","anlam":"Kayıtlama, kayıt ve şarta bağlama; istisna getirme.","kategori":"fikih","misal":"Bir kimse «Vallâhi ben şu hurma ağacından yemeyeceğim» diye yemin etse, yemininin bozulması o ağacın meyvesinden yemesiyle takyid olunur. O ağacın meyvesinden kaynatılan pekmezi veya o ağacın dalını başka bir ağaca aşılamakla meydana gelen meyveyi yemesiyle yemini bozulmaz. (İbni Âbidîn) Bir mal satıldığı zaman, akdi muhayyerlik şartı ile takyîd etmek caizdir. (İbni Âbidîn)","osmanli":"تقييد"},{"kelime":"TALÂK","anlam":"Çözmek. Nikâh bağını çözme, evliliğe son verme, zevcesini boşama.","kategori":"dil","misal":"Ey Peygamber (ve O’na ümmet olanlar)! Kadınlara talâk vermek istediğinizde, onlara (âdet hâllerinden) temizlendiklerinde talâk verin ve iddeti (üç hayzdan temizlenme müddetini) sayın. Rabbiniz olan Allah’tan korkun. (Talâk sûresi: 1) Eğer size itâat ediyorlarsa, artık talâk için yol aramayın. (Nisâ sûresi: 34) Allahü teâlânın izin verip de yapılmasından hoşnûd olmadığı, beğenmediği şey talâktır. (Hadîs-i şerîfEbû Dâ…","osmanli":"طلاق","alternatif":["talak"],"baglamlar":[{"baglam":"ric'î","anlam":"Kocanın iddet içinde karısına dönebileceği boşama; bir veya iki talâk."},{"baglam":"bâin","anlam":"Kocanın doğrudan dönemeyeceği, yeni nikâh gerektiren boşama."},{"baglam":"selâse","anlam":"Üç talâk; kadın başka biriyle evlenip boşanmadıkça eski kocasına dönemez."}]},{"kelime":"Talâk-ı Bâin","anlam":"Ayırıcı boşanma. Ev-","kategori":"dil","misal":"liliği hemen sona erdiren boşanma. Zifaf olmamış ise veya bedel ile boşanılmış ise yâhud koca kinâî lafızlarla ama boşama niyetiyle boşamış ise ya da üçüncü defa ric’î talâkla boşamış ise veya elbette, gibi çokluk veya şiddet bildiren bir söz kullanılmış ise yâhud boşanma mahkeme kararıyla olmuş ise, bu hâllerin her birisinde talâk-ı bâinden söz edilir. (İbni Âbidîn) Talâk-ı bâinde verilen talâk bir veya iki ise, ay…","osmanli":"بائن طلاق"},{"kelime":"Talâk-ı Ric’î","anlam":"“Dönülebilir boşanma” mânâsına, zifafa girdiği zevcesine hitâben, bir ivaza (bedele) bağlı olmaksızın ve “Sen benden bâinsin” gibi beynûnete (ayrılığa) delâlet eden bir sıfatla sıfatlanmamış ve bir şeye benzetilmemiş sarîh (açık) lafızlarla veya işaretlerle v…","kategori":"dil","misal":"Talâk-ı ric’îde koca, kadının iddeti içinde, söz ile veya fiilen eski nikâhına rücû‘ edebilir (dönebilir). Evliliği devam eder. Şâhid lâzım olmaz ise de, iki âdil şâhide haber vermesi müstehâb olur. (İbni Âbidîn) Ric’î talâkta, eğer erkek hanımına dönmezse, nikâh; iddet (üç hayz yani âdet) müddeti bitince bozulur. (Mecmua-i Zühdiyye)","osmanli":"رجعى طلاق"},{"kelime":"Talâk-ı Selâse","anlam":"Zevcin, zevcesini üçüncü defa veya bir defada üç kez boşaması.","kategori":"dil","misal":"Talâk-ı selâse ile boşanan kadın, bir başkası ile evlenip, zifafa girerek bu evlilik boşanma veya ölüm ile sona ermedikçe, eski kocası bununla evlenemez. (İbni Âbidîn)","osmanli":"ثلاثه طلاق"},{"kelime":"TALÂK SûRESİ","anlam":"Kur’ân-ı kerî-min altmış beşinci sûresi.","kategori":"dil","misal":"On iki âyet-i kerîme olup, Medîne-i Münevve-re’de nâzil oldu. Boşanma konularından bah-settiği için bu adı aldı. “Sûretü’n-Nisâi’l-Kusrâ” (Kısa Nisa sûresi) da denir. Sûrenin başında İslâm âile hukûkunun boşanma konusundaki hükümleri, sonunda da, Allahü teâlânın bil-dirdiği hak yoldan ayrılan eski kavimlerin uğradıkları cezâlar ve Muhammed aleyhis-selâma inanıp hayırlı işler yapanlara verile-cek âhiret nîmetleri bildirilmektedir. (Mefâti-hü’l-Gayb, Kurtubî)","osmanli":"سى سوره طلاق"},{"kelime":"TALEB","anlam":"İstemek, aramak.","kategori":"dil","misal":"Her Müslüman kadın ve erkeğe ilim talep etmek (ilmihâlini öğrenmek) farzdır. (Ha-dîs-i şerîf-İbn-i Mâce) Taleb, kavuşmanın müjdecisidir. Yanıp yakılmak da, kavuşmanın başlangıcı demektir. Büyükler-den biri buyuruyor ki: “Vermek istemeseydi, ta-lep vermezdi.” (Mektûbât-ı İmâm-ı Rabbânî) İlim meclislerinde aradım kıldım taleb, İlim geride kaldı, ille edeb, ille edeb. (Yûnus Emre)","osmanli":"طلب"},{"kelime":"TÂLİB","anlam":"Taleb eden, isteyen; ilim öğ-renmeye çalışan kimse, talebe.","kategori":"dil","misal":"Tâlib sâdık olunca, zikr ve teveccüh olmasa dahi yalnız ihlâsı ve muhabbeti ile ilerler. (Mektû-bât-ı Ma’sûmiyye)","osmanli":"طالب"},{"kelime":"TALMûD","anlam":"1.Öğrenme, talim etme. 2.Ya-hudilikte Hazret-i Mûsâ’ya verilen sözlü emir-lerin toplandığı mukaddes metin.","kategori":"dil","misal":"Yahudilere göre; Mûsâ aleyhisselâm, Tûr-i Sînâ’da verilen sözlü ilahî emirleri, nesilden ne-sile intikal ederek, mîlâdın II. asrında Yahuda ha-Nassi tarafından bir kitâp hâline getirilmiş; Mişnâ denen bu kitaba, III. asırda Kudüs ve VI. asırda Bâbil’de Gamâra adlı birer şerh ya-zılmış; Mişna ve bu iki Gamâra’ya beraberce Talmûd adı verilmiştir. Kudüs nüshasına Ku-düs Talmûdu; Bâbil nüshasına Bâbil Talmûdu denmiştir. Talmûd, çeşitli hikâyelerden başka, Tevrat’ın tefsiri ile şer’î hükümler ve izahların-dan teşekkül eder. (Dıyâü’l-Kulûb)","osmanli":"تلمود"},{"kelime":"TAM FENÂ","anlam":"Allahü teâlâdan başka her şeyi unutma, mutlak fenâ.","kategori":"akaid","misal":"(Bkz. Fenâ)","osmanli":"فنا تام"},{"kelime":"TAM MÜLK","anlam":"Bir kimsenin başkasının hakkı bulunmayan ve kullanılması mümkün olan meşru malı.","kategori":"muamelat","misal":"Tam mülk olan malın zekâtını vermek farzdır. (İbni Âbidîn) Efendisiyle muayyen bir bedel ödeyerek azatlanmak üzere anlaşan mükâteb köle zekât vermez. Her ne kadar çalışıp kazandığı mülkü olsa da bu mülk tam değildir. (İbni Âbidîn)","osmanli":"ملك تام"},{"kelime":"TAM RÂBITA","anlam":"Kendisini, rehberi olan velînin şeklinde, kıyafetinde görerek yapılan râbıta.","kategori":"tasavvuf","misal":"Râbıta-i telebbüsiyye. (Bkz. Râbıta)","osmanli":"رابطه تام"},{"kelime":"TAM ŞEHÎD","anlam":"Allah yolunda haksız yere öldürülen ve hemen vefat eden Müslüman.","kategori":"akaid","misal":"Tam şehîd, dünyada yıkanmaz, kefene sarılmaz. Kefen mikdarından fazla olan elbisesi soyulup, çamaşırı ile defnolunur. Cenâze namazı Hanefî mezhebinde kılınır. Şâfiî mezhebinde kılınmaz. Âhirette de şehîd sevâbına kavuşurlar. (İbni Âbidîn)","osmanli":"شهيد تام"},{"kelime":"TAM TEMİZLİK","anlam":"Sıhhatli bir kadının âdet zamanından sonra başlayan, on beş gün veya daha fazla devam eden temizlik.","kategori":"osmanli","misal":"İki hayz (âdet) arasında tam temizlik bulunması lâzımdır. (İbni Âbidîn)","osmanli":"تميزلك تام"},{"kelime":"TANRI","anlam":"Ma’bûd, ilâh, tapınılan şey. Allahü teâlâ, İslâmiyet’in bildirdiği isimler ile çağrılır ve onlar ile zikir olunur. Bunlardan başka isimler ile çağırmağa, zikir etmeğe, İs-lâmiyet izin vermemiştir. Allahü teâlâya tanrı demeğe izin yoktur. Allah ismini kullanmak is-temeyip, bunun yerine, tanrı demek çok büyük ve çirkin suç olur. (Seâdet-i Ebediyye)","kategori":"akaid","misal":"Birdir Allah andan artık tanrı yok. (Mevlid-i Süleyman Çelebi)","osmanli":"تاݣری"},{"kelime":"TAPu","anlam":"Gayrımenkul mülkiyet senedi.","kategori":"hadis","osmanli":"تاﭘو"},{"kelime":"TARAFEYN","anlam":"1.“İki taraf ” mânâsına akdin veya dâvânın iki tarafı.","kategori":"dil","misal":"Tarafeynden lisân bilmeyen kimesnenin ifâde-sini terceme için mahkemede mevsûk ve mü’te-men [sağlam ve güvenilir] tercümân bulundu-rulur. (Mecelle, m. 1825) Fıkıhta İmâm Ebû Hanife ile talebesi İmâm Muhammed için kullanılan tabir.","osmanli":"طرفين"},{"kelime":"TÂRÎH","anlam":"1.İnsanlık hayatının zaman içindeki akışı. 2.Geçmişe ait hâdiselerin vesikalar ışığında bilinen kısmı. 3.Bir hâdisenin meydana geldiği zaman.","kategori":"hadis","osmanli":"تاريخ"},{"kelime":"TARÎK","anlam":"Yol, cadde; meslek.","kategori":"dil","osmanli":"طريق"},{"kelime":"TARÎKAT","anlam":"İnsanları kemâle getirip Allahü teâlâya kavuşturan tasavvuf yolu.","kategori":"tasavvuf","misal":"Tarîkatların çeşitli isimler alması, başka başka olmalarından değildir. Aynı mürşidin talebeleri, birbirlerini tanımak ve mürşidleriyle tanınmak için bulundukları yola mürşidlerinin ismini vermişlerdir. (Mekâtib-i Şerife)","osmanli":"طريقت"},{"kelime":"TASARRuF","anlam":"1.Sarf etme; bir şeyi dilediği gibi kullanma. 2.İdare etme, hükmetme.","kategori":"dil","misal":"Bir kimsenin mülkünde onun izni olmaksızın âhar bir kimsenin tasarruf etmesi câ’iz değildir. (Mecelle, madde: 96) Ra’iye yani teb’a üzerine tasarruf maslahata menûttur. (Mecelle, madde: 58)","osmanli":"تصرف"},{"kelime":"TASAVVuF (Tesavvuf)","anlam":"Kalbi kötü huylardan temizleyip, iyi huylarla doldurmak suretiyle imanı vicdanîleştirme, böylece Allahü teâlâyı tanıma ve O’na kavuşma yollarını gösteren usûl.","kategori":"tasavvuf","misal":"İmâm-ı Mâlik buyurdu ki: “Fıkh öğrenmeyip, tasavvuf ile uğraşan, zındık olur. Fıkh öğrenip tasavvuftan haberi olmayan bid’at sahibi olur. Her ikisini edinen, hakîkate varır” (Merecü’l-Bahreyn)","osmanli":"تصوف"},{"kelime":"TASDÎK","anlam":"(A. Sıdk’tan) Doğrulama, ka-bul etme, inanma.","kategori":"dil","misal":"Kendisinden önceki kitabları tasdik eden Hak Kitab’ı Allahü teâlâ sana indirdi. (Âl-i İmrân sûresi: 3) Ya Rabbi! Kim bana ina-nır, beni tasdik eder ve senden bana gele-nin (kitabın) hak olduğuna şehâdet ederse, sen onun malını da evlâdını da az ver ve ru-hunu da erken kabzet. Ya Rabbi ona sana kavuşmayı sevdir ve ölümünü de ta’cil et! (Hadîs-i şerîf-Beyhekî) Tüccar, zekât memuruna, senenin tamamlan-madığını veya zekâtını daha evvel başka bir zekât memuruna verdiğini yeminiyle söylerse, tasdik olunur. (İbni Âbidîn)","osmanli":"تصديق"},{"kelime":"TASFİYE","anlam":"(A. Saf ’dan) Saflaştırma, arıtma; parlatma.","kategori":"dil","misal":"Kalbin tasfiyesi, dinimizin emir ve yasaklarına uymakla ve sünnetlere yapışmakla ve bid‘atler-den kaçmakla ve nefse tatlı gelen şeylerden sa-kınmakla olur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تصفيه"},{"kelime":"TASHÎH","anlam":"Düzeltme. Âkıl ve bâliğ erkek ve kadının birinci vazifesi, i’tikâdını Ehl-i sünnet âlimlerinin bildirdiği şekilde tashîh etmesi ve bunlara uygun olarak yaşamasıdır.","kategori":"hadis","misal":"(Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تصحيح"},{"kelime":"TASNÎF","anlam":"Sınıflara ayırma, sıralama; bir mevzuda daha öncekilerin söylediklerini kendine mahsus bir usûlle kitap hâline getirme, kitap yazma.","kategori":"fikih","misal":"İmâm-ı A’zâm, İmâm-ı Gazâlî, İmâm-ı Rabbânî gibi büyük İslâm âlimlerinin eserleri tasniftir. (Abdullah-ı Dehlevî)","osmanli":"تصنيف"},{"kelime":"TASVÎR","anlam":"(A. Sûret’ten) Resim yapma; bir şeyi resim yapar gibi bütün cihetleriyle an-latma; suret çıkarma, kopyalama.","kategori":"dil","misal":"Bir kimse dünyada bir canlıyı tasvir etse, kıya-mette ona can vermesi için teklif olunarak ta-zib olunur. Hâlbuki o ona can veremez. (Ha-dîs-i şerîf-Nesaî) Resûlullah aleyhisselâm, Hazret-i Aişe’nin oda-sında üzerinde tasvirler bulunan bir perde gö-rünce birden rengi değişti. Eliyle çekip çıkardı ve; “Kıyâmet günü en çok azap görenler, Al-lahü teâlânın yarattığına benzeterek tasvîr yapanlardır” buyurdu. (Hadîs-i şerîf-Buhârî, Müslim)","osmanli":"تصوير"},{"kelime":"TATLÎK","anlam":"Talâk verme, boşama.","kategori":"dil","misal":"(Bkz. Talâk)","osmanli":"تطليق"},{"kelime":"TAVÂF","anlam":"Bir şeyin etrafında dönme; Kâbe-i Muazzama etrafında ibâdet niyetiyle yedi defa dönme.","kategori":"ibadet","misal":"İşte kim o beyti (Kâbe’yi) hac veya umre niyetiyle ziyaret ederse, bunları güzelce tavâf etmesinde üzerine bir beis yoktur. (Bakara sûresi: 58) Allahü teâlâ şu Mescid-i Haram’dakilere her gün ve her gece yüz yirmi rahmet indirir. Altmışı Kâbe’yi tavaf edenlere, kırkı namaz kılanlara, yirmisi de Kâbe’yi seyredenleredir. (Hadîs-i şerîfTaberânî) Haccın farzlarından üçüncüsü; dördü farz, üçü vâcib olmak üzere yedi kere…","osmanli":"طواف","alternatif":["tavaf"]},{"kelime":"Tavâf-ı Kudûm","anlam":"Mekke-i Mükerre-me’ye varınca, yapılan ilk tavâf.","kategori":"ibadet","misal":"Tavâf-ı Kudûm, âfâkîler için yani dışardan gelenler için sünnettir. (Ni’met-i İslâm)","osmanli":"قدوم طواف"},{"kelime":"Tavâf-ı Sadr (Sader)","anlam":"Hac esnâsında cemrelerin taşlanması bittikten sonra Mina’dan Mekke’ye inildiğinde yapılan tavâf.","kategori":"ibadet","misal":"Buna Tavâf-ı vedâ da denilir. Hac vazifeleri bununla sona erer. Âfâkî olan yani Mîkât denilen yerden daha uzak memleketlerin hacılarının Mekke’den ayrılacağı gün, Tavâf-ı sadr yapmaları haccın vâciblerindendir. Âdet gören kadına bu tavâf vâcib değildir. (İbni Âbidîn)","osmanli":"صدر طواف"},{"kelime":"Tavâf-ı Ziyaret","anlam":"Hacıların Arafât’tan indikten sonra, Kurban bayramı günlerinde yapılan farz tavâf.","kategori":"ibadet","misal":"Buna ifâda tavâfı da denir. Her hac edene, Tavâf-ı ziyareti Arafât’tan sonra yapmak farzdır. Onun için diğer bir ismi de Tavâf-ı rükündür. Haccın farzlarındandır. (Ni’met-i İslâm)","osmanli":"زيارت طواف"},{"kelime":"TAVÂŞÎ","anlam":"Hadım, haremağası.","kategori":"dil","osmanli":"طواشى"},{"kelime":"TAVLA","anlam":"İki kısma ayrılmış bir tahta üzerinde, zar atıp taşlarını hareket ettirmek suretiyle oynanan oyun. Nerd.","kategori":"dil","misal":"Tavla oynayan sanki elini domuz kanına bu-laştırmış gibidir. (Hadîs-i şerîf-Müslim, Ebû Dâvûd, Müsnedü İmâm-ı Ahmed) Kim tavla oynarsa Allah ve Resûlune isyan etmiştir. (Hadîs-i şerîf-Ebû Dâvûd, İbn-i Mâce, Mâlik, Müsnedü İmâm-ı Ahmed)","osmanli":"طاوله"},{"kelime":"TAYFûRİYYE","anlam":"Hicrî III. asırda İran’da yaşamış velî Bâyezîd Bistâmî’nin tasavvuftaki yolu.","kategori":"tasavvuf","misal":"Esas ismi Tayfur olduğu için bu isimle anılmıştır.","osmanli":"طيفوريه"},{"kelime":"TAYYİB","anlam":"Hoş, iyi, güzel, temiz.","kategori":"dil","misal":"Ey îmân edenler! Size rızık olarak verdiğimiz şeylerin tayyib olanlarından yiyin! (Bakara sûresi: 172) Ey îmân edenler! Kazandıkları-nızın ve sizin için yerden çıkardıklarımızın en tayyib olanından, Allah yolunda harcayın (zekât ve sadaka verin). (Bakara sûresi: 267) Yetimlere (rüşdüne gelince, âkıl bâliğ olunca) mallarını verin. Tayyib olanı habis olana de-ğişmeyin. Onların mallarını kendi malları-nıza katarak yemeyin. Çünki bu, muhakkak büyük bir günahtır. (Nisâ sûresi: 2) Tarlayı abdestsiz sürmek, tohumunu abdestsiz ekmek; rızkın bereketini, tayyib olmasını gide-rir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"طيب"},{"kelime":"TAZMÎN","anlam":"Sebeb olunan zarar ve ziyânı ödeme.","kategori":"fikih","misal":"Gasp, hırsızlık, rüşvet, fâsid akid gibi sebeblerle eline geçen başkasına ait malı aynen iade etmek; mevcut değilse, tazmin etmek vâcibdir. (İbni Âbidîn)","osmanli":"تضمين"},{"kelime":"TE‘ALLuK","anlam":"(Bkz.Ta‘alluk)","kategori":"dil","osmanli":"تعلق"},{"kelime":"TE‘ASSuB","anlam":"(Bkz. Ta‘assûb)","kategori":"dil","osmanli":"تعصب"},{"kelime":"TE‘ÂTÎ","anlam":"Karşılıklı alıp verme.","kategori":"dil","osmanli":"تعاطى"},{"kelime":"TE‘AYYÜN","anlam":"Ta’yîn edilme; alışverişte söz kesilirken ta’yin (belli) edilen malın, hep ayn olarak kalması, deyn (borç) hâline dönmemesi.","kategori":"muamelat","misal":"Te‘ayyün eden malın kendisini vermek lâzımdır. Benzerini hattâ daha iyisini alması için müşteri zorlanamaz. (Hamza Efendi Risâlesi)","osmanli":"تعين"},{"kelime":"Te‘ayyün-i Evvel","anlam":"İlm-i ilâhîde ilk te‘ayyün, zuhûr, ortaya çıkış. Aktâbın (kutb","kategori":"dil","misal":"mertebesindeki sôfilerin) ulaşabileceği en üst nokta. Te‘ayyün-i hubbî.","osmanli":"اول تعين"},{"kelime":"TE’DÎB","anlam":"1.Edeblendirme, terbiye etme; (Bkz. Edeb) Kişinin çocuğunu te’dîb etmesi, sadaka vermesinden daha hayırlıdır. 2.Suçluyu cezâlandırma.","kategori":"tasavvuf","misal":"(Hadîs-i şerîfTirmizî) Rabbim beni en güzel bir edeb ile te’dîb etti. (Hadîs-i şerîfMektûbât-ı İmâm-ı Rabbânî)","osmanli":"تأديب"},{"kelime":"TE’HÎR","anlam":"(A. Âhar’dan) Geciktirmek, geri bırakmak.","kategori":"dil","misal":"Öğle namazını te’hîr ediniz. Zira, o sıcağın şiddeti Cehennem’in nefesindendir. (Hadîs-i şerîf-Buhârî) Kim güç vaziyetteki borçlusu-nun borcunu te’hîr eder veya bir kısmını afv ederse, Allahü teâlâ onu kıyamet gününde, kendi gölgesinden başka bir gölge olmadığı günde, arşının gölgesi altında gölgelendirir. (Hadîs-i şerîf-Tirmizî) İyi, hayırlı işler akla gelince bunu te’hîr etme-den hemen yerine getirmelidir. Zîrâ insanın nefsi ve şeytân bu hayırlı işi yaptırmamak için araya binbir sebeb koyar. (Berîka)","osmanli":"تأخير"},{"kelime":"TE’LÎF","anlam":"1.Hangi ilimde olursa olsun, birçok meselelerin içinde toplandığı bir eser yazma. 2.Bir araya getirme, uzlaştırma, uyuşturma.","kategori":"dil","misal":"Bunu yapana müellif denir. Allahü teâla, kendi kitabından başka hiç bir kitabın hatasız olmasını takdir buyurmamış-tır. Kendi kitabı için ise, “Ona önünden ve ar-kasından bâtıl gelemez!” buyurmuştur. Başka kitaplarda hata ve kusur olabilir. Çünki onları insan te’lîf etmiştir. (İbni Âbidîn) Eşbah’da bir yerde “Menfaat sağlayan her borç haramdır. Bunun için rehin alınan evde, rehin alan kişinin oturması, rehnedenin izniyle de olsa mekrûhtur” diyor. Başka yerde ise “Rehin verenin izni olmaksızın, alan kişinin ondan is-tifade etmesi mekrûhtur” diye yazıyor. Şu hâlde istifade başta şart koşulursa fâiz, koşulmaz da sonradan izin verilirse mübah olur. Böylece iki ifade arasında bir te’lîf yapılmış olur. Bu da bir-birine zıt kalmalarından iyidir. (İbni Âbidîn)","osmanli":"تأليف"},{"kelime":"TE’MÎN","anlam":"1.Emniyet altına alma; bir kimseyi bir şey üzerine emîn kılma; emân verme. 2.Sigorta akdi.","kategori":"dil","osmanli":"تأمين"},{"kelime":"TE’MÎNÂT","anlam":"Bir şeyin güvenilir oldu-ğunu tesbit etmek üzere verilen şey veya söy-lenen söz. Garanti verme. (Bkz. Emân)","kategori":"ibadet","osmanli":"تأمينات"},{"kelime":"TEBÂREKE SûRESİ","anlam":"Kur’ân-ı kerîmin altmış yedinci sûresi.","kategori":"dil","misal":"Mülk sûresi)","osmanli":"سى سوره تبارك"},{"kelime":"TEBCÎL","anlam":"Büyütme, ululama, yüceltme, ta’zim etme.","kategori":"dil","misal":"Müslüman olmayan birini tebcîl etmek için selâm verenin îmânı gider. (İbni Âbidîn)","osmanli":"تبجيل"},{"kelime":"TEBE‘-İ TÂBİ‘ÎN","anlam":"Resûlullah aleyhisselâmın Eshâbını gören ve Tâbiîn denen zâtları görmekle şereflenenler.","kategori":"dil","misal":"Resûlullah efendimiz tarafından övülmüştür. (Mevlânâ Hâlid-i Bağdâdî)","osmanli":"تابعين تبأ"},{"kelime":"TEBERRu‘","anlam":"Bir şeyi karşılık beklemek-sizin verme. Bağış, bağışlama, hibe.","kategori":"muamelat","misal":"Teberru‘ ancak kabz [teslim alma] ile tamam olur. Meselâ bir adam birine bir şey hibe etse, kable’l-kabz [kabzdan evvel] hibe tamam ol-maz. (Mecelle, madde: 57)","osmanli":"تبرع"},{"kelime":"TEBERRÜK","anlam":"Bereketlenme, uğurlu sayma.","kategori":"ibadet","misal":"Resûlullah aleyhisselâm havuzlara adam gönderip su getirtir; ondan içer ve Müslümanların ellerinin değdiği işte teberrük addederlerdi. (Hadîs-i şerîfEbû Nuaym)","osmanli":"تبرك"},{"kelime":"TEBESSÜM","anlam":"Gülümseme, kendinin işit-meyeceği şekilde sessiz gülme.","kategori":"dil","misal":"Kahkaha şeytândan; tebessüm Allah’tandır. (Hadîs-i şerîf-Taberânî) Resûlullah aleyhis-selâm konuşurken tebessüm ederlerdi. (Ha-dîs-i şerîf-Müsnedü İmâm-ı Ahmed) Rükû’ ve secdeleri olan namazda kahkaha ile gülmek, namazı da abdesti de bozar. Na-mazda tebessüm, namazı da abdesti de boz-maz. (Halebî)","osmanli":"تبسم"},{"kelime":"TEBKÎR","anlam":"Erken davranmak; câmiye erken gelmek.","kategori":"ibadet","misal":"Hâcetlerinizi talepte tebkîr ediniz. Ey Allah’ım! Ümmetim için tebkîr edenlerin işlerini bereketli kıl! (Hadîs-i şerîfHatîb) Tebkîr, ümmetimin fıkarasının haccıdır. (Hadîs-i şerîfDeylemî) Cum‘a günü namaza tebkîr, sünnettir. (İbni Âbidîn)","osmanli":"تبكير"},{"kelime":"TEBLÎĞ","anlam":"(A. Bülûğ’dan) Eriştirme, ulaş-tırma, nakletme, bildirme. Peygamberlerin sıfatlarından.","kategori":"akaid","misal":"Onlar (Peygamberler) Allahü teâlânın insan-lara gönderdiklerini tebliğ ederler. O’ndan korkarlar. Allah’tan başka kimseden kork-mazlar. (Ahzâb sûresi: 39) Resûlullah aley-hisselâm Veda Haccı sırasında bir hutbe irad ettiler. En son “Acaba tebliğ ettim mi?” bu-yurdular. Cemaat bir ağızdan, “Evet!” dediler. Resûlullah: üç defa “Ya Rab, şâhid ol!” bu-yurdu. (Hadîs-i şerîf-Buhârî, Müslim)","osmanli":"تبليغ"},{"kelime":"TEBRÎK","anlam":"(A. Bereket’ten) Bir şeyin be-reketli, kutlu ve mübarek olmasını temenni etme, kutlama.","kategori":"dil","misal":"Sizden biri bir din kardeşinin nefsinde veya malında hoşuna giden bir şeyi görünce, onu tebrik etsin ve Bârekallah desin. Zira nazar haktır. (Hadîs-i şerîf-Taberânî)","osmanli":"تبريك"},{"kelime":"TEBŞÎR","anlam":"Müjdeleme, sevin-dirici bir haber ulaştırma.","kategori":"dil","misal":"Mü’minler ve sâlihlere altlarından ırmak-lar akan cennetler olduğunu tebşîr eyle! (Bakara sûresi: 25) Karanlıkta câmilere yü-rümekte olanları, kıyamette nur ile tebşîr eyle! (Hadîs-i şerîf-Tirmizî, Taberânî, İbni Nec-câr) İnsanları tebşîr et ki; “Lâ ilâhe illallah vahdehu lâ şerîke leh” diyene Cennet vâcib olur. (Hadîs-i şerîf-Nesaî) Eğer ölüyü ağzı açık, sanki gülüyor, yüzü gü-lümsüyor, gözü dahi kırpık gibi görür isen; bil-miş ol ki, o kimse, âhirette kavuşacağı sürûr ile tebşîr olunmuştur. (Dürretü’l-Fâhire)","osmanli":"تبشير"},{"kelime":"TEBYÎN","anlam":"Beyan etme, açıklama, izah etme, gerçeği ortaya koyma.","kategori":"muamelat","misal":"Biz bu zikri (Kur’ân-ı kerîmi) insanlara tebyîn edesin diye indirdik. (Nahl sûresi: 44)","osmanli":"تبيين"},{"kelime":"TEBZÎR","anlam":"İsraf, malı aklın ve dinin mü-nasip görmediği yerlere dağıtma.","kategori":"dil","misal":"Akrabâya, yoksula ve yolda kalmışa hak-kını ver. Malını tebzîr etme. Çünki tebzîr edenler, şeytânların kardeşleridir. Şeytân ise Rabbine çok nankördür. (İsrâ sûresi: 26, 27) Tebzîr’in haram olduğu muhakkaktır. Kalbin hastalığıdır. Kötü bir huydur. Dinimizin; hasis-liği, israftan daha çok kötülemesi, israfın cimri-lik kadar kötü olmadığını göstermez. Hasisliğin daha çok kötülenmesi, insanların çoğu, yara-tılıştan, mal biriktirmeği sevdiği içindir. (Bir-givî Vasîyetnâmesi)","osmanli":"تبذير"},{"kelime":"TECDÎD-İ ÎMÂN","anlam":"İmanı yenileme. Bilerek veya bilmeyerek küfre düşüren bir sözü söylemek veya bir işi yapmak yâhud böyle bir şeyi yapmış olma ihtimâli üzerine, “Lâ ilâhe illallah Muhammedün Resûlullah” sözünü; mânâsını bilerek ve inanarak söyleyip, îmânını yenileme, tâzeleme.","kategori":"akaid","misal":"“Lâ ilâhe illallah” diyerek tecdîd-i îmân yapınız. (Hadîs-i şerîfHâkim) Kadın ve erkek her Müslümanın, her gün sabah ve akşam tecdîd-i îmân duâsını okuması lâzımdır. Zevc ile zevcenin (hanımın) birlikte okumaları iyi olur. (Birgivî)","osmanli":"ايمان تجديد"},{"kelime":"TECDÎD-İ NİKÂH","anlam":"Nikâhı yenileme. Bilerek veya bilmeyerek küfre düşüren bir sözü söylemek veya bir işi yapmak yâhud böyle bir şeyi yapmış olma ihtimâli varsa, tövbe ve istiğfâr ile tecdid-i iman ve iki şâhid yanında tecdid-i nikâh lâzım gelir.","kategori":"dil","misal":"Bir kadın zevcinden ayrılmak için -Allah saklasın- mürted olsa, hapis ve dövme ile İslâmiyet’e dönmesine cebr olunur. Başka bir kimse ile evlenemez. Fakat evvelki zevcine az bir mehirle tecdid-i nikâha cebrolunur. (İbni Âbidîn) Tecdîd-i îmân ve tecdîd-i nikâh duâsı şöyledir: “Allahümme innî ürîdü en üceddidelîmâne vennikâha tecdîden bikavli lâ ilâhe illallah Muhammedün Resûlullah.” Câmide cemâatin çok olduğu bir nam…","osmanli":"نكاح تجديد"},{"kelime":"TECELLÎ","anlam":"Görünme, zuhur etme, be-lirme. Allahü teâlânın zâtının ve isimlerinin insanlarda ve tabiatta zuhûru.","kategori":"akaid","misal":"Zât-ı ilâhînin (Allahü teâlânın) tecellîsi bu dün-yada yalnız Muhammed aleyhisselâma nasip oldu. Başkalarına ise âhirette nasip olacağı bil-dirildi. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تجلى"},{"kelime":"Tecellî-i Sıfat","anlam":"Allahü teâlânın sıfatlarının tecellîsi.","kategori":"akaid","osmanli":"صفات تجلئ"},{"kelime":"Tecellî-i Zât","anlam":"İsim ve sıfatlar araya girmeden sâdece zât-ı ilâhînin tecellî etmesi. Tecellî-i zât, Peygamberlerin sonuncusuna (Mu-hammed aleyhisselâma) mahsûstur. O’nun ya-nısıra başka peygamberlere ve O’na çok uyan bu ümmetin evliyâsında da hâsıl olur. Başka pey-gamberlerin ümmetlerine nasip olmaz. Bunun için bu ümmet, ümmetlerin hayırlısı olmuştur. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"ذات تجلئ"},{"kelime":"TECEMMÜL","anlam":"Cemâl sahibi olma, süs-lenme, güzelleşme.","kategori":"dil","misal":"Tecemmül etmek, müstehâbdır. Helâl şeylerle zînetlenmek mubâhtır. İmâm-ı A’zâm Ebû Hanîfe dört yüz altın kıymetinde cübbe gi-yerdi. (İbni Âbidîn)","osmanli":"تجمل"},{"kelime":"TECESSÜS","anlam":"Gizlice gözetleme, insan-ların gizli hâllerini anlamaya çalışma.","kategori":"dil","misal":"Ey îmân edenler! Zannın bir çoğundan ka-çının. Çünki bazı zan (vardır ki) günahtır. Tecessüs etmeyiniz. Biriniz diğerinizi gıy-bet etmesin. (Hucurât sûresi: 12) Sû-i zan etmeyiniz. Sû-i zan, yanlış karar vermeye sebeb olur. Tecessüs etmeyiniz. Münâkaşa etmeyiniz, birbirinizi çekiştirmeyiniz, kar-deş gibi sevişiniz. Müslüman Müslümanın kardeşidir. Ona zulmetmez, yardım eder. Onu kendinden aşağı görmez. (Hadîs-i şerîf-Buhârî, Müslim) Tecessüs etmek harâmdır. (Berîka)","osmanli":"تجسس"},{"kelime":"TECHÎZ","anlam":"1.Lüzumlu hazırlıkları yapma, donatma. 2.Vefat eden kimsenin yıkanmasın-dan defnine kadar yapılması lâzım gelen iş-ler.","kategori":"ibadet","misal":"Gasli, tekfîni (kefenlenmesi), tabuta kon-ması, musallâya götürülmesi, cenâze namazı kılındıktan sonra da kabre götürülmesi (teş-yii) ve defni. Meyyitin techîzi farz-ı kifâyedir. Müslümanların bazısı bu vazifeleri yerine getirirse, diğerlerinin üzerinden bu vazifeleri yapmak düşer. (Berîka) Meyyitin bıraktığı maldan ilk önce onun techîz ve tekfînine harcanır. Bu harcama işinde israf-tan ve cimrilikten kaçınılır. (Mevkûfât)","osmanli":"تجهيز"},{"kelime":"TECVÎD","anlam":"1.Güzel yapmak. 2.Kur’ân-ı kerîmi harflerin mahreclerine (çıkış yerlerine) ve sıfatlarına uygun olarak okumak ve bunu anlatan ilim.","kategori":"dil","misal":"Din adamlarının insanlara yapamayacakları fetvâları bildirmeleri de fitneye sebeb olur. Köylüye ve ihtiyâra, tecvîdsiz namaz kılınmaz demek de böyledir. Çünki bunlar artık öğrenemez ve namazı büsbütün bırakırlar. Hâlbuki, tecvîdsiz namazın câiz olduğuna fetvâ verenler vardır. Bu fetvâ zayıf ise de namazın terk edilmesinden iyidir. (Berîka)","osmanli":"تجويد"},{"kelime":"TEDÂVÎ","anlam":"(A. Devâ’dan) Deva verme, iyi etme, iyileştirme, hastalığı gidermek için ilaç kullanma ve gerekli tedbirleri alma.","kategori":"dil","misal":"Ey Allah’ın kulları, tedavi olunuz. (Hadîs-i şerîf-Ebû Dâvûd,Taberânî)","osmanli":"تداوى"},{"kelime":"TEDBÎR","anlam":"1.Bir şeyi elde edecek veya önleyecek yol, çâre; bir işin sonunu düşüne-rek hareket etmek. 2.Kölesini ölümünden sonrası için âzâd etme.","kategori":"dil","misal":"Tedbîr gibi akıl, güzel huy gibi asâlet ola-maz. (Hadîs-i şerîf-İbn-i Mâce) İnsan bu âlemde, sebeblere yapışmakla vazife-lidir. Allahü teâlânın kendisi için takdîr buyur-duğu şeylerin başına geleceğine ve sakınmanın, tedbîrin, kaderde olacak (ezelde yazılan) şey-lere mâni olamayacağına inanması da insanın vazifesidir. (Mefâtihü’l-Gayb) Tez olma teemmül kıl, Her hâle tahammül kıl, Allah’a tevekkül kıl, Tedbîri bozar takdîr. (İbni Kemâl) Tedbîr-i Menzil: منـزيل تدبير (A) İnsanın ço-luk-çocuğuna karşı hareketlerinin nasıl ola- cağı ve ev idâresine dair husûslardan bahse- den ilim. Ev idaresi âdâbı.","osmanli":"تدبير"},{"kelime":"TEFÂHÜR","anlam":"Öğünme. Biliniz ki, dünya hayâtı; elbette la’b (oyun) ve lehv (eğlence) ve zînet (süslenmek) ve tefâhür ve malı, parayı ve evlâdı çoğaltmaktır.","kategori":"tasavvuf","misal":"Tefâhür haramdır. (Ahlâk-ı A’lâî)","osmanli":"تفاخر"},{"kelime":"TEFEKKÜR","anlam":"1.Fikretme, ibret alacak ve faydalanacak şekilde derin düşünme. 2.Ta-savvufta, maddî dünyaya ait bütün varlıklar-dan el çekip içe dönerek ilahî hakikati anla-maya çalışma.","kategori":"dil","misal":"Onlar (o selîm akıl sahipleri öyle insanlardır ki) ayakta iken, otururken, yanları üstünde (yatar) iken (hep) Allah’ı hatırlayıp anarlar ve göklerin, yerin yaratılışı hakkında tefekkür ederler. (Bu tefekkür edenler şöyle derler;) “Ey Rabbimiz! Sen bunları boşuna yaratmadın. Sen (bundan) pâk ve münezzehsin. Bizi ate-şin azâbından koru.” (Âl-i İmrân sûresi: 191) İşte biz tefekkür eden bir kavim (topluluk) için âyetleri (delilleri) böyle açıklarız. (A’râf sûresi: 24) Bir lahza tefekkür, bir geceyi ihyâ etmekten hayırlıdır. (Hadîs-i şerîf-Ebû Şeyh) Her şey hakkında tefekkür edin. Fakat Al-lahü teâlânın zâtı hususunda tefekkür etme-yin. Zira, Arş-ı kürsi ile yedinci kat gök ara-sında yedibin perde vardır. Ve Allah’ın şanı (manevî makamı) bunların üstündedir. (Ha-dîs-i şerîf-Beyhekî, Ebû Şeyh, İbni Ebiddünyâ) İnsanın günahlarını tefekkür etmesi ve bunlara tövbe etmesi, tâatlarını, ibâdetlerini düşünüp bunlara da şükretmesi lâzımdır. Mahlûklardaki (yaratılmışlardaki) ve kendi bedenindeki ince sanatları, düzenleri, birbirlerine olan bağlılık-larını tefekkür ederek de Allahü teâlânın bü-yüklüğünü anlaması lâzımdır. Aklı başında olan kimsenin tefekkür vazifesini hiç ihmâl et-memesi lâzımdır. Allahü teâlâ hiçbir şeyi bâtıl yani boş, faydasız yaratmamıştır. İnsanların anlayamadıkları, göremedikleri faydalar, an-layabildiklerinden kat kat daha çoktur. Tefek-kür dört türlü olur demişlerdir. Allahü teâlâ-nın mahlûklarındaki güzel sanatları, faydaları tefekkür etmek, O’na inanmaya ve sevmeye se-beb olur. O’nun vâd ettiği sevabları tefekkür et-mek, ibâdet yapmaya sebeb olur. O’nun haber verdiği azapları tefekkür etmek, O’ndan kork-maya, kimseye kötülük yapmamaya sebeb olur. O’nun nîmetlerine, ihsânlarına karşılık nefsine uyarak günah işlediğini, gaflet içinde yaşadığını tefekkür etmek, Allah’tan hayâ etmeye, utan-maya sebeb olur. Allahü teâlâ yerlerde ve gök-lerde bulunan mahlûkları düşünerek ibret alan-ları sever. (Berîka)","osmanli":"تفكر"},{"kelime":"TEFRÎK","anlam":"1.Ayırma. 2.Evliliğin mahkeme kararıyla sona erdirilmesi.","kategori":"osmanli","misal":"Kocası, innet (iktidarsızlık) veya delilik, cüzzam gibi beraber yaşamayı imkânsız kılan bir hastalığa dûçâr olmuş kadın, mahkemeye müracaat ederek tefrîk isteyebilir. (İbni Âbidîn) Şâfiî mezhebinde buna ilâveten nafakadan acz; Mâlikî ve Hanbelî mezheblerinde kötü muamele ve mefkudluk (terk, gâiplik) da tefrîk sebebidir. (elFıkhu ale’l-Mezâhibi’l-Erbaa)","osmanli":"تفريق"},{"kelime":"TEFRÎT","anlam":"(A. Fart’tan) Gevşek ve ihmalkâr davranma. İfrat’ın zıddı.","kategori":"dil","osmanli":"تفريط"},{"kelime":"TEFSÎR","anlam":"1.Örtülü, kapalı olan şeyi ortaya çıkarmak, açmak, beyân etmek. 2.Kur’ân-ı kerîm âyetlerindeki murâd-ı ilâhîyi, Allahü teâlânın murâdını anlamak.","kategori":"dil","misal":"Kur’ân-ı kerîmi kendi reyi ile tefsir eden, isabet etse de muhakkak hatâ etmiştir. (Hadîs-i şerîfTirmizî) Kim Kur’ân-ı kerîmi kendi reyi ile tefsir ederse, ateşten oturacağı yeri hazırlasın. (Hadîs-i şerîfTirmizî) Bize tefsir kitaplarına göre amel etmek emredilmedi. Fıkıh kitaplarına tâbi olmamız emredildi. (Berîka)","osmanli":"تفسير"},{"kelime":"TEFVÎZ (Tefvîd)","anlam":"Ismarlama, havâle etme; sebeblere yapıştıktan sonra bir işin neticesini Allahü teâlâya havâle etme.","kategori":"akaid","misal":"Sen Hakk’a tevekkül kıl, Tefvîz et ve rahat bul, Sabreyle ve râzı ol, Mevlâ görelim n’eyler, N’eylerse güzel eyler. (Tevfiznâmeİbrâhim Hakkı Erzurûmî)","osmanli":"تفويض"},{"kelime":"TEGÂBÜN SûRESİ","anlam":"Kur’ân-ı kerîmin altmış dördüncü sûresi.","kategori":"dil","misal":"Medîne-i Münevvere’de nâzil oldu. On sekiz âyet-i kerîmedir. Dokuzuncu âyette geçen ve aldanma mânâsına gelen Tegâbün kelimesi sûreye isim olmuştur. Sûrede; insanların mü’min ve kâfir olarak iki kısma ayrıldığı, mal ve çolukçocuğun bir imtihan olduğu bildirilmektedir. (İbn-i Atıyye, Râzî) Kim Tegâbün sûresini okursa, ansızın ölüm ondan uzak olur. (Hadîs-i şerîfBeydâvî)","osmanli":"سى سوره تغابن"},{"kelime":"TEGANNÎ","anlam":"Musiki perdelerine (no-talara) uyarak, elhân ile, ahenk ile okumak, söylemek.","kategori":"dil","misal":"Tegannî ile okumak, mânâyı bozarsa, namazı da bozar. Mânâ değişmezse, namaz bozulmaz. Tegannî, kelimenin mânâsını değiştirmezse ve harfler, iki harf kadar uzamazsa, yalnız sesi gü-zelleştirip kırâeti süslerse, câiz olur. Hattâ na-maz içinde de, namaz dışında da, müstehab olur. (İbni Âbidîn)","osmanli":"تغنى"},{"kelime":"TEHAFFuZ","anlam":"(A. Hıfz’dan) Koruma, sa-kınma, kendini muhafaza etme; barınma.","kategori":"dil","osmanli":"تحفظ"},{"kelime":"TEHÂFÜT (Tahâfüt)","anlam":"1.Tutarsızlık. 2.İmâm Gazâlî’nin felsefecilere reddiyesi ile başlayan ve felsefecilerin tutarsızlıklarını mevzu edinen eserlerin yazıldığı ilim geleneği.","kategori":"ibadet","osmanli":"تهافت"},{"kelime":"TEHAVVÜL","anlam":"Değişme. Bir hâlden başka bir hâle geçme.","kategori":"dil","osmanli":"تحول"},{"kelime":"TEHECCÜD","anlam":"1.Uyuyup uyanmak.","kategori":"dil","misal":"Uy-kuyu terk etmek.","osmanli":"تهجد"},{"kelime":"TEHİYYETÜ’L-MESCİD","anlam":"“Mescidi selâmlama” mânâsına bir mescide girince, oturmadan önce, mescidin sahibine, yani Allahü teâlâya ta’zim için kılınan iki rek‘at nâfile namaz.","kategori":"ibadet","misal":"Şüphesiz her mescidin bir tehiyyesi vardır. O da iki rek’at namazdır. (Hadîs-i şerîfİbni Hibbân) Câmiye girenin tehiyyetü’l-mescid olarak iki rek‘at namaz kılması, söz birliği ile sünnettir. Sesli Kur’ân-ı kerîm okunuyorsa tehiyye-tü’l-mescid namazı kılınmaz. (Uyûnü’l-Besâir) Mescide girdiği esnâda kılınan farz veya sünnet ile tehiyyetü’l-mescid sevâbı dahi hâsıl olduğu gibi, abdesti müteâkib kılınan farz veya sünne…","osmanli":"المسجد تحية"},{"kelime":"TEHLÎL","anlam":"“Lâ ilâhe illallah” (Allahü teâlâdan başka ilâh yoktur) sözünü söylemek.","kategori":"akaid","misal":"Fısk meclislerinde, alay edenler arasında tesbih, tehlîl, zikr, tekbîr, hadîs ve benzerlerini okumak günahtır. (Halebî)","osmanli":"تهليل"},{"kelime":"TEKÂ‘ÜD","anlam":"Emekli olma; ihtiyarlık, hastalık gibi bir sebeble vazifeyi bırakıp muayyen bir ücrete hak kazanma.","kategori":"akaid","osmanli":"تقاعد"},{"kelime":"TEKBÎR","anlam":"1.Ululama, büyükleme. 2.Allahü teâlâyı yüceltmek, noksan sıfatlardan, şirkten, yarattıklarına benzemekten tenzîh etmek; bu mânâda “Allahü ekber” sözünü söylemek. şekilde şükür yapılamayacağını ifâde etmektedir. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"akaid","osmanli":"تكبير"},{"kelime":"Tekbîr-i Teşrîk","anlam":"Ramazan ve Kurban bayramlarında okunan “Allahü ekber, Allahü ekber.","kategori":"ibadet","misal":"Lâ ilâhe illallahü vallahü ekber, Allahü ekber ve lillâhilhamd” sözü. Teşrîk tekbîri. Teşrîk, “et kurutma” mânâsına gelir ve Kurban Bayramı günlerini ifade eder. Arefe günü sabah namazından Kurban bayramının dördüncü günü ikindi namazı sonrasına kadar farz namazlardan selâm verince hemen tekbîr-i teşrîk söylemek vâcibdir. (İbni Âbidîn) (Bkz. Teşrîk Tekbîri)","osmanli":"تشريق تكبير"},{"kelime":"Tekbîr-i Zevâid","anlam":"Bayram namazlarında birinci rek‘atte Sübhâneke’den sonra üç, ikinci rek‘atte zamm-ı sûreyi okuyup rükû‘a gitmeden önce de üç kere olmak üzere alınan altı vâcib tekbir.","kategori":"ibadet","misal":"Bayram namazında birinci rek’atte Sübhâne-ke’den sonra eller üç defâ kulaklara kaldırılıp, tekbîr-i zevâid alınır; birinci ve ikincide, iki yana uzatılır, üçüncüde göbek altına bağlanır. İkinci rek’atte ise, Fâtiha ve zamm-ı sûre okunduktan sonra, rükû‘a gitmeden, yine üç tekbîr-i zevâid alınır. İki el yine kulaklara kaldırılır, eller üçünde de yanlara bırakılır. Namaza âit olan dördüncü tekbirde elleri kulaklara ka…","osmanli":"زوائد تكبير"},{"kelime":"TEKDÎR","anlam":"Azarlama, azar; ta’zîr için verilen cezâlardan.","kategori":"dil","misal":"Nush ile yola gelmeyeni etmeli tekdîr, Tekdîr ile uslanmayanın hakkı kötektir. (Ziya Paşa)","osmanli":"تكدير"},{"kelime":"TEKEBBÜR","anlam":"Kibirlenme, kibir sahibi olma, büyüklenme, kendini büyük gösterme. Tekebbürden kaçının! (Hadîs-i şerîf-İbni Adiyy)","kategori":"hadis","misal":"Aklı başında olan, kendini ve Rabbini tanıyan kimse, hiç tekebbür edebilir mi? (Berîka)","osmanli":"تكبر"},{"kelime":"TEKFÎN","anlam":"Kefenleme.","kategori":"dil","misal":"Resûlullah aleyhisselâm üç parça elbise ile tekfîn edildi. (Hadîs-i şerîf-Buhârî, Müslim, Ebû Dâvûd, Tirmizî, Nesaî) Her kim karde-şini kefenlerse, tekfîn işini ihtimâmlı yap-sın. (Hadîs-i şerîf-Müslim, Ebû Dâvûd, Tir-mizî, Nesaî)","osmanli":"تكفين"},{"kelime":"TEKFÎR","anlam":"Bir kimseye küfr isnâd etme, kâfir demek.","kategori":"hadis","misal":"“Lâ ilâhe illallah” ehlinden dilinizi tutun. Onları bir günah sebebiyle tekfîr etmeyin. Kim “Lâ ilâhe illallah” ehlini tekfîr ederse onun kendisi küfre daha yakındır. (Hadîs-i şerîfTaberânî) Bir kimse Müslüman kardeşini tekfir etse o (söz) ikisinden birine döner. [Yani söylenen bu söze müstehak değilse, söyleyene döner.] (Hadîs-i şerîfMüslim) Bir kimsede küfre sebeb olan iş veya söz görülünce, hemen tekfîr etmemelid…","osmanli":"تكفير"},{"kelime":"TEKKE","anlam":"Tasavvufun öğretildiği; tasavvuf yolcusunun terbiye gördüğü; tarikat mensublarının beraberce âyin yaptığı mekân.","kategori":"tasavvuf","misal":"İslâm tarihinde ilk tekke, Ebû Hâşim elKûfî adına hicrî ikinci asır sonlarına doğru, Şam yakınlarındaki Remle’de tesis edilmiştir. (Hilyetü’l-EvliyâEbû Nuaym)","osmanli":"تكه"},{"kelime":"TEKLİF","anlam":"Külfet yükleme; vergi. Bir işin yapılmasını isteme. Şâri’nin bir işin yapılmasını veya yapılmamasını istemesi. Tahyîr’in zıddı. Teklîf kat’i ise, bu işin hükmü farz, vâcib ve haram; kat’i değilse sünnet, müstehab, men-dub ve mekrûh olabilir. Eğer bir şeyin yapıl-masını isteyiş kesin olursa, teklifî hüküm “vâ-cib”, kesin olmazsa “mendup” olur.","kategori":"fikih","osmanli":"تكليف"},{"kelime":"TEKMÎL","anlam":"1.Kemâle getirme, olgunlaş-tırma, tamamlama. 2.Tasavvufta başkalarını yetiştirebilmek derecesine ulaşma makamı.","kategori":"dil","misal":"Tasavvuf yolunda nihâyete kavuştuktan sonra geriye dönenler, irşâd (öğretme, yetiştirme) ve tekmîl makamına kavuşur. Allahü teâlânın kullarını da’vet için, onlara faydalı olmak için Hak’tan halka dönerler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تكميل"},{"kelime":"TEKMÎLE","anlam":"1.Tamamla-yıcı. 2.Bir kitaba tamamlayıcı, ilâve olarak yazılan kitap.","kategori":"dil","misal":"(A. Kemâl’den)","osmanli":"تكميله"},{"kelime":"TEKVÎN","anlam":"1.Meydana ge-tirme, yaratma. 2.Her şeyi yaratan, yoktan var eden, kendisinden gayrı yaratıcı olmayan mânâsına Allahü teâlânın subûtî sıfatlarından. 3.Tevrat’ı meydana getiren beş kitabdan birincisi.","kategori":"akaid","misal":"Allahü teâlâ, ilim gibi, kudret gibi bütün sıfat-larından kullarına biraz ihsân buyurmuştur. Fakat yalnız üç sıfatı kendine mahsûstur. Bu üç sıfatı Kibriyâ (büyüklük), Ganî olmak (baş-kalarına muhtaç olmamak, her şey O’na muh-taç olmak) ve Tekvîn sıfatlarıdır.” (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تكوين"},{"kelime":"TEKZÎB","anlam":"Yalanlama. Tas-dik’in zıddı.","kategori":"dil","misal":"Ey insanlar ve cinler! Öyleyken, Rabbinizin nimetlerinden hangisini tekzîb edebilirsiniz? (Rahmân sûresi: 13) Âhir zamanda, ümme-tim için en korktuğum üç şey: Müneccim-lere inanmak; kaderi tekzib ve sultanın zül-müdür. (Hadîs-i şerîf-Taberânî)","osmanli":"تكذيب"},{"kelime":"TEL‘ÎN","anlam":"Lânetleme, lânet etme; bir kimsenin Allahü teâlânın rahmetinden uzak olmasını dileme.","kategori":"akaid","misal":"(Bkz. Lânet)","osmanli":"تلعين"},{"kelime":"TELBİYE","anlam":"“Lebbeyk, Allâhümme lebbeyk, lebbeyke lâ şerîke leke lebbeyk.","kategori":"akaid","misal":"Cibril bana geldi ve; “Allah sana eshabına telbiye esnasında seslerini yükseltmelerini bildirmeni emrediyor. Zira o, haccın şiarındandır.” dedi. (Hadîs-i şerîfEbû Dâvûd, Tirmizî, İbn-i Mâce, Nesaî, Müsnedü Ahmed, Hâkim) Erkekler hac ve umre için ihrâmda bulunduğu müddetçe, arkadaşları ile karşılaştığı vakitte, toplantı yerlerinde, tepelere yükselip, vadilere indikte, vâsıtaya biniş ve inişlerde yüksek sesle telbiye…","osmanli":"تلبيه"},{"kelime":"TELFÎK","anlam":"Mezheblerin çeşitli hükümlerini, yapılan amelin bu mezheblerden hiç birine göre sahih olmayacak şekilde bir araya getirme.","kategori":"fikih","misal":"Bir ibâdeti veya bir işi yaparken, birkaç mezhebi telfîk etmek, dört mezhebten çıkmak ve beşinci bir mezheb meydana getirmek olur. Telfîk edilmiş hüküm bâtıldır. (Hülâsatü’t-Tahkîk) Eli kanadığı için Şâfiî’yi taklit eden birisi, sonra kadına değdiği için de Hanefî’yi taklit ederse, telfîk yapmış olur. Zira bu kimsenin o iki mezhebe göre de abdesti yoktur. (İbni Âbidîn)","osmanli":"تلفيق"},{"kelime":"TELHÎS","anlam":"Hülâsa etme, özetleme; bir metni mânâsında eksiklik olmaksızın hülâsa etme.","kategori":"dil","osmanli":"تلخيص"},{"kelime":"TELKÎN","anlam":"1.Bir şeyi zihinde yerleştirme, bir fikri aşılama, kulağına koyma, hatırlatma. 2.Cenazenin defnedilmesinden sonra Allahü teâlâdan meyyitin af ve bağışlanması için duâ ve niyazda bulunma, kabirde sorulacak sual-lerin cevaplarını hatırlatma. Definden sonra kabre ve kıbleye karşı ayakta durarak telkîn vermek sünnettir. (İbni Âbidîn) Telkînin mânâsı şudur: “Ey falan kişi! Bil ki bu kabir senin dünyaya âit son, âhirete âit ilk ko-nağındır. Artık bu fânî dünyadan ayrılıp son-suz âleme göçtün. Şimdi sana Münker ve Ne-kir adında iki melek gelecek. Korkma, mahzûn olma. Onlar Allahü teâlâ tarafından gönderil-miştir. Münker ve Nekir sana; “Rabbin kim? Peygamberin kim? Dinin nedir? Kitâbın ne-dir? Kıblen neresidir? İ’tikâdda mezhebin ne-dir?” diye sorarlar. Onlara; “Rabbim Allahü teâlâ. Peygamberim Muhammed aleyhisselâm. Dinim İslâm. Kitâbım Kur’ân-ı kerîm. Kıblem, Kâbe-i şerîftir. İ’tikâdda mezhebim, Ehl-i sün-net ve’l-cemâattir.” diye cevap ver. Bil ki, ölüm haktır, kabir haktır, Münker ve Nekirin sual-leri haktır, haşr, neşr, hesap, mîzân (terâzî), sırât haktır. Mü’minler için hazırlanmış olan Cennet ve inanmayanlar için hazırlanan Ce-hennem haktır, gerçektir. Yâ Rabbî! Bu kişiyi doğru cevap vermeye kâdir eyle. Eğer sâlih, iyi bir kimse ise, ona ihsânını ziyâde eyle, art-tır. Eğer günahkâr ise, onu mağfiret eyle, affet. Âmîn.” (Miftahü’l-Cenne)","kategori":"hadis","misal":"Ölülerinize kelime-i tevhidi telkîn ediniz. (Hadîs-i şerîf-İbn-i Mâce, Deylemî, Taberânî, Ebû Nuaym, Hâkim) Hastalığım artınca iyâdetime yani hatırımı sor-maya gelen din kardeşlerim ihlas sûresini oku-mayı telkîn etsinler. (Birgivî Vasîyetnâmesi)","osmanli":"تلقين"},{"kelime":"TEMELLûK","anlam":"İfrât derecede tevâzû; yaltaklanma, dalkavukluk.","kategori":"tasavvuf","misal":"Temellûk, Müslüman ahlâkından değildir. (Hadîs-i şerîfİbni Adiy) Temellûk ancak üstâda ve tabibe karşı câizdir. Başkalarına karşı câiz değildir. (Berîka)","osmanli":"تملق"},{"kelime":"TEMELLÜK","anlam":"Mülk edinme. Müslümana şarabın temlik ve temellükü yasak edilmiştir.","kategori":"muamelat","misal":"(İbni Âbidîn)","osmanli":"تملك"},{"kelime":"TEMENNÎ","anlam":"Bir şeyin tahakkukunu bütün kalbiyle isteme; rica, istek.","kategori":"tasavvuf","misal":"Temennî insanı tembelliğe götürür. Recâ (sebebine yapıştıktan sonra o işin olmasını beklemek) ise, çalışmaya sebeb olur. (Berîka)","osmanli":"تمنى"},{"kelime":"TEMETTu‘","anlam":"1.Faydalanma, istifâde etme; kâr etme, kazanç temin etme. 2.Hac günlerinden önce umre için ihrâma girip ve bu umre yapıldıktan sonra memleketine dönmeden, tekrar ihrâma girerek yapılan hac. Hacc-ı Temettû‘. (Bkz. Hac) Temettû’ hac sevâbı, ifrâd haccından çoktur. (İbni Âbidîn)","kategori":"akaid","osmanli":"تمتع"},{"kelime":"TEMÎME","anlam":"Nazar değmemesi, musibet-ten korunmak için umumiyetle boyna asılan ip, boncuk, muska, hamâil gibi şey, nazarlık, nazar boncuğu; muska.","kategori":"dil","misal":"Sabî çocukların kollarına ve beşiklerine temîme takmakta bir mahzur yoktur. (Hindiyye)","osmanli":"تميمه"},{"kelime":"TEMKÎN","anlam":"1.Ağırbaşlılık; ihtiyatlılık; sakınma. 2.Tasavvufta değişmek-ten, hâlden hâle geçmekten kurtulup, huzur ve sükûna kavuşma.","kategori":"tasavvuf","misal":"(A. Mekân’dan) Kalb, telvinden (değişik hâllerden), hâllere kul olmaktan kurtulmuş ve temkîn makamına ye-tişmiş ise, hâller artık nefse gelir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تمكين"},{"kelime":"TEMLÎK","anlam":"Bir mal veya hakkı bir başkasına mülk olarak verme, devretme.","kategori":"muamelat","misal":"Zekât, malı Müslüman fakire temlik etmekle olur. (İbni Âbidîn) Erkek, talâk hakkını zevcesine temlik ettiği haberi zevceye ulaşınca, zevce, haberi aldığı mecliste kendini boşayabilir. (Mecmua-i Zühdiyye)","osmanli":"تمليك"},{"kelime":"TEMYÎZ","anlam":"1.Herhangi birkaç şeyi veya doğruyla yanlışı, iyiyle kötüyü birbirinden ayırt etme. 2.Bir kimsenin, satın alınan malın mülk olaca-ğını ve satınca mülkten çıkacağını anlar hâlde bulunması.","kategori":"dil","misal":"Mebi’in ma’lûmiyyeti sâ’irinden temyîz edecek hâl ve vasfını beyân ile hâsıl olur. Meselâ şu ka-dar kile kızılca buğdayı yâhud filân hudûd ile mahdûd olan arsa diye satılsa mebi’ ma’lûm ve bey’i sahih olur. (Mecelle, m. 201) Temyîz edene mümeyyiz denir. Sagîr-i gayri mümeyyiz; bey’ ve şirâyı fehm et-meyen yani mülkiyeti bey’in sâlib ve şirânın câ-lib olduğunu bilmeyen ve onda beş aldanmak gibi gabn-i fâhiş olduğu zâhir olan bir gabni, gabn-i yesîrden temyîz ve tefrîk eylemeyen ço-cuk olup bunları temyîz eden çocuğa sagîr-i mümeyyiz denilir. (Mecelle, m. 943)","osmanli":"تمييز"},{"kelime":"TENÂSÜH","anlam":"Ölen kimsenin ruhunun başka bir insanın veya hayvanın bedenine geçtiğine dâir inanç.","kategori":"akaid","misal":"Reenkarnasyon. Tenâsüh, îmânı giderir, Tenâsüh vardır diyen, İslâm dinine inanmamış olur. Rûhların, cisim şekil alarak iş görmelerini, bazı kimseler tenâsüh sanmıştır. Bu aslâ tenâsüh değildir. Yani ruhlar, başka bir bedene girmemiştir. Bu hâl, birçok câhillerin ayaklarının kaymasına sebeb olmuştur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تناسخ"},{"kelime":"TENBÎH","anlam":"1.Îkâz, uyarma, uyarı. 2.Ta’zîr için verilen cezalardan.","kategori":"dil","misal":"(Bkz. Ta’zîr)","osmanli":"تنبيه"},{"kelime":"TENEŞİR","anlam":"Ölünün yıkandığı masa şek-lindeki dört ayaklı uzun tahta zemin, serîr. Tenşûy.","kategori":"dil","osmanli":"تنشير"},{"kelime":"TENKÎH","anlam":"Nikâhlama, evlendirme.","kategori":"dil","misal":"İçinizdeki bekârları tenkîh ediniz. Fakir iseler, Allah onları fazl-u kereminden zengin eder. (Nûr sûresi: 32)","osmanli":"تنكيح"},{"kelime":"TENZÎH","anlam":"Kusur ve ayıplardan uzak tutma, temizleme; Allahü teâlâyı, şânına lâyık olmayan şeylerden, her türlü eksik ve noksanlıklardan uzak tutma; Sübhânallah zikrini söyleme.","kategori":"akaid","osmanli":"تنـزيه"},{"kelime":"TENZÎHEN MEKRûH","anlam":"Yasak olmasına kuvvetli, açık bir delil, sened bulunmayıp, yapılması iyi olmayan şeyler.","kategori":"hadis","misal":"Dinde müekked, kuvvetli olmayan sünnetleri ve müstehabları yapmamak tenzîhen mekrûhtur. Tenzîhen mekrûhu işleyene azap olmaz. Fakat sevabdan mahrum kalır. (İbni Âbidîn)","osmanli":"مكروه تنـزيها"},{"kelime":"TENZÎL","anlam":"(A. Nüzûl’den) İndirme.","kategori":"dil","misal":"İnzâl kelimesinde bir defada indirmek mânâsı bulunduğu hâlde, tenzîlde azar azar indirme mânâsı vardır. Kur’ân-ı kerîm Levh-i Mahfûz’dan Beytü’l-izze (Kur’ân-ı kerîmin bir bütün hâlinde indirildiği ve dünya semâsında bulunduğu ri-vâyet edilen yer) denilen makama topluca in-dirilmiştir ki, buna inzâl, buradan Peygamber efendimize vahy yoluyla parça parça indiril-miştir ki, buna da tenzîl denir. Kur’ân-ı kerîm, Allahü teâlânın tenzîlidir. (Yâsîn sûresi: 5)","osmanli":"تنـزيل"},{"kelime":"TERAKKÎ","anlam":"Her çeşit mânevî ilerleme. Rûh da, melekler de terakkî etmez. Yaratıldığı mertebede kalır. Rûh bu beden ile birleşince, te-rakkî etmek hâssasını kazanır. (Ahlâk-ı A’lâî)","kategori":"akaid","osmanli":"ترقى"},{"kelime":"TERÂVİH","anlam":"Ramazân ayında yatsı namazından sonra kılınan yirmi rek‘atlik nâfile namaz.","kategori":"ibadet","misal":"çokluk hâlidir. Her dört rek‘atte bir dinlenildiği için bu ismi almıştır. Şüphesiz Allahü teâlâ Ramazan orucunu farz kıldı. Ben de size terâvihi sünnet kıldım. Öyle ise kim ki, iman ederek ve sevabını kesin olarak Allah’tan bekleyerek gündüzünü oruçlu, gecesini de ibâdetle geçirirse, bu geçmiş günahlarına keffaret olur. (Hadîs-i şerîfİbn-i Mâce, Nesaî) Erkeklerin ve kadınların terâvih namazı kılması sünnet-i müekked…","osmanli":"تراويح"},{"kelime":"TERBÎ‘","anlam":"1.Dörtleme. 2.Tabu-tun kolundan el ile tutarak dört kişinin taşı-ması. 3.Mezârın dört köşe ve düz yapılması. 4.Her kamerî ayın yedinci gecesi.","kategori":"hadis","misal":"(A. Rub’dan) Kabrin üzerine terbi‘ yapmak Hanefî’de sünnet değildir. Müsennem yani balık sırtı gibi yuvar-lak yapmak sünnettir. (Halebî) Ayın yarım görünmesi ve böylece dört safha ile ayın ta-mamlanması sebebiyle bu ismi almıştır.","osmanli":"تربيع"},{"kelime":"TERBİYE","anlam":"Yetiştirme, eğitme; hafif ceza verme.","kategori":"dil","misal":"Bir kimsenin evlâdını terbiye etmesi, onun bir sa‘ sadaka vermesinden hayırlıdır. (Ha-dîs-i şerîf-Tirmizî) Atları terbiye edin. (Ha-dîs-i şerîf-İbni Adiy) Çocuğun terbiyesine çok dikkat etmelidir. Onun kötü arkadaşlarla düşüp kalkmasına mâni ol-malıdır. Kötü arkadaş, çocuğun edeb ve terbi-yesini bozar. (Kimyâ-i Seâdet)","osmanli":"تربيه"},{"kelime":"TERCEME (Tercüme)","anlam":"Bir sözü bir dilden başka bir dile çevirmek.","kategori":"dil","misal":"Secde âyetinin Farsça tercümesini işitene secde ayeti olduğu haber verilince secde etmesi vâcib olur. (İbni Âbidîn) Şâhidin söylediklerini tercümede âdil bir kişinin ifadesiyle iktifâ edilir. (İbni Âbidîn)","osmanli":"ترجمه"},{"kelime":"TERCÎ‘","anlam":"1.Geri çevirme, döndürme. 2.Sesi yükseltip alçaltarak ve tekrarlayarak okuma.","kategori":"dil","misal":"Resûlullah aleyhisselâm kıraatı uzatırlardı (med yaparlardı) fakat tercî‘ (sesi titretme) yapmazlardı. (Hadîs-i şerîf-Taberânî) Kur’ân-ı kerîmi ve ezânı tercî‘ ile okumak tenzî-hen mekrûhtur. Âyet-i kerîmelerin ve ezânın keli-meleri değiştirilmezse mübâh olur. (İbni Âbidîn)","osmanli":"ترجيع"},{"kelime":"TERCÎH","anlam":"1.Bir şeyi, diğerine göre daha üstün, iyi ve mühim addetme. 2.Birbi-rine zıt gibi görünen iki hadîs-i şerîf veya iki ictihaddan, muayyen vasıfları taşıması sebe-biyle birisini hükme esas alma.","kategori":"hadis","osmanli":"ترجيح"},{"kelime":"Tercîh Ehli","anlam":"Muhtelif ictihadlar-dan, gelişinin daha sağlam oluşu, delilinin kuvveti ve zaruret veya örf sebebiyle birini di-ğerine üstün tutarak hükme esas almaya sala-hiyetli âlimler. (Bkz. Eshâb-ı Tercîh)","kategori":"fikih","osmanli":"اهلى ترجيح"},{"kelime":"TERCÎHuN BİLÂ MÜRECCİH","anlam":"","kategori":"dil","misal":"(A) Tercih sebebi olmadığı hâlde bir şeyi diğe-rine tercîh etmek yani üstün tutmak. Âlemin yaratıcısının iki olduğu kabûl edilse, her iki ilâhın, bütün mümkinâta kudretleri-nin kâfî gelmesi, müsâvî olur. Çünki, kudreti kâfî olmak, imkânın, yani var ve yok etmenin sebebidir. Var ve yok olabilmek, ya’nî mümkin olmak ise, bütün varlıklar arasında müşterek bir vasıfdır. Buna göre, âlemde hiçbir varlığın olmaması îcâb eder. Çünki mevcûd olacak, ya-ratılacak şeyin vücûdunda, yaratılmasında, iki ilâhdan her ikisi de te’sîr etmez veya biri tesir edip, diğeri tesir etmez. Her iki sûrette de ter-cîh-i bilâ müreccih olması lâzım gelir. Tercîhun bilâ müreccih ise bâtıldır. (Beydâvî)","osmanli":"مرجح بلا ترجيح"},{"kelime":"TEREKE (Terîke)","anlam":"Ölenin geriye bıraktığı mal, mülk, eşya vs.","kategori":"miras","misal":"Vefât eden kimsenin terekesinden sırasıyla şu işler yapılır: 1) Techîz ve tekfîni (yıkama, kefenleme ve defn masrafları) 2) Borçlarının ödenmesi; 3) Kalan malın üçte birinden meşru vasîyetlerinin tenfîzi (yerine getirilmesi) 4) Geriye kalan malın mirasçılar arasında taksimi. (Mevkûfât)","osmanli":"تركه"},{"kelime":"TERTÎB","anlam":"1.Sırayı gözet-mek, uygun bir sıra ile yapmak.","kategori":"dil","misal":"Namaz fiillerini sırayla yapma. Namazın farzlarından kıyâm, rükû’ ve secde arasında tertîbi gözetmek farz; vâciblerde tertîbi gözetmek ise vâcibdir. (İbni Âbidîn) Kazâya kalmış namazları kazâ ederken sı-rasını gözetme. Kazâya kalmış namazlarda tertîb vâcibdir. Bir vaktin namazını kazâya bırakan kimse, bunu kılmadan sonraki vaktin namazını kılamaz. Kılarsa, sahih olmaz. Önce kazâya kalmış na-mazı kazâ eder; sonra o vaktin namazını iade eder. (İbni Âbidîn) Abdest ve teyemmüm alırken uzuvlarını muayyen bir sıra ile yıkama. Abdestte tertîb, Hanefî mezhebinde sünnet, Şa-fiî ve Hanbelî mezheblerinde farzdır. Teyem-mümde tertîb Hanbelî mezhebinde farzdır. (el-Mîzânü’l-Kübrâ)","osmanli":"ترتيب"},{"kelime":"Tertîb Sâhibi","anlam":"Üzerinde kazâya kalmış beşten fazla namaz borcu bulunmayan kimse.","kategori":"akaid","misal":"Bir günlük beş vakit farzı ve vitir namazını kılarken ve kaza ederken tertîb sahibi olmak farzdır. (İbni Âbidîn)","osmanli":"صاحبى ترتيب"},{"kelime":"TERTÎL","anlam":"1.Yerli yerince, tane tane, açık konuşma. 2.Kur’ân-ı kerîmi yavaş yavaş, tane tane, üze-rinde tefekkür ederek tecvîde göre okuma.","kategori":"dil","misal":"Resûlullah’ın sallallahü aleyhi ve sellem mü-barek sözlerinde tertîl ve tersîl vardı. (Mevâ-hib-i Ledünniyye) Kur’ân’ı (güzel sesle tegannî yapmadan) tertîl üzere oku. (Müzzemmil sûresi: 4)","osmanli":"ترتيل"},{"kelime":"TERVİYE GÜNÜ","anlam":"Zilhicce ayı-nın sekizinci günü. Suya kandırma veya de-rin düşünme mânâsına revâ’dan gelir.","kategori":"dil","misal":"Terviye günü oruç tutmak bütün senenin, Arefe günü oruç tutmak ise iki senenin gü-nahlarına keffarettir. (Hadîs-i şerîf-Ebû Şeyh) Terviye günü sabah namâzından sonra Ara-fat’a gitmek için Mekke-i Mükerreme’den çık-mak haccın sünnetlerindendir. (İbni Âbidîn) Bu güne terviye denmesinin bir sebebi, hacılar, susuz bir sahrayı kat edeceklerinden dolayı, bu günde su hazırlığı yapar, bineklerini suya kan-dırırlar. Bir sebebi de İbrâhim aleyhisselâmın, oğlu İsmâil’i kurban etmesine ait rüyayı birinci defa gördüğünde, bu rüyanın rahmânî mi, şey-tânî mi olduğunu düşünmekle, tefekkürle geçir-diği için bu ismi almıştır. (Günyetü’t-Tâlibîn)","osmanli":"ﮔونى ترويه"},{"kelime":"TESBÎH","anlam":"1.Sübhânallah demek; Allahü teâlâyı, O’na yakışmayan her şeyden ve mahlûkların alâmetlerinden tenzîh ve takdîs etmek.","kategori":"akaid","misal":"Yedi gökle yer ve bunların içinde bulunanlar (melekler, cinler ve insanlar) Allahü teâlâyı tesbih ederler. Her şey, Allahü teâlâyı hamd etmekle tesbih eder. Fakat siz, onların tesbihini anlayamazsınız. (İsrâ sûresi: 44) Akşam ve sabah vakitlerinde Allah’ı tesbih edin. Göklerde ve yeryüzünde onların yaptıkları ve ikindi ve öğle vakitlerinde yapılan hamdler, Allahü teâlâ içindir. (Rûm sûresi: 17, 18) Allahü teâlâyı yü…","osmanli":"تسبيح"},{"kelime":"TEŞBÎH","anlam":"1.Benzetme. 2.Bir şeyi başka bir şeye benzetmek suretiyle maksadı daha kısa yoldan ifade etmek üzerine dayalı edebî sanat. 3.Allahü teâlâyı başka bir varlığa benzetme esasına dayalı bid‘at inancı.","kategori":"akaid","osmanli":"تشبيه"},{"kelime":"Tesbih Mikdârı","anlam":"Sübhânallah diyecek kadar geçen zaman, bir mikdar.","kategori":"ibadet","osmanli":"مقدارى تسبيح"},{"kelime":"TEŞEBBÜH","anlam":"Benzeme, kendini ben-zetme, taklit etme.","kategori":"dil","misal":"Kim bir kavme teşebbüh ederse, onlardan-dır. (Hadîs-i şerîf-Ebû Dâvûd, Müsned, Hâkim) Ehl-i kitâba benzemenin dereceleri vardır. Ye-mek, içmek gibi âdet olan zararsız şeylerde benzemek câizdir. Kötü, zararlı şeylerde teşeb-büh kasd ederek benzemek haramdır. Teşebbüh kasd etmezse câiz olur. Ehl-i kitâbın dinlerine mahsus olup, dinlerinin alâmeti olan şeylerde, kasd olmadan da benzemek küfr olur. Fay-dalı dünya işlerinde benzemek câiz, hattâ se-vab olur. Şu hâlde hadîs-i şerîfin men ettiği te-şebbüh, ibâdetlerde ve mezmum (kötü) işlerde olan teşebbühtür. Âdete dair işleri, teşebbüh kasdı olmadan yapmak câizdir. (Merâkı’l-Felâh Hâşiyesi-Tahtâvî) İmâmeyn namazda mushafa bakarak okumayı Ehl-i kitâba teşebbüh olduğu için mekrûh gördü. Çünki onlar namazlarında bakarak okurlar. (İbni Âbidîn)","osmanli":"تشبه"},{"kelime":"TEŞEFFÜ‘","anlam":"1.Şefaatçi yapma; Bir iste-ğin yerine gelmesi için, peygamberleri veya evliyâyı vesîle ederek Allahü teâlâya yalvarma. 2.Şâfi‘î mezhebine geçme, bu mezhebi tak-lit etme.","kategori":"akaid","misal":"(Bkz. İstigâse, Tevessül)","osmanli":"تشفع"},{"kelime":"TEŞEHHÜD","anlam":"Namazın her ka’desinde (oturuşunda) ettehiyyâtü duâsını okumak.","kategori":"ibadet","misal":"Namazda ikinci rek‘atten sonraki oturuşta teşehhüd mikdarı oturmak ve ka’de-i ahîrede teşehhüd vâcibdir. (Ni’met-i İslâm)","osmanli":"تشهد"},{"kelime":"Teselsül","anlam":"1.Sonu gelme-yen işlerin birbirini takip etmesi, zincirleme. 2.Sonradan var olan şeylerin birbirinin varlı-ğına sebeb olarak geriye doğru sonsuza kadar zincirleme birbiri ardısıra gitmesi. Teselsülün butlânı, yani teselsülün muhâl (im-kânsız) olduğu, burhân-ı tatbîk ile ispat olu-nur. Meselâ bir şeyin sonsuz yaratıcılarını bi-rinciden başlayarak, sonsuz olarak, yan yana dizelim. İkinci yaratıcıdan başlayarak, ikinci bir sıra daha düşünelim. Sonsuza giden ikinci sıra, birinci sıradan bir noksan olduğu için, kı-sadır. Kısa olana sonsuz denilemez. İkinci sıra, sonsuz olamadığı için, bundan bir fazla olan birinci sıra da, sonsuz olamaz. Yani, bir ucu sonsuza giden yarım doğru düşünülebilir. Fa-kat böyle bir şey mevcud olamaz. Dolayısıyla teselsül olamaz. Bu sebeble sonsuz sayıda ya-ratıcılar olamaz. Sonsuz var olan bir yaratıcı olur. Bu tek yaratıcı, ezelîdir, ebedîdir, sonsuz olarak vardır. Varlığı kendindendir, başkasın-dan değildir. (Şerh-i Emâlî-Âsım Efendi)","kategori":"dil","osmanli":"تسلسل"},{"kelime":"TESETTÜR","anlam":"Örtünme. (Bkz. Setr-i Avret)","kategori":"dil","misal":"Kadınlar için ezan ve ikamet mekrûhtur. Çünki onların hâlleri tesettür üzerine kurulmuştur. Seslerini yükseltmeleri haramdır. (İbni Âbidîn)","osmanli":"تستر"},{"kelime":"TESLÎM","anlam":"1.Bir şeyi sahibine verme. 2.İtâ‘at etme, boyun eğme. 3.Müslüman olma.","kategori":"dil","misal":"Akid, icab ve kabul ile in’ikad eder. Müşteri semeni verir. Satıcı, malı teslim eder. Teslim, akdin sıhhatinin şartı değildir. (İbni Âbidîn) TESLÎS: تثليث (A) Üçleme; Hristiyanlıkta Tan-rı’nın birbirinden ayrılmaz Baba, Oğul ve Rû- hülkuds adında üç esastan meydana geldiğine dair inanış. Üç Uknûm. Ekânim-i Selâse. Trinite. Teslîs inancının esası, Eflâtun (Platon) felse-fesine dayanır. Eflâtun, esasta dünyayı yara-tan kudretin tek olduğunu düşünmekle be-raber, onun iki yardımcısı daha olabileceğini ileri sürmüştü. İncillerde açıkça yer almayan; ancak her şeyin sahibi olan baba ve onun çok sevdiği kulu mânâsına oğul ifadeleri te’vîlsiz kabul edilerek II. asırda baba ve oğul şeklinde ortaya atılan inanca, 381 senesindeki İstanbul Konsili’nde Îsâ aleyhisselâma verilen ilahî kud-ret mânâsına Rûhülkuds de eklenmiştir. (Îzâ-hü’l-Merâm)","osmanli":"تسليم"},{"kelime":"TESLÎS","anlam":"Üçleme; Hristiyanlıkta Tan-rı’nın birbirinden ayrılmaz Baba, Oğul ve Rû-","kategori":"dil","misal":"hülkuds adında üç esastan meydana geldiğine dair inanış. Üç Uknûm. Ekânim-i Selâse. Trinite. Teslîs inancının esası, Eflâtun (Platon) felsefesine dayanır. Eflâtun, esasta dünyayı yaratan kudretin tek olduğunu düşünmekle beraber, onun iki yardımcısı daha olabileceğini ileri sürmüştü. İncillerde açıkça yer almayan; ancak her şeyin sahibi olan baba ve onun çok sevdiği kulu mânâsına oğul ifadeleri te’vîlsiz kabul ediler…","osmanli":"تثليث"},{"kelime":"TEŞRÎ‘","anlam":"Hukuk kâideleri koyma; din ve şeriat koyma. (Bkz. Şârî‘)","kategori":"dil","misal":"Teşrî‘, Allah ve Resûlüne âittir. Resûlullah aley-hisselâmın teşrî‘ vazifesi fiilî (bizzât yaparak) ve kavlî (söyleyerek) olduğu gibi, dine aykırı olmayan bir şey gördüklerinde de susarlar, o işe mâni olmazlardı. Buna Resûlullah aleyhis-selâmın takrîrî sünneti denir. (Usûl-i Serahsî)","osmanli":"تشريع"},{"kelime":"TETAVVû‘","anlam":"Farz ve vâcib olmayıp, sırf Allah rızâsı için yapılan nâfile ibâdet.","kategori":"fikih","misal":"Hac farzdır. umre tetavvû‘dur. (Hadîs-i şerîf-İbni Ebiddünyâ) Tetavvû’ namazlarının kendilerine mahsus se-vabları ve fazîletleri vardır. Tetavvu‘ namazla-rından bazıları şunlardır: Tehiyyetü’l-Mescîd: Mescide girildiğinde kılınan namaz. Duhâ na-mazı: Kuşluk vakti kılınan namaz. Teheccüd namazı: Gecenin üçte ikisi geçtikten sonra, imsâk vaktinden önce kılınan namaz. Tehec-cüd ve duhâ (kuşluk) namazlarının en çoğu on iki rek‘attir. Nâfile namazlarda gece iki, gün-düz dört rek‘atte bir selâm verilir. (İbni Âbidîn)","osmanli":"تطوع"},{"kelime":"TETAYYuR","anlam":"Uğursuzluk, uğursuzluğa inanma. (Bkz. Tayere)","kategori":"dil","misal":"Tetayyur eden ve tetayyur olunan ve kâhin-lik yapan ve kâhine giden ve sihir, büyü ya-pan ve yaptıran ve bunlara inanan bizden değildir. Kur’ân-ı kerîme inanmamıştır. (Ha-dîs-i şerîf-Hadîkatü’n-Nediyye)","osmanli":"تطير"},{"kelime":"TEVÂ","anlam":"Havâlenin bozulma sebeblerinden olup, havâleyi kabul edendeki alacağın telef (yok) olması.","kategori":"fikih","misal":"(Bkz. Havâle)","osmanli":"توا"},{"kelime":"TEVÂCÜD","anlam":"Tasavvuf yolcusunun vecd sahibi olmayı istemesi, bunun için çalışması.","kategori":"tasavvuf","misal":"(Bkz. Vecd)","osmanli":"تواجد"},{"kelime":"TEVÂTÜR","anlam":"Her asırda, yalan üzere it-tifakı mümkün olmayan güvenilir bir toplu-luğun hepsinin aynı şekilde bildirdiği haber. Tevâtürde adalet aranmaz. Tevâtür ilm-i yakîn ifade eder.","kategori":"dil","misal":"Mûsâ, Îsâ ve diğer peygamberlerin aleyhimüs-selâm mûcizeler gösterdiği haber verildiği gibi, Muhammed aleyhisselâmın da mûcizeler göster-diği haber verilmiştir. Bu haberler tevâtür hâ-lindedir. Muhammed aleyhisselâm, mûcizeler göstermiş ve bu mûcizeler bizlere tevâtür yo-luyla bildirilmiştir. (Mefâtihü’l-Gayb)","osmanli":"تواتر"},{"kelime":"TEVÂZu‘ (Tevâdu‘)","anlam":"Alçak gönüllülük; kendisini başkalarından üstün görmemek.","kategori":"tasavvuf","misal":"Allahü teâlâ, tevâzû üzere olmağı bana emreyledi. Hiçbiriniz, hiçbir kimseye tekebbür etmeyiniz. (Hadîs-i şerîfEbû Dâvûd) Allah için tevâzû edeni, Allahü teâlâ yükseltir. (Hadîs-i şerîfTaberânî)","osmanli":"تواضع"},{"kelime":"Tevbe Bi‘atı","anlam":"Mürşid-i kâmil denilen velî bir zâtın, huzurunda tövbe edip günah işlememek üzere söz vermek.","kategori":"tasavvuf","osmanli":"بيعتى توبه"},{"kelime":"Tevbe-i Nasûh","anlam":"Sâdık tövbe, iş-lediği günahı bir daha yapmamak üzere tövbe etmek ve bu tövbesinde tam kararlı olmak. Ey îmân edenler! Günahlarınızdan Allahü teâlâya tevbe-i nasûh ile tövbe ediniz. (Tah-rîm sûresi: 8)","kategori":"dil","misal":"Tövbe-i nasûh dört şey ile tamam olur. 1) Dil ile istiğfâr etmek (bağışlanmayı dilemek). 2) Günahı işleyen âzâ ile günahı terk etmek. 3) Bu günahı bir daha işlemeyeceğine kalb ile ke-sin karar vermek. 4) Günah işlemeye sevk eden her türlü vâsıta ve arkadaştan uzaklaşmak. (Miftahü’n-Necât)","osmanli":"نصوح توبهء"},{"kelime":"TEVBE SûRESİ","anlam":"129.âyet-i kerîmeleri Mekke’de indi.","kategori":"dil","misal":"Kur’ân-ı kerîmin dokuzuncu sûresi. Berâe sûresi de denir. Medîne’de nâzil oldu. 128 ve Yüz yirmi dokuz âyettir. Evvelinde Besmele nâzil olmamıştır. Sûre, müşriklerin Allahü teâlâ ile alâkalarının kesildiğini, bundan sonra onların Kâbe’ye yaklaştırılmayacağını, Müslüman olmadıkları takdirde öldürüleceklerini bildiren bir ültimatom mâhiyetindedir. Sûre, Peygamber efendimizin şefkat ve merhâmetini bildiren âyet-i ke…","osmanli":"سى سوره توبه"},{"kelime":"TEVBE (Tövbe)","anlam":"Günah işledikten sonra, pişman olup, Allah rızası için bir daha yapmamaya karar verme.","kategori":"akaid","misal":"Ey mü’minler! Hepiniz Allah’a tövbe ediniz ki felâh (kurtuluş) bulasınız. (Nûr sûresi: 31) Allahü teâlâ tövbe edenleri sever. (Bakara sûresi: 222) Pişmanlık tevbedir. Günahından tövbe eden, hiç günah işlememiş gibidir. (Hadîs-i şerîfTaberânî, Beyhekî) Tövbenin doğru olması için, üç şart vardır: Günaha son vermek, yaptığına pişman olmak ve bir daha hiç yapmamaya karar vermek. Eğer kul hakkı da varsa, hakkını ödeyip,…","osmanli":"توبه"},{"kelime":"TEVECCÜH","anlam":"1.Bir tarafa yönelme, yüzünü çevirme; sevme, yakınlık duyma, sevdiği kimseye yönelme. 2.Tasavvuf yolunda ilerlemeye vesile olmak üzere, mürşidin müride nazar etmesi yâhud başka yollarla kalbindeki mâsivâ ve dünya sev-gisini, günah lekelerini temizleyip, yerini feyz, mârifet, ilim ve hikmetle yani mânevî ilimler, iyilikler, bereketler ve fâidelerle doldurması. Umumiyetle bazı günler sabah namazından sonra mürşidin müridleriyle kucaklaşıp kalb-lerini kalbi üzerine koymak suretiyle yapılır. Pîrin teveccühü, her ne sûretle ortaya çıkarsa çıksın, sâdık talebeden, zulmet ve keder dağlarını kaldırıp, uzaklaştırır. (Mektûbât-ı Ma’sûmiyye) Tasavvuf yolunda çok yüksekleri aramalı, ele geçenlere bağlanıp kalmamalıdır. Verâların verâsını yani öteler ötesini aramalıdır. Böyle bir istek, böyle çok çalışmak ancak vazife alı-nan büyüğün teveccühü ile elde edilebilir. Onun teveccühü de mürîdin ona olan sevgisi, bağlı-lığı kadar olur. (Mektûbât-ı İmâm-ı Rabbânî)","kategori":"dil","misal":"Resûlullah’ın yanına bir âmâ (gözleri görmeyen) birisi geldi. Gözlerinin açılması için duâ etme-sini diledi (istedi). Resûlullah sallallahü aleyhi ve sellem, ona; “İstersen duâ edeyim, istersen sabret. Sebretmek, senin için daha iyi olur” buyurdu. O kimse; “Duâ etmeni istiyorum. Be-nim bakacak kimsem yoktur. Çok sıkılıyorum” deyince; “İyi bir abdest al! Sonra; “Allahümme innî es’elüke ve eteveccühü ileyke bi-Nebiy-yike Muhammedin Nebiyyirrahme, yâ Mu-hammed innî eteveccehü bike ilâ Rabbî fî hâcetî-hâzihî, li takdiye-lî Allahümme şef-fi’hü fiyye” duâsını oku!” buyurdu. Duâ-nın mânâsı şudur: “Yâ Rabbî! İnsanlara rah-met olarak gönderdiğin sevgili Peygamberin ile sana teveccüh ediyorum. Senden istiyorum. Yâ Muhammed aleyhisselâm! Dileğimin hâsıl ol-ması (yerine gelmesi) için Rabbime senin ile te-veccüh ediyorum. Allah’ım! O’nu bana şefâatçi eyle!” (Hadis-i şerif- Nesâî, Tirmizî, Beyhekî) Rûhu olgun bir velînin kabri yanına gidip, bir zaman durulur ve o tapraktaki velîye teveccüh edilirse, ruhu o toprağa bağlanır. Meyyitin ruhu da bu toprağa bağlı olduğu için, gelen insanın ruhu ile velînin ruhu buluşmuş olurlar. Bu iki ruh karşılıklı iki ayna olur. Herbirinde olan meârif (ilimler) ve kemâlât (olgunluklar) öte-kine aks eder, yansır. (Mefâtihü’l-Gayb)","osmanli":"توجه"},{"kelime":"TEVEKKÜL","anlam":"Sebeblere yapıştıktan sonra kadere râzı olma; her işinde Allahü teâlâya itimad etme.","kategori":"akaid","misal":"Kim Allahü teâlâdan korkarsa, Allahü teâlâ ona (darlıktan genişliğe) bir çıkış yolu ihsân eder ve ona ummadığı yerden rızık verir. Her kim, Allahü teâlâya tevekkül ederse, Allahü teâlâ ona kâfidir. (Talâk sûresi: 2, 3) Eğer îmânınız varsa, Allahü teâlâya tevekkül ediniz. (Mâide sûresi: 23) Allahü teâlâ, tevekkül edenleri sever. (Âl-i İmrân sûresi: 259) Allahü teâlâya tam tevekkül etseydiniz, kuşların rızkını verdiği…","osmanli":"توكل"},{"kelime":"TEVERRÜK","anlam":"Kaba etleri yere koyup, uyluklarını birbirine yaklaştırarak, ayaklarını sağ taraftan dışarı çıkarıp, sol uyluğu üze-rine oturma.","kategori":"dil","misal":"Kadınlar, namazda teverrük ederek otururlar. (Dürrü’l-Muhtar) Dizleri dikip, başını dizlerine koyarak, diz çö-kerek, bağdaş kurarak, teverrük ederek uyursa, abdesti bozulmaz. (Ni’met-i İslâm)","osmanli":"تورك"},{"kelime":"TEVESSÜL","anlam":"1.Bir isteğin, bir maksadın hâsıl olması için bir şeyi vesîle, sebeb yapmak. 2.Allahü teâlânın sevdiklerini araya koyarak; “Onların hâtırı, hürmeti için” diyerek duâ etmek veya bu sûretle yapılan duâ. Ömer bin Hattâb radıyallahü anh kıtlık olduğu zaman Peygamber efendimizin amcası Hazret-i Abbâs ile tevessül etti. Yani onu vesîle ederek Allahü teâlâdan yağmur istedi: “Yâ Rabbî! Kıtlık olduğu zaman,Resûlullah efendimizle sana tevessül ederdik. Sen bize yağmur verirdin.Şimdi sana, Resûlullah efendimizin amcası ile tevessül ediyoruz. Bize yağmur ihsân et.” diye duâ edince, Allahü teâlâ onlara yağmur verdi. (Buhârî)","kategori":"akaid","osmanli":"توسل"},{"kelime":"TEVFÎK","anlam":"1.Uygun hâle ge-tirme, uygun yapma. 2.Allahü teâlânın yardımı.","kategori":"akaid","misal":"(Şuayb aleyhisselâm), kavmine şöyle dedi: “Benim tevfîkim, Allahü teâlânın hidâyeti ve yardımı iledir”. (Hûd sûresi: 88)","osmanli":"توفيق"},{"kelime":"TEVHÎD","anlam":"1.Birleştirme, birkaç şeyi bir araya getirme. 2.Allahü teâlânın bir olduğuna inanmak, O’na kimseyi ortak etmemek. 3.Tasavvufta kalbi Allahü teâlâdan başka şeylere bağlılıktan kurtarma.","kategori":"akaid","misal":"(Bkz. Kelime-i Tevhîd)","osmanli":"توحيد"},{"kelime":"Tevhîd-i Ef‘âlî","anlam":"Mahlûkların bütün işlerini, bütün hareketlerini, tek bir yapıcının işlerinden olarak görmek.","kategori":"akaid","osmanli":"افعالى توحيد"},{"kelime":"Tevhîd-i Sıfatî","anlam":"Mahlûkların sı-fatları, hususiyetlerini, Hak teâlânın sıfatla-rını, görüntüleri bilmek ve her varlığı Allahü teâlânın varlığında yok görmek.","kategori":"akaid","osmanli":"صفاتى توحيد"},{"kelime":"Tevhîd-i Şuhûdî","anlam":"Mâsivâyı (Allahü teâlâdan başka her şeyi) görmemek ve düşünmemek.","kategori":"akaid","misal":"Tasavvuf yolunda yürümekten, nefsin istemediği zor gelen şeyleri yapmaktan ve sıkıntı çekmekten maksat, Allahü teâlâdan başka, her şeyin sevgisinden kurtulmaktır. Bu da tevhîd-i şuhûdî ile hâsıl olmaktadır. Bütün bu uğraşmalar, kulluğun, aczin, zavallılığın meydana çıkması ve hiç olduğumuzun anlaşılması içindir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"شهودى توحيد"},{"kelime":"Tevhîd-i Vücûdî","anlam":"Mâsivâyı, Allahü teâlâdan başka her şeyi yok bilmektir.","kategori":"akaid","osmanli":"وجودى توحيد"},{"kelime":"TEVKÎFÎ","anlam":"İslâmiyet’in bildirmesine bağlı olan, tefsir ve ictihada müsait olmayan.","kategori":"dil","misal":"Allahü teâlânın ism-i şerîfleri tevkîfîdir. Şeriatin bildirdiği isimler söylenir. Bunlardan başka isimler ile zikretmeye, anmaya şeriat izin vermemiştir. (Birgivî Vasıyyetnâmesi Şerhi)","osmanli":"توقيفى"},{"kelime":"TEVKÎL","anlam":"Vekîl tâyin etme. (Bkz. Vekîl) Tevkîlin rüknü îcâb ve kabuldür. Şöyle ki mü-vekkil şu husûsa seni vekîl ettim deyip de vekîl dahi kabul ettim dese veyahûd kabulü müş’ir başka bir söz söylese vekâlet mün’akid olur. Kezâlik vekîl bir şey söylemeyip de ol husûsun icrâsına teşebbüs eylese delâleten vekâleti ka-bul etmiş olmakla tasarrufu sahîh olur. Ammâ ba’de’l-îcâb vekîl reddetse îcâbın hükmü kalmaz. (Mecelle, madde: 1451)","kategori":"dil","osmanli":"توكيل"},{"kelime":"TEVLİYET","anlam":"Vakıf mallarını idare etme vazifesi, mütevellîlik.","kategori":"muamelat","osmanli":"توليت"},{"kelime":"TEVRÂT","anlam":"Mûsâ aleyhisselâma indirilen mukaddes kitab.","kategori":"dil","misal":"Biz, Mûsâ için Tevrat’ın levhalarında, mev’i-zaya (nasihatlere) ve din hükümlerinin açıklamasına âit her şeyi yazdık. (A’râf sûresi: 145) ÂsûrBâbil hükümdârı Buhtunnasar, Mîlâddan Evvel VI. asırda Kudüs’ü alıp Mescid-i Aksâ’yı yıktığı zaman, Tevrat nüshaları yakıldı. Tevrat’ı ezberlemiş olanlar da zamanla unuttu. Haham Azra, Mîlâddan Evvel IV. asırda hatırlarda kalan kısımları toplayıp bugünki Tevrat’ı meydana getir…","osmanli":"توراة"},{"kelime":"TEYEMMÜM","anlam":"Su bulunmadığı veya bulunup da özür sebebiyle kullanmak mümkün olmadığı takdirde; temiz toprak veya taş, kum, kerpiç gibi toprak cinsinden bir şey ile abdest almak üzere, elleri toprağa sürüp yüzü ve kolları mesh etmek.","kategori":"ibadet","misal":"Hicretin beşinci senesinde Benî Müstalık Gazvesi sırasında mücâhidler yani Eshâb-ı kirâm su bulamadıkları için bir sabah namazını kılamama tehlikesi ile karşı karşıya kalmışlardı. Bunun üzerine teyemüm ile alâkalı âyet-i kerîme (Mâide sûresi: 6) nâzil oldu (indi). Meâlen; “Su bulamadığınız zaman temiz toprağa teyemmüm ediniz” buyruldu. (Tefsir-i Mazharî) Hastanın, abdest veya gusül ile veya hareket etmekle, hastalığ…","osmanli":"تيمم"},{"kelime":"TEZEKKÜR","anlam":"Akla getirme, hatırlama.","kategori":"dil","osmanli":"تذكر"},{"kelime":"Tezekkür-i Mevt","anlam":"Ölümü hatır-lamak. İnsanın kendini ölmüş, teneşir tah-tası üzerinde yıkanmış, kefene sarılmış ve tabuta konulmuş ve mezâra gömülmüş ola-rak düşünmesi.","kategori":"dil","misal":"Tezekkür-i mevt, sadakadır. (Hadîs-i şerîf-Dey-lemî)","osmanli":"موت تذكر"},{"kelime":"TEZELLÜL","anlam":"(A. Zillet’ten) Bayağılık, ken-dini aşağı tutma. Tevâzûnun aşırı derecesi. Tezellül kötü huylardan biridir. Bir âlimin ya-nına câhil bir kimse geldiği zaman, âlimin ayağa kalkıp, yerine bunu oturtması ve gideceği zaman kapıya kadar yanında yürümesi ve kundurala-rını önüne koyması tezellüle bir misâldir. Yal-nız ayağa kalkıp otursaydı, ona yer gösterseydi ve işini, hâlini ve niçin geldiğini sorsaydı, suâl-lerine güler yüzle cevap verseydi, da’vetini ka-bul etseydi ve sıkıntısını giderecek bir şey yap-saydı, tevâzû göstermiş olurdu. Fazla hediye almak için az bir şeyi hediye vermek de tezel-lül olur. Âyet-i kerîme, böyle hediye vermeyi men etmektedir. (Berîka)","kategori":"dil","osmanli":"تذلل"},{"kelime":"TEZEVVÜC","anlam":"Evlenme; karıkoca olma.","kategori":"dil","osmanli":"تزوج"},{"kelime":"TEZKİYE","anlam":"(A. Zekâ’dan) Temizleme; te-mize çıkartma.","kategori":"dil","misal":"Bir sâlik (tasavvuf yolcusu), niyetini düzelttik-ten ve kendini dünya arzularından kurtardık-tan sonra, Allahü teâlânın ismini zikretmeye başlar. Güç riyâzetler (nefsin arzularını yapma-mak) çeker. Şiddetli, ağır mücâhedeler (nefsin istemediği şeyleri yapmak) yapar. Böylece tez-kiye hâsıl olur ve kötü huyları iyi huylara dö-ner. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"تزكيه"},{"kelime":"TEZVÎC","anlam":"Evlendirme, kocaya verme, nikâhlama.","kategori":"dil","misal":"Kadını, kendisi veya vekîli yâhud velîsi (babası, dedesi, sonra erkek kardeşi, amcası...) tezvîc eder. (Ni’met-i İslâm) Erkek velîleri bulunmayan yetimleri, Hanefî mezhebinde anaları tezvîc edebilir. (İbni Âbidîn)","osmanli":"تزويج"},{"kelime":"TEZYÎN","anlam":"(A. Ziynet’ten) Süslemek. Üstlerindeki göğe bakmazlar mı ki, onu nasıl yapmış ve nasıl tezyîn etmişiz! Onda hiçbir çatlak da yoktur. (Kaf sûresi: 6) Cen-net’ten bir tırnağın yükleneceği bir şey dün-yaya gelse, mağrib ile maşrik arasındakileri tezyîn ederdi. (Hadîs-i şerîf-Tirmizî) Kur’ân-ı kerîmi seslerinizle tezyîn ediniz. (Hadîs-i şerîf-Taberânî)","kategori":"hadis","misal":"Herkes dışa kıymet verip, dışını süslerken siz içinizi tezyîn edin. İslâm’ın emir ve yasaklarına uyarak kalbinizi tezyîn edin. (Miftahü’n-Necât)","osmanli":"تزيين"},{"kelime":"TİCÂRET EŞYÂSI","anlam":"Ticârete karar veren kimsenin bu niyetle aldığı zekâta tâbi eşya.","kategori":"ibadet","misal":"Eşyanın ticâret eşyası sayılması için ticâret niyetiyle satın alınması lâzımdır. Uşur topraklarından hâsıl olan, miras olarak ele geçen, hediye, vasîyet yoluyla ele geçen mallarda ticârete niyet edilse de bunlar ticâret eşyası olmaz. (İbni Âbidîn)","osmanli":"اشياسى تجارت"},{"kelime":"TILÂ’","anlam":"Tâze üzüm şırasının, ateşte veya güneşte ısıtılarak üçte birinden fazlasının uç-masıyla elde edilen alkollü içki.","kategori":"dil","misal":"Tıla’, gaz çıkararak kabarıp, tadı keskin olunca, sarhoş eder. Şarap gibi, damlası haram ve kaba necs olur. (İbni Âbidîn)","osmanli":"طلاء"},{"kelime":"TİLÂVET","anlam":"Kur’ân-ı kerîm okumak.","kategori":"dil","misal":"Onlar geceleri secdeye kapanarak Allah’ın âyetlerini tilâvet ederler. (Âl-i İmrân sûresi: 113) Onlara Allah’ın âyetleri tilâvet olunduğu zaman ağlayarak secdeye kapanırlardı. (Meryem sûresi: 58) Bu Kur’ân-ı kerîmi öğreniniz. Şüphesiz ki onu tilâvet etmekle her harfine bedel on sevabla mükâfâtlandırılırsınız. (Hadîs-i şerîfDârimî)","osmanli":"تلاوت"},{"kelime":"Tilâvet Secdesi","anlam":"Kur’ân-ı kerîmdeki on dört secde âyetinden herhangi birini okuyan veya işiten bir mükellefin, yani âkıl ve bâliğ Müslümanın yapması vâcib olan secde.","kategori":"dil","misal":"Secde âyetleri, Kur’ân-ı kerîmin; A’râf, Ra’d, Nahl, İsrâ, Meryem, Hac, Furkân, Neml, Secde, Sâd, Necm, İnşikâk ve Alak sûrelerinde bulunmaktadır. (Bkz. Secde) Namazda aranan şartlar, tilâvet secdesinde de aranır. (İbni Âbidîn) Tilâvet secdesi şöyle yapılır: Niyet edilerek eller kaldırılmadan Allahü ekber diyerek secdeye varılır. Secdede üç kere; “Sübhâne rabbiyel a‘lâ” denir. Sonra Allahü ekber denilerek ayağa kalk…","osmanli":"سى سجده تلاوت"},{"kelime":"TIMAR (Tîmâr)","anlam":"Osmanlı Devleti’nde muayyen hizmet veya vazife karşılığı kişilere tahsis edilen ve geliri 20 bin akçeden az olan mîrî toprak.","kategori":"osmanli","misal":"Dirlik. Timar verilen kişi (sipahi), bu arâzînin kirâsını toplar; mukabilinde asker besler.","osmanli":"تيمار"},{"kelime":"TİMSÂL","anlam":"Sembol, rümuz; resim, suret.","kategori":"dil","misal":"Üzerinde timsâl bulunan elbise ile namaz kıl-mak tahrîmen mekrûhtur. Cansız resimleri bu-lunursa, mekrûh olmaz. (İbni Âbidîn)","osmanli":"تمثال"},{"kelime":"TİVELE","anlam":"Kadını kocasına sevdirmek için yapılan büyü.","kategori":"osmanli","misal":"Tivele şirktir. (Hadîs-i şerîfEbû Dâvûd) Rukyede, âyetler ve Resûlullah’tan gelen duâlar değil de; bunlardan başka şeyler yazılır veya okunursa, o tivele sihir hükmünde olur. (İbni Âbidîn)","osmanli":"تيوله"},{"kelime":"TRİNİTE","anlam":"Hristiyanların teslîs inancı.","kategori":"dil","misal":"(Bkz. Teslîs)","osmanli":"ترينيته"},{"kelime":"TuFEYLÎ","anlam":"Birine uyan, onun izinde giden, ona benzeyen. Asalak.","kategori":"dil","misal":"Sâlik tabi iken, uymakta iken, tufeylî iken, ikisi arasındaki işler, hizmetçi ile hizmet olu-nan kimsenin işleri gibi başka başkadır. (Mek-tûbât-ı İmâm-ı Rabbânî)","osmanli":"طفيلى"},{"kelime":"TuMÂNÎNET","anlam":"Namaz kılarken, rükû‘, secde, kavme ve celsede bütün uzuvların hareketsiz kalması.","kategori":"ibadet","misal":"Namazda tumânînet, vâcibdir. (İbni Âbidîn) Namazda, ta’dîl-i erkâna dikkat etmelidir. Yani rükû‘da ve secdelerde ve kavmede ve celsede tumânînet bulduktan sonra biraz durmalıdır ki, Hanefî mezhebi âlimlerinin çoğu buna vâcib demiştir. İmâm-ı Ebû Yûsuf ve İmâm-ı Şâfiî ve Mâlik ise, farz demiştir. Bazı Hanefî âlimleri de sünnet demişlerdir. Müslümanların çoğu bunu yapmıyor. Bu bir ameli (işi) meydana çıkarana Allah yo…","osmanli":"طمانينت"},{"kelime":"TûR-İ SÎNÂ","anlam":"Mûsâ aleyhisselâmın peygamberlikle müjdelendiği ve Tevrat’ın indirildiği, Kızıldeniz’in kuzeyinde, Sinâ yarımadasının güney kısmında yer alan dağ.","kategori":"dil","misal":"Tûr Dağı. Biz Mûsâ’ya Tûr-i Sînâ yanında, sağ tarafından nidâ ettik ve münâcât ettiği (yalvardığı) hâlde kendisine yüksek mertebe verdik. (Meryem sûresi: 52) Vaktâ ki, Mûsâ (aleyhisselâm, kararlaştırılan) vakti tam olarak yerine getirdikten sonra (Hazret-i Şuayb’dan izin alıp) hanımıyla birlikte (Mısır’a gitmek üzere) yola çıktı. Yolda Tûr-i Sînâ tarafında bir ateş gördü. Hanımına; “Siz burada bekleyin ben bir ateş…","osmanli":"سينا طور"},{"kelime":"TÜRBE","anlam":"Meşhur bir kimsenin meza-rının bulunduğu bina. Aslı Arabca toprak mânâsına gelir.","kategori":"dil","misal":"Mevtaya sevgi ve hürmet göstermek ve oku-maya, duâ etmeye gelenleri yağmurdan, güneş-ten korumak için türbe yapmak câizdir. Mu-hammed bin Hanefiyye, Abdullah bin Abbâs’ı defn edince, kabri üzerine çadır kurdu. Ziya-retçiler, üç gün bu çadırda okudular. (Mec-ma‘ul-Enhür) Âlimlerin, velîlerin kabrleri üzerine türbe yap-mak, onları câhillerin hakâretlerinden koru-mak içindir. (Keşfü’n-Nûr) u","osmanli":"تربه"},{"kelime":"uBûDİYYET","anlam":"Kulluk; Allahü teâlâ-nın emirlerine teslimiyet ve boyun eğmek; Al-lahü teâlânın işinden râzı olmak; Her an Al-lahü teâlâyı hatırlamak, anmak.","kategori":"akaid","misal":"Ubûdiyyetin alâmeti, Allahü teâlânın emirle-rini yapmak, yasak ettiklerinden sakınmaktır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عبوديت"},{"kelime":"ÜCRET","anlam":"Bir iş, hizmet veya bir şey-den faydalanma karşılığında verilen para veya mal, karşılık. İcâre (kira) akdi semeni. Ecr. (Bkz. Ecr, İcâre, Kirâ)","kategori":"muamelat","misal":"Ey kavmim! Peygamberliği tebliğ işinden dolayı sizden bir ücret istemiyorum. Be-nim ücretim ancak Allah’a âittir. (Hûd sû-resi: 29) Biriniz bir işçi çalıştığıracağı zaman onun ücretini kendisine bildirsin. (Hadîs-i şerîf-Darekutnî) İşçinin ücretini teri kuru-madan ödeyiniz. (Hadîs-i şerîf-İbn-i Mâce) İcâre (kirâ) akdinde ücret konuşulmazsa, akid fâsid olur. (İbni Âbidîn)","osmanli":"اجرت"},{"kelime":"ÜCûR","anlam":"Ecirler, sevablar.","kategori":"dil","osmanli":"اجور"},{"kelime":"uFKÎ","anlam":"Ufka ait; ufka doğru, yatay.","kategori":"dil","osmanli":"افقى"},{"kelime":"ÜFKÎ","anlam":"(Bkz. Ufkî)","kategori":"dil","osmanli":"افقى"},{"kelime":"ÜFTÂDE","anlam":"1.Düşmüş, düşkün. 2.Âşık. 1.Batma, kaybolma; görünmez olma; ölme. 2.Alışma, kaynaşma; görüşüp ko- nuşma; ahbablık, dostluk.","kategori":"dil","misal":"ÜFûL: افول (A)","osmanli":"افتاده"},{"kelime":"uĞuRSuZLuK","anlam":"Bir şeyi veya bir hâdiseyi şerre, kötülüğe yorumlamak, şum; bir şeyde bereketin yokluğu.","kategori":"hadis","osmanli":"اوغورسزلق"},{"kelime":"uHuD GAZÂSI","anlam":"Hicretin üçüncü senesinde Medîne yakınlarında Uhûd Dağı ci-varında Mekkeli müşriklerle yapılan ve Haz-ret-i Hamza’nın şehid düştüğü muharebe.","kategori":"dil","osmanli":"غزاسى احد"},{"kelime":"uKÂH","anlam":"Câhiliyye devrinde kabile-ler arasında taksim edilen vazifelerden, Ku-reyş sancağını taşımaya dair olanıdır ki, Beni Ümeyye’ye aitti.","kategori":"dil","osmanli":"عقاح"},{"kelime":"uKBÂ","anlam":"1.Cezâ, karşılık. 2.Âhiret âlemi.","kategori":"akaid","misal":"uKNûM: اقنوم (A) Hristiyanların kabul ettiği tes-lis inancındaki üç asıl veya üç esas varlıktan her birine verilen ad. Üçüne birden üç uknum mânâsına ekânim-i selâse denir. (Bkz. Teslîs) Hristiyanlığın başlangıcında üç uknum inanışı yoktu. Eflâtun’un ortaya koyduğu üç uknumu, üçlü tanrı inancı şeklinde mîlâddan 200 sene sonra Sibelius adlı bir papaz teklif etmiştir. 200 senesinde yalnız baba, oğul uknumları öne sü-rülmüştü. Daha sonra bunlara rûhü’l-kuds uk-numu ilâve edildi. (Îzâhu’l-Merâm)","osmanli":"عقبى"},{"kelime":"uKûBÂT","anlam":"Cezâlar. Fıkh ilminin dört kısmından biri. Ukûbet’in çokluk hâli.","kategori":"fikih","misal":"Ukûbâtta kefâlet sahîh değildir. Bu sebeble birinin yerine kefîli îdâm edilemez. (Dürerü’l-Hükkâm)","osmanli":"عقوبات"},{"kelime":"uLEMÂ","anlam":"Âlimler.","kategori":"dil","misal":"Kulları içinden ancak âlimler Allahü teâlâ-dan (hakkıyla) korkar. (Fâtır sûresi: 28) ulema yeryüzünün kandilleri, benim ve diğer pey-gamberlerin vârisleridir. (Hadîs-i şerîf-Ebû Nuaym, Deylemî) Ulemânın ilimleri, nübüvvet kandilinden alın-mıştır. Sofiyyenin marifetleri ise keşf ve ilham-dır. (Mektubbat-ı İmâm-ı Rabbânî)","osmanli":"علماء"},{"kelime":"ulemâ-i Râsihîn","anlam":"“Dinde rüsûh sahibi âlimler” mânâsına, muhkemât bilgile-rini elde ettikten sonra, müteşâbihât ile ne de-nilmek istenildiğini anlayan, sûret ile hakî-kati, yani muhkem ile müteşâbihi birleştiren; Kur’ân-ı kerîmin ve hadîs-i şerîflerin derin ve ince mânâlarını, işâretlerini anlayabilen âlim-ler için kullanılan tabir.","kategori":"dil","misal":"Sana Kitab’ı indiren O’dur. Onun (Kur’ân’ın) bazı âyetleri muhkemdir ki, bunlar Kitab’ın esasıdır. Diğerleri de müteşâbih âyetlerin pe-şine düşerler. Hâlbuki onun te’vîlini ancak Allah bilir. ulemâ-i râsihîn ise, “İnandık; hepsi Rabbimiz tarafındadır” derler. (Bu inceliği) ancak aklıselim sahipleri düşünüp anlar. (Âl-i İmrân sûresi: 7) Bir kimsenin eli açık, dili dürüst, kalbi temiz olup, boğazına ve fercine de sahip olursa o kimse ulemâ-i râsihîndendir. (Hadîs-i şerîf-Taberânî) Şeriat, zâhir ve hakîkat-i şeriat [şeriatin hakî-kati] olarak iki kısmdır. Ulemâ-ı râsihîn her kısma vâkıftır. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"راسخين علماء"},{"kelime":"ulemâ-i Zâhir","anlam":"Zâhir âlimleri. Tasavvuf dışındaki ilimlerle meşgul âlimler. uLûHİYYET: الوهيت (A) İlâhlık, ibâdet olun-","kategori":"akaid","misal":"maya hakkı olmak. Ulûhiyyete, ma’bûdiyyete hakkı olan yalnız Al-lahü teâlâdır. Şerîki, ortağı, benzeri yoktur. Vâ-cibü’l-vücûddur. Varlığı elbette lâzımdır. Nok-sanlık ve yaratılmak sıfatları, alâmetleri O’nda yoktur. (İtikadnâme)","osmanli":"ظاهر علماء"},{"kelime":"ulûhiyyet Sıfatları","anlam":"1.Bir şeye taalluk etme; ya- pışma, 2.Gebe kalma.","kategori":"akaid","misal":"Allahü teâlânın sıfat-ı zâtiyye ve sıfat-ı sübûtiyyesi. uLûK: علوق (A)","osmanli":"صفتلرى الوهيت"},{"kelime":"uLûM","anlam":"İlimler, bilgiler. İlm’in çokluk hâli. ulûm-iAkliyye: عقليه علوم (A) Aklî ilimler. His uzuvları ile duyularak, akıl ile tetkik edilerek,","kategori":"dil","misal":"tecrübe ve hesab ile elde edilen ilimler. Ulûm-i akliyyeyi İslâmiyet yasaklamamış, sı-nırlamamış ancak bunların dinin nakl bilgi-leri ile birlikte öğrenilmesini ve neticelerinin dine uygun, insanlara faydalı olarak kullanıl-masını, zulüm, işkence, felâket vâsıtası yapıl-mamasını emretmiştir. Ulûm-i akliyye, İslâm bilgilerinin bir kısmıdır. İslâmiyet’e lâzımdırlar. Müslümanlar, birçok fen vâsıtası yapmışlar ve kullanmışlardır. (Seâdet-i Ebediyye)","osmanli":"علوم"},{"kelime":"ulûm-i Âliyye","anlam":"Âlet ilimleri. Şer’î ilimlerin elde edilmesine vâsıta olan. sarf, nahv (gramer) ve mantık gibi ilimler. Ulûm-i ibtidâiyye.","kategori":"muamelat","osmanli":"آليه علوم"},{"kelime":"ulûm-i ‘Âliyye","anlam":"Yüksek din bilgileri. Ulûm-i âliyye bilgileri sekizdir: 1) Tefsir, 2) Usûl-i kelâm, 3) Kelâm, 4) Usûl-i hadîs, 5) Hadîs, 6) Usûl-i fıkıh, 7) Fıkıh, 8) Tasavvuf. (İbni Âbidîn)","kategori":"hadis","osmanli":"عاليه علوم"},{"kelime":"uLûM-İ BÂTINİYYE","anlam":"Bâtınî ilim-ler. Kalb bilgileri, tasavvuf bilgileri.","kategori":"dil","osmanli":"باطنيه علوم"},{"kelime":"ulûm-i Felekiyye","anlam":"Gökyüzü ilim-leri. Astronomi.","kategori":"dil","osmanli":"فلكيه علوم"},{"kelime":"ulûm-i Hikemiyye","anlam":"Hikmet ilim-leri. Fizik, kimya gibi, varlıklara dair ilimler. ulûm-i İbtidâiyye: ابتدائيه علوم (A) Başlangıç ilim-","kategori":"dil","misal":"leri. Âlet ilimleri. Dinî ilimleri öğrenmek için yardımcı olan sarf, nahv, belâgat, mantık vs. gibi ilimler. (Bkz. Âlet İlimleri, Ulûm-i Âliyye) ulûm-i İslâmiyye: اسلاميه علوم (A) İslâm bilgi- leri. Müslümanların bilmesi, öğrenmesi lâ- zım olan bilgiler. Gerek âlet ilimleri ve yük-sek ilimler, gerekse aklî ilimler.","osmanli":"حكميه علوم"},{"kelime":"ulûm-i Nakliyye","anlam":"Naklî ilimler. Tecrübe, müşahede ve akıl ile değil, nakil ile anlaşılan bilgiler. Edille-i şer’iyye denilen di-nin dört esas kaynağından (Kur’ân-ı kerîm, hadîs-i şerîf, icmâ ve kıyas) elde edilen ilim-ler. (Bkz. Naklî İlimler)","kategori":"hadis","misal":"Bu ilimler aklın, insan dimağı gücünün dışında ve üstündedir. Bunlar hiçbir zaman, kimse ta-rafından değiştirilemez. Dinde reform olmaz sözünün mânâsı budur. Ulûm-i nakliyye Ehl-i sünnet âlimlerinin (Peygamber efendimizin ve Eshâb-ı kirâmın yolunda olan ve onların bil-dirdiklerine uyan âlimlerin) yazdıkları kıymetli kitaplardan öğrenilir. (Fâideli Bilgiler)","osmanli":"نقليه علوم"},{"kelime":"ulûm-i Tabî‘iyye","anlam":"Tabiî ilimler. Fizik, kimya, biyoloji, tıb gibi pozitif ilimler. ulûm-i Tıbbiyye: طبيه علوم (A) Tıb ilimleri. Can-","kategori":"dil","misal":"lıları öğreten ilimler.","osmanli":"طبيعيه علوم"},{"kelime":"ulûm-i Zâhîre","anlam":"Fıkıh gibi, zâhire vuran amelleri mevzu edinen ilimler.","kategori":"akaid","osmanli":"ظاهره علوم"},{"kelime":"uMACI","anlam":"Çocukları korkutan ha-yalî varlık.","kategori":"dil","osmanli":"اوماجى"},{"kelime":"ÜMMET","anlam":"Cemâat, topluluk; bir peygambere iman eden insanlar.","kategori":"akaid","misal":"(İbrâhim aleyhisselâmı dünyada hayırlı, âhirette sâlihlerden) kıldığımız gibi, ey Müslümanlar sizi (de) seçkin ve hayırlı bir ümmet kıldık ki, kıyâmet gününde peygamberlerin ümmetlerine vahyi tebliğ ettiklerine şâhidler olasınız, Peygamber de sizin adâletiniz üzerine şâhid ola. (Bakara sûresi: 143) Siz ümmetlerin en iyisi oldunuz. İnsanların iyiliği için yaratıldınız. İyilik yapılmasını emreder, kötülükten nehyeders…","osmanli":"امت"},{"kelime":"ÜMMÎ","anlam":"1.“Annesinden doğduğu gibi” mânâsına kitap okumamış, yazı yazmamış, kimseden ders görmemiş kişi. 2.Allah tara-fından yetiştirilen, terbiye edilen.","kategori":"ibadet","misal":"Onlar ki, yanlarında bulunan Tevrat ve İn-cîl’de ismini yazılı buldukları O ümmî resûle tâbi olurlar. O (Resûl) kendilerine iyiliği em-rediyor, kötülükten sakındırıyor... (Resû-lüm) de ki: “Ey insanlar! Gerçekten ben si-zin hepinize gelen, Allah’ın peygamberiyim. O Allah ki, yer ve göklerin tasarrufu (idâ-resi) O’nundur. O’ndan başka hiçbir ilâh yoktur, öldürür ve diriltir. Onun için hem Allah’a hem de bütün kelimelerine îmân eden O ümmî peygambere, resûlüne îmân edin ve O peygambere uyun ki, doğru yolu bulasınız. (A’râf sûresi: 157,158) Ben ümmî, doğru ve tertemiz peygamberim. Beni ya-lanlayan ve benden yüz çevirene yazıklar olsun. Beni barındıran, bana yardım eden, sözümü tasdik eden ve benimle beraber ci-had edenlere müjdeler olsun. (Hadîs-i şerîf-İbni Sa‘d) Biz ümmî bir milletiz. Hesab bil-meyiz. Hilâli görür oruç tutarız, hilâli görür iftar ederiz. (Hadîs-i şerîf-Buhârî, Müslim, Ebû Dâvûd, Nesâî) Resûlullah aleyhisselâm ümmî idi. Mekke’de doğup, büyüyüp belli kimseler arasında yetişip seyâhat etmemiş iken, Tevrat’ta, İncîl’de ve Yu-nan ve Roma devirlerinde yazılmış kitablarda bulunan bilgilerden, hâdiselerden haber verdi. (Mevâhib-i Ledünniyye)","osmanli":"امى"},{"kelime":"ÜMMÎD (Ümîd)","anlam":"Ummak, arzu, istek. Sebeblere yapıştıktan sonra iyi netice beklemek.","kategori":"fikih","misal":"Allahü teâlâdan korkmalı, O’nun rahmetinden ümidi kesmemelidir. Ümid, korkudan çok olmalıdır. Böyle olanın ibâdetleri zevkli olur. Gençlerde korkunun, ihtiyarlarda ve hastalarda ümidin fazla olması lâzımdır denildi. Korkusuz ümit, ümitsiz korku câiz değildir. (Berîka)","osmanli":"اميد"},{"kelime":"ÜMMÜ VELED (Ümm-i Veled)","anlam":"Çocuk annesi. Efendisinden çocuğu olan câriye, köle kadın.","kategori":"osmanli","misal":"Ümmü veled satılamaz ve hibe olunamaz. Efendisi vefât edince âzâd (hür) olur ise de, zevce gibi vâris olamaz. Çocuğu ise, hür ve babasına mirasçı olur. (Ni’met-i İslâm)","osmanli":"ولد ام"},{"kelime":"uMRE","anlam":"1.Ziyaret etme. 2.Hac dışında, ihrâma girip tavâf ve sa’ydan ibaret bir ibâdet.","kategori":"ibadet","misal":"Hacc-ı asgar (küçük hac). Başladığınız hac ve umreyi Allah için ta-mamlayın. Alıkonursanız, kolayınıza ge-len bir kurban gönderin. (Bakara sûresi: 196) umre, kendisiyle öbür umre arasında işleni-len (küçük) günahlara keffârettir (Onların af edilmesine, bağışlanmasına vesîle olur.) (Ha-dîs-i şerîf-Buhârî) Umre, Hanefî ve Mâlikîlere göre sünnet-i mü-ekkededir. Şâfiîlere göre ömründe bir defâ farz-dır. (Dürrü’l-Muhtar)","osmanli":"عمره"},{"kelime":"uMûM","anlam":"(A. Âmm’dan) Hep, bütün, cümle. uMûMÎ BELVÂ: بلوى عمومى (T) Hemen her-kesin kaçınmakta güçlük çektiği şey. Zarûret","kategori":"dil","misal":"hükmünün herkese teşmili. Belvâ-yı âmm. Umûmü’l-belvâ. At ve kümes hayvanları dışındaki eti yenen ehlî hayvanların dışkı ve idrarları ile kuşların pis-likleri, beden veya elbiseye bulaşırsa, dörtte bire kadar namaza mâni olmaz. Kedi, fare, serbest dolaşan tavuk gibi evlerin çevresinde insanlarla yaşayan hayvanların artıkları da temizdir. Zira umumî belvâdır. (İbni Âbidîn)","osmanli":"عموم"},{"kelime":"uMûMÎ VEKİL","anlam":"Dilediği gibi hareket etmek üzere vekil edilen kimse.","kategori":"dil","misal":"Vekil sahibinden izin almadıkça veya umûmî vekil olmadıkça, başkasını kendine vekil yapa-maz. Yalnız, zekât vermek için olan vekîl, izin-siz olarak başkasını, o da başkasını vekil yapa-bilirler. (İbni Âbidîn)","osmanli":"وكيل عمومى"},{"kelime":"ÜNS","anlam":"Aşinalık, yakınlık.","kategori":"dil","osmanli":"انس"},{"kelime":"uRûC","anlam":"Yukarı çıkma, yükselme. Urûc ederken, ilerlerken birbirinden ayrılıklar bulunursa ve bir asldan, başka asla geçiliyorsa, böyle kemâlâtın hepsi, Evliyâlıktadır. (Mektû-bât-ı İmâm-ı Rabbânî)","kategori":"tasavvuf","osmanli":"عروج"},{"kelime":"uRûZ","anlam":"Nukûd (altın, gümüş), hay-van, mekîl ve mevzûn (ağırlıkla ve hacimle öl-çülen) mallardan başka her çeşit menkul mal. Arâz’ın çokluk hâli.","kategori":"ibadet","misal":"Urûz kelimesi akar ve hayvanât ve mekilât ve mevzûnâta mukâbil olarak isti’mâl olunur ise de ba’zen dahi yalnız hayvan ve akara mukâbil olarak isti’mâl olunur. Mecelle’nin yüz altmış be-şinci maddesinde mekilât ve mevzûnât mezkûr olmadığından urûz burada mekilât ve mevzûnâta şâmil olur. Mecelle Cemi’yeti’nde bu vecihle mu-tala‘a olunmuştur. (Mecelle, madde 165 şerhi) Ticâret urûzundan nass ile bildirilen kendinin kırkta biri verilir. Kendi cinsinden olan başka mal verilirse, iyi yerine orta veya aşağı mal ve-rilince, aradaki farkı tamamlamak lâzım olur. (İbni Âbidîn)","osmanli":"عروض"},{"kelime":"uRYÂN","anlam":"Çıplak.","kategori":"dil","osmanli":"عريان"},{"kelime":"uSÂRE","anlam":"Sıkılan şeylerden çıkan su.","kategori":"dil","osmanli":"عصاره"},{"kelime":"uşrlu Toprak","anlam":"Mahsulünden uşr (öşür) alınan arâzî. Arâzî-i Memleket. uŞŞÂKİYYE: عشاقيه (A) Anadolu’da hicrî XI.","kategori":"muamelat","misal":"asırda yaşamış Halvetî şeyhi Hasan Hüsâmed- dîn Uşâkî’nin tasavvuftaki yolu.","osmanli":"طوﭘراق عشرلى"},{"kelime":"ÜSTÂD","anlam":"Muallim, öğretici, rehber. Üstâd mâhir ve müşfik, talebe de zekî ve çalış-kan olursa, öğrenilmeyecek mesele yoktur. (Ab-dülhakîm Arvâsî)","kategori":"akaid","osmanli":"استاد"},{"kelime":"ÜSTÂZ","anlam":"Hoca, üstad.","kategori":"dil","osmanli":"استاذ"},{"kelime":"ÜSTÜRLAB","anlam":"Namaz vakitlerinin hesaplanmasında ve yıldızların arza nazaran yükseklik derecesini ölçmekte kullanılan âlet.","kategori":"ibadet","misal":"(Bkz. Rub’-ı Dâire)","osmanli":"اوسطرلاب"},{"kelime":"ÜSTÜVÂNE","anlam":"1.Direk; içi boş. 2.Silindir.","kategori":"dil","misal":"ÜSVE-İ HASENE (Üsvetün Hasenetün): اسوء حسنه (A) “Güzel numune” mânâsına Resûlul- lah aleyhisselâmın lakabı.. Andolsun ki Resûlullah’ta sizin için, Allahü teâlâya ve âhiret gününe kavuşmayı uman-lar ve Allah’ı çok zikredenler için üsve-i ha-sene vardır. (Ahzâb sûresi: 21)","osmanli":"استوانه"},{"kelime":"uSûL","anlam":"1.Asıllar, kökler, temeller. 2.Bir ilmin öğrenilme metodu, metodolojisi. 3.Yol, yordam.","kategori":"fikih","misal":"Baba, dede, anne ve nineler. Asl ke-limesinin çokluk hâli. Usûlsüz vusûl olmaz. (Kelâm-ı kibar)","osmanli":"اصول"},{"kelime":"usûl Bilgileri","anlam":"1.Bir ilmin asıl mevzuundan evvel öğrenilmesi gereken baş-langıç bilgileri. 2.Hanefî mezhebinin İmâm Muhammed’in ilk altı kitabı ile bildirilen hükümleri.","kategori":"hadis","misal":"Bir ilmin nasıl çıkarıldığını öğ-reten ilim. (Bkz. İlm-i Usûl-i Fıkh, İlm-i Usûl-i Hadîs, İlm-i Usûl-i Kelâm) Zâhir haberler. Zâhirü’r-Rivâye. Hanefî mezhebinin birinci derece mehazı olan usûl bilgileri, İmâm Ebû Hanîfe ile İmâm-ı Ebû Yûsuf ve İmâm-ı Muhammed’in kaville-rini ihtivâ eden el-Mebsût, ez-Ziyâdât, el-Câ-miu’s-Sagîr, es-Siyerü’s-Sagîr, el-Câmiü’l-Ke-bîr, es-Siyerü’l-Kebîr adlı altı kitapta yer alır. Bu altı kitabı İmâm-ı Muhammed yazmıştır. Bu kitabları İmâm-ı Muhammed’den güvenilir kimseler bildirdiği için, bunlara zâhir haberler denmiştir. Usûl bilgilerini ilk toplayan Hakîm Şehîd’dir. Bunun Kâfî kitabı meşhurdur. Hanefî mezhebi hükümlerini bildiren diğer iki kısım Nevâdir ve Vâkıat haberleridir. (İbni Âbidîn)","osmanli":"بيلگيلرى اصول"},{"kelime":"usûl-i Din","anlam":"1.İman bilgileri. 2.Tefsir, hadîs ve usûl-i hadîs ilimleri.","kategori":"hadis","misal":"Usû-lü’d-dîn. usûl-i Erba‘a: اربعه اصول (A) Dört asıl. İslâm dininin kaynakları olan kitap, sünnet, icma’ ve kıyas.","osmanli":"دين اصول"},{"kelime":"usûl-i Kelâm","anlam":"Îmân bilgilerinin âyet-i kerîmelerden ve hadîs-i şerîflerden nasıl çıka-rıldığını öğreten ilim. Usûlü’l-Kelâm.","kategori":"dil","osmanli":"كلام اصول"},{"kelime":"usûl ve Fürû’","anlam":"1.Asllar (kök-ler) ve fer’ler (dallar). 2.İmân ve fıkıh bilgileri.","kategori":"fikih","misal":"Baba, dede, ana ve ni-neler ile çocuklar ve torunlar. Usûl ve furû’a ve zevceye zekât verilmez. (Ni’met-i İslâm)","osmanli":"فروع و اصول"},{"kelime":"ÜVEYSÎ","anlam":"Bir velînin ruhâniyyetinden feyz alan kimse; ruhların terbiye ettiği kimse.","kategori":"akaid","misal":"Behâüddîn-i Buhârî’nin üstâdı, Emîr Külâl hazretleri idi. Fakat ayrıca Hâce Abdülhâlık Goncdüvânî’nin rûhâniyetinden istifâde ettiği için aynı zamanda üveysî idi. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"اويسى"},{"kelime":"uZVİYYET","anlam":"Canlılık; organizma.","kategori":"dil","osmanli":"عضويت"},{"kelime":"VAAZ (Va‘z)","anlam":"Nasihat; dil ile emr-i ma’rûf ve nehy-i münker.","kategori":"dil","misal":"Va’z edenlerin, din adamlarının, cemâatin anlayamayacakları şeyleri söylemeleri ve yazmaları fitne olur. Herkese anlayabileceği kadar söylemelidir. (Berîka)","osmanli":"وعظ"},{"kelime":"VÂCİB","anlam":"1.Dinen yapılması şart ve yapılmaması hâlinde karşılığı azap olan şey, farz. 2.Hanefî mezhebinde, açık olmayan âyetler gibi sübûtu zannî veya bir kişinin bildirdiği ahad hadîs gibi delâleti zannî olan bir delille sâbit olan hüküm. Amelî farz. Resûlullah aleyhisselâmın devamlı yapıp, yapmayanı inkâr ettiği işler vâcibdir. Kurban, bayram namazı, fıtra gibi. Vâcibin terki, tahrîmen mekrûhtur. (İbni Âbidîn) Vâcibin inkârı küfr değildir. Terki ise, tahrîmen mekrûhtur. (İbni Âbidîn)","kategori":"fikih","osmanli":"واجب","alternatif":["vacib","vacip"]},{"kelime":"VÂCİD","anlam":"Bulan, mâlik olan. Ma’bûd, Rab, ilâh olan, zâtında bulunması lâzım ve lâyık olan bütün sıfatları kendisinde","kategori":"akaid","misal":"bulunan, hiçbir şeye muhtaç olmayan, kendisinden hiçbir şey gizli kalmayan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elVâcid). ElVâcid ism-i şerîfini okuyanın kalbi kuvvet bulur. (Elİstigâsetü’l-Kübrâ)","osmanli":"واجد"},{"kelime":"VAD’-I HAML","anlam":"Doğum yapmak. Zinâdan hâmile kadını, vad’-ı haml etmeden evvel nikâh etmek sahîhtir.","kategori":"dil","misal":"Fakat vad’ı haml edinceye kadar vaty etmek (yaklaşmak) câiz olmaz ve nafakası vâcib olmaz. (İbni Âbidîn)","osmanli":"حمل وضع"},{"kelime":"VAHDET","anlam":"Birlik. Tasavvufta, her şeyi bir olarak ve bir içinde, nesneleri Allah ile görmek.","kategori":"akaid","osmanli":"وحدت"},{"kelime":"Vahdet-i Vücûd","anlam":"“Varlığın birliği” mânâsına Allahü teâlâdan başka hakikî varlık olmadığının idrak ve şuuruna sahip olma.","kategori":"akaid","misal":"Mümkinâtı, yani mahlûkâtı tek bir varlık olarak görme.","osmanli":"وجود وحدت"},{"kelime":"VÂHİD","anlam":"1.Bir, birinci, tek. 2.Zâtında, sıfatlarında ve fiillerinde benzeri ve ortağı bulunmayıp tek olan mânâsına Allahü teâlâ-nın Esmâ-i hüsnâsından (el-Vâhid). (Habîbim!) De ki: Allah her şeyin yaratı-cısıdır. (O’nun ortağı yoktur.) O, Vâhid’dir. Kahhâr (her şeye gâlib)dır. (Ra’d sûresi: 16)","kategori":"dil","osmanli":"واحد"},{"kelime":"VAHÎM","anlam":"Vahâmetli, sonu tehlikeli, çok korkulu.","kategori":"dil","osmanli":"وخيم"},{"kelime":"VAHŞET","anlam":"Vahşîlik, yabanîlik; ıssız-lık, tenhalık; korku, ürküntü.","kategori":"dil","osmanli":"وحشت"},{"kelime":"VAHŞÎ","anlam":"Yabanî, insandan kaçan; ür-kek, korkak; duygusuz, merhametsiz.","kategori":"dil","osmanli":"وحشى"},{"kelime":"Vahy Kâtibi","anlam":"Resûlullah aleyhisselâma gelen vahyi, O’nun emri ile yazan sahâbîlere verilen isim.","kategori":"dil","misal":"Eshâb-ı kirâm arasında kırküç kadar vahiy kâtibi vardı. Meşhûr vahiy kâtibleri, Hazret-i Ebû Bekr, Hazret-i Ömer, Hazret-i Osman, Hazret-i Ali, Hazret-i Muâviye, Hâlid bin Velîd, Abdullah bin Zeyd, Zeyd bin Sâbit radıyallahü anhüm idi. İçlerinde en çok katiplik yapan Zeyd bin Sâbit ile Muaviye bin Ebi Süfyân idi. (elİsâbe)","osmanli":"كاتبى وحى"},{"kelime":"VAHY (Vahiy)","anlam":"1.Gizli konuşma, fısıldama, ilham etme, öğretme.","kategori":"dil","misal":"Rabbin bal arısına: Dağlardan, ağaçlardan ve insanların yaptıkları çardaklardan kendine evler edin. Sonra meyvelerin her birinden ye ve Rabbinin sana kolaylaştırdığı yaylım yollarına gir, diye vahyetti. Onların karınlarından renkleri çeşitli bir şerbet (bal) çıkar ki, onda insanlar için şifâ bulunur. Elbette bunda düşünen bir kavim için büyük bir ibret vardır. (Nahl sûresi: 68-69) Hâmil-i Kur’ân (Kur’ân-ı kerîmi ezb…","osmanli":"وحى"},{"kelime":"VAKF (Vakıf)","anlam":"1.Durma; tutma, alıkoyma. 2.Mükellef bir Müslümanın malının mülkiyetini umuma ait tutup, menfaatini ise muayyen bir cihete tahsis etmesi.","kategori":"muamelat","misal":"Çokluk hâli evkâf gelir. Vakfedene vâkıf, vakfedilen şeye mevkûf, vakfın menfaati kendisine bırakılana mevkûfun aleyh, vakfın kuruluş senedine de vakfiye denir. Abdullah ibni Ömer buyurdu ki: “Babam Ömer (radıyallahü anh) Hayber topraklarındaki mülkü olan bahçesini, tasadduk etmek yani sadaka olarak vermek istiyordu. Peygamber efendimize ne yapmasını sormuştu. Peygamber efendimiz; “…","osmanli":"وقف"},{"kelime":"VAKFE","anlam":"1.Durma, ayakta durma. 2.Haccın farzlarından olup, Arefe günü Arafat’ta öğle ile ikindi namazından sonra bir mikdar durma. 3.Kur’ân-ı Kerîmi kırâet ederken durulacak yerler.","kategori":"ibadet","misal":"Secâvend, durak. (Bkz. Vakf)","osmanli":"وقفه","alternatif":["vukuf"]},{"kelime":"VÂKÎ","anlam":"1.Bir şeyi ıslah edip düzene sokan, koruyup gözeten, himâye eden. 2.Mü’minleri dünyada belâlardan ve âhirette azaptan koruyan mânâsına Allahü teâlânın sı-fatlarından (el-Vâkî).","kategori":"akaid","misal":"(A. Vikâye’den) Dünya hayatında onlar (kâfirler) için azap vardır. Âhiret azâbı ise daha zordur. Onları Allah’ın azâbından koruyacak vâkî yoktur. (Ra’d sûresi: 34)","osmanli":"واقى"},{"kelime":"VÂKI‘ÂT","anlam":"1.Gerçek hâdiseler. 2.Hanefî mezhebinde, İmâm Ebû Hanîfe, Ebû Yûsuf ve Muhammed’den bildirilmiş olmayıp, bunların talebelerinin ve talebesi talebelerinin ictihâd ettikleri hükümler. Zâhirü’r-rivâye (Usûl) ve Nevâdir haberlerinden sonra üçüncü derecede gelir. (Bkz. Hanefî Mezhebi) Hanefî mezhebinde vâkı‘ât haberlerini ilk toplayan Ebü’l-Leys Semerkandî olup, Nevâzil kitabını yazmıştır. (İbni Âbidîn)","kategori":"hadis","misal":"çokluk hâli.","osmanli":"واقعات"},{"kelime":"VÂKIF","anlam":"1.Vakfeden. 2.Vukuf sahibi; bir işten haberi olan. 3.Arafât’ta vakfeye duran.","kategori":"muamelat","misal":"Vâkıfın Müslüman, hür, âkıl ve bâliğ olması lâzımdır. (İbni Âbidîn) Şart-ı Vâkıf (vâkıfın koyduğu şart), nass-ı şârî (din sahibinin koyduğu kânun) gibidir. (İbni Âbidîn) Meşveret olunan kimsenin vâkıf olmadığı şeyi veya vâkıf olduğunun aksini söylemesi günahtır. Hatâ ile söylemesi günah olmaz. (Berîka)","osmanli":"واقف","baglamlar":[{"baglam":"hukuk","anlam":"Bir malı veya mülkü, Allahü teâlânın mülkü hükmünde sayarak, gelirini fakirlere veya hayır işlerine bırakma."},{"baglam":"kurum","anlam":"Vakıf müessesesi; hayır amacıyla kurulan, Osmanlı medeniyetinin temel kurumlarından."}]},{"kelime":"VÂLÎ","anlam":"1.Vilâyet sahibi, bir vilâyeti idare eden yüksek memur. 2.Mâlik, sahip. 3.Her şeyin mâliki (sahibi), ya-ratıcısı, bütün işler tasarrufunda olan, her şey O’nun irâdesi, hükmü ile olan mânâsına Al-lahü teâlânın Esmâ-i hüsnâsından (el-Vâlî). el-Vâlî ism-i şerîfini söyleyen, yıldırım ve başka âfetlerden kurtulmuş olur. (El-İstigâsetü’l-Kübrâ)","kategori":"dil","misal":"Bir vâlî kapısını ihtiyaç ve dilek sahiplerinin yüzüne kapatırsa, Allahü teâlâ da mutlaka onun ihtiyaç ve dileklerine karşı gök kapı-larını kapatır. (Hadîs-i şerîf-Tirmizî, Müsnedü İmâm-ı Ahmed) Cum‘a namazının şartlarından biri, devlet ve hükûmet reîsinin veya vâlînin izni ile kılmak-tır. (İbni Âbidîn)","osmanli":"والى"},{"kelime":"VALLÂHİ","anlam":"“Allahü teâlâya yemin ederim” mânâsına bir yemin sözü.","kategori":"akaid","misal":"Yemîn yalnız Allahü teâlânın isimleri ile olur. Başka şeylerle, Müslüman yemîni olmaz. Allahü teâlânın isimleri ile yemîn ya harf ile veya kelime ile olur. İsmin başında be, te, ve harflerinden biri söylenip, ismin sonu esre okunursa, yemin olur. Meselâ billâhi, tallâhi, vallâhi demek gibi. (Dürrü’l-Muhtar)","osmanli":"والله"},{"kelime":"VÂRİDÂT","anlam":"1.Vürûd edenler, gelen-ler. 2.Gelirler. 3.Hatıra gelenler, içe doğanlar.","kategori":"dil","misal":"Vâride’nin çokluk hâli..","osmanli":"واردات"},{"kelime":"Vâridât-i İlâhiyye","anlam":"Allahü teâlâdan vürûd eden, gelen feyz ve ilhamlar.","kategori":"akaid","misal":"Abdullah-ı Dehlevî hazretlerinin çok kerâmetleri görüldü. En büyük kerâmeti, gelen sâdık kimselerin kalblerine teveccüh (nazar) ederek feyz ve bereketle doldurmasıydı. Binlerce âşıkı bir bakışta vâridât-ı ilâhiyyeye kavuştururdu. (Dürrü’l-Meârif)","osmanli":"الهيه واردات"},{"kelime":"VÂRİS","anlam":"1.Mirasçı, akrabalık veya başka yolla, vefât eden kimsenin bıraktığı mallardan almaya hak kazanan. 2.Vefat eden birinin maddî veya manevî mülkünde tasarruf eden.","kategori":"miras","misal":"Vârise vasîyet yoktur. Diğer vârisler izin verirse, o başka. (Hadîs-i şerîfBeyhekî) Âlimler, peygamberlerin vârisleridir. (Hadîs-i şerîfDeylemî, Ebû Nuaym)","osmanli":"وارث"},{"kelime":"VASATÎ","anlam":"Ortalama, ikisi ortası.","kategori":"dil","osmanli":"وسطى"},{"kelime":"VASF","anlam":"1.Bir kimsenin veya şeyin taşıdığı sıfat. 2.Bir kimseyi veya şeyi hususiyetlerini ortaya koyarak tarif etme; övme.","kategori":"akaid","osmanli":"وصف"},{"kelime":"VÂSİ‘","anlam":"1.Geniş, vüs’atli. 2.Rahmeti, ilmi, kudreti, ihsânı ve nîmetleri her şeyi kuşatan ve her şeye kâfi olan, kudretinin ve ilminin nihâyeti olmayan mânâsına Allahü teâlânın Esmâ-i hüsnâsından. Allahü teâlâ mülkün sahibidir. Mülkünü dilediğine verir. Allah Vâsi‘dir, her şeyi bilir. (Bakara sûresi: 247) Allahü teâlâ, madde değildir, cisim değildir, araz, hâl değildir. Hudûdlu, boyutlu değildir. Uzun, kısa, geniş, dar değildir. Ona. (Vâsi‘) yani geniş deriz. Fakat; bu genişlik, bizim bildiğimiz, anladığımız gibi değildir. (Mektûbât-ı İmâm-ı Rabbânî) ElVâsi‘ ism-i şerîfini söyleyen, fakirlik sıkıntısına düşme…","kategori":"akaid","osmanli":"واسع"},{"kelime":"VASÎ","anlam":"1.Vesâyet eden, bir vasîyeti tenfiz etmek (yerine getirmek) üzere tayin edilen kimse. 2.Çocuk, akıl hastası, sefih gibi mahcur birinin mallarında onun rızası olmaksızın tasarruf etmeye salâhiyetli kimse.","kategori":"miras","misal":"Ey vasîler, yetimlerin malları ile ticaret edin ki, zekât mallarını yiyip bitirmesin. (Hadîs-i şerîfTaberânî) Fâsık, müsrif olmayan baba, baba ölmüş ise babanın vasîsi, bu da ölmüş ise, ölürken vasıyyet ettiği kimse, bu ikinci vasî de yoksa, babanın âdil olan babası, bu da yoksa, dedenin vasîsi veya vasîsinin vasîsi, birinci derece velîdirler. (Dürer) Vasî, âkıl, bâliğ, reşid, emîn, âdil ve çocuk ile aynı dinden olm…","osmanli":"وصى"},{"kelime":"VASIYYET (Vasîyet)","anlam":"1.Bir işi bir başkasına havale etme, vasî tayin etme. 2.Bir kimsenin vefatından sonra yapılmasını istediği şey veya bir malı veya menfaatini bir şahsa veya bir hayır cihetine bırakması. Ey iman edenler! Birinize ölüm gelip çatınca vasîyet ederken içinizden iki âdil kimse şâhidlik etsin. (Mâide sûresi: 106) Vasîyet edeceği bir şey olup da vasîyetini yazmadan iki gece geçirmek bir Müslümana lâyık değildir. (Hadîs-i şerîfBuhârî) Vasîyet üçte biridir. Vârisleri zengin etmek, onları başkalarına muhtaç etmekten daha hayırlıdır. (Hadîs-i şerîfMüslim) Üzerinde zekât, keffâret, hac gibi yerine getirilmemiş…","kategori":"miras","osmanli":"وصيت"},{"kelime":"VASL","anlam":"1.Kavuşma.","kategori":"akaid","misal":"Allahü teâlâya ka-vuşma; velî olma. Birleştirme. Kur’ân-ı kerîm kıraat ederken, geçilecek yerde geçip, iki kelimeyi birleştirme. Belâgat ilminde, bir cümlenin atıf harfi ile diğer cümleye bağlanması. Fasl’ın zıddı.","osmanli":"وصل"},{"kelime":"Vasl-ı uryânî","anlam":"Tasavvuf yolculuğunun sonunda Allahü teâlâya kavuşma hâli.","kategori":"akaid","misal":"Vasl-ı uryânîde sâlik (tasavvuf yolcusu), vücûdunun her zerresi ile Allahü teâlâyı zikreder. (Mektûbât-ı İmâm-ı Rabbânî) Vasl-ı uryânî, nûrânî perdelerin tamâmen yanmasından sonradır. (Mektûbât-ı İmâm-ı Rabbânî) Ben tenden kurtulurum, o hayâlden kurtulur, Gideyim, vasl-ı uryânî ancak böyle bulunur. (Mevlânâ Celâleddin)","osmanli":"عريانى وصل"},{"kelime":"VATAN","anlam":"İnsanın yerleştiği, oturduğu yer, memleket, yurt.","kategori":"dil","misal":"Vatan sevgisi îmândandır. (Hadîs-i şerîf-el-Makâ-sıdü’l-Hasene, Mesnevî, Mektûbât-ı Rabbânî)) Vatan-ı Aslî: اصلى وطن (A) İnsanın doğduğu veya evlendiği veya ayrılmamak niyeti ile yerleştiği yer. Vatan-ı aslî, yalnız misli ile bâtıl olur. Bir kimse, bir yerde evlenir veya orada yerleşmeye ka-rar verince, önceki vatan-ı aslîsi bozulur; bu-rası yeni vatan-ı aslîsi olur. Sefere çıkmak, va-tan-ı aslîyi bozmaz. Bir kimse, vatan-ı aslîye girince mukîm olur. Namazlarını dört kılar. (İbni Âbidîn) Zevcesini bir yerde yerleştirip, sonra kendisi başka yere yerleşse, ikisi de vatan-ı aslîsi olur. (İbni Âbidîn)","osmanli":"وطن"},{"kelime":"Vatan-ı İkâmet","anlam":"Giriş ve çıkış günlerinden başka Hanefî’de onbeş, diğer üç mezhebte dört gün veya daha fazla kalıp, sonra çıkmaya niyet edilen yer.","kategori":"ibadet","misal":"Vatan-ı ikamet, ya mislî ile ya vatan-ı aslî ile veya oradan sefere çıkmakla bâtıl olur. (İbni Âbidîn)","osmanli":"اقامت وطن"},{"kelime":"Vatan-ı Süknâ","anlam":"Giriş ve çıkış günlerinden başka Hanefî’de onbeş, diğer üç mezhebte üç gün veya daha az kalıp, sonra çıkmaya niyet edilen yer.","kategori":"fikih","misal":"Misâfir, vatan-ı süknâda farzları hep iki kılar. Burada iken mukim sayılmaz. (İbni Âbidîn)","osmanli":"سكنى وطن"},{"kelime":"VATY","anlam":"Erkeğin hanımına yaklaşması; cimâ.","kategori":"ibadet","misal":"Zinâdan hâmile kadını, vad’-ı haml etmeden (doğum yapmadan) evvel nikâh etmek sahîh-tir, olur. Fakat doğum yapıncaya kadar vaty etmek câiz olmaz ve nafakası vâcib olmaz. (İbni Âbidîn)","osmanli":"وطى"},{"kelime":"VAZÎFE","anlam":"1.Bir kimsenin yapmaya mecbur olduğu iş. 2.Bir kimseye, her gün için takdir edilen erzak; vakfın gelirlerinden veri-len maaş ve tayinât.","kategori":"dil","misal":"Çokluk hâli vezâif gelir.","osmanli":"وظيفه"},{"kelime":"VECD","anlam":"1.Bulma, var olma. 2.Tasavvufta sâlikin isteği ve gayreti olmaksızın kalbine gelen ilahî tecelliler; elde olmayarak coşma.","kategori":"tasavvuf","misal":"Hâller ve vecdler, matlûbun başlangıcıdır, maksat değildir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"وجد"},{"kelime":"VECÎBE","anlam":"Vâcib olan şey, borç hük-münde olan vazife.","kategori":"muamelat","osmanli":"وجيبه"},{"kelime":"VECÎZ","anlam":"Kısa, derlitoplu. Manası de-rin olan söz.","kategori":"dil","osmanli":"وجيز"},{"kelime":"VEDÂ HACCI","anlam":"Hicretin onuncu senesinde Resûlullah aleyhisselâmın onbinlerce sahâbinin katılmasıyla yaptığı hac.","kategori":"ibadet","misal":"Peygamber efendimiz Vedâ haccında Arafât vadisinin ortasında öğleden sonra, Kusvâ adındaki devesinin üstünde Vedâ hutbesini okuyup Eshâb-ı kirâm ile vedâlaştı. Mekke’de on gün kalıp vedâ haccını tamamladı ve vedâ tavâfı yaparak Medîne’ye döndü. Vedâ haccından sonra Eshâb-ı kirâm geldikleri yerlere gidip Resûlullah’ın bildirdiği ve emrettiği şeyleri oralarda anlattılar. (Siretü İbni Hişâm)","osmanli":"حجى وداع"},{"kelime":"VEDÎ‘A","anlam":"Bir malı saklamak üzere bir kimse nezdinde emânet bırakma.","kategori":"muamelat","misal":"Bir kimse mâlını bir dükkâncının yanına bırakıb gitse ve o dahi görüp sükût etse ol dükkân sâhibi nezdinde vedî‘a olur. Ve eğer dükkân sâhibi kabûl etmem diyerek reddetse îdâ‘ mün‘akid olmaz. (Mecelle, m. 73) Vedî‘a, sahibinden izinsiz kullanılamaz; âriyet, kirâ ve rehin ve ödünç verilemez ve sahibinin borcu, onun izni olmadan ödenemez. Bunları izin ile yapabilir. (Dürerü’l-Hükkâm)","osmanli":"وديعه"},{"kelime":"VEDÎ (Vedy)","anlam":"Umumiyetle idrardan sonra çıkan, yapışkan, beyaz ve bulanık koyu sıvı.","kategori":"muamelat","misal":"Vedî çıkınca dört mezhebte de abdest bozulur. Hanbelî mezhebinde gusül de lâzım olur. (Halebî) Vedî, Hanefî mezhebinde kaba necâsettir. (İbni Âbidîn)","osmanli":"ودى"},{"kelime":"VEDûD","anlam":"Mü’minleri çok seven, onlardan râzı olan ve bol ihsanda bulunnan mânâsına Allahü teâlânın Esmâ-i hüsnâsından (elVedûd).","kategori":"akaid","misal":"ElVedûd ism-i şerîfini söyleyen karıkocanın birbirine karşı sevgi ve muhabbeti çoğalır. (elİstigâsetü’l-Kübrâ)","osmanli":"ودود"},{"kelime":"VEFÂ","anlam":"1.Sözünde durma; borcunu ödeme. 2.Yetişme, kâfi gelme. 3.Dostluğu devam ettirme ve yapılan iyiliği unutmama.","kategori":"muamelat","misal":"(Bkz. Ahd) Kim Allahü teâlâ ile olan ahdine vefâ gösterirse, Allah ona büyük bir mükâfat verecektir. (Feth sûresi: 10) Ahde vefâ imandandır. (Hadîs-i şerîfHâkim) Allahü teâlânın üzerinizdeki hakkını yerini getirin. Çünki Allah vefâ gösterilmeye en lâyık zâttır. (Hadîs-i şerîfBuhârî, Neseî, Dârimî) Dünyaya ve buna düşkün olanlara inanılmaz.…","osmanli":"وفاء"},{"kelime":"VEFİYYÂT","anlam":"Ölümler. Vefât’ın çokluk hâli. VEHHÂB: وهاب (A. Vehb’den) Mahlûkâtına, ih-sân hazînelerinden karşılıksız bol bol veren","kategori":"dil","misal":"mânâsına Allahü teâlânın Esmâ-i hüsnâsın- dan (el-Vehhâb). Yâ Rabbî! Bizi doğru yola hidâyet ettikten (ilettikten) sonra kalblerimizi şek ve şüpheye saptırma, meylettirme. Bize, kendi tarafın-dan rahmet (tevfîk, îmân, hidâyet ve doğru yolda devam etmek) ver. Şüphesiz sen, Veh-hâb’sın. (Âl-i İmrân sûresi: 8) El-Vehhâb ism-i şerîfini kim duhâ (kuşluk) namazından sonra söylerse, başkasına muh-taç olmaz. Kalblerde heybet hâsıl eder. (El-İs-tigâsetü’l-Kübrâ)","osmanli":"وفيات"},{"kelime":"VEHHÂBÎLİK (Vehhâbiyye)","anlam":"XVIII. asırda Arabistan’da Muhammed bin Abdülvehhâb tarafından XIII.","kategori":"dil","misal":"asırda yaşamış İbni Teymiyye’nin fikirlerine dayanma iddiasıyla kurulan ve Suud ailesinin desteğiyle XX. asır başında Arabistan’a hâkim olan bid‘at fırkası. Vehhâbîlik, Allahü teâlânın Kur’ân-ı kerîmde bildirilen sıfatları ile el, yüz gibi ifâdeleri te’vîl etmeyip, zâhirî (görünen) mânâsını alarak, zaman zaman teşbih ve tecsîme (Allahü teâlâyı yarattıklarına benzetme inancına) düşer. Şefâat, tevessül, istigâse, kabi…","osmanli":"وهابيلك"},{"kelime":"VEHM","anlam":"Müphem, mânâsız korku; belirsiz fikir; insanın kalbinde bir şey hakkında hâsıl olan iki ihtimâlden zayıf olanı.","kategori":"tasavvuf","misal":"Sâlih veya fâsık olduğu bilinmeyen mü’mine hüsn-i zan etmelidir. Fâsık ve sâlih olmasının ihtimâli müsâvî ise, şek, şübhe olur. Müsâvî değilse, vehm olur. Bunlardan kaçınmak lâzımdır. (Berîka)","osmanli":"وهم"},{"kelime":"Vehm Mertebesi","anlam":"Var olmayıp, var görünen. (Bkz. Nokta-i Cevvâle)","kategori":"dil","misal":"Allahü teâlâ bütün mahlûkları vehm mertebe-sinde yarattı. Fakat görünüşlerini devam ettir-mektedir. Böylece var olmaları görünüş değil, doğrudur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"سى مرتبه وهم"},{"kelime":"VEKÂHET","anlam":"Hayâsızlık, utanmazlık, edebsizlik, yüzsüzlük.","kategori":"tasavvuf","misal":"Vekâhet ile îmânın bir arada durmayacağını, bir gün belki ânında îmânı yok edeceğini düşünmedin ise, nefs-i emmâreye hoş gelen şeylerin Allahü teâlâ tarafından gadab edilen şeyler olduğunu hâlâ anlayamadınsa ve “Din, edebden ibârettir” mübârek sözünü tutmadın ise, İslâm ipine, yani baştan başa edeb olan İslâm dinine sarılmadın ise yazıklar olsun sana! (Berîka)","osmanli":"وقاهت"},{"kelime":"VEKÂLET","anlam":"Bir kimsenin, bir işi yapmak için, başkasını kendi yerine koyması, başkasına iş havâlesi.","kategori":"muamelat","misal":"Vekâlet, îcâb ve kabul ile olur. Yani müvekkilin seni vekil yaptım ve vekilin de kabul ettim sözleri veya yazıları ile olur. (Dürerü’l-Hükkâm)","osmanli":"وكالت"},{"kelime":"VEKÎL","anlam":"1.Bir kimsenin, bir işi yapmak için kendi yerine koyduğu, işini havâle ettiği kimse.","kategori":"muamelat","misal":"Vekil edenin, işi yapabilecek kimse olması; vekîlin de âkıl (akıllı) olması şarttır. Bâliğ olması şart değildir. (Dürerü’l-Hükkâm) Vekîl, sahibinden ayrıca izin almadıkça veya istediğini yap diyerek umûmî vekil edilmedikçe başkasını kendine vekîl, yapamaz. Yalnız zekât vermek için olan vekîl, izinsiz olarak başkasını vekil yapabilir. (İbni Âbidîn) Her şeye vekîlimsin denilen umûmî vekil, talâk, hediye, sadaka ve vak…","osmanli":"وكيل"},{"kelime":"VELÂ","anlam":"Efendi ile azatlı kölesi arasında devam eden veya nesebi meçhul bir şahsın, icabında diyetini ödemek ve kendisine vâris olmak üzere bir başkasıyla kurduğu hükmî yakınlık.","kategori":"fikih","misal":"Velâ, verâset sebebidir. Eshâb-ı ferâiz ve asebe sınıfında vârisi olmayan kimsenin vârisi, mevlâsı ve onun vârisleridir. (İbni Âbidîn)","osmanli":"ولاء"},{"kelime":"VELÂDET","anlam":"(Bkz. Vilâdet)","kategori":"dil","osmanli":"ولادت"},{"kelime":"VELED-İ ZİNÂ","anlam":"Zinâdan (nikâhsız birleşmeden) meydana gelen çocuk.","kategori":"dil","misal":"Çocuğun dini, yanında bulunan anababasından dini daha iyi olanı gibidir. Veled-i zinâ için de böyledir. Yalnız veled-i zinâya babası nafaka vermez ve baba tarafından mîrâs almaz. (İbni Âbidîn) Veled-i zinânın imâm olması mekrûhtur. Çünki bunda câhillik galiptir. (Dürrü’l-Muhtar)","osmanli":"زنا ولد"},{"kelime":"VELÎ","anlam":"1.Velâyet sahibi.","kategori":"tasavvuf","misal":"Allah’ın size velî kıldığı kimselere itaat edip onları dinlemenizi emrediyorum. (Hadîs-i şerîfİbn-i Mâce) Çocuğun, delinin velisi sırasıyla babası, babasının babası, yoksa amcası, yoksa erkek tarafından en yakın akrabasıdır. (İbni Âbidîn) Bir kimse, ağır hasta olursa, öldükten sonra namaz keffâreti yapılması için vasîyyet etmesi, velîsinin de bu vasîyyeti yerine getirmesi lâzımdır. (Tahtâvî)","osmanli":"ولى"},{"kelime":"VERA‘","anlam":"Haramlardan ve şüpheli şey-","kategori":"fikih","misal":"lerden sakınmak. Dininizin direği verâdır. (Hadîs-i şerîfİbni Asâkir) Bir kimse, şu on şeyi kendine farz bilmedikçe, tam verâ sahibi olamaz: Gıybet etmemek; mü’mine sû-i zan etmemek; kötü bilmemek; kimse ile alay etmemek; yabancı kadınlara, kızlara bakmamak; doğru söylemek; kendini beğenmemek için, Allahü teâlânın, kendisine yaptığı ihsânları nîmetlerini düşünmek; malını helâl yere harc edip, harâmlara vermemek; nef…","osmanli":"ورع"},{"kelime":"VERÂSET","anlam":"Vâris ile mûris arasındaki münasebet; vâris olma, mirasçılık.","kategori":"miras","misal":"(Bkz. Mûris, Vâris)","osmanli":"وراثت"},{"kelime":"VERESİYE SATIŞ","anlam":"Bedelini, parasını sonra ödemek üzere yapılan alış-veriş. Veresiye satışta satılan malın bedelinin ödene-ceği zamanı belirtmek lâzımdır. Veresiye deyip de, “Ne zaman istersen ver, paran olduğu za-man ver” şeklinde satış fâsiddir. (İbni Âbidîn) Fâiz illeti bulunan yani, ölçülen ve tartılan mal-lar aynı cinsten oldukları takdirde veresiye satış-ları fâiz olup, câiz değildir. (Riyâdü’n-Nâsihîn)","kategori":"muamelat","osmanli":"صاتيش سيه ويره"},{"kelime":"VESENİYYE","anlam":"Putperestlik, puta tapma inancı. İki elle tapınıldığı için ikili mânâsına sünâî’den gelir.","kategori":"dil","osmanli":"وثنيه"},{"kelime":"VESÎKA","anlam":"Bir hususu tevsîk, ispat ve i’lâm için tanzim ve tertip olunan delil. Çok-luk hâli vesâik gelir.","kategori":"dil","osmanli":"وثيقه"},{"kelime":"VESÎLE","anlam":"1.Sebeb, vasıta, kendisi ile başkasına yaklaşılan şey. 2.Cennet’te Resûlullah aleyhisselâma verilen bir makam.","kategori":"fikih","misal":"Ey îmân edenler! Allahü teâlâdan korkunuz! O’na yaklaşmak için vesîle arayınız! (Mâide sûresi: 35) Allah için işlediğiniz bir iş varsa hatırlayın ve onu vesile ederek yalvarın. Belki sizi bu belâdan kurtarır. (Hadîs-i şerîfBuhârî, Müslim, Nesaî) İbâdetler, duâlar, mübârek zâtlar, Allahü teâlânın rızâsına kavuşmak için hep vesîledirler. (Tefsir-i Mazharî)","osmanli":"وسيله"},{"kelime":"VESK","anlam":"Bir deve yükü (altmış sa‘ ikiyüzelli litre) mikdarında bir hacim ölçeği.","kategori":"ibadet","misal":"İmâm-ı A’zâm’a göre, her sebzenin ve meyvenin, az olsun çok olsun mahsul topraktan alındığı zaman uşrunu vermek farz olur. İmâm Ebû Yûsuf ile Muhammed’e göre uşr vermek için, mahsûlün, bir sene dayanıklı olması ve mikdarının beş veskten çok olması lâzımdır. Fetvâ, İmâm-ı A’zâm’a göre verilmiştir. (İbni Âbidîn)","osmanli":"وسق"},{"kelime":"VESVESE","anlam":"Şüphe, kuruntu, aslı esası olmayan ihtimallere dair düşünceler, insanın kalbine şeytânın getirdiği düşünceler.","kategori":"tasavvuf","misal":"Cinden olsun insanlardan olsun insanların göğüslerine (kalblerine) vesvese veren hannâsın (şeytânın) şerrinden (kötülüğünden) insanların Rabbine sığınırım. (Nâs sûresi) Şeytân iman hususunda size vesvese verirse, Allahü teâlâya sığının; “Ben Allah ve Resûlüne iman ettim” deyin! (Hadîs-i şerîfBuhârî, Müslim, Ebû Dâvûd) Çamaşır yıkarken, su kullanırken, acaba temiz mi diye vesvese etmek verâ‘ değildir. Sıddıklar böyle…","osmanli":"وسوسه"},{"kelime":"VEYL","anlam":"1.”Vay hâline!”, “Yazıklar olsun!” mânâsında bir hayıflanma ve kınama sözü. 2.Bir kimse veya topluluğun işledikleri kötü-lükler sebebiyle karşılaşacakları azâbı, kötü hâlleri ve acınacak bir hâlde bulunduklarını ifâde eden bir söz. Ölçüde ve tartıda hîle yapanlara veyl ol-sun. (Mutaffifîn sûresi: 1) (Ey Habîbim!) De ki: Ben ancak sizin gibi bir insanım. (Yal-nız) bana şu vahy olunuyor; sizin ilâhınız ancak tek ilâhtır. Onun için hepiniz O’na (îmân ve tâatle) yönelin. O’ndan mağfiret isteyin. O Allah’a ortak koşanlara veyl ol-sun. (Fussilet sûresi: 6) 3.Cehennem’de bir vadinin adı.","kategori":"dil","misal":"Hayır biz hakkı bâtılın tepesine atarız da onu parçalar. Bir de bakarsın o anda (bâtıl) mahv olmuştur. (Allah çocuk edinmiştir, me-lekler Allah’ın kızlarıdır gibi) Allah’a isnâd et-tiğiniz (noksan) vasıflardan dolayı sizin için veyl vardır. (Enbiyâ sûresi: 18)","osmanli":"ويل"},{"kelime":"VEZN","anlam":"Ağırlık; tartma.","kategori":"dil","osmanli":"وزن"},{"kelime":"VEZNÎ","anlam":"Vezn (ağırlık) ile ölçülen şey. Mevzûn. Çokluk hâli vezniyyât gelir.","kategori":"dil","misal":"Altın ile gümüş, dâimâ veznîdir. Hadîs-i şerîfte keylî olduğu bildirilen buğday, arpa, hurma ve tuz dışındaki şeylerin mekîl veya mevzûn olma-ları, âdete bağlıdır. Çarşıda, pazarda nasıl ölçü-lüyorsa, öyle olduğu kabul edilir. (İbni Âbidîn)","osmanli":"وزنى"},{"kelime":"VİCDÂN","anlam":"İnsanın içinde iyiyi kötüden ayırmaya yarayan manevî his, acıma duygusu.","kategori":"dil","osmanli":"وجدان"},{"kelime":"VİLÂDET","anlam":"1.Doğum, dünyaya gelme. 2.Süleyman Çelebi’nin Mevlid’inde Resûlullah aleyhisselâmın doğuşunun anlatıldığı kısım.","kategori":"tasavvuf","misal":"Bekâret/ vilâdet ve kadın ayıbları için bir ka-dın, başka haklar için iki erkek yahud bir er-kek ile iki kadın şâhid lâzımdır. (Nikâye) [Velâdet şeklindeki söylenişi galattır.]","osmanli":"ولادت"},{"kelime":"Vilâyet-i Âmme","anlam":"İslâmiyet’in yalnız sûretine uyanların kavuştuğu evliyâlık makamı.","kategori":"tasavvuf","misal":"Vilâyet-i âmmeye kavuşanlar tasavvuf yolunda ilerleyerek vilâyet-i hâssaya (seçilmiş olanların evliyâlığına) kavuşabilirler. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"عامه ولايت"},{"kelime":"Vilâyet-i Hâssa","anlam":"Tasavvufta, nefsin îmân ve itâ‘ate geldiği ve bütün ibâdetlerin hakîkî ve kusursuz olduğu makam.","kategori":"tasavvuf","misal":"Kulun dileği ve isteği sâdece sahibi ve sahibinin dileği olmalıdır. Başka hiçbir dileği bulunmamalıdır. Böyle olmazsa, kulluk bağını koparmış, kölelikten kaçmış olur. Allahü teâlâya kul olmak nîmetine kavuşmak, ancak vilâyet-i hâssa hâsıl olunca ele geçer. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خاصه ولايت"},{"kelime":"Vilâyet-i Muhammediyye","anlam":"Resû-lullah aleyhisselâmın kendine mahsûs vilâyetle birlikte bütün peygamberlerin vilâyetlerini (evliyâlık derecelerini) kendisinde toplamış olması. Vilâyet-i Mustafaviyye.","kategori":"dil","osmanli":"محمديه ولايت"},{"kelime":"VİLÂYET (Velâyet)","anlam":"1.İdare etme, vâlî, velî, vasî, kâdı, mütevellî gibi, bir kimsenin şahsı ve malları üzerinde onun rızası aranmaksızın tasarruf edebilme salâhiyeti. 2.Bir vâlî tarafından idare olunan mülkî mıntıka. 3.Allah dostu olan zâtın hâl ve sıfatı, velîlik, evliyâlık, velîlik makamı, Allahü teâlâya yakın olma.","kategori":"tasavvuf","misal":"Vâlilik. İl. Velâyete kavuşmak için mâsivâyı (Allahü teâlâdan başka şeyleri) kalbden çıkarmak lâzımdır. Tasavvuf büyüklerinin hepsi Ehl-i sünnet idi. Bid‘at sahiplerinden (bozuk, sapık kimselerden) hiçbiri, Allahü teâlânın mârifetine (O’nu tanıma şerefine) yaklaşama…","osmanli":"ولايت"},{"kelime":"Vilâyet Yolu","anlam":"Bir vâsıtanın yani yetişmiş bir velînin yol göstermesi lâzım olan, insanı Allahü teâlâya kavuşturan evliyâlık yolu.","kategori":"tasavvuf","misal":"Vilâyet yolundan vâsıl olanların (kavuşanların) önderi ve en üstünleri ve ötekilere vâsıta olanı Hazret-i Ali Murtezâ’dır. Bu yoldan gelen feyzlerin kaynağı odur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"يولى ولايت"},{"kelime":"VİSÂL","anlam":"(A. Vasl’dan) Kavuşma, ulaşma, bitişme.","kategori":"dil","osmanli":"وصال"},{"kelime":"VÜCûB","anlam":"Bir şeyin şer’an zimmete terettüp etmesi; bir şeyin vâcib ve lüzumlu olması.","kategori":"fikih","osmanli":"وجوب"},{"kelime":"Vücûb Şartları","anlam":"Bir ibâdetin bir kimseye farz olmasının şartları.","kategori":"fikih","misal":"Haccın vücûb şartları, İmâm-ı A’zâm’a göre sekizdir: 1) Müslüman olmak, 2) Kâfir memleketinde olanın, haccın farz olduğunu işitmesi, 3) Akıllı olmak, 4) Bâliğ (ergenlik, yani evlenecek çağa gelmiş) olmak. 5) Hür olup, köle olmamak, 6) Geçim ihtiyâcından fazla olarak hacca götürüp, getirecek ve geride kalanlara yetecek kadar helâl parası olmak, 7) Hac vakti gelmiş olmak. Hac vakti Arefe ve bayram günleri olmak üzere…","osmanli":"شرطلرى وجود"},{"kelime":"VÜCûD","anlam":"1.Var olma. 2.Allahü teâlânın kendiliğinden var olması mânâsına zâtî sıfatlarından.","kategori":"akaid","osmanli":"وجود"},{"kelime":"Vücûd-i Hâricî","anlam":"Hâriçte var olma. Vücûd-i hâricî, bizim fehmimizin, idrakimizin ötesidir.","kategori":"dil","misal":"Vücûd-i hâricîde zât-i teâlâ ve tekaddesden gayri his nesne yoktur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"خارجى وجود"},{"kelime":"Vücûd-i Vehmî","anlam":"Tasavvuf ehlinin, eşyanın gördüğümüz varlığına verdikleri isim.","kategori":"tasavvuf","osmanli":"وهمى وجود"},{"kelime":"VÜDu‘","anlam":"Abdest.","kategori":"ibadet","osmanli":"وضوع"},{"kelime":"VuKû‘","anlam":"Vâki‘ olma, rastlama, mey-dana gelme; düşme.","kategori":"dil","osmanli":"وقوع"},{"kelime":"VuKûF","anlam":"1.Durma, duruş; kalma. 2.Bir şeyi derinlemesine bilme, vâkıf olma.","kategori":"muamelat","osmanli":"وقوف"},{"kelime":"VuSLAT","anlam":"1.Vâsıl olmak, erişmek, kavuşmak, 2.Gönlün devamlı olarak ve kıl kadar istikâmet değiştirmeyerek Allahü teâlâya bağlı kalması.","kategori":"akaid","misal":"Tasavvuf yolunun âşıkları, yakınlık görünen uzaklıkla sevinmezler. Onlar uzak görünen bir yakınlık ve ayrılık görülen bir vuslat ararlar. İşin geciktirilmesine, sonraya bırakılmasına râzı olmazlar. Tembelliği, gericiliği çirkin bilirler. Kıymetli dakikaları, yaldızlı pislikler için elden kaçırmazlar. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"وصلت"},{"kelime":"VuSûL","anlam":"Vâsıl olma, kavuşma, bi-tişme, ulaşma.","kategori":"fikih","osmanli":"وصول"},{"kelime":"YA‘KûB (aleyhisselâm)","anlam":"Ken‘an halkına gönderilen ve Kur’ân-ı kerîmde ismi geçen peygamberden.","kategori":"dil","misal":"İshâk aleyhisselâmın oğlu, Yûsuf aleyhisselâmın babasıdır. Yâkub, İbrânice, “Allahü teâlânın temiz kıldığı kul” veya ikiz kardeşi Iys ondan önce doğduğu için “takip ediyor” mânâsına gelmektedir. Bir adı da İsrâil (Allah’ın kulu) olup, onun on iki oğlunun neslinden gelenlere İsrâiloğulları adı verilmiştir. Yakub dedi ki: “Oğullarım! Allahü teâlâ sizin için bu dini seçti. O hâlde müslümanlar olarak ölünüz.” (Bakara sû…","osmanli":"يعقوب"},{"kelime":"YABÂNÎ","anlam":"Yabana (çöle, sahraya) men-sub, ıssız yerde yaşayan; vahşî.","kategori":"dil","misal":"Dünyaya gelmeden evvel yavruyu, memede olan sütü, tarlada yetişen yabanî otları biçme-den önce ve mülkünde bulunan kaynaktaki, nehirdeki suyu, bulunduğu yerde iken satmak bâtıldır. Çünki kendiliğinden yetişen otu, yer-den çıkan suyu kullanmak ve birinin ateşinde ısınmak, herkesin hakkı olduğu hadîs-i şerîfte bildirildi. (İbni Âbidîn) Yabânî eşek eti ve sütü helâldir. (İbni Âbidîn)","osmanli":"يابانى"},{"kelime":"YÂD","anlam":"Hatırlamak, anmak. Zikir.","kategori":"tasavvuf","misal":"Allah’ın adını yâd et, ruh ve kalbin şâd et, Bülbül gibi feryâd et, yalvar güzel Allah’a. (Tâceddîn Halvetî)","osmanli":"ياد"},{"kelime":"YÂD-I DAŞT","anlam":"Nakşibendiyye yolundaki on temel esastan biri; zikrin, Allahü teâlâyı anmanın ve hatırlamanın kalbe yerleşmesi, meleke hâline gelmesi; devamlı ve hiç kaybolmayan huzur.","kategori":"tasavvuf","misal":"Yâd-ı daşt en yüksek mertebedir. Ondan sonra mertebe yoktur. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"يادداشت"},{"kelime":"YÂDİGÂR","anlam":"Hâtıra, bir kimseyi veya şeyi hatırlatacak şey.","kategori":"dil","osmanli":"يادﮔار"},{"kelime":"YAĞMuR DuÂSI","anlam":"Yağmur yağdırması için Allahü teâlâya yapılan duâ.","kategori":"akaid","misal":"Resûlullah sallallahü aleyhi ve sellem efendimiz ve Eshâb-ı kirâm ve İslâm âlimleri yağmur duâsı yaptılar. Yağmur duâsı için çıkılan yerde imâm, evvelâ yalnızca veya cemâatle iki rek‘at namaz kılar ve kalkmayıp, yerde asâya dayanıp bir hutbe okur. Sonra kıbleye dönüp, avuçları semâya karşı açık olarak omuzları hizâsına kaldırıp, ayakta duâ eder. Hazır olanlar, arkasında oturarak dinleyip âmin der. Yalnız yağmur duâs…","osmanli":"دعاسى ياغمور"},{"kelime":"YAHYÂ (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi geçen Benî İsrâil peygamberlerinden.","kategori":"dil","misal":"Zekeriyya (aleyhisselâm) mâbedde durmuş namaz kılarken melekler ona şöyle nidâ ettiler: “Allah sana, kendisi tarafından gelen bir kelimeyi (Îsâ aleyhisselâmı) tasdik edici, efendi, iffetli ve sâlihlerden bir peygamber olarak Yahya’yı müjdeler!” (Âl-i İmrân sûresi: 39) Allah kardeşim Yahya’ya rahmet eylesin ki, küçükken iki çocuk kendisini oyuna çağırdıklarında “Ben oyun için mi yaratıldım?” buyurdu. O küçük iken bir…","osmanli":"يحيى"},{"kelime":"YAKAZA","anlam":"(A. Eykaz’dan) Uyanıklık hâli.","kategori":"dil","osmanli":"يقظه"},{"kelime":"YAKÎN","anlam":"1.Şek ve şüpheden uzak; sağ-lam, kat‘î. 2.Sağlam, tereddütsüz, hakikî iman; Allahü teâlâyı kemâliyle bilme. 3.Ölüm.","kategori":"dil","misal":"Biraz bekledi, çok geçmeden Hüdhüd ge-lip, şunları söyledi: “Ben senin bilmediğin bir şey öğrendim. Sana Sebe’den yakîn bir haber getirdim.” (Neml sûresi: 22) Namazda üç veya dört rek‘at kıldığı hususunda tered-düde düşerseniz, namazı yakînine göre bina ediniz; sonra sehiv secdesi yapınız. (Hadîs-i şerîf-Müslim) Âgâh olunuz ki; insana dünyada yakîn ve âfiyetten (günahlardan uzak olmaktan) daha hayırlı bir şey verilmemiştir. Öyle ise Al-lah’tan o ikisini isteyin. (Hadîs-i şerîf-Beyhekî) Yakîn ihsân edilen birinin kerâmetlere, hâri-kalara, ihtiyâcı olmaz. Bütün bu kerâmetler, Zât-ı ilâhînin zikrinden ve kalbin bu zikr ile zînetlenmesinden aşağıda kalır. (Mektûbât-ı İmâm-ı Rabbânî) Sana yakîn gelinceye kadar da Rabbine ibâ-det et. (Hicr sûresi: 99); Mücrimlere, sizi Ce-hennem’e sokan nedir? derler. (Onlar da ce-vap verirler): Biz namaz kılanlardan değildik. Yoksulu doyurmazdık. (Bâtıla) dalanlarla be-raber dalardık. Hesâb gününü de yalan sa-yardık. Nihâyet bize yakîn gelip çattı. (Müd-dessir sûresi: 41-47)","osmanli":"يقين"},{"kelime":"YALAN","anlam":"Bir kimsenin hakikate mu-halif olduğunu bile bile kandırmak için söy-lediği söz. Kizb.","kategori":"dil","misal":"Yalancıların vay hâline! (Mutaffifîn sûresi: 10) Üç şey, münâfığın alâmetidir: Konuştu-ğunda yalan söyler; söz verdiğinde sözünde durmaz; kendisine güvenilince hıyanet eder. (Hadîs-i şerîf-Buhârî, Müslim, Bezzâr) Yalan ancak üç hâlde câizdir: Harbde düşmana karşı; insanları barıştırmak için; karı-koca arasını düzeltmek için. (Hadîs-i şerîf-Tir-mizî, Müsned) Bir iyi maksada hem doğru, hem de yalan sözle ulaşılabiliyorsa, yalan söylemek haramdır. Bir zâlime, aradığı kimseyi gördüğümüz hâlde gör-mediğini söylemek gibi, zaruri hâllerde gerçeği saklamak yalan olmaz. (İhyâ) İş bitiren bir yalan, iyidir fitne çıkaran doğru-dan (Mektûbât İmâm-ı Rabbânî)","osmanli":"يالان"},{"kelime":"YÂRÂN","anlam":"Dostlar, arkadaşlar, sevgili-ler. Yâr’ın çokluk hâli.","kategori":"dil","osmanli":"ياران"},{"kelime":"YARATMAK","anlam":"Hiç yoktan var etmek veya mevcut şeyleri fizikî, kimyevî, fizyolojik ve metafizik kanunlarla bir şekilden başka hassâlı şekillere çevirmek. Halk etme. Allahü teâlânın tekvîn sıfatı.","kategori":"akaid","osmanli":"ياراتمق"},{"kelime":"YAS","anlam":"Bir felâketten, bilhassa bir ölüm-den duyulan büyük acı; bu acıyı gösteren ha-reketler. Mâtem.","kategori":"dil","osmanli":"ياس"},{"kelime":"YÂSÎN SûRESİ","anlam":"Kur’ân-ı kerîmin otuz altıncı sûresi.","kategori":"dil","misal":"Mekke-i Mükerreme’de nâzil olmuştur. Seksen üç âyet-i kerîmedir. Yâsîn diye başladığı için, bu ismi almıştır. Bazı âlimler, Yâsîn ile murâdın; ey insan veya ey insanların efendisi mânâsına Resûlullah aleyhisselâm olduğunu bildirmişlerdir. İhlâs ile (Allah rızâsı için) okuyanların dünya ve âhiret nîmetlerine kavuşmalarına vesîle olacağı ve okunduğunda vefât etmiş olan Müslümanların ruhlarına hediye edildiği için bu s…","osmanli":"سى سوره يس"},{"kelime":"Yatsı Vakti","anlam":"Akşam namazı vaktinin çıkmasından itibaren, fecrin ağarmasına kadar devam eder.","kategori":"ibadet","misal":"Üç mezhebe ve Hanefî’de İmâmeyn’e göre gökteki kırmızılık, İmâm-ı A’zâm Ebû Hanîfe’ye göre beyazlık kaybolunca başlar. İmâm Ebû Hanife’ye göre şark ufkunda beyazlığın görülmesi, üç mezhebe ve Hanefî’de İmâmeyn’e göre yayılmasına kadar devam eder.","osmanli":"وقتى ياتسى"},{"kelime":"YE’CûC VE ME’CûC","anlam":"Kur’ân-ı kerîmde adı geçen ve kıyâmete yakın, yeryüzüne yayılacak olan zararlı ve bozguncu iki kötü kavim.","kategori":"dil","misal":"Nihâyet Ye’cûc ve Me’cûc’ün seddi açılıp da her tepeden saldırdıkları ve hak olan va‘d (kıyâmet) yaklaştığı vakit, işte o zaman kâfir olanların gözleri hemen dikilecek: “Vah bizlere! Biz bundan gaflet ettik, doğrusu kendimize zulmetmiş olduk,” diyecekler. (Enbiyâ sûresi: 96, 97) Ye’cûc ve Me’cûc, Zülkarneyn’in inşâ ettiği seddi her gün oyuyorlar. Tam delecekleri sırada, başlarında bulunan reis; “Bırakın artık delme…","osmanli":"ومأجوج يأجوج"},{"kelime":"YED","anlam":"1.El. 2.Allahü teâlâ hakkında kudret, gücü yetmek mânâsı verilen lafız, söz.","kategori":"akaid","misal":"(Habîbim) de ki: Ey mülkün sahibi (olan) Allah’ım! Sen mülkü dilediğine verirsin. Dilediğinden mülkü alırsın. Dilediğini azîz, dilediğini zelîl edersin (alçaltırsın). Hayır (ve şer) senin yed’indedir. Şüphesiz sen, her şeye kâdirsin (gücü yetensin). (Âl-i İmrân sûresi: 26)","osmanli":"يد"},{"kelime":"YEGÂNE","anlam":"Biricik, tek.","kategori":"dil","osmanli":"يگانه"},{"kelime":"YEHûD","anlam":"Mûsâ aleyhisselâmın dininde olan kimseler.","kategori":"dil","misal":"Yahudi’nin çokluk hâli.","osmanli":"يهود"},{"kelime":"YEKSÂN","anlam":"1.Düz. 2.Bir, beraber. 3.Her zaman, bir düziye, aynı seviyede.","kategori":"dil","osmanli":"سان يك"},{"kelime":"YEKTÂ","anlam":"Tek, eşsiz, benzersiz.","kategori":"dil","osmanli":"يكتا"},{"kelime":"YEKûN","anlam":"Toplam.","kategori":"dil","osmanli":"يكون"},{"kelime":"YEMÂME CENGİ","anlam":"Resûlullah aleyhisselâmın vefatından sonra sahte peygamber","kategori":"akaid","misal":"Müseyleme-i Kezzâb ile yapılan ve Müslümanların gâlibiyetiyle biten muharebe.","osmanli":"جنگى يمامه"},{"kelime":"YEMÎN","anlam":"1.Sağ taraf. 2.Kuvvet. 3.Bir haberi yâhud bir işi yapma veya yapmama hususundaki azmi, iddiâyı, Allahü teâlânın ismini anmak suretiyle veya dinin izin verdiği sözlerle kuvvetlendirmek. Yemînlerinizi koruyun. (Mâide sûresi: 89) İspat dâvâcıya, yemîn de inkâr edene düşer. (Hadîs-i şerîfTirmizî) Yalan yere yemîn etmek büyük günahlardandır. (Hadîs-i şerîfBuhârî, Tirmizî) Doğru olsa bile çok yemîn etmek, Allahü teâlânın ism-i şerîfine ve yemîne kıymet vermemek olur. (Dürrü’l-Muhtar)","kategori":"akaid","osmanli":"يمين"},{"kelime":"Yemîn Keffâreti","anlam":"Yapılan yemîne riâyet etmeyip, yemîni bozan bir Müslümana lâzım gelen keffâret, cezâ.","kategori":"dil","misal":"Yemîni bozmadan keffâret verilmez. Yemîni bozduktan sonra keffâreti geciktirmek günah-tır. Yemîn keffâreti için bir köle âzâd edilir. Yâ-hud zekât alması câiz olan erkek veya kadın on fakîre bütün bedenini örtecek kadar bir kat çamaşır verilir. Veya aç olan on fakîr bir gün iki defâ (sabah-akşam) doyurulur. Bu üçünden birini yapamayan fakir, üç gün ard arda oruç tutar. Bu oruçlara geceden niyet edilir.Kadın üç günü tamamlamadan hayz başlarsa, hayz bit-tikten sonra yeniden üç gün tutar. (İbni Âbidîn)","osmanli":"كفارتى يمين"},{"kelime":"YERHAMÜKALLAH","anlam":"Aksırıp, Elhamdülillah diyene, yanında bulunan kimsenin “Allahü teâlâ sana merhamet etsin” mânâsına söylediği söz.","kategori":"akaid","misal":"gitmek ve aksırıp Elhamdülillah diyene yerhamükallah demek. (Hadîs-i şerîfBuhârî, Müslim) Aksırıp, “Elhamdülillah” diyene, yanındaki bir kimse “Yerhamükallah” diye cevap verdikten sonra, orada bulunan başka biri, şayet üçüncü bir kimse yoksa aksıranın kendisi, “Yehdîkümüllah” veya “Yehdîna ve yehdikümüllah” der. (Şir’atü’l-İslâm) Aksırıp, Elhamdülillah diyene, namazda iken yerhamükallah demek namazı bozar. Namazın d…","osmanli":"الله يرحمك"},{"kelime":"YERMÜK GAZÂSI","anlam":"13.(M.","kategori":"dil","misal":"Hicretin 634) senesinde Doğu Roma İmpa-ratoru Heraklius’un ordusuyla Şam yakınla-rında yapılan ve Müslümanların galibiyetiyle biten muharebe.","osmanli":"غزاسى يرموك"},{"kelime":"YESÂR","anlam":"Zenginlik.","kategori":"dil","osmanli":"يسار"},{"kelime":"YESEVİYYE","anlam":"Evliyânın büyüklerin-den, Yûsuf Hemedânî halîfesi ve 1166 sene-sinde Türkistan’da vefat eden Ahmed Yesevî hazretlerinin tasavvuftaki yolu.","kategori":"tasavvuf","osmanli":"يسويه"},{"kelime":"YESÎR","anlam":"Kolay; az şey.","kategori":"dil","osmanli":"يسير"},{"kelime":"YETÎM","anlam":"1.Yalnız, tek, eşi bulunmayan.","kategori":"dil","misal":"Bulûğa ulaşmadan babası ölmüş çocuk. Yetimlere bâliğ oldukları zaman mallarını verin. Helâli harâma değişmeyin. Kendi mal-larınıza katarak yemeyin. Çünki bu büyük bir günahtır. (Nisâ sûresi: 2); Yetimlerin mal-larını zulmen (haksız olarak) yiyenler, ka-rınlarına ancak bir ateş yerler ve yakında alevli ateşe girecekler. (Nisâ sûresi: 10); Ye-timin malına da yaklaşmayın. Ancak büluğ (ergenlik) çağına ulaşıp rüşdü (malını dinin ve aklın uygun gördüğü yerlerde kullandığı) görülünceye kadar en güzel şekilde (malını koruyup çoğaltmak için) yaklaşabilirsiniz. Bir de ahdi (yapılan sözleşmeyi) yerine ge-tirin. Çünki verdiği sözden cayan (kıyâmet günü) mes‘ûldür. (İsrâ sûresi: 34) Kim şef-kat ve merhametle bir yetimin başını ok-şarsa, elinin dokunduğu tüyler sayısınca sevab alır. (Hadîs-i şerîf-Taberânî, Müsnedü İmâm-ı Ahmed) Yetîmlik, büluğa gelmekle sona erer. (İbni Âbidîn)","osmanli":"يتيم"},{"kelime":"YEVM","anlam":"Gün.","kategori":"dil","osmanli":"يوم"},{"kelime":"Yevm-i Şek","anlam":"Şüpheli gün. Havanın bulutlu olup, Ramazan ayı hilâlinin görülme-mesi sebebiyle Şâbân ayının otuzuncu günü mü, yoksa Ramazân-ı şerîfin ilk günü mü ol-duğu bilinmeyen, Şâbân’ın yirmi dokuzundan sonra gelen gün.","kategori":"ibadet","misal":"Yevm-i şekte Ramazân-ı şerîf orucuna veya vâ-cib bir oruca niyet edilerek oruç tutulması tah-rîmen mekrûhtur. (Mevkûfât)","osmanli":"شك يوم"},{"kelime":"YEVMİYE","anlam":"Günlük; bir günlük iş için verilen ücret.","kategori":"dil","osmanli":"يوميه"},{"kelime":"YEZDÂN","anlam":"1.Zerdüşt dininde hayır ilahı. 2.Allahü teâlâ.","kategori":"dil","osmanli":"يزدان"},{"kelime":"YEZÎDÎLİK","anlam":"Güneydoğu Anadolu ve Kuzey Irak’ta esası Zerdüşt dinine dayanan, güneşe ve tavus denilen şeytâna hürmet edilen, Yahudi, Hristiyan ve Müslümanlık tesirleri de görülen, tanrıya Ezd dedikleri için bu isimle anılan ve Emevî halifesi Yezîd ile bir alâkası bulunmay…","kategori":"dil","misal":"Ezdîlik.","osmanli":"يزيديلك"},{"kelime":"YOBAZ","anlam":"Bir fikri körü körüne müda-faa eden, fanatik, câhil ve kaba saba kimse.","kategori":"dil","osmanli":"يوباز"},{"kelime":"YOL KESİCİ","anlam":"Dârülislâmda silah kuvveti ile şehirler arası yollarda insanlara sal-dıran; insanların, İslâmiyet’i doğru olarak öğ-renmelerine mani olan. Kâtı‘-ı tarîk.","kategori":"osmanli","misal":"Yol kesici, mal soymadan ve can kaybı olma-dan ele geçerlerse, dövülür ve tövbe hâli görü-lünceye veya ölünceye kadar habs olunurlar. (İbni Âbidîn)","osmanli":"كسيجى يول"},{"kelime":"YOLCu","anlam":"Yola çıkan, misafir; seferî.","kategori":"dil","misal":"(Bkz. Müsâfir, Seferî)","osmanli":"يولجى"},{"kelime":"YORTu","anlam":"Hristiyanlıkta dinî bayram, bilhassa bir hâdiseye veya azize adanmış mukaddes gün.","kategori":"dil","osmanli":"يورطو"},{"kelime":"YûNuS (aleyhisselâm)","anlam":"Irak’ın şimâlindeki Ninova (Musul) ahâlisine gönderilen ve","kategori":"dil","misal":"ismi Kur’ân-ı kerîmde zikredilen peygamberlerden. Bir balık tarafından yutulduğu için Zünnûn veya Sâhibü’l-Hût da denir. Doğrusu Yunus (aleyhisselâm) da gönderilen peygamberlerdendi. Hani o, (kavminin iman etmemesine kızarak) dolu bir gemiye binip kaçmıştı. Gemide olanlarla karşılıklı kur‘a çektiler de kaybedenlerden oldu. (Kaçak olduğu anlaşılıp, fırtınaya kapılan geminin kurtulması için kendisini denize attılar.)…","osmanli":"يونس"},{"kelime":"YûNuS SûRESİ","anlam":"96.âyetler ise Medîne’de nâzil oldu.","kategori":"dil","misal":"Kur’ân-ı kerî-min onuncu sûresi. Mekke’de nâzil oldu. 40, 94, 95 ve Yüz dokuz âyet-i kerî-medir. Doksan sekizinci âyet-i kerîmede Yû-nus aleyhisselâmın kavminden bahsedildiği için, sûreye bu isim verilmiştir. Sûrede; Nûh ve Mûsâ aleyhimesselâma dâir kıssalar, rahmet-i ilâhiyyenin, azab-ı ilâhîden daha çok olduğu bildirilmektedir. (Mefâtihü’l-Gayb, Kurtubî) Kim Yûnus sûresini okursa, Yûnus aley-hisselâmı tasdik (îmân) ve tekzîb edenlerin (yalanlayanların) ve Fir‘avn ile boğulanla-rın adedinin on katı sevab verilir. (Hadîs-i şerîf-Beydâvî)","osmanli":"سى سوره يونس"},{"kelime":"YûŞÂ (aleyhisselâm)","anlam":"Benî İsrâil peygamberlerinden.","kategori":"dil","misal":"Mûsâ aleyhisselâmın yeğeni ve halîfesi olup, kavmini Arz-ı Mev‘ud’a (Va‘dedilmiş Topraklara) kavuşturmuştur.","osmanli":"يوشى"},{"kelime":"YûSuF (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde adı geçen Benî İsrâil peygamberlerinden.","kategori":"dil","misal":"Doğrusu Yûsuf (aleyhisselâm) o bizim ihlâslı kullarımızdandır. (Yûsuf sûresi: 24) Hiç şüphe yok ki, kerim oğlu kerim oğlu kerim oğlu kerim, İbrâhim oğlu İshâk oğlu Ya‘kub oğlu Yûsuf ’tur. Eğer ben onun kadar hapiste olsaydım, son da’vete icabet ederdim. Lût’a rahmet olsun ki, “Kuvvetli bir duvar (sığınak) bulsaydım ona sığınırdım.” dedi. Ondan sonra Allah, nebilerini bu hâle düşürmedi; kavimlerine hâkim gönderdi. (H…","osmanli":"يوسف"},{"kelime":"YûSuF SûRESİ","anlam":"3.âyetleri ise Me-dîne’de nâzil oldu.","kategori":"dil","misal":"Kur’ân-ı kerî-min on ikinci sûresi. Ahsenü’l-kasas. Mekke’de nâzil oldu. 1, 2 ve Yüzonbir âyettir. Yûsuf aley-hisselâmın kıssasından bahsedildiği için bu ismi almıştır. (Kurtubî)","osmanli":"سى سوره يوسف"},{"kelime":"ZABT","anlam":"1.Koruma, sıkı tutma. 2.İda-resi altına alma, kendisine mal etme. 3.An-lama. 4.Bir hadîs râvîsinin uyanık ve dikkatli olması; ezberlediği hadîsi hatasız ve eksiksiz rivâyet edebilmesi.","kategori":"hadis","osmanli":"ضبط"},{"kelime":"ZÂD","anlam":"Azık, erzak.","kategori":"dil","osmanli":"زاد"},{"kelime":"ZÂDE","anlam":"Oğul.","kategori":"dil","osmanli":"زاده"},{"kelime":"ZAFER","anlam":"Düşmana karşı galip gelme. Kim bulur zor ile maksûdına dâim zafer, Gelir elbet zuhûra ne ise hükm-i kader!","kategori":"akaid","osmanli":"ظفر"},{"kelime":"ZÂHİD","anlam":"1.Zühd sahibi; kıymet vermeyen, değer vermeyen, aldırmayan. 2.Dünyaya düşkün olmayan, şüpheli olma korkusuyla mübahların çoğunu terk eden.","kategori":"tasavvuf","misal":"(Kafile Mısır’a vardığında) onu (Yûsuf ’u) değersiz bir pahaya, sayılı birkaç dirheme sattılar. Onlar zaten (Yûsuf ’a kıymet vermeyen) zâhidlerdi. (Yûsuf sûresi: 20) Allahü teâlâ bir kulunu severse, onu dünyada zâhid, âhirete râgıb (isteyen) yapar. Ayıblarını ona bildirir. (Hadîs-i şerîfBeyhekî) Zâhid, dünyaya gönül bağlamadığı için insan…","osmanli":"زاهد"},{"kelime":"ZÂHİR","anlam":"1.Zuhur eden, açık, görünen, dış görünüş, insanın dış görünüşü. 2.Varlığında şek ve şübhe olmayan, her ese-rinde varlığına deliller, işâretler bulunan mânâsına Allahü teâlânın Esmâ-i hüsnâsın-dan (ez-Zâhir). Her şeyin başlangıcı ve sonu, Zâhir ve Bâtın O’dur. (Hadîd sûresi: 3) İşrak vaktinde ez-Zâhir ism-i şerîfi söylendi-ğinde kalbde evliyâlık nûru meydana gelir. (el-İstigâsetü’l-Kübrâ) Fıkıh usûlünde, sözün asıl söyleniş sebebi olmadığı hâlde, açıkça ve kolayca bu mânâya delâlet eden söz. Resûlümün size verdiğini alınız. Nehy, men’ ettiği şeyden sakınınız. (Haşr sûresi: 7) Bu âyet-i kerîme harbsiz ele geçen mal-ların (fey’in) taksiminde Resûlullah aleyhis-selâma itâat edilmesi hakkında nâzil olmuş-tur. Ayrıca, bu âyet-i kerîme, her emrettiği ve her yasak ettiği şeyde Peygamberimize sallal-lahü aleyhi ve sellem itâat etmenin vâcib oldu-ğuna delâlet etmesi bakımından da zâhirdir. Beden ve his uzuvları.","kategori":"akaid","misal":"Bâzı kimseler, güzellikleriyle tekebbür ederler. Hâlbuki güzellik insanda kalıcı değildir. Çabuk gider. Âriyet, ödünç olan şeyle kibirlenmek ve öğünmek ahmaklıktır. Zâhirin güzelliği, kalbin güzelliği ile yani iyi huyla birlikte olunca, kıy-metlidir. Kalbin temizliği de Resûlullah’ın sün-netine uymakla belli olur. (Berîka)","osmanli":"ظاهر"},{"kelime":"Zâhir Haberler","anlam":"Hanefî mezhebinin, İmâm-ı A’zâm Ebû Hanîfe ve talebelerinden gelen kuvvetli, güvenilir haberleri.","kategori":"ibadet","misal":"Usûl haberleri. Zâhirü’r-Rivâye.","osmanli":"خبرلر ظاهر"},{"kelime":"ZAHÎRE","anlam":"İhtiyaç için anbarda sakla-nan hububat.","kategori":"akaid","osmanli":"ذخيره"},{"kelime":"ZÂHİREN","anlam":"Görünüşe göre; görünüşte; âşikâre; meydanda olarak.","kategori":"akaid","osmanli":"ظاهرا"},{"kelime":"ZÂHİRÎ","anlam":"1.Görünen, görünürdeki. 2.Ebû Dâvûd Zâhirî’nin mezhebine mensub.","kategori":"akaid","misal":"ZÂHİRİYYE: ظاهريه (A) Kur’ân-ı kerîm ve ha-dîs-i şerîflerin zâhir, görünen mânâlarına iti- bar edip, kıyâsı kabul etmeyen ve 270 [M. 883] senesinde Bağdad’da vefat eden Dâvûd Zâhirî’nin kurduğu bozuk mezheb.","osmanli":"ظاهرى"},{"kelime":"ZÂHİRİYYE","anlam":"Kur’ân-ı kerîm ve hadîs-i şerîflerin zâhir, görünen mânâlarına iti-","kategori":"dil","misal":"bar edip, kıyâsı kabul etmeyen ve 270 [M. 883] senesinde Bağdad’da vefat eden Dâvûd Zâhirî’nin kurduğu bozuk mezheb.","osmanli":"ظاهريه"},{"kelime":"ZÂİL","anlam":"1.Zevâl bulan, sona eren, devamlı olmayan. 2.Geçen, geçmiş olan.","kategori":"dil","misal":"(A. Zevâl’den)","osmanli":"زائل"},{"kelime":"ZÂKİR","anlam":"1.Zikreden, anan, hatırlayan. 2.Tasavvufta, zikir meclislerinde zikir âyinini idare eden, ilâhîler okuyup zikredenleri coş-turan kimse.","kategori":"tasavvuf","osmanli":"ذاكر"},{"kelime":"ZÂLİM","anlam":"1.Zulm eden, haksızlık eden, insanlara kötülük yapan. 2.Allahü teâlâya inanmayan, kâfir.","kategori":"akaid","misal":"Allahü teâlâ zâlimleri sevmez. (Âl-i İmrân sûresi: 57, 140) Allah zâlime mühlet verir. Yakalanınca bir daha bırakmaz. (Hadîs-i şerîf-Buhârî) Bir zâlime yardım edene Al-lahü teâlâ o zâlimi musallat eder. (Hadîs-i şerîf-İbni Asâkir) Alması haram olan şeyin, vermesi de haram-dır. Zâlimin zulmünü defetmek veya bir hak-kını tahsil etmek için mal vermek caizdir. Rüş-vet değildir. (İbni Âbidîn)","osmanli":"ظالم"},{"kelime":"ZÂMİN (Dâmin)","anlam":"Bir şeyin mislini veya bedelini ödemekle mükellef kimse; kefil, güvenilir.","kategori":"fikih","misal":"Mübâşir (kişi, bizzat kendisi) müteammid (kasten) olmasa da zarar verdiği şeyi zâmin olur. Mübâşir, kasten yaparsa, hem zâmin hem günahkâr olur. (İbni Âbidîn)","osmanli":"ضامن"},{"kelime":"ZAMM-I SûRE","anlam":"Sure ekleme, farz namazın ilk iki rek‘atinde, sünnet namazların ve vitrin her rek‘atinde kıyamda Fâtiha’dan sonra sûre veya en az üç kısa âyet veyâhud üç kısa âyet mikdarında bir uzun âyet okuma.","kategori":"dil","misal":"Farzın ilk iki rek’atinde zamm-ı sûreyi unutan, üçüncü ve dördüncü rek‘atlerde okuyup, sonra secde-i sehv yapar. Zamm-ı sûrenin bir parçasını rükû‘da okuyana, Ettehiyyâtüden sonra az bir şey okuyarak, üçüncü rek‘ati geciktirene sec-de-i sehv lâzım gelir. (Halebî)","osmanli":"سوره ضم"},{"kelime":"ZÂNÎ","anlam":"Zinâ eden, kendi nikâhlısı veya câriyesi olmayan bir kadınla gayrımeşru münasebette bulunan erkek.","kategori":"dil","misal":"Zânî ve zâniyenin her birine yüzer değnek vurun. Allah’a ve âhiret gününe inanıyorsanız, Allah’ın dini hususunda o ikisine acımayın. Mü’minlerden bir cemaat de bu cezanın tatbikine şâhid olsun. (Nûr sûresi: 2) Çocuk yatağında doğduğu adama aittir. Zânî için recm vardır. (Hadîs-i şerîfTaberânî)","osmanli":"زانى"},{"kelime":"ZÂNİYE","anlam":"Zinâ eden, kendi nikâhlısı [veya câriye ise efendisi] olmayan bir erkekle gayrımeşru münasebette bulunan kadın.","kategori":"dil","osmanli":"زانيه"},{"kelime":"ZANN","anlam":"1.Şüphe ile bilme, sanma. 2.Düşünme, sezme.","kategori":"hadis","misal":"Zanların çoğundan kaçının, zîrâ bazı zan-lar günahtır. Tecessüs etmeyin. (Hucurât sû-resi: 12) Zandan sakının. (Hadîs-i şerîf-Buhârî, Müslim, Taberânî) Kulum beni nasıl zannederse ben öyleyim. Hayır zannederse hayır, şer zannederse şer bulur. (Hadîs-i Kudsî-Taberânî, Hâkim) Yolda rastlanan bir suyun temiz olduğu, iyi bi-linir veya temiz olduğu çok zannedilirse, bu-nunla abdest alınır. (Halebî)","osmanli":"ظن"},{"kelime":"Zann-ı Gâlib","anlam":"Çok kuvvetli zan. Abdest aldım mı, almadım mı diye şüpheye düşüp, zann-ı gâlibi abdestsiz olduğu yönde olursa, abdesti bozulur.","kategori":"ibadet","misal":"(Miftahü’l-Cenne)","osmanli":"غالب ظن"},{"kelime":"ZANNÎ","anlam":"Zanna ait, kat‘î olmayıp zan-nedilen.","kategori":"dil","osmanli":"ظنى"},{"kelime":"Zannî Delil","anlam":"Mânâsı açık anlaşılmayan âyet-i kerîme ve hadîs-i şerîfler ile mânâsı açık olmakla beraber tek sahâbî tarafından bildirilen hadîs-i şerîf.","kategori":"hadis","misal":"Zannî delil, vâcib ile tahrîmen mekrûhu bildirir. Meselâ, kurban kesmek, vitir namazı kılmak zannî delil ile bildirilmiştir. Bunları yapmamak tahrîmen mekrûhtur. (İbni Âbidîn)","osmanli":"دليل ظنى"},{"kelime":"ZÂR","anlam":"1.Ağlayan. 2.İsimlere eklenerek yer adı bildirir.","kategori":"dil","osmanli":"زار"},{"kelime":"ZARAR-I FÂHİŞ","anlam":"Aşırı zarar, bir malı kullanmaya mâni olan zarar.","kategori":"dil","misal":"Demirci dükkanı, değirmen bitişik binayı sal-larsa veya fırın dumanı, yağhanenin pis kokusu, harman tozları, bitişik evde oturulamayacak kadar sıkıntı verirse, lağım, kanalizasyon yol-larının sızıntılarından komşu duvarı zarar gö-rürse, sonra yapılanlar zarar-ı fâhiş olup men edilirler. (Mecelle, m. 1198)","osmanli":"فاحش ضرر"},{"kelime":"ZÂRÎ","anlam":"Ağlayıp sızlama.","kategori":"dil","osmanli":"زارى"},{"kelime":"ZÂRİYÂT SûRESİ","anlam":"Kur’ân-ı kerî-min elli birinci sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Altmış âyettir. Zâriyât ke-limesi ile başladığından, bu isim verilmiştir. Sûrenin başındaki âyet-i kerîmeler, öldükten sonra dirilmenin, âhiret hayâtının ve âhirette mükâfât ve cezânın vukû bulacağını, pek mu-azzam kudret eserlerinin bir kısmına yeminle beyân edilmiştir. (Râzî, Kurtubî) Kim Zâriyât sûresini okursa, Allahü teâlâ ona, dünyada cereyân eden ve esen her bir rüzgârın adedi için on hasenât (sevab) ve-rir. (Hadîs-i şerîf-Envârü’t-Tenzîl)","osmanli":"سى سوره ذاريات"},{"kelime":"ZARûRET","anlam":"1.Yasaklanan bir işin yapılmasını mübâh kılan sebeb, meşakkat, ihtiyaç. 2.İslâmiyet’in emir ve yasak etmesi, tedavi edilmeyen şiddetli bir ağrı, bir uzvun yâhud hayatın telef olmak tehlikesi ve başka bir şey yapamamak mecburiyeti. Zarûretler memnû‘ olan şeyleri mübâh kılar. (Mecelle, m. 21) Zarûretler kendi mikdarlarınca takdîr olunur. (Mecelle, m. 22) Zarûretler, dînen haram, yasak olan şeyleri mübâh kılar. Yani mübâhı yapan nasıl muâheze olunmazsa (cezâlandırılmazsa), zarûret olan bir işi yapan da muâheze olunmaz. Bir kimse, mûteber bir ikrah (zorlama, cebr) ile başkasının malını telef etse, ikrah zarûreti bu işin haramlığını, yasaklığını g…","kategori":"fikih","osmanli":"ضرورت"},{"kelime":"ZARûRÎ","anlam":"Yapılması kaçınılmaz olan, mecburî.","kategori":"dil","osmanli":"ضرورى"},{"kelime":"ZARûRİYYÂT","anlam":"Şer‘î hükümle-rin nazara aldığı menfaatlerin birinci dere-cesi; şer‘î hükümlerde gözetilen dinin, canın, aklın, neslin ve malın muhafazası maksadı.","kategori":"dil","osmanli":"ضروريات"},{"kelime":"ZARûRİYYÂT-I DÎN","anlam":"İnanı-lacak ve yapılacak işlerle alâkalı, âlim ve câ-hil herkesin bilmesi lâzım olan din bilgileri.","kategori":"dil","misal":"Her şeyden önce zarûriyyât-ı dini öğrenmek lâzımdır. Bunları bırakıp, başka şeylerle uğ-raşmak, kıymetli ömrü faydasız şeylere har-camak olur. Hadîs-i şerîfte; “Allahü teâlânın bir kulunu sevmemesinin alâmeti, onun mâlâyânî (kendisini alâkadar etmeyen, fay-dasız şeyler) ile vakit geçirmesidir.” Zarû-riyyât-ı dinden olan bilgiler o kadar çoktur ki, insan mâlâyânî ile uğraşmaya vakit bulamaz. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"دين ضروريات"},{"kelime":"ZÂT","anlam":"Kendi, asıl, öz, cevher; kişi, şahıs. Allahü teâlâ zâtı ile vardır. Varlığı kendi ken-diyledir. Şimdi var olduğu gibi, hep var idi ve hep var olacaktır. Varlığının önünde ve sonunda yokluk olamaz. Çünki, O’nun varlığı lâzımdır. (İtikadnâme)","kategori":"akaid","osmanli":"ذات"},{"kelime":"Zât-ı İlâhî","anlam":"Allahü teâlânın zâtı.","kategori":"akaid","osmanli":"الهى ذات"},{"kelime":"ZÂVİYE","anlam":"1.Köşe, açı. 2.Tasavvuf ehlinin zikr ve ibâdet için çekildiği veya toplandığı küçük tekke.","kategori":"tasavvuf","osmanli":"زاويه"},{"kelime":"ZE‘ÂMET","anlam":"99.999 akçe arasındaki mirî (devlete ait) toprak.","kategori":"osmanli","misal":"Osmanlılar zamanında subaylara maaş karşılığı ve asker yetiştirmek üzere verilen, geliri 20 bin ile Subay toprağı.","osmanli":"زعامت"},{"kelime":"ZEBÂN","anlam":"Dil, lisan.","kategori":"dil","osmanli":"زبان"},{"kelime":"ZEBÂNÎ","anlam":"Cehennem meleği, azap yapıcı melek.","kategori":"akaid","misal":"Zebânîlere Cehennem’deki vazifeleri esnâsında, Cehennem ateşi zarar vermez. Denizin, balığa zararlı olmaması gibidir. (İtikadnâme)","osmanli":"زبانى"},{"kelime":"ZEBÂYIH","anlam":"Kesilecek kurbanlık hayvanlar, kurban edilmiş, kurban olarak kesilmiş hayvanlar.","kategori":"ibadet","misal":"Zebîha’nın çokluk hâli.","osmanli":"ذبايح"},{"kelime":"ZEBH","anlam":"Boğazlama, hayvanı boğazlama.","kategori":"dil","misal":"Eti helâl olan hayvanlardan boynu uzun olanla-rın hepsi nahr, boynu kısa olanların hepsi zebh edilir. (İbni Âbidîn) Deve kesmekte sünnet olan nahrdır (damarları boynun alt tarafından, göğsün bitim yerinden kesmek). Sığır cinsi, koyun ve tavuk gibi zebh olunur. Deveyi zebh ve sığırı ve koyunu nahr etmek mekrûhtur. (Fetâvây-i Hindiyye) Hayvanın boğazında merî denilen yemek bo-rusu, hulkûm denilen hava borusu ve evdâc de-nilen iki yanda birer kan damarı vardır. Zebh ve nahrda bu dört borudan üçü bir anda ke-silmelidir. (İbni Âbidîn) Zebh edilmeksizin ölen hayvan, meyte (leş) ol-duğu gibi dinin bildirdiği şekilde zebh edilmeyip de boğulmak ve başı koparılmak yâhud beyni üzerinde tokmak vurulmak veya kulak tozuna şiş saplanmak şeklinde öldürülen hayvan dahi meyte (leş) demektir. (Ni’met-i İslâm)","osmanli":"ذبح"},{"kelime":"ZEBûN","anlam":"Zayıf, güçsüz, âciz.","kategori":"dil","osmanli":"زبون"},{"kelime":"ZEBûR","anlam":"Dört mukaddes kitabdan Dâvûd aleyhisselâma indirilenin adı.","kategori":"dil","misal":"Dâvûd’a (aleyhisselâm) Zebûr’u verdiğimiz gibi. (Habîbim) şüphesiz sana da vahyettik. (Nisâ sûresi: 163); Tevrat’tan sonra Zebûr’da da yazmışızdır ki, arza (Cennet’e ancak) sâlih kullarım mîrâsçı olur. (Enbiyâ sûresi: 105) Allahü teâlânın peygamberleri vâsıtasıyla kullarına gönderdiği dört büyük kitabdan biri olan Zebûr, manzûm olup, İbrânî dili üzere idi. Tevrat’tan sonra indirilmiştir. Vâz ve nasihat şeklinde olup…","osmanli":"زبور"},{"kelime":"ZEHEB","anlam":"Altın.","kategori":"dil","osmanli":"ذهب"},{"kelime":"ZEKÂ","anlam":"Sebeb ile netîce arasındaki irti-","kategori":"fikih","misal":"batı bulmak, benzeyiş ve ayrılışları anlamak, yeni îcab ve vaziyetlere zihnin en iyi şekilde uyması, beynin süratli çalışması. Abdülhakîm Arvâsî buyuruyorki: Akıl, iyiyi ve kötüyü, fâideliyi ve zararlıyı anlar, ayırır. Her akıllı zekî, her zekî de akıllı olmayabilir. Aklı az olanın zekâsı çok olabilir. Zekâsı çok olan din düşmanlarını, akıllı sanmak doğru değildir. (Seâdet-i Ebediyye)","osmanli":"ذكاء"},{"kelime":"ZEKÂT","anlam":"İslâm’ın beş şartından, muayyen malların muayyen bir nisbetini Allah rızası için muayyen kimselere verme.","kategori":"ibadet","misal":"İman edip sâlih ameller yapan, namaz kılan ve zekât verenler var ya, onların mükâfatları Rableri katındadır. Onlara korku yoktur, onlar üzüntü de çekmezler. (Bakara sûresi: 277) Mallarınızı zekât ile koruyun. (Hadîs-i şerîfDeylemî) Dört çeşit malın zekâtı vardır. Bu mallar altın ve gümüş, ticâret eşyası, hayvanlar ve toprak mahsulleridir. (İbni Âbidîn)","osmanli":"زكات","alternatif":["zekat"]},{"kelime":"ZEKERİYYÂ (aleyhisselâm)","anlam":"Benî İsrâil’e gönderilen ve Kur’ân-ı kerîmde zikredilen peygamberlerden.","kategori":"dil","misal":"Süleymân aleyhisselâm soyundan ve Yahyâ aleyhisselâmın babasıdır. Zekeriya şöyle yalvarmıştı: “Rabbim! Beni tek başıma bırakma! Sen vârislerin en hayırlısısın! (Her şey sonunda sana kalır.)” Biz de icabet edip, (ileri yaşlarında ona ve zevcesine) Yahya’yı oğul bahşettik! (Enbiyâ sûresi: 89-90)","osmanli":"زكريا"},{"kelime":"ZELÎL","anlam":"Zillette olan, aşağı, alçak, hor, hakîr.","kategori":"dil","misal":"Allah, dilediğini aziz, dilediğini zelîl eder. (Âl-i İmrân sûresi: 26) Bir Müslümanın gücü yetmeyecek belâlara atılarak kendisini zelîl etmesi câiz olmaz. (Hadîs-i şerîf-Tirmizî) Sadaka istemek, kendini zelîl etmektir. Mü’mi-nin Allah’dan başkasına boyun bükmesi câiz de-ğildir. (Mektûbât-ı İmâm-ı Rabbânî)","osmanli":"ذليل"},{"kelime":"ZEMHERÎR","anlam":"1.Kışın en şiddetli so-ğuk devresi. 2.Soğuk cehennem.","kategori":"akaid","misal":"Zemheririn soğukluğu pek şiddetlidir. Bir an da-yanılmaz. Kâfirlere, bir soğuk, bir sıcak, sonra soğuk sonra sıcak Cehennem’e atılarak azap yapılacaktır. Cinler ateşten etkilenmezler. Ce-hennemlik olanları zemherirde azap görecek-lerdir. (Âmentü Şerhi)","osmanli":"زمهرير"},{"kelime":"ZEMZEM","anlam":"Kâbe-i Muazzama’nın Hacerü’l-esved köşesi karşısındaki kuyudan çıkan mübârek su.","kategori":"dil","misal":"İbrâhim aleyhisselâmın zevcesi ve İsmâil aleyhisselâmın annesi olan Hâcer, su aramak üzere Safâ ve Merve tepeleri arasında gidip gelirken, Zemzem kuyusunun bulunduğu yerde, Cibrîl aleyhisselâm göründü. Topuğu ile (veya kanadıyla) toprağı kazıp suyu meydana çıkardı. Hâcer zâyi olmasın diye hemen suyun etrâfını çevirip, havuz hâline getirdi. Bir taraftan da testisini doldurmaya çalışıyordu. Su ise avuç avuç alındıkça…","osmanli":"زمزم"},{"kelime":"ZEN","anlam":"Kadın.","kategori":"osmanli","osmanli":"زن"},{"kelime":"ZENB","anlam":"Günah, suç, cürm.","kategori":"dil","misal":"Nitekim onlardan her birini zenbi sebebiyle cezalandırdık. (Ankebut sûresi: 40) Zenbine tövbe eden, hiç zenbi olmayan gibidir. (Hadîs-i şerîf-Hâkim, İbn-i Asâkir, İbn-i Ebi’d-Dünya)","osmanli":"ذنب"},{"kelime":"ZENBİL","anlam":"Sepet.","kategori":"dil","osmanli":"زنبيل"},{"kelime":"ZENGİN","anlam":"1.Malı, mülkü çok olan. 2.Zekât, fıtra, kurban, hac gibi ibadetleri yerine getirebilecek kadar asgari mal varlığına sahip bulunan kimse; nisâba sahip Müslüman. Borçtan ve aslî ihtiyaçtan fazla olarak, 200 dirhem gümüşe veya o kıymette mala mâlik olan kimse, zengin sayılır. Kendisine sadaka-i fıtr, kurban ve akraba nafakası vâcib olur; sadaka alması haram olur. (Ni’met-i İslâm)","kategori":"ibadet","osmanli":"زنگين"},{"kelime":"ZERDÜŞT","anlam":"1.İran’ın eski dinini kuran ve M. 2.Zerdüşt dinine mensub kimse, ateşperest.","kategori":"dil","misal":"Ö. V. asırda yaşayan kimse.","osmanli":"زردشت"},{"kelime":"ZERK","anlam":"Bir sıvıyı ilaç olarak derinin al-tına şırınga etme.","kategori":"dil","osmanli":"زرك"},{"kelime":"ZERK","anlam":"Riya.","kategori":"dil","osmanli":"زرق"},{"kelime":"ZEVÂİD","anlam":"Fazla, ziyâde olan şeyler. Zâi-de’nin çokluk hâli.","kategori":"dil","osmanli":"زوائد"},{"kelime":"ZEVÂL","anlam":"1.Yok olma, sona erme. 2.Güneşin tam tepede olduğu zaman.","kategori":"dil","misal":"Ölmez imiş âşık cânı, Hiç çürümez imiş teni, Aşk her kimi kıldı fânî, Ona zevâl ermez imiş. (Yûnus Emre) Zuhr, yani öğle namazının evvel vakti, güneşin zevâlden ayrıldığı vakit başlar. (Kedûsî)","osmanli":"زوال"},{"kelime":"ZEVÂT","anlam":"Şahıslar; yüksek kimseler. Zât’ın çokluk hâli.","kategori":"dil","osmanli":"ذوات"},{"kelime":"ZEVC","anlam":"Eş; koca, bir kadının nikâhına sahip olan erkek.","kategori":"dil","misal":"Çokluk hâli ezvâc gelir.","osmanli":"زوج"},{"kelime":"ZEVCÂT-I TÂHİRÂT","anlam":"“Temiz zevceler” mânâsına Resûlullah aleyhisselâmın zevceleri için kullanılan tabir.","kategori":"dil","misal":"(Bkz. Ezvâc-ı Tâhirât)","osmanli":"طاهرات زوجات"},{"kelime":"ZEVCE","anlam":"Karı, bir erkeğin nikâhı altında bulunan kadın.","kategori":"dil","misal":"Çokluk hâli zevcât gelir.","osmanli":"زوجه"},{"kelime":"ZEYDİYYE","anlam":"Zeyd bin Zeynelâbidin’e nisbet edilen, Hazret-i Ali’yi üstün tutmakla beraber, ilk üç halîfenin halîfeliklerini meşru kabul eden mutedil Şiî fırkası.","kategori":"dil","osmanli":"زيديه"},{"kelime":"ZEYL","anlam":"1.Kuyruk, ek, ilâve. 2.Bir kitaba ilâve olarak yazılan şeyler.","kategori":"dil","osmanli":"زيل"},{"kelime":"ZEYNİYYE","anlam":"Halvetiyye tarikatının 838 (M.","kategori":"tasavvuf","misal":"1435) senesinde Horasan’da vefat eden Zeynüddin Hafî tarafından kurulan kolu.","osmanli":"زينيه"},{"kelime":"ZEYT","anlam":"Yağ, zeytin yağı.","kategori":"dil","osmanli":"زيت"},{"kelime":"ZÎ RAHM","anlam":"“Rahm sahibi” mânâsına aynı soydan gelen akrabaları ifade eden bir ta-bir. Çokluk hâli zevü’l-erham gelir.","kategori":"dil","osmanli":"رحم ذى"},{"kelime":"ZÎ RAHM-İ MAHREM","anlam":"Bir erkeğin ve kadının hiç evlenemeyeceği, kan ile olan nesepten (soydan) akrabâsı.","kategori":"dil","misal":"Zî rahm-i mahrem şunlardır: Baba, dede, oğul, oğlun oğlu, erkek kardeş, erkek ve kız kardeşinin oğlu, amca, dayı; anne, nine, kız, kızın kızı, kız kardeşi, erkek ve kız kardeşin kızı, hala, teyze. (İbni Âbidîn) Zî rahm-i mahrem olmayan kadınların, avret yerlerine bakmak, konuşmak, halvet etmek harâmdır. (Ni’met-i İslâm)","osmanli":"محرم رحم ذى"},{"kelime":"ZİFÂF","anlam":"Kocanın karısıyla ilk cinsî mü-nasebeti. Gerdek.","kategori":"dil","misal":"Nikâhsız, nikâh şüphesiyle veya fâsid ve bâtıl nikâhla vâki cinsî münasebete zifaf denmez; vaty adı verilir. Halvet olmadığı zevcesini zifafa girmeden boşa-yan erkek, mehr-i müsemmânın yarısını öder. (Ni’met-i İslam) Başından zifaf ile neticelenmiş bir nikâh geçen Müslüman ve hür kimse muhsandır. Bunun zinâsının cezası recmdir. (İbni Âbidîn)","osmanli":"زفاف"},{"kelime":"ZIHÂR","anlam":"Erkeğin, hanımını veya onun yüz, baş, ferc gibi bir uzvunu, kendisine nikâhı ebedî haram olan bir kadına veya onun bakılması harâm yerine; “Sen anam gibisin” veya “Senin sırtın anamın sırtı gibidir” gibi sözlerle benzetmesi.","kategori":"fikih","misal":"Hanımına “Senin başın anamın sırtı gibidir” diyen bir erkeğin, keffâret vermedikçe hanımına sarılması, öpmesi ve cimâ etmesi harâm olur. Zıhâr keffâreti, oruç keffâreti gibidir. (Bah-ru’r-Râik)","osmanli":"ظهار"},{"kelime":"ZİHN","anlam":"Düşünme, anlama, unutmama kuvveti, hâfıza.","kategori":"dil","osmanli":"ذهن"},{"kelime":"ZİKR","anlam":"1.Hatırlama, anma, yâd etme. 2.Allahü teâlânın ismini ve sıfatlarını hatırlamak, dille söylemek, kalbe yerleştirmek.","kategori":"tasavvuf","misal":"İyi biliniz ki, kalbler, Allahü teâlânın zikri ile itmînâna, rahata kavuşur. (Ra‘d sûresi: 30) (Kullarım!) Siz beni (tâat ile beğendiğim işleri yapmak sûretiyle) zikrederseniz, ben de sizi (rahmet, mağfiret, ihsân ve tövbe kapılarını açmak sûretiyle) anarım. (Bakara sûresi: 152) Ey mü’minler! Allah’ı çokça zikredin! (Ahzâb sûresi…","osmanli":"ذكر"},{"kelime":"Zikr-i Cehrî","anlam":"Allahü teâlâyı yüksek sesle anma.","kategori":"tasavvuf","misal":"Zikr-i aleniyye.","osmanli":"جهرى ذكر"},{"kelime":"Zikr-i Hafî","anlam":"Allahü teâlâyı gizli (sessiz) olarak ve kalb ile anma.","kategori":"tasavvuf","misal":"Zikrin hayırlısı, zikr-i hafîdir. (Hadîs-i şerîfİbni Hibbân)","osmanli":"خفى ذكر"},{"kelime":"ZILÂL","anlam":"Gölgeler. Zıll’ın çokluk hâli.","kategori":"dil","osmanli":"ظلال"},{"kelime":"ZİLHİCCE","anlam":"Kamerî senenin ayları olan Arabî aylardan sonuncusu. Hac mena-siki ifa edildiği için “Hac sahibi” mânâsına bu ismi almıştır.","kategori":"ibadet","misal":"Zilhicce’nin on gününde yapılan ibadet ka-dar diğer günlerin hiç birindeki ibadet Al-lahü teâlâya sevgili değildir. Bu günlerden her birinin orucu bir yılın orucuna, gece-lerinden her birinin ihyâsı da Kadr gecesi-nin ihyâsına denktir. (Hadîs-i şerîf-Tirmizî)","osmanli":"الحجه ذى"},{"kelime":"ZILL","anlam":"Gölge, görünüş.","kategori":"dil","misal":"Kâmil bir Müslüman, namaza durunca, sanki dünyadan çıkıp âhirete girer. Çünki dünyada Allahü teâlâya yaklaşmak çok az nasip olur. Eğer nasip olursa, o da zılle, sûrete yakınlık-tır. Âhiret ise, asla yakınlık yeridir. (Mektû-bât-ı Ma’sûmiyye)","osmanli":"ظل"},{"kelime":"ZİLLET","anlam":"Aşağılık, horluk, hakîrlik, iti-barsızlık.","kategori":"dil","misal":"İyi davrananlara; daima daha iyisi ve üstünü verilir. Onların yüzlerine ne bir kara leke, ne de zillet bulaşır. İşte onlar Cennetlikler-dir, orada temelli kalırlar. Kötülük yapan-lara kötülükleri kadar ceza verilir. Onların yüzlerini zillet bürür. Allah’a karşı onları savunacak yoktur. Yüzleri, geceden kara bir parçayla örtülmüş gibidir. Bunlar Cehen-nemliklerdir, orada temelli kalırlar. (Yûnus sûresi: 26-27) Cihadı terk ettiğiniz zaman, Allah sizi zillete düşürür. (Hadîs-i şerîf-Ebû Dâvûd, Müsnedü İmâm-ı Ahmed) İstiskâda (yağmur duâsında) müstehab olan, yamalı ve eski elbiseleri giyinip boyun büke-rek, son derece zillet, huşû‘ ve tevazu üzere ol-maktır. (Ni’met-i İslâm)","osmanli":"ذلت"},{"kelime":"ZILLÎ","anlam":"Gölgeye mensub, gölge ile alâkalı.","kategori":"dil","osmanli":"ظلى"},{"kelime":"ZİMMET","anlam":"1.Borç, mes’ûliyet, insanda bulunup leh ve aleyhine olan şeylere ehil olmasını ifade eden manevî vasıf. 2.Uhde, ahd, emân, himayeyi temin eden anlaşma.","kategori":"muamelat","misal":"Kim ki, yemin etmesi istenir de, o da bir Müslümanın malını zimmetine geçirmek için yalan yere yemin ederse, Allah’ın huzuruna Allah kendisine gazap etmiş olarak varır. (Hadîs-i şerîfBuhârî, Müslim, Ebû Dâvûd) İslâm devleti ile gayrımüslimler arasında, cizye karşılığı vatandaş statüsünde yaşamaları üzere yapılan anlaşma. Gayrımüslimlerin can, mal ve din hürriyetinin Mü…","osmanli":"ذمت"},{"kelime":"ZİMMÎ","anlam":"İslâm devletinde kendisiyle zimmet anlaşması yapılarak vatandaş statüsü tanınan gayrimüslim.","kategori":"muamelat","misal":"Zimmîyi haksız yere öldüren, Cennetin kokusunu duyamaz. (Hadîs-i şerîf- Buhârî, Ebû Dâvûd, Tirmizî, İbn-i Mâce, Dârimî, Müsned, İbni Hibbân) Zimmîye zulmetmek, Müslümana zulmetmekten; hayvana zulüm, zimmîye zulmetmekten daha fenâdır. Zimmîyi eziyetlendirmemek için selâm vermek ve müsâfeha etmek câiz olur. (Dürrü’l-Muhtâr)","osmanli":"ذمى"},{"kelime":"ZİNÂ","anlam":"Âkıl ve bâliğ kadın ve erkeğin aralarında nikâh olmadan gayrımeşrû münâsebette bulunması.","kategori":"dil","misal":"De ki: Geliniz size Rabbiniz neleri harâm etmiştir, okuyayım: “O’na hiçbir şeyi ortak koşmayın, anaya babaya iyilik edin, fakîrlik yüzünden çocuklarınızı öldürmeyin. Sizin de onların da rızkını biz veririz. Zinâ gibi kötülüklerin açığına da, gizlisine de yanaşmayınız. Allah’ın muhterem kıldığı canı haksız yere öldürmeyin.” İşte bu yasaklara riâyet etmeyi (uymayı) Allahü teâlâ size tavsiye etti. Olur ki, düşünür ve a…","osmanli":"زناء"},{"kelime":"ZINDIK","anlam":"Müslüman olmadığı hâlde, böyle görünen, dinin bazı esaslarını kabul edip, bazılarını kabul etmeyerek mü’minleri dinden soğutmaya çalışan kimse.","kategori":"dil","misal":"Zındık, Allahü teâlâya ve Muhammed aleyhis-selâmın peygamber olduğuna inandığını, Kur’ân’a ve hadîslere uyduğunu söyler. Fakat, Kur’ân-ı kerîmi ve hadîs-i şerîfleri kendi câhil kafasına ve kısa görüşüne göre mânâlandırır. Bu bozuk anladıklarını, sapık düşüncelerini, Müslüman-lık olarak yazmaya uğraşır. Ehl-i sünnet âlim-lerinin doğru sözlerini beğenmez. İslâm âlim-lerine câhil der. Bunlar kendilerini müctehîd, aydın din adamı olarak tanıtırlar. (İbni Âbidîn)","osmanli":"زندق"},{"kelime":"ZÎNET","anlam":"Süs, ihtiyaçtan fazla olup, tatlı gelen, hoşa giden şeyler.","kategori":"dil","misal":"Dünya hayâtı elbette la’b, yani oyun ve lehv yani eğlence ve zînet ve tefâhür yani öğünme ve malı, parayı, evlâdı çoğaltmaktır. (Ha-dîd sûresi: 20) Erkeklerin evde ve sokakta, kadınların yalnız evde, mübah şeylerle zinetlenmeleri caizdir. (İbn-i Nüceym)","osmanli":"زينت"},{"kelime":"ZİNNûREYN","anlam":"Resûlullah aleyhisselâmın iki kızı ile evlendiği için “İki nûr sahibi” mânâsına Hazret-i Osman’a verilen lakab Resûlullah sallallahü aleyhi ve sellem Osman radıyallahü anha birbiri ardınca iki kızını vermiştir.","kategori":"dil","misal":"Bu sebeble Zinnûreyn’dir. İki kızı da vefât edince; “Bir kızım daha olsaydı verirdim” buyurmuştur. (Mir’ât-ı Kâinât)","osmanli":"النورين ذي"},{"kelime":"ZİYÂ","anlam":"Işık, aydınlık.","kategori":"dil","osmanli":"ضياء"},{"kelime":"ZİYÂFET","anlam":"(A. Dayf ’dan) Misafir etme, misafire ikramda bulunma.","kategori":"dil","misal":"Düğün için bir koyun kesin de ziyafet ve-rin! (Hadîs-i şerîf-Buhârî) En kötü ziyafet, zenginlerin çağırılıp fakirlerin çağırılma-dığıdır. (Hadîs-i şerîf-Buhârî)","osmanli":"ضيافت"},{"kelime":"ZİYÂN","anlam":"Zarar, kayıp.","kategori":"dil","osmanli":"زيان"},{"kelime":"ZİYÂRET","anlam":"1.Görüşmeye gitme, bi-rini görmeye gitme. 2.İhrâmlı olarak tavaf, sa’y, vakfe gibi haccın menâsikini zamanında ve usûlüne muvafık şekilde yerine getirme.","kategori":"ibadet","osmanli":"زيارت"},{"kelime":"ZÜHÂL","anlam":"Satürn gezegeni.","kategori":"dil","osmanli":"زحل"},{"kelime":"ZÜHD","anlam":"1.Aldırış etmeme, mühimsememe. 2.Dünyadan ve dünyalık olan şeylerden uzak durma; şüpheli olma korkusu ile mübâhların çoğundan sakınma.","kategori":"fikih","misal":"Bir kimseye dünyada zühd ve az konuşma verildiğini gördüğünüzde ona yakın olunuz. Zira, o kimse hikmete ulaşmıştır. (Hadîs-i şerîfİbn-i Mâce) Dünyada zühd, helâli harâm etmek ve malı ziyan etmekte değildir. Zühd odur ki, Allahü teâlânın elindekine, kendi elindekinden fazla bağlanmaktır. (Hadîs-i şerîfBeyhekî) Zühd, Allah’ın sevdiğini sevmen, Allah’ın sevmediğini sevmemen ve dünyanın hâcetinden fazla helâlinin, harâm…","osmanli":"زهد"},{"kelime":"ZuHR","anlam":"Öğle.","kategori":"dil","osmanli":"ظهر"},{"kelime":"Zuhr Vakti","anlam":"Öğle namazı vakti. Güneşin zevâlden yani tepe noktasından ayrılıp yere dikili bir çubuğun gölgesinin yere düşmeye başladığı andan, çubuğun gölgesinin bir veya iki misli olduğu zamana kadar devam eden vakit.","kategori":"ibadet","osmanli":"وقتى ظهر"},{"kelime":"ZuHûRÂT","anlam":"Hesapta olmayan, umul-madık, sürpriz şeyler.","kategori":"dil","osmanli":"ظهورات"},{"kelime":"ZÜLFİKÂR","anlam":"Bedr’de Resûlullah aleyhisselâma geçip, Hazret-i Ali’ye hediye ettiği ve ucu çatallı olduğu rivâyet edilen meşhur kılıç.","kategori":"dil","osmanli":"ذوالفقار"},{"kelime":"ZÜLKARNEYN (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi ve seyahat kıssası zikredilen peygamber veya velî.","kategori":"dil","misal":"Asıl ismi İskender olup, dünyanın doğusu ve batısına gittiği için “iki boynuzlu” mânâsına Zülkarneyn nâmıyla anılmıştır. Yemen hükümdarı İskender ile Makedonyalı İskender’den daha evvel yaşamıştır. Biz, Zülkarneyn’i yeryüzünde kudret sahibi kıldık, ona her şey için bir vasıta ve yol verdik. (Kehf sûresi: 83-84)","osmanli":"ذوالقرنين"},{"kelime":"ZÜLKİFL (aleyhisselâm)","anlam":"Kur’ân-ı kerîmde ismi zikredilen Benî İsrâil’e gönderilen peygamberlerden.","kategori":"dil","misal":"İsmail’i, Elyesa’ı, Zülkifl’i de an. Hepsi iyilerdendir. (Sâd sûresi: 48)","osmanli":"الكفل ذو"},{"kelime":"ZuLMET","anlam":"Karanlık; kalbin kararması.","kategori":"tasavvuf","misal":"Hak teâlâ nûr ile zulmeti, aydınlık ile karanlığı zikrettiği yerde, aydınlıktan ilmi, karanlıktan câhilliği murâd etti. Nitekim Allahü teâlâ; “Onları karanlıktan aydınlığa çıkarırız” buyurdu. (Kimyâ-i Seâdet)","osmanli":"ظلمت"},{"kelime":"ZÜMER SûRESİ","anlam":"Kur’ân-ı kerîmin otuz dokuzuncu sûresi.","kategori":"dil","misal":"Mekke’de nâzil oldu. Yetmiş beş âyettir. İsmini yetmiş bir ve yetmiş üçüncü âyetlerde geçen Zümre kelimesinin çoğulu olan zümer lafzından almıştır. Sûrede Kur’ân-ı kerîmin Allahü teâlâ tarafından indirildiği, zâlimlerin âhirette cezâlarının sonsuz olduğu, kıyâmet ve âhiret hâlleri bildirilmektedir. (Tefsir-i Kurtubî, Mefâtihü’l-Gayb, Tefsir-i Mazharî) Resûl-i ekrem, Zümer ve İsrâ sûrelerini okumadan uyumazdı. (Hadîs…","osmanli":"سى سوره زمر"},{"kelime":"ZÜNNÂR","anlam":"Papazların bellerine bağladıkları ipten veya kıldan örme kaba sert ve uçları öne sarkık kuşak.","kategori":"dil","misal":"Kâfirlerin âyinlerini beğenmek, zarûret yok iken zünnâr kuşanmak ve küfr alâmetlerini kullanmak imanı giderir. (Miftahü’l-Cenne) Sen dereyi geçmeden ummânı arzularsın, Zünnârını kesmeden îmânı arzularsın. (Niyâzi Mısrî)","osmanli":"زنار"},{"kelime":"ZÜRRİYYET","anlam":"Soy, nesil.","kategori":"dil","misal":"Ey Rabbimiz! Bizi sana teslimde, boyun eğ-mekte ve ihlâsta sâbit kıl. Zürriyyetimizden bir topluluğu da sana itâatkâr ve boyun eğici kıl. (Bakara sûresi: 128) Hudâ Rabbim, Nebîm hakka, Muhammed-dir Resûlullah, Hem İslâm dinidir, dinim, kitabımdır kelâmullah. Akâidde, Ehl-i sünnet oldu mezhebim hamdolsun, Amelde Ebû Hanîfe mezhebi, mezhebim vallah. Dahî zürriyyetiyim Âdem aleyhisselâmın hem, Halîl’in milletiyim, dahî, kıblem Kâbe, Beytullah. (Erzurumlu İbrâhim Hakkı)","osmanli":"ذريت"},{"kelime":"ZÜYûF","anlam":"Altın ve gümüş nisbeti yarı-dan az olan paralar. Mağşuş paralar. Zeyf’in çokluk hâli.","kategori":"dil","misal":"Züyûf ile ödünç verdikten sonra, o züyûfun kıymeti kalmasa, İmâmeyne yani İmâm-ı Ebû Yûsuf ve Muhammed’e göre teslim ettiği za-mandaki kıymetinde altın veya bu kadar altın karşılığı geçer akçe ile ödenir. Kıymeti değişirse, Ebû Yûsuf ’a göre yine böyledir. (İbni Âbidîn)","osmanli":"زيوف"}];